window.BOOK={"slug": "leviticus", "name": "Leviticus", "testament": "OT", "orig_label": "Hebrew · WLC", "rtl": true, "translations": [{"id": "kjv", "label": "KJV (1611)"}, {"id": "web", "label": "WEB (modern)"}, {"id": "bsb", "label": "Berean Standard"}, {"id": "asv", "label": "ASV (1901)"}, {"id": "ylt", "label": "Young's Literal"}, {"id": "tyndale", "label": "Tyndale (1526)"}, {"id": "dra", "label": "Douay-Rheims"}, {"id": "bbe", "label": "Basic English"}, {"id": "geneva", "label": "Geneva (1599)"}, {"id": "wycliffe", "label": "Wycliffe (1382)"}, {"id": "rotherham", "label": "Rotherham Emph."}, {"id": "darby", "label": "Darby"}, {"id": "twenty", "label": "20th Century NT"}, {"id": "jps", "label": "JPS Tanakh (1917)"}, {"id": "acv", "label": "A Conservative Version"}, {"id": "anderson", "label": "Anderson NT (1864)"}, {"id": "haweis", "label": "Haweis NT (1795)"}, {"id": "noyes", "label": "Noyes NT (1869)"}, {"id": "webster", "label": "Webster (1833)"}, {"id": "vulgate", "label": "Vulgate · Latin"}, {"id": "brenton", "label": "LXX · Brenton (Eng)"}], "books": [{"slug": "mark", "name": "Mark", "file": "Mark.html", "testament": "NT"}, {"slug": "matthew", "name": "Matthew", "file": "Matthew.html", "testament": "NT"}, {"slug": "luke", "name": "Luke", "file": "Luke.html", "testament": "NT"}, {"slug": "john", "name": "John", "file": "John.html", "testament": "NT"}, {"slug": "acts", "name": "Acts", "file": "Acts.html", "testament": "NT"}, {"slug": "romans", "name": "Romans", "file": "Romans.html", "testament": "NT"}, {"slug": "1corinthians", "name": "1 Corinthians", "file": "1Corinthians.html", "testament": "NT"}, {"slug": "philippians", "name": "Philippians", "file": "Philippians.html", "testament": "NT"}, {"slug": "colossians", "name": "Colossians", "file": "Colossians.html", "testament": "NT"}, {"slug": "philemon", "name": "Philemon", "file": "Philemon.html", "testament": "NT"}, {"slug": "hebrews", "name": "Hebrews", "file": "Hebrews.html", "testament": "NT"}, {"slug": "genesis", "name": "Genesis", "file": "Genesis.html", "testament": "OT"}, {"slug": "exodus", "name": "Exodus", "file": "Exodus.html", "testament": "OT"}, {"slug": "leviticus", "name": "Leviticus", "file": "Leviticus.html", "testament": "OT"}, {"slug": "numbers", "name": "Numbers", "file": "Numbers.html", "testament": "OT"}, {"slug": "deuteronomy", "name": "Deuteronomy", "file": "Deuteronomy.html", "testament": "OT"}, {"slug": "ruth", "name": "Ruth", "file": "Ruth.html", "testament": "OT"}, {"slug": "job", "name": "Job", "file": "Job.html", "testament": "OT"}, {"slug": "psalms", "name": "Psalms", "file": "Psalms.html", "testament": "OT"}, {"slug": "isaiah", "name": "Isaiah", "file": "Isaiah.html", "testament": "OT"}, {"slug": "ezekiel", "name": "Ezekiel", "file": "Ezekiel.html", "testament": "OT"}, {"slug": "daniel", "name": "Daniel", "file": "Daniel.html", "testament": "OT"}], "chapters": [{"c": 1, "verses": [{"v": 1, "ref": "1:1", "o": "וַ/יִּקְרָ֖א אֶל מֹשֶׁ֑ה וַ/יְדַבֵּ֤ר יְהוָה֙ אֵלָ֔י/ו מֵ/אֹ֥הֶל מוֹעֵ֖ד לֵ/אמֹֽר", "en": {"kjv": "And the Lord called unto Moses, and spake unto him out of the tabernacle of the congregation, saying,", "web": "Yahweh called to Moses, and spoke to him from the Tent of Meeting, saying,", "bsb": "Then the LORD called to Moses and spoke to him from the Tent of Meeting, saying,", "asv": "And Jehovah called unto Moses, and spake unto him out of the tent of meeting, saying,", "ylt": "And Jehovah calleth unto Moses, and speaketh unto him out of the tent of meeting, saying,", "tyndale": "And the Lorde called Moses, And spake vnto him oute off the tabernacle of witnesse sayenge.", "dra": "And the Lord called Moses, and spoke to him from the tabernacle of the testimony, saying:", "bbe": "And the voice of the Lord came to Moses out of the Tent of meeting, saying,", "geneva": "Nowe the Lord called Moses, and spake vnto him out of the Tabernacle of the Congregation, saying,", "wycliffe": "Forsothe the Lord clepide Moyses, and spak to him fro the tabernacle of witnessyng, `and seide,", "rotherham": "Then called he unto Moses,—and Yahweh spake unto him, out of the tent of meeting, saying:", "darby": "And Jehovah called to Moses and spoke to him out of the tent of meeting, saying,", "twenty": "", "jps": "THE HaShem called unto Moses, and spoke unto him out of the tent of meeting, saying:", "acv": "And Jehovah called to Moses, and spoke to him out of the tent of meeting, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD called to Moses, and spoke to him out of the tabernacle of the congregation, saying,", "vulgate": "vocavit autem Mosen et locutus est ei Dominus de tabernaculo testimonii dicens;", "brenton": "And the Lord called Moses again and spoke to him out of the tabernacle of witness, saying, Speak to the children of Israel, and thou shalt say to them,"}}, {"v": 2, "ref": "1:2", "o": "דַּבֵּ֞ר אֶל בְּנֵ֤י יִשְׂרָאֵל֙ וְ/אָמַרְתָּ֣ אֲלֵ/הֶ֔ם אָדָ֗ם כִּֽי יַקְרִ֥יב מִ/כֶּ֛ם קָרְבָּ֖ן לַֽ/יהוָ֑ה מִן הַ/בְּהֵמָ֗ה מִן הַ/בָּקָר֙ וּ/מִן הַ/צֹּ֔אן תַּקְרִ֖יבוּ אֶת קָרְבַּנְ/כֶֽם", "en": {"kjv": "Speak unto the children of Israel, and say unto them, If any man of you bring an offering unto the Lord, ye shall bring your offering of the cattle, even of the herd, and of the flock.", "web": "“Speak to the children of Israel, and tell them, ‘When anyone of you offers an offering to Yahweh, you shall offer your offering of the livestock, from the herd and from the flock.", "bsb": "“Speak to the Israelites and tell them: When any of you brings an offering to the LORD, you may bring as your offering an animal from the herd or the flock.", "asv": "Speak unto the children of Israel, and say unto them, When any man of you offereth an oblation unto Jehovah, ye shall offer your oblation of the cattle, even of the herd and of the flock.", "ylt": "`Speak unto the sons of Israel, and thou hast said unto them, Any man of you when he doth bring near an offering to Jehovah, out of the cattle--out of the herd, or out of the flock--ye do bring near your offering.", "tyndale": "Speake vnto the childern of Israel, and saye vnto them. Who soeuer of you shall bringe a gifte vnto the Lorde, shall bringe it of the catell: euen of the oxen and of the shepe.", "dra": "Speak to the children of Israel, and thou shalt say to them: The man among you that shall offer to the Lord a sacrifice of the cattle, that is, offering victims of oxen and sheep:", "bbe": "Give these orders to the children of Israel: When anyone of you makes an offering to the Lord, you are to take it from the cattle, from the herd or from the flock.", "geneva": "Speake vnto the children of Israel, and thou shalt say vnto them, If any of you offer a sacrifice vnto the Lord, ye shall offer your sacrifice of cattell, as of beeues and of the sheepe.", "wycliffe": "Speke thou to the sones of Israel, and thou schalt seie to hem, A man of you, that offrith to the Lord a sacrifice of beestis, that is, of oxun and of scheep, and offrith slayn sacrifices, if his offryng is brent sacrifice,", "rotherham": "Speak thou unto the sons of Israel, and thou shalt say unto them When any man, would bring near from among you an oblation, unto Yahweh, from the beasts, from the herd or from the flock, shall ye bring near your oblation.", "darby": "Speak unto the children of Israel and say unto them, When any man of you presenteth an offering to Jehovah, ye shall present your offering of the cattle, of the herd and of the flock.", "twenty": "", "jps": "Speak unto the children of Israel, and say unto them: When any man of you bringeth an offering unto HaShem, ye shall bring your offering of the cattle, even of the herd or of the flock.", "acv": "Speak to the sons of Israel, and say to them, When any man of you offers an oblation to Jehovah, ye shall offer your oblation of the cattle, even of the herd and of the flock.", "anderson": "", "haweis": "", "noyes": "", "webster": "Speak to the children of Israel, and say to them, If any man of you shall bring an offering to the LORD, ye shall bring your offering of the cattle, [even] of the herd, and of the flock.", "vulgate": "loquere filiis Israhel et dices ad eos homo qui obtulerit ex vobis hostiam Domino de pecoribus id est de bubus et ovibus offerens victimas;", "brenton": "If any man of you shall bring gifts to the Lord, ye shall bring your gifts of the cattle and of the oxen and of the sheep."}}, {"v": 3, "ref": "1:3", "o": "אִם עֹלָ֤ה קָרְבָּנ/וֹ֙ מִן הַ/בָּקָ֔ר זָכָ֥ר תָּמִ֖ים יַקְרִיבֶ֑/נּוּ אֶל פֶּ֝תַח אֹ֤הֶל מוֹעֵד֙ יַקְרִ֣יב אֹת֔/וֹ לִ/רְצֹנ֖/וֹ לִ/פְנֵ֥י יְהוָֽה", "en": {"kjv": "If his offering be a burnt sacrifice of the herd, let him offer a male without blemish: he shall offer it of his own voluntary will at the door of the tabernacle of the congregation before the Lord.", "web": "“‘If his offering is a burnt offering from the herd, he shall offer a male without defect. He shall offer it at the door of the Tent of Meeting, that he may be accepted before Yahweh.", "bsb": "If one’s offering is a burnt offering from the herd, he is to present an unblemished male. He must bring it to the entrance to the Tent of Meeting for its acceptance before the LORD.", "asv": "If his oblation be a burnt-offering of the herd, he shall offer it a male without blemish: he shall offer it at the door of the tent of meeting, that he may be accepted before Jehovah.", "ylt": "`If his offering is a burnt-offering out of the herd--a male, a perfect one, he doth bring near, unto the opening of the tent of meeting he doth bring it near, at his pleasure, before Jehovah;", "tyndale": "Yf he brynge a burntoffrynge of the oxen he shall offre a male without blimesh, and shal brynge him to the dore of the tabernacle of witnesse, that he maye be accepted before the Lorde.", "dra": "If his offering be a holocaust, and of the herd, he shall offer a male without blemish, at the door of the testimony, to make the Lord favourable to him.", "bbe": "If the offering is a burned offering of the herd, let him give a male without a mark: he is to give it at the door of the Tent of meeting so that he may be pleasing to the Lord.", "geneva": "If his sacrifice be a burnt offering of the heard, he shall offer a male without blemish, presenting him of his owne voluntarie will at the doore of the Tabernacle of the Congregation before the Lord.", "wycliffe": "and of the droue of oxun, he schal offre a male beeste without wem at the dore of the tabernacle of witnessyng, to make the Lord plesid to hym.", "rotherham": "If an ascending-sacrifice, be his oblation—of the herd, a male without defect, shall he bring near,—unto the entrance of the tent of meeting, shall he bring it, for its acceptance, before Yahweh.", "darby": "If his offering be a burnt-offering of the herd, he shall present it a male without blemish: at the entrance of the tent of meeting shall he present it, for his acceptance before Jehovah.", "twenty": "", "jps": "If his offering be a burnt-offering of the herd, he shall offer it a male without blemish; he shall bring it to the door of the tent of meeting, that he may be accepted before HaShem.", "acv": "If his oblation be a burnt offering of the herd, he shall offer it a male without blemish. He shall offer it at the door of the tent of meeting, that he may be accepted before Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "If his offering shall [be] a burnt-sacrifice of the herd, let him offer a male without blemish: he shall offer it of his own voluntary will at the door of the tabernacle of the congregation before the LORD.", "vulgate": "si holocaustum fuerit eius oblatio ac de armento masculum inmaculatum offeret ad ostium tabernaculi testimonii ad placandum sibi Dominum;", "brenton": "If his gift be a whole-burnt-offering, he shall bring an unblemished male of the herd to the door of the tabernacle of witness, he shall bring it as acceptable before the Lord."}}, {"v": 4, "ref": "1:4", "o": "וְ/סָמַ֣ךְ יָד֔/וֹ עַ֖ל רֹ֣אשׁ הָ/עֹלָ֑ה וְ/נִרְצָ֥ה ל֖/וֹ לְ/כַפֵּ֥ר עָלָֽי/ו", "en": {"kjv": "And he shall put his hand upon the head of the burnt offering; and it shall be accepted for him to make atonement for him.", "web": "He shall lay his hand on the head of the burnt offering, and it shall be accepted for him to make atonement for him.", "bsb": "He is to lay his hand on the head of the burnt offering, so it can be accepted on his behalf to make atonement for him.", "asv": "And he shall lay his hand upon the head of the burnt-offering; and it shall be accepted for him to make atonement for him.", "ylt": "and he hath laid his hand on the head of the burnt-offering, and it hath been accepted for him to make atonement for him;", "tyndale": "And let him put his hande apon the heed of the burntsacrifice, and fauoure shalbe geuen him to make an attonemet for hym,", "dra": "And he shall put his hand upon the head of the victim: and it shall be acceptable, and help to its expiation.", "bbe": "And he is to put his hand on the head of the burned offering and it will be taken for him, to take away his sin.", "geneva": "And he shall put his hande vpon the head of the burnt offering, and it shalbe accepted to the Lord, to be his atonement.", "wycliffe": "And he schal sette hondis on the heed of the sacrifice, and it schal be acceptable, and profityng in to clensyng of hym.", "rotherham": "Then shall he lean his hand, upon the head of the ascending-sacrifice,—and it shall be accepted for him to put a propitiatory covering over him;", "darby": "And he shall lay his hand on the head of the burnt-offering; and it shall be accepted for him to make atonement for him.", "twenty": "", "jps": "And he shall lay his hand upon the head of the burnt-offering; and it shall be accepted for him to make atonement for him.", "acv": "And he shall lay his hand upon the head of the burnt offering, and it shall be accepted for him to make atonement for him.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall put his hand upon the head of the burnt-offering; and it shall be accepted for him to make atonement for him.", "vulgate": "ponetque manus super caput hostiae et acceptabilis erit atque in expiationem eius proficiens;", "brenton": "And he shall lay his hand on the head of the burnt-offering as a thing acceptable for him, to make atonement for him."}}, {"v": 5, "ref": "1:5", "o": "וְ/שָׁחַ֛ט אֶת בֶּ֥ן הַ/בָּקָ֖ר לִ/פְנֵ֣י יְהוָ֑ה וְ֠/הִקְרִיבוּ בְּנֵ֨י אַהֲרֹ֤ן הַֽ/כֹּֽהֲנִים֙ אֶת הַ/דָּ֔ם וְ/זָרְק֨וּ אֶת הַ/דָּ֤ם עַל הַ/מִּזְבֵּ֨חַ֙ סָבִ֔יב אֲשֶׁר פֶּ֖תַח אֹ֥הֶל מוֹעֵֽד", "en": {"kjv": "And he shall kill the bullock before the Lord: and the priests, Aaron’s sons, shall bring the blood, and sprinkle the blood round about upon the altar that is by the door of the tabernacle of the congregation.", "web": "He shall kill the bull before Yahweh. Aaron’s sons, the priests, shall present the blood and sprinkle the blood around on the altar that is at the door of the Tent of Meeting.", "bsb": "And he shall slaughter the young bull before the LORD, and Aaron’s sons the priests are to present the blood and sprinkle it on all sides of the altar at the entrance to the Tent of Meeting.", "asv": "And he shall kill the bullock before Jehovah: and Aaron’s sons, the priests, shall present the blood, and sprinkle the blood round about upon the altar that is at the door of the tent of meeting.", "ylt": "and he hath slaughtered the son of the herd before Jehovah; and sons of Aaron, the priests, have brought the blood near, and sprinkled the blood on the altar round about, which is at the opening of the tent of meeting.", "tyndale": "ad let him kyll the oxe before the Lorde. And let the preastes Aarons sonnes brynge the bloude and let them sprinckell it rounde aboute apon the alter that is before the dore of the tabernacle of witnesse,", "dra": "And he shall immolate the calf before the Lord: and the priests the sons of Aaron shall offer the blood thereof, pouring it round about the altar, which is before the door of the tabernacle.", "bbe": "And the ox is to be put to death before the Lord: then Aaron's sons, the priests, are to take the blood and put some of it on and round the altar which is at the door of the Tent of meeting.", "geneva": "And he shall kill the bullocke before the Lord, and the Priestes Aarons sonnes shall offer the blood, and shall sprinckle it round about vpon the altar, that is by the doore of the Tabernacle of the Congregation.", "wycliffe": "And he schal offre a calf bifor the Lord, and the sones of Aaron, preestis, schulen offre the blood ther of, and thei schulen schede bi the cumpas of the auter, which is bifor the dore of the tabernacle.", "rotherham": "and he shall slay the young bullock before Yahweh,—and the sons of Aaron, the priests, shall bring near the blood, and shall dash the blood against the altar round about, [even the altar] that is at the entrance of the tent of meeting.", "darby": "And he shall slaughter the bullock before Jehovah; and Aaron's sons, the priests, shall present the blood and sprinkle the blood round about on the altar that is at the entrance of the tent of meeting.", "twenty": "", "jps": "And he shall kill the bullock before HaShem; and Aaron's sons, the priests, shall present the blood, and dash the blood round about against the altar that is at the door of the tent of meeting.", "acv": "And he shall kill the bullock before Jehovah, and Aaron's sons, the priests, shall present the blood, and sprinkle the blood round about upon the altar that is at the door of the tent of meeting.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall kill the bullock before the LORD: and the priests, Aaron's sons, shall bring the blood, and sprinkle the blood around upon the altar that [is by] the door of the tabernacle of the congregation.", "vulgate": "immolabitque vitulum coram Domino et offerent filii Aaron sacerdotes sanguinem eius fundentes super altaris circuitum quod est ante ostium tabernaculi;", "brenton": "And they shall slay the calf before the Lord; and the sons of Aaron the priests shall bring the blood, and they shall pour the blood round about on the altar, which is at the doors of the tabernacle of witness."}}, {"v": 6, "ref": "1:6", "o": "וְ/הִפְשִׁ֖יט אֶת הָ/עֹלָ֑ה וְ/נִתַּ֥ח אֹתָ֖/הּ לִ/נְתָחֶֽי/הָ", "en": {"kjv": "And he shall flay the burnt offering, and cut it into his pieces.", "web": "He shall flay the burnt offering, and cut it into pieces.", "bsb": "Next, he is to skin the burnt offering and cut it into pieces.", "asv": "And he shall flay the burnt-offering, and cut it into its pieces.", "ylt": "`And he hath stripped the burnt-offering, and hath cut it into its pieces;", "tyndale": "And let the burntoffrynges be strypped and hewed in peces.", "dra": "And when they have flayed the victim, they shall cut the joints into pieces:", "bbe": "And the burned offering is to be skinned and cut up into its parts.", "geneva": "Then shall he fley the burnt offering, and cut it in pieces.", "wycliffe": "And whanne the skyn of the sacrifice is drawun awei, thei schulen kitte the membris in to gobetis;", "rotherham": "Then shall he flay the ascending-sacrifice,—and cut it up into its pieces.", "darby": "And he shall flay the burnt-offering, and cut it up into its pieces.", "twenty": "", "jps": "And he shall flay the burnt-offering, and cut it into its pieces.", "acv": "And he shall skin the burnt offering, and cut it into its pieces.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall flay the burnt-offering, and cut it into its pieces,", "vulgate": "detractaque pelle hostiae artus in frusta concident;", "brenton": "And having flayed the whole burnt-offering, they shall divide it by its limbs."}}, {"v": 7, "ref": "1:7", "o": "וְ֠/נָתְנוּ בְּנֵ֨י אַהֲרֹ֧ן הַ/כֹּהֵ֛ן אֵ֖שׁ עַל הַ/מִּזְבֵּ֑חַ וְ/עָרְכ֥וּ עֵצִ֖ים עַל הָ/אֵֽשׁ", "en": {"kjv": "And the sons of Aaron the priest shall put fire upon the altar, and lay the wood in order upon the fire:", "web": "The sons of Aaron the priest shall put fire on the altar, and lay wood in order on the fire;", "bsb": "The sons of Aaron the priest shall put a fire on the altar and arrange wood on the fire.", "asv": "And the sons of Aaron the priest shall put fire upon the altar, and lay wood in order upon the fire;", "ylt": "and the sons of Aaron the priest have put fire on the altar, and arranged wood on the fire;", "tyndale": "And the let the sonnes of Aaron the preast put fire apo the alter and put wodd apon the fire,", "dra": "And shall put fire on the altar, having before laid in order a pile of wood.", "bbe": "And Aaron's sons, the priests, are to put fire on the altar and put the wood in order on the fire:", "geneva": "So the sonnes of Aaron the Priest shall put fire vpon the altar, and lay the wood in order vpon the fire.", "wycliffe": "and thei schulen put vndur in the auter fier , and thei schulen make an heep of wode bifore; and thei schulen ordeyne aboue", "rotherham": "And the sons of Aaron the priest shall place fire upon the altar,—and arrange wood, upon the fire.", "darby": "And the sons of Aaron the priest shall put fire on the altar, and lay wood in order on the fire;", "twenty": "", "jps": "And the sons of Aaron the priest shall put fire upon the altar, and lay wood in order upon the fire.", "acv": "And the sons of Aaron the priest shall put fire upon the altar, and lay wood in order upon the fire.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the sons of Aaron the priest shall put fire upon the altar, and lay the wood in order upon the fire.", "vulgate": "et subicient in altari ignem strue lignorum ante conposita;", "brenton": "And the sons of Aaron the priests shall put fire on the altar, and shall pile wood on the fire."}}, {"v": 8, "ref": "1:8", "o": "וְ/עָרְכ֗וּ בְּנֵ֤י אַהֲרֹן֙ הַ/כֹּ֣הֲנִ֔ים אֵ֚ת הַ/נְּתָחִ֔ים אֶת הָ/רֹ֖אשׁ וְ/אֶת הַ/פָּ֑דֶר עַל הָ/עֵצִים֙ אֲשֶׁ֣ר עַל הָ/אֵ֔שׁ אֲשֶׁ֖ר עַל הַ/מִּזְבֵּֽחַ", "en": {"kjv": "And the priests, Aaron’s sons, shall lay the parts, the head, and the fat, in order upon the wood that is on the fire which is upon the altar:", "web": "and Aaron’s sons, the priests, shall lay the pieces, the head, and the fat in order on the wood that is on the fire which is on the altar;", "bsb": "Then Aaron’s sons the priests are to arrange the pieces, including the head and the fat, atop the burning wood on the altar.", "asv": "and Aaron’s sons, the priests, shall lay the pieces, the head, and the fat, in order upon the wood that is on the fire which is upon the altar:", "ylt": "and sons of Aaron, the priests, have arranged the pieces, with the head and the fat, on the wood, which is on the fire, which is on the altar;", "tyndale": "and let them laye the peces with the heed and the fatte, apon the wod that is on the fire in the alter.", "dra": "And they shall lay the parts that are cut out in order thereupon: to wit, the head, and all things that cleave to the liver;", "bbe": "And Aaron's sons, the priests, are to put the parts, the head and the fat, in order on the wood which is on the fire on the altar:", "geneva": "Then the Priestes Aarons sonnes shall lay the parts in order, the head and the kall vpon the wood that is in the fire which is vpon the altar.", "wycliffe": "`the trees tho thingis that ben kit, that is, the heed, and alle thingis that cleuen to the mawe,", "rotherham": "And the sons of Aaron, the priests, shall arrange the pieces, the head and the fat,—upon the wood, that is on the fire, that is on the altar.", "darby": "and Aaron's sons, the priests, shall lay the pieces, the head, and the fat, in order on the wood that is on the fire which is on the altar;", "twenty": "", "jps": "And Aaron's sons, the priests, shall lay the pieces, and the head, and the suet, in order upon the wood that is on the fire which is upon the altar;", "acv": "And Aaron's sons, the priests, shall lay the pieces, the head, and the fat, in order upon the wood that is on the fire which is upon the altar,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priests, Aaron's sons, shall lay the parts, the head, and the fat, in order upon the wood that [is] on the fire which [is] upon the altar.", "vulgate": "et membra quae caesa sunt desuper ordinantes caput videlicet et cuncta quae adherent iecori;", "brenton": "And the sons of Aaron the priests shall pile up the divided parts, and the head, and the fat on the wood on the fire, the wood which is on the altar."}}, {"v": 9, "ref": "1:9", "o": "וְ/קִרְבּ֥/וֹ וּ/כְרָעָ֖י/ו יִרְחַ֣ץ בַּ/מָּ֑יִם וְ/הִקְטִ֨יר הַ/כֹּהֵ֤ן אֶת הַ/כֹּל֙ הַ/מִּזְבֵּ֔חָ/ה עֹלָ֛ה אִשֵּׁ֥ה רֵֽיחַ נִיח֖וֹחַ לַֽ/יהוָֽה", "en": {"kjv": "But his inwards and his legs shall he wash in water: and the priest shall burn all on the altar, to be a burnt sacrifice, an offering made by fire, of a sweet savour unto the Lord.", "web": "but its innards and its legs he shall wash with water. The priest shall burn all of it on the altar, for a burnt offering, an offering made by fire, of a pleasant aroma to Yahweh.", "bsb": "The entrails and legs must be washed with water, and the priest shall burn all of it on the altar as a burnt offering, an offering made by fire, a pleasing aroma to the LORD.", "asv": "but its inwards and its legs shall he wash with water. And the priest shall burn the whole on the altar, for a burnt-offering, an offering made by fire, of a sweet savor unto Jehovah.", "ylt": "and its inwards and its legs he doth wash with water; and the priest hath made perfume with the whole on the altar, a burnt-offering, a fire-offering of sweet fragrance to Jehovah.", "tyndale": "But the inwardes ad the legges they shall wash in water, and the preast shall burne altogither apon the alter, that it be a burntsacrifice, and an offerynge of a swete odoure vnto the Lorde.", "dra": "The entrails and feet being washed with water. And the priest shall burn them upon the altar for a holocaust, and a sweet savour to the Lord.", "bbe": "But its inside parts and its legs are to be washed with water, and it will all be burned on the altar by the priest for a burned offering, an offering made by fire, for a sweet smell to the Lord.", "geneva": "But the inwardes thereof and the legges thereof he shall wash in water, and the Priest shall burne all on the altar: for it is a burnt offering, an oblation made by fire, for a sweete sauour vnto the Lord.", "wycliffe": "whanne the entrailis and feet ben waischid with watir; and the preest schal brenne tho on the auter, in to brent sacrifice, and swete odour to the Lord.", "rotherham": "But its inwards and its legs, shall they bathe with water,—then shall the priest make, of the whole, a perfume at the altar, an ascending-sacrifice an altar-flame of a satisfying odour unto Yahweh.", "darby": "but its inwards and its legs shall he wash in water; and the priest shall burn all on the altar, a burnt-offering, an offering by fire to Jehovah of a sweet odour.", "twenty": "", "jps": "but its inwards and its legs shall he wash with water; and the priest shall make the whole smoke on the altar, for a burnt-offering, an offering made by fire, of a sweet savour unto HaShem.", "acv": "but its innards and its legs he shall wash with water. And the priest shall burn the whole on the altar, for a burnt offering, an offering made by fire, of a sweet savor to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "But his inwards and his legs shall he wash in water: and the priest shall burn all on the altar, [to be] a burnt-sacrifice, an offering made by fire, of a sweet savor to the LORD.", "vulgate": "intestinis et pedibus lotis aqua adolebitque ea sacerdos super altare in holocaustum et suavem odorem Domino;", "brenton": "And the entrails and the feet they shall wash in water, and the priests shall put all on the altar: it is a burnt-offering, a sacrifice, a smell of sweet savour to the Lord."}}, {"v": 10, "ref": "1:10", "o": "וְ/אִם מִן הַ/צֹּ֨אן קָרְבָּנ֧/וֹ מִן הַ/כְּשָׂבִ֛ים א֥וֹ מִן הָ/עִזִּ֖ים לְ/עֹלָ֑ה זָכָ֥ר תָּמִ֖ים יַקְרִיבֶֽ/נּוּ", "en": {"kjv": "And if his offering be of the flocks, namely, of the sheep, or of the goats, for a burnt sacrifice; he shall bring it a male without blemish.", "web": "“‘If his offering is from the flock, from the sheep, or from the goats, for a burnt offering, he shall offer a male without defect.", "bsb": "If, however, one’s offering is a burnt offering from the flock—from the sheep or goats—he is to present an unblemished male.", "asv": "And if his oblation be of the flock, of the sheep, or of the goats, for a burnt-offering; he shall offer it a male without blemish.", "ylt": "`And if his offering is out of the flock--out of the sheep or out of the goats--for a burnt-offering, a male, a perfect one, he doth bring near,", "tyndale": "Yf he will offer a burntsacrifice of the shepe whether it be of the lambes or of the gootes: he shall offer a male without blimesh.", "dra": "And if the offering be of the flocks, a holocaust of sheep or of goats, he shall offer a male without blemish.", "bbe": "And if his offering is of the flock, a burned offering of sheep or goats, let him give a male without a mark.", "geneva": "And if his sacrifice for the burnt offering be of the flocks (as of the sheepe, or of the goats) he shall offer a male without blemish,", "wycliffe": "That if the offryng is of litle beestis, a brent sacrifice of scheep, ethir of geet, he schal offre a male beeste with out wem,", "rotherham": "But, if of the flock, be his oblation,—of the sheep or of the goats, for an ascending-sacrifice, a male without defect, shall he bring near.", "darby": "And if his offering be of the flock, of the sheep or of the goats, for a burnt-offering, he shall present it a male without blemish.", "twenty": "", "jps": "And if his offering be of the flock, whether of the sheep, or of the goats, for a burnt-offering, he shall offer it a male without blemish.", "acv": "And if his oblation be of the flock, of the sheep, or of the goats, for a burnt offering, he shall offer it a male without blemish.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if his offering [be] of the flocks, [namely], of the sheep, or of the goats, for a burnt-sacrifice; he shall bring it a male without blemish.", "vulgate": "quod si de pecoribus oblatio est de ovibus sive de capris holocaustum anniculum et absque macula offeret;", "brenton": "And if his gift be of the sheep to the Lord, or of the lambs, or of the kids for whole-burnt-offerings, he shall bring it a male without blemish."}}, {"v": 11, "ref": "1:11", "o": "וְ/שָׁחַ֨ט אֹת֜/וֹ עַ֣ל יֶ֧רֶךְ הַ/מִּזְבֵּ֛חַ צָפֹ֖נָ/ה לִ/פְנֵ֣י יְהוָ֑ה וְ/זָרְק֡וּ בְּנֵי֩ אַהֲרֹ֨ן הַ/כֹּהֲנִ֧ים אֶת דָּמ֛/וֹ עַל הַ/מִּזְבֵּ֖חַ סָבִֽיב", "en": {"kjv": "And he shall kill it on the side of the altar northward before the Lord: and the priests, Aaron’s sons, shall sprinkle his blood round about upon the altar.", "web": "He shall kill it on the north side of the altar before Yahweh. Aaron’s sons, the priests, shall sprinkle its blood around on the altar.", "bsb": "He shall slaughter it on the north side of the altar before the LORD, and Aaron’s sons the priests are to sprinkle its blood against the altar on all sides.", "asv": "And he shall kill it on the side of the altar northward before Jehovah: and Aaron’s sons, the priests, shall sprinkle its blood upon the altar round about.", "ylt": "and he hath slaughtered it by the side of the altar northward, before Jehovah; and sons of Aaron, the priests, have sprinkled its blood on the altar round about;", "tyndale": "And let him kyll it on the north syde of the alter, before the Lorde. And let the preastes Aarons sonnes sprinkle the bloude of it, rounde aboute apon the alter.", "dra": "And he shall immolate it at the side of the altar that looketh to the north, before the Lord: but the sons of Aaron shall pour the blood thereof upon the altar round about.", "bbe": "And he is to put it to death on the north side of the altar before the Lord: and Aaron's sons, the priests, are to put some of the blood on and round the altar.", "geneva": "And he shall kill it on the Northside of the altar before the Lord, and the Priestes Aarons sonnes shall sprinckle the blood thereof rounde about vpon the altar.", "wycliffe": "and he schal offre at the side of the auter that biholdith to the north, bifore the Lord. Sotheli the sones of Aaron schulen schede the blood therof on the auter `bi cumpas,", "rotherham": "And he shall slay it on the side of the altar northward, before Yahweh,—and the sons of Aaron the priests shall dash its blood against the altar round about.", "darby": "And he shall slaughter it on the side of the altar northward before Jehovah; and Aaron's sons, the priests, shall sprinkle its blood on the altar round about.", "twenty": "", "jps": "And he shall kill it on the side of the altar northward before HaShem; and Aaron's sons, the priests, shall dash its blood against the altar round about.", "acv": "And he shall kill it on the side of the altar northward before Jehovah, and Aaron's sons, the priests, shall sprinkle its blood upon the altar round about.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall kill it on the side of the altar northward before the LORD: and the priests, Aaron's sons, shall sprinkle his blood around upon the altar:", "vulgate": "immolabitque ad latus altaris quod respicit ad aquilonem coram Domino sanguinem vero illius fundent super altare filii Aaron per circuitum;", "brenton": "And he shall lay his hand on its head; and they shall kill it by the side of the altar, toward the north before the Lord, and the sons of Aaron the priests shall pour its blood on the altar round about."}}, {"v": 12, "ref": "1:12", "o": "וְ/נִתַּ֤ח אֹת/וֹ֙ לִ/נְתָחָ֔י/ו וְ/אֶת רֹאשׁ֖/וֹ וְ/אֶת פִּדְר֑/וֹ וְ/עָרַ֤ךְ הַ/כֹּהֵן֙ אֹתָ֔/ם עַל הָֽ/עֵצִים֙ אֲשֶׁ֣ר עַל הָ/אֵ֔שׁ אֲשֶׁ֖ר עַל הַ/מִּזְבֵּֽחַ", "en": {"kjv": "And he shall cut it into his pieces, with his head and his fat: and the priest shall lay them in order on the wood that is on the fire which is upon the altar:", "web": "He shall cut it into its pieces, with its head and its fat. The priest shall lay them in order on the wood that is on the fire which is on the altar,", "bsb": "He is to cut the animal into pieces, and the priest shall arrange them, including the head and fat, atop the burning wood that is on the altar.", "asv": "And he shall cut it into its pieces, with its head and its fat; and the priest shall lay them in order on the wood that is on the fire which is upon the altar:", "ylt": "and he hath cut it into its pieces, and its head and its fat, and the priest hath arranged them on the wood, which is on the fire, which is on the altar;", "tyndale": "And let it be cut in peces: euen with his heed and his fatte, and let the preast putte them apon the wodd that lyeth apon the fire in the alter.", "dra": "And they shall divide the joints, the head, and all that cleave to the liver: and shall lay them upon the wood, under which the fire is to be put.", "bbe": "And the offering is to be cut into its parts, with its head and its fat; and the priest is to put them in order on the wood which is on the fire on the altar:", "geneva": "And he shall cut it in pieces, separating his head and his kall, and the Priest shall lay them in order vpon the wood that lyeth in the fire which is on the altar:", "wycliffe": "and thei schulen departe the membris, the heed, and alle thingis that cleuen to the mawe, and thei schulen putte on the trees, vndur whiche the fier schal be set;", "rotherham": "And he shall cut it up into its pieces, and its head, and its fat,—and the priest shall arrange them upon the wood that is on the fire, that is on the altar,", "darby": "And he shall cut it into its pieces, and its head, and its fat; and the priest shall lay them in order on the wood that is on the fire which is on the altar;", "twenty": "", "jps": "And he shall cut it into its pieces; and the priest shall lay them, with its head and its suet, in order on the wood that is on the fire which is upon the altar.", "acv": "And he shall cut it into its pieces, with its head and its fat, and the priest shall lay them in order on the wood that is on the fire which is upon the altar,", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall cut it into its pieces, with its head and its fat: and the priest shall lay them in order on the wood that [is] on the fire which [is] upon the altar:", "vulgate": "dividentque membra caput et omnia quae adherent iecori et inponent super ligna quibus subiciendus est ignis;", "brenton": "And they shall divide it by its limbs, and its head and its fat, and the priests shall pile them up on the wood which is on the fire, on the altar."}}, {"v": 13, "ref": "1:13", "o": "וְ/הַ/קֶּ֥רֶב וְ/הַ/כְּרָעַ֖יִם יִרְחַ֣ץ בַּ/מָּ֑יִם וְ/הִקְרִ֨יב הַ/כֹּהֵ֤ן אֶת הַ/כֹּל֙ וְ/הִקְטִ֣יר הַ/מִּזְבֵּ֔חָ/ה עֹלָ֣ה ה֗וּא אִשֵּׁ֛ה רֵ֥יחַ נִיחֹ֖חַ לַ/יהוָֽה", "en": {"kjv": "But he shall wash the inwards and the legs with water: and the priest shall bring it all, and burn it upon the altar: it is a burnt sacrifice, an offering made by fire, of a sweet savour unto the Lord.", "web": "but the innards and the legs he shall wash with water. The priest shall offer the whole, and burn it on the altar. It is a burnt offering, an offering made by fire, of a pleasant aroma to Yahweh.", "bsb": "The entrails and legs must be washed with water, and the priest shall bring all of it and burn it on the altar; it is a burnt offering, an offering made by fire, a pleasing aroma to the LORD.", "asv": "but the inwards and the legs shall he wash with water. And the priest shall offer the whole, and burn it upon the altar: it is a burnt-offering, an offering made by fire, of a sweet savor unto Jehovah.", "ylt": "and the inwards and the legs he doth wash with water, and the priest hath brought the whole near, and hath made perfume on the altar; it is a burnt-offering, a fire-offering of sweet fragrance to Jehovah.", "tyndale": "But let him wash the inwardes and the legges with water, and than bringe altogether and burne it apon the alter: that is a burntoffrynge and a sacrifice of swete sauoure vnto the Lorde.", "dra": "But the entrails and the feet they shall wash with water. And the priest shall offer it all and burn it all upon the altar for a holocaust, and most sweet savour to the Lord.", "bbe": "But the inside parts and the legs are to be washed with water; and the priest will make an offering of all of it, burning it on the altar: it is a burned offering, an offering made by fire, for a sweet smell to the Lord.", "geneva": "But he shall wash the inwardes, and the legges with water, and the Priest shall offer the whole and burne it vpon the altar: for it is a burnt offering, an oblation made by fire for a sweete sauour vnto the Lord.", "wycliffe": "sotheli thei schulen waische in watir the entrailis and feet; and the preest schal brenne alle thingis offrid on the auter, in to brent sacrifice, and swettest odour to the Lord.", "rotherham": "But the inwards and the legs, shall he bathe in water,—then shall the priest bring near the whole and make a perfume at the altar, an ascending-sacrifice, it is an altar-flame of a satisfying odour, unto Yahweh.", "darby": "but the inwards and the legs shall he wash with water; and the priest shall present [it] all, and burn [it] on the altar: it is a burnt-offering, an offering by fire to Jehovah of a sweet odour.", "twenty": "", "jps": "But the inwards and the legs shall he wash with water; and the priest shall offer the whole, and make it smoke upon the altar; it is a burnt-offering, an offering made by fire, of a sweet savour unto HaShem.", "acv": "but the innards and the legs he shall wash with water. And the priest shall offer the whole, and burn it upon the altar. It is a burnt offering, an offering made by fire, of a sweet savor to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "But he shall wash the inwards and the legs with water: and the priest shall bring [it] all, and burn [it] upon the altar: it [is] a burnt sacrifice, an offering made by fire, of a sweet savor to the LORD.", "vulgate": "intestina vero et pedes lavabunt aqua et oblata omnia adolebit sacerdos super altare in holocaustum et odorem suavissimum Domino;", "brenton": "And they shall wash the entrails and the feet with water, and the priest shall bring all the parts and put them on the altar: it is a burnt-offering, a sacrifice, a smell of sweet savour to the Lord."}}, {"v": 14, "ref": "1:14", "o": "וְ/אִ֧ם מִן הָ/ע֛וֹף עֹלָ֥ה קָרְבָּנ֖/וֹ לַֽ/יהוָ֑ה וְ/הִקְרִ֣יב מִן הַ/תֹּרִ֗ים א֛וֹ מִן בְּנֵ֥י הַ/יּוֹנָ֖ה אֶת קָרְבָּנֽ/וֹ", "en": {"kjv": "And if the burnt sacrifice for his offering to the Lord be of fowls, then he shall bring his offering of turtledoves, or of young pigeons.", "web": "“‘If his offering to Yahweh is a burnt offering of birds, then he shall offer his offering of turtledoves, or of young pigeons.", "bsb": "If, instead, one’s offering to the LORD is a burnt offering of birds, he is to present a turtledove or a young pigeon.", "asv": "And if his oblation to Jehovah be a burnt-offering of birds, then he shall offer his oblation of turtle-doves, or of young pigeons.", "ylt": "`And if his offering is a burnt-offering out of the fowl to Jehovah, than he hath brought near his offering out of the turtle-doves or out of the young pigeons,", "tyndale": "Yf he will offer a burntoffrynge of the foules he shall offer eyther of the turtyll doues or of the ionge pigeons.", "dra": "But if the oblation of a holocaust to the Lord be of birds, of turtles, or of young pigeons:", "bbe": "And if his offering to the Lord is a burned offering of birds, then he is to make his offering of doves or of young pigeons.", "geneva": "And if his sacrifice be a burnt offring to the Lord of ye foules, then he shall offer his sacrifice of the turtle doues, or of the yong pigeons.", "wycliffe": "Forsothe if the offryng of brent sacrifice to the Lord is of briddis, of turtlis, and of culuer briddis,", "rotherham": "But, if, of birds, be the ascending-sacrifice of his oblation unto Yahweh, then shall he bring near of the turtle-doves or of the young pigeons, his oblation.", "darby": "And if his offering to Jehovah be a burnt-offering of fowls, then he shall present his offering of turtle-doves, or of young pigeons.", "twenty": "", "jps": "And if his offering to HaShem be a burnt-offering of fowls, then he shall bring his offering of turtle-doves, or of young pigeons.", "acv": "And if his oblation to Jehovah be a burnt offering of birds, then he shall offer his oblation of turtle-doves, or of young pigeons.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if the burnt sacrifice for his offering to the LORD shall [be] of fowls, then he shall bring his offering of turtle doves, or of young pigeons.", "vulgate": "sin autem de avibus holocausti oblatio fuerit Domino de turturibus et pullis columbae;", "brenton": "And if he bring his gift, a burnt-offering to the Lord, of birds, then shall he bring his gift of doves or pigeons."}}, {"v": 15, "ref": "1:15", "o": "וְ/הִקְרִיב֤/וֹ הַ/כֹּהֵן֙ אֶל הַ/מִּזְבֵּ֔חַ וּ/מָלַק֙ אֶת רֹאשׁ֔/וֹ וְ/הִקְטִ֖יר הַ/מִּזְבֵּ֑חָ/ה וְ/נִמְצָ֣ה דָמ֔/וֹ עַ֖ל קִ֥יר הַ/מִּזְבֵּֽחַ", "en": {"kjv": "And the priest shall bring it unto the altar, and wring off his head, and burn it on the altar; and the blood thereof shall be wrung out at the side of the altar:", "web": "The priest shall bring it to the altar, and wring off its head, and burn it on the altar; and its blood shall be drained out on the side of the altar;", "bsb": "Then the priest shall bring it to the altar, twist off its head, and burn it on the altar; its blood should be drained out on the side of the altar.", "asv": "And the priest shall bring it unto the altar, and wring off its head, and burn it on the altar; and the blood thereof shall be drained out on the side of the altar;", "ylt": "and the priest hath brought it near unto the altar, and hath wrung off its head, and hath made perfume on the altar, and its blood hath been wrung out by the side of the altar;", "tyndale": "And the preast shall brynge it vnto the alter, and wrynge the necke a sundre of it, and burne it on the alter, and let the bloude runne out apon the sydes of the alter,", "dra": "The priest shall offer it at the altar: and twisting back the neck, and breaking the place of the wound, he shall make the blood run down upon the brim of the altar.", "bbe": "And the priest is to take it to the altar, and after its head has been twisted off, it is to be burned on the altar, and its blood drained out on the side of the altar:", "geneva": "And the Priest shall bring it vnto the altar, and wring the necke of it asunder, and burne it on the altar: and the blood thereof shall bee shed vpon the side of the altar.", "wycliffe": "the preest schal offre it at the auter; and whanne the heed is writhun to the necke, and the place of the wounde is brokun, he schal make the blood renne doun on the brenke of the auter.", "rotherham": "And the priest shall bring it near unto the altar shall nip off its head, and make a perfume at the altar,—and its blood shall be drained out upon the wall of the altar.", "darby": "And the priest shall bring it near to the altar and pinch off its head and burn it on the altar; and its blood shall be pressed out at the side of the altar.", "twenty": "", "jps": "And the priest shall bring it unto the altar, and pinch off its head, and make it smoke on the altar; and the blood thereof shall be drained out on the side of the altar.", "acv": "And the priest shall bring it to the altar, and wring off its head, and burn it on the altar. And the blood of it shall be drained out on the side of the altar.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall bring it to the altar, and wring off its head, and burn [it] on the altar: and its blood shall be wrung out at the side of the altar:", "vulgate": "offeret eam sacerdos ad altare et retorto ad collum capite ac rupto vulneris loco decurrere faciet sanguinem super crepidinem altaris;", "brenton": "And the priest shall bring it to the altar, and shall wring off its head; and the priest shall put it on the altar, and shall wring out the blood at the bottom of the altar."}}, {"v": 16, "ref": "1:16", "o": "וְ/הֵסִ֥יר אֶת מֻרְאָת֖/וֹ בְּ/נֹצָתָ֑/הּ וְ/הִשְׁלִ֨יךְ אֹתָ֜/הּ אֵ֤צֶל הַ/מִּזְבֵּ֨חַ֙ קֵ֔דְמָ/ה אֶל מְק֖וֹם הַ/דָּֽשֶׁן", "en": {"kjv": "And he shall pluck away his crop with his feathers, and cast it beside the altar on the east part, by the place of the ashes:", "web": "and he shall take away its crop with its filth, and cast it beside the altar on the east part, in the place of the ashes.", "bsb": "And he is to remove the crop with its contents and throw it to the east side of the altar, in the place for ashes.", "asv": "and he shall take away its crop with the filth thereof, and cast it beside the altar on the east part, in the place of the ashes:", "ylt": "and he hath turned aside its crop with its feathers, and hath cast it near the altar, eastward, unto the place of ashes;", "tyndale": "ad plucke awaye his croppe ad his fethers, ad cast the besyde the alter on the east parte vppo the hepe of asshes,", "dra": "But the crop of the throat, and the feathers he shall cast beside the altar at the east side, in the place where the ashes are wont to be poured out.", "bbe": "And he is to take away its stomach, with its feathers, and put it down by the east side of the altar, where the burned waste is put:", "geneva": "And he shall plucke out his maw with his fethers, and cast them beside the altar on the East part in the place of the ashes.", "wycliffe": "Sotheli he schal caste forth the litil bladdir of the throte, and fetheris bisidis the auter, at the eest coost, in the place in which the aischis ben wont to be sched out;", "rotherham": "Then shall he take away its crop with its plumage,—and cast it beside the altar, eastward, into the place of fat ashes;", "darby": "And he shall remove its crop with its feathers, and cast it beside the altar on the east, into the place of the ashes;", "twenty": "", "jps": "And he shall take away its crop with the feathers thereof, and cast it beside the altar on the east part, in the place of the ashes.", "acv": "And he shall take away its crop with the filth of it, and cast it beside the altar on the east part, in the place of the ashes.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall pluck away its crop with its feathers, and cast it beside the altar on the east part, by the place of the ashes:", "vulgate": "vesiculam vero gutturis et plumas proiciet propter altare ad orientalem plagam in loco in quo cineres effundi solent;", "brenton": "And he shall take away the crop with the feathers, and shall cast it forth by the altar toward the east to the place of the ashes."}}, {"v": 17, "ref": "1:17", "o": "וְ/שִׁסַּ֨ע אֹת֣/וֹ בִ/כְנָפָי/ו֮ לֹ֣א יַבְדִּיל֒ וְ/הִקְטִ֨יר אֹת֤/וֹ הַ/כֹּהֵן֙ הַ/מִּזְבֵּ֔חָ/ה עַל הָ/עֵצִ֖ים אֲשֶׁ֣ר עַל הָ/אֵ֑שׁ עֹלָ֣ה ה֗וּא אִשֵּׁ֛ה רֵ֥יחַ נִיחֹ֖חַ לַ/יהוָֽה", "en": {"kjv": "And he shall cleave it with the wings thereof, but shall not divide it asunder: and the priest shall burn it upon the altar, upon the wood that is upon the fire: it is a burnt sacrifice, an offering made by fire, of a sweet savour unto the Lord.", "web": "He shall tear it by its wings, but shall not divide it apart. The priest shall burn it on the altar, on the wood that is on the fire. It is a burnt offering, an offering made by fire, of a pleasant aroma to Yahweh.", "bsb": "He shall tear it open by its wings, without dividing the bird completely. And the priest is to burn it on the altar atop the burning wood. It is a burnt offering, an offering made by fire, a pleasing aroma to the LORD.", "asv": "and he shall rend it by the wings thereof, but shall not divide it asunder. And the priest shall burn it upon the altar, upon the wood that is upon the fire: it is a burnt-offering, an offering made by fire, of a sweet savor unto Jehovah.", "ylt": "and he hath cleaved it with its wings (he doth not separate it ), and the priest hath made it a perfume on the altar, on the wood, which is on the fire; it is a burnt-offering, a fire-offering of sweet fragrance to Jehovah.", "tyndale": "ad breke his winges but plucke the not a sundre. And the let the preast burne it vpo the alter, eue apo the wodd that lyeth apo the fire, a burntsacrifice ad an offerynge of a swete sauoure vnto the Lorde.", "dra": "And he shall break the pinions thereof, and shall not cut, nor divide it with a knife: and shall burn it upon the altar, putting fire under the wood. It is a holocaust and oblation of most sweet savour to the Lord.", "bbe": "And let it be broken open at the wings, but not cut in two; and let it be burned on the altar by the priest on the wood which is on the fire; it is a burned offering; an offering made by fire for a sweet smell to the Lord.", "geneva": "And he shall cleaue it with his wings, but not deuide it asunder: and the Priest shall burne it vpon the altar vpon the wood that is in the fire: for it is a burnt offering, an oblation made by fire for a sweete sauour vnto the Lord.", "wycliffe": "and he schal breke the wyngis therof, and he schal not kerue, nether he schal departe it with yrun; and he schal brenne it on the auter, whanne fier is set vndur the trees; it is a brent sacrifice, and an offryng of swete odour to the Lord.", "rotherham": "and he shall cleave it in its wings—he shall not divide it asunder, so shall the priest make a perfume therewith, at the altar, upon the wood that is on the fire,—an ascending-sacrifice, it is, an altar-flame of a satisfying odour, unto Yahweh.", "darby": "and he shall split it open at its wings, [but] shall not divide [it] asunder; and the priest shall burn it on the altar on the wood that is on the fire: it is a burnt-offering, an offering by fire to Jehovah of a sweet odour.", "twenty": "", "jps": "And he shall rend it by the wings thereof, but shall not divide it asunder; and the priest shall make it smoke upon the altar, upon the wood that is upon the fire; it is a burnt-offering, an offering made by fire, of a sweet savour unto HaShem.", "acv": "And he shall rend it by the wings of it, but shall not divide it apart, and the priest shall burn it upon the altar, upon the wood that is upon the fire. It is a burnt offering, an offering made by fire, of a sweet savor to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall cleave it with its wings, [but] shall not divide [it] asunder: and the priest shall burn it upon the altar, upon the wood that [is] upon the fire: it [is] a burnt sacrifice, an offering made by fire, of a sweet savor to the LORD.", "vulgate": "confringetque ascellas eius et non secabit nec ferro dividet eam et adolebit super altare lignis igne subposito holocaustum est et oblatio suavissimi odoris Domino;", "brenton": "And he shall break it off from the wings and shall not separate it, and the priest shall put it on the altar on the wood which is on the fire: it is a burnt-offering, a sacrifice, a sweet-smelling savour to the Lord."}}]}, {"c": 2, "verses": [{"v": 1, "ref": "2:1", "o": "וְ/נֶ֗פֶשׁ כִּֽי תַקְרִ֞יב קָרְבַּ֤ן מִנְחָה֙ לַֽ/יהוָ֔ה סֹ֖לֶת יִהְיֶ֣ה קָרְבָּנ֑/וֹ וְ/יָצַ֤ק עָלֶ֨י/הָ֙ שֶׁ֔מֶן וְ/נָתַ֥ן עָלֶ֖י/הָ לְבֹנָֽה", "en": {"kjv": "And when any will offer a meat offering unto the Lord, his offering shall be of fine flour; and he shall pour oil upon it, and put frankincense thereon:", "web": "“‘When anyone offers an offering of a meal offering to Yahweh, his offering shall be of fine flour; and he shall pour oil on it, and put frankincense on it.", "bsb": "“When anyone brings a grain offering to the LORD, his offering must consist of fine flour. He is to pour olive oil on it, put frankincense on it,", "asv": "And when any one offereth an oblation of a meal-offering unto Jehovah, his oblation shall be of fine flour; and he shall pour oil upon it, and put frankincense thereon:", "ylt": "`And when a person bringeth near an offering, a present to Jehovah, of flour is his offering, and he hath poured on it oil, and hath put on it frankincense;", "tyndale": "Yf any soule will offer a meatoffrynge vnto the Lorde, his offerynge shalbe fine floure, and he shall poure thereto oyle ad put frankencens theron", "dra": "When any one shall offer an oblation of sacrifice to the Lord, his offering shall be of fine flour: and he shall pour oil upon it, and put frankincense,", "bbe": "And when anyone makes a meal offering to the Lord, let his offering be of the best meal, with oil on it and perfume:", "geneva": "And when any will offer a meate offering vnto the Lord, his offering shall be of fine floure, and he shall powre oyle vpon it, and put incense thereon,", "wycliffe": "Whanne a soule offrith an offryng of sacrifice to the Lord, flour of wheete schal be his offring. And he schal schede oile ther onne,", "rotherham": "But, when any person would bring near as an oblation, a meal-offering, unto Yahweh, of fine meal, shall be his oblation,—and he shall pour out thereon oil, and place thereon, frankincense;", "darby": "And when any one will present an oblation to Jehovah, his offering shall be of fine flour; and he shall pour oil on it, and put frankincense thereon.", "twenty": "", "jps": "And when any one bringeth a meal-offering unto HaShem, his offering shall be of fine flour; and he shall pour oil upon it, and put frankincense thereon.", "acv": "And when anyone offers an oblation of a meal offering to Jehovah, his oblation shall be of fine flour, and he shall pour oil upon it, and put frankincense on it.", "anderson": "", "haweis": "", "noyes": "", "webster": "And when any will offer a meat-offering to the LORD, his offering shall be [of] fine flour; and he shall pour oil upon it, and put frankincense upon it.", "vulgate": "anima cum obtulerit oblationem sacrificii Domino simila erit eius oblatio fundetque super eam oleum et ponet tus;", "brenton": "And if a soul bring a gift, a sacrifice to the Lord, his gift shall be fine flour; and he shall pour oil upon it, and shall put frankincense on it: it is a sacrifice."}}, {"v": 2, "ref": "2:2", "o": "וֶֽ/הֱבִיאָ֗/הּ אֶל בְּנֵ֣י אַהֲרֹן֮ הַ/כֹּהֲנִים֒ וְ/קָמַ֨ץ מִ/שָּׁ֜ם מְלֹ֣א קֻמְצ֗/וֹ מִ/סָּלְתָּ/הּ֙ וּ/מִ/שַּׁמְנָ֔/הּ עַ֖ל כָּל לְבֹנָתָ֑/הּ וְ/הִקְטִ֨יר הַ/כֹּהֵ֜ן אֶת אַזְכָּרָתָ/הּ֙ הַ/מִּזְבֵּ֔חָ/ה אִשֵּׁ֛ה רֵ֥יחַ נִיחֹ֖חַ לַ/יהוָֽה", "en": {"kjv": "And he shall bring it to Aaron’s sons the priests: and he shall take thereout his handful of the flour thereof, and of the oil thereof, with all the frankincense thereof; and the priest shall burn the memorial of it upon the altar, to be an offering made by fire, of a sweet savour unto the Lord:", "web": "He shall bring it to Aaron’s sons, the priests; and he shall take his handful of its fine flour, and of its oil, with all its frankincense; and the priest shall burn its memorial on the altar, an offering made by fire, of a pleasant aroma to Yahweh.", "bsb": "and bring it to Aaron’s sons the priests. The priest shall take a handful of the flour and oil, together with all the frankincense, and burn this as a memorial portion on the altar, an offering made by fire, a pleasing aroma to the LORD.", "asv": "and he shall bring it to Aaron’s sons the priests; and he shall take thereout his handful of the fine flour thereof, and of the oil thereof, with all the frankincense thereof. And the priest shall burn it as the memorial thereof upon the altar, an offering made by fire, of a sweet savor unto Jehovah:", "ylt": "and he hath brought it in unto the sons of Aaron, the priests, and he hath taken from thence the fulness of his hand of its flour and of its oil, besides all its frankincense, and the priest hath made perfume with its memorial on the altar, a fire-offering of sweet fragrance to Jehovah;", "tyndale": "and shall bringe it vnto Aarons sonnes the preastes. And one of them shall take thereout his handfull of the floure, and of the oyle with all the frankences, ad burne it for a memoriall apo the alter: an offryng of a swete sauoure vnto the Lord.", "dra": "And shall bring it to the sons of Aaron the priests. And one of them shall take a handful of the flour and oil, and all the frankincense; and shall put it a memorial upon the altar for a most sweet savour to the Lord.", "bbe": "And let him take it to Aaron's sons, the priests; and having taken in his hand some of the meal and of the oil, with all the perfume, let him give it to the priest to be burned on the altar, as a sign, an offering made by fire, for a sweet smell to the Lord.", "geneva": "And shall bring it vnto Aarons sonnes the Priestes, and he shall take thence his handfull of the flowre, and of the oyle with al the incense, and the Priest shall burne it for a memoriall vpon the altar: for it is an offering made by fire for a sweete sauour vnto the Lord.", "wycliffe": "and he schal putte encense, and he schal bere to the sones of Aaron, preest, of whiche sones oon schal take an handful of `flour of whete, and of oile, and alle the encense; and he schal putte a memorial on the auter, in to swettest odour to the Lord.", "rotherham": "so shall he bring it in unto the sons of Aaron, the priests, and he shall grasp therefrom a handful of the fine meal thereof and of the oil thereof, besides all the frankincense thereof,—and the priest shall make a perfume with the memorial thereof at the altar, an altar-flame of a satisfying odour unto Yahweh.", "darby": "And he shall bring it to Aaron's sons, the priests; and he shall take thereout his handful of the flour thereof, and of the oil thereof, with all the frankincense thereof; and the priest shall burn the memorial thereof on the altar, an offering by fire to Jehovah of a sweet odour.", "twenty": "", "jps": "And he shall bring it to Aaron's sons the priests; and he shall take thereout his handful of the fine flour thereof, and of the oil thereof, together with all the frankincense thereof; and the priest shall make the memorial-part thereof smoke upon the altar, an offering made by fire, of a sweet savour unto HaShem.", "acv": "And he shall bring it to Aaron's sons the priests, and he shall take out of it his handful of the fine flour of it, and of the oil of it, with all the frankincense of it. And the priest shall burn the memorial of it upon the altar, an offering made by fire, of a sweet savor to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall bring it to Aaron's sons the priests: and he shall take out of it his handful of its flour, and of its oil, with all its frankincense; and the priest shall burn the memorial of it upon the altar, [to be] an offering made by fire, of a sweet savor to the LORD:", "vulgate": "ac deferet ad filios Aaron sacerdotes quorum unus tollet pugillum plenum similae et olei ac totum tus et ponet memoriale super altare in odorem suavissimum Domino;", "brenton": "And he shall bring it to the priests the sons of Aaron: and having taken from it a handful of the fine flour with the oil, and all its frankincense, then the priest shall put the memorial of it on the altar: it is a sacrifice, an odour of sweet savour to the Lord."}}, {"v": 3, "ref": "2:3", "o": "וְ/הַ/נּוֹתֶ֨רֶת֙ מִן הַ/מִּנְחָ֔ה לְ/אַהֲרֹ֖ן וּ/לְ/בָנָ֑י/ו קֹ֥דֶשׁ קָֽדָשִׁ֖ים מֵ/אִשֵּׁ֥י יְהוָֽה", "en": {"kjv": "And the remnant of the meat offering shall be Aaron’s and his sons’: it is a thing most holy of the offerings of the Lord made by fire.", "web": "That which is left of the meal offering shall be Aaron’s and his sons’. It is a most holy thing of the offerings of Yahweh made by fire.", "bsb": "The remainder of the grain offering shall belong to Aaron and his sons; it is a most holy part of the offerings made by fire to the LORD.", "asv": "and that which is left of the meal-offering shall be Aaron’s and his sons’: it is a thing most holy of the offerings of Jehovah made by fire.", "ylt": "and the remnant of the present is for Aaron and for his sons, most holy, of the fire-offerings of Jehovah.", "tyndale": "And the renaunt of the meatofferynge shalbe Aarons ad his sonnes, as a thinge most holye of the sacrifices of the Lorde.", "dra": "And the remnant of the sacrifice shall be Aaron's, and his sons', holy of holies of the offerings of the Lord.", "bbe": "And the rest of the meal offering will be for Aaron and his sons; it is most holy among the Lord's fire offerings.", "geneva": "But the remnant of the meate offering shalbe Aarons and his sonnes: for it is most holy of the Lordes offrings made by fire.", "wycliffe": "Forsothe that that `is residue of the sacrifice schal be Aarons and hise sones, the hooli of hooli thingis of offryngis to the Lord.", "rotherham": "But, the remainder of the meal-offering, pertaineth unto Aaron and unto his sons,—most holy, from among the altar-flames of Yahweh.", "darby": "And the remainder of the oblation shall be Aaron's and his sons': [it is] most holy of Jehovah's offerings by fire.", "twenty": "", "jps": "But that which is left of the meal-offering shall be Aaron's and his sons'; it is a thing most holy of the offerings of HaShem made by fire.", "acv": "And that which is left of the meal offering shall be Aaron's and his sons'. It is a thing most holy of the offerings of Jehovah made by fire.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the remnant of the meat-offering [shall be] Aaron's and his sons': [it is] a thing most holy of the offerings of the LORD made by fire.", "vulgate": "quod autem reliquum fuerit de sacrificio erit Aaron et filiorum eius sanctum sanctorum de oblationibus Domini;", "brenton": "And the remainder of the sacrifice shall be for Aaron and his sons, a most holy portion from the sacrifices of the Lord."}}, {"v": 4, "ref": "2:4", "o": "וְ/כִ֥י תַקְרִ֛ב קָרְבַּ֥ן מִנְחָ֖ה מַאֲפֵ֣ה תַנּ֑וּר סֹ֣לֶת חַלּ֤וֹת מַצֹּת֙ בְּלוּלֹ֣ת בַּ/שֶּׁ֔מֶן וּ/רְקִיקֵ֥י מַצּ֖וֹת מְשֻׁחִ֥ים בַּ/שָּֽׁמֶן", "en": {"kjv": "And if thou bring an oblation of a meat offering baken in the oven, it shall be unleavened cakes of fine flour mingled with oil, or unleavened wafers anointed with oil.", "web": "“‘When you offer an offering of a meal offering baked in the oven, it shall be unleavened cakes of fine flour mixed with oil, or unleavened wafers anointed with oil.", "bsb": "Now if you bring an offering of grain baked in an oven, it must consist of fine flour, either unleavened cakes mixed with oil or unleavened wafers coated with oil.", "asv": "And when thou offerest an oblation of a meal-offering baken in the oven, it shall be unleavened cakes of fine flour mingled with oil, or unleavened wafers anointed with oil.", "ylt": "`And when thou bringest near an offering, a present baked in an oven, it is of unleavened cakes of flour mixed with oil, or thin unleavened cakes anointed with oil.", "tyndale": "Yf any ma bringe a meatoffrynge that is bake in the oue, let him brynge swete cakes of fine floure mingled with oyle, ad vnleuended wafers anoynted with oyle.", "dra": "But when thou offerest a sacrifice baked in the oven of flour, to wit, loaves without leaven, tempered with oil, and unleavened wafers, anointed with oil:", "bbe": "And when you give a meal offering cooked in the oven, let it be of unleavened cakes of the best meal mixed with oil, or thin unleavened cakes covered with oil.", "geneva": "If thou bring also a meate offring baken in the ouen, it shalbe an vnleauened cake of fine floure mingled with oyle, or an vnleauened wafer anointed with oyle.", "wycliffe": "Forsothe whanne thou offrist a sacrifice bakun in an ouene of whete flour, that is, loouys without sour dow, spreynd with oile, and therf breed sodun in watir, bawmed with oile;", "rotherham": "Moreover, when thou wouldst bring near as an oblation of a meal-offering, something baked in an oven, round unleavened cakes of fine meal, overflowed with oil, [shall it be], or unleavened wafers anointed with oil.", "darby": "And if thou present an offering of an oblation baken in the oven, it shall be unleavened cakes of fine flour mingled with oil, or unleavened wafers anointed with oil.", "twenty": "", "jps": "And when thou bringest a meal-offering baked in the oven, it shall be unleavened cakes of fine flour mingled with oil, or unleavened wafers spread with oil.", "acv": "And when thou offer an oblation of a meal offering baked in the oven, it shall be unleavened cakes of fine flour mingled with oil, or unleavened wafers anointed with oil.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if thou shalt bring an oblation of a meat-offering baked in the oven, [it shall be] unleavened cakes of fine flour mingled with oil, or unleavened wafers anointed with oil.", "vulgate": "cum autem obtuleris sacrificium coctum in clibano de simila panes scilicet absque fermento conspersos oleo et lagana azyma oleo lita;", "brenton": "And if he bring as a gift a sacrifice baked from the oven, a gift to the Lord of fine flour, he shall bring unleavened bread kneaded with oil, and unleavened cakes anointed with oil."}}, {"v": 5, "ref": "2:5", "o": "וְ/אִם מִנְחָ֥ה עַל הַֽ/מַּחֲבַ֖ת קָרְבָּנֶ֑/ךָ סֹ֛לֶת בְּלוּלָ֥ה בַ/שֶּׁ֖מֶן מַצָּ֥ה תִהְיֶֽה", "en": {"kjv": "And if thy oblation be a meat offering baken in a pan, it shall be of fine flour unleavened, mingled with oil.", "web": "If your offering is a meal offering of the griddle, it shall be of unleavened fine flour, mixed with oil.", "bsb": "If your offering is a grain offering prepared on a griddle, it must be unleavened bread made of fine flour mixed with oil.", "asv": "And if thy oblation be a meal-offering of the baking-pan, it shall be of fine flour unleavened, mingled with oil.", "ylt": "`And if thine offering is a present made on the girdel, it is of flour, mixed with oil, unleavened;", "tyndale": "Yf thy meatoffrynge be baken in the fryenge pan, then it shalbe of swete floure mingled with oyle.", "dra": "If thy oblation be from the fryingpan, of flour tempered with oil, and without leaven:", "bbe": "And if you give a meal offering cooked on a flat plate, let it be of the best meal, unleavened and mixed with oil.", "geneva": "But if thy meate offring be an oblation of the frying pan, it shall be of fine flowre vnleauened, mingled with oyle.", "wycliffe": "if thin offryng is `of a friyng panne, of wheete flour spreynd with oile and without sour dow,", "rotherham": "But, if, a meal-offering, on a girdle, be thine oblation, of fine meal, overflowed with oil unleavened, shall it be;", "darby": "And if thine offering be an oblation [baken] on the pan, it shall be fine flour unleavened, mingled with oil.", "twenty": "", "jps": "And if thy offering be a meal-offering baked on a griddle, it shall be of fine flour unleavened, mingled with oil.", "acv": "And if thy oblation be a meal offering of the baking-pan, it shall be of fine flour unleavened, mingled with oil.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if thy oblation [shall be] a meat-offering [baked] in a pan, it shall be [of] fine flour unleavened, mingled with oil.", "vulgate": "si oblatio tua fuerit de sartagine similae conspersae oleo et absque fermento;", "brenton": "And if thy gift be a sacrifice from a pan, it is fine flour mingled with oil, unleavened offerings."}}, {"v": 6, "ref": "2:6", "o": "פָּת֤וֹת אֹתָ/הּ֙ פִּתִּ֔ים וְ/יָצַקְתָּ֥ עָלֶ֖י/הָ שָׁ֑מֶן מִנְחָ֖ה הִֽוא", "en": {"kjv": "Thou shalt part it in pieces, and pour oil thereon: it is a meat offering.", "web": "You shall cut it in pieces, and pour oil on it. It is a meal offering.", "bsb": "Crumble it and pour oil on it; it is a grain offering.", "asv": "Thou shalt part it in pieces, and pour oil thereon: it is a meal-offering.", "ylt": "divide thou it into parts, and thou hast poured on it oil; it is a present.", "tyndale": "And thou shalt mynce it small, ad poure oyle thereon: ad so is it a meatoffrynge.", "dra": "Thou shalt divide it into little pieces, and shalt pour oil upon it.", "bbe": "Let it be broken into bits, and put oil on it; it is a meal offering.", "geneva": "And thou shalt part it in pieces, and power oyle thereon: for it is a meate offring.", "wycliffe": "thou schalt departe it in smale partis, and thou schalt schede oile ther onne.", "rotherham": "parting it into pieces, then shalt thou pour thereon oil,—a meal-offering, it is,", "darby": "Thou shalt part it in pieces, and pour oil thereon: it is an oblation.", "twenty": "", "jps": "Thou shalt break it in pieces, and pour oil thereon; it is a meal-offering.", "acv": "Thou shall part it in pieces, and pour oil in it. It is a meal offering.", "anderson": "", "haweis": "", "noyes": "", "webster": "Thou shalt part it in pieces, and pour oil upon it: it [is] a meat-offering.", "vulgate": "divides eam minutatim et fundes supra oleum;", "brenton": "And thou shalt break them into fragments and pour oil upon them: it is a sacrifice to the Lord."}}, {"v": 7, "ref": "2:7", "o": "וְ/אִם מִנְחַ֥ת מַרְחֶ֖שֶׁת קָרְבָּנֶ֑/ךָ סֹ֥לֶת בַּ/שֶּׁ֖מֶן תֵּעָשֶֽׂה", "en": {"kjv": "And if thy oblation be a meat offering baken in the fryingpan, it shall be made of fine flour with oil.", "web": "If your offering is a meal offering of the pan, it shall be made of fine flour with oil.", "bsb": "If your offering is a grain offering cooked in a pan, it must consist of fine flour with oil.", "asv": "And if thy oblation be a meal-offering of the frying-pan, it shall be made of fine flour with oil.", "ylt": "`And if thine offering is a present made on the frying-pan, of flour with oil it is made,", "tyndale": "Yf thy meatofferynge be a thynge broyled vppon the greadyerne, of floure myngled with oyle it shalbe.", "dra": "And if the sacrifice be from the gridiron, in like manner the flour shall be tempered with oil.", "bbe": "And if your offering is of meal cooked in fat over the fire, let it be made of the best meal mixed with oil.", "geneva": "And if thy meate offring be an oblation made in the caldron, it shalbe made of fine floure with oyle.", "wycliffe": "Ellis if the sacrifice is of a gridele, euenli the whete flour schal be spreynd with oile;", "rotherham": "But, if a meal-offering of the boiler, be thine oblation, of fine meal with oil, shall it be made.", "darby": "And if thine offering be an oblation [prepared] in the cauldron, it shall be made of fine flour with oil.", "twenty": "", "jps": "And if thy offering be a meal-offering of the stewing-pan, it shall be made of fine flour with oil.", "acv": "And if thy oblation be a meal offering of the frying-pan, it shall be made of fine flour with oil.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if thy oblation [shall be] a meat-offering [baked] in the frying-pan, it shall be made [of] fine flour with oil.", "vulgate": "sin autem de craticula sacrificium aeque simila oleo conspergetur;", "brenton": "And if thy gift be a sacrifice from the hearth, it shall be made of fine flour with oil."}}, {"v": 8, "ref": "2:8", "o": "וְ/הֵבֵאתָ֣ אֶת הַ/מִּנְחָ֗ה אֲשֶׁ֧ר יֵעָשֶׂ֛ה מֵ/אֵ֖לֶּה לַ/יהוָ֑ה וְ/הִקְרִיבָ/הּ֙ אֶל הַ/כֹּהֵ֔ן וְ/הִגִּישָׁ֖/הּ אֶל הַ/מִּזְבֵּֽחַ", "en": {"kjv": "And thou shalt bring the meat offering that is made of these things unto the Lord: and when it is presented unto the priest, he shall bring it unto the altar.", "web": "You shall bring the meal offering that is made of these things to Yahweh: and it shall be presented to the priest, and he shall bring it to the altar.", "bsb": "When you bring to the LORD the grain offering made in any of these ways, it is to be presented to the priest, and he shall take it to the altar.", "asv": "And thou shalt bring the meal-offering that is made of these things unto Jehovah: and it shall be presented unto the priest, and he shall bring it unto the altar.", "ylt": "and thou hast brought in the present which is made of these to Jehovah, and one hath brought it near unto the priest, and he hath brought it nigh unto the altar,", "tyndale": "And thou shalt brynge the meatoffryng that is made of these thinges vnto the Lorde, and shalt delyuer it vnto the preast, and he shall brynge it vnto the altare", "dra": "And when thou offerest it to the Lord, thou shalt deliver it to the hands of the priest.", "bbe": "And you are to give the meal offering made of these things to the Lord, and let the priest take it to the altar.", "geneva": "After, thou shalt bring the meate offering (that is made of these things) vnto the Lord, and shalt present it vnto the Priest, and he shall bring it to the altar,", "wycliffe": "which whete flour thou schalt offre to the Lord, and schalt bitake in the hondis of the preest.", "rotherham": "Then shalt thou bring in the meal-offering that is made of these, unto Yahweh,—and one shall bring it near unto the priest, and he shall take it near unto the altar.", "darby": "And thou shalt bring the oblation that is made of these things to Jehovah; and it shall be presented to the priest, and he shall bring it to the altar.", "twenty": "", "jps": "And thou shalt bring the meal-offering that is made of these things unto HaShem; and it shall be presented unto the priest, and he shall bring it unto the altar.", "acv": "And thou shall bring the meal offering that is made of these things to Jehovah, and it shall be presented to the priest, and he shall bring it to the altar.", "anderson": "", "haweis": "", "noyes": "", "webster": "And thou shalt bring the meat-offering that is made of these things to the LORD: and when it is presented to the priest, he shall bring it to the altar.", "vulgate": "quam offeres Domino tradens manibus sacerdotis;", "brenton": "And he shall offer the sacrifice which he shall make of these to the Lord, and shall bring it to the priest."}}, {"v": 9, "ref": "2:9", "o": "וְ/הֵרִ֨ים הַ/כֹּהֵ֤ן מִן הַ/מִּנְחָה֙ אֶת אַזְכָּ֣רָתָ֔/הּ וְ/הִקְטִ֖יר הַ/מִּזְבֵּ֑חָ/ה אִשֵּׁ֛ה רֵ֥יחַ נִיחֹ֖חַ לַ/יהוָֽה", "en": {"kjv": "And the priest shall take from the meat offering a memorial thereof, and shall burn it upon the altar: it is an offering made by fire, of a sweet savour unto the Lord.", "web": "The priest shall take from the meal offering its memorial, and shall burn it on the altar, an offering made by fire, of a pleasant aroma to Yahweh.", "bsb": "The priest is to remove the memorial portion from the grain offering and burn it on the altar as an offering made by fire, a pleasing aroma to the LORD.", "asv": "And the priest shall take up from the meal-offering the memorial thereof, and shall burn it upon the altar, an offering made by fire, of a sweet savor unto Jehovah.", "ylt": "and the priest hath lifted up from the present its memorial, and hath made perfume on the altar, a fire-offering of sweet fragrance to Jehovah;", "tyndale": "and shall heue vppe parte of the meatoffrynge for a memoriall, and shall burne it apon the alter: an offerynge of a swete sauoure vnto the Lorde.", "dra": "And when he hath offered it, he shall take a memorial out of the sacrifice, and burn it upon the altar for a sweet savour to the Lord.", "bbe": "And he is to take from the meal offering a part, for a sign, burning it on the altar; an offering made by fire for a sweet smell to the Lord.", "geneva": "And the Priest shall take from the meate offring a memoriall of it, and shall burne it vpon the altar: for it is an oblation made by fire for a sweete sauour vnto the Lord.", "wycliffe": "And whanne he hath offrid it, he schal take a memorial of the sacrifice, and he schal brenne it on the auter, in to `odour of swetnesse to the Lord.", "rotherham": "Then shall the priest uplift out of the meal-offering, a memorial thereof, and make a perfume at the altar,—an altar-flame of a satisfying odour unto Yahweh.", "darby": "And the priest shall take from the oblation a memorial thereof, and shall burn it on the altar, an offering by fire to Jehovah of a sweet odour.", "twenty": "", "jps": "And the priest shall take off from the meal-offering the memorial-part thereof, and shall make it smoke upon the altar--an offering made by fire, of a sweet savour unto HaShem.", "acv": "And the priest shall take up from the meal offering the memorial of it, and shall burn it upon the altar, an offering made by fire, of a sweet savor to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall take from the meat-offering a memorial of it, and shall burn [it] upon the altar: [it is] an offering made by fire, of a sweet savor to the LORD.", "vulgate": "qui cum obtulerit eam tollet memoriale de sacrificio et adolebit super altare in odorem suavitatis Domino;", "brenton": "And the priest shall approach the altar, and shall take away from the sacrifice a memorial of it, and the priest shall place it on the altar: a burnt offering, a smell of sweet savour to the Lord."}}, {"v": 10, "ref": "2:10", "o": "וְ/הַ/נּוֹתֶ֨רֶת֙ מִן הַ/מִּנְחָ֔ה לְ/אַהֲרֹ֖ן וּ/לְ/בָנָ֑י/ו קֹ֥דֶשׁ קָֽדָשִׁ֖ים מֵ/אִשֵּׁ֥י יְהוָֽה", "en": {"kjv": "And that which is left of the meat offering shall be Aaron’s and his sons’: it is a thing most holy of the offerings of the Lord made by fire.", "web": "That which is left of the meal offering shall be Aaron’s and his sons’. It is a thing most holy of the offerings of Yahweh made by fire.", "bsb": "But the remainder of the grain offering shall belong to Aaron and his sons; it is a most holy part of the offerings made by fire to the LORD.", "asv": "And that which is left of the meal-offering shall be Aaron’s and his sons’: it is a thing most holy of the offerings of Jehovah made by fire.", "ylt": "and the remnant of the present is for Aaron and for his sons, most holy, of the fire-offerings of Jehovah.", "tyndale": "And that which is left of the meatofferynge shalbe Aarons and his sonnes, as a thynge that is most holye of the offerynges off the Lorde.", "dra": "And whatsoever is left, shall be Aaron's, and his sons': holy of holies of the offerings of the Lord.", "bbe": "And the rest of the meal offering will be for Aaron and his sons; it is most holy among the Lord's fire offerings.", "geneva": "But that which is left of the meate offring, shalbe Aarons and his sonnes: for it is most holy of the offrings of the Lord made by fire.", "wycliffe": "Sotheli what euer thing `is residue, it schal be Aarons and hise sones, the hooly of hooli thingis of the offryngis to the Lord.", "rotherham": "But the remainder of the meal-offering pertaineth to Aaron and to his sons,—most holy from among the altar-flames of Yahweh.", "darby": "And the remainder of the oblation [shall be] Aaron's and his sons': [it is] most holy of Jehovah's offerings by fire.", "twenty": "", "jps": "But that which is left of the meal-offering shall be Aaron's and his sons'; it is a thing most holy of the offerings of HaShem made by fire.", "acv": "And that which is left of the meal offering shall be Aaron's and his sons'. It is a thing most holy of the offerings of Jehovah made by fire.", "anderson": "", "haweis": "", "noyes": "", "webster": "And that which is left of the meat-offering [shall be] Aaron's and his sons': [it is] a thing most holy, of the offerings of the LORD made by fire.", "vulgate": "quicquid autem reliquum est erit Aaron et filiorum eius sanctum sanctorum de oblationibus Domini;", "brenton": "And that which is left of the sacrifice shall be for Aaron and his sons, most holy from the burnt-offerings of the Lord."}}, {"v": 11, "ref": "2:11", "o": "כָּל הַ/מִּנְחָ֗ה אֲשֶׁ֤ר תַּקְרִ֨יבוּ֙ לַ/יהוָ֔ה לֹ֥א תֵעָשֶׂ֖ה חָמֵ֑ץ כִּ֤י כָל שְׂאֹר֙ וְ/כָל דְּבַ֔שׁ לֹֽא תַקְטִ֧ירוּ מִמֶּ֛/נּוּ אִשֶּׁ֖ה לַֽ/יהוָֽה", "en": {"kjv": "No meat offering, which ye shall bring unto the Lord, shall be made with leaven: for ye shall burn no leaven, nor any honey, in any offering of the Lord made by fire.", "web": "“‘No meal offering, which you shall offer to Yahweh, shall be made with yeast; for you shall burn no yeast, nor any honey, as an offering made by fire to Yahweh.", "bsb": "No grain offering that you present to the LORD may be made with leaven, for you are not to burn any leaven or honey as an offering made by fire to the LORD.", "asv": "No meal-offering, which ye shall offer unto Jehovah, shall be made with leaven; for ye shall burn no leaven, nor any honey, as an offering made by fire unto Jehovah.", "ylt": "No present which ye bring near to Jehovah is made fermented, for with any leaven or any honey ye perfume no fire-offering to Jehovah.", "tyndale": "All the meatoffrynges which ye shall brynge vnto the Lorde, shalbe made without leue. For ye shall nether burne leuen nor honye in any offerynge of the Lorde:", "dra": "Every oblation that is offered to the Lord shall be made without leaven: neither shall any leaven or honey be burnt in the sacrifice to the Lord.", "bbe": "No meal offering which you give to the Lord is to be made with leaven; no leaven or honey is to be burned as an offering made by fire to the Lord.", "geneva": "All the meate offrings which ye shall offer vnto the Lord, shalbe made without leauen: for ye shall neither burne leauen nor honie in any offring of the Lord made by fire.", "wycliffe": "Ech offryng which is offrid to the Lord, schal be without sour dow, nether ony thing of sour dow, and of hony, schal be brent in the sacrifice of the Lord.", "rotherham": "None of the meal-offerings which ye bring near unto Yahweh shall be made into anything leavened,—for, of no leaven and Of no syrup, may ye make a perfume, as an altar-flame unto Yahweh.", "darby": "No oblation which ye shall present to Jehovah shall be made with leaven; for no leaven and no honey shall ye burn [in] any fire-offering to Jehovah.", "twenty": "", "jps": "No meal-offering, which ye shall bring unto HaShem, shall be made with leaven; for ye shall make no leaven, nor any honey, smoke as an offering made by fire unto HaShem.", "acv": "No meal offering, which ye shall offer to Jehovah, shall be made with leaven, for ye shall burn no leaven, nor any honey, as an offering made by fire to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "No meat-offering which ye shall bring to the LORD shall be made with leaven: for ye shall burn no leaven, nor any honey, in any offering of the LORD made by fire.", "vulgate": "omnis oblatio quae offertur Domino absque fermento fiet nec quicquam fermenti ac mellis adolebitur in sacrificio Domini;", "brenton": "Ye shall not leaven any sacrifice which ye shall bring to the Lord; for as to any leaven, or any honey, ye shall not bring of it to offer a gift to the Lord."}}, {"v": 12, "ref": "2:12", "o": "קָרְבַּ֥ן רֵאשִׁ֛ית תַּקְרִ֥יבוּ אֹתָ֖/ם לַ/יהוָ֑ה וְ/אֶל הַ/מִּזְבֵּ֥חַ לֹא יַעֲל֖וּ לְ/רֵ֥יחַ נִיחֹֽחַ", "en": {"kjv": "As for the oblation of the firstfruits, ye shall offer them unto the Lord: but they shall not be burnt on the altar for a sweet savour.", "web": "As an offering of first fruits you shall offer them to Yahweh: but they shall not ascend for a pleasant aroma on the altar.", "bsb": "You may bring them to the LORD as an offering of firstfruits, but they are not to be offered on the altar as a pleasing aroma.", "asv": "As an oblation of first-fruits ye shall offer them unto Jehovah: but they shall not come up for a sweet savor on the altar.", "ylt": "`An offering of first- fruits --ye bring them near to Jehovah, but on the altar they go not up, for sweet fragrance.", "tyndale": "Notwithstondinge ye shall bryng the firstlynges of them vnto the Lorde: But they shall not come apon the alter to make a swete sauoure.", "dra": "You shall offer only the firstfruits of them and gifts: but they shall not be put upon the altar, for a savour of sweetness.", "bbe": "You may give them as an offering of first-fruits to the Lord, but they are not to go up as a sweet smell on the altar.", "geneva": "In the oblation of the first fruits ye shall offer them vnto the Lord, but they shall not be burnt vpon the altar for a sweete sauour.", "wycliffe": "Ye schulen offre oneli the firste fruytis of tho, and yiftis; sotheli tho schulen not be put on the auter, in to odour of swetnesse.", "rotherham": "As for an oblation of first-fruits, ye shall bring them near unto Yahweh,—but unto the altar, they shall not take them up, as a satisfying odour.", "darby": "As to the offering of the first-fruits, ye shall present them to Jehovah; but they shall not be offered upon the altar for a sweet odour.", "twenty": "", "jps": "As an offering of first-fruits ye may bring them unto HaShem; but they shall not come up for a sweet savour on the altar.", "acv": "As an oblation of first-fruits ye shall offer them to Jehovah, but they shall not come up for a sweet savor on the altar.", "anderson": "", "haweis": "", "noyes": "", "webster": "As for the oblation of the first-fruits, ye shall offer them to the LORD: but they shall not be burnt on the altar for a sweet savor.", "vulgate": "primitias tantum eorum offeretis et munera super altare vero non ponentur in odorem suavitatis;", "brenton": "Ye shall bring them in the way of fruits to the Lord, but they shall not be offered on the altar for a sweet-smelling savour to the Lord."}}, {"v": 13, "ref": "2:13", "o": "וְ/כָל קָרְבַּ֣ן מִנְחָתְ/ךָ֮ בַּ/מֶּ֣לַח תִּמְלָח֒ וְ/לֹ֣א תַשְׁבִּ֗ית מֶ֚לַח בְּרִ֣ית אֱלֹהֶ֔י/ךָ מֵ/עַ֖ל מִנְחָתֶ֑/ךָ עַ֥ל כָּל קָרְבָּנְ/ךָ֖ תַּקְרִ֥יב מֶֽלַח", "en": {"kjv": "And every oblation of thy meat offering shalt thou season with salt; neither shalt thou suffer the salt of the covenant of thy God to be lacking from thy meat offering: with all thine offerings thou shalt offer salt.", "web": "Every offering of your meal offering you shall season with salt; neither shall you allow the salt of the covenant of your God to be lacking from your meal offering. With all your offerings you shall offer salt.", "bsb": "And you shall season each of your grain offerings with salt. You must not leave the salt of the covenant of your God out of your grain offering; you are to add salt to each of your offerings.", "asv": "And every oblation of thy meal-offering shalt thou season with salt; neither shalt thou suffer the salt of the covenant of thy God to be lacking from thy meal-offering: with all thine oblations thou shalt offer salt.", "ylt": "And every offering--thy present--with salt thou dost season, and thou dost not let the salt of the covenant of thy God cease from thy present; with all thine offerings thou dost bring near salt.", "tyndale": "All thy meatofferynges thou shalt salt with salt: nether shalt thou soffre the salt of the couenaunt of thy God to be lackynge from thy meatofferynge: but apon all thyne offerynges thou shalt brynge salt.", "dra": "Whatsoever sacrifice thou offerest, thou shalt season it with salt: neither shalt thou take away the salt of the covenant of thy God from thy sacrifice. In all thy oblations thou shalt offer salt.", "bbe": "And every meal offering is to be salted with salt; your meal offering is not to be without the salt of the agreement of your God: with all your offerings give salt.", "geneva": "(All the meate offrings also shalt thou season with salt, neither shalt thou suffer the salt of the couenant of thy God to be lacking from thy meate offring, but vpon all thine oblations thou shalt offer salt)", "wycliffe": "Whateuer thing of sacrifice thou schalt offre, thou schalt make it sauery with salt, nether thou schalt take awey the salt of the boond of pees of thi God fro thi sacrifice; in ech offryng thou schalt offre salt.", "rotherham": "And, every meal-offering oblation of thine, with salt, shalt thou season, and thou shalt not suffer to be lacking the salt of the covenant of thy God, from upon thy meal-offering,—upon every oblation of thine, shalt thou offer salt.", "darby": "And every offering of thine oblation shalt thou season with salt; neither shalt thou suffer the salt of the covenant of thyGod to be lacking from thine oblation: with all thine offerings thou shalt offer salt.", "twenty": "", "jps": "And every meal-offering of thine shalt thou season with salt; neither shalt thou suffer the salt of the covenant of thy G-d to be lacking from thy meal-offering; with all thy offerings thou shalt offer salt.", "acv": "And every oblation of thy meal offering thou shall season with salt, nor shall thou allow the salt of the covenant of thy God to be lacking from thy meal offering. With all thine oblations thou shall offer salt.", "anderson": "", "haweis": "", "noyes": "", "webster": "And every oblation of thy meat-offering shalt thou season with salt: neither shalt thou suffer the salt of the covenant of thy God to be lacking from thy meat-offering: with all thy offerings thou shalt offer salt.", "vulgate": "quicquid obtuleris sacrificii sale condies nec auferes sal foederis Dei tui de sacrificio tuo in omni oblatione offeres sal;", "brenton": "And every gift of your sacrifice shall be seasoned with salt; omit not the salt of the covenant of the Lord from your sacrifices: on every gift of yours ye shall offer salt to the Lord your God."}}, {"v": 14, "ref": "2:14", "o": "וְ/אִם תַּקְרִ֛יב מִנְחַ֥ת בִּכּוּרִ֖ים לַ/יהוָ֑ה אָבִ֞יב קָל֤וּי בָּ/אֵשׁ֙ גֶּ֣רֶשׂ כַּרְמֶ֔ל תַּקְרִ֕יב אֵ֖ת מִנְחַ֥ת בִּכּוּרֶֽי/ךָ", "en": {"kjv": "And if thou offer a meat offering of thy firstfruits unto the Lord, thou shalt offer for the meat offering of thy firstfruits green ears of corn dried by the fire, even corn beaten out of full ears.", "web": "“‘If you offer a meal offering of first fruits to Yahweh, you shall offer for the meal offering of your first fruits grain in the ear parched with fire, bruised grain of the fresh ear.", "bsb": "If you bring a grain offering of firstfruits to the LORD, you shall offer crushed heads of new grain roasted on the fire.", "asv": "And if thou offer a meal-offering of first-fruits unto Jehovah, thou shalt offer for the meal-offering of thy first-fruits grain in the ear parched with fire, bruised grain of the fresh ear.", "ylt": "`And if thou bring near a present of first-ripe fruits to Jehovah, --of green ears, roasted with fire, beaten out corn of a fruitful field thou dost bring near the present of thy first-ripe fruits ,", "tyndale": "Yf thou offer a meatofferynge of the firstripe frutes vnto the Lorde, then take of that which is yet grene and drye it by the fire ad beat it small, and so offer the meatofferynge of thy firstrype frutes.", "dra": "But if thou offer a gift of the firstfruits of thy corn to the Lord, of the ears yet green, thou shalt dry it at the fire, and break it small like meal; and so shalt thou offer thy firstfruits to the Lord:", "bbe": "And if you give a meal offering of first-fruits to the Lord, give, as your offering of first-fruits, new grain, made dry with fire, crushed new grain.", "geneva": "If then thou offer a meate offring of thy first fruites vnto the Lord, thou shalt offer for thy meate offering of thy first fruites eares of corne dryed by the fire, and wheate beaten out of the greene eares.", "wycliffe": "Forsothe if thou offrist a yifte of the firste thingis of thi fruytis to the Lord, of `eeris of corn yit grene, thou schalt seenge tho in fier, and thou schalt breke in the maner of seedis; and so thou schalt offre thi firste fruytis to the Lord,", "rotherham": "But, if thou wouldst bring near a meal-offering of first-ripe corn, unto Yahweh, of green ears roasted in fire crushed grain of garden-land, shalt thou bring near thy meal-offering of first-ripe corn.", "darby": "And if thou present an oblation of thy first-fruits to Jehovah, thou shalt present as the oblation of thy first-fruits green ears of corn roasted in fire, corn beaten out of full ears.", "twenty": "", "jps": "And if thou bring a meal-offering of first-fruits unto HaShem, thou shalt bring for the meal-offering of thy first-fruits corn in the ear parched with fire, even groats of the fresh ear.", "acv": "And if thou offer a meal offering of first-fruits to Jehovah, thou shall offer for the meal offering of thy first-fruits grain in the ear parched with fire, crushed grain of the fresh ear.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if thou shalt offer a meat-offering of thy first-fruits to the LORD, thou shalt offer for the meat-offering of thy first-fruits, green ears of corn dried by the fire, [even] corn beaten out of full ears.", "vulgate": "sin autem obtuleris munus primarum frugum tuarum Domino de spicis adhuc virentibus torres eas igni et confringes in morem farris et sic offeres primitias tuas Domino;", "brenton": "And if thou wouldest offer a sacrifice of first-fruits to the Lord, it shall be new grains ground and roasted for the Lord; so shalt thou bring the sacrifice of the first-fruits."}}, {"v": 15, "ref": "2:15", "o": "וְ/נָתַתָּ֤ עָלֶ֨י/הָ֙ שֶׁ֔מֶן וְ/שַׂמְתָּ֥ עָלֶ֖י/הָ לְבֹנָ֑ה מִנְחָ֖ה הִֽוא", "en": {"kjv": "And thou shalt put oil upon it, and lay frankincense thereon: it is a meat offering.", "web": "You shall put oil on it, and lay frankincense on it: it is a meal offering.", "bsb": "And you are to put oil and frankincense on it; it is a grain offering.", "asv": "And thou shalt put oil upon it, and lay frankincense thereon: it is a meal-offering.", "ylt": "and thou hast put on it oil, and laid on it frankincense, it is a present;", "tyndale": "And than poure oyle thereto, and put frankencens thereon: and so it is a meatoffrynge.", "dra": "Pouring oil upon it and putting on frankincense, because it is the oblation of the Lord.", "bbe": "And put oil on it and perfume: it is a meal offering.", "geneva": "After, thou shalt put oyle vpon it, and lay incense thereon: for it is a meate offring.", "wycliffe": "and thou schalt schede oyle theronne, and schalt putte encense, for it is the offryng of the Lord.", "rotherham": "And thou shalt place thereon, oil and shalt put thereon, frankincense,—a meal-offering, it is.", "darby": "And thou shalt put oil on it, and lay frankincense thereon: it is an oblation.", "twenty": "", "jps": "And thou shalt put oil upon it, and lay frankincense thereon; it is a meal-offering.", "acv": "And thou shall put oil upon it, and lay frankincense on it. It is a meal offering.", "anderson": "", "haweis": "", "noyes": "", "webster": "And thou shalt put oil upon it, and lay frankincense upon it: [it is] a meat-offering.", "vulgate": "fundens supra oleum et tus inponens quia oblatio Domini est;", "brenton": "And thou shalt pour oil upon it, and shalt put frankincense on it: it is a sacrifice."}}, {"v": 16, "ref": "2:16", "o": "וְ/הִקְטִ֨יר הַ/כֹּהֵ֜ן אֶת אַזְכָּרָתָ֗/הּ מִ/גִּרְשָׂ/הּ֙ וּ/מִ/שַּׁמְנָ֔/הּ עַ֖ל כָּל לְבֹנָתָ֑/הּ אִשֶּׁ֖ה לַ/יהוָֽה", "en": {"kjv": "And the priest shall burn the memorial of it, part of the beaten corn thereof, and part of the oil thereof, with all the frankincense thereof: it is an offering made by fire unto the Lord.", "web": "The priest shall burn as its memorial, part of its bruised grain, and part of its oil, along with all its frankincense: it is an offering made by fire to Yahweh.", "bsb": "The priest shall then burn the memorial portion of the crushed grain and the oil, together with all its frankincense, as an offering made by fire to the LORD.", "asv": "And the priest shall burn the memorial of it, part of the bruised grain thereof, and part of the oil thereof, with all the frankincense thereof: it is an offering made by fire unto Jehovah.", "ylt": "and the priest hath made perfume with its memorial from its beaten out corn , and from its oil, besides all its frankincense--a fire-offering to Jehovah.", "tyndale": "And the preast shall burne parte of the beten corne and parte of that oyle, with all the frakencens: for a remembraunce. That is an offerynge vnto the Lorde.", "dra": "Whereof the priest shall burn for a memorial of the gift, part of the corn broken small and of the oil, and all the frankincense.", "bbe": "And part of the meal of the offering and part of the oil and all the perfume is to be burned for a sign by the priest: it is an offering made by fire to the Lord.", "geneva": "And the Priest shall burne the memoriall of it, euen of that that is beaten, and of the oyle of it, with all the incense thereof: for it is an offring vnto the Lord made by fire.", "wycliffe": "Of which the preest schal brenne, in to mynde of the yifte, a part of the `seedis brokun, and of oyle, and al the encense.", "rotherham": "Then shall the priest make a perfume, with the memorial thereof,—from the crushed grain thereof and from the oil thereof, besides all the frankincense thereof,—an altar-flame, unto Yahweh.", "darby": "And the priest shall burn the memorial thereof, [part] of the beaten corn thereof, and [part] of the oil thereof, with all the frankincense thereof: [it is] an offering by fire to Jehovah.", "twenty": "", "jps": "And the priest shall make the memorial-part of it smoke, even of the groats thereof, and of the oil thereof, with all the frankincense thereof; it is an offering made by fire unto HaShem.", "acv": "And the priest shall burn the memorial of it, part of the crushed grain of it, and part of the oil of it, with all the frankincense of it. It is an offering made by fire to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall burn the memorial of it, [part] of its beaten corn, and [part] of its oil, with all its frankincense: [it is] an offering made by fire to the LORD.", "vulgate": "de qua adolebit sacerdos in memoriam muneris partem farris fracti et olei ac totum tus;", "brenton": "And the priest shall offer the memorial of it taken from the grains with the oil, and all its frankincense: it is a burnt-offering to the Lord."}}]}, {"c": 3, "verses": [{"v": 1, "ref": "3:1", "o": "וְ/אִם זֶ֥בַח שְׁלָמִ֖ים קָרְבָּנ֑/וֹ אִ֤ם מִן הַ/בָּקָר֙ ה֣וּא מַקְרִ֔יב אִם זָכָר֙ אִם נְקֵבָ֔ה תָּמִ֥ים יַקְרִיבֶ֖/נּוּ לִ/פְנֵ֥י יְהוָֽה", "en": {"kjv": "And if his oblation be a sacrifice of peace offering, if he offer it of the herd; whether it be a male or female, he shall offer it without blemish before the Lord.", "web": "“‘If his offering is a sacrifice of peace offerings; if he offers it from the herd, whether male or female, he shall offer it without defect before Yahweh.", "bsb": "“If one’s offering is a peace offering and he offers an animal from the herd, whether male or female, he must present it without blemish before the LORD.", "asv": "And if his oblation be a sacrifice of peace-offerings; if he offer of the herd, whether male or female, he shall offer it without blemish before Jehovah.", "ylt": "`And if his offering is a sacrifice of peace-offerings, if out of the herd he is bringing near, whether male or female, a perfect one he doth bring near before Jehovah,", "tyndale": "Yf any man brynge a peaceofferynge of the oxen: whether it be male or female, he shall brynge such as is without blemysh, before the Lorde,", "dra": "And if his oblation be a sacrifice of peace offerings, and he will offer of the herd, whether male or female: he shall offer them without blemish before the Lord.", "bbe": "And if his offering is given for a peace-offering; if he gives of the herd, male or female, let him give it without any mark on it, before the Lord.", "geneva": "Also if his oblation be a peace offering, if he will offer of the droue (whether it be male or female) he shall offer such as is without blemish, before the Lord,", "wycliffe": "That if his offryng is a sacrifice of pesible thingis, and he wole offre of oxun, he schal offre bifore the Lord a male, ether a female, without wem.", "rotherham": "But, if a peace-offering, be his oblation, if, of the herd, he himself, be bringing near,—whether male or female, without defect, shall he bring it near before Yahweh.", "darby": "And if his offering be a sacrifice of peace-offering, — if he present [it] of the herd, whether a male or female, he shall present it without blemish before Jehovah.", "twenty": "", "jps": "And if his offering be a sacrifice of peace-offerings: if he offer of the herd, whether male or female, he shall offer it without blemish before HaShem.", "acv": "And if his oblation be a sacrifice of peace offerings, if he offer of the herd, whether male or female, he shall offer it without blemish before Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if his oblation [shall be] a sacrifice of peace-offering, if he shall offer [it] of the herd, whether a male or female; he shall offer it without blemish before the LORD.", "vulgate": "quod si hostia pacificorum fuerit eius oblatio et de bubus voluerit offerre marem sive feminam inmaculata offeret coram Domino;", "brenton": "And if his gift to the Lord be a peace-offering, if he should bring it of the oxen, whether it be male or whether it be female, he shall bring it unblemished before the Lord."}}, {"v": 2, "ref": "3:2", "o": "וְ/סָמַ֤ךְ יָד/וֹ֙ עַל רֹ֣אשׁ קָרְבָּנ֔/וֹ וּ/שְׁחָט֕/וֹ פֶּ֖תַח אֹ֣הֶל מוֹעֵ֑ד וְ/זָרְק֡וּ בְּנֵי֩ אַהֲרֹ֨ן הַ/כֹּהֲנִ֧ים אֶת הַ/דָּ֛ם עַל הַ/מִּזְבֵּ֖חַ סָבִֽיב", "en": {"kjv": "And he shall lay his hand upon the head of his offering, and kill it at the door of the tabernacle of the congregation: and Aaron’s sons the priests shall sprinkle the blood upon the altar round about.", "web": "He shall lay his hand on the head of his offering, and kill it at the door of the Tent of Meeting: and Aaron’s sons, the priests, shall sprinkle the blood around on the altar.", "bsb": "He is to lay his hand on the head of the offering and slaughter it at the entrance to the Tent of Meeting. Then Aaron’s sons the priests shall sprinkle the blood on all sides of the altar.", "asv": "And he shall lay his hand upon the head of his oblation, and kill it at the door of the tent of meeting: and Aaron’s sons the priests shall sprinkle the blood upon the altar round about.", "ylt": "and he hath laid his hand on the head of his offering, and hath slaughtered it at the opening of the tent of meeting, and sons of Aaron, the priests, have sprinkled the blood on the altar round about.", "tyndale": "and let him put his hande apon the heed of his offerynge, and kyll it before the dore of the tabernacle of witnesse. And Aarons sonnes the preastes, shall sprinkle the bloude apon the alter rounde aboute.", "dra": "And he shall lay his hand upon the head of his victim, which shall be slain in the entry of the tabernacle of the testimony: and the sons of Aaron the priests shall pour the blood round about upon the altar.", "bbe": "And he is to put his hand on the head of his offering and put it to death at the door of the Tent of meeting; and Aaron's sons, the priests, are to put some of the blood on and round the altar.", "geneva": "And shall put his hande vpon the head of his offering, and kill it at the doore of the Tabernacle of the Congregation: and Aarons sonnes the Priestes shall sprinkle the blood vpon the altar rounde about.", "wycliffe": "And he schal sette hond on the heed of his sacrifice, that schal be offrid in the entryng of the tabernacle; and the sones of Aaron preest schulen schede the blood bi the cumpas of the auter.", "rotherham": "Then shall he lean his hand upon the head of his oblation, and slay it at the entrance of the tent of meeting,—and the sons of Aaron the priests shall dash the blood against the altar round about,", "darby": "And he shall lay his hand on the head of his offering, and slaughter it at the entrance of the tent of meeting; and Aaron's sons, the priests, shall sprinkle the blood on the altar round about.", "twenty": "", "jps": "And he shall lay his hand upon the head of his offering, and kill it at the door of the tent of meeting; and Aaron's sons the priests shall dash the blood against the altar round about.", "acv": "And he shall lay his hand upon the head of his oblation, and kill it at the door of the tent of meeting. And Aaron's sons the priests shall sprinkle the blood upon the altar round about.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall lay his hand upon the head of his offering, and kill it [at] the door of the tabernacle of the congregation: and Aaron's sons the priests shall sprinkle the blood upon the altar round about.", "vulgate": "ponetque manum super caput victimae suae quae immolabitur in introitu tabernaculi fundentque filii Aaron sacerdotes sanguinem per circuitum altaris;", "brenton": "And he shall lay his hands on the head of the gift, and shall slay it before the Lord, by the doors of the tabernacle of witness. And the priests the sons of Aaron shall pour the blood on the altar of burnt-offerings round about."}}, {"v": 3, "ref": "3:3", "o": "וְ/הִקְרִיב֙ מִ/זֶּ֣בַח הַ/שְּׁלָמִ֔ים אִשֶּׁ֖ה לַ/יהוָ֑ה אֶת הַ/חֵ֨לֶב֙ הַֽ/מְכַסֶּ֣ה אֶת הַ/קֶּ֔רֶב וְ/אֵת֙ כָּל הַ/חֵ֔לֶב אֲשֶׁ֖ר עַל הַ/קֶּֽרֶב", "en": {"kjv": "And he shall offer of the sacrifice of the peace offering an offering made by fire unto the Lord; the fat that covereth the inwards, and all the fat that is upon the inwards,", "web": "He shall offer of the sacrifice of peace offerings an offering made by fire to Yahweh; the fat that covers the innards, and all the fat that is on the innards,", "bsb": "From the peace offering he is to bring an offering made by fire to the LORD: the fat that covers the entrails, all the fat that is on them,", "asv": "And he shall offer of the sacrifice of peace-offerings an offering made by fire unto Jehovah; the fat that covereth the inwards, and all the fat that is upon the inwards,", "ylt": "`And he hath brought near from the sacrifice of the peace-offerings a fire-offering to Jehovah, the fat which is covering the inwards, and all the fat which is on the inwards,", "tyndale": "And they shall offre of the peaceofferynge to be a sacrifice vnto the Lord: the fatt that couereth the inwardes and all the fatt that is apon the inwardes:", "dra": "And they shall offer of the sacrifice of peace offerings, for an oblation to the Lord: the fat that covereth the entrails, and all the fat that is within,", "bbe": "And he is to give of the peace-offering, as an offering made by fire to the Lord; the fat covering the inside parts and all the fat on the inside parts,", "geneva": "So he shall offer part of the peace offerings as a sacrifice made by fire vnto the Lord, euen the fat that couereth the inwardes, and all the fat that is vpon the inwardes.", "wycliffe": "And thei schulen offre of the sacrifice of pesible thingis in to offryng to the Lord, the fatnesse that hilith the entrailis, and what euer thing of fatnesse is with ynne;", "rotherham": "Then shall he bring near out of the peace-offering, an altar-flame unto Yahweh,—the fat that covereth the inwards, and all the fat that is upon the inwards;", "darby": "And he shall present of the sacrifice of peace-offering an offering by fire to Jehovah; the fat that covereth the inwards, and all the fat that is on the inwards,", "twenty": "", "jps": "And he shall present of the sacrifice of peace-offerings an offering made by fire unto HaShem: the fat that covereth the inwards, and all the fat that is upon the inwards,", "acv": "And he shall offer of the sacrifice of peace offerings an offering made by fire to Jehovah, he shall take away the fat that covers the innards, and all the fat that is upon the innards,", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall offer of the sacrifice of the peace-offering, an offering made by fire to the LORD; the fat that covereth the inwards, and all the fat that [is] upon the inwards,", "vulgate": "et offerent de hostia pacificorum in oblationem Domini adipem qui operit vitalia et quicquid pinguedinis intrinsecus est;", "brenton": "And they shall bring of the peace-offering a burnt-sacrifice to the Lord, the fat covering the belly, and all the fat on the belly."}}, {"v": 4, "ref": "3:4", "o": "וְ/אֵת֙ שְׁתֵּ֣י הַ/כְּלָיֹ֔ת וְ/אֶת הַ/חֵ֨לֶב֙ אֲשֶׁ֣ר עֲלֵ/הֶ֔ן אֲשֶׁ֖ר עַל הַ/כְּסָלִ֑ים וְ/אֶת הַ/יֹּתֶ֨רֶת֙ עַל הַ/כָּבֵ֔ד עַל הַ/כְּלָי֖וֹת יְסִירֶֽ/נָּה", "en": {"kjv": "And the two kidneys, and the fat that is on them, which is by the flanks, and the caul above the liver, with the kidneys, it shall he take away.", "web": "and the two kidneys, and the fat that is on them, which is by the loins, and the cover on the liver, with the kidneys, he shall take away.", "bsb": "both kidneys with the fat on them near the loins, and the lobe of the liver, which he is to remove with the kidneys.", "asv": "and the two kidneys, and the fat that is on them, which is by the loins, and the caul upon the liver, with the kidneys, shall he take away.", "ylt": "and the two kidneys, and the fat which is on them, which is on the flanks, and the redundance above the liver, (beside the kidneys he doth turn it aside),", "tyndale": "and the two kydneys with the fatt that lyeth apon the loynes: and the kall that ys on the lyuer, they shall take awaye with the kydneyes.", "dra": "The two kidneys with the fat wherewith the flanks are covered, and the caul of the liver with the two little kidneys.", "bbe": "And the two kidneys, and the fat on them, which is by the top part of the legs, and the fat joining the liver and the kidneys, he is to take away;", "geneva": "He shall also take away the two kidneis, and the fat that is on them, and vpon the flankes, and the kall on the liuer with the kidneis.", "wycliffe": "thei schulen offre twey kydeneris, with the fatnesse bi which the guttis clepid ylyon ben hilid, and the calle of the lyuer with the litle reynes.", "rotherham": "and the two kidneys, and the fat which is upon them, which is upon the loins,—and the caul upon the liver, upon the kidneys, shall he remove it.", "darby": "and the two kidneys, and the fat that is on them, which is by the flanks, and the net above the liver which he shall take away as far as the kidneys;", "twenty": "", "jps": "and the two kidneys, and the fat that is on them, which is by the loins, and the lobe above the liver, which he shall take away hard by the kidneys.", "acv": "and the two kidneys, and the fat that is on them, which is by the loins, and the caul upon the liver, with the kidneys.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the two kidneys, and the fat that [is] on them, which [is] by the flanks, and the caul above the liver, with the kidneys, it shall he take away.", "vulgate": "duos renes cum adipe quo teguntur ilia et reticulum iecoris cum renunculis;", "brenton": "And the two kidneys and the fat that is upon them; he shall take away that which is on the thighs, and the caul above the liver together with the kidneys."}}, {"v": 5, "ref": "3:5", "o": "וְ/הִקְטִ֨ירוּ אֹת֤/וֹ בְנֵֽי אַהֲרֹן֙ הַ/מִּזְבֵּ֔חָ/ה עַל הָ֣/עֹלָ֔ה אֲשֶׁ֥ר עַל הָ/עֵצִ֖ים אֲשֶׁ֣ר עַל הָ/אֵ֑שׁ אִשֵּׁ֛ה רֵ֥יחַ נִיחֹ֖חַ לַֽ/יהוָֽה", "en": {"kjv": "And Aaron’s sons shall burn it on the altar upon the burnt sacrifice, which is upon the wood that is on the fire: it is an offering made by fire, of a sweet savour unto the Lord.", "web": "Aaron’s sons shall burn it on the altar on the burnt offering, which is on the wood that is on the fire: it is an offering made by fire, of a pleasant aroma to Yahweh.", "bsb": "Then Aaron’s sons are to burn it on the altar atop the burnt offering that is on the burning wood, as an offering made by fire, a pleasing aroma to the LORD.", "asv": "And Aaron’s sons shall burn it on the altar upon the burnt-offering, which is upon the wood that is on the fire: it is an offering made by fire, of a sweet savor unto Jehovah.", "ylt": "and sons of Aaron have made it a perfume on the altar, on the burnt-offering which is on the wood, which is on the fire--a fire-offering of sweet fragrance to Jehovah.", "tyndale": "And Aarons sonnes shall burne them apon the alter with the burntsacrifice which is apon the wodd on the fire. That is a sacrifice of a swete sauoure vnto the Lorde.", "dra": "And they shall burn them upon the altar, for a holocaust, putting fire under the wood: for an oblation of most sweet savour to the Lord.", "bbe": "That it may be burned by Aaron's sons on the altar, on the burned offering which is on the wood on the fire: it is an offering made by fire of a sweet smell to the Lord.", "geneva": "And Aarons sonnes shall burne it on the altar, with the burnt offering, which is vpon the wood, that is on the fire: this is a sacrifice made by fire for a sweete sauour vnto the Lord.", "wycliffe": "And thei schulen brenne tho on the auter, in to brent sacrifice, whanne fier is put vndur the trees, in to offryng of swettest odour to the Lord.", "rotherham": "Then shall the sons of Aaron make thereof a perfume at the altar, upon the ascending-sacrifice which is on the wood, which is on the fire,—an altar-flame of a satisfying odour unto Yahweh.", "darby": "and Aaron's sons shall burn it on the altar upon the burnt-offering which [lieth] on the wood that is upon the fire: [it is] an offering by fire to Jehovah of a sweet odour.", "twenty": "", "jps": "And Aaron's sons shall make it smoke on the altar upon the burnt-offering, which is upon the wood that is on the fire; it is an offering made by fire, of a sweet savour unto HaShem.", "acv": "And Aaron's sons shall burn it on the altar upon the burnt offering, which is upon the wood that is on the fire. It is an offering made by fire, of a sweet savor to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Aaron's sons shall burn it on the altar, upon the burnt-sacrifice which [is] upon the wood that [is] on the fire: [it is] an offering made by fire, of a sweet savor to the LORD.", "vulgate": "adolebuntque ea super altare in holocaustum lignis igne subposito in oblationem suavissimi odoris Domino;", "brenton": "And the priests the sons of Aaron shall offer them on the altar on the burnt-offering, on the wood which is on the fire upon the altar: it is a burnt-offering, a smell of sweet savour to the Lord."}}, {"v": 6, "ref": "3:6", "o": "וְ/אִם מִן הַ/צֹּ֧אן קָרְבָּנ֛/וֹ לְ/זֶ֥בַח שְׁלָמִ֖ים לַ/יהוָ֑ה זָכָר֙ א֣וֹ נְקֵבָ֔ה תָּמִ֖ים יַקְרִיבֶֽ/נּוּ", "en": {"kjv": "And if his offering for a sacrifice of peace offering unto the Lord be of the flock; male or female, he shall offer it without blemish.", "web": "“‘If his offering for a sacrifice of peace offerings to Yahweh is from the flock; male or female, he shall offer it without defect.", "bsb": "If, however, one’s peace offering to the LORD is from the flock, he must present a male or female without blemish.", "asv": "And if his oblation for a sacrifice of peace-offerings unto Jehovah be of the flock; male or female, he shall offer it without blemish.", "ylt": "`And if his offering is out of the flock for a sacrifice of peace-offerings to Jehovah, male or female, a perfect one he doth bring near;", "tyndale": "Yf a man brynge a peaceoffrynge vnto the Lorde from of the flocke: whether it be male, or female, it shalbe without blemysh.", "dra": "But if his oblation and the sacrifice of peace offering be of the flock, whether he offer male or female, they shall be without blemish.", "bbe": "And if what he gives for a peace-offering to the Lord is of the flock, let him give a male or female, without any mark on it.", "geneva": "Also if his oblation be a peace offring vnto the Lord out of ye flocke, whether it be male or female, he shall offer it without blemish.", "wycliffe": "Sotheli if his offryng is of scheep, and a sacrifice of pesible thingis, whether he offrith a male ether a female, tho schulen be without wem.", "rotherham": "But, if out of the flock, be his oblation for a peace-offering unto Yahweh, whether male or female—without defect, shall he bring it near.", "darby": "And if his offering for a sacrifice of peace-offering to Jehovah be of small cattle, male or female, he shall present it without blemish.", "twenty": "", "jps": "And if his offering for a sacrifice of peace-offerings unto HaShem be of the flock, male or female, he shall offer it without blemish.", "acv": "And if his oblation for a sacrifice of peace offerings to Jehovah be of the flock, male or female, he shall offer it without blemish.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if his offering for a sacrifice of peace-offering to the LORD shall be [of] the flock, male or female; he shall offer it without blemish.", "vulgate": "si vero de ovibus fuerit eius oblatio et pacificorum hostia sive masculum sive feminam obtulerit inmaculata erunt;", "brenton": "And if his gift be of the sheep, a peace-offering to the Lord, male or female, he shall bring it unblemished."}}, {"v": 7, "ref": "3:7", "o": "אִם כֶּ֥שֶׂב הֽוּא מַקְרִ֖יב אֶת קָרְבָּנ֑/וֹ וְ/הִקְרִ֥יב אֹת֖/וֹ לִ/פְנֵ֥י יְהוָֽה", "en": {"kjv": "If he offer a lamb for his offering, then shall he offer it before the Lord.", "web": "If he offers a lamb for his offering, then he shall offer it before Yahweh;", "bsb": "If he is presenting a lamb for his offering, he must present it before the LORD.", "asv": "If he offer a lamb for his oblation, then shall he offer it before Jehovah;", "ylt": "if a sheep he is bringing near for his offering, then he hath brought it near before Jehovah,", "tyndale": "Yf he offre a lambe, he shall brynge it before the Lord", "dra": "If he offer a lamb before the Lord:", "bbe": "If his offering is a lamb, then let it be placed before the Lord:", "geneva": "If he offer a lambe for his oblation, then he shall bring it before the Lord,", "wycliffe": "If he offrith a lombe bifor the Lord,", "rotherham": "If a young sheep, he himself, be bringing near as his oblation, then shall he bring it near, before Yahweh.", "darby": "If he present a sheep for his offering, then shall he present it before Jehovah,", "twenty": "", "jps": "If he bring a lamb for his offering, then shall he present it before HaShem.", "acv": "If he offers a lamb for his oblation, then he shall offer it before Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "If he shall offer a lamb for his offering, then shall he offer it before the LORD.", "vulgate": "si agnum obtulerit coram Domino;", "brenton": "If he bring a lamb for his gift, he shall bring it before the Lord."}}, {"v": 8, "ref": "3:8", "o": "וְ/סָמַ֤ךְ אֶת יָד/וֹ֙ עַל רֹ֣אשׁ קָרְבָּנ֔/וֹ וְ/שָׁחַ֣ט אֹת֔/וֹ לִ/פְנֵ֖י אֹ֣הֶל מוֹעֵ֑ד וְ֠/זָרְקוּ בְּנֵ֨י אַהֲרֹ֧ן אֶת דָּמ֛/וֹ עַל הַ/מִּזְבֵּ֖חַ סָבִֽיב", "en": {"kjv": "And he shall lay his hand upon the head of his offering, and kill it before the tabernacle of the congregation: and Aaron’s sons shall sprinkle the blood thereof round about upon the altar.", "web": "and he shall lay his hand on the head of his offering, and kill it before the Tent of Meeting: and Aaron’s sons shall sprinkle its blood around on the altar.", "bsb": "He is to lay his hand on the head of his offering and slaughter it in front of the Tent of Meeting. Then Aaron’s sons shall sprinkle its blood on all sides of the altar.", "asv": "and he shall lay his hand upon the head of his oblation, and kill it before the tent of meeting: and Aaron’s sons shall sprinkle the blood thereof upon the altar round about.", "ylt": "and hath laid his hand on the head of his offering, and hath slaughtered it before the tent of meeting, and sons of Aaron have sprinkled its blood on the altar round about.", "tyndale": "and put his hande apon his offrynges heede and kyll it in the doore off the tabernacle off wytnesse and Aarons sonnes shall sprinkle the bloude thereof rounde aboute the alter.", "dra": "He shall put his hand upon the head of the victim. And it shall be slain in the entry of the tabernacle of the testimony: and the sons of Aaron shall pour the blood thereof round about upon the altar.", "bbe": "And he is to put his hand on the head of his offering and put it to death before the Tent of meeting; and Aaron's sons are to put some of its blood on and round the altar.", "geneva": "And lay his hand vpon the head of his offring, and shall kill it before the Tabernacle of the Congregation, and Aarons sonnes shall sprinckle the blood thereof round about vpon the altar.", "wycliffe": "he schal sette his hond on the heed of his sacrifice, that schal be offrid in the porche of the tabernacle of witnessyng; and the sones of Aaron schulen schede the blood therof bi `the cumpas of the auter.", "rotherham": "And he shall lean his hand upon the head of his oblation, and shall slay it before the tent of meeting,—and the sons of Aaron shall dash the blood thereof against the altar round about.", "darby": "and shall lay his hand on the head of his offering, and slaughter it before the tent of meeting; and Aaron's sons shall sprinkle the blood thereof upon the altar round about.", "twenty": "", "jps": "And he shall lay his hand upon the head of his offering, and kill it before the tent of meeting; and Aaron's sons shall dash the blood thereof against the altar round about.", "acv": "And he shall lay his hand upon the head of his oblation, and kill it before the tent of meeting. And Aaron's sons shall sprinkle the blood of it upon the altar round about.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall lay his hand upon the head of his offering, and kill it before the tabernacle of the congregation: and Aaron's sons shall sprinkle the blood of it around upon the altar.", "vulgate": "ponet manum super caput victimae suae quae immolabitur in vestibulo tabernaculi testimonii fundentque filii Aaron sanguinem eius per altaris circuitum;", "brenton": "And he shall lay his hands on the head of his offering, and shall slay it by the doors of the tabernacle of witness; and the priests the sons of Aaron shall pour out the blood on the altar round about."}}, {"v": 9, "ref": "3:9", "o": "וְ/הִקְרִ֨יב מִ/זֶּ֣בַח הַ/שְּׁלָמִים֮ אִשֶּׁ֣ה לַ/יהוָה֒ חֶלְבּ/וֹ֙ הָ/אַלְיָ֣ה תְמִימָ֔ה לְ/עֻמַּ֥ת הֶ/עָצֶ֖ה יְסִירֶ֑/נָּה וְ/אֶת הַ/חֵ֨לֶב֙ הַֽ/מְכַסֶּ֣ה אֶת הַ/קֶּ֔רֶב וְ/אֵת֙ כָּל הַ/חֵ֔לֶב אֲשֶׁ֖ר עַל הַ/קֶּֽרֶב", "en": {"kjv": "And he shall offer of the sacrifice of the peace offering an offering made by fire unto the Lord; the fat thereof, and the whole rump, it shall he take off hard by the backbone; and the fat that covereth the inwards, and all the fat that is upon the inwards,", "web": "He shall offer from the sacrifice of peace offerings an offering made by fire to Yahweh; its fat, the entire tail fat, he shall take away close to the backbone; and the fat that covers the inwards, and all the fat that is on the inwards,", "bsb": "And from the peace offering he shall bring an offering made by fire to the LORD consisting of its fat: the entire fat tail cut off close to the backbone, the fat that covers the entrails, all the fat that is on them,", "asv": "And he shall offer of the sacrifice of peace-offerings an offering made by fire unto Jehovah; the fat thereof, the fat tail entire, he shall take away hard by the backbone; and the fat that covereth the inwards, and all the fat that is upon the inwards,", "ylt": "`And he hath brought near from the sacrifice of the peace-offerings a fire-offering to Jehovah, its fat, the whole fat tail (over-against the bone he doth turn it aside), and the fat which is covering the inwards, and all the fat which is on the inwards,", "tyndale": "And of the peaseoffringe they shall brynge a sacrifyce vnto the Lorde: the fatt there of ad the rompe altogether, which they shall take off harde by the backe bone: and the fatt that couereth the inwardes and all the fatt that is apon the inwardes", "dra": "And they shall offer of the victim of peace offerings, a sacrifice to the Lord: the fat and the whole rump,", "bbe": "And of the peace-offering, let him give an offering made by fire to the Lord; the fat of it, all the fat tail, he is to take away near the backbone; and the fat covering the inside parts and all the fat on the inside parts,", "geneva": "After, of the peace offrings he shall offer an offring made by fire vnto the Lord: he shall take away the fat therof, and the rump altogether, hard by the backe bone, and the fat that couereth the inwardes, and all the fat that is vpon the inwards.", "wycliffe": "And thei schulen offre of the sacrifice of pesible thingis a sacrifice to the Lord, the innere fatnesse,", "rotherham": "Then shall he bring near out of the peace-offering, an altar-flame unto Yahweh, the fat thereof the fat-tail thereof entire close to the backbone, shall he remove it,—and the fat that covereth the inwards, and all the fat that is upon the inwards;", "darby": "And he shall present of the sacrifice of peace-offering an offering by fire to Jehovah; the fat thereof, the whole fat tail, which he shall take off close by the backbone, and the fat that covereth the inwards, and all the fat that is on the inwards,", "twenty": "", "jps": "And he shall present of the sacrifice of peace-offerings an offering made by fire unto HaShem: the fat thereof, the fat tail entire, which he shall take away hard by the rump-bone; and the fat that covereth the inwards, and all the fat that is upon the inwards,", "acv": "And he shall offer of the sacrifice of peace offerings an offering made by fire to Jehovah. The fat of it, the entire fat tail, he shall take away close by the backbone. And he shall take away the fat that covers the innards, and all the fat that is upon the innards,", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall offer of the sacrifice of the peace-offering an offering made by fire to the LORD: its fat, [and] the whole rump, that shall he take off hard by the back-bone; and the fat that covereth the inwards, and all the fat that [is] upon the inwards,", "vulgate": "et offerent de pacificorum hostia sacrificium Domino adipem et caudam totam;", "brenton": "And he shall bring of the peace-offering a burnt-sacrifice to the Lord: the fat and the hinder part unblemished he shall take away with the loins, and having taken away all the fat that covers the belly, and all the fat that is on the belly,"}}, {"v": 10, "ref": "3:10", "o": "וְ/אֵת֙ שְׁתֵּ֣י הַ/כְּלָיֹ֔ת וְ/אֶת הַ/חֵ֨לֶב֙ אֲשֶׁ֣ר עֲלֵ/הֶ֔ן אֲשֶׁ֖ר עַל הַ/כְּסָלִ֑ים וְ/אֶת הַ/יֹּתֶ֨רֶת֙ עַל הַ/כָּבֵ֔ד עַל הַ/כְּלָיֹ֖ת יְסִירֶֽ/נָּה", "en": {"kjv": "And the two kidneys, and the fat that is upon them, which is by the flanks, and the caul above the liver, with the kidneys, it shall he take away.", "web": "and the two kidneys, and the fat that is on them, which is by the loins, and the cover on the liver, with the kidneys, he shall take away.", "bsb": "both kidneys with the fat on them near the loins, and the lobe of the liver, which he is to remove with the kidneys.", "asv": "and the two kidneys, and the fat that is upon them, which is by the loins, and the caul upon the liver, with the kidneys, shall he take away.", "ylt": "and the two kidneys, and the fat which is on them, which is on the flanks, and the redundance above the liver, (beside the kidneys he doth turn it aside),", "tyndale": "and the .ij. kydneyes with the fatt that lyeth apon them and apon the loynes, and the kall that is apon the lyuer he shall take awaye with the kydneyes.", "dra": "With the kidneys, and the fat that covereth the belly and all the vitals and both the little kidneys, with the fat that is about the flanks, and the caul of the liver with the little kidneys.", "bbe": "And the two kidneys, with the fat on them, which is by the top part of the legs, and the fat joining the liver and the kidneys, he is to take away;", "geneva": "Also hee shall take away the two kidneis, with the fat that is vpon them, and vpon the flankes, and the kall vpon the liuer with the kidneis.", "wycliffe": "and al the tail with the reynes, and the fatnesse that hilith the wombe, and alle the entrailis, and euer eithir litil reyne, with the fatnesse which is bisidis the `guttis clepid ylion, and the calle of the mawe, with the litle reynes.", "rotherham": "and the two kidneys, with the fat that is on them, which is on the loins,—and the caul that is on the liver, on the kidneys, shall he remove it.", "darby": "and the two kidneys, and the fat that is on them, which is by the flanks, and the net above the liver which he shall take away as far as the kidneys;", "twenty": "", "jps": "and the two kidneys, and the fat that is upon them, which is by the loins, and the lobe above the liver, which he shall take away by the kidneys.", "acv": "and the two kidneys, and the fat that is upon them, which is by the loins, and the caul upon the liver, with the kidneys.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the two kidneys, and the fat that [is] upon them, which [is] by the flanks, and the caul above the liver, with the kidneys, that shall he take away.", "vulgate": "cum renibus et pinguedinem quae operit ventrem atque universa vitalia et utrumque renunculum cum adipe qui est iuxta ilia reticulumque iecoris cum renunculis;", "brenton": "and both the kidneys and the fat that is upon them, and that which is on the thighs, and the caul which is on the liver with the kidneys,"}}, {"v": 11, "ref": "3:11", "o": "וְ/הִקְטִיר֥/וֹ הַ/כֹּהֵ֖ן הַ/מִּזְבֵּ֑חָ/ה לֶ֥חֶם אִשֶּׁ֖ה לַ/יהוָֽה", "en": {"kjv": "And the priest shall burn it upon the altar: it is the food of the offering made by fire unto the Lord.", "web": "The priest shall burn it on the altar: it is the food of the offering made by fire to Yahweh.", "bsb": "Then the priest is to burn them on the altar as food, an offering made by fire to the LORD.", "asv": "And the priest shall burn it upon the altar: it is the food of the offering made by fire unto Jehovah.", "ylt": "and the priest hath made it a perfume on the altar--bread of a fire-offering to Jehovah.", "tyndale": "And the preast shall burne them apon the alter to fede the Lordes offrynge withall.", "dra": "And the priest shall burn them upon the altar, for the food of the fire, and of the oblation of the Lord.", "bbe": "That it may be burned by the priest on the altar; it is the food of the offering made by fire to the Lord.", "geneva": "Then the Priest shall burne it vpon the altar, as the meat of an offring made by fire vnto the Lord.", "wycliffe": "And the preest schal brenne tho on the auter, in to the fedyng of fier, and of the offryng to the Lord.", "rotherham": "Then shall the priest make a perfume, at the altar,—the food of an altar-flame, unto Yahweh.", "darby": "and the priest shall burn it on the altar: [it is] the food of the offering by fire to Jehovah.", "twenty": "", "jps": "And the priest shall make it smoke upon the altar; it is the food of the offering made by fire unto HaShem.", "acv": "And the priest shall burn it upon the altar. It is the food of the offering made by fire to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall burn it upon the altar: [it is] the food of the offering made by fire to the LORD.", "vulgate": "et adolebit ea sacerdos super altare in pabulum ignis et oblationis Domini;", "brenton": "the priest shall offer these on the altar: it is a sacrifice of sweet savour, a burnt-offering to the Lord."}}, {"v": 12, "ref": "3:12", "o": "וְ/אִ֥ם עֵ֖ז קָרְבָּנ֑/וֹ וְ/הִקְרִיב֖/וֹ לִ/פְנֵ֥י יְהוָֽה", "en": {"kjv": "And if his offering be a goat, then he shall offer it before the Lord.", "web": "“‘If his offering is a goat, then he shall offer it before Yahweh:", "bsb": "If one’s offering is a goat, he is to present it before the LORD.", "asv": "And if his oblation be a goat, then he shall offer it before Jehovah:", "ylt": "`And if his offering is a goat, then he hath brought it near before Jehovah,", "tyndale": "Yf the offrynge be a goote, he shall brynge it before the Lorde", "dra": "If his offering be a goat, and he offer it to the Lord:", "bbe": "And if his offering is a goat, then let it be placed before the Lord,", "geneva": "Also if his offring be a goate, then shall he offer it before the Lord,", "wycliffe": "If his offryng is a geet, and he offrith it to the Lord,", "rotherham": "But if a goat, be his oblation, then shall he bring it near, before Yahweh.", "darby": "And if his offering be a goat, then he shall present it before Jehovah.", "twenty": "", "jps": "And if his offering be a goat, then he shall present it before HaShem.", "acv": "And if his oblation be a goat, then he shall offer it before Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if his offering [shall be] a goat, then he shall offer it before the LORD.", "vulgate": "si capra fuerit eius oblatio et obtulerit eam Domino;", "brenton": "And if his offering be of the goats, then shall he bring it before the Lord."}}, {"v": 13, "ref": "3:13", "o": "וְ/סָמַ֤ךְ אֶת יָד/וֹ֙ עַל רֹאשׁ֔/וֹ וְ/שָׁחַ֣ט אֹת֔/וֹ לִ/פְנֵ֖י אֹ֣הֶל מוֹעֵ֑ד וְ֠/זָרְקוּ בְּנֵ֨י אַהֲרֹ֧ן אֶת דָּמ֛/וֹ עַל הַ/מִּזְבֵּ֖חַ סָבִֽיב", "en": {"kjv": "And he shall lay his hand upon the head of it, and kill it before the tabernacle of the congregation: and the sons of Aaron shall sprinkle the blood thereof upon the altar round about.", "web": "and he shall lay his hand on its head, and kill it before the Tent of Meeting; and the sons of Aaron shall sprinkle its blood around on the altar.", "bsb": "He must lay his hand on its head and slaughter it in front of the Tent of Meeting. Then Aaron’s sons shall sprinkle its blood on all sides of the altar.", "asv": "and he shall lay his hand upon the head of it, and kill it before the tent of meeting; and the sons of Aaron shall sprinkle the blood thereof upon the altar round about.", "ylt": "and hath laid his hand on its head, and hath slaughtered it before the tent of meeting, and sons of Aaron have sprinkled its blood on the altar round about;", "tyndale": "and put his hande apon the head of it and kyll it before the tabernacle of witnesse and the sonnes of Aaron shall sprinkle the bloude thereof apon the alter rounde aboute.", "dra": "He shall put his hand upon the head thereof: and shall immolate it in the entry of the tabernacle of the testimony. And the sons of Aaron shall pour the blood thereof round about upon the altar.", "bbe": "And let him put his hand on the head of it and put it to death before the Tent of meeting; and the sons of Aaron are to put some of its blood on and round the altar.", "geneva": "And shall put his hande vpon the head of it, and kill it before the Tabernacle of the Congregation, and the sonnes of Aaron shall sprinkle the blood thereof vpon the altar round about.", "wycliffe": "he schal sette his hond on the heed therof, and he schal offre it in to the entryng of the tabernacle of witnessyng; and the sones of Aaron schulen schede the blood therof bi the cumpas of the auter.", "rotherham": "And he shall lean his hand upon its head, and shall slay it before the tent of meeting,—and the sons of Aaron shall dash its blood against the altar, round about.", "darby": "And he shall lay his hand on the head of it, and slaughter it before the tent of meeting; and the sons of Aaron shall sprinkle the blood thereof on the altar round about.", "twenty": "", "jps": "And he shall lay his hand upon the head of it, and kill it before the tent of meeting; and the sons of Aaron shall dash the blood thereof against the altar round about.", "acv": "And he shall lay his hand upon the head of it, and kill it before the tent of meeting. And the sons of Aaron shall sprinkle the blood of it upon the altar round about.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall lay his hand upon the head of it, and kill it before the tabernacle of the congregation: and the sons of Aaron shall sprinkle its blood upon the altar round about.", "vulgate": "ponet manum suam super caput eius immolabitque eam in introitu tabernaculi testimonii et fundent filii Aaron sanguinem eius per altaris circuitum;", "brenton": "And he shall lay his hands on its head; and they shall slay it before the Lord by the doors of the tabernacle of witness; and the priests the sons of Aaron shall pour out the blood on the altar round about."}}, {"v": 14, "ref": "3:14", "o": "וְ/הִקְרִ֤יב מִמֶּ֨/נּוּ֙ קָרְבָּנ֔/וֹ אִשֶּׁ֖ה לַֽ/יהוָ֑ה אֶת הַ/חֵ֨לֶב֙ הַֽ/מְכַסֶּ֣ה אֶת הַ/קֶּ֔רֶב וְ/אֵת֙ כָּל הַ/חֵ֔לֶב אֲשֶׁ֖ר עַל הַ/קֶּֽרֶב", "en": {"kjv": "And he shall offer thereof his offering, even an offering made by fire unto the Lord; the fat that covereth the inwards, and all the fat that is upon the inwards,", "web": "He shall offer from it as his offering, an offering made by fire to Yahweh; the fat that covers the innards, and all the fat that is on the innards,", "bsb": "And from his offering he shall present an offering made by fire to the LORD: the fat that covers the entrails, all the fat that is on them,", "asv": "And he shall offer thereof his oblation, even an offering made by fire unto Jehovah; the fat that covereth the inwards, and all the fat that is upon the inwards,", "ylt": "and he hath brought near from it his offering, a fire-offering to Jehovah, the fat which is covering the inwards, and all the fat which is on the inwards,", "tyndale": "And he shall brynge thereof his offrynge vnto the Lordes sacrifyce: the fatt that couereth the inwardes and all the fatt that is apo the inwardes", "dra": "And they shall take of it for the food of the Lord's fire, the fat that covereth the belly, and that covereth all the vital parts:", "bbe": "And of it let him make his offering, an offering made by fire to the Lord; the fat covering the inside parts and all the fat on the inside parts,", "geneva": "Then he shall offer thereof his offring, euen an offring made by fire vnto the Lord, the fat that couereth the inwardes, and all the fatte that is vpon the inwardes.", "wycliffe": "And thei schulen take therof, in to `the fedyng of the Lordis fier, the fatnesse that hilith the wombe, and that hilith alle the entrailis,", "rotherham": "Then shall he bring near therefrom as his oblation an altar-flame unto Yahweh,—the fat that covereth the inwards, and all the fat that is upon the inwards;", "darby": "And he shall present thereof his offering, an offering by fire to Jehovah; the fat that covereth the inwards and all the fat that is on the inwards,", "twenty": "", "jps": "And he shall present thereof his offering, even an offering made by fire unto HaShem: the fat that covereth the inwards, and all the fat that is upon the inwards,", "acv": "And he shall offer his oblation from it, even an offering made by fire to Jehovah. He shall take away the fat that covers the innards, and all the fat that is upon the innards,", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall offer of it his offering, [even] an offering made by fire to the LORD; the fat that covereth the inwards, and all the fat that [is] upon the inwards,", "vulgate": "tollentque ex ea in pastum ignis dominici adipem qui operit ventrem et qui tegit universa vitalia;", "brenton": "And he shall offer of it a burnt-offering to the Lord, even the fat that covers the belly, and all the fat that is on the belly."}}, {"v": 15, "ref": "3:15", "o": "וְ/אֵת֙ שְׁתֵּ֣י הַ/כְּלָיֹ֔ת וְ/אֶת הַ/חֵ֨לֶב֙ אֲשֶׁ֣ר עֲלֵ/הֶ֔ן אֲשֶׁ֖ר עַל הַ/כְּסָלִ֑ים וְ/אֶת הַ/יֹּתֶ֨רֶת֙ עַל הַ/כָּבֵ֔ד עַל הַ/כְּלָיֹ֖ת יְסִירֶֽ/נָּה", "en": {"kjv": "And the two kidneys, and the fat that is upon them, which is by the flanks, and the caul above the liver, with the kidneys, it shall he take away.", "web": "and the two kidneys, and the fat that is on them, which is by the loins, and the cover on the liver, with the kidneys, he shall take away.", "bsb": "both kidneys with the fat on them near the loins, and the lobe of the liver, which he is to remove with the kidneys.", "asv": "and the two kidneys, and the fat that is upon them, which is by the loins, and the caul upon the liver, with the kidneys, shall he take away.", "ylt": "and the two kidneys, and the fat which is upon them, which is on the flanks, and the redundance above the liver, (beside the kidneys he doth turn it aside),", "tyndale": "and the .ij. kydneyes and the fatt that lyeth apon them and apon the loynes, and the kall that is apo the lyuer he shall take awaye with the kydneyes.", "dra": "The two little kidneys with the caul that is upon them which is by the flanks, and the fat of the liver with the little kidneys.", "bbe": "And the two kidneys, with the fat on them, which is by the top part of the legs, and the fat joining the liver and the kidneys, let him take away;", "geneva": "Also hee shall take away the two kidneis, and the fat that is vpon them, and vpon ye flankes, and the kall vpon the liuer with the kidneis.", "wycliffe": "and twei litle reynes with the calle which is on tho bisidis ilion, and the fatnesse of the mawe, with the entrails that cleuen to the litle reynes.", "rotherham": "and the two kidneys, and the fat that is on them which is on the loins,—the caul upon the liver, on the kidneys, shall he remove it.", "darby": "and the two kidneys, and the fat that is on them, which is by the flanks, and the net above the liver which he shall take away as far as the kidneys;", "twenty": "", "jps": "and the two kidneys, and the fat that is upon them, which is by the loins, and the lobe above the liver, which he shall take away by the kidneys.", "acv": "and the two kidneys, and the fat that is upon them, which is by the loins, and the caul upon the liver, with the kidneys.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the two kidneys, and the fat that [is] upon them, which [is] by the flanks, and the caul above the liver, with the kidneys, that shall he take away.", "vulgate": "duos renunculos cum reticulo qui est super eos iuxta ilia et arvinam iecoris cum renunculis;", "brenton": "And both the kidneys, and all the fat that is upon them, that which is upon the thighs, and the caul of the liver with the kidneys, shall he take away."}}, {"v": 16, "ref": "3:16", "o": "וְ/הִקְטִירָ֥/ם הַ/כֹּהֵ֖ן הַ/מִּזְבֵּ֑חָ/ה לֶ֤חֶם אִשֶּׁה֙ לְ/רֵ֣יחַ נִיחֹ֔חַ כָּל חֵ֖לֶב לַ/יהוָֽה", "en": {"kjv": "And the priest shall burn them upon the altar: it is the food of the offering made by fire for a sweet savour: all the fat is the Lord’s.", "web": "The priest shall burn them on the altar: it is the food of the offering made by fire, for a pleasant aroma; all the fat is Yahweh’s.", "bsb": "Then the priest is to burn the food on the altar as an offering made by fire, a pleasing aroma. All the fat is the LORD’s.", "asv": "And the priest shall burn them upon the altar: it is the food of the offering made by fire, for a sweet savor; all the fat is Jehovah’s.", "ylt": "and the priest hath made them a perfume on the altar--bread of a fire-offering, for sweet fragrance; all the fat is Jehovah's.", "tyndale": "And the preast shall burne them apo the alter to fede the Lordes sacrifyce wyth all ad to make a swete sauoure.", "dra": "And the priest shall burn them upon the altar, for the food of the fire, and of a most sweet savour. All the fat shall be the Lord's.", "bbe": "That it may be burned by the priest on the altar; it is the food of the offering made by fire for a sweet smell: all the fat is the Lord's.", "geneva": "So the Priest shall burne them vpon the altar, as the meate of an offering made by fire for a sweete sauour: all the fatte is the Lordes.", "wycliffe": "And the preest schal brenne tho on the auter, in to the fedyng of fier, and of swettest odour; al the fatnesse schal be the Lordis,", "rotherham": "Then shall the priest make a perfume at the altar,—the food of an altar-flame for a satisfying odour,—all the fat—unto Yahweh.", "darby": "and the priest shall burn them on the altar: [it is] the food of the offering by fire for a sweet odour. All the fat [shall be] Jehovah's.", "twenty": "", "jps": "And the priest shall make them smoke upon the altar; it is the food of the offering made by fire, for a sweet savour; all the fat is HaShem'S.", "acv": "And the priest shall burn them upon the altar. It is the food of the offering made by fire, for a sweet savor. All the fat is Jehovah's.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall burn them upon the altar: [it is] the food of the offering made by fire for a sweet savor: all the fat [is] the LORD'S.", "vulgate": "adolebitque ea sacerdos super altare in alimoniam ignis et suavissimi odoris omnis adeps Domini erit;", "brenton": "And the priest shall offer it upon the altar: it is a burnt-offering, a smell of sweet savour to the Lord. All the fat belongs to the Lord."}}, {"v": 17, "ref": "3:17", "o": "חֻקַּ֤ת עוֹלָם֙ לְ/דֹרֹ֣תֵי/כֶ֔ם בְּ/כֹ֖ל מֽוֹשְׁבֹתֵי/כֶ֑ם כָּל חֵ֥לֶב וְ/כָל דָּ֖ם לֹ֥א תֹאכֵֽלוּ", "en": {"kjv": "It shall be a perpetual statute for your generations throughout all your dwellings, that ye eat neither fat nor blood.", "web": "“‘It shall be a perpetual statute throughout your generations in all your dwellings, that you shall eat neither fat nor blood.’”", "bsb": "This is a permanent statute for the generations to come, wherever you live: You must not eat any fat or any blood.”", "asv": "It shall be a perpetual statute throughout your generations in all your dwellings, that ye shall eat neither fat nor blood.", "ylt": "`A statute age-during to your generations in all your dwellings: any fat or any blood ye do not eat.'", "tyndale": "And thus shal all the fatt be the Lordes and it shalbe a lawe forever amonge youre generacions after you in youre dwellynge places: that ye eate nether fatt nor bloude.", "dra": "By a perpetual law for your generations, and in all your habitations: neither blood nor fat shall you eat at all.", "bbe": "Let it be an order for ever, through all your generations, in all your houses, that you are not to take fat or blood for food.", "geneva": "This shalbe a perpetual ordinance for your generations, throughout al your dwellings, so that ye shall eate neither fatte nor blood.", "wycliffe": "by euerlastynge riyt in generaciouns, and in alle youre dwellyng placis, nether in ony maner ye schulen ete blood, nethir fatnesse.", "rotherham": "An age-abiding statute to your generations, in all your dwellings,—none of the fat nor of the blood, shall ye eat.", "darby": "[It is] an everlasting statute for your generations throughout all your dwellings: no fat and no blood shall ye eat.", "twenty": "", "jps": "It shall be a perpetual statute throughout your generations in all your dwellings, that ye shall eat neither fat nor blood.", "acv": "It shall be a perpetual statute throughout your generations in all your dwellings, that ye shall eat neither fat nor blood.", "anderson": "", "haweis": "", "noyes": "", "webster": "[It shall be] a perpetual statute for your generations throughout all your dwellings, that ye eat neither fat nor blood.", "vulgate": "iure perpetuo in generationibus et cunctis habitaculis vestris nec adipes nec sanguinem omnino comedetis;", "brenton": "It is a perpetual statute throughout your generations, in all your habitations; ye shall eat no fat and no blood."}}]}, {"c": 4, "verses": [{"v": 1, "ref": "4:1", "o": "וַ/יְדַבֵּ֥ר יְהוָ֖ה אֶל מֹשֶׁ֥ה לֵּ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh spoke to Moses, saying,", "bsb": "Then the LORD said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde talked with Moses saynge:", "dra": "And the Lord spoke to Moses, saying:", "bbe": "And the Lord said to Moses,", "geneva": "Moreouer the Lord spake vnto Moses, saying,", "wycliffe": "And the Lord spak to Moises, and seide, Speke thou to the sones of Israel,", "rotherham": "And Yahweh spake, unto Moses, saying:", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses, saying:", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "locutusque est Dominus ad Mosen dicens;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 2, "ref": "4:2", "o": "דַּבֵּ֞ר אֶל בְּנֵ֣י יִשְׂרָאֵ֘ל לֵ/אמֹר֒ נֶ֗פֶשׁ כִּֽי תֶחֱטָ֤א בִ/שְׁגָגָה֙ מִ/כֹּל֙ מִצְוֺ֣ת יְהוָ֔ה אֲשֶׁ֖ר לֹ֣א תֵעָשֶׂ֑ינָה וְ/עָשָׂ֕ה מֵ/אַחַ֖ת מֵ/הֵֽנָּה", "en": {"kjv": "Speak unto the children of Israel, saying, If a soul shall sin through ignorance against any of the commandments of the Lord concerning things which ought not to be done, and shall do against any of them:", "web": "“Speak to the children of Israel, saying, ‘If anyone sins unintentionally, in any of the things which Yahweh has commanded not to be done, and does any one of them:", "bsb": "“Tell the Israelites to do as follows with one who sins unintentionally against any of the LORD’s commandments and does what is forbidden by them:", "asv": "Speak unto the children of Israel, saying, If any one shall sin unwittingly, in any of the things which Jehovah hath commanded not to be done, and shall do any one of them:", "ylt": "`Speak unto the sons of Israel, saying, When a person doth sin through ignorance against any of the commands of Jehovah regarding things which are not to be done, and hath done something against one of these--", "tyndale": "speake vnto the childern of Israel ad saye: when a soule synneth thorow ignoraunce and hath done any of those thinges which the Lorde hath forbydden in his commaundmentes to be done:", "dra": "Say to the children of Israel: The soul that sinneth through ignorance, and doth any thing concerning any of the commandments of the Lord, which he commanded not to be done:", "bbe": "Say to the children of Israel: These are the offerings of anyone who does wrong through error, doing any of the things which by the Lord's order are not to be done:", "geneva": "Speake vnto the children of Israel, saying, If any shall sinne through ignorance, in any of the commandementes of the Lord, (which ought not to be done) but shall doe contrary to any of them,", "wycliffe": "Whanne a soule hath do synne bi ignoraunce, and hath do ony thing of alle comaundementis `of the Lord, whiche he comaundide that tho schulen not be don; if a preest which is anoyntid,", "rotherham": "Speak thou unto the sons of Israel, saying—When any person, shall sin by mistake, departing from any of the commandments of Yahweh, as to things which should not be done, and shall do any one of them,—", "darby": "Speak unto the children of Israel, saying, If a soul shall sin through inadvertence against any of the commandments of Jehovah [in things] that ought not to be done, and do any of them;", "twenty": "", "jps": "Speak unto the children of Israel, saying: If any one shall sin through error, in any of the things which HaShem hath commanded not to be done, and shall do any one of them:", "acv": "Speak to the sons of Israel, saying, If a soul shall sin unwittingly, in any of the things which Jehovah has commanded not to be done, and shall do any one of them,", "anderson": "", "haweis": "", "noyes": "", "webster": "Speak to the children of Israel, saying, If a soul shall sin through ignorance against any of the commandments of the LORD [concerning things] which ought not to be done, and shall violate any of them:", "vulgate": "loquere filiis Israhel anima cum peccaverit per ignorantiam et de universis mandatis Domini quae praecepit ut non fierent quippiam fecerit;", "brenton": "Speak to the children of Israel, saying, If a soul shall sin unwillingly before the Lord, in any of the commandments of the Lord concerning things which he ought not to do, and shall do some of them;"}}, {"v": 3, "ref": "4:3", "o": "אִ֣ם הַ/כֹּהֵ֧ן הַ/מָּשִׁ֛יחַ יֶחֱטָ֖א לְ/אַשְׁמַ֣ת הָ/עָ֑ם וְ/הִקְרִ֡יב עַ֣ל חַטָּאת/וֹ֩ אֲשֶׁ֨ר חָטָ֜א פַּ֣ר בֶּן בָּקָ֥ר תָּמִ֛ים לַ/יהוָ֖ה לְ/חַטָּֽאת", "en": {"kjv": "If the priest that is anointed do sin according to the sin of the people; then let him bring for his sin, which he hath sinned, a young bullock without blemish unto the Lord for a sin offering.", "web": "if the anointed priest sins so as to bring guilt on the people, then let him offer for his sin, which he has sinned, a young bull without defect to Yahweh for a sin offering.", "bsb": "If the anointed priest sins, bringing guilt on the people, he must bring to the LORD a young bull without blemish as a sin offering for the sin he has committed.", "asv": "if the anointed priest shall sin so as to bring guilt on the people, then let him offer for his sin, which he hath sinned, a young bullock without blemish unto Jehovah for a sin-offering.", "ylt": "`If the priest who is anointed doth sin according to the guilt of the people, then he hath brought near for his sin which he hath sinned a bullock, a son of the herd, a perfect one, to Jehovah, for a sin-offering,", "tyndale": "Yf the preast that is anoynted synne and make the people to doo amysse he shall brynge for his synne which he hath done: an oxe wythout blemysh vnto the Lorde for a synneoffrynge.", "dra": "If the priest that is anointed shall sin, making the people to offend, he shall offer to the Lord for his sin a calf without blemish.", "bbe": "If the chief priest by doing wrong becomes a cause of sin to the people, then let him give to the Lord for the sin which he has done, an ox, without any mark, for a sin-offering.", "geneva": "If the Priest that is anointed doe sinne (according to the sinne of the people) then shall he offer, for his sinne which hee hath sinned, a yong bullocke without blemish vnto the Lord for a sinne offring,", "wycliffe": "hath do synne, makynge the puple to trespasse, he schal offre for his synne a calf without wem to the Lord.", "rotherham": "If, the anointed priest, shall sin, so as to bring guilt upon the people, then shall he bring near for his sin which he hath committed a choice young bullock without defect, unto Yahweh as a sin-bearer.", "darby": "if the priest that is anointed sin according to the trespass of the people; then for his sin which he hath sinned shall he present a young bullock without blemish to Jehovah for a sin-offering.", "twenty": "", "jps": "if the anointed priest shall sin so as to bring guilt on the people, then let him offer for his sin, which he hath sinned, a young bullock without blemish unto HaShem for a sin-offering.", "acv": "if the anointed priest shall sin so as to bring guilt on the people, then let him offer for his sin, which he has sinned, a young bullock without blemish to Jehovah for a sin offering.", "anderson": "", "haweis": "", "noyes": "", "webster": "If the priest that is anointed shall sin according to the sin of the people; then let him bring, for his sin which he hath sinned, a young bullock without blemish to the LORD for a sin-offering.", "vulgate": "si sacerdos qui est unctus peccaverit delinquere faciens populum offeret pro peccato suo vitulum inmaculatum Domino;", "brenton": "if the anointed priest sin so as to cause the people to sin, then shall he bring for his sin, which he has sinned, an unblemished calf of the herd to the Lord for his sin."}}, {"v": 4, "ref": "4:4", "o": "וְ/הֵבִ֣יא אֶת הַ/פָּ֗ר אֶל פֶּ֛תַח אֹ֥הֶל מוֹעֵ֖ד לִ/פְנֵ֣י יְהוָ֑ה וְ/סָמַ֤ךְ אֶת יָד/וֹ֙ עַל רֹ֣אשׁ הַ/פָּ֔ר וְ/שָׁחַ֥ט אֶת הַ/פָּ֖ר לִ/פְנֵ֥י יְהוָֽה", "en": {"kjv": "And he shall bring the bullock unto the door of the tabernacle of the congregation before the Lord; and shall lay his hand upon the bullock’s head, and kill the bullock before the Lord.", "web": "He shall bring the bull to the door of the Tent of Meeting before Yahweh; and he shall lay his hand on the head of the bull, and kill the bull before Yahweh.", "bsb": "He must bring the bull to the entrance to the Tent of Meeting before the LORD, lay his hand on the bull’s head, and slaughter it before the LORD.", "asv": "And he shall bring the bullock unto the door of the tent of meeting before Jehovah; and he shall lay his hand upon the head of the bullock, and kill the bullock before Jehovah.", "ylt": "and he hath brought in the bullock unto the opening of the tent of meeting before Jehovah, and hath laid his hand on the head of the bullock, and hath slaughtered the bullock before Jehovah.", "tyndale": "And he shall brynge the oxe vnto the dore of the tabernacle of wytnesse before the Lorde, and shall put his hande apon the oxes heade and kyll him before the Lorde.", "dra": "And he shall bring it to the door of the testimony before the Lord: and shall put his hand upon the head thereof, and shall sacrifice it to the Lord.", "bbe": "And he is to take the ox to the door of the Tent of meeting before the Lord; and put his hand on its head and put it to death before the Lord.", "geneva": "And hee shall bring the bullocke vnto the dore of the Tabernacle of the Congregation before the Lord, and shall put his hande vpon the bullocks head, and kill the bullocke before the Lord.", "wycliffe": "And he schal brynge it to the dore of the tabernacle of witnessyng, bifor the Lord, and he schal sette hond on the heed therof, and he schal offre it to the Lord.", "rotherham": "And he shall bring in the bullock unto the entrance of the tent of meeting, before Yahweh,—and shall lean his hand upon the head of the bullock, and shall slay the bullock before Yahweh.", "darby": "And he shall bring the bullock to the entrance of the tent of meeting before Jehovah; and shall lay his hand on the bullock's head, and slaughter the bullock before Jehovah.", "twenty": "", "jps": "And he shall bring the bullock unto the door of the tent of meeting before HaShem; and he shall lay his hand upon the head of the bullock, and kill the bullock before HaShem.", "acv": "And he shall bring the bullock to the door of the tent of meeting before Jehovah. And he shall lay his hand upon the head of the bullock, and kill the bullock before Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall bring the bullock to the door of the tabernacle of the congregation before the LORD; and shall lay his hand upon the bullock's head, and kill the bullock before the LORD.", "vulgate": "et adducet illum ad ostium tabernaculi testimonii coram Domino ponetque manum super caput eius et immolabit eum Domino;", "brenton": "And he shall bring the calf to the door of the tabernacle of witness before the Lord, and he shall put his hand on the head of the calf before the Lord, and shall slay the calf in the presence of the Lord."}}, {"v": 5, "ref": "4:5", "o": "וְ/לָקַ֛ח הַ/כֹּהֵ֥ן הַ/מָּשִׁ֖יחַ מִ/דַּ֣ם הַ/פָּ֑ר וְ/הֵבִ֥יא אֹת֖/וֹ אֶל אֹ֥הֶל מוֹעֵֽד", "en": {"kjv": "And the priest that is anointed shall take of the bullock’s blood, and bring it to the tabernacle of the congregation:", "web": "The anointed priest shall take some of the blood of the bull, and bring it to the Tent of Meeting.", "bsb": "Then the anointed priest shall take some of the bull’s blood and bring it into the Tent of Meeting.", "asv": "And the anointed priest shall take of the blood of the bullock, and bring it to the tent of meeting:", "ylt": "`And the priest who is anointed hath taken of the blood of the bullock, and hath brought it in unto the tent of meeting,", "tyndale": "And the preast that is anoynted shall take of the oxes bloude and brynge it in to the tabernacle of witnesse", "dra": "He shall take also of the blood of the calf: and carry it into the tabernacle of the testimony.", "bbe": "And the chief priest is to take some of its blood and take it to the Tent of meeting;", "geneva": "And the Priest that is anointed shall take of the bullocks blood, and bring it into the Tabernacle of the Congregation.", "wycliffe": "And he schal take vp of the blood `of the calf, and schal brynge it in to the tabernacle of witnessyng.", "rotherham": "And the anointed priest shall take of the blood of the bullock,—and bring it into the tent of meeting;", "darby": "And the priest that is anointed shall take of the bullock's blood, and bring it into the tent of meeting;", "twenty": "", "jps": "And the anointed priest shall take of the blood of the bullock, and bring it to the tent of meeting.", "acv": "And the anointed priest shall take of the blood of the bullock, and bring it to the tent of meeting.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest that is anointed shall take of the bullock's blood, and bring it to the tabernacle of the congregation:", "vulgate": "hauriet quoque de sanguine vituli inferens illud in tabernaculum testimonii;", "brenton": "And the anointed priest who has been consecrated having received of the blood of the calf, shall then bring it into the tabernacle of witness."}}, {"v": 6, "ref": "4:6", "o": "וְ/טָבַ֧ל הַ/כֹּהֵ֛ן אֶת אֶצְבָּע֖/וֹ בַּ/דָּ֑ם וְ/הִזָּ֨ה מִן הַ/דָּ֜ם שֶׁ֤בַע פְּעָמִים֙ לִ/פְנֵ֣י יְהוָ֔ה אֶת פְּנֵ֖י פָּרֹ֥כֶת הַ/קֹּֽדֶשׁ", "en": {"kjv": "And the priest shall dip his finger in the blood, and sprinkle of the blood seven times before the Lord, before the vail of the sanctuary.", "web": "The priest shall dip his finger in the blood, and sprinkle some of the blood seven times before Yahweh, before the veil of the sanctuary.", "bsb": "The priest is to dip his finger in the blood and sprinkle some of it seven times before the LORD, in front of the veil of the sanctuary.", "asv": "and the priest shall dip his finger in the blood, and sprinkle of the blood seven times before Jehovah, before the veil of the sanctuary.", "ylt": "and the priest hath dipped his finger in the blood, and sprinkled of the blood seven times before Jehovah, at the front of the vail of the sanctuary;", "tyndale": "and shall dyppe his fynger in the bloude and sprinkle thereof .vij. tymes before the Lorde: euen before the hangynge of the holy place.", "dra": "And having dipped his finger in the blood, he shall sprinkle with it seven times before the Lord, before the veil of the sanctuary.", "bbe": "And the priest is to put his finger in the blood, shaking drops of it before the Lord seven times, in front of the veil of the holy place.", "geneva": "Then the Priest shall dippe his finger in the blood, and sprinkle of the blood seuen times before the Lord, before the vaile of the Sanctuarie.", "wycliffe": "And whanne he hath dippid the fyngir in to the blood, he schal sprenge it seuen sithis bifor the Lord, ayens the veil of the seyntuarie.", "rotherham": "and the priest shall dip his finger in the blood,—and sprinkle of the blood seven times, before Yahweh, in front of the veil of the sanctuary.", "darby": "and the priest shall dip his finger in the blood, and sprinkle of the blood seven times before Jehovah before the veil of the sanctuary;", "twenty": "", "jps": "And the priest shall dip his finger in the blood, and sprinkle of the blood seven times before HaShem, in front of the veil of the sanctuary.", "acv": "And the priest shall dip his finger in the blood, and sprinkle of the blood seven times before Jehovah, before the veil of the sanctuary.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall dip his finger in the blood, and sprinkle of the blood seven times before the LORD, before the vail of the sanctuary.", "vulgate": "cumque intinxerit digitum in sanguinem asperget eo septies coram Domino contra velum sanctuarii;", "brenton": "And the priest shall dip his finger into the blood, and sprinkle of the blood seven times before the Lord, over against the holy veil."}}, {"v": 7, "ref": "4:7", "o": "וְ/נָתַן֩ הַ/כֹּהֵ֨ן מִן הַ/דָּ֜ם עַל קַ֠רְנוֹת מִזְבַּ֨ח קְטֹ֤רֶת הַ/סַּמִּים֙ לִ/פְנֵ֣י יְהוָ֔ה אֲשֶׁ֖ר בְּ/אֹ֣הֶל מוֹעֵ֑ד וְ/אֵ֣ת כָּל דַּ֣ם הַ/פָּ֗ר יִשְׁפֹּךְ֙ אֶל יְסוֹד֙ מִזְבַּ֣ח הָ/עֹלָ֔ה אֲשֶׁר פֶּ֖תַח אֹ֥הֶל מוֹעֵֽד", "en": {"kjv": "And the priest shall put some of the blood upon the horns of the altar of sweet incense before the Lord, which is in the tabernacle of the congregation; and shall pour all the blood of the bullock at the bottom of the altar of the burnt offering, which is at the door of the tabernacle of the congregation.", "web": "The priest shall put some of the blood on the horns of the altar of sweet incense before Yahweh, which is in the Tent of Meeting; and he shall pour out all of rest of the blood of the bull at the base of the altar of burnt offering, which is at the door of the Tent of Meeting.", "bsb": "The priest must then put some of the blood on the horns of the altar of fragrant incense that is before the LORD in the Tent of Meeting. And he is to pour out the rest of the bull’s blood at the base of the altar of burnt offering at the entrance to the Tent of Meeting.", "asv": "And the priest shall put of the blood upon the horns of the altar of sweet incense before Jehovah, which is in the tent of meeting; and all the blood of the bullock shall he pour out at the base of the altar of burnt-offering, which is at the door of the tent of meeting.", "ylt": "and the priest hath put of the blood on the horns of the altar of spice-perfume before Jehovah, which is in the tent of meeting, and all the blood of the bullock he doth pour out at the foundation of the altar of the burnt-offering, which is at the opening of the tent of meeting.", "tyndale": "And he shall put some of the bloude apon the hornes of the alter of swete cens before the Lorde which is in the tabernacle of witnesse, and shall poure all the bloude of the oxe apon the botome of the alter of burntofferynges which is by the dore of the tabernacle of witnesse.", "dra": "And he shall put some of the same blood upon the horns of the altar of the sweet incense most acceptable to the Lord, which is in the tabernacle of the testimony. And he shall pour all the rest of the blood at the foot of the altar of holocaust in the entry of the tabernacle.", "bbe": "And the priest is to put some of the blood on the horns of the altar on which perfume is burned before the Lord in the Tent of meeting, draining out all the rest of the blood of the ox at the base of the altar of burned offering which is at the door of the Tent of meeting.", "geneva": "The Priest also shall put some of the blood before the Lord, vpon the hornes of the altar of sweete incense, which is in the Tabernacle of the Congregation, then shall hee powre all the rest of the blood of the bullocke at the foote of the altar of burnt offring, which is at the doore of the Tabernacle of the Congregation.", "wycliffe": "And he schal putte of the same blood on the corners of the auter of encense moost acceptable to the Lord, which auter is in the tabernacle of witnessyng; sotheli he schal schede al the `tother blood in to the foundement of the auter of brent sacrifice in the entryng of the tabernacle.", "rotherham": "Then shall the priest put of the blood upon the horns of the altar of fragrant incense before Yahweh, which is in the tent of meeting,—and, all the [remainder of the] blood of the bullock, shall he pour out at the base of the altar of ascending-sacrifice, which is at the entrance of the tent of meeting,", "darby": "and the priest shall put of the blood on the horns of the altar of fragrant incense, which is in the tent of meeting, before Jehovah; and he shall pour all the blood of the bullock at the bottom of the altar of burnt-offering, which is at the entrance of the tent of meeting.", "twenty": "", "jps": "And the priest shall put of the blood upon the horns of the altar of sweet incense before HaShem, which is in the tent of meeting; and all the remaining blood of the bullock shall he pour out at the base of the altar of burnt-offering, which is at the door of the tent of meeting.", "acv": "And the priest shall put of the blood upon the horns of the altar of sweet incense before Jehovah, which is in the tent of meeting, and all the blood of the bullock he shall pour out at the base of the altar of burnt offering, which is at the door of the tent of meeting.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall put [some] of the blood upon the horns of the altar of sweet incense before the LORD, which [is] in the tabernacle of the congregation; and shall pour all the blood of the bullock at the bottom of the altar of the burnt-offering, which [is at] the door of the tabernacle of the congregation.", "vulgate": "ponetque de eodem sanguine super cornua altaris thymiamatis gratissimi Domino quod est in tabernaculo testimonii omnem autem reliquum sanguinem fundet in basim altaris holocausti in introitu tabernaculi;", "brenton": "And the priest shall put of the blood of the calf on the horns of the altar of the compound incense which is before the Lord, which is in the tabernacle of witness; and all the blood of the calf shall he pour out by the foot of the altar of whole-burnt-offerings, which is by the doors of the tabernacle of witness."}}, {"v": 8, "ref": "4:8", "o": "וְ/אֶת כָּל חֵ֛לֶב פַּ֥ר הַֽ/חַטָּ֖את יָרִ֣ים מִמֶּ֑/נּוּ אֶת הַ/חֵ֨לֶב֙ הַֽ/מְכַסֶּ֣ה עַל הַ/קֶּ֔רֶב וְ/אֵת֙ כָּל הַ/חֵ֔לֶב אֲשֶׁ֖ר עַל הַ/קֶּֽרֶב", "en": {"kjv": "And he shall take off from it all the fat of the bullock for the sin offering; the fat that covereth the inwards, and all the fat that is upon the inwards,", "web": "He shall take all the fat of the bull of the sin offering off of it; the fat that covers the innards, and all the fat that is on the innards,", "bsb": "Then he shall remove all the fat from the bull of the sin offering—the fat that covers the entrails, all the fat that is on them,", "asv": "And all the fat of the bullock of the sin-offering he shall take off from it; the fat that covereth the inwards, and all the fat that is upon the inwards,", "ylt": "`And all the fat of the bullock of the sin-offering he doth lift up from it, the fat which is covering over the inwards, and all the fat which is on the inwards,", "tyndale": "And he shall take awaye all the fatt of the oxe that is the synneofferynge: the fatt that couereth the inwardes and all the fatt that is aboute them,", "dra": "And he shall take off the fat of the calf for the sin offering, as well that which covereth the entrails, as all the inwards:", "bbe": "And he is to take away all the fat of the ox of the sin-offering; the fat covering the inside parts and all the fat of the inside parts,", "geneva": "And hee shall take away all the fat of the bullocke for the sinne offring: to wit, the fat that couereth the inwardes, and all the fatte that is about the inwardes.", "wycliffe": "And he schal offre for synne the ynnere fatnesse of the calf, as well it that hilith the entrails, as alle thingis that ben with ynne,", "rotherham": "And all the fat of the sin-bearing bullock, shall he heave up therefrom,—the fat that covereth over the inwards, and all the fat that is upon the inwards;", "darby": "And all the fat of the bullock of the sin-offering shall he take off from it; the fat that covereth the inwards, and all the fat that is on the inwards,", "twenty": "", "jps": "And all the fat of the bullock of the sin-offering he shall take off from it; the fat that covereth the inwards, and all the fat that is upon the inwards,", "acv": "And all the fat of the bullock of the sin offering he shall take off from it. The fat that covers the innards, and all the fat that is upon the innards,", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall take off from it all the fat of the bullock for the sin-offering; the fat that covereth the inwards, and all the fat that [is] upon the inwards,", "vulgate": "et adipem vituli auferet pro peccato tam eum qui operit vitalia quam omnia quae intrinsecus sunt;", "brenton": "and all the fat of the calf of the sin-offering shall he take off from it; the fat that covers the inwards, and all the fat that is on the inwards,"}}, {"v": 9, "ref": "4:9", "o": "וְ/אֵת֙ שְׁתֵּ֣י הַ/כְּלָיֹ֔ת וְ/אֶת הַ/חֵ֨לֶב֙ אֲשֶׁ֣ר עֲלֵי/הֶ֔ן אֲשֶׁ֖ר עַל הַ/כְּסָלִ֑ים וְ/אֶת הַ/יֹּתֶ֨רֶת֙ עַל הַ/כָּבֵ֔ד עַל הַ/כְּלָי֖וֹת יְסִירֶֽ/נָּה", "en": {"kjv": "And the two kidneys, and the fat that is upon them, which is by the flanks, and the caul above the liver, with the kidneys, it shall he take away,", "web": "and the two kidneys, and the fat that is on them, which is by the loins, and the cover on the liver, with the kidneys, he shall take away,", "bsb": "both kidneys with the fat on them near the loins, and the lobe of the liver, which he is to remove with the kidneys—", "asv": "and the two kidneys, and the fat that is upon them, which is by the loins, and the caul upon the liver, with the kidneys, shall he take away,", "ylt": "and the two kidneys, and the fat which is on them, which is on the flanks, and the redundance above the liver, (beside the kidneys he doth turn it aside),", "tyndale": "and the .ij. kydneyes with the fatt that lyeth apon the and apon the loynes, and the kall apon the lyuer let them take awaye also with the kydneyes:", "dra": "The two little kidneys, and the caul that is upon them, which is by the flanks, and the fat of the liver with the little kidneys:", "bbe": "And the two kidneys, with the fat on them, which is by the top part of the legs, and the fat joining the liver and the kidneys, he is to take away,", "geneva": "He shall take away also the two kidneis, and the fat that is vpon them, and vpon the flankes, and the kall vpon the liuer with the kidneis,", "wycliffe": "twei litle reynes, and the calle, which is on tho bisidis ilion, and the fatnesse of the mawe,", "rotherham": "and the two kidneys, and the fat that is upon them which is upon the loins,—and as for the caul upon the liver, upon the kidneys, shall he remove it:", "darby": "and the two kidneys, and the fat that is on them, which is by the flanks, and the net above the liver which he shall take away as far as the kidneys,", "twenty": "", "jps": "and the two kidneys, and the fat that is upon them, which is by the loins, and the lobe above the liver, which he shall take away by kidneys,", "acv": "and the two kidneys, and the fat that is upon them, which is by the loins, and the caul upon the liver, with the kidneys, he shall take away,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the two kidneys, and the fat that [is] upon them, which [is] by the flanks, and the caul above the liver, with the kidneys, that shall he take away,", "vulgate": "duos renunculos et reticulum quod est super eos iuxta ilia et adipem iecoris cum renunculis;", "brenton": "and the two kidneys, and the fat that is upon them, which is on the thighs, and the caul that is on the liver with the kidneys, them shall he take away,"}}, {"v": 10, "ref": "4:10", "o": "כַּ/אֲשֶׁ֣ר יוּרַ֔ם מִ/שּׁ֖וֹר זֶ֣בַח הַ/שְּׁלָמִ֑ים וְ/הִקְטִירָ/ם֙ הַ/כֹּהֵ֔ן עַ֖ל מִזְבַּ֥ח הָ/עֹלָֽה", "en": {"kjv": "As it was taken off from the bullock of the sacrifice of peace offerings: and the priest shall burn them upon the altar of the burnt offering.", "web": "as it is taken off of the bull of the sacrifice of peace offerings. The priest shall burn them on the altar of burnt offering.", "bsb": "just as the fat is removed from the ox of the peace offering. Then the priest shall burn them on the altar of burnt offering.", "asv": "as it is taken off from the ox of the sacrifice of peace-offerings: and the priest shall burn them upon the altar of burnt-offering.", "ylt": "as it is lifted up from the ox of the sacrifice of the peace-offerings; and the priest hath made them a perfume on the altar of the burnt-offering.", "tyndale": "as it was taken from the oxe of the peaceoffrynge and let the preast burne them apon the altare of burntofferynges.", "dra": "As it is taken off from the calf of the sacrifice of peace offerings. And he shall burn them upon the altar of holocaust.", "bbe": "As it is taken from the ox of the peace-offering; and it is to be burned by the priest on the altar of burned offerings.", "geneva": "As it was taken away from the bullock of the peace offrings, and the Priest shall burne them vpon the altar of burnt offring.", "wycliffe": "with the litle reines, as it is offrid of the calf of the sacrifice of pesible thingis; and he schal brenne tho on the auter of brent sacrifice.", "rotherham": "just as it is heaved up from the ox of the peace-offering,—and the priest shall make of them a perfume on the altar of ascending-sacrifice,", "darby": "as it is taken off from the ox of the sacrifice of peace-offering; and the priest shall burn them on the altar of burnt-offering.", "twenty": "", "jps": "as it is taken off from the ox of the sacrifice of peace-offerings; and the priest shall make them smoke upon the altar of burnt-offering.", "acv": "as it is taken off from the ox of the sacrifice of peace offerings. And the priest shall burn them upon the altar of burnt offering.", "anderson": "", "haweis": "", "noyes": "", "webster": "As it was taken off from the bullock of the sacrifice of peace-offerings: and the priest shall burn them upon the altar of the burnt-offering.", "vulgate": "sicut aufertur de vitulo hostiae pacificorum et adolebit ea super altare holocausti;", "brenton": "as he takes it away from the calf of the sacrifice of peace-offering, so shall the priest offer it on the altar of burnt-offering."}}, {"v": 11, "ref": "4:11", "o": "וְ/אֶת ע֤וֹר הַ/פָּר֙ וְ/אֶת כָּל בְּשָׂר֔/וֹ עַל רֹאשׁ֖/וֹ וְ/עַל כְּרָעָ֑י/ו וְ/קִרְבּ֖/וֹ וּ/פִרְשֽׁ/וֹ", "en": {"kjv": "And the skin of the bullock, and all his flesh, with his head, and with his legs, and his inwards, and his dung,", "web": "The bull’s skin, all its flesh, with its head, and with its legs, its innards, and its dung,", "bsb": "But the hide of the bull and all its flesh, with its head and legs and its entrails and dung—", "asv": "And the skin of the bullock, and all its flesh, with its head, and with its legs, and its inwards, and its dung,", "ylt": "`And the skin of the bullock, and all its flesh, besides its head, and besides its legs, and its inwards, and its dung--", "tyndale": "But the skynne of the oxe and all his flesh with his heede, his legges, his inwardes with his donge,", "dra": "But the skin and all the flesh with the head and the feet and the bowels and the dung:", "bbe": "And the skin of the ox and all its flesh, with its head and its legs and its inside parts and its waste,", "geneva": "But the skinne of the bullocke, and all his flesh, with his heade, and his legs, and his inwardes, and his dung shall he beare out.", "wycliffe": "Sotheli he schal bere out of the castels the skyn, and alle the fleischis, with the heed, and feet, and entrails,", "rotherham": "But, as for the skin of the bullock and all its flesh with its head and with its legs,—and its inwards, and its dung,", "darby": "And the skin of the bullock, and all its flesh, with its head, and with its legs, and its inwards, and its dung,", "twenty": "", "jps": "But the skin of the bullock, and all its flesh, with its head, and with its legs, and its inwards, and its dung,", "acv": "And the skin of the bullock, and all its flesh, with its head, and with its legs, and its innards, and its dung,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the skin of the bullock, and all his flesh, with his head, and with his legs, and his inwards, and his dung,", "vulgate": "pellem vero et omnes carnes cum capite et pedibus et intestinis et fimo;", "brenton": "And they shall take the skin of the calf, and all his flesh with the head and the extremities and the belly and the dung,"}}, {"v": 12, "ref": "4:12", "o": "וְ/הוֹצִ֣יא אֶת כָּל הַ֠/פָּר אֶל מִ/ח֨וּץ לַֽ/מַּחֲנֶ֜ה אֶל מָק֤וֹם טָהוֹר֙ אֶל שֶׁ֣פֶךְ הַ/דֶּ֔שֶׁן וְ/שָׂרַ֥ף אֹת֛/וֹ עַל עֵצִ֖ים בָּ/אֵ֑שׁ עַל שֶׁ֥פֶךְ הַ/דֶּ֖שֶׁן יִשָּׂרֵֽף", "en": {"kjv": "Even the whole bullock shall he carry forth without the camp unto a clean place, where the ashes are poured out, and burn him on the wood with fire: where the ashes are poured out shall he be burnt.", "web": "he shall carry the whole bull outside of the camp to a clean place, where the ashes are poured out, and burn it on wood with fire. Where the ashes are poured out, it shall be burned.", "bsb": "all the rest of the bull—he must take outside the camp to a ceremonially clean place where the ashes are poured out, and there he must burn it on a wood fire on the ash heap.", "asv": "even the whole bullock shall he carry forth without the camp unto a clean place, where the ashes are poured out, and burn it on wood with fire: where the ashes are poured out shall it be burnt.", "ylt": "he hath even brought out the whole bullock unto the outside of the camp, unto a clean place, unto the place of the pouring out of the ashes, and he hath burnt it on the wood with fire; beside the place of the pouring out of the ashes it is burnt.", "tyndale": "shall he carye altogither out of the hoste vnto a clene place: euen where the asshes are poured out, and burne hi on wodd with fyre: euen apon the heape of asshes.", "dra": "And the rest of the body, he shall carry forth without the camp into a clean place where the ashes are wont to be poured out: and he shall burn them upon a pile of wood. They shall be burnt in the place where the ashes are poured out.", "bbe": "All the ox, he is to take away outside the circle of the tents into a clean place where the burned waste is put, and there it is to be burned on wood with fire.", "geneva": "So he shall cary the whole bullocke out of the host vnto a cleane place, where the ashes are powred, and shall burne him on ye wood in the fire: where ye ashes are cast out, shall he be burnt.", "wycliffe": "and dung, and the `residue bodi in to a clene place, where aischis ben wont to be sched out; and he schal brenne tho on the heep of trees, whiche schulen be brent in the place of aischis sched out.", "rotherham": "he shall take forth the entire bullock—unto the outside of the camp, unto a clean place unto the outpoured heap of fat-ashes, and shall burn it up on wood in the fire,—upon the outpoured heap of fat-ashes, shall it be burned up.", "darby": "even the whole bullock shall he carry forth outside the camp unto a clean place, where the ashes are poured out, and burn it on wood with fire; where the ashes are poured out shall it be burnt.", "twenty": "", "jps": "even the whole bullock shall he carry forth without the camp unto a clean place, where the ashes are poured out, and burn it on wood with fire; where the ashes are poured out shall it be burnt.", "acv": "even the whole bullock he shall carry forth outside the camp to a clean place, where the ashes are poured out, and burn it on wood with fire. It shall be burnt where the ashes are poured out.", "anderson": "", "haweis": "", "noyes": "", "webster": "Even the whole bullock shall he carry forth without the camp to a clean place, where the ashes are poured out, and burn him on the wood with fire: where the ashes are poured out shall he be burnt.", "vulgate": "et reliquo corpore efferet extra castra in locum mundum ubi cineres effundi solent incendetque ea super lignorum struem quae in loco effusorum cinerum cremabuntur;", "brenton": "and they shall carry out the whole calf out of the camp into a clean place, where they pour out the ashes, and they shall consume it there on wood with fire: it shall be burnt on the ashes poured out."}}, {"v": 13, "ref": "4:13", "o": "וְ/אִ֨ם כָּל עֲדַ֤ת יִשְׂרָאֵל֙ יִשְׁגּ֔וּ וְ/נֶעְלַ֣ם דָּבָ֔ר מֵ/עֵינֵ֖י הַ/קָּהָ֑ל וְ֠/עָשׂוּ אַחַ֨ת מִ/כָּל מִצְוֺ֧ת יְהוָ֛ה אֲשֶׁ֥ר לֹא תֵעָשֶׂ֖ינָה וְ/אָשֵֽׁמוּ", "en": {"kjv": "And if the whole congregation of Israel sin through ignorance, and the thing be hid from the eyes of the assembly, and they have done somewhat against any of the commandments of the Lord concerning things which should not be done, and are guilty;", "web": "“‘If the whole congregation of Israel sins, and the thing is hidden from the eyes of the assembly, and they have done any of the things which Yahweh has commanded not to be done, and are guilty;", "bsb": "Now if the whole congregation of Israel strays unintentionally and the matter escapes the notice of the assembly so that they violate any of the LORD’s commandments and incur guilt by doing what is forbidden,", "asv": "And if the whole congregation of Israel err, and the thing be hid from the eyes of the assembly, and they have done any of the things which Jehovah hath commanded not to be done, and are guilty;", "ylt": "`And if the whole company of Israel err ignorantly, and the thing hath been hidden from the eyes of the assembly, and they have done something against one of all the commands of Jehovah concerning things which are not to be done, and have been guilty;", "tyndale": "Yf the hole comynalte of the childern of Israel synne thorow ygnoraunce and the thynge be hyd from their eyes: so that they haue commytted any of these thinges which the Lorde hath forbidden to be done in his commaundmentes ad haue offended,", "dra": "And if all the multitude of Israel shall be ignorant, and through ignorance shall do that which is against the commandment of the Lord,", "bbe": "And if all the people of Israel do wrong, without anyone's knowledge; if they have done any of the things which by the Lord's order are not to be done, causing sin to come on them;", "geneva": "And if the whole Congregation of Israel shall sinne through ignorance, and the thing be hid from the eyes of the multitude, and haue done against any of the commandements of the Lord which should not be done, and haue offended:", "wycliffe": "That if al the cumpeny of the sones of Israel knowith not, and doith by vnkunnyng that that is ayens the comaundement of the Lord,", "rotherham": "And, if the whole assembly of Israel, shall make a mistake, and a matter be hidden from the eyes of the convocation,—and so they do something, whereby they depart from any of the commandments of Yahweh as to things which should not be done, and become guilty;", "darby": "And if the whole assembly of Israel sin inadvertently, and the thing be hid from the eyes of the congregation, and they do [somewhat against] any of all the commandments of Jehovah [in things] which should not be done, and are guilty;", "twenty": "", "jps": "And if the whole congregation of Israel shall err, the thing being hid from the eyes of the assembly, and do any of the things which HaShem hath commanded not to be done, and are guilty:", "acv": "And if the whole congregation of Israel err, and the thing be hid from the eyes of the assembly, and they have done any of the things which Jehovah has commanded not to be done, and are guilty,", "anderson": "", "haweis": "", "noyes": "", "webster": "And if the whole congregation of Israel shall sin through ignorance, and the thing be hid from the eyes of the assembly, and they have done [somewhat against] any of the commandments of the LORD [concerning things] which should not be done, and are guilty;", "vulgate": "quod si omnis turba Israhel ignoraverit et per inperitiam fecerit quod contra mandatum Domini est;", "brenton": "And if the whole congregation of Israel trespass ignorantly, and a thing should escape the notice of the congregation, and they should do one thing forbidden of any of the commands of the Lord, which ought not to be done, and should transgress:"}}, {"v": 14, "ref": "4:14", "o": "וְ/נֽוֹדְעָה֙ הַֽ/חַטָּ֔את אֲשֶׁ֥ר חָטְא֖וּ עָלֶ֑י/הָ וְ/הִקְרִ֨יבוּ הַ/קָּהָ֜ל פַּ֤ר בֶּן בָּקָר֙ לְ/חַטָּ֔את וְ/הֵבִ֣יאוּ אֹת֔/וֹ לִ/פְנֵ֖י אֹ֥הֶל מוֹעֵֽד", "en": {"kjv": "When the sin, which they have sinned against it, is known, then the congregation shall offer a young bullock for the sin, and bring him before the tabernacle of the congregation.", "web": "when the sin in which they have sinned is known, then the assembly shall offer a young bull for a sin offering, and bring it before the Tent of Meeting.", "bsb": "when they become aware of the sin they have committed, then the assembly must bring a young bull as a sin offering and present it before the Tent of Meeting.", "asv": "when the sin wherein they have sinned is known, then the assembly shall offer a young bullock for a sin-offering, and bring it before the tent of meeting.", "ylt": "when the sin which they have sinned concerning it hath been known, then have the assembly brought near a bullock, a son of the herd, for a sin-offering, and they have brought it in before the tent of meeting;", "tyndale": "ad the synne which they haue synned be afterwarde knowne, than shal they offre an oxe for a synneofferynge ad shall brynge him before the tabernacle of witnesse,", "dra": "And afterwards shall understand their sin: they shall offer for their sin a calf, and shall bring it to the door of the tabernacle.", "bbe": "When the sin which they have done comes to light, then let all the people give an ox for a sin-offering, and take it before the Tent of meeting.", "geneva": "When the sinne which they haue committed shalbe knowen, then the Congregation shall offer a yong bullocke for the sinne, and bring him before the Tabernacle of the Congregation,", "wycliffe": "and aftirward vndirstondith his synne, it schal offre a calf for synne, and it schal brynge the calf to the dore of the tabernacle.", "rotherham": "and the sin shall become known, which they have committed therein, then shall the convocation bring near a choice young bullock as a sin-bearer, yea they shall bring it in. before the tent of meeting;", "darby": "and the sin wherewith they have sinned against it have become known; then the congregation shall present a young bullock for the sin-offering, and shall bring it before the tent of meeting;", "twenty": "", "jps": "when the sin wherein they have sinned is known, then the assembly shall offer a young bullock for a sin-offering, and bring it before the tent of meeting.", "acv": "when the sin by which they have sinned is known, then the assembly shall offer a young bullock for a sin offering, and bring it before the tent of meeting.", "anderson": "", "haweis": "", "noyes": "", "webster": "When the sin which they have sinned against it is known, then the congregation shall offer a young bullock for the sin, and bring him before the tabernacle of the congregation.", "vulgate": "et postea intellexerit peccatum suum offeret vitulum pro peccato adducetque eum ad ostium tabernaculi;", "brenton": "and the sin wherein they have sinned should become known to them, then shall the congregation bring an unblemished calf of the herd for a sin-offering, and they shall bring it to the doors of the tabernacle of witness."}}, {"v": 15, "ref": "4:15", "o": "וְ֠/סָמְכוּ זִקְנֵ֨י הָ/עֵדָ֧ה אֶת יְדֵי/הֶ֛ם עַל רֹ֥אשׁ הַ/פָּ֖ר לִ/פְנֵ֣י יְהוָ֑ה וְ/שָׁחַ֥ט אֶת הַ/פָּ֖ר לִ/פְנֵ֥י יְהוָֽה", "en": {"kjv": "And the elders of the congregation shall lay their hands upon the head of the bullock before the Lord: and the bullock shall be killed before the Lord.", "web": "The elders of the congregation shall lay their hands on the head of the bull before Yahweh; and the bull shall be killed before Yahweh.", "bsb": "The elders of the congregation are to lay their hands on the bull’s head before the LORD, and it shall be slaughtered before the LORD.", "asv": "And the elders of the congregation shall lay their hands upon the head of the bullock before Jehovah; and the bullock shall be killed before Jehovah.", "ylt": "and the elders of the company have laid their hands on the head of the bullock, before Jehovah, and one hath slaughtered the bullock before Jehovah.", "tyndale": "and the elders of the multitude shall put their handes apon his heed before the Lorde", "dra": "And the ancients of the people shall put their hands upon the head thereof before the Lord. And the calf being immolated in the sight of the Lord:", "bbe": "And let the chiefs of the people put their hands on its head before the Lord, and put the ox to death before the Lord.", "geneva": "And the Elders of the Congregation shall put their handes vpon the head of the bullocke before the Lord, and he shall kill the bullocke before the Lord.", "wycliffe": "And the eldere men of the puple schulen sette hondis on the heed therof bifor the Lord; and whanne the calf is offrid in the siyt of the Lord,", "rotherham": "and the elders of the assembly shall lean their hands upon the head of the bullock before Yahweh,—and shall slay the bullock, before Yahweh;", "darby": "and the elders of the assembly shall lay their hands on the head of the bullock before Jehovah; and one shall slaughter the bullock before Jehovah.", "twenty": "", "jps": "And the elders of the congregation shall lay their hands upon the head of the bullock before HaShem; and the bullock shall be killed before HaShem.", "acv": "And the elders of the congregation shall lay their hands upon the head of the bullock before Jehovah, and the bullock shall be killed before Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the elders of the congregation shall lay their hands upon the head of the bullock before the LORD: and the bullock shall be killed before the LORD.", "vulgate": "et ponent seniores populi manus super caput eius coram Domino immolatoque vitulo in conspectu Domini;", "brenton": "And the elders of the congregation shall lay their hands on the head of the calf before the Lord, and they shall slay the calf before the Lord."}}, {"v": 16, "ref": "4:16", "o": "וְ/הֵבִ֛יא הַ/כֹּהֵ֥ן הַ/מָּשִׁ֖יחַ מִ/דַּ֣ם הַ/פָּ֑ר אֶל אֹ֖הֶל מוֹעֵֽד", "en": {"kjv": "And the priest that is anointed shall bring of the bullock’s blood to the tabernacle of the congregation:", "web": "The anointed priest shall bring of the blood of the bull to the Tent of Meeting:", "bsb": "Then the anointed priest is to bring some of the bull’s blood into the Tent of Meeting,", "asv": "And the anointed priest shall bring of the blood of the bullock to the tent of meeting:", "ylt": "`And the priest who is anointed hath brought in of the blood of the bullock unto the tent of meeting,", "tyndale": "And the preast that is anoynted shall brynge of his bloude in to the tabernacle of witnesse,", "dra": "The priest that is anointed shall carry of the blood into the tabernacle of the testimony.", "bbe": "And the priest is to take some of its blood to the Tent of meeting;", "geneva": "Then the Priest that is anointed, shall bring of the bullockes blood into the Tabernacle of the Congregation,", "wycliffe": "the preest which is anoyntid schal bere ynne of his blood in to the tabernacle of witnessyng;", "rotherham": "and the anointed priest shall bring in of the blood of the bullock,—into the tent of meeting;", "darby": "And the priest that is anointed shall bring of the bullock's blood into the tent of meeting;", "twenty": "", "jps": "And the anointed priest shall bring of the blood of the bullock to the tent of meeting.", "acv": "And the anointed priest shall bring of the blood of the bullock to the tent of meeting.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest that is anointed shall bring of the bullock's blood to the tabernacle of the congregation:", "vulgate": "inferet sacerdos qui unctus est de sanguine eius in tabernaculum testimonii;", "brenton": "And the anointed priest shall bring in of the blood of the calf into the tabernacle of witness."}}, {"v": 17, "ref": "4:17", "o": "וְ/טָבַ֧ל הַ/כֹּהֵ֛ן אֶצְבָּע֖/וֹ מִן הַ/דָּ֑ם וְ/הִזָּ֞ה שֶׁ֤בַע פְּעָמִים֙ לִ/פְנֵ֣י יְהוָ֔ה אֵ֖ת פְּנֵ֥י הַ/פָּרֹֽכֶת", "en": {"kjv": "And the priest shall dip his finger in some of the blood, and sprinkle it seven times before the Lord, even before the vail.", "web": "and the priest shall dip his finger in the blood, and sprinkle it seven times before Yahweh, before the veil.", "bsb": "and he is to dip his finger in the blood and sprinkle it seven times before the LORD in front of the veil.", "asv": "and the priest shall dip his finger in the blood, and sprinkle it seven times before Jehovah, before the veil.", "ylt": "and the priest hath dipped his finger in the blood, and hath sprinkled seven times before Jehovah at the front of the vail,", "tyndale": "and shall dyppe his finger in the bloude, and sprinkle it seuen tymes before the Lorde: euen before the uayle.", "dra": "And shall dip his finger in it and sprinkle it seven times before the veil.", "bbe": "And put his finger in the blood, shaking drops of the blood seven times before the Lord in front of the veil.", "geneva": "And the Priest shall dip his finger in the blood, and sprinkle it seuen times before the Lord, euen before the vaile.", "wycliffe": "and whanne the fyngur `is dippid, he schal sprenge seuen sithis ayens the veil.", "rotherham": "and the priest shall dip his finger in the blood,—and shall sprinkle of the blood seven times before Yahweh, upon the face of the veil;", "darby": "and the priest shall dip his finger in the blood, and sprinkle it seven times before Jehovah, before the veil;", "twenty": "", "jps": "And the priest shall dip his finger in the blood, and sprinkle it seven times before HaShem, in front of the veil.", "acv": "And the priest shall dip his finger in the blood, and sprinkle it seven times before Jehovah, before the veil.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall dip his finger [in some] of the blood, and sprinkle [it] seven times before the LORD, [even] before the vail.", "vulgate": "tincto digito aspergens septies contra velum;", "brenton": "And the priest shall dip his finger into some of the blood of the calf, and shall sprinkle it seven times before the Lord, in front of the veil of the sanctuary."}}, {"v": 18, "ref": "4:18", "o": "וּ/מִן הַ/דָּ֞ם יִתֵּ֣ן עַל קַרְנֹ֣ת הַ/מִּזְבֵּ֗חַ אֲשֶׁר֙ לִ/פְנֵ֣י יְהוָ֔ה אֲשֶׁ֖ר בְּ/אֹ֣הֶל מוֹעֵ֑ד וְ/אֵ֣ת כָּל הַ/דָּ֗ם יִשְׁפֹּךְ֙ אֶל יְסוֹד֙ מִזְבַּ֣ח הָ/עֹלָ֔ה אֲשֶׁר פֶּ֖תַח אֹ֥הֶל מוֹעֵֽד", "en": {"kjv": "And he shall put some of the blood upon the horns of the altar which is before the Lord, that is in the tabernacle of the congregation, and shall pour out all the blood at the bottom of the altar of the burnt offering, which is at the door of the tabernacle of the congregation.", "web": "He shall put some of the blood on the horns of the altar which is before Yahweh, that is in the Tent of Meeting; and the rest of the blood he shall pour out at the base of the altar of burnt offering, which is at the door of the Tent of Meeting.", "bsb": "He is also to put some of the blood on the horns of the altar that is before the LORD in the Tent of Meeting, and he must pour out the rest of the blood at the base of the altar of burnt offering at the entrance to the Tent of Meeting.", "asv": "And he shall put of the blood upon the horns of the altar which is before Jehovah, that is in the tent of meeting; and all the blood shall he pour out at the base of the altar of burnt-offering, which is at the door of the tent of meeting.", "ylt": "and some of the blood he doth put on the horns of the altar which is before Jehovah, which is in the tent of meeting; and all the blood he doth pour out at the foundation of the altar of the burnt-offering, which is at the opening of the tent of meeting;", "tyndale": "And shall put of the bloude apon the hornes of the alter whiche is before the Lorde in the tabernacle of witnesse, and shall poure all the bloude apon the botome of the alter of burntoffrynges which is by the dore of the tabernacle of witnesse,", "dra": "And he shall put of the same blood on the horns of the altar that is before the Lord, in the tabernacle of the testimony. And the rest of the blood he shall pour at the foot of the altar of holocaust, which is at the door of the tabernacle of the testimony.", "bbe": "And he is to put some of the blood on the horns of the altar which is before the Lord in the Tent of meeting; and all the rest of the blood is to be drained out at the base of the altar of burned offering at the door of the Tent of meeting.", "geneva": "Also he shall put some of ye blood vpon the hornes of the altar, which is before the Lord, that is in the Tabernacle of the Congregation: then shall he powre all the rest, of the blood at ye foote of the altar of burnt offring, which is at the doore of the Tabernacle of the Congregation,", "wycliffe": "And he schal putte of the same blood in the hornes of the auter, which is bifor the Lord in the tabernacle of witnessyng; sotheli he schal schede the `residue blood bisidis the foundement of the auter of brent sacrifice, which is in the dore of tabernacle of witnessyng.", "rotherham": "and, some of the blood, shall he put upon the horns of the altar which is before Yahweh, which is in the tent of meeting; and, all the [remainder of the] blood, shall he pour out at the base of the altar of ascending-sacrifice, which is at the entrance of the tent of meeting;", "darby": "and he shall put of the blood on the horns of the altar that is before Jehovah which is in the tent of meeting; and he shall pour out all the blood at the bottom of the altar of burnt-offering, which is at the entrance of the tent of meeting.", "twenty": "", "jps": "And he shall put of the blood upon the horns of the altar which is before HaShem, that is in the tent of meeting, and all the remaining blood shall he pour out at the base of the altar of burnt-offering, which is at the door of the tent of meeting.", "acv": "And he shall put of the blood upon the horns of the altar which is before Jehovah, that is in the tent of meeting, and all the blood he shall pour out at the base of the altar of burnt offering, which is at the door of the tent of meeting.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall put [some] of the blood upon the horns of the altar which [is] before the LORD, that [is] in the tabernacle of the congregation, and shall pour out all the blood at the bottom of the altar of the burnt-offering, which [is] at the door of the tabernacle of the congregation.", "vulgate": "ponetque de eodem sanguine in cornibus altaris quod est coram Domino in tabernaculo testimonii reliquum autem sanguinem fundet iuxta basim altaris holocaustorum quod est in ostio tabernaculi testimonii;", "brenton": "And the priest shall put some of the blood on the horns of the altar of the incense of composition, which is before the Lord, which is in the tabernacle of witness; and he shall pour out all the blood at the bottom of the altar of whole-burnt-offerings, which is by the door of the tabernacle of witness."}}, {"v": 19, "ref": "4:19", "o": "וְ/אֵ֥ת כָּל חֶלְבּ֖/וֹ יָרִ֣ים מִמֶּ֑/נּוּ וְ/הִקְטִ֖יר הַ/מִּזְבֵּֽחָ/ה", "en": {"kjv": "And he shall take all his fat from him, and burn it upon the altar.", "web": "All its fat he shall take from it, and burn it on the altar.", "bsb": "And he is to remove all the fat from it and burn it on the altar.", "asv": "And all the fat thereof shall he take off from it, and burn it upon the altar.", "ylt": "and all its fat he doth lift up from it, and hath made perfume on the altar.", "tyndale": "and shall take all his fatt from him and burne it apon the altare,", "dra": "And all the fat thereof he shall take off, and shall burn it upon the altar:", "bbe": "And he is to take off all its fat, burning it on the altar.", "geneva": "And he shall take all his fat from him, and burne it vpon the altar.", "wycliffe": "And he schal take al the fatnesse therof, and schal brenne it on the auter;", "rotherham": "and, as for all the fat thereof, he shall heave up therefrom,—and make a perfume at the altar.", "darby": "And all its fat shall he take off from it and burn on the altar.", "twenty": "", "jps": "And all the fat thereof shall he take off from it, and make it smoke upon the altar.", "acv": "And all the fat of it he shall take off from it, and burn it upon the altar.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall take all his fat from him, and burn [it] upon the altar.", "vulgate": "omnemque eius adipem tollet et adolebit super altare;", "brenton": "And he shall take away all the fat from it, and shall offer it up on the altar."}}, {"v": 20, "ref": "4:20", "o": "וְ/עָשָׂ֣ה לַ/פָּ֔ר כַּ/אֲשֶׁ֤ר עָשָׂה֙ לְ/פַ֣ר הַֽ/חַטָּ֔את כֵּ֖ן יַעֲשֶׂה לּ֑/וֹ וְ/כִפֶּ֧ר עֲלֵ/הֶ֛ם הַ/כֹּהֵ֖ן וְ/נִסְלַ֥ח לָ/הֶֽם", "en": {"kjv": "And he shall do with the bullock as he did with the bullock for a sin offering, so shall he do with this: and the priest shall make an atonement for them, and it shall be forgiven them.", "web": "Thus shall he do with the bull; as he did with the bull of the sin offering, so shall he do with this; and the priest shall make atonement for them, and they shall be forgiven.", "bsb": "He shall offer this bull just as he did the bull for the sin offering; in this way the priest will make atonement on their behalf, and they will be forgiven.", "asv": "Thus shall he do with the bullock; as he did with the bullock of the sin-offering, so shall he do with this; and the priest shall make atonement for them, and they shall be forgiven.", "ylt": "`And he hath done to the bullock as he hath done to the bullock of the sin-offering, so he doth to it; and the priest hath made atonement for them, and it hath been forgiven them;", "tyndale": "and shall do with his oxe as he dyd wyth the synneoffryngeoxe. And the preast shal make an attonement for them, ad so it shalbe forgeuen them.", "dra": "Doing so with this calf, as he did also with that before. And the priest praying for them, the Lord will be merciful unto them.", "bbe": "Let him do with the ox as he did with the ox of the sin-offering; and the priest will take away their sin and they will have forgiveness.", "geneva": "And the Priest shall doe with this bullocke, as he did with the bullocke for his sinne: so shall he do with this: so the Priest shall make an atonement for them, and it shalbe forgiuen them.", "wycliffe": "and so he schal do also of this calf, as he dide also bifor; and whanne the prest schal preye for hem, the Lord schal be merciful.", "rotherham": "And he shall do to the bullock, as he did to the [first] sin-bearing bullock, so shall he do with this,—and the priest shall put a propitiatory-covering over them, and it shall be forgiven them.", "darby": "And he shall do with the bullock as he did with the bullock of sin-offering: so shall he do with it. And the priest shall make atonement for them; and it shall be forgiven them.", "twenty": "", "jps": "Thus shall he do with the bullock; as he did with the bullock of the sin-offering, so shall he do with this; and the priest shall make atonement for them, and they shall be forgiven.", "acv": "Thus he shall do with the bullock, as he did with the bullock of the sin offering, so he shall do with this. And the priest shall make atonement for them, and they shall be forgiven.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall do with the bullock as he did with the bullock for a sin-offering, so shall he do with this: and the priest shall make an atonement for them, and it shall be forgiven them.", "vulgate": "sic faciens et de hoc vitulo quomodo fecit et prius et rogante pro eis sacerdote propitius erit Dominus;", "brenton": "And he shall do to the calf as he did to the calf of the sin-offering, so shall it be done; and the priest shall make atonement for them, and the trespass shall be forgiven them."}}, {"v": 21, "ref": "4:21", "o": "וְ/הוֹצִ֣יא אֶת הַ/פָּ֗ר אֶל מִ/חוּץ֙ לַֽ/מַּחֲנֶ֔ה וְ/שָׂרַ֣ף אֹת֔/וֹ כַּ/אֲשֶׁ֣ר שָׂרַ֔ף אֵ֖ת הַ/פָּ֣ר הָ/רִאשׁ֑וֹן חַטַּ֥את הַ/קָּהָ֖ל הֽוּא", "en": {"kjv": "And he shall carry forth the bullock without the camp, and burn him as he burned the first bullock: it is a sin offering for the congregation.", "web": "He shall carry the bull outside the camp, and burn it as he burned the first bull. It is the sin offering for the assembly.", "bsb": "Then he is to take the bull outside the camp and burn it, just as he burned the first bull. It is the sin offering for the assembly.", "asv": "And he shall carry forth the bullock without the camp, and burn it as he burned the first bullock: it is the sin-offering for the assembly.", "ylt": "and he hath brought out the bullock unto the outside of the camp, and hath burned it as he hath burned the first bullock; it is a sin-offering of the assembly.", "tyndale": "And he shall brynge the oxe without the hoste, ad burne him as he burned the first, so is this the synneofferynge of the comynalte.", "dra": "But the calf itself he shall carry forth without the camp, and shall burn it as he did the former calf: because it is for the sin of the multitude.", "bbe": "Then let the ox be taken away outside the tent-circle, that it may be burned as the other ox was burned; it is the sin-offering for all the people.", "geneva": "For he shall carie the bullocke without the hoste, and burne him as he burned the first bullock: for it is an offring for the sinne of the Congregation.", "wycliffe": "Forsothe he schal bere out thilke calf, and schal brenne it, as also the formere calf, for it is for the synne of the multitude.", "rotherham": "And he shall take forth the bullock unto the outside of the camp, and burn it up, just as he burned up the first bullock,—the sin-bearer of the convocation, it is.", "darby": "And he shall carry forth the bullock outside the camp, and burn it as he burned the first bullock: it is a sin-offering of the congregation.", "twenty": "", "jps": "And he shall carry forth the bullock without the camp, and burn it as he burned the first bullock; it is the sin-offering for the assembly.", "acv": "And he shall carry forth the bullock outside the camp, and burn it as he burned the first bullock. It is the sin offering for the assembly.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall carry forth the bullock without the camp, and burn him as he burned the first bullock: it [is] a sin-offering for the congregation.", "vulgate": "ipsum autem vitulum efferet extra castra atque conburet sicut et priorem vitulum quia pro peccato est multitudinis;", "brenton": "And they shall carry forth the calf whole without the camp, and they shall burn the calf as they burnt the former calf: it is the sin-offering of the congregation."}}, {"v": 22, "ref": "4:22", "o": "אֲשֶׁ֥ר נָשִׂ֖יא יֶֽחֱטָ֑א וְ/עָשָׂ֡ה אַחַ֣ת מִ/כָּל מִצְוֺת֩ יְהוָ֨ה אֱלֹהָ֜י/ו אֲשֶׁ֧ר לֹא תֵעָשֶׂ֛ינָה בִּ/שְׁגָגָ֖ה וְ/אָשֵֽׁם", "en": {"kjv": "When a ruler hath sinned, and done somewhat through ignorance against any of the commandments of the Lord his God concerning things which should not be done, and is guilty;", "web": "“‘When a ruler sins, and unwittingly does any one of all the things which Yahweh his God has commanded not to be done, and is guilty;", "bsb": "When a leader sins unintentionally and does what is prohibited by any of the commandments of the LORD his God, he incurs guilt.", "asv": "When a ruler sinneth, and doeth unwittingly any one of all the things which Jehovah his God hath commanded not to be done, and is guilty;", "ylt": "`When a prince doth sin, and hath done something against one of all the commands of Jehovah his God regarding things which are not to be done, through ignorance, and hath been guilty--", "tyndale": "When a Lorde synneth and committeth thorow ignoraunce any of these thynges whiche the Lorde his God hath forbydden to be done in his commaundmentes and hath so offended:", "dra": "If a prince shall sin, and through ignorance do any one of the things that the law of the Lord forbiddeth,", "bbe": "If a ruler does wrong, and in error does any of the things which, by the order of the Lord his God, are not to be done, causing sin to come on him;", "geneva": "When a ruler shall sinne, and do through ignorance against any of the commandements of the Lord his God, which should not be done, and shall offend,", "wycliffe": "If the prince synneth, and doith bi ignoraunce o thing of many, which is forbodun in the lawe of the Lord,", "rotherham": "When a prince, shall sin,—and shall do something, departing from any of the commandments of Yahweh his God as to things which should not be done, by mistake and shall become aware of his guilt;", "darby": "When a prince sinneth and through inadvertence doeth [somewhat against] any of all the commandments of Jehovah hisGod [in things] which should not be done, and is guilty;", "twenty": "", "jps": "When a ruler sinneth, and doeth through error any one of all the things which HaShem his G-d hath commanded not to be done, and is guilty:", "acv": "When a ruler sins, and does unwittingly any one of all the things which Jehovah his God has commanded not to be done, and is guilty,", "anderson": "", "haweis": "", "noyes": "", "webster": "When a ruler hath sinned, and done [somewhat] through ignorance [against] any of the commandments of the LORD his God [concerning things] which should not be done, and is guilty;", "vulgate": "si peccaverit princeps et fecerit unum e pluribus per ignorantiam quod Domini lege prohibetur;", "brenton": "And if a ruler sin, and break one of all the commands of the Lord his God, doing the thing which ought not to be done, unwillingly, and shall sin and trespass,"}}, {"v": 23, "ref": "4:23", "o": "אֽוֹ הוֹדַ֤ע אֵלָי/ו֙ חַטָּאת֔/וֹ אֲשֶׁ֥ר חָטָ֖א בָּ֑/הּ וְ/הֵבִ֧יא אֶת קָרְבָּנ֛/וֹ שְׂעִ֥יר עִזִּ֖ים זָכָ֥ר תָּמִֽים", "en": {"kjv": "Or if his sin, wherein he hath sinned, come to his knowledge; he shall bring his offering, a kid of the goats, a male without blemish:", "web": "if his sin, in which he has sinned, is made known to him, he shall bring as his offering a goat, a male without defect.", "bsb": "When he becomes aware of the sin he has committed, he must bring an unblemished male goat as his offering.", "asv": "if his sin, wherein he hath sinned, be made known to him, he shall bring for his oblation a goat, a male without blemish.", "ylt": "or his sin wherein he hath sinned hath been made known unto him, then he hath brought in his offering, a kid of the goats, a male, a perfect one,", "tyndale": "when his synne is shewed vnto him which he hath synned, he shall brynge for hys offerynge an he goote without blemysh", "dra": "And afterwards shall come to know his sin: he shall offer a buck goat without blemish, a sacrifice to the Lord.", "bbe": "When the sin which he has done is made clear to him, let him give for his offering a goat, a male without any mark.", "geneva": "If one shewe vnto him his sinne, which he hath committed, the shall he bring for his offring an hee goat without blemish,", "wycliffe": "and aftirward vndirstondith his synne, he schal offre to the Lord a sacrifice, a `buk of geet, `that hath no wem;", "rotherham": "or his sin wherein he hath sinned be made known unto him, then shall he bring in. as his oblation a he-goat a male without defect;", "darby": "if his sin, wherein he hath sinned, come to his knowledge, he shall bring his offering, a buck of the goats, a male without blemish.", "twenty": "", "jps": "if his sin, wherein he hath sinned, be known to him, he shall bring for his offering a goat, a male without blemish.", "acv": "if his sin, by which he has sinned, be made known to him, he shall bring for his oblation a goat, a male without blemish.", "anderson": "", "haweis": "", "noyes": "", "webster": "Or if his sin, in which he hath sinned, shall come to his knowledge; he shall bring his offering, a kid of the goats, a male without blemish:", "vulgate": "et postea intellexerit peccatum suum offeret hostiam Domino hircum de capris inmaculatum;", "brenton": "and his trespass wherein he has sinned, be known to him, then shall he offer for his gift a kid of the goats, a male without blemish."}}, {"v": 24, "ref": "4:24", "o": "וְ/סָמַ֤ךְ יָד/וֹ֙ עַל רֹ֣אשׁ הַ/שָּׂעִ֔יר וְ/שָׁחַ֣ט אֹת֔/וֹ בִּ/מְק֛וֹם אֲשֶׁר יִשְׁחַ֥ט אֶת הָ/עֹלָ֖ה לִ/פְנֵ֣י יְהוָ֑ה חַטָּ֖את הֽוּא", "en": {"kjv": "And he shall lay his hand upon the head of the goat, and kill it in the place where they kill the burnt offering before the Lord: it is a sin offering.", "web": "He shall lay his hand on the head of the goat, and kill it in the place where they kill the burnt offering before Yahweh. It is a sin offering.", "bsb": "He is to lay his hand on the head of the goat and slaughter it at the place where the burnt offering is slaughtered before the LORD. It is a sin offering.", "asv": "And he shall lay his hand upon the head of the goat, and kill it in the place where they kill the burnt-offering before Jehovah: it is a sin-offering.", "ylt": "and he hath laid his hand on the head of the goat, and hath slaughtered it in the place where he doth slaughter the burnt-offering before Jehovah; it is a sin-offering.", "tyndale": "and laye his hande apon the heed of it, and kyll it in the place where the burntofferynges are kylled before the Lorde: this is a synneoffrynge.", "dra": "And he shall put his hand upon the head thereof: and when he hath immolated it in the place where the holocaust is wont to be slain before the Lord, because it is for sin,", "bbe": "And he is to put his hand on the head of the goat and put it to death in the place where they put to death the burned offering before the Lord: it is a sin-offering.", "geneva": "And shall lay his hand vpon the heade of the he goate, and kill it in the place where he should kill the burnt offring before the Lord: for it is a sinne offring.", "wycliffe": "and he schal sette his hond on the heed therof. And whanne he hath offrid it in the place, where brent sacrifice is wont to be slayn, bifor the Lord, for it is for synne;", "rotherham": "and shall lean his hand upon the head of the goat, and shall slay it in the place where they slay the ascending-sacrifice before Yahweh,—a sin-bearer, it is.", "darby": "And he shall lay his hand on the head of the goat, and slaughter it at the place where they slaughter the burnt-offering before Jehovah: it is a sin-offering.", "twenty": "", "jps": "And he shall lay his hand upon the head of the goat, and kill it in the place where they kill the burnt-offering before HaShem; it is a sin-offering.", "acv": "And he shall lay his hand upon the head of the goat, and kill it in the place where they kill the burnt offering before Jehovah. It is a sin offering.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall lay his hand upon the head of the goat, and kill it in the place where they kill the burnt-offering before the LORD: it [is] a sin-offering.", "vulgate": "ponetque manum suam super caput eius cumque immolaverit eum in loco ubi solet mactari holocaustum coram Domino quia pro peccato est;", "brenton": "And he shall lay his hand on the head of the kid, and they shall kill it in the place where they kill the victims for whole-burnt-offerings before the Lord; it is a sin-offering."}}, {"v": 25, "ref": "4:25", "o": "וְ/לָקַ֨ח הַ/כֹּהֵ֜ן מִ/דַּ֤ם הַֽ/חַטָּאת֙ בְּ/אֶצְבָּע֔/וֹ וְ/נָתַ֕ן עַל קַרְנֹ֖ת מִזְבַּ֣ח הָ/עֹלָ֑ה וְ/אֶת דָּמ֣/וֹ יִשְׁפֹּ֔ךְ אֶל יְס֖וֹד מִזְבַּ֥ח הָ/עֹלָֽה", "en": {"kjv": "And the priest shall take of the blood of the sin offering with his finger, and put it upon the horns of the altar of burnt offering, and shall pour out his blood at the bottom of the altar of burnt offering.", "web": "The priest shall take some of the blood of the sin offering with his finger, and put it on the horns of the altar of burnt offering. He shall pour out the rest of its blood at the base of the altar of burnt offering.", "bsb": "Then the priest is to take some of the blood of the sin offering with his finger, put it on the horns of the altar of burnt offering, and pour out the rest of the blood at the base of the altar.", "asv": "And the priest shall take of the blood of the sin-offering with his finger, and put it upon the horns of the altar of burnt-offering; and the blood thereof shall he pour out at the base of the altar of burnt-offering.", "ylt": "`And the priest hath taken of the blood of the sin-offering with his finger, and hath put on the horns of the altar of the burnt-offering, and its blood he doth pour out at the foundation of the altar of the burnt-offering,", "tyndale": "Tha let the preast take of the bloude of the synneoffrynge with his finger, and put it apon the hornes of the burntofferyngalter, and poure his bloude apon the botome of the burntofferyngealter", "dra": "The priest shall dip his finger in the blood of the victim for sin, touching therewith the horns of the altar of holocaust, and pouring out the rest at the foot thereof.", "bbe": "And the priest is to take some of the blood of the offering with his finger and put it on the horns of the altar of burned offering, draining out the rest of the blood at the base of the altar of burned offering.", "geneva": "Then the Priest shall take of the blood of the sinne offring with his finger, and put it vpon the hornes of the burnt offring altar, and shall powre the rest of his blood at the foote of the burnt offring altar,", "wycliffe": "the preest schal dippe the fyngur in the blood of sacrifice for synne, and he schal touche the corneris of the auter of brent sacrifice, and he schal schede the `residue blood at the foundement therof.", "rotherham": "And the priest shall take of the blood of the sin-bearer with his finger, and put upon the horns of the altar of ascending-sacrifice; and, the [remainder of the] blood thereof, shall he pour out at the base of the altar of ascending-sacrifice;", "darby": "And the priest shall take of the blood of the sin-offering with his finger, and put it on the horns of the altar of burnt-offering, and shall pour out its blood at the bottom of the altar of burnt-offering.", "twenty": "", "jps": "And the priest shall take of the blood of the sin-offering with his finger, and put it upon the horns of the altar of burnt-offering, and the remaining blood thereof shall he pour out at the base of the altar of burnt-offering.", "acv": "And the priest shall take of the blood of the sin offering with his finger, and put it upon the horns of the altar of burnt offering, and the blood of it he shall pour out at the base of the altar of burnt offering.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall take of the blood of the sin-offering with his finger, and put [it] upon the horns of the altar of burnt-offering, and shall pour out his blood at the bottom of the altar of burnt-offering.", "vulgate": "tinguet sacerdos digitum in sanguine hostiae pro peccato tangens cornua altaris holocausti et reliquum fundens ad basim eius;", "brenton": "And the priest shall put some of the blood of the sin-offering with his finger on the horns of the altar of whole-burnt-offering; and he shall pour out all its blood by the bottom of the altar of whole-burnt-offerings."}}, {"v": 26, "ref": "4:26", "o": "וְ/אֶת כָּל חֶלְבּ/וֹ֙ יַקְטִ֣יר הַ/מִּזְבֵּ֔חָ/ה כְּ/חֵ֖לֶב זֶ֣בַח הַ/שְּׁלָמִ֑ים וְ/כִפֶּ֨ר עָלָ֧י/ו הַ/כֹּהֵ֛ן מֵ/חַטָּאת֖/וֹ וְ/נִסְלַ֥ח לֽ/וֹ", "en": {"kjv": "And he shall burn all his fat upon the altar, as the fat of the sacrifice of peace offerings: and the priest shall make an atonement for him as concerning his sin, and it shall be forgiven him.", "web": "All its fat he shall burn on the altar, like the fat of the sacrifice of peace offerings; and the priest shall make atonement for him concerning his sin, and he will be forgiven.", "bsb": "He must burn all its fat on the altar, like the fat of the peace offerings; thus the priest will make atonement for that man’s sin, and he will be forgiven.", "asv": "And all the fat thereof shall he burn upon the altar, as the fat of the sacrifice of peace-offerings; and the priest shall make atonement for him as concerning his sin, and he shall be forgiven.", "ylt": "and with all its fat he doth make perfume on the altar, as the fat of the sacrifice of the peace-offerings; and the priest hath made atonement for him because of his sin, and it hath been forgiven him.", "tyndale": "and burne all his fatt apon the alter as he doth the fatt of the peaceofferynges. And the preast shall make an attonement for him as concernynge his synne, and so it shalbe forgeuen him.", "dra": "But the fat he shall burn upon it, as is wont to be done with the victims of peace offerings. And the priest shall pray for him, and for his sin: and it shall be forgiven him.", "bbe": "And all the fat of it is to be burned on the altar like the fat of the peace-offering; and the priest will take away his sin and he will have forgiveness.", "geneva": "And shall burne all his fat vpon the altar, as the fat of the peace offring: so the Priest shall make an atonement for him, concerning his sinne, and it shalbe forgiuen him.", "wycliffe": "Sotheli the preest schal brenne the innere fatnesse aboue the auter, as it is wont to be doon in the sacrifice of pesible thingis, and the preest schal preye for hym, and for his synne, and it schal be foryouun to hym.", "rotherham": "and with all the fat thereof, shall he make a perfume at the altar, as with the fat of the peace-offering,—so shall the priest put a propitiatory-covering over him because of his sin, and it shall be forgiven him.", "darby": "And he shall burn all its fat on the altar, as the fat of the sacrifice of peace-offering; and the priest shall make atonement for him [to cleanse him] from his sin, and it shall be forgiven him.", "twenty": "", "jps": "And all the fat thereof shall he make smoke upon the altar, as the fat of the sacrifice of peace-offerings; and the priest shall make atonement for him as concerning his sin, and he shall be forgiven.", "acv": "And all the fat of it he shall burn upon the altar, as the fat of the sacrifice of peace offerings. And the priest shall make atonement for him as concerning his sin, and he shall be forgiven.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall burn all his fat upon the altar, as the fat of the sacrifice of peace-offerings: and the priest shall make an atonement for him as concerning his sin, and it shall be forgiven him.", "vulgate": "adipem vero adolebit supra sicut in victimis pacificorum fieri solet rogabitque pro eo et pro peccato eius ac dimittetur ei;", "brenton": "And he shall offer up all his fat on the altar, as the fat of the sacrifice of peace-offering; and the priest shall make atonement for him concerning his sin, and it shall be forgiven him."}}, {"v": 27, "ref": "4:27", "o": "וְ/אִם נֶ֧פֶשׁ אַחַ֛ת תֶּחֱטָ֥א בִ/שְׁגָגָ֖ה מֵ/עַ֣ם הָ/אָ֑רֶץ בַּ֠/עֲשֹׂתָ/הּ אַחַ֨ת מִ/מִּצְוֺ֧ת יְהוָ֛ה אֲשֶׁ֥ר לֹא תֵעָשֶׂ֖ינָה וְ/אָשֵֽׁם", "en": {"kjv": "And if any one of the common people sin through ignorance, while he doeth somewhat against any of the commandments of the Lord concerning things which ought not to be done, and be guilty;", "web": "“‘If anyone of the common people sins unwittingly, in doing any of the things which Yahweh has commanded not to be done, and is guilty;", "bsb": "And if one of the common people sins unintentionally and does what is prohibited by any of the LORD’s commandments, he incurs guilt.", "asv": "And if any one of the common people sin unwittingly, in doing any of the things which Jehovah hath commanded not to be done, and be guilty;", "ylt": "`And if any person of the people of the land sin through ignorance, by his doing something against one of the commands of Jehovah regarding things which are not to be done, and hath been guilty--", "tyndale": "Yf one of the come people of the londe synne thorowe ignoraunce and committe any off the thinges which the Lorde hath forbidden, in his commaundementes to be done and so hath trespased,", "dra": "And if any one of the people of the land shall sin through ignorance, doing any of those things that by the law of the Lord are forbidden, and offending,", "bbe": "And if any one of the common people does wrong in error, doing any of the things which the Lord has given orders are not to be done, causing sin to come on him;", "geneva": "Likewise if any of the people of ye lande shall sinne through ignoraunce in doing against any of the commandements of the Lord, which should not be done, and shall offend,", "wycliffe": "That if a soule of the puple of the lond synneth bi ignoraunce, that he do ony thing of these that ben forbodun in the lawe of the Lord, and trespassith,", "rotherham": "And, if, any person, shall sin, by mistake from among the people of the land,—by his doing anything departing from any of the commandments of Yahweh, as to things which should not be done, and shall become aware of his guilt;", "darby": "And if any one of the people of the land sin through inadvertence, that he do [somewhat against] any of the commandments of Jehovah [in things] which should not be done, and be guilty;", "twenty": "", "jps": "And if any one of the common people sin through error, in doing any of the things which HaShem hath commanded not to be done, and be guilty:", "acv": "And if any soul of the common people sin unwittingly, in doing any of the things which Jehovah has commanded not to be done, and be guilty,", "anderson": "", "haweis": "", "noyes": "", "webster": "And if any one of the common people shall sin through ignorance, while he doeth [somewhat against] any of the commandments of the LORD [concerning things] which ought not to be done, and be guilty;", "vulgate": "quod si peccaverit anima per ignorantiam de populo terrae ut faciat quicquam ex his quae Domini lege prohibentur atque delinquat;", "brenton": "And if a soul of the people of the land should sin unwillingly, in doing a thing contrary to any of the commandments of the Lord, which ought not to be done, and shall transgress,"}}, {"v": 28, "ref": "4:28", "o": "א֚וֹ הוֹדַ֣ע אֵלָ֔י/ו חַטָּאת֖/וֹ אֲשֶׁ֣ר חָטָ֑א וְ/הֵבִ֨יא קָרְבָּנ֜/וֹ שְׂעִירַ֤ת עִזִּים֙ תְּמִימָ֣ה נְקֵבָ֔ה עַל חַטָּאת֖/וֹ אֲשֶׁ֥ר חָטָֽא", "en": {"kjv": "Or if his sin, which he hath sinned, come to his knowledge: then he shall bring his offering, a kid of the goats, a female without blemish, for his sin which he hath sinned.", "web": "if his sin, which he has sinned, is made known to him, then he shall bring for his offering a goat, a female without defect, for his sin which he has sinned.", "bsb": "When he becomes aware of the sin he has committed, he must bring an unblemished female goat as his offering for that sin.", "asv": "if his sin, which he hath sinned, be made known to him, then he shall bring for his oblation a goat, a female without blemish, for his sin which he hath sinned.", "ylt": "or his sin which he hath sinned hath been made known unto him, then he hath brought in his offering, a kid of the goats, a perfect one, a female, for his sin which he hath sinned,", "tyndale": "when his synne whiche he hath synned is come to his knowlege, he shall bringe for his offerynge, a she goote without blemish for his synne which he hath synned,", "dra": "And shall come to know his sin: he shall offer a she goat without blemish.", "bbe": "When the sin which he has done is made clear to him, then he is to give for his offering a goat, a female without any mark, for the sin which he has done.", "geneva": "If one shewe him his sinne which he hath committed, then he shall bring for his offring, a shee goate without blemish for his sinne which he hath committed,", "wycliffe": "and knowith his synne, he schal offre a geet without wem;", "rotherham": "or his sin which he hath committed shall be made known unto, him, then shall he bring in, as his oblation, a kid of the goats a female, without defect, for his sin which he hath committed;", "darby": "if his sin, which he hath sinned, come to his knowledge, then he shall bring his offering, a goat, a female without blemish, for his sin which he hath sinned.", "twenty": "", "jps": "if his sin, which he hath sinned, be known to him, then he shall bring for his offering a goat, a female without blemish, for his sin which he hath sinned.", "acv": "if his sin, which he has sinned, be made known to him, then he shall bring for his oblation a goat, a female without blemish, for his sin which he has sinned.", "anderson": "", "haweis": "", "noyes": "", "webster": "Or if his sin which he hath sinned shall come to his knowledge: then he shall bring his offering, a kid of the goats, a female without blemish, for his sin which he hath sinned.", "vulgate": "et cognoverit peccatum suum offeret capram inmaculatam;", "brenton": "and his sin should be known to him, wherein he has sinned, then shall he bring a kid of the goats, a female without blemish shall he bring for his sin, which he has sinned."}}, {"v": 29, "ref": "4:29", "o": "וְ/סָמַךְ֙ אֶת יָד֔/וֹ עַ֖ל רֹ֣אשׁ הַֽ/חַטָּ֑את וְ/שָׁחַט֙ אֶת הַ֣/חַטָּ֔את בִּ/מְק֖וֹם הָ/עֹלָֽה", "en": {"kjv": "And he shall lay his hand upon the head of the sin offering, and slay the sin offering in the place of the burnt offering.", "web": "He shall lay his hand on the head of the sin offering, and kill the sin offering in the place of burnt offering.", "bsb": "He is to lay his hand on the head of the sin offering and slaughter it at the place of the burnt offering.", "asv": "And he shall lay his hand upon the head of the sin-offering, and kill the sin-offering in the place of burnt-offering.", "ylt": "and he hath laid his hand on the head of the sin-offering, and hath slaughtered the sin-offering in the place of the burnt-offering.", "tyndale": "and laye his hande apon the heed of the synneofferynge ad slee it in the place of burntoffrynges.", "dra": "And he shall put his hand upon the head of the victim that is for sin: and shall immolate it in the place of the holocaust.", "bbe": "And he is to put his hand on the head of the sin-offering and put it to death in the place where they put to death the burned offering.", "geneva": "And he shall lay his hand vpon the head of the sinne offring, and slay the sinne offring in the place of burnt offring.", "wycliffe": "and he schal sette hond on the heed of the sacrifice which is for synne, and he schal offre it in the place of brent sacrifice.", "rotherham": "and shall lean his hand upon the head of the sin-bearer,—and shall slay the sin-bearer in the place of the ascending-sacrifice.", "darby": "And he shall lay his hand on the head of the sin-offering, and slaughter the sin-offering at the place of the burnt-offering.", "twenty": "", "jps": "And he shall lay his hand upon the head of the sin-offering, and kill the sin-offering in the place of burnt-offering.", "acv": "And he shall lay his hand upon the head of the sin offering, and kill the sin offering in the place of burnt offering.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall lay his hand upon the head of the sin-offering, and slay the sin-offering in the place of the burnt-offering.", "vulgate": "ponetque manum super caput hostiae quae pro peccato est et immolabit eam in loco holocausti;", "brenton": "And he shall lay his hand on the head of his sin-offering, and they shall slay the kid of the sin-offering in the place where they slay the victims for whole-burnt-offerings."}}, {"v": 30, "ref": "4:30", "o": "וְ/לָקַ֨ח הַ/כֹּהֵ֤ן מִ/דָּמָ/הּ֙ בְּ/אֶצְבָּע֔/וֹ וְ/נָתַ֕ן עַל קַרְנֹ֖ת מִזְבַּ֣ח הָ/עֹלָ֑ה וְ/אֶת כָּל דָּמָ֣/הּ יִשְׁפֹּ֔ךְ אֶל יְס֖וֹד הַ/מִּזְבֵּֽחַ", "en": {"kjv": "And the priest shall take of the blood thereof with his finger, and put it upon the horns of the altar of burnt offering, and shall pour out all the blood thereof at the bottom of the altar.", "web": "The priest shall take some of its blood with his finger, and put it on the horns of the altar of burnt offering; and the rest of its blood he shall pour out at the base of the altar.", "bsb": "Then the priest is to take some of its blood with his finger, put it on the horns of the altar of burnt offering, and pour out the rest of the blood at the base of the altar.", "asv": "And the priest shall take of the blood thereof with his finger, and put it upon the horns of the altar of burnt-offering; and all the blood thereof shall he pour out at the base of the altar.", "ylt": "`And the priest hath taken of its blood with his finger, and hath put on the horns of the altar of the burnt-offering, and all its blood he doth pour out at the foundation of the altar,", "tyndale": "And the preast shall take of the bloude with his finger ad put it apo the hornes of the burntoffryngealter and poure all the bloude apo the botome of the alter,", "dra": "And the priest shall take of the blood with his finger, and shall touch the horns of the altar of holocaust: and shall pour out the rest at the foot thereof.", "bbe": "And the priest is to take some of the blood with his finger, and put it on the horns of the altar of burned offering, and all the rest of its blood is to be drained out at the base of the altar.", "geneva": "Then the Priest shall take of the blood thereof with his finger, and put it vpon the hornes of the burnt offring altar, and powre all the rest of the blood thereof at the foote of the altar,", "wycliffe": "And the preest schal take of the blood on his fyngur, and he schal touche the hornes of the auter of brent sacryfice, and he schal schede the residue at the foundement therof.", "rotherham": "Then shall the priest take of the blood thereof with his finger, and put upon the horns of the altar of ascending-sacrifice,—and all the [remaining] blood thereof, shall he pour out, at the base of the altar;", "darby": "And the priest shall take of the blood thereof with his finger, and put [it] on the horns of the altar of burnt-offering, and shall pour out all the blood thereof at the bottom of the altar.", "twenty": "", "jps": "And the priest shall take of the blood thereof with his finger, and put it upon the horns of the altar of burnt-offering, and all the remaining blood thereof shall he pour out at the base of the altar.", "acv": "And the priest shall take of the blood of it with his finger, and put it upon the horns of the altar of burnt offering, and all the blood of it he shall pour out at the base of the altar.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall take of the blood of it with his finger, and put [it] upon the horns of the altar of burnt-offering, and shall pour out all the blood thereof at the bottom of the altar.", "vulgate": "tolletque sacerdos de sanguine in digito suo et tangens cornua altaris holocausti reliquum fundet ad basim eius;", "brenton": "And the priest shall take of its blood with his finger, and shall put it on the horns of the altar of whole-burnt-offerings; and all its blood he shall pour forth by the foot of the altar."}}, {"v": 31, "ref": "4:31", "o": "וְ/אֶת כָּל חֶלְבָּ֣/הּ יָסִ֗יר כַּ/אֲשֶׁ֨ר הוּסַ֣ר חֵלֶב֮ מֵ/עַ֣ל זֶ֣בַח הַ/שְּׁלָמִים֒ וְ/הִקְטִ֤יר הַ/כֹּהֵן֙ הַ/מִּזְבֵּ֔חָ/ה לְ/רֵ֥יחַ נִיחֹ֖חַ לַ/יהוָ֑ה וְ/כִפֶּ֥ר עָלָ֛י/ו הַ/כֹּהֵ֖ן וְ/נִסְלַ֥ח לֽ/וֹ", "en": {"kjv": "And he shall take away all the fat thereof, as the fat is taken away from off the sacrifice of peace offerings; and the priest shall burn it upon the altar for a sweet savour unto the Lord; and the priest shall make an atonement for him, and it shall be forgiven him.", "web": "All its fat he shall take away, like the fat is taken away from off of the sacrifice of peace offerings; and the priest shall burn it on the altar for a pleasant aroma to Yahweh; and the priest shall make atonement for him, and he will be forgiven.", "bsb": "Then he is to remove all the fat, just as it is removed from the peace offering, and the priest is to burn it on the altar as a pleasing aroma to the LORD. In this way the priest will make atonement for him, and he will be forgiven.", "asv": "And all the fat thereof shall he take away, as the fat is taken away from off the sacrifice of peace-offerings; and the priest shall burn it upon the altar for a sweet savor unto Jehovah; and the priest shall make atonement for him, and he shall be forgiven.", "ylt": "and all its fat he doth turn aside, as the fat hath been turned aside from off the sacrifice of the peace-offerings, and the priest hath made perfume on the altar, for sweet fragrance to Jehovah; and the priest hath made atonement for him, and it hath been forgiven him.", "tyndale": "ad shall take awaye all his fatt as the fatt of the peaceoffrynges is take awaye. And the preast shal burne it apo the alter for a swete sauoure vnto the Lorde, and the preast shall make an attonemet for him ad it shalbe forgeuen him.", "dra": "But taking off all the fat, as is wont to be taken away of the victims of peace offerings, he shall burn it upon the altar, for a sweet savour to the Lord: and he shall pray for him, and it shall be forgiven him.", "bbe": "And let all its fat be taken away, as the fat is taken away from the peace-offerings, and let it be burned on the altar by the priest for a sweet smell to the Lord; and the priest will take away his sin and he will have forgiveness.", "geneva": "And shall take away all his fat, as the fat of the peace offringes is taken away, and the Priest shall burne it vpon the altar for a sweete sauour vnto the Lord, and the Priest shall make an atonement for him, and it shalbe forgiuen him.", "wycliffe": "Sotheli he schal take a wei al the ynnere fatnesse, as it is wont to be don a wei of the sacrifices of pesible thingis, and he schal brenne it on the auter, in to odour of swetnesse to the Lord; and the preest schal preye for hym, and it schal be foryouun to hym.", "rotherham": "and all the fat thereof, shall he remove as the fat from off the peace-offering was removed, and the priest shall make a perfume at the altar, for a satisfying odour unto Yahweh,—so shall the priest put a propitiatory-covering over him, and it shall be forgiven him.", "darby": "And he shall take away all the fat thereof, as the fat is taken away from off the sacrifice of peace-offering; and the priest shall burn it on the altar, for a sweet odour to Jehovah; and the priest shall make atonement for him, and it shall be forgiven him.", "twenty": "", "jps": "And all the fat thereof shall he take away, as the fat is taken away from off the sacrifice of peace-offerings; and the priest shall make it smoke upon the altar for a sweet savour unto HaShem; and the priest shall make atonement for him, and he shall be forgiven.", "acv": "And all the fat of it he shall take away, as the fat is taken away from off the sacrifice of peace offerings, and the priest shall burn it upon the altar for a sweet savor to Jehovah. And the priest shall make atonement for him, and he shall be forgiven.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall take away all its fat, as the fat is taken away from off the sacrifice of peace-offerings; and the priest shall burn it upon the altar for a sweet savor to the LORD; and the priest shall make an atonement for him, and it shall be forgiven him.", "vulgate": "omnem autem auferens adipem sicut auferri solet de victimis pacificorum adolebit super altare in odorem suavitatis Domino rogabitque pro eo et dimittetur ei;", "brenton": "And he shall take away all the fat, as the fat is taken away from the sacrifice of peace-offering, and the priest shall offer it on the altar for a smell of sweet savour to the Lord; and the priest shall make atonement for him, and his sin shall be forgiven him."}}, {"v": 32, "ref": "4:32", "o": "וְ/אִם כֶּ֛בֶשׂ יָבִ֥יא קָרְבָּנ֖/וֹ לְ/חַטָּ֑את נְקֵבָ֥ה תְמִימָ֖ה יְבִיאֶֽ/נָּה", "en": {"kjv": "And if he bring a lamb for a sin offering, he shall bring it a female without blemish.", "web": "“‘If he brings a lamb as his offering for a sin offering, he shall bring a female without defect.", "bsb": "If, however, he brings a lamb as a sin offering, he must bring an unblemished female.", "asv": "And if he bring a lamb as his oblation for a sin-offering, he shall bring it a female without blemish.", "ylt": "`And if he bring in a sheep for his offering, for a sin-offering, a female, a perfect one, he doth bring in,", "tyndale": "yf he bringe a shepe ad offer it for a synneofferynge, he shall bringe a yewe without blemish", "dra": "But if he offer of the flock a victim for his sin, to wit, an ewe without blemish:", "bbe": "And if he gives a lamb as his sin-offering, let it be a female without any mark;", "geneva": "And if he bring a lambe for his sinne offring, he shall bring a female without blemish,", "wycliffe": "Sotheli if he offrith of litle beestis a sacrifice for synne, that is,", "rotherham": "And, if a lamb, he bring in. as his oblation for a sin-bearer, a female without defect, shall he bring in;", "darby": "And if he bring a sheep for his offering for sin, a female without blemish shall he bring it.", "twenty": "", "jps": "And if he bring a lamb as his offering for a sin-offering, he shall bring it a female without blemish.", "acv": "And if he brings a lamb as his oblation for a sin offering, he shall bring it a female without blemish.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if he shall bring a lamb for a sin-offering, he shall bring it a female without blemish.", "vulgate": "sin autem de pecoribus obtulerit victimam pro peccato ovem scilicet inmaculatam;", "brenton": "And if he should offer a lamb for his sin-offering, he shall offer it a female without blemish."}}, {"v": 33, "ref": "4:33", "o": "וְ/סָמַךְ֙ אֶת יָד֔/וֹ עַ֖ל רֹ֣אשׁ הַֽ/חַטָּ֑את וְ/שָׁחַ֤ט אֹתָ/הּ֙ לְ/חַטָּ֔את בִּ/מְק֕וֹם אֲשֶׁ֥ר יִשְׁחַ֖ט אֶת הָ/עֹלָֽה", "en": {"kjv": "And he shall lay his hand upon the head of the sin offering, and slay it for a sin offering in the place where they kill the burnt offering.", "web": "He shall lay his hand on the head of the sin offering, and kill it for a sin offering in the place where they kill the burnt offering.", "bsb": "And he is to lay his hand on the head of the sin offering and slaughter it as a sin offering at the place where the burnt offering is slaughtered.", "asv": "And he shall lay his hand upon the head of the sin-offering, and kill it for a sin-offering in the place where they kill the burnt-offering.", "ylt": "and he hath laid his hand on the head of the sin-offering, and hath slaughtered it for a sin-offering in the place where he slaughtereth the burnt-offering.", "tyndale": "and laye his hande apon the heed of the synneofferynge and slee it in the place where the burntoffrynges are slayne.", "dra": "He shall put his hand upon the head thereof, and shall immolate it in the place where the victims of holocausts are wont to be slain.", "bbe": "And he is to put his hand on the head of the offering and put it to death for a sin-offering in the place where they put to death the burned offering.", "geneva": "And shall lay his hand vpon the head of the sinne offring, and hee shall slay it for a sinne offring in the place where hee shoulde kill the burnt offring.", "wycliffe": "a scheep without wem, he schal putte the hond on the heed therof, and he schal offre it in the place where the beest of brent sacrifices ben wont to be slayn.", "rotherham": "and shall lean his hand upon the head of the sin-bearer,—and shall slay it as a sin-bearer, in the place where they slay the ascending-sacrifice.", "darby": "And he shall lay his hand on the head of the sin-offering, and slaughter it for a sin-offering at the place where they slaughter the burnt-offering.", "twenty": "", "jps": "And he shall lay his hand upon the head of the sin-offering, and kill it for a sin-offering in the place where they kill the burnt-offering.", "acv": "And he shall lay his hand upon the head of the sin offering, and kill it for a sin offering in the place where they kill the burnt offering.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall lay his hand upon the head of the sin-offering, and slay it for a sin-offering in the place where they kill the burnt-offering.", "vulgate": "ponet manum super caput eius et immolabit eam in loco ubi solent holocaustorum caedi hostiae;", "brenton": "And he shall lay his hand on the head of the sin-offerings, and they shall kill it in the place where they kill the victims for whole-burnt-offerings."}}, {"v": 34, "ref": "4:34", "o": "וְ/לָקַ֨ח הַ/כֹּהֵ֜ן מִ/דַּ֤ם הַֽ/חַטָּאת֙ בְּ/אֶצְבָּע֔/וֹ וְ/נָתַ֕ן עַל קַרְנֹ֖ת מִזְבַּ֣ח הָ/עֹלָ֑ה וְ/אֶת כָּל דָּמָ֣/הּ יִשְׁפֹּ֔ךְ אֶל יְס֖וֹד הַ/מִּזְבֵּֽחַ", "en": {"kjv": "And the priest shall take of the blood of the sin offering with his finger, and put it upon the horns of the altar of burnt offering, and shall pour out all the blood thereof at the bottom of the altar:", "web": "The priest shall take some of the blood of the sin offering with his finger, and put it on the horns of the altar of burnt offering; and all the rest of its blood he shall pour out at the base of the altar.", "bsb": "Then the priest is to take some of the blood of the sin offering with his finger, put it on the horns of the altar of burnt offering, and pour out the rest of its blood at the base of the altar.", "asv": "And the priest shall take of the blood of the sin-offering with his finger, and put it upon the horns of the altar of burnt-offering; and all the blood thereof shall he pour out at the base of the altar.", "ylt": "`And the priest hath taken of the blood of the sin-offering with his finger, and hath put on the horns of the altar of the burnt-offering, and all its blood he poureth out at the foundation of the altar,", "tyndale": "And the preast shal take of the bloude of the synneofferynge with his finger, ad put it apo the hornes of the burntoffryngealter, ad shall poure all the bloude thereof vnto the botome of the alter.", "dra": "And the priest shall take of the blood thereof with his finger, and shall touch the horns of the altar of holocaust: and the rest he shall pour out at the foot thereof.", "bbe": "And the priest is to take some of the blood of the offering with his finger and put it on the horns of the altar of burned offering, and all the rest of the blood is to be drained out at the base of the altar;", "geneva": "Then the Priest shall take of the blood of the sinne offring with his finger, and put it vpon the hornes of the burnt offring altar, and shall powre al the rest of the blood thereof at the foote of the altar.", "wycliffe": "And the preest schal take of the blood therof in his fyngur, and he schal touche the hornes of the autir of brent sacrifice, and he schal schede the residue at the foundement therof.", "rotherham": "Then shall the priest take of the blood of the sin-bearer with his finger, and put upon the horns of the altar of ascending-sacrifice,—and all the [remaining] blood thereof, shall he pour out, at the base of the altar;", "darby": "And the priest shall take of the blood of the sin-offering with his finger, and put [it] on the horns of the altar of burnt-offering, and shall pour out all the blood thereof at the bottom of the altar.", "twenty": "", "jps": "And the priest shall take of the blood of the sin-offering with his finger, and put it upon the horns of the altar of burnt-offering, and all the remaining blood thereof shall he pour out at the base of the altar.", "acv": "And the priest shall take of the blood of the sin offering with his finger, and put it upon the horns of the altar of burnt offering, and all the blood of it he shall pour out at the base of the altar.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall take of the blood of the sin-offering with his finger, and put [it] upon the horns of the altar of burnt-offering, and shall pour out all the blood of it at the bottom of the altar:", "vulgate": "sumetque sacerdos de sanguine eius digito suo et tangens cornua altaris holocausti reliquum fundet ad basim eius;", "brenton": "And the priest shall take of the blood of the sin-offering with his finger, and shall put it on the horns of the altar of whole-burnt-offerings, and he shall pour out all its blood by the bottom of the altar of whole-burnt-offering."}}, {"v": 35, "ref": "4:35", "o": "וְ/אֶת כָּל חֶלְבָּ֣/ה יָסִ֗יר כַּ/אֲשֶׁ֨ר יוּסַ֥ר חֵֽלֶב הַ/כֶּשֶׂב֮ מִ/זֶּ֣בַח הַ/שְּׁלָמִים֒ וְ/הִקְטִ֨יר הַ/כֹּהֵ֤ן אֹתָ/ם֙ הַ/מִּזְבֵּ֔חָ/ה עַ֖ל אִשֵּׁ֣י יְהוָ֑ה וְ/כִפֶּ֨ר עָלָ֧י/ו הַ/כֹּהֵ֛ן עַל חַטָּאת֥/וֹ אֲשֶׁר חָטָ֖א וְ/נִסְלַ֥ח לֽ/וֹ", "en": {"kjv": "And he shall take away all the fat thereof, as the fat of the lamb is taken away from the sacrifice of the peace offerings; and the priest shall burn them upon the altar, according to the offerings made by fire unto the Lord: and the priest shall make an atonement for his sin that he hath committed, and it shall be forgiven him.", "web": "All its fat he shall take away, like the fat of the lamb is taken away from the sacrifice of peace offerings; and the priest shall burn them on the altar, on the offerings of Yahweh made by fire; and the priest shall make atonement for him concerning his sin that he has sinned, and he will be forgiven.", "bsb": "And he shall remove all the fat, just as the fat of the lamb is removed from the peace offerings, and he shall burn it on the altar along with the offerings made by fire to the LORD. In this way the priest will make atonement for him for the sin he has committed, and he will be forgiven.", "asv": "And all the fat thereof shall he take away, as the fat of the lamb is taken away from the sacrifice of peace-offerings; and the priest shall burn them on the altar, upon the offerings of Jehovah made by fire; and the priest shall make atonement for him as touching his sin that he hath sinned, and he shall be forgiven.", "ylt": "and all its fat he turneth aside, as the fat of the sheep is turned aside from the sacrifice of the peace-offerings, and the priest hath made them a perfume on the altar, according to the fire-offerings of Jehovah, and the priest hath made atonement for him, for his sin which he hath sinned, and it hath been forgiven him.", "tyndale": "And he shall take awaye all the fatt thereof, as the fatte of the shepe of the peaceoffringes was take awaye. And the preast shall burne it apo the alter for the lordes sacrifice, and the preast shal make an attonemet for his synne, and it shalbe forgeuen him.", "dra": "All the fat also he shall take off, as the fat of the ram that is offered for peace offerings is wont to be taken away: and shall burn it upon the altar, for a burnt sacrifice of the Lord. And he shall pray for him and his sin, and it shall be forgiven him.", "bbe": "And let him take away all its fat, as the fat is taken away from the lamb of the peace-offerings; and let it be burned by the priest on the altar among the offerings made by fire to the Lord: and the priest will take away his sin and he will have forgiveness.", "geneva": "And he shall take away all the fat thereof, as the fatte of the lambe of the peace offrings is taken away: then the Priest shall burne it vpon the altar with the oblations of the Lord made by fire, and the Priest shall make an atonement for him concerning his sinne that he hath committed, and it shalbe forgiuen him.", "wycliffe": "And he schal do awey al the ynnere fatnesse as the innere fatnesse of the ram which is offrid for pesible thingis, is wont to be don a wei, and he schal brenne it on the auter of encense of the Lord; and the preest schal preye for hym, and for his synne, and it schal be foryouun to hym.", "rotherham": "and all the fat thereof, shall he remove as the fat of the lamb is removed, from the peace-offering, and the priest shall make a perfume therewith at the altar, upon the altar-flames of Yahweh,—so shall the priest put a propitiatory-covering over him on account of his sin which he hath committed, and it shall be forgiven him.", "darby": "And he shall take away all the fat thereof, as the fat of the lamb is taken away from the sacrifice of peace-offering; and the priest shall burn them on the altar, with Jehovah's offerings by fire; and the priest shall make atonement for him concerning his sin which he hath sinned, and it shall be forgiven him.", "twenty": "", "jps": "And all the fat thereof shall he take away, as the fat of the lamb is taken away from the sacrifice of peace-offerings; and the priest shall make them smoke on the altar, upon the offerings of HaShem made by fire; and the priest shall make atonement for him as touching his sin that he hath sinned, and he shall be forgiven.", "acv": "And all the fat of it he shall take away, as the fat of the lamb is taken away from the sacrifice of peace offerings, and the priest shall burn them on the altar, upon the offerings of Jehovah made by fire. And the priest shall make atonement for him concerning his sin that he has sinned, and he shall be forgiven.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall take away all its fat, as the fat of the lamb is taken away from the sacrifice of the peace-offerings; and the priest shall burn them upon the altar, according to the offerings made by fire to the LORD: and the priest shall make an atonement for his sin that he hath committed, and it shall be forgiven him.", "vulgate": "omnem quoque auferens adipem sicut auferri solet adeps arietis qui immolatur pro pacificis et cremabit super altare in incensum Domini rogabitque pro eo et pro peccato eius et dimittetur illi;", "brenton": "And he shall take away all his fat, as the fat of the lamb of the sacrifice of peace-offering is taken away, and the priest shall put it on the altar for a whole-burnt-offering to the Lord; and the priest shall make atonement for him for the sin which he sinned, and it shall be forgiven him."}}]}, {"c": 5, "verses": [{"v": 1, "ref": "5:1", "o": "וְ/נֶ֣פֶשׁ כִּֽי תֶחֱטָ֗א וְ/שָֽׁמְעָה֙ ק֣וֹל אָלָ֔ה וְ/ה֣וּא עֵ֔ד א֥וֹ רָאָ֖ה א֣וֹ יָדָ֑ע אִם ל֥וֹא יַגִּ֖יד וְ/נָשָׂ֥א עֲוֺנֽ/וֹ", "en": {"kjv": "And if a soul sin, and hear the voice of swearing, and is a witness, whether he hath seen or known of it; if he do not utter it, then he shall bear his iniquity.", "web": "“‘If anyone sins, in that he hears the voice of adjuration, he being a witness, whether he has seen or known, if he doesn’t report it, then he shall bear his iniquity.", "bsb": "“If someone sins by failing to testify when he hears a public charge about something he has witnessed, whether he has seen it or learned of it, he shall bear the iniquity.", "asv": "And if any one sin, in that he heareth the voice of adjuration, he being a witness, whether he hath seen or known, if he do not utter it, then he shall bear his iniquity.", "ylt": "`And when a person doth sin, and hath heard the voice of an oath, and he is witness, or hath seen, or hath known--if he declare not, then he hath borne his iniquity:", "tyndale": "Whe a soule hath synned ad herde the voyce of cursyng ad is a witnesse: whether he hath sene or knowne of it yf he haue not vttered it, he shall bere his synne.", "dra": "If any one sin, and hear the voice of one swearing, and is a witness either because he himself hath seen, or is privy to it: if he do not utter it, he shall bear his iniquity.", "bbe": "And if anyone does wrong by saying nothing when he is put under oath as a witness of something he has seen or had knowledge of, then he will be responsible:", "geneva": "Also if any haue sinned, that is, If he haue heard the voyce of an othe, and hee can be a witnes, whether he hath seene or knowen of it, if hee doe not vtter it, he shall beare his iniquitie:", "wycliffe": "If a soule synneth, and hereth the vois of a swerere , and is witnesse, `for ether he siy, ether `is witynge, if he schewith not, he schal bere his synne.", "rotherham": "Any person, moreover, whensoever he shall sin in that, when he heareth a voice of swearing, he himself, being a witness either seeing or knowing,—if he do not tell and so hath to bear his iniquity:—", "darby": "And if any one sin, and hear the voice of adjuration, and he is a witness whether he hath seen or known [it], if he do not give information, then he shall bear his iniquity.", "twenty": "", "jps": "And if any one sin, in that he heareth the voice of adjuration, he being a witness, whether he hath seen or known, if he do not utter it, then he shall bear his iniquity;", "acv": "And if a soul sins, in that he hears the voice of an oath, he being a witness, whether he has seen or known, if he does not testify, then he shall bear his iniquity.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if a soul shall sin, and hear the voice of swearing, and be a witness, whether he hath seen or known [of it]; if he doth not utter [it], then he shall bear his iniquity.", "vulgate": "si peccaverit anima et audierit vocem iurantis testisque fuerit quod aut ipse vidit aut conscius est nisi indicaverit portabit iniquitatem suam;", "brenton": "And if a soul sin, and hear the voice of swearing, and he is a witness or has seen or been conscious, if he do not report it, he shall bear his iniquity."}}, {"v": 2, "ref": "5:2", "o": "א֣וֹ נֶ֗פֶשׁ אֲשֶׁ֣ר תִּגַּע֮ בְּ/כָל דָּבָ֣ר טָמֵא֒ אוֹ֩ בְ/נִבְלַ֨ת חַיָּ֜ה טְמֵאָ֗ה א֤וֹ בְּ/נִבְלַת֙ בְּהֵמָ֣ה טְמֵאָ֔ה א֕וֹ בְּ/נִבְלַ֖ת שֶׁ֣רֶץ טָמֵ֑א וְ/נֶעְלַ֣ם מִמֶּ֔/נּוּ וְ/ה֥וּא טָמֵ֖א וְ/אָשֵֽׁם", "en": {"kjv": "Or if a soul touch any unclean thing, whether it be a carcase of an unclean beast, or a carcase of unclean cattle, or the carcase of unclean creeping things, and if it be hidden from him; he also shall be unclean, and guilty.", "web": "“‘Or if anyone touches any unclean thing, whether it is the carcass of an unclean animal, or the carcass of unclean livestock, or the carcass of unclean creeping things, and it is hidden from him, and he is unclean, then he shall be guilty.", "bsb": "Or if a person touches anything unclean—whether the carcass of any unclean wild animal or livestock or crawling creature—even if he is unaware of it, he is unclean and guilty.", "asv": "Or if any one touch any unclean thing, whether it be the carcass of an unclean beast, or the carcass of unclean cattle, or the carcass of unclean creeping things, and it be hidden from him, and he be unclean, then he shall be guilty.", "ylt": "`Or when a person cometh against any thing unclean, or against a carcase of an unclean beast, or against a carcase of unclean cattle, or against a carcase of an unclean teeming creature, and it hath been hidden from him, and he unclean, and guilty;", "tyndale": "Ether when a ma toucheth any vnclene thinge: whether it be the caryon of an vnclene beest or of vnclene catell or vnclene worme and is not warre of it, he is also vnclene and hath offended.", "dra": "Whosoever toucheth any unclean thing, either that which hath been killed by a beast, or died of itself, or any other creeping thing: and forgetteth his uncleanness, he is guilty, and hath offended.", "bbe": "If anyone becomes unclean through touching unconsciously some unclean thing, such as the dead body of an unclean beast or of unclean cattle or of any unclean animal which goes flat on the earth, he will be responsible:", "geneva": "Either if one touche any vncleane thing, whether it be a carion of an vncleane beast, or a carion of vncleane cattel, or a carion of vncleane creeping things, and is not ware of it, yet he is vncleane, and hath offended:", "wycliffe": "A persone that touchith ony vnclene thing, ether which is slayn of a beeste, ether is deed bi it silf, ether touchith ony other crepynge beeste, and foryetith his vnclennesse, he is gilti, and trespassith.", "rotherham": "Or, any person, who toucheth anything unclean, whether the carcase of an unclean wild-beast or the carcase of an unclean tame-beast, or the carcase of an unclean creeping thing,—and it is hidden from him, he himself being unclean, and he becometh aware of his guilt:—", "darby": "Or if any one touch any unclean thing, whether it be the carcase of an unclean beast, or the carcase of unclean cattle, or the carcase of an unclean crawling thing, and it be hid from him, — he also is unclean and guilty;", "twenty": "", "jps": "or if any one touch any unclean thing, whether it be the carcass of an unclean beast, or the carcass of unclean cattle, or the carcass of unclean swarming things, and be guilty, it being hidden from him that he is unclean;", "acv": "Or if a soul touches any unclean thing, whether it be the carcass of an unclean beast, or the carcass of unclean cattle, or the carcass of unclean creeping things, and it be hidden from him, and he be unclean, then he shall be guilty.", "anderson": "", "haweis": "", "noyes": "", "webster": "Or if a soul shall touch any unclean thing, whether a carcass of an unclean beast, or a carcass of unclean cattle, or the carcass of unclean creeping animals, and it shall be hidden from him; he also shall be unclean, and guilty.", "vulgate": "anima quae tetigerit aliquid inmundum sive quod occisum a bestia est aut per se mortuum vel quodlibet aliud reptile et oblita fuerit inmunditiae suae rea est et deliquit;", "brenton": "That soul which shall touch any unclean thing, or carcase, or that which is unclean being taken of beasts, or the dead bodies of abominable reptiles which are unclean, or carcases of unclean cattle,"}}, {"v": 3, "ref": "5:3", "o": "א֣וֹ כִ֤י יִגַּע֙ בְּ/טֻמְאַ֣ת אָדָ֔ם לְ/כֹל֙ טֻמְאָת֔/וֹ אֲשֶׁ֥ר יִטְמָ֖א בָּ֑/הּ וְ/נֶעְלַ֣ם מִמֶּ֔/נּוּ וְ/ה֥וּא יָדַ֖ע וְ/אָשֵֽׁם", "en": {"kjv": "Or if he touch the uncleanness of man, whatsoever uncleanness it be that a man shall be defiled withal, and it be hid from him; when he knoweth of it, then he shall be guilty.", "web": "“‘Or if he touches the uncleanness of man, whatever his uncleanness is with which he is unclean, and it is hidden from him; when he knows of it, then he shall be guilty.", "bsb": "Or if he touches human uncleanness—anything by which one becomes unclean—even if he is unaware of it, when he realizes it, he is guilty.", "asv": "Or if he touch the uncleanness of man, whatsoever his uncleanness be wherewith he is unclean, and it be hid from him; when he knoweth of it, then he shall be guilty.", "ylt": "`Or when he cometh against uncleanness of man, even any of his uncleanness whereby he is unclean, and it hath been hidden from him, and he hath known, and hath been guilty:", "tyndale": "Ether when he toucheth any vnclennesse of ma (what soeuer vnclennesse it be that a man is defyled with all) and is not warre of it and afterwarde cometh to the knowlege of it, he is a trespaser.", "dra": "And if he touch any thing of the uncleanness of man, according to any uncleanness wherewith he is wont to be defiled: and having forgotten it, come afterwards to know it, he shall be guilty of an offence.", "bbe": "Or if he becomes unclean through touching unconsciously any unclean thing of man, whatever it may be, when it is made clear to him he will be responsible:", "geneva": "Eyther if hee touche any vncleannesse of man (whatsoeuer vncleannes it be, that hee is defiled with) and is not ware of it, and after commeth to the knowledge of it, he hath sinned:", "wycliffe": "And if he touchith ony thing of the vnclennesse of man, bi al the vnclennesse bi which he is wont to be defoulid, and he foryetith, and knowith afterward, he schal be suget to trespas.", "rotherham": "Or whensoever one shall touch the uncleanness of man, as regardeth any uncleanness of his, wherewith one may become unclean,—and it be hidden from him, and then he himself, getting to know it becometh aware of his guilt:—", "darby": "or if he touch the uncleanness of man, any uncleanness of him by which he is defiled, and it be hid from him, when he knoweth [it], then he is guilty.", "twenty": "", "jps": "or if he touch the uncleanness of man, whatsoever his uncleanness be wherewith he is unclean, and it be hid from him; and, when he knoweth of it, be guilty;", "acv": "Or if he touch the uncleanness of man, whatever his uncleanness be with which he is unclean, and it be hid from him, when he knows of it, then he shall be guilty.", "anderson": "", "haweis": "", "noyes": "", "webster": "Or if he shall touch the uncleanness of man, whatever uncleanness [it may be] that a man shall be defiled with, and it be hid from him; when he knoweth [of it], then he shall be guilty.", "vulgate": "et si tetigerit quicquam de inmunditia hominis iuxta omnem inpuritatem qua pollui solet oblitaque cognoverit postea subiacebit delicto;", "brenton": "or should touch the uncleanness of a man, or whatever kind, which he may touch and be defiled by, and it should have escaped him, but afterwards he should know, —then he shall have transgressed."}}, {"v": 4, "ref": "5:4", "o": "א֣וֹ נֶ֡פֶשׁ כִּ֣י תִשָּׁבַע֩ לְ/בַטֵּ֨א בִ/שְׂפָתַ֜יִם לְ/הָרַ֣ע א֣וֹ לְ/הֵיטִ֗יב לְ֠/כֹל אֲשֶׁ֨ר יְבַטֵּ֧א הָ/אָדָ֛ם בִּ/שְׁבֻעָ֖ה וְ/נֶעְלַ֣ם מִמֶּ֑/נּוּ וְ/הוּא יָדַ֥ע וְ/אָשֵׁ֖ם לְ/אַחַ֥ת מֵ/אֵֽלֶּה", "en": {"kjv": "Or if a soul swear, pronouncing with his lips to do evil, or to do good, whatsoever it be that a man shall pronounce with an oath, and it be hid from him; when he knoweth of it, then he shall be guilty in one of these.", "web": "“‘Or if anyone swears rashly with his lips to do evil, or to do good, whatever it is that a man might utter rashly with an oath, and it is hidden from him; when he knows of it, then he shall be guilty of one of these.", "bsb": "Or if someone swears thoughtlessly with his lips to do anything good or evil—in whatever matter a man may rashly pronounce an oath—even if he is unaware of it, when he realizes it, he is guilty in the matter.", "asv": "Or if any one swear rashly with his lips to do evil, or to do good, whatsoever it be that a man shall utter rashly with an oath, and it be hid from him; when he knoweth of it, then he shall be guilty in one of these things.", "ylt": "`Or when a person sweareth, speaking wrongfully with the lips to do evil, or to do good, even anything which man speaketh wrongfully with an oath, and it hath been hid from him; --when he hath known then he hath been guilty of one of these;", "tyndale": "Ether when a soule sweareth: so that he pronounceth with his lippes to do euell or to do good (what soeuer it be that a man pronounceth with an othe) and the thinge be out of his mynde and afterwarde cometh to the knowlege of it, than he hath offended in one of these.", "dra": "The person that sweareth, and uttereth with his lips, that he would do either evil or good, and bindeth the same with an oath, and his word: and having forgotten it afterwards understandeth his offence,", "bbe": "Or if anyone, without thought, takes an oath to do evil or to do good, whatever he says without thought, with an oath, having no knowledge of what he is doing; when it becomes clear to him, he will be responsible for any of these things.", "geneva": "Either if any sweare and pronounce with his lippes to do euill, or to doe good (whatsoeuer it bee that a man shall pronounce with an othe) and it be hid from him, and after knoweth that he hath offended in one of these poyntes,", "wycliffe": "A soule that swerith, and bryngith forth with hise lippis, that it schulde do ether yuel, ether wel, and doith not, and confermeth the same thing with an ooth, ethir with a word, and foryetith, and aftirward vndirstondith his trespas, do it penaunce for synne,", "rotherham": "Or, any person, whensoever he shall swear, speaking unadvisedly with the lips, to harm or to help, as regardeth anything wherein the son of earth may speak unadvisedly by way of oath, and it be hidden from him,—and then, he himself, getting to know it, becometh aware of his guilt as regardeth any one of these things.", "darby": "Or if any one swear, talking rashly with the lips, to do evil or to do good, in everything that a man shall say rashly with an oath, and it be hid from him, when he knoweth [it], then is he guilty in one of these.", "twenty": "", "jps": "or if any one swear clearly with his lips to do evil, or to do good, whatsoever it be that a man shall utter clearly with an oath, and it be hid from him; and, when he knoweth of it, be guilty in one of these things;", "acv": "Or if a soul swears rashly with his lips to do evil, or to do good, whatever it be that a man shall utter rashly with an oath, and it be hid from him, when he realizes it, then he shall be guilty in one of these.", "anderson": "", "haweis": "", "noyes": "", "webster": "Or if a soul shall swear, pronouncing with [his] lips to do evil, or to do good, whatever [it may be], that a man shall pronounce with an oath, and it be hid from him; when he knoweth [of it], then he shall be guilty in one of these.", "vulgate": "anima quae iuraverit et protulerit labiis suis ut vel male quid faceret vel bene et id ipsum iuramento et sermone firmaverit oblitaque postea intellexerit delictum suum;", "brenton": "That unrighteous soul, which determines with his lips to do evil or to do good according to whatsoever a man may determine with an oath, and it shall have escaped his notice, and he shall afterwards know it, and so he should sin in some one of these things:"}}, {"v": 5, "ref": "5:5", "o": "וְ/הָיָ֥ה כִֽי יֶאְשַׁ֖ם לְ/אַחַ֣ת מֵ/אֵ֑לֶּה וְ/הִ֨תְוַדָּ֔ה אֲשֶׁ֥ר חָטָ֖א עָלֶֽי/הָ", "en": {"kjv": "And it shall be, when he shall be guilty in one of these things, that he shall confess that he hath sinned in that thing:", "web": "It shall be, when he is guilty of one of these, he shall confess that in which he has sinned:", "bsb": "If someone incurs guilt in one of these ways, he must confess the sin he has committed,", "asv": "And it shall be, when he shall be guilty in one of these things, that he shall confess that wherein he hath sinned:", "ylt": "`And it hath been when he is guilty of one of these, that he hath confessed concerning that which he hath sinned,", "tyndale": "Than when he hath synned in one of these thinges, he shall confesse that wherein that he hath synned,", "dra": "Let him do penance for his sin:", "bbe": "And whoever is responsible for any such sin, let him make a statement openly of his wrongdoing;", "geneva": "Whe he hath sinned in any of these things, then he shall confesse that he hath sinned therein.", "wycliffe": "and offre it of the flockis a femal lomb, ethir a goet;", "rotherham": "Then shall it be, when he becometh aware of his guilt, as regardeth any one of these things, that he shall confess that wherein he hath sinned;", "darby": "And it shall be, when he shall be guilty in one of these, that he shall confess wherein he hath sinned;", "twenty": "", "jps": "and it shall be, when he shall be guilty in one of these things, that he shall confess that wherein he hath sinned;", "acv": "And it shall be, when he shall be guilty in one of these, that he shall confess that by which he has sinned.", "anderson": "", "haweis": "", "noyes": "", "webster": "And it shall be, when he shall be guilty in one of these [things], that he shall confess that he hath sinned in that [thing]:", "vulgate": "agat paenitentiam pro peccato;", "brenton": "—then shall he declare his sin in the tings wherein he has sinned by that sin."}}, {"v": 6, "ref": "5:6", "o": "וְ/הֵבִ֣יא אֶת אֲשָׁמ֣/וֹ לַ/יהוָ֡ה עַ֣ל חַטָּאת/וֹ֩ אֲשֶׁ֨ר חָטָ֜א נְקֵבָ֨ה מִן הַ/צֹּ֥אן כִּשְׂבָּ֛ה אֽוֹ שְׂעִירַ֥ת עִזִּ֖ים לְ/חַטָּ֑את וְ/כִפֶּ֥ר עָלָ֛י/ו הַ/כֹּהֵ֖ן מֵ/חַטָּאתֽ/וֹ", "en": {"kjv": "And he shall bring his trespass offering unto the Lord for his sin which he hath sinned, a female from the flock, a lamb or a kid of the goats, for a sin offering; and the priest shall make an atonement for him concerning his sin.", "web": "and he shall bring his trespass offering to Yahweh for his sin which he has sinned, a female from the flock, a lamb or a goat, for a sin offering; and the priest shall make atonement for him concerning his sin.", "bsb": "and he must bring his guilt offering to the LORD for the sin he has committed: a female lamb or goat from the flock as a sin offering. And the priest will make atonement for him concerning his sin.", "asv": "and he shall bring his trespass-offering unto Jehovah for his sin which he hath sinned, a female from the flock, a lamb or a goat, for a sin-offering; and the priest shall make atonement for him as concerning his sin.", "ylt": "and hath brought in his guilt-offering to Jehovah for his sin which he hath sinned, a female out of the flock, a lamb, or a kid of the goats, for a sin-offering, and the priest hath made atonement for him, because of his sin.", "tyndale": "and shall bringe his trespaceofferynge vnto the Lorde for his synne which he hath synned. A female from the flocke, whether it be an yewe or a she goote, for a synneofferynge. And the preast shall make an attonement for him for his synne.", "dra": "And offer of the flocks an ewe lamb, or a she goat, and the priest shall pray for him and for his sin.", "bbe": "And take to the Lord the offering for the wrong which he has done, a female from the flock, a lamb or a goat, for a sin-offering, and the priest will take away his sin.", "geneva": "Therefore shall he bring his trespasse offring vnto the Lord for his sinne which he hath committed, euen a female from ye flocke, be it a lambe or a she goat for a sinne offring, and the Priest shall make an atonement for him, concerning his sinne.", "wycliffe": "and the preest schal preie for hym, and for his synne.", "rotherham": "and shall bring in as his guilt-bearer unto Yahweh for his sin which he hath committed, a female from the flock—a lamb or a kid of the goats—as a sin-bearer,—so shall the priest put propitiatory-covering over him, because of his sin.", "darby": "and he shall bring his trespass-offering to Jehovah for his sin which he hath sinned, a female from the small cattle, a sheep or doe goat, for a sin-offering; and the priest shall make atonement for him [to cleanse him] from his sin.", "twenty": "", "jps": "and he shall bring his forfeit unto HaShem for his sin which he hath sinned, a female from the flock, a lamb or a goat, for a sin-offering; and the priest shall make atonement for him as concerning his sin.", "acv": "And he shall bring his trespass offering to Jehovah for his sin which he has sinned, a female from the flock, a lamb or a goat, for a sin offering. And the priest shall make atonement for him as concerning his sin.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall bring his trespass-offering to the LORD for his sin which he hath sinned, a female from the flock, a lamb or a kid of the goats, for a sin-offering; and the priest shall make an atonement for him concerning his sin.", "vulgate": "et offerat agnam de gregibus sive capram orabitque pro eo sacerdos et pro peccato eius;", "brenton": "And he shall bring for his transgressions against the Lord, for his sin which he has sinned, a ewe lamb of the flock, or a kid of the goats, for a sin-offering; and the priest shall make an atonement for him for his sin which he has sinned, and his sin shall be forgiven him."}}, {"v": 7, "ref": "5:7", "o": "וְ/אִם לֹ֨א תַגִּ֣יע יָד/וֹ֮ דֵּ֣י שֶׂה֒ וְ/הֵבִ֨יא אֶת אֲשָׁמ֜/וֹ אֲשֶׁ֣ר חָטָ֗א שְׁתֵּ֥י תֹרִ֛ים אֽוֹ שְׁנֵ֥י בְנֵֽי יוֹנָ֖ה לַֽ/יהוָ֑ה אֶחָ֥ד לְ/חַטָּ֖את וְ/אֶחָ֥ד לְ/עֹלָֽה", "en": {"kjv": "And if he be not able to bring a lamb, then he shall bring for his trespass, which he hath committed, two turtledoves, or two young pigeons, unto the Lord; one for a sin offering, and the other for a burnt offering.", "web": "“‘If he can’t afford a lamb, then he shall bring his trespass offering for that in which he has sinned, two turtledoves, or two young pigeons, to Yahweh; one for a sin offering, and the other for a burnt offering.", "bsb": "If, however, he cannot afford a lamb, he may bring to the LORD as restitution for his sin two turtledoves or two young pigeons—one as a sin offering and the other as a burnt offering.", "asv": "And if his means suffice not for a lamb, then he shall bring his trespass-offering for that wherein he hath sinned, two turtle-doves, or two young pigeons, unto Jehovah; one for a sin-offering, and the other for a burnt-offering.", "ylt": "`And if his hand reach not to the sufficiency of a lamb, then he hath brought in his guilt-offering--he who hath sinned--two turtle-doves or two young pigeons to Jehovah, one for a sin-offering, and one for a burnt-offering;", "tyndale": "But yf he be not able to brynge a shepe, then let him brynge for his trespace which he hath synned, two turtyll doues or two yonge pygeons vnto the Lorde one for a synneoffrynge and another for a burntofferynge.", "dra": "But if he be not able to offer a beast, let him offer two turtles, or two young pigeons to the Lord, one for sin, and the other for a holocaust,", "bbe": "And if he has not money enough for a lamb, then let him give, for his offering to the Lord, two doves or two young pigeons; one for a sin-offering and one for a burned offering.", "geneva": "But if he be not able to bring a sheepe, he shall bring for his trespas which he hath committed, two turtle doues, or two yong pigeons vnto the Lord, one for a sinne offring, and the other for a burnt offring.", "wycliffe": "But if he may not offre a beeste, offre he twei turtlis, ethir `briddis of culuers to the Lord, oon for synne, and the tother in to brent sacrifice.", "rotherham": "And, if his hand cannot reach sufficient for a lamb, then shall he bring in to bear his guilt—for that he hath sinned—two turtle-doves, or two young pigeons unto Yahweh,—one for a sin-bearer, and one for an ascending-sacrifice.", "darby": "And if his hand be not able to bring what is so much as a sheep, then he shall bring for his trespass which he hath sinned two turtle-doves or two young pigeons, to Jehovah; one for a sin-offering, and the other for a burnt-offering.", "twenty": "", "jps": "And if his means suffice not for a lamb, then he shall bring his forfeit for that wherein he hath sinned, two turtle-doves, or two young pigeons, unto HaShem: one for a sin-offering, and the other for a burnt-offering.", "acv": "And if his means is not sufficient for a lamb, then he shall bring his trespass offering for that by which he has sinned, two turtle-doves, or two young pigeons, to Jehovah, one for a sin offering, and the other for a burnt offering.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if he shall not be able to bring a lamb, then he shall bring for his trespass which he hath committed, two turtle-doves, or two young pigeons, to the LORD; one for a sin-offering, and the other for a burnt-offering.", "vulgate": "sin autem non potuerit offerre pecus offerat duos turtures vel duos pullos columbarum Domino unum pro peccato et alterum in holocaustum;", "brenton": "And if he cannot afford a sheep, he shall bring for his sin which he has sinned, two turtle-doves or two young pigeons to the Lord; one for a sin-offering, and the other for a burnt-offering."}}, {"v": 8, "ref": "5:8", "o": "וְ/הֵבִ֤יא אֹתָ/ם֙ אֶל הַ/כֹּהֵ֔ן וְ/הִקְרִ֛יב אֶת אֲשֶׁ֥ר לַ/חַטָּ֖את רִאשׁוֹנָ֑ה וּ/מָלַ֧ק אֶת רֹאשׁ֛/וֹ מִ/מּ֥וּל עָרְפּ֖/וֹ וְ/לֹ֥א יַבְדִּֽיל", "en": {"kjv": "And he shall bring them unto the priest, who shall offer that which is for the sin offering first, and wring off his head from his neck, but shall not divide it asunder:", "web": "He shall bring them to the priest, who shall first offer the one which is for the sin offering, and wring off its head from its neck, but shall not sever it completely.", "bsb": "He is to bring them to the priest, who shall first present the one for the sin offering. He is to twist its head at the front of its neck without severing it;", "asv": "And he shall bring them unto the priest, who shall offer that which is for the sin-offering first, and wring off its head from its neck, but shall not divide it asunder:", "ylt": "and he hath brought them in unto the priest, and hath brought near that which is for a sin-offering first, and hath wrung off its head from its neck, and doth not separate it ,", "tyndale": "And he shall brynge them vnto the preast, which shall offer the synneoffrynge first and wringe the necke a sundre of it, but plucke it not clene of.", "dra": "And he shall give them to the priest: who shall offer the first for sin, and twist back the head of it to the little pinions, so that it stick to the neck, and be not altogether broken off.", "bbe": "And let him take them to the priest, who will first give the sin-offering, twisting off its head from its neck, but not cutting it in two;", "geneva": "So he shall bring them vnto the Priest, who shall offer the sinne offring first, and wring the necke of it a sunder, but not plucke it cleane off.", "wycliffe": "And he schal yyue tho to the preest, which schal offre the firste for synne, and schal folde ayen the heed therof to the wengis, so that it cleue to the necke, and be not `brokyn outirli.", "rotherham": "And he shall take them in unto the priest, who shall bring near that which is for a sin-bearer first,—and shall nip through the neck close to the head but shall not divide it asunder.", "darby": "And he shall bring them unto the priest, who shall present that which is for the sin-offering first, and pinch off his head at the neck, but shall not divide it;", "twenty": "", "jps": "And he shall bring them unto the priest, who shall offer that which is for the sin-offering first, and pinch off its head close by its neck, but shall not divide it asunder.", "acv": "And he shall bring them to the priest, who shall offer that which is for the sin offering first, and wring off its head from its neck, but shall not divide it apart.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall bring them to the priest, who shall offer [that] which [is] for the sin-offering first, and wring off his head from his neck, but shall not divide [it] asunder:", "vulgate": "dabitque eos sacerdoti qui primum offerens pro peccato retorquebit caput eius ad pinnulas ita ut collo hereat et non penitus abrumpatur;", "brenton": "And he shall bring them to the priest, and the priest shall bring the sin-offering first; and the priest shall pinch off the head from the neck, and shall not divide the body."}}, {"v": 9, "ref": "5:9", "o": "וְ/הִזָּ֞ה מִ/דַּ֤ם הַ/חַטָּאת֙ עַל קִ֣יר הַ/מִּזְבֵּ֔חַ וְ/הַ/נִּשְׁאָ֣ר בַּ/דָּ֔ם יִמָּצֵ֖ה אֶל יְס֣וֹד הַ/מִּזְבֵּ֑חַ חַטָּ֖את הֽוּא", "en": {"kjv": "And he shall sprinkle of the blood of the sin offering upon the side of the altar; and the rest of the blood shall be wrung out at the bottom of the altar: it is a sin offering.", "web": "He shall sprinkle some of the blood of the sin offering on the side of the altar; and the rest of the blood shall be drained out at the base of the altar. It is a sin offering.", "bsb": "then he is to sprinkle some of the blood of the sin offering on the side of the altar, while the rest of the blood is drained out at the base of the altar. It is a sin offering.", "asv": "and he shall sprinkle of the blood of the sin-offering upon the side of the altar; and the rest of the blood shall be drained out at the base of the altar: it is a sin-offering.", "ylt": "and he hath sprinkled of the blood of the sin-offering on the side of the altar, and that which is left of the blood is wrung out at the foundation of the altar; it is a sin-offering.", "tyndale": "And let him sprinkle of the bloude of the synneofferynge apon the syde of the alter, and let the reste of the bloude blede apon the botome of the alter, and than it is a synneofferynge.", "dra": "And of its blood he shall sprinkle the side of the altar: and whatever is left, he shall let it drop at the bottom thereof, because it is for sin.", "bbe": "And he is to put drops of the blood of the offering on the side of the altar, and the rest of the blood is to be drained out at the base of the altar; it is a sin-offering.", "geneva": "After he shall sprinkle of the blood of the sinne offring vpon the side of the altar, and the rest of the blood shall be shed at the foote of the altar: for it is a sinne offering.", "wycliffe": "And the preest schal sprynge the wal of the auter, of the blood therof; sotheli what euer `is residue, he schal make to droppe doun at the `foundement of the auter, for it is for synne.", "rotherham": "And he shall sprinkle of the blood of the sin-bearer upon the wall of the altar, and the remainder of the blood, shall he drain out at the base of the altar,—a, sin-bearer, it is.", "darby": "and he shall sprinkle of the blood of the sin-offering on the wall of the altar; and the rest of the blood shall be wrung out at the bottom of the altar: it is a sin-offering.", "twenty": "", "jps": "And he shall sprinkle of the blood of the sin-offering upon the side of the altar; and the rest of the blood shall be drained out at the base of the altar; it is a sin-offering.", "acv": "And he shall sprinkle of the blood of the sin offering upon the side of the altar, and the rest of the blood shall be drained out at the base of the altar. It is a sin offering.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall sprinkle of the blood of the sin-offering upon the side of the altar; and the rest of the blood shall be wrung out at the bottom of the altar: it [is] a sin-offering.", "vulgate": "et asperget de sanguine eius parietem altaris quicquid autem reliquum fuerit faciet destillare ad fundamentum eius quia pro peccato est;", "brenton": "And he shall sprinkle of the blood of the sin-offering on the side of the altar, but the rest of the blood he shall drop at the foot of the altar, for it is a sin-offering."}}, {"v": 10, "ref": "5:10", "o": "וְ/אֶת הַ/שֵּׁנִ֛י יַעֲשֶׂ֥ה עֹלָ֖ה כַּ/מִּשְׁפָּ֑ט וְ/כִפֶּ֨ר עָלָ֧י/ו הַ/כֹּהֵ֛ן מֵ/חַטָּאת֥/וֹ אֲשֶׁר חָטָ֖א וְ/נִסְלַ֥ח לֽ/וֹ", "en": {"kjv": "And he shall offer the second for a burnt offering, according to the manner: and the priest shall make an atonement for him for his sin which he hath sinned, and it shall be forgiven him.", "web": "He shall offer the second for a burnt offering, according to the ordinance; and the priest shall make atonement for him concerning his sin which he has sinned, and he shall be forgiven.", "bsb": "And the priest must prepare the second bird as a burnt offering according to the ordinance. In this way the priest will make atonement for him for the sin he has committed, and he will be forgiven.", "asv": "And he shall offer the second for a burnt-offering, according to the ordinance; and the priest shall make atonement for him as concerning his sin which he hath sinned, and he shall be forgiven.", "ylt": "`And the second he maketh a burnt-offering, according to the ordinance, and the priest hath made atonement for him, because of his sin which he hath sinned, and it hath been forgiven him.", "tyndale": "And let him offer the seconde for a burntoffrynge as the maner is: ad so shall the preast make an atonement for him for the synne which he hath synned, and it shalbe forgeuen him.", "dra": "And the other he shall burn for a holocaust, as is wont to be done. And the priest shall pray for him, and for his sin, and it shall be forgiven him.", "bbe": "And the second is for a burned offering, in agreement with the law; and the priest will take away his sin and he will have forgiveness.", "geneva": "Also he shall offer the seconde for a burnt offring as the maner is: so shall the Priest make an atonement for him (for his sinne which hee hath committed) and it shalbe forgiuen him.", "wycliffe": "Sotheli he schal brenne the tother brid in to brent sacrifice, as it is wont to be doon; and the preest schal preie for hym, and for his synne, and it schal be foryouun to hym.", "rotherham": "And of the second, shall he make an ascending-sacrifice according to the regulation,—so shall the priest put a propitiatory-covering over him, because of his sin which he hath committed and it shall be forgiven him.", "darby": "And he shall offer the other for a burnt-offering, according to the ordinance. And the priest shall make atonement for him [to cleanse him] from his sin which he hath sinned, and it shall be forgiven him.", "twenty": "", "jps": "And he shall prepare the second for a burnt-offering, according to the ordinance; and the priest shall make atonement for him as concerning his sin which he hath sinned, and he shall be forgiven.", "acv": "And he shall offer the second for a burnt offering, according to the ordinance. And the priest shall make atonement for him as concerning his sin which he has sinned, and he shall be forgiven.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall offer the second [for] a burnt-offering, according to the manner: and the priest shall make an atonement for him for his sin which he hath sinned, and it shall be forgiven him.", "vulgate": "alterum vero adolebit holocaustum ut fieri solet rogabitque pro eo sacerdos et pro peccato eius et dimittetur ei;", "brenton": "And he shall make the second a whole-burnt-offering, as it is fit; and the priest shall make atonement for his sin which he has sinned, and it shall be forgiven him."}}, {"v": 11, "ref": "5:11", "o": "וְ/אִם לֹא֩ תַשִּׂ֨יג יָד֜/וֹ לִ/שְׁתֵּ֣י תֹרִ֗ים אוֹ֮ לִ/שְׁנֵ֣י בְנֵי יוֹנָה֒ וְ/הֵבִ֨יא אֶת קָרְבָּנ֜/וֹ אֲשֶׁ֣ר חָטָ֗א עֲשִׂירִ֧ת הָ/אֵפָ֛ה סֹ֖לֶת לְ/חַטָּ֑את לֹא יָשִׂ֨ים עָלֶ֜י/הָ שֶׁ֗מֶן וְ/לֹא יִתֵּ֤ן עָלֶ֨י/הָ֙ לְבֹנָ֔ה כִּ֥י חַטָּ֖את הִֽיא", "en": {"kjv": "But if he be not able to bring two turtledoves, or two young pigeons, then he that sinned shall bring for his offering the tenth part of an ephah of fine flour for a sin offering; he shall put no oil upon it, neither shall he put any frankincense thereon: for it is a sin offering.", "web": "“‘But if he can’t afford two turtledoves, or two young pigeons, then he shall bring his offering for that in which he has sinned, the tenth part of an ephah of fine flour for a sin offering. He shall put no oil on it, neither shall he put any frankincense on it, for it is a sin offering.", "bsb": "But if he cannot afford two turtledoves or two young pigeons, he may bring a tenth of an ephah of fine flour as a sin offering. He must not put olive oil or frankincense on it, because it is a sin offering.", "asv": "But if his means suffice not for two turtle-doves, or two young pigeons, then he shall bring his oblation for that wherein he hath sinned, the tenth part of an ephah of fine flour for a sin-offering: he shall put no oil upon it, neither shall he put any frankincense thereon; for it is a sin-offering.", "ylt": "`And if his hand reach not to two turtle-doves, or to two young pigeons, then he hath brought in his offering--he who hath sinned--a tenth of an ephah of flour for a sin-offering; he putteth no oil on it, nor doth he put on it frankincense, for it is a sin-offering,", "tyndale": "And yet yf he be not able to brynge .ij. turtyll doues or two yonge pigeons, then let hym brynge his offerynge for his synne: the tenth parte of an Epha of fine floure for a synneofferynge, but put none oyle thereto nether put ony frankencens thereon, for it is a synneofferinge.", "dra": "And if his hand be not able to offer two turtles, or two young pigeons, he shall offer for his sin the tenth part of an ephi of flour. He shall not put oil upon it, nor put any frankincense thereon, because it is for sin.", "bbe": "But if he has not enough money for two doves or two young pigeons, then let him give, for the sin he has done, the tenth part of an ephah of the best meal, for a sin-offering; let him put no oil on it, and no perfume, for it is a sin-offering.", "geneva": "But if he be not able to bring two turtle doues, or two yong pigeons, then he that hath sinned, shall bring for his offring, the tenth parte of an Ephah of fine floure for a sinne offring, he shall put none oyle thereto, neither put any incense thereon: for it is a sinne offering.", "wycliffe": "That if his hond mai not offre twei turtlis, ethir twei `briddis of culueris, he schal offre for his synne the tenthe part of ephi of wheete flour; he schal not putte oile `in to it, nether he schal putte ony thing of encense, for it is for synne.", "rotherham": "But if his hand cannot lay hold of two turtledove, or two young pigeons, then shall he bring in as his oblation—because he hath sinned—the tenth of an ephah of fine meal for bearing sin,—he shall not put thereon oil, neither shall he lay thereon frankincense, for a sin-bearer, it is.", "darby": "But if his hand cannot attain to two turtle-doves, or two young pigeons, then he that sinned shall bring for his offering the tenth part of an ephah of fine flour for a sin-offering: he shall put no oil on it, neither shall he put frankincense thereon; for it is a sin-offering.", "twenty": "", "jps": "But if his means suffice not for two turtledoves, or two young pigeons, then he shall bring his offering for that wherein he hath sinned, the tenth part of an ephah of fine flour for a sin-offering; he shall put no oil upon it, neither shall he put any frankincense thereon; for it is a sin-offering.", "acv": "But if his means is not sufficient for two turtle-doves, or two young pigeons, then he shall bring his oblation for that by which he has sinned, the tenth part of an ephah of fine flour for a sin offering. He shall put no oil upon it, nor shall he put any frankincense on it, for it is a sin offering.", "anderson": "", "haweis": "", "noyes": "", "webster": "But if he shall not be able to bring two turtle-doves, or two young pigeons; then he that sinned shall bring for his offering the tenth part of an ephah of fine flour for a sin-offering; he shall put no oil upon it, neither shall he put [any] frankincense upon it: for it [is] a sin-offering.", "vulgate": "quod si non quiverit manus eius offerre duos turtures vel duos pullos columbae offeret pro peccato similam partem oephi decimam non mittet in eam oleum nec turis aliquid inponet quia pro peccato est;", "brenton": "And if he cannot afford a pair of turtle-doves, or two young pigeons, then shall he bring as his gift for his sin, the tenth part of an ephah of fine flour for a sin-offering; he shall not pour oil upon it, nor shall he put frankincense upon it, because it is a sin-offering."}}, {"v": 12, "ref": "5:12", "o": "וֶ/הֱבִיאָ/הּ֮ אֶל הַ/כֹּהֵן֒ וְ/קָמַ֣ץ הַ/כֹּהֵ֣ן מִ֠מֶּ/נָּה מְל֨וֹא קֻמְצ֜/וֹ אֶת אַזְכָּרָתָ/ה֙ וְ/הִקְטִ֣יר הַ/מִּזְבֵּ֔חָ/ה עַ֖ל אִשֵּׁ֣י יְהוָ֑ה חַטָּ֖את הִֽוא", "en": {"kjv": "Then shall he bring it to the priest, and the priest shall take his handful of it, even a memorial thereof, and burn it on the altar, according to the offerings made by fire unto the Lord: it is a sin offering.", "web": "He shall bring it to the priest, and the priest shall take his handful of it as the memorial portion, and burn it on the altar, on the offerings of Yahweh made by fire. It is a sin offering.", "bsb": "He is to bring it to the priest, who shall take a handful from it as a memorial portion and burn it on the altar atop the offerings made by fire to the LORD; it is a sin offering.", "asv": "And he shall bring it to the priest, and the priest shall take his handful of it as the memorial thereof, and burn it on the altar, upon the offerings of Jehovah made by fire: it is a sin-offering.", "ylt": "and he hath brought it in unto the priest, and the priest hath taken a handful from it--the fulness of his hand--its memorial--and hath made perfume on the altar, according to the fire-offerings of Jehovah; it is a sin-offering.", "tyndale": "And let him brynge it to the preast, and the preast shall take his handfull of it and burne it apon the alter for a remembraunce to be a sacryfice for the Lorde: that is a synneoffrynge.", "dra": "And he shall deliver it to the priest, who shall take a handful thereof, and shall burn it upon the altar for a memorial of him that offered it:", "bbe": "And let him come to the priest with it, and the priest will take some of it in his hand, to be burned on the altar as a sign, among the offerings of the Lord made by fire: it is a sin-offering.", "geneva": "Then shall hee bring it to the Priest, and the Priest shall take his handfull of it for the remembrance thereof, and burne it vpon the altar with the offrings of the Lord made by fire: for it is a sinne offring.", "wycliffe": "And he schal yyue it to the preest, which preest schal take vp an handful therof, and schal brenne on the auter, in to mynde of hym that offeride,", "rotherham": "And he shall bring it in unto the priest, and the priest shall take therefrom a handful, as the memorial thereof, and shall make a perfume at the altar, upon the altar-flames of Yahweh,—a sin-bearer, it is.", "darby": "And he shall bring it to the priest, and the priest shall take his handful of it, the memorial thereof, and burn it on the altar, with Jehovah's offerings by fire: it is a sin-offering.", "twenty": "", "jps": "And he shall bring it to the priest, and the priest shall take his handful of it as the memorial-part thereof, and make it smoke on the altar, upon the offerings of HaShem made by fire; it is a sin-offering.", "acv": "And he shall bring it to the priest, and the priest shall take his handful of it as the memorial of it, and burn it on the altar, upon the offerings of Jehovah made by fire. It is a sin offering.", "anderson": "", "haweis": "", "noyes": "", "webster": "Then shall he bring it to the priest, and the priest shall take his handful of it, [even] a memorial of it, and burn [it] on the altar, according to the offerings made by fire to the LORD: it [is] a sin-offering.", "vulgate": "tradetque eam sacerdoti qui plenum ex toto pugillum hauriens cremabit super altare in monumentum eius qui obtulit;", "brenton": "And he shall bring it to the priest; and the priest having taken a handful of it, shall lay the memorial of it on the altar of whole-burnt-offerings to the Lord; it is a sin-offering."}}, {"v": 13, "ref": "5:13", "o": "וְ/כִפֶּר֩ עָלָ֨י/ו הַ/כֹּהֵ֜ן עַל חַטָּאת֧/וֹ אֲשֶׁר חָטָ֛א מֵֽ/אַחַ֥ת מֵ/אֵ֖לֶּה וְ/נִסְלַ֣ח ל֑/וֹ וְ/הָיְתָ֥ה לַ/כֹּהֵ֖ן כַּ/מִּנְחָֽה", "en": {"kjv": "And the priest shall make an atonement for him as touching his sin that he hath sinned in one of these, and it shall be forgiven him: and the remnant shall be the priest’s, as a meat offering.", "web": "The priest shall make atonement for him concerning his sin that he has sinned in any of these things, and he will be forgiven; and the rest shall be the priest’s, as the meal offering.’”", "bsb": "In this way the priest will make atonement for him for any of these sins he has committed, and he will be forgiven. The remainder will belong to the priest, like the grain offering.”", "asv": "And the priest shall make atonement for him as touching his sin that he hath sinned in any of these things, and he shall be forgiven: and the remnant shall be the priest’s, as the meal-offering.", "ylt": "`And the priest hath made atonement for him, for his sin which he hath sinned against one of these, and it hath been forgiven him, and the remnant hath been to the priest, like the present.'", "tyndale": "And let the preast make an atonement for him for his synne (what soeuer of these he hath synned) and it shalbe forgeuen. And the remnaute shalbe the preastes, as it is in the meateofferynge.", "dra": "Praying for him and making atonement. But the part that is left, he himself shall have for a gift.", "bbe": "And the priest will take away his sin and he will have forgiveness: and the rest of the offering will be the priest's, in the same way as the meal offering.", "geneva": "So the Priest shall make an atonement for him, as touching his sinne that he hath committed in one of these poyntes, and it shall bee forgiuen him: and the remnant shalbe the Priests, as the meate offring.", "wycliffe": "and the preest schal preie for hym, and schal clense; forsothe he schal have the tother part in yifte.", "rotherham": "So shall the priest put a propitiatory-covering over him, on account of his sin which he hath committed, departing from some one of these things, and it shall be forgiven him,—then shall it be the priest’s, like the meal-offering.", "darby": "And the priest shall make atonement for him concerning his sin which he hath sinned in one of these, and it shall be forgiven him; and it shall be the priest's, as the oblation.", "twenty": "", "jps": "And the priest shall make atonement for him as touching his sin that he hath sinned in any of these things, and he shall be forgiven; and the remnant shall be the priest's, as the meal-offering.", "acv": "And the priest shall make atonement for him concerning his sin that he has sinned in any of these things, and he shall be forgiven. And the remnant shall be the priest's, as the meal offering.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall make an atonement for him as concerning his sin that he hath sinned in one of these, and it shall be forgiven him: and [the remnant] shall be the priest's, as a meat-offering.", "vulgate": "rogans pro illo et expians reliquam vero partem ipse habebit in munere;", "brenton": "And the priest shall make atonement for him for his sin, which he has sinned in one of these things, and it shall be forgiven him; and that which is left shall be the priest's, as an offering of fine flour."}}, {"v": 14, "ref": "5:14", "o": "וַ/יְדַבֵּ֥ר יְהוָ֖ה אֶל מֹשֶׁ֥ה לֵּ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh spoke to Moses, saying,", "bsb": "Then the LORD said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde comyned with Moses sayenge:", "dra": "And the Lord spoke to Moses, saying:", "bbe": "And the Lord said to Moses,", "geneva": "And the Lord spake vnto Moses, saying,", "wycliffe": "And the Lord spak to Moises,", "rotherham": "And Yahweh spake unto Moses, saying—", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses, saying:", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "locutus est Dominus ad Mosen dicens;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 15, "ref": "5:15", "o": "נֶ֚פֶשׁ כִּֽי תִמְעֹ֣ל מַ֔עַל וְ/חָֽטְאָה֙ בִּ/שְׁגָגָ֔ה מִ/קָּדְשֵׁ֖י יְהוָ֑ה וְ/הֵבִיא֩ אֶת אֲשָׁמ֨/וֹ לַֽ/יהוָ֜ה אַ֧יִל תָּמִ֣ים מִן הַ/צֹּ֗אן בְּ/עֶרְכְּ/ךָ֛ כֶּֽסֶף שְׁקָלִ֥ים בְּ/שֶֽׁקֶל הַ/קֹּ֖דֶשׁ לְ/אָשָֽׁם", "en": {"kjv": "If a soul commit a trespass, and sin through ignorance, in the holy things of the Lord; then he shall bring for his trespass unto the Lord a ram without blemish out of the flocks, with thy estimation by shekels of silver, after the shekel of the sanctuary, for a trespass offering:", "web": "“If anyone commits a trespass, and sins unwittingly, in the holy things of Yahweh; then he shall bring his trespass offering to Yahweh, a ram without defect from the flock, according to your estimation in silver by shekels, after the shekel of the sanctuary, for a trespass offering.", "bsb": "“If someone acts unfaithfully and sins unintentionally against any of the LORD’s holy things, he must bring his guilt offering to the LORD: an unblemished ram from the flock, of proper value in silver shekels according to the sanctuary shekel; it is a guilt offering.", "asv": "If any one commit a trespass, and sin unwittingly, in the holy things of Jehovah; then he shall bring his trespass-offering unto Jehovah, a ram without blemish out of the flock, according to thy estimation in silver by shekels, after the shekel of the sanctuary, for a trespass-offering:", "ylt": "`When a person committeth a trespass, and hath sinned through ignorance against the holy things of Jehovah, then he hath brought in his guilt-offering to Jehovah, a ram, a perfect one, out of the flock, at thy valuation in silver--shekels by the shekel of the sanctuary--for a guilt-offering.", "tyndale": "when a soule trespaceth ad synneth thorow ignoraunce in any of the holy thinges of the Lorde, he shall brynge for his trespace vnto the Lord, a ram without blymesh out of the flocke valowed at two sycles after the holy sycle, for a trespaceofferynge.", "dra": "If any one shall sin through mistake, transgressing the ceremonies in those things that are sacrificed to the Lord, he shall offer for his offence a ram without blemish out of the flocks, that may be bought for two sicles, according to the weight of the sanctuary.", "bbe": "If anyone is untrue, sinning in error in connection with the holy things of the Lord, let him take his offering to the Lord, a male sheep from the flock, without any mark, of the value fixed by you in silver by shekels, by the scale of the holy place.", "geneva": "If any person transgresse and sinne through ignorance by taking away things consecrated vnto the Lord, hee shall then bring for his trespasse offring vnto the Lord a ramme without blemish out of the flocke, worth two shekels of siluer by thy estimation after the shekel of the Sanctuarie, for a trespasse offring.", "wycliffe": "and seide, If a soule brekith cerymonyes bi errour, and synneth in these thingis that ben halewid to the Lord, it schal offre for his trespas a ram without wem of the flockis, that may be bouyt for twey siclis, bi the weiyte of the seyntuarie.", "rotherham": "Whensoever, any person, shall commit a trespass, and shall take away by mistake, from the holy things of Yahweh, then shall he bring in as his guilt-bearer unto Yahweh, a ram without defect out of the flock, with thine estimate in silver by shekels, after the shekel of the sanctuary, for a guilt-bearer:", "darby": "If any one act unfaithfully and sin through inadvertence in the holy things of Jehovah, then he shall bring his trespass-offering to Jehovah, a ram without blemish out of the small cattle, according to thy valuation by shekels of silver, according to the shekel of the sanctuary, for a trespass-offering.", "twenty": "", "jps": "If any one commit a trespass, and sin through error, in the holy things of HaShem, then he shall bring his forfeit unto HaShem, a ram without blemish out of the flock, according to thy valuation in silver by shekels, after the shekel of the sanctuary, for a guilt-offering.", "acv": "If a soul commits a trespass, and sins unwittingly in the holy things of Jehovah, then he shall bring his trespass offering to Jehovah, a ram without blemish out of the flock, according to thy estimation in silver by shekels, after the shekel of the sanctuary, for a trespass offering.", "anderson": "", "haweis": "", "noyes": "", "webster": "If a soul shall commit a trespass, and sin through ignorance, in the holy things of the LORD; then he shall bring for his trespass to the LORD a ram without blemish out of the flocks, with thy estimation by shekels of silver, after the shekel of the sanctuary, for a trespass-offering:", "vulgate": "anima si praevaricans caerimonias per errorem in his quae Domino sunt sanctificata peccaverit offeret pro delicto suo arietem inmaculatum de gregibus qui emi potest duobus siclis iuxta pondus sanctuarii;", "brenton": "The soul which shall be really unconscious, and shall sin unwillingly in any of the holy things of the Lord, shall even bring to the Lord for his transgression, a ram of the flock without blemish, valued according to shekels of silver according to the shekel of the sanctuary, for his transgression wherein he transgressed."}}, {"v": 16, "ref": "5:16", "o": "וְ/אֵ֣ת אֲשֶׁר֩ חָטָ֨א מִן הַ/קֹּ֜דֶשׁ יְשַׁלֵּ֗ם וְ/אֶת חֲמִֽישִׁת/וֹ֙ יוֹסֵ֣ף עָלָ֔י/ו וְ/נָתַ֥ן אֹת֖/וֹ לַ/כֹּהֵ֑ן וְ/הַ/כֹּהֵ֗ן יְכַפֵּ֥ר עָלָ֛י/ו בְּ/אֵ֥יל הָ/אָשָׁ֖ם וְ/נִסְלַ֥ח לֽ/וֹ", "en": {"kjv": "And he shall make amends for the harm that he hath done in the holy thing, and shall add the fifth part thereto, and give it unto the priest: and the priest shall make an atonement for him with the ram of the trespass offering, and it shall be forgiven him.", "web": "He shall make restitution for that which he has done wrong in the holy thing, and shall add a fifth part to it, and give it to the priest; and the priest shall make atonement for him with the ram of the trespass offering, and he will be forgiven.", "bsb": "Regarding any holy thing he has harmed, he must make restitution by adding a fifth of its value to it and giving it to the priest, who will make atonement on his behalf with the ram as a guilt offering, and he will be forgiven.", "asv": "and he shall make restitution for that which he hath done amiss in the holy thing, and shall add the fifth part thereto, and give it unto the priest; and the priest shall make atonement for him with the ram of the trespass-offering, and he shall be forgiven.", "ylt": "`And that which he hath sinned against the holy thing he repayeth, and its fifth is adding to it, and hath given it to the priest, and the priest maketh atonement for him with the ram of the guilt-offering, and it hath been forgiven him.", "tyndale": "And he shall make amendes for the harme that he hath done in the holy thynge, and put the fifte parte moare thereto and geue it vnto the preast. And the preast shall make an attonemet for him with the ram of the trespaceofferynge, and it shalbe forgeue hym.", "dra": "And he shall make good the damage itself which he hath done, and shall add the fifth part besides, delivering it to the priest, who shall pray for him, offering the ram: and it shall be forgiven him.", "bbe": "And he is to make payment to the priest for what he has done wrong in relation to the holy thing, together with a fifth part of its value in addition; and the priest will take away his sin by the sheep of his offering, and he will have forgiveness.", "geneva": "So hee shall restore that wherein hee hath offended, in taking away of the holy thing, and shall put the fift part more thereto, and giue it vnto the Priest: so the Priest shall make an atonement for him with the ram of ye trespasse offring, and it shalbe forgiuen him.", "wycliffe": "And he schal restore that harm that he dide, and he schal putte the fyuethe part aboue, and schal yyue to the preest, which preest schal preye for hym, and offre the ram, and it schal be foryouun to hym.", "rotherham": "that, moreover, which he took away from the sanctuary, shall he make good and the fifth part thereof, shall he add thereunto, and shall give it to the priest,—and, the priest, shall put a propitiatory-covering over him with the guilt-bearing ram and it shall be forgiven him.", "darby": "And he shall make restitution for the wrong that he hath done in the holy things, and shall add the fifth part thereto, and shall give it unto the priest; and the priest shall make atonement for him with the ram of the trespass-offering, and it shall be forgiven him.", "twenty": "", "jps": "And he shall make restitution for that which he hath done amiss in the holy thing, and shall add the fifth part thereto, and give it unto the priest; and the priest shall make atonement for him with the ram of the guilt-offering, and he shall be forgiven.", "acv": "And he shall make restitution for that which he has done amiss in the holy thing, and shall add the fifth part to it, and give it to the priest. And the priest shall make atonement for him with the ram of the trespass offering, and he shall be forgiven.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall make amends for the harm that he hath done in the holy thing, and shall add to it the fifth part, and give it to the priest: and the priest shall make an atonement for him with the ram of the trespass-offering, and it shall be forgiven him.", "vulgate": "ipsumque quod intulit damni restituet et quintam partem ponet supra tradens sacerdoti qui rogabit pro eo offerens arietem et dimittetur ei;", "brenton": "And he shall make compensation for that wherein he has sinned in the holy things; and he shall add the fifth part to it, and give it to the priest; and the priest shall make atonement for him with the ram of transgression, and his sin shall be forgiven him."}}, {"v": 17, "ref": "5:17", "o": "וְ/אִם נֶ֨פֶשׁ֙ כִּ֣י תֶֽחֱטָ֔א וְ/עָֽשְׂתָ֗ה אַחַת֙ מִ/כָּל מִצְוֺ֣ת יְהוָ֔ה אֲשֶׁ֖ר לֹ֣א תֵעָשֶׂ֑ינָה וְ/לֹֽא יָדַ֥ע וְ/אָשֵׁ֖ם וְ/נָשָׂ֥א עֲוֺנֽ/וֹ", "en": {"kjv": "And if a soul sin, and commit any of these things which are forbidden to be done by the commandments of the Lord; though he wist it not, yet is he guilty, and shall bear his iniquity.", "web": "“If anyone sins, and does any of the things which Yahweh has commanded not to be done; though he didn’t know it, yet he is guilty, and shall bear his iniquity.", "bsb": "If someone sins and violates any of the LORD’s commandments even though he was unaware, he is guilty and shall bear his punishment.", "asv": "And if any one sin, and do any of the things which Jehovah hath commanded not to be done; though he knew it not, yet is he guilty, and shall bear his iniquity.", "ylt": "`And when any person sinneth, and hath done something against one of all the commands of Jehovah regarding things which are not to be done, and hath not known, and he hath been guilty, and hath borne his iniquity,", "tyndale": "When a soule synneth and committeth any of these thinges which are forbidde to be done by the comaundmentes of the Lorde: though he wist it not, he hath yet offended and is in synne,", "dra": "If any one sin through ignorance, and do one of those things which by the law of the Lord are forbidden, and being guilty of sin, understand his iniquity:", "bbe": "And if anyone does wrong, and does any of the things which the Lord has given orders are not to be done, though he has no knowledge of it, still he is in the wrong and he is responsible.", "geneva": "Also if any sinne and doe against any of the commandements of the Lord, which ought not to be done, and knowe not and sinne and beare his iniquitie,", "wycliffe": "A soule that synneth bi ignoraunce, and doith oon of these thingis that ben forbodun in the lawe of the Lord, and is gilti of synne, and vndirstondith his wickidnesse,", "rotherham": "And if any person when he shall sin, and do something, departing from any of the commandments of Yahweh, as to things which should not be done,—though he knew it not, shall so become guilty, and shall bear his iniquity,", "darby": "And if any one sin and do against any of all the commandments of Jehovah what should not be done, and hath not known [it], yet is he guilty, and shall bear his iniquity.", "twenty": "", "jps": "And if any one sin, and do any of the things which HaShem hath commanded not to be done, though he know it not, yet is he guilty, and shall bear his iniquity.", "acv": "And if a soul sins, and does any of the things which Jehovah has commanded not to be done, though he did not know it, yet he is guilty, and shall bear his iniquity.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if a soul shall sin, and commit any of these things which are forbidden to be done by the commandments of the LORD; though he knew [it] not, yet is he guilty, and shall bear his iniquity.", "vulgate": "anima si peccaverit per ignorantiam feceritque unum ex his quae Domini lege prohibentur et peccati rea intellexerit iniquitatem suam;", "brenton": "And the soul which shall sin, and do one thing against any of the commandments of the Lord, which it is not right to do, and has not known it, and shall have transgressed, and shall have contracted guilt,"}}, {"v": 18, "ref": "5:18", "o": "וְ֠/הֵבִיא אַ֣יִל תָּמִ֧ים מִן הַ/צֹּ֛אן בְּ/עֶרְכְּ/ךָ֥ לְ/אָשָׁ֖ם אֶל הַ/כֹּהֵ֑ן וְ/כִפֶּר֩ עָלָ֨י/ו הַ/כֹּהֵ֜ן עַ֣ל שִׁגְגָת֧/וֹ אֲשֶׁר שָׁגָ֛ג וְ/ה֥וּא לֹֽא יָדַ֖ע וְ/נִסְלַ֥ח לֽ/וֹ", "en": {"kjv": "And he shall bring a ram without blemish out of the flock, with thy estimation, for a trespass offering, unto the priest: and the priest shall make an atonement for him concerning his ignorance wherein he erred and wist it not, and it shall be forgiven him.", "web": "He shall bring a ram without defect from of the flock, according to your estimation, for a trespass offering, to the priest; and the priest shall make atonement for him concerning the thing in which he sinned and didn’t know it, and he will be forgiven.", "bsb": "He is to bring to the priest an unblemished ram of proper value from the flock as a guilt offering. Then the priest will make atonement on his behalf for the wrong he has committed in ignorance, and he will be forgiven.", "asv": "And he shall bring a ram without blemish out of the flock, according to thy estimation, for a trespass-offering, unto the priest; and the priest shall make atonement for him concerning the thing wherein he erred unwittingly and knew it not, and he shall be forgiven.", "ylt": "`Then he hath brought in a ram, a perfect one, out of the flock, at thy valuation, for a guilt-offering, unto the priest; and the priest hath made atonement for him, for his ignorance in which he hath erred and he hath not known, and it hath been forgiven him;", "tyndale": "ad shall brige a ram without blymesh out of the flocke that is estemed to be worthe a synneofferynge, vnto the preast. And the preast shall make an attonement for him for the ignoraunce whiche he dyd and was not ware, and it shalbe forgeuen him.", "dra": "He shall offer of the flocks a ram without blemish to the priest, according to the measure and estimation of the sin. And the priest shall pray for him, because he did it ignorantly: And it shall be forgiven him,", "bbe": "Let him come to the priest with a sheep, a male without any mark out of the flock, of the value fixed by you, as an offering for his error; and the priest will take away the sin which he did in error, and he will have forgiveness.", "geneva": "Then shall he bring a ramme without blemishe out of the flocke, in thy estimation worth two shekels for a trespasse offring vnto ye Priest: and the Priest shall make an atonement for him concerning his ignorance wherein he erred, and was not ware: so it shalbe forgiuen him.", "wycliffe": "it schal offre to the preest a ram without wem of the flockis, bi the mesure of estymacioun of synne; and the preest schal preye for hym, for he dide vnwytynge, and it schal be foryouun to him,", "rotherham": "then shall he bring in a ram without defect out of the flock by thine estimate as a guilt-bearer unto the priest,—and the priest shall put a propitiatory-covering over him, on account of his mistake which he made though he knew it not and it shall be forgiven him:", "darby": "And he shall bring a ram without blemish out of the small cattle, according to thy valuation, as trespass-offering, unto the priest; and the priest shall make atonement for him concerning his inadvertence wherein he sinned inadvertently, and knew [it] not, and it shall be forgiven him.", "twenty": "", "jps": "And he shall bring a ram without blemish out of the flock, according to thy valuation, for a guilt-offering, unto the priest; and the priest shall make atonement for him concerning the error which he committed, though he knew it not, and he shall be forgiven.", "acv": "And he shall bring a ram without blemish out of the flock, according to thy estimation, for a trespass offering, to the priest. And the priest shall make atonement for him concerning the thing by which he erred unwittingly and knew it not, and he shall be forgiven.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall bring a ram without blemish out of the flock, with thy estimation, for a trespass-offering to the priest; and the priest shall make an atonement for him concerning his ignorance wherein he erred and knew [it] not, and it shall be forgiven him.", "vulgate": "offeret arietem inmaculatum de gregibus sacerdoti iuxta mensuram aestimationemque peccati qui orabit pro eo quod nesciens fecerit et dimittetur ei;", "brenton": "he shall even bring a ram without blemish from the flock, valued at a price of silver for his transgression to the priest; and the priest shall make atonement for his trespass of ignorance, wherein he ignorantly trespassed, and he knew it not; and it shall be forgiven him."}}, {"v": 19, "ref": "5:19", "o": "אָשָׁ֖ם ה֑וּא אָשֹׁ֥ם אָשַׁ֖ם לַ/יהוָֽה", "en": {"kjv": "It is a trespass offering: he hath certainly trespassed against the Lord.", "web": "It is a trespass offering. He is certainly guilty before Yahweh.”", "bsb": "It is a guilt offering; he was certainly guilty before the LORD.”", "asv": "It is a trespass-offering: he is certainly guilty before Jehovah.", "ylt": "it is a guilt-offering; he hath been certainly guilty before Jehovah.'", "tyndale": "This is a trespaceofferynge, for he trespaced agaynst the Lorde.", "dra": "Because by mistake he trespassed against the Lord.", "bbe": "It is an offering for his error: he is certainly responsible before the Lord.", "geneva": "This is the trespasse offring for the trespasse committed against the Lord.", "wycliffe": "for by errour he trespasside ayens the Lord.", "rotherham": "a guilt-bearer, it is,—he was, verily guilty against Yahweh.", "darby": "It is a trespass-offering: he hath certainly trespassed against Jehovah.", "twenty": "", "jps": "It is a guilt-offering--he is certainly guilty before HaShem.", "acv": "It is a trespass offering. He is certainly guilty before Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "It [is] a trespass-offering: he hath certainly trespassed against the LORD.", "vulgate": "quia per errorem deliquit in Dominum;", "brenton": "For he has surely been guilty of transgression before the Lord."}}]}, {"c": 6, "verses": [{"v": 1, "ref": "6:1", "o": "וַ/יְדַבֵּ֥ר יְהוָ֖ה אֶל מֹשֶׁ֥ה לֵּ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh spoke to Moses, saying,", "bsb": "And the LORD said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde talked with Moses sayenge:", "dra": "The Lord spoke to Moses, saying:", "bbe": "And the Lord said to Moses,", "geneva": "And the Lord spake vnto Moses, saying,", "wycliffe": "And the Lord spak to Moises,", "rotherham": "And Yahweh spake unto Moses, saying—", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses, saying:", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "locutus est Dominus ad Mosen dicens;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 2, "ref": "6:2", "o": "צַ֤ו אֶֽת אַהֲרֹן֙ וְ/אֶת בָּנָ֣י/ו לֵ/אמֹ֔ר זֹ֥את תּוֹרַ֖ת הָ/עֹלָ֑ה הִ֣וא הָ/עֹלָ֡ה עַל֩ מוֹקְדָ֨ה עַל הַ/מִּזְבֵּ֤חַ כָּל הַ/לַּ֨יְלָה֙ עַד הַ/בֹּ֔קֶר וְ/אֵ֥שׁ הַ/מִּזְבֵּ֖חַ תּ֥וּקַד בּֽ/וֹ", "en": {"kjv": "If a soul sin, and commit a trespass against the Lord, and lie unto his neighbour in that which was delivered him to keep, or in fellowship, or in a thing taken away by violence, or hath deceived his neighbour;", "web": "“If anyone sins, and commits a trespass against Yahweh, and deals falsely with his neighbor in a matter of deposit, or of bargain, or of robbery, or has oppressed his neighbor,", "bsb": "“If someone sins and acts unfaithfully against the LORD by deceiving his neighbor in regard to a deposit or security entrusted to him or stolen, or if he extorts his neighbor", "asv": "If any one sin, and commit a trespass against Jehovah, and deal falsely with his neighbor in a matter of deposit, or of bargain, or of robbery, or have oppressed his neighbor,", "ylt": "`When any person doth sin, and hath committed a trespass against Jehovah, and hath lied to his fellow concerning a deposit, or concerning fellowship, or concerning violent robbery, or hath oppressed his fellow;", "tyndale": "when a soule synneth ad trespaceth agaynst the Lorde and denyed vnto his neyghboure that which was taken him to kepe, or that was put vnder his hande, or that which he hath violently taken awaye, or that whiche he hath deceaued his neyghboure off wyth sotylte,", "dra": "Whosoever shall sin, and despising the Lord, shall deny to his neighbour the thing delivered to his keeping, which was committed to his trust; or shall by force extort any thing, or commit oppression;", "bbe": "If anyone does wrong, and is untrue to the Lord, acting falsely to his neighbour in connection with something put in his care, or something given for a debt, or has taken away anything by force, or has been cruel to his neighbour,", "geneva": "If any sinne and commit a trespasse against the Lord, and denie vnto his neighbour that, which was take him to keepe, or that which was put to him of trust, or doth by robberie, or by violence oppresse his neighbour,", "wycliffe": "and seide, A soule that synneth, and dispisith the Lord, and denyeth to his neiybore a thing bitakun to kepyng, that was bitakun to his feith, ethir takith maisterfuli a thing bi violence, ether makith fals chaleng,", "rotherham": "When any person, shall sin, and shall commit a trespass against Yahweh,—and shall withhold something of the truth from his neighbour in respect of a deposit, or a pledge or anything plundered, or shall use extortion with his neighbour;", "darby": "If any one sin and act unfaithfully against Jehovah, and lie to his neighbour as to an entrusted thing or a deposit or [that in which] he hath robbed or wronged his neighbour,", "twenty": "", "jps": "Command Aaron and his sons, saying: This is the law of the burnt-offering: it is that which goeth up on its firewood upon the altar all night unto the morning; and the fire of the altar shall be kept burning thereby.", "acv": "If a soul sins, and commits a trespass against Jehovah, and deals falsely with his neighbor in a matter of deposit, or of bargain, or of robbery, or have oppressed his neighbor,", "anderson": "", "haweis": "", "noyes": "", "webster": "If a soul shall sin, and commit a trespass against the LORD, and lie to his neighbor, in that which was delivered him to keep, or in fellowship, or in a thing taken away by violence, or hath deceived his neighbor;", "vulgate": "anima quae peccaverit et contempto Domino negaverit depositum proximo suo quod fidei eius creditum fuerat vel vi aliquid extorserit aut calumniam fecerit;", "brenton": "The soul which shall have sinned, and willfully overlooked the commandments of the Lord, and shall have dealt falsely in the affairs of his neighbour in the matter of a deposit, or concerning fellowship, or concerning plunder, or has in anything wronged his neighbour,"}}, {"v": 3, "ref": "6:3", "o": "וְ/לָבַ֨שׁ הַ/כֹּהֵ֜ן מִדּ֣/וֹ בַ֗ד וּ/מִֽכְנְסֵי בַד֮ יִלְבַּ֣שׁ עַל בְּשָׂר/וֹ֒ וְ/הֵרִ֣ים אֶת הַ/דֶּ֗שֶׁן אֲשֶׁ֨ר תֹּאכַ֥ל הָ/אֵ֛שׁ אֶת הָ/עֹלָ֖ה עַל הַ/מִּזְבֵּ֑חַ וְ/שָׂמ֕/וֹ אֵ֖צֶל הַ/מִּזְבֵּֽחַ", "en": {"kjv": "Or have found that which was lost, and lieth concerning it, and sweareth falsely; in any of all these that a man doeth, sinning therein:", "web": "or has found that which was lost, and dealt falsely therein, and swearing to a lie; in any of all these things that a man does, sinning therein;", "bsb": "or finds lost property and lies about it and swears falsely, or if he commits any such sin that a man might commit—", "asv": "or have found that which was lost, and deal falsely therein, and swear to a lie; in any of all these things that a man doeth, sinning therein;", "ylt": "or hath found a lost thing, and hath lied concerning it, and hath sworn to a falsehood, concerning one of all these which man doth, sinning in them:", "tyndale": "or hath founde that whiche was loste and denyeth it, and swereth falsely, in what soeuer thinge it be that a man doth and synneth therein,", "dra": "Or shall find a thing lost, and denying it, shall also swear falsely, or shall do any other of the many things, wherein men are wont to sin:", "bbe": "Or has taken a false oath about the loss of something which he has come across by chance; if a man has done any of these evil things,", "geneva": "Or hath found that which was lost, and denieth it, and sweareth falsely, for any of these things that a man doeth, wherein he sinneth:", "wycliffe": "ether fyndith a thing lost, and denyeth ferthermore and forswerith, and doth ony other thing of manye in whiche thingis men ben wont to do synne,", "rotherham": "or shall find something lost and shall withhold something of the truth therein, and shall swear to a falsehood,—as regardeth a single thing of all that a son of earth may do, to commit sin thereby;", "darby": "or have found what was lost, and denieth it, and sweareth falsely in anything of all that man doeth, sinning therein;", "twenty": "", "jps": "And the priest shall put on his linen garment, and his linen breeches shall he put upon his flesh; and he shall take up the ashes whereto the fire hath consumed the burnt-offering on the altar, and he shall put them beside the altar.", "acv": "or has found that which was lost, and deal falsely by it, and swears to a lie, in any of all these things that a man does, sinning by it,", "anderson": "", "haweis": "", "noyes": "", "webster": "Or hath found that which was lost, and lieth concerning it, and sweareth falsely; in any of all these that a man doeth, sinning therein:", "vulgate": "sive rem perditam invenerit et infitians insuper peierarit et quodlibet aliud ex pluribus fecerit in quibus peccare solent homines;", "brenton": "or has found that which was lost, and shall have lied concerning it, and shall have sworn unjustly concerning any one of all the things, whatsoever a man may do, so as to sin hereby;"}}, {"v": 4, "ref": "6:4", "o": "וּ/פָשַׁט֙ אֶת בְּגָדָ֔י/ו וְ/לָבַ֖שׁ בְּגָדִ֣ים אֲחֵרִ֑ים וְ/הוֹצִ֤יא אֶת הַ/דֶּ֨שֶׁן֙ אֶל מִ/ח֣וּץ לַֽ/מַּחֲנֶ֔ה אֶל מָק֖וֹם טָהֽוֹר", "en": {"kjv": "Then it shall be, because he hath sinned, and is guilty, that he shall restore that which he took violently away, or the thing which he hath deceitfully gotten, or that which was delivered him to keep, or the lost thing which he found,", "web": "then it shall be, if he has sinned, and is guilty, he shall restore that which he took by robbery, or the thing which he has gotten by oppression, or the deposit which was committed to him, or the lost thing which he found,", "bsb": "once he has sinned and becomes guilty, he must return what he has stolen or taken by extortion, or the deposit entrusted to him, or the lost property he found,", "asv": "then it shall be, if he hath sinned, and is guilty, that he shall restore that which he took by robbery, or the thing which he hath gotten by oppression, or the deposit which was committed to him, or the lost thing which he found,", "ylt": "`Then it hath been, when he sinneth, and hath been guilty, that he hath returned the plunder which he hath taken violently away, or the thing which he hath got by oppression, or the deposit which hath been deposited with him, or the lost thing which he hath found;", "tyndale": "Then when he hath synned or trespaced, he shall restore agayne that he toke violently awaye, or the wronge whiche he dyd, or that whiche was delyuered him to kepe, or the lost thinge which he founde,", "dra": "Being convicted of the offence, he shall restore", "bbe": "Causing sin to come on him, then he will have to give back the thing he took by force or got by cruel acts, or the goods which were put in his care or the thing he came on by chance,", "geneva": "When, I say, he thus sinneth and trespasseth, he shall then restore the robbery that he robbed, or the thing taken by violence which hee tooke by force, or the thing which was deliuered him to keepe, or the lost thing which he founde,", "wycliffe": "`if it is conuict of the gilt,", "rotherham": "and so it shall come about that he shall commit sin and then become aware of his guilt, then shall he return the plunder which he had plundered, or the extortion which he had extorted, or the deposit that was deposited with him,—or the lost thing which he hath found:", "darby": "then it shall be, if he hath sinned and transgressed, that he shall restore what he robbed or that in which he hath defrauded, or the deposit, or the lost thing which he found,", "twenty": "", "jps": "And he shall put off his garments, and put on other garments, and carry forth the ashes without the camp unto a clean place.", "acv": "then it shall be, if he has sinned, and is guilty, that he shall restore that which he took by robbery, or the thing which he has gotten by oppression, or the deposit which was committed to him, or the lost thing which he found,", "anderson": "", "haweis": "", "noyes": "", "webster": "Then it shall be, because he hath sinned, and is guilty, that he shall restore that which he took by force, or the thing which he obtained by deceit, or that which was delivered him to keep, or the lost thing which he found,", "vulgate": "convicta delicti reddet;", "brenton": "it shall come to pass, whensoever he shall have sinned, and transgressed, that he shall restore the plunder which he has seized, or redress the injury which he has committed, or restore the deposit which was entrusted to him, or the lost article which he has found of any kind, about which he swore unjustly, he shall even restore it in full; and he shall add to it a fifth part besides; he shall restore it to him whose it is in the day in which he happens to be convicted."}}, {"v": 5, "ref": "6:5", "o": "וְ/הָ/אֵ֨שׁ עַל הַ/מִּזְבֵּ֤חַ תּֽוּקַד בּ/וֹ֙ לֹ֣א תִכְבֶּ֔ה וּ/בִעֵ֨ר עָלֶ֧י/הָ הַ/כֹּהֵ֛ן עֵצִ֖ים בַּ/בֹּ֣קֶר בַּ/בֹּ֑קֶר וְ/עָרַ֤ךְ עָלֶ֨י/הָ֙ הָֽ/עֹלָ֔ה וְ/הִקְטִ֥יר עָלֶ֖י/הָ חֶלְבֵ֥י הַ/שְּׁלָמִֽים", "en": {"kjv": "Or all that about which he hath sworn falsely; he shall even restore it in the principal, and shall add the fifth part more thereto, and give it unto him to whom it appertaineth, in the day of his trespass offering.", "web": "or any thing about which he has sworn falsely; he shall restore it even in full, and shall add a fifth part more to it. To him to whom it belongs he shall give it, in the day of his being found guilty.", "bsb": "or anything else about which he has sworn falsely. He must make restitution in full, add a fifth of the value, and pay it to the owner on the day he acknowledges his guilt.", "asv": "or any thing about which he hath sworn falsely; he shall even restore it in full, and shall add the fifth part more thereto: unto him to whom it appertaineth shall he give it, in the day of his being found guilty.", "ylt": "or all that concerning which he sweareth falsely, he hath even repaid it in its principal, and its fifth he is adding to it; to him whose it is he giveth it in the day of his guilt-offering.", "tyndale": "or what soeuer it be aboute which he hath sworne falsely, he shall restore it agayne in the whole sume and shal adde the fifte parte moare thereto and geue it vnto him to whome it pertayneth, the same daye that he offereth for his trespace,", "dra": "All that he would have gotten by fraud, in the principal, and the fifth part besides, to the owner, whom he wronged.", "bbe": "Or anything about which he took a false oath; he will have to give it all back, with the addition of a fifth of its value, to him whose property it is, when he has been judged to be in the wrong.", "geneva": "Or for whatsoeuer he hath sworne falsely, he shall both restore it in the whole summe, and shall adde the fift parte more thereto, and giue it vnto him to whome perteyneth, the same day that he offreth for trespasse.", "wycliffe": "it schal yelde hool alle thingis whiche it wolde gete bi fraude, and ferthermore the fyuethe part to the lord, to whom it dide harm.", "rotherham": "or in anything as to which he hath been swearing to a falsehood, then shall he make it good in the principal thereof, and the fifth part thereof, shall he add thereunto,—to whomsoever it belongeth, to him, shall he give it in the day he becometh aware of his guilt;", "darby": "or all that about which he hath sworn falsely; and he shall restore it in the principal, and shall add the fifth part more thereto; to [him to] whom it belongeth shall he give it, on the day of his trespass-offering.", "twenty": "", "jps": "And the fire upon the altar shall be kept burning thereby, it shall not go out; and the priest shall kindle wood on it every morning; and he shall lay the burnt-offering in order upon it, and shall make smoke thereon the fat of the peace-offerings.", "acv": "or anything about which he has sworn falsely, he shall even restore it in full, and shall add the fifth part more to it. He shall give it to him to whom it pertains, in the day of his being found guilty.", "anderson": "", "haweis": "", "noyes": "", "webster": "Or all that about which he hath sworn falsely; he shall even restore it in the principal, and shall add to it the fifth part more, [and] give it to him to whom it appertaineth, in the day of his trespass-offering.", "vulgate": "omnia quae per fraudem voluit obtinere integra et quintam insuper partem domino cui damnum intulerat;", "brenton": "And he shall bring to the Lord for his trespass, a ram of the flock, without blemish, of value to the amount of the thing in which he trespassed."}}, {"v": 6, "ref": "6:6", "o": "אֵ֗שׁ תָּמִ֛יד תּוּקַ֥ד עַל הַ/מִּזְבֵּ֖חַ לֹ֥א תִכְבֶֽה", "en": {"kjv": "And he shall bring his trespass offering unto the Lord, a ram without blemish out of the flock, with thy estimation, for a trespass offering, unto the priest:", "web": "He shall bring his trespass offering to Yahweh, a ram without defect from the flock, according to your estimation, for a trespass offering, to the priest.", "bsb": "Then he must bring to the priest his guilt offering to the LORD: an unblemished ram of proper value from the flock.", "asv": "And he shall bring his trespass-offering unto Jehovah, a ram without blemish out of the flock, according to thy estimation, for a trespass-offering, unto the priest:", "ylt": "`And his guilt-offering he bringeth in to Jehovah, a ram, a perfect one, out of the flock, at thy estimation, for a guilt-offering, unto the priest,", "tyndale": "and shall brynge for his trespace offerynge vnto the Lorde, a ram without blymesh out of the flocke, that is estemed worth a trespaceofferynge vnto the preast.", "dra": "Moreover for his sin he shall offer a ram without blemish out of the flock: and shall give it to the priest, according to the estimation and measure of the offence.", "bbe": "Then let him take to the Lord the offering for his wrongdoing; giving to the priest for his offering, a male sheep from the flock, without any mark, of the value fixed by you:", "geneva": "Also he shall bring for his trespasse vnto the Lord, a ramme without blemish out of the flocke in thy estimation worth two shekels for a trespasse offring vnto the Priest.", "wycliffe": "Sotheli for his synne it schal offre a ram vnwemmed of the floc, and it schal yyue that ram to the preest, bi the valu and mesure of the trespas;", "rotherham": "but, his guilt-bearer, itself, shall he bring in unto Yahweh,—a ram without defect out of the flock by thine estimate as a guilt-bearer, unto the priest.", "darby": "And his trespass-offering shall he bring to Jehovah, a ram without blemish out of the small cattle according to thy valuation, as a trespass-offering, unto the priest.", "twenty": "", "jps": "Fire shall be kept burning upon the altar continually; it shall not go out.", "acv": "And he shall bring his trespass offering to Jehovah, a ram without blemish out of the flock, according to thy estimation, for a trespass offering, to the priest.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall bring his trespass-offering to the LORD, a ram without blemish out of the flock, with thy estimation, for a trespass-offering, to the priest:", "vulgate": "pro peccato autem suo offeret arietem inmaculatum de grege et dabit eum sacerdoti iuxta aestimationem mensuramque delicti;", "brenton": "And the priest shall make atonement for him before the Lord, and he shall be forgiven for any one of all the things which he did and trespassed in it."}}, {"v": 7, "ref": "6:7", "o": "וְ/זֹ֥את תּוֹרַ֖ת הַ/מִּנְחָ֑ה הַקְרֵ֨ב אֹתָ֤/הּ בְּנֵֽי אַהֲרֹן֙ לִ/פְנֵ֣י יְהוָ֔ה אֶל פְּנֵ֖י הַ/מִּזְבֵּֽחַ", "en": {"kjv": "And the priest shall make an atonement for him before the Lord: and it shall be forgiven him for any thing of all that he hath done in trespassing therein.", "web": "The priest shall make atonement for him before Yahweh, and he will be forgiven concerning whatever he does to become guilty.”", "bsb": "In this way the priest will make atonement for him before the LORD, and he will be forgiven for anything he may have done to incur guilt.”", "asv": "and the priest shall make atonement for him before Jehovah; and he shall be forgiven concerning whatsoever he doeth so as to be guilty thereby.", "ylt": "and the priest hath made atonement for him before Jehovah, and it hath been forgiven him, concerning one thing of all that he doth, by being guilty therein.'", "tyndale": "And the prest shall make an atonemet for him before the Lorde, ad it shall be forgeue hi in what soeuer thinge it be that a ma doth ad trespaceth therein.", "dra": "And he shall pray for him before the Lord: and he shall have forgiveness for every thing in doing of which he bath sinned.", "bbe": "And the priest will take away his sin from before the Lord, and he will have forgiveness for whatever crime he has done", "geneva": "And the Priest shall make an atonement for him before the Lord, and it shall be forgiuen him, whatsoeuer thing he hath done, and trespassed therein.", "wycliffe": "and the preest schal preie for hym bifor the Lord, and it schal be foryouun to hym, for alle thingis whiche he synnede in doyng.", "rotherham": "So shall the priest put a propitiatory-covering over him before Yahweh, and it shall be forgiven him,—on account of any one thing, of all which one might do, so as to become guilty therein.", "darby": "And the priest shall make atonement for him before Jehovah, and it shall be forgiven him concerning anything of all that he hath done so as to trespass therein.", "twenty": "", "jps": "And this is the law of the meal-offering: the sons of Aaron shall offer it before HaShem, in front of the altar.", "acv": "And the priest shall make atonement for him before Jehovah, and he shall be forgiven concerning whatever he does so as to be guilty by it.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall make an atonement for him before the LORD: and it shall be forgiven him for any thing of all that he hath done in trespassing therein.", "vulgate": "qui rogabit pro eo coram Domino et dimittetur illi pro singulis quae faciendo peccaverit;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 8, "ref": "6:8", "o": "וְ/הֵרִ֨ים מִמֶּ֜/נּוּ בְּ/קֻמְצ֗/וֹ מִ/סֹּ֤לֶת הַ/מִּנְחָה֙ וּ/מִ/שַּׁמְנָ֔/הּ וְ/אֵת֙ כָּל הַ/לְּבֹנָ֔ה אֲשֶׁ֖ר עַל הַ/מִּנְחָ֑ה וְ/הִקְטִ֣יר הַ/מִּזְבֵּ֗חַ רֵ֧יחַ נִיחֹ֛חַ אַזְכָּרָתָ֖/הּ לַ/יהוָֽה", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh spoke to Moses, saying,", "bsb": "Then the LORD said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde spake vnto Moses saynge.", "dra": "And the Lord spoke to Moses, saying:", "bbe": "And the Lord said to Moses,", "geneva": "Then the Lord spake vnto Moses, saying,", "wycliffe": "And the Lord spak to Moises, and seide,", "rotherham": "And Yahweh spake unto Moses saying:", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "And he shall take up therefrom his handful, of the fine flour of the meal-offering, and of the oil thereof, and all the frankincense which is upon the meal-offering, and shall make the memorial-part thereof smoke upon the altar for a sweet savour unto HaShem.", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "locutus est Dominus ad Mosen dicens;", "brenton": "Charge Aaron and his sons, saying,"}}, {"v": 9, "ref": "6:9", "o": "וְ/הַ/נּוֹתֶ֣רֶת מִמֶּ֔/נָּה יֹאכְל֖וּ אַהֲרֹ֣ן וּ/בָנָ֑י/ו מַצּ֤וֹת תֵּֽאָכֵל֙ בְּ/מָק֣וֹם קָדֹ֔שׁ בַּ/חֲצַ֥ר אֹֽהֶל מוֹעֵ֖ד יֹאכְלֽוּ/הָ", "en": {"kjv": "Command Aaron and his sons, saying, This is the law of the burnt offering: It is the burnt offering, because of the burning upon the altar all night unto the morning, and the fire of the altar shall be burning in it.", "web": "“Command Aaron and his sons, saying, ‘This is the law of the burnt offering: the burnt offering shall be on the hearth on the altar all night until the morning; and the fire of the altar shall be kept burning on it.", "bsb": "“Command Aaron and his sons that this is the law of the burnt offering: The burnt offering is to remain on the hearth of the altar all night, until morning, and the fire must be kept burning on the altar.", "asv": "Command Aaron and his sons, saying, This is the law of the burnt-offering: the burnt-offering shall be on the hearth upon the altar all night unto the morning; and the fire of the altar shall be kept burning thereon.", "ylt": "`Command Aaron and his sons, saying, This is a law of the burnt-offering (it is the burnt-offering, because of the burning on the altar all the night unto the morning, and the fire of the altar is burning on it,)", "tyndale": "Commaunde Aaron and his sonnes saynge: this is the lawe of the burntoffrynge. The burntofferynge shalbe apon the herth of the alter all nyghte vnto the mornynge, and the fire of the alter shall burne therein.", "dra": "Command Aaron and his sons: This is the law of a holocaust. It shall be burnt upon the altar, all night until morning: the fire shall be of the same altar.", "bbe": "Give orders to Aaron and to his sons, saying, This is the law for the burned offering: the offering is to be on the fire-wood on the altar all night till the morning; and the fire of the altar is to be kept burning.", "geneva": "Commaund Aaron and his sonnes, saying, This is the lawe of the burnt offring, (it is the burnt offring because it burneth vpon the altar al the night vnto the morning, and the fire burneth on the altar)", "wycliffe": "Comaunde thou to Aaron, and to hise sones, This is the lawe of brent sacrifice; it schal be brent in the auter al nyyt til the morewe; fier that is youun fro heuene schal be of the same auter.", "rotherham": "Command Aaron and his sons, saying, This is the law of the ascending-sacrifice,—the same, is the ascending-sacrifice, which is upon the hearth, upon the altar, all the night until the morning,—and the fire of the altar, shall be kept burning therein.", "darby": "Command Aaron and his sons, saying, This is the law of the burnt-offering; this, the burnt-offering, shall be on the hearth on the altar all night unto the morning, and the fire of the altar shall be kept burning on it.", "twenty": "", "jps": "And that which is left thereof shall Aaron and his sons eat; it shall be eaten without leaven in a holy place; in the court of the tent of meeting they shall eat it.", "acv": "Command Aaron and his sons, saying, This is the law of the burnt offering: The burnt offering shall be on the hearth upon the altar all night to the morning, and the fire of the altar shall be kept burning on it.", "anderson": "", "haweis": "", "noyes": "", "webster": "Command Aaron and his sons, saying, This [is] the law of the burnt-offering: It [is] the burnt-offering, because of the burning upon the altar all night until the morning, and the fire of the altar shall be burning in it.", "vulgate": "praecipe Aaron et filiis eius haec est lex holocausti cremabitur in altari tota nocte usque mane ignis ex eodem altari erit;", "brenton": "This is the law of whole-burnt-offering; this is the whole-burnt-offering in its burning on the altar all the night till the morning; and the fire of the altar shall burn on it, it shall not be put out."}}, {"v": 10, "ref": "6:10", "o": "לֹ֤א תֵאָפֶה֙ חָמֵ֔ץ חֶלְקָ֛/ם נָתַ֥תִּי אֹתָ֖/הּ מֵ/אִשָּׁ֑/י קֹ֤דֶשׁ קָֽדָשִׁים֙ הִ֔וא כַּ/חַטָּ֖את וְ/כָ/אָשָֽׁם", "en": {"kjv": "And the priest shall put on his linen garment, and his linen breeches shall he put upon his flesh, and take up the ashes which the fire hath consumed with the burnt offering on the altar, and he shall put them beside the altar.", "web": "The priest shall put on his linen garment, and he shall put on his linen breeches upon his body; and he shall remove the ashes from where the fire has consumed the burnt offering on the altar, and he shall put them beside the altar.", "bsb": "And the priest shall put on his linen robe and linen undergarments, and he shall remove from the altar the ashes of the burnt offering that the fire has consumed and place them beside it.", "asv": "And the priest shall put on his linen garment, and his linen breeches shall he put upon his flesh; and he shall take up the ashes whereto the fire hath consumed the burnt-offering on the altar, and he shall put them beside the altar.", "ylt": "that the priest hath put on his long robe of fine linen, and his fine linen trousers he doth put on his flesh, and hath lifted up the ashes which the fire consumeth with the burnt-offering on the altar, and hath put them near the altar;", "tyndale": "And the preast shall put on his lynen albe and his lynen breches apon his flesh, and take awaye the asshes whiche the fire of the burntsacrifice in the altare hath made, and put them besyde the alter,", "dra": "The priest shall be vested with the tunick and the linen breeches; and he shall take up the ashes of that which the devouring fire hath burnt: and putting them beside the altar,", "bbe": "And the priest is to put on his linen robes and his linen trousers, and take up what is over of the offering after it has been burned on the altar, and put it by the side of the altar.", "geneva": "And the Priest shall put on his linen garment, and shall put on his linen breeches vpon his flesh, and take away the ashes when the fire hath consumed the burnt offring vpon the altar, and he shall put them beside the altar.", "wycliffe": "The preest schal be clothid with a coote, and `pryuy lynnun clothis; and he schal take awei the aischis, which the fier deuourynge brente, and he schal putte bisidis the auter;", "rotherham": "So then the priest shall put on his upper garment of linen, and, breeches of linen, shall he put on over his flesh, then shall he take up the fat-ashes, whereto the fire consumeth the ascending-sacrifice on the altar,—and shall put them beside the altar.", "darby": "And the priest shall put on his linen raiment, and his linen breeches shall he put on his flesh, and take up the ashes to which the fire hath consumed the burnt-offering on the altar, and he shall put them beside the altar.", "twenty": "", "jps": "It shall not be baked with leaven. I have given it as their portion of My offerings made by fire; it is most holy, as the sin-offering, and as the guilt-offering.", "acv": "And the priest shall put on his linen garment, and he shall put his linen breeches upon his flesh, and he shall take up the ashes of the fire which has consumed the burnt offering on the altar, and he shall put them beside the altar.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall put on his linen garment, and his linen breeches shall he put upon his flesh, and take up the ashes which the fire hath consumed with the burnt-offering on the altar, and he shall put them beside the altar.", "vulgate": "vestietur sacerdos tunica et feminalibus lineis tolletque cineres quos vorans ignis exusit et ponens iuxta altare;", "brenton": "And the priest shall put on the linen tunic, and he shall put the linen drawers on his body; and shall take away that which has been thoroughly burnt, which the fire shall have consumed, even the whole-burnt-offering from the altar, and he shall put it near the altar."}}, {"v": 11, "ref": "6:11", "o": "כָּל זָכָ֞ר בִּ/בְנֵ֤י אַהֲרֹן֙ יֹֽאכֲלֶ֔/נָּה חָק עוֹלָם֙ לְ/דֹרֹ֣תֵי/כֶ֔ם מֵ/אִשֵּׁ֖י יְהוָ֑ה כֹּ֛ל אֲשֶׁר יִגַּ֥ע בָּ/הֶ֖ם יִקְדָּֽשׁ", "en": {"kjv": "And he shall put off his garments, and put on other garments, and carry forth the ashes without the camp unto a clean place.", "web": "He shall take off his garments, and put on other garments, and carry the ashes outside the camp to a clean place.", "bsb": "Then he must take off his garments, put on other clothes, and carry the ashes outside the camp to a ceremonially clean place.", "asv": "And he shall put off his garments, and put on other garments, and carry forth the ashes without the camp unto a clean place.", "ylt": "and he hath stripped off his garments, and hath put on other garments, and hath brought out the ashes unto the outside of the camp, unto a clean place.", "tyndale": "ad the put off his raymet ad put on other and carye the asshes out without the hoste vnto a clene place.", "dra": "Shall put off his former vestments, and being clothed with others, shall carry them forth without the camp, and shall cause them to be consumed to dust in a very clean place.", "bbe": "Then having taken off his linen robes and put on other clothing, he is to take it away into a clean place, outside the tent-circle.", "geneva": "After, he shall put off his garments, and put on other raiment, and cary the ashes foorth without the hoste vnto a cleane place.", "wycliffe": "and he schal be spuylid of the formere clothis, and he schal be clothid with other, and schal bere aischis out of the castels, and in a moost clene place he schal make tho to be wastid til to a deed sparcle.", "rotherham": "Then shall he put off his garments, and put on other garments,—and shall carry forth the fat-ashes unto the outside of the camp, unto a clean place,", "darby": "And he shall put off his garments, and put on other garments, and carry forth the ashes without the camp unto a clean place.", "twenty": "", "jps": "Every male among the children of Aaron may eat of it, as a due for ever throughout your generations, from the offerings of HaShem made by fire; whatsoever toucheth them shall be holy.", "acv": "And he shall put off his garments, and put on other garments, and carry forth the ashes outside the camp to a clean place.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall put off his garments, and put on other garments, and carry forth the ashes without the camp to a clean place.", "vulgate": "spoliabitur prioribus vestimentis indutusque aliis efferet eos extra castra et in loco mundissimo usque ad favillam consumi faciet;", "brenton": "And he shall put off his robe, and put on another robe, and he shall take forth the offering that has been burnt without the camp into a clean place."}}, {"v": 12, "ref": "6:12", "o": "וַ/יְדַבֵּ֥ר יְהוָ֖ה אֶל מֹשֶׁ֥ה לֵּ/אמֹֽר", "en": {"kjv": "And the fire upon the altar shall be burning in it; it shall not be put out: and the priest shall burn wood on it every morning, and lay the burnt offering in order upon it; and he shall burn thereon the fat of the peace offerings.", "web": "The fire on the altar shall be kept burning on it, it shall not go out; and the priest shall burn wood on it every morning: and he shall lay the burnt offering in order upon it, and shall burn on it the fat of the peace offerings.", "bsb": "The fire on the altar shall be kept burning; it must not be extinguished. Every morning the priest is to add wood to the fire, arrange the burnt offering on it, and burn the fat portions of the peace offerings on it.", "asv": "And the fire upon the altar shall be kept burning thereon, it shall not go out; and the priest shall burn wood on it every morning: and he shall lay the burnt-offering in order upon it, and shall burn thereon the fat of the peace-offerings.", "ylt": "`And the fire on the altar is burning on it, it is not quenched, and the priest hath burned on it wood morning by morning, and hath arranged on it the burnt-offering, and hath made perfume on it with the fat of the peace-offerings;", "tyndale": "The fire that is apon the alter shall burne therein and not goo out. And the preast shall put wodd on the fire euery morninge ad put the burntsacrifice apon it, and he shall burne thereon the fatt of the peaceofferynges.", "dra": "And the fire on the altar shall always burn, and the priest shall feed it, putting wood on it every day in the morning: and laying on the holocaust, shall burn thereupon the fat of the peace offerings.", "bbe": "The fire on the altar is to be kept burning; it is never to go out; every morning the priest is to put wood on it, placing the burned offering in order on it, and there the fat of the peace-offering is to be burned.", "geneva": "But the fire vpon the altar shall burne thereon and neuer be put out: wherefore the Priest shall burne wood on it euery morning, and lay the burnt offering in order vpon it, and he shall burne thereon the fat of the peace offrings.", "wycliffe": "Forsothe fier schal brenne euere in the auter, which fier the preest schal nurische, puttynge trees vndur, in the morewtid bi ech dai; and whanne brent sacrifice is put aboue, the preest schal brenne the ynnere fatnessis of pesible thingis.", "rotherham": "And, the fire on the altar, shall be kept burning therein, it shall not be suffered to go out, but the priest shall kindle up thereon pieces of wood, morning by morning,—and shall set in order thereupon the ascending-sacrifice, and shall make a perfume thereon with the fat-pieces of the peace-offerings:", "darby": "And the fire upon the altar shall be kept burning on it: it shall not be put out; and the priest shall burn wood on it every morning, and lay the burnt-offering in order upon it; and he shall burn thereon the fat of the peace-offerings.", "twenty": "", "jps": "And HaShem spoke unto Moses, saying:", "acv": "And the fire upon the altar shall be kept burning on it; it shall not go out. And the priest shall burn wood on it every morning, and he shall lay the burnt offering in order upon it, and shall burn the fat of the peace offerings on it.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the fire upon the altar shall be burning on it; it shall not be extinguished: and the priest shall burn wood on it every morning, and lay the burnt-offering in order upon it; and he shall burn on it the fat of the peace-offerings.", "vulgate": "ignis autem in altari semper ardebit quem nutriet sacerdos subiciens ligna mane per singulos dies et inposito holocausto desuper adolebit adipes pacificorum;", "brenton": "And the fire on the altar shall be kept burning on it, and shall not be extinguished; and the priest shall burn on it wood every morning, and shall heap on it the whole-burnt-offering, and shall lay on it the fat of the peace-offering."}}, {"v": 13, "ref": "6:13", "o": "זֶ֡ה קָרְבַּן֩ אַהֲרֹ֨ן וּ/בָנָ֜י/ו אֲשֶׁר יַקְרִ֣יבוּ לַֽ/יהוָ֗ה בְּ/יוֹם֙ הִמָּשַׁ֣ח אֹת֔/וֹ עֲשִׂירִ֨ת הָ/אֵפָ֥ה סֹ֛לֶת מִנְחָ֖ה תָּמִ֑יד מַחֲצִיתָ֣/הּ בַּ/בֹּ֔קֶר וּ/מַחֲצִיתָ֖/הּ בָּ/עָֽרֶב", "en": {"kjv": "The fire shall ever be burning upon the altar; it shall never go out.", "web": "Fire shall be kept burning on the altar continually; it shall not go out.", "bsb": "The fire shall be kept burning on the altar continually; it must not be extinguished.", "asv": "Fire shall be kept burning upon the altar continually; it shall not go out.", "ylt": "fire is continually burning on the altar, it is not quenched.", "tyndale": "The fire shall euer burne apon the alter and neuer goo out.", "dra": "This is the perpetual fire which shall never go out on the altar.", "bbe": "Let the fire be kept burning on the altar at all times; it is never to go out.", "geneva": "The fire shall euer burne vpon the altar, and neuer go out.", "wycliffe": "This is euerlastynge fier, that schal neuer faile in the auter.", "rotherham": "fire, shall continually be kept burning on the altar, it shall not be suffered to go out.", "darby": "A continual fire shall be kept burning on the altar: it shall never go out.", "twenty": "", "jps": "This is the offering of Aaron and of his sons, which they shall offer unto HaShem in the day when he is anointed: the tenth part of an ephah of fine flour for a meal-offering perpetually, half of it in the morning, and half thereof in the evening.", "acv": "Fire shall be kept burning upon the altar continually; it shall not go out.", "anderson": "", "haweis": "", "noyes": "", "webster": "The fire shall ever be burning upon the altar; it shall never go out.", "vulgate": "ignis est iste perpetuus qui numquam deficiet in altari;", "brenton": "And the fire shall always burn on the altar; it shall not be extinguished."}}, {"v": 14, "ref": "6:14", "o": "עַֽל מַחֲבַ֗ת בַּ/שֶּׁ֛מֶן תֵּעָשֶׂ֖ה מֻרְבֶּ֣כֶת תְּבִיאֶ֑/נָּה תֻּפִינֵי֙ מִנְחַ֣ת פִּתִּ֔ים תַּקְרִ֥יב רֵֽיחַ נִיחֹ֖חַ לַ/יהוָֽה", "en": {"kjv": "And this is the law of the meat offering: the sons of Aaron shall offer it before the Lord, before the altar.", "web": "“‘This is the law of the meal offering: the sons of Aaron shall offer it before Yahweh, before the altar.", "bsb": "Now this is the law of the grain offering: Aaron’s sons shall present it before the LORD in front of the altar.", "asv": "And this is the law of the meal-offering: the sons of Aaron shall offer it before Jehovah, before the altar.", "ylt": "`And this is a law of the present: sons of Aaron have brought it near before Jehovah unto the front of the altar,", "tyndale": "This is the lawe of the meatoffrynge: Aarons sonnes shall bringe it before the Lorde, vnto the alter:", "dra": "This is the law of the sacrifice and libations, which the children of Aaron shall offer before the Lord, and before the altar.", "bbe": "And this is the law for the meal offering: it is to be offered to the Lord before the altar by the sons of Aaron.", "geneva": "Also this is the lawe of the meate offring, which Aarons sonnes shall offer in the presence of the Lord, before the altar.", "wycliffe": "This is the lawe of sacrifice, and of fletynge offryngis, whiche `the sones of Aaron schulen offre bifore the Lord, and bifor the auter.", "rotherham": "And, this, is the law of the meal-offering,—the sons of Aaron shall bring it near before Yahweh, unto the front of the altar.", "darby": "And this is the law of the oblation: [one of] the sons of Aaron shall present it before Jehovah, before the altar.", "twenty": "", "jps": "On a griddle it shall be made with oil; when it is soaked, thou shalt bring it in; in broken pieces shalt thou offer the meal-offering for a sweet savour unto HaShem.", "acv": "And this is the law of the meal offering: The sons of Aaron shall offer it before Jehovah, before the altar.", "anderson": "", "haweis": "", "noyes": "", "webster": "And this [is] the law of the meat-offering: the sons of Aaron shall offer it before the LORD, before the altar.", "vulgate": "haec est lex sacrificii et libamentorum quae offerent filii Aaron coram Domino et coram altari;", "brenton": "This is the law of the sacrifice, which the sons of Aaron shall bring near before the Lord, before the altar."}}, {"v": 15, "ref": "6:15", "o": "וְ/הַ/כֹּהֵ֨ן הַ/מָּשִׁ֧יחַ תַּחְתָּ֛י/ו מִ/בָּנָ֖י/ו יַעֲשֶׂ֣ה אֹתָ֑/הּ חָק עוֹלָ֕ם לַ/יהוָ֖ה כָּלִ֥יל תָּקְטָֽר", "en": {"kjv": "And he shall take of it his handful, of the flour of the meat offering, and of the oil thereof, and all the frankincense which is upon the meat offering, and shall burn it upon the altar for a sweet savour, even the memorial of it, unto the Lord.", "web": "He shall take from there his handful of the fine flour of the meal offering, and of its oil, and all the frankincense which is on the meal offering, and shall burn it on the altar for a pleasant aroma, as its memorial, to Yahweh.", "bsb": "The priest is to remove a handful of fine flour and olive oil, together with all the frankincense from the grain offering, and burn the memorial portion on the altar as a pleasing aroma to the LORD.", "asv": "And he shall take up therefrom his handful, of the fine flour of the meal-offering, and of the oil thereof, and all the frankincense which is upon the meal-offering, and shall burn it upon the altar for a sweet savor, as the memorial thereof, unto Jehovah.", "ylt": "and one hath lifted up of it with his hand from the flour of the present, and from its oil, and all the frankincense which is on the present, and hath made perfume on the altar, sweet fragrance--its memorial to Jehovah.", "tyndale": "and one of them shall take hys handfull of the floure of the meatoffrynge ad of the oyle with all the frankencens whiche ys thereon and shall burne it vnto a remebraunce apon the alter to be a swete sauoure of the memoriall of it vnto the Lorde.", "dra": "The priest shall take a handful of the flour that is tempered with oil, and all the frankincense that is put upon the flour: and he shall burn on the altar for a memorial of most sweet odour to the Lord.", "bbe": "The priest is to take in his hand some of the meal of the meal offering and of the oil of it, and all the perfume on it, burning it on the altar as a sign, for a sweet smell to the Lord.", "geneva": "He shall euen take thence his handfull of fine flowre of the meate offring and of the oyle, and all the incense which is vpon the meat offring, and shall burne it vpon the altar for a sweete sauour, as a memoriall therefore vnto the Lord:", "wycliffe": "The preest schal take an handful of wheete flour, which is spreynd with oile, and al the encense which is put on the wheete flour, and he schal brenne it in the auter, in to mynde of swettist odour to the Lord.", "rotherham": "Then shall one lift up therefrom a handful of the fine meal of the meal-offering, and of the oil thereof, and all the frankincense which is upon the meal-offering,—and shall make a perfume at the altar, an altar-flame of a satisfying odour, shall the memorial thereof be, unto Yahweh.", "darby": "And he shall take of it his handful of the fine flour of the oblation, and of the oil thereof, and all the frankincense which is on the meat-offering, and shall burn [it] on the altar: [it is] a sweet odour of the memorial thereof to Jehovah.", "twenty": "", "jps": "And the anointed priest that shall be in his stead from among his sons shall offer it, it is a due for ever; it shall be wholly made to smoke unto HaShem.", "acv": "And he shall take up his handful from it, of the fine flour of the meal offering, and of the oil of it, and all the frankincense which is upon the meal offering, and shall burn it upon the altar for a sweet savor, as the memorial of it, to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall take of it his handful, of the flour of the meat-offering, and of the oil thereof, and all the frankincense which [is] upon the meat-offering, and shall burn [it] upon the altar [for] a sweet savor, [even] the memorial of it, to the LORD.", "vulgate": "tollet sacerdos pugillum similae quae conspersa est oleo et totum tus quod super similam positum est adolebitque illud in altari in monumentum odoris suavissimi Domino;", "brenton": "And he shall take from it a handful of the fine flour of the sacrifice with its oil, and with all its frankincense, which are upon the sacrifice; and he shall offer up on the altar a burnt-offering as a sweet-smelling savour, a memorial of it to the Lord."}}, {"v": 16, "ref": "6:16", "o": "וְ/כָל מִנְחַ֥ת כֹּהֵ֛ן כָּלִ֥יל תִּהְיֶ֖ה לֹ֥א תֵאָכֵֽל", "en": {"kjv": "And the remainder thereof shall Aaron and his sons eat: with unleavened bread shall it be eaten in the holy place; in the court of the tabernacle of the congregation they shall eat it.", "web": "That which is left of it Aaron and his sons shall eat. It shall be eaten without yeast in a holy place. They shall eat it in the court of the Tent of Meeting.", "bsb": "Aaron and his sons are to eat the remainder. It must be eaten without leaven in a holy place; they are to eat it in the courtyard of the Tent of Meeting.", "asv": "And that which is left thereof shall Aaron and his sons eat: it shall be eaten without leaven in a holy place; in the court of the tent of meeting they shall eat it.", "ylt": "`And the remnant of it do Aaron and his sons eat; with unleavened things it is eaten, in the holy place, in the court of the tent of meeting they do eat it.", "tyndale": "And the rest thereof, Aaron ad his sonnes shall eate: vnleuended it shalbe eaten in the holy place: eue in the courte of the tabernacle of witnesse they shall eate it.", "dra": "And the part of the flour that is left, Aaron and his sons shall eat, without leaven: and he shall eat it in the holy place of the court of the tabernacle.", "bbe": "And whatever is over Aaron and his sons may have for their food, taking it without leaven in a holy place; in the open space of the Tent of meeting they may take a meal of it.", "geneva": "But the rest thereof shall Aaron and his sonnes eate: it shalbe eaten without leauen in the holy place: in the court of the Tabernacle of the Congregation they shall eate it.", "wycliffe": "Forsothe Aaron with hise sones schal ete the tother part of wheete flour, without sour dow; and he schal ete in the hooli place of the greet street of the tabernacle.", "rotherham": "And the remainder thereof, shall Aaron and his sons eat,—as unleavened cakes, shall it be eaten, in a holy place, within the court of the tent of meeting, shall they eat it.", "darby": "And the remainder thereof shall Aaron and his sons eat: unleavened shall it be eaten in a holy place; in the court of the tent of meeting shall they eat it.", "twenty": "", "jps": "And every meal-offering of the priest shall be wholly made to smoke; it shall not be eaten.", "acv": "And that which is left of it Aaron and his sons shall eat. It shall be eaten without leaven in a holy place. They shall eat it in the court of the tent of meeting.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the remainder of it shall Aaron and his sons eat: with unleavened bread shall it be eaten in the holy place; in the court of the tabernacle of the congregation they shall eat it.", "vulgate": "reliquam autem partem similae comedet Aaron cum filiis suis absque fermento et comedet in loco sancto atrii tabernaculi;", "brenton": "And Aaron and his sons shall eat that which is left of it: it shall be eaten without leaven in a holy place, they shall eat it in the court of the tabernacle of witness."}}, {"v": 17, "ref": "6:17", "o": "וַ/יְדַבֵּ֥ר יְהוָ֖ה אֶל מֹשֶׁ֥ה לֵּ/אמֹֽר", "en": {"kjv": "It shall not be baken with leaven. I have given it unto them for their portion of my offerings made by fire; it is most holy, as is the sin offering, and as the trespass offering.", "web": "It shall not be baked with yeast. I have given it as their portion of my offerings made by fire. It is most holy, as the sin offering, and as the trespass offering.", "bsb": "It must not be baked with leaven; I have assigned it as their portion of My offerings made by fire. It is most holy, like the sin offering and the guilt offering.", "asv": "It shall not be baken with leaven. I have given it as their portion of my offerings made by fire; it is most holy, as the sin-offering, and as the trespass-offering.", "ylt": "It is not baken with any thing fermented, their portion I have given it, out of My fire-offerings; it is most holy, like the sin-offering, and like the guilt-offering.", "tyndale": "Their parte whiche I haue geuen them of my sacrifice, shall not be baken with leuen, for it is most holye, as is the synneofferynge, and trespaceoffrynge.", "dra": "And therefore it shall not be leavened, because part thereof is offered for the burnt sacrifice of the Lord. It shall be most holy, as that which is offered for sin and for trespass.", "bbe": "It is not to be cooked with leaven. I have given it to them as their part of the offerings made by fire to me; it is most holy, as are the sin-offerings and the offerings for error.", "geneva": "It shall not be baken with leauen: I haue giuen it for their portion of mine offrings made by fire: for it is as the sinne offering and as the trespasse offring.", "wycliffe": "Sotheli herfor it schal not be `diyt with sour dow, for a part therof is offrid in to encense of the Lord; it schal be hooli `of the noumbre of holi thingis, as for synne and for trespas.", "rotherham": "It shall not be baked into anything leavened, as their portion, have I given it, from among the altar-flames of Yahweh,—most holy, it is, like the sin-bearer, and like the guilt-bearer,", "darby": "It shall not be baken with leaven. As their portion have I given it [unto them] of my offerings by fire: it is most holy; as the sin-offering, and as the trespass-offering.", "twenty": "", "jps": "And HaShem spoke unto Moses, saying:", "acv": "It shall not be baked with leaven. I have given it as their portion of my offerings made by fire, it is most holy, as the sin offering, and as the trespass offering.", "anderson": "", "haweis": "", "noyes": "", "webster": "It shall not be baked with leaven. I have given it [to them for] their portion of my offerings made by fire; It [is] most holy, as [is] the sin-offering, and as the trespass-offering.", "vulgate": "ideo autem non fermentabitur quia pars eius in Domini offertur incensum sanctum sanctorum erit sicut pro peccato atque delicto;", "brenton": "It shall not be baked with leaven. I have given it as a portion to them of the burnt-offerings of the Lord: it is most holy, as the offering for sin, and as the offering for trespass."}}, {"v": 18, "ref": "6:18", "o": "דַּבֵּ֤ר אֶֽל אַהֲרֹן֙ וְ/אֶל בָּנָ֣י/ו לֵ/אמֹ֔ר זֹ֥את תּוֹרַ֖ת הַֽ/חַטָּ֑את בִּ/מְק֡וֹם אֲשֶׁר֩ תִּשָּׁחֵ֨ט הָ/עֹלָ֜ה תִּשָּׁחֵ֤ט הַֽ/חַטָּאת֙ לִ/פְנֵ֣י יְהוָ֔ה קֹ֥דֶשׁ קָֽדָשִׁ֖ים הִֽוא", "en": {"kjv": "All the males among the children of Aaron shall eat of it. It shall be a statute for ever in your generations concerning the offerings of the Lord made by fire: every one that toucheth them shall be holy.", "web": "Every male among the children of Aaron shall eat of it, as their portion forever throughout your generations, from the offerings of Yahweh made by fire. Whoever touches them shall be holy.’”", "bsb": "Any male among the sons of Aaron may eat it. This is a permanent portion from the offerings made by fire to the LORD for the generations to come. Anything that touches them will become holy.”", "asv": "Every male among the children of Aaron shall eat of it, as his portion for ever throughout your generations, from the offerings of Jehovah made by fire: whosoever toucheth them shall be holy.", "ylt": "Every male among the sons of Aaron doth eat it--a statute age-during to your generations, out of the fire-offerings of Jehovah: all that cometh against them is holy.'", "tyndale": "All the males amonge the childern of Aaron, shall eate of it: and it shalbe a dutye for euer vnto youre generacyons of the sacrifices of the Lorde, nether shal any man twytche it, but he that is halowed.", "dra": "The males only of the race of Aaron shall eat it. It shall be an ordinance everlasting in your generations concerning the sacrifices of the Lord: Every one that toucheth them shall be sanctified.", "bbe": "Every male among the children of Aaron may have it for food; it is their right for ever through all your generations, from the offerings made by fire to the Lord: anyone touching them will be holy.", "geneva": "All the males among the children of Aaron shall eate of it: It shalbe a statute for euer in your generations concerning the offrings of the Lord, made by fire: whatsoeuer toucheth them shall be holy.", "wycliffe": "Malis oonli of the kynrede of Aaron schulen ete it; it is a lawful thing and euerlastynge in youre generaciouns, of the sacrifice of the Lord; ech man that touchith tho schal be halewyd.", "rotherham": "Any male among the sons of Aaron may eat it, an age-abiding statute to your generations from among the altar-flames of Yahweh,—every one that toucheth them shall be hallowed.", "darby": "All the males among the children of Aaron shall eat of it. [It is] an everlasting statute in your generations, [their portion] of Jehovah's offerings by fire: whatever toucheth these shall be holy.", "twenty": "", "jps": "Speak unto Aaron and to his sons, saying: This is the law of the sin-offering: in the place where the burnt-offering is killed shall the sin-offering be killed before HaShem; it is most holy.", "acv": "Every male among the sons of Aaron shall eat of it, as a portion forever throughout your generations, from the offerings of Jehovah made by fire. Whoever touches them shall be holy.", "anderson": "", "haweis": "", "noyes": "", "webster": "All the males among the children of Aaron shall eat of it. [It shall be] a statute for ever in your generations concerning the offerings of the LORD made by fire: every one that toucheth them shall be holy.", "vulgate": "mares tantum stirpis Aaron comedent illud legitimum ac sempiternum est in generationibus vestris de sacrificiis Domini omnis qui tetigerit illa sanctificabitur;", "brenton": "Every male of the priests shall eat it: it is a perpetual ordinance throughout your generations of the burnt-offerings of the Lord; whosoever shall touch them shall be hallowed."}}, {"v": 19, "ref": "6:19", "o": "הַ/כֹּהֵ֛ן הַֽ/מְחַטֵּ֥א אֹתָ֖/הּ יֹאכֲלֶ֑/נָּה בְּ/מָק֤וֹם קָדֹשׁ֙ תֵּֽאָכֵ֔ל בַּ/חֲצַ֖ר אֹ֥הֶל מוֹעֵֽד", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh spoke to Moses, saying,", "bsb": "Then the LORD said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde spake vnto Moses sayenge:", "dra": "And the Lord spoke to Moses, saying:", "bbe": "And the Lord said to Moses,", "geneva": "Agayne the Lord spake vnto Moses, saying,", "wycliffe": "And the Lord spak to Moises,", "rotherham": "And Yahweh spake unto Moses, saying—", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "The priest that offereth it for sin shall eat it; in a holy place shall it be eaten, in the court of the tent of meeting.", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "et locutus est Dominus ad Mosen dicens;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 20, "ref": "6:20", "o": "כֹּ֛ל אֲשֶׁר יִגַּ֥ע בִּ/בְשָׂרָ֖/הּ יִקְדָּ֑שׁ וַ/אֲשֶׁ֨ר יִזֶּ֤ה מִ/דָּמָ/הּ֙ עַל הַ/בֶּ֔גֶד אֲשֶׁר֙ יִזֶּ֣ה עָלֶ֔י/הָ תְּכַבֵּ֖ס בְּ/מָק֥וֹם קָדֹֽשׁ", "en": {"kjv": "This is the offering of Aaron and of his sons, which they shall offer unto the Lord in the day when he is anointed; the tenth part of an ephah of fine flour for a meat offering perpetual, half of it in the morning, and half thereof at night.", "web": "“This is the offering of Aaron and of his sons, which they shall offer to Yahweh in the day when he is anointed: the tenth part of an ephah of fine flour for a meal offering perpetually, half of it in the morning, and half of it in the evening.", "bsb": "“This is the offering that Aaron and his sons must present to the LORD on the day he is anointed: a tenth of an ephah of fine flour as a regular grain offering, half of it in the morning and half in the evening.", "asv": "This is the oblation of Aaron and of his sons, which they shall offer unto Jehovah in the day when he is anointed: the tenth part of an ephah of fine flour for a meal-offering perpetually, half of it in the morning, and half thereof in the evening.", "ylt": "`This is an offering of Aaron and of his sons, which they bring near to Jehovah in the day of his being anointed; a tenth of the ephah of flour for a continual present, half of it in the morning, and half of it in the evening;", "tyndale": "this is the offrynge of Aaron ad of his sonnes which he shall offer vnto the Lorde in the daye when they are anoynted: the tenth parte of an Epha of floure, which is a dayly meatofferinge perpetually: halfe in the morninge and halfe at nighte:", "dra": "This is the oblation of Aaron, and of his sons, which they must offer to the Lord, in the day of their anointing. They shall offer the tenth part of an ephi of flour for a perpetual sacrifice, half of it in the morning, and half of it in the evening.", "bbe": "This is the offering which Aaron and his sons are to make to the Lord on the day when he is made a priest: the tenth part of an ephah of the best meal for a meal offering for ever; half of it in the morning and half in the evening.", "geneva": "This is the offering of Aaron and his sonnes, which they shall offer vnto the Lord in the day when he is anointed: the tenth part of an Ephah of fine floure, for a meate offering perpetuall: halfe of it in ye morning, and halfe thereof at night.", "wycliffe": "and seide, This is the offryng of Aaron, and of hise sones, which thei owen offre to the Lord in the day of her anoyntyng ; thei schulen offre the tenthe part of ephi of wheete flour, in euerlastynge sacrifice, the myddis therof in the morewtid, and the myddis therof in the euentid;", "rotherham": "This, is the oblation of Aaron and his sons, which they shall bring near unto Yahweh in the day when he is anointed, The tenth of an ephah of fine meal, as a continual meal-offering,—half thereof in the morning, and half thereof in the evening;", "darby": "This is the offering of Aaron and of his sons, which they shall present to Jehovah on the day when he is anointed: the tenth part of an ephah of fine flour as a continual oblation, half of it in the morning, and half thereof at night.", "twenty": "", "jps": "Whatsoever shall touch the flesh thereof shall be holy; and when there is sprinkled of the blood thereof upon any garment, thou shalt wash that whereon it was sprinkled in a holy place.", "acv": "This is the oblation of Aaron and of his sons, which they shall offer to Jehovah in the day when he is anointed: the tenth part of an ephah of fine flour for a meal offering perpetually, half of it in the morning, and half of it in the evening.", "anderson": "", "haweis": "", "noyes": "", "webster": "This [is] the offering of Aaron and of his sons, which they shall offer to the LORD in the day when he is anointed; the tenth part of an ephah of fine flour for a meat-offering perpetual, half of it in the morning, and half of it at night.", "vulgate": "haec est oblatio Aaron et filiorum eius quam offerre debent Domino in die unctionis suae decimam partem oephi offerent similae in sacrificio sempiterno medium eius mane et medium vespere;", "brenton": "This is the gift of Aaron and of his sons, which they shall offer to the Lord in the day in which thou shalt anoint him; the tenth of an ephah of fine flour for a sacrifice continually, the half of it in the morning, and the half of it in the evening."}}, {"v": 21, "ref": "6:21", "o": "וּ/כְלִי חֶ֛רֶשׂ אֲשֶׁ֥ר תְּבֻשַּׁל בּ֖/וֹ יִשָּׁבֵ֑ר וְ/אִם בִּ/כְלִ֤י נְחֹ֨שֶׁת֙ בֻּשָּׁ֔לָה וּ/מֹרַ֥ק וְ/שֻׁטַּ֖ף בַּ/מָּֽיִם", "en": {"kjv": "In a pan it shall be made with oil; and when it is baken, thou shalt bring it in: and the baken pieces of the meat offering shalt thou offer for a sweet savour unto the Lord.", "web": "It shall be made with oil in a griddle. When it is soaked, you shall bring it in. You shall offer the meal offering in baked pieces for a pleasant aroma to Yahweh.", "bsb": "It shall be prepared with oil on a griddle; you are to bring it well-kneaded and present it as a grain offering broken in pieces, a pleasing aroma to the LORD.", "asv": "On a baking-pan it shall be made with oil; when it is soaked, thou shalt bring it in: in baken pieces shalt thou offer the meal-offering for a sweet savor unto Jehovah.", "ylt": "on a girdel with oil it is made--fried thou dost bring it in; baked pieces of the present thou dost bring near, a sweet fragrance to Jehovah.", "tyndale": "ad in the fryenge pan it shalbe made with oyle. And whe it is fryed, thou shalt brynge it in as a baken meatofferynge mynsed small, and shalt offer it for a swete sauoure vnto the Lorde.", "dra": "It shall be tempered with oil, and shall be fried in a fryingpan.", "bbe": "Let it be made with oil on a flat plate; when it is well mixed and cooked, let it be broken and taken in as a meal offering, for a sweet smell to the Lord.", "geneva": "In the frying panne it shalbe made with oyle: thou shalt bring it fryed, and shalt offer the baken pieces of the meate offering for a sweete sauour vnto the Lord.", "wycliffe": "which schal be spreynt with oile in the friyng panne, and schal be fried.", "rotherham": "on a pan, with oil, shall it be made when well mingled, shalt thou bring it in,—in baked portions, as a meal-offering in pieces, shalt thou bring it near as a satisfying odour unto Yahweh.", "darby": "It shall be prepared in the pan with oil: saturated with oil shalt thou bring it: baken pieces of the oblation shalt thou present [for] a sweet odour to Jehovah.", "twenty": "", "jps": "But the earthen vessel wherein it is sodden shall be broken; and if it be sodden in a brazen vessel, it shall be scoured, and rinsed in water. 22 Every male among the priests may eat thereof; it is most holy.", "acv": "It shall be made with oil on a baking-pan. Thou shall bring it in when it is soaked. Thou shall offer the meal offering in baked pieces for a sweet savor to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "In a pan it shall be made with oil; [and when it is] baked, thou shalt bring it in: [and] the baked pieces of the meat-offering shalt thou offer [for] a sweet savor to the LORD.", "vulgate": "quae in sartagine oleo conspersa frigetur offeret autem eam calidam in odorem suavissimum Domino;", "brenton": "It shall be made with oil in a frying-pan; he shall offer it kneaded and in rolls, an offering of fragments, an offering of a sweet savour unto the Lord."}}, {"v": 22, "ref": "6:22", "o": "כָּל זָכָ֥ר בַּ/כֹּהֲנִ֖ים יֹאכַ֣ל אֹתָ֑/הּ קֹ֥דֶשׁ קָֽדָשִׁ֖ים הִֽוא", "en": {"kjv": "And the priest of his sons that is anointed in his stead shall offer it: it is a statute for ever unto the Lord; it shall be wholly burnt.", "web": "The anointed priest that will be in his place from among his sons shall offer it. By a statute forever, it shall be wholly burnt to Yahweh.", "bsb": "The priest, who is one of Aaron’s sons and will be anointed to take his place, is to prepare it. As a permanent portion for the LORD, it must be burned completely.", "asv": "And the anointed priest that shall be in his stead from among his sons shall offer it: by a statute for ever it shall be wholly burnt unto Jehovah.", "ylt": "`And the priest who is anointed in his stead, from among his sons, doth make it, --a statute age-during of Jehovah: it is completely perfumed;", "tyndale": "And that preast of his sonnes that is anoynted in his steade, shall offer it: ad it shall be the lordes dutye for euer, and it shalbe burnt altogether.", "dra": "And the priest that rightfully succeedeth his father, shall offer it hot, for a most sweet odour to the Lord: and it shall he wholly burnt on the altar.", "bbe": "And the same offering is to be given by that one of his sons who takes his place as priest; by an order for ever, all of it is to be burned before the Lord.", "geneva": "And the Priest that is anointed in his steade, among his sonnes shall offer it: It is the Lordes ordinance for euer, it shall be burnt altogether.", "wycliffe": "Sotheli the preest which is successour to the fadir `bi riyt, schal offre it hoot, in to sweteste odour to the Lord; and al it schal be brent in the auter.", "rotherham": "And the priest that is anointed in his stead from among his sons, shall prepare it,—[it is] an age-abiding statute, that unto Yahweh, shall a perfume, of the entire gift, be made:", "darby": "And the priest who is anointed of his sons in his stead shall prepare it: [it is] an everlasting statute; it shall be wholly burned to Jehovah.", "twenty": "", "jps": "", "acv": "And the anointed priest who shall be in his stead from among his sons shall offer it. It shall be wholly burnt to Jehovah by a statute forever.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest of his sons that is anointed in his stead shall offer it: [it is] a statute for ever to the LORD; it shall be wholly burnt.", "vulgate": "sacerdos qui patri iure successerit et tota cremabitur in altari;", "brenton": "The anointed priest who is in his place, one of his sons, shall offer it: it is a perpetual statute, it shall all be consumed."}}, {"v": 23, "ref": "6:23", "o": "וְ/כָל חַטָּ֡את אֲשֶׁר֩ יוּבָ֨א מִ/דָּמָ֜/הּ אֶל אֹ֧הֶל מוֹעֵ֛ד לְ/כַפֵּ֥ר בַּ/קֹּ֖דֶשׁ לֹ֣א תֵאָכֵ֑ל בָּ/אֵ֖שׁ תִּשָּׂרֵֽף", "en": {"kjv": "For every meat offering for the priest shall be wholly burnt: it shall not be eaten.", "web": "Every meal offering of a priest shall be wholly burned. It shall not be eaten.”", "bsb": "Every grain offering for a priest shall be burned completely; it is not to be eaten.”", "asv": "And every meal-offering of the priest shall be wholly burnt: it shall not be eaten.", "ylt": "and every present of a priest is a whole burnt-offering; it is not eaten.'", "tyndale": "For all the meatoffrynges of the preastes shalbe burnt altogether, ad shal not be eaten.", "dra": "For every sacrifice of the priest shall be consumed with fire: neither shall any man eat thereof.", "bbe": "Every meal offering offered for the priest is to be completely burned: nothing of it is to be taken for food.", "geneva": "For euery meate offring of the Priest shall be burnt altogether, it shall not be eaten.", "wycliffe": "For al the sacrifice of preestis schal be wastid with fier, nether ony man schal ete therof.", "rotherham": "yea, every meal-offering of a priest, shall be, entire—it shall not be eaten.", "darby": "And every oblation of the priest shall be wholly burned; it shall not be eaten.", "twenty": "", "jps": "And no sin-offering, whereof any of the blood is brought into the tent of meeting to make atonement in the holy place, shall be eaten; it shall be burnt with fire.", "acv": "And every meal offering of the priest shall be wholly burnt; it shall not be eaten.", "anderson": "", "haweis": "", "noyes": "", "webster": "For every meat-offering for the priest shall be wholly burnt: it shall not be eaten.", "vulgate": "omne enim sacrificium sacerdotum igne consumetur nec quisquam comedet ex eo;", "brenton": "And every sacrifice of a priest shall be thoroughly burnt, and shall not be eaten."}}, {"v": 24, "ref": "6:24", "o": "", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh spoke to Moses, saying,", "bsb": "And the LORD said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde talked with Moses sayenge:", "dra": "And the Lord spoke to Moses. saying:", "bbe": "And the Lord said to Moses,", "geneva": "Furthermore, the Lord spake vnto Moses, saying,", "wycliffe": "And the Lord spak to Moises, and seide,", "rotherham": "And Yahweh spake unto Moses, saying—", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "locutus est Dominus ad Mosen dicens;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 25, "ref": "6:25", "o": "", "en": {"kjv": "Speak unto Aaron and to his sons, saying, This is the law of the sin offering: In the place where the burnt offering is killed shall the sin offering be killed before the Lord: it is most holy.", "web": "“Speak to Aaron and to his sons, saying, ‘This is the law of the sin offering: in the place where the burnt offering is killed, the sin offering shall be killed before Yahweh. It is most holy.", "bsb": "“Tell Aaron and his sons that this is the law of the sin offering: In the place where the burnt offering is slaughtered, the sin offering shall be slaughtered before the LORD; it is most holy.", "asv": "Speak unto Aaron and to his sons, saying, This is the law of the sin-offering: in the place where the burnt-offering is killed shall the sin-offering be killed before Jehovah: it is most holy.", "ylt": "`Speak unto Aaron and unto his sons, saying, This is a law of the sin-offering: in the place where the burnt-offering is slaughtered is the sin-offering slaughtered before Jehovah; it is most holy.", "tyndale": "speake vnto Aaron and vnto his sonnes and saye. This is the lawe of the synneoffrynge, In the place where the burntofferynge is kylled, shall the synneofferynge be kylled also before the Lorde, for it is most holy.", "dra": "Say to Aaron and his sons: This is the law of the victim for sin. In the place where the holocaust is offered, it shall be immolated before the Lord. It is holy of holies.", "bbe": "Say to Aaron and his sons, This is the law for the sin-offering: the sin-offering is to be put to death before the Lord in the same place as the burned offering; it is most holy.", "geneva": "Speake vnto Aaron, and vnto his sonnes, and say, This is the Lawe of the sinne offering, In the place where the burnt offring is killed, shall the sinne offring be killed before the Lord, for it is most holy.", "wycliffe": "Spek thou to Aaron and to hise sones, This is the lawe of sacrifice for synne; it schal be offrid bifor the Lord, in the place where brent sacrifice is offrid; it is hooli `of the noumbre of hooli thingis.", "rotherham": "Speak unto Aaron and unto his sons, saying, This, is the law of the sin-bearer. In the place where the ascending-sacrifice is slain, shall the sin-bearer be slain, before Yahweh, most holy, it is.", "darby": "Speak unto Aaron and to his sons, saying, This is the law of the sin-offering. At the place where the burnt-offering is slaughtered shall the sin-offering be slaughtered before Jehovah: it is most holy.", "twenty": "", "jps": "", "acv": "Speak to Aaron and to his sons, saying, This is the law of the sin offering: In the place where the burnt offering is killed the sin offering shall be killed before Jehovah. It is most holy.", "anderson": "", "haweis": "", "noyes": "", "webster": "Speak to Aaron and to his sons, saying, This [is] the law of the sin-offering: In the place where the burnt-offering is killed shall the sin-offering be killed before the LORD: it [is] most holy.", "vulgate": "loquere Aaron et filiis eius ista est lex hostiae pro peccato in loco ubi offertur holocaustum immolabitur coram Domino sanctum sanctorum est;", "brenton": "Speak to Aaron and to his sons, saying, This is the law of the sin-offering; —in the place where they slay the whole-burnt-offering, they shall slay the sin-offerings before the Lord: they are most holy."}}, {"v": 26, "ref": "6:26", "o": "", "en": {"kjv": "The priest that offereth it for sin shall eat it: in the holy place shall it be eaten, in the court of the tabernacle of the congregation.", "web": "The priest who offers it for sin shall eat it. It shall be eaten in a holy place, in the court of the Tent of Meeting.", "bsb": "The priest who offers it shall eat it; it must be eaten in a holy place, in the courtyard of the Tent of Meeting.", "asv": "The priest that offereth it for sin shall eat it: in a holy place shall it be eaten, in the court of the tent of meeting.", "ylt": "`The priest who is making atonement with it doth eat it, in the holy place it is eaten, in the court of the tent of meeting;", "tyndale": "The preast that offereth it shall eate it in the holye place: eve in the courte of the tabernacle of witnesse", "dra": "The priest that offereth it, shall eat it in a holy place, in the court of the tabernacle.", "bbe": "The priest by whom it is offered for sin, is to take it for his food in a holy place, in the open space of the Tent of meeting.", "geneva": "The Priest that offreth this sinne offring, shall eate it: in the holy place shall it be eaten, in the court of ye Tabernacle of the Congregation.", "wycliffe": "The preest that offrith it, schal ete it in the hooli place, in the greet street of the tabernacle.", "rotherham": "The priest who maketh it a sin-bearer, shall eat it,—in a holy place, shall it be eaten, in the court of the tent of meeting.", "darby": "The priest that offereth it for sin shall eat it: in a holy place shall it be eaten, in the court of the tent of meeting.", "twenty": "", "jps": "", "acv": "The priest who offers it for sin shall eat it. It shall be eaten in a holy place, in the court of the tent of meeting.", "anderson": "", "haweis": "", "noyes": "", "webster": "The priest that offereth it for sin shall eat it: in the holy place shall it be eaten, in the court of the tabernacle of the congregation.", "vulgate": "sacerdos qui offert comedet eam in loco sancto in atrio tabernaculi;", "brenton": "The priest that offers it shall eat it: in a holy place it shall be eaten, in the court of the tabernacle of witness."}}, {"v": 27, "ref": "6:27", "o": "", "en": {"kjv": "Whatsoever shall touch the flesh thereof shall be holy: and when there is sprinkled of the blood thereof upon any garment, thou shalt wash that whereon it was sprinkled in the holy place.", "web": "Whatever shall touch its flesh shall be holy. When there is any of its blood sprinkled on a garment, you shall wash that on which it was sprinkled in a holy place.", "bsb": "Anything that touches its flesh will become holy, and if any of the blood is spattered on a garment, you must wash it in a holy place.", "asv": "Whatsoever shall touch the flesh thereof shall be holy; and when there is sprinkled of the blood thereof upon any garment, thou shalt wash that whereon it was sprinkled in a holy place.", "ylt": "all that cometh against its flesh is holy, and when any of its blood is sprinkled on the garment, that on which it is sprinkled thou dost wash in the holy place;", "tyndale": "Noman shall touche the flesh thereof, saue he that is halowed. And yf any rayment be sprynckled therewyth, it shalbe wasshed in an holy place,", "dra": "Whatsoever shall touch the flesh thereof, shall be sanctified. If a garment be sprinkled with the blood thereof, it shall be washed in a holy place.", "bbe": "Anyone touching the flesh of it will be holy: and if any of the blood is dropped on any clothing, the thing on which the blood has been dropped is to be washed in a holy place.", "geneva": "Whatsoeuer shall touch the flesh thereof shalbe holy: and when there droppeth of the blood thereof vpon a garment, thou shalt wash that whereon it droppeth in the holy place.", "wycliffe": "What euer thing schal touche the fleischis therof, it schal be halewid; if a cloth is bispreynt of the blood therof, it schal be waischun in the hooli place.", "rotherham": "Every one who toucheth the flesh thereof, shall be hallowed; and when one sprinkleth some of the blood thereof upon a garment, that whereon it was sprinkled, shalt thou wash in a holy place.", "darby": "Everything that toucheth the flesh thereof shall be holy; and if there be splashed of the blood thereof on a garment — that whereon it is sprinkled shalt thou wash in a holy place.", "twenty": "", "jps": "", "acv": "Whatever shall touch the flesh of it shall be holy. And when there is of the blood sprinkled upon any garment, thou shall wash that on which it was sprinkled in a holy place.", "anderson": "", "haweis": "", "noyes": "", "webster": "Whatever shall touch the flesh of it shall be holy: and when there is sprinkled of its blood upon any garment, thou shalt wash that on which it was sprinkled in the holy place.", "vulgate": "quicquid tetigerit carnes eius sanctificabitur si de sanguine illius vestis fuerit aspersa lavabitur in loco sancto;", "brenton": "Every one that touches the flesh of it shall be holy, and on whosesoever garment any of its blood shall have been sprinkled, whosoever shall have it sprinkled, shall be washed in the holy place."}}, {"v": 28, "ref": "6:28", "o": "", "en": {"kjv": "But the earthen vessel wherein it is sodden shall be broken: and if it be sodden in a brasen pot, it shall be both scoured, and rinsed in water.", "web": "But the earthen vessel in which it is boiled shall be broken; and if it is boiled in a bronze vessel, it shall be scoured, and rinsed in water.", "bsb": "The clay pot in which the sin offering is boiled must be broken; if it is boiled in a bronze pot, the pot must be scoured and rinsed with water.", "asv": "But the earthen vessel wherein it is boiled shall be broken; and if it be boiled in a brazen vessel, it shall be scoured, and rinsed in water.", "ylt": "and an earthen vessel in which it is boiled is broken, and if in a brass vessel it is boiled, then it is scoured and rinsed with water.", "tyndale": "and the erthe pott that it is sodde in shalbe broken. Yf it be sodden in brasse, then the pott shalbe scoured and plunged in the water.", "dra": "And the earthen vessel, wherein it was sodden, shall be broken: but if the vessel be of brass, it shall be scoured, and washed with water.", "bbe": "But the vessel of earth in which the flesh was cooked is to be broken; or if a brass vessel was used, it is to be rubbed clean and washed out with water.", "geneva": "Also the earthen pot that it is sodden in, shalbe broken, but if it be sodden in a brasen pot, it shall both be scoured and washed with water.", "wycliffe": "Sotheli the erthun vessel, in which it is sodun, schal be brokun; that if the vessel is of bras, it schal be scourid, and `schal be waischun with watir.", "rotherham": "But, the earthen vessel wherein it is boiled, shall be broken,—or, if, in a vessel of bronze, it hath been boiled, then shall the vessel be scoured and rinsed in water.", "darby": "And the earthen vessel wherein it hath been sodden shall be broken; and if it have been sodden in a copper pot, it shall be both scoured and rinsed with water.", "twenty": "", "jps": "", "acv": "But the earthen vessel in which it is boiled shall be broken, and if it be boiled in a brazen vessel, it shall be scoured, and rinsed in water.", "anderson": "", "haweis": "", "noyes": "", "webster": "But the earthen vessel in which it is boiled shall be broken: and if it shall be boiled in a brazen pot, it shall be both scoured, and rinsed in water.", "vulgate": "vas autem fictile in quo cocta est confringetur quod si vas aeneum fuerit defricabitur et lavabitur aqua;", "brenton": "And the earthen vessel, in whichsoever it shall have been sodden, shall be broken; and if it shall have been sodden in a brazen vessel, he shall scour it and wash it with water."}}, {"v": 29, "ref": "6:29", "o": "", "en": {"kjv": "All the males among the priests shall eat thereof: it is most holy.", "web": "Every male among the priests shall eat of it: it is most holy.", "bsb": "Any male among the priests may eat it; it is most holy.", "asv": "Every male among the priests shall eat thereof: it is most holy.", "ylt": "`Every male among the priests doth eat it--it is most holy;", "tyndale": "All the males amonge the childern of Aaro shall eate therof, for it is most holy.", "dra": "Every male of the priestly race shall eat of the flesh thereof, because it is holy of holies.", "bbe": "Every male among the priests may take it for his food: it is most holy.", "geneva": "All the males among the Priestes shall eate thereof, for it is most holy.", "wycliffe": "Ech male of preestis kyn schal ete of the fleischis therof; for it is hooli `of the noumbre of hooli thingis.", "rotherham": "Any male among the priests may eat thereof,—most holy, it is.", "darby": "All the males among the priests shall eat thereof: it is most holy.", "twenty": "", "jps": "", "acv": "Every male among the priests shall eat of it. It is most holy.", "anderson": "", "haweis": "", "noyes": "", "webster": "All the males among the priests shall eat of it: it [is] most holy.", "vulgate": "omnis masculus de genere sacerdotali vescetur carnibus eius quia sanctum sanctorum est;", "brenton": "Every male among the priests shall eat it: it is most holy to the Lord."}}, {"v": 30, "ref": "6:30", "o": "", "en": {"kjv": "And no sin offering, whereof any of the blood is brought into the tabernacle of the congregation to reconcile withal in the holy place, shall be eaten: it shall be burnt in the fire.", "web": "No sin offering, of which any of the blood is brought into the Tent of Meeting to make atonement in the Holy Place, shall be eaten: it shall be burned with fire.", "bsb": "But no sin offering may be eaten if its blood has been brought into the Tent of Meeting to make atonement in the Holy Place; it must be burned.", "asv": "And no sin-offering, whereof any of the blood is brought into the tent of meeting to make atonement in the holy place, shall be eaten: it shall be burnt with fire.", "ylt": "and no sin-offering, any of whose blood is brought in unto the tent of meeting to make atonement in the sanctuary is eaten; with fire it is burnt.", "tyndale": "Notwithstodinge no synneofferynge that hath his bloude brought in to the tabernacle of witnesse to reconcyle with all in the holy place, shalbe eaten: but shalbe burnt in the fire.", "dra": "For the victim that is slain for sin, the blood of which is carried into the tabernacle of the testimony to make atonement in the sanctuary, shall not be eaten, but shall be burnt with fire.", "bbe": "No sin-offering, the blood of which is taken into the Tent of meeting, to take away sin in the holy place, may be used for food: it is to be burned with fire.", "geneva": "But no sinne offering, whose blood is brought into the Tabernacle of the Congregation to make reconciliation in the holy place, shalbe eaten, but shalbe burnt in the fire.", "wycliffe": "Sotheli the sacrifice which is slayn for synne, whos blood is borun in to the tabernacle of witnessyng to clense in the seyntuarie, schal not be etun, but it schal be brent in fier.", "rotherham": "But, no sin-bearer whereof any of the blood is taken into the tent of meeting to make a propitiatory-covering in the sanctuary, shall be eaten,—with fire, shall it be consumed.", "darby": "And no sin-offering whereof blood hath been brought to the tent of meeting, to make atonement in the sanctuary, shall be eaten: it shall be burned with fire.", "twenty": "", "jps": "", "acv": "And no sin offering, from which any of the blood is brought into the tent of meeting to make atonement in the holy place, shall be eaten; it shall be burnt with fire.", "anderson": "", "haweis": "", "noyes": "", "webster": "And no sin-offering, of which [any] of the blood is brought into the tabernacle of the congregation to make reconciliation in the holy [place], shall be eaten: it shall be burnt in the fire.", "vulgate": "hostia enim quae caeditur pro peccato cuius sanguis infertur in tabernaculum testimonii ad expiandum in sanctuario non comedetur sed conburetur igni;", "brenton": "And no offerings for sin, of whose blood there shall be brought any into the tabernacle of witness to make atonement in the holy place, shall be eaten: they shall be burned with fire."}}]}, {"c": 7, "verses": [{"v": 1, "ref": "7:1", "o": "וְ/זֹ֥את תּוֹרַ֖ת הָ/אָשָׁ֑ם קֹ֥דֶשׁ קָֽדָשִׁ֖ים הֽוּא", "en": {"kjv": "Likewise this is the law of the trespass offering: it is most holy.", "web": "“‘This is the law of the trespass offering. It is most holy.", "bsb": "“Now this is the law of the guilt offering, which is most holy:", "asv": "And this is the law of the trespass-offering: it is most holy.", "ylt": "`And this is a law of the guilt-offering: it is most holy;", "tyndale": "This is the lawe of the trespaceofferynge which is most holy.", "dra": "This also is the law of the sacrifice for a trespass: it is most holy.", "bbe": "And this is the law of the offering for wrongdoing: it is most holy.", "geneva": "Likewise this is the lawe of the trespasse offering, it is most holy.", "wycliffe": "And this is the lawe of sacrifice for trespas; it is hooli `of the noumbre of hooli thingis.", "rotherham": "And this, is the law of the guilt-bearer,—most holy, it is!", "darby": "And this is the law of the trespass-offering — it is most holy:", "twenty": "", "jps": "And this is the law of the guilt-offering: it is most holy.", "acv": "And this is the law of the trespass offering. It is most holy.", "anderson": "", "haweis": "", "noyes": "", "webster": "Likewise this [is] the law of the trespass-offering: it [is] most holy.", "vulgate": "haec quoque est lex hostiae pro delicto sancta sanctorum est;", "brenton": "This is the law of the sacrifice of peace-offering, which they shall bring to the Lord."}}, {"v": 2, "ref": "7:2", "o": "בִּ/מְק֗וֹם אֲשֶׁ֤ר יִשְׁחֲטוּ֙ אֶת הָ֣/עֹלָ֔ה יִשְׁחֲט֖וּ אֶת הָ/אָשָׁ֑ם וְ/אֶת דָּמ֛/וֹ יִזְרֹ֥ק עַל הַ/מִּזְבֵּ֖חַ סָבִֽיב", "en": {"kjv": "In the place where they kill the burnt offering shall they kill the trespass offering: and the blood thereof shall he sprinkle round about upon the altar.", "web": "In the place where they kill the burnt offering, he shall kill the trespass offering; and its blood he shall sprinkle around on the altar.", "bsb": "The guilt offering must be slaughtered in the place where the burnt offering is slaughtered, and the priest shall sprinkle its blood on all sides of the altar.", "asv": "In the place where they kill the burnt-offering shall they kill the trespass-offering; and the blood thereof shall he sprinkle upon the altar round about.", "ylt": "in the place where they slaughter the burnt-offering they do slaughter the guilt-offering, and its blood one doth sprinkle on the altar round about,", "tyndale": "In the place where the burntoffrynge is kylled, the trespaceoffrynge shalbe kylled also: ad his bloude shalbe sprikled rounde aboute apon the alter.", "dra": "Therefore where the holocaust is immolated, the victim also for a trespass shall be slain: the blood thereof shall be poured round about the altar.", "bbe": "They are to put to death the offering for wrongdoing in the same place as the burned offering; and the priest is to put the blood on and round the altar.", "geneva": "In the place where they kill the burnt offering, shall they kill the trespasse offering, and the blood thereof shall he sprinkle rounde about vpon the altar.", "wycliffe": "Therfor where brent sacrifice is offrid, also the sacrifice for trespas schal be slayn; the blood therof schal be sched bi the cumpas of the auter.", "rotherham": "In the place where they slay the ascending-sacrifice, shall they slay the guilt-bearer; and, the blood thereof, shall one dash against the altar, round about;", "darby": "in the place where they slaughter the burnt-offering shall they slaughter the trespass-offering; and the blood thereof shall he sprinkle on the altar round about.", "twenty": "", "jps": "In the place where they kill the burnt-offering shall they kill the guilt-offering: and the blood thereof shall be dashed against the altar round about.", "acv": "In the place where they kill the burnt offering they shall kill the trespass offering, and the blood of it he shall sprinkle upon the altar round about.", "anderson": "", "haweis": "", "noyes": "", "webster": "In the place where they kill the burnt-offering shall they kill the trespass-offering: and the blood of it shall he sprinkle around upon the altar.", "vulgate": "idcirco ubi immolatur holocaustum mactabitur et victima pro delicto sanguis eius per gyrum fundetur altaris;", "brenton": "If a man should offer it for praise, then shall he bring, for the sacrifice of praise, loaves of fine flour made up with oil, and unleavened cakes anointed with oil, and fine flour kneaded with oil."}}, {"v": 3, "ref": "7:3", "o": "וְ/אֵ֥ת כָּל חֶלְבּ֖/וֹ יַקְרִ֣יב מִמֶּ֑/נּוּ אֵ֚ת הָֽ/אַלְיָ֔ה וְ/אֶת הַ/חֵ֖לֶב הַֽ/מְכַסֶּ֥ה אֶת הַ/קֶּֽרֶב", "en": {"kjv": "And he shall offer of it all the fat thereof; the rump, and the fat that covereth the inwards,", "web": "He shall offer all of its fat: the fat tail, and the fat that covers the innards,", "bsb": "And all the fat from it shall be offered: the fat tail, the fat that covers the entrails,", "asv": "And he shall offer of it all the fat thereof: the fat tail, and the fat that covereth the inwards,", "ylt": "and all its fat he bringeth near out of it, the fat tail, and the fat which is covering the inwards,", "tyndale": "And all the fatt thereof shalbe offered: the rompe and the fatt that couered the inwardes,", "dra": "They shall offer thereof the rump and the fat that covereth the entrails:", "bbe": "And all the fat of it, the fat tail and the fat covering the inside parts, is to be given as an offering.", "geneva": "All the fat thereof also shall he offer, the rumpe, and the fat that couereth the inwardes.", "wycliffe": "Thei schulen offre the tail therof, and the fatnesse that hilith the entrailis,", "rotherham": "and, as for all the fat thereof, one shall bring near therefrom,—the fat-tail, and the fat that covereth the inwards;", "darby": "And he shall present of it all the fat thereof; the fat tail and the fat that covereth the inwards,", "twenty": "", "jps": "And he shall offer of it all the fat thereof: the fat tail, and the fat that covereth the inwards,", "acv": "And he shall offer from it all the fat of it. He shall take away the fat tail, and the fat that covers the innards,", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall offer of it all its fat; the rump, and the fat that covereth the inwards,", "vulgate": "offerent ex ea caudam et adipem qui operit vitalia;", "brenton": "With leavened bread he shall offer his gifts, with the peace-offering of praise."}}, {"v": 4, "ref": "7:4", "o": "וְ/אֵת֙ שְׁתֵּ֣י הַ/כְּלָיֹ֔ת וְ/אֶת הַ/חֵ֨לֶב֙ אֲשֶׁ֣ר עֲלֵי/הֶ֔ן אֲשֶׁ֖ר עַל הַ/כְּסָלִ֑ים וְ/אֶת הַ/יֹּתֶ֨רֶת֙ עַל הַ/כָּבֵ֔ד עַל הַ/כְּלָיֹ֖ת יְסִירֶֽ/נָּה", "en": {"kjv": "And the two kidneys, and the fat that is on them, which is by the flanks, and the caul that is above the liver, with the kidneys, it shall he take away:", "web": "and the two kidneys, and the fat that is on them, which is by the loins, and the cover on the liver, with the kidneys, shall he take away;", "bsb": "both kidneys with the fat on them near the loins, and the lobe of the liver, which is to be removed with the kidneys.", "asv": "and the two kidneys, and the fat that is on them, which is by the loins, and the caul upon the liver, with the kidneys, shall he take away;", "ylt": "and the two kidneys, and the fat which is on them, which is on the flanks, and the redundance above the liver (beside the kidneys he doth turn it aside);", "tyndale": "and the .ij. kydneyes with the fatt that lyeth on them and apon the loynes: and the kall on the lyuer shalbe taken awaye with the kydneyes,", "dra": "The two little kidneys, and the fat which is by the flanks, and the caul of the liver with the little kidneys.", "bbe": "And the two kidneys, and the fat on them, which is by the top of the legs, and the fat joining the liver and the kidneys, he is to take away:", "geneva": "After he shall take away the two kidneis, with the fat that is on them and vpon the flankes, and the kall on the liuer with the kidneis.", "wycliffe": "the twei litle reynes, and the fatnesse which is bisidis ilioun, and the calle of the mawe, with the litle reynes.", "rotherham": "and the two kidneys, with the fat that is upon them, which is upon the loins,—and the caul upon the liver, up to the kidneys, shall he remove it.", "darby": "and the two kidneys, and the fat that is on them, which is by the flanks, and the net above the liver, which he shall take away as far as the kidneys.", "twenty": "", "jps": "and the two kidneys, and the fat that is on them, which is by the loins, and the lobe above the liver, which he shall take away by the kidneys.", "acv": "and the two kidneys, and the fat that is on them, which is by the loins, and the caul upon the liver, with the kidneys.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the two kidneys, and the fat that [is] on them, which [is] by the flanks, and the caul [that is] above the liver, with the kidneys, that shall he take away:", "vulgate": "duos renunculos et pinguedinem quae iuxta ilia est reticulumque iecoris cum renunculis;", "brenton": "And he shall bring one of all his gifts, a separate offering to the Lord: it shall belong to the priest who pours forth the blood of the peace-offering."}}, {"v": 5, "ref": "7:5", "o": "וְ/הִקְטִ֨יר אֹתָ֤/ם הַ/כֹּהֵן֙ הַ/מִּזְבֵּ֔חָ/ה אִשֶּׁ֖ה לַ/יהוָ֑ה אָשָׁ֖ם הֽוּא", "en": {"kjv": "And the priest shall burn them upon the altar for an offering made by fire unto the Lord: it is a trespass offering.", "web": "and the priest shall burn them on the altar for an offering made by fire to Yahweh: it is a trespass offering.", "bsb": "The priest shall burn them on the altar as an offering made by fire to the LORD; it is a guilt offering.", "asv": "and the priest shall burn them upon the altar for an offering made by fire unto Jehovah: it is a trespass-offering.", "ylt": "and the priest hath made them a perfume on the altar, a fire-offering to Jehovah; it is a guilt-offering.", "tyndale": "And the preast shall burne them apon the altare, to be an offerynge vnto the Lorde: this is a trespaceofferynge.", "dra": "And the priest shall burn them upon the altar: it is the burnt sacrifice of the Lord for a trespass.", "bbe": "They are to be burned by the priest on the altar for an offering made by fire to the Lord: it is an offering for wrongdoing.", "geneva": "Then the Priest shall burne them vpon the altar, for an offring made by fire vnto the Lord: this is a trespasse offring.", "wycliffe": "And the preest schal brenne tho on the auter; it is encense of the Lord, for trespas.", "rotherham": "And the priest shall make a perfume with them at the altar, an altar-flame unto Yahweh—a guilt-bearer, it is,", "darby": "And the priest shall burn them on the altar, an offering by fire to Jehovah: it is a trespass-offering.", "twenty": "", "jps": "And the priest shall make them smoke upon the altar for an offering made by fire unto HaShem; it is a guilt-offering.", "acv": "And the priest shall burn them upon the altar for an offering made by fire to Jehovah. It is a trespass offering.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall burn them upon the altar [for] an offering made by fire to the LORD: it [is] a trespass-offering.", "vulgate": "et adolebit ea sacerdos super altare incensum est Domini pro delicto;", "brenton": "And the flesh of the sacrifice of the peace-offering of praise shall be his, and it shall be eaten in the day in which it is offered: they shall not leave of it till the morning."}}, {"v": 6, "ref": "7:6", "o": "כָּל זָכָ֥ר בַּ/כֹּהֲנִ֖ים יֹאכְלֶ֑/נּוּ בְּ/מָק֤וֹם קָדוֹשׁ֙ יֵאָכֵ֔ל קֹ֥דֶשׁ קָֽדָשִׁ֖ים הֽוּא", "en": {"kjv": "Every male among the priests shall eat thereof: it shall be eaten in the holy place: it is most holy.", "web": "Every male among the priests may eat of it. It shall be eaten in a holy place. It is most holy.", "bsb": "Every male among the priests may eat of it. It must be eaten in a holy place; it is most holy.", "asv": "Every male among the priests shall eat thereof: it shall be eaten in a holy place: it is most holy.", "ylt": "`Every male among the priests doth eat it; in the holy place it is eaten--it is most holy;", "tyndale": "All the males amonge the preastes shal eate thereof in the holy place, for it is most holy.", "dra": "Every male of the priestly race, shall eat this flesh in a holy place, because it is most holy.", "bbe": "Every male among the priests may have it as food in a holy place: it is most holy.", "geneva": "All the males among the Priestes shall eate thereof, it shalbe eaten in the holy place, for it is most holy.", "wycliffe": "Ech male of the preestis kyn schal ete these fleischis in the hooli place, for it is hooli `of the noumbre of hooli thingis.", "rotherham": "Any male among the priests, may eat thereof,—in a holy place, shall it be eaten, most holy, it is.", "darby": "Every male among the priests shall eat thereof; in a holy place shall it be eaten: it is most holy.", "twenty": "", "jps": "Every male among the priests may eat thereof; it shall be eaten in a holy place; it is most holy.", "acv": "Every male among the priests shall eat of it. It shall be eaten in a holy place; it is most holy.", "anderson": "", "haweis": "", "noyes": "", "webster": "Every male among the priests shall eat of it: it shall be eaten in the holy place: it [is] most holy.", "vulgate": "omnis masculus de sacerdotali genere in loco sancto vescetur his carnibus quia sanctum sanctorum est;", "brenton": "And if it be a vow, or he offer his gift of his own will, on whatsoever day he shall offer his sacrifice, it shall be eaten, and on the morrow."}}, {"v": 7, "ref": "7:7", "o": "כַּֽ/חַטָּאת֙ כָּֽ/אָשָׁ֔ם תּוֹרָ֥ה אַחַ֖ת לָ/הֶ֑ם הַ/כֹּהֵ֛ן אֲשֶׁ֥ר יְכַפֶּר בּ֖/וֹ ל֥/וֹ יִהְיֶֽה", "en": {"kjv": "As the sin offering is, so is the trespass offering: there is one law for them: the priest that maketh atonement therewith shall have it.", "web": "“‘As is the sin offering, so is the trespass offering; there is one law for them. The priest who makes atonement with them shall have it.", "bsb": "The guilt offering is like the sin offering; the same law applies to both. It belongs to the priest who makes atonement with it.", "asv": "As is the sin-offering, so is the trespass-offering; there is one law for them: the priest that maketh atonement therewith, he shall have it.", "ylt": "as is a sin-offering, so is a guilt-offering; one law is for them; the priest who maketh atonement by it--it is his.", "tyndale": "As the synneofferynge is, so is the trespaceofferynge, one lawe serueth for both: and it shall be the preastes that reconcyleth therewith.", "dra": "As the sacrifice for sin is offered, so is also that for a trespass: the same shall be the law of both these sacrifices. It shall belong to the priest that offereth it.", "bbe": "As is the sin-offering, so is the offering for wrongdoing; there is one law for them: the priest who makes the offering to take away sin, he is to have it.", "geneva": "As the sinne offring is, so is the trespasse offring, one lawe serueth for both: that wherewith the Priest shall make atonement, shalbe his.", "wycliffe": "As a sacrifice is offrid for synne, so and for trespas, o lawe schal be of euer eithir sacrifice; it schal perteyne to the preest, that offrith it.", "rotherham": "As the sin-bearer, so the guilt-bearer,—one law, for them,—the priest who maketh a propitiatory-covering, therewith,—to him, shall it belong,", "darby": "As the sin-offering, so is the trespass-offering; [there shall] be one law for them: it shall be the priest's who maketh atonement therewith.", "twenty": "", "jps": "As is the sin-offering, so is the guilt-offering; there is one law for them; the priest that maketh atonement therewith, he shall have it.", "acv": "As is the sin offering, so is the trespass offering, there is one law for them. The priest who makes atonement with it, he shall have it.", "anderson": "", "haweis": "", "noyes": "", "webster": "As the sin-offering [is], so [is] the trespass-offering: [there is] one law for them: the priest that maketh atonement with it shall have [it].", "vulgate": "sicut pro peccato offertur hostia ita et pro delicto utriusque hostiae lex una erit ad sacerdotem qui eam obtulerit pertinebit;", "brenton": "And that which is left of the flesh of the sacrifice till the third day, shall be consumed with fire."}}, {"v": 8, "ref": "7:8", "o": "וְ/הַ֨/כֹּהֵ֔ן הַ/מַּקְרִ֖יב אֶת עֹ֣לַת אִ֑ישׁ ע֤וֹר הָֽ/עֹלָה֙ אֲשֶׁ֣ר הִקְרִ֔יב לַ/כֹּהֵ֖ן ל֥/וֹ יִהְיֶֽה", "en": {"kjv": "And the priest that offereth any man’s burnt offering, even the priest shall have to himself the skin of the burnt offering which he hath offered.", "web": "The priest who offers any man’s burnt offering, even the priest shall have for himself the skin of the burnt offering which he has offered.", "bsb": "As for the priest who presents a burnt offering for anyone, the hide of that offering belongs to him.", "asv": "And the priest that offereth any man’s burnt-offering, even the priest shall have to himself the skin of the burnt-offering which he hath offered.", "ylt": "`And the priest who is bringing near any man's burnt-offering, the skin of the burnt-offering which he hath brought near, it is the priest's, his own;", "tyndale": "And the preast that offered a mans burntofferynge, shall haue the skyn of the burntofferynge which he hath offered.", "dra": "The priest that offereth the victim of holocaust, shall have the skin thereof.", "bbe": "And the priest offering any man's burned offering for him, may have the skin of the burned offering which is offered by him.", "geneva": "Also the Priest that offereth any mans burnt offring, shall haue the skinne of the burnt offring which he hath offered.", "wycliffe": "The preest that offrith the beeste of brent sacrifice, schal haue the skyn therof.", "rotherham": "And, as for the priest who bringeth near the ascending-sacrifice of any man, the skin of the ascending-sacrifice which he hath brought near, to the priest himself, shall it belong.", "darby": "And [as to] the priest that presenteth any man's burnt-offering, the skin of the burnt-offering which he hath presented shall be the priest's for himself.", "twenty": "", "jps": "And the priest that offereth any man's burnt-offering, even the priest shall have to himself the skin of the burnt-offering which he hath offered.", "acv": "And the priest who offers any man's burnt offering, even the priest shall have to himself the skin of the burnt offering which he has offered.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest that offereth any man's burnt-offering, [even] the priest shall have to himself the skin of the burnt-offering which he hath offered.", "vulgate": "sacerdos qui offert holocausti victimam habebit pellem eius;", "brenton": "And if he do at all eat of the flesh on the third day, it shall not be accepted for him that offers: it shall not be reckoned to him, it is pollution; and whatsoever soul shall eat of it, shall bear his iniquity."}}, {"v": 9, "ref": "7:9", "o": "וְ/כָל מִנְחָ֗ה אֲשֶׁ֤ר תֵּֽאָפֶה֙ בַּ/תַּנּ֔וּר וְ/כָל נַעֲשָׂ֥ה בַ/מַּרְחֶ֖שֶׁת וְ/עַֽל מַחֲבַ֑ת לַ/כֹּהֵ֛ן הַ/מַּקְרִ֥יב אֹתָ֖/הּ ל֥/וֹ תִֽהְיֶֽה", "en": {"kjv": "And all the meat offering that is baken in the oven, and all that is dressed in the fryingpan, and in the pan, shall be the priest’s that offereth it.", "web": "Every meal offering that is baked in the oven, and all that is dressed in the pan, and on the griddle, shall be the priest’s who offers it.", "bsb": "Likewise, every grain offering that is baked in an oven or cooked in a pan or on a griddle belongs to the priest who presents it,", "asv": "And every meal-offering that is baken in the oven, and all that is dressed in the frying-pan, and on the baking-pan, shall be the priest’s that offereth it.", "ylt": "and every present which is baked in an oven, and every one done in a frying-pan, and on a girdel, is the priest's who is bringing it near; it is his;", "tyndale": "And all the meatofferynges that are baken in the ouen, ad all that is dressed apon the gredyerne ad in the fryenge pan, shalbe the preastes that offereth them.", "dra": "And every sacrifice of flour that is baked in the oven, and whatsoever is dressed on the gridiron, or in the fryingpan, shall be the priest's that offereth it.", "bbe": "And every meal offering which is cooked in the oven and everything made in a cooking pot or on a flat plate, is for the priest by whom it is offered.", "geneva": "And all the meate offring that is baken in the ouen, and that is dressed in the pan, and in the frying pan, shall be the Priestes that offereth it.", "wycliffe": "And ech sacrifice of wheete flour, which is bakun in an ouene, and what euer is maad redi in a gridile, ethir in a friyng panne, it schal be that preestis, of whom it is offrid,", "rotherham": "And as for any meal-offering that may be baked in an oven, or anything that hath been prepared in a boiler or on a girdle, to the priest that bringeth it near—to him, shall it belong,", "darby": "And every oblation that is baken in the oven, and all that is prepared in the cauldron and in the pan, shall be the priest's who offereth it; to him it shall belong.", "twenty": "", "jps": "And every meal-offering that is baked in the oven, and all that is dressed in the stewing-pan, and on the griddle, shall be the priest's that offereth it.", "acv": "And every meal offering that is baked in the oven, and all that is dressed in the frying-pan, and on the baking-pan, shall be the priest's who offers it.", "anderson": "", "haweis": "", "noyes": "", "webster": "And all the meat-offering that is baked in the oven, and all that is dressed in the frying-pan, and in the pan, shall be the priest's that offereth it.", "vulgate": "et omne sacrificium similae quod coquitur in clibano et quicquid in craticula vel in sartagine praeparatur eius erit sacerdotis a quo offertur;", "brenton": "And whatsoever flesh shall have touched any unclean thing, it shall not be eaten, it shall be consumed with fire; every one that is clean shall eat the flesh."}}, {"v": 10, "ref": "7:10", "o": "וְ/כָל מִנְחָ֥ה בְלוּלָֽה בַ/שֶּׁ֖מֶן וַ/חֲרֵבָ֑ה לְ/כָל בְּנֵ֧י אַהֲרֹ֛ן תִּהְיֶ֖ה אִ֥ישׁ כְּ/אָחִֽי/ו", "en": {"kjv": "And every meat offering, mingled with oil, and dry, shall all the sons of Aaron have, one as much as another.", "web": "Every meal offering, mixed with oil or dry, belongs to all the sons of Aaron, one as well as another.", "bsb": "and every grain offering, whether dry or mixed with oil, belongs equally to all the sons of Aaron.", "asv": "And every meal-offering, mingled with oil, or dry, shall all the sons of Aaron have, one as well as another.", "ylt": "and every present, mixed with oil or dry, is for all the sons of Aaron--one as another.", "tyndale": "And all the meatofferynges that are myngled with oyle or drye, shall pertayne vnto all the sonnes of Aaron, and one shall haue as moche as another.", "dra": "Whether they be tempered with oil, or dry, all the sons of Aaron shall have one as much as another.", "bbe": "And every meal offering, mixed with oil or dry, is for all the sons of Aaron in equal measure.", "geneva": "And euery meate offering mingled with oyle, and that is dry, shall pertaine vnto all the sonnes of Aaron, to all alike.", "wycliffe": "whether it is spreynt with oile, ethir is drye. To alle the sones of Aaron euene mesure schal be departyd, `to ech `bi hem silf.", "rotherham": "And, as for any meal-offering overflowed with oil or dry,—to all the sons of Aaron, shall it belong, to one as much as to another.", "darby": "And every oblation, mingled with oil, and dry, shall all the sons of Aaron have, one as the other.", "twenty": "", "jps": "And every meal-offering, mingled with oil, or dry, shall all the sons of Aaron have, one as well as another.", "acv": "And every meal offering, mingled with oil, or dry, all the sons of Aaron shall have, one as well as another.", "anderson": "", "haweis": "", "noyes": "", "webster": "And every meat-offering mingled with oil, and dry, shall all the sons of Aaron have, one [as much] as another.", "vulgate": "sive oleo conspersa sive arida fuerit cunctis filiis Aaron aequa mensura per singulos dividetur;", "brenton": "And whatsoever soul shall eat of the flesh of the sacrifice of the peace-offering which is the Lord's, and his uncleanness be upon him, that soul shall perish from his people."}}, {"v": 11, "ref": "7:11", "o": "וְ/זֹ֥את תּוֹרַ֖ת זֶ֣בַח הַ/שְּׁלָמִ֑ים אֲשֶׁ֥ר יַקְרִ֖יב לַ/יהוָֽה", "en": {"kjv": "And this is the law of the sacrifice of peace offerings, which he shall offer unto the Lord.", "web": "“‘This is the law of the sacrifice of peace offerings, which one shall offer to Yahweh.", "bsb": "Now this is the law of the peace offering that one may present to the LORD:", "asv": "And this is the law of the sacrifice of peace-offerings, which one shall offer unto Jehovah.", "ylt": "`And this is a law of the sacrifice of the peace-offerings which one bringeth near to Jehovah:", "tyndale": "This is the lawe of the peaceoffringes whiche shalbe offered vnto the Lorde.", "dra": "This is the law of the sacrifice of peace offerings that is offered to the Lord.", "bbe": "And this is the law for the peace-offerings offered to the Lord.", "geneva": "Furthermore, this is the lawe of the peace offrings, which he shall offer vnto the Lord.", "wycliffe": "This is the lawe of `the sacrifice of pesible thingis, which is offrid to the Lord.", "rotherham": "And, this, is the law of the peace-offering which one may bring near unto Yahweh.", "darby": "And this is the law of the sacrifice of peace-offering, which [a man] shall present to Jehovah.", "twenty": "", "jps": "And this is the law of the sacrifice of peace-offerings, which one may offer unto HaShem.", "acv": "And this is the law of the sacrifice of peace offerings, which he shall offer to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And this [is] the law of the sacrifice of peace-offerings, which he shall offer to the LORD.", "vulgate": "haec est lex hostiae pacificorum quae offertur Domino;", "brenton": "And whatsoever soul shall touch any unclean thing, either of the uncleanness of a man, or of unclean quadrupeds, or any unclean abominable thing, and shall eat of the flesh of the sacrifice of the peace-offering, which is the Lord's, that soul shall perish from his people."}}, {"v": 12, "ref": "7:12", "o": "אִ֣ם עַל תּוֹדָה֮ יַקְרִיבֶ/נּוּ֒ וְ/הִקְרִ֣יב עַל זֶ֣בַח הַ/תּוֹדָ֗ה חַלּ֤וֹת מַצּוֹת֙ בְּלוּלֹ֣ת בַּ/שֶּׁ֔מֶן וּ/רְקִיקֵ֥י מַצּ֖וֹת מְשֻׁחִ֣ים בַּ/שָּׁ֑מֶן וְ/סֹ֣לֶת מֻרְבֶּ֔כֶת חַלֹּ֖ת בְּלוּלֹ֥ת בַּ/שָּֽׁמֶן", "en": {"kjv": "If he offer it for a thanksgiving, then he shall offer with the sacrifice of thanksgiving unleavened cakes mingled with oil, and unleavened wafers anointed with oil, and cakes mingled with oil, of fine flour, fried.", "web": "If he offers it for a thanksgiving, then he shall offer with the sacrifice of thanksgiving unleavened cakes mixed with oil, and unleavened wafers anointed with oil, and cakes mixed with oil.", "bsb": "If he offers it in thanksgiving, then along with the sacrifice of thanksgiving he shall offer unleavened cakes mixed with olive oil, unleavened wafers coated with oil, and well-kneaded cakes of fine flour mixed with oil.", "asv": "If he offer it for a thanksgiving, then he shall offer with the sacrifice of thanksgiving unleavened cakes mingled with oil, and unleavened wafers anointed with oil, and cakes mingled with oil, of fine flour soaked.", "ylt": "if for a thank-offering he bring it near, then he hath brought near with the sacrifice of thank-offering unleavened cakes mixed with oil, and thin unleavened cakes anointed with oil, and of fried flour cakes mixed with oil;", "tyndale": "Yf he offer to geue thanckes, he shall brynge vnto his thanckofferynge: swete cakes myngled with oyle and swete wafers anoynted with oyle, and cakes myngled with oyle of fine floure fryed,", "dra": "If the oblation be for thanksgiving, they shall offer loaves without leaven tempered with oil, and unleavened wafers anointed with oil, and fine flour fried, and cakes tempered and mingled with oil.", "bbe": "If any man gives his offering as a praise-offering, then let him give with the offering, unleavened cakes mixed with oil and thin unleavened cakes covered with oil and cakes of the best meal well mixed with oil.", "geneva": "If he offer it to giue thankes, then he shall offer for his thankes offering, vnleauened cakes mingled with oyle, and vnleauened wafers anointed with oyle, and fine floure fryed with the cakes mingled with oyle.", "wycliffe": "If the offryng is for doyng of thankyngis, thei schulen offre looues without sour dow spreynt with oile, and `therf looues sodun in watir, that ben anoyntid with oile; and thei schulen offre wheete flour bakun, and thinne looues spreynt to gidere with the medlyng of oile.", "rotherham": "If, for thanksgiving, he bring it near, then shall he bring near, with the thanksgiving sacrifice perforated cakes unleavened, overflowed with oil, and wafers unleavened anointed with oil,—and of fine flour moistened, perforated cakes overflowed with oil.", "darby": "If he present it for a thanksgiving, then he shall present with the sacrifice of thanksgiving unleavened cakes mingled with oil, and unleavened wafers anointed with oil, and fine flour saturated with oil, cakes mingled with oil.", "twenty": "", "jps": "If he offer it for a thanksgiving, then he shall offer with the sacrifice of thanksgiving unleavened cakes mingled with oil, and unleavened wafers spread with oil, and cakes mingled with oil, of fine flour soaked.", "acv": "If he offers it for a thanksgiving, then he shall offer with the sacrifice of thanksgiving unleavened cakes mingled with oil, and unleavened wafers anointed with oil, and cakes mingled with oil, of fine flour soaked.", "anderson": "", "haweis": "", "noyes": "", "webster": "If he shall offer it for a thanksgiving, then he shall offer with the sacrifice of thanksgiving unleavened cakes mingled with oil, and unleavened wafers anointed with oil, and cakes mingled with oil, of fine flour, fried.", "vulgate": "si pro gratiarum actione fuerit oblatio offerent panes absque fermento conspersos oleo et lagana azyma uncta oleo coctamque similam et collyridas olei admixtione conspersas;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 13, "ref": "7:13", "o": "עַל חַלֹּת֙ לֶ֣חֶם חָמֵ֔ץ יַקְרִ֖יב קָרְבָּנ֑/וֹ עַל זֶ֖בַח תּוֹדַ֥ת שְׁלָמָֽי/ו", "en": {"kjv": "Besides the cakes, he shall offer for his offering leavened bread with the sacrifice of thanksgiving of his peace offerings.", "web": "With cakes of leavened bread he shall offer his offering with the sacrifice of his peace offerings for thanksgiving.", "bsb": "Along with his peace offering of thanksgiving he is to present an offering with cakes of leavened bread.", "asv": "With cakes of leavened bread he shall offer his oblation with the sacrifice of his peace-offerings for thanksgiving.", "ylt": "besides the cakes, fermented bread he doth bring near with his offering, besides the sacrifice of thank-offering of his peace-offerings;", "tyndale": "ad he shall brynge his offerynge apon cakes made of leuended bred vnto the thanckoffrynge of his peaceofferynges,", "dra": "Moreover loaves of leavened bread with the sacrifice of thanks, which is offered for peace offerings:", "bbe": "With his peace-offering let him give cakes of leavened bread, as a praise-offering.", "geneva": "He shall offer also his offring with cakes of leauened bread, for his peace offrings, to giue thankes.", "wycliffe": "Also thei schulen offre `looues diyt with sour dow, with the sacrifice of thankyngis which is offrid for pesible thingis;", "rotherham": "With perforated cakes of leavened bread, shall he bring near his oblation, with his peace-offering of thanksgiving,", "darby": "Besides the cakes, he shall present his offering of leavened bread with the sacrifice of his peace-offering of thanksgiving.", "twenty": "", "jps": "With cakes of leavened bread he shall present his offering with the sacrifice of his peace-offerings for thanksgiving.", "acv": "He shall offer his oblation with the sacrifice of his peace offerings for thanksgiving with cakes of leavened bread.", "anderson": "", "haweis": "", "noyes": "", "webster": "Besides the cakes, he shall offer [for] his offering, leavened bread, with the sacrifice of thanksgiving of his peace-offerings.", "vulgate": "panes quoque fermentatos cum hostia gratiarum quae immolatur pro pacificis;", "brenton": "Speak to the children of Israel, saying, Ye shall eat no fat of oxen or sheep or goats."}}, {"v": 14, "ref": "7:14", "o": "וְ/הִקְרִ֨יב מִמֶּ֤/נּוּ אֶחָד֙ מִ/כָּל קָרְבָּ֔ן תְּרוּמָ֖ה לַ/יהוָ֑ה לַ/כֹּהֵ֗ן הַ/זֹּרֵ֛ק אֶת דַּ֥ם הַ/שְּׁלָמִ֖ים ל֥/וֹ יִהְיֶֽה", "en": {"kjv": "And of it he shall offer one out of the whole oblation for an heave offering unto the Lord, and it shall be the priest’s that sprinkleth the blood of the peace offerings.", "web": "Of it he shall offer one out of each offering for a heave offering to Yahweh. It shall be the priest’s who sprinkles the blood of the peace offerings.", "bsb": "From the cakes he must present one portion of each offering as a contribution to the LORD. It belongs to the priest who sprinkles the blood of the peace offering.", "asv": "And of it he shall offer one out of each oblation for a heave-offering unto Jehovah; it shall be the priest’s that sprinkleth the blood of the peace-offerings.", "ylt": "and he hath brought near out of it one of the whole offering--a heave-offering to Jehovah; to the priest who is sprinkling the blood of the peace-offerings--it is his;", "tyndale": "ad of them all he shall offer one to be an heueoffrynge vnto the Lorde, ad it shalbe the preastes that sprynkleth the bloude of the peaceofferynges.", "dra": "Of which one shall be offered to the Lord for firstfruits, and shall be the priest's that shall pour out the blood of the victim.", "bbe": "And let him give one out of every offering to be lifted up before the Lord; that it may be for the priest who puts the blood of the peace-offering on the altar.", "geneva": "And of all the sacrifice he shall offer one cake for an heaue offering vnto the Lord, and it shalbe the Priestes that sprinckleth the blood of the peace offrings.", "wycliffe": "of whiche o loof schal be offrid to the Lord for the firste fruytis, and it schal be the preestis that schal schede the blood of the sacrifice,", "rotherham": "Then shall he bring near therefrom one of each oblation, a heave-offering unto Yahweh,—to the priest who dasheth [against the altar] the blood of the peace-offering—to him, shall it belong.", "darby": "And of it he shall present one out of the whole offering as a heave-offering to Jehovah; to the priest that sprinkleth the blood of the peace-offering, to him it shall belong.", "twenty": "", "jps": "And of it he shall present one out of each offering for a gift unto HaShem; it shall be the priest's that dasheth the blood of the peace-offerings against the altar.", "acv": "And from it he shall offer one out of each oblation for a heave offering to Jehovah. It shall be the priest's who sprinkles the blood of the peace offerings.", "anderson": "", "haweis": "", "noyes": "", "webster": "And of it he shall offer one out of the whole oblation [for] a heave-offering to the LORD, [and] it shall be the priest's that sprinkleth the blood of the peace-offerings.", "vulgate": "ex quibus unus pro primitiis offeretur Domino et erit sacerdotis qui fundet hostiae sanguinem;", "brenton": "And the fat of such animals as have died of themselves, or have been seized of beasts, may be employed for any work; but it shall not be eaten for food."}}, {"v": 15, "ref": "7:15", "o": "וּ/בְשַׂ֗ר זֶ֚בַח תּוֹדַ֣ת שְׁלָמָ֔י/ו בְּ/י֥וֹם קָרְבָּנ֖/וֹ יֵאָכֵ֑ל לֹֽא יַנִּ֥יחַ מִמֶּ֖/נּוּ עַד בֹּֽקֶר", "en": {"kjv": "And the flesh of the sacrifice of his peace offerings for thanksgiving shall be eaten the same day that it is offered; he shall not leave any of it until the morning.", "web": "The flesh of the sacrifice of his peace offerings for thanksgiving shall be eaten on the day of his offering. He shall not leave any of it until the morning.", "bsb": "The meat of the sacrifice of his peace offering of thanksgiving must be eaten on the day he offers it; none of it may be left until morning.", "asv": "And the flesh of the sacrifice of his peace-offerings for thanksgiving shall be eaten on the day of his oblation; he shall not leave any of it until the morning.", "ylt": "as to the flesh of the sacrifice of the thank-offering of his peace-offerings, in the day of his offering it is eaten; he doth not leave of it till morning.", "tyndale": "And the fleshe of the thankofferynge of his peaceofferynges shalbe eaten the same daye that it is offred, and there shall none of it be layde vpp vntyll the mornynge.", "dra": "And the flesh of it shall be eaten the same day: neither shall any of it remain until the morning.", "bbe": "And the flesh of the praise-offering is to be taken as food on the day when it is offered; no part of it may be kept till the morning.", "geneva": "Also the flesh of his peace offerings, for thankesgiuing, shalbe eaten the same day that it is offered: he shall leaue nothing thereof vntill the morning.", "wycliffe": "whose fleischis schulen be etun in the same dai, nether ony thing of tho schal dwelle til the morewtid.", "rotherham": "But, as for the flesh of his peace-offering of thanksgiving, on the day of bringing it near, shall it be eaten,—he shall not leave thereof until morning,", "darby": "And the flesh of the sacrifice of his peace-offering of thanksgiving shall be eaten the same day that it is presented; he shall not let any of it remain until the morning.", "twenty": "", "jps": "And the flesh of the sacrifice of his peace-offerings for thanksgiving shall be eaten on the day of his offering; he shall not leave any of it until the morning.", "acv": "And the flesh of the sacrifice of his peace offerings for thanksgiving shall be eaten on the day of his oblation; he shall not leave any of it until the morning.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the flesh of the sacrifice of his peace-offerings for thanksgiving shall be eaten the same day that it is offered; he shall not leave any of it until the morning.", "vulgate": "cuius carnes eadem comedentur die nec remanebit ex eis quicquam usque mane;", "brenton": "Every one that eats fat off the beasts, from which he will bring a burnt-offering to the Lord—that soul shall perish from his people."}}, {"v": 16, "ref": "7:16", "o": "וְ/אִם נֶ֣דֶר א֣וֹ נְדָבָ֗ה זֶ֚בַח קָרְבָּנ֔/וֹ בְּ/י֛וֹם הַקְרִיב֥/וֹ אֶת זִבְח֖/וֹ יֵאָכֵ֑ל וּ/מִֽ/מָּחֳרָ֔ת וְ/הַ/נּוֹתָ֥ר מִמֶּ֖/נּוּ יֵאָכֵֽל", "en": {"kjv": "But if the sacrifice of his offering be a vow, or a voluntary offering, it shall be eaten the same day that he offereth his sacrifice: and on the morrow also the remainder of it shall be eaten:", "web": "“‘But if the sacrifice of his offering is a vow, or a freewill offering, it shall be eaten on the day that he offers his sacrifice; and on the next day what remains of it shall be eaten:", "bsb": "If, however, the sacrifice he offers is a vow or a freewill offering, it shall be eaten on the day he presents his sacrifice, but the remainder may be eaten on the next day.", "asv": "But if the sacrifice of his oblation be a vow, or a freewill-offering, it shall be eaten on the day that he offereth his sacrifice; and on the morrow that which remaineth of it shall be eaten:", "ylt": "`And if the sacrifice of his offering is a vow or free-will offering, in the day of his bringing near his sacrifice it is eaten; and on the morrow also the remnant of it is eaten;", "tyndale": "Yf it be a vowe or a fre willofferynge that he bryngeth, the same daye that he offereth it, it shalbe eaten, and that which remayneth may be eaten on the morowe:", "dra": "If any man by vow, or of his own accord offer a sacrifice, it shall in like manner be eaten the same day. And if any of it remain until the morrow, it is lawful to eat it.", "bbe": "But if his offering is made because of an oath or given freely, it may be taken as food on the day when it is offered; and the rest may be used up on the day after:", "geneva": "But if the sacrifice of his offring be a vow, or a free offering, it shalbe eaten the same day that he offreth his sacrifice: and so in the morning the residue thereof shalbe eaten.", "wycliffe": "If a man offrith a sacrifice bi a vow, ethir bi fre wille, it schal be etun in lijk maner in the same dai; but also if ony thing dwellith `in to the morew, it is leueful to ete it;", "rotherham": "But, if, a vow or a freewill offering, be his sacrifice of oblation, in the day he bringeth near his sacrifice, shall it be eaten, and on the morrow, then may the remainder thereof, be eaten;", "darby": "And if the sacrifice of his offering be a vow, or voluntary, it shall be eaten the same day that he presented his sacrifice; on the morrow also the remainder of it shall be eaten;", "twenty": "", "jps": "But if the sacrifice of his offering be a vow, or a freewill-offering, it shall be eaten on the day that he offereth his sacrifice; and on the morrow that which remaineth of it may be eaten.", "acv": "But if the sacrifice of his oblation be a vow, or a freewill offering, it shall be eaten on the day that he offers his sacrifice, and on the morrow that which remains of it shall be eaten,", "anderson": "", "haweis": "", "noyes": "", "webster": "But if the sacrifice of his offering [shall be] a vow or a voluntary offering, it shall be eaten the same day that he offereth his sacrifice: and on the morrow also the remainder of it shall be eaten:", "vulgate": "si voto vel sponte quisquam obtulerit hostiam eadem similiter edetur die sed et si quid in crastinum remanserit vesci licitum est;", "brenton": "Ye shall eat no blood in all your habitations, either of beasts or of birds."}}, {"v": 17, "ref": "7:17", "o": "וְ/הַ/נּוֹתָ֖ר מִ/בְּשַׂ֣ר הַ/זָּ֑בַח בַּ/יּוֹם֙ הַ/שְּׁלִישִׁ֔י בָּ/אֵ֖שׁ יִשָּׂרֵֽף", "en": {"kjv": "But the remainder of the flesh of the sacrifice on the third day shall be burnt with fire.", "web": "but what remains of the flesh of the sacrifice on the third day shall be burned with fire.", "bsb": "But any meat of the sacrifice remaining until the third day must be burned up.", "asv": "but that which remaineth of the flesh of the sacrifice on the third day shall be burnt with fire.", "ylt": "and the remnant of the flesh of the sacrifice on the third day with fire is burnt;", "tyndale": "but as moche of the offered flesh as remaneth vnto the thirde daye shalbe burned with fire.", "dra": "But whatsoever shall be found on the third day shall be consumed with fire.", "bbe": "But if any of the flesh of the offering is still unused on the third day, it is to be burned with fire.", "geneva": "But as much of the offered flesh as remaineth vnto the third day, shalbe burnt with fire.", "wycliffe": "sotheli fier schal waaste, whateuer thing the thridde day schal fynde.", "rotherham": "but as for the remainder of the flesh of the sacrifice, on the third day—in fire, shall it be consumed.", "darby": "and the remainder of the flesh of the sacrifice on the third day shall be burned with fire.", "twenty": "", "jps": "But that which remaineth of the flesh of the sacrifice on the third day shall be burnt with fire.", "acv": "but that which remains of the flesh of the sacrifice on the third day shall be burnt with fire.", "anderson": "", "haweis": "", "noyes": "", "webster": "But the remainder of the flesh of the sacrifice on the third day shall be burnt with fire.", "vulgate": "quicquid autem tertius invenerit dies ignis absumet;", "brenton": "Every soul that shall eat blood, that soul shall perish from his people."}}, {"v": 18, "ref": "7:18", "o": "וְ/אִ֣ם הֵאָכֹ֣ל יֵ֠אָכֵל מִ/בְּשַׂר זֶ֨בַח שְׁלָמָ֜י/ו בַּ/יּ֣וֹם הַ/שְּׁלִישִׁי֮ לֹ֣א יֵרָצֶה֒ הַ/מַּקְרִ֣יב אֹת֗/וֹ לֹ֧א יֵחָשֵׁ֛ב ל֖/וֹ פִּגּ֣וּל יִהְיֶ֑ה וְ/הַ/נֶּ֛פֶשׁ הָ/אֹכֶ֥לֶת מִמֶּ֖/נּוּ עֲוֺנָ֥/הּ תִּשָּֽׂא", "en": {"kjv": "And if any of the flesh of the sacrifice of his peace offerings be eaten at all on the third day, it shall not be accepted, neither shall it be imputed unto him that offereth it: it shall be an abomination, and the soul that eateth of it shall bear his iniquity.", "web": "If any of the flesh of the sacrifice of his peace offerings is eaten on the third day, it will not be accepted, neither shall it be imputed to him who offers it. It will be an abomination, and the soul who eats any of it will bear his iniquity.", "bsb": "If any of the meat from his peace offering is eaten on the third day, it will not be accepted. It will not be credited to the one who presented it; it shall be an abomination, and the one who eats of it shall bear his iniquity.", "asv": "And if any of the flesh of the sacrifice of his peace-offerings be eaten on the third day, it shall not be accepted, neither shall it be imputed unto him that offereth it: it shall be an abomination, and the soul that eateth of it shall bear his iniquity.", "ylt": "and if any of the flesh of the sacrifice of his peace-offerings be really eaten on the third day, it is not pleasing; for him who is bringing it near it is not reckoned; it is an abominable thing, and the person who is eating of it his iniquity doth bear.", "tyndale": "For yf any of the flesh of the peaceoffrynges be eaten the thirde daye then shall he that offered it optayne no fauour, nether shall it be rekened vnto him: but shalbe an abhomynacion, and the soule that eateth of it shall beare the synne thereof.", "dra": "If any man eat of the flesh of the victim of peace offerings on the third day, the oblation shall be of no effect: neither shall it profit the offerer. Yea rather, whatsoever soul shall defile itself with such meat, shall be guilty of transgression.", "bbe": "And if any of the flesh of the peace-offering is taken as food on the third day, it will not be pleasing to God and will not be put to the account of him who gives it; it will be unclean and a cause of sin to him who takes it as food.", "geneva": "For if any of the flesh of his peace offrings be eaten in the third day, he shall not be accepted that offereth it, neither shall it be reckoned vnto him, but shalbe an abomination: therefore ye person that eateth of it shall beare his iniquitie.", "wycliffe": "If ony man etith in the thridde dai of the fleischis of sacrifice of pesible thingis, his offryng schal be maad voide, nethir it schal profite to the offerere; but rather whateuer soule defoulith hym silf with suche mete, he schal be gilti of `brekyng of the lawe.", "rotherham": "And, if any of the flesh of his peace-offering, be at all eaten, on the third day, he that brought it near [shall not be accepted] it shall not be reckoned to him, unclean, shall it be,—and the person who shall eat thereof, shall bear his iniquity.", "darby": "And if [any] of the flesh of the sacrifice of his peace-offering be eaten at all on the third day, it shall not be accepted, it shall not be reckoned to him that hath presented it; it shall be an unclean thing, and the soul that eateth of it shall bear his iniquity.", "twenty": "", "jps": "And if any of the flesh of the sacrifice of his peace-offerings be at all eaten on the third day, it shall not be accepted, neither shall it be imputed unto him that offereth it; it shall be an abhorred thing, and the soul that eateth of it shall bear his iniquity.", "acv": "And if any of the flesh of the sacrifice of his peace offerings is eaten on the third day, it shall not be accepted, nor shall it be imputed to him who offers it. It shall be an abomination, and the soul that eats of it shall bear his iniquity.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if [any] of the flesh of the sacrifice of his peace-offerings shall be eaten at all on the third day, it shall not be accepted, neither shall it be imputed to him that offereth it; it shall be an abomination, and the soul that eateth of it shall bear his iniquity.", "vulgate": "si quis de carnibus victimae pacificorum die tertio comederit irrita fiet oblatio nec proderit offerenti quin potius quaecumque anima tali se edulio contaminarit praevaricationis rea erit;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 19, "ref": "7:19", "o": "וְ/הַ/בָּשָׂ֞ר אֲשֶׁר יִגַּ֤ע בְּ/כָל טָמֵא֙ לֹ֣א יֵֽאָכֵ֔ל בָּ/אֵ֖שׁ יִשָּׂרֵ֑ף וְ/הַ֨/בָּשָׂ֔ר כָּל טָה֖וֹר יֹאכַ֥ל בָּשָֽׂר", "en": {"kjv": "And the flesh that toucheth any unclean thing shall not be eaten; it shall be burnt with fire: and as for the flesh, all that be clean shall eat thereof.", "web": "“‘The flesh that touches any unclean thing shall not be eaten. It shall be burned with fire. As for the flesh, everyone who is clean may eat it;", "bsb": "Meat that touches anything unclean must not be eaten; it is to be burned up. As for any other meat, anyone who is ceremonially clean may eat it.", "asv": "And the flesh that toucheth any unclean thing shall not be eaten; it shall be burnt with fire. And as for the flesh, every one that is clean shall eat thereof:", "ylt": "`And the flesh which cometh against any unclean thing is not eaten; with fire it is burnt; as to the flesh, every clean one doth eat of the flesh;", "tyndale": "The flesh that twycheth any vnclene thinge shall not be eaten. but burnt with fire: and all that be clene in their flesh, maye eate flesh.", "dra": "The flesh that hath touched any unclean thing, shall not be eaten: but shall be burnt with fire. He that is clean shall eat of it.", "bbe": "And flesh touched by any unclean thing may not be taken for food: it is to be burned with fire; and as for the flesh of the peace-offerings, everyone who is clean may take it as food:", "geneva": "The flesh also that toucheth any vncleane thing, shall not be eaten, but burnt with fire: but of this flesh all that be cleane shall eate thereof.", "wycliffe": "Fleisch that touchith ony vnclene thing, schal not be etun, but it schal be brent bi fier; he that is clene, schal ete it.", "rotherham": "And, the flesh that toucheth anything unclean, shall not be eaten, in fire, shall it be consumed,—but, as for the [other] flesh, any one who is clean, may eat flesh.", "darby": "And the flesh that toucheth anything unclean shall not be eaten; it shall be burned with fire. And as to the flesh, all that are clean may eat [the] flesh.", "twenty": "", "jps": "And the flesh that toucheth any unclean thing shall not be eaten; it shall be burnt with fire. And as for the flesh, every one that is clean may eat thereof.", "acv": "And the flesh that touches any unclean thing shall not be eaten; it shall be burnt with fire. And as for the flesh, every clean man shall eat of it,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the flesh that toucheth any unclean [thing] shall not be eaten; it shall be burnt with fire: and as for the flesh, all that shall be clean shall eat of it.", "vulgate": "caro quae aliquid tetigerit inmundum non comedetur sed conburetur igni qui fuerit mundus vescetur ea;", "brenton": "Thou shalt also speak to the children of Israel, saying, He that offers a sacrifice of peace-offering, shall bring his gift to the Lord also from the sacrifice of peace-offering."}}, {"v": 20, "ref": "7:20", "o": "וְ/הַ/נֶּ֜פֶשׁ אֲשֶׁר תֹּאכַ֣ל בָּשָׂ֗ר מִ/זֶּ֤בַח הַ/שְּׁלָמִים֙ אֲשֶׁ֣ר לַ/יהוָ֔ה וְ/טֻמְאָת֖/וֹ עָלָ֑י/ו וְ/נִכְרְתָ֛ה הַ/נֶּ֥פֶשׁ הַ/הִ֖וא מֵ/עַמֶּֽי/הָ", "en": {"kjv": "But the soul that eateth of the flesh of the sacrifice of peace offerings, that pertain unto the Lord, having his uncleanness upon him, even that soul shall be cut off from his people.", "web": "but the soul who eats of the flesh of the sacrifice of peace offerings, that belongs to Yahweh, having his uncleanness on him, that soul shall be cut off from his people.", "bsb": "But if anyone who is unclean eats meat from the peace offering that belongs to the LORD, that person must be cut off from his people.", "asv": "but the soul that eateth of the flesh of the sacrifice of peace-offerings, that pertain unto Jehovah, having his uncleanness upon him, that soul shall be cut off from his people.", "ylt": "and the person who eateth of the flesh of the sacrifice of the peace-offerings which are Jehovah's, and his uncleanness upon him, even that person hath been cut off from his people.", "tyndale": "Yf any soule eate of the flesh of the peaceofferynges, that pertayne vnto the Lorde and hys vnclennesse yet apon him, the same soule shall perisshe from amonge his peoole.", "dra": "If any one that is defiled shall eat of the flesh of the sacrifice of peace offerings, which is offered to the Lord, he shall be cut off from his people.", "bbe": "But he who is unclean when he takes as food the flesh of the peace-offerings, which are the Lord's, will be cut off from his people.", "geneva": "But if any eate of the flesh of the peace offerings that pertaineth to the Lord, hauing his vncleannesse vpon him, euen the same person shalbe cut off from his people.", "wycliffe": "A pollutid soule, that etith of the fleischis of the sacrifice of pesible thingis, which is offrid to the Lord, schal perische fro hise puplis.", "rotherham": "But as for the person who shall eat flesh from the peace-offering, which pertaineth unto Yahweh, while his uncleanness is on him, then shall that person be cut off from among his kinsfolk.", "darby": "But the soul that eateth the flesh of the sacrifice of peace-offering which is for Jehovah, having his uncleanness upon him, that soul shall be cut off from his peoples.", "twenty": "", "jps": "But the soul that eateth of the flesh of the sacrifice of peace-offerings, that pertain unto HaShem, having his uncleanness upon him, that soul shall be cut off from his people.", "acv": "but the soul that eats of the flesh of the sacrifice of peace offerings, that pertain to Jehovah, having his uncleanness upon him, that soul shall be cut off from his people.", "anderson": "", "haweis": "", "noyes": "", "webster": "But the soul that eateth [of] the flesh of the sacrifice of peace-offerings that [pertain] to the LORD, having his uncleanness upon him, even that soul shall be cut off from his people.", "vulgate": "anima polluta quae ederit de carnibus hostiae pacificorum quae oblata est Domino peribit de populis suis;", "brenton": "His hands shall bring the burnt-offerings to the Lord; the fat which is on the breast and the lobe of the liver, he shall bring them, so as to set them for a gift before the Lord."}}, {"v": 21, "ref": "7:21", "o": "וְ/נֶ֜פֶשׁ כִּֽי תִגַּ֣ע בְּ/כָל טָמֵ֗א בְּ/טֻמְאַ֤ת אָדָם֙ א֣וֹ בִּ/בְהֵמָ֣ה טְמֵאָ֗ה א֚וֹ בְּ/כָל שֶׁ֣קֶץ טָמֵ֔א וְ/אָכַ֛ל מִ/בְּשַׂר זֶ֥בַח הַ/שְּׁלָמִ֖ים אֲשֶׁ֣ר לַ/יהוָ֑ה וְ/נִכְרְתָ֛ה הַ/נֶּ֥פֶשׁ הַ/הִ֖וא מֵ/עַמֶּֽי/הָ", "en": {"kjv": "Moreover the soul that shall touch any unclean thing, as the uncleanness of man, or any unclean beast, or any abominable unclean thing, and eat of the flesh of the sacrifice of peace offerings, which pertain unto the Lord, even that soul shall be cut off from his people.", "web": "When anyone touches any unclean thing, the uncleanness of man, or an unclean animal, or any unclean abomination, and eats some of the flesh of the sacrifice of peace offerings, which belong to Yahweh, that soul shall be cut off from his people.’”", "bsb": "If one touches anything unclean, whether human uncleanness, an unclean animal, or any unclean, detestable thing, and then eats any of the meat of the peace offering that belongs to the LORD, that person must be cut off from his people.”", "asv": "And when any one shall touch any unclean thing, the uncleanness of man, or an unclean beast, or any unclean abomination, and eat of the flesh of the sacrifice of peace-offerings, which pertain unto Jehovah, that soul shall be cut off from his people.", "ylt": "`And when a person cometh against any thing unclean, of the uncleanness of man, or of the uncleanness of beasts, or of any unclean teeming creature, and hath eaten of the flesh of the sacrifice of the peace-offerings which are Jehovah's, even that person hath been cut off from his people.'", "tyndale": "Moreouer yf a soule twych any vnclene thinge, whether it be the vnclennesse of man or of any vnclene beest or any abhominacion that is vnclene: ad the eate of the flesh of the peaceoffrynges whiche pertayne vnto the Lord, that soule shall perissh from his people.", "dra": "And he that hath touched the uncleanness of man, or of beast, or of any thing that can defile, and shall eat of such kind of flesh: shall be cut off from his people.", "bbe": "And anyone who, after touching any unclean thing of man or an unclean beast or any unclean and disgusting thing, takes as food the flesh of the peace-offerings, which are the Lord's, will be cut off from his people.", "geneva": "Moreouer, whe any toucheth any vncleane thing, as the vncleannesse of man, or of an vncleane beast, or of any filthie abomination, and eate of the flesh of the peace offrings, which pertaineth vnto the Lord, euen that person shalbe cut off from his people.", "wycliffe": "And he that touchith vnclennesse of man, ether of beeste, ether of alle thing that may defoule, and etith of suche fleischis, schal perische fro hise puplis.", "rotherham": "Yea, as for, any person, whensoever he shall touch anything unclean—the uncleanness of man or an unclean beast, or any unclean disgusting thing,—and then eateth of the flesh of a peace-offering that pertaineth unto Yahweh, then shall that person be cut off from among his kinsfolk.", "darby": "And if any one touch anything unclean, the uncleanness of man, or unclean beast, or any unclean abomination, and eat of the flesh of the sacrifice of peace-offering, which is for Jehovah, that soul shall be cut off from his peoples.", "twenty": "", "jps": "And when any one shall touch any unclean thing, whether it be the uncleanness of man, or an unclean beast, or any unclean detestable thing, and eat of the flesh of the sacrifice of peace-offerings, which pertain unto HaShem, that soul shall be cut off from his people.", "acv": "And when a soul shall touch any unclean thing, the uncleanness of man, or an unclean beast, or any unclean abomination, and eats of the flesh of the sacrifice of peace offerings, which pertain to Jehovah, that soul shall be cut off from his people.", "anderson": "", "haweis": "", "noyes": "", "webster": "Moreover, the soul that shall touch any unclean [thing], [as] the uncleanness of man, or [any] unclean beast, or any abominable unclean [thing], and eat of the flesh of the sacrifice of peace-offerings which [pertain] to the LORD, even that soul shall be cut off from his people.", "vulgate": "et quae tetigerit inmunditiam hominis vel iumenti sive omnis rei quae polluere potest et comederit de huiuscemodi carnibus interibit de populis suis;", "brenton": "And the priest shall offer the fat upon the altar, and the breast shall be Aaron's and his sons,"}}, {"v": 22, "ref": "7:22", "o": "וַ/יְדַבֵּ֥ר יְהוָ֖ה אֶל מֹשֶׁ֥ה לֵּ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh spoke to Moses, saying,", "bsb": "Then the LORD said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde spake vnto Moses saynge:", "dra": "And the Lord spoke to Moses, saying:", "bbe": "And the Lord said to Moses,", "geneva": "Againe ye Lord spake vnto Moses, saying,", "wycliffe": "And the Lord spak to Moises,", "rotherham": "And Yahweh spake unto Moses, saying—", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses, saying:", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "locutusque est Dominus ad Mosen dicens;", "brenton": "and ye shall give the right shoulder for a choice piece to the priest of your sacrifices of peace-offering."}}, {"v": 23, "ref": "7:23", "o": "דַּבֵּ֛ר אֶל בְּנֵ֥י יִשְׂרָאֵ֖ל לֵ/אמֹ֑ר כָּל חֵ֜לֶב שׁ֥וֹר וְ/כֶ֛שֶׂב וָ/עֵ֖ז לֹ֥א תֹאכֵֽלוּ", "en": {"kjv": "Speak unto the children of Israel, saying, Ye shall eat no manner of fat, of ox, or of sheep, or of goat.", "web": "“Speak to the children of Israel, saying, ‘You shall eat no fat, of bull, or sheep, or goat.", "bsb": "“Speak to the Israelites and say, ‘You are not to eat any of the fat of an ox, a sheep, or a goat.", "asv": "Speak unto the children of Israel, saying, Ye shall eat no fat, of ox, or sheep, or goat.", "ylt": "`Speak unto the sons of Israel, saying, Any fat of ox and sheep and goat ye do not eat;", "tyndale": "speake vnto the childern of Israel ad saye. Ye shall eate no maner fatt of oxen, shepe or gootes:", "dra": "Say to the children of Israel: The fat of a sheep, and of an ox, and of a goat you shall not eat.", "bbe": "Say to the children of Israel: You are not to take any fat, of ox or sheep or goat, for food.", "geneva": "Speake vnto the children of Israel, and say, Ye shall eate no fat of beeues, nor of sheepe, nor of goates:", "wycliffe": "and seide, Speke thou to the sones of Israel, Ye schulen not ete the ynnere fatnesse of a scheep, of an oxe, and of a geet;", "rotherham": "Speak unto the sons of Israel, saying,—No fat, of ox or sheep or goat, shall ye eat:", "darby": "Speak unto the children of Israel, saying, No fat, of ox, or of sheep, or of goat shall ye eat.", "twenty": "", "jps": "Speak unto the children of Israel, saying: Ye shall eat no fat, of ox, or sheep, or goat.", "acv": "Speak to the sons of Israel, saying, Ye shall eat no fat, of ox, or sheep, or goat.", "anderson": "", "haweis": "", "noyes": "", "webster": "Speak to the children of Israel, saying, Ye shall eat no manner of fat, of ox, or of sheep, or of goat.", "vulgate": "loquere filiis Israhel adipem bovis et ovis et caprae non comedetis;", "brenton": "He that offers the blood of the peace-offering, and the fat, of the sons of Aaron, his shall be the right shoulder for a portion."}}, {"v": 24, "ref": "7:24", "o": "וְ/חֵ֤לֶב נְבֵלָה֙ וְ/חֵ֣לֶב טְרֵפָ֔ה יֵעָשֶׂ֖ה לְ/כָל מְלָאכָ֑ה וְ/אָכֹ֖ל לֹ֥א תֹאכְלֻֽ/הוּ", "en": {"kjv": "And the fat of the beast that dieth of itself, and the fat of that which is torn with beasts, may be used in any other use: but ye shall in no wise eat of it.", "web": "The fat of that which dies of itself, and the fat of that which is torn of animals, may be used for any other service, but you shall in no way eat of it.", "bsb": "The fat of an animal found dead or mauled by wild beasts may be used for any other purpose, but you must not eat it.", "asv": "And the fat of that which dieth of itself, and the fat of that which is torn of beasts, may be used for any other service; but ye shall in no wise eat of it.", "ylt": "and the fat of a carcase, and the fat of a torn thing is prepared for any work, but ye do certainly not eat it;", "tyndale": "neuerthelater the fatt of the beest that dyeth alone ad the fatt of that which is torne with wilde beestes, maye be occupide in all maner vses: but ye shal in no wise eate of it.", "dra": "The fat of a carcass that hath died of itself, and of a beast that was caught by another beast, you shall have for divers uses.", "bbe": "And the fat of that which comes to a natural death, and the fat of that which is attacked by beasts, may be used for other purposes, but not in any way for food.", "geneva": "Yet the fat of the dead beast, and the fat of that, which is torne with beastes, shalbe occupied to any vse, but ye shall not eate of it.", "wycliffe": "ye schulen haue in to dyuerse vsis the ynnere fatnesse of a carkeis deed by it silf, and of that beeste which is takun of a rauenus beeste.", "rotherham": "and though the fat of what dieth of itself and the fat of that which has been torn in pieces, may be used for any other service, yet shall ye, in nowise eat it.", "darby": "But the fat of a dead carcase, and the fat of that which is torn, may be used in any other use; but ye shall in no wise eat it.", "twenty": "", "jps": "And the fat of that which dieth of itself, and the fat of that which is torn of beasts, may be used for any other service; but ye shall in no wise eat of it.", "acv": "And the fat of that which dies of itself, and the fat of that which is torn of beasts, may be used for any other service, but ye shall certainly not eat of it.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the fat of the beast that dieth of itself, and the fat of that which is torn with beasts, may be used for any other purpose; but ye shall in no wise eat of it.", "vulgate": "adipem cadaveris morticini et eius animalis quod a bestia captum est habebitis in usus varios;", "brenton": "For I have taken the wave-breast and shoulder of separation from the children of Israel from the sacrifices of your peace-offerings, and I have given them to Aaron the priest and his sons, a perpetual ordinance due from the children of Israel."}}, {"v": 25, "ref": "7:25", "o": "כִּ֚י כָּל אֹכֵ֣ל חֵ֔לֶב מִן הַ֨/בְּהֵמָ֔ה אֲשֶׁ֨ר יַקְרִ֥יב מִמֶּ֛/נָּה אִשֶּׁ֖ה לַ/יהוָ֑ה וְ/נִכְרְתָ֛ה הַ/נֶּ֥פֶשׁ הָ/אֹכֶ֖לֶת מֵֽ/עַמֶּֽי/הָ", "en": {"kjv": "For whosoever eateth the fat of the beast, of which men offer an offering made by fire unto the Lord, even the soul that eateth it shall be cut off from his people.", "web": "For whoever eats the fat of the animal, of which men offer an offering made by fire to Yahweh, even the soul who eats it shall be cut off from his people.", "bsb": "If anyone eats the fat of an animal from which an offering made by fire may be presented to the LORD, the one who eats it must be cut off from his people.", "asv": "For whosoever eateth the fat of the beast, of which men offer an offering made by fire unto Jehovah, even the soul that eateth it shall be cut off from his people.", "ylt": "for whoever eateth the fat of the beast, of which one bringeth near a fire-offering to Jehovah, even the person who eateth hath been cut off from his people.", "tyndale": "For whosoeuer eateth the fatt of the beest of which me bring an offring vnto the Lorde, that soule that eateth it shall perissh fro his people.", "dra": "If any man eat the fat that should be offered for the burnt sacrifice of the Lord, he shall perish out of his people.", "bbe": "For anyone who takes as food the fat of any beast of which men make an offering by fire to the Lord, will be cut off from his people.", "geneva": "For whosoeuer eateth the fat of the beast, of the which he shall offer an offering made by fire to the Lord, euen the person that eateth, shalbe cut off from his people.", "wycliffe": "If ony man etith the ynnere fatnesse, that owith to be offrid in to encense of the Lord, he schal perische fro his puple.", "rotherham": "Nay, as touching any one who eateth the fat of any beast, wherefrom he might bring near an altar-flame unto Yahweh, then shall the person that eateth be cut off from among his kinsfolk.", "darby": "For whoever eateth the fat of the beast of which men present an offering by fire to Jehovah, the soul that hath eaten shall be cut off from his peoples.", "twenty": "", "jps": "For whosoever eateth the fat of the beast, of which men present an offering made by fire unto HaShem, even the soul that eateth it shall be cut off from his people.", "acv": "For whoever eats the fat of the beast, of which men offer an offering made by fire to Jehovah, even the soul that eats it shall be cut off from his people.", "anderson": "", "haweis": "", "noyes": "", "webster": "For whoever eateth the fat of the beast, of which men offer an offering made by fire to the LORD, even the soul that eateth [it] shall be cut off from his people.", "vulgate": "si quis adipem qui offerri debet in incensum Domini comederit peribit de populo suo;", "brenton": "This is the anointing of Aaron, and the anointing of his sons, their portion of the burnt-offerings of the Lord, in the day in which he brought them forward to minister as priests to the Lord;"}}, {"v": 26, "ref": "7:26", "o": "וְ/כָל דָּם֙ לֹ֣א תֹאכְל֔וּ בְּ/כֹ֖ל מוֹשְׁבֹתֵי/כֶ֑ם לָ/ע֖וֹף וְ/לַ/בְּהֵמָֽה", "en": {"kjv": "Moreover ye shall eat no manner of blood, whether it be of fowl or of beast, in any of your dwellings.", "web": "You shall not eat any blood, whether it is of bird or of animal, in any of your dwellings.", "bsb": "You must not eat the blood of any bird or animal in any of your dwellings.", "asv": "And ye shall eat no manner of blood, whether it be of bird or of beast, in any of your dwellings.", "ylt": "`And any blood ye do not eat in all your dwellings, of fowl, or of beast;", "tyndale": "Moreouer ye shall eate no maner of bloud, wheresoeuer ye dwell, whether it be of foule or of beest.", "dra": "Moreover you shall not eat the blood of any creature whatsoever, whether of birds or beasts.", "bbe": "And you are not to take for food any blood, of bird or of beast, in any of your houses.", "geneva": "Neither shall ye eate any blood, either of foule, or of beast in all your dwellings.", "wycliffe": "Also ye schulen not take in mete the blood of ony beeste, as wel of briddis as of beestis;", "rotherham": "And no manner of blood, shall ye eat, in any of your dwellings,—whether of bird or of beast:", "darby": "And no blood shall ye eat in any of your dwellings, whether it be of fowl or of cattle.", "twenty": "", "jps": "And ye shall eat no manner of blood, whether it be of fowl or of beast, in any of your dwellings.", "acv": "And ye shall eat no manner of blood, whether it be of bird or of beast, in any of your dwellings.", "anderson": "", "haweis": "", "noyes": "", "webster": "Moreover, ye shall eat no manner of blood, [whether] of fowl or of beast, in any of your dwellings.", "vulgate": "sanguinem quoque omnis animalis non sumetis in cibo tam de avibus quam de pecoribus;", "brenton": "as the Lord commanded to give to them in the day in which he anointed them of the sons of Israel, a perpetual statute through their generations."}}, {"v": 27, "ref": "7:27", "o": "כָּל נֶ֖פֶשׁ אֲשֶׁר תֹּאכַ֣ל כָּל דָּ֑ם וְ/נִכְרְתָ֛ה הַ/נֶּ֥פֶשׁ הַ/הִ֖וא מֵֽ/עַמֶּֽי/הָ", "en": {"kjv": "Whatsoever soul it be that eateth any manner of blood, even that soul shall be cut off from his people.", "web": "Whoever it is who eats any blood, that soul shall be cut off from his people.’”", "bsb": "If anyone eats blood, that person must be cut off from his people.’”", "asv": "Whosoever it be that eateth any blood, that soul shall be cut off from his people.", "ylt": "any person who eateth any blood, even that person hath been cut off from his people.'", "tyndale": "What soeuer soule it be that eateth any maner of bloude the same soule shal perisshe fro his people.", "dra": "Every one that eateth blood, shall perish from among the people.", "bbe": "Whoever takes any blood for food will be cut off from his people.", "geneva": "Euery person that eateth any blood, euen the same person shall be cut off from his people.", "wycliffe": "ech man that etith blood schal perische fro his puplis.", "rotherham": "as touching any person who eateth any manner of blood, then shall that person be cut off from among his kinsfolk.", "darby": "Whatever soul it be that eateth any manner of blood, that soul shall be cut off from his peoples.", "twenty": "", "jps": "Whosoever it be that eateth any blood, that soul shall be cut off from his people.", "acv": "Whoever it is who eats any blood, that soul shall be cut off from his people.", "anderson": "", "haweis": "", "noyes": "", "webster": "Whatever soul [it may be] that eateth any manner of blood, even that soul shall be cut off from his people.", "vulgate": "omnis anima quae ederit sanguinem peribit de populis suis;", "brenton": "This is the law of the whole-burnt-offerings, and of sacrifice, and of sin-offering, and of offering for transgression, and of the sacrifice of consecration, and of the sacrifice of peace-offering;"}}, {"v": 28, "ref": "7:28", "o": "וַ/יְדַבֵּ֥ר יְהוָ֖ה אֶל מֹשֶׁ֥ה לֵּ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh spoke to Moses, saying,", "bsb": "Then the LORD said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde talked with Moses sayenge:", "dra": "And the Lord spoke to Moses, saying:", "bbe": "And the Lord said to Moses,", "geneva": "And the Lord talked with Moses, saying,", "wycliffe": "And the Lord spak to Moises,", "rotherham": "And Yahweh spake unto Moses, saying,", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses, saying:", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "locutus est Dominus ad Mosen dicens;", "brenton": "as the Lord commanded Moses in the mount Sina, in the day in which he commanded the children of Israel to offer their gifts before the Lord in the wilderness of Sina."}}, {"v": 29, "ref": "7:29", "o": "דַּבֵּ֛ר אֶל בְּנֵ֥י יִשְׂרָאֵ֖ל לֵ/אמֹ֑ר הַ/מַּקְרִ֞יב אֶת זֶ֤בַח שְׁלָמָי/ו֙ לַ/יהוָ֔ה יָבִ֧יא אֶת קָרְבָּנ֛/וֹ לַ/יהוָ֖ה מִ/זֶּ֥בַח שְׁלָמָֽי/ו", "en": {"kjv": "Speak unto the children of Israel, saying, He that offereth the sacrifice of his peace offerings unto the Lord shall bring his oblation unto the Lord of the sacrifice of his peace offerings.", "web": "“Speak to the children of Israel, saying, ‘He who offers the sacrifice of his peace offerings to Yahweh shall bring his offering to Yahweh out of the sacrifice of his peace offerings.", "bsb": "“Speak to the Israelites and say, ‘Anyone who presents a peace offering to the LORD must bring it as his sacrifice to the LORD.", "asv": "Speak unto the children of Israel, saying, He that offereth the sacrifice of his peace-offerings unto Jehovah shall bring his oblation unto Jehovah out of the sacrifice of his peace-offerings:", "ylt": "`Speak unto the sons of Israel, saying, He who is bringing near the sacrifice of his peace-offerings to Jehovah doth bring in his offering to Jehovah from the sacrifice of his peace-offerings;", "tyndale": "speake vnto the childre of Israel ad saye He that offereth his peaceofferynge vnto the Lord, shall bringe his gifte vnto the Lord of his peaceoffrynges:", "dra": "Speak to the children of Israel, saying: He that offereth a victim of peace offerings to the Lord, let him offer therewith a sacrifice also, that is, the libations thereof.", "bbe": "Say to the children of Israel: He who makes a peace-offering to the Lord, is to give an offering to the Lord out of his peace-offering:", "geneva": "Speake vnto the children of Israel, and say, Hee that offereth his peace offerings vnto the Lord, shall bring his gifte vnto the Lord of his peace offerings:", "wycliffe": "and seide, Speke thou to the sones of Israel, He that offrith a sacrifice of pesible thingis to the Lord, offre togidere also a sacrifice, that is, fletynge offryngis therof.", "rotherham": "Speak unto the sons of Israel saying,—He that offereth his peace-offering unto Yahweh, shall bring in his own oblation unto Yahweh out of his peace-offering:", "darby": "Speak unto the children of Israel, saying, He that presenteth the sacrifice of his peace-offering to Jehovah shall bring his offering to Jehovah of the sacrifice of his peace-offering.", "twenty": "", "jps": "Speak unto the children of Israel, saying: He that offereth his sacrifice of peace-offerings unto HaShem shall bring his offering unto HaShem out of his sacrifice of peace-offerings.", "acv": "Speak to the sons of Israel, saying, He who offers the sacrifice of his peace offerings to Jehovah shall bring his oblation to Jehovah out of the sacrifice of his peace offerings.", "anderson": "", "haweis": "", "noyes": "", "webster": "Speak to the children of Israel, saying, He that offereth the sacrifice of his peace-offerings to the LORD, shall bring his oblation to the LORD of the sacrifice of his peace-offerings.", "vulgate": "loquere filiis Israhel qui offert victimam pacificorum Domino offerat simul et sacrificium id est libamenta eius;", "brenton": ""}}, {"v": 30, "ref": "7:30", "o": "יָדָ֣י/ו תְּבִיאֶ֔ינָה אֵ֖ת אִשֵּׁ֣י יְהוָ֑ה אֶת הַ/חֵ֤לֶב עַל הֶֽ/חָזֶה֙ יְבִיאֶ֔/נּוּ אֵ֣ת הֶ/חָזֶ֗ה לְ/הָנִ֥יף אֹת֛/וֹ תְּנוּפָ֖ה לִ/פְנֵ֥י יְהוָֽה", "en": {"kjv": "His own hands shall bring the offerings of the Lord made by fire, the fat with the breast, it shall he bring, that the breast may be waved for a wave offering before the Lord.", "web": "With his own hands he shall bring the offerings of Yahweh made by fire. He shall bring the fat with the breast, that the breast may be waved for a wave offering before Yahweh.", "bsb": "With his own hands he is to bring the offerings made by fire to the LORD; he shall bring the fat, together with the breast, and wave the breast as a wave offering before the LORD.", "asv": "his own hands shall bring the offerings of Jehovah made by fire; the fat with the breast shall he bring, that the breast may be waved for a wave-offering before Jehovah.", "ylt": "his own hands do bring in the fire-offerings of Jehovah, the fat beside the breast, it he doth bring in with the breast, to wave it--a wave-offering before Jehovah.", "tyndale": "his owne handes shal bringe the offrynge of the Lorde: eue the fatt apo the brest he shall bringe with the brest to waue it a waueoffrynge before the Lorde.", "dra": "He shall hold in his hands the fat of the victim, and the breast. And when he hath offered and consecrated both to the Lord, he shall deliver them to the priest,", "bbe": "He himself is to take to the Lord the offering made by fire, even the fat with the breast, so that the breast may be waved for a wave offering before the Lord.", "geneva": "His handes shall bring the offerings of the Lord made by fire: euen the fatte with the breast shall he bring, that the breast may be shaken to and from before the Lord.", "wycliffe": "He schal holde in the hondis the ynnere fatnesse of the sacrifice, and the brest; and whanne he hath halewid bothe offrid to the Lord, he schal yyue to the preest,", "rotherham": "his own hands shall bring in the altar-flames of Yahweh,—the fat with the breast, he shall bring it in, the breast, to wave it as a wave-offering before Yahweh.", "darby": "His own hands shall bring Jehovah's offerings by fire, the fat with the breast shall he bring: the breast, that it may be waved as a wave-offering before Jehovah.", "twenty": "", "jps": "His own hands shall bring the offerings of HaShem made by fire: the fat with the breast shall he bring, that the breast may be waved for a wave-offering before HaShem.", "acv": "His own hands shall bring the offerings of Jehovah made by fire. He shall bring the fat with the breast, that the breast may be waved for a wave offering before Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "His own hands shall bring the offerings of the LORD made by fire, the fat with the breast, that shall he bring, that the breast may be waved [for] a wave-offering before the LORD.", "vulgate": "tenebit manibus adipem hostiae et pectusculum cumque ambo oblata Domino consecrarit tradet sacerdoti;", "brenton": ""}}, {"v": 31, "ref": "7:31", "o": "וְ/הִקְטִ֧יר הַ/כֹּהֵ֛ן אֶת הַ/חֵ֖לֶב הַ/מִּזְבֵּ֑חָ/ה וְ/הָיָה֙ הֶֽ/חָזֶ֔ה לְ/אַהֲרֹ֖ן וּ/לְ/בָנָֽי/ו", "en": {"kjv": "And the priest shall burn the fat upon the altar: but the breast shall be Aaron’s and his sons’.", "web": "The priest shall burn the fat on the altar, but the breast shall be Aaron’s and his sons’.", "bsb": "The priest is to burn the fat on the altar, but the breast belongs to Aaron and his sons.", "asv": "And the priest shall burn the fat upon the altar; but the breast shall be Aaron’s and his sons’.", "ylt": "`And the priest hath made perfume with the fat on the altar, and the breast hath been Aaron's and his sons;", "tyndale": "And the preast shall burne the fatt apon the alter, ad the brest shalbe Aaros ad his sonnes.", "dra": "Who shall burn the fat upon the altar. But the breast shall be Aaron's and his sons'.", "bbe": "And the fat is to be burned by the priest on the altar, but the breast is for Aaron and his sons.", "geneva": "Then the Priest shall burne the fatte vpon the Altar, and the breast shall be Aarons and his sonnes.", "wycliffe": "which schal brenne the ynnere fatnesse on the auter; sotheli the brest schal be Aarons and hise sones;", "rotherham": "Then shall the priest make a perfume with the fat at the altar,—and the breast shall be for Aaron and for his sons.", "darby": "And the priest shall burn the fat on the altar; and the breast shall be Aaron's and his sons'.", "twenty": "", "jps": "And the priest shall make the fat smoke upon the altar; but the breast shall be Aaron's and his sons'.", "acv": "And the priest shall burn the fat upon the altar, but the breast shall be Aaron's and his sons'.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall burn the fat upon the altar: but the breast shall be Aaron's and his sons'.", "vulgate": "qui adolebit adipem super altare pectusculum autem erit Aaron et filiorum eius;", "brenton": ""}}, {"v": 32, "ref": "7:32", "o": "וְ/אֵת֙ שׁ֣וֹק הַ/יָּמִ֔ין תִּתְּנ֥וּ תְרוּמָ֖ה לַ/כֹּהֵ֑ן מִ/זִּבְחֵ֖י שַׁלְמֵי/כֶֽם", "en": {"kjv": "And the right shoulder shall ye give unto the priest for an heave offering of the sacrifices of your peace offerings.", "web": "The right thigh you shall give to the priest for a heave offering out of the sacrifices of your peace offerings.", "bsb": "And you are to give the right thigh to the priest as a contribution from your peace offering.", "asv": "And the right thigh shall ye give unto the priest for a heave-offering out of the sacrifices of your peace-offerings.", "ylt": "and the right leg ye do make a heave-offering to the priest of the sacrifices of your peace-offerings;", "tyndale": "And the right shulder they shall geue vnto the preast, to be an heueoffrynge, of their peaceoffringes.", "dra": "The right shoulder also of the victim, of peace offerings shall fall to the priest for firstfruits.", "bbe": "And the right leg you are to give to the priest for an offering to be lifted up out of what is given for your peace-offerings.", "geneva": "And the right shoulder shall ye giue vnto the Priest for an heaue offering, of your peace offrings.", "wycliffe": "and the riyt schuldur of the sacrifices of pesible thingis schal turne in to the firste fruytis of the preest.", "rotherham": "But, the right shoulder, shall ye give as a heave-offering, unto the priest,—from among your peace-offerings", "darby": "And the right shoulder of the sacrifices of your peace-offerings shall ye give as a heave-offering unto the priest.", "twenty": "", "jps": "And the right thigh shall ye give unto the priest for a heave-offering out of your sacrifices of peace-offerings.", "acv": "And the right thigh ye shall give to the priest for a heave offering out of the sacrifices of your peace offerings.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the right shoulder shall ye give to the priest [for] a heave-offering of the sacrifices of your peace-offerings.", "vulgate": "armus quoque dexter de pacificorum hostiis cedet in primitias sacerdotis;", "brenton": ""}}, {"v": 33, "ref": "7:33", "o": "הַ/מַּקְרִ֞יב אֶת דַּ֧ם הַ/שְּׁלָמִ֛ים וְ/אֶת הַ/חֵ֖לֶב מִ/בְּנֵ֣י אַהֲרֹ֑ן ל֧/וֹ תִהְיֶ֛ה שׁ֥וֹק הַ/יָּמִ֖ין לְ/מָנָֽה", "en": {"kjv": "He among the sons of Aaron, that offereth the blood of the peace offerings, and the fat, shall have the right shoulder for his part.", "web": "He among the sons of Aaron who offers the blood of the peace offerings, and the fat, shall have the right thigh for a portion.", "bsb": "The son of Aaron who presents the blood and fat of the peace offering shall have the right thigh as a portion.", "asv": "He among the sons of Aaron that offereth the blood of the peace-offerings, and the fat, shall have the right thigh for a portion.", "ylt": "he of the sons of Aaron who is bringing near the blood of the peace-offerings, and the fat, his is the right leg for a portion.", "tyndale": "And the same that offreth the bloud of the peaceoffringes ad the fatt, amog the sones of Aaro, shall haue the right shulder vnto his parte,", "dra": "He among the sons of Aaron, that offereth the blood, and the fat: he shall have the right shoulder also for his portion.", "bbe": "That man, among the sons of Aaron, by whom the blood of the peace-offering and the fat are offered, is to have the right leg for his part.", "geneva": "The same that offreth the blood of ye peace offrings, and the fatte, among the sonnes of Aaron, shall haue the right shoulder for his parte.", "wycliffe": "He that of Aarons sones offrith the blood, and the ynnere fatnesse, schal haue also the riyt schuldur in his porcioun.", "rotherham": "he that bringeth near the blood of the peace-offerings and the fat from among the sons of Aaron, to him, shall belong the right shoulder for a portion.", "darby": "He of the sons of Aaron that presenteth the blood of the peace-offerings, and the fat, shall have the right shoulder for [his] part.", "twenty": "", "jps": "He among the sons of Aaron, that offereth the blood of the peace-offerings, and the fat, shall have the right thigh for a portion.", "acv": "He among the sons of Aaron who offers the blood of the peace offerings, and the fat, shall have the right thigh for a portion.", "anderson": "", "haweis": "", "noyes": "", "webster": "He among the sons' of Aaron that offereth the blood of the peace-offerings, and the fat, shall have the right shoulder for [his] part.", "vulgate": "qui obtulerit sanguinem et adipem filiorum Aaron ipse habebit et armum dextrum in portione sua;", "brenton": ""}}, {"v": 34, "ref": "7:34", "o": "כִּי֩ אֶת חֲזֵ֨ה הַ/תְּנוּפָ֜ה וְ/אֵ֣ת שׁ֣וֹק הַ/תְּרוּמָ֗ה לָקַ֨חְתִּי֙ מֵ/אֵ֣ת בְּנֵֽי יִשְׂרָאֵ֔ל מִ/זִּבְחֵ֖י שַׁלְמֵי/הֶ֑ם וָ/אֶתֵּ֣ן אֹ֠תָ/ם לְ/אַהֲרֹ֨ן הַ/כֹּהֵ֤ן וּ/לְ/בָנָי/ו֙ לְ/חָק עוֹלָ֔ם מֵ/אֵ֖ת בְּנֵ֥י יִשְׂרָאֵֽל", "en": {"kjv": "For the wave breast and the heave shoulder have I taken of the children of Israel from off the sacrifices of their peace offerings, and have given them unto Aaron the priest and unto his sons by a statute for ever from among the children of Israel.", "web": "For the waved breast and the heaved thigh I have taken from the children of Israel out of the sacrifices of their peace offerings, and have given them to Aaron the priest and to his sons as their portion forever from the children of Israel.’”", "bsb": "I have taken from the sons of Israel the breast of the wave offering and the thigh of the contribution of their peace offerings, and I have given them to Aaron the priest and his sons as a permanent portion from the sons of Israel.’”", "asv": "For the wave-breast and the heave-thigh have I taken of the children of Israel out of the sacrifices of their peace-offerings, and have given them unto Aaron the priest and unto his sons as their portion for ever from the children of Israel.", "ylt": "`For the breast of the wave-offering, and the leg of the heave-offering, I have taken from the sons of Israel, from the sacrifices of their peace-offerings, and I give them to Aaron the priest, and to his sons, by a statute age-during, from the sons of Israel.'", "tyndale": "for the wauebrest ad the heueshulder I haue take of the childern of Israel, euen of their peaceoffringes, ad haue geue it vnto Aaro the prest and vnto his sonnes: to be a dutie for euer of the childern of Israel.", "dra": "For the breast that is elevated and the shoulder that is separated I have taken of the children of Israel, from off their victims of peace offerings: and have given them to Aaron the priest, and to his sons, by a law for ever, from all the people of Israel.", "bbe": "For the breast which is waved and the right leg which is lifted up on high I have taken from the children of Israel, from their peace-offerings, and have given them to Aaron the priest and to his sons as their right for ever from the children of Israel.", "geneva": "For the breast shaken to and from, and the shoulder lifted vp, haue I taken of the children of Israel, euen of their peace offrings, and haue giuen them vnto Aaron the Priest and vnto his sonnes by a statute for euer from among the children of Israel.", "wycliffe": "For Y haue take fro the sones of Israel the brest of reisyng, and the schuldur of departyng, of the pesible sacrifices `of hem, and Y haue youe to Aaron the preest and to hise sones, bi euerlastynge lawe, of al the puple of Israel.", "rotherham": "For, the wave-breast and the heave-shoulder, have I taken of the sons of Israel, out of their peace-offerings,—and have given them unto Aaron the priest and unto his sons as an age-abiding statute, from the sons of Israel.", "darby": "For the breast of the wave-offering, and the shoulder of the heave-offering, have I taken of the children of Israel from the sacrifices of their peace-offerings, and have given them unto Aaron the priest and unto his sons from the children of Israel by an everlasting statute.", "twenty": "", "jps": "For the breast of waving and the thigh of heaving have I taken of the children of Israel out of their sacrifices of peace-offerings, and have given them unto Aaron the priest and unto his sons as a due for ever from the children of Israel.", "acv": "For I have taken the wave-breast and the heave-thigh from the sons of Israel out of the sacrifices of their peace offerings, and have given them to Aaron the priest and to his sons as a portion forever from the sons of Israel.", "anderson": "", "haweis": "", "noyes": "", "webster": "For the wave-breast and the heave-shoulder have I taken of the children of Israel from off the sacrifices of their peace-offerings, and have given them to Aaron the priest, and to his sons, by a statute for ever, from among the children of Israel.", "vulgate": "pectusculum enim elationis et armum separationis tuli a filiis Israhel de hostiis eorum pacificis et dedi Aaron sacerdoti ac filiis eius lege perpetua ab omni populo Israhel;", "brenton": ""}}, {"v": 35, "ref": "7:35", "o": "זֹ֣את מִשְׁחַ֤ת אַהֲרֹן֙ וּ/מִשְׁחַ֣ת בָּנָ֔י/ו מֵ/אִשֵּׁ֖י יְהוָ֑ה בְּ/יוֹם֙ הִקְרִ֣יב אֹתָ֔/ם לְ/כַהֵ֖ן לַ/יהוָֽה", "en": {"kjv": "This is the portion of the anointing of Aaron, and of the anointing of his sons, out of the offerings of the Lord made by fire, in the day when he presented them to minister unto the Lord in the priest’s office;", "web": "This is the anointing portion of Aaron, and the anointing portion of his sons, out of the offerings of Yahweh made by fire, in the day when he presented them to minister to Yahweh in the priest’s office;", "bsb": "This is the portion of the offerings made by fire to the LORD for Aaron and his sons since the day they were presented to serve the LORD as priests.", "asv": "This is the anointing-portion of Aaron, and the anointing-portion of his sons, out of the offerings of Jehovah made by fire, in the day when he presented them to minister unto Jehovah in the priest’s office;", "ylt": "This is the anointing of Aaron, and the anointing of his sons out of the fire-offerings of Jehovah, in the day he hath brought them near to act as priest to Jehovah,", "tyndale": "This is the anoyntinge of Aaron ad of the sacryfices of the Lorde, in the daye when they were offered to be preastes vnto the Lorde,", "dra": "This is the anointing of Aaron and his sons, in the ceremonies of the Lord, in the day when Moses offered them, that they might do the office of priesthood,", "bbe": "This is the holy part given to Aaron and to his sons, out of the offerings made to the Lord by fire, on the day when they were made priests before the Lord;", "geneva": "This is the anointing of Aaron, and the anointing of his sonnes, concerning the offerings of the Lord made by fire, in the day when he presented them to serue in the Priestes office vnto the Lord.", "wycliffe": "This is the anoyntyng of Aaron, and of hise sones, in the cerymonyes of the Lord, in the dai where ynne Moises offride hem that thei schulden be set in preesthod,", "rotherham": "This, is what pertaineth to the anointing of Aaron and to the anointing of his sons out of the altar-flames of Yahweh,—[granted] in the day when he brought them near, to minister as priests unto Yahweh:", "darby": "This is [the portion] of the anointing of Aaron and of the anointing of his sons, from Jehovah's offerings by fire, in the day [when] he presented them to serve Jehovah as priests,", "twenty": "", "jps": "This is the consecrated portion of Aaron, and the consecrated portion of his sons, out of the offerings of HaShem made by fire, in the day when they were presented to minister unto HaShem in the priest's office;", "acv": "This is the anointing-portion of Aaron, and the anointing-portion of his sons, out of the offerings of Jehovah made by fire, in the day when he presented them to minister to Jehovah in the priest's office,", "anderson": "", "haweis": "", "noyes": "", "webster": "This [is the portion] of the anointing of Aaron, and of the anointing of his sons, out of the offerings of the LORD made by fire, in the day [when] he presented them to minister to the LORD in the priest's office;", "vulgate": "haec est unctio Aaron et filiorum eius in caerimoniis Domini die qua obtulit eos Moses ut sacerdotio fungerentur;", "brenton": ""}}, {"v": 36, "ref": "7:36", "o": "אֲשֶׁר֩ צִוָּ֨ה יְהוָ֜ה לָ/תֵ֣ת לָ/הֶ֗ם בְּ/יוֹם֙ מָשְׁח֣/וֹ אֹתָ֔/ם מֵ/אֵ֖ת בְּנֵ֣י יִשְׂרָאֵ֑ל חֻקַּ֥ת עוֹלָ֖ם לְ/דֹרֹתָֽ/ם", "en": {"kjv": "Which the Lord commanded to be given them of the children of Israel, in the day that he anointed them, by a statute for ever throughout their generations.", "web": "which Yahweh commanded to be given them of the children of Israel, in the day that he anointed them. It is their portion forever throughout their generations.", "bsb": "On the day they were anointed, the LORD commanded that this be given them by the sons of Israel. It is a permanent portion for the generations to come.", "asv": "which Jehovah commanded to be given them of the children of Israel, in the day that he anointed them. It is their portion for ever throughout their generations.", "ylt": "which Jehovah hath commanded to give to them in the day of His anointing them, from the sons of Israel--a statute age-during to their generations.", "tyndale": "whiche the Lorde commaunded to be geuen them in the daye when he anoynted them, of the childern of Israel, and to be a dutie for euer amonge their generacions.", "dra": "And the things that the Lord commanded to be given them by the children of Israel, by a perpetual observance in their generations.", "bbe": "Which the Lord said the children of Israel were to give them, on the day when he made them his priests. It is their right for ever from generation to generation.", "geneva": "The which portions the Lord commanded to giue them in the day that he anointed them from among the children of Israel, by a statute for euer in their generations.", "wycliffe": "and whiche thingis the Lord comaundide to be youun to hem of the sones of Israel, bi euerlastynge religioun in her generaciouns.", "rotherham": "which Yahweh commanded to give them in the day when he anointed them, from among the sons of Israel,—an age-abiding statute to their generations.", "darby": "which Jehovah commanded to be given them by the children of Israel in the day that he anointed them: [it is] an everlasting statute, throughout their generations.", "twenty": "", "jps": "which HaShem commanded to be given them of the children of Israel, in the day that they were anointed. It is a due for ever throughout their generations.", "acv": "which Jehovah commanded to be given them from the sons of Israel, in the day that he anointed them. It is a portion forever throughout their generations.", "anderson": "", "haweis": "", "noyes": "", "webster": "Which the LORD commanded to be given to them by the children of Israel, in the day that he anointed them, [by] a statute for ever throughout their generations.", "vulgate": "et quae praecepit dari eis Dominus a filiis Israhel religione perpetua in generationibus suis;", "brenton": ""}}, {"v": 37, "ref": "7:37", "o": "זֹ֣את הַ/תּוֹרָ֗ה לָֽ/עֹלָה֙ לַ/מִּנְחָ֔ה וְ/לַֽ/חַטָּ֖את וְ/לָ/אָשָׁ֑ם וְ/לַ֨/מִּלּוּאִ֔ים וּ/לְ/זֶ֖בַח הַ/שְּׁלָמִֽים", "en": {"kjv": "This is the law of the burnt offering, of the meat offering, and of the sin offering, and of the trespass offering, and of the consecrations, and of the sacrifice of the peace offerings;", "web": "This is the law of the burnt offering, of the meal offering, and of the sin offering, and of the trespass offering, and of the consecration, and of the sacrifice of peace offerings;", "bsb": "This is the law of the burnt offering, the grain offering, the sin offering, the guilt offering, the ordination offering, and the peace offering,", "asv": "This is the law of the burnt-offering, of the meal-offering, and of the sin-offering, and of the trespass-offering, and of the consecration, and of the sacrifice of peace-offerings;", "ylt": "This is the law for burnt-offering, for present, and for sin-offering, and for guilt-offering, and for consecrations, and for a sacrifice of the peace-offerings,", "tyndale": "This is the lawe of burntoffrynges, of meatoffrynges, of synneoffrynges, of trespaceoffrynges, of fulloffrynges, of peaceoffrynges,", "dra": "This is the law of holocaust, and of the sacrifice for sin, and for trespass, and for consecration, and the victims of peace offerings:", "bbe": "These are the laws for the burned offering, the meal offering, and the offering for wrongdoing; and for the making of priests, and for the giving of peace-offerings;", "geneva": "This is also the lawe of the burnt offring of the meate offring, and of the sinne offring, and of the trespasse offring, and of the consecrations, and of the peace offrings,", "wycliffe": "This is the lawe of brent sacrifice, and of sacrifice for synne, and for trespas, and for halewyng, and for the sacrifices of pesible thingis;", "rotherham": "This is the law—for the ascending-sacrifice, for the meal-offering, and for the sin-bearer, and for the guilt-bearer,—and for the installation-offerings, and for the peace-offering:", "darby": "This is the law of the burnt-offering, of the oblation, and of the sin-offering, and of the trespass-offering, and of the consecration-offering, and of the sacrifice of peace-offering,", "twenty": "", "jps": "This is the law of the burnt-offering, of the meal-offering, and of the sin-offering, and of the guilt-offering, and of the consecration-offering, and of the sacrifice of peace-offerings;", "acv": "This is the law of the burnt offering, of the meal offering, and of the sin offering, and of the trespass offering, and of the consecration, and of the sacrifice of peace offerings,", "anderson": "", "haweis": "", "noyes": "", "webster": "This [is] the law of the burnt-offering, of the meat-offering, and of the sin-offering, and of the trespass-offering, and of the consecrations, and of the sacrifice of the Peace-offerings;", "vulgate": "ista est lex holocausti et sacrificii pro peccato atque delicto et pro consecratione et pacificorum victimis;", "brenton": ""}}, {"v": 38, "ref": "7:38", "o": "אֲשֶׁ֨ר צִוָּ֧ה יְהוָ֛ה אֶת מֹשֶׁ֖ה בְּ/הַ֣ר סִינָ֑י בְּ/י֨וֹם צַוֺּת֜/וֹ אֶת בְּנֵ֣י יִשְׂרָאֵ֗ל לְ/הַקְרִ֧יב אֶת קָרְבְּנֵי/הֶ֛ם לַ/יהוָ֖ה בְּ/מִדְבַּ֥ר סִינָֽי", "en": {"kjv": "Which the Lord commanded Moses in mount Sinai, in the day that he commanded the children of Israel to offer their oblations unto the Lord, in the wilderness of Sinai.", "web": "which Yahweh commanded Moses in Mount Sinai, in the day that he commanded the children of Israel to offer their offerings to Yahweh, in the wilderness of Sinai.", "bsb": "which the LORD gave Moses on Mount Sinai on the day He commanded the Israelites to present their offerings to the LORD in the Wilderness of Sinai.", "asv": "which Jehovah commanded Moses in mount Sinai, in the day that he commanded the children of Israel to offer their oblations unto Jehovah, in the wilderness of Sinai.", "ylt": "which Jehovah hath commanded Moses in Mount Sinai, in the day of his commanding the sons of Israel to bring near their offerings to Jehovah, in the wilderness of Sinai.", "tyndale": "which the Lorde commaunded Moses in the mount of Sinai, in the daye when he commaunded the childern of Israel to offer their offrynges vnto the Lorde in the wildernesse of Sinai.", "dra": "Which the Lord appointed to Moses in mount Sinai, when he commanded the children of Israel, that they should offer their oblations to the Lord in the desert of Sinai.", "bbe": "As they were given by the Lord to Moses on Mount Sinai, on the day when the Lord gave orders to the children of Israel to make their offerings to the Lord, in the waste land of Sinai.", "geneva": "Which the Lord commanded Moses in the mount Sinai, when he commanded the children of Israel to offer their giftes vnto the Lord in the wildernesse of Sinai.", "wycliffe": "which lawe the Lord ordeynede to Moises in the hil of Synay, whanne he comaundide to the sones of Israel that thei schulden offre her offryngis to the Lord, in the deseert of Synay.", "rotherham": "which Yahweh commanded Moses in Mount Sinai,—in the day when he commanded the sons of Israel to bring near their oblations unto Yahweh in the desert of Sinai.", "darby": "which Jehovah commanded Moses in mount Sinai, in the day that he commanded the children of Israel to present their offerings to Jehovah, in the wilderness of Sinai.", "twenty": "", "jps": "which HaShem commanded Moses in mount Sinai, in the day that he commanded the children of Israel to present their offerings unto HaShem, in the wilderness of Sinai.", "acv": "which Jehovah commanded Moses at mount Sinai, in the day that he commanded the sons of Israel to offer their oblations to Jehovah, in the wilderness of Sinai.", "anderson": "", "haweis": "", "noyes": "", "webster": "Which the LORD commanded Moses in mount Sinai, in the day that he commanded the children of Israel to offer their oblations to the LORD, in the wilderness of Sinai.", "vulgate": "quas constituit Dominus Mosi in monte Sinai quando mandavit filiis Israhel ut offerrent oblationes suas Domino in deserto Sinai;", "brenton": ""}}]}, {"c": 8, "verses": [{"v": 1, "ref": "8:1", "o": "וַ/יְדַבֵּ֥ר יְהוָ֖ה אֶל מֹשֶׁ֥ה לֵּ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh spoke to Moses, saying,", "bsb": "Then the LORD said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde spake vnto Moses saynge:", "dra": "And the Lord spoke to Moses, saying:", "bbe": "And the Lord said to Moses,", "geneva": "Afterwarde the Lord spake vnto Moses, saying,", "wycliffe": "And the Lord spak to Moises, and seide, Take thou Aaron with hise sones,", "rotherham": "Then spake Yahweh unto Moses, saying:", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses, saying:", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "locutusque est Dominus ad Mosen dicens;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 2, "ref": "8:2", "o": "קַ֤ח אֶֽת אַהֲרֹן֙ וְ/אֶת בָּנָ֣י/ו אִתּ֔/וֹ וְ/אֵת֙ הַ/בְּגָדִ֔ים וְ/אֵ֖ת שֶׁ֣מֶן הַ/מִּשְׁחָ֑ה וְ/אֵ֣ת פַּ֣ר הַֽ/חַטָּ֗את וְ/אֵת֙ שְׁנֵ֣י הָֽ/אֵילִ֔ים וְ/אֵ֖ת סַ֥ל הַ/מַּצּֽוֹת", "en": {"kjv": "Take Aaron and his sons with him, and the garments, and the anointing oil, and a bullock for the sin offering, and two rams, and a basket of unleavened bread;", "web": "“Take Aaron and his sons with him, and the garments, and the anointing oil, and the bull of the sin offering, and the two rams, and the basket of unleavened bread;", "bsb": "“Take Aaron and his sons, their garments, the anointing oil, the bull of the sin offering, the two rams, and the basket of unleavened bread,", "asv": "Take Aaron and his sons with him, and the garments, and the anointing oil, and the bullock of the sin-offering, and the two rams, and the basket of unleavened bread;", "ylt": "`Take Aaron and his sons with him, and the garments, and the anointing oil, and the bullock of the sin-offering, and the two rams, and the basket of unleavened things,", "tyndale": "take Aaron and his sonnes with hi, and the vestures and the anoyntinge oyle, and an oxe for a synneofferynge and two rammes ad a baskett of swete bred:", "dra": "Take Aaron with his sons, their vestments, and the oil of unction: a calf for sin, two rams, a basket with unleavened bread.", "bbe": "Take Aaron, and his sons with him, and the robes and the holy oil and the ox of the sin-offering and the two male sheep and the basket of unleavened bread;", "geneva": "Take Aaron and his sonnes with him, and the garments and the anointing oyle, and a bullocke for the sinne offring, and two rammes, and a basket of vnleauened bread,", "wycliffe": "`the clothes of hem, and the oile of anoyntyng, a calf for synne, twei rammes, a panyere with therf looues;", "rotherham": "Take thou Aaron and his sons with him, and the garments, and the anointing oil,—and the sin-bearing bullock, and the two rams, and the basket of unleavened cakes;", "darby": "Take Aaron and his sons with him, and the garments and the anointing oil, and the bullock of the sin-offering, and the two rams, and the basket of unleavened [bread];", "twenty": "", "jps": "'Take Aaron and his sons with him, and the garments, and the anointing oil, and the bullock of the sin-offering, and the two rams, and the basket of unleavened bread;", "acv": "Take Aaron and his sons with him, and the garments, and the anointing oil, and the bullock of the sin offering, and the two rams, and the basket of unleavened bread,", "anderson": "", "haweis": "", "noyes": "", "webster": "Take Aaron and his sons with him, and the garments, and the anointing oil, and a bullock for the sin-offering, and two rams, and a basket of unleavened bread;", "vulgate": "tolle Aaron cum filiis suis vestes eorum et unctionis oleum vitulum pro peccato duos arietes canistrum cum azymis;", "brenton": "Take Aaron and his sons, and his robes and the anointing oil, and the calf for the sin-offering, and the two rams, and the basket of unleavened bread,"}}, {"v": 3, "ref": "8:3", "o": "וְ/אֵ֥ת כָּל הָ/עֵדָ֖ה הַקְהֵ֑ל אֶל פֶּ֖תַח אֹ֥הֶל מוֹעֵֽד", "en": {"kjv": "And gather thou all the congregation together unto the door of the tabernacle of the congregation.", "web": "and assemble all the congregation at the door of the Tent of Meeting.”", "bsb": "and assemble the whole congregation at the entrance to the Tent of Meeting.”", "asv": "and assemble thou all the congregation at the door of the tent of meeting.", "ylt": "and all the company assemble thou unto the opening of the tent of meeting.'", "tyndale": "ad gather all the comentye together vnto the dore of the tabernacle of witnesse.", "dra": "And thou shalt gather together all the congregation to the door of the tabernacle.", "bbe": "And let all the people come together at the door of the Tent of meeting.", "geneva": "And assemble all the company at the doore of the Tabernacle of the Congregation.", "wycliffe": "and thou schalt gedere al the cumpanye to the dore of the tabernacle.", "rotherham": "and all the assembly, call thou together,—unto the entrance of the tent of meeting.", "darby": "and gather all the assembly together at the entrance of the tent of meeting.", "twenty": "", "jps": "and assemble thou all the congregation at the door of the tent of meeting.'", "acv": "and assemble thou all the congregation at the door of the tent of meeting.", "anderson": "", "haweis": "", "noyes": "", "webster": "And assemble thou all the congregation to the door of the tabernacle of the congregation.", "vulgate": "et congregabis omnem coetum ad ostium tabernaculi;", "brenton": "and assemble the whole congregation at the door of the tabernacle of witness."}}, {"v": 4, "ref": "8:4", "o": "וַ/יַּ֣עַשׂ מֹשֶׁ֔ה כַּֽ/אֲשֶׁ֛ר צִוָּ֥ה יְהוָ֖ה אֹת֑/וֹ וַ/תִּקָּהֵל֙ הָֽ/עֵדָ֔ה אֶל פֶּ֖תַח אֹ֥הֶל מוֹעֵֽד", "en": {"kjv": "And Moses did as the Lord commanded him; and the assembly was gathered together unto the door of the tabernacle of the congregation.", "web": "Moses did as Yahweh commanded him; and the congregation was assembled at the door of the Tent of Meeting.", "bsb": "So Moses did as the LORD had commanded him, and the assembly gathered at the entrance to the Tent of Meeting.", "asv": "And Moses did as Jehovah commanded him; and the congregation was assembled at the door of the tent of meeting.", "ylt": "And Moses doth as Jehovah hath commanded him, and the company is assembled unto the opening of the tent of meeting,", "tyndale": "And Moses dyd as the Lorde commaunded him, and the people gathered them selues togither vnto the doore of the tabernacle of witnesse.", "dra": "And Moses did as the Lord had commanded. And all the multitude being gathered together before the door of the tabernacle:", "bbe": "And Moses did as the Lord said, and all the people came together at the door of the Tent of meeting.", "geneva": "So Moses did as the Lord had commanded him, and the companie was assembled at the doore of the Tabernacle of the Congregation.", "wycliffe": "Moises dide as the Lord comaundide; and whanne al the company was gaderid bifor the yatis of the tabernacle, he seide,", "rotherham": "And Moses did, as Yahweh commanded him,—and the assembly was called together, unto the entrance of the tent of meeting.", "darby": "And Moses did as Jehovah had commanded him; and the assembly was collected at the entrance of the tent of meeting.", "twenty": "", "jps": "And Moses did as HaShem commanded him; and the congregation was assembled at the door of the tent of meeting.", "acv": "And Moses did as Jehovah commanded him, and the congregation was assembled at the door of the tent of meeting.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Moses did as the LORD commanded him; and the assembly was gathered to the door of the tabernacle of the congregation.", "vulgate": "fecit Moses ut Dominus imperarat congregataque omni turba ante fores;", "brenton": "And Moses did as the Lord appointed him, and he assembled the congregation at the door of the tabernacle of witness."}}, {"v": 5, "ref": "8:5", "o": "וַ/יֹּ֥אמֶר מֹשֶׁ֖ה אֶל הָ/עֵדָ֑ה זֶ֣ה הַ/דָּבָ֔ר אֲשֶׁר צִוָּ֥ה יְהוָ֖ה לַ/עֲשֽׂוֹת", "en": {"kjv": "And Moses said unto the congregation, This is the thing which the Lord commanded to be done.", "web": "Moses said to the congregation, “This is the thing which Yahweh has commanded to be done.”", "bsb": "And Moses said to them, “This is what the LORD has commanded to be done.”", "asv": "And Moses said unto the congregation, This is the thing which Jehovah hath commanded to be done.", "ylt": "and Moses saith unto the company, `This is the thing which Jehovah hath commanded to do.'", "tyndale": "And Moses sayde vnto the people: this is the thinge which the Lorde commaunded to do.", "dra": "He said: This is the word that the Lord hath commanded to be done.", "bbe": "And Moses said to the people, This is what the Lord has given orders to be done.", "geneva": "Then Moses said vnto the company, This is the thing which the Lord hath commanded to doe.", "wycliffe": "This is the word which the Lord comaundid to be don.", "rotherham": "Then said Moses unto the assembly,—This is the thing, which Yahweh hath commanded to be done.", "darby": "And Moses said to the assembly, This is the thing which Jehovah has commanded to be done.", "twenty": "", "jps": "And Moses said unto the congregation: 'This is the thing which HaShem hath commanded to be done.'", "acv": "And Moses said to the congregation, This is the thing which Jehovah has commanded to be done.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Moses said to the congregation, This [is] the thing which the LORD commanded to be done.", "vulgate": "ait iste est sermo quem iussit Dominus fieri;", "brenton": "And Moses said to the congregation, This is the thing which the Lord has commanded you to do."}}, {"v": 6, "ref": "8:6", "o": "וַ/יַּקְרֵ֣ב מֹשֶׁ֔ה אֶֽת אַהֲרֹ֖ן וְ/אֶת בָּנָ֑י/ו וַ/יִּרְחַ֥ץ אֹתָ֖/ם בַּ/מָּֽיִם", "en": {"kjv": "And Moses brought Aaron and his sons, and washed them with water.", "web": "Moses brought Aaron and his sons, and washed them with water.", "bsb": "Then Moses presented Aaron and his sons and washed them with water.", "asv": "And Moses brought Aaron and his sons, and washed them with water.", "ylt": "And Moses bringeth near Aaron and his sons, and doth bathe them with water,", "tyndale": "And Moses broughte Aaron and his sonnes, and wasshed them with water,", "dra": "And immediately, he offered Aaron and his sons. And when he had washed them,", "bbe": "Then Moses took Aaron and his sons; and after washing them with water,", "geneva": "And Moses brought Aaron and his sonnes, and washed them with water,", "wycliffe": "And anoon Moises offride Aaron and hise sones; and whanne he hadde waischun hem,", "rotherham": "So Moses brought near Aaron and his sons,—and bathed them with water,", "darby": "And Moses brought Aaron near, and his sons, and bathed them with water.", "twenty": "", "jps": "And Moses brought Aaron and his sons, and washed them with water.", "acv": "And Moses brought Aaron and his sons, and washed them with water.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Moses brought Aaron and his sons, and washed them with water.", "vulgate": "statimque obtulit Aaron et filios eius cumque lavisset eos;", "brenton": "And Moses brought nigh Aaron and his sons, and washed them with water,"}}, {"v": 7, "ref": "8:7", "o": "וַ/יִּתֵּ֨ן עָלָ֜י/ו אֶת הַ/כֻּתֹּ֗נֶת וַ/יַּחְגֹּ֤ר אֹת/וֹ֙ בָּֽ/אַבְנֵ֔ט וַ/יַּלְבֵּ֤שׁ אֹת/וֹ֙ אֶֽת הַ/מְּעִ֔יל וַ/יִּתֵּ֥ן עָלָ֖י/ו אֶת הָ/אֵפֹ֑ד וַ/יַּחְגֹּ֣ר אֹת֗/וֹ בְּ/חֵ֨שֶׁב֙ הָֽ/אֵפֹ֔ד וַ/יֶּאְפֹּ֥ד ל֖/וֹ בּֽ/וֹ", "en": {"kjv": "And he put upon him the coat, and girded him with the girdle, and clothed him with the robe, and put the ephod upon him, and he girded him with the curious girdle of the ephod, and bound it unto him therewith.", "web": "He put the coat on him, tied the sash on him, clothed him with the robe, put the ephod on him, and he tied the skillfully woven band of the ephod on him, and fastened it to him with it.", "bsb": "He put the tunic on Aaron, tied the sash around him, clothed him with the robe, and put the ephod on him. He tied the woven band of the ephod around him and fastened it to him.", "asv": "And he put upon him the coat, and girded him with the girdle, and clothed him with the robe, and put the ephod upon him, and he girded him with the skilfully woven band of the ephod, and bound it unto him therewith.", "ylt": "and doth put on him the coat, and doth gird him with the girdle, and doth clothe him with the upper robe, and doth put on him the ephod, and doth gird him with the girdle of the ephod, and doth bind it to him with it,", "tyndale": "and put apon him the albe and gyrde him with a girdel and put apon him the tunycle and put the Ephod thereon, and gyrded him with the broderd girdel of the Ephod, and bounde it vnto him therewith.", "dra": "He vested the high priest with the strait linen garment, girding him with the girdle, and putting on him the violet tunick: and over it he put the ephod.", "bbe": "He put the coat on him, making it tight with its band, and then the robe, and over it the ephod, with its band of needlework to keep it in place.", "geneva": "And put vpon him the coate, and girded him with a girdle, and clothed him with the robe, and put the Ephod on him, which he girded with the broydred garde of the Ephod, and bounde it vnto him therewith.", "wycliffe": "he clothide the bischop with a lynnun schirte, `and girdide `the bischop with a girdil, and clothide with a coote of iacynt, and `puttide the cloth on the schuldris aboue,", "rotherham": "and put upon him the tunic and girded him with the band, and clothed him with the robe, and put upon him the ephod, and girded him with the curiously-woven band of the ephod, and bound it to him therewith;", "darby": "And he put upon him the vest and girded him with the girdle, and clothed him with the cloak, and put the ephod on him, and he girded him with the girdle of the ephod, and fastened the ephod on him.", "twenty": "", "jps": "And he put upon him the tunic, and girded him with the girdle, and clothed him with the robe, and put the ephod upon him, and he girded him with the skilfully woven band of the ephod, and bound it unto him therewith.", "acv": "And he put upon him the tunic, and girded him with the sash, and clothed him with the robe, and put the ephod upon him, and he girded him with the skillfully woven band of the ephod, and bound it to him therewith.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he put upon him the coat, and girded him with the girdle, and clothed him with the robe, and put the ephod upon him, and he girded him with the curious girdle of the ephod, and bound [it] to him with it.", "vulgate": "vestivit pontificem subucula linea accingens eum balteo et induens tunica hyacinthina et desuper umerale inposuit;", "brenton": "and put on him the coat, and girded him with the girdle, and clothed him with the tunic, and put on him the ephod;"}}, {"v": 8, "ref": "8:8", "o": "וַ/יָּ֥שֶׂם עָלָ֖י/ו אֶת הַ/חֹ֑שֶׁן וַ/יִּתֵּן֙ אֶל הַ/חֹ֔שֶׁן אֶת הָ/אוּרִ֖ים וְ/אֶת הַ/תֻּמִּֽים", "en": {"kjv": "And he put the breastplate upon him: also he put in the breastplate the Urim and the Thummim.", "web": "He placed the breastplate on him; and in the breastplate he put the Urim and the Thummim.", "bsb": "Then he put the breastpiece on him and placed the Urim and Thummim in the breastpiece.", "asv": "And he placed the breastplate upon him: and in the breastplate he put the Urim and the Thummim.", "ylt": "and doth put on him the breastplate, and doth put unto the breastplate the Lights and the Perfections,", "tyndale": "And he put the brestlappe thereon, ad put in the brestlappe lighte ad perfectnesse.", "dra": "And binding it with the girdle, he fitted it to the rational, on which was Doctrine and Truth.", "bbe": "And he put the priest's bag on him, and in the bag he put the Urim and Thummim.", "geneva": "After he put the brest plate thereon, and put in the breast plate the Vrim and the Thummim.", "wycliffe": "which cloth on the schuldris he boond with a girdil, and `dresside to the racional, wherynne doctryn and truthe was.", "rotherham": "and he put upon him the breastpiece,—and placed, in the breastpiece, the Lights and the Perfections;", "darby": "And he put the breastplate on it, and put on the breastplate the Urim and the Thummim;", "twenty": "", "jps": "And he placed the breastplate upon him; and in the breastplate he put the Urim and the Thummim.", "acv": "And he placed the breastplate upon him, and he put the Urim and the Thummim in the breastplate.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he put the breast-plate upon him: also he put in the breast-plate the Urim and the Thummim.", "vulgate": "quod adstringens cingulo aptavit rationali in quo erat doctrina et veritas;", "brenton": "and girded him with a girdle according to the make of the ephod, and clasped him closely with it: and put upon it the oracle, and put upon the oracle the Manifestation and the Truth."}}, {"v": 9, "ref": "8:9", "o": "וַ/יָּ֥שֶׂם אֶת הַ/מִּצְנֶ֖פֶת עַל רֹאשׁ֑/וֹ וַ/יָּ֨שֶׂם עַֽל הַ/מִּצְנֶ֜פֶת אֶל מ֣וּל פָּנָ֗י/ו אֵ֣ת צִ֤יץ הַ/זָּהָב֙ נֵ֣זֶר הַ/קֹּ֔דֶשׁ כַּ/אֲשֶׁ֛ר צִוָּ֥ה יְהוָ֖ה אֶת מֹשֶֽׁה", "en": {"kjv": "And he put the mitre upon his head; also upon the mitre, even upon his forefront, did he put the golden plate, the holy crown; as the Lord commanded Moses.", "web": "He set the turban on his head; and on the turban, in front, he set the golden plate, the holy crown; as Yahweh commanded Moses.", "bsb": "Moses also put the turban on Aaron’s head and set the gold plate, the holy diadem, on the front of the turban, as the LORD had commanded him.", "asv": "And he set the mitre upon his head; and upon the mitre, in front, did he set the golden plate, the holy crown; as Jehovah commanded Moses.", "ylt": "and doth put the mitre on his head, and doth put on the mitre, over-against its front, the golden flower of the holy crown, as Jehovah hath commanded Moses.", "tyndale": "And he put the myter apon his heed ad put apo the myter eue apo the forefrot of it, the golden plate of the holy croune, as the Lorde commaunded Moses.", "dra": "He put also the mitre upon his head: and upon the mitre over the forehead, he put the plate of gold, consecrated with sanctification, as the Lord had commanded him.", "bbe": "And on his head he put the head-dress, and in front of the head-dress the plate of gold, the holy crown, as the Lord gave orders to Moses.", "geneva": "Also he put the miter vpon his head, and put vpon the miter on the fore front the golden plate, and the holy crowne, as the Lord had commanded Moses.", "wycliffe": "And Moises hilide the heed with a mytre, and `settide theronne, ayens the forhed, the goldun plate halewid in halewyng, as the Lord comaundide to hym.", "rotherham": "and he put the turban upon his head,—and put upon the turban, on the forefront thereof the burnished plate of gold—the holy crown, As Yahweh commanded Moses.", "darby": "and he put the turban upon his head; and upon the turban, on the front of it, he put the golden plate, the holy diadem; as Jehovah had commanded Moses.", "twenty": "", "jps": "And he set the mitre upon his head; and upon the mitre, in front, did he set the golden plate, the holy crown; as HaShem commanded Moses.", "acv": "And he set the miter upon his head. And upon the miter, in front, he set the golden plate, the holy crown, as Jehovah commanded Moses.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he put the miter upon his head; also upon the miter, [even] upon his front, did he put the golden plate, the holy crown; as the LORD commanded Moses.", "vulgate": "cidarim quoque texit caput et super eam contra frontem posuit lamminam auream consecratam in sanctificationem sicut praeceperat ei Dominus;", "brenton": "And he put the mitre on his head, and put upon the mitre in front the golden plate, the most holy thing, as the Lord commanded Moses."}}, {"v": 10, "ref": "8:10", "o": "וַ/יִּקַּ֤ח מֹשֶׁה֙ אֶת שֶׁ֣מֶן הַ/מִּשְׁחָ֔ה וַ/יִּמְשַׁ֥ח אֶת הַ/מִּשְׁכָּ֖ן וְ/אֶת כָּל אֲשֶׁר בּ֑/וֹ וַ/יְקַדֵּ֖שׁ אֹתָֽ/ם", "en": {"kjv": "And Moses took the anointing oil, and anointed the tabernacle and all that was therein, and sanctified them.", "web": "Moses took the anointing oil, and anointed the tabernacle and all that was in it, and sanctified them.", "bsb": "Next, Moses took the anointing oil and anointed the tabernacle and everything in it; and so he consecrated them.", "asv": "And Moses took the anointing oil, and anointed the tabernacle and all that was therein, and sanctified them.", "ylt": "And Moses taketh the anointing oil, and anointeth the tabernacle, and all that is in it, and sanctifieth them;", "tyndale": "And Moses toke the anoyntynge oyle and anoynted the habitacion and all that was therein and sanctified them,", "dra": "He took also the oil of unction, with which he anointed the tabernacle, with all the furniture thereof.", "bbe": "And Moses took the holy oil and put it on the House and on all the things in it, to make them holy.", "geneva": "(Nowe Moses had taken the anointing oyle, and anoynted the Tabernacle, and al that was therein, and sanctified them,", "wycliffe": "He took also the oile of anoyntyng, with which he anoyntide the tabernacle with al his purtenaunce;", "rotherham": "And Moses took the anointing oil, and anointed the habitation and all that was therein,—and hallowed them;", "darby": "And Moses took the anointing oil, and anointed the tabernacle and all that was in it, and hallowed them.", "twenty": "", "jps": "And Moses took the anointing oil, and anointed the tabernacle and all that was therein, and sanctified them.", "acv": "And Moses took the anointing oil, and anointed the tabernacle and all that was in it, and sanctified them.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Moses took the anointing oil, and anointed the tabernacle and all that [was] in it, and sanctified them.", "vulgate": "tulit et unctionis oleum quo levit tabernaculum cum omni supellectili sua;", "brenton": "And Moses took of the anointing oil,"}}, {"v": 11, "ref": "8:11", "o": "וַ/יַּ֥ז מִמֶּ֛/נּוּ עַל הַ/מִּזְבֵּ֖חַ שֶׁ֣בַע פְּעָמִ֑ים וַ/יִּמְשַׁ֨ח אֶת הַ/מִּזְבֵּ֜חַ וְ/אֶת כָּל כֵּלָ֗י/ו וְ/אֶת הַ/כִּיֹּ֛ר וְ/אֶת כַּנּ֖/וֹ לְ/קַדְּשָֽׁ/ם", "en": {"kjv": "And he sprinkled thereof upon the altar seven times, and anointed the altar and all his vessels, both the laver and his foot, to sanctify them.", "web": "He sprinkled it on the altar seven times, and anointed the altar and all its vessels, and the basin and its base, to sanctify them.", "bsb": "He sprinkled some of the oil on the altar seven times, anointing the altar and all its utensils, and the basin with its stand, to consecrate them.", "asv": "And he sprinkled thereof upon the altar seven times, and anointed the altar and all its vessels, and the laver and its base, to sanctify them.", "ylt": "and he sprinkleth of it on the altar seven times, and anointeth the altar, and all its vessels, and the laver, and its base, to sanctify them;", "tyndale": "and sprynkled thereof apon the alter .vij. tymes and anoynted the alter and all his vessels, and the lauer with hys fote, to sanctifie them.", "dra": "And when he had sanctified and sprinkled the altar seven times, he anointed it, and all the vessels thereof: and the laver with the foot thereof, he sanctified with the oil.", "bbe": "Seven times he put oil on the altar and on all its vessels, and on the washing-basin and its base, to make them holy.", "geneva": "And sprinkled thereof vpon the altar seuen times, and anointed the altar and all his instruments, and the lauer, and his foote, to sanctifie them)", "wycliffe": "and whanne he hadde halewid and hadde spreynt the auter seuen sithes, he anoyntide it, and halewide with oile alle the vessels therof, and the `greet waischyng vessel with his foundement.", "rotherham": "and he sprinkled thereof upon the altar seven times,—and anointed the altar, and all the utensils thereof and the laver and its stand to hallow them", "darby": "And he sprinkled thereof on the altar seven times, and anointed the altar and all its utensils, and the laver and its stand, to hallow them.", "twenty": "", "jps": "And he sprinkled thereof upon the altar seven times, and anointed the altar and all its vessels, and the laver and its base, to sanctify them.", "acv": "And he sprinkled of it upon the altar seven times, and anointed the altar and all its vessels, and the laver and its base, to sanctify them.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he sprinkled part of it upon the altar seven times, and anointed the altar and all its vessels, both the laver and its foot, to sanctify them.", "vulgate": "cumque sanctificans aspersisset altare septem vicibus unxit illud et omnia vasa eius labrumque cum basi sua sanctificavit oleo;", "brenton": "and sprinkled of it seven times on the altar; and anointed the altar, and hallowed it, and all things on it, and the laver, and its foot, and sanctified them; and anointed the tabernacle and all its furniture, and hallowed it."}}, {"v": 12, "ref": "8:12", "o": "וַ/יִּצֹק֙ מִ/שֶּׁ֣מֶן הַ/מִּשְׁחָ֔ה עַ֖ל רֹ֣אשׁ אַהֲרֹ֑ן וַ/יִּמְשַׁ֥ח אֹת֖/וֹ לְ/קַדְּשֽׁ/וֹ", "en": {"kjv": "And he poured of the anointing oil upon Aaron’s head, and anointed him, to sanctify him.", "web": "He poured some of the anointing oil on Aaron’s head, and anointed him, to sanctify him.", "bsb": "He also poured some of the anointing oil on Aaron’s head and anointed him to consecrate him.", "asv": "And he poured of the anointing oil upon Aaron’s head, and anointed him, to sanctify him.", "ylt": "and he poureth of the anointing oil on the head of Aaron, and anointeth him to sanctify him.", "tyndale": "And he poured of the anoyntynge oyle apon Aarons heed and anoynted him to sanctifie him.", "dra": "And he poured it upon Aaron's head: and he anointed and consecrated him.", "bbe": "And some of the oil he put on Aaron's head, to make him holy.", "geneva": "And he powred of the anointing oyle vpon Aarons head, and anointed him, to sanctifie him.", "wycliffe": "Which oile he schedde on `the heed of Aaron, and anoyntide hym, and halewide.", "rotherham": "and he poured of the anointing oil, upon the head of Aaron,—and anointed him, to hallow him.", "darby": "And he poured of the anointing oil on Aaron's head, and anointed him, to hallow him.", "twenty": "", "jps": "And he poured of the anointing oil upon Aaron's head, and anointed him, to sanctify him.", "acv": "And he poured of the anointing oil upon Aaron's head, and anointed him, to sanctify him.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he poured of the anointing oil upon Aaron's head, and anointed him, to sanctify him.", "vulgate": "quod fundens super caput Aaron unxit eum et consecravit;", "brenton": "And Moses poured of the anointing oil on the head of Aaron; and he anointed him and sanctified him."}}, {"v": 13, "ref": "8:13", "o": "וַ/יַּקְרֵ֨ב מֹשֶׁ֜ה אֶת בְּנֵ֣י אַהֲרֹ֗ן וַ/יַּלְבִּשֵׁ֤/ם כֻּתֳּנֹת֙ וַ/יַּחְגֹּ֤ר אֹתָ/ם֙ אַבְנֵ֔ט וַ/יַּחֲבֹ֥שׁ לָ/הֶ֖ם מִגְבָּע֑וֹת כַּ/אֲשֶׁ֛ר צִוָּ֥ה יְהוָ֖ה אֶת מֹשֶֽׁה", "en": {"kjv": "And Moses brought Aaron’s sons, and put coats upon them, and girded them with girdles, and put bonnets upon them; as the Lord commanded Moses.", "web": "Moses brought Aaron’s sons, and clothed them with coats, and tied sashes on them, and put headbands on them; as Yahweh commanded Moses.", "bsb": "Then Moses presented Aaron’s sons, put tunics on them, wrapped sashes around them, and tied headbands on them, just as the LORD had commanded him.", "asv": "And Moses brought Aaron’s sons, and clothed them with coats, and girded them with girdles, and bound head-tires upon them; as Jehovah commanded Moses.", "ylt": "And Moses bringeth near the sons of Aaron, and doth clothe them with coats, and girdeth them with girdles, and bindeth for them turbans, as Jehovah hath commanded Moses.", "tyndale": "And he broughte Aarons sonnes and put albes apon them, and gyrde them with gyrdels, ad put bonettes apo their heedes: as the Lorde comaunded Moses", "dra": "And after he had offered his sons, he vested them with linen tunicks, and girded them with girdles: and put mitres on them as the Lord had commanded.", "bbe": "Then he took Aaron's sons, clothing them with the coats, and putting the bands round them, and the head-dresses on their heads, as the Lord had given him orders.", "geneva": "After, Moses brought Aarons sonnes, and put coates vpon them, and girded them with girdles, and put bonets vpon their heades, as the Lord had commanded Moses.", "wycliffe": "And he clothide with lynnun cootis, and girdide with girdils `his sones offrid, and settide on mytris, as the Lord comaundide.", "rotherham": "And Moses brought near the sons of Aaron and clothed them with tunics and girded them with bands, and wrapped round for them turbans,—As Yahweh commanded Moses.", "darby": "And Moses brought Aaron's sons near and clothed them with the vests, and girded them with the girdles, and bound the high caps on them, as Jehovah had commanded Moses.", "twenty": "", "jps": "And Moses brought Aaron's sons, and clothed them with tunics, and girded them with girdles, and bound head-tires upon them; as HaShem commanded Moses.", "acv": "And Moses brought Aaron's sons, and clothed them with tunics, and girded them with sashes, and bound head-coverings upon them, as Jehovah commanded Moses.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Moses brought Aaron's sons, and put coats upon them, and girded them with girdles, and put bonnets upon them; as the LORD commanded Moses.", "vulgate": "filios quoque eius oblatos vestivit tunicis lineis et cinxit balteo inposuitque mitras ut iusserat Dominus;", "brenton": "And Moses brought the sons of Aaron near, and put on them coast and girded them with girdles, and put on them bonnets, as the Lord commanded Moses."}}, {"v": 14, "ref": "8:14", "o": "וַ/יַּגֵּ֕שׁ אֵ֖ת פַּ֣ר הַֽ/חַטָּ֑את וַ/יִּסְמֹ֨ךְ אַהֲרֹ֤ן וּ/בָנָי/ו֙ אֶת יְדֵי/הֶ֔ם עַל רֹ֖אשׁ פַּ֥ר הַֽ/חַטָּֽאת", "en": {"kjv": "And he brought the bullock for the sin offering: and Aaron and his sons laid their hands upon the head of the bullock for the sin offering.", "web": "He brought the bull of the sin offering, and Aaron and his sons laid their hands on the head of the bull of the sin offering.", "bsb": "Moses then brought the bull near for the sin offering, and Aaron and his sons laid their hands on its head.", "asv": "And he brought the bullock of the sin-offering: and Aaron and his sons laid their hands upon the head of the bullock of the sin-offering.", "ylt": "And he bringeth nigh the bullock of the sin-offering, and Aaron layeth--his sons also--their hands on the head of the bullock of the sin-offering,", "tyndale": "And the synneoffrynge was brought. And Aaron and his sonnes put their handes apon the heed of the oxe of the synneoffryng.", "dra": "He offered also the calf for sin: and when Aaron and his sons had put their hands upon the head thereof,", "bbe": "And he took the ox of the sin-offering: and Aaron and his sons put their hands on the head of the ox,", "geneva": "Then he brought the bullocke for the sinne offring, and Aaron and his sonnes put their handes vpon the head of the bullocke for the sinne offring.", "wycliffe": "He offeride also a calf for synne; and whanne Aaron and hise sones hadden put her hondis on `that calf,", "rotherham": "Then was led near the sin-bearing bullock,—and Aaron and his sons leaned their hands upon the head of the sin-bearing bullock,", "darby": "And he brought near the bullock for the sin-offering; and Aaron and his sons laid their hands on the head of the bullock for the sin-offering;", "twenty": "", "jps": "And the bullock of the sin-offering was brought; and Aaron and his sons laid their hands upon the head of the bullock of the sin-offering.", "acv": "And he brought the bullock of the sin offering. And Aaron and his sons laid their hands upon the head of the bullock of the sin offering,", "anderson": "", "haweis": "", "noyes": "", "webster": "And he brought the bullock for the sin-offering: and Aaron and his sons laid their hands upon the head of the bullock for the sin-offering.", "vulgate": "obtulit et vitulum pro peccato cumque super caput eius posuissent Aaron et filii eius manus suas;", "brenton": "And Moses brought near the calf for the sin-offering, and Aaron and his sons laid their hands on the head of the calf of the sin-offering."}}, {"v": 15, "ref": "8:15", "o": "וַ/יִּשְׁחָ֗ט וַ/יִּקַּ֨ח מֹשֶׁ֤ה אֶת הַ/דָּם֙ וַ֠/יִּתֵּן עַל קַרְנ֨וֹת הַ/מִּזְבֵּ֤חַ סָבִיב֙ בְּ/אֶצְבָּע֔/וֹ וַ/יְחַטֵּ֖א אֶת הַ/מִּזְבֵּ֑חַ וְ/אֶת הַ/דָּ֗ם יָצַק֙ אֶל יְס֣וֹד הַ/מִּזְבֵּ֔חַ וַֽ/יְקַדְּשֵׁ֖/הוּ לְ/כַפֵּ֥ר עָלָֽי/ו", "en": {"kjv": "And he slew it; and Moses took the blood, and put it upon the horns of the altar round about with his finger, and purified the altar, and poured the blood at the bottom of the altar, and sanctified it, to make reconciliation upon it.", "web": "He killed it; and Moses took the blood, and put it around on the horns of the altar with his finger, and purified the altar, and poured out the blood at the base of the altar, and sanctified it, to make atonement for it.", "bsb": "Moses slaughtered the bull, took some of the blood, and applied it with his finger to all four horns of the altar, purifying the altar. He poured out the rest of the blood at the base of the altar and consecrated it so that atonement could be made on it.", "asv": "And he slew it; and Moses took the blood, and put it upon the horns of the altar round about with his finger, and purified the altar, and poured out the blood at the base of the altar, and sanctified it, to make atonement for it.", "ylt": "and one slaughtereth, and Moses taketh the blood, and putteth on the horns of the altar round about with his finger, and cleanseth the altar, and the blood he hath poured out at the foundation of the altar, and sanctifieth it, to make atonement upon it.", "tyndale": "And when it was slayne, Moses toke of the bloude, and put it apon the hornes of the alter rounde aboute with his finger and purified it, ad poured the bloud vnto the botome of the alter ad sanctified it ad reconcyled it.", "dra": "He immolated it: and took the blood, and dipping his finger in it, he touched the horns of the altar round about. Which being expiated, and sanctified, he poured the rest of the blood at the bottom thereof.", "bbe": "And he put it to death; and Moses took the blood and put it on the horns of the altar and round it with his finger, and made the altar clean, draining out the blood at the base of the altar; so he made it holy, taking away what was unclean.", "geneva": "And Moses slew him, and tooke the blood, which he put vpon the hornes of the Altar roud about with his finger, and purified the altar, and powred the rest of the blood at the foote of ye altar: so he sanctified it, to make reconciliation vpon it.", "wycliffe": "he offride it, and drow up blood; and whanne the fyngur was dippid, he touchide the corneris of the auter bi cumpas; whanne the auter was clensid and halewid, he schedde the `residue blood at the `foundement therof.", "rotherham": "Then was it slain, and Moses took the blood and put [thereof] upon the horns of the altar round about, with his finger, and cleansed the altar from sin,—and the [remainder of the] blood, poured he forth at the base of the altar, and hallowed it putting a propitiatory-covering thereupon.", "darby": "and he slaughtered [it], and Moses took the blood, and put [it] on the horns of the altar round about with his finger, and cleansed the altar from sin, and the blood he poured at the bottom of the altar, and hallowed it, making atonement for it.", "twenty": "", "jps": "And when it was slain, Moses took the blood, and put it upon the horns of the altar round about with his finger, and purified the altar, and poured out the remaining blood at the base of the altar, and sanctified it, to make atonement for it.", "acv": "and he killed it. And Moses took the blood, and put it upon the horns of the altar round about with his finger, and purified the altar, and poured out the blood at the base of the altar, and sanctified it, to make atonement for it.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he slew [it]; and Moses took the blood, and put [it] upon the horns of the altar round about with his finger, and purified the altar, and poured the blood at the bottom of the altar, and sanctified it, to make reconciliation upon it.", "vulgate": "immolavit eum hauriens sanguinem et tincto digito tetigit cornua altaris per gyrum quo expiato et sanctificato fudit reliquum sanguinem ad fundamenta eius;", "brenton": "And he slew it; and Moses took of the blood, and put it on the horns of the altar round about with his finger; and he purified the altar, and poured out the blood at the bottom of the altar, and sanctified it, to make atonement upon it."}}, {"v": 16, "ref": "8:16", "o": "וַ/יִּקַּ֗ח אֶֽת כָּל הַ/חֵלֶב֮ אֲשֶׁ֣ר עַל הַ/קֶּרֶב֒ וְ/אֵת֙ יֹתֶ֣רֶת הַ/כָּבֵ֔ד וְ/אֶת שְׁתֵּ֥י הַ/כְּלָיֹ֖ת וְ/אֶֽת חֶלְבְּ/הֶ֑ן וַ/יַּקְטֵ֥ר מֹשֶׁ֖ה הַ/מִּזְבֵּֽחָ/ה", "en": {"kjv": "And he took all the fat that was upon the inwards, and the caul above the liver, and the two kidneys, and their fat, and Moses burned it upon the altar.", "web": "He took all the fat that was on the innards, and the cover of the liver, and the two kidneys, and their fat; and Moses burned it on the altar.", "bsb": "Moses also took all the fat that was on the entrails, the lobe of the liver, and both kidneys and their fat, and burned it all on the altar.", "asv": "And he took all the fat that was upon the inwards, and the caul of the liver, and the two kidneys, and their fat; and Moses burned it upon the altar.", "ylt": "And he taketh all the fat that is on the inwards, and the redundance above the liver, and the two kidneys, and their fat, and Moses maketh Perfume on the altar,", "tyndale": "And he toke all the fatt that was apon the inwardes ad the kal that was on the lyuer ad the two kydneyes with their fatt ad burned it apo the alter.", "dra": "But the fat that was upon the entrails, and the caul of the liver, and the two little kidneys, with their fat, he burnt upon the altar.", "bbe": "And he took all the fat on the inside parts, and the fat on the liver, and the two kidneys with their fat, to be burned on the altar;", "geneva": "Then he tooke all the fatte that was vpon the inwardes, and the kall of the liuer and the two kidneis, with their fat, which Moses burned vpon the Altar.", "wycliffe": "Sotheli he brent on the auter the ynnere fatnesse that was on the entrails, and the calle of the mawe, and the twei litle reynes with her litle fatnessis;", "rotherham": "And he took all the fat that was on the inwards, and the caul of the liver, and the two kidneys and their fat,—and Moses made a perfume at the altar.", "darby": "And he took all the fat that was on the inwards, and the net of the liver, and the two kidneys, and their fat, and Moses burned [them] on the altar.", "twenty": "", "jps": "And he took all the fat that was upon the inwards, and the lobe of the liver, and the two kidneys, and their fat, and Moses made it smoke upon the altar.", "acv": "And he took all the fat that was upon the innards, and the caul of the liver, and the two kidneys, and their fat, and Moses burned it upon the altar.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he took all the fat that [was] upon the inwards, and the caul [above] the liver, and the two kidneys, and their fat, and Moses burned [it] upon the altar.", "vulgate": "adipem autem qui erat super vitalia et reticulum iecoris duosque renunculos cum arvinulis suis adolevit super altare;", "brenton": "And Moses took all the fat that was upon the inwards, and the lobe on the liver, and both the kidneys, and the fat that was upon them, and Moses offered them on the altar."}}, {"v": 17, "ref": "8:17", "o": "וְ/אֶת הַ/פָּ֤ר וְ/אֶת עֹר/וֹ֙ וְ/אֶת בְּשָׂר֣/וֹ וְ/אֶת פִּרְשׁ֔/וֹ שָׂרַ֣ף בָּ/אֵ֔שׁ מִ/ח֖וּץ לַֽ/מַּחֲנֶ֑ה כַּ/אֲשֶׁ֛ר צִוָּ֥ה יְהוָ֖ה אֶת מֹשֶֽׁה", "en": {"kjv": "But the bullock, and his hide, his flesh, and his dung, he burnt with fire without the camp; as the Lord commanded Moses.", "web": "But the bull, and its skin, and its flesh, and its dung, he burned with fire outside the camp; as Yahweh commanded Moses.", "bsb": "But the bull with its hide, flesh, and dung he burned outside the camp, as the LORD had commanded him.", "asv": "But the bullock, and its skin, and its flesh, and its dung, he burnt with fire without the camp; as Jehovah commanded Moses.", "ylt": "and the bullock, and its skin, and its flesh, and its dung, he hath burnt with fire, at the outside of the camp, as Jehovah hath commanded Moses.", "tyndale": "But the oxe, the hide, his flesh ad his donge, he burnt with fire without the hoste, as the Lorde commaunded Moses.", "dra": "And the calf with the skin, and the flesh and the dung, he burnt without the camp, as the Lord had commanded.", "bbe": "But the ox, with its skin and its flesh and its waste, was burned with fire outside the tent-circle, as the Lord gave orders to Moses.", "geneva": "But the bullocke and his hide, and his flesh, and his doung, hee burnt with fire without the host as the Lord had commanded Moses.", "wycliffe": "and he brente without the castels the calf, with the skyn, fleischis, and dung, as the Lord comaundide.", "rotherham": "But the bullock itself, and its skin and its flesh and its dung, consumed he with fire, outside the camp,—As Yahweh commanded Moses,", "darby": "And the bullock, and its skin, and its flesh, and its dung he burned with fire outside the camp, as Jehovah had commanded Moses.", "twenty": "", "jps": "But the bullock, and its skin, and its flesh, and its dung, were burnt with fire without the camp; as HaShem commanded Moses.", "acv": "But the bullock, and its skin, and its flesh, and its dung, he burnt with fire outside the camp, as Jehovah commanded Moses.", "anderson": "", "haweis": "", "noyes": "", "webster": "But the bullock, and his hide, his flesh, and his dung, he burnt with fire without the camp; as the LORD commanded Moses.", "vulgate": "vitulum cum pelle carnibus et fimo cremans extra castra sicut praeceperat Dominus;", "brenton": "But the calf, and his hide, and his flesh, and his dung, he burnt with fire without the camp, as the Lord commanded Moses."}}, {"v": 18, "ref": "8:18", "o": "וַ/יַּקְרֵ֕ב אֵ֖ת אֵ֣יל הָ/עֹלָ֑ה וַֽ/יִּסְמְכ֞וּ אַהֲרֹ֧ן וּ/בָנָ֛י/ו אֶת יְדֵי/הֶ֖ם עַל רֹ֥אשׁ הָ/אָֽיִל", "en": {"kjv": "And he brought the ram for the burnt offering: and Aaron and his sons laid their hands upon the head of the ram.", "web": "He presented the ram of the burnt offering: and Aaron and his sons laid their hands on the head of the ram.", "bsb": "Then Moses presented the ram for the burnt offering, and Aaron and his sons laid their hands on its head.", "asv": "And he presented the ram of the burnt-offering: and Aaron and his sons laid their hands upon the head of the ram.", "ylt": "And he bringeth near the ram of the burnt-offering, and Aaron and his sons lay their hands on the head of the ram,", "tyndale": "And he broughte the ram of the burntofferynge, and Aaron ad his sonnes put their handes apon the heed of the ram,", "dra": "He offered also a ram for holocaust. And when Aaron and his sons had put their hands upon its head:", "bbe": "And he put the male sheep of the burned offering before the Lord, and Aaron and his sons put their hands on its head,", "geneva": "Also hee brought the ram for the burnt offring, and Aaron and his sonnes put their hands vpon the head of the ramme.", "wycliffe": "He offride also a ram in to brent sacrifice; and whanne Aaron and hise sones hadden set her hondis on the heed therof,", "rotherham": "Then was brought near the ram for the ascending-sacrifice,—and Aaron and his sons leaned their hands upon the head of the ram;", "darby": "And he presented the ram of the burnt-offering; and Aaron and his sons laid their hands on the head of the ram;", "twenty": "", "jps": "And the ram of the burnt-offering was presented; and Aaron and his sons laid their hands upon the head of the ram.", "acv": "And he presented the ram of the burnt offering. And Aaron and his sons laid their hands upon the head of the ram,", "anderson": "", "haweis": "", "noyes": "", "webster": "And he brought the ram for the burnt-offering: and Aaron and his sons laid their hands upon the head of the ram.", "vulgate": "obtulit et arietem in holocaustum super cuius caput cum inposuissent Aaron et filii eius manus suas;", "brenton": "And Moses brought near the ram for a whole-burnt-offering, and Aaron and his sons laid their hands on the head of the ram. And Moses slew the ram: and Moses poured the blood on the altar round about."}}, {"v": 19, "ref": "8:19", "o": "וַ/יִּשְׁחָ֑ט וַ/יִּזְרֹ֨ק מֹשֶׁ֧ה אֶת הַ/דָּ֛ם עַל הַ/מִּזְבֵּ֖חַ סָבִֽיב", "en": {"kjv": "And he killed it; and Moses sprinkled the blood upon the altar round about.", "web": "He killed it; and Moses sprinkled the blood around on the altar.", "bsb": "Moses slaughtered the ram and sprinkled the blood on all sides of the altar.", "asv": "And he killed it; and Moses sprinkled the blood upon the altar round about.", "ylt": "and one slaughtereth, and Moses sprinkleth the blood on the altar round about;", "tyndale": "and it was kylled. And Moses sprinkled the bloud apo the alter roude aboute,", "dra": "He immolated it, and poured the blood thereof round about the altar.", "bbe": "And he put it to death; and Moses put some of the blood on and round the altar.", "geneva": "So Moses killed it, and sprinkled the blood vpon the Altar round about,", "wycliffe": "he offride it, and schedde the blood therof bi the cumpas of the auter.", "rotherham": "and it was slain,—and Moses dashed the blood against the altar round about;", "darby": "and he slaughtered [it]; and Moses sprinkled the blood on the altar round about.", "twenty": "", "jps": "And when it was killed, Moses dashed the blood against the altar round about.", "acv": "and he killed it. And Moses sprinkled the blood upon the altar round about.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he killed [it]; and Moses sprinkled the blood upon the altar round about.", "vulgate": "immolavit eum et fudit sanguinem eius per altaris circuitum;", "brenton": "And he divided the ram by its limbs, and Moses offered the head, and the limbs, and the fat; and he washed the belly and the feet with water."}}, {"v": 20, "ref": "8:20", "o": "וְ/אֶת הָ/אַ֔יִל נִתַּ֖ח לִ/נְתָחָ֑י/ו וַ/יַּקְטֵ֤ר מֹשֶׁה֙ אֶת הָ/רֹ֔אשׁ וְ/אֶת הַ/נְּתָחִ֖ים וְ/אֶת הַ/פָּֽדֶר", "en": {"kjv": "And he cut the ram into pieces; and Moses burnt the head, and the pieces, and the fat.", "web": "He cut the ram into its pieces; and Moses burned the head, and the pieces, and the fat.", "bsb": "He cut the ram into pieces and burned the head, the pieces, and the fat.", "asv": "And he cut the ram into its pieces; and Moses burnt the head, and the pieces, and the fat.", "ylt": "and the ram he hath cut into its pieces, and Moses maketh perfume with the head, and the pieces, and the fat,", "tyndale": "ad cutt the ram in peces ad burnt the heed, the peces ad the fatte,", "dra": "And cutting the ram into pieces, the head thereof, and the joints, and the fat he burnt in the fire.", "bbe": "And when the sheep had been cut into parts, the head and the parts and the fat were burned by Moses.", "geneva": "And Moses cut the ram in pieces, and burnt the head with the pieces, and the fat,", "wycliffe": "And he kittide thilke ram in to gobetis, and brente with fier the heed therof, and membris,", "rotherham": "and the ram itself, was cut up into its pieces,—and Moses made a perfume with the head and with the pieces and with the fat;", "darby": "And the ram he cut up into its pieces; and Moses burned the head, and the pieces, and the fat;", "twenty": "", "jps": "And when the ram was cut into its pieces, Moses made the head, and the pieces, and the suet smoke.", "acv": "And he cut the ram into its pieces, and Moses burnt the head, and the pieces, and the fat.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he cut the ram into pieces; and Moses burnt the head, and the pieces, and the fat.", "vulgate": "ipsumque arietem in frusta concidens caput eius et artus et adipem adolevit igni;", "brenton": "And Moses offered up the whole ram on the altar: it is a whole-burnt-offering for a sweet-smelling savour; it is a burnt-offering to the Lord, as the Lord commanded Moses."}}, {"v": 21, "ref": "8:21", "o": "וְ/אֶת הַ/קֶּ֥רֶב וְ/אֶת הַ/כְּרָעַ֖יִם רָחַ֣ץ בַּ/מָּ֑יִם וַ/יַּקְטֵר֩ מֹשֶׁ֨ה אֶת כָּל הָ/אַ֜יִל הַ/מִּזְבֵּ֗חָ/ה עֹלָ֨ה ה֤וּא לְ/רֵֽיחַ נִיחֹ֨חַ֙ אִשֶּׁ֥ה הוּא֙ לַ/יהוָ֔ה כַּ/אֲשֶׁ֛ר צִוָּ֥ה יְהוָ֖ה אֶת מֹשֶֽׁה", "en": {"kjv": "And he washed the inwards and the legs in water; and Moses burnt the whole ram upon the altar: it was a burnt sacrifice for a sweet savour, and an offering made by fire unto the Lord; as the Lord commanded Moses.", "web": "He washed the innards and the legs with water; and Moses burned the whole ram on the altar. It was a burnt offering for a pleasant aroma. It was an offering made by fire to Yahweh; as Yahweh commanded Moses.", "bsb": "He washed the entrails and legs with water and burned the entire ram on the altar as a burnt offering, a pleasing aroma, an offering made by fire to the LORD, just as the LORD had commanded Moses.", "asv": "And he washed the inwards and the legs with water; and Moses burnt the whole ram upon the altar: it was a burnt-offering for a sweet savor: it was an offering made by fire unto Jehovah; as Jehovah commanded Moses.", "ylt": "and the inwards and the legs he hath washed with water, and Moses maketh perfume with the whole ram on the altar; it is a burnt-offering, for sweet fragrance; it is a fire-offering to Jehovah, as Jehovah hath commanded Moses.", "tyndale": "ad wasshed the inwardes ad the legges in water, and burnt the ram euery whitt apo the alter. That was a burntsacrifice of a swete sauoure ad an offrynge vnto the Lorde, as the Lorde comaunded Moses.", "dra": "Having first washed the entrails, and the feet, and the whole ram together he burnt upon the altar: because it was a holocaust of most sweet odour to the Lord, as he had commanded him.", "bbe": "And the inside parts and the legs were washed with water and all the sheep was burned by Moses on the altar; it was a burned offering for a sweet smell: it was an offering made by fire to the Lord, as the Lord gave orders to Moses.", "geneva": "And washed the inwardes and the legges in water: so Moses burnt the ram euery whit vpon ye Altar: for it was a burnt offring for a sweete sauour, which was made by fire vnto the Lord, as the Lord had commanded Moses.", "wycliffe": "and ynnere fatnesse, whanne the entrails and feet weren waischun bifore; and he brente al the ram togidere on the auter, for it was the brent sacrifice of swettiste odour to the Lord, as the Lord comaundide to hym.", "rotherham": "but the inwards and the legs, were bathed in water,—and Moses made a perfume with the whole ram at the altar, an ascending-sacrifice, it was—for a satisfying odour an altar-flame, it was unto Yahweh, As Yahweh commanded Moses.", "darby": "and the inwards and the legs he washed in water; and Moses burned the whole ram on the altar: it was a burnt-offering for a sweet odour, it was an offering by fire to Jehovah; as Jehovah had commanded Moses.", "twenty": "", "jps": "And when the inwards and the legs were washed with water, Moses made the whole ram smoke upon the altar; it was a burnt-offering for a sweet savour; it was an offering made by fire unto HaShem; as HaShem commanded Moses.", "acv": "And he washed the innards and the legs with water. And Moses burnt the whole ram upon the altar. It was a burnt offering for a sweet savor. It was an offering made by fire to Jehovah, as Jehovah commanded Moses.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he washed the inwards and the legs in water; and Moses burnt the whole ram upon the altar: it [was] a burnt-sacrifice for a sweet savor, [and] an offering made by fire to the LORD; as the LORD commanded Moses.", "vulgate": "lotis prius intestinis et pedibus totumque simul arietem incendit super altare eo quod esset holocaustum suavissimi odoris Domino sicut praeceperat ei;", "brenton": "And Moses brought the second ram, the ram of consecration, and Aaron and his sons laid their hands on the head of the ram, and he slew him;"}}, {"v": 22, "ref": "8:22", "o": "וַ/יַּקְרֵב֙ אֶת הָ/אַ֣יִל הַ/שֵּׁנִ֔י אֵ֖יל הַ/מִּלֻּאִ֑ים וַֽ/יִּסְמְכ֞וּ אַהֲרֹ֧ן וּ/בָנָ֛י/ו אֶת יְדֵי/הֶ֖ם עַל רֹ֥אשׁ הָ/אָֽיִל", "en": {"kjv": "And he brought the other ram, the ram of consecration: and Aaron and his sons laid their hands upon the head of the ram.", "web": "He presented the other ram, the ram of consecration: and Aaron and his sons laid their hands on the head of the ram.", "bsb": "After that, Moses presented the other ram, the ram of ordination, and Aaron and his sons laid their hands on its head.", "asv": "And he presented the other ram, the ram of consecration: and Aaron and his sons laid their hands upon the head of the ram.", "ylt": "And he bringeth near the second ram, a ram of the consecrations, and Aaron and his sons lay their hands on the head of the ram,", "tyndale": "And he broughte the other ram that was the fullofferynge, and Aaron and his sonnes put their hades apo the heed of the ram:", "dra": "He offered also the second ram, in the consecration of priests: and Aaron, and his sons put their hands upon the head thereof.", "bbe": "And he put the other sheep before the Lord, the sheep with which they were made priests; and Aaron and his sons put their hands on the head of the sheep,", "geneva": "After, he brought the other ram, the ram of consecrations, and Aaron and his sonnes layed their handes vpon the head of the ram,", "wycliffe": "He offride also the secounde ram, in to the halewyng of preestis; and Aaron and hise sones puttiden her hondis on the heed therof.", "rotherham": "Then was brought near the second ram, the ram of installation, and Aaron and his sons leaned their hands upon the head of the ram;", "darby": "And he presented the second ram, the ram of consecration; and Aaron and his sons laid their hands on the head of the ram;", "twenty": "", "jps": "And the other ram was presented, the ram of consecration, and Aaron and his sons laid their hands upon the head of the ram.", "acv": "And he presented the other ram, the ram of consecration. And Aaron and his sons laid their hands upon the head of the ram,", "anderson": "", "haweis": "", "noyes": "", "webster": "And he brought the other ram, the ram of consecration: and Aaron and his sons laid their hands upon the head of the ram.", "vulgate": "obtulit et arietem secundum in consecrationem sacerdotum posueruntque super caput illius Aaron et filii eius manus suas;", "brenton": "and Moses took of his blood, and put it upon the tip of Aaron's right ear, and on the thumb of his right hand, and on the great toe of his right foot."}}, {"v": 23, "ref": "8:23", "o": "וַ/יִּשְׁחָ֓ט וַ/יִּקַּ֤ח מֹשֶׁה֙ מִ/דָּמ֔/וֹ וַ/יִּתֵּ֛ן עַל תְּנ֥וּךְ אֹֽזֶן אַהֲרֹ֖ן הַ/יְמָנִ֑ית וְ/עַל בֹּ֤הֶן יָד/וֹ֙ הַ/יְמָנִ֔ית וְ/עַל בֹּ֥הֶן רַגְל֖/וֹ הַ/יְמָנִֽית", "en": {"kjv": "And he slew it; and Moses took of the blood of it, and put it upon the tip of Aaron’s right ear, and upon the thumb of his right hand, and upon the great toe of his right foot.", "web": "He killed it; and Moses took some of its blood, and put it on the tip of Aaron’s right ear, and on the thumb of his right hand, and on the great toe of his right foot.", "bsb": "Moses slaughtered the ram and took some of its blood and put it on Aaron’s right earlobe, on the thumb of his right hand, and on the big toe of his right foot.", "asv": "And he slew it; and Moses took of the blood thereof, and put it upon the tip of Aaron’s right ear, and upon the thumb of his right hand, and upon the great toe of his right foot.", "ylt": "and one slaughtereth, and Moses taketh of its blood, and putteth on the tip of the right ear of Aaron, and on the thumb of his right hand, and on the great toe of his right foot;", "tyndale": "And when it was slayne, Moses toke of the bloude of it, and put it apon the typpe of Aarons ryght eare and apon the thombe of his right hande and apon the great too of his righte fote.", "dra": "And when Moses had immolated it, he took of the blood thereof, and touched the tip of Aaron's right ear, and the thumb of his right hand, and in like manner also the great toe of his right foot.", "bbe": "And he put it to death; and Moses took some of the blood and put it on the point of Aaron's right ear and on the thumb of his right hand and on the great toe of his right foot.", "geneva": "Which Moses slewe, and tooke of the blood of it, and put it vpon the lappe of Aarons right eare, and vpon the thumbe of his right hand, and vpon the great toe of his right foote.", "wycliffe": "And whanne Moises hadde offrid the ram, he took of the blood, and touchide the laste part of the riyt eere of Aaron, and the thombe of his riyt hond, in lijk maner and of the foot.", "rotherham": "and it was slain, and Moses took of the blood thereof, and put upon the tip of Aaron’s right ear,—and upon the thumb of his right hand, and upon the great toe of his right foot.", "darby": "and one slaughtered [it]; and Moses took of its blood, and put [it] on the tip of Aaron's right ear, and on the thumb of his right hand, and on the great toe of his right foot;", "twenty": "", "jps": "And when it was slain, Moses took of the blood thereof, and put it upon the tip of Aaron's right ear, and upon the thumb of his right hand, and upon the great toe of his right foot.", "acv": "and he killed it. And Moses took of the blood of it, and put it upon the tip of Aaron's right ear, and upon the thumb of his right hand, and upon the great toe of his right foot.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he slew [it]; and Moses took of its blood, and put [it] upon the tip of Aaron's right ear, and upon the thumb of his right hand, and upon the great toe of his right foot.", "vulgate": "quem cum immolasset Moses sumens de sanguine tetigit extremum auriculae dextrae Aaron et pollicem manus eius dextrae similiter et pedis;", "brenton": "And Moses brought near the sons of Aaron; and Moses put of the blood on the tips of their right ears, and on the thumbs of their right hands, and on the great toes of their right feet, and Moses poured out the blood on the altar round about."}}, {"v": 24, "ref": "8:24", "o": "וַ/יַּקְרֵ֞ב אֶת בְּנֵ֣י אַהֲרֹ֗ן וַ/יִּתֵּ֨ן מֹשֶׁ֤ה מִן הַ/דָּם֙ עַל תְּנ֤וּךְ אָזְנָ/ם֙ הַ/יְמָנִ֔ית וְ/עַל בֹּ֤הֶן יָדָ/ם֙ הַ/יְמָנִ֔ית וְ/עַל בֹּ֥הֶן רַגְלָ֖/ם הַ/יְמָנִ֑ית וַ/יִּזְרֹ֨ק מֹשֶׁ֧ה אֶת הַ/דָּ֛ם עַל הַֽ/מִּזְבֵּ֖חַ סָבִֽיב", "en": {"kjv": "And he brought Aaron’s sons, and Moses put of the blood upon the tip of their right ear, and upon the thumbs of their right hands, and upon the great toes of their right feet: and Moses sprinkled the blood upon the altar round about.", "web": "He brought Aaron’s sons; and Moses put some of the blood on the tip of their right ear, and on the thumb of their right hand, and on the great toe of their right foot; and Moses sprinkled the blood around on the altar.", "bsb": "Moses also presented Aaron’s sons and put some of the blood on their right earlobes, on the thumbs of their right hands, and on the big toes of their right feet. Then he sprinkled the blood on all sides of the altar.", "asv": "And he brought Aaron’s sons; and Moses put of the blood upon the tip of their right ear, and upon the thumb of their right hand, and upon the great toe of their right foot: and Moses sprinkled the blood upon the altar round about.", "ylt": "and he bringeth near the sons of Aaron, and Moses putteth of the blood on the tip of their right ear, and on the thumb of their right hand, and on the great toe of their right foot. And Moses sprinkleth the blood on the altar round about,", "tyndale": "Then were Aarons sonnes broughte, ad Moses put of the bloude on the typpe of the right eare of them, and apon the thombes of theire righte handes, and apon the great tooes of their righte fete, and sprinkled the bloud apo the alter rounde aboute.", "dra": "He offered also the sons of Aaron: and when with the blood of the ram that was immolated, he had touched the tip of the right ear of every one of them, and the thumbs of their right hands, and the great toes of their right feet, the rest he poured on the altar round about.", "bbe": "Then he took Aaron's sons, and Moses put some of the blood on the point of their right ears and on the thumbs of their right hands and on the great toes of their right feet: and Moses put the blood on and round the altar.", "geneva": "Then Moses brought Aarons sonnes, and put of the blood on the lap of their right eares, and vpon the thumbes of their right handes, and vpon the great toes of their right feete, and Moses sprinckled the rest of the blood vpon the Altar round about.", "wycliffe": "He offride also `the sones of Aaron. And whanne he hadde touchid of the blood of the ram offrid the laste part of `the riyt eeris of alle, and `the thombis of the riyt hond and foot, he schedde the `tothir blood on the auter bi cumpas.", "rotherham": "Then were brought near the sons of Aaron, and Moses put of the blood upon the tip of their right ear, and upon the thumb of their right hand, and upon the great toe of their right foot,—and Moses dashed the blood against the altar round about.", "darby": "and he brought Aaron's sons near, and Moses put of the blood on the tip of their right ear, and on the thumb of their right hand, and on the great toe of their right foot; and Moses sprinkled the blood upon the altar round about.", "twenty": "", "jps": "And Aaron's sons were brought, and Moses put of the blood upon the tip of their right ear, and upon the thumb of their right hand, and upon the great toe of their right foot; and Moses dashed the blood against the altar round about.", "acv": "And he brought Aaron's sons, and Moses put of the blood upon the tip of their right ear, and upon the thumb of their right hand, and upon the great toe of their right foot. And Moses sprinkled the blood upon the altar round about.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he brought Aaron's sons, and Moses put of the blood upon the tip of their right ear, and upon the thumbs of their right hands, and upon the great toes of their right feet: and Moses sprinkled the blood upon the altar round about.", "vulgate": "obtulit et filios Aaron cumque de sanguine arietis immolati tetigisset extremum auriculae singulorum dextrae et pollices manus ac pedis dextri reliquum fudit super altare per circuitum;", "brenton": "And he took the fat, and the rump, and the fat on the belly, and the lobe of the liver, and the two kidneys, and the fat that is upon them, and the right shoulder."}}, {"v": 25, "ref": "8:25", "o": "וַ/יִּקַּ֞ח אֶת הַ/חֵ֣לֶב וְ/אֶת הָֽ/אַלְיָ֗ה וְ/אֶֽת כָּל הַ/חֵלֶב֮ אֲשֶׁ֣ר עַל הַ/קֶּרֶב֒ וְ/אֵת֙ יֹתֶ֣רֶת הַ/כָּבֵ֔ד וְ/אֶת שְׁתֵּ֥י הַ/כְּלָיֹ֖ת וְ/אֶֽת חֶלְבְּ/הֶ֑ן וְ/אֵ֖ת שׁ֥וֹק הַ/יָּמִֽין", "en": {"kjv": "And he took the fat, and the rump, and all the fat that was upon the inwards, and the caul above the liver, and the two kidneys, and their fat, and the right shoulder:", "web": "He took the fat, and the fat tail, and all the fat that was on the innards, and the cover of the liver, and the two kidneys, and their fat, and the right thigh;", "bsb": "And Moses took the fat—the fat tail, all the fat that was on the entrails, the lobe of the liver, and both kidneys with their fat—as well as the right thigh.", "asv": "And he took the fat, and the fat tail, and all the fat that was upon the inwards, and the caul of the liver, and the two kidneys, and their fat, and the right thigh:", "ylt": "and taketh the fat, and the fat tail, and all the fat that is on the inwards, and the redundance above the liver, and the two kidneys, and their fat, and the right leg;", "tyndale": "And he toke the fatt ad the rompe ad all the fatt that was apon the inwardes, ad the kall of the lyuer, ad the .ij. kydneyes with their fatt ad their righte shulder.", "dra": "But the fat, and the rump, and all the fat that covereth the entrails, and the caul of the liver, and the two kidneys with their fat, and with the right shoulder, he separated.", "bbe": "And he took the fat, and the fat tail, and the fat on the inside parts, and the fat on the liver, and the two kidneys with their fat, and the right leg;", "geneva": "And he tooke the fat and the rumpe and all the fat that was vpon the inwards, and the kall of the liuer, and the two kidneis with their fat, and the right shoulder.", "wycliffe": "Sotheli he departide the ynnere fatnesse, and the taile, and al the fatnesse that hilith the entrails, and the calle of the mawe, and the twey reynes with her fatnessis and with the riyt schuldur.", "rotherham": "And he took the fat and the fat-tail, and all the fat that was on the inwards, and the caul of the liver, and the two kidneys and their fat,—and the right shoulder;", "darby": "And he took the fat, and the fat tail, and all the fat that was on the inwards, and the net of the liver, and the two kidneys and their fat, and the right shoulder;", "twenty": "", "jps": "And he took the fat, and the fat tail, and all the fat that was upon the inwards, and the lobe of the liver, and the two kidneys, and their fat, and the right thigh.", "acv": "And he took the fat, and the fat tail, and all the fat that was upon the innards, and the caul of the liver, and the two kidneys, and their fat, and the right thigh,", "anderson": "", "haweis": "", "noyes": "", "webster": "And he took the fat, and the rump, and all the fat that [was] upon the inwards, and the caul [above] the liver, and the two kidneys, and their fat, and the right shoulder:", "vulgate": "adipem vero et caudam omnemque pinguedinem quae operit intestina reticulumque iecoris et duos renes cum adipibus suis et armo dextro separavit;", "brenton": "And from the basket of consecration, which was before the Lord, he also took one unleavened loaf, and one loaf made with oil, and one cake; and put them upon the fat, and the right shoulder:"}}, {"v": 26, "ref": "8:26", "o": "וּ/מִ/סַּ֨ל הַ/מַּצּ֜וֹת אֲשֶׁ֣ר לִ/פְנֵ֣י יְהוָ֗ה לָ֠קַח חַלַּ֨ת מַצָּ֤ה אַחַת֙ וְֽ/חַלַּ֨ת לֶ֥חֶם שֶׁ֛מֶן אַחַ֖ת וְ/רָקִ֣יק אֶחָ֑ד וַ/יָּ֨שֶׂם֙ עַל הַ֣/חֲלָבִ֔ים וְ/עַ֖ל שׁ֥וֹק הַ/יָּמִֽין", "en": {"kjv": "And out of the basket of unleavened bread, that was before the Lord, he took one unleavened cake, and a cake of oiled bread, and one wafer, and put them on the fat, and upon the right shoulder:", "web": "and out of the basket of unleavened bread, that was before Yahweh, he took one unleavened cake, and one cake of oiled bread, and one wafer, and placed them on the fat, and on the right thigh.", "bsb": "And from the basket of unleavened bread that was before the LORD, he took one cake of unleavened bread, one cake of bread made with oil, and one wafer, and he placed them on the fat portions and on the right thigh.", "asv": "and out of the basket of unleavened bread, that was before Jehovah, he took one unleavened cake, and one cake of oiled bread, and one wafer, and placed them on the fat, and upon the right thigh:", "ylt": "and out of the basket of unleavened things, which is before Jehovah, he hath taken one unleavened cake, and one cake of oiled bread, and one thin cake, and putteth them on the fat, and on the right leg;", "tyndale": "And out of the basket of swete bred that was before the Lorde, he toke one swete cake of oyled bred ad one wafer, ad put the on the fatt ad apon the righte shulder,", "dra": "And taking out of the basket of unleavened bread, which was before the Lord, a loaf without leaven, and a cake tempered with oil and a wafer, he put them upon the fat, and the right shoulder:", "bbe": "And out of the basket of unleavened bread which was before the Lord he took one unleavened cake, and one cake of bread with oil on it, and one thin cake, and put them on the fat and on the right leg:", "geneva": "Also he tooke of ye basket of ye vnleauened bread that was before the Lord, one vnleauened cake and a cake of oiled bread, and one wafer, and put them on the fat, and vpon the right shoulder.", "wycliffe": "Forsothe he took of the panyere of therf looues, that was bifor the Lord, looues without sour dow, and a cake spreynt with oile, and he puttide looues first sodun in watir and aftirward fried in oile on the ynnere fatnesse, and the riyt schuldur; and bitook alle thingis togidere to Aaron,", "rotherham": "and out of the basket of unleavened-cakes that was before Yahweh, took he one round unleavened-cake and one round oil-cake, and one wafer, and put them upon the fat portions, and upon the right shoulder;", "darby": "and out of the basket of unleavened bread that was before Jehovah he took one unleavened cake, and a cake of oiled bread, and one wafer, and put them on the fat and upon the right shoulder;", "twenty": "", "jps": "And out of the basket of unleavened bread, that was before HaShem, he took one unleavened cake, and one cake of oiled bread, and one wafer, and placed them on the fat, and upon the right thigh.", "acv": "and out of the basket of unleavened bread, that was before Jehovah, he took one unleavened cake, and one cake of oiled bread, and one wafer, and placed them on the fat, and upon the right thigh.", "anderson": "", "haweis": "", "noyes": "", "webster": "And out of the basket of unleavened bread, that [was] before the LORD, he took one unleavened cake, and a cake of oiled bread, and one wafer, and put [them] on the fat, and upon the right shoulder:", "vulgate": "tollens autem de canistro azymorum quod erat coram Domino panem absque fermento et collyridam conspersam oleo laganumque posuit super adipes et armum dextrum;", "brenton": "and put them all on the hands of Aaron, and upon the hands of his sons, and offered them up for a wave-offering before the Lord."}}, {"v": 27, "ref": "8:27", "o": "וַ/יִּתֵּ֣ן אֶת הַ/כֹּ֔ל עַ֚ל כַּפֵּ֣י אַהֲרֹ֔ן וְ/עַ֖ל כַּפֵּ֣י בָנָ֑י/ו וַ/יָּ֧נֶף אֹתָ֛/ם תְּנוּפָ֖ה לִ/פְנֵ֥י יְהוָֽה", "en": {"kjv": "And he put all upon Aaron’s hands, and upon his sons’ hands, and waved them for a wave offering before the Lord.", "web": "He put all these in Aaron’s hands and in his sons’ hands, and waved them for a wave offering before Yahweh.", "bsb": "He put all these in the hands of Aaron and his sons and waved them before the LORD as a wave offering.", "asv": "and he put the whole upon the hands of Aaron, and upon the hands of his sons, and waved them for a wave-offering before Jehovah.", "ylt": "and putteth the whole on the hands of Aaron, and on the hands of his sons, and waveth them--a wave-offering before Jehovah.", "tyndale": "ad put altogether apo Aarons handes ad apo his sonnes handes, ad waued it a waueofferynge before the Lorde.", "dra": "Delivering all to Aaron, and to his sons. Who having lifted them up before the Lord,", "bbe": "And he put them all on the hands of Aaron and on the hands of his sons, waving them for a wave offering before the Lord.", "geneva": "So hee put all in Aarons handes, and in his sonnes handes, and shooke it to and from before the Lord.", "wycliffe": "and to hise sones. And aftir that thei `reisiden tho bifore the Lord,", "rotherham": "and placed the whole upon the opened palms of Aaron, and upon the opened palms of his sons,—and waved them as a wave-offering, before Yahweh.", "darby": "and he gave all into Aaron's hands, and into his sons' hands, and waved them as a wave-offering before Jehovah.", "twenty": "", "jps": "And he put the whole upon the hands of Aaron, and upon the hands of his sons, and waved them for a wave-offering before HaShem.", "acv": "And he put the whole upon the hands of Aaron, and upon the hands of his sons, and waved them for a wave offering before Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he put all upon Aaron's hands, and upon his sons' hands, and waved them [for] a wave-offering before the LORD.", "vulgate": "tradens simul omnia Aaron et filiis eius qui postquam levaverunt ea coram Domino;", "brenton": "And Moses took them at their hands, and Moses offered them on the altar, on the whole-burnt-offering of consecration, which is a smell of sweet savour: it is a burnt-offering to the Lord."}}, {"v": 28, "ref": "8:28", "o": "וַ/יִּקַּ֨ח מֹשֶׁ֤ה אֹתָ/ם֙ מֵ/עַ֣ל כַּפֵּי/הֶ֔ם וַ/יַּקְטֵ֥ר הַ/מִּזְבֵּ֖חָ/ה עַל הָ/עֹלָ֑ה מִלֻּאִ֥ים הֵם֙ לְ/רֵ֣יחַ נִיחֹ֔חַ אִשֶּׁ֥ה ה֖וּא לַ/יהוָֽה", "en": {"kjv": "And Moses took them from off their hands, and burnt them on the altar upon the burnt offering: they were consecrations for a sweet savour: it is an offering made by fire unto the Lord.", "web": "Moses took them from their hands, and burned them on the altar on the burnt offering. They were a consecration for a pleasant aroma. It was an offering made by fire to Yahweh.", "bsb": "Then Moses took these from their hands and burned them on the altar with the burnt offering. This was an ordination offering, a pleasing aroma, an offering made by fire to the LORD.", "asv": "And Moses took them from off their hands, and burnt them on the altar upon the burnt-offering: they were a consecration for a sweet savor: it was an offering made by fire unto Jehovah.", "ylt": "And Moses taketh them from off their hands, and maketh perfume on the altar, on the burnt-offering, they are consecrations for sweet fragrance; it is a fire-offering to Jehovah;", "tyndale": "And tha Moses toke the from of their handes agayne ad burnt the apo the alter, euen apon the burntoffrynge: These are the fulloffrynges of a swete sauoure ad a sacrifice vnto the Lorde.", "dra": "He took them again from their hands, and burnt them upon the altar of holocaust: because it was the oblation of consecration, for a sweet odour of sacrifice to the Lord.", "bbe": "And Moses took them from their hands, and they were burned on the altar on the burned offering, as a priest's offering for a sweet smell, an offering made by fire to the Lord.", "geneva": "After, Moses tooke the out of their hands, and burnt them vpon the altar for a burnt offring: for these were consecrations for a sweete sauour which were made by fire vnto the Lord.", "wycliffe": "eft `he brente tho takun of her hondis, on the auter of brent sacrifice, for it was the offryng of halewyng, in to the odour of swetnesse of sacrifice `into his part to the Lord.", "rotherham": "And Moses took them from off their opened palms, and made a perfume at the altar upon the ascending-sacrifice,—an installation, they were for a satisfying odour, an altar-flame, it was unto Yahweh.", "darby": "And Moses took them from off their hands, and burned [them] on the altar, over the burnt-offering: they were a consecration-offering for a sweet odour: it was an offering by fire to Jehovah.", "twenty": "", "jps": "And Moses took them from off their hands, and made them smoke on the altar upon the burnt-offering; they were a consecration-offering for a sweet savour; it was an offering made by fire unto HaShem.", "acv": "And Moses took them from off their hands, and burnt them on the altar upon the burnt offering. They were a consecration for a sweet savor. It was an offering made by fire to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Moses took them from off their hands, and burnt [them] on the altar upon the burnt-offering: they [were] consecrations for a sweet savor: it [is] an offering made by fire to the LORD.", "vulgate": "rursum suscepta de manibus eorum adolevit super altare holocausti eo quod consecrationis esset oblatio in odorem suavitatis sacrificii Domini;", "brenton": "And Moses took the breast, and separated it for a heave-offering before the Lord, from the ram of consecration; and it became Moses' portion, as the Lord commanded Moses."}}, {"v": 29, "ref": "8:29", "o": "וַ/יִּקַּ֤ח מֹשֶׁה֙ אֶת הֶ֣/חָזֶ֔ה וַ/יְנִיפֵ֥/הוּ תְנוּפָ֖ה לִ/פְנֵ֣י יְהוָ֑ה מֵ/אֵ֣יל הַ/מִּלֻּאִ֗ים לְ/מֹשֶׁ֤ה הָיָה֙ לְ/מָנָ֔ה כַּ/אֲשֶׁ֛ר צִוָּ֥ה יְהוָ֖ה אֶת מֹשֶֽׁה", "en": {"kjv": "And Moses took the breast, and waved it for a wave offering before the Lord: for of the ram of consecration it was Moses’ part; as the Lord commanded Moses.", "web": "Moses took the breast, and waved it for a wave offering before Yahweh. It was Moses’ portion of the ram of consecration, as Yahweh commanded Moses.", "bsb": "He also took the breast—Moses’ portion of the ram of ordination—and waved it before the LORD as a wave offering, as the LORD had commanded him.", "asv": "And Moses took the breast, and waved it for a wave-offering before Jehovah: it was Moses’ portion of the ram of consecration; as Jehovah commanded Moses.", "ylt": "and Moses taketh the breast, and waveth it--a wave-offering before Jehovah; of the ram of the consecrations it hath been to Moses for a portion, as Jehovah hath commanded Moses.", "tyndale": "And Moses toke the breste and waued it a waueoffrynge before the Lorde, of the ram of the fuloffrynges: ad it was Moses parte, as the Lorde commaunded Moses.", "dra": "And he took of the ram of consecration, the breast for his portion, elevating it before the Lord, as the Lord had commanded him.", "bbe": "And Moses took the breast, waving it for a wave offering before the Lord; it was Moses' part of the sheep of the priest's offering, as the Lord gave orders to Moses.", "geneva": "Likewise Moses tooke the breast of the ram of consecrations, and shooke it to and from before the Lord: for it was Moses portion, as the Lord had commanded Moses.", "wycliffe": "He took also the brest of the ram of consecracioun in to his part, and reiside it bifor the Lord, as the Lord comaundide to hym.", "rotherham": "And Moses took the breast, and waved it as a wave-offering, before Yahweh,—of the ram of installation, unto Moses it belonged, as a portion, As Yahweh commanded Moses.", "darby": "And Moses took the breast, and waved it as a wave-offering before Jehovah; of the ram of consecration it was Moses' part; as Jehovah had commanded Moses.", "twenty": "", "jps": "And Moses took the breast, and waved it for a wave-offering before HaShem; it was Moses' portion of the ram of consecration; as HaShem commanded Moses.", "acv": "And Moses took the breast, and waved it for a wave offering before Jehovah. It was Moses' portion of the ram of consecration, as Jehovah commanded Moses.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Moses took the breast, and waved it [for] a wave-offering before the LORD: [for] of the ram of consecration it was Moses's part; as the LORD commanded Moses.", "vulgate": "tulit et pectusculum elevans illud coram Domino de ariete consecrationis in partem suam sicut praeceperat ei Dominus;", "brenton": "And Moses took of the anointing oil, and of the blood that was on the altar, and sprinkled it on Aaron, and on his garments, and his sons, and the garments of his sons with him."}}, {"v": 30, "ref": "8:30", "o": "וַ/יִּקַּ֨ח מֹשֶׁ֜ה מִ/שֶּׁ֣מֶן הַ/מִּשְׁחָ֗ה וּ/מִן הַ/דָּם֮ אֲשֶׁ֣ר עַל הַ/מִּזְבֵּחַ֒ וַ/יַּ֤ז עַֽל אַהֲרֹן֙ עַל בְּגָדָ֔י/ו וְ/עַל בָּנָ֛י/ו וְ/עַל בִּגְדֵ֥י בָנָ֖י/ו אִתּ֑/וֹ וַ/יְקַדֵּ֤שׁ אֶֽת אַהֲרֹן֙ אֶת בְּגָדָ֔י/ו וְ/אֶת בָּנָ֛י/ו וְ/אֶת בִּגְדֵ֥י בָנָ֖י/ו אִתּֽ/וֹ", "en": {"kjv": "And Moses took of the anointing oil, and of the blood which was upon the altar, and sprinkled it upon Aaron, and upon his garments, and upon his sons, and upon his sons’ garments with him; and sanctified Aaron, and his garments, and his sons, and his sons’ garments with him.", "web": "Moses took some of the anointing oil, and some of the blood which was on the altar, and sprinkled it on Aaron, on his garments, and on his sons, and on his sons’ garments with him, and sanctified Aaron, his garments, and his sons, and his sons’ garments with him.", "bsb": "Next, Moses took some of the anointing oil and some of the blood that was on the altar and sprinkled them on Aaron and his garments, and on his sons and their garments. So he consecrated Aaron and his garments, as well as Aaron’s sons and their garments.", "asv": "And Moses took of the anointing oil, and of the blood which was upon the altar, and sprinkled it upon Aaron, upon his garments, and upon his sons, and upon his sons’ garments with him, and sanctified Aaron, his garments, and his sons, and his sons’ garments with him.", "ylt": "And Moses taketh of the anointing oil, and of the blood which is on the altar, and sprinkleth on Aaron, on his garments, and on his sons, and on the garments of his sons with him, and he sanctifieth Aaron, his garments, and his sons, and the garments of his sons with him.", "tyndale": "And Moses toke of the anoynting oyle ad of the bloude whiche was apon the alter, and sprinkled it apo Aaro ad apon his vestimetes ad apo his sones ad on their vestimetes with hi ad sanctified Aaro ad his vesturs ad his sones and his sonnes vestures also.", "dra": "And taking the ointment, and the blood that was upon the altar, he sprinkled Aaron, and his vestments, and his sons, and their vestments with it.", "bbe": "And Moses took some of the holy oil and of the blood which was on the altar and put it on Aaron and on his robes, and on his sons and on his sons' robes; and made Aaron holy, and his robes and his sons and his sons' robes with him.", "geneva": "Also Moses tooke of the anointing oyle, and of the blood which was vpon the Altar, and sprinkled it vpon Aaron, vpon his garments, and vpon his sonnes, and on his sonnes garments with him: so hee sanctified Aaron, his garments, and his sonnes, and his sonnes garments with him.", "wycliffe": "And he took the oynement, and blood that was in the auter, and `spreynte on Aaron, and hise clothis, and on `the sones of hym, and on her clothis.", "rotherham": "And Moses took of the anointing oil and of the blood that was upon the altar, and sprinkled upon Aaron, upon his garments, and upon his sons and upon the garments of his sons with him,—and hallowed Aaron, his garments, and his sons and the garments of his sons with him.", "darby": "And Moses took of the anointing oil, and of the blood that was on the altar, and sprinkled [it] on Aaron, on his garments, and on his sons, and on his sons' garments with him; and hallowed Aaron, his garments, and his sons, and his sons' garments with him.", "twenty": "", "jps": "And Moses took of the anointing oil, and of the blood which was upon the altar, and sprinkled it upon Aaron, and upon his garments, and upon his sons, and upon his sons' garments with him, and sanctified Aaron, and his garments, and his sons, and his sons' garments with him.", "acv": "And Moses took of the anointing oil, and of the blood which was upon the altar, and sprinkled it upon Aaron, upon his garments, and upon his sons, and upon his sons' garments with him, and sanctified Aaron, his garments, and his sons, and his sons' garments with him.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Moses took of the anointing oil, and of the blood which [was] upon the altar, and sprinkled [it] upon Aaron, [and] upon his garments, and upon his sons, and upon his sons' garments with him; and sanctified Aaron, [and] his garments, and his sons, and his sons' garments with him.", "vulgate": "adsumensque unguentum et sanguinem qui erat in altari aspersit super Aaron et vestimenta eius et super filios illius ac vestes eorum;", "brenton": "And he sanctified Aaron and his garments, and his sons, and the garments of his sons with him."}}, {"v": 31, "ref": "8:31", "o": "וַ/יֹּ֨אמֶר מֹשֶׁ֜ה אֶל אַהֲרֹ֣ן וְ/אֶל בָּנָ֗י/ו בַּשְּׁל֣וּ אֶת הַ/בָּשָׂר֮ פֶּ֣תַח אֹ֣הֶל מוֹעֵד֒ וְ/שָׁם֙ תֹּאכְל֣וּ אֹת֔/וֹ וְ/אֶ֨ת הַ/לֶּ֔חֶם אֲשֶׁ֖ר בְּ/סַ֣ל הַ/מִּלֻּאִ֑ים כַּ/אֲשֶׁ֤ר צִוֵּ֨יתִי֙ לֵ/אמֹ֔ר אַהֲרֹ֥ן וּ/בָנָ֖י/ו יֹאכְלֻֽ/הוּ", "en": {"kjv": "And Moses said unto Aaron and to his sons, Boil the flesh at the door of the tabernacle of the congregation: and there eat it with the bread that is in the basket of consecrations, as I commanded, saying, Aaron and his sons shall eat it.", "web": "Moses said to Aaron and to his sons, “Boil the flesh at the door of the Tent of Meeting, and there eat it and the bread that is in the basket of consecration, as I commanded, saying, ‘Aaron and his sons shall eat it.’", "bsb": "And Moses said to Aaron and his sons, “Boil the meat at the entrance to the Tent of Meeting and eat it there with the bread that is in the basket of ordination offerings, as I commanded, saying, ‘Aaron and his sons are to eat it.’", "asv": "And Moses said unto Aaron and to his sons, Boil the flesh at the door of the tent of meeting: and there eat it and the bread that is in the basket of consecration, as I commanded, saying, Aaron and his sons shall eat it.", "ylt": "And Moses saith unto Aaron, and unto his sons, `Boil ye the flesh at the opening of the tent of meeting, and there ye do eat it and the bread which is in the basket of the consecrations, as I have commanded, saying, Aaron and his sons do eat it.", "tyndale": "Then Moses sayde vnto Aaron and his sonnes: boyle the flesh in the doore of the tabernacle of witnesse, and there eate it with the bred that is in the basket of fullofferynges, as the Lorde commaunded sayenge. Aaron and his sonnes shall eate it:", "dra": "And when he had sanctified them in their vestments, he commanded them, saying: Boil the flesh before the door of the tabernacle, and there eat it. Eat ye also the loaves of consecration, that are laid in the basket, as the Lord commanded me, saying: Aaron and his sons shall eat them.", "bbe": "And Moses said to Aaron and to his sons, The flesh is to be cooked in water at the door of the Tent of meeting, and there you are to take it as food, together with the bread in the basket, as I have given orders, saying, It is the food of Aaron and his sons.", "geneva": "Afterward Moses saide vnto Aaron and his sonnes, Seethe the flesh at the doore of the Tabernacle of the Congregation, and there eate it with the bread that is in the basket of consecrations, as I commanded, saying, Aaron and his sonnes shall eate it,", "wycliffe": "And whanne he hadde halewid hem in her clothing, he comaundide to hem, and seide, Sethe ye fleischis bifor the `yatis of the tabernacle, and there ete ye tho; also ete ye the looues of halewyng, that ben put in the panyere, as God comaundide to me, `and seide, Aaron and hise sones schulen ete tho looues;", "rotherham": "And Moses said unto Aaron and unto his sons Boil ye the flesh, at the entrance of the tent of meeting, and there, shall ye eat it, and the bread which is in the basket of installation,—as I have been commanded, saying, Aaron and his sons, shall eat it.", "darby": "And Moses spoke to Aaron and to his sons, Boil the flesh at the entrance of the tent of meeting; and there eat it and the bread that is in the basket of the consecration-offering, as I commanded, saying, Aaron and his sons shall eat it.", "twenty": "", "jps": "And Moses said unto Aaron and to his sons: 'Boil the flesh at the door of the tent of meeting; and there eat it and the bread that is in the basket of consecration, as I commanded, saying: Aaron and his sons shall eat it.", "acv": "And Moses said to Aaron and to his sons, Boil the flesh at the door of the tent of meeting, and there eat it and the bread that is in the basket of consecration, as I commanded, saying, Aaron and his sons shall eat it.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Moses said to Aaron and to his sons, Boil the flesh [at] the door of the tabernacle of the congregation; and there eat it with the bread that [is] in the basket of consecrations, as I commanded, saying, Aaron and his sons shall eat it.", "vulgate": "cumque sanctificasset eos in vestitu suo praecepit eis dicens coquite carnes ante fores tabernaculi et ibi comedite eas panes quoque consecrationis edite qui positi sunt in canistro sicut praecepit mihi dicens Aaron et filii eius comedent eos;", "brenton": "And Moses said to Aaron and to his sons, Boil the flesh in the tent of the tabernacle of witness in the holy place; and there ye shall eat it and the loaves in the basket of consecration, as it has been appointed me, the Lord saying, Aaron and his sons shall eat them."}}, {"v": 32, "ref": "8:32", "o": "וְ/הַ/נּוֹתָ֥ר בַּ/בָּשָׂ֖ר וּ/בַ/לָּ֑חֶם בָּ/אֵ֖שׁ תִּשְׂרֹֽפוּ", "en": {"kjv": "And that which remaineth of the flesh and of the bread shall ye burn with fire.", "web": "What remains of the flesh and of the bread you shall burn with fire.", "bsb": "Then you must burn up the remainder of the meat and bread.", "asv": "And that which remaineth of the flesh and of the bread shall ye burn with fire.", "ylt": "`And the remnant of the flesh and of the bread with fire ye burn;", "tyndale": "ad that whiche remayneth of the flesh and of the brede, burne with fire.", "dra": "And whatsoever shall be left of the flesh and the loaves, shall be consumed with fire.", "bbe": "And that which is over of the flesh and of the bread is to be burned with fire.", "geneva": "But that which remaineth of the flesh and of the bread, shall ye burne with fire.", "wycliffe": "sotheli whateuer thing is residue of the fleisch and looues, fier schal waste.", "rotherham": "But, that which is left of the flesh, and of the bread, with fire, shall ye consume.", "darby": "And that which remaineth of the flesh and of the bread shall ye burn with fire.", "twenty": "", "jps": "And that which remaineth of the flesh and of the bread shall ye burn with fire.", "acv": "And that which remains of the flesh and of the bread ye shall burn with fire.", "anderson": "", "haweis": "", "noyes": "", "webster": "And that which remaineth of the flesh and of the bread shall ye burn with fire.", "vulgate": "quicquid autem reliquum fuerit de carne et panibus ignis absumet;", "brenton": "And that which is left of the flesh and of the loaves burn ye with fire."}}, {"v": 33, "ref": "8:33", "o": "וּ/מִ/פֶּתַח֩ אֹ֨הֶל מוֹעֵ֜ד לֹ֤א תֵֽצְאוּ֙ שִׁבְעַ֣ת יָמִ֔ים עַ֚ד י֣וֹם מְלֹ֔את יְמֵ֖י מִלֻּאֵי/כֶ֑ם כִּ֚י שִׁבְעַ֣ת יָמִ֔ים יְמַלֵּ֖א אֶת יֶדְ/כֶֽם", "en": {"kjv": "And ye shall not go out of the door of the tabernacle of the congregation in seven days, until the days of your consecration be at an end: for seven days shall he consecrate you.", "web": "You shall not go out from the door of the Tent of Meeting seven days, until the days of your consecration are fulfilled: for he shall consecrate you seven days.", "bsb": "You must not go outside the entrance to the Tent of Meeting for seven days, until the days of your ordination are complete; for it will take seven days to ordain you.", "asv": "And ye shall not go out from the door of the tent of meeting seven days, until the days of your consecration be fulfilled: for he shall consecrate you seven days.", "ylt": "and from the opening of the tent of meeting ye go not out seven days, till the day of the fulness, the days of your consecration--for seven days he doth consecrate your hand;", "tyndale": "And se that ye departe not from the doore of the tabernacle of witnesse seuen dayes longe: vntill the dayes of youre fullofferynges be at an ende. For .vij. dayes must youre hades be filled,", "dra": "And you shall not go out of the door of the tabernacle for seven days, until the day wherein the time of your consecration shall be expired. For in seven days the consecration is finished:", "bbe": "And you are not to go out from the door of the Tent of meeting for seven days, till the days for making you priest are ended; for this will be the work of seven days.", "geneva": "And ye shall not depart from the doore of the Tabernacle of the Congregation seuen dayes, vntill the dayes of your consecrations bee at an ende: for seuen dayes, saide the Lord, shall hee consecrate you,", "wycliffe": "Also ye schulen not go out of the dore of the tabernacle in seuene daies, til to the day in which the tyme of youre halewyng schal be fillid; for the halewyng is endid in seuene dayes,", "rotherham": "And from the entrance of the tent of meeting, shall ye not go forth for seven days, until the day that filleth up the days of your installation,—because for seven days, will he install you:", "darby": "And ye shall not go out from the entrance of the tent of meeting seven days, until the day when the days of your consecration are at an end: for seven days shall ye be consecrated.", "twenty": "", "jps": "And ye shall not go out from the door of the tent of meeting seven days, until the days of your consecration be fulfilled; for He shall consecrate you seven days.", "acv": "And ye shall not go out from the door of the tent of meeting seven days, until the days of your consecration be fulfilled, for he shall consecrate you seven days.", "anderson": "", "haweis": "", "noyes": "", "webster": "And ye shall not go out of the door of the tabernacle of the congregation [in] seven days, until the days of your consecration shall be at an end: for seven days shall he consecrate you.", "vulgate": "de ostio quoque tabernaculi non exibitis septem diebus usque ad diem quo conplebitur tempus consecrationis vestrae septem enim diebus finitur consecratio;", "brenton": "And ye shall not go out from the door of the tabernacle of witness for seven days, until the day be fulfilled, the day of your consecration; for in seven days shall he consecrate you,"}}, {"v": 34, "ref": "8:34", "o": "כַּ/אֲשֶׁ֥ר עָשָׂ֖ה בַּ/יּ֣וֹם הַ/זֶּ֑ה צִוָּ֧ה יְהוָ֛ה לַ/עֲשֹׂ֖ת לְ/כַפֵּ֥ר עֲלֵי/כֶֽם", "en": {"kjv": "As he hath done this day, so the Lord hath commanded to do, to make an atonement for you.", "web": "What has been done this day, so Yahweh has commanded to do, to make atonement for you.", "bsb": "What has been done today has been commanded by the LORD in order to make atonement on your behalf.", "asv": "As hath been done this day, so Jehovah hath commanded to do, to make atonement for you.", "ylt": "as he hath done on this day, Jehovah hath commanded to do, to make atonement for you;", "tyndale": "as they were this daye: eue so the Lorde hath commauded to do, to reconcyle you with all.", "dra": "As at this present it hath been done, that the rite of the sacrifice might be accomplished.", "bbe": "What has been done this day, has been ordered by the Lord to take away your sin.", "geneva": "As hee hath done this day: so the Lord hath commanded to doe, to make an atonement for you.", "wycliffe": "as it is doon in present tyme, that the riytfulnesse of sacrifice were fillid.", "rotherham": "as hath been done this day, [so] hath Yahweh commanded to be done, to put a propitiatory-covering over you.", "darby": "As he hath done this day, [so] Jehovah hath commanded to do, to make atonement for you.", "twenty": "", "jps": "As hath been done this day, so HaShem hath commanded to do, to make atonement for you.", "acv": "As has been done this day, so Jehovah has commanded to do, to make atonement for you.", "anderson": "", "haweis": "", "noyes": "", "webster": "As he hath done this day, [so] the LORD hath commanded to do, to make an atonement for you.", "vulgate": "sicut et inpraesentiarum factum est ut ritus sacrificii conpleretur;", "brenton": "as he did in this day on which the Lord commanded me to do so, to make an atonement for you."}}, {"v": 35, "ref": "8:35", "o": "וּ/פֶתַח֩ אֹ֨הֶל מוֹעֵ֜ד תֵּשְׁב֨וּ יוֹמָ֤ם וָ/לַ֨יְלָה֙ שִׁבְעַ֣ת יָמִ֔ים וּ/שְׁמַרְתֶּ֛ם אֶת מִשְׁמֶ֥רֶת יְהוָ֖ה וְ/לֹ֣א תָמ֑וּתוּ כִּי כֵ֖ן צֻוֵּֽיתִי", "en": {"kjv": "Therefore shall ye abide at the door of the tabernacle of the congregation day and night seven days, and keep the charge of the Lord, that ye die not: for so I am commanded.", "web": "You shall stay at the door of the Tent of Meeting day and night seven days, and keep Yahweh’s command, that you don’t die: for so I am commanded.”", "bsb": "You must remain at the entrance to the Tent of Meeting day and night for seven days and keep the LORD’s charge so that you will not die, for this is what I have been commanded.”", "asv": "And at the door of the tent of meeting shall ye abide day and night seven days, and keep the charge of Jehovah, that ye die not: for so I am commanded.", "ylt": "and at the opening of the tent of meeting ye abide, by day and by night seven days, and ye have kept the charge of Jehovah, and die not, for so I have been commanded.'", "tyndale": "Se therfore that ye abyde in the dore of the tabernacle of witnesse daye and nyghte seuen dayes longe: and kepe the watch of the Lorde that ye dye not: for so I am commaunded.", "dra": "Day and night shall you remain in the tabernacle observing the watches of the Lord, lest you die. For so it hath been commanded me.", "bbe": "And you are to keep watch for the Lord at the door of the Tent of meeting day and night for seven days, so that death may not come to you: for so he has given me orders.", "geneva": "Therefore shall yee abide at the doore of the Tabernacle of the Congregation day and night, seuen dayes, and shall keepe the watch of the Lord, that ye dye not: for so I am commanded.", "wycliffe": "Ye schulen dwelle dai and nyyt in the tabernacle, and ye schulen kepe the kepyngis of the Lord, that ye die not; for so it is comaundid to me.", "rotherham": "Even at the entrance of the tent of meeting, shall ye abide day and night for seven days, and shall keep the watch of Yahweh and shall not die,—for, so, am I commanded.", "darby": "And ye shall abide at the entrance of the tent of meeting day and night seven days, and keep the charge of Jehovah, that ye die not; for so I am commanded.", "twenty": "", "jps": "And at the door of the tent of meeting shall ye abide day and night seven days, and keep the charge of HaShem, that ye die not; for so I am commanded.", "acv": "And ye shall remain at the door of the tent of meeting day and night seven days, and keep the charge of Jehovah, that ye not die, for so I am commanded.", "anderson": "", "haweis": "", "noyes": "", "webster": "Therefore shall ye abide [at] the door of the tabernacle of the congregation day and night seven days, and keep the charge of the LORD, that ye die not: for so I am commanded.", "vulgate": "die ac nocte manebitis in tabernaculo observantes custodias Domini ne moriamini sic enim mihi praeceptum est;", "brenton": "And ye shall remain seven days at the door of the tabernacle of witness, day and night; ye shall observe the ordinances of the Lord, that ye die not; for so has the Lord God commanded me."}}, {"v": 36, "ref": "8:36", "o": "וַ/יַּ֥עַשׂ אַהֲרֹ֖ן וּ/בָנָ֑י/ו אֵ֚ת כָּל הַ/דְּבָרִ֔ים אֲשֶׁר צִוָּ֥ה יְהוָ֖ה בְּ/יַד מֹשֶֽׁה", "en": {"kjv": "So Aaron and his sons did all things which the Lord commanded by the hand of Moses.", "web": "Aaron and his sons did all the things which Yahweh commanded by Moses.", "bsb": "So Aaron and his sons did everything the LORD had commanded through Moses.", "asv": "And Aaron and his sons did all the things which Jehovah commanded by Moses.", "ylt": "And Aaron doth--his sons also--all the things which Jehovah hath commanded by the hand of Moses.", "tyndale": "And Aaron and his sonnes dyd all thynges which the Lorde commaunded by the hande of Moses.", "dra": "And Aaron and his sons did all things which the Lord spoke by the hand of Moses.", "bbe": "And Aaron and his sons did all the things about which the Lord had given orders through Moses.", "geneva": "So Aaron and his sonnes did all thinges which the Lord had commanded by the hand of Moses.", "wycliffe": "And Aaron and hise sones diden alle thingis, whiche the Lord spak bi the hond of Moises.", "rotherham": "And Aaron and his sons did all the things which Yahweh had commanded through the mediation of Moses.", "darby": "And Aaron and his sons did all things that Jehovah had commanded by the hand of Moses.", "twenty": "", "jps": "And Aaron and his sons did all the things which HaShem commanded by the hand of Moses.", "acv": "And Aaron and his sons did all the things which Jehovah commanded by Moses.", "anderson": "", "haweis": "", "noyes": "", "webster": "So Aaron and his sons did all things which the LORD commanded by the hand of Moses.", "vulgate": "feceruntque Aaron et filii eius cuncta quae locutus est Dominus per manum Mosi;", "brenton": "And Aaron and his sons performed all these commands which the Lord commanded Moses."}}]}, {"c": 9, "verses": [{"v": 1, "ref": "9:1", "o": "וַ/יְהִי֙ בַּ/יּ֣וֹם הַ/שְּׁמִינִ֔י קָרָ֣א מֹשֶׁ֔ה לְ/אַהֲרֹ֖ן וּ/לְ/בָנָ֑י/ו וּ/לְ/זִקְנֵ֖י יִשְׂרָאֵֽל", "en": {"kjv": "And it came to pass on the eighth day, that Moses called Aaron and his sons, and the elders of Israel;", "web": "On the eighth day, Moses called Aaron and his sons, and the elders of Israel;", "bsb": "On the eighth day Moses summoned Aaron and his sons and the elders of Israel.", "asv": "And it came to pass on the eighth day, that Moses called Aaron and his sons, and the elders of Israel;", "ylt": "And it cometh to pass on the eighth day, Moses hath called for Aaron and for his sons, and for the elders of Israel,", "tyndale": "And the .viij. daye Moses called Aaron and his sonnes and the elders of Israel,", "dra": "And when the eighth day was come, Moses called Aaron and his sons, and the ancients of Israel, and said to Aaron:", "bbe": "And on the eighth day Moses sent for Aaron and his sons and the responsible men of Israel;", "geneva": "And in the eight day Moses called Aaron and his sonnes, and the Elders of Israel:", "wycliffe": "Forsothe whanne the eiytithe dai was maad, Moises clepide Aaron, and hise sones, and the grettere men in birthe of Israel;", "rotherham": "And it came to pass on the eighth day, that Moses called for Aaron, and for his sons,—and for the elders of Israel;", "darby": "And it came to pass on the eighth day, [that] Moses called Aaron and his sons, and the elders of Israel,", "twenty": "", "jps": "And it came to pass on the eighth day, that Moses called Aaron and his sons, and the elders of Israel;", "acv": "And it came to pass on the eighth day, that Moses called Aaron and his sons, and the elders of Israel,", "anderson": "", "haweis": "", "noyes": "", "webster": "And it came to pass on the eighth day, [that] Moses called Aaron and his sons, and the elders of Israel;", "vulgate": "facto autem octavo die vocavit Moses Aaron et filios eius ac maiores natu Israhel dixitque ad Aaron;", "brenton": "And it came to pass on the eighth day, that Moses called Aaron and his sons, and the elders of Israel,"}}, {"v": 2, "ref": "9:2", "o": "וַ/יֹּ֣אמֶר אֶֽל אַהֲרֹ֗ן קַח לְ֠/ךָ עֵ֣גֶל בֶּן בָּקָ֧ר לְ/חַטָּ֛את וְ/אַ֥יִל לְ/עֹלָ֖ה תְּמִימִ֑ם וְ/הַקְרֵ֖ב לִ/פְנֵ֥י יְהוָֽה", "en": {"kjv": "And he said unto Aaron, Take thee a young calf for a sin offering, and a ram for a burnt offering, without blemish, and offer them before the Lord.", "web": "and he said to Aaron, “Take a calf from the herd for a sin offering, and a ram for a burnt offering, without defect, and offer them before Yahweh.", "bsb": "He said to Aaron, “Take for yourself a young bull for a sin offering and a ram for a burnt offering, both without blemish, and present them before the LORD.", "asv": "and he said unto Aaron, Take thee a calf of the herd for a sin-offering, and a ram for a burnt-offering, without blemish, and offer them before Jehovah.", "ylt": "and he saith unto Aaron, `Take to thyself a calf, a son of the herd, for a sin-offering, and a ram for a burnt-offering, perfect ones, and bring near before Jehovah.", "tyndale": "and sayde vnto Aaron: take a calfe for a synneoffrynge, and a ram for a burntoffrynge: both without blemish, and brynge them before the Lorde.", "dra": "Take of the herd a calf for sin, and a ram for a holocaust, both without blemish, and offer them before the Lord.", "bbe": "And he said to Aaron, Take a young ox for a sin-offering and a male sheep for a burned offering, without a mark, and make an offering of them before the Lord.", "geneva": "Then hee sayde vnto Aaron, Take thee a yong calfe for a sinne offring, and a ram for a burnt offring, both without blemish, and bring them before the Lord.", "wycliffe": "and he seide to Aaron, Take thou of the droue a calf for synne, and a ram `in to brent sacrifice, euer either with oute wem, and offre tho bifor the Lord.", "rotherham": "and said unto Aaron—Take for thyself a choice calf, as a sin-bearer, and a ram for an ascending-sacrifice, each without defect,—and bring them near before Yahweh;", "darby": "and said to Aaron, Take thee a young calf for a sin-offering, and a ram for a burnt-offering, without blemish, and present [them] before Jehovah;", "twenty": "", "jps": "and he said unto Aaron: 'Take thee a bull-calf for a sin-offering, and a ram for a burnt-offering, without blemish, and offer them before HaShem.", "acv": "and he said to Aaron, Take thee a calf of the herd for a sin offering, and a ram for a burnt offering, without blemish, and offer them before Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he said to Aaron, Take thee a young calf for a sin-offering, and a ram for a burnt-offering, without blemish, and offer [them] before the LORD.", "vulgate": "tolle de armento vitulum pro peccato et arietem in holocaustum utrumque inmaculatos et offer illos coram Domino;", "brenton": "and Moses said to Aaron, Take to thyself a young calf of the herd for a sin-offering, and a ram for a whole-burnt-offering, unblemished, and offer them before the Lord."}}, {"v": 3, "ref": "9:3", "o": "וְ/אֶל בְּנֵ֥י יִשְׂרָאֵ֖ל תְּדַבֵּ֣ר לֵ/אמֹ֑ר קְח֤וּ שְׂעִיר עִזִּים֙ לְ/חַטָּ֔את וְ/עֵ֨גֶל וָ/כֶ֧בֶשׂ בְּנֵי שָׁנָ֛ה תְּמִימִ֖ם לְ/עֹלָֽה", "en": {"kjv": "And unto the children of Israel thou shalt speak, saying, Take ye a kid of the goats for a sin offering; and a calf and a lamb, both of the first year, without blemish, for a burnt offering;", "web": "You shall speak to the children of Israel, saying, ‘Take a male goat for a sin offering; and a calf and a lamb, both a year old, without defect, for a burnt offering;", "bsb": "Then speak to the Israelites and say, ‘Take a male goat for a sin offering, a calf and a lamb—both a year old and without blemish—for a burnt offering,", "asv": "And unto the children of Israel thou shalt speak, saying, Take ye a he-goat for a sin-offering; and a calf and a lamb, both a year old, without blemish, for a burnt-offering;", "ylt": "`And unto the sons of Israel thou dost speak, saying, Take ye a kid of the goats for a sin-offering, and a calf, and a lamb, sons of a year, perfect ones, for a burnt-offering,", "tyndale": "And vnto the childern of Israel he spake sayenge: take ye an he goote for a synneofferynge, and a calfe and a lambe bothe two of a yere olde, and without blemysh for a burntsacrifice,", "dra": "And to the children of Israel thou shalt say: Take ye a he goat for sin, and a calf, and a lamb, both of a year old, and without blemish for a holocaust.", "bbe": "And say to the children of Israel: Take a he-goat for a sin-offering, and a young ox and a lamb, in their first year, without any mark on them, for a burned offering;", "geneva": "And vnto the children of Israel thou shalt speake, saying, Take yee an hee goate for a sinne offring, and a calfe, and a lambe, both of a yeere olde, without blemish for a burnt offring:", "wycliffe": "And thou schalt speke to the sones of Israel, Take ye a buk of geet for synne, and a calf, and a lomb of o yeer and with out wem,", "rotherham": "and unto the sons of Israel, shalt thou speak, saying,—Take ye a he-goat, as a sin-bearer, and a calf and a young sheep, each a year old, without defect for an ascending-sacrifice;", "darby": "and to the children of Israel shalt thou speak, saying, Take a buck of the goats for a sin-offering, and a calf and a lamb, yearlings, without blemish, for a burnt-offering;", "twenty": "", "jps": "And unto the children of Israel thou shalt speak, saying: Take ye a he-goat for a sin-offering; and a calf and a lamb, both of the first year, without blemish, for a burnt-offering;", "acv": "And thou shall speak to the sons of Israel, saying, Take ye a he-goat for a sin offering, and a calf and a lamb, both a year old, without blemish, for a burnt offering,", "anderson": "", "haweis": "", "noyes": "", "webster": "And to the children of Israel thou shalt speak, saying, Take ye a kid of the goats for a sin-offering; and a calf and a lamb, [both] of the first year, without blemish, for a burnt-offering;", "vulgate": "et ad filios Israhel loqueris tollite hircum pro peccato et vitulum atque agnum anniculos et sine macula in holocaustum;", "brenton": "And speak to the elders of Israel, saying, Take one kid of the goats for a sin-offering, and a young calf, and a lamb of a year old for a whole-burnt-offering, spotless,"}}, {"v": 4, "ref": "9:4", "o": "וְ/שׁ֨וֹר וָ/אַ֜יִל לִ/שְׁלָמִ֗ים לִ/זְבֹּ֨חַ֙ לִ/פְנֵ֣י יְהוָ֔ה וּ/מִנְחָ֖ה בְּלוּלָ֣ה בַ/שָּׁ֑מֶן כִּ֣י הַ/יּ֔וֹם יְהוָ֖ה נִרְאָ֥ה אֲלֵי/כֶֽם", "en": {"kjv": "Also a bullock and a ram for peace offerings, to sacrifice before the Lord; and a meat offering mingled with oil: for to day the Lord will appear unto you.", "web": "and a bull and a ram for peace offerings, to sacrifice before Yahweh; and a meal offering mixed with oil: for today Yahweh appears to you.’”", "bsb": "an ox and a ram for a peace offering to sacrifice before the LORD, and a grain offering mixed with oil. For today the LORD will appear to you.’”", "asv": "and an ox and a ram for peace-offerings, to sacrifice before Jehovah; and a meal-offering mingled with oil: for to-day Jehovah appeareth unto you.", "ylt": "and a bullock and a ram for peace-offerings, to sacrifice before Jehovah, and a present mixed with oil; for to-day Jehovah hath appeared unto you.'", "tyndale": "and an oxe and a ram for peaceoffrynges, to offer before the Lorde, and a meateofferyng myngled with oyle, for to daye the Lorde will appere vnto you.", "dra": "Also a bullock and a ram for peace offerings. And immolate them before the Lord, offering for the sacrifice of every one of them flour tempered with oil: for to day the Lord will appear to you.", "bbe": "And an ox and a male sheep for peace-offerings, to be put to death before the Lord; and a meal offering mixed with oil: for this day you are to see the Lord.", "geneva": "Also a bullock, and a ramme for peace offringes, to offer before the Lord, and a meate offring mingled with oyle: for to day the Lord will appeare vnto you.", "wycliffe": "in to brent sacrifice, an oxe and a ram for pesible thingis; and offre ye tho bifor the Lord, and offre ye whete flour spreynt with oile in the sacrifice of ech; for to dai the Lord schal appere to you.", "rotherham": "and an ox and a ram for peace-offerings, to sacrifice before Yahweh, and a meal-offering overflowed with oil,—for, to-day, doth, Yahweh, appear unto you.", "darby": "and a bullock and a ram for a peace-offering, to sacrifice before Jehovah; and an oblation mingled with oil; for to-day Jehovah will appear to you.", "twenty": "", "jps": "and an ox and a ram for peace-offerings, to sacrifice before HaShem; and a meal-offering mingled with oil; for to-day HaShem appeareth unto you.'", "acv": "and an ox and a ram for peace offerings, to sacrifice before Jehovah, and a meal offering mingled with oil. For today Jehovah appears to you.", "anderson": "", "haweis": "", "noyes": "", "webster": "Also a bullock and a ram for peace-offerings, to sacrifice before the LORD; and a meat-offering mingled with oil: for to-day the LORD will appear to you.", "vulgate": "bovem et arietem pro pacificis et immolate eos coram Domino in sacrificio singulorum similam oleo conspersam offerentes hodie enim Dominus apparebit vobis;", "brenton": "and a calf and a ram for a peace offering before the Lord, and fine flour mingled with oil, for to-day the Lord will appear among you."}}, {"v": 5, "ref": "9:5", "o": "וַ/יִּקְח֗וּ אֵ֚ת אֲשֶׁ֣ר צִוָּ֣ה מֹשֶׁ֔ה אֶל פְּנֵ֖י אֹ֣הֶל מוֹעֵ֑ד וַֽ/יִּקְרְבוּ֙ כָּל הָ֣/עֵדָ֔ה וַ/יַּֽעַמְד֖וּ לִ/פְנֵ֥י יְהוָֽה", "en": {"kjv": "And they brought that which Moses commanded before the tabernacle of the congregation: and all the congregation drew near and stood before the Lord.", "web": "They brought what Moses commanded before the Tent of Meeting: and all the congregation drew near and stood before Yahweh.", "bsb": "So they took what Moses had commanded to the front of the Tent of Meeting, and the whole congregation drew near and stood before the LORD.", "asv": "And they brought that which Moses commanded before the tent of meeting: and all the congregation drew near and stood before Jehovah.", "ylt": "And they take that which Moses hath commanded unto the front of the tent of meeting, and all the company draw near and stand before Jehovah;", "tyndale": "And they brought that which Moses commaunded vnto the tabernacle of witnesse, ad all the people came and stode before the Lorde.", "dra": "They brought therefore all things that Moses had commanded before the door of the tabernacle: where when all the multitude stood,", "bbe": "And they took the things ordered by Moses, before the Tent of meeting, and all the people came near, waiting before the Lord.", "geneva": "Then they brought that which Moses commanded before the Tabernacle of the Congregation, and all the assembly drewe neere and stood before the Lord.", "wycliffe": "Therfor thei token alle thingis, whiche Moises comaundide, to the dore of the tabernacle, where, whanne al the multitude stood,", "rotherham": "So they brought that which Moses commanded before the tent of meeting,—and all the assembly drew near, and stood before Yahweh.", "darby": "And they brought what Moses commanded before the tent of meeting; and all the assembly approached and stood before Jehovah.", "twenty": "", "jps": "And they brought that which Moses commanded before the tent of meeting; and all the congregation drew near and stood before HaShem.", "acv": "And they brought that which Moses commanded before the tent of meeting, and all the congregation drew near and stood before Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And they brought [that] which Moses commanded before the tabernacle of the congregation: and all the congregation drew near and stood before the LORD.", "vulgate": "tulerunt ergo cuncta quae iusserat Moses ad ostium tabernaculi ubi cum omnis staret multitudo;", "brenton": "And they took as Moses commanded them before the tabernacle of witness, and all the congregation drew nigh, and they stood before the Lord."}}, {"v": 6, "ref": "9:6", "o": "וַ/יֹּ֣אמֶר מֹשֶׁ֔ה זֶ֧ה הַ/דָּבָ֛ר אֲשֶׁר צִוָּ֥ה יְהוָ֖ה תַּעֲשׂ֑וּ וְ/יֵרָ֥א אֲלֵי/כֶ֖ם כְּב֥וֹד יְהוָֽה", "en": {"kjv": "And Moses said, This is the thing which the Lord commanded that ye should do: and the glory of the Lord shall appear unto you.", "web": "Moses said, “This is the thing which Yahweh commanded that you should do: and Yahweh’s glory shall appear to you.”", "bsb": "And Moses said, “This is what the LORD has commanded you to do, so that the glory of the LORD may appear to you.”", "asv": "And Moses said, This is the thing which Jehovah commanded that ye should do: and the glory of Jehovah shall appear unto you.", "ylt": "and Moses saith, `This is the thing which Jehovah hath commanded; do it , and the honour of Jehovah doth appear unto you.'", "tyndale": "And Moses sayde, this is the thynge which the Lorde commaunded that ye shulde do: ad then the glorye of the Lorde shall appere vnto you.", "dra": "Moses said: This is the word, which the Lord hath commanded. Do it, and his glory will appear to you.", "bbe": "And Moses said, This is what the Lord has said you are to do; and you will see the glory of the Lord.", "geneva": "(For Moses had sayde, This is the thing, which the Lord commanded that ye should do, and the glory of the Lord shall appeare vnto you)", "wycliffe": "Moises seide, This is the word, which the Lord comaundide, do ye, and his glorie schal appere to you.", "rotherham": "And Moses said—This, is the thing which Yahweh hath commanded that ye shall do,—that the glory of Yahweh may appear unto you.", "darby": "And Moses said, This is the thing which Jehovah has commanded that ye should do; and the glory of Jehovah shall appear to you.", "twenty": "", "jps": "And Moses said: 'This is the thing which HaShem commanded that ye should do; that the glory of HaShem may appear unto you.'", "acv": "And Moses said, This is the thing which Jehovah commanded that ye should do, and the glory of Jehovah shall appear to you.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Moses said, This [is] the thing which the LORD commanded that ye should do: and the glory of the LORD shall appear to you.", "vulgate": "ait Moses iste est sermo quem praecepit Dominus facite et apparebit vobis gloria eius;", "brenton": "And Moses said, This is the thing which the Lord has spoken; do it, and the glory of the Lord shall appear among you."}}, {"v": 7, "ref": "9:7", "o": "וַ/יֹּ֨אמֶר מֹשֶׁ֜ה אֶֽל אַהֲרֹ֗ן קְרַ֤ב אֶל הַ/מִּזְבֵּ֨חַ֙ וַ/עֲשֵׂ֞ה אֶת חַטָּֽאתְ/ךָ֙ וְ/אֶת עֹ֣לָתֶ֔/ךָ וְ/כַפֵּ֥ר בַּֽעַדְ/ךָ֖ וּ/בְעַ֣ד הָ/עָ֑ם וַ/עֲשֵׂ֞ה אֶת קָרְבַּ֤ן הָ/עָם֙ וְ/כַפֵּ֣ר בַּֽעֲדָ֔/ם כַּ/אֲשֶׁ֖ר צִוָּ֥ה יְהוָֽה", "en": {"kjv": "And Moses said unto Aaron, Go unto the altar, and offer thy sin offering, and thy burnt offering, and make an atonement for thyself, and for the people: and offer the offering of the people, and make an atonement for them; as the Lord commanded.", "web": "Moses said to Aaron, “Draw near to the altar, and offer your sin offering, and your burnt offering, and make atonement for yourself, and for the people; and offer the offering of the people, and make atonement for them; as Yahweh commanded.”", "bsb": "Then Moses said to Aaron, “Approach the altar and sacrifice your sin offering and your burnt offering to make atonement for yourself and for the people. And sacrifice the people’s offering to make atonement for them, as the LORD has commanded.”", "asv": "And Moses said unto Aaron, Draw near unto the altar, and offer thy sin-offering, and thy burnt-offering, and make atonement for thyself, and for the people; and offer the oblation of the people, and make atonement for them; as Jehovah commanded.", "ylt": "And Moses saith unto Aaron, `Draw near unto the altar, and make thy sin-offering, and thy burnt-offering, and make atonement for thyself, and for the people, and make the offering of the people, and make atonement for them, as Jehovah hath commanded.'", "tyndale": "And Moses sayde vnto Aaron: go vnto the alter and offer thy synneofferynge, and make an attonement for the and for the people: and then offer the offerynge of the people and reconcyle them also, as the Lorde comaunded Moses.", "dra": "And he said to Aaron: Approach to the altar, and offer sacrifice for thy sin. Offer the holocaust, and pray for thyself and for the people: and when thou hast slain the people's victim, pray for them, as the Lord hath commanded.", "bbe": "And Moses said to Aaron, Come near to the altar and make your sin-offering and your burned offering to take away your sin and the sin of the people, and make the people's offering to take away their sin; as the Lord has given orders.", "geneva": "Then Moses sayd vnto Aaron, Draw neere to the Altar, and offer thy sinne offering, and thy burnt offring, and make an attonement for thee and for the people: offer also the offring of the people, and make an atonement for them, as the Lord hath commanded.", "wycliffe": "And Moises seide to Aaron, Neiye thou to the auter, and offre thou for thi synne; offre thou brent sacrifice, and preye for thee, and for the puple; and whanne thou hast slayn the sacrifice of the puple, preye thou for hem, as the Lord comaundide.", "rotherham": "and Moses said unto Aaron—Draw near unto the altar, and offer thy sin-bearer and thine ascending-sacrifice, and put a propitiatory-covering about thyself and about the people,—and offer the oblation of the people and put a propitiatory-covering about them, As Yahweh hath commanded.", "darby": "And Moses said unto Aaron, Go to the altar, and offer thy sin-offering, and thy burnt-offering, and make atonement for thyself, and for the people; and offer the offering of the people, and make atonement for them, as Jehovah has commanded.", "twenty": "", "jps": "And Moses said unto Aaron: 'Draw near unto the altar, and offer thy sin-offering, and thy burnt-offering, and make atonement for thyself, and for the people; and present the offering of the people, and make atonement for them; as HaShem commanded.'", "acv": "And Moses said to Aaron, Draw near to the altar, and offer thy sin offering, and thy burnt offering, and make atonement for thyself, and for the people. And offer the oblation of the people, and make atonement for them, as Jehovah commanded.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Moses said to Aaron, Go to the altar, and offer thy sin-offering, and thy burnt-offering, and make an atonement for thyself, and for the people: and offer the offering of the people, and make an atonement for them; as the LORD commanded.", "vulgate": "dixit et ad Aaron accede ad altare et immola pro peccato tuo offer holocaustum et deprecare pro te et pro populo cumque mactaveris hostiam populi ora pro eo sicut praecepit Dominus;", "brenton": "And Moses said to Aaron, Draw nigh to the altar, and offer thy sin-offering, and thy whole-burnt-offering, and make atonement for thyself, and for thy house; and offer the gifts of the people, and make atonement for them, as the Lord commanded Moses."}}, {"v": 8, "ref": "9:8", "o": "וַ/יִּקְרַ֥ב אַהֲרֹ֖ן אֶל הַ/מִּזְבֵּ֑חַ וַ/יִּשְׁחַ֛ט אֶת עֵ֥גֶל הַ/חַטָּ֖את אֲשֶׁר לֽ/וֹ", "en": {"kjv": "Aaron therefore went unto the altar, and slew the calf of the sin offering, which was for himself.", "web": "So Aaron drew near to the altar, and killed the calf of the sin offering, which was for himself.", "bsb": "So Aaron approached the altar and slaughtered the calf as a sin offering for himself.", "asv": "So Aaron drew near unto the altar, and slew the calf of the sin-offering, which was for himself.", "ylt": "And Aaron draweth near unto the altar, and slaughtereth the calf of the sin-offering, which is for himself;", "tyndale": "And Aaron went vnto the alter, and slewe the calfe that was his synneoffrynge.", "dra": "And forthwith Aaron, approaching to the altar, immolated the calf for his sin.", "bbe": "So Aaron came near to the altar and put to death the ox for the sin-offering for himself;", "geneva": "Aaron therefore went vnto the Altar, and killed the calfe of the sinne offring, which was for himselfe.", "wycliffe": "And anoon Aaron neiyede to the auter, and offride a calf for his synne;", "rotherham": "So Aaron drew near unto the altar,—and slew the sin-bearing calf which was for himself;", "darby": "And Aaron went to the altar and slaughtered the calf of the sin-offering which was for himself;", "twenty": "", "jps": "So Aaron drew near unto the altar, and slew the calf of the sin-offering, which was for himself.", "acv": "So Aaron drew near to the altar, and killed the calf of the sin offering, which was for himself.", "anderson": "", "haweis": "", "noyes": "", "webster": "Aaron therefore went to the altar, and slew the calf of the sin-offering, which [was] for himself.", "vulgate": "statimque Aaron accedens ad altare immolavit vitulum pro peccato suo;", "brenton": "And Aaron drew nigh to the altar, and slew the calf of his sin-offering."}}, {"v": 9, "ref": "9:9", "o": "וַ֠/יַּקְרִבוּ בְּנֵ֨י אַהֲרֹ֣ן אֶת הַ/דָּם֮ אֵלָי/ו֒ וַ/יִּטְבֹּ֤ל אֶצְבָּע/וֹ֙ בַּ/דָּ֔ם וַ/יִּתֵּ֖ן עַל קַרְנ֣וֹת הַ/מִּזְבֵּ֑חַ וְ/אֶת הַ/דָּ֣ם יָצַ֔ק אֶל יְס֖וֹד הַ/מִּזְבֵּֽחַ", "en": {"kjv": "And the sons of Aaron brought the blood unto him: and he dipped his finger in the blood, and put it upon the horns of the altar, and poured out the blood at the bottom of the altar:", "web": "The sons of Aaron presented the blood to him; and he dipped his finger in the blood, and put it on the horns of the altar, and poured out the blood at the base of the altar:", "bsb": "The sons of Aaron brought the blood to him, and he dipped his finger in the blood and applied it to the horns of the altar. And he poured out the rest of the blood at the base of the altar.", "asv": "And the sons of Aaron presented the blood unto him; and he dipped his finger in the blood, and put it upon the horns of the altar, and poured out the blood at the base of the altar:", "ylt": "and the sons of Aaron bring the blood near unto him, and he dippeth his finger in the blood, and putteth it on the horns of the altar, and the blood he hath poured out at the foundation of the altar;", "tyndale": "And the sonnes of Aaron broughte the bloude vnto him, and he dypte his finger in the bloude and put it apon the hornes of the alter, and poured the bloude vnto the botome of the alter.", "dra": "And his sons brought him the blood of it: and he dipped his finger therein, and touched the horns of the altar, and poured the rest at the foot thereof.", "bbe": "And the sons of Aaron gave him the blood and he put his finger in the blood and put it on the horns of the altar, draining out the blood at the base of the altar;", "geneva": "And the sonnes of Aaron brought ye blood vnto him, and he dipt his finger in the blood, and put it vpon the hornes of the Altar, and powred the rest of the blood at the foote of the Altar.", "wycliffe": "whos blood hise sones offriden to him, in which blood he dippide the fyngur, and touchide the hornes of the auter , and schedde the residue at the foundement therof;", "rotherham": "and the sons of Aaron brought the blood unto him, and he dipped his finger in the blood, and put [thereof] upon the horns of the altar,—and the [remainder of the] blood, poured he out at the base of the altar;", "darby": "and the sons of Aaron presented the blood to him, and he dipped his finger in the blood, and put [it] on the horns of the altar, and poured out the blood at the bottom of the altar.", "twenty": "", "jps": "And the sons of Aaron presented the blood unto him; and he dipped his finger in the blood, and put it upon the horns of the altar, and poured out the blood at the base of the altar.", "acv": "And the sons of Aaron presented the blood to him, and he dipped his finger in the blood, and put it upon the horns of the altar, and poured out the blood at the base of the altar,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the sons of Aaron brought the blood to him: and he dipped his finger in the blood, and put [it] upon the horns of the altar, and poured out the blood at the bottom of the altar:", "vulgate": "cuius sanguinem obtulerunt ei filii sui in quo tinguens digitum tetigit cornua altaris et fudit residuum ad basim eius;", "brenton": "And the sons of Aaron brought the blood to him, and he dipped his finger into the blood, and put it on the horns of the altar, and he poured out the blood at the bottom of the altar."}}, {"v": 10, "ref": "9:10", "o": "וְ/אֶת הַ/חֵ֨לֶב וְ/אֶת הַ/כְּלָיֹ֜ת וְ/אֶת הַ/יֹּתֶ֤רֶת מִן הַ/כָּבֵד֙ מִן הַ֣/חַטָּ֔את הִקְטִ֖יר הַ/מִּזְבֵּ֑חָ/ה כַּ/אֲשֶׁ֛ר צִוָּ֥ה יְהוָ֖ה אֶת מֹשֶֽׁה", "en": {"kjv": "But the fat, and the kidneys, and the caul above the liver of the sin offering, he burnt upon the altar; as the Lord commanded Moses.", "web": "but the fat, and the kidneys, and the cover from the liver of the sin offering, he burned upon the altar; as Yahweh commanded Moses.", "bsb": "On the altar he burned the fat, the kidneys, and the lobe of the liver from the sin offering, as the LORD had commanded Moses.", "asv": "but the fat, and the kidneys, and the caul from the liver of the sin-offering, he burnt upon the altar; as Jehovah commanded Moses.", "ylt": "and the fat, and the kidneys, and the redundance of the liver, of the sin-offering, he hath made a perfume on the altar, as Jehovah hath commanded Moses;", "tyndale": "And the fatt and the two kydneyes with the kall of the lyuer of the synneoffrynge, he burnt vppon the alter, as the Lorde commaunded Moses:", "dra": "And the fat, and the little kidneys, and the caul of the liver, which are for sin, he burnt upon the altar, as the Lord had commanded Moses.", "bbe": "But the fat and the kidneys and the fat on the liver of the sin-offering were burned by him on the altar as the Lord gave orders to Moses.", "geneva": "But the fat and the kidneis and the kall of the liuer of the sinne offring, he burnt vpon the Altar, as the Lord had commanded Moses.", "wycliffe": "and he brente on the auter the ynnere fatnesse, and litle reynes, and the calle of the mawe, as the Lord comaundide to Moises.", "rotherham": "and with the fat and the kidneys and the caul a from the liver, of the sin-bearer, made he a perfume at the altar,—As Yahweh commanded Moses.", "darby": "And the fat, and the kidneys, and the net above the liver, of the sin-offering, he burned on the altar, as Jehovah had commanded Moses.", "twenty": "", "jps": "But the fat, and the kidneys, and the lobe of the liver of the sin-offering, he made smoke upon the altar; as HaShem commanded Moses.", "acv": "but he burnt the fat, and the kidneys, and the caul from the liver of the sin offering, upon the altar, as Jehovah commanded Moses.", "anderson": "", "haweis": "", "noyes": "", "webster": "But the fat, and the kidneys, and the caul above the liver of the sin-offering, he burnt upon the altar; as the LORD commanded Moses.", "vulgate": "adipemque et renunculos ac reticulum iecoris quae sunt pro peccato adolevit super altare sicut praeceperat Dominus Mosi;", "brenton": "And he offered up on the altar the fat and the kidneys and the lobe of the liver of the sin-offering, according as the Lord commanded Moses."}}, {"v": 11, "ref": "9:11", "o": "וְ/אֶת הַ/בָּשָׂ֖ר וְ/אֶת הָ/ע֑וֹר שָׂרַ֣ף בָּ/אֵ֔שׁ מִ/ח֖וּץ לַֽ/מַּחֲנֶֽה", "en": {"kjv": "And the flesh and the hide he burnt with fire without the camp.", "web": "The flesh and the skin he burned with fire outside the camp.", "bsb": "But he burned up the flesh and the hide outside the camp.", "asv": "And the flesh and the skin he burnt with fire without the camp.", "ylt": "and the flesh and the skin he hath burnt with fire, at the outside of the camp.", "tyndale": "but the flesh and the hyde he burnt with fyre without the hoste.", "dra": "But the flesh and skins thereof he burnt with fire without the camp.", "bbe": "And the flesh and the skin were burned with fire outside the tent-circle;", "geneva": "The flesh also and the hide hee burnt with fire without the hoste.", "wycliffe": "Forsothe he brente bi fier without the castels the fleischis and skyn therof.", "rotherham": "But, the flesh and the skin, consumed he with fire, outside the camp.", "darby": "And the flesh and the skin he burned with fire outside the camp.", "twenty": "", "jps": "And the flesh and the skin were burnt with fire without the camp.", "acv": "And he burnt the flesh and the skin with fire outside the camp.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the flesh and the hide he burnt with fire without the camp.", "vulgate": "carnes vero et pellem eius extra castra conbusit igni;", "brenton": "And the flesh and the hide he burnt with fire outside of the camp."}}, {"v": 12, "ref": "9:12", "o": "וַ/יִּשְׁחַ֖ט אֶת הָ/עֹלָ֑ה וַ֠/יַּמְצִאוּ בְּנֵ֨י אַהֲרֹ֤ן אֵלָי/ו֙ אֶת הַ/דָּ֔ם וַ/יִּזְרְקֵ֥/הוּ עַל הַ/מִּזְבֵּ֖חַ סָבִֽיב", "en": {"kjv": "And he slew the burnt offering; and Aaron’s sons presented unto him the blood, which he sprinkled round about upon the altar.", "web": "He killed the burnt offering; and Aaron’s sons delivered the blood to him, and he sprinkled it around on the altar.", "bsb": "Then Aaron slaughtered the burnt offering. His sons brought him the blood, and he sprinkled it on all sides of the altar.", "asv": "And he slew the burnt-offering; and Aaron’s sons delivered unto him the blood, and he sprinkled it upon the altar round about.", "ylt": "And he slaughtereth the burnt-offering, and the sons of Aaron have presented unto him the blood, and he sprinkleth it on the altar round about;", "tyndale": "After warde he slewe the burntofferynge, ad Aarons sonnes brought the bloude vnto him, and he sprinkled it rounde aboute apon the alter.", "dra": "He immolated also the victim of holocaust: and his sons brought him the blood thereof, which he poured round about on the altar.", "bbe": "And he put to death the burned offering; and Aaron's sons gave him the blood and he put some of it on and round the altar;", "geneva": "After, he slewe the burnt offering, and Aarons sonnes brought vnto him the blood, which he sprinckled round about vpon the Altar.", "wycliffe": "And he offride the beeste of brent sacrifice, and hise sones offriden to hym the blood therof, which he schedde bi the cumpas of the auter;", "rotherham": "Then slew he the ascending-sacrifice,—and the sons of Aaron presented unto him the blood, and he dashed it against the altar round about.", "darby": "And he slaughtered the burnt-offering; and Aaron's sons delivered to him the blood, which he sprinkled on the altar round about.", "twenty": "", "jps": "And he slew the burnt-offering; and Aaron's sons delivered unto him the blood, and he dashed it against the altar round about.", "acv": "And he killed the burnt offering. And Aaron's sons delivered to him the blood, and he sprinkled it upon the altar round about.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he slew the burnt-offering; and Aaron's sons presented to him the blood, which he sprinkled around upon the altar.", "vulgate": "immolavit et holocausti victimam obtuleruntque ei filii sui sanguinem eius quem fudit per altaris circuitum;", "brenton": "And he slew the whole-burnt-offering; and the sons of Aaron brought the blood to him, and he poured it on the altar round about."}}, {"v": 13, "ref": "9:13", "o": "וְ/אֶת הָ/עֹלָ֗ה הִמְצִ֧יאוּ אֵלָ֛י/ו לִ/נְתָחֶ֖י/הָ וְ/אֶת הָ/רֹ֑אשׁ וַ/יַּקְטֵ֖ר עַל הַ/מִּזְבֵּֽחַ", "en": {"kjv": "And they presented the burnt offering unto him, with the pieces thereof, and the head: and he burnt them upon the altar.", "web": "They delivered the burnt offering to him, piece by piece, and the head: and he burned them upon the altar.", "bsb": "They brought him the burnt offering piece by piece, including the head, and he burned them on the altar.", "asv": "And they delivered the burnt-offering unto him, piece by piece, and the head: and he burnt them upon the altar.", "ylt": "and the burnt-offering they have presented unto him, by its pieces, and the head, and he maketh perfume on the altar;", "tyndale": "And they brought the burntofferynge vnto him in peces and the heed also and he burnt it apon the alter", "dra": "And the victim being cut into pieces, they brought to him the head and all the members: all which he burnt with fire upon the altar.", "bbe": "And they gave him the parts of the burned offering, in their order, and the head, to be burned on the altar.", "geneva": "Also they brought the burnt offring vnto him with the pieces thereof, and the head, and he burnt them vpon the Altar.", "wycliffe": "thei offriden also thilke sacrifice kit in to gobetis, with the heed, and alle membris; and he brente bi fier alle these thingis on the auter,", "rotherham": "And the ascending-sacrifice, presented they unto him piece by piece thereof also the head,—and he made a perfume upon the altar:", "darby": "And they delivered the burnt-offering to him, in the pieces thereof, and the head; and he burned [them] on the altar.", "twenty": "", "jps": "And they delivered the burnt-offering unto him, piece by piece, and the head; and he made them smoke upon the altar.", "acv": "And they delivered the burnt offering to him, piece by piece, and the head, and he burnt them upon the altar.", "anderson": "", "haweis": "", "noyes": "", "webster": "And they presented the burnt-offering to him, with the pieces of it, and the head: and he burnt [them] upon the altar.", "vulgate": "ipsam etiam hostiam in frusta concisam cum capite et membris singulis obtulerunt quae omnia super altare cremavit igni;", "brenton": "And they brought the whole-burnt-offering, according to its pieces; them and the head he put upon the altar."}}, {"v": 14, "ref": "9:14", "o": "וַ/יִּרְחַ֥ץ אֶת הַ/קֶּ֖רֶב וְ/אֶת הַ/כְּרָעָ֑יִם וַ/יַּקְטֵ֥ר עַל הָ/עֹלָ֖ה הַ/מִּזְבֵּֽחָ/ה", "en": {"kjv": "And he did wash the inwards and the legs, and burnt them upon the burnt offering on the altar.", "web": "He washed the innards and the legs, and burned them on the burnt offering on the altar.", "bsb": "He washed the entrails and the legs and burned them atop the burnt offering on the altar.", "asv": "And he washed the inwards and the legs, and burnt them upon the burnt-offering on the altar.", "ylt": "and he washeth the inwards and the legs, and maketh perfume for the burnt-offering on the altar.", "tyndale": "and dyd wasshe the inwardes and the legges and burnt them also apon the burntofferynge in the alter.", "dra": "Having first washed the entrails and the feet with water.", "bbe": "And the inside parts and the legs, when they had been washed with water, were burned on the burned offering on the altar.", "geneva": "Likewise he did wash the inwardes and the legs, and burnt them vpon the burnt offring on the Altar.", "wycliffe": "whanne the entrailis and feet weren waischun bifor with watir.", "rotherham": "and he bathed the inwards and the legs,—and made a perfume upon the ascending-sacrifice at the altar.", "darby": "And he washed the inwards and the legs, and burned [them] upon the burnt-offering, on the altar.", "twenty": "", "jps": "And he washed the inwards and the legs, and made them smoke upon the burnt-offering on the altar.", "acv": "And he washed the innards and the legs, and burnt them upon the burnt offering on the altar.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he washed the inwards and the legs, and burnt [them] upon the burnt-offering on the altar.", "vulgate": "lotis prius aqua intestinis et pedibus;", "brenton": "And he washed the belly and the feet with water, and he put them on the whole-burnt-offering on the altar."}}, {"v": 15, "ref": "9:15", "o": "וַ/יַּקְרֵ֕ב אֵ֖ת קָרְבַּ֣ן הָ/עָ֑ם וַ/יִּקַּ֞ח אֶת שְׂעִ֤יר הַֽ/חַטָּאת֙ אֲשֶׁ֣ר לָ/עָ֔ם וַ/יִּשְׁחָטֵ֥/הוּ וַֽ/יְחַטְּאֵ֖/הוּ כָּ/רִאשֽׁוֹן", "en": {"kjv": "And he brought the people’s offering, and took the goat, which was the sin offering for the people, and slew it, and offered it for sin, as the first.", "web": "He presented the people’s offering, and took the goat of the sin offering which was for the people, and killed it, and offered it for sin, like the first.", "bsb": "Aaron then presented the people’s offering. He took the male goat for the people’s sin offering, slaughtered it, and offered it for sin like the first one.", "asv": "And he presented the people’s oblation, and took the goat of the sin-offering which was for the people, and slew it, and offered it for sin, as the first.", "ylt": "And he bringeth near the offering of the people, and taketh the goat of the sin-offering which is for the people, and slaughtered it, and maketh it a sin-offering, like the first;", "tyndale": "And than he broughte the peoples offerynge and toke the goote that was the peoples synneofferynge and slewe it and offered it for a synofferynge: as he dyd the first.", "dra": "Then offering for the sin of the people, he slew the he goat: and expiating the altar,", "bbe": "And he made an offering for the people and took the goat of the sin-offering for the people and put it to death, offering it for sin, in the same way as the first.", "geneva": "Then he offred the peoples offring, and tooke a goate, which was the sinne offring for the people, and slewe it: and offred it for sinne, as the first:", "wycliffe": "And he offride and killide a buk of geet, for the synne of the puple; and whanne the auter was clensid,", "rotherham": "Then brought he near the oblation of the people,—and took the sin-bearing goat which pertained to the people, and slew it and made therewith a sin-bearer, like the first.", "darby": "And he presented the people's offering, and took the goat of the sin-offering which was for the people and slaughtered it, and offered it for sin, as the first.", "twenty": "", "jps": "And the people's offering was presented; and he took the goat of the sin-offering which was for the people, and slew it, and offered it for sin, as the first.", "acv": "And he presented the people's oblation. And took the goat of the sin offering which was for the people, and killed it, and offered it for sin, as the first.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he brought the people's offering, and took the goat, which [was] the sin-offering for the people, and slew it, and offered it for sin, as the first.", "vulgate": "et pro peccato populi offerens mactavit hircum expiatoque altari;", "brenton": "And he brought the gift of the people, and took the goat of the sin-offering of the people, and slew it, and purified it as also the first."}}, {"v": 16, "ref": "9:16", "o": "וַ/יַּקְרֵ֖ב אֶת הָ/עֹלָ֑ה וַֽ/יַּעֲשֶׂ֖/הָ כַּ/מִּשְׁפָּֽט", "en": {"kjv": "And he brought the burnt offering, and offered it according to the manner.", "web": "He presented the burnt offering, and offered it according to the ordinance.", "bsb": "He presented the burnt offering and offered it according to the ordinance.", "asv": "And he presented the burnt-offering, and offered it according to the ordinance.", "ylt": "and he bringeth near the burnt-offering, and maketh it, according to the ordinance;", "tyndale": "And then broughte the burntofferynge and offered it as the maner", "dra": "He offered the holocaust.", "bbe": "And he took the burned offering, offering it in the ordered way;", "geneva": "So he offred the burnt offring, and prepared it, according to the maner.", "wycliffe": "he made brent sacrifice,", "rotherham": "Then brought he near the ascending-sacrifice,—and offered it, according to the regulation,", "darby": "And he presented the burnt-offering and offered it according to the ordinance.", "twenty": "", "jps": "And the burnt-offering was presented; and he offered it according to the ordinance.", "acv": "And he presented the burnt offering, and offered it according to the ordinance.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he brought the burnt-offering, and offered it according to the manner.", "vulgate": "fecit holocaustum;", "brenton": "And he brought the whole-burnt-offering, and offered it in due form."}}, {"v": 17, "ref": "9:17", "o": "וַ/יַּקְרֵב֮ אֶת הַ/מִּנְחָה֒ וַ/יְמַלֵּ֤א כַפּ/וֹ֙ מִמֶּ֔/נָּה וַ/יַּקְטֵ֖ר עַל הַ/מִּזְבֵּ֑חַ מִ/לְּ/בַ֖ד עֹלַ֥ת הַ/בֹּֽקֶר", "en": {"kjv": "And he brought the meat offering, and took an handful thereof, and burnt it upon the altar, beside the burnt sacrifice of the morning.", "web": "He presented the meal offering, and filled his hand from there, and burned it upon the altar, besides the burnt offering of the morning.", "bsb": "Next he presented the grain offering, took a handful of it, and burned it on the altar in addition to the morning’s burnt offering.", "asv": "And he presented the meal-offering, and filled his hand therefrom, and burnt it upon the altar, besides the burnt-offering of the morning.", "ylt": "and he bringeth near the present, and filleth his palm with it, and maketh perfume on the altar, apart from the burnt-offering of the morning.", "tyndale": "was and broughte the meatofferynge and fylled his hande thereof, and burnt it apon the alter besydes the burntsacrifyce in the mornynge:", "dra": "Adding in the sacrifice the libations, which are offered withal, and burning them upon the altar, besides the ceremonies of the morning holocaust.", "bbe": "And he put the meal offering before the Lord, and taking some of it in his hand he had it burned on the altar, separately from the burned offering of the morning.", "geneva": "He presented also the meate offring, and filled his hand thereof, and beside the burnt sacrifice of the morning he burnt this vpon the Altar.", "wycliffe": "and addide in to the sacrifice fletynge offryngis that ben offrid togidere; and he brente tho on the auter, without cerymonyes of brent sacrifice of the morewtid.", "rotherham": "Then brought he near the meal-offering, and filled his hand therefrom, and made a perfume upon the altar,—in addition to the ascending-sacrifice of the morning.", "darby": "And he presented the oblation, and took a handful of it, and burned it on the altar, besides the burnt-offering of the morning.", "twenty": "", "jps": "And the meal-offering was presented; and he filled his hand therefrom, and made it smoke upon the altar, besides the burnt-offering of the morning.", "acv": "And he presented the meal offering, and filled his hand from it, and burnt it upon the altar, besides the burnt offering of the morning.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he brought the meat-offering, and took a handful of it, and burnt [it] upon the altar, beside the burnt-sacrifice of the morning.", "vulgate": "addens in sacrificio libamenta quae pariter offeruntur et adolens ea super altare absque caerimoniis holocausti matutini;", "brenton": "And he brought the sacrifice and filled his hands with it, and laid it on the altar, besides the morning whole-burnt-offering."}}, {"v": 18, "ref": "9:18", "o": "וַ/יִּשְׁחַ֤ט אֶת הַ/שּׁוֹר֙ וְ/אֶת הָ/אַ֔יִל זֶ֥בַח הַ/שְּׁלָמִ֖ים אֲשֶׁ֣ר לָ/עָ֑ם וַ֠/יַּמְצִאוּ בְּנֵ֨י אַהֲרֹ֤ן אֶת הַ/דָּם֙ אֵלָ֔י/ו וַ/יִּזְרְקֵ֥/הוּ עַל הַ/מִּזְבֵּ֖חַ סָבִֽיב", "en": {"kjv": "He slew also the bullock and the ram for a sacrifice of peace offerings, which was for the people: and Aaron’s sons presented unto him the blood, which he sprinkled upon the altar round about,", "web": "He also killed the bull and the ram, the sacrifice of peace offerings, which was for the people: and Aaron’s sons delivered to him the blood, which he sprinkled around on the altar,", "bsb": "Then he slaughtered the ox and the ram as the people’s peace offering. His sons brought him the blood, and he sprinkled it on all sides of the altar.", "asv": "He slew also the ox and the ram, the sacrifice of peace-offerings, which was for the people: and Aaron’s sons delivered unto him the blood, which he sprinkled upon the altar round about,", "ylt": "And he slaughtereth the bullock and the ram, a sacrifice of the peace-offerings, which are for the people, and sons of Aaron present the blood unto him (and he sprinkleth it on the altar round about),", "tyndale": "Then he slewe the oxe and the ram that were the peoples peaseofferynges and Aarons sonnes broughte the bloude vnto him and he sprinkled it apon the alter rounde aboute,", "dra": "He immolated also the bullock and the ram, and peace offerings of the people: and his sons brought him the blood, which he poured upon the altar round about.", "bbe": "And he put to death the ox and the sheep, which were the peace-offerings for the people; and Aaron's sons gave him the blood and he put some of it on and round the altar;", "geneva": "He slewe also the bullock, and the ram for the peace offrings, that was for the people, and Arons sonnes brought vnto him the blood, which he sprinkled vpon the Altar round about,", "wycliffe": "He offride also an oxe, and a ram, pesible sacrifices of the puple; and hise sones offriden to hym the blood, which he schedde bi the cumpas of the auter.", "rotherham": "Then slew he the ox, and the ram, as a peace-offering, which pertained unto the people,—and the sons of Aaron presented the blood unto him, and he dashed it against the altar, round about;", "darby": "And he slaughtered the bullock and the ram of the sacrifice of peace-offering which was for the people. And Aaron's sons delivered to him the blood, and he sprinkled it on the altar round about;", "twenty": "", "jps": "He slew also the ox and the ram, the sacrifice of peace-offerings, which was for the people; and Aaron's sons delivered unto him the blood, and he dashed it against the altar round about,", "acv": "He also killed the ox and the ram, the sacrifice of peace offerings, which was for the people. And Aaron's sons delivered to him the blood, which he sprinkled upon the altar round about,", "anderson": "", "haweis": "", "noyes": "", "webster": "He slew also the bullock and the ram [for] a sacrifice of peace-offerings, which [was] for the people: and Aaron's sons presented to him the blood, which he sprinkled around upon the altar,", "vulgate": "immolavit et bovem atque arietem hostias pacificas populi obtuleruntque ei filii sui sanguinem quem fudit super altare in circuitu;", "brenton": "And he slew the calf, and the ram of the sacrifice of peace-offering of the people; and the sons of Aaron brought the blood to him, and he poured it out on the altar round about."}}, {"v": 19, "ref": "9:19", "o": "וְ/אֶת הַ/חֲלָבִ֖ים מִן הַ/שּׁ֑וֹר וּ/מִן הָ/אַ֔יִל הָֽ/אַלְיָ֤ה וְ/הַֽ/מְכַסֶּה֙ וְ/הַ/כְּלָיֹ֔ת וְ/יֹתֶ֖רֶת הַ/כָּבֵֽד", "en": {"kjv": "And the fat of the bullock and of the ram, the rump, and that which covereth the inwards, and the kidneys, and the caul above the liver:", "web": "and the fat of the bull and of the ram, the fat tail, and that which covers the innards, and the kidneys, and the cover of the liver:", "bsb": "They also brought the fat portions from the ox and the ram—the fat tail, the fat covering the entrails, the kidneys, and the lobe of the liver—", "asv": "and the fat of the ox and of the ram, the fat tail, and that which covereth the inwards, and the kidneys, and the caul of the liver:", "ylt": "and the fat of the bullock, and of the ram, the fat tail, and the covering of the inwards , and the kidneys, and the redundance above the liver,", "tyndale": "and toke the fatt of the oxe and of the ram: the rope and the fatt that couereth the inwardes and the kydneyes and the kall of the lyuer:", "dra": "The fat also of the bullock, and the rump of the ram, and the two little kidneys with their fat, and the caul of the liver,", "bbe": "And as for the fat of the ox and the fat tail of the sheep and the fat covering the inside parts and the kidneys and the fat on the liver;", "geneva": "With the fat of the bullocke, and of the ram, the rumpe, and that which couereth the inwards and the kidneis, and the kall of the liuer.", "wycliffe": "Forsothe thei puttiden on the brestis the ynnere fatnesse of the oxe, and the tail of the ram, and the litle reynes with her fatnessis, and the calle of the mawe.", "rotherham": "and the portions of fat from the ox,—and from the ram, the fat-tail, and the covering, and the kidneys, and the caul of the liver;", "darby": "and the pieces of fat of the bullock and of the ram, the fat tail and what covers [the inwards], and the kidneys, and the net of the liver;", "twenty": "", "jps": "and the fat of the ox, and of the ram, the fat tail, and that which covereth the inwards, and the kidneys, and the lobe of the liver.", "acv": "and the fat of the ox and of the ram, the fat tail, and that which covers the innards, and the kidneys, and the caul of the liver.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the fat of the bullock, and of the ram, the rump, and that which covereth [the inwards], and the kidneys, and the caul [above] the liver:", "vulgate": "adipes autem bovis et caudam arietis renunculosque cum adipibus suis et reticulum iecoris;", "brenton": "And he took the fat of the calf, and the hind quarters of the ram, and the fat covering the belly, and the two kidneys, and the fat upon them, and the caul on the liver."}}, {"v": 20, "ref": "9:20", "o": "וַ/יָּשִׂ֥ימוּ אֶת הַ/חֲלָבִ֖ים עַל הֶ/חָז֑וֹת וַ/יַּקְטֵ֥ר הַ/חֲלָבִ֖ים הַ/מִּזְבֵּֽחָ/ה", "en": {"kjv": "And they put the fat upon the breasts, and he burnt the fat upon the altar:", "web": "and they put the fat upon the breasts, and he burned the fat on the altar:", "bsb": "and placed these on the breasts. Aaron burned the fat portions on the altar,", "asv": "and they put the fat upon the breasts, and he burnt the fat upon the altar:", "ylt": "and they set the fat on the breasts, and he maketh perfume with the fat on the altar;", "tyndale": "and put them apon the brestes and burnt it apon the alter:", "dra": "They put upon the breasts. And after the fat was burnt upon the altar,", "bbe": "They put the fat on the breasts, and the fat was burned on the altar.", "geneva": "So they layed the fat vpon the breasts, and he burnt the fat vpon the Altar.", "wycliffe": "And whanne the ynnere fatnessis weren brent in the auter,", "rotherham": "and they put the portions of fat upon the breasts,—and he made a perfume with the fat at the altar;", "darby": "and they put the pieces of fat on the breast-pieces, and he burned the pieces of fat on the altar;", "twenty": "", "jps": "And they put the fat upon the breasts, and he made the fat smoke upon the altar.", "acv": "And they put the fat upon the breasts, and he burnt the fat upon the altar.", "anderson": "", "haweis": "", "noyes": "", "webster": "And they put the fat upon the breasts, and he burnt the fat upon the altar:", "vulgate": "posuerunt super pectora cumque cremati essent adipes in altari;", "brenton": "And he put the fat on the breasts, and offered the fat on the altar."}}, {"v": 21, "ref": "9:21", "o": "וְ/אֵ֣ת הֶ/חָז֗וֹת וְ/אֵת֙ שׁ֣וֹק הַ/יָּמִ֔ין הֵנִ֧יף אַהֲרֹ֛ן תְּנוּפָ֖ה לִ/פְנֵ֣י יְהוָ֑ה כַּ/אֲשֶׁ֖ר צִוָּ֥ה מֹשֶֽׁה", "en": {"kjv": "And the breasts and the right shoulder Aaron waved for a wave offering before the Lord; as Moses commanded.", "web": "and the breasts and the right thigh Aaron waved for a wave offering before Yahweh, as Moses commanded.", "bsb": "but he waved the breasts and the right thigh as a wave offering before the LORD, as Moses had commanded.", "asv": "and the breasts and the right thigh Aaron waved for a wave-offering before Jehovah; as Moses commanded.", "ylt": "and the breasts, and the right leg hath Aaron waved--a wave-offering before Jehovah, as He hath commanded Moses.", "tyndale": "but the brestes and the righte shulders Aaron waued before the Lorde as the Lorde comaunded Moses.", "dra": "Aaron separated their breasts, and the right shoulders, elevating them before the Lord, as Moses had commanded.", "bbe": "And Aaron took the breasts and the right leg, waving them for a wave offering before the Lord, as Moses gave orders.", "geneva": "But the breastes and the right shoulder Aaron shooke to and from before the Lord, as the Lord had commanded Moses.", "wycliffe": "Aaron departide the brestis, and the riyt schuldris of tho, and reiside bifor the Lord, as Moises comaundide.", "rotherham": "but the breasts and the right shoulder, did Aaron wave as a wave-offering, before Yahweh,—as Moses commanded,", "darby": "and the breast-pieces and the right shoulder Aaron waved as a wave-offering before Jehovah, as Moses had commanded.", "twenty": "", "jps": "And the breasts and the right thigh Aaron waved for a wave-offering before HaShem; as Moses commanded.", "acv": "And the breasts and the right thigh Aaron waved for a wave offering before Jehovah, as Moses commanded.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the breasts and the right shoulder Aaron waved [for] a wave-offering before the LORD; as Moses commanded.", "vulgate": "pectora eorum et armos dextros separavit Aaron elevans coram Domino sicut praeceperat Moses;", "brenton": "And Aaron separated the breast and the right shoulder as a choice-offering before the Lord, as the Lord commanded Moses."}}, {"v": 22, "ref": "9:22", "o": "וַ/יִּשָּׂ֨א אַהֲרֹ֧ן אֶת יד/ו יָדָ֛י/ו אֶל הָ/עָ֖ם וַֽ/יְבָרְכֵ֑/ם וַ/יֵּ֗רֶד מֵ/עֲשֹׂ֧ת הַֽ/חַטָּ֛את וְ/הָ/עֹלָ֖ה וְ/הַ/שְּׁלָמִֽים", "en": {"kjv": "And Aaron lifted up his hand toward the people, and blessed them, and came down from offering of the sin offering, and the burnt offering, and peace offerings.", "web": "Aaron lifted up his hands toward the people, and blessed them; and he came down from offering the sin offering, and the burnt offering, and the peace offerings.", "bsb": "Aaron lifted up his hands toward the people and blessed them. And having made the sin offering, the burnt offering, and the peace offering, he stepped down.", "asv": "And Aaron lifted up his hands toward the people, and blessed them; and he came down from offering the sin-offering, and the burnt-offering, and the peace-offerings.", "ylt": "And Aaron lifteth up his hand towards the people, and blesseth them, and cometh down from making the sin-offering, and the burnt-offering, and the peace-offerings.", "tyndale": "And Aaron lifte vpp his hande ouer the people and blessed the, and came doune from offerynge of synofferynges burntofferynges ad peaseofferynges.", "dra": "And stretching forth his hands to the people, he blessed them. And so the victims for sin, and the holocausts, and the peace offerings being finished, he came down.", "bbe": "And Aaron, lifting up his hands to the people, gave them a blessing; and he came down from offering the sin-offering, and the burned offering, and the peace-offerings.", "geneva": "So Aaron lift vp his hand toward the people, and blessed them, and came downe from offring of the sinne offring, and the burnt offring, and the peace offrings.", "wycliffe": "And he streiyte forth hondis to the puple, and blesside it; and so whanne the sacrifices for synne, and brent sacrifices, and pesible sacrifices, weren fillid, he cam doun.", "rotherham": "Then Aaron lifted up his hands towards the people, and blessed them,—and he came down from offering the sin-bearer, and the ascending-sacrifice and the peace-offering.", "darby": "And Aaron lifted up his hands toward the people and blessed them, and came down after the offering of the sin-offering, and the burnt-offering, and the peace-offering.", "twenty": "", "jps": "And Aaron lifted up his hands toward the people, and blessed them; and he came down from offering the sin-offering, and the burnt-offering, and the peace-offerings.", "acv": "And Aaron lifted up his hands toward the people, and blessed them. And he came down from offering the sin offering, and the burnt offering, and the peace offerings.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Aaron lifted up his hand towards the people, and blessed them; and came down from offering the sin-offering, and the burnt-offering, and peace-offerings.", "vulgate": "et tendens manum contra populum benedixit eis sicque conpletis hostiis pro peccato et holocaustis et pacificis descendit;", "brenton": "And Aaron lifted up his hands on the people and blessed them; and after he had offered the sin-offering, and the whole-burnt-offerings, and the peace-offerings, he came down."}}, {"v": 23, "ref": "9:23", "o": "וַ/יָּבֹ֨א מֹשֶׁ֤ה וְ/אַהֲרֹן֙ אֶל אֹ֣הֶל מוֹעֵ֔ד וַ/יֵּ֣צְא֔וּ וַֽ/יְבָרֲכ֖וּ אֶת הָ/עָ֑ם וַ/יֵּרָ֥א כְבוֹד יְהוָ֖ה אֶל כָּל הָ/עָֽם", "en": {"kjv": "And Moses and Aaron went into the tabernacle of the congregation, and came out, and blessed the people: and the glory of the Lord appeared unto all the people.", "web": "Moses and Aaron went into the Tent of Meeting, and came out, and blessed the people: and Yahweh’s glory appeared to all the people.", "bsb": "Moses and Aaron then entered the Tent of Meeting. When they came out, they blessed the people, and the glory of the LORD appeared to all the people.", "asv": "And Moses and Aaron went into the tent of meeting, and came out, and blessed the people: and the glory of Jehovah appeared unto all the people.", "ylt": "And Moses goeth in--Aaron also--unto the tent of meeting, and they come out, and bless the people, and the honour of Jehovah appeareth unto all the people;", "tyndale": "Then Moses and Aaron wet in to the tabernacle of witnesse and came out agayne and blessed the people and the glorye of the Lorde apered vnto all the people.", "dra": "And Moses and Aaron went into the tabernacle of the testimony, and afterwards came forth and blessed the people. And the glory of the Lord appeared to all the multitude.", "bbe": "And Moses and Aaron went into the Tent of meeting, and came out and gave the people a blessing, and the glory of the Lord was seen by all the people.", "geneva": "After, Moses and Aaron went into the Tabernacle of the Congregation, and came out, and blessed the people, and the glorie of the Lord appeared to all the people.", "wycliffe": "Sotheli Moyses and Aaron entriden in to the tabernacle of witnessyng, and yeden out aftirward, and blessiden the puple; and the glorie of the Lord apperide to al the multitude.", "rotherham": "And when Moses and Aaron had entered into the tent of meeting,—and had come forth, and blessed the people, then appeared the glory of Yahweh, unto all the people;", "darby": "And Moses and Aaron went into the tent of meeting, and came out and blessed the people; and the glory of Jehovah appeared to all the people.", "twenty": "", "jps": "And Moses and Aaron went into the tent of meeting, and came out, and blessed the people; and the glory of HaShem appeared unto all the people.", "acv": "And Moses and Aaron went into the tent of meeting, and came out, and blessed the people. And the glory of Jehovah appeared to all the people.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Moses and Aaron went into the tabernacle of the congregation, and came out, and blessed the people: and the glory of the LORD appeared to all the people.", "vulgate": "ingressi autem Moses et Aaron tabernaculum testimonii et deinceps egressi benedixerunt populo apparuitque gloria Domini omni multitudini;", "brenton": "And Moses and Aaron entered into the tabernacle of witness. And they came out and blessed all the people, and the glory of the Lord appeared to all the people."}}, {"v": 24, "ref": "9:24", "o": "וַ/תֵּ֤צֵא אֵשׁ֙ מִ/לִּ/פְנֵ֣י יְהוָ֔ה וַ/תֹּ֨אכַל֙ עַל הַ/מִּזְבֵּ֔חַ אֶת הָ/עֹלָ֖ה וְ/אֶת הַ/חֲלָבִ֑ים וַ/יַּ֤רְא כָּל הָ/עָם֙ וַ/יָּרֹ֔נּוּ וַֽ/יִּפְּל֖וּ עַל פְּנֵי/הֶֽם", "en": {"kjv": "And there came a fire out from before the Lord, and consumed upon the altar the burnt offering and the fat: which when all the people saw, they shouted, and fell on their faces.", "web": "Fire came out from before Yahweh, and consumed the burnt offering and the fat upon the altar. When all the people saw it, they shouted, and fell on their faces.", "bsb": "Fire came out from the presence of the LORD and consumed the burnt offering and the fat portions on the altar. And when all the people saw it, they shouted for joy and fell facedown.", "asv": "And there came forth fire from before Jehovah, and consumed upon the altar the burnt-offering and the fat: and when all the people saw it, they shouted, and fell on their faces.", "ylt": "and fire cometh out from before Jehovah, and consumeth on the altar the burnt-offering, and the fat; and all the people see, and cry aloud, and fall on their faces.", "tyndale": "And there came a fyre out from before the Lorde and consumed apon the alter: the burntofferynge and the fatt. And all the people sawe it and showted, and fell on their faces.", "dra": "And, behold, a fire, coming forth from the Lord, devoured the holocaust, and the fat that was upon the altar: which when the multitude saw, they praised the Lord, falling on their faces.", "bbe": "And fire came out from before the Lord, burning up the offering on the altar and the fat: and when all the people saw it, they gave a loud cry, falling down on their faces.", "geneva": "And there came a fire out from the Lord and consumed vpon the Altar the burnt offring and the fatte: which when all the people sawe, they gaue thankes, and fell on their faces.", "wycliffe": "And lo! fier yede out fro the Lord, and deuouride the brent sacrifice, and the ynnere fatnesses that weren on the auter; and whanne the cumpanyes hadden seyn this thing, thei preiseden the Lord, `and felden on her faces.", "rotherham": "yea, there came forth fire from before Yahweh, and consumed upon the altar, the ascending-sacrifice and the portions of fat,—and all the people beheld and shouted, and fell down upon their faces.", "darby": "And there went out fire from before Jehovah, and consumed on the altar the burnt-offering, and the pieces of fat; and all the people saw it, and they shouted, and fell on their face.", "twenty": "", "jps": "And there came forth fire from before HaShem, and consumed upon the altar the burnt-offering and the fat; and when all the people saw it, they shouted, and fell on their faces.", "acv": "And there came forth fire from before Jehovah, and consumed the burnt offering and the fat upon the altar. And when all the people saw it, they shouted, and fell on their faces.", "anderson": "", "haweis": "", "noyes": "", "webster": "And there came out a fire from before the LORD, and consumed upon the altar the burnt-offering and the fat: [which], when all the people saw, they shouted, and fell on their faces.", "vulgate": "et ecce egressus ignis a Domino devoravit holocaustum et adipes qui erant super altare quod cum vidissent turbae laudaverunt Dominum ruentes in facies suas;", "brenton": "And fire came forth from the Lord, and devoured the offerings on the altar, both the whole-burnt-offerings and the fat; and all the people saw, and were amazed, and fell upon their faces."}}]}, {"c": 10, "verses": [{"v": 1, "ref": "10:1", "o": "וַ/יִּקְח֣וּ בְנֵֽי אַ֠הֲרֹן נָדָ֨ב וַ/אֲבִיה֜וּא אִ֣ישׁ מַחְתָּת֗/וֹ וַ/יִּתְּנ֤וּ בָ/הֵן֙ אֵ֔שׁ וַ/יָּשִׂ֥ימוּ עָלֶ֖י/הָ קְטֹ֑רֶת וַ/יַּקְרִ֜בוּ לִ/פְנֵ֤י יְהוָה֙ אֵ֣שׁ זָרָ֔ה אֲשֶׁ֧ר לֹ֦א צִוָּ֖ה אֹתָֽ/ם", "en": {"kjv": "And Nadab and Abihu, the sons of Aaron, took either of them his censer, and put fire therein, and put incense thereon, and offered strange fire before the Lord, which he commanded them not.", "web": "Nadab and Abihu, the sons of Aaron, each took his censer, and put fire in it, and laid incense on it, and offered strange fire before Yahweh, which he had not commanded them.", "bsb": "Now Aaron’s sons Nadab and Abihu took their censers, put fire in them and added incense, and offered unauthorized fire before the LORD, contrary to His command.", "asv": "And Nadab and Abihu, the sons of Aaron, took each of them his censer, and put fire therein, and laid incense thereon, and offered strange fire before Jehovah, which he had not commanded them.", "ylt": "And the sons of Aaron, Nadab and Abihu, take each his censer, and put in them fire, and put on it perfume, and bring near before Jehovah strange fire, which He hath not commanded them;", "tyndale": "And Nadab and Abihu the sonnes of Aaron toke ether of them his censor ad put fyre therein and put cens apo, and broughte straunge fyre before the Lorde: which he comaunded the not", "dra": "And Nadab and Abiu, the sons of Aaron, taking their censers, put fire therein, and incense on it, offering before the Lord strange fire: which was not commanded them.", "bbe": "And Nadab and Abihu, the sons of Aaron, took their vessels and put fire in them and perfume, burning strange fire before the Lord, which he had not given them orders to do.", "geneva": "But Nadab and Abihu, the sonnes of Aaron, tooke either of them his censor, and put fire therein, and put incense thereupon, and offred strange fire before the Lord, which hee had not commanded them.", "wycliffe": "And whanne Nadab and Abyu, the sones of Aaron, hadden take censeris, thei puttiden fier and encense aboue, and offriden bifor the Lord alien fier, which thing was not comaundid to hem.", "rotherham": "Then Aaron’s sons, Nadab and Abihu, took each man his censer and placed therein fire, and put thereon incense,—and brought near before Yahweh strange fire, which he had not commanded them.", "darby": "And the sons of Aaron, Nadab and Abihu, took each of them his censer, and put fire in it, and put incense on it, and presented strange fire before Jehovah, which he had not commanded them.", "twenty": "", "jps": "And Nadab and Abihu, the sons of Aaron, took each of them his censer, and put fire therein, and laid incense thereon, and offered strange fire before HaShem, which He had not commanded them.", "acv": "And Nadab and Abihu, the sons of Aaron, each of them took his censer, and put fire in it, and laid incense on it, and offered strange fire before Jehovah, which he had not commanded them.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Nadab and Abihu, the sons of Aaron, took each of them his censer, and put fire in it, and put incense on it, and offered strange fire before the LORD, which he commanded them not.", "vulgate": "arreptisque Nadab et Abiu filii Aaron turibulis posuerunt ignem et incensum desuper offerentes coram Domino ignem alienum quod eis praeceptum non erat;", "brenton": "And the two sons of Aaron, Nadab and Abiud, took each his censer, and put fire therein, and threw incense thereon, and offered strange fire before the Lord, which the Lord did not command them,"}}, {"v": 2, "ref": "10:2", "o": "וַ/תֵּ֥צֵא אֵ֛שׁ מִ/לִּ/פְנֵ֥י יְהוָ֖ה וַ/תֹּ֣אכַל אוֹתָ֑/ם וַ/יָּמֻ֖תוּ לִ/פְנֵ֥י יְהוָֽה", "en": {"kjv": "And there went out fire from the Lord, and devoured them, and they died before the Lord.", "web": "Fire came out from before Yahweh, and devoured them, and they died before Yahweh.", "bsb": "So fire came out from the presence of the LORD and consumed them, and they died in the presence of the LORD.", "asv": "And there came forth fire from before Jehovah, and devoured them, and they died before Jehovah.", "ylt": "and fire goeth out from before Jehovah, and consumeth them, and they die before Jehovah.", "tyndale": "and there went a fyre out fro the Lorde and cosumed the and they dyed before the Lorde.", "dra": "And fire coming out from the Lord destroyed them: and they died before the Lord.", "bbe": "And fire came out from before the Lord, burning them up and causing their destruction before the Lord.", "geneva": "Therefore a fire went out from the Lord, and deuoured them: so they dyed before the Lord.", "wycliffe": "And fier yede out fro the Lord, and deuouride hem, and thei weren deed bifor the Lord.", "rotherham": "Then came there forth fire from before Yahweh, and consumed them,—and they died before Yahweh.", "darby": "And there went out fire from before Jehovah, and devoured them, and they died before Jehovah.", "twenty": "", "jps": "And there came forth fire from before HaShem, and devoured them, and they died before HaShem.", "acv": "And there came forth fire from before Jehovah, and devoured them, and they died before Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And there went out fire from the LORD, and devoured them, and they died before the LORD.", "vulgate": "egressusque ignis a Domino devoravit eos et mortui sunt coram Domino;", "brenton": "and fire came forth from the Lord, and devoured them, and they died before the Lord."}}, {"v": 3, "ref": "10:3", "o": "וַ/יֹּ֨אמֶר מֹשֶׁ֜ה אֶֽל אַהֲרֹ֗ן הוּא֩ אֲשֶׁר דִּבֶּ֨ר יְהוָ֤ה לֵ/אמֹר֙ בִּ/קְרֹבַ֣/י אֶקָּדֵ֔שׁ וְ/עַל פְּנֵ֥י כָל הָ/עָ֖ם אֶכָּבֵ֑ד וַ/יִּדֹּ֖ם אַהֲרֹֽן", "en": {"kjv": "Then Moses said unto Aaron, This is it that the Lord spake, saying, I will be sanctified in them that come nigh me, and before all the people I will be glorified. And Aaron held his peace.", "web": "Then Moses said to Aaron, “This is what Yahweh spoke of, saying, ‘I will show myself holy to those who come near me, and before all the people I will be glorified.’” Aaron held his peace.", "bsb": "Then Moses said to Aaron, “This is what the LORD meant when He said: ‘To those who come near Me I will show My holiness, and in the sight of all the people I will reveal My glory.’” But Aaron remained silent.", "asv": "Then Moses said unto Aaron, This is it that Jehovah spake, saying, I will be sanctified in them that come nigh me, and before all the people I will be glorified. And Aaron held his peace.", "ylt": "And Moses saith unto Aaron, `It is that which Jehovah hath spoken, saying, By those drawing near to Me I am sanctified, and in the face of all the people I am honoured;' and Aaron is silent.", "tyndale": "Then Moses sayde vnto Aaro this is it that the Lorde spake saynge: I will be sanctifyed in them that come nye me, ad before all the people I wilbe glorifyed. And Aaron helde his pease.", "dra": "And Moses said to Aaron: This is what the Lord hath spoken. I will be sanctified in them that approach to me: and I will be glorified in the sight of all the people. And when Aaron heard this, he held his peace.", "bbe": "Then Moses said to Aaron, This is what the Lord said, I will be holy in the eyes of all those who come near to me, and I will be honoured before all the people. And Aaron said nothing.", "geneva": "Then Moses sayde vnto Aaron, This is it that the Lord spake, saying, I will bee sanctified in the that come neere me, and before all the people I will be glorified: but Aaron held his peace.", "wycliffe": "And Moises seide to Aaron, This thing it is which the Lord spak, Y schal be halewid in hem that neiyen to me, and Y schal be glorified in the siyt of al the puple; which thing Aaron herde, and was stille.", "rotherham": "Then said Moses unto Aaron—The very thing, that Yahweh spake, saying—In them that draw near to me, must I be hallowed, And before the faces of all the people, must I get myself honour,—And Aaron, was dumb.", "darby": "And Moses said to Aaron, This is what Jehovah spoke, saying, I will be hallowed in them that come near me, and before all the people I will be glorified. And Aaron was silent.", "twenty": "", "jps": "Then Moses said unto Aaron: 'This is it that HaShem spoke, saying: Through them that are nigh unto Me I will be sanctified, and before all the people I will be glorified.' And Aaron held his peace.", "acv": "Then Moses said to Aaron, This is it that Jehovah spoke, saying, I will be sanctified in those who come near me. And I will be glorified before all the people. And Aaron remained silent.", "anderson": "", "haweis": "", "noyes": "", "webster": "Then Moses said to Aaron, This [is] what the LORD spoke, saying, I will be sanctified in them that come nigh me, and before all the people I will be glorified. And Aaron held his peace.", "vulgate": "dixitque Moses ad Aaron hoc est quod locutus est Dominus sanctificabor in his qui adpropinquant mihi et in conspectu omnis populi glorificabor quod audiens tacuit Aaron;", "brenton": "And Moses said to Aaron, This is the thing which the Lord spoke, saying, I will be sanctified among them that draw night to me, and I will be glorified in the whole congregation; and Aaron was pricked in his heart."}}, {"v": 4, "ref": "10:4", "o": "וַ/יִּקְרָ֣א מֹשֶׁ֗ה אֶל מִֽישָׁאֵל֙ וְ/אֶ֣ל אֶלְצָפָ֔ן בְּנֵ֥י עֻזִּיאֵ֖ל דֹּ֣ד אַהֲרֹ֑ן וַ/יֹּ֣אמֶר אֲלֵ/הֶ֗ם קִ֠רְב֞וּ שְׂא֤וּ אֶת אֲחֵי/כֶם֙ מֵ/אֵ֣ת פְּנֵי הַ/קֹּ֔דֶשׁ אֶל מִ/ח֖וּץ לַֽ/מַּחֲנֶֽה", "en": {"kjv": "And Moses called Mishael and Elzaphan, the sons of Uzziel the uncle of Aaron, and said unto them, Come near, carry your brethren from before the sanctuary out of the camp.", "web": "Moses called Mishael and Elzaphan, the sons of Uzziel the uncle of Aaron, and said to them, “Draw near, carry your brothers from before the sanctuary out of the camp.”", "bsb": "Moses summoned Mishael and Elzaphan, sons of Aaron’s uncle Uzziel, and said to them, “Come here; carry the bodies of your cousins outside the camp, away from the front of the sanctuary.”", "asv": "And Moses called Mishael and Elzaphan, the sons of Uzziel the uncle of Aaron, and said unto them, Draw near, carry your brethren from before the sanctuary out of the camp.", "ylt": "And Moses calleth unto Mishael and unto Elzaphan, sons of Uzziel, uncle of Aaron, and saith unto them, `Come near, bear your brethren from the front of the sanctuary unto the outside of the camp;'", "tyndale": "And Moses called Misael and Elesapha the sonnes of Vsiel the vncle of Aaron, and sayde vnto the: goo to and carye youre brethre from the holy place out of the hoste.", "dra": "And Moses called Misael and Elisaphan, the sons of Oziel, the uncle of Aaron, and said to them: Go and take away your brethren from before the sanctuary, and carry them without the camp.", "bbe": "And Moses sent for Mishael and Elzaphan, the sons of Uzziel, the brother of Aaron's father, and said to them, Come near and take your brothers away from before the holy place, outside the tent-circle.", "geneva": "And Moses called Mishael and Elzaphan the sonnes of Vzziel, the vncle of Aaron, and saide vnto them, Come neere, cary your brethre from before the Sanctuarie out of the hoste.", "wycliffe": "Sotheli whanne Moises hadde clepid Mysael and Elisaphan, the sones of Oziel, brother of Aaron's fadir, he seide to hem, Go ye, and take awey youre britheren fro the siyt of seyntuarie, and bere ye out of the castels.", "rotherham": "Then called Moses unto Mishael, and unto Elzaphan, sons of Uzziel, uncle of Aaron,—and said unto them—Draw near bear away your brethren from before the sanctuary, unto the outside of the camp.", "darby": "And Moses called Mishael and Elzaphan, the sons of Uzziel the uncle of Aaron, and said to them, Come near, carry your brethren from before the sanctuary out of the camp.", "twenty": "", "jps": "And Moses called Mishael and Elzaphan, the sons of Uzziel the uncle of Aaron, and said unto them: 'Draw near, carry your brethren from before the sanctuary out of the camp.'", "acv": "And Moses called Mishael and Elzaphan, the sons of Uzziel the uncle of Aaron, and said to them, Draw near. Carry your brothers from before the sanctuary out of the camp.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Moses called Mishael and Elzaphan, the sons of Uzziel the uncle of Aaron, and said to them, Come near, carry your brethren from before the sanctuary out of the camp.", "vulgate": "vocatis autem Moses Misahel et Elsaphan filios Ozihel patrui Aaron ait ad eos ite et colligite fratres vestros de conspectu sanctuarii et asportate extra castra;", "brenton": "And Moses called Misadae, and Elisaphan, sons of Oziel, sons of the brother of Aaron's father, and said to them, Draw near and take your brethren from before the sanctuary out of the camp."}}, {"v": 5, "ref": "10:5", "o": "וַֽ/יִּקְרְב֗וּ וַ/יִּשָּׂאֻ/ם֙ בְּ/כֻתֳּנֹתָ֔/ם אֶל מִ/ח֖וּץ לַֽ/מַּחֲנֶ֑ה כַּ/אֲשֶׁ֖ר דִּבֶּ֥ר מֹשֶֽׁה", "en": {"kjv": "So they went near, and carried them in their coats out of the camp; as Moses had said.", "web": "So they drew near, and carried them in their coats out of the camp, as Moses had said.", "bsb": "So they came forward and carried them, still in their tunics, outside the camp, as Moses had directed.", "asv": "So they drew near, and carried them in their coats out of the camp, as Moses had said.", "ylt": "and they come near, and bear them in their coats unto the outside of the camp, as Moses hath spoken.", "tyndale": "And they went to them and caryed them in their albes out of the hoste, as Moses bad.", "dra": "And they went forthwith and took them as they lay, vested with linen tunicks, and cast them forth, as had been commanded them.", "bbe": "So they came and took them, in their coats, outside the tent-circle, as Moses had said.", "geneva": "Then they went, and caried them in their coates out of the host, as Moses had comaunded.", "wycliffe": "And anoon thei yeden, and token hem, as thei laien clothid with lynnun cootis, and castiden out, as it was comaundid to hem.", "rotherham": "So they drew near and bare them away, in their tunics, unto the outside of the camp,—as spake Moses.", "darby": "And they went near, and carried them in their vests out of the camp, as Moses had said.", "twenty": "", "jps": "So they drew near, and carried them in their tunics out of the camp, as Moses had said.", "acv": "So they drew near, and carried them in their tunics out of the camp, as Moses had said.", "anderson": "", "haweis": "", "noyes": "", "webster": "So they went near, and carried them in their coats out of the camp; as Moses had said.", "vulgate": "confestimque pergentes tulerunt eos sicut iacebant vestitos lineis tunicis et eiecerunt foras ut sibi fuerat imperatum;", "brenton": "And they came near and took them in their coats out of the camp, as Moses said."}}, {"v": 6, "ref": "10:6", "o": "וַ/יֹּ֣אמֶר מֹשֶׁ֣ה אֶֽל אַהֲרֹ֡ן וּ/לְ/אֶלְעָזָר֩ וּ/לְ/אִֽיתָמָ֨ר בָּנָ֜י/ו רָֽאשֵׁי/כֶ֥ם אַל תִּפְרָ֣עוּ וּ/בִגְדֵי/כֶ֤ם לֹֽא תִפְרֹ֨מוּ֙ וְ/לֹ֣א תָמֻ֔תוּ וְ/עַ֥ל כָּל הָ/עֵדָ֖ה יִקְצֹ֑ף וַ/אֲחֵי/כֶם֙ כָּל בֵּ֣ית יִשְׂרָאֵ֔ל יִבְכּוּ֙ אֶת הַ/שְּׂרֵפָ֔ה אֲשֶׁ֖ר שָׂרַ֥ף יְהוָֽה", "en": {"kjv": "And Moses said unto Aaron, and unto Eleazar and unto Ithamar, his sons, Uncover not your heads, neither rend your clothes; lest ye die, and lest wrath come upon all the people: but let your brethren, the whole house of Israel, bewail the burning which the Lord hath kindled.", "web": "Moses said to Aaron, and to Eleazar and to Ithamar, his sons, “Don’t let the hair of your heads go loose, neither tear your clothes; that you don’t die, and that he not be angry with all the congregation; but let your brothers, the whole house of Israel, bewail the burning which Yahweh has kindled.", "bsb": "Then Moses said to Aaron and his sons Eleazar and Ithamar, “Do not let your hair become disheveled and do not tear your garments, or else you will die, and the LORD will be angry with the whole congregation. But your brothers, the whole house of Israel, may mourn on account of the fire that the LORD has ignited.", "asv": "And Moses said unto Aaron, and unto Eleazar and unto Ithamar, his sons, Let not the hair of your heads go loose, neither rend your clothes; that ye die not, and that he be not wroth with all the congregation: but let your brethren, the whole house of Israel, bewail the burning which Jehovah hath kindled.", "ylt": "And Moses saith unto Aaron, and to Eleazar, and to Ithamar his sons, `Your heads ye do not uncover, and your garments ye do not rend, that ye die not, and on all the company He be wroth; as to your brethren, the whole house of Israel, they bewail the burning which Jehovah hath kindled;", "tyndale": "And Moses sayde vnto Aaron and vnto Eleazar and Ithamar his eldest sonnes: vncouer not youre heed nether rent youre clothes lest ye dye and wrath come apon all the people lett youre brethren the hole house of Israel bewepe the burnynge which the Lorde hath burnt.", "dra": "And Moses said to Aaron, and to Eleazar and Ithamar, his sons: Uncover not your heads, and rend not your garments, lest perhaps you die, and indignation come upon all the congregation. Let your brethren, and all the house of Israel, bewail the burning which the Lord has kindled.", "bbe": "And Moses said to Aaron and to Eleazar and Ithamar, his sons, Do not let your hair be loose, and give no signs of grief; so that death may not overtake you, and his wrath come on all the people; but let there be weeping among your brothers and all the house of Israel for this burning of the Lord's fire.", "geneva": "After, Moses saide vnto Aaron and vnto Eleazar and Ithamar his sonnes, Vncouer not your heads, neither rent your clothes, least ye dye, and least wrath come vpon all ye people: but let your brethren, all the house of Israel bewayle the burning which the Lord hath kindled.", "wycliffe": "And Moises spak to Aaron, and to Eliasar and Ithamar, the sones of Aaron, Nyle ye make nakid youre heedis, and nyle ye reende clothis, lest perauenture ye dien, and indignacioun rise on al the cumpany; youre britheren and all the hows of Israel byweile the brennyng which the Lord reiside.", "rotherham": "Then said Moses unto Aaron and to Eleazar and to Ithamar, his sons—Your heads, ye may not bare and your garments, ye shall not rend so shall ye not die, neither against all the assembly, will he be wroth,—but let, your brethren the whole house of Israel, bewail the consuming fire wherewith Yahweh hath consumed.", "darby": "And Moses said to Aaron, and to Eleazar and to Ithamar his sons, Your heads shall ye not uncover, neither rend your clothes; lest ye die, and lest wrath come on all the assembly; but your brethren, the whole house of Israel, shall bewail the burning which Jehovah hath kindled.", "twenty": "", "jps": "And Moses said unto Aaron, and unto Eleazar and unto Ithamar, his sons: 'Let not the hair of your heads go loose, neither tend your clothes, that ye die not, and that He be not wroth with all the congregation; but let your brethren, the whole house of Israel, bewail the burning which HaShem hath kindled.", "acv": "And Moses said to Aaron, and to Eleazar and to Ithamar, his sons, Let not the hair of your heads go loose, neither tear your clothes, that ye not die, and that he not be angry with all the congregation, but let your brothers, the whole house of Israel, bewail the burning which Jehovah has kindled.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Moses said to Aaron, and to Eleazar and to Ithamar, his sons, Uncover not your heads, neither rend your clothes; lest ye die, and lest wrath come upon all the people: but let your brethren, the whole house of Israel, bewail the burning which the LORD hath kindled.", "vulgate": "locutus est Moses ad Aaron et ad Eleazar atque Ithamar filios eius capita vestra nolite nudare et vestimenta nolite scindere ne forte moriamini et super omnem coetum oriatur indignatio fratres vestri et omnis domus Israhel plangant incendium quod Dominus suscitavit;", "brenton": "And Moses said to Aaron, and Eleazar and Ithamar his sons that were left, Ye shall not make bare your heads, and ye shall not tear your garments; that ye die not, and so there should be wrath on all the congregation: but your brethren, even all the house of Israel, shall lament for the burning, with which they were burnt by the Lord."}}, {"v": 7, "ref": "10:7", "o": "וּ/מִ/פֶּתַח֩ אֹ֨הֶל מוֹעֵ֜ד לֹ֤א תֵֽצְאוּ֙ פֶּן תָּמֻ֔תוּ כִּי שֶׁ֛מֶן מִשְׁחַ֥ת יְהוָ֖ה עֲלֵי/כֶ֑ם וַֽ/יַּעֲשׂ֖וּ כִּ/דְבַ֥ר מֹשֶֽׁה", "en": {"kjv": "And ye shall not go out from the door of the tabernacle of the congregation, lest ye die: for the anointing oil of the Lord is upon you. And they did according to the word of Moses.", "web": "You shall not go out from the door of the Tent of Meeting, lest you die; for the anointing oil of Yahweh is on you.” They did according to the word of Moses.", "bsb": "You shall not go outside the entrance to the Tent of Meeting, or you will die, for the LORD’s anointing oil is on you.” So they did as Moses instructed.", "asv": "And ye shall not go out from the door of the tent of meeting, lest ye die; for the anointing oil of Jehovah is upon you. And they did according to the word of Moses.", "ylt": "and from the opening of the tent of meeting ye do not go out, lest ye die, for the anointing oil of Jehovah is upon you;' and they do according to the word of Moses.", "tyndale": "But goo ye not out from the dore of the tabernacle of wytnesse lest ye dye: for the anoyntynge oyle of the Lorde is apon you. And they dyd as Moses bad.", "dra": "But you shall not go out of the door of the tabernacle: otherwise you shall perish, for the oil of the holy unction is on you. And they did all things according to the precept of Moses.", "bbe": "And do not go out from the door of the Tent of meeting, or death will come to you; for the holy oil of the Lord is on you. And they did as Moses said.", "geneva": "And go not yee out from the doore of the Tabernacle of the Congregation, least ye dye: for the anointing oyle of the Lord is vpon you: and they did according to Moses commandement.", "wycliffe": "But ye schulen not go out of the yatis of the tabernacle, ellis ye schulen perische; for the oile of hooli anoyntyng is on you. Whiche diden alle thingis bi the comaundement of Moises.", "rotherham": "But, from the entrance of the tent of meeting, shall ye not go forth, lest ye die, for, the anointing oil of Yahweh is upon you. And they did according to the word of Moses.", "darby": "And ye shall not go out from the entrance of the tent of meeting, lest ye die; for the anointing oil of Jehovah is upon you. And they did according to the word of Moses.", "twenty": "", "jps": "And ye shall not go out from the door of the tent of meeting, lest ye die; for the anointing oil of HaShem is upon you.' And they did according to the word of Moses.", "acv": "And ye shall not go out from the door of the tent of meeting, lest ye die, for the anointing oil of Jehovah is upon you. And they did according to the word of Moses.", "anderson": "", "haweis": "", "noyes": "", "webster": "And ye shall not go out from the door of the tabernacle of the congregation, lest ye die: for the anointing oil of the LORD [is] upon you. And they did according to the word of Moses.", "vulgate": "vos autem non egredimini fores tabernaculi alioquin peribitis oleum quippe sanctae unctionis est super vos qui fecerunt omnia iuxta praeceptum Mosi;", "brenton": "And ye shall not go forth from the door of the tabernacle of witness, that ye die not; for the Lord's anointing oil is upon you: and they did according to the word of Moses."}}, {"v": 8, "ref": "10:8", "o": "וַ/יְדַבֵּ֣ר יְהוָ֔ה אֶֽל אַהֲרֹ֖ן לֵ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Aaron, saying,", "web": "Then Yahweh said to Aaron,", "bsb": "Then the LORD said to Aaron,", "asv": "And Jehovah spake unto Aaron, saying,", "ylt": "And Jehovah speaketh unto Aaron, saying,", "tyndale": "And the Lorde spake vnto Aaron saynge:", "dra": "The Lord also said to Aaron:", "bbe": "And the Lord said to Aaron:", "geneva": "And the Lord spake vnto Aaron, saying,", "wycliffe": "Also the Lord seide to Aaron,", "rotherham": "Then spake Yahweh unto Aaron, saying:", "darby": "And Jehovah spoke to Aaron, saying,", "twenty": "", "jps": "And HaShem spoke unto Aaron, saying:", "acv": "And Jehovah spoke to Aaron, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Aaron, saying,", "vulgate": "dixit quoque Dominus ad Aaron;", "brenton": "And the Lord spoke to Aaron, saying,"}}, {"v": 9, "ref": "10:9", "o": "יַ֣יִן וְ/שֵׁכָ֞ר אַל תֵּ֣שְׁתְּ אַתָּ֣ה וּ/בָנֶ֣י/ךָ אִתָּ֗/ךְ בְּ/בֹאֲ/כֶ֛ם אֶל אֹ֥הֶל מוֹעֵ֖ד וְ/לֹ֣א תָמֻ֑תוּ חֻקַּ֥ת עוֹלָ֖ם לְ/דֹרֹתֵי/כֶֽם", "en": {"kjv": "Do not drink wine nor strong drink, thou, nor thy sons with thee, when ye go into the tabernacle of the congregation, lest ye die: it shall be a statute for ever throughout your generations:", "web": "“You and your sons are not to drink wine or strong drink whenever you go into the Tent of Meeting, or you will die. This shall be a statute forever throughout your generations.", "bsb": "“You and your sons are not to drink wine or strong drink when you enter the Tent of Meeting, or else you will die; this is a permanent statute for the generations to come.", "asv": "Drink no wine nor strong drink, thou, nor thy sons with thee, when ye go into the tent of meeting, that ye die not: it shall be a statute for ever throughout your generations:", "ylt": "`Wine and strong drink thou dost not drink, thou, and thy sons with thee, in your going in unto the tent of meeting, and ye die not--a statute age-during to your generations;", "tyndale": "drynke no wyne nor stronge drynke nether thou nor thi sonnes with the: when ye go in to the tabernacle of witnesse lest ye dye. And let it be a lawe foreuer vnto youre childern after you:", "dra": "You shall not drink wine nor any thing that may make drunk, thou nor thy sons, when you enter into the tabernacle of the testimony, lest you die. Because it is an everlasting precept; through your generations:", "bbe": "Take no wine, or strong drink, you or your sons with you, when you go into the Tent of meeting, that it may not be the cause of death to you; this is an order for ever through all your generations.", "geneva": "Thou shalt not drinke wine nor strong drinke, thou, nor thy sonnes with thee, when yee come into the Tabernacle of the Congregation, lest ye die: this is an ordinance for euer throughout your generations,", "wycliffe": "Thou and thi sones schulen not drynke wyn, and al thing that may make drunkun, whanne ye schulen entre in to the tabernacle of witnessing, lest ye dien; for it is euerlastynge comaundement in to youre generaciouns,", "rotherham": "Wine and strong drink, thou mayest not drink,—thou nor thy sons with thee when ye enter into the tent of meeting, so shall ye not die,—an age-abiding statute to your generations;", "darby": "Thou shalt not drink wine nor strong drink, thou, and thy sons with thee, when ye go into the tent of meeting, lest ye die — [it is] an everlasting statute throughout your generations,", "twenty": "", "jps": "'Drink no wine nor strong drink, thou, nor thy sons with thee, when ye go into the tent of meeting, that ye die not; it shall be a statute forever throughout your generations.", "acv": "Drink no wine nor strong drink, thou, nor thy sons with thee, when ye go into the tent of meeting, that ye not die-it shall be a statute forever throughout your generations-", "anderson": "", "haweis": "", "noyes": "", "webster": "Do not drink wine nor strong drink, thou, nor thy sons with thee, when ye go into the tabernacle of the congregation, lest ye die: [it shall be] a statute for ever throughout your generations:", "vulgate": "vinum et omne quod inebriare potest non bibetis tu et filii tui quando intratis tabernaculum testimonii ne moriamini quia praeceptum est sempiternum in generationes vestras;", "brenton": "Ye shall not drink wine nor strong drink, thou and thy sons with thee, whensoever ye enter into the tabernacle of witness, or when ye approach the altar, so shall ye not die; it is a perpetual statute for your generations,"}}, {"v": 10, "ref": "10:10", "o": "וּֽ/לֲ/הַבְדִּ֔יל בֵּ֥ין הַ/קֹּ֖דֶשׁ וּ/בֵ֣ין הַ/חֹ֑ל וּ/בֵ֥ין הַ/טָּמֵ֖א וּ/בֵ֥ין הַ/טָּהֽוֹר", "en": {"kjv": "And that ye may put difference between holy and unholy, and between unclean and clean;", "web": "You are to make a distinction between the holy and the common, and between the unclean and the clean.", "bsb": "You must distinguish between the holy and the common, between the clean and the unclean,", "asv": "and that ye may make a distinction between the holy and the common, and between the unclean and the clean;", "ylt": "so as to make a separation between the holy and the common, and between the unclean and the pure;", "tyndale": "that ye maye put difference betwene holy and vnholy and betwene vnclene and clene", "dra": "And that you may have knowledge to discern between holy and unholy, between unclean and clean:", "bbe": "And make a division between the holy and the common, and between the unclean and the clean;", "geneva": "That ye may put difference betweene the holy and the vnholy, and betweene the cleane and the vncleane,", "wycliffe": "that ye haue kunnyng to make doom bytwixe hooli thing and vnhooli, bitwixe pollutid thing and cleene;", "rotherham": "That ye may make a difference, between the sacred and the common,—and between the unclean and the clean;", "darby": "that ye may put difference between the holy and the unholy, and between unclean and clean,", "twenty": "", "jps": "And that ye may put difference between the holy and the common, and between the unclean and the clean;", "acv": "and that ye may make a distinction between the holy and the common, and between the unclean and the clean,", "anderson": "", "haweis": "", "noyes": "", "webster": "And that ye may make a difference between holy and unholy, and between unclean and clean;", "vulgate": "et ut habeatis scientiam discernendi inter sanctum et profanum inter pollutum et mundum;", "brenton": "to distinguish between sacred and profane, and between clean and unclean,"}}, {"v": 11, "ref": "10:11", "o": "וּ/לְ/הוֹרֹ֖ת אֶת בְּנֵ֣י יִשְׂרָאֵ֑ל אֵ֚ת כָּל הַ֣/חֻקִּ֔ים אֲשֶׁ֨ר דִּבֶּ֧ר יְהוָ֛ה אֲלֵי/הֶ֖ם בְּ/יַד מֹשֶֽׁה", "en": {"kjv": "And that ye may teach the children of Israel all the statutes which the Lord hath spoken unto them by the hand of Moses.", "web": "You are to teach the children of Israel all the statutes which Yahweh has spoken to them by Moses.”", "bsb": "so that you may teach the Israelites all the statutes that the LORD has given them through Moses.”", "asv": "and that ye may teach the children of Israel all the statutes which Jehovah hath spoken unto them by Moses.", "ylt": "and to teach the sons of Israel all the statutes which Jehovah hath spoken unto them by the hand of Moses.'", "tyndale": "and that ye maye teach the childern of Israel: all the ordynaunces which the Lorde hath comaunded them by the handes of Moses.", "dra": "And may teach the children of Israel all my ordinances which the Lord hath spoken to them by the hand of Moses.", "bbe": "Teaching the children of Israel all the laws which the Lord has given them by the hand of Moses.", "geneva": "And that ye may teach the children of Israel all the statutes which the Lord hath commanded them by the hand of Moses.", "wycliffe": "and that ye teche the sones of Israel alle my lawful thingis, whiche the Lord spak to hem bi the hond of Moyses.", "rotherham": "And may teach the sons of Israel,—all the statutes which Yahweh hath spoken unto them, by the mediation of Moses.", "darby": "and that ye may teach the children of Israel all the statutes which Jehovah hath spoken to them by the hand of Moses.", "twenty": "", "jps": "and that ye may teach the children of Israel all the statutes which HaShem hath spoken unto them by the hand of Moses.'", "acv": "and that ye may teach the sons of Israel all the statutes which Jehovah has spoken to them by Moses.", "anderson": "", "haweis": "", "noyes": "", "webster": "And that ye may teach the children of Israel all the statutes which the LORD hath spoken to them by the hand of Moses.", "vulgate": "doceatisque filios Israhel omnia legitima mea quae locutus est Dominus ad eos per manum Mosi;", "brenton": "and to teach the children of Israel all the statutes, which the Lord spoke to them by Moses."}}, {"v": 12, "ref": "10:12", "o": "וַ/יְדַבֵּ֨ר מֹשֶׁ֜ה אֶֽל אַהֲרֹ֗ן וְ/אֶ֣ל אֶ֠לְעָזָר וְ/אֶל אִ֨יתָמָ֥ר בָּנָי/ו֮ הַ/נּֽוֹתָרִים֒ קְח֣וּ אֶת הַ/מִּנְחָ֗ה הַ/נּוֹתֶ֨רֶת֙ מֵ/אִשֵּׁ֣י יְהוָ֔ה וְ/אִכְל֥וּ/הָ מַצּ֖וֹת אֵ֣צֶל הַ/מִּזְבֵּ֑חַ כִּ֛י קֹ֥דֶשׁ קָֽדָשִׁ֖ים הִֽוא", "en": {"kjv": "And Moses spake unto Aaron, and unto Eleazar and unto Ithamar, his sons that were left, Take the meat offering that remaineth of the offerings of the Lord made by fire, and eat it without leaven beside the altar: for it is most holy:", "web": "Moses spoke to Aaron, and to Eleazar and to Ithamar, his sons who were left, “Take the meal offering that remains of the offerings of Yahweh made by fire, and eat it without yeast beside the altar; for it is most holy;", "bsb": "And Moses said to Aaron and his remaining sons, Eleazar and Ithamar, “Take the grain offering that remains from the offerings made by fire to the LORD and eat it without leaven beside the altar, because it is most holy.", "asv": "And Moses spake unto Aaron, and unto Eleazar and unto Ithamar, his sons that were left, Take the meal-offering that remaineth of the offerings of Jehovah made by fire, and eat it without leaven beside the altar; for it is most holy;", "ylt": "And Moses speaketh unto Aaron, and unto Eleazar, and unto Ithamar his sons, who are left, `Take ye the present that is left from the fire-offerings of Jehovah, and eat it unleavened near the altar, for it is most holy,", "tyndale": "And Moses sayde vnto Aaron and vnto Eleazar ad Ithamar his sonnes that were lefte: take the meatofferynge that remayneth of the sacrifyces of the Lorde and eate it without leuen besyde the alter for it is most holy:", "dra": "And Moses spoke to Aaron, and to Eleazar and Ithamar, his sons that were left: Take the sacrifice that is remaining of the oblation of the Lord, and eat it without leaven beside the altar, because it is holy of holies.", "bbe": "And Moses said to Aaron and to Eleazar and Ithamar, his sons who were still living, Take the rest of the meal offering from the offerings of the Lord made by fire, and take it for your food, without leaven, at the side of the altar, for it is most holy.", "geneva": "Then Moses saide vnto Aaron and vnto Eleazar and to Ithamar his sonnes that were left, Take the meate offring that remaineth of the offrings of the Lord, made by fire, and eate it without leauen beside ye altar: for it is most holy:", "wycliffe": "And Moises spak to Aaron, and to Eliazar and Ythamar, hise sones, that weren residue, Take ye the sacrifice that lefte of the offryng of the Lord, and ete ye it with out sour dow, bisidis the auter, for it is hooli `of the noumbre of hooli thingis.", "rotherham": "Then spake Moses unto Aaron and unto Eleazar and unto Ithamar his sons that were left, Take ye the meal-offering that is left of the altar-flames of Yahweh, and eat it unleavened beside the altar,—for, most holy, it is;", "darby": "And Moses spoke to Aaron, and to Eleazar and to Ithamar, his sons that were left, Take the oblation that is left of Jehovah's offerings by fire, and eat it with unleavened bread beside the altar; for it is most holy.", "twenty": "", "jps": "And Moses spoke unto Aaron, and unto Eleazar and unto Ithamar, his sons that were left: 'Take the meal-offering that remaineth of the offerings of HaShem made by fire, and eat it without leaven beside the altar; for it is most holy.", "acv": "And Moses spoke to Aaron, and to Eleazar and to Ithamar, his sons who were left, Take the meal offering that remains of the offerings of Jehovah made by fire, and eat it without leaven beside the altar, for it is most holy.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Moses spoke to Aaron, and to Eleazar and to Ithamar, his sons that were left, Take the meat-offering that remaineth of the offerings of the LORD made by fire, and eat it without leaven beside the altar: for it [is] most holy:", "vulgate": "locutusque est Moses ad Aaron et ad Eleazar atque Ithamar filios eius qui residui erant tollite sacrificium quod remansit de oblatione Domini et comedite illud absque fermento iuxta altare quia sanctum sanctorum est;", "brenton": "And Moses said to Aaron, and to Eleazar and Ithamar, the sons of Aaron who survived, Take the sacrifice that is left of the burnt-offerings of the Lord, and ye shall eat unleavened bread by the altar: it is most holy."}}, {"v": 13, "ref": "10:13", "o": "וַ/אֲכַלְתֶּ֤ם אֹתָ/הּ֙ בְּ/מָק֣וֹם קָדֹ֔שׁ כִּ֣י חָקְ/ךָ֤ וְ/חָק בָּנֶ֨י/ךָ֙ הִ֔וא מֵ/אִשֵּׁ֖י יְהוָ֑ה כִּי כֵ֖ן צֻוֵּֽיתִי", "en": {"kjv": "And ye shall eat it in the holy place, because it is thy due, and thy sons’ due, of the sacrifices of the Lord made by fire: for so I am commanded.", "web": "and you shall eat it in a holy place, because it is your portion, and your sons’ portion, of the offerings of Yahweh made by fire: for so I am commanded.", "bsb": "You shall eat it in a holy place, because it is your share and your sons’ share of the offerings made by fire to the LORD; for this is what I have been commanded.", "asv": "and ye shall eat it in a holy place, because it is thy portion, and thy sons’ portion, of the offerings of Jehovah made by fire: for so I am commanded.", "ylt": "and ye have eaten it in the holy place, for it is thy portion, and the portion of thy sons, from the fire-offerings of Jehovah; for so I have been commanded.", "tyndale": "eate it therfore in the holy place, because it is thi dutye and thi sonnes dutye of the sacrifyce of the Lorde: for so I am commaunded.", "dra": "And you shall eat it in a holy place: which is given to thee and thy sons of the oblations of the Lord, as it hath been commanded me.", "bbe": "It is to be for your food in a holy place, because it is your right and your sons' right, from the offerings of the Lord made by fire: for so am I ordered.", "geneva": "And ye shall eate it in the holy place, because it is thy duetie and thy sonnes duety of the offringes of the Lord made by fire: for so I am commanded.", "wycliffe": "Sotheli ye schulen ete in the hooli place that that is youun to thee and to thi sones, of the offryngis of the Lord, as it is comaundid to me Also thou,", "rotherham": "therefore shall ye eat it in a holy place, for, thine by statute, and thy sons’ by statute, it is, from among the altar-flames of Yahweh,—for, so, am I commanded.", "darby": "And ye shall eat it in a holy place, because it is thy due, and thy sons' due, of Jehovah's offerings by fire; for so I am commanded.", "twenty": "", "jps": "And ye shall eat it in a holy place, because it is thy due, and thy sons' due, of the offerings of HaShem made by fire; for so I am commanded.", "acv": "And ye shall eat it in a holy place, because it is thy portion, and thy sons' portion, of the offerings of Jehovah made by fire. For so I am commanded.", "anderson": "", "haweis": "", "noyes": "", "webster": "And ye shall eat it in the holy place, because it [is] thy due, and thy sons' due, of the sacrifices of the LORD made by fire: for so I am commanded.", "vulgate": "comedetis autem in loco sancto quod datum est tibi et filiis tuis de oblationibus Domini sicut praeceptum est mihi;", "brenton": "And ye shall eat it in the holy place; for this is a statute for thee and a statute for thy sons, of the burnt-offerings to the Lord; for so it has been commanded me."}}, {"v": 14, "ref": "10:14", "o": "וְ/אֵת֩ חֲזֵ֨ה הַ/תְּנוּפָ֜ה וְ/אֵ֣ת שׁ֣וֹק הַ/תְּרוּמָ֗ה תֹּֽאכְלוּ֙ בְּ/מָק֣וֹם טָה֔וֹר אַתָּ֕ה וּ/בָנֶ֥י/ךָ וּ/בְנֹתֶ֖י/ךָ אִתָּ֑/ךְ כִּֽי חָקְ/ךָ֤ וְ/חָק בָּנֶ֨י/ךָ֙ נִתְּנ֔וּ מִ/זִּבְחֵ֥י שַׁלְמֵ֖י בְּנֵ֥י יִשְׂרָאֵֽל", "en": {"kjv": "And the wave breast and heave shoulder shall ye eat in a clean place; thou, and thy sons, and thy daughters with thee: for they be thy due, and thy sons’ due, which are given out of the sacrifices of peace offerings of the children of Israel.", "web": "The waved breast and the heaved thigh you shall eat in a clean place, you, and your sons, and your daughters with you: for they are given as your portion, and your sons’ portion, out of the sacrifices of the peace offerings of the children of Israel.", "bsb": "And you and your sons and daughters may eat the breast of the wave offering and the thigh of the contribution in a ceremonially clean place, because these portions have been assigned to you and your children from the peace offerings of the sons of Israel.", "asv": "And the wave-breast and the heave-thigh shall ye eat in a clean place, thou, and thy sons, and thy daughters with thee: for they are given as thy portion, and thy sons’ portion, out of the sacrifices of the peace-offerings of the children of Israel.", "ylt": "`And the breast of the wave-offering, and the leg of the heave-offering, ye do eat in a clean place, thou, and thy sons, and thy daughters with thee; for thy portion and the portion of thy sons they have been given, out of the sacrifices of peace-offerings of the sons of Israel;", "tyndale": "And the wauebrest and heueshulder eate in a clene place: both thou and thy sonnes and thy doughters with the. For it is thy dutye and thy sonnes dutye with the, of the peaceofferynges off the childern of Israel.", "dra": "The breast also that is offered, and the shoulder that is separated, you shall eat in a most clean place, thou and thy sons, and thy daughters with thee. For they are set aside for thee and thy children, of the victims of peace offerings of the children of Israel.", "bbe": "And the breast which is waved and the leg which is lifted up on high, you are to take as your food in a clean place; you and your sons and your daughters with you: for they are given to you as your right and your sons' right, from the peace-offerings of the children of Israel.", "geneva": "Also the shaken breast and the heaue shoulder shall yee eate in a cleane place: thou, and thy sonnes, and thy daughters with thee: for they are giuen as thy duetie and thy sonnes duety, of the peace offringes of the children of Israel.", "wycliffe": "and thi sones, and thi douytris with thee, schulen ete in the clenneste place the brest which is offrid, and the schuldur which is departid; for tho ben kept to thee and to thi fre sones, of the heelful sacrifices of the sones of Israel;", "rotherham": "And the wave-breast, and the heave-shoulder, shall ye eat in clean place, thou, and thy sons and thy daughters with thee,—for as thine by statute and thy sons’ by statute, have they been given, from among the peace-offerings of the sons of Israel.", "darby": "And the breast of the wave-offering, and the shoulder of the heave-offering shall ye eat in a clean place, thou, and thy sons, and thy daughters with thee; for [as] thy due, and thy sons' due, are they given of the sacrifices of peace-offerings of the children of Israel.", "twenty": "", "jps": "And the breast of waving and the thigh of heaving shall ye eat in a clean place; thou, and thy sons, and thy daughters with thee; for they are given as thy due, and thy sons' due, out of the sacrifices of the peace-offerings of the children of Israel.", "acv": "And ye shall eat the wave-breast and the heave-thigh in a clean place, thou, and thy sons, and thy daughters with thee. For they are given as thy portion, and thy sons' portion, out of the sacrifices of the peace offerings of the sons of Israel.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the wave-breast and heave-shoulder shall ye eat in a clean place; thou, and thy sons, and thy daughters with thee: for [they are] thy due, and thy sons' due, [which] are given out of the sacrifices of peace-offerings of the children of Israel.", "vulgate": "pectusculum quoque quod oblatum est et armum qui separatus est edetis in loco mundissimo tu et filii tui ac filiae tuae tecum tibi enim ac liberis tuis reposita sunt de hostiis salutaribus filiorum Israhel;", "brenton": "And ye shall eat the breast of separation, and the shoulder of the choice-offering in the holy place, thou and thy sons and thy house with thee; for it has been given as an ordinance for thee and an ordinance for thy sons, of the sacrifices of peace-offering of the children of Israel."}}, {"v": 15, "ref": "10:15", "o": "שׁ֣וֹק הַ/תְּרוּמָ֞ה וַ/חֲזֵ֣ה הַ/תְּנוּפָ֗ה עַ֣ל אִשֵּׁ֤י הַ/חֲלָבִים֙ יָבִ֔יאוּ לְ/הָנִ֥יף תְּנוּפָ֖ה לִ/פְנֵ֣י יְהוָ֑ה וְ/הָיָ֨ה לְ/ךָ֜ וּ/לְ/בָנֶ֤י/ךָ אִתְּ/ךָ֙ לְ/חָק עוֹלָ֔ם כַּ/אֲשֶׁ֖ר צִוָּ֥ה יְהוָֽה", "en": {"kjv": "The heave shoulder and the wave breast shall they bring with the offerings made by fire of the fat, to wave it for a wave offering before the Lord; and it shall be thine, and thy sons’ with thee, by a statute for ever; as the Lord hath commanded.", "web": "The heaved thigh and the waved breast they shall bring with the offerings made by fire of the fat, to wave it for a wave offering before Yahweh: and it shall be yours, and your sons’ with you, as a portion forever; as Yahweh has commanded.”", "bsb": "They are to bring the thigh of the contribution and the breast of the wave offering, together with the fat portions of the offerings made by fire, to wave as a wave offering before the LORD. It will belong permanently to you and your children, as the LORD has commanded.”", "asv": "The heave-thigh and the wave-breast shall they bring with the offerings made by fire of the fat, to wave it for a wave-offering before Jehovah: and it shall be thine, and thy sons’ with thee, as a portion for ever; as Jehovah hath commanded.", "ylt": "the leg of the heave-offering, and breast of the wave-offering, besides fire-offerings of the fat, they do bring in to wave a wave-offering before Jehovah, and it hath been to thee, and to thy sons with thee, by a statute age-during, as Jehovah hath commanded.'", "tyndale": "For the heueshulder ad the wauebrest whiche they brynge with the sacrifices of the fatt, to waue it before the Lorde, shalbe thyne and thy sonnes with the, and be a lawe for euer, as the Lorde hath commaunded.", "dra": "Because they have elevated before the Lord the shoulder and the breast, and the fat that is burnt on the altar: and they belong to thee and to thy sons by a perpetual law, as the Lord hath commanded.", "bbe": "Let them take the breast which is waved and the leg which is lifted up on high, with the fat of the burned offering, to be waved for a wave offering before the Lord; and this will be for you and for your sons with you, for a right for ever, as the Lord has given orders.", "geneva": "The heaue shoulder, and the shaken breast shall they bring with the offringes made by fire of the fat, to shake it to and from before the Lord, and it shalbe thine and thy sonnes with thee by a lawe for euer, as the Lord hath commanded.", "wycliffe": "for thei reiseden bifor the Lord the schuldur and brest, and the ynnere fatnessis that ben brent in the auter; and perteynen tho to thee, and to thi sones, bi euerlastynge lawe, as the Lord comaundide.", "rotherham": "The heave-shoulder and the wave-breast upon the altar-flames of the fat portions, shall they bring in, to wave as a wave-offering, before Yahweh,—so shall they be thine, and thy sons’ with thee, by an age-abiding statute, As Yahweh hath commanded.", "darby": "The shoulder of the heave-offering and the breast of the wave-offering shall they bring, with the fire-offering of the pieces of fat, to wave [them] as a wave-offering before Jehovah; and they shall be thine, and thy sons' with thee, for an everlasting statute, as Jehovah has commanded.", "twenty": "", "jps": "The thigh of heaving and the breast of waving shall they bring with the offerings of the fat made by fire, to wave it for a wave-offering before HaShem; and it shall be thine, and thy sons' with thee, as a due for ever; as HaShem hath commanded.'", "acv": "They shall bring the heave-thigh and the wave-breast with the offerings made by fire of the fat, to wave it for a wave offering before Jehovah, and it shall be thine, and thy sons' with thee, as a portion forever, as Jehovah has commanded.", "anderson": "", "haweis": "", "noyes": "", "webster": "The heave-shoulder and the wave-breast shall they bring, with the offerings made by fire of the fat, to wave [it for] a wave-offering before the LORD; and it shall be thine, and thy sons' with thee, by a statute for ever; as the LORD hath commanded.", "vulgate": "eo quod armum et pectus et adipes qui cremantur in altari elevaverint coram Domino et pertineant ad te et ad filios tuos lege perpetua sicut praecepit Dominus;", "brenton": "They shall bring the shoulder of the choice-offering, and the breast of the separation upon the burnt-offerings of the fat, to separate for a separation before the Lord; and it shall be a perpetual ordinance for thee and thy sons and thy daughters with thee, as the Lord commanded Moses."}}, {"v": 16, "ref": "10:16", "o": "וְ/אֵ֣ת שְׂעִ֣יר הַֽ/חַטָּ֗את דָּרֹ֥שׁ דָּרַ֛שׁ מֹשֶׁ֖ה וְ/הִנֵּ֣ה שֹׂרָ֑ף וַ֠/יִּקְצֹף עַל אֶלְעָזָ֤ר וְ/עַל אִֽיתָמָר֙ בְּנֵ֣י אַהֲרֹ֔ן הַ/נּוֹתָרִ֖ם לֵ/אמֹֽר", "en": {"kjv": "And Moses diligently sought the goat of the sin offering, and, behold, it was burnt: and he was angry with Eleazar and Ithamar, the sons of Aaron which were left alive, saying,", "web": "Moses diligently inquired about the goat of the sin offering, and, behold, it was burned: and he was angry with Eleazar and with Ithamar, the sons of Aaron who were left, saying,", "bsb": "Later, Moses searched carefully for the goat of the sin offering, and behold, it had been burned up. He was angry with Eleazar and Ithamar, Aaron’s remaining sons, and asked,", "asv": "And Moses diligently sought the goat of the sin-offering, and, behold, it was burnt: and he was angry with Eleazar and with Ithamar, the sons of Aaron that were left, saying,", "ylt": "And the goat of the sin-offering hath Moses diligently sought, and lo, it is burnt, and he is wroth against Eleazar, and against Ithamar, sons of Aaron, who are left, saying,", "tyndale": "And Moses soughte for the goote that was the synneofferynge, and se, it was burnt. And he was angrye with Eleazar and Ithamar the sonnes of Aaron, which were lefte alyue sayenge:", "dra": "While these things were a doing, when Moses sought for the buck goat, that had been offered for sin, he found it burnt. And being angry with Eleazar and Ithamar, the sons of Aaron that were left, he said:", "bbe": "And Moses was looking for the goat of the sin-offering, but it was burned; and he was angry with Eleazar and Ithamar, the sons of Aaron, who were still living, saying,", "geneva": "And Moses sought the goate that was offred for sinne, and lo, it was burnt: therefore he was angrie with Eleazar and Ithamar the sonnes of Aaron, which were left aliue, saying,", "wycliffe": "Among these thingis whanne Moises souyte the `buk of geet that was offrid for synne, he foond it brent, and he was wrooth ayens Eliazar and Ythamar, `the sones of Aaron that weren left.", "rotherham": "Now, as for the sin-bearing goat, Moses diligently sought it but lo! it had been burnt up,—then was he wroth against Eleazar and against Ithamar, the sons of Aaron that were left, saying:", "darby": "And Moses diligently sought the goat of the sin-offering, and behold, it was burnt up: then he was wroth with Eleazar and Ithamar, the sons of Aaron that were left, saying,", "twenty": "", "jps": "And Moses diligently inquired for the goat of the sin-offering, and, behold, it was burnt; and he was angry with Eleazar and with Ithamar, the sons of Aaron that were left, saying:", "acv": "And Moses diligently sought the goat of the sin offering, and, behold, it was burnt. And he was angry with Eleazar and with Ithamar, the sons of Aaron who were left, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And Moses diligently sought the goat of the sin-offering, and behold, it was burnt: and he was angry with Eleazar and Ithamar, the sons of Aaron [who were] left [alive], saying,", "vulgate": "inter haec hircum qui oblatus fuerat pro peccato cum quaereret Moses exustum repperit iratusque contra Eleazar et Ithamar filios Aaron qui remanserant ait;", "brenton": "And Moses diligently sought the goat of the sin-offering, but it had been consumed by fire; and Moses was angry with Eleazar and Ithamar the sons of Aaron that were left, saying,"}}, {"v": 17, "ref": "10:17", "o": "מַדּ֗וּעַ לֹֽא אֲכַלְתֶּ֤ם אֶת הַֽ/חַטָּאת֙ בִּ/מְק֣וֹם הַ/קֹּ֔דֶשׁ כִּ֛י קֹ֥דֶשׁ קָֽדָשִׁ֖ים הִ֑וא וְ/אֹתָ֣/הּ נָתַ֣ן לָ/כֶ֗ם לָ/שֵׂאת֙ אֶת עֲוֺ֣ן הָ/עֵדָ֔ה לְ/כַפֵּ֥ר עֲלֵי/הֶ֖ם לִ/פְנֵ֥י יְהוָֽה", "en": {"kjv": "Wherefore have ye not eaten the sin offering in the holy place, seeing it is most holy, and God hath given it you to bear the iniquity of the congregation, to make atonement for them before the Lord?", "web": "“Why haven’t you eaten the sin offering in the place of the sanctuary, since it is most holy, and he has given it you to bear the iniquity of the congregation, to make atonement for them before Yahweh?", "bsb": "“Why didn’t you eat the sin offering in the holy place? For it is most holy; it was given to you to take away the guilt of the congregation by making atonement for them before the LORD.", "asv": "Wherefore have ye not eaten the sin-offering in the place of the sanctuary, seeing it is most holy, and he hath given it you to bear the iniquity of the congregation, to make atonement for them before Jehovah?", "ylt": "`Wherefore have ye not eaten the sin-offering in the holy place, for it is most holy--and it He hath given to you to take away the iniquity of the company, to make atonement for them before Jehovah?", "tyndale": "wherefore haue ye not eaten the synneofferynge in the holy place, seynge it is most holye: and for as moch as it is geuen you to bere the synne of the people, and make agrement for them before the Lorde?", "dra": "Why did you not eat in the holy place the sacrifice for sin, which is most holy, and given to you, that you may bear the iniquity of the people, and may pray for them in the sight of the Lord.", "bbe": "Why did you not make a meal of the sin-offering in the holy place? For it is most holy and he has given it to you, so that the sin of the people may be put on it, to take away their sin before the Lord.", "geneva": "Wherfore haue ye not eaten the sinne offring in the holy place, seeing it is most Holie? and God hath giuen it you, to beare the iniquitie of the Congregation, to make an atonement for them before the Lord.", "wycliffe": "And he seide, Whi eten not ye the sacrifice for synne in the hooli place, which sacrifice is hooli `of the noumbre of hooli thingis, and is youun to you, that ye bere the wickydnesse of the multitude, and preye for it in the siyt of the Lord;", "rotherham": "Wherefore did ye not eat the sin-bearer in the holy place? for most, holy, it is,—and thee same, hath he given you that ye may bear the iniquity of the assembly, to put a propitiatory-covering over them before Yahweh.", "darby": "Why have ye not eaten the sin-offering in a holy place? for it is most holy, and he has given it to you that ye might bear the iniquity of the assembly, to make atonement for them before Jehovah.", "twenty": "", "jps": "'Wherefore have ye not eaten the sin-offering in the place of the sanctuary, seeing it is most holy, and He hath given it you to bear the iniquity of the congregation, to make atonement for them before HaShem?", "acv": "Why have ye not eaten the sin offering in the place of the sanctuary, seeing it is most holy, and he has given it to you to bear the iniquity of the congregation, to make atonement for them before Jehovah?", "anderson": "", "haweis": "", "noyes": "", "webster": "Why have ye not eaten the sin-offering in the holy place, seeing it [is] most holy, and [God] hath given it you to bear the iniquity of the congregation, to make atonement for them before the LORD?", "vulgate": "cur non comedistis hostiam pro peccato in loco sancto quae sancta sanctorum est et data vobis ut portetis iniquitatem multitudinis et rogetis pro ea in conspectu Domini;", "brenton": "Why did ye not eat the sin-offering in the holy place? for because it is most holy he has given you this to eat, that ye might take away the sin of the congregation, and make atonement for them before the Lord."}}, {"v": 18, "ref": "10:18", "o": "הֵ֚ן לֹא הוּבָ֣א אֶת דָּמָ֔/הּ אֶל הַ/קֹּ֖דֶשׁ פְּנִ֑ימָה אָכ֨וֹל תֹּאכְל֥וּ אֹתָ֛/הּ בַּ/קֹּ֖דֶשׁ כַּ/אֲשֶׁ֥ר צִוֵּֽיתִי", "en": {"kjv": "Behold, the blood of it was not brought in within the holy place: ye should indeed have eaten it in the holy place, as I commanded.", "web": "Behold, its blood was not brought into the inner part of the sanctuary: you certainly should have eaten it in the sanctuary, as I commanded.”", "bsb": "Since its blood was not brought inside the holy place, you should have eaten it in the sanctuary area, as I commanded.”", "asv": "Behold, the blood of it was not brought into the sanctuary within: ye should certainly have eaten it in the sanctuary, as I commanded.", "ylt": "lo, its blood hath not been brought in unto the holy place within; eating ye do eat it in the holy place, as I have commanded.'", "tyndale": "Beholde, the bloude of it was not brought in within the holy place therfore shulde ye haue eaten it in the holy place as I commaunded.", "dra": "Especially, whereas none of the blood thereof hath been carried within the holy places: and you ought to have eaten it in the sanctuary, as was commanded me?", "bbe": "See, its blood was not taken into the holy place: certainly it was right for you to have taken it as food in the holy place, as I gave orders.", "geneva": "Beholde, the blood of it was not brought within the holy place: ye should haue eaten it in the holy place, as I commanded.", "wycliffe": "moost sithen of the blood therof is not borun yn with ynne hooli thingis, and ye ouyten ete it in the seyntuarie, as it is comaundid to me?", "rotherham": "Lo! the blood thereof had not been taken into the holy place, within,—ye should have, indeed eaten, it, in a holy place, as I commanded.", "darby": "Lo, its blood was not brought in within the sanctuary: ye should certainly have eaten it in the sanctuary, as I commanded.", "twenty": "", "jps": "Behold, the blood of it was not brought into the sanctuary within; ye should certainly have eaten it in the sanctuary, as I commanded.'", "acv": "Behold, the blood of it was not brought into the sanctuary inside. Ye should certainly have eaten it in the sanctuary, as I commanded.", "anderson": "", "haweis": "", "noyes": "", "webster": "Behold, the blood of it was not brought within the holy [place]: ye should indeed have eaten it in the holy [place], as I commanded.", "vulgate": "praesertim cum de sanguine illius non sit inlatum intra sancta et comedere eam debueritis in sanctuario sicut praeceptum est mihi;", "brenton": "For the blood of it was not brought into the holy place: ye shall eat it within, before the Lord, as the Lord commanded me."}}, {"v": 19, "ref": "10:19", "o": "וַ/יְדַבֵּ֨ר אַהֲרֹ֜ן אֶל מֹשֶׁ֗ה הֵ֣ן הַ֠/יּוֹם הִקְרִ֨יבוּ אֶת חַטָּאתָ֤/ם וְ/אֶת עֹֽלָתָ/ם֙ לִ/פְנֵ֣י יְהוָ֔ה וַ/תִּקְרֶ֥אנָה אֹתִ֖/י כָּ/אֵ֑לֶּה וְ/אָכַ֤לְתִּי חַטָּאת֙ הַ/יּ֔וֹם הַ/יִּיטַ֖ב בְּ/עֵינֵ֥י יְהוָֽה", "en": {"kjv": "And Aaron said unto Moses, Behold, this day have they offered their sin offering and their burnt offering before the Lord; and such things have befallen me: and if I had eaten the sin offering to day, should it have been accepted in the sight of the Lord?", "web": "Aaron spoke to Moses, “Behold, this day they have offered their sin offering and their burnt offering before Yahweh; and such things as these have happened to me. If I had eaten the sin offering today, would it have been pleasing in the sight of Yahweh?”", "bsb": "But Aaron replied to Moses, “Behold, this very day they presented their sin offering and their burnt offering before the LORD. Since these things have happened to me, if I had eaten the sin offering today, would it have been acceptable in the sight of the LORD?”", "asv": "And Aaron spake unto Moses, Behold, this day have they offered their sin-offering and their burnt-offering before Jehovah; and there have befallen me such things as these: and if I had eaten the sin-offering to-day, would it have been well-pleasing in the sight of Jehovah?", "ylt": "And Aaron speaketh unto Moses, `Lo, to-day they have brought near their sin-offering and their burnt-offering before Jehovah; and things like these meet me, yet I have eaten a sin-offering to-day; is it good in the eyes of Jehovah?'", "tyndale": "And Aaron sayde vnto Moses: behold, this daye haue they offered their synneoffrynge and their burntoffrynge before the Lorde, and it is chaunced me after thys maner. Yf I shulde eate of the synneofferynge to daye, wolde the Lorde be content with all?", "dra": "Aaron answered: This day hath been offered the victim for sin, and the holocaust before the Lord: and to me what thou seest has happened. How could I eat it, or please the Lord in the ceremonies, having a sorrowful heart?", "bbe": "And Aaron said to Moses, You have seen that today they have made their sin-offering and their burned offering before the Lord, and such things as these have come on me. If I had taken the sin-offering as food today, would it have been pleasing to the Lord?", "geneva": "And Aaron said vnto Moses, Behold, this day haue they offred their sinne offring, and their burnt offring before the Lord, and such things as thou knowest are come vnto mee: If I had eaten the sinne offring to day, should it haue bene accepted in the sight of the Lord?", "wycliffe": "And Aaron answeride, Sacrifice for synne, and brent sacrifice is offrid to dai bifor the Lord; sotheli this that thou seest, bifelde to me; how myyte Y ete it, ether plese God in cerymonyes with soreuful soule?", "rotherham": "Then spake Aaron unto Moses—Lo! this very day, when they had brought near their own sin-bearer, and their own ascending-sacrifice, there befell me such things as these,—if, then, I had eaten of the sin-bearer this day, would it have been well-pleasing in the eyes of Yahweh?", "darby": "And Aaron said to Moses, Behold, to-day have they presented their sin-offering and their burnt-offering before Jehovah; and such things have befallen me; and had I to-day eaten the sin-offering, would it have been good in the sight of Jehovah?", "twenty": "", "jps": "And Aaron spoke unto Moses: 'Behold, this day have they offered their sin-offering and their burnt-offering before HaShem, and there have befallen me such things as these; and if I had eaten the sin-offering to-day, would it have been well-pleasing in the sight of HaShem?", "acv": "And Aaron spoke to Moses, Behold, this day they have offered their sin offering and their burnt offering before Jehovah, and there have befallen me such things as these. And if I had eaten the sin offering today, would it have been well-pleasing in the sight of Jehovah?", "anderson": "", "haweis": "", "noyes": "", "webster": "And Aaron said to Moses, Behold, this day have they offered their sin-offering, and their burnt-offering before the LORD; and such things have befallen me: and [if] I had eaten the sin-offering to day, would it have been accepted in the sight of the LORD?", "vulgate": "respondit Aaron oblata est hodie victima pro peccato et holocaustum coram Domino mihi autem accidit quod vides quomodo potui comedere eam aut placere Domino in caerimoniis mente lugubri;", "brenton": "And Aaron spoke to Moses, saying, If they have brought nigh to-day their sin-offerings, and their whole-burnt-offerings before the Lord, and these events have happened to me, and yet I should eat to-day of the sin-offerings, would it be pleasing to the Lord?"}}, {"v": 20, "ref": "10:20", "o": "וַ/יִּשְׁמַ֣ע מֹשֶׁ֔ה וַ/יִּיטַ֖ב בְּ/עֵינָֽי/ו", "en": {"kjv": "And when Moses heard that, he was content.", "web": "When Moses heard that, it was pleasing in his sight.", "bsb": "And when Moses heard this explanation, he was satisfied.", "asv": "And when Moses heard that, it was well-pleasing in his sight.", "ylt": "And Moses hearkeneth, and it is good in his eyes.", "tyndale": "And when Moses herde that, he was content.", "dra": "Which when Moses had heard he was satisfied.", "bbe": "And after hearing this, Moses was no longer angry.", "geneva": "So when Moses heard it, he was content.", "wycliffe": "And whanne Moises hadde herd this, he resseyuede satisfaccioun.", "rotherham": "And, when Moses heard that, then was it well-pleasing in his eyes.", "darby": "And Moses heard it; and it was good in his sight.", "twenty": "", "jps": "And when Moses heard that, it was well-pleasing in his sight.", "acv": "And when Moses heard, it was well-pleasing in his sight.", "anderson": "", "haweis": "", "noyes": "", "webster": "And when Moses heard [that], he was content.", "vulgate": "quod cum audisset Moses recepit satisfactionem;", "brenton": "And Moses heard it, and it pleased him."}}]}, {"c": 11, "verses": [{"v": 1, "ref": "11:1", "o": "וַ/יְדַבֵּ֧ר יְהוָ֛ה אֶל מֹשֶׁ֥ה וְ/אֶֽל אַהֲרֹ֖ן לֵ/אמֹ֥ר אֲלֵ/הֶֽם", "en": {"kjv": "And the Lord spake unto Moses and to Aaron, saying unto them,", "web": "Yahweh spoke to Moses and to Aaron, saying to them,", "bsb": "The LORD spoke again to Moses and Aaron, telling them,", "asv": "And Jehovah spake unto Moses and to Aaron, saying unto them,", "ylt": "And Jehovah speaketh unto Moses and unto Aaron, saying unto them,", "tyndale": "And the Lorde spake vnto Moses and Aaron sayenge:", "dra": "And the Lord spoke to Moses and Aaron, saying:", "bbe": "And the Lord said to Moses and Aaron,", "geneva": "After, the Lord spake vnto Moses and to Aaron, saying vnto them,", "wycliffe": "And the Lord spak to Moises and Aaron, and seide,", "rotherham": "And Yahweh spake unto Moses and unto Aaron, saying unto them:", "darby": "And Jehovah spoke to Moses and to Aaron, saying to them,", "twenty": "", "jps": "And HaShem spoke unto Moses and to Aaron, saying unto them:", "acv": "And Jehovah spoke to Moses and to Aaron, saying to them,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses and to Aaron, saying to them.", "vulgate": "locutus est Dominus ad Mosen et Aaron dicens;", "brenton": "And the Lord spoke to Moses and Aaron, saying,"}}, {"v": 2, "ref": "11:2", "o": "דַּבְּר֛וּ אֶל בְּנֵ֥י יִשְׂרָאֵ֖ל לֵ/אמֹ֑ר זֹ֤את הַֽ/חַיָּה֙ אֲשֶׁ֣ר תֹּאכְל֔וּ מִ/כָּל הַ/בְּהֵמָ֖ה אֲשֶׁ֥ר עַל הָ/אָֽרֶץ", "en": {"kjv": "Speak unto the children of Israel, saying, These are the beasts which ye shall eat among all the beasts that are on the earth.", "web": "“Speak to the children of Israel, saying, ‘These are the living things which you may eat among all the animals that are on the earth.", "bsb": "“Say to the Israelites, ‘Of all the beasts of the earth, these ones you may eat:", "asv": "Speak unto the children of Israel, saying, These are the living things which ye may eat among all the beasts that are on the earth.", "ylt": "`Speak unto the sons of Israel, saying, This is the beast which ye do eat out of all the beasts which are on the earth:", "tyndale": "speake vnto the childre of Israel and saye, these are the beestes whiche ye shall eate amonge all the beestes that are on the erth:", "dra": "Say to the children of Israel: These are the animals which you are to eat of all the living things of the earth.", "bbe": "Say to the children of Israel: These are the living things which you may have for food among all the beasts on the earth.", "geneva": "Speake vnto the children of Israel, and say, These are the beastes which yee shall eate, among all the beasts that are on the earth.", "wycliffe": "Seie ye to the sones of Israel, Kepe ye alle thingis whiche Y wroot to you, that Y be youre God. These ben the beestis, whiche ye schulen ete, of alle lyuynge beestis of erthe;", "rotherham": "Speak ye unto the sons of Israel saying,—These are the living things which ye may eat, of all the beasts which are upon the earth:", "darby": "Speak unto the children of Israel, saying, These are the animals which ye shall eat of all the beasts which are on the earth.", "twenty": "", "jps": "Speak unto the children of Israel, saying: These are the living things which ye may eat among all the beasts that are on the earth.", "acv": "Speak to the sons of Israel, saying, These are the living things which ye may eat among all the beasts that are on the earth.", "anderson": "", "haweis": "", "noyes": "", "webster": "Speak to the children of Israel, saying, These [are] the beasts which ye may eat among all the beasts that [are] on the earth.", "vulgate": "dicite filiis Israhel haec sunt animalia quae comedere debetis de cunctis animantibus terrae;", "brenton": "Speak ye to the sons of Israel, saying, These are the beasts which ye shall eat of all beasts that are upon the earth."}}, {"v": 3, "ref": "11:3", "o": "כֹּ֣ל מַפְרֶ֣סֶת פַּרְסָ֗ה וְ/שֹׁסַ֤עַת שֶׁ֨סַע֙ פְּרָסֹ֔ת מַעֲלַ֥ת גֵּרָ֖ה בַּ/בְּהֵמָ֑ה אֹתָ֖/הּ תֹּאכֵֽלוּ", "en": {"kjv": "Whatsoever parteth the hoof, and is clovenfooted, and cheweth the cud, among the beasts, that shall ye eat.", "web": "Whatever parts the hoof, and is cloven-footed, and chews the cud among the animals, that you may eat.", "bsb": "You may eat any animal that has a split hoof completely divided and that chews the cud.", "asv": "Whatsoever parteth the hoof, and is clovenfooted, and cheweth the cud, among the beasts, that may ye eat.", "ylt": "any dividing a hoof, and cleaving the cleft of the hoofs, bringing up the cud, among the beasts, it ye do eat.", "tyndale": "what soeuer hath hoffe and dyuydeth it in to two clawes ad cheweth cud among the beestes, that shall ye eate.", "dra": "Whatsoever hath the hoof divided, and cheweth the cud among the beasts, you shall eat.", "bbe": "You may have as food any beast which has a division in the horn of its foot, and whose food comes back into its mouth to be crushed again.", "geneva": "Whatsoeuer parteth the hoofe, and is clouen footed, and cheweth the cudde, among the beastes, that shall ye eate.", "wycliffe": "ye schulen ete `al thing among beestis that hath a clee departid, and chewith code;", "rotherham": "Whatsoever parteth the hoof and is cloven-footed, and cheweth the cud among beasts, that, may ye eat.", "darby": "Whatever hath cloven hoofs, and feet quite split open, and cheweth the cud, among the beasts — that shall ye eat.", "twenty": "", "jps": "Whatsoever parteth the hoof, and is wholly cloven-footed, and cheweth the cud, among the beasts, that may ye eat.", "acv": "Whatever parts the hoof, and is cloven footed, and chews the cud, among the beasts, that may ye eat.", "anderson": "", "haweis": "", "noyes": "", "webster": "Whatever parteth the hoof, and is cloven-footed, [and] cheweth the cud among the beasts, that shall ye eat.", "vulgate": "omne quod habet divisam ungulam et ruminat in pecoribus comedetis;", "brenton": "Every beast parting the hoof and making divisions of two claws, and chewing the cud among beasts, these ye shall eat."}}, {"v": 4, "ref": "11:4", "o": "אַ֤ךְ אֶת זֶה֙ לֹ֣א תֹֽאכְל֔וּ מִֽ/מַּעֲלֵי֙ הַ/גֵּרָ֔ה וּ/מִ/מַּפְרִיסֵ֖י הַ/פַּרְסָ֑ה אֶֽת הַ֠/גָּמָל כִּֽי מַעֲלֵ֨ה גֵרָ֜ה ה֗וּא וּ/פַרְסָה֙ אֵינֶ֣/נּוּ מַפְרִ֔יס טָמֵ֥א ה֖וּא לָ/כֶֽם", "en": {"kjv": "Nevertheless these shall ye not eat of them that chew the cud, or of them that divide the hoof: as the camel, because he cheweth the cud, but divideth not the hoof; he is unclean unto you.", "web": "“‘Nevertheless these you shall not eat of those that chew the cud, or of those who part the hoof: the camel, because he chews the cud but doesn’t have a parted hoof, he is unclean to you.", "bsb": "But of those that only chew the cud or only have a divided hoof, you are not to eat the following: The camel, though it chews the cud, does not have a divided hoof; it is unclean for you.", "asv": "Nevertheless these shall ye not eat of them that chew the cud, or of them that part the hoof: the camel, because he cheweth the cud but parteth not the hoof, he is unclean unto you.", "ylt": "`Only, this ye do not eat--of those bringing up the cud, and of those dividing the hoof--the camel, though it is bringing up the cud, yet the hoof not dividing--it is unclean to you;", "tyndale": "Neuerthelesse, these shall ye not eate of them that chewe cud and haue hoffes. The camel, for he cheweth cud but he deuydeth not the hoffe in to two clawes therfore he shall be vnclene vnto you.", "dra": "But whatsoever cheweth indeed the cud, and hath a hoof, but divideth it not, as the camel, and others: that you shall not eat, but shall reckon it among the unclean.", "bbe": "But, at the same time, of those beasts, you may not take for food the camel, because its food comes back but the horn of its foot is not parted in two; it is unclean to you.", "geneva": "But of them that chewe the cud, or deuide the hoofe onely, of them yee shall not eate: as the camel, because he cheweth the cud, and deuideth not ye hoofe, he shall be vncleane vnto you.", "wycliffe": "sotheli what euer thing chewith code, and hath a clee, but departith not it, as a camel and othere beestis doon, ye schulen not ete it, and ye schulen arette among vnclene thingis.", "rotherham": "Nevertheless, these, shall ye not eat, of them that chew the cud, and of them that part the hoof,—the camel, because though he, cheweth the cud, yet, the hoof, he parteth not, unclean, he is to you;", "darby": "Only these shall ye not eat of those that chew the cud, or of those with cloven hoofs: the camel, for it cheweth the cud, but hath not cloven hoofs — it shall be unclean unto you;", "twenty": "", "jps": "Nevertheless these shall ye not eat of them that only chew the cud, or of them that only part the hoof: the camel, because he cheweth the cud but parteth not the hoof, he is unclean unto you.", "acv": "Nevertheless these shall ye not eat of those that chew the cud, or of those that part the hoof: the camel, because he chews the cud but does not part the hoof, he is unclean to you.", "anderson": "", "haweis": "", "noyes": "", "webster": "Nevertheless, these shall ye not eat, of them that chew the cud, or of them that divide the hoof: the camel, because he cheweth the cud, but divideth not the hoof; he [is] unclean to you.", "vulgate": "quicquid autem ruminat quidem et habet ungulam sed non dividit eam sicut camelus et cetera non comedetis illud et inter inmunda reputabitis;", "brenton": "But of these ye shall not eat, of those that chew the cud, and of those that part the hoofs, and divide claws; the camel, because it chews the cud, but does not divide the hoof, this is unclean to you."}}, {"v": 5, "ref": "11:5", "o": "וְ/אֶת הַ/שָּׁפָ֗ן כִּֽי מַעֲלֵ֤ה גֵרָה֙ ה֔וּא וּ/פַרְסָ֖ה לֹ֣א יַפְרִ֑יס טָמֵ֥א ה֖וּא לָ/כֶֽם", "en": {"kjv": "And the coney, because he cheweth the cud, but divideth not the hoof; he is unclean unto you.", "web": "The cony, because he chews the cud but doesn’t have a parted hoof, he is unclean to you.", "bsb": "The rock badger, though it chews the cud, does not have a divided hoof; it is unclean for you.", "asv": "And the coney, because he cheweth the cud but parteth not the hoof, he is unclean unto you.", "ylt": "and the rabbit, though it is bringing up the cud, yet the hoof it divideth not--unclean it is to you;", "tyndale": "And the Conye, for he cheweth the cud but deuydeth not the hoffe in to two clawes, therfore he is vnclene to you.", "dra": "The cherogrillus which cheweth the cud, but divideth not the hoof, is unclean.", "bbe": "And the rock-badger, for the same reason, is unclean to you.", "geneva": "Likewise the conie, because he cheweth the cud and deuideth not the hoofe, he shall bee vncleane to you.", "wycliffe": "A cirogrille , which chewith code, and departith not the clee, is vnclene; and an hare,", "rotherham": "And, the coney, because, though he cheweth the cud, yet, the hoof, he parteth not,—unclean, he is to you;", "darby": "and the rock-badger, for it cheweth the cud, but hath not cloven hoofs — it shall be unclean unto you;", "twenty": "", "jps": "And the rock-badger, because he cheweth the cud but parteth not the hoof, he is unclean unto you.", "acv": "And the coney, because he chews the cud but does not part the hoof, he is unclean to you.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the coney, because he cheweth the cud, but divideth not the hoof; he [is] unclean to you.", "vulgate": "chyrogryllius qui ruminat ungulamque non dividit inmundus est;", "brenton": "And the rabbit, because it chews the cud, but does not divide the hoof, this is unclean to you."}}, {"v": 6, "ref": "11:6", "o": "וְ/אֶת הָ/אַרְנֶ֗בֶת כִּֽי מַעֲלַ֤ת גֵּרָה֙ הִ֔וא וּ/פַרְסָ֖ה לֹ֣א הִפְרִ֑יסָה טְמֵאָ֥ה הִ֖וא לָ/כֶֽם", "en": {"kjv": "And the hare, because he cheweth the cud, but divideth not the hoof; he is unclean unto you.", "web": "The hare, because she chews the cud but doesn’t part the hoof, she is unclean to you.", "bsb": "The rabbit, though it chews the cud, does not have a divided hoof; it is unclean for you.", "asv": "And the hare, because she cheweth the cud but parteth not the hoof, she is unclean unto you.", "ylt": "and the hare, though it is bringing up the cud, yet the hoof hath not divided--unclean it is to you;", "tyndale": "And the hare, for he likewise cheweth the cud, but deuydeth not the hoffe in to two clawes, he is therfore vnclene to you.", "dra": "The hare also: for that too cheweth the cud, but divideth not the hoof.", "bbe": "And the hare, because the horn of its foot is not parted in two, is unclean to you.", "geneva": "Also the hare, because he cheweth the cud, and deuideth not the hoofe, he shalbe vncleane to you.", "wycliffe": "for also he chewith code, but departith not the clee;", "rotherham": "And the hare, because though she cheweth the cud, yet the hoof, she parteth not,—unclean, she is to you;", "darby": "and the hare, for it cheweth the cud, but hath not cloven hoofs — it shall be unclean unto you;", "twenty": "", "jps": "And the hare, because she cheweth the cud but parteth not the hoof, she is unclean unto you", "acv": "And the hare, because she chews the cud but does not part the hoof, she is unclean to you.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the hare, because he cheweth the cud, but divideth not the hoof: he [is] unclean to you.", "vulgate": "lepus quoque nam et ipse ruminat sed ungulam non dividit;", "brenton": "And the hare, because it does not chew the cud, and does not divide the hoof, this is unclean to you."}}, {"v": 7, "ref": "11:7", "o": "וְ/אֶת הַ֠/חֲזִיר כִּֽי מַפְרִ֨יס פַּרְסָ֜ה ה֗וּא וְ/שֹׁסַ֥ע שֶׁ֨סַע֙ פַּרְסָ֔ה וְ/ה֖וּא גֵּרָ֣ה לֹֽא יִגָּ֑ר טָמֵ֥א ה֖וּא לָ/כֶֽם", "en": {"kjv": "And the swine, though he divide the hoof, and be clovenfooted, yet he cheweth not the cud; he is unclean to you.", "web": "The pig, because he has a split hoof, and is cloven-footed, but doesn’t chew the cud, he is unclean to you.", "bsb": "And the pig, though it has a split hoof completely divided, does not chew the cud; it is unclean for you.", "asv": "And the swine, because he parteth the hoof, and is clovenfooted, but cheweth not the cud, he is unclean unto you.", "ylt": "and the sow, though it is dividing the hoof, and cleaving the cleft of the hoof, yet the cud it bringeth not up--unclean it is to you.", "tyndale": "And the swyne, for though he deuyde the hoffe in to two clawes, yet he cheweth not the cud ad therfore is vnclene to you,", "dra": "And the swine, which, though it divideth the hoof, cheweth not the cud.", "bbe": "And the pig is unclean to you, because though the horn of its foot is parted, its food does not come back.", "geneva": "And the swine, because he parteth ye hoofe and is clouen footed, but cheweth not the cud, he shalbe vncleane to you.", "wycliffe": "and a swiyn, that chewith not code, thouy he departith the clee.", "rotherham": "And, the swine, because though he parteth the hoof, and is cloven-footed, yet, the cud, he cheweth not,—unclean, he is to you;", "darby": "and the swine, for it hath cloven hoofs, and feet quite split open, but it cheweth not the cud — it shall be unclean unto you.", "twenty": "", "jps": "And the swine, because he parteth the hoof, and is cloven-footed, but cheweth not the cud, he is unclean unto you.", "acv": "And the swine, because he parts the hoof, and is cloven footed, but does not chew the cud, he is unclean to you.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the swine, though he divideth the hoof, and [is] cloven-footed, yet he cheweth not the cud; he [is] unclean to you.", "vulgate": "et sus qui cum ungulam dividat non ruminat;", "brenton": "And the swine, because this animal divides the hoof, and makes claws of the hoof, and it does not chew the cud, is unclean to you."}}, {"v": 8, "ref": "11:8", "o": "מִ/בְּשָׂרָ/ם֙ לֹ֣א תֹאכֵ֔לוּ וּ/בְ/נִבְלָתָ֖/ם לֹ֣א תִגָּ֑עוּ טְמֵאִ֥ים הֵ֖ם לָ/כֶֽם", "en": {"kjv": "Of their flesh shall ye not eat, and their carcase shall ye not touch; they are unclean to you.", "web": "Of their flesh you shall not eat, and their carcasses you shall not touch; they are unclean to you.", "bsb": "You must not eat their meat or touch their carcasses; they are unclean for you.", "asv": "Of their flesh ye shall not eat, and their carcasses ye shall not touch; they are unclean unto you.", "ylt": "`Of their flesh ye do not eat, and against their carcase ye do not come--unclean they are to you.", "tyndale": "Of their flesh see that ye eate not ad their carkasses se that ye twych not for they are vnclene to you.", "dra": "The flesh of these you shall not eat, nor shall you touch their carcasses, because they are unclean to you.", "bbe": "Their flesh may not be used for food, and their dead bodies may not even be touched; they are unclean to you.", "geneva": "Of their flesh shall yee not eate, and their carkeise shall yee not touch: for they shall bee vncleane to you.", "wycliffe": "Ye schulen not ete the fleischis of these, nether ye schulen touche the deed bodies, for tho ben vnclene to you.", "rotherham": "Of their flesh, shall ye not eat, and, their carcase, shall ye not touch,—unclean, they are to you.", "darby": "Of their flesh shall ye not eat, and their carcase shall ye not touch: they shall be unclean unto you.", "twenty": "", "jps": "Of their flesh ye shall not eat, and their carcasses ye shall not touch; they are unclean unto you.", "acv": "Of their flesh ye shall not eat, and their carcasses ye shall not touch, they are unclean to you.", "anderson": "", "haweis": "", "noyes": "", "webster": "Of their flesh shall ye not eat, and their carcass shall ye not touch; they [are] unclean to you.", "vulgate": "horum carnibus non vescemini nec cadavera contingetis quia inmunda sunt vobis;", "brenton": "Ye shall not eat of their flesh, and ye shall not touch their carcases; these are unclean to you."}}, {"v": 9, "ref": "11:9", "o": "אֶת זֶה֙ תֹּֽאכְל֔וּ מִ/כֹּ֖ל אֲשֶׁ֣ר בַּ/מָּ֑יִם כֹּ֣ל אֲשֶׁר ל/וֹ֩ סְנַפִּ֨יר וְ/קַשְׂקֶ֜שֶׂת בַּ/מַּ֗יִם בַּ/יַּמִּ֛ים וּ/בַ/נְּחָלִ֖ים אֹתָ֥/ם תֹּאכֵֽלוּ", "en": {"kjv": "These shall ye eat of all that are in the waters: whatsoever hath fins and scales in the waters, in the seas, and in the rivers, them shall ye eat.", "web": "“‘These you may eat of all that are in the waters: whatever has fins and scales in the waters, in the seas, and in the rivers, that you may eat.", "bsb": "Of all the creatures that live in the water, whether in the seas or in the streams, you may eat anything with fins and scales.", "asv": "These may ye eat of all that are in the waters: whatsoever hath fins and scales in the waters, in the seas, and in the rivers, that may ye eat.", "ylt": "`This ye do eat of all which are in the waters; any one that hath fins and scales in the waters, in the seas, and in the brooks, them ye do eat;", "tyndale": "These shall ye eate of all that are in the waters: what soeuer hath finnes and skales in the waters, sees and ryuers, that shall ye eate.", "dra": "These are the things that breed in the waters, and which it is lawful to eat. All that hath fins, and scales, as well in the sea, as in the rivers, and the pools, you shall eat.", "bbe": "These you may have for food of all things living in the water: anything living in the water, in the seas or rivers, which has special parts for swimming and skin formed of thin plates, may be used for food.", "geneva": "These shall ye eate, of all that are in the waters: whatsoeuer hath finnes and skales in ye waters, in the seas, or in the riuers, them shall ye eate.", "wycliffe": "Also these thingis ben that ben gendrid in watris, and is leueful to ete;", "rotherham": "these, may ye eat, of all that are in the waters,—all that have fins and scales in the waters, in the seas and in the rivers, them, may ye eat.", "darby": "These shall ye eat of all that are in the waters: whatever hath fins and scales in waters, in seas and in rivers, these shall ye eat;", "twenty": "", "jps": "These may ye eat of all that are in the waters: whatsoever hath fins and scales in the waters, in the seas, and in the rivers, them may ye eat.", "acv": "These may ye eat of all that are in the waters: whatever has fins and scales in the waters, in the seas, and in the rivers, that may ye eat.", "anderson": "", "haweis": "", "noyes": "", "webster": "These shall ye eat, of all that [are] in the waters: whatever hath fins and scales in the waters, in the seas, and in the rivers, them shall ye eat.", "vulgate": "haec sunt quae gignuntur in aquis et vesci licitum est omne quod habet pinnulas et squamas tam in mari quam in fluminibus et stagnis comedetis;", "brenton": "And these are what ye shall eat of all that are in the waters: all things that have fins and scales in the waters, and in the seas, and in the brooks, these ye shall eat."}}, {"v": 10, "ref": "11:10", "o": "וְ/כֹל֩ אֲשֶׁ֨ר אֵֽין ל֜/וֹ סְנַפִּ֣יר וְ/קַשְׂקֶ֗שֶׂת בַּ/יַּמִּים֙ וּ/בַ/נְּחָלִ֔ים מִ/כֹּל֙ שֶׁ֣רֶץ הַ/מַּ֔יִם וּ/מִ/כֹּ֛ל נֶ֥פֶשׁ הַ/חַיָּ֖ה אֲשֶׁ֣ר בַּ/מָּ֑יִם שֶׁ֥קֶץ הֵ֖ם לָ/כֶֽם", "en": {"kjv": "And all that have not fins and scales in the seas, and in the rivers, of all that move in the waters, and of any living thing which is in the waters, they shall be an abomination unto you:", "web": "All that don’t have fins and scales in the seas, and in the rivers, of all that move in the waters, and of all the living creatures that are in the waters, they are an abomination to you,", "bsb": "But the following among all the teeming life and creatures in the water are detestable to you: everything in the seas or streams that does not have fins and scales.", "asv": "And all that have not fins and scales in the seas, and in the rivers, of all that move in the waters, and of all the living creatures that are in the waters, they are an abomination unto you,", "ylt": "and any one that hath not fins and scales in the seas, and in the brooks, of any teeming creature of the waters, and of any creature which liveth, which is in the waters--an abomination they are to you;", "tyndale": "And all that haue not finnes ad skales in the sees ad ryuers of all that moue and lyue in the waters shall ye abhorre.", "dra": "But whatsoever hath not fins and scales, of those things that move and live in the waters, shall be an abomination to you,", "bbe": "All other things living and moving in the water, in the sea or in the rivers, are a disgusting thing to you;", "geneva": "But all that haue not finnes nor skales in the seas, or in the riuers, of all that moueth in the waters, and of al liuing things that are in the waters, they shalbe an abomination vnto you.", "wycliffe": "ye schulen ete al thing that hath fynnes and scalis, as wel in the see, as in floodis and stondynge watris; sotheli what euer thing of tho that ben moued and lyuen in watris, hath not fynnes and scalis, schal be abhominable, and wlatsum to you;", "rotherham": "But, all that have not fins and scales, in the seas and in the rivers, of all that swarm in the waters, and of all the living souls that are in the waters, an abomination, they are unto you;", "darby": "but all that have not fins and scales in seas and in rivers, of all that swarm in the waters, and of every living soul which is in the waters — they shall be an abomination unto you.", "twenty": "", "jps": "And all that have not fins and scales in the seas, and in the rivers, of all that swarm in the waters, and of all the living creatures that are in the waters, they are a detestable thing unto you,", "acv": "And all that have no fins and scales in the seas, and in the rivers, of all that move in the waters, and of all the living creatures that are in the waters, they are an abomination to you,", "anderson": "", "haweis": "", "noyes": "", "webster": "And all that have not fins nor scales in the seas, and in the rivers, of all that move in the waters, and of any living animal which [is] in the waters, they [shall be] an abomination to you:", "vulgate": "quicquid autem pinnulas et squamas non habet eorum quae in aquis moventur et vivunt abominabile vobis;", "brenton": "And all things which have not fins or scales in the water, or in the seas, and in the brooks, of all which the waters produce, and of every soul living in the water, are an abomination; and they shall be abominations to you."}}, {"v": 11, "ref": "11:11", "o": "וְ/שֶׁ֖קֶץ יִהְי֣וּ לָ/כֶ֑ם מִ/בְּשָׂרָ/ם֙ לֹ֣א תֹאכֵ֔לוּ וְ/אֶת נִבְלָתָ֖/ם תְּשַׁקֵּֽצוּ", "en": {"kjv": "They shall be even an abomination unto you; ye shall not eat of their flesh, but ye shall have their carcases in abomination.", "web": "and you detest them. You shall not eat of their flesh, and you shall detest their carcasses.", "bsb": "They shall be an abomination to you; you must not eat their meat, and you must detest their carcasses.", "asv": "and they shall be an abomination unto you; ye shall not eat of their flesh, and their carcasses ye shall have in abomination.", "ylt": "yea, an abomination they are to you; of their flesh ye do not eat, and their carcase ye abominate.", "tyndale": "Se that ye eate not of their flesh, ad also that ye abhorre their carkases:", "dra": "And detestable. Their flesh you shall not eat: and their carcasses you shall avoid.", "bbe": "They may not be used for food, and their dead bodies are disgusting to you.", "geneva": "They, I say, shalbe an abomination to you: ye shall not eate of their flesh, but shall abhorre their carkeis.", "wycliffe": "ye schulen not ete the fleischis of tho, and ye schulen eschewe the bodies deed bi hem silf.", "rotherham": "and an abomination, shall they remain to you,—of their flesh, ye shall not eat, and their carcases, shall ye abhor.", "darby": "They shall be even an abomination unto you: of their flesh shall ye not eat, and their carcase ye shall have in abomination.", "twenty": "", "jps": "and they shall be a detestable thing unto you; ye shall not eat of their flesh, and their carcasses ye shall have in detestation.", "acv": "and they shall be an abomination to you. Ye shall not eat of their flesh, and their carcasses ye shall have in abomination.", "anderson": "", "haweis": "", "noyes": "", "webster": "They shall be even an abomination to you; ye shall not eat of their flesh, but ye shall have their carcasses in abomination.", "vulgate": "et execrandum erit carnes eorum non comedetis et morticina vitabitis;", "brenton": "Ye shall not eat of their flesh, and ye shall abhor their carcases."}}, {"v": 12, "ref": "11:12", "o": "כֹּ֣ל אֲשֶׁ֥ר אֵֽין ל֛/וֹ סְנַפִּ֥יר וְ/קַשְׂקֶ֖שֶׂת בַּ/מָּ֑יִם שֶׁ֥קֶץ ה֖וּא לָ/כֶֽם", "en": {"kjv": "Whatsoever hath no fins nor scales in the waters, that shall be an abomination unto you.", "web": "Whatever has no fins nor scales in the waters, that is an abomination to you.", "bsb": "Everything in the water that does not have fins and scales shall be detestable to you.", "asv": "Whatsoever hath no fins nor scales in the waters, that is an abomination unto you.", "ylt": "`Any one that hath not fins and scales in the waters--an abomination it is to you.", "tyndale": "for all that haue no finnes nor scales in the waters, shalbe abhominacion vnto you.", "dra": "All that have not fins and scales, in the waters, shall be unclean.", "bbe": "Anything in the water which has no special parts for swimming and no thin plates on its skin is disgusting to you.", "geneva": "Whatsoeuer hath not fins nor skales in the waters, that shalbe abomination vnto you.", "wycliffe": "Alle thingis in watris that han not fynnes and scalis, schulen be pollutid,", "rotherham": "Whatsoever hath not fins and scales in the waters, an abomination, it is unto you.", "darby": "Whatever in the waters hath no fins and scales, that shall be an abomination unto you.", "twenty": "", "jps": "Whatsoever hath no fins nor scales in the waters, that is a detestable thing unto you.", "acv": "Whatever has no fins nor scales in the waters, that is an abomination to you.", "anderson": "", "haweis": "", "noyes": "", "webster": "Whatever hath no fins nor scales in the waters, that [shall be] an abomination to you.", "vulgate": "cuncta quae non habent pinnulas et squamas in aquis polluta erunt;", "brenton": "And all things that have not fins or scales of those that are in the waters, these are an abomination to you."}}, {"v": 13, "ref": "11:13", "o": "וְ/אֶת אֵ֨לֶּה֙ תְּשַׁקְּצ֣וּ מִן הָ/ע֔וֹף לֹ֥א יֵאָכְל֖וּ שֶׁ֣קֶץ הֵ֑ם אֶת הַ/נֶּ֨שֶׁר֙ וְ/אֶת הַ/פֶּ֔רֶס וְ/אֵ֖ת הָ/עָזְנִיָּֽה", "en": {"kjv": "And these are they which ye shall have in abomination among the fowls; they shall not be eaten, they are an abomination: the eagle, and the ossifrage, and the ospray,", "web": "“‘These you shall detest among the birds; they shall not be eaten, they are an abomination: the eagle, and the vulture, and the black vulture,", "bsb": "Additionally, you are to detest the following birds, and they must not be eaten because they are detestable: the eagle, the bearded vulture, the black vulture,", "asv": "And these ye shall have in abomination among the birds; they shall not be eaten, they are an abomination: the eagle, and the gier-eagle, and the ospray,", "ylt": "`And these ye do abominate of the fowl; they are not eaten, an abomination they are : the eagle, and the ossifrage, and the ospray,", "tyndale": "These are the foules which ye shall abhorre and which shall not be eaten, for they are an abhominacion. The egle, the gooshauke, the cormoraunte, the kyte,", "dra": "Of birds these are they which you must not eat, and which are to be avoided by you: The eagle, and the griffon, and the osprey.", "bbe": "And among birds these are to be disgusting to you, and not to be used for food: the eagle and the gier-eagle and the ospray;", "geneva": "These shall ye haue also in abomination among the foules, they shall not be eaten: for they are an abomination, the eagle, and the goshauke, and the osprey:", "wycliffe": "These thingis ben of foulis whiche ye schulen not ete, and schulen be eschewid of you; an egle, and a grippe, aliete , and a kyte, and a vultur by his kynde;", "rotherham": "And, these, shall ye abhor of birds, they shall not be eaten, an abomination, they are,—the eagle, and the ossifrage, and the osprey;", "darby": "And these shall ye have in abomination of the fowls; they shall not be eaten; an abomination shall they be: the eagle, and the ossifrage, and the sea-eagle,", "twenty": "", "jps": "And these ye shall have in detestation among the fowls; they shall not be eaten, they are a detestable thing: the great vulture, and the bearded vulture, and the ospray;", "acv": "And these ye shall have in abomination among the birds, they shall not be eaten, they are an abomination: the eagle, and the vulture, and the osprey,", "anderson": "", "haweis": "", "noyes": "", "webster": "And these [are they which] ye shall have in abomination among the fowls; they shall not be eaten, they [are] an abomination: the eagle, and the ossifrage, and the ospray,", "vulgate": "haec sunt quae de avibus comedere non debetis et vitanda sunt vobis aquilam et grypem et alietum;", "brenton": "And these are the things which ye shall abhor of birds, and they shall not be eaten, they are an abomination: the eagle and the ossifrage, and the sea-eagle."}}, {"v": 14, "ref": "11:14", "o": "וְ/אֶת הַ֨/דָּאָ֔ה וְ/אֶת הָ/אַיָּ֖ה לְ/מִינָֽ/הּ", "en": {"kjv": "And the vulture, and the kite after his kind;", "web": "and the red kite, any kind of black kite,", "bsb": "the kite, any kind of falcon,", "asv": "and the kite, and the falcon after its kind,", "ylt": "and the vulture, and the kite after its kind,", "tyndale": "the vultur and all his kynd", "dra": "And the kite, and the vulture, according to their kind.", "bbe": "And the kite and the falcon, and birds of that sort;", "geneva": "Also the vultur, and the kite after his kinde,", "wycliffe": "and al of `rauyns kynde bi his licnesse;", "rotherham": "and the vulture, and the falcon, after its kind;", "darby": "and the falcon, and the kite, after its kind;", "twenty": "", "jps": "and the kite, and the falcon after its kinds;", "acv": "and the kite, and the falcon after its kind,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the vultur, and the kite after his kind;", "vulgate": "milvum ac vulturem iuxta genus suum;", "brenton": "And the vulture, and the kite, and the like to it;"}}, {"v": 15, "ref": "11:15", "o": "אֵ֥ת כָּל עֹרֵ֖ב לְ/מִינֽ/וֹ", "en": {"kjv": "Every raven after his kind;", "web": "any kind of raven,", "bsb": "any kind of raven,", "asv": "every raven after its kind,", "ylt": "every raven after its kind,", "tyndale": "and all kynde of rauens,", "dra": "And all that is of the raven kind, according to their likeness.", "bbe": "Every raven, and birds of that sort;", "geneva": "And all rauens after their kinde:", "wycliffe": "a strucioun,", "rotherham": "every raven, after its kind;", "darby": "every raven after its kind;", "twenty": "", "jps": "every raven after its kinds;", "acv": "every raven after its kind,", "anderson": "", "haweis": "", "noyes": "", "webster": "Every raven after his kind;", "vulgate": "et omne corvini generis in similitudinem suam;", "brenton": "and the sparrow, and the owl, and the sea-mew, and the like to it:"}}, {"v": 16, "ref": "11:16", "o": "וְ/אֵת֙ בַּ֣ת הַֽ/יַּעֲנָ֔ה וְ/אֶת הַ/תַּחְמָ֖ס וְ/אֶת הַ/שָּׁ֑חַף וְ/אֶת הַ/נֵּ֖ץ לְ/מִינֵֽ/הוּ", "en": {"kjv": "And the owl, and the night hawk, and the cuckow, and the hawk after his kind,", "web": "the horned owl, the screech owl, and the gull, any kind of hawk,", "bsb": "the ostrich, the screech owl, the gull, any kind of hawk,", "asv": "and the ostrich, and the night-hawk, and the sea-mew, and the hawk after its kind,", "ylt": "and the owl, and the night-hawk, and the cuckoo, and the hawk after its kind,", "tyndale": "the estrich, the nightcrowe, the cocow, the sparowhauke and al the kynde:", "dra": "The ostrich, and the owl, and the larus, and the hawk according to its kind.", "bbe": "And the ostrich and the night-hawk and the sea-hawk, and birds of that sort;", "geneva": "The ostrich also, and the night crowe, and the seameaw, and the hauke after his kinde:", "wycliffe": "and nyyt crowe, a lare, and an hauke bi his kinde;", "rotherham": "and the female ostrich, and the male ostrich, and the sea-gull,—and the hawk after its kind;", "darby": "and the female ostrich and the male ostrich, and the sea-gull, and the hawk, after its kind;", "twenty": "", "jps": "and the ostrich, and the night-hawk, and the sea-mew, and the hawk after its kinds;", "acv": "and the ostrich, and the night-hawk, and the sea-gull, and the hawk after its kind,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the owl, and the night-hawk, and the cuckow, and the hawk after his kind,", "vulgate": "strutionem et noctuam et larum et accipitrem iuxta genus suum;", "brenton": "and every raven, and the birds like it, and the hawk and his like,"}}, {"v": 17, "ref": "11:17", "o": "וְ/אֶת הַ/כּ֥וֹס וְ/אֶת הַ/שָּׁלָ֖ךְ וְ/אֶת הַ/יַּנְשֽׁוּף", "en": {"kjv": "And the little owl, and the cormorant, and the great owl,", "web": "the little owl, the cormorant, the great owl,", "bsb": "the little owl, the cormorant, the great owl,", "asv": "and the little owl, and the cormorant, and the great owl,", "ylt": "and the little owl, and the cormorant, and the great owl,", "tyndale": "the litle oule, the storcke, the great oule", "dra": "The screech owl, and the cormorant, and the ibis.", "bbe": "And the little owl and the cormorant and the great owl;", "geneva": "The litle owle also, and the connorant, and the great owle.", "wycliffe": "an owle, and dippere, and ibis ;", "rotherham": "and the pelican and the gannet, and the bittern;", "darby": "and the owl, and the gannet, and the ibis,", "twenty": "", "jps": "and the little owl, and the cormorant, and the great owl;", "acv": "and the little owl, and the cormorant, and the great owl,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the little owl, and the cormorant, and the great owl,", "vulgate": "bubonem et mergulum et ibin;", "brenton": "and the night-raven and the cormorant and the stork,"}}, {"v": 18, "ref": "11:18", "o": "וְ/אֶת הַ/תִּנְשֶׁ֥מֶת וְ/אֶת הַ/קָּאָ֖ת וְ/אֶת הָ/רָחָֽם", "en": {"kjv": "And the swan, and the pelican, and the gier eagle,", "web": "the white owl, the desert owl, the osprey,", "bsb": "the white owl, the desert owl, the osprey,", "asv": "and the horned owl, and the pelican, and the vulture,", "ylt": "and the swan, and the pelican, and the gier eagle,", "tyndale": "the backe, the pellicane, the pye,", "dra": "And the swan, and the bittern, and the porphyrion.", "bbe": "And the water-hen and the pelican and the vulture;", "geneva": "Also the redshanke and the pelicane, and the swanne:", "wycliffe": "a swan and cormoraunt, and a pellican;", "rotherham": "and the swan and the vomiting pelican and the little vulture;", "darby": "and the swan, and the pelican, and the carrion vulture,", "twenty": "", "jps": "and the horned owl, and the pelican, and the carrion-vulture;", "acv": "and the horned owl, and the pelican, and the carrion vulture,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the swan, and the pelican, and the gier-eagle,", "vulgate": "cycnum et onocrotalum et porphirionem;", "brenton": "and the red-bill, and the pelican, and swan,"}}, {"v": 19, "ref": "11:19", "o": "וְ/אֵת֙ הַ/חֲסִידָ֔ה הָ/אֲנָפָ֖ה לְ/מִינָ֑/הּ וְ/אֶת הַ/דּוּכִיפַ֖ת וְ/אֶת הָ/עֲטַלֵּֽף", "en": {"kjv": "And the stork, the heron after her kind, and the lapwing, and the bat.", "web": "the stork, any kind of heron, the hoopoe, and the bat.", "bsb": "the stork, any kind of heron, the hoopoe, and the bat.", "asv": "and the stork, the heron after its kind, and the hoopoe, and the bat.", "ylt": "and the stork, the heron after its kind, and the lapwing, and the bat.", "tyndale": "the heron, the Iaye with the kynde, the lappwynge ad the swalowe.", "dra": "The heron, and the charadroin according to its kind, the houp also, and the bat.", "bbe": "The stork and the heron, and birds of that sort, and the hoopoe and the bat.", "geneva": "The storke also, the heron after his kinde, and the lapwing, and the backe:", "wycliffe": "a fawcun, a iay bi his kynde; a leepwynke, and a reremows.", "rotherham": "and the stork, and the parrot, after its kind,—and the mountain-cock and the bat.", "darby": "and the stork; the heron after its kind, and the hoopoe, and the bat.", "twenty": "", "jps": "and the stork, and the heron after its kinds, and the hoopoe, and the bat.", "acv": "and the stork, the heron after its kind, and the hoopoe, and the bat.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the stork, and the heron after her kind, and the lapwing, and the bat.", "vulgate": "erodionem et charadrion iuxta genus suum opupam quoque et vespertilionem;", "brenton": "and the heron, and the lapwing, and the like to it, and the hoopoe and the bat."}}, {"v": 20, "ref": "11:20", "o": "כֹּ֚ל שֶׁ֣רֶץ הָ/ע֔וֹף הַ/הֹלֵ֖ךְ עַל אַרְבַּ֑ע שֶׁ֥קֶץ ה֖וּא לָ/כֶֽם", "en": {"kjv": "All fowls that creep, going upon all four, shall be an abomination unto you.", "web": "“‘All flying insects that walk on all fours are an abomination to you.", "bsb": "All flying insects that walk on all fours are detestable to you.", "asv": "All winged creeping things that go upon all fours are an abomination unto you.", "ylt": "`Every teeming creature which is flying, which is going on four--an abomination it is to you.", "tyndale": "And all foules that crepe ad goo apo all iiij. shalbe an abhominacion vnto you.", "dra": "Of things that fly, whatsoever goeth upon four feet, shall be abominable to you.", "bbe": "Every winged four-footed thing which goes on the earth is disgusting to you;", "geneva": "Also euery foule that creepeth and goeth vpon all foure, such shalbe an abomination vnto you.", "wycliffe": "Al thing of foulis that goith on foure feet, schal be abhomynable to you;", "rotherham": "Every creeping thing that flieth, that goeth on all-fours, an abomination, it is unto you.", "darby": "Every winged crawling thing that goeth upon all four shall be an abomination unto you.", "twenty": "", "jps": "All winged swarming things that go upon all fours are a detestable thing unto you.", "acv": "All winged creeping things that go upon all fours are an abomination to you.", "anderson": "", "haweis": "", "noyes": "", "webster": "All fowls that creep, going upon [all] four, [shall be] an abomination to you.", "vulgate": "omne de volucribus quod graditur super quattuor pedes abominabile erit vobis;", "brenton": "And all winged creatures that creep, which go upon four feet, are abominations to you."}}, {"v": 21, "ref": "11:21", "o": "אַ֤ךְ אֶת זֶה֙ תֹּֽאכְל֔וּ מִ/כֹּל֙ שֶׁ֣רֶץ הָ/ע֔וֹף הַ/הֹלֵ֖ךְ עַל אַרְבַּ֑ע אֲשֶׁר לא ל֤/וֹ כְרָעַ֨יִם֙ מִ/מַּ֣עַל לְ/רַגְלָ֔י/ו לְ/נַתֵּ֥ר בָּ/הֵ֖ן עַל הָ/אָֽרֶץ", "en": {"kjv": "Yet these may ye eat of every flying creeping thing that goeth upon all four, which have legs above their feet, to leap withal upon the earth;", "web": "Yet you may eat these: of all winged creeping things that go on all fours, which have legs above their feet, with which to hop on the earth.", "bsb": "However, you may eat the following kinds of flying insects that walk on all fours: those having jointed legs above their feet for hopping on the ground.", "asv": "Yet these may ye eat of all winged creeping things that go upon all fours, which have legs above their feet, wherewith to leap upon the earth;", "ylt": "`Only--this ye do eat of any teeming thing which is flying, which is going on four, which hath legs above its feet, to move with them on the earth;", "tyndale": "Yet these maye ye eate of all the foules that moue and goo apon .iiij. fete: euen those that haue no knees aboue vppon their fete to lepe with all apon the erthe,", "dra": "But whatsoever walketh upon four feet, but hath the legs behind longer, wherewith it hoppeth upon the earth,", "bbe": "But of the winged four-footed things, those which have long legs for jumping on the earth you may have for food;", "geneva": "Yet these shall ye eate: of euery foule that creepeth, and goeth vpon all foure which haue their feete and legs all of one to leape withal vpon the earth,", "wycliffe": "sotheli what euer thing goith on foure feet, but hath lengere hipis bihynde, bi whiche it skippith on the erthe, ye schulen ete;", "rotherham": "Nevertheless, these, may ye eat, of all creeping things that fly, that go on all-fours,—such as have legs above their feet, to leap therewith, upon the earth—", "darby": "Yet these shall ye eat of every winged crawling thing that goeth upon all four: those which have legs above their feet with which to leap upon the earth.", "twenty": "", "jps": "Yet these may ye eat of all winged swarming things that go upon all fours, which have jointed legs above their feet, wherewith to leap upon the earth;", "acv": "Yet these ye may eat of all winged creeping things that go upon all fours, which have legs above their feet, with which to leap upon the earth,", "anderson": "", "haweis": "", "noyes": "", "webster": "Yet these may ye eat, of every flying creeping animal that goeth upon [all] four, which have legs above their feet, to leap with upon the earth;", "vulgate": "quicquid autem ambulat quidem super quattuor pedes sed habet longiora retro crura per quae salit super terram;", "brenton": "But these ye shall eat of the creeping winged animals, which go upon four feet, which have legs above their feet, to leap with on the earth."}}, {"v": 22, "ref": "11:22", "o": "אֶת אֵ֤לֶּה מֵ/הֶם֙ תֹּאכֵ֔לוּ אֶת הָֽ/אַרְבֶּ֣ה לְ/מִינ֔/וֹ וְ/אֶת הַ/סָּלְעָ֖ם לְ/מִינֵ֑/הוּ וְ/אֶת הַ/חַרְגֹּ֣ל לְ/מִינֵ֔/הוּ וְ/אֶת הֶ/חָגָ֖ב לְ/מִינֵֽ/הוּ", "en": {"kjv": "Even these of them ye may eat; the locust after his kind, and the bald locust after his kind, and the beetle after his kind, and the grasshopper after his kind.", "web": "Even of these you may eat: any kind of locust, any kind of katydid, any kind of cricket, and any kind of grasshopper.", "bsb": "Of these you may eat any kind of locust, katydid, cricket, or grasshopper.", "asv": "even these of them ye may eat: the locust after its kind, and the bald locust after its kind, and the cricket after its kind, and the grasshopper after its kind.", "ylt": "these of them ye do eat: the locust after its kind, and the bald locust after its kind, and the beetle after its kind, and the grasshopper after its kind;", "tyndale": "euen these of them ye maye eate: the arbe and all his kynde: the Soleam with all his kynde: the Hargol and all the kynde, ad the Hagab ad all his kynd.", "dra": "That you shall eat: as the bruchus in its kind, the attacus, and ophimachus, and the locust, every, one according to their kind.", "bbe": "Such as all the different sorts of locust.", "geneva": "Of them ye shall eate these, the grashopper after his kinde, and the solean after his kinde, the hargol after his kinde, and the hagab after his kind.", "wycliffe": "as is a bruke in his kynde, and acatus , and opymacus , and a locuste, alle bi her kynde.", "rotherham": "these of them, may ye eat: the swarming-locust after its kind, and the devouring locust after its kind,—and the chargol-locust after its kind, and the chagab-locust after its kind.", "darby": "These shall ye eat of them: the arbeh after its kind, and the solam after its kind, and the hargol after its kind, and the hargab after its kind.", "twenty": "", "jps": "even these of them ye may eat: the locust after its kinds, and the bald locust after its kinds, and the cricket after its kinds, and the grasshopper after its kinds.", "acv": "even these of them ye may eat: the locust after its kind, and the bald locust after its kind, and the cricket after its kind, and the grasshopper after its kind.", "anderson": "", "haweis": "", "noyes": "", "webster": "[Even] these of them ye may eat; the locust after its kind, and the bald locust after its kind, and the beetle after its kind, and the grasshopper after its kind.", "vulgate": "comedere debetis ut est brucus in genere suo et attacus atque ophiomachus ac lucusta singula iuxta genus suum;", "brenton": "And these of them ye shall eat: the caterpillar and his like, and the attacus and his like, and the cantharus and his like, and the locust and his like."}}, {"v": 23, "ref": "11:23", "o": "וְ/כֹל֙ שֶׁ֣רֶץ הָ/ע֔וֹף אֲשֶׁר ל֖/וֹ אַרְבַּ֣ע רַגְלָ֑יִם שֶׁ֥קֶץ ה֖וּא לָ/כֶֽם", "en": {"kjv": "But all other flying creeping things, which have four feet, shall be an abomination unto you.", "web": "But all winged creeping things which have four feet, are an abomination to you.", "bsb": "All other flying insects that have four legs are detestable to you.", "asv": "But all winged creeping things, which have four feet, are an abomination unto you.", "ylt": "and every teeming thing which is flying, which hath four feet--an abomination it is to you.", "tyndale": "Al other foules that moue ad haue .iiij. fete, shalbe abhominacion vnto you.", "dra": "But of flying things whatsoever hath four feet only, shall be an abomination to you.", "bbe": "But all other winged four-footed things which go on the earth are disgusting to you.", "geneva": "But al other foules that creepe and haue foure feete, they shalbe abomination vnto you.", "wycliffe": "Forsothe what euer thing of briddis hath foure feet oneli, it schal be abhomynable to you;", "rotherham": "But every [other] creeping thing that flieth, which hath four feet, an abomination, it is unto you;", "darby": "But every winged crawling thing that hath four feet shall be an abomination unto you.", "twenty": "", "jps": "But all winged swarming things, which have four feet, are a detestable thing unto you.", "acv": "But all winged creeping things, which have four feet, are an abomination to you,", "anderson": "", "haweis": "", "noyes": "", "webster": "But all [other] flying creeping animals, which have four feet, [shall be] an abomination to you.", "vulgate": "quicquid autem ex volucribus quattuor tantum habet pedes execrabile erit vobis;", "brenton": "Every creeping thing from among the birds, which has four feet, is an abomination to you."}}, {"v": 24, "ref": "11:24", "o": "וּ/לְ/אֵ֖לֶּה תִּטַּמָּ֑אוּ כָּל הַ/נֹּגֵ֥עַ בְּ/נִבְלָתָ֖/ם יִטְמָ֥א עַד הָ/עָֽרֶב", "en": {"kjv": "And for these ye shall be unclean: whosoever toucheth the carcase of them shall be unclean until the even.", "web": "“‘By these you will become unclean: whoever touches their carcass shall be unclean until the evening.", "bsb": "These creatures will make you unclean. Whoever touches their carcasses will be unclean until evening,", "asv": "And by these ye shall become unclean: whosoever toucheth the carcass of them shall be unclean until the even;", "ylt": "`And by these ye are made unclean, any one who is coming against their carcase is unclean till the evening;", "tyndale": "In soch ye shalbe vnclene whosoeuer touch the carkesse of the shalbe vnclene vnto the euen,", "dra": "And whosoever shall touch the carcasses of them, shall be defiled: and shall be unclean until the evening:", "bbe": "By these you will be made unclean; anyone touching their dead bodies will be unclean till evening:", "geneva": "For by such ye shalbe polluted: whosoeuer toucheth their carkeis, shalbe vncleane vnto the euening.", "wycliffe": "and who euer touchith her bodies deed bi hem silf, schal be defoulid, and `schal be vnclene `til to euentid;", "rotherham": "and, for these, shall ye count yourselves unclean—whosoever toucheth the carcase of them shall be unclean until the evening;", "darby": "And by these ye shall make yourselves unclean; whoever toucheth their carcase shall be unclean until the even.", "twenty": "", "jps": "And by these ye shall become unclean; whosoever toucheth the carcass of them shall be unclean until even.", "acv": "and by these ye shall become unclean. Whoever touches the carcass of them shall be unclean until the evening.", "anderson": "", "haweis": "", "noyes": "", "webster": "And for these ye shall be unclean: whoever toucheth the carcass of them shall be unclean until the evening.", "vulgate": "et quicumque morticina eorum tetigerit polluetur et erit inmundus usque ad vesperum;", "brenton": "And by these ye shall be defiled; every one that touches their carcases shall be unclean till the evening."}}, {"v": 25, "ref": "11:25", "o": "וְ/כָל הַ/נֹּשֵׂ֖א מִ/נִּבְלָתָ֑/ם יְכַבֵּ֥ס בְּגָדָ֖י/ו וְ/טָמֵ֥א עַד הָ/עָֽרֶב", "en": {"kjv": "And whosoever beareth ought of the carcase of them shall wash his clothes, and be unclean until the even.", "web": "Whoever carries any part of their carcass shall wash his clothes, and be unclean until the evening.", "bsb": "and whoever picks up one of their carcasses must wash his clothes, and he will be unclean until evening.", "asv": "and whosoever beareth aught of the carcass of them shall wash his clothes, and be unclean until the even.", "ylt": "and anyone who is lifting up aught of their carcase doth wash his garments, and hath been unclean till the evening: --", "tyndale": "ad whosoeuer bereth the carkesse of the, shal wash his clothes ad shalbe vnclene vntyll euen.", "dra": "And if it be necessary that he carry any of these things when they are dead: he shall wash his clothes, and shall be unclean until the sun set.", "bbe": "Whoever takes away the dead body of one of them is to have his clothing washed, and will be unclean till evening.", "geneva": "Whosoeuer also beareth of their carkeis, shall wash his clothes, and be vncleane vntil euen.", "wycliffe": "and if it is nede, that he bere ony deed thing of these, he schal waische his clothis, and he schal be vnclene til to the goyng doun of the sunne.", "rotherham": "and whosoever beareth away aught of the carcase of them, shall wash his clothes and be unclean until the evening.", "darby": "And whoever carrieth [ought] of their carcase shall wash his garments, and be unclean until the even.", "twenty": "", "jps": "And whosoever beareth aught of the carcass of them shall wash his clothes, and be unclean until the even.", "acv": "And whoever bears any of the carcass of them shall wash his clothes, and be unclean until the evening.", "anderson": "", "haweis": "", "noyes": "", "webster": "And whoever beareth [aught] of the carcass of them shall wash his clothes, and be unclean until the evening.", "vulgate": "et si necesse fuerit ut portet quippiam horum mortuum lavabit vestimenta sua et inmundus erit usque ad solis occasum;", "brenton": "And every one that takes of their dead bodies shall wash his garments, and shall be unclean till the evening."}}, {"v": 26, "ref": "11:26", "o": "לְֽ/כָל הַ/בְּהֵמָ֡ה אֲשֶׁ֣ר הִוא֩ מַפְרֶ֨סֶת פַּרְסָ֜ה וְ/שֶׁ֣סַע אֵינֶ֣/נָּה שֹׁסַ֗עַת וְ/גֵרָה֙ אֵינֶ֣/נָּה מַעֲלָ֔ה טְמֵאִ֥ים הֵ֖ם לָ/כֶ֑ם כָּל הַ/נֹּגֵ֥עַ בָּ/הֶ֖ם יִטְמָֽא", "en": {"kjv": "The carcases of every beast which divideth the hoof, and is not clovenfooted, nor cheweth the cud, are unclean unto you: every one that toucheth them shall be unclean.", "web": "“‘Every animal which parts the hoof, and is not cloven-footed, nor chews the cud, is unclean to you. Everyone who touches them shall be unclean.", "bsb": "Every animal with hooves not completely divided or that does not chew the cud is unclean for you. Whoever touches any of them will be unclean.", "asv": "Every beast which parteth the hoof, and is not clovenfooted, nor cheweth the cud, is unclean unto you: every one that toucheth them shall be unclean.", "ylt": "even every beast which is dividing the hoof, and is not cloven-footed, and the cud is not bringing up--unclean they are to you; any one who is coming against them is unclean.", "tyndale": "Amonge all maner beestes, they that haue hoffes and deuyde them not in to two clawes or that chewe not the cud, shalbe vnclene vnto you: and all that twicheth them shalbe vnclene.", "dra": "Every beast that hath a hoof, but divideth it not, nor cheweth the cud shall be unclean: and he that toucheth it, shall be defiled.", "bbe": "Every beast, in the horn of whose foot there is not a complete division, and whose food does not come back, is unclean to you: anyone touching one of these will be unclean.", "geneva": "Euery beast that hath clawes deuided, and is not clouen footed, nor cheweth the cud, such shalbe vncleane vnto you: euery one that toucheth them, shalbe vncleane.", "wycliffe": "Sotheli ech beeste that hath a clee, but departith not it, nether chewith code, schal be vnclene; and what euer thing touchith it, schal be defoulid.", "rotherham": "As for every kind of beast which, though it parteth the hoof, yet is not cloven-footed nor cheweth the cud, unclean, they are unto you,—every one who toucheth them shall be unclean.", "darby": "Every beast that hath cloven hoofs, but not feet quite split open, nor cheweth the cud, shall be unclean unto you: every one that toucheth them shall be unclean.", "twenty": "", "jps": "Every beast which parteth the hoof, but is not cloven footed, nor cheweth the cud, is unclean unto you; every one that to toucheth them shall be unclean.", "acv": "Every beast which parts the hoof, and is not cloven footed, nor chews the cud, is unclean to you. Everyone who touches them shall be unclean.", "anderson": "", "haweis": "", "noyes": "", "webster": "[The carcasses] of every beast which divideth the hoof, and [is] not cloven-footed, nor cheweth the cud, [are] unclean to you: every one that toucheth them shall be unclean.", "vulgate": "omne animal quod habet quidem ungulam sed non dividit eam nec ruminat inmundum erit et quicquid tetigerit illud contaminabitur;", "brenton": "And whichever among the beasts divides the hoof and makes claws, and does not chew the cud, shall be unclean to you; every one that touches their dead bodies shall be unclean till evening."}}, {"v": 27, "ref": "11:27", "o": "וְ/כֹ֣ל הוֹלֵ֣ךְ עַל כַּפָּ֗י/ו בְּ/כָל הַֽ/חַיָּה֙ הַ/הֹלֶ֣כֶת עַל אַרְבַּ֔ע טְמֵאִ֥ים הֵ֖ם לָ/כֶ֑ם כָּל הַ/נֹּגֵ֥עַ בְּ/נִבְלָתָ֖/ם יִטְמָ֥א עַד הָ/עָֽרֶב", "en": {"kjv": "And whatsoever goeth upon his paws, among all manner of beasts that go on all four, those are unclean unto you: whoso toucheth their carcase shall be unclean until the even.", "web": "Whatever goes on its paws, among all animals that go on all fours, they are unclean to you. Whoever touches their carcass shall be unclean until the evening.", "bsb": "All the four-footed animals that walk on their paws are unclean for you; whoever touches their carcasses will be unclean until evening,", "asv": "And whatsoever goeth upon its paws, among all beasts that go on all fours, they are unclean unto you: whoso toucheth their carcass shall be unclean until the even.", "ylt": "`And any one going on its paws, among all the beasts which are going on four--unclean they are to you; any one who is coming against their carcase is unclean until the evening;", "tyndale": "And all that goeth apon his handes amonge all maner beestes that goo on all foure, are vnclene vnto you: and as many as twych their carkesses, shalbe vnclene vntyll the euen.", "dra": "That which walketh upon hands of all animals which go on all four, shall be unclean: he that shall touch their carcasses shall be defiled until evening.", "bbe": "Any four-footed beast which goes on the ball of its foot, is unclean to you: anyone touching the dead body of one of these will be unclean till evening.", "geneva": "And whatsoeuer goeth vpon his pawes among all maner beastes that goeth on all foure, such shalbe vncleane vnto you: who so doth touch their carkeis shalbe vncleane vntil the euen.", "wycliffe": "That that goith on hondis, of alle beestis that gon on foure feet, schal be vnclene; he, that touchith her bodies deed bi hem silf, schal be defoulid `til to euentid;", "rotherham": "And, all that go upon their paws, among all the living things that go on all-fours, unclean, they are unto you,—whoso toucheth the carcase of them, shall be unclean until the evening.", "darby": "And whatever goeth on its paws, among all manner of beasts that go upon all four, those are unclean unto you: whoever toucheth their carcase shall be unclean until the even.", "twenty": "", "jps": "And whatsoever goeth upon its paws, among all beasts that go on all fours, they are unclean unto you; whoso toucheth their carcass shall be unclean until the even.", "acv": "And whatever goes upon its paws, among all beasts that go on all fours, they are unclean to you. Whoever touches their carcass shall be unclean until the evening.", "anderson": "", "haweis": "", "noyes": "", "webster": "And whatever goeth upon its paws, among all manner of beasts that go on [all] four, those [are] unclean to you: whoever toucheth their carcass shall be unclean until the evening.", "vulgate": "quod ambulat super manus ex cunctis animantibus quae incedunt quadrupedia inmundum erit qui tetigerit morticina eorum polluetur usque ad vesperum;", "brenton": "And every one among all the wild beasts that moves upon its fore feet, which goes on all four, is unclean to you; every one that touches their dead bodies shall be unclean till evening."}}, {"v": 28, "ref": "11:28", "o": "וְ/הַ/נֹּשֵׂא֙ אֶת נִבְלָתָ֔/ם יְכַבֵּ֥ס בְּגָדָ֖י/ו וְ/טָמֵ֣א עַד הָ/עָ֑רֶב טְמֵאִ֥ים הֵ֖מָּה לָ/כֶֽם", "en": {"kjv": "And he that beareth the carcase of them shall wash his clothes, and be unclean until the even: they are unclean unto you.", "web": "He who carries their carcass shall wash his clothes, and be unclean until the evening. They are unclean to you.", "bsb": "and anyone who picks up a carcass must wash his clothes, and he will be unclean until evening. They are unclean for you.", "asv": "And he that beareth the carcass of them shall wash his clothes, and be unclean until the even: they are unclean unto you.", "ylt": "and he who is lifting up their carcase doth wash his garments, and hath been unclean until the evening--unclean they are to you.", "tyndale": "And he that beareth the carkesse of them, shall wasshe his clothes ad be vnclene vntyll the euen for soch are vnclene vnto you.", "dra": "And he that shall carry such carcasses, shall wash his clothes, and shall be unclean until evening: because all these things are unclean to you.", "bbe": "Anyone who takes away the dead body of one of these is to have his clothing washed and be unclean till evening.", "geneva": "And he that beareth their carkeis, shall wash his clothes, and be vncleane vntill the euen: for such shalbe vncleane vnto you.", "wycliffe": "and he, that berith siche deed bodies, schal waische hise clothis, and he schal be vnclene `til to euentid; for alle these thingis ben vnclene to you.", "rotherham": "And, he that beareth away the carcase of them shall wash his clothes, and shall be unclean until the evening,—unclean, they are unto you.", "darby": "And he that carrieth their carcase shall wash his garments, and be unclean until the even: they shall be unclean unto you.", "twenty": "", "jps": "And he that beareth the carcass of them shall wash his clothes, and be unclean until the even; they are unclean unto you.", "acv": "And he who bears the carcass of them shall wash his clothes, and be unclean until the evening; they are unclean to you.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he that beareth the carcass of them shall wash his clothes, and be unclean until the evening: they [are] unclean to you.", "vulgate": "et qui portaverit huiuscemodi cadavera lavabit vestimenta sua et inmundus erit usque ad vesperum quia omnia haec inmunda sunt vobis;", "brenton": "And he that takes of their dead bodies shall wash his garments, and shall be unclean till evening: these are unclean to you."}}, {"v": 29, "ref": "11:29", "o": "וְ/זֶ֤ה לָ/כֶם֙ הַ/טָּמֵ֔א בַּ/שֶּׁ֖רֶץ הַ/שֹּׁרֵ֣ץ עַל הָ/אָ֑רֶץ הַ/חֹ֥לֶד וְ/הָ/עַכְבָּ֖ר וְ/הַ/צָּ֥ב לְ/מִינֵֽ/הוּ", "en": {"kjv": "These also shall be unclean unto you among the creeping things that creep upon the earth; the weasel, and the mouse, and the tortoise after his kind,", "web": "“‘These are they which are unclean to you among the creeping things that creep on the earth: the weasel, the rat, any kind of great lizard,", "bsb": "The following creatures that move along the ground are unclean for you: the mole, the mouse, any kind of great lizard,", "asv": "And these are they which are unclean unto you among the creeping things that creep upon the earth: the weasel, and the mouse, and the great lizard after its kind,", "ylt": "`And this is to you the unclean among the teeming things which are teeming on the earth: the weasel, and the mouse, and the tortoise after its kind,", "tyndale": "And these are also unclene to you amonge the thinges that crepe apon the erth: the wesell the mouse, the tode and all his kynde,", "dra": "These also shall be reckoned among unclean things, of all that move upon the earth. The weasel, and the mouse, and the crocodile, every one according to their kind:", "bbe": "And these are unclean to you among things which go low down on the earth; the weasel and the mouse and the great lizard, and animals of that sort;", "geneva": "Also these shalbe vncleane to you amog the things that creepe and moue vpon the earth, the weasell, and the mouse, and the frog, after his kinde:", "wycliffe": "Also these thingis schulen be arettid among defoulid thingis, of these that ben moued on erthe; a wesele, and mows, and a cocodrille , `alle bi her kynde;", "rotherham": "And, these, unto you, shall be unclean, among the creeping things that creep upon the earth,—the weasel and the mouse, and the lizard after its kind;", "darby": "And these shall be unclean unto you among the crawling things which crawl on the earth: the mole, and the field-mouse, and the lizard, after its kind;", "twenty": "", "jps": "And these are they which are unclean unto you among the swarming things that swarm upon the earth: the weasel, and the mouse, and the great lizard after its kinds,", "acv": "And these are those which are unclean to you among the creeping things that creep upon the earth: the weasel, and the mouse, and the great lizard after its kind,", "anderson": "", "haweis": "", "noyes": "", "webster": "These also [shall be] unclean to you among the creeping animals that creep upon the earth; the weasel, and the mouse, and the tortoise, after its kind,", "vulgate": "hoc quoque inter polluta reputabitur de his quae moventur in terra mustela et mus et corcodillus singula iuxta genus suum;", "brenton": "And these are unclean to you of reptiles upon the earth, the weasel, and the mouse, and the lizard,"}}, {"v": 30, "ref": "11:30", "o": "וְ/הָ/אֲנָקָ֥ה וְ/הַ/כֹּ֖חַ וְ/הַ/לְּטָאָ֑ה וְ/הַ/חֹ֖מֶט וְ/הַ/תִּנְשָֽׁמֶת", "en": {"kjv": "And the ferret, and the chameleon, and the lizard, and the snail, and the mole.", "web": "the gecko, and the monitor lizard, the wall lizard, the skink, and the chameleon.", "bsb": "the gecko, the monitor lizard, the common lizard, the skink, and the chameleon.", "asv": "and the gecko, and the land-crocodile, and the lizard, and the sand-lizard, and the chameleon.", "ylt": "and the ferret, and the chameleon, and the lizard, and the snail, and the mole;", "tyndale": "the hedgehogge, stellio, the licerte, the snayle and the moule.", "dra": "The shrew, and the chameleon, and the stellio, and the lizard, and the mole.", "bbe": "And the ferret and the land crocodile and the lizard and the sand-lizard and the chameleon.", "geneva": "Also the rat, and the lizard, and the chameleon, and the stellio, and the molle.", "wycliffe": "mygal , camelion , and stellio , and lacerta , and a maldewerp.", "rotherham": "and the ferret and the chameleon and the wall-lizard,—and the winding lizard, and the mole.", "darby": "and the groaning lizard, and the great red lizard, and the climbing lizard, and the chomet, and the chameleon.", "twenty": "", "jps": "and the gecko, and the land-crocodile, and the lizard, and the sand-lizard, and the chameleon.", "acv": "and the gecko, and the land-crocodile, and the lizard, and the sand-lizard, and the chameleon.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the ferret and the chameleon, and the lizard, and the snail, and the mole.", "vulgate": "migale et cameleon et stelio ac lacerta et talpa;", "brenton": "the ferret, and the chameleon, and the evet, and the newt, and the mole."}}, {"v": 31, "ref": "11:31", "o": "אֵ֛לֶּה הַ/טְּמֵאִ֥ים לָ/כֶ֖ם בְּ/כָל הַ/שָּׁ֑רֶץ כָּל הַ/נֹּגֵ֧עַ בָּ/הֶ֛ם בְּ/מֹתָ֖/ם יִטְמָ֥א עַד הָ/עָֽרֶב", "en": {"kjv": "These are unclean to you among all that creep: whosoever doth touch them, when they be dead, shall be unclean until the even.", "web": "These are they which are unclean to you among all that creep. Whoever touches them when they are dead, shall be unclean until the evening.", "bsb": "These animals are unclean for you among all the crawling creatures. Whoever touches them when they are dead shall be unclean until evening.", "asv": "These are they which are unclean to you among all that creep: whosoever doth touch them, when they are dead, shall be unclean until the even.", "ylt": "these are the unclean to you among all which are teeming; any one who is coming against them in their death is unclean till the evening.", "tyndale": "These are vnclene to you amonge all that moue, and all that twych them when they be dead, shalbe vnclene vntyll the euen.", "dra": "All these are unclean. He that toucheth their carcasses shall be unclean until the evening.", "bbe": "All these are unclean to you: anyone touching them when they are dead will be unclean till evening.", "geneva": "These shall be vncleane to you among all that creepe: whosoeuer doeth touch them when they be dead, shalbe vncleane vntil the euen.", "wycliffe": "Alle these ben vnclene; he that touchith her bodies deed bi hem silf, schal be vnclene `til to euentid;", "rotherham": "These, are they which are unclean to you among all that creep,—whosoever toucheth them when they are dead shall be unclean until the evening;", "darby": "These shall be unclean unto you among all that crawl: whoever toucheth them when they are dead, shall be unclean until the even.", "twenty": "", "jps": "These are they which are unclean to you among all that swarm; whosoever doth touch them, when they are dead, shall be unclean until the even.", "acv": "These are those which are unclean to you among all that creep. Whoever touches them, when they are dead, shall be unclean until the evening.", "anderson": "", "haweis": "", "noyes": "", "webster": "These [are] unclean to you among all that creep: whoever doth touch them, when they are dead, shall be unclean until the evening.", "vulgate": "omnia haec inmunda sunt qui tetigerit morticina eorum inmundus erit usque ad vesperum;", "brenton": "These are unclean to you of all the reptiles which are on the earth; every one who touches their carcases shall be unclean till evening."}}, {"v": 32, "ref": "11:32", "o": "וְ/כֹ֣ל אֲשֶׁר יִפֹּל עָלָי/ו֩ מֵ/הֶ֨ם בְּ/מֹתָ֜/ם יִטְמָ֗א מִ/כָּל כְּלִי עֵץ֙ א֣וֹ בֶ֤גֶד אוֹ עוֹר֙ א֣וֹ שָׂ֔ק כָּל כְּלִ֕י אֲשֶׁר יֵעָשֶׂ֥ה מְלָאכָ֖ה בָּ/הֶ֑ם בַּ/מַּ֧יִם יוּבָ֛א וְ/טָמֵ֥א עַד הָ/עֶ֖רֶב וְ/טָהֵֽר", "en": {"kjv": "And upon whatsoever any of them, when they are dead, doth fall, it shall be unclean; whether it be any vessel of wood, or raiment, or skin, or sack, whatsoever vessel it be, wherein any work is done, it must be put into water, and it shall be unclean until the even; so it shall be cleansed.", "web": "On whatever any of them falls when they are dead, it shall be unclean; whether it is any vessel of wood, or clothing, or skin, or sack, whatever vessel it is, with which any work is done, it must be put into water, and it shall be unclean until the evening; then it will be clean.", "bsb": "When one of them dies and falls on something, that article becomes unclean; any article of wood, clothing, leather, sackcloth, or any implement used for work must be rinsed with water and will remain unclean until evening; then it will be clean.", "asv": "And upon whatsoever any of them, when they are dead, doth fall, it shall be unclean; whether it be any vessel of wood, or raiment, or skin, or sack, whatsoever vessel it be, wherewith any work is done, it must be put into water, and it shall be unclean until the even; then shall it be clean.", "ylt": "`And anything on which any one of them falleth, in their death, is unclean, of any vessel of wood or garment or skin or sack, any vessel in which work is done is brought into water, and hath been unclean till the evening, then it hath been clean;", "tyndale": "And what soeuer any of the dead carkesses of them fall apon, shalbe vnclene: what soeuer vessell of wodd it be, or rayment, or skynne, or bagge or what soeuer thinge it be that any worke is wroughte with all. And they shalbe plunged in the water and be vnclene vntill the eue, and then they shalbe clene agayne.", "dra": "And upon what thing soever any of their carcasses shall fall, it shall be defiled, whether it be a vessel of wood, or a garment, or skins or haircloths: or any thing in which work is done. They shall be dipped in water, and shall be unclean until the evening, and so afterwards shall be clean.", "bbe": "The dead body of any of these, falling on anything, will make that thing unclean; if it is any vessel of wood, or clothing, or skin, or bag, whatever it is, if it is used for any purpose, it will have to be put into water, and will be unclean till evening; after that it will be clean.", "geneva": "Also whatsoeuer any of the dead carkeises of them doth fall vpon, shalbe vncleane, whether it be vessel of wood, or rayment, or skinne, or sacke: whatsoeuer vessel it be that is occupied, it shalbe put in the water as vncleane vntil the euen, and so be purified.", "wycliffe": "and that thing schal be defoulid, on which ony thing of her bodies deed bi hem silf fallith, as wel a vessel of tree, and a cloth, as skynnes `and heiris; and in what euer thing werk is maad, it schal be dippid in watir, and tho thingis schulen be defoulid `til to euentid, and so aftirward tho schulen be clensid.", "rotherham": "and, everything whereon any of them shall fall when they are dead shall be unclean—of any articles of wood, or cloth, or skin, or sackcloth, any article wherewith any work is done,—shall be put in water and shall be unclean until the evening, and then be clean,", "darby": "And on whatever any of them when they are dead doth fall, it shall be unclean; all vessels of wood, or garment, or skin, or sack, every vessel wherewith work is done — it shall be put into water, and be unclean until the even; then shall it be clean.", "twenty": "", "jps": "And upon whatsoever any of them, when they are dead, doth fall, it shall be unclean; whether it be any vessel of wood, or raiment, or skin, or sack, whatsoever vessel it be, wherewith any work is done, it must be put into water, and it shall be unclean until the even; then shall it be clean.", "acv": "And upon whatever any of them falls when they are dead, it shall be unclean, whether it be any vessel of wood, or raiment, or skin, or sack. Whatever vessel it be, with which any work is done, it must be put into water, and it shall be unclean until the evening, then it shall be clean.", "anderson": "", "haweis": "", "noyes": "", "webster": "And upon whatever [any] of them, when they are dead, doth fall, it shall be unclean; whether [it is] any vessel of wood, or raiment, or skin, or sack, whatever vessel [it is], in which [any] work is done, it must be put into water, and it shall be unclean until the evening; so it shall be cleansed.", "vulgate": "et super quod ceciderit quicquam de morticinis eorum polluetur tam vas ligneum et vestimentum quam pelles et cilicia et in quocumque fit opus tinguentur aqua et polluta erunt usque ad vesperum et sic postea mundabuntur;", "brenton": "And on whatsoever one of their dead bodies shall fall it shall be unclean; whatever wooden vessel, or garment, or skin, or sack it may be, every vessel in which work should be done, shall be dipped in water, and shall be unclean till evening; and then it shall be clean."}}, {"v": 33, "ref": "11:33", "o": "וְ/כָל כְּלִי חֶ֔רֶשׂ אֲשֶׁר יִפֹּ֥ל מֵ/הֶ֖ם אֶל תּוֹכ֑/וֹ כֹּ֣ל אֲשֶׁ֧ר בְּ/תוֹכ֛/וֹ יִטְמָ֖א וְ/אֹת֥/וֹ תִשְׁבֹּֽרוּ", "en": {"kjv": "And every earthen vessel, whereinto any of them falleth, whatsoever is in it shall be unclean; and ye shall break it.", "web": "Every earthen vessel, into which any of them falls, all that is in it shall be unclean, and you shall break it.", "bsb": "If any of them falls into a clay pot, everything in it will be unclean; you must break the pot.", "asv": "And every earthen vessel, whereinto any of them falleth, whatsoever is in it shall be unclean, and it ye shall break.", "ylt": "and any earthen vessel, into the midst of which any one of them falleth, all that is in its midst is unclean, and it ye do break.", "tyndale": "All maner of erthen vessell where in to any of them falleth, is vnclene with all that therein is: and ye shall breake it.", "dra": "But an earthen vessel, into which any of these shall fall, shall be defiled: and therefore is to be broken.", "bbe": "And if one of them gets into any vessel of earth, whatever is in the vessel will be unclean and the vessel will have to be broken.", "geneva": "But euery earthen vessel, whereinto any of them falleth, whatsoeuer is within it shalbe vncleane, and ye shall breake it.", "wycliffe": "Sotheli a vessel of erthe, in which ony thing of these fallith with ynne, schal be defoulid, and therfor it schal be brokun.", "rotherham": "And, as for any earthen vessel whereinto any of them may fall, everything therein shall be unclean, and, the vessel itself, shall ye break in pieces.", "darby": "And every earthen vessel into which [any] of them falleth — whatever is in it shall be unclean; and ye shall break it.", "twenty": "", "jps": "And every earthen vessel whereinto any of them falleth, whatsoever is in it shall be unclean, and it ye shall break.", "acv": "And every earthen vessel, into which any of them falls, whatever is in it shall be unclean, and ye shall break it.", "anderson": "", "haweis": "", "noyes": "", "webster": "And every earthen vessel, into which [any] of them falleth, whatever [is] in it shall be unclean; and ye shall break it.", "vulgate": "vas autem fictile in quo horum quicquam intro ceciderit polluetur et idcirco frangendum est;", "brenton": "And every earthen vessel into which one of these things shall fall, whatsoever is inside it, shall be unclean, and it shall be broken."}}, {"v": 34, "ref": "11:34", "o": "מִ/כָּל הָ/אֹ֜כֶל אֲשֶׁ֣ר יֵאָכֵ֗ל אֲשֶׁ֨ר יָב֥וֹא עָלָ֛י/ו מַ֖יִם יִטְמָ֑א וְ/כָל מַשְׁקֶה֙ אֲשֶׁ֣ר יִשָּׁתֶ֔ה בְּ/כָל כְּלִ֖י יִטְמָֽא", "en": {"kjv": "Of all meat which may be eaten, that on which such water cometh shall be unclean: and all drink that may be drunk in every such vessel shall be unclean.", "web": "All food which may be eaten, that on which water comes, shall be unclean; and all drink that may be drunk in every such vessel shall be unclean.", "bsb": "Any food coming into contact with water from that pot will be unclean, and any drink in such a container will be unclean.", "asv": "All food therein which may be eaten, that on which water cometh, shall be unclean; and all drink that may be drunk in every such vessel shall be unclean.", "ylt": "`Of all the food which is eaten, that on which cometh such water, is unclean, and all drink which is drunk in any such vessel is unclean;", "tyndale": "All maner meate that is eaten, yf any soch water come apon it, it shall be vnclene. And all maner drynke that is droke in all maner soch vessels, shalbe vnclene.", "dra": "Any meat which you eat, if water from such a vessel be poured upon it, shall be unclean; and every liquor that is drunk out of any such vessel, shall be unclean.", "bbe": "Any food in it, and anything on which water from it comes, will be unclean: any drink taken from such a vessel will be unclean.", "geneva": "Al meate also that shalbe eaten, if any such water come vpon it, shalbe vncleane: and all drinke that shalbe drunke in al such vessels shalbe vncleane.", "wycliffe": "Ech mete, which ye schulen ete, schal be vnclene, if water is sched thereon; and ech fletynge thing, which is drunkun of ech vessel, `where ynne vnclene thingis bifelden, schal be vnclene;", "rotherham": "Of all the food that may be eaten, that whereon shall come water, shall be unclean,—and, all drink which might be drunk in any [such] vessel, shall be unclean.", "darby": "All food that is eaten on which [such] water hath come shall be unclean; and all drink that is drunk shall be unclean, in every [such] vessel.", "twenty": "", "jps": "All food therein which may be eaten, that on which water cometh, shall be unclean; and all drink in every such vessel that may be drunk shall be unclean.", "acv": "All food therein which may be eaten, that on which water comes, shall be unclean, and all drink that may be drunk in every such vessel shall be unclean.", "anderson": "", "haweis": "", "noyes": "", "webster": "Of all meat which may be eaten, [that] on which [such] water cometh shall be unclean: and all drink that may be drank in every [such] vessel, shall be unclean.", "vulgate": "omnis cibus quem comeditis si fusa fuerit super eum aqua inmundus erit et omne liquens quod bibitur de universo vase inmundum erit;", "brenton": "And all food that is eaten, on which water shall come from such a vessel, shall be unclean; and every beverage which is drunk in any such vessel, shall be unclean."}}, {"v": 35, "ref": "11:35", "o": "וְ֠/כֹל אֲשֶׁר יִפֹּ֨ל מִ/נִּבְלָתָ֥/ם עָלָי/ו֮ יִטְמָא֒ תַּנּ֧וּר וְ/כִירַ֛יִם יֻתָּ֖ץ טְמֵאִ֣ים הֵ֑ם וּ/טְמֵאִ֖ים יִהְי֥וּ לָ/כֶֽם", "en": {"kjv": "And every thing whereupon any part of their carcase falleth shall be unclean; whether it be oven, or ranges for pots, they shall be broken down: for they are unclean, and shall be unclean unto you.", "web": "Everything whereupon part of their carcass falls shall be unclean; whether oven, or range for pots, it shall be broken in pieces: they are unclean, and shall be unclean to you.", "bsb": "Anything upon which one of their carcasses falls will be unclean. If it is an oven or cooking pot, it must be smashed; it is unclean and will remain unclean for you.", "asv": "And every thing whereupon any part of their carcass falleth shall be unclean; whether oven, or range for pots, it shall be broken in pieces: they are unclean, and shall be unclean unto you.", "ylt": "and anything on which any of their carcase falleth is unclean (oven or double pots), it is broken down, unclean they are , yea, unclean they are to you.", "tyndale": "And whether it be ouen or kettel, it shalbe broken. For they are vnclene and shalbe vnclene vnto you:", "dra": "And upon whatsoever thing any of these dead beasts shall fall, it shall be unclean. Whether it be oven, or pots with feet, they shall be destroyed, and shall be unclean.", "bbe": "Any part of the dead body of one of these, falling on anything, will make it unclean; if it is an oven or a cooking-pot it will have to be broken: they are unclean and will be unclean to you.", "geneva": "And euery thing that their carkeis fall vpon, shalbe vncleane: the fornais or the pot shalbe broken: for they are vncleane, and shalbe vncleane vnto you.", "wycliffe": "and what euer thing of siche deed bodies bi hem silf felde theronne, it schal be vnclene, whether furneisis, ethir vessels of thre feet, tho schulen be destried, and schulen be vnclene.", "rotherham": "And, everything whereon shall fall any part of the carcase of them shall be unclean, oven or fire-range, it shall be destroyed, unclean, they are,—and, unclean, Shall they remain to you.", "darby": "And everything where upon [any part] of their carcase falleth shall be unclean; oven and hearth shall be broken down: they are unclean, and shall be unclean unto you.", "twenty": "", "jps": "And every thing whereupon any part of their carcass falleth shall be unclean; whether oven, or range for pots, it shall be broken in pieces; they are unclean, and shall be unclean unto you.", "acv": "And everything upon which any part of their carcass falls shall be unclean, whether oven, or range for pots, it shall be broken in pieces; they are unclean, and shall be unclean to you.", "anderson": "", "haweis": "", "noyes": "", "webster": "And every [thing] on which [any part] of their carcass falleth, shall be unclean; [whether] an oven, or ranges for pots, they shall be broken down: [for] they [are] unclean, and shall be unclean to you.", "vulgate": "et quicquid de morticinis istiusmodi ceciderit super illud inmundum erit sive clibani sive cytropodes destruentur et inmundi erunt;", "brenton": "And every thing on which there shall fall of their dead bodies shall be unclean; ovens and stands for jars shall be broken down: these are unclean, and they shall be unclean to you."}}, {"v": 36, "ref": "11:36", "o": "אַ֣ךְ מַעְיָ֥ן וּ/ב֛וֹר מִקְוֵה מַ֖יִם יִהְיֶ֣ה טָה֑וֹר וְ/נֹגֵ֥עַ בְּ/נִבְלָתָ֖/ם יִטְמָֽא", "en": {"kjv": "Nevertheless a fountain or pit, wherein there is plenty of water, shall be clean: but that which toucheth their carcase shall be unclean.", "web": "Nevertheless a spring or a cistern in which water is gathered shall be clean: but that which touches their carcass shall be unclean.", "bsb": "Nevertheless, a spring or cistern containing water will remain clean, but one who touches a carcass in it will be unclean.", "asv": "Nevertheless a fountain or a pit wherein is a gathering of water shall be clean: but that which toucheth their carcass shall be unclean.", "ylt": "`Only--a fountain or pit, a collection of water, is clean, but that which is coming against their carcase is unclean;", "tyndale": "Neuerthelater, yet the fountaynes ad welles and pondes of water, shalbe clene styll. But whosoeuer twycheth their carkesses, shall be vnclene.", "dra": "But fountains and cisterns, and all gatherings together of waters shall be clean. He that toucheth their carcasses shall be defiled.", "bbe": "But at the same time a fountain or a place where water is stored for use will be clean; but anyone touching their dead bodies will be unclean.", "geneva": "Yet the fountaines and welles where there is plentie of water shalbe cleane: but that which toucheth their carkeises shalbe vncleane.", "wycliffe": "Sotheli wellis and cisternes, and al the congregacioun of watris, schal be clene. He that touchith her bodi deed bi it silf, schal be defoulid.", "rotherham": "Notwithstanding, a fountain or cistern wherein is a gathering of waters shall be clean,—but, he that toucheth the carcase of them shall be unclean.", "darby": "Nevertheless, a spring or a well, a quantity of water, shall be clean. But he that toucheth their carcase shall be unclean.", "twenty": "", "jps": "Nevertheless a fountain or a cistern wherein is a gathering of water shall be clean; but he who toucheth their carcass shall be unclean.", "acv": "Nevertheless a fountain or a pit in which is a gathering of water shall be clean, but that which touches their carcass shall be unclean.", "anderson": "", "haweis": "", "noyes": "", "webster": "Nevertheless, a fountain or pit, [in which there is] plenty of water, shall be clean: but that which toucheth their carcass shall be unclean.", "vulgate": "fontes vero et cisternae et omnis aquarum congregatio munda erit qui morticinum eorum tetigerit polluetur;", "brenton": "Only if the water be of fountains of water, or a pool, or confluence of water, it shall be clean; but he that touches their carcases shall be unclean."}}, {"v": 37, "ref": "11:37", "o": "וְ/כִ֤י יִפֹּל֙ מִ/נִּבְלָתָ֔/ם עַל כָּל זֶ֥רַע זֵר֖וּעַ אֲשֶׁ֣ר יִזָּרֵ֑עַ טָה֖וֹר הֽוּא", "en": {"kjv": "And if any part of their carcase fall upon any sowing seed which is to be sown, it shall be clean.", "web": "If part of their carcass falls on any sowing seed which is to be sown, it is clean.", "bsb": "If a carcass falls on any seed for sowing, the seed is clean;", "asv": "And if aught of their carcass fall upon any sowing seed which is to be sown, it is clean.", "ylt": "and when any of their carcase falleth on any sown seed which is sown--it is clean;", "tyndale": "Yf the dead carkesse of any soch fall apo any seed vsed to sowe, yt shall yet be clene styll:", "dra": "If it fall upon seed corn, it shall not defile it.", "bbe": "If any part of the dead body of one of these gets on to any seed for planting, it is clean;", "geneva": "And if there fal of their dead carkeis vpon any seede, which vseth to be sowe, it shalbe cleane.", "wycliffe": "If it fallith on seed, it schal not defoule the seed;", "rotherham": "And when any part of the carcase of them shall fall upon seed for sowing, which is to be sown, the same is, clean.", "darby": "And if any part of their carcase fall upon any sowing-seed which is to be sown, it shall be clean;", "twenty": "", "jps": "And if aught of their carcass fall upon any sowing seed which is to be sown, it is clean.", "acv": "And if any of their carcass falls upon any sowing seed which is to be sown, it is clean.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if [any part] of their carcass shall fall upon any sowing-seed which is to be sown, it [shall be] clean.", "vulgate": "si ceciderint super sementem non polluent eam;", "brenton": "And if one of their carcases should fall upon any sowing seed which shall be sown, it shall be clean."}}, {"v": 38, "ref": "11:38", "o": "וְ/כִ֤י יֻתַּן מַ֨יִם֙ עַל זֶ֔רַע וְ/נָפַ֥ל מִ/נִּבְלָתָ֖/ם עָלָ֑י/ו טָמֵ֥א ה֖וּא לָ/כֶֽם", "en": {"kjv": "But if any water be put upon the seed, and any part of their carcase fall thereon, it shall be unclean unto you.", "web": "But if water is put on the seed, and part of their carcass falls on it, it is unclean to you.", "bsb": "but if water has been put on the seed and a carcass falls on it, it is unclean for you.", "asv": "But if water be put upon the seed, and aught of their carcass fall thereon, it is unclean unto you.", "ylt": "and when water is put on the seed, and any of its carcase hath fallen on it--unclean it is to you.", "tyndale": "but ad yf any water be poured apo the seed ad afterward the dead carkesse of them fall thereo, then it shalbe vnclene vnto you.", "dra": "But if any man pour water upon the seed, and afterwards it be touched by the carcasses, it shall be forthwith defiled.", "bbe": "But if water is put on the seed, and any part of the dead body gets on to it, it will be unclean to you.", "geneva": "But if any water be powred vpon ye seede, and there fal of their dead carkeis thereon, it shall be vncleane vnto you.", "wycliffe": "sotheli if ony man schedith seed with watir, and aftirward the watir is touchid with deed bodies bi hem silf, it schal be defoulid anoon.", "rotherham": "But, when water shall be put upon seed, and there shall fall thereon any part of the carcase of them, unclean, it is to you.", "darby": "but if water have been put on the seed, and any part of their carcase fall thereon, it shall be unclean unto you.", "twenty": "", "jps": "But if water be put upon the seed, and aught of their carcass fall thereon, it is unclean unto you.", "acv": "But if water is put upon the seed, and any of their carcass falls in it, it is unclean to you.", "anderson": "", "haweis": "", "noyes": "", "webster": "But if [any] water shall be put upon the seed, and [any part] of their carcass shall fall on it, it [shall be] unclean to you.", "vulgate": "sin autem quispiam aqua sementem perfuderit et postea morticinis tacta fuerit ilico polluetur;", "brenton": "But if water be poured on any seed, and one of their dead bodies fall upon it, it is unclean to you."}}, {"v": 39, "ref": "11:39", "o": "וְ/כִ֤י יָמוּת֙ מִן הַ/בְּהֵמָ֔ה אֲשֶׁר הִ֥יא לָ/כֶ֖ם לְ/אָכְלָ֑ה הַ/נֹּגֵ֥עַ בְּ/נִבְלָתָ֖/הּ יִטְמָ֥א עַד הָ/עָֽרֶב", "en": {"kjv": "And if any beast, of which ye may eat, die; he that toucheth the carcase thereof shall be unclean until the even.", "web": "“‘If any animal, of which you may eat, dies; he who touches its carcass shall be unclean until the evening.", "bsb": "If an animal that you may eat dies, anyone who touches the carcass will be unclean until evening.", "asv": "And if any beast, of which ye may eat, die; he that toucheth the carcass thereof shall be unclean until the even.", "ylt": "`And when any of the beasts which are to you for food dieth, he who is coming against its carcase is unclean till the evening;", "tyndale": "Yf any beest of whiche ye eate dye, he that twitcheth the dead carkesse shalbe vnclene vntyll the euen.", "dra": "If any beast die, of which it is lawful for you to eat, he that toucheth the carcass thereof, shall be unclean until the evening.", "bbe": "And if any beast which may be used for food comes to a natural death, anyone touching its dead body will be unclean till evening.", "geneva": "If also any beast, whereof ye may eate, die, he that toucheth the carkeis thereof shall be vncleane vntil the euen.", "wycliffe": "If a beeste is deed, which it is leueful to you to ete, he that touchith the deed bodi therof schal be vnclene `til to euentid; and he that etith therof ony thing,", "rotherham": "And, when any of the beasts which are yours for food shall die, he that toucheth the carcase of it shall be unclean until the evening.", "darby": "And if any beast which is to you for food die, he that toucheth the carcase thereof shall be unclean until the even.", "twenty": "", "jps": "And if any beast, of which ye may eat, die, he that toucheth the carcass thereof shall be unclean until the even.", "acv": "And if any beast, of which ye may eat, dies, he who touches the carcass of it shall be unclean until the evening.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if any beast, of which ye may eat, shall die; he that toucheth its carcass shall be unclean until the evening.", "vulgate": "si mortuum fuerit animal quod licet vobis comedere qui cadaver eius tetigerit inmundus erit usque ad vesperum;", "brenton": "And if one of the cattle die, which it is lawful for you to eat, he that touches their carcases shall be unclean till evening."}}, {"v": 40, "ref": "11:40", "o": "וְ/הָֽ/אֹכֵל֙ מִ/נִּבְלָתָ֔/הּ יְכַבֵּ֥ס בְּגָדָ֖י/ו וְ/טָמֵ֣א עַד הָ/עָ֑רֶב וְ/הַ/נֹּשֵׂא֙ אֶת נִבְלָתָ֔/הּ יְכַבֵּ֥ס בְּגָדָ֖י/ו וְ/טָמֵ֥א עַד הָ/עָֽרֶב", "en": {"kjv": "And he that eateth of the carcase of it shall wash his clothes, and be unclean until the even: he also that beareth the carcase of it shall wash his clothes, and be unclean until the even.", "web": "He who eats of its carcass shall wash his clothes, and be unclean until the evening. He also who carries its carcass shall wash his clothes, and be unclean until the evening.", "bsb": "Whoever eats from the carcass must wash his clothes and will be unclean until evening, and anyone who picks up the carcass must wash his clothes and will be unclean until evening.", "asv": "And he that eateth of the carcass of it shall wash his clothes, and be unclean until the even: he also that beareth the carcass of it shall wash his clothes, and be unclean until the even.", "ylt": "and he who is eating of its carcase doth wash his garments, and hath been unclean till the evening; and he who is lifting up its carcase doth wash his garments, and hath been unclean till the evening.", "tyndale": "And he that eateth of any soche dead carkesse, shall wasshe his clothes and remayne vnclene vntyll the euen. And he also that beareth the carkesse of it, shall wasshe his clothes and be vnclene vntyll euen.", "dra": "And he that eateth or carrieth any thing thereof, shall wash his clothes, and shall be unclean until the evening.", "bbe": "And he who makes use of any part of its body for food is to have his clothing washed and be unclean till evening; and anyone taking away its body is to have his clothing washed and be unclean till evening.", "geneva": "And he that eateth of the carkeis of it, shall wash his clothes and be vncleane vntil the euen: he also that beareth the carkeis of it, shall wash his clothes, and be vncleane vntil the euen.", "wycliffe": "ethir berith, schal waische his clothis, and schal be vnclene `til to euentid.", "rotherham": "And, he that eateth of the carcase of it, shall wash his clothes, and be unclean until the evening,—he also that carrieth away the carcase thereof shall wash his clothes, and be unclean until the evening.", "darby": "And he that eateth of its carcase shall wash his garments, and be unclean until the even: he also that carrieth its carcase shall wash his garments, and be unclean until the even.", "twenty": "", "jps": "And he that eateth of the carcass of it shall wash his clothes, and be unclean until the even; he also that beareth the carcass of it shall wash his clothes, and be unclean until the even.", "acv": "And he who eats of the carcass of it shall wash his clothes, and be unclean until the evening. He also who bears the carcass of it shall wash his clothes, and be unclean until the evening.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he that eateth of its carcass shall wash his clothes, and be unclean until the evening; he also that beareth its carcass shall wash his clothes and be unclean until the evening.", "vulgate": "et qui comederit ex eo quippiam sive portaverit lavabit vestimenta sua et inmundus erit usque ad vesperum;", "brenton": "And he that eats of their carcases shall wash his garments, and be unclean till evening; and he that carries any of their carcases shall wash his garments, and bathe himself in water, and be unclean till evening."}}, {"v": 41, "ref": "11:41", "o": "וְ/כָל הַ/שֶּׁ֖רֶץ הַ/שֹּׁרֵ֣ץ עַל הָ/אָ֑רֶץ שֶׁ֥קֶץ ה֖וּא לֹ֥א יֵאָכֵֽל", "en": {"kjv": "And every creeping thing that creepeth upon the earth shall be an abomination; it shall not be eaten.", "web": "“‘Every creeping thing that creeps on the earth is an abomination. It shall not be eaten.", "bsb": "Every creature that moves along the ground is detestable; it must not be eaten.", "asv": "And every creeping thing that creepeth upon the earth is an abomination; it shall not be eaten.", "ylt": "`And every teeming thing which is teeming on the earth is an abomination, it is not eaten;", "tyndale": "All that scrauleth apon the erth, is an abhominacyon and shall not be eaten.", "dra": "All that creepeth upon the earth shall be abominable: neither shall it be taken for meat.", "bbe": "Everything which goes flat on its body on the earth is disgusting, and is not to be used for food.", "geneva": "Euery creeping thing therefore that creepeth vpon the earth shalbe an abomination, and not be eaten.", "wycliffe": "Al thing that crepith on erthe, schal be abhomynable, nether schal be takun in to mete.", "rotherham": "And, any creeping thing that creepeth upon the earth, an abomination, it is—it shall not be eaten.", "darby": "And every crawling thing which crawleth on the earth shall be an abomination; it shall not be eaten.", "twenty": "", "jps": "And every swarming thing that swarmeth upon the earth is a detestable thing; it shall not be eaten.", "acv": "And every creeping thing that creeps upon the earth is an abomination; it shall not be eaten.", "anderson": "", "haweis": "", "noyes": "", "webster": "And every creeping animal that creepeth upon the earth [shall be] an abomination; it shall not be eaten.", "vulgate": "omne quod reptat super terram abominabile erit nec adsumetur in cibum;", "brenton": "And every reptile that creeps on the earth, this shall be an abomination to you; it shall not be eaten."}}, {"v": 42, "ref": "11:42", "o": "כֹּל֩ הוֹלֵ֨ךְ עַל גָּח֜ וְ/כֹ֣ל הוֹלֵ֣ךְ עַל אַרְבַּ֗ע עַ֚ד כָּל מַרְבֵּ֣ה רַגְלַ֔יִם לְ/כָל הַ/שֶּׁ֖רֶץ הַ/שֹּׁרֵ֣ץ עַל הָ/אָ֑רֶץ לֹ֥א תֹאכְל֖וּ/ם כִּי שֶׁ֥קֶץ הֵֽם", "en": {"kjv": "Whatsoever goeth upon the belly, and whatsoever goeth upon all four, or whatsoever hath more feet among all creeping things that creep upon the earth, them ye shall not eat; for they are an abomination.", "web": "Whatever goes on its belly, and whatever goes on all fours, or whatever has many feet, even all creeping things that creep on the earth, them you shall not eat; for they are an abomination.", "bsb": "Do not eat any creature that moves along the ground, whether it crawls on its belly or walks on four or more feet; for such creatures are detestable.", "asv": "Whatsoever goeth upon the belly, and whatsoever goeth upon all fours, or whatsoever hath many feet, even all creeping things that creep upon the earth, them ye shall not eat; for they are an abomination.", "ylt": "any thing going on the belly, and any going on four, unto every multiplier of feet, to every teeming thing which is teeming on the earth--ye do not eat them, for they are an abomination;", "tyndale": "And what soeuer goeth apon the brest ad what soeuer goeth apon .iiij. or moo fete amonge all that scrauleth apon the erth, of that se ye eate not: for they are abhomynable.", "dra": "Whatsoever goeth upon the breast on four feet, or hath many feet, or traileth on the earth, you shall not eat, because it is abominable.", "bbe": "Whatever goes on its stomach or on four feet or has a great number of feet, even all those going flat on the earth, may not be used for food, for they are disgusting.", "geneva": "Whatsoeuer goeth vpon the breast, and whatsoeuer goeth vpon al foure, or that hath many feete among all creeping thinges that creepe vpon the earth, ye shall not eate of them, for they shalbe abomination.", "wycliffe": "`What euer thing goith on the brest and foure feet, and hath many feet, ethir drawun bi the erthe, ye schulen not ete, for it is abhomynable.", "rotherham": "Everything that goeth upon the belly, and everything that goeth upon all-fours, even to everything having many feet, as regardeth any creeping thing that creepeth upon the earth, ye shall not eat them for, an abomination, they are.", "darby": "Whatever goeth on the belly, and whatever goeth on all four, and all that have a great many feet, of every manner of crawling thing which crawleth on the earth — these ye shall not eat; for they are an abomination.", "twenty": "", "jps": "Whatsoever goeth upon the belly, and whatsoever goeth upon all fours, or whatsoever hath many feet, even all swarming things that swarm upon the earth, them ye shall not eat; for they are a detestable thing.", "acv": "Whatever goes upon the belly, and whatever goes upon all fours, or whatever has many feet, even all creeping things that creep upon the earth, them ye shall not eat, for they are an abomination.", "anderson": "", "haweis": "", "noyes": "", "webster": "Whatever goeth upon the belly, and whatever goeth upon [all] four, or whatever hath more feet among all creeping animals that creep upon the earth, them ye shall not eat; for they [are] an abomination.", "vulgate": "quicquid super pectus quadrupes graditur et multos habet pedes sive per humum trahitur non comedetis quia abominabile est;", "brenton": "And every animal that creeps on its belly, and every one that goes on four feet continually, which abounds with feet among all the reptiles creeping upon the earth—ye shall not eat it, for it is an abomination to you."}}, {"v": 43, "ref": "11:43", "o": "אַל תְּשַׁקְּצוּ֙ אֶת נַפְשֹׁ֣תֵי/כֶ֔ם בְּ/כָל הַ/שֶּׁ֖רֶץ הַ/שֹּׁרֵ֑ץ וְ/לֹ֤א תִֽטַּמְּאוּ֙ בָּ/הֶ֔ם וְ/נִטְמֵתֶ֖ם בָּֽ/ם", "en": {"kjv": "Ye shall not make yourselves abominable with any creeping thing that creepeth, neither shall ye make yourselves unclean with them, that ye should be defiled thereby.", "web": "You shall not make yourselves abominable with any creeping thing that creeps, neither shall you make yourselves unclean with them, that you should be defiled thereby.", "bsb": "Do not defile yourselves by any crawling creature; do not become unclean or defiled by them.", "asv": "Ye shall not make yourselves abominable with any creeping thing that creepeth, neither shall ye make yourselves unclean with them, that ye should be defiled thereby.", "ylt": "ye do not make yourselves abominable with any teeming thing which is teeming, nor do ye make yourselves unclean with them, so that ye have been unclean thereby.", "tyndale": "Make not youre soules abhominable. Make not youre soules abhomynable with nothinge that crepeth, nether make youre soules vnclene with them: that ye shulde be defiled thereby.", "dra": "Do not defile your souls, nor touch aught thereof, lest you be unclean,", "bbe": "You are not to make yourselves disgusting with anything which goes about flat on the earth; you may not make yourselves unclean with them, in such a way that you are not holy to me.", "geneva": "Ye shall not pollute your selues with any thing that creepeth, neither make your selues vncleane with them, neither defile your selues thereby: ye shall not, I say, be defiled by them,", "wycliffe": "Nyle ye defoule youre soulis, nether touche ye ony thing of tho, lest ye ben vnclene;", "rotherham": "Do not make your persons abominable, with any creeping thing that creepeth,—neither shall ye make yourselves unclean with them, that ye should become unclean thereby.", "darby": "Ye shall not make yourselves abominable through any crawling thing which crawleth, neither shall ye make yourselves unclean with them, that ye should be defiled thereby.", "twenty": "", "jps": "Ye shall not make yourselves detestable with any swarming thing that swarmeth, neither shall ye make yourselves unclean with them, that ye should be defiled thereby.", "acv": "Ye shall not make yourselves abominable with any creeping thing that creeps, nor shall ye make yourselves unclean with them, that ye should be defiled by it.", "anderson": "", "haweis": "", "noyes": "", "webster": "Ye shall not make your selves abominable with any creeping animal that creepeth, neither shall ye make yourselves unclean with them, that ye should be defiled by them.", "vulgate": "nolite contaminare animas vestras nec tangatis quicquam eorum ne inmundi sitis;", "brenton": "And ye shall not defile your souls with any of the reptiles that creep upon the earth, and ye shall not be polluted with them, and ye shall not be unclean by them."}}, {"v": 44, "ref": "11:44", "o": "כִּ֣י אֲנִ֣י יְהוָה֮ אֱלֹֽהֵי/כֶם֒ וְ/הִתְקַדִּשְׁתֶּם֙ וִ/הְיִיתֶ֣ם קְדֹשִׁ֔ים כִּ֥י קָד֖וֹשׁ אָ֑נִי וְ/לֹ֤א תְטַמְּאוּ֙ אֶת נַפְשֹׁ֣תֵי/כֶ֔ם בְּ/כָל הַ/שֶּׁ֖רֶץ הָ/רֹמֵ֥שׂ עַל הָ/אָֽרֶץ", "en": {"kjv": "For I am the Lord your God: ye shall therefore sanctify yourselves, and ye shall be holy; for I am holy: neither shall ye defile yourselves with any manner of creeping thing that creepeth upon the earth.", "web": "For I am Yahweh your God. Sanctify yourselves therefore, and be holy; for I am holy: neither shall you defile yourselves with any kind of creeping thing that moves on the earth.", "bsb": "For I am the LORD your God; consecrate yourselves, therefore, and be holy, because I am holy. You must not defile yourselves by any creature that crawls along the ground.", "asv": "For I am Jehovah your God: sanctify yourselves therefore, and be ye holy; for I am holy: neither shall ye defile yourselves with any manner of creeping thing that moveth upon the earth.", "ylt": "`For I am Jehovah your God, and ye have sanctified yourselves, and ye have been holy, for I am holy; and ye do not defile your persons with any teeming thing which is creeping on the earth;", "tyndale": "For I am the Lorde youre God, be sanctified therfore that ye maye be holy, for I am holy: and defile not youre soules with any maner thinge that crepeth apon the erth.", "dra": "For I am the Lord your God. Be holy because I am holy. Defile not your souls by any creeping thing, that moveth upon the earth.", "bbe": "For I am the Lord your God: for this reason, make and keep yourselves holy, for I am holy; you are not to make yourselves unclean with any sort of thing which goes about flat on the earth.", "geneva": "For I am the Lord your God: be sanctified therefore, and be holy, for I am holy, and defile not your selues with any creeping thing, that creepeth vpon the earth.", "wycliffe": "for Y am youre Lord God; be ye hooli, for Y am hooli. Defoule ye not youre soulis in ech crepynge `beeste which is moued on erthe; for Y am the Lord,", "rotherham": "For, I—Yahweh, am your God, therefore shall ye hallow yourselves and remain holy; for, holy, am, I,—therefore shall ye not make your persons unclean, with any creeping thing that crawleth upon the earth;", "darby": "For I am Jehovah yourGod; and ye shall hallow yourselves, and ye shall be holy; for I am holy; and ye shall not make yourselves unclean through any manner of crawling thing which creepeth on the earth.", "twenty": "", "jps": "For I am HaShem your G-d; sanctify yourselves therefore, and be ye holy; for I am holy; neither shall ye defile yourselves with any manner of swarming thing that moveth upon the earth.", "acv": "For I am Jehovah your God. Sanctify yourselves therefore, and become ye holy, since I am holy. Neither shall ye defile yourselves with any manner of creeping thing that moves upon the earth.", "anderson": "", "haweis": "", "noyes": "", "webster": "For I [am] the LORD your God: ye shall therefore sanctify yourselves, and ye shall be holy; for I [am] holy: neither shall ye defile yourselves with any manner of creeping animal that creepeth upon the earth.", "vulgate": "ego enim sum Dominus Deus vester sancti estote quoniam et ego sanctus sum ne polluatis animas vestras in omni reptili quod movetur super terram;", "brenton": "For I am the Lord your God; and ye shall be sanctified, and ye shall be holy, because I the Lord your God am holy; and ye shall not defile your souls with any of the reptiles creeping upon the earth."}}, {"v": 45, "ref": "11:45", "o": "כִּ֣י אֲנִ֣י יְהוָ֗ה הַֽ/מַּעֲלֶ֤ה אֶתְ/כֶם֙ מֵ/אֶ֣רֶץ מִצְרַ֔יִם לִ/הְיֹ֥ת לָ/כֶ֖ם לֵ/אלֹהִ֑ים וִ/הְיִיתֶ֣ם קְדֹשִׁ֔ים כִּ֥י קָד֖וֹשׁ אָֽנִי", "en": {"kjv": "For I am the Lord that bringeth you up out of the land of Egypt, to be your God: ye shall therefore be holy, for I am holy.", "web": "For I am Yahweh who brought you up out of the land of Egypt, to be your God. You shall therefore be holy, for I am holy.", "bsb": "For I am the LORD, who brought you up out of the land of Egypt so that I would be your God; therefore be holy, because I am holy.", "asv": "For I am Jehovah that brought you up out of the land of Egypt, to be your God: ye shall therefore be holy, for I am holy.", "ylt": "for I am Jehovah who am bringing you up out of the land of Egypt to become your God; and ye have been holy, for I am holy.", "tyndale": "For I am the Lorde that brought you out of the londe off Egipte to be youre God: be holy therfore, for I am holy.", "dra": "For I am the Lord, who brought you out of the land of Egypt, that I might be your God.", "bbe": "For I am the Lord, who took you out of the land of Egypt, to be your God; so be you holy, for I am holy.", "geneva": "For I am the Lord that brought you out of the lande of Egypt, to be your God, and that you should be holy, for I am holy.", "wycliffe": "that ladde you out of the lond of Egipt, that Y schulde be to you in to God; ye schulen be hooli, for Y am hooli.", "rotherham": "for, I—Yahweh, am he that brought you up out of the land of Egypt, that I might become your God,—therefore shall ye be holy, for, holy, am, I.", "darby": "For I am Jehovah who brought you up out of the land of Egypt, to be yourGod: ye shall therefore be holy, for I am holy.", "twenty": "", "jps": "For I am HaShem that brought you up out of the land of Egypt, to be your G-d; ye shall therefore be holy, for I am holy.", "acv": "For I am Jehovah who brought you up out of the land of Egypt, to be your God. Ye shall therefore be holy, for I am holy.", "anderson": "", "haweis": "", "noyes": "", "webster": "For I [am] the LORD that bringeth you out of the land of Egypt, to be your God: ye shall therefore be holy, for I [am] holy.", "vulgate": "ego sum Dominus qui eduxi vos de terra Aegypti ut essem vobis in Deum sancti eritis quia et ego sanctus sum;", "brenton": "For I am the Lord who brought you up out of the land of Egypt to be your God; and ye shall be holy, for I the Lord am holy."}}, {"v": 46, "ref": "11:46", "o": "זֹ֣את תּוֹרַ֤ת הַ/בְּהֵמָה֙ וְ/הָ/ע֔וֹף וְ/כֹל֙ נֶ֣פֶשׁ הַֽ/חַיָּ֔ה הָ/רֹמֶ֖שֶׂת בַּ/מָּ֑יִם וּ/לְ/כָל נֶ֖פֶשׁ הַ/שֹּׁרֶ֥צֶת עַל הָ/אָֽרֶץ", "en": {"kjv": "This is the law of the beasts, and of the fowl, and of every living creature that moveth in the waters, and of every creature that creepeth upon the earth:", "web": "“‘This is the law of the animal, and of the bird, and of every living creature that moves in the waters, and of every creature that creeps on the earth,", "bsb": "This is the law regarding animals, birds, all living creatures that move in the water, and all creatures that crawl along the ground.", "asv": "This is the law of the beast, and of the bird, and of every living creature that moveth in the waters, and of every creature that creepeth upon the earth;", "ylt": "`This is a law of the beasts, and of the fowl, and of every living creature which is moving in the waters, and of every creature which is teeming on the earth,", "tyndale": "This is the lawe of beest and foule and off all maner thinge that lyueth ad moueth in the water ad of all thinges that crepe apo the erth", "dra": "You shall be holy, because I am holy. This is the law of beasts and fowls, and of every living creature that moveth in the waters, and creepeth on the earth:", "bbe": "This is the law about beasts and birds and every living thing moving in the waters, and every living thing which goes flat on the earth:", "geneva": "This is the law of beasts, and of foules, and of euery liuing thing that moueth in the waters, and of euery thing that creepeth vpon the earth:", "wycliffe": "This is the lawe of lyuynge beestes, and of foulis, and of ech lyuynge soule which is moued in watir, and crepith in erthe;", "rotherham": "This, is the law of beast and of bird, and of every living soul that moveth in the waters,—and as to every soul that creepeth upon the earth:", "darby": "This is the law of cattle, and of fowl, and of every living soul that moveth in the waters, and of every soul that crawleth on the earth;", "twenty": "", "jps": "This is the law of the beast, and of the fowl, and of every living creature that moveth in the waters, and of every creature that swarmeth upon the earth;", "acv": "This is the law of the beast, and of the bird, and of every living creature that moves in the waters, and of every creature that creeps upon the earth,", "anderson": "", "haweis": "", "noyes": "", "webster": "This [is] the law of the beasts, and of the fowl, and of every living creature that moveth in the waters, and of every creature that creepeth upon the earth;", "vulgate": "ista est lex animantium et volucrum et omnis animae viventis quae movetur in aqua et reptat in terra;", "brenton": "This is the law concerning beasts and birds and every living creature moving in the water, and every living creature creeping on the earth;"}}, {"v": 47, "ref": "11:47", "o": "לְ/הַבְדִּ֕יל בֵּ֥ין הַ/טָּמֵ֖א וּ/בֵ֣ין הַ/טָּהֹ֑ר וּ/בֵ֤ין הַֽ/חַיָּה֙ הַֽ/נֶּאֱכֶ֔לֶת וּ/בֵין֙ הַֽ/חַיָּ֔ה אֲשֶׁ֖ר לֹ֥א תֵאָכֵֽל", "en": {"kjv": "To make a difference between the unclean and the clean, and between the beast that may be eaten and the beast that may not be eaten.", "web": "to make a distinction between the unclean and the clean, and between the living thing that may be eaten and the living thing that may not be eaten.’”", "bsb": "You must distinguish between the unclean and the clean, between animals that may be eaten and those that may not.’”", "asv": "to make a distinction between the unclean and the clean, and between the living thing that may be eaten and the living thing that may not be eaten.", "ylt": "to make separation between the unclean and the pure, and between the beast that is eaten, and the beast that is not eaten.'", "tyndale": "that ye may put differece betwene vnclene ad clene, ad betwene the beestes that are eate and the beestes that are not eaten.", "dra": "That you may know the differences of the clean, and unclean, and know what you ought to eat, and what to refuse.", "bbe": "Marking out the unclean from the clean, and the living thing which may be used for food from that which may not.", "geneva": "That there may be a difference betweene the vncleane and cleane, and betweene the beast that may be eaten, and the beast that ought not to be eaten.", "wycliffe": "that ye knowe differences of clene thing and vnclene, and that ye wite what ye schulen ete, and what ye owen forsake.", "rotherham": "That ye may make a difference—between the unclean and the clean,—and between the living thing that may be eaten, and the living thing which may not be eaten.", "darby": "to make a difference between the unclean and the clean, and between the beast that is to be eaten and the beast that is not to be eaten.", "twenty": "", "jps": "to make a difference between the unclean and the clean, and between the living thing that may be eaten and the living thing that may not be eaten.", "acv": "to make a distinction between the unclean and the clean, and between the living thing that may be eaten and the living thing that may not be eaten.", "anderson": "", "haweis": "", "noyes": "", "webster": "To make a difference between the unclean and the clean, and between the beast that may be eaten and the beast that may not be eaten.", "vulgate": "ut differentias noveritis mundi et inmundi et sciatis quid comedere et quid respuere debeatis;", "brenton": "to distinguish between the unclean and the clean; and between those that bring forth alive, such as should be eaten, and those that bring forth alive, such as should not be eaten."}}]}, {"c": 12, "verses": [{"v": 1, "ref": "12:1", "o": "וַ/יְדַבֵּ֥ר יְהוָ֖ה אֶל מֹשֶׁ֥ה לֵּ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh spoke to Moses, saying,", "bsb": "Then the LORD said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde spake vnto Moses and sayde:", "dra": "And the Lord spoke to Moses, saying:", "bbe": "And the Lord said to Moses,", "geneva": "And the Lord spake vnto Moses, saying,", "wycliffe": "And the Lord spak to Moises, `and seide, Speke thou to the sones of Israel,", "rotherham": "And Yahweh spake unto Moses, saying:", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses, saying:", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "locutus est Dominus ad Mosen dicens;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 2, "ref": "12:2", "o": "דַּבֵּ֞ר אֶל בְּנֵ֤י יִשְׂרָאֵל֙ לֵ/אמֹ֔ר אִשָּׁה֙ כִּ֣י תַזְרִ֔יעַ וְ/יָלְדָ֖ה זָכָ֑ר וְ/טָֽמְאָה֙ שִׁבְעַ֣ת יָמִ֔ים כִּ/ימֵ֛י נִדַּ֥ת דְּוֺתָ֖/הּ תִּטְמָֽא", "en": {"kjv": "Speak unto the children of Israel, saying, If a woman have conceived seed, and born a man child: then she shall be unclean seven days; according to the days of the separation for her infirmity shall she be unclean.", "web": "“Speak to the children of Israel, saying, ‘If a woman conceives, and bears a male child, then she shall be unclean seven days; as in the days of her monthly period she shall be unclean.", "bsb": "“Say to the Israelites, ‘A woman who becomes pregnant and gives birth to a son will be unclean for seven days, as she is during the days of her menstruation.", "asv": "Speak unto the children of Israel, saying, If a woman conceive seed, and bear a man-child, then she shall be unclean seven days; as in the days of the impurity of her sickness shall she be unclean.", "ylt": "`Speak unto the sons of Israel, saying, A woman when she giveth seed, and hath born a male, then she hath been unclean seven days, according to the days of separation for her sickness she is unclean;", "tyndale": "speake vnto the childern of Israel ad saye: whe a woma hath conceaued ad hath borne a man childe, she shalbe vnclene .vij. dayes: euen in like maner as when she is put aparte in tyme of hir naturall disease.", "dra": "Speak to the children of Israel, and thou shalt say to them: If a woman having received seed shall bear a man child, she shall be unclean seven days, according to the days of separation of her flowers.", "bbe": "Say to the children of Israel, If a woman is with child and gives birth to a male child, she will be unclean for seven days, as when she is unwell.", "geneva": "Speake vnto the children of Israel, and say, When a woman hath brought forth seede, and borne a manchilde, shee shalbe vncleane seuen dayes, like as she is vncleane when she is put apart for her disease.", "wycliffe": "and thou schalt seie to hem, If a womman, whanne sche hath resseyued seed, childith a knaue child, sche schal be vnclene bi seuene daies bi the daies of departyng of corrupt blood, that renneth bi monethis;", "rotherham": "Speak unto the sons of Israel, saying, A woman when she conceiveth seed and giveth birth to a male child, then shall she be unclean seven days, according to the days of her removal in her sickness shall she be unclean.", "darby": "Speak unto the children of Israel, saying, If a woman conceive seed, and bear a male, then she shall be unclean seven days; as in the days of the separation of her infirmity shall she be unclean.", "twenty": "", "jps": "Speak unto the children of Israel, saying: If a woman be delivered, and bear a man-child, then she shall be unclean seven days; as in the days of the impurity of her sickness shall she be unclean.", "acv": "Speak to the sons of Israel, saying, If a woman conceives seed, and bears a man-child, then she shall be unclean seven days, as in the days of the impurity of her sickness she shall be unclean.", "anderson": "", "haweis": "", "noyes": "", "webster": "Speak to the children of Israel, saying, If a woman hath conceived seed, and borne a male-child; then she shall be unclean seven days; according to the days of the separation for her infirmity shall she be unclean.", "vulgate": "loquere filiis Israhel et dices ad eos mulier si suscepto semine pepererit masculum inmunda erit septem diebus iuxta dies separationis menstruae;", "brenton": "Speak to the children of Israel, and thou shalt say to them, Whatsoever woman shall have conceived and born a male child shall be unclean seven days, she shall be unclean according to the days of separation for her monthly courses."}}, {"v": 3, "ref": "12:3", "o": "וּ/בַ/יּ֖וֹם הַ/שְּׁמִינִ֑י יִמּ֖וֹל בְּשַׂ֥ר עָרְלָתֽ/וֹ", "en": {"kjv": "And in the eighth day the flesh of his foreskin shall be circumcised.", "web": "In the eighth day the flesh of his foreskin shall be circumcised.", "bsb": "And on the eighth day the flesh of the boy’s foreskin is to be circumcised.", "asv": "And in the eighth day the flesh of his foreskin shall be circumcised.", "ylt": "and in the eighth day is the flesh of his foreskin circumcised;", "tyndale": "And in the viij. daye the flesh of the childes foreskynne shalbe cut awaye.", "dra": "And on the eighth day the infant shall be circumcised:", "bbe": "And on the eighth day let him be given circumcision.", "geneva": "(And in the eight day, the foreskin of the childes flesh shalbe circumcised)", "wycliffe": "and the yong child schal be circumsidid in the eiytithe dai.", "rotherham": "And, on the eighth day, shall the flesh of his foreskin be circumcised.", "darby": "And on the eighth day shall the flesh of his foreskin be circumcised.", "twenty": "", "jps": "And in the eighth day the flesh of his foreskin shall be circumcised.", "acv": "And in the eighth day the flesh of his foreskin shall be circumcised.", "anderson": "", "haweis": "", "noyes": "", "webster": "And in the eighth day the flesh of his foreskin shall be circumcised.", "vulgate": "et die octavo circumcidetur infantulus;", "brenton": "And on the eighth day she shall circumcise the flesh of his foreskin."}}, {"v": 4, "ref": "12:4", "o": "וּ/שְׁלֹשִׁ֥ים יוֹם֙ וּ/שְׁלֹ֣שֶׁת יָמִ֔ים תֵּשֵׁ֖ב בִּ/דְמֵ֣י טָהֳרָ֑ה בְּ/כָל קֹ֣דֶשׁ לֹֽא תִגָּ֗ע וְ/אֶל הַ/מִּקְדָּשׁ֙ לֹ֣א תָבֹ֔א עַד מְלֹ֖את יְמֵ֥י טָהֳרָֽ/הּ", "en": {"kjv": "And she shall then continue in the blood of her purifying three and thirty days; she shall touch no hallowed thing, nor come into the sanctuary, until the days of her purifying be fulfilled.", "web": "She shall continue in the blood of purification thirty-three days. She shall not touch any holy thing, nor come into the sanctuary, until the days of her purifying are completed.", "bsb": "The woman shall continue in purification from her bleeding for thirty-three days. She must not touch anything sacred or go into the sanctuary until the days of her purification are complete.", "asv": "And she shall continue in the blood of her purifying three and thirty days; she shall touch no hallowed thing, nor come into the sanctuary, until the days of her purifying be fulfilled.", "ylt": "and thirty and three days she doth abide in the blood of her cleansing; against any holy thing she doth not come, and unto the sanctuary she doth not go in, till the fulness of the days of her cleansing.", "tyndale": "And she shall cotynue in the bloude of hir purifienge .xxxiij. dayes, she shal twytch no halowed thinge nor come in to the sanctuary, vntyll the tyme of hir purifienge be out.", "dra": "But she shall remain three and thirty days in the blood of her purification. She shall touch no holy thing: neither shall she enter into the sanctuary, until the days of her purification, be fulfilled.", "bbe": "And she will be unclean for thirty-three days till the flow of her blood is stopped; no holy thing may be touched by her, and she may not come into the holy place, till the days for making her clean are ended.", "geneva": "And she shall continue in the blood of her purifying three and thirtie dayes: she shall touch no halowed thing, nor come into the Sanctuarie, vntil the time of her purifying be out.", "wycliffe": "Sotheli sche schal dwelle thre and thretti daies in the blood of hir purifiyng; sche schal not touche ony hooli thing, nethir sche schal entre in to the seyntuarie, til the daies of her clensing be fillid.", "rotherham": "And, for thirty-three days, shall she continue in the blood of purification,—no hallowed thing, shall she touch, and, into the sanctuary, shall she not enter, until her days of purification are fulfilled.", "darby": "And she shall continue thirty-three days in the blood of her cleansing; no holy thing shall she touch, nor come into the sanctuary, until the days of her cleansing are fulfilled.", "twenty": "", "jps": "And she shall continue in the blood of purification three and thirty days; she shall touch no hallowed thing, nor come into the sanctuary, until the days of her purification be fulfilled.", "acv": "And she shall continue in the blood of her purifying thirty-three days. She shall touch no hallowed thing, nor come into the sanctuary, until the days of her purifying be fulfilled.", "anderson": "", "haweis": "", "noyes": "", "webster": "And she shall then continue in the blood of her purifying three and thirty days: she shall touch no hallowed thing, nor come into the sanctuary, until the days of her purifying be fulfilled.", "vulgate": "ipsa vero triginta tribus diebus manebit in sanguine purificationis suae omne sanctum non tanget nec ingredietur sanctuarium donec impleantur dies purificationis eius;", "brenton": "And for thirty-three days she shall continue in her unclean blood; she shall touch nothing holy, and shall not enter the sanctuary, until the days of her purification be fulfilled."}}, {"v": 5, "ref": "12:5", "o": "וְ/אִם נְקֵבָ֣ה תֵלֵ֔ד וְ/טָמְאָ֥ה שְׁבֻעַ֖יִם כְּ/נִדָּתָ֑/הּ וְ/שִׁשִּׁ֥ים יוֹם֙ וְ/שֵׁ֣שֶׁת יָמִ֔ים תֵּשֵׁ֖ב עַל דְּמֵ֥י טָהֳרָֽה", "en": {"kjv": "But if she bear a maid child, then she shall be unclean two weeks, as in her separation: and she shall continue in the blood of her purifying threescore and six days.", "web": "But if she bears a female child, then she shall be unclean two weeks, as in her period; and she shall continue in the blood of purification sixty-six days.", "bsb": "If, however, she gives birth to a daughter, the woman will be unclean for two weeks as she is during her menstruation. Then she must continue in purification from her bleeding for sixty-six days.", "asv": "But if she bear a maid-child, then she shall be unclean two weeks, as in her impurity; and she shall continue in the blood of her purifying threescore and six days.", "ylt": "`And if a female she bear, then she hath been unclean two weeks, as in her separation; and sixty and six days she doth abide for the blood of her cleansing.", "tyndale": "Yf she bere a maydehilde, then she shalbe vnclene two wekes as when she hath hir naturall disease. And she shall contynue in the bloude of hir purifienge .lxvj. dayes.", "dra": "But if she shall bear a maid child, she shall be unclean two weeks, according to the custom of her monthly courses. And she shall remain in the blood of her purification sixty-six days.", "bbe": "But if she gives birth to a female child, then she will be unclean for two weeks, as when she is unwell; and she will not be completely clean for sixty-six days.", "geneva": "But if she beare a mayde childe, then shee shalbe vncleane two weekes, as when shee hath her disease: and she shall continue in the blood of her purifying three score and sixe dayes.", "wycliffe": "Sotheli if sche childith a female, sche schal be vnclene twei woukis, bi the custom of flowyng of vnclene blood, and `thre scoor and sixe daies sche schal dwelle in the blood of her clensyng.", "rotherham": "But if, a female child, she bear, then shall she be unclean two weeks as in her removal,—and, for sixty-six days, shall she continue in the blood of purification.", "darby": "And if she bear a female, then she shall be unclean two weeks, as in her separation; and she shall continue sixty-six days in the blood of her cleansing.", "twenty": "", "jps": "But if she bear a maid-child, then she shall be unclean two weeks, as in her impurity; and she shall continue in the blood of purification threescore and six days.", "acv": "But if she bears a maid-child, then she shall be unclean two weeks, as in her impurity, and she shall continue in the blood of her purifying sixty-six days.", "anderson": "", "haweis": "", "noyes": "", "webster": "But if she shall bear a female-child, then she shall be unclean two weeks, as in her separation: and she shall continue in the blood of her purifying sixty six days.", "vulgate": "sin autem feminam pepererit inmunda erit duabus ebdomadibus iuxta ritum fluxus menstrui et sexaginta ac sex diebus manebit in sanguine purificationis suae;", "brenton": "But if she should have born a female child, then she shall be unclean twice seven days, according to the time of her monthly courses; and for sixty-six days shall she remain in her unclean blood."}}, {"v": 6, "ref": "12:6", "o": "וּ/בִ/מְלֹ֣את יְמֵ֣י טָהֳרָ֗/הּ לְ/בֵן֮ א֣וֹ לְ/בַת֒ תָּבִ֞יא כֶּ֤בֶשׂ בֶּן שְׁנָת/וֹ֙ לְ/עֹלָ֔ה וּ/בֶן יוֹנָ֥ה אוֹ תֹ֖ר לְ/חַטָּ֑את אֶל פֶּ֥תַח אֹֽהֶל מוֹעֵ֖ד אֶל הַ/כֹּהֵֽן", "en": {"kjv": "And when the days of her purifying are fulfilled, for a son, or for a daughter, she shall bring a lamb of the first year for a burnt offering, and a young pigeon, or a turtledove, for a sin offering, unto the door of the tabernacle of the congregation, unto the priest:", "web": "“‘When the days of her purification are completed, for a son, or for a daughter, she shall bring to the priest at the door of the Tent of Meeting, a year old lamb for a burnt offering, and a young pigeon, or a turtledove, for a sin offering:", "bsb": "When the days of her purification are complete, whether for a son or for a daughter, she is to bring to the priest at the entrance to the Tent of Meeting a year-old lamb for a burnt offering and a young pigeon or a turtledove for a sin offering.", "asv": "And when the days of her purifying are fulfilled, for a son, or for a daughter, she shall bring a lamb a year old for a burnt-offering, and a young pigeon, or a turtle-dove, for a sin-offering, unto the door of the tent of meeting, unto the priest:", "ylt": "`And in the fulness of the days of her cleansing for son or for daughter she doth bring in a lamb, a son of a year, for a burnt-offering, and a young pigeon or a turtle-dove for a sin-offering, unto the opening of the tent of meeting, unto the priest;", "tyndale": "And when the dayes of hir purifienge are out: whether it be a sonne or a doughter, she shall brynge a lambe of one yere olde for a burntoffrynge and a yonge pigeon or a turtill doue for a synneoffrynge vnto the dore of the tabernacle of witnesse vnto the preast:", "dra": "And when the days of her purification are expired, for a son, or for a daughter, she shall bring to the door of the tabernacle of the testimony, a lamb of a year old for a holocaust, and a young pigeon or a turtle for sin: and shall deliver them to the priest.", "bbe": "And when the days are ended for making her clean for a son or a daughter, let her take to the priest at the door of the Tent of meeting, a lamb of the first year for a burned offering and a young pigeon or a dove for a sin-offering:", "geneva": "Nowe when the dayes of her purifying are out, (whether it be for a sonne or for a daughter) shee shall bring to the Priest a lambe of one yeere olde for a burnt offering, and a yong pigeon or a turtle doue for a sinne offring, vnto the doore of the Tabernacle of the Congregation,", "wycliffe": "And whanne the daies of hir clensyng, for a sone, ether for a douytir, ben fillid, sche schal brynge a lomb of o yeer in to brent sacrifice, and a `bryd of a culuer, ethir a turtle, for synne, to the dore of the tabernacle of witnessyng;", "rotherham": "And, when the days of her purification are fulfilled, whether for a son or for a daughter, she shall bring in a lamb, the choice of its year, as an ascending-sacrifice, and a young pigeon or a turtle-dove, as a sin-bearer, unto the entrance of the tent of meeting, unto the priest;", "darby": "And when the days of her cleansing are fulfilled, for a son or for a daughter, she shall bring a yearling lamb for a burnt-offering, and a young pigeon or a turtle-dove for a sin-offering, to the entrance of the tent of meeting, unto the priest.", "twenty": "", "jps": "And when the days of her purification are fulfilled, for a son, or for a daughter, she shall bring a lamb of the first year for a burnt-offering, and a young pigeon, or a turtle-dove, for a sin-offering, unto the door of the tent of meeting, unto the priest.", "acv": "And when the days of her purifying are fulfilled, for a son, or for a daughter, she shall bring a lamb a year old for a burnt offering, and a young pigeon, or a turtle-dove, for a sin offering, to the door of the tent of meeting, to the priest.", "anderson": "", "haweis": "", "noyes": "", "webster": "And when the days of her purifying are fulfilled, for a son, or for a daughter, she shall bring a lamb of the first year for a burnt-offering, and a young pigeon, or a turtle-dove, for a sin-offering, to the door of the tabernacle of the congregation, to the priest;", "vulgate": "cumque expleti fuerint dies purificationis eius pro filio sive pro filia deferet agnum anniculum in holocaustum et pullum columbae sive turturem pro peccato ad ostium tabernaculi testimonii et tradet sacerdoti;", "brenton": "And when the days of her purification shall have been fulfilled for a son or a daughter, she shall bring a lamb of a year old without blemish for a whole-burnt-offering, and a young pigeon or turtle-dove for a sin-offering to the door of the tabernacle of witness, to the priest."}}, {"v": 7, "ref": "12:7", "o": "וְ/הִקְרִיב֞/וֹ לִ/פְנֵ֤י יְהוָה֙ וְ/כִפֶּ֣ר עָלֶ֔י/הָ וְ/טָהֲרָ֖ה מִ/מְּקֹ֣ר דָּמֶ֑י/הָ זֹ֤את תּוֹרַת֙ הַ/יֹּלֶ֔דֶת לַ/זָּכָ֖ר א֥וֹ לַ/נְּקֵבָֽה", "en": {"kjv": "Who shall offer it before the Lord, and make an atonement for her; and she shall be cleansed from the issue of her blood. This is the law for her that hath born a male or a female.", "web": "and he shall offer it before Yahweh, and make atonement for her; and she shall be cleansed from the fountain of her blood. “‘This is the law for her who bears, whether a male or a female.", "bsb": "And the priest will present them before the LORD and make atonement for her; and she shall be ceremonially cleansed from her flow of blood. This is the law for a woman giving birth, whether to a male or to a female.", "asv": "and he shall offer it before Jehovah, and make atonement for her; and she shall be cleansed from the fountain of her blood. This is the law for her that beareth, whether a male or a female.", "ylt": "and he hath brought it near before Jehovah, and hath made atonement for her, and she hath been cleansed from the fountain of her blood; this is the law of her who is bearing, in regard to a male or to a female.", "tyndale": "which shall offer them before the Lorde and make an attonement for her, and so she shalbe purged of hir yssue of bloude. This is the lawe of her that hath borne a childe, whether it be male or female.", "dra": "Who shall offer them before the Lord, and shall pray for her: and so she shall be cleansed from the issue of her blood. This is the law for her that beareth a man child or a maid child.", "bbe": "And the priest is to make an offering of it before the Lord and take away her sin, and she will be made clean from the flow of her blood. This is the law for a woman who gives birth to a male or a female.", "geneva": "Who shall offer it before the Lord, and make an atonement for her: so she shalbe purged of the issue of her blood this is the law for her that hath borne a male or female.", "wycliffe": "and sche schal yyue to the preest, which schal offre tho bifor the Lord, and schal preye for hir, and so sche schal be clensid fro the fowyng of hir blood. This is the lawe of a womman childynge a male, ethir a female.", "rotherham": "and he shall bring it near before Yahweh so shall the priest put a propitiatory-covering over her, and she shall be clean from her fountain of blood. This, is the law for her that hath given birth, to a male child or to a female.", "darby": "And he shall present it before Jehovah, and make atonement for her; and she shall be clean from the flux of her blood. This is the law for her that hath borne a male or a female.", "twenty": "", "jps": "And he shall offer it before HaShem, and make atonement for her; and she shall be cleansed from the fountain of her blood. This is the law for her that beareth, whether a male or a female.", "acv": "And he shall offer it before Jehovah, and make atonement for her, and she shall be cleansed from the fountain of her blood. This is the law for her who bears, whether a male or a female.", "anderson": "", "haweis": "", "noyes": "", "webster": "Who shall offer it before the LORD, and make an atonement for her; and she shall be cleansed from the issue of her blood. This [is] the law for her that hath borne a male or a female.", "vulgate": "qui offeret illa coram Domino et rogabit pro ea et sic mundabitur a profluvio sanguinis sui ista est lex parientis masculum ac feminam;", "brenton": "And he shall present it before the Lord, and the priest shall make atonement for her, and shall purge her from the fountain of her blood; this is the law of her who bears a male or a female."}}, {"v": 8, "ref": "12:8", "o": "וְ/אִם לֹ֨א תִמְצָ֣א יָדָ/הּ֮ דֵּ֣י שֶׂה֒ וְ/לָקְחָ֣ה שְׁתֵּֽי תֹרִ֗ים א֤וֹ שְׁנֵי֙ בְּנֵ֣י יוֹנָ֔ה אֶחָ֥ד לְ/עֹלָ֖ה וְ/אֶחָ֣ד לְ/חַטָּ֑את וְ/כִפֶּ֥ר עָלֶ֛י/הָ הַ/כֹּהֵ֖ן וְ/טָהֵֽרָה", "en": {"kjv": "And if she be not able to bring a lamb, then she shall bring two turtles, or two young pigeons; the one for the burnt offering, and the other for a sin offering: and the priest shall make an atonement for her, and she shall be clean.", "web": "If she cannot afford a lamb, then she shall take two turtledoves, or two young pigeons; the one for a burnt offering, and the other for a sin offering: and the priest shall make atonement for her, and she shall be clean.’”", "bsb": "But if she cannot afford a lamb, she shall bring two turtledoves or two young pigeons, one for a burnt offering and the other for a sin offering. Then the priest will make atonement for her, and she will be clean.’”", "asv": "And if her means suffice not for a lamb, then she shall take two turtle-doves, or two young pigeons; the one for a burnt-offering, and the other for a sin-offering: and the priest shall make atonement for her, and she shall be clean.", "ylt": "`And if her hand find not the sufficiency of a sheep, then she hath taken two turtle-doves, or two young pigeons, one for a burnt-offering, and one for a sin-offering, and the priest hath made atonement for her, and she hath been cleansed.'", "tyndale": "But and yf she be not able to bringe a shepe, then let her brynge two turtyls or two yonge pigeons: the one for the burntofferynge, and the other for the synneofferynge. And the preast shall make an attonement for her, ad she shalbe clene.", "dra": "And if her hand find not sufficiency, and she is not able to offer a lamb, she shall take two turtles, or two young pigeons, one for a holocaust, and another for sin: and the priest shall pray for her, and so she shall be cleansed.", "bbe": "And if she has not money enough for a lamb, then let her take two doves or two young pigeons, one for a burned offering and the other for a sin-offering, and the priest will take away her sin and she will be clean,", "geneva": "But if she bee not able to bring a lambe, she shall bring two turtles, or two yong pigeons: the one for a burnt offring, and the other for a sinne offring: and the Priest shall make an atonement for her: so she shall be cleane.", "wycliffe": "That if hir hond fyndith not, nethir may offre a lomb, sche schal take twei turtlis, ethir twei `briddis of culueres, oon in to brent sacrifice, and the tother for synne; and the preest schal preye for hir, and so sche schal be clensid.", "rotherham": "But, if her hand findeth not sufficiency for a lamb, then shall she take two turtle doves or two young pigeons, one for an ascending-sacrifice and one for a sin-bearer,—so shall the priest put a propitiatory-covering over her, and she shall be clean.", "darby": "And if her hand cannot find what is sufficient for a sheep, she shall bring two turtle-doves or two young pigeons; one for a burnt-offering, and the other for a sin-offering; and the priest shall make atonement for her; and she shall be clean.", "twenty": "", "jps": "And if her means suffice not for a lamb, then she shall take two turtle-doves, or two young pigeons: the one for a burnt-offering, and the other for a sin-offering; and the priest shall make atonement for her, and she shall be clean.", "acv": "And if her means are not sufficient for a lamb, then she shall take two turtle-doves, or two young pigeons, the one for a burnt offering, and the other for a sin offering. And the priest shall make atonement for her, and she shall be clean.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if she shall not be able to bring a lamb, then she shall bring two turtles, or two young pigeons; the one for the burnt-offering, and the other for a sin-offering: and the priest shall make an atonement for her, and she shall be clean.", "vulgate": "quod si non invenerit manus eius nec potuerit offerre agnum sumet duos turtures vel duos pullos columbae unum in holocaustum et alterum pro peccato orabitque pro ea sacerdos et sic mundabitur;", "brenton": "And if she cannot afford a lamb, then shall she take two turtle-doves or two young pigeons, one for a whole-burnt-offering, and one for a sin-offering; and the priest shall make atonement for her, and she shall be purified."}}]}, {"c": 13, "verses": [{"v": 1, "ref": "13:1", "o": "וַ/יְדַבֵּ֣ר יְהוָ֔ה אֶל מֹשֶׁ֥ה וְ/אֶֽל אַהֲרֹ֖ן לֵ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses and Aaron, saying,", "web": "Yahweh spoke to Moses and to Aaron, saying,", "bsb": "Then the LORD said to Moses and Aaron,", "asv": "And Jehovah spake unto Moses and unto Aaron, saying,", "ylt": "And Jehovah speaketh unto Moses, and unto Aaron, saying,", "tyndale": "And the Lord spake vnto Moses ad uto Aaro saynge:", "dra": "And the Lord spoke to Moses and Aaron, saying:", "bbe": "And the Lord said to Moses and Aaron,", "geneva": "Moreouer the Lord spake vnto Moses, and to Aaron, saying,", "wycliffe": "The Lord spak to Moyses and Aaron, and seide,", "rotherham": "And Yahweh spake unto Moses and unto Aaron, saying—", "darby": "And Jehovah spoke to Moses and to Aaron, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses and unto Aaron, saying:", "acv": "And Jehovah spoke to Moses and to Aaron, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses and Aaron, saying,", "vulgate": "locutus est Dominus ad Mosen et Aaron dicens;", "brenton": "And the Lord spoke to Moses and Aaron, saying,"}}, {"v": 2, "ref": "13:2", "o": "אָדָ֗ם כִּֽי יִהְיֶ֤ה בְ/עוֹר בְּשָׂר/וֹ֙ שְׂאֵ֤ת אֽוֹ סַפַּ֨חַת֙ א֣וֹ בַהֶ֔רֶת וְ/הָיָ֥ה בְ/עוֹר בְּשָׂר֖/וֹ לְ/נֶ֣גַע צָרָ֑עַת וְ/הוּבָא֙ אֶל אַהֲרֹ֣ן הַ/כֹּהֵ֔ן א֛וֹ אֶל אַחַ֥ד מִ/בָּנָ֖י/ו הַ/כֹּהֲנִֽים", "en": {"kjv": "When a man shall have in the skin of his flesh a rising, a scab, or bright spot, and it be in the skin of his flesh like the plague of leprosy; then he shall be brought unto Aaron the priest, or unto one of his sons the priests:", "web": "“When a man shall have a rising in his body’s skin, or a scab, or a bright spot, and it becomes in the skin of his body the plague of leprosy, then he shall be brought to Aaron the priest, or to one of his sons, the priests:", "bsb": "“When someone has a swelling or rash or bright spot on his skin that could become an infectious skin disease, he must be brought to Aaron the priest or to one of his sons who is a priest.", "asv": "When a man shall have in the skin of his flesh a rising, or a scab, or a bright spot, and it become in the skin of his flesh the plague of leprosy, then he shall be brought unto Aaron the priest, or unto one of his sons the priests:", "ylt": "`When a man hath in the skin of his flesh a rising, or scab, or bright spot, and it hath become in the skin of his flesh a leprous plague, then he hath been brought in unto Aaron the priest, or unto one of his sons the priests;", "tyndale": "whe there apeareth a rysinge in any mas flesh ether a scabbe or a glistrige whyte: as though the plage of leprosye were in the skynne of his flesh, then let him be brought vnto Aaron the preast or vnto one of hys sonnes the preastes,", "dra": "The man in whose skin or flesh shall arise a different colour or a blister, or as it were something shining, that is the stroke of the leprosy, shall be brought to Aaron the priest, or any or of his sons.", "bbe": "If a man has on his skin a growth or a mark or a white place, and it becomes the disease of a leper, let him be taken to Aaron the priest, or to one of the priests, his sons;", "geneva": "The man that shall haue in the skin of his flesh a swelling or a skab, or a white spot, so that in the skinne of his flesh it be like the plague of leprosie, then he shalbe brought vnto Aaron the Priest, or vnto one of his sonnes the Priestes,", "wycliffe": "A man in whos skyn and fleisch rysith dyuerse colour, ether whelke, ethir as `sum schynynge thing, that is, a wounde of lepre, he schal be brouyt to Aaron preest, ether to oon `who euer of hise sones;", "rotherham": "When, any man, shall have—in the skin of his flesh—a rising, or a scab, or a bright spot, and it shall become in the skin of his flesh the plague-spot of leprosy, then shall he be brought in unto Aaron the priest, or unto one of his sons the priests;", "darby": "When a man shall have in the skin of his flesh a rising or a scab, or bright spot, and it become in the skin of his flesh a sore [as] of leprosy, then he shall be brought unto Aaron the priest, or unto one of his sons the priests.", "twenty": "", "jps": "When a man shall have in the skin of his flesh a rising, or a scab, or a bright spot, and it become in the skin of his flesh the plague of leprosy, then he shall be brought unto Aaron the priest, or unto one of his sons the priests.", "acv": "When a man shall have in the skin of his flesh a rising, or a scab, or a bright spot, and it becomes in the skin of his flesh a leprous disease, then he shall be brought to Aaron the priest, or to one of his sons the priests.", "anderson": "", "haweis": "", "noyes": "", "webster": "When a man shall have in the skin of his flesh a rising, a scab, or bright spot, and it be in the skin of his flesh [like] the plague of leprosy; then he shall be brought to Aaron the priest, or to one of his sons the priests:", "vulgate": "homo in cuius carne et cute ortus fuerit diversus color sive pustula aut quasi lucens quippiam id est plaga leprae adducetur ad Aaron sacerdotem vel ad unum quemlibet filiorum eius;", "brenton": "If any man should have in the skin of his flesh a bright clear spot, and there should be in the skin of his flesh a plague of leprosy, he shall be brought to Aaron the priest, or to one of his sons the priests."}}, {"v": 3, "ref": "13:3", "o": "וְ/רָאָ֣ה הַ/כֹּהֵ֣ן אֶת הַ/נֶּ֣גַע בְּ/עֽוֹר הַ֠/בָּשָׂר וְ/שֵׂעָ֨ר בַּ/נֶּ֜גַע הָפַ֣ךְ לָבָ֗ן וּ/מַרְאֵ֤ה הַ/נֶּ֨גַע֙ עָמֹק֙ מֵ/ע֣וֹר בְּשָׂר֔/וֹ נֶ֥גַע צָרַ֖עַת ה֑וּא וְ/רָאָ֥/הוּ הַ/כֹּהֵ֖ן וְ/טִמֵּ֥א אֹתֽ/וֹ", "en": {"kjv": "And the priest shall look on the plague in the skin of the flesh: and when the hair in the plague is turned white, and the plague in sight be deeper than the skin of his flesh, it is a plague of leprosy: and the priest shall look on him, and pronounce him unclean.", "web": "and the priest shall examine the plague in the skin of the body: and if the hair in the plague has turned white, and the appearance of the plague is deeper than the body’s skin, it is the plague of leprosy; and the priest shall examine him, and pronounce him unclean.", "bsb": "The priest is to examine the infection on his skin, and if the hair in the infection has turned white and the sore appears to be deeper than the skin, it is a skin disease. After the priest examines him, he must pronounce him unclean.", "asv": "and the priest shall look on the plague in the skin of the flesh: and if the hair in the plague be turned white, and the appearance of the plague be deeper than the skin of his flesh, it is the plague of leprosy; and the priest shall look on him, and pronounce him unclean.", "ylt": "and the priest hath seen the plague in the skin of the flesh, and the hair in the plague hath turned white, and the appearance of the plague is deeper than the skin of his flesh--it is a plague of leprosy, and the priest hath seen him, and hath pronounced him unclean.", "tyndale": "and let the preast loke on the sore that is in the skynne of his fleshe. Yf the heer in the sore be turned vnto whyte, and the sore also seme to be lower than the skynne of his fleshe then it is suerly a leprosye, and let the preast loke on him and make hym vnclene.", "dra": "And if he see the leprosy in his skin, and the hair turned white and the place where the leprosy appears lower than the skin and the rest of the flesh: it is the stroke of the leprosy, and upon his judgment he shall be separated.", "bbe": "And if, when the priest sees the mark on his skin, the hair on the place is turned white and the mark seems to go deeper than the skin, it is the mark of a leper: and the priest, after looking at him, will say that he is unclean.", "geneva": "And the Priest shall looke on the sore in the skinne of his flesh: if the heare in the sore be turned into white, and the sore seeme to be lower then the skinne of his flesh, it is a plague of leprosie. therefore the Priest shall looke on him, and pronounce him vncleane:", "wycliffe": "and whanne he seeth lepre in the skyn, and the heeris chaungide in to whijte colour, and that spice of lepre lowere than the tother skyn and fleisch, it is a wounde of lepre, and he schal be departid at the `doom of the preest.", "rotherham": "and the priest shall view the spot in the skin of his flesh—if, the hair in the plague, have turned white and the appearance of the spot be deeper than the skin of his flesh, the plague-spot of leprosy, it is,—so the priest shall view him and pronounce him unclean.", "darby": "And when the priest looketh on the sore in the skin of the flesh, and the hair in the sore is turned white, and the sore looketh deeper than the skin of his flesh, it is the sore of leprosy; and the priest shall look on him and pronounce him unclean.", "twenty": "", "jps": "And the priest shall look upon the plague in the skin of the flesh; and if the hair in the plague be turned white, and the appearance of the plague be deeper than the skin of his flesh, it is the plague of leprosy; and the priest shall look on him, and pronounce him unclean.", "acv": "And the priest shall look on the disease in the skin of the flesh, and if the hair in the disease has turned white, and the appearance of the disease is deeper than the skin of his flesh, it is a leprous disease. And the priest shall look on him, and pronounce him unclean.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall look on the plague in the skin of the flesh: and [when] the hair in the plague is turned white, and the plague in sight [is] deeper than the skin of his flesh, it [is] a plague of leprosy: and the priest shall look on him, and pronounce him unclean.", "vulgate": "qui cum viderit lepram in cute et pilos in album mutatos colorem ipsamque speciem leprae humiliorem cute et carne reliqua plaga leprae est et ad arbitrium eius separabitur;", "brenton": "And the priest shall view the spot in the skin of his flesh; and if the hair in the spot be changed to white, and the appearance of the spot be below the skin of the flesh, it is a plague of leprosy; and the priest shall look upon it, and pronounce him unclean."}}, {"v": 4, "ref": "13:4", "o": "וְ/אִם בַּהֶרֶת֩ לְבָנָ֨ה הִ֜וא בְּ/ע֣וֹר בְּשָׂר֗/וֹ וְ/עָמֹק֙ אֵין מַרְאֶ֣/הָ מִן הָ/ע֔וֹר וּ/שְׂעָרָ֖/ה לֹא הָפַ֣ךְ לָבָ֑ן וְ/הִסְגִּ֧יר הַ/כֹּהֵ֛ן אֶת הַ/נֶּ֖גַע שִׁבְעַ֥ת יָמִֽים", "en": {"kjv": "If the bright spot be white in the skin of his flesh, and in sight be not deeper than the skin, and the hair thereof be not turned white; then the priest shall shut up him that hath the plague seven days:", "web": "If the bright spot is white in the skin of his body, and its appearance isn’t deeper than the skin, and its hair hasn’t turned white, then the priest shall isolate the infected person for seven days.", "bsb": "If, however, the spot on his skin is white and does not appear to be deeper than the skin, and the hair in it has not turned white, the priest shall isolate the infected person for seven days.", "asv": "And if the bright spot be white in the skin of his flesh, and the appearance thereof be not deeper than the skin, and the hair thereof be not turned white, then the priest shall shut up him that hath the plague seven days:", "ylt": "`And if the bright spot is white in the skin of his flesh, and its appearance is not deeper than the skin, and its hair hath not turned white, then hath the priest shut up him who hath the plague seven days.", "tyndale": "Yf there be but a white plecke in the skynne of his fleshe and seme not to be lower than the other skynne nor the heer thereof is turned unto white: then let the preast shitt him vpp seuen dayes.", "dra": "But if there be a shining whiteness in the skin, and not lower than the other flesh, and the hair be of the former colour, the priest shall shut him up seven days.", "bbe": "But if the mark on his skin is white, and does not seem to go deeper than the skin, and the hair on it is not turned white, then the priest will keep him shut up for seven days;", "geneva": "But if the white spot be in the skinne of his flesh, and seeme not to bee lower then the skin, nor the heare thereof be turned vnto white, then the Priest shall shut vp him that hath the plague, seuen dayes.", "wycliffe": "Sotheli if schynyng whijtnesse is in the skyn, nethir is lower than the tother fleisch, and the heeris ben of the formere colour, the preest schal close hym seuene daies;", "rotherham": "But, if the bright spot, though white in the skin of his flesh, is not deeper in appearance than the skin, and, the hair, hath not turned white, then shall the priest shut up the plagued one, seven days.", "darby": "But if the bright spot be white in the skin of his flesh, and look not deeper than the skin, and the hair thereof be not turned white, the priest shall shut up [him that hath] the sore seven days.", "twenty": "", "jps": "And if the bright spot be white in the skin of his flesh, and the appearance thereof be not deeper than the skin, and the hair thereof be not turned white, then the priest shall shut up him that hath the plague seven days.", "acv": "And if the bright spot is white in the skin of his flesh, and the appearance of it is not deeper than the skin, and the hair of it has not turned white, then the priest shall shut up the disease seven days.", "anderson": "", "haweis": "", "noyes": "", "webster": "If the bright spot [is] white in the skin of his flesh, and in sight, not deeper than the skin, and the hair of it not turned white; then the priest shall shut up [him that hath] the plague seven days:", "vulgate": "sin autem lucens candor fuerit in cute nec humilior carne reliqua et pili coloris pristini recludet eum sacerdos septem diebus;", "brenton": "But if the spot be clear and white in the skin of his flesh, yet the appearance of it be not deep below the skin, and its hair have not changed itself for white hair, but it is dark, then the priest shall separate him that has the spot seven days;"}}, {"v": 5, "ref": "13:5", "o": "וְ/רָאָ֣/הוּ הַ/כֹּהֵן֮ בַּ/יּ֣וֹם הַ/שְּׁבִיעִי֒ וְ/הִנֵּ֤ה הַ/נֶּ֨גַע֙ עָמַ֣ד בְּ/עֵינָ֔י/ו לֹֽא פָשָׂ֥ה הַ/נֶּ֖גַע בָּ/ע֑וֹר וְ/הִסְגִּיר֧/וֹ הַ/כֹּהֵ֛ן שִׁבְעַ֥ת יָמִ֖ים שֵׁנִֽית", "en": {"kjv": "And the priest shall look on him the seventh day: and, behold, if the plague in his sight be at a stay, and the plague spread not in the skin; then the priest shall shut him up seven days more:", "web": "The priest shall examine him on the seventh day, and, behold, if in his eyes the plague is arrested, and the plague hasn’t spread in the skin, then the priest shall isolate him for seven more days.", "bsb": "On the seventh day the priest is to reexamine him, and if he sees that the infection is unchanged and has not spread on the skin, the priest must isolate him for another seven days.", "asv": "and the priest shall look on him the seventh day: and, behold, if in his eyes the plague be at a stay, and the plague be not spread in the skin, then the priest shall shut him up seven days more:", "ylt": "`And the priest hath seen him on the seventh day, and lo, the plague hath stood in his eyes, the plague hath not spread in the skin, and the priest hath shut him up a second seven days.", "tyndale": "And let the preast loke apon hym the .vij. daye: yf the sore seme to him to abyde styll and to go no further in the skyne, then let the preast shutt him vppe yet .vij. dayes moo.", "dra": "And the seventh day he shall look on him: and if the leprosy be grown no farther, and hath not spread itself in the skin, he shall shut him up again other seven days.", "bbe": "And the priest is to see him on the seventh day; and if, in his opinion, the place on his skin has not become worse and is not increased in size, then the priest will keep him shut up for seven days more:", "geneva": "After, the Priest shall looke vpon him the seuenth day: and if the plague seeme to him to abide still, and the plague growe not in the skin, the Priest shall shut him vp yet seuen dayes more.", "wycliffe": "and schal biholde hym in the seuenthe dai, and sotheli if the lepre wexith not ferther, nethir passith the formere termes in the fleisch, eft the preest schal close hym ayen seuene other daies;", "rotherham": "And the priest shall view him on the seventh day, and lo! if the spot hath stayed to his sight, and the spot hath not spread in the skin, then shall the priest shut him up seven days more,", "darby": "And the priest shall look on him the seventh day; and behold, in his sight, the sore remaineth as it was, the sore hath not spread in the skin, then the priest shall shut him up seven days a second time.", "twenty": "", "jps": "And the priest shall look on him the seventh day; and, behold, if the plague stay in its appearance, and the plague be not spread in the skin, then the priest shall shut him up seven days more.", "acv": "And the priest shall look on him the seventh day, and, behold, if in his eyes the disease is arrested, and the disease is not spread in the skin, then the priest shall shut him up seven days more.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall look on him the seventh day: and behold, [if] the plague in his sight is at a stay, [and] the plague spreadeth not in the skin; then the priest shall shut him up seven days more:", "vulgate": "et considerabit die septimo et siquidem lepra ultra non creverit nec transierit in cute priores terminos rursum includet eum septem diebus aliis;", "brenton": "and the priest shall look on the spot the seventh day; and, behold, if the spot remains before him, if the spot has not spread in the skin, then the priest shall separate him the second time seven days."}}, {"v": 6, "ref": "13:6", "o": "וְ/רָאָה֩ הַ/כֹּהֵ֨ן אֹת֜/וֹ בַּ/יּ֣וֹם הַ/שְּׁבִיעִי֮ שֵׁנִית֒ וְ/הִנֵּה֙ כֵּהָ֣ה הַ/נֶּ֔גַע וְ/לֹא פָשָׂ֥ה הַ/נֶּ֖גַע בָּ/ע֑וֹר וְ/טִהֲר֤/וֹ הַ/כֹּהֵן֙ מִסְפַּ֣חַת הִ֔יא וְ/כִבֶּ֥ס בְּגָדָ֖י/ו וְ/טָהֵֽר", "en": {"kjv": "And the priest shall look on him again the seventh day: and, behold, if the plague be somewhat dark, and the plague spread not in the skin, the priest shall pronounce him clean: it is but a scab: and he shall wash his clothes, and be clean.", "web": "The priest shall examine him again on the seventh day; and behold, if the plague has faded, and the plague hasn’t spread in the skin, then the priest shall pronounce him clean. It is a scab. He shall wash his clothes, and be clean.", "bsb": "The priest will examine him again on the seventh day, and if the sore has faded and has not spread on the skin, the priest shall pronounce him clean; it is a rash. The person must wash his clothes and be clean.", "asv": "and the priest shall look on him again the seventh day; and, behold, if the plague be dim, and the plague be not spread in the skin, then the priest shall pronounce him clean: it is a scab: and he shall wash his clothes, and be clean.", "ylt": "`And the priest hath seen him on the second seventh day, and lo, the plague is become weak, and the plague hath not spread in the skin--and the priest hath pronounced him clean, it is a scab, and he hath washed his garments, and hath been clean.", "tyndale": "And let the preast loke on him agayne the .vij. daye. Then yf the sore be waxed blackesh and is not growen abrode in the skynne, let the preast make him clene, for it is but a skyrfe. And let him wasshe his clothes, and then he is clene", "dra": "And on the seventh day, he shall look on him. If the leprosy be somewhat obscure, and not spread in the skin, he shall declare him clean, because it is but a scab: and the man shall wash his clothes, and shall be clean.", "bbe": "And the priest is to see him again on the seventh day; and if the mark is less bright and is not increased on his skin, then let the priest say that he is clean: it is only a skin-mark, and after his clothing has been washed he will be clean.", "geneva": "Then the Priest shall looke on him againe the seuenth day, and if the plague be darke, and the sore grow not in the skinne, then the Priest shall pronounce him cleane, for it is a skab: therefore he shall washe his clothes and be cleane.", "wycliffe": "and schal biholde in the seuenthe day, if the lepre is derkere, and wexith not in the fleisch, the preest schal clense hym , for it is a scabbe; and the man schal waische hise clothis, and he schal be clene.", "rotherham": "Then shall the priest view him on the seventh day, a second time, and lo! if the spot is, faint, and the spot hath not spread in the skin, then shall the priest pronounce him clean—it is, a scab, and he shall wash his clothes, and be clean.", "darby": "And the priest shall look on him again the seventh day, and behold, the sore is become pale and the sore hath not spread in the skin, then the priest shall pronounce him clean; it is a scab; and he shall wash his garments and be clean.", "twenty": "", "jps": "And the priest shall look on him again the seventh day; and, behold, if the plague be dim, and the plague be not spread in the skin, then the priest shall pronounce him clean: it is a scab; and he shall wash his clothes, and be clean.", "acv": "And the priest shall look on him again the seventh day, and, behold, if the disease is dim, and the disease has not spread in the skin, then the priest shall pronounce him clean. It is a scab, and he shall wash his clothes, and be clean.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall look on him again the seventh day: and behold, [if] the plague [is] somewhat dark, [and] the plague spreadeth not in the skin, the priest shall pronounce him clean: it [is but] a scab: and he shall wash his clothes, and be clean.", "vulgate": "et die septimo contemplabitur si obscurior fuerit lepra et non creverit in cute mundabit eum quia scabies est lavabitque homo vestimenta sua et mundus erit;", "brenton": "And the priest shall look upon him the second time on the seventh day; and, behold, if the spot be dark, and the spot have not spread in the skin, then the priest shall pronounce him clean; for it is a mere mark, and the man shall wash his garments and be clean."}}, {"v": 7, "ref": "13:7", "o": "וְ/אִם פָּשֹׂ֨ה תִפְשֶׂ֤ה הַ/מִּסְפַּ֨חַת֙ בָּ/ע֔וֹר אַחֲרֵ֧י הֵרָאֹת֛/וֹ אֶל הַ/כֹּהֵ֖ן לְ/טָהֳרָת֑/וֹ וְ/נִרְאָ֥ה שֵׁנִ֖ית אֶל הַ/כֹּהֵֽן", "en": {"kjv": "But if the scab spread much abroad in the skin, after that he hath been seen of the priest for his cleansing, he shall be seen of the priest again:", "web": "But if the scab spreads on the skin, after he has shown himself to the priest for his cleansing, he shall show himself to the priest again.", "bsb": "But if the rash spreads further on his skin after he has shown himself to the priest for his cleansing, he must present himself again to the priest.", "asv": "But if the scab spread abroad in the skin, after that he hath showed himself to the priest for his cleansing, he shall show himself to the priest again:", "ylt": "`And if the scab spread greatly in the skin, after his being seen by the priest for his cleansing, then he hath been seen a second time by the priest;", "tyndale": "But and yf the scabbe growe in the skynne after that he is sene of the preast agayne.", "dra": "But, if the leprosy grow again, after he was seen by the priest and restored to cleanness, he shall be brought to him:", "bbe": "But if the size of the mark on his skin is increased after he has been seen by the priest, let him go to the priest again:", "geneva": "But if the skab growe more in the skinne, after that he is seene of ye Priest for to be purged, he shall be seene of the Priest yet againe.", "wycliffe": "That if the lepre wexith eft, aftir that he is seyn of the preest, and is yoldun to clennesse, he schal be brouyt to the preest, and schal be demed of vnclennesse.", "rotherham": "But if the scab shall have, verily spread, in the skin, since he was shown to the priest that he might be cleansed, then shall he shew himself again unto the priest;", "darby": "But if the scab have spread much in the skin, after that he hath been seen by the priest for his cleansing, he shall be seen by the priest again;", "twenty": "", "jps": "But if the scab spread abroad in the skin, after that he hath shown himself to the priest for his cleansing, he shall show himself to the priest again.", "acv": "But if the scab spreads abroad in the skin after he has shown himself to the priest for his cleansing, he shall show himself to the priest again.", "anderson": "", "haweis": "", "noyes": "", "webster": "But if the scab shall spread much in the skin, after he hath been seen by the priest for his cleansing, he shall be seen by the priest again:", "vulgate": "quod si postquam a sacerdote visus est et redditus munditiae iterum lepra creverit adducetur ad eum;", "brenton": "But if the bright spot should have changed and spread in the skin, after the priest has seen him for the purpose of purifying him, then shall he appear the second time to the priest,"}}, {"v": 8, "ref": "13:8", "o": "וְ/רָאָה֙ הַ/כֹּהֵ֔ן וְ/הִנֵּ֛ה פָּשְׂתָ֥ה הַ/מִּסְפַּ֖חַת בָּ/ע֑וֹר וְ/טִמְּא֥/וֹ הַ/כֹּהֵ֖ן צָרַ֥עַת הִֽוא", "en": {"kjv": "And if the priest see that, behold, the scab spreadeth in the skin, then the priest shall pronounce him unclean: it is a leprosy.", "web": "The priest shall examine him; and behold, if the scab has spread on the skin, then the priest shall pronounce him unclean. It is leprosy.", "bsb": "The priest will reexamine him, and if the rash has spread on the skin, the priest must pronounce him unclean; he has a skin disease.", "asv": "and the priest shall look; and, behold, if the scab be spread in the skin, then the priest shall pronounce him unclean: it is leprosy.", "ylt": "and the priest hath seen, and lo, the scab hath spread in the skin, and the priest hath pronounced him unclean; it is leprosy.", "tyndale": "Yf the preast se that the scabbe be growen abrode in the skynne, let him make him vnclene: for it is suerly a leprosye.", "dra": "And shall be condemned of uncleanness.", "bbe": "And if, after looking at him, he sees that the mark is increased in his skin, let the priest say that he is unclean; he is a leper.", "geneva": "Then the Priest shall consider, and if the skab growe in the skin, then the Priest shall pronounce him vncleane: for it is leprosie.", "wycliffe": "If the wounde of lepre is in man, he schal be brouyt to the preest, and he schal se the man;", "rotherham": "and the priest shall take a view, and lo! if the scab hath spread in the skin, then shall the priest pronounce him unclean—leprosy, it is.", "darby": "and the priest shall look on him, and behold, the scab hath spread in the skin; then the priest shall pronounce him unclean: it is leprosy.", "twenty": "", "jps": "And the priest shall look, and, behold, if the scab be spread in the skin, then the priest shall pronounce him unclean: it is leprosy.", "acv": "And the priest shall look, and, behold, if the scab is spread in the skin, then the priest shall pronounce him unclean. It is a leprous disease.", "anderson": "", "haweis": "", "noyes": "", "webster": "And [if] the priest shall see, that behold, the scab spreadeth in the skin, then the priest shall pronounce him unclean: it [is] a leprosy.", "vulgate": "et inmunditiae condemnabitur;", "brenton": "and the priest shall look upon him; and, behold, if the mark have spread in the skin, then the priest shall pronounce him unclean: it is a leprosy."}}, {"v": 9, "ref": "13:9", "o": "נֶ֣גַע צָרַ֔עַת כִּ֥י תִהְיֶ֖ה בְּ/אָדָ֑ם וְ/הוּבָ֖א אֶל הַ/כֹּהֵֽן", "en": {"kjv": "When the plague of leprosy is in a man, then he shall be brought unto the priest;", "web": "“When the plague of leprosy is in a man, then he shall be brought to the priest;", "bsb": "When anyone develops a skin disease, he must be brought to the priest.", "asv": "When the plague of leprosy is in a man, then he shall be brought unto the priest;", "ylt": "`When a plague of leprosy is in a man, then he hath been brought in unto the priest,", "tyndale": "Yf the plage of leprosye be in a man, let hi be broughte vnto the preast,", "dra": "If the stroke of the leprosy be in a man, he shall be brought to the priest:", "bbe": "When the disease of a leper is seen on a man, let him be taken to the priest;", "geneva": "When the plague of leprosie is in a man, he shalbe brought vnto the Priest,", "wycliffe": "and whanne whijt colour is in the fleisch, and chaungith the siyt of heeris , and thilke fleisch apperith quyk,", "rotherham": "When, the plague of leprosy, cometh to be in any human being, then shall he be brought in unto the priest;", "darby": "When a sore [as] of leprosy is in a man, he shall be brought unto the priest;", "twenty": "", "jps": "When the plague of leprosy is in a man, then he shall be brought unto the priest.", "acv": "When the leprous disease is in a man, then he shall be brought to the priest.", "anderson": "", "haweis": "", "noyes": "", "webster": "When the plague of leprosy is in a man, then he shall be brought to the priest:", "vulgate": "plaga leprae si fuerit in homine adducetur ad sacerdotem;", "brenton": "And if a man have a plague of leprosy, then he shall come to the priest;"}}, {"v": 10, "ref": "13:10", "o": "וְ/רָאָ֣ה הַ/כֹּהֵ֗ן וְ/הִנֵּ֤ה שְׂאֵת לְבָנָה֙ בָּ/ע֔וֹר וְ/הִ֕יא הָפְכָ֖ה שֵׂעָ֣ר לָבָ֑ן וּ/מִֽחְיַ֛ת בָּשָׂ֥ר חַ֖י בַּ/שְׂאֵֽת", "en": {"kjv": "And the priest shall see him: and, behold, if the rising be white in the skin, and it have turned the hair white, and there be quick raw flesh in the rising;", "web": "and the priest shall examine him. Behold, if there is a white rising in the skin, and it has turned the hair white, and there is raw flesh in the rising,", "bsb": "The priest will examine him, and if there is a white swelling on the skin that has turned the hair white, and there is raw flesh in the swelling,", "asv": "and the priest shall look; and, behold, if there be a white rising in the skin, and it have turned the hair white, and there be quick raw flesh in the rising,", "ylt": "and the priest hath seen, and lo, a white rising in the skin, and it hath turned the hair white, and a quickening of raw flesh is in the rising, --", "tyndale": "and let the preast se him. Yf the rysinge apeare white in the skynne ad haue also made the heer white, ad there be rawe flesh in the sore also:", "dra": "And he shall view him. And when there shall be a white colour in the skin, and it shall have changed the look of the hair, and the living flesh itself shall appear:", "bbe": "And if the priest sees that there is a white growth on the skin, and the hair is turned white, and there is diseased flesh in the growth,", "geneva": "And the Priest shall see him: and if the swelling be white in ye skin, and haue made ye heare white, and there be rawe flesh in the swelling,", "wycliffe": "it schal be demid eldest lepre, and growun to the skyn; therfor the preest schal defoule hym ,", "rotherham": "and the priest shall take a view, and lo! if there is a white rising in the skin and, the same, hath turned the hair white,—and there be a wound of raw flesh in the rising,", "darby": "and the priest shall look on him, and behold, there is a white rising in the skin, and it hath turned the hair white, and a trace of raw flesh is in the rising:", "twenty": "", "jps": "And the priest shall look, and, behold, if there be a white rising in the skin, and it have turned the hair white, and there be quick raw flesh in the rising,", "acv": "And the priest shall look, and, behold, if there is a white rising in the skin, and it has turned the hair white, and there is quick raw flesh in the rising,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall see [him]: and behold, [if] the rising [is] white in the skin, and it hath turned the hair white, and [there is] raw flesh in the rising;", "vulgate": "et videbit eum cumque color albus in cute fuerit et capillorum mutarit aspectum ipsa quoque caro viva apparuerit;", "brenton": "and the priest shall look, and, behold, if it is a white spot in the skin, and it has changed the hair to white, and there be some of the sound part of the quick flesh in the sore—"}}, {"v": 11, "ref": "13:11", "o": "צָרַ֨עַת נוֹשֶׁ֤נֶת הִוא֙ בְּ/ע֣וֹר בְּשָׂר֔/וֹ וְ/טִמְּא֖/וֹ הַ/כֹּהֵ֑ן לֹ֣א יַסְגִּרֶ֔/נּוּ כִּ֥י טָמֵ֖א הֽוּא", "en": {"kjv": "It is an old leprosy in the skin of his flesh, and the priest shall pronounce him unclean, and shall not shut him up: for he is unclean.", "web": "it is a chronic leprosy in the skin of his body, and the priest shall pronounce him unclean. He shall not isolate him, for he is already unclean.", "bsb": "it is a chronic skin disease and the priest must pronounce him unclean. He need not isolate him, for he is unclean.", "asv": "it is an old leprosy in the skin of his flesh, and the priest shall pronounce him unclean: he shall not shut him up; for he is unclean.", "ylt": "an old leprosy it is in the skin of his flesh, and the priest hath pronounced him unclean; he doth not shut him up, for he is unclean.", "tyndale": "then it is an olde leprosye in the skynne of his flesh. And the preast shall make him vnclene, ad shall not shutte him vp for he is vnclene.", "dra": "It shall be judged an inveterate leprosy, and grown into the skin. The priest therefore shall declare him unclean: and shall not shut him up, because he is evidently unclean.", "bbe": "It is an old disease in the skin of his flesh, and the priest will say that he is unclean; he will not have to be shut up, for he is clearly unclean.", "geneva": "It is an old leprosie in the skin of his flesh: and the Priest shall pronounce him vncleane, and shall not shut him vp, for he is vncleane.", "wycliffe": "and he schal not close eft, for it is of opyn vnclennesse.", "rotherham": "an old leprosy, it is in the skin of his flesh, and the priest shall pronounce him unclean,—he shall not shut him up, for unclean, he is.", "darby": "it is an old leprosy in the skin of his flesh; and the priest shall pronounce him unclean, and he shall not shut him up, for he is unclean.", "twenty": "", "jps": "it is an old leprosy in the skin of his flesh, and the priest shall pronounce him unclean; he shall not shut him up; for he is unclean.", "acv": "it is an old leprous disease in the skin of his flesh, and the priest shall pronounce him unclean. He shall not shut him up, for he is unclean.", "anderson": "", "haweis": "", "noyes": "", "webster": "It [is] an old leprosy in the skin of his flesh, and the priest shall pronounce him unclean, and shall not shut him up; for he [is] unclean.", "vulgate": "lepra vetustissima iudicabitur atque inolita cuti contaminabit itaque eum sacerdos et non recludet quia perspicue inmunditia est;", "brenton": "it is a leprosy waxing old in the skin of the flesh; and the priest shall pronounce him unclean, and shall separate him, because he is unclean."}}, {"v": 12, "ref": "13:12", "o": "וְ/אִם פָּר֨וֹחַ תִּפְרַ֤ח הַ/צָּרַ֨עַת֙ בָּ/ע֔וֹר וְ/כִסְּתָ֣ה הַ/צָּרַ֗עַת אֵ֚ת כָּל ע֣וֹר הַ/נֶּ֔גַע מֵ/רֹאשׁ֖/וֹ וְ/עַד רַגְלָ֑י/ו לְ/כָל מַרְאֵ֖ה עֵינֵ֥י הַ/כֹּהֵֽן", "en": {"kjv": "And if a leprosy break out abroad in the skin, and the leprosy cover all the skin of him that hath the plague from his head even to his foot, wheresoever the priest looketh;", "web": "“If the leprosy breaks out all over the skin, and the leprosy covers all the skin of the infected person from his head even to his feet, as far as it appears to the priest;", "bsb": "But if the skin disease breaks out all over his skin so that it covers all the skin of the infected person from head to foot, as far as the priest can see,", "asv": "And if the leprosy break out abroad in the skin, and the leprosy cover all the skin of him that hath the plague from his head even to his feet, as far as appeareth to the priest;", "ylt": "`And if the leprosy break out greatly in the skin, and the leprosy hath covered all the skin of him who hath the plague, from his head even unto his feet, to all that appeareth to the eyes of the priest,", "tyndale": "Yf a leprosye breake out in the skynne and couer all the skynne from the heed to the fote ouer all wheresoeuer the preast loketh,", "dra": "But if the leprosy spring out running about in the skin, and cover all the skin from the head to the feet, whatsoever falleth under the sight of the eyes:", "bbe": "And if the disease comes out all over his skin, from his head to his feet, as far as the priest is able to see,", "geneva": "Also if the leprosie breake out in the skin, and the leprosie couer all the skin of the plague, from his head euen to his feete, wheresoeuer the Priest looketh,", "wycliffe": "But if lepre rennynge about in the skyn `flourith out, and hilith al the fleisch, fro the heed til to the feet, what euer thing fallith vndur the siyt of iyen; the preest schal biholde hym,", "rotherham": "But, if the leprosy, cometh quite out, in the skin, and the leprosy covereth all the skin of him that, is plagued, from his head even unto his feet,—so far as appeareth to the eyes of the priest,", "darby": "But if the leprosy break out much in the skin, and the leprosy cover all the skin of [him that hath] the sore, from his head even to his foot, wherever the eyes of the priest look,", "twenty": "", "jps": "And if the leprosy break out abroad in the skin, and the leprosy cover all the skin of him that hath the plague from his head even to his feet, as far as appeareth to the priest;", "acv": "And if the leprous disease breaks out abroad in the skin, and the leprous disease covers all the skin of the disease from his head even to his feet, as far as appears to the priest,", "anderson": "", "haweis": "", "noyes": "", "webster": "And if a leprosy shall break out in the skin, and the leprosy shall cover all the skin of [him that hath] the plague from his head even to his foot, wherever the priest looketh;", "vulgate": "sin autem effloruerit discurrens lepra in cute et operuerit omnem carnem a capite usque ad pedes quicquid sub aspectu oculorum cadit;", "brenton": "And if the leprosy should have come out very evidently in the skin, and the leprosy should cover all the skin of the patient from the head to the feet, wheresoever the priest shall look;"}}, {"v": 13, "ref": "13:13", "o": "וְ/רָאָ֣ה הַ/כֹּהֵ֗ן וְ/הִנֵּ֨ה כִסְּתָ֤ה הַ/צָּרַ֨עַת֙ אֶת כָּל בְּשָׂר֔/וֹ וְ/טִהַ֖ר אֶת הַ/נָּ֑גַע כֻּלּ֛/וֹ הָפַ֥ךְ לָבָ֖ן טָה֥וֹר הֽוּא", "en": {"kjv": "Then the priest shall consider: and, behold, if the leprosy have covered all his flesh, he shall pronounce him clean that hath the plague: it is all turned white: he is clean.", "web": "then the priest shall examine him; and, behold, if the leprosy has covered all his flesh, he shall pronounce him clean of the plague. It has all turned white: he is clean.", "bsb": "the priest shall examine him, and if the disease has covered his entire body, he is to pronounce the infected person clean. Since it has all turned white, he is clean.", "asv": "then the priest shall look; and, behold, if the leprosy have covered all his flesh, he shall pronounce him clean that hath the plague: it is all turned white: he is clean.", "ylt": "then hath the priest seen, and lo, the leprosy hath covered all his flesh, and he hath pronounced him who hath the plague clean; it hath all turned white; he is clean.", "tyndale": "then let the preast loke apon him. Yf the leprosye haue couered all his flesh, let him make the disease clene: for in as moch as he is altogether white he is therfore cleane.", "dra": "The priest shall view him, and shall judge that the leprosy which he has is very clean: because it is all turned into whiteness, and therefore the man shall be clean.", "bbe": "And if the priest sees that all his flesh is covered with the leper's disease, the priest will say that he is clean: it is all turned white, he is clean.", "geneva": "Then the Priest shall consider: and if the leprosie couer all his flesh, he shall pronounce the plague to bee cleane, because it is all turned into whitenesse: so he shalbe cleane.", "wycliffe": "and schal deme `that he is holdun with clenneste lepre, for all the skyn is turned in to whijtnesse, and therfor the man schal be cleene.", "rotherham": "then shall the priest takes view and lo! if the leprosy hath covered all his flesh, then shall he pronounce clean him that was plagued,—all of it, hath turned white, clean, he is.", "darby": "and the priest looketh, and behold, the leprosy covereth all his flesh, he shall pronounce [him] clean [that hath] the sore; it is all turned white; he is clean.", "twenty": "", "jps": "then the priest shall look; and, behold, if the leprosy have covered all his flesh, he shall pronounce him clean that hath the plague; it is all turned white: he is clean.", "acv": "then the priest shall look. And, behold, if the leprous disease has covered all his flesh, he shall pronounce him clean of the disease. It is all turned white; he is clean.", "anderson": "", "haweis": "", "noyes": "", "webster": "Then the priest shall consider: and behold, [if] the leprosy hath covered all his flesh, he shall pronounce [him] clean [that hath] the plague: it is all turned white: he [is] clean.", "vulgate": "considerabit eum sacerdos et teneri lepra mundissima iudicabit eo quod omnis in candorem versa sit et idcirco homo mundus erit;", "brenton": "then the priest shall look, and, behold, the leprosy has covered all the skin of the flesh; and the priest shall pronounce him clean of the plague, because it has changed all to white, it is clean."}}, {"v": 14, "ref": "13:14", "o": "וּ/בְ/י֨וֹם הֵרָא֥וֹת בּ֛/וֹ בָּשָׂ֥ר חַ֖י יִטְמָֽא", "en": {"kjv": "But when raw flesh appeareth in him, he shall be unclean.", "web": "But whenever raw flesh appears in him, he shall be unclean.", "bsb": "But whenever raw flesh appears on someone, he will be unclean.", "asv": "But whensoever raw flesh appeareth in him, he shall be unclean.", "ylt": "`And in the day of raw flesh being seen in him he is unclean;", "tyndale": "But and yf there be rawe flesh on him when he is sene, then he shalbe vncleane.", "dra": "But when the live flesh shall appear in him:", "bbe": "But whenever diseased flesh is seen on him, he will be unclean.", "geneva": "But if there be raw flesh on him when he is seene, he shalbe vncleane.", "wycliffe": "Sotheli whanne quyk fleisch apperith in hym,", "rotherham": "But, the very day there appeareth in him raw flesh, he shall be unclean;", "darby": "And on the day when raw flesh appeareth in him, he shall be unclean.", "twenty": "", "jps": "But whensoever raw flesh appeareth in him, he shall be unclean.", "acv": "But whenever raw flesh appears in him, he shall be unclean.", "anderson": "", "haweis": "", "noyes": "", "webster": "But when raw flesh appeareth in him, he shall be unclean.", "vulgate": "quando vero caro vivens in eo apparuerit;", "brenton": "But on whatsoever day the quick flesh shall appear on him, he shall be pronounced unclean."}}, {"v": 15, "ref": "13:15", "o": "וְ/רָאָ֧ה הַ/כֹּהֵ֛ן אֶת הַ/בָּשָׂ֥ר הַ/חַ֖י וְ/טִמְּא֑/וֹ הַ/בָּשָׂ֥ר הַ/חַ֛י טָמֵ֥א ה֖וּא צָרַ֥עַת הֽוּא", "en": {"kjv": "And the priest shall see the raw flesh, and pronounce him to be unclean: for the raw flesh is unclean: it is a leprosy.", "web": "The priest shall examine the raw flesh, and pronounce him unclean: the raw flesh is unclean. It is leprosy.", "bsb": "When the priest sees the raw flesh, he must pronounce him unclean. The raw flesh is unclean; it is a skin disease.", "asv": "And the priest shall look on the raw flesh, and pronounce him unclean: the raw flesh is unclean: it is leprosy.", "ylt": "and the priest hath seen the raw flesh, and hath pronounced him unclean; the raw flesh is unclean, it is leprosy.", "tyndale": "Therfore when the preast seeth the rawe flesh, let him make him vnclene. For in as moch as his flesh is rawe, he is vnclene and it is suerly a true leprosye.", "dra": "Then by the judgment of the priest he shall be defiled, and shall be reckoned among the unclean. For live flesh, if it be spotted with leprosy, is unclean.", "bbe": "And when the priest sees the diseased flesh he will say that he is unclean; the diseased flesh is unclean, he is a leper.", "geneva": "For the Priest shall see the rawe flesh, and declare him to be vncleane: for the rawe flesh is vncleane, therefore it is the leprosie.", "wycliffe": "thanne he schal be defoulid bi the doom of the preest, and he schal be arettid among vncleene men; for quyk fleisch is vnclene, if it is spreynt with lepre.", "rotherham": "so then the priest shall view the raw flesh, and pronounce him unclean,—as for the raw flesh, unclean, it is, leprosy, it is.", "darby": "And the priest shall look on the raw flesh, and shall pronounce him unclean: the raw flesh is unclean, it is leprosy.", "twenty": "", "jps": "And the priest shall look on the raw flesh, and pronounce him unclean; the raw flesh is unclean: it is leprosy.", "acv": "And the priest shall look on the raw flesh, and pronounce him unclean. The raw flesh is unclean; it is a leprous disease.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall see the raw flesh, and pronounce him to be unclean: [for] the raw flesh [is] unclean: it [is] a leprosy.", "vulgate": "tunc sacerdotis iudicio polluetur et inter inmundos reputabitur caro enim viva si lepra aspergatur inmunda est;", "brenton": "And the priest shall look upon the sound flesh, and the sound flesh shall prove him to be unclean; for it is unclean, it is a leprosy."}}, {"v": 16, "ref": "13:16", "o": "א֣וֹ כִ֥י יָשׁ֛וּב הַ/בָּשָׂ֥ר הַ/חַ֖י וְ/נֶהְפַּ֣ךְ לְ/לָבָ֑ן וּ/בָ֖א אֶל הַ/כֹּהֵֽן", "en": {"kjv": "Or if the raw flesh turn again, and be changed unto white, he shall come unto the priest;", "web": "Or if the raw flesh turns again, and is changed to white, then he shall come to the priest;", "bsb": "But if the raw flesh changes and turns white, he must go to the priest.", "asv": "Or if the raw flesh turn again, and be changed unto white, then he shall come unto the priest;", "ylt": "Or when the raw flesh turneth back, and hath been turned to white, then he hath come in unto the priest,", "tyndale": "But and yf the rawe flesh departe agayne and chaunge vnto white, then let him come to the preast", "dra": "And if again it be turned into whiteness, and cover all the man:", "bbe": "Or if the diseased flesh is turned again and changed to white then he is to come to the priest,", "geneva": "Or if the rawe flesh change and be turned into white, then he shall come to the Priest,", "wycliffe": "That if the fleisch is turned eft in to whijtnesse, and hilith al the man,", "rotherham": "Or, if the raw flesh turn again and be changed to white, then shall he come in unto the priest;", "darby": "But if the raw flesh change again, and be turned white, he shall come unto the priest;", "twenty": "", "jps": "But if the raw flesh again be turned into white, then he shall come unto the priest;", "acv": "Or if the raw flesh turns again, and is changed to white, then he shall come to the priest.", "anderson": "", "haweis": "", "noyes": "", "webster": "Or if the raw flesh shall turn again, and be changed into white, he shall come to the priest;", "vulgate": "quod si rursum versa fuerit in alborem et totum hominem operuerit;", "brenton": "But if the sound flesh be restored and changed to white, then shall he come to the priest;"}}, {"v": 17, "ref": "13:17", "o": "וְ/רָאָ֨/הוּ֙ הַ/כֹּהֵ֔ן וְ/הִנֵּ֛ה נֶהְפַּ֥ךְ הַ/נֶּ֖גַע לְ/לָבָ֑ן וְ/טִהַ֧ר הַ/כֹּהֵ֛ן אֶת הַ/נֶּ֖גַע טָה֥וֹר הֽוּא", "en": {"kjv": "And the priest shall see him: and, behold, if the plague be turned into white; then the priest shall pronounce him clean that hath the plague: he is clean.", "web": "and the priest shall examine him; and, behold, if the plague has turned white, then the priest shall pronounce him clean of the plague. He is clean.", "bsb": "The priest will reexamine him, and if the infection has turned white, the priest is to pronounce the infected person clean; then he is clean.", "asv": "and the priest shall look on him; and, behold, if the plague be turned into white, then the priest shall pronounce him clean that hath the plague: he is clean.", "ylt": "and the priest hath seen him, and lo, the plague hath been turned to white, and the priest hath pronounced clean him who hath the plague; he is clean.", "tyndale": "and let the preast se him: Yf the sore be chaunged vnto white, let the preast make the disease cleane, ad the he is cleane.", "dra": "The priest shall view him, and shall judge him to be clean.", "bbe": "And the priest will see him: and if the place is turned white, then the priest will say that he is free from the disease.", "geneva": "And the Priest shall beholde him and if the sore be changed into white, then the Priest shall pronounce the plague cleane, for it is cleane.", "wycliffe": "the preest schal biholde hym, and schal deme, that he is cleene.", "rotherham": "and the priest shall view him, and lo! if the spot hath changed to white, then shall the priest pronounce clean him that was plagued—clean, he is.", "darby": "and the priest shall look on him, and behold, the sore is turned white; then the priest shall pronounce [him] clean [that hath] the sore: he is clean.", "twenty": "", "jps": "and the priest shall look on him; and, behold, if the plague be turned into white, then the priest shall pronounce him clean that hath the plague: he is clean.", "acv": "And the priest shall look on him, and, behold, if the disease is turned into white, then the priest shall pronounce him clean of the disease; he is clean.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall see him: and behold, [if] the plague is turned into white: then the priest shall pronounce [him] clean [that hath] the plague: he [is] clean.", "vulgate": "considerabit eum sacerdos et mundum esse decernet;", "brenton": "and the priest shall see him, and, behold, if the plague is turned white, then the priest shall pronounce the patient clean: he is clean."}}, {"v": 18, "ref": "13:18", "o": "וּ/בָשָׂ֕ר כִּֽי יִהְיֶ֥ה בֽ/וֹ בְ/עֹר֖/וֹ שְׁחִ֑ין וְ/נִרְפָּֽא", "en": {"kjv": "The flesh also, in which, even in the skin thereof, was a boil, and is healed,", "web": "“When the body has a boil on its skin, and it has healed,", "bsb": "When a boil appears on someone’s skin and it heals,", "asv": "And when the flesh hath in the skin thereof a boil, and it is healed,", "ylt": "`And when flesh hath in it, in its skin, an ulcer, and it hath been healed,", "tyndale": "When there is a byele in the skynne of any mans flesh and is helede", "dra": "When also there has been an ulcer in the flesh and the skin, and it has been healed:", "bbe": "And if a bad place has come out on the skin and is well again,", "geneva": "The flesh also in whose skin there is a bile and is healed,", "wycliffe": "Fleisch and skyn, in which a botche is bred,", "rotherham": "And, when, any one’s flesh, hath, in the skin thereof, a boil,—and then it is healed;", "darby": "And the flesh — when in the skin thereof cometh a boil, and it is healed,", "twenty": "", "jps": "And when the flesh hath in the skin thereof a boil, and it is healed,", "acv": "And when the flesh has a boil in the skin of it, and it is healed,", "anderson": "", "haweis": "", "noyes": "", "webster": "The flesh also, in which, [even] in the skin of it, was a boil, and is healed,", "vulgate": "caro et cutis in qua ulcus natum est et sanatum;", "brenton": "And if the flesh should have become an ulcer in his skin, and should be healed,"}}, {"v": 19, "ref": "13:19", "o": "וְ/הָיָ֞ה בִּ/מְק֤וֹם הַ/שְּׁחִין֙ שְׂאֵ֣ת לְבָנָ֔ה א֥וֹ בַהֶ֖רֶת לְבָנָ֣ה אֲדַמְדָּ֑מֶת וְ/נִרְאָ֖ה אֶל הַ/כֹּהֵֽן", "en": {"kjv": "And in the place of the boil there be a white rising, or a bright spot, white, and somewhat reddish, and it be shewed to the priest;", "web": "and in the place of the boil there is a white rising, or a bright spot, reddish-white, then it shall be shown to the priest;", "bsb": "and a white swelling or a reddish-white spot develops where the boil was, he must present himself to the priest.", "asv": "and in the place of the boil there is a white rising, or a bright spot, reddish-white, then it shall be showed to the priest;", "ylt": "and there hath been in the place of the ulcer a white rising, or a bright white spot, very red, then it hath been seen by the priest,", "tyndale": "and after in the place of the byele there appeare a whyte rysyng ether a shynynge white somwhat redysh, let him be sene of the preast.", "dra": "And in the place of the ulcer, there appeareth a white scar, or somewhat red, the man shall be brought to the priest.", "bbe": "And on the same place there is a white growth of a bright mark, red and white, then let the priest see it;", "geneva": "And in ye place of the bile there be a white swelling, or a white spot somewhat reddish, it shall be seene of the Priest.", "wycliffe": "and is heelid, and `a step of wounde apperith whijt, ethir `sum deel reed, `in the place of the botche, the man schal be brouyt to the preest;", "rotherham": "but in the place of the boil, is a white rising, or a bright spot, reddish white, then shall it be shown unto the priest.", "darby": "and there is in the place of the boil a white rising, or a white-reddish bright spot, it shall be shewn to the priest;", "twenty": "", "jps": "and in the place of the boil there is a white rising, or a bright spot, reddish-white, then it shall be shown to the priest.", "acv": "and in the place of the boil there is a white rising, or a bright spot, reddish-white, then it shall be shown to the priest.", "anderson": "", "haweis": "", "noyes": "", "webster": "And in the place of the boil there shall be a white rising, or a bright spot, white, and somewhat reddish, and it be showed to the priest;", "vulgate": "et in loco ulceris cicatrix apparuerit alba sive subrufa adducetur homo ad sacerdotem;", "brenton": "and there should be in the place of the ulcer a white sore, or one looking white and bright, or fiery, and it shall be seen by the priest;"}}, {"v": 20, "ref": "13:20", "o": "וְ/רָאָ֣ה הַ/כֹּהֵ֗ן וְ/הִנֵּ֤ה מַרְאֶ֨/הָ֙ שָׁפָ֣ל מִן הָ/ע֔וֹר וּ/שְׂעָרָ֖/הּ הָפַ֣ךְ לָבָ֑ן וְ/טִמְּא֧/וֹ הַ/כֹּהֵ֛ן נֶֽגַע צָרַ֥עַת הִ֖וא בַּ/שְּׁחִ֥ין פָּרָֽחָה", "en": {"kjv": "And if, when the priest seeth it, behold, it be in sight lower than the skin, and the hair thereof be turned white; the priest shall pronounce him unclean: it is a plague of leprosy broken out of the boil.", "web": "and the priest shall examine it; and behold, if its appearance is lower than the skin, and its hair has turned white, then the priest shall pronounce him unclean. It is the plague of leprosy. It has broken out in the boil.", "bsb": "The priest shall examine it, and if it appears to be beneath the skin and the hair in it has turned white, the priest shall pronounce him unclean; it is a diseased infection that has broken out in the boil.", "asv": "and the priest shall look; and, behold, if the appearance thereof be lower than the skin, and the hair thereof be turned white, then the priest shall pronounce him unclean: it is the plague of leprosy, it hath broken out in the boil.", "ylt": "and the priest hath seen, and lo, its appearance is lower than the skin, and its hair hath turned white, and the priest hath pronounced him unclean; it is a plague of leprosy--in an ulcer it hath broken out.", "tyndale": "Yf when the preast seeth hi it appeare lower than the other skynne and the heer thereof be chaunged vnto white, let the preast make hi vncleane: for it is a very leprosye, that is broken out in the place of the byele", "dra": "And when he shall see the place of the leprosy lower than the other flesh, and the hair turned white: he shall declare him unclean, for the plague of leprosy is broken out in the ulcer.", "bbe": "And after looking at it, if it seems to go deeper than the skin, and the hair on it is turned white, then the priest will say that the man is unclean: it is the leper's disease, it has come out in the bad place.", "geneva": "And when the Priest seeth it, if it appeare lower then the skinne, and the heare thereof bee changed into white, ye Priest then shall pronounce him vncleane: for it is a plague of leprosie, broken out in the bile.", "wycliffe": "and whanne the preest seeth the place of lepre lowere than the tother fleisch, and the heeris turned in to whijtnesse, the preest schal defoule hym ; for the wounde of lepre is bred in the botche.", "rotherham": "And the priest shall take a view and lo! if the appearance thereof, is lower than the skin, and, the hair thereof, hath turned white, then shall the priest pronounce him unclean—the plague-spot of leprosy, it, is, in the boil, broken out.", "darby": "and the priest shall look on it, and behold, it looketh deeper than the skin, and the hair thereof is turned white; then the priest shall pronounce him unclean: it is the sore of leprosy broken out in the boil.", "twenty": "", "jps": "And the priest shall look; and, behold, if the appearance thereof be lower than the skin, and the hair thereof be turned white, then the priest shall pronounce him unclean: it is the plague of leprosy, it hath broken out in the boil.", "acv": "And the priest shall look, and, behold, if the appearance of it is deeper than the skin, and the hair of it has turned white, then the priest shall pronounce him unclean. It is a leprous disease; it has broken out in the boil.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if, when the priest seeth it, behold, it [is] in sight lower than the skin, and the hair of it [is] turned white; the priest shall pronounce him unclean: it [is] a plague of leprosy broken out of the boil.", "vulgate": "qui cum viderit locum leprae humiliorem carne reliqua et pilos versos in candorem contaminabit eum plaga enim leprae orta est in ulcere;", "brenton": "then the priest shall look, and, behold, if the appearance be beneath the skin, and its hair has changed to white, then the priest shall pronounce him unclean; because it is a leprosy, it has broken out in the ulcer."}}, {"v": 21, "ref": "13:21", "o": "וְ/אִ֣ם יִרְאֶ֣/נָּה הַ/כֹּהֵ֗ן וְ/הִנֵּ֤ה אֵֽין בָּ/הּ֙ שֵׂעָ֣ר לָבָ֔ן וּ/שְׁפָלָ֥ה אֵינֶ֛/נָּה מִן הָ/ע֖וֹר וְ/הִ֣יא כֵהָ֑ה וְ/הִסְגִּיר֥/וֹ הַ/כֹּהֵ֖ן שִׁבְעַ֥ת יָמִֽים", "en": {"kjv": "But if the priest look on it, and, behold, there be no white hairs therein, and if it be not lower than the skin, but be somewhat dark; then the priest shall shut him up seven days:", "web": "But if the priest examines it, and behold, there are no white hairs in it, and it isn’t deeper than the skin, but is dim, then the priest shall isolate him seven days.", "bsb": "But when the priest examines it, if there is no white hair in it, and it is not beneath the skin and has faded, the priest shall isolate him for seven days.", "asv": "But if the priest look on it, and, behold, there be no white hairs therein, and it be not lower than the skin, but be dim; then the priest shall shut him up seven days:", "ylt": "`And if the priest see it, and lo, there is no white hair in it, and it is not lower than the skin, and is become weak, then hath the priest shut him up seven days;", "tyndale": "But and yf when the preast loketh on it there be no white heeres therein nether the scabbe lower than the other skynne and be somwhat blackesh, then the preast shall shutt him aparte vij. dayes.", "dra": "But if the hair be of the former colour, and the scar somewhat obscure, and be not lower than the flesh that is near it: he shall shut him up seven days.", "bbe": "But if, after looking at it, he sees that there are no white hairs on it, and it is not deeper than the skin, and it is not very bright, then let the priest keep him shut up for seven days:", "geneva": "But if the Priest looke on it, and there be no white heares therein, and if it bee not lower then the skin, but be darker, then the Priest shall shut him vp seuen dayes.", "wycliffe": "That if the heer is of the former colour, and the signe of wounde is sumdeel derk, and is not lowere than the `nyy fleisch, the preest schal close the man seuene daies;", "rotherham": "But, if the priest shall view it and lo! there is no white hair therein, and it is not deeper than the skin, and, in itself, is faint, then shall the priest shut him up seven days;", "darby": "But if the priest look on it, and behold, there are no white hairs therein, and it is not deeper than the skin, and is pale, the priest shall shut him up seven days;", "twenty": "", "jps": "But if the priest look on it, and, behold, there be no white hairs therein, and it be not lower than the skin, but be dim, then the priest shall shut him up seven days.", "acv": "But if the priest looks on it, and, behold, there are no white hairs in it, and it is not deeper than the skin, but is dim, then the priest shall shut him up seven days.", "anderson": "", "haweis": "", "noyes": "", "webster": "But if the priest shall look on it, and behold, [there are] no white hairs in it, and [if] it [is] not lower than the skin, but somewhat dark; then the priest shall shut him up seven days:", "vulgate": "quod si pilus coloris est pristini et cicatrix subobscura et vicina carne non est humilior recludet eum septem diebus;", "brenton": "But if the priest look, and behold there is no white hair on it, and it be not below the skin of the flesh, and it be dark-coloured; then the priest shall separate him seven days."}}, {"v": 22, "ref": "13:22", "o": "וְ/אִם פָּשֹׂ֥ה תִפְשֶׂ֖ה בָּ/ע֑וֹר וְ/טִמֵּ֧א הַ/כֹּהֵ֛ן אֹת֖/וֹ נֶ֥גַע הִֽוא", "en": {"kjv": "And if it spread much abroad in the skin, then the priest shall pronounce him unclean: it is a plague.", "web": "If it spreads in the skin, then the priest shall pronounce him unclean. It is a plague.", "bsb": "If it spreads any further on the skin, the priest must pronounce him unclean; it is an infection.", "asv": "and if it spread abroad in the skin, then the priest shall pronounce him unclean: it is a plague.", "ylt": "and if it spread greatly in the skin, then hath the priest pronounced him unclean, it is a plague;", "tyndale": "Yf it sprede abrode in the meane season, then let the preast make him vnclene: for it is a leprosye.", "dra": "And if it spread, he shall judge him to have the leprosy:", "bbe": "And if it is increasing on the skin, the priest will say that he is unclean: it is a disease.", "geneva": "And if it spred abroad in the flesh, ye Priest shall pronounce him vncleane, for it is a sore.", "wycliffe": "and sotheli, if it wexith, the preest schal deme the man of lepre;", "rotherham": "and, if it, clearly spreadeth, in the skin, then shall the priest pronounce him unclean—a plague-spot, it is.", "darby": "and if it spread much in the skin, then the priest shall pronounce him unclean: it is the sore.", "twenty": "", "jps": "And if it spread abroad in the skin, then the priest shall pronounce him unclean: it is a plague.", "acv": "And if it spreads abroad in the skin, then the priest shall pronounce him unclean; it is a disease.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if it hath spread much in the skin, then the priest shall pronounce him unclean: it [is] a plague.", "vulgate": "et siquidem creverit adiudicabit eum leprae;", "brenton": "But if it manifestly spread over the skin, then the priest shall pronounce him unclean: it is a plague of leprosy; it has broken out in the ulcer."}}, {"v": 23, "ref": "13:23", "o": "וְ/אִם תַּחְתֶּ֜י/הָ תַּעֲמֹ֤ד הַ/בַּהֶ֨רֶת֙ לֹ֣א פָשָׂ֔תָה צָרֶ֥בֶת הַ/שְּׁחִ֖ין הִ֑וא וְ/טִהֲר֖/וֹ הַ/כֹּהֵֽן", "en": {"kjv": "But if the bright spot stay in his place, and spread not, it is a burning boil; and the priest shall pronounce him clean.", "web": "But if the bright spot stays in its place, and hasn’t spread, it is the scar from the boil; and the priest shall pronounce him clean.", "bsb": "But if the spot remains unchanged and does not spread, it is only the scar from the boil, and the priest shall pronounce him clean.", "asv": "But if the bright spot stay in its place, and be not spread, it is the scar of the boil; and the priest shall pronounce him clean.", "ylt": "and if in its place the bright spot stay--it hath not spread--it is an inflammation of the ulcer; and the priest hath pronounced him clean.", "tyndale": "But ad yf the glistringe white abyde styll in one place and go no further, then it is but the prynte of the byele, and the preast shal make him cleane.", "dra": "But if it stay in its place, it is but the scar of an ulcer: and the man shall be clean.", "bbe": "But if the bright mark keeps in the same place and gets no greater, it is the mark of the old wound, and the priest will say that he is clean.", "geneva": "But if the spot continue in his place, and growe not, it is a burning bile: therefore the Priest shall declare him to be cleane.", "wycliffe": "forsothe if it stondith in his place, it is a signe of botche, and the man schal be cleene.", "rotherham": "But if in its place the bright spot stayeth hath not spread, a boil, it is,—and the priest shall pronounce him clean.", "darby": "But if the bright spot have remained in its place, [and] have not spread, it is the scar of the boil; and the priest shall pronounce him clean.", "twenty": "", "jps": "But if the bright spot stay in its place, and be not spread, it is the scar of the boil; and the priest shall pronounce him clean.", "acv": "But if the bright spot stays in its place, and has not spread, it is the scar of the boil, and the priest shall pronounce him clean.", "anderson": "", "haweis": "", "noyes": "", "webster": "But if the bright spot shall stay in its place, [and] not spread, it [is] a burning boil; and the priest shall pronounce him clean.", "vulgate": "sin autem steterit in loco suo ulceris est cicatrix et homo mundus erit;", "brenton": "But if the bright spot should remain in its place and not spread, it is the scar of the ulcer; and the priest shall pronounce him clean."}}, {"v": 24, "ref": "13:24", "o": "א֣וֹ בָשָׂ֔ר כִּֽי יִהְיֶ֥ה בְ/עֹר֖/וֹ מִכְוַת אֵ֑שׁ וְֽ/הָיְתָ֞ה מִֽחְיַ֣ת הַ/מִּכְוָ֗ה בַּהֶ֛רֶת לְבָנָ֥ה אֲדַמְדֶּ֖מֶת א֥וֹ לְבָנָֽה", "en": {"kjv": "Or if there be any flesh, in the skin whereof there is a hot burning, and the quick flesh that burneth have a white bright spot, somewhat reddish, or white;", "web": "“Or when the body has a burn from fire on its skin, and the raw flesh of the burn becomes a bright spot, reddish-white, or white,", "bsb": "When there is a burn on someone’s skin and the raw area of the burn becomes reddish-white or white,", "asv": "Or when the flesh hath in the skin thereof a burning by fire, and the quick flesh of the burning become a bright spot, reddish-white, or white;", "ylt": "`Or when flesh hath in its skin a fiery burning, and the quickening of the burning, the bright white spot, hath been very red or white,", "tyndale": "When the skynne of any mas flesh is burnt with fire that it be rawe and there apere in the burnynge a glistringe white that is somwhat redysh or altogether white,", "dra": "The flesh also and skin that hath been burnt, and after it is healed hath a white or a red scar:", "bbe": "Or if there is a burn on the skin of the flesh, and if the diseased flesh in the burn becomes a bright place, red and white or white,", "geneva": "If there be any flesh, in whose skin there is an hote burning, and the quick flesh of ye burning haue a white spot, somewhat reddish or pale,", "wycliffe": "Fleisch and skyn, which the fier hath brent, and is heelid, and hath a whijt ethir reed `signe of wounde,", "rotherham": "Or, when, any one’s flesh, hath in the skin thereof a fiery burning,—and the burning wound becometh a bright spot reddish white, or white,", "darby": "Or if in the flesh, in the skin thereof, there is a burning inflammation, and the place of the inflammation become a bright spot white-reddish or white,", "twenty": "", "jps": "Or when the flesh hath in the skin thereof a burning by fire, and the quick flesh of the burning become a bright spot, reddish-white, or white;", "acv": "Or when the flesh has a burning by fire in the skin of it, and the quick of the burning become a bright spot, reddish-white, or white,", "anderson": "", "haweis": "", "noyes": "", "webster": "Or if there [is any] flesh, in the skin of which [there is] a hot burning, and the live [flesh] that burneth hath a white bright spot, somewhat reddish or white;", "vulgate": "caro et cutis quam ignis exuserit et sanata albam sive rufam habuerit cicatricem;", "brenton": "And if the flesh be in his skin in a state of fiery inflammation, and there should be in his skin the part which is healed of the inflammation, bright, clear, and white, suffused with red or very white;"}}, {"v": 25, "ref": "13:25", "o": "וְ/רָאָ֣ה אֹתָ֣/הּ הַ/כֹּהֵ֡ן וְ/הִנֵּ֣ה נֶהְפַּךְ֩ שֵׂעָ֨ר לָבָ֜ן בַּ/בַּהֶ֗רֶת וּ/מַרְאֶ֨/הָ֙ עָמֹ֣ק מִן הָ/ע֔וֹר צָרַ֣עַת הִ֔וא בַּ/מִּכְוָ֖ה פָּרָ֑חָה וְ/טִמֵּ֤א אֹת/וֹ֙ הַ/כֹּהֵ֔ן נֶ֥גַע צָרַ֖עַת הִֽוא", "en": {"kjv": "Then the priest shall look upon it: and, behold, if the hair in the bright spot be turned white, and it be in sight deeper than the skin; it is a leprosy broken out of the burning: wherefore the priest shall pronounce him unclean: it is the plague of leprosy.", "web": "then the priest shall examine it; and behold, if the hair in the bright spot has turned white, and its appearance is deeper than the skin; it is leprosy. It has broken out in the burning, and the priest shall pronounce him unclean. It is the plague of leprosy.", "bsb": "the priest must examine it. If the hair in the spot has turned white and the spot appears to be deeper than the skin, it is a disease that has broken out in the burn. The priest must pronounce him unclean; it is a diseased infection.", "asv": "then the priest shall look upon it; and, behold, if the hair in the bright spot be turned white, and the appearance thereof be deeper than the skin; it is leprosy, it hath broken out in the burning: and the priest shall pronounce him unclean: it is the plague of leprosy.", "ylt": "and the priest hath seen it, and lo, the hair hath turned white in the bright spot, and its appearance is deeper than the skin; leprosy it is , in the burning it hath broken out, and the priest hath pronounced him unclean; it is a plague of leprosy.", "tyndale": "let the preast loke apon it. Yf the heer in that brightnesse be chaunged to white and it also appeare lower than the other skynne, than it is a leprosye that is broken out in the place of the burnynge. And the preast shall make him vncleane, for it is a leprosye.", "dra": "The priest shall view it, and if he see it turned white, and the place thereof is lower than the other skin: he shall declare him unclean, because the evil of leprosy is broken out in the scar.", "bbe": "The priest is to see it: and if the hair on the bright place is turned white and it seems to go deeper than the skin, he is a leper: it has come out in the burn, and the priest will say that he is unclean: it is the leper's disease.", "geneva": "Then the Priest shall looke vpon it: and if the heare in that spot be changed into white, and it appeare lower then the skin, it is a leprosie broken out in the burning therefore the Priest shall pronounce him vncleane: for it is the plague of leprosie.", "wycliffe": "the preest schal biholde it, and lo! if it is turned in to whijtnesse, and the place therof is lowere than the tothir skyn, the preest schal defoule the man, for a wounde of lepre is bred in the `signe of wounde.", "rotherham": "then shall the priest view it—and lo! if the hair is turned white in the bright spot and the appearance thereof is deeper than the skin, leprosy, it is, broken out, in the burning,—so the priest shall pronounce him unclean, the plague-spot of leprosy, it is.", "darby": "and the priest look on it, and behold, the hair is turned white in the bright spot, and it looketh deeper than the skin, it is a leprosy which is broken out in the inflammation; and the priest shall pronounce him unclean: it is the sore of leprosy.", "twenty": "", "jps": "then the priest shall look upon it; and, behold, if the hair in the bright spot be turned white, and the appearance thereof be deeper than the skin, it is leprosy, it hath broken out in the burning; and the priest shall pronounce him unclean: it is the plague of leprosy.", "acv": "then the priest shall look upon it. And, behold, if the hair in the bright spot has turned white, and the appearance of it is deeper than the skin, it is a leprous disease. It has broken out in the burning, and the priest shall pronounce him unclean; it is a leprous disease.", "anderson": "", "haweis": "", "noyes": "", "webster": "Then the priest shall look upon it: and behold, [if] the hair in the bright spot [is] turned white, and it [is in] sight deeper than the skin: it [is] a leprosy broken out of the burning: wherefore the priest shall pronounce him unclean: it [is] the plague of leprosy.", "vulgate": "considerabit eam sacerdos et ecce versa est in alborem et locus eius reliqua cute humilior contaminabit eum quia plaga leprae in cicatrice orta est;", "brenton": "then the priest shall look upon him, and, behold, if the hair being white is changed to a bright colour, and its appearance is lower than the skin, it is a leprosy; it has broken out in the inflammation, and the priest shall pronounce him unclean: it is a plague of leprosy."}}, {"v": 26, "ref": "13:26", "o": "וְ/אִ֣ם יִרְאֶ֣/נָּה הַ/כֹּהֵ֗ן וְ/הִנֵּ֤ה אֵֽין בַּ/בֶּהֶ֨רֶת֙ שֵׂעָ֣ר לָבָ֔ן וּ/שְׁפָלָ֥ה אֵינֶ֛/נָּה מִן הָ/ע֖וֹר וְ/הִ֣וא כֵהָ֑ה וְ/הִסְגִּיר֥/וֹ הַ/כֹּהֵ֖ן שִׁבְעַ֥ת יָמִֽים", "en": {"kjv": "But if the priest look on it, and, behold, there be no white hair in the bright spot, and it be no lower than the other skin, but be somewhat dark; then the priest shall shut him up seven days:", "web": "But if the priest examines it, and behold, there is no white hair in the bright spot, and it isn’t lower than the skin, but is faded; then the priest shall isolate him seven days.", "bsb": "But if the priest examines it and there is no white hair in the spot, and it is not beneath the skin but has faded, the priest shall isolate him for seven days.", "asv": "But if the priest look on it, and, behold, there be no white hair in the bright spot, and it be no lower than the skin, but be dim; then the priest shall shut him up seven days:", "ylt": "`And if the priest see it, and lo, there is no white hair on the bright spot, and it is not lower than the skin, and it is become weak, then the priest hath shut him up seven days;", "tyndale": "But and yf (when the preast loketh on it) he se that there is no white heer in the bryghtenesse and that it is no lower than the other skynne and that it is also blackesh, then let the preast shutt him upp seuen dayes.", "dra": "But if the colour of the hair be not changed, nor the blemish lower than the other flesh, and the appearance of the leprosy be somewhat obscure: he shall shut him up seven days,", "bbe": "But if, after looking at it, the priest sees that there is no white hair on the bright place, and it is not deeper than the skin, and is not very bright, then let the priest keep him shut up for seven days:", "geneva": "But if the Priest looke on it, and there be no white heare in the spot, and be no lower then the other skinne, but be darker, then the Priest shall shut him vp seuen dayes.", "wycliffe": "That if the colour of heeris is not chaungid, nether the wounde is lowere than the tother fleisch, and thilke spice of lepre is sumdeel derk, the preest schal close the man bi seuene daies;", "rotherham": "But, if the priest shall view it and lo! there is not, in the bright spot white hair, and it is not deeper than the skin but, itself, is faint, then shall the priest shut him up seven days;", "darby": "But if the priest look on it, and behold, there is no white hair in the bright spot, and it is no deeper than the skin, and is pale, the priest shall shut him up seven days.", "twenty": "", "jps": "But if the priest look on it, and, behold, there be no white hair in the bright spot, and it be no lower than the skin, but be dim; then the priest shall shut him up seven days.", "acv": "But if the priest looks on it, and, behold, there is no white hair in the bright spot, and it is no deeper than the skin, but is dim, then the priest shall shut him up seven days.", "anderson": "", "haweis": "", "noyes": "", "webster": "But if the priest shall look on it, and behold, [there is] no white hair in the bright spot, and it [is] no lower than the [other] skin, but [is] somewhat dark; then the priest shall shut him up seven days:", "vulgate": "quod si pilorum color non fuerit inmutatus nec humilior plaga carne reliqua et ipsa leprae species fuerit subobscura recludet eum septem diebus;", "brenton": "But if the priest should look, and, behold, there is not in the bright spot any white hair, and it should not be lower than the skin, and it should be dark, then the priest shall separate him seven days."}}, {"v": 27, "ref": "13:27", "o": "וְ/רָאָ֥/הוּ הַ/כֹּהֵ֖ן בַּ/יּ֣וֹם הַ/שְּׁבִיעִ֑י אִם פָּשֹׂ֤ה תִפְשֶׂה֙ בָּ/ע֔וֹר וְ/טִמֵּ֤א הַ/כֹּהֵן֙ אֹת֔/וֹ נֶ֥גַע צָרַ֖עַת הִֽוא", "en": {"kjv": "And the priest shall look upon him the seventh day: and if it be spread much abroad in the skin, then the priest shall pronounce him unclean: it is the plague of leprosy.", "web": "The priest shall examine him on the seventh day. If it has spread in the skin, then the priest shall pronounce him unclean. It is the plague of leprosy.", "bsb": "On the seventh day the priest is to reexamine him, and if it has spread further on the skin, the priest must pronounce him unclean; it is a diseased infection.", "asv": "and the priest shall look upon him the seventh day: if it spread abroad in the skin, then the priest shall pronounce him unclean: it is the plague of leprosy.", "ylt": "and the priest hath seen him on the seventh day, if it spread greatly in the skin, then the priest hath pronounced him unclean; a plague of leprosy it is .", "tyndale": "And yf (when the preast loketh on him the seuenth daye) it be growen abrode in the skynne, lett him make him vncleane: for it is a leprosye.", "dra": "And on the seventh day he shall view him. If the leprosy be grown farther in the skin, he shall declare him unclean.", "bbe": "And the priest is to see him again on the seventh day; if it is increased in the skin, then the priest will say that he is unclean: it is the leper's disease.", "geneva": "After, the Priest shall looke on him the seuenth day: if it be growen abroad in the skinne, then the Priest shall pronounce him vncleane: for it is the plague of leprosie.", "wycliffe": "and in the seuenthe dai he schal biholde; if the lepre wexith in the fleisch, the preest schal defoule the man;", "rotherham": "and the priest shall view him on the seventh day,—if it, hath plainly spread in the skin, then shall the priest pronounce him unclean, the plague-spot of leprosy, it is.", "darby": "And the priest shall look on him the seventh day, and if it have spread much in the skin, the priest shall pronounce him unclean: it is the sore of leprosy.", "twenty": "", "jps": "And the priest shall look upon him the seventh day; if it spread abroad in the skin, then the priest shall pronounce him unclean: it is the plague of leprosy.", "acv": "And the priest shall look upon him the seventh day. If it spread abroad in the skin, then the priest shall pronounce him unclean; it is a leprous disease.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall look upon him the seventh day: [and] if it [is] spread much in the skin, then the priest shall pronounce him unclean: it [is] the plague of leprosy,", "vulgate": "et die septimo contemplabitur si creverit in cute lepra contaminabit eum;", "brenton": "And the priest shall look upon him on the seventh day; and if the spot be much spread in the skin, then the priest shall pronounce him unclean: it is a plague of leprosy, it has broken out in the ulcer."}}, {"v": 28, "ref": "13:28", "o": "וְ/אִם תַּחְתֶּי/הָ֩ תַעֲמֹ֨ד הַ/בַּהֶ֜רֶת לֹא פָשְׂתָ֤ה בָ/עוֹר֙ וְ/הִ֣וא כֵהָ֔ה שְׂאֵ֥ת הַ/מִּכְוָ֖ה הִ֑וא וְ/טִֽהֲר/וֹ֙ הַ/כֹּהֵ֔ן כִּֽי צָרֶ֥בֶת הַ/מִּכְוָ֖ה הִֽוא", "en": {"kjv": "And if the bright spot stay in his place, and spread not in the skin, but it be somewhat dark; it is a rising of the burning, and the priest shall pronounce him clean: for it is an inflammation of the burning.", "web": "If the bright spot stays in its place, and hasn’t spread in the skin, but is faded, it is the swelling from the burn, and the priest shall pronounce him clean; for it is the scar from the burn.", "bsb": "But if the spot is unchanged and has not spread on the skin but has faded, it is a swelling from the burn, and the priest is to pronounce him clean; for it is only the scar from the burn.", "asv": "And if the bright spot stay in its place, and be not spread in the skin, but be dim; it is the rising of the burning, and the priest shall pronounce him clean: for it is the scar of the burning.", "ylt": "`And if the bright spot stay in its place, it hath not spread in the skin, and is become weak; a rising of the burning it is , and the priest hath pronounced him clean; for it is inflammation of the burning.", "tyndale": "But and yf that bryghtnesse abyde styll in one place and goo no further in the skynne ad be blackesh, than it is but a rysyng in the place of the burnynge, and the preast shall make hym cleane: for it is but the prynte of the burnynge only.", "dra": "But if the whiteness stay in its place, and be not very clear, it is the sore of a burning: and therefore he shall be cleansed, because it is only the scar of a burning.", "bbe": "And if the bright place keeps the same size and gets no greater on the skin, but is less bright, it is the effect of the burn, and the priest will say that he is clean: it is the mark of the burn.", "geneva": "And if the spot abide in his place, not growing in the skin, but is darke, it is a rising of the burning: the Priest shall therefore declare him cleane, for it is the drying vp of the burning.", "wycliffe": "ellis if the whijtnesse stondith in his place, and is not cleer ynow, it is a wounde of brennyng, and therfor the man schal be clensid, for it is a signe of brennyng.", "rotherham": "But, if, in its place the bright spot hath stayed, and hath not spread in the skin, but, itself, is faint, the rising of a burning, it is,—and the priest shall pronounce him clean, for only the inflaming of the burning, it is.", "darby": "But if the bright spot have remained in its place, [and] not spread in the skin, and is pale, it is the rising of the inflammation; and the priest shall pronounce him clean; for it is the scar of the inflammation.", "twenty": "", "jps": "And if the bright spot stay in its place, and be not spread in the skin, but be dim, it is the rising of the burning, and the priest shall pronounce him clean; for it is the scar of the burning.", "acv": "And if the bright spot stays in its place, and has not spread in the skin, but is dim, it is the rising of the burning, and the priest shall pronounce him clean, for it is the scar of the burning.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if the bright spot shall stay in its place, [and] not spread in the skin, but [be] somewhat dark; it [is] a rising of the burning, and the priest shall pronounce him clean: for it [is] an inflammation of the burning.", "vulgate": "sin autem in loco suo candor steterit non satis clarus plaga conbustionis est et idcirco mundabitur quia cicatrix est conbusturae;", "brenton": "But if the bright spot remain stationary, and be not spread in the skin, but the sore should be dark, it is a scar of inflammation; and the priest shall pronounce him clean, for it is the mark of the inflammation."}}, {"v": 29, "ref": "13:29", "o": "וְ/אִישׁ֙ א֣וֹ אִשָּׁ֔ה כִּֽי יִהְיֶ֥ה ב֖/וֹ נָ֑גַע בְּ/רֹ֖אשׁ א֥וֹ בְ/זָקָֽן", "en": {"kjv": "If a man or woman have a plague upon the head or the beard;", "web": "“When a man or woman has a plague on the head or on the beard,", "bsb": "If a man or woman has an infection on the head or chin,", "asv": "And when a man or woman hath a plague upon the head or upon the beard,", "ylt": "`And when a man (or a woman) hath in him a plague in the head or in the beard,", "tyndale": "Whe ether man or woman hath a breakinge out apon the heed or the beerde, let the preast se it.", "dra": "If the leprosy break out in the head or the beard of a man or woman, the priest shall see them,", "bbe": "And when a man or a woman has a disease on the head, or in the hair of the chin,", "geneva": "If also a man or woman hath a sore on the head or in the beard,", "wycliffe": "A man ethir womman, in whos heed ether beerd lepre buriounneth, the preest schal se hem;", "rotherham": "And, when there cometh to be in, any man or woman, a spot,—in the head or in the beard,", "darby": "And if a man or a woman have a sore on the head or on the beard,", "twenty": "", "jps": "And when a man or woman hath a plague upon the head or upon the beard,", "acv": "And when a man or woman has a disease upon the head or upon the beard,", "anderson": "", "haweis": "", "noyes": "", "webster": "If a man or woman shall have a plague upon the head or the beard;", "vulgate": "vir sive mulier in cuius capite vel barba germinarit lepra videbit eos sacerdos;", "brenton": "And if a man or a woman have in them a plague of leprosy in the head or the beard;"}}, {"v": 30, "ref": "13:30", "o": "וְ/רָאָ֨ה הַ/כֹּהֵ֜ן אֶת הַ/נֶּ֗גַע וְ/הִנֵּ֤ה מַרְאֵ֨/הוּ֙ עָמֹ֣ק מִן הָ/ע֔וֹר וּ/ב֛/וֹ שֵׂעָ֥ר צָהֹ֖ב דָּ֑ק וְ/טִמֵּ֨א אֹת֤/וֹ הַ/כֹּהֵן֙ נֶ֣תֶק ה֔וּא צָרַ֧עַת הָ/רֹ֛אשׁ א֥וֹ הַ/זָּקָ֖ן הֽוּא", "en": {"kjv": "Then the priest shall see the plague: and, behold, if it be in sight deeper than the skin; and there be in it a yellow thin hair; then the priest shall pronounce him unclean: it is a dry scall, even a leprosy upon the head or beard.", "web": "then the priest shall examine the plague; and behold, if its appearance is deeper than the skin, and the hair in it is yellow and thin, then the priest shall pronounce him unclean: it is an itch, it is leprosy of the head or of the beard.", "bsb": "the priest shall examine the infection, and if it appears to be deeper than the skin and the hair in it is yellow and thin, the priest must pronounce him unclean; it is a scaly outbreak, an infectious disease of the head or chin.", "asv": "then the priest shall look on the plague; and, behold, if the appearance thereof be deeper than the skin, and there be in it yellow thin hair, then the priest shall pronounce him unclean: it is a scall, it is leprosy of the head or of the beard.", "ylt": "then hath the priest seen the plague, and lo, its appearance is deeper than the skin, and in it a thin shining hair, and the priest hath pronounced him unclean; it is a scall--it is a leprosy of the head or of the beard.", "tyndale": "And yf it apeare lower than the other skynne and there be therein golden heeres ad thyn, let the preast make him vncleane, for it is a breaking out of leprosye apo the heed or berde.", "dra": "And if the place be lower than the other flesh, and the hair yellow, and thinner than usual: he shall declare them unclean, because it is the leprosy of the head and the beard;", "bbe": "Then the priest is to see the diseased place: and if it seems to go deeper than the skin, and if there is thin yellow hair in it, then the priest will say that he is unclean: he has the mark of the leper's disease on his head or in the hair of his chin.", "geneva": "Then the Priest shall see his sore: and if it appeare lower then the skin, and there be in it a small yellow haire, then the Priest shall pronouce him vncleane: for it is a blacke spot, and leprosie of the head or of the beard.", "wycliffe": "and if the place is lowere than the tothir fleisch, and the heer is whijt, `and is sotilere, `ether smallere, than it is wont, the preest schal defoule hem, for it is lepre of the heed, and of the beerd.", "rotherham": "then shall the priest view the spot and lo! if, the appearance thereof, is deeper than the skin, and, therein, is yellow, thin hair, then shall the priest pronounce him unclean a scall, it is, a leprosy of the head or of the beard, it is.", "darby": "and the priest look on the sore, and behold, it looketh deeper than the skin, and there is in it yellow thin hair, then the priest shall pronounce him unclean; it is a scall, the leprosy of the head or the beard.", "twenty": "", "jps": "then the priest shall look on the plague; and, behold, if the appearance thereof be deeper than the skin, and there be in it yellow thin hair, then the priest shall pronounce him unclean: it is a scall, it is leprosy of the head or of the beard.", "acv": "then the priest shall look on the disease. And, behold, if the appearance of it is deeper than the skin, and there is yellow thin hair in it, then the priest shall pronounce him unclean; it is a scall. It is a leprous disease of the head or of the beard.", "anderson": "", "haweis": "", "noyes": "", "webster": "Then the priest shall see the plague: and behold, if it [is] in sight deeper than the skin, [and there is] in it a yellow thin hair; then the priest shall pronounce him unclean: it [is] a dry scall, [even] a leprosy upon the head or beard.", "vulgate": "et siquidem humilior fuerit locus carne reliqua et capillus flavus solitoque subtilior contaminabit eos quia lepra capitis ac barbae est;", "brenton": "then the priest shall look on the plague, and, behold, if the appearance of it be beneath the skin, and in it there be thin yellowish hair, then the priest shall pronounce him unclean: it is a scurf, it is a leprosy of the head or a leprosy of the beard."}}, {"v": 31, "ref": "13:31", "o": "וְ/כִֽי יִרְאֶ֨ה הַ/כֹּהֵ֜ן אֶת נֶ֣גַע הַ/נֶּ֗תֶק וְ/הִנֵּ֤ה אֵין מַרְאֵ֨/הוּ֙ עָמֹ֣ק מִן הָ/ע֔וֹר וְ/שֵׂעָ֥ר שָׁחֹ֖ר אֵ֣ין בּ֑/וֹ וְ/הִסְגִּ֧יר הַ/כֹּהֵ֛ן אֶת נֶ֥גַע הַ/נֶּ֖תֶק שִׁבְעַ֥ת יָמִֽים", "en": {"kjv": "And if the priest look on the plague of the scall, and, behold, it be not in sight deeper than the skin, and that there is no black hair in it; then the priest shall shut up him that hath the plague of the scall seven days:", "web": "If the priest examines the plague of itching, and behold, its appearance isn’t deeper than the skin, and there is no black hair in it, then the priest shall isolate the person infected with itching seven days.", "bsb": "But if the priest examines the scaly infection and it does not appear to be deeper than the skin, and there is no black hair in it, the priest shall isolate the infected person for seven days.", "asv": "And if the priest look on the plague of the scall, and, behold, the appearance thereof be not deeper than the skin, and there be no black hair in it, then the priest shall shut up him that hath the plague of the scall seven days:", "ylt": "`And when the priest seeth the plague of the scall, and lo, its appearance is not deeper than the skin, and there is no black hair in it, then hath the priest shut up him who hath the plague of the scall seven days.", "tyndale": "yf (whe the preast loketh on the breakige out) he se that it is no lower tha the other skynne ad that there are blacke heeres therein let hi shutt hi vp .vij. dayes.", "dra": "But if he perceive the place of the spot is equal with the flesh that is near it, and the hair black: he shall shut him up seven days,", "bbe": "And after looking at the diseased place, if it does not seem to go deeper than the skin, and there is no black hair in it, then the priest will have him shut up for seven days:", "geneva": "And if the Priest looke on the sore of the blacke spotte, and if it seeme not lower then the skinne, nor haue any blacke heare in it, then the Priest shall shut vp him, that hath the sore of the blacke spot, seuen dayes.", "wycliffe": "Ellis if he seeth the place of wem euene with the nyy fleisch, and seeth the here blak, the preest schal close hem bi seuene daies, and schal se in the seuenthe dai;", "rotherham": "But when the priest vieweth the spot, and lo! there is, no appearance, of it deeper than the skin, and, no dark hair, is therein, then shall the priest shut up him that hath the plague-spot of scall, seven days;", "darby": "And if the priest look on the sore of the scall, and behold, it is not in sight deeper than the skin, and there is no black hair in it, the priest shall shut up [him that hath] the sore of the scall seven days.", "twenty": "", "jps": "And if the priest look on the plague of the scall, and, behold, the appearance thereof be not deeper than the skin, and there be no black hair in it, then the priest shall shut up him that hath the plague of the scall seven days.", "acv": "And if the priest looks on the disease of the scall, and, behold, the appearance of it is not deeper than the skin, and there is no black hair in it, then the priest shall shut up the disease of the scall seven days.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if the priest shall look on the plague of the scall, and behold, it [is] not in sight deeper than the skin, and no black hair in it; then the priest shall shut up [him that hath] the plague of the scall seven days:", "vulgate": "sin autem viderit et locum maculae aequalem vicinae carni et capillum nigrum recludet eos septem diebus;", "brenton": "And if the priest should see the plague of the scurf, and, behold, the appearance of it be not beneath the skin, and there is no yellowish hair in it, then the priest shall set apart him that has the plague of the scurf seven days."}}, {"v": 32, "ref": "13:32", "o": "וְ/רָאָ֨ה הַ/כֹּהֵ֣ן אֶת הַ/נֶּגַע֮ בַּ/יּ֣וֹם הַ/שְּׁבִיעִי֒ וְ/הִנֵּה֙ לֹא פָשָׂ֣ה הַ/נֶּ֔תֶק וְ/לֹא הָ֥יָה ב֖/וֹ שֵׂעָ֣ר צָהֹ֑ב וּ/מַרְאֵ֣ה הַ/נֶּ֔תֶק אֵ֥ין עָמֹ֖ק מִן הָ/עֽוֹר", "en": {"kjv": "And in the seventh day the priest shall look on the plague: and, behold, if the scall spread not, and there be in it no yellow hair, and the scall be not in sight deeper than the skin;", "web": "On the seventh day the priest shall examine the plague; and behold, if the itch hasn’t spread, and there is no yellow hair in it, and the appearance of the itch isn’t deeper than the skin,", "bsb": "On the seventh day the priest is to reexamine the infection, and if the scaly outbreak has not spread and there is no yellow hair in it, and it does not appear to be deeper than the skin,", "asv": "and in the seventh day the priest shall look on the plague; and, behold, if the scall be not spread, and there be in it no yellow hair, and the appearance of the scall be not deeper than the skin,", "ylt": "`And the priest hath seen the plague on the seventh day, and lo, the scall hath not spread, and a shining hair hath not been in it, and the appearance of the scall is not deeper than the skin,", "tyndale": "And let the preast loke on the disease the seuenth daye: ad yf the breakynge oute be gone no forther nether be any golden heeres therein nether the scabbe be lower than the other skynne,", "dra": "And on the seventh day he shall look upon it. If the spot be not grown, and the hair keep its colour, and the place of the blemish be even with the other flesh:", "bbe": "And on the seventh day the priest will see the place: and if it is not increased, and there is no yellow hair in it, and it does not seem to go deeper than the skin,", "geneva": "After, in the seuenth day the Priest shall looke on the sore: and if the blacke spot growe not, and there be in it no yelowe heare, and the blacke spot seeme not lower then the skinne,", "wycliffe": "if the wem waxith not, and the heer is of his colour, and the place of wounde is euene with the tother fleisch,", "rotherham": "and the priest shall view the spot on the seventh day, and lo! if the scall hath not spread, and there hath not come to be therein yellow hair,—and, the appearance of the scall, is not deeper than the skin,", "darby": "And when the priest looketh on the sore on the seventh day, and behold, the scall hath not spread, and there is in it no yellow hair, and the scall doth not look deeper than the skin,", "twenty": "", "jps": "And in the seventh day the priest shall look on the plague; and, behold, if the scall be not spread, and there be in it no yellow hair, and the appearance of the scall be not deeper than the skin,", "acv": "And in the seventh day the priest shall look on the disease, and, behold, if the scall has not spread, and there is in it no yellow hair, and the appearance of the scall is not deeper than the skin,", "anderson": "", "haweis": "", "noyes": "", "webster": "And in the seventh day the priest shall look on the plague: and behold, [if] the scall spreadeth not, and there is in it no yellow hair, and the scall [is] not in sight deeper than the skin;", "vulgate": "et die septimo intuebitur si non creverit macula et capillus sui coloris est et locus plagae carni reliquae aequalis;", "brenton": "And the priest shall look at the plague on the seventh day; and, behold, if the scurf be not spread, and there be no yellowish hair on it, and the appearance of the scurf is not hollow under the skin;"}}, {"v": 33, "ref": "13:33", "o": "וְ/הִ֨תְגַּלָּ֔ח וְ/אֶת הַ/נֶּ֖תֶק לֹ֣א יְגַלֵּ֑חַ וְ/הִסְגִּ֨יר הַ/כֹּהֵ֧ן אֶת הַ/נֶּ֛תֶק שִׁבְעַ֥ת יָמִ֖ים שֵׁנִֽית", "en": {"kjv": "He shall be shaven, but the scall shall he not shave; and the priest shall shut up him that hath the scall seven days more:", "web": "then he shall be shaved, but he shall not shave the itch; and the priest shall shut him up who has the itch seven more days.", "bsb": "then the person must shave himself except for the scaly area. Then the priest shall isolate him for another seven days.", "asv": "then he shall be shaven, but the scall shall he not shave; and the priest shall shut up him that hath the scall seven days more:", "ylt": "then he hath shaved himself, but the scall he doth not shave; and the priest hath shut up him who hath the scall a second seven days.", "tyndale": "then lett him be shauen, but lett hym not shaue the scabbe, and let the preast shutt him vpp seuen dayes moo.", "dra": "The man shall be shaven all but the place of the spot: and he shall be shut up other seven days.", "bbe": "Then his hair is to be cut off, but not on the diseased place, and he is to be shut up for seven days more:", "geneva": "Then he shalbe shauen, but the place of the blacke spot shall he not shaue: but the Priest shall shut vp him, that hath the blacke spot, seuen dayes more.", "wycliffe": "the man schal be schauun, without the place of wem, and he schal be closid eft bi seuene othere daies.", "rotherham": "then shall he shave himself, but the scall, shall he not shave, and the priest shall shut up him who hath the scall seven days, more;", "darby": "he [that hath the sore] shall shave himself; but the scall shall he not shave; and the priest shall shut up [him that hath] the scall seven days a second time.", "twenty": "", "jps": "then he shall be shaven, but the scall shall he not shave; and the priest shall shut up him that hath the scall seven days more.", "acv": "then he shall be shaven, but the scall he shall not shave, and the priest shall shut up him who has the scall seven days more.", "anderson": "", "haweis": "", "noyes": "", "webster": "He shall be shaven, but the scall shall he not shave; and the priest shall shut up [him that hath] the scall seven days more:", "vulgate": "radetur homo absque loco maculae et includetur septem diebus aliis;", "brenton": "then the skin shall be shaven, but the scurf shall not be shaven; and the priest shall set aside the person having the scurf the second time for seven days."}}, {"v": 34, "ref": "13:34", "o": "וְ/רָאָה֩ הַ/כֹּהֵ֨ן אֶת הַ/נֶּ֜תֶק בַּ/יּ֣וֹם הַ/שְּׁבִיעִ֗י וְ֠/הִנֵּה לֹא פָשָׂ֤ה הַ/נֶּ֨תֶק֙ בָּ/ע֔וֹר וּ/מַרְאֵ֕/הוּ אֵינֶ֥/נּוּ עָמֹ֖ק מִן הָ/ע֑וֹר וְ/טִהַ֤ר אֹת/וֹ֙ הַ/כֹּהֵ֔ן וְ/כִבֶּ֥ס בְּגָדָ֖י/ו וְ/טָהֵֽר", "en": {"kjv": "And in the seventh day the priest shall look on the scall: and, behold, if the scall be not spread in the skin, nor be in sight deeper than the skin; then the priest shall pronounce him clean: and he shall wash his clothes, and be clean.", "web": "On the seventh day, the priest shall examine the itch; and behold, if the itch hasn’t spread in the skin, and its appearance isn’t deeper than the skin, then the priest shall pronounce him clean. He shall wash his clothes, and be clean.", "bsb": "On the seventh day the priest shall examine the scaly outbreak, and if it has not spread on the skin and does not appear to be deeper than the skin, the priest is to pronounce him clean. He must wash his clothes, and he will be clean.", "asv": "and in the seventh day the priest shall look on the scall; and, behold, if the scall be not spread in the skin, and the appearance thereof be not deeper than the skin; then the priest shall pronounce him clean: and he shall wash his clothes, and be clean.", "ylt": "And the priest hath seen the scall on the seventh day, and lo, the scall hath not spread in the skin, and its appearance is not deeper than the skin, and the priest hath pronounced him clean, and he hath washed his garments, and hath been clean.", "tyndale": "And let the preast loke on the breakynge out the .vij. daye agayne: Yf the breakynge out be gone no further in the skynne nor moare lower the the other skynne, then lett the preaste make him cleane, and let him wasshe his clothes and then he is cleane.", "dra": "If on the seventh day the evil seem to have stayed in its place, and not lower than the other flesh, he shall cleanse him: and his clothes being washed he shall be clean.", "bbe": "And on the seventh day the priest will see the place: and if it is not increased, and does not seem to go deeper than the skin, the priest will say that he is clean: and after his clothing has been washed he will be clean.", "geneva": "And the seuenth day the Priest shall looke on the blacke spot: and if the blacke spot growe not in the skinne, nor seeme lower then the other skinne, then the Priest shall clense him, and hee shall wash his clothes, and be cleane.", "wycliffe": "If in the seuenthe day the wounde is seyn to haue stonde in his place, nether is lowere than the tother fleisch, the preest schal clense the man; and whanne his clothis ben waischun, he schal be cleene.", "rotherham": "then shall the priest view the scall, on the seventh day, and lo! if the scall hath not spread in the skin, and, the appearance thereof, is not deeper than the skin, then shall the priest pronounce him clean, and he shall wash his clothes, and be clean.", "darby": "And the priest shall look on the scall on the seventh day, and behold, the scall hath not spread in the skin, nor is in sight deeper than the skin, then the priest shall pronounce him clean; and he shall wash his garments, and be clean.", "twenty": "", "jps": "And in the seventh day the priest shall look on the scall; and, behold, if the scall be not spread in the skin, and the appearance thereof be not deeper than the skin, then the priest shall pronounce him clean; and he shall wash his clothes, and be clean.", "acv": "And in the seventh day the priest shall look on the scall, and, behold, if the scall has not spread in the skin, and the appearance of it is not deeper than the skin, then the priest shall pronounce him clean. And he shall wash his clothes, and be clean.", "anderson": "", "haweis": "", "noyes": "", "webster": "And in the seventh day the priest shall look on the scall: and behold, [if] the scall is not spread in the skin, nor [is] in sight deeper than the skin; then the priest shall pronounce him clean: and he shall wash his clothes, and be clean.", "vulgate": "si die septimo visa fuerit stetisse plaga in loco suo nec humilior carne reliqua mundabit eum lotisque vestibus mundus erit;", "brenton": "And the priest shall see the scurf on the seventh day; and, behold, if the scurf is not spread in the skin after the man's being shaved, and the appearance of the scurf is not hollow beneath the skin, then the priest shall pronounce him clean; and he shall wash his garments, and be clean."}}, {"v": 35, "ref": "13:35", "o": "וְ/אִם פָּשֹׂ֥ה יִפְשֶׂ֛ה הַ/נֶּ֖תֶק בָּ/ע֑וֹר אַחֲרֵ֖י טָהֳרָתֽ/וֹ", "en": {"kjv": "But if the scall spread much in the skin after his cleansing;", "web": "But if the itch spreads in the skin after his cleansing,", "bsb": "If, however, the scaly outbreak spreads further on the skin after his cleansing,", "asv": "But if the scall spread abroad in the skin after his cleansing,", "ylt": "`And if the scall spread greatly in the skin after his cleansing,", "tyndale": "Yf the breakynge out growe in the skynne after that he is once made cleane,", "dra": "But if after his cleansing the spot spread again in the skin:", "bbe": "But if the disease in his skin becomes worse after he has been made clean,", "geneva": "But if the blacke spot growe abroad in the flesh after his clensing,", "wycliffe": "Ellis if aftir the clensyng a spotte wexith eft in the skyn,", "rotherham": "But, if the scall do indeed spread in the skin,—after he hath been pronounced clean,", "darby": "But if the scall have spread much in the skin after his cleansing,", "twenty": "", "jps": "But if the scall spread abroad in the skin after his cleansing,", "acv": "But if the scall spreads abroad in the skin after his cleansing,", "anderson": "", "haweis": "", "noyes": "", "webster": "But if the scall shall spread much in the skin after his cleansing;", "vulgate": "sin autem post emundationem rursus creverit macula in cute;", "brenton": "But if the scurf be indeed spread in the skin after he has been purified,"}}, {"v": 36, "ref": "13:36", "o": "וְ/רָאָ֨/הוּ֙ הַ/כֹּהֵ֔ן וְ/הִנֵּ֛ה פָּשָׂ֥ה הַ/נֶּ֖תֶק בָּ/ע֑וֹר לֹֽא יְבַקֵּ֧ר הַ/כֹּהֵ֛ן לַ/שֵּׂעָ֥ר הַ/צָּהֹ֖ב טָמֵ֥א הֽוּא", "en": {"kjv": "Then the priest shall look on him: and, behold, if the scall be spread in the skin, the priest shall not seek for yellow hair; he is unclean.", "web": "then the priest shall examine him; and behold, if the itch has spread in the skin, the priest shall not look for the yellow hair; he is unclean.", "bsb": "the priest is to examine him, and if the scaly outbreak has spread on the skin, the priest need not look for yellow hair; the person is unclean.", "asv": "then the priest shall look on him; and, behold, if the scall be spread in the skin, the priest shall not seek for the yellow hair; he is unclean.", "ylt": "and the priest hath seen him, and lo, the scall hath spread in the skin, the priest seeketh not for the shining hair, he is unclean;", "tyndale": "let the preast see him. Yf it be growne abrode in dede in the skynne, let the preast seke no further for ony golden heeres, for he is vncleane.", "dra": "He shall seek no more whether the hair be turned yellow, because he is evidently unclean.", "bbe": "Then the priest is to see him: and if the mark is increased, the priest, without looking for the yellow hair, will say that he is unclean.", "geneva": "Then the Priest shall looke on it: and if the blacke spot grow in the skin, the Priest shall not seeke for the yelowe heare: for he is vncleane.", "wycliffe": "the preest schal no more enquere, whether the heer is chaungid in to whijt colour, for apeertli he is vncleene.", "rotherham": "then shall the priest take a view, and lo! if the scall hath spread in the skin, the priest shall not search for the yellow hair—unclean, he is.", "darby": "and the priest shall look on him, and behold, the scall hath spread in the skin, the priest shall not seek for yellow hair: he is unclean.", "twenty": "", "jps": "then the priest shall look on him; and, behold, if the scall be spread in the skin, the priest shall not seek for the yellow hair: he is unclean.", "acv": "then the priest shall look on him. And, behold, if the scall has spread in the skin, the priest shall not seek for the yellow hair, he is unclean.", "anderson": "", "haweis": "", "noyes": "", "webster": "Then the priest shall look on him: and behold, if the scall is spread in the skin, the priest shall not seek for yellow hair; he [is] unclean.", "vulgate": "non quaeret amplius utrum capillus in flavum colorem sit commutatus quia aperte inmundus est;", "brenton": "then the priest shall look, and, behold, if the scurf be spread in the skin, the priest shall not examine concerning the yellow hair, for he is unclean."}}, {"v": 37, "ref": "13:37", "o": "וְ/אִם בְּ/עֵינָי/ו֩ עָמַ֨ד הַ/נֶּ֜תֶק וְ/שֵׂעָ֨ר שָׁחֹ֧ר צָֽמַח בּ֛/וֹ נִרְפָּ֥א הַ/נֶּ֖תֶק טָה֣וֹר ה֑וּא וְ/טִהֲר֖/וֹ הַ/כֹּהֵֽן", "en": {"kjv": "But if the scall be in his sight at a stay, and that there is black hair grown up therein; the scall is healed, he is clean: and the priest shall pronounce him clean.", "web": "But if in his eyes the itch is arrested, and black hair has grown in it; the itch is healed, he is clean. The priest shall pronounce him clean.", "bsb": "If, however, in his sight the scaly outbreak is unchanged and black hair has grown in it, then it has healed. He is clean, and the priest is to pronounce him clean.", "asv": "But if in his eyes the scall be at a stay, and black hair be grown up therein; the scall is healed, he is clean: and the priest shall pronounce him clean.", "ylt": "and if in his eyes the scall hath stayed, and black hair hath sprung up in it, the scall hath been healed--he is clean--and the priest hath pronounced him clean.", "tyndale": "But and yf he se that the scabbe stonde styll and that there is blacke heer growne vpp there in, the the scabbe is healed and he is cleane: and the preast shall make him cleane.", "dra": "But if the spot be stayed, and the hair be black, let him know that the man is healed: and let him confidently pronounce him clean.", "bbe": "But if, in his opinion, the growth is stopped, and black hair has come up on it, the disease has gone; he is clean and the priest will say that he is clean.", "geneva": "But if ye blacke spot seeme to him to abide, and that blacke heare growe therein, the blacke spot is healed, he is cleane, and the Priest shall declare him to be cleane.", "wycliffe": "Sotheli if the spotte stondith, and the heeris ben blake, knowe the preest that the man is heelid, and tristili `pronounce he the man cleene.", "rotherham": "But, if in his eyes, the scall is at a stay, and dark hair hath grown up therein, the scall is healed, clean, he is,—and the priest shall pronounce him clean.", "darby": "But if the scall have in his sight remained as it was, and there is black hair grown up therein, the scall is healed: he is clean; and the priest shall pronounce him clean.", "twenty": "", "jps": "But if the scall stay in its appearance, and black hair be grown up therein; the scall is healed, he is clean; and the priest shall pronounce him clean.", "acv": "But if in his eyes the scall is arrested, and black hair is grown up in it, the scall is healed. He is clean, and the priest shall pronounce him clean.", "anderson": "", "haweis": "", "noyes": "", "webster": "But if the scall shall be in his sight at a stay, and there is black hair grown in it; the scall is healed, he [is] clean: and the priest shall pronounce him clean.", "vulgate": "porro si steterit macula et capilli nigri fuerint noverit hominem esse sanatum et confidenter eum pronuntiet mundum;", "brenton": "But if the scurf remain before him in its place, and a dark hair should have arisen in it, the scurf is healed: he is clean, and the priest shall pronounce him clean."}}, {"v": 38, "ref": "13:38", "o": "וְ/אִישׁ֙ אֽוֹ אִשָּׁ֔ה כִּֽי יִהְיֶ֥ה בְ/עוֹר בְּשָׂרָ֖/ם בֶּהָרֹ֑ת בֶּהָרֹ֖ת לְבָנֹֽת", "en": {"kjv": "If a man also or a woman have in the skin of their flesh bright spots, even white bright spots;", "web": "“When a man or a woman has bright spots in the skin of the body, even white bright spots;", "bsb": "When a man or a woman has white spots on the skin,", "asv": "And when a man or a woman hath in the skin of the flesh bright spots, even white bright spots;", "ylt": "`And when a man or woman hath in the skin of their flesh bright spots, white bright spots,", "tyndale": "Yf there be founde in the skynne of the flesh of man or woman a glisterynge white,", "dra": "If a whiteness appear in the skin of a man or a woman,", "bbe": "And if a man or a woman has bright marks on the skin of their flesh, that is, bright white marks,", "geneva": "Furthermore if there bee many white spots in the skin of the flesh of man or woman,", "wycliffe": "A man ethir a womman, in whos skyn whijtnesse apperith, the preest schal biholde hem;", "rotherham": "And when either, man or woman, hath in the skin of their flesh bright spots,—bright spots that are white,", "darby": "And if a man or a woman have in the skin of their flesh bright spots, white bright spots,", "twenty": "", "jps": "And if a man or a woman have in the skin of their flesh bright spots, even white bright spots;", "acv": "And when a man or a woman has bright spots in the skin of the flesh, even white bright spots,", "anderson": "", "haweis": "", "noyes": "", "webster": "If a man also or a woman shall have in the skin of their flesh bright spots, [even] white bright spots;", "vulgate": "vir et mulier in cuius cute candor apparuerit;", "brenton": "And if a man or woman should have in the skin of their flesh spots of a bright whiteness,"}}, {"v": 39, "ref": "13:39", "o": "וְ/רָאָ֣ה הַ/כֹּהֵ֗ן וְ/הִנֵּ֧ה בְ/עוֹר בְּשָׂרָ֛/ם בֶּהָרֹ֖ת כֵּה֣וֹת לְבָנֹ֑ת בֹּ֥הַק ה֛וּא פָּרַ֥ח בָּ/ע֖וֹר טָה֥וֹר הֽוּא", "en": {"kjv": "Then the priest shall look: and, behold, if the bright spots in the skin of their flesh be darkish white; it is a freckled spot that groweth in the skin; he is clean.", "web": "then the priest shall examine them; and behold, if the bright spots on the skin of their body are a dull white, it is a harmless rash, it has broken out in the skin; he is clean.", "bsb": "the priest shall examine them, and if the spots are dull white, it is a harmless rash that has broken out on the skin; the person is clean.", "asv": "then the priest shall look; and, behold, if the bright spots in the skin of their flesh be of a dull white, it is a tetter, it hath broken out in the skin; he is clean.", "ylt": "and the priest hath seen, and lo, in the skin of their flesh white weak bright spots, it is a freckled spot broken out in the skin; he is clean.", "tyndale": "let the preast se it. Yf there appeare in their flesh a glisterynge white somwhat blackesh, the it is but frekels growe vpp in the skynne: ad he is cleane", "dra": "The priest shall view them. If he find that a darkish whiteness shineth in the skin, let him know that it is not the leprosy, but a white blemish, and that the man is clean.", "bbe": "Then the priest is to see them: and if the white marks on their skin are not very bright, it is a skin disease which has come out on the skin; he is clean.", "geneva": "Then the Priest shall consider: and if the spots in the skin of their flesh be somewhat darke and white withall, it is but a white spot broken out in the skin: therefore he is cleane.", "wycliffe": "if he perseyueth, that whijtnesse `sum deel derk schyneth in the skyn, wite he, that it is no lepre, but a spotte of whijt colour, and that the man is cleene.", "rotherham": "then shall the priest take a view and lo! if, in the skin of their flesh, are bright spots that are dull white, dead white spot, it is, that hath broken through in the skin—clean, he is.", "darby": "and the priest look, and behold, there are in the skin of their flesh pale white spots, it is an eruption which is broken out in the skin: he is clean.", "twenty": "", "jps": "then the priest shall look; and, behold, if the bright spots in the skin of their flesh be of a dull white, it is a tetter, it hath broken out in the skin: he is clean.", "acv": "then the priest shall look. And, behold, if the bright spots in the skin of their flesh are of a dull white, it is a tetter. It has broken out in the skin; he is clean.", "anderson": "", "haweis": "", "noyes": "", "webster": "Then the priest shall look: and behold, [if] the bright spots in the skin of their flesh [are] darkish white; it [is] a freckled spot [that] groweth in the skin; he [is] clean.", "vulgate": "intuebitur eos sacerdos si deprehenderit subobscurum alborem lucere in cute sciat non esse lepram sed maculam coloris candidi et hominem mundum;", "brenton": "then the priest shall look; and, behold, there being bright spots of a bright whiteness in the skin of their flesh, it is a tetter; it burst forth in the skin of his flesh; he is clean."}}, {"v": 40, "ref": "13:40", "o": "וְ/אִ֕ישׁ כִּ֥י יִמָּרֵ֖ט רֹאשׁ֑/וֹ קֵרֵ֥חַ ה֖וּא טָה֥וֹר הֽוּא", "en": {"kjv": "And the man whose hair is fallen off his head, he is bald; yet is he clean.", "web": "“If a man’s hair has fallen from his head, he is bald. He is clean.", "bsb": "Now if a man loses his hair and is bald, he is still clean.", "asv": "And if a man’s hair be fallen off his head, he is bald; yet is he clean.", "ylt": "`And when a man's head is polished, he is bald, he is clean;", "tyndale": "Yf a mans heer fall of his heed, the he is heedbaulde and cleane.", "dra": "The man whose hair falleth off from his head, he is bald and clean:", "bbe": "And if a man's hair has come out and he has no hair, still he is clean.", "geneva": "And the man whose heare is fallen off his head, and is balde, is cleane.", "wycliffe": "A man of whos heed heeris fleten awei, is calu, and clene;", "rotherham": "And, when, any man’s, head loseth its hair, though, bald, he is, clean.", "darby": "And if a man's hair have fallen off his head, he is bald: he is clean;", "twenty": "", "jps": "And if a man's hair be fallen off his head, he is bald; yet is he clean.", "acv": "And if a man's hair is fallen off his head, he is bald; he is clean.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the man whose hair hath fallen off his head, he [is] bald; [yet is] he clean.", "vulgate": "vir de cuius capite capilli fluunt calvus ac mundus est;", "brenton": "And if any one's head should lose the hair, he is only bald, he is clean."}}, {"v": 41, "ref": "13:41", "o": "וְ/אִם֙ מִ/פְּאַ֣ת פָּנָ֔י/ו יִמָּרֵ֖ט רֹאשׁ֑/וֹ גִּבֵּ֥חַ ה֖וּא טָה֥וֹר הֽוּא", "en": {"kjv": "And he that hath his hair fallen off from the part of his head toward his face, he is forehead bald: yet is he clean.", "web": "If his hair has fallen off from the front part of his head, he is forehead bald. He is clean.", "bsb": "Or if his hairline recedes and he is bald on his forehead, he is still clean.", "asv": "And if his hair be fallen off from the front part of his head, he is forehead bald; yet is he clean.", "ylt": "and if from the corner of his face his head is polished, he is bald of the forehead; he is clean.", "tyndale": "yf his heer fall before in his foreheade, then he is foreheadbalde and cleane.", "dra": "And if the hair fall from his forehead, he is bald before and clean.", "bbe": "And if the hair has gone from the front part of his head, so that he has no hair there, still he is clean.", "geneva": "And if his head lose the heare on the forepart, and be balde before, he is cleane.", "wycliffe": "and if heeris fallen fro the forheed, he is ballid,", "rotherham": "And if, in front, his head loseth its hair, though bald in the forehead, he is, clean.", "darby": "and if he have the hair fallen off from the part of the head towards his face, he is forehead-bald: he is clean.", "twenty": "", "jps": "And if his hair be fallen off from the front part of his head, he is forehead-bald; yet is he clean.", "acv": "And if his hair is fallen off from the front part of his head, he is forehead bald; he is clean.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he that hath his hair fallen off from the part of his head towards his face, he [is] forehead-bald; [yet is] he clean.", "vulgate": "et si a fronte ceciderint pili recalvaster et mundus est;", "brenton": "And if his head should lose the hair in front, he is forehead bald: he is clean."}}, {"v": 42, "ref": "13:42", "o": "וְ/כִֽי יִהְיֶ֤ה בַ/קָּרַ֨חַת֙ א֣וֹ בַ/גַּבַּ֔חַת נֶ֖גַע לָבָ֣ן אֲדַמְדָּ֑ם צָרַ֤עַת פֹּרַ֨חַת֙ הִ֔וא בְּ/קָרַחְתּ֖/וֹ א֥וֹ בְ/גַבַּחְתּֽ/וֹ", "en": {"kjv": "And if there be in the bald head, or bald forehead, a white reddish sore; it is a leprosy sprung up in his bald head, or his bald forehead.", "web": "But if there is in the bald head, or the bald forehead, a reddish-white plague; it is leprosy breaking out in his bald head, or his bald forehead.", "bsb": "But if there is a reddish-white sore on the bald head or forehead, it is an infectious disease breaking out on it.", "asv": "But if there be in the bald head, or the bald forehead, a reddish-white plague; it is leprosy breaking out in his bald head, or his bald forehead.", "ylt": "`And when there is in the bald back of the head, or in the bald forehead, a very red white plague, it is a leprosy breaking out in the bald back of the head, or in the bald forehead;", "tyndale": "yf there be in the baulde head or baulde forehead a redysh white scabbe, then there is leprosye spronge vpp in his baulde head or baulde foreheade.", "dra": "But if in the bald head or in the bald forehead there be risen a white or reddish colour:", "bbe": "But if, on his head or on his brow, where he has no hair, there is a red and white place, it is the disease of the leper coming out on his head or on his brow.", "geneva": "But if there be in the balde head, or in the balde forehead a white reddish sore, it is a leprosie springing in his balde head, or in his balde forehead.", "wycliffe": "and is cleene; ellis if in the ballidnesse bifore, ether in the ballidnesse bihynde, whijt ether reed colour is bred, and the preest seeth this,", "rotherham": "But, should there be, in the baldness behind, or in the baldness in front, a spot that is reddish white, leprosy broken out, it is, in his baldness behind, or in his baldness in front.", "darby": "And if there be in the bald head, or bald forehead, a white-reddish sore, it is a leprosy which hath broken out in his bald head, or his bald forehead.", "twenty": "", "jps": "But if there be in the bald head, or the bald forehead, a reddish-white plague, it is leprosy breaking out in his bald head, or his bald forehead.", "acv": "But if there is a reddish-white disease in the bald head, or the bald forehead, it is a leprous disease breaking out in his bald head, or his bald forehead.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if there is in the bald head, or bald forehead, a white reddish sore; [it is] a leprosy sprung up on his bald head, or his bald forehead.", "vulgate": "sin autem in calvitio sive in recalvatione albus vel rufus color fuerit exortus;", "brenton": "And if there should be in his baldness of head, or his baldness of forehead, a white or fiery plague, it is leprosy in his baldness of head, or baldness of forehead."}}, {"v": 43, "ref": "13:43", "o": "וְ/רָאָ֨ה אֹת֜/וֹ הַ/כֹּהֵ֗ן וְ/הִנֵּ֤ה שְׂאֵת הַ/נֶּ֨גַע֙ לְבָנָ֣ה אֲדַמְדֶּ֔מֶת בְּ/קָרַחְתּ֖/וֹ א֣וֹ בְ/גַבַּחְתּ֑/וֹ כְּ/מַרְאֵ֥ה צָרַ֖עַת ע֥וֹר בָּשָֽׂר", "en": {"kjv": "Then the priest shall look upon it: and, behold, if the rising of the sore be white reddish in his bald head, or in his bald forehead, as the leprosy appeareth in the skin of the flesh;", "web": "Then the priest shall examine him; and, behold, if the rising of the plague is reddish-white in his bald head, or in his bald forehead, like the appearance of leprosy in the skin of the flesh,", "bsb": "The priest is to examine him, and if the swelling of the infection on his bald head or forehead is reddish-white like a skin disease,", "asv": "Then the priest shall look upon him; and, behold, if the rising of the plague be reddish-white in his bald head, or in his bald forehead, as the appearance of leprosy in the skin of the flesh;", "ylt": "and the priest hath seen him, and lo, the rising of the very red white plague in the bald back of the head, or in the bald forehead, is as the appearance of leprosy, in the skin of the flesh,", "tyndale": "And let the preast se it: and yf the rysynge of the sore be reddyshwhite in his baulde heade or foreheade after the maner of a leprosye in the skynne of the flesh,", "dra": "And the priest perceive this, he shall condemn him undoubtedly of leprosy which is risen in the bald part.", "bbe": "Then if the priest sees that the growth of the disease has become red and white on his head or on his brow where there is no hair, like the mark in the skin of a leper;", "geneva": "Therefore the Priest shall looke vpon it, and if the rising of the sore bee white reddish in his balde head, or in his bald forehead, appearing like leprosie in the skin of the flesh,", "wycliffe": "he schal condempne the man without doute of lepre, which is bred in the ballidnesse.", "rotherham": "So the priest shall view it, and lo! if, the rising-spot, be reddish white in his baldness behind or in his baldness in front,—like the appearance of leprosy in the skin of the flesh,", "darby": "And the priest shall look on it, and behold, the rising of the sore is white-reddish in his bald head, or in his bald forehead, like the appearance of the leprosy in the skin of the flesh;", "twenty": "", "jps": "Then the priest shall look upon him; and, behold, if the rising of the plague be reddish-white in his bald head, or in his bald forehead, as the appearance of leprosy in the skin of the flesh,", "acv": "Then the priest shall look upon him, and, behold, if the rising of the disease is reddish-white in his bald head, or in his bald forehead, as the appearance of a leprous disease in the skin of the flesh,", "anderson": "", "haweis": "", "noyes": "", "webster": "Then the priest shall look upon it: and behold, [if] the rising of the sore is white reddish on his bald head, or on his bald forehead, as the leprosy appeareth in the skin of the flesh;", "vulgate": "et hoc sacerdos viderit condemnabit eum haut dubiae leprae quae orta est in calvitio;", "brenton": "And the priest shall look upon him, and, behold, if the appearance of the plague be white or inflamed in his baldness of head or baldness in front, as the appearance of leprosy in the skin of his flesh,"}}, {"v": 44, "ref": "13:44", "o": "אִישׁ צָר֥וּעַ ה֖וּא טָמֵ֣א ה֑וּא טַמֵּ֧א יְטַמְּאֶ֛/נּוּ הַ/כֹּהֵ֖ן בְּ/רֹאשׁ֥/וֹ נִגְעֽ/וֹ", "en": {"kjv": "He is a leprous man, he is unclean: the priest shall pronounce him utterly unclean; his plague is in his head.", "web": "he is a leprous man. He is unclean. The priest shall surely pronounce him unclean. His plague is on his head.", "bsb": "the man is diseased; he is unclean. The priest must pronounce him unclean because of the infection on his head.", "asv": "he is a leprous man, he is unclean: the priest shall surely pronounce him unclean; his plague is in his head.", "ylt": "he is a leprous man, he is unclean; the priest doth pronounce him utterly unclean; his plague is in his head.", "tyndale": "then he is a leper and vncleane: ad the preast shall make him vncleane, for the plage of his heede.", "dra": "Now whosoever shall be defiled with the leprosy, and is separated by the judgment of the priest:", "bbe": "He is a leper and unclean; the priest is to say that he is most certainly unclean: the disease is in his head.", "geneva": "He is a leper and vncleane: therefore the Priest shall pronounce him altogether vncleane: for the sore is in his head.", "wycliffe": "Therfor whoeuer is defoulid with lepre, and is departid at the doom of the preest,", "rotherham": "a leprous man, is he, unclean, he is,—unclean, shall the priest pronounce him in his head, is his plague.", "darby": "he is a leprous man, he is unclean; the priest shall pronounce him utterly unclean; his sore is in his head.", "twenty": "", "jps": "he is a leprous man, he is unclean; the priest shall surely pronounce him unclean: his plague is in his head.", "acv": "he is a leprous man; he is unclean. The priest shall surely pronounce him unclean; his disease is on his head.", "anderson": "", "haweis": "", "noyes": "", "webster": "He is a leprous man, he [is] unclean: the priest shall pronounce him utterly unclean; his plague [is] in his head.", "vulgate": "quicumque ergo maculatus fuerit lepra et separatus ad arbitrium sacerdotis;", "brenton": "he is a leprous man: the priest shall surely pronounce him unclean, his plague is in his head."}}, {"v": 45, "ref": "13:45", "o": "וְ/הַ/צָּר֜וּעַ אֲשֶׁר בּ֣/וֹ הַ/נֶּ֗גַע בְּגָדָ֞י/ו יִהְי֤וּ פְרֻמִים֙ וְ/רֹאשׁ/וֹ֙ יִהְיֶ֣ה פָר֔וּעַ וְ/עַל שָׂפָ֖ם יַעְטֶ֑ה וְ/טָמֵ֥א טָמֵ֖א יִקְרָֽא", "en": {"kjv": "And the leper in whom the plague is, his clothes shall be rent, and his head bare, and he shall put a covering upon his upper lip, and shall cry, Unclean, unclean.", "web": "“The leper in whom the plague is shall wear torn clothes, and the hair of his head shall hang loose. He shall cover his upper lip, and shall cry, ‘Unclean! Unclean!’", "bsb": "A diseased person must wear torn clothes and let his hair hang loose, and he must cover his mouth and cry out, ‘Unclean, unclean!’", "asv": "And the leper in whom the plague is, his clothes shall be rent, and the hair of his head shall go loose, and he shall cover his upper lip, and shall cry, Unclean, unclean.", "ylt": "`As to the leper in whom is the plague, his garments are rent, and his head is uncovered, and he covereth over the upper lip, and `Unclean! unclean!' he calleth;", "tyndale": "And the leper in whome the plage is shall haue his clothes rent and his heade bare ad his mouth moffeld, and shalbe called vncleane.", "dra": "Shall have his clothes hanging loose, his head bare, his mouth covered with a cloth: and he shall cry out that he is defiled and unclean.", "bbe": "And the leper who has the disease on him is to go about with signs of grief, with his hair loose and his mouth covered, crying, Unclean, unclean.", "geneva": "The leper also in whom the plague is, shall haue his clothes rent, and his head bare, and shall put a couering vpon his lips, and shall cry, I am vncleane, I am vncleane.", "wycliffe": "he schal haue hise clothis vnsewid, bareheed, the mouth hilid with a cloth, he schal crye hym silf defoulid, and viyl;", "rotherham": "Now, as for the leper in whom is the plague, His clothes, shall be rent, And, his head, shall be bare, And, his beard, shall he cover,—And, Unclean! Unclean! shall he cry.", "darby": "And as to the leper in whom the sore is, — his garments shall be rent, and his head shall be uncovered, and he shall put a covering on his beard, and shall cry, Unclean, unclean!", "twenty": "", "jps": "And the leper in whom the plague is, his clothes shall be rent, and the hair of his head shall go loose, and he shall cover his upper lip, and shall cry: 'Unclean, unclean.'", "acv": "And the man with a leprous disease in whom the disease is, his clothes shall be torn, and the hair of his head shall go loose, and he shall cover his upper lip, and shall cry, Unclean, unclean.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the leper in whom the plague [is], his clothes shall be rent, and his head bare, and he shall put a covering upon his upper lip, and shall cry, Unclean, unclean.", "vulgate": "habebit vestimenta dissuta caput nudum os veste contectum contaminatum ac sordidum se clamabit;", "brenton": "And the leper in whom the plague is, let his garments be ungirt, and his head uncovered; and let him have a covering put upon his mouth, and he shall be called unclean."}}, {"v": 46, "ref": "13:46", "o": "כָּל יְמֵ֞י אֲשֶׁ֨ר הַ/נֶּ֥גַע בּ֛/וֹ יִטְמָ֖א טָמֵ֣א ה֑וּא בָּדָ֣ד יֵשֵׁ֔ב מִ/ח֥וּץ לַֽ/מַּחֲנֶ֖ה מוֹשָׁבֽ/וֹ", "en": {"kjv": "All the days wherein the plague shall be in him he shall be defiled; he is unclean: he shall dwell alone; without the camp shall his habitation be.", "web": "All the days in which the plague is in him he shall be unclean. He is unclean. He shall dwell alone. Outside of the camp shall be his dwelling.", "bsb": "As long as he has the infection, he remains unclean. He must live alone in a place outside the camp.", "asv": "All the days wherein the plague is in him he shall be unclean; he is unclean: he shall dwell alone; without the camp shall his dwelling be.", "ylt": "all the days that the plague is in him he is unclean; he is unclean, alone he doth dwell, at the outside of the camp is his dwelling.", "tyndale": "And as longe as the dysease lesteth apon him, he shalbe vncleane: for he is vncleane, and shall therfore dwell alone, ad even without the host shall his habitacion be.", "dra": "All the time that he is a leper and unclean he shall dwell alone without the camp.", "bbe": "While the disease is on him, he will be unclean. He is unclean: let him keep by himself, living outside the tent-circle.", "geneva": "As long as the disease shall be vpon him, he shalbe polluted, for he is vncleane: he shall dwell alone, without the campe shall his habitation be.", "wycliffe": "in al tyme in which he is lepre and vnclene, he schal dwelle aloone without the castels.", "rotherham": "All the days that the plague is in him, shall he continue unclean, Unclean, he is,—Alone, shall he remain, Outside the camp, shall be his dwelling.", "darby": "All the days that the sore shall be in him he shall be unclean: he is unclean; he shall dwell apart; outside the camp shall his dwelling be.", "twenty": "", "jps": "All the days wherein the plague is in him he shall be unclean; he is unclean; he shall dwell alone; without the camp shall his dwelling be.", "acv": "All the days in which the disease is in him he shall be unclean; he is unclean. He shall dwell alone; his dwelling shall be outside the camp.", "anderson": "", "haweis": "", "noyes": "", "webster": "All the days in which the plague [shall be] in him he shall be defiled; he [is] unclean: he shall dwell alone, without the camp [shall] his habitation [be].", "vulgate": "omni tempore quo leprosus est et inmundus solus habitabit extra castra;", "brenton": "All the days in which the plague shall be upon him, being unclean, he shall be esteemed unclean; he shall dwell apart, his place of sojourn shall be without the camp."}}, {"v": 47, "ref": "13:47", "o": "וְ/הַ/בֶּ֕גֶד כִּֽי יִהְיֶ֥ה ב֖/וֹ נֶ֣גַע צָרָ֑עַת בְּ/בֶ֣גֶד צֶ֔מֶר א֖וֹ בְּ/בֶ֥גֶד פִּשְׁתִּֽים", "en": {"kjv": "The garment also that the plague of leprosy is in, whether it be a woollen garment, or a linen garment;", "web": "“The garment also that the plague of leprosy is in, whether it is a woolen garment, or a linen garment;", "bsb": "If any fabric is contaminated with mildew—any wool or linen garment,", "asv": "The garment also that the plague of leprosy is in, whether it be a woollen garment, or a linen garment;", "ylt": "`And when there is in any garment a plague of leprosy, --in a garment of wool, or in a garment of linen,", "tyndale": "When the plage of leprosye is in a cloth: whether it be lynen or wollen,", "dra": "A woollen or linen garment that shall have the leprosy", "bbe": "And any clothing of wool or of linen in which is the mark of the disease;", "geneva": "Also the garment that the plague of leprosie is in, whether it be a wollen garment or a linen garment,", "wycliffe": "A wollun cloth, ethir lynnun, that hath lepre in the warp,", "rotherham": "And, when, in a garment, there is a plague-spot of leprosy,—whether in a garment of wool, or a garment of flax;", "darby": "And if a sore of leprosy is in a garment, in a woollen garment, or a linen garment,", "twenty": "", "jps": "And when the plague of leprosy is in a garment, whether it be a woolen garment, or a linen garment;", "acv": "The garment also that a leprous disease is in, whether it be a woolen garment, or a linen garment,", "anderson": "", "haweis": "", "noyes": "", "webster": "The garment also that the plague of leprosy is in, [whether] a woolen garment, or a linen garment;", "vulgate": "vestis lanea sive linea quae lepram habuerit;", "brenton": "And if a garment have in it the plague of leprosy, a garment of wool, or a garment of flax,"}}, {"v": 48, "ref": "13:48", "o": "א֤וֹ בִֽ/שְׁתִי֙ א֣וֹ בְ/עֵ֔רֶב לַ/פִּשְׁתִּ֖ים וְ/לַ/צָּ֑מֶר א֣וֹ בְ/ע֔וֹר א֖וֹ בְּ/כָל מְלֶ֥אכֶת עֽוֹר", "en": {"kjv": "Whether it be in the warp, or woof; of linen, or of woollen; whether in a skin, or in any thing made of skin;", "web": "whether it is in warp, or woof; of linen, or of wool; whether in a skin, or in anything made of skin;", "bsb": "any weave or knit of linen or wool, or any article of leather—", "asv": "whether it be in warp, or woof; of linen, or of woollen; whether in a skin, or in anything made of skin;", "ylt": "or in the warp, or in the woof, of linen or of wool, or in a skin, or in any work of skin,", "tyndale": "yee and whether it be in the warpe or wolfe of the lynen or of the wollen: ether in a skynne or any thinge made of skynne", "dra": "In the warp, and the woof: or skin, or whatsoever is made of a skin:", "bbe": "If it is in the threads of the linen or of the wool, or in leather, or in anything made of skin;", "geneva": "Whether it bee in the warpe or in ye woofe of linen or of wollen, either in a skin, or in any thing made of skin,", "wycliffe": "ethir oof, ethir certis a skyn, ether what euer thing is maad of skiyn,", "rotherham": "either in warp or in weft, made with flax, or with wool,—or in a skin, or in anything wrought of skin;", "darby": "either in the warp or in the woof of linen or of wool, or in a skin, or in anything made of skin,", "twenty": "", "jps": "or in the warp, or in the woof, whether they be of linen, or of wool; or in a skin, or in any thing made of skin.", "acv": "whether it be in warp, or woof, of linen, or of woolen, whether in a skin, or in anything made of skin,", "anderson": "", "haweis": "", "noyes": "", "webster": "Whether in the warp, or woof, of linen, or of woolen: whether in a skin, or in any thing made of skin:", "vulgate": "in stamine atque subtemine aut certe pellis vel quicquid ex pelle confectum est;", "brenton": "either in the warp or in the woof, or in the linen, or in the woollen threads, or in a skin, or in any workmanship of skin,"}}, {"v": 49, "ref": "13:49", "o": "וְ/הָיָ֨ה הַ/נֶּ֜גַע יְרַקְרַ֣ק א֣וֹ אֲדַמְדָּ֗ם בַּ/בֶּגֶד֩ א֨וֹ בָ/ע֜וֹר אֽוֹ בַ/שְּׁתִ֤י אוֹ בָ/עֵ֨רֶב֙ א֣וֹ בְ/כָל כְּלִי ע֔וֹר נֶ֥גַע צָרַ֖עַת ה֑וּא וְ/הָרְאָ֖ה אֶת הַ/כֹּהֵֽן", "en": {"kjv": "And if the plague be greenish or reddish in the garment, or in the skin, either in the warp, or in the woof, or in any thing of skin; it is a plague of leprosy, and shall be shewed unto the priest:", "web": "if the plague is greenish or reddish in the garment, or in the skin, or in the warp, or in the woof, or in anything made of skin; it is the plague of leprosy, and shall be shown to the priest.", "bsb": "and if the mark in the fabric, leather, weave, knit, or leather article is green or red, then it is contaminated with mildew and must be shown to the priest.", "asv": "if the plague be greenish or reddish in the garment, or in the skin, or in the warp, or in the woof, or in anything of skin; it is the plague of leprosy, and shall be showed unto the priest.", "ylt": "and the plague hath been very green or very red in the garment, or in the skin, or in the warp, or in the woof, or in any vessel of skin, it is a plague of leprosy, and it hath been shewn the priest.", "tyndale": "yf the disease be pale or somwhat redysh in the cloth or skynne: whether it be in the warpe or wolfe or any thinge that is made of skynne, the it is a very leprosye and must be shewed vnto the preast.", "dra": "If it be infected with a white or red spot, it shall be accounted the leprosy, and shall be shewn to the priest.", "bbe": "If there are red or green marks on the clothing, or on the leather, or in the threads of the cloth, or in anything made of skin, it is the leper's disease: let the priest see it.", "geneva": "And if the sore be greene or somewhat reddish in the garment or in ye skin, or in the warpe, or in the woofe, or in any thing that is made of skin, it is a plague of leprosie and shalbe shewed vnto the Priest.", "wycliffe": "if it is corrupt with a whijt spotte, ethir reed, it schal be arettid lepre, and it schal be schewid to the preest;", "rotherham": "and the spot cometh to be of a greenish yellow or reddish, in the garment or in the skin, whether in warp or in weft, or in any utensil of skin, the plague-spot of leprosy, it is,—and shall be shown unto the priest;", "darby": "and the sore is greenish or reddish in the garment, or in the skin, or in the warp, or in the woof, or in anything of skin, it is the sore of leprosy, and shall be shewn unto the priest.", "twenty": "", "jps": "If the plague be greenish or reddish in the garment, or in the skin, or in the warp, or in the woof, or in any thing of skin, it is the plague of leprosy, and shall be shown unto the priest.", "acv": "if the disease is greenish or reddish in the garment, or in the skin, or in the warp, or in the woof, or in anything of skin, it is a leprous disease, and shall be shown to the priest.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if the plague is greenish or reddish in the garment, or in the skin, either in the warp, or in the woof, or in any thing of skin: it [is] a plague of leprosy, and shall be shown to the priest:", "vulgate": "si alba aut rufa macula fuerit infecta lepra reputabitur ostendeturque sacerdoti;", "brenton": "and the plague be greenish or reddish in the skin, or in the garment, either in the warp, or in the woof, or in any utensil of skin, it is a plague of leprosy, and he shall show it to the priest."}}, {"v": 50, "ref": "13:50", "o": "וְ/רָאָ֥ה הַ/כֹּהֵ֖ן אֶת הַ/נָּ֑גַע וְ/הִסְגִּ֥יר אֶת הַ/נֶּ֖גַע שִׁבְעַ֥ת יָמִֽים", "en": {"kjv": "And the priest shall look upon the plague, and shut up it that hath the plague seven days:", "web": "The priest shall examine the plague, and isolate the plague seven days.", "bsb": "And the priest is to examine the mildew and isolate the contaminated fabric for seven days.", "asv": "And the priest shall look upon the plague, and shut up that which hath the plague seven days:", "ylt": "`And the priest hath seen the plague, and hath shut up that which hath the plague, seven days;", "tyndale": "And whe the preast seeth the plage, let him shutt it vpp .vij. dayes,", "dra": "And he shall look upon it and shall shut it up seven days.", "bbe": "And after it has been seen by the priest, the thing which is so marked is to be shut up for seven days:", "geneva": "Then the Priest shall see the plague, and shut vp it that hath the plague, seuen dayes,", "wycliffe": "which schal close it biholden bi seuene daies.", "rotherham": "and the priest shall view the spot,—and shall shut up him that is plagued seven days;", "darby": "And the priest shall look on the sore, and shall shut up [that which hath] the sore seven days.", "twenty": "", "jps": "And the priest shall look upon the plague, and shut up that which hath the plague seven days.", "acv": "And the priest shall look upon the disease, and shut up the disease seven days.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall look upon the plague, and shut up [that which hath] the plague seven days:", "vulgate": "qui consideratam recludet septem diebus;", "brenton": "And the priest shall look upon the plague, and the priest shall set apart that which has the plague seven days."}}, {"v": 51, "ref": "13:51", "o": "וְ/רָאָ֨ה אֶת הַ/נֶּ֜גַע בַּ/יּ֣וֹם הַ/שְּׁבִיעִ֗י כִּֽי פָשָׂ֤ה הַ/נֶּ֨גַע֙ בַּ֠/בֶּגֶד אֽוֹ בַ/שְּׁתִ֤י אֽוֹ בָ/עֵ֨רֶב֙ א֣וֹ בָ/ע֔וֹר לְ/כֹ֛ל אֲשֶׁר יֵעָשֶׂ֥ה הָ/ע֖וֹר לִ/מְלָאכָ֑ה צָרַ֧עַת מַמְאֶ֛רֶת הַ/נֶּ֖גַע טָמֵ֥א הֽוּא", "en": {"kjv": "And he shall look on the plague on the seventh day: if the plague be spread in the garment, either in the warp, or in the woof, or in a skin, or in any work that is made of skin; the plague is a fretting leprosy; it is unclean.", "web": "He shall examine the plague on the seventh day. If the plague has spread in the garment, either in the warp, or in the woof, or in the skin, whatever use the skin is used for, the plague is a destructive mildew. It is unclean.", "bsb": "On the seventh day the priest shall reexamine it, and if the mildew has spread in the fabric, weave, knit, or leather, then regardless of how it is used, it is a harmful mildew; the article is unclean.", "asv": "and he shall look on the plague on the seventh day: if the plague be spread in the garment, either in the warp, or in the woof, or in the skin, whatever service skin is used for; the plague is a fretting leprosy; it is unclean.", "ylt": "and he hath seen the plague on the seventh day, and the plague hath spread in the garment, or in the warp, or in the woof, or in the skin, of all that is made of skin for work; the plague is a fretting leprosy, it is unclean.", "tyndale": "and let him loke on the plage the seuenth daye. yf it be increased in the cloth: whether it be in the warpe or wolfe or in a skynne or in any thynge that is made of skynne, then the plage is a fretynge leprosye and it is vncleane:", "dra": "And on the seventh day when he looketh on it again, if he find that it is grown, it is a fixed leprosy. He shall judge the garment unclean, and every thing wherein it shall be found.", "bbe": "And he is to see the mark on the seventh day; if the mark is increased in the clothing, or in the threads of the material, or in the leather, whatever the leather is used for, it is the disease biting into it: it is unclean.", "geneva": "And shall looke on the plague the seuenth day: if the plague growe in the garment or in the warpe, or in the woofe, or in the skinne, or in any thing that is made of skin, that plague is a fretting leprosie and vncleane.", "wycliffe": "And eft he schal biholde in the seuenthe dai, and if he perseyueth, that it wexide, it schal be contynuel lepre; he schal deme the cloth defoulid, and al thing in which it is foundun;", "rotherham": "then shall he view the spot, on the seventh day if the spot hath spread in the garment whether in warp or in weft, or in the skin, or anything which may be made of skin for service, the spot is a fretting leprosy, unclean, it is.", "darby": "And he shall see the sore on the seventh day: if the sore have spread in the garment, either in the warp or in the woof, or in a skin, in any work that may be made of skin, the sore is a corroding leprosy: it is unclean.", "twenty": "", "jps": "And he shall look on the plague on the seventh day: if the plague be spread in the garment, or in the warp, or in the woof, or in the skin, whatever service skin is used for, the plague is a malignant leprosy: it is unclean.", "acv": "And he shall look on the disease on the seventh day. If the disease has spread in the garment, either in the warp, or in the woof, or in the skin, whatever service skin is used for, the disease is a fretting leprosy, it is unclean.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall look on the plague on the seventh day: if the plague is spread in the garment, either in the warp, or in the woof, [or] in a skin, [or] in any work that is made of skin: the plague [is] a fretting leprosy; it [is] unclean.", "vulgate": "et die septimo rursus aspiciens si crevisse deprehenderit lepra perseverans est pollutum iudicabit vestimentum et omne in quo fuerit inventa;", "brenton": "And the priest shall look upon the plague on the seventh day; and if the plague be spread in the garment, either in the warp or in the woof, or in the skin, in whatsoever things skins may be used in their workmanship, the plague is a confirmed leprosy; it is unclean."}}, {"v": 52, "ref": "13:52", "o": "וְ/שָׂרַ֨ף אֶת הַ/בֶּ֜גֶד א֥וֹ אֶֽת הַ/שְּׁתִ֣י א֣וֹ אֶת הָ/עֵ֗רֶב בַּ/צֶּ֨מֶר֙ א֣וֹ בַ/פִּשְׁתִּ֔ים א֚וֹ אֶת כָּל כְּלִ֣י הָ/ע֔וֹר אֲשֶׁר יִהְיֶ֥ה ב֖/וֹ הַ/נָּ֑גַע כִּֽי צָרַ֤עַת מַמְאֶ֨רֶת֙ הִ֔וא בָּ/אֵ֖שׁ תִּשָּׂרֵֽף", "en": {"kjv": "He shall therefore burn that garment, whether warp or woof, in woollen or in linen, or any thing of skin, wherein the plague is: for it is a fretting leprosy; it shall be burnt in the fire.", "web": "He shall burn the garment, whether the warp or the woof, in wool or in linen, or anything of skin, in which the plague is: for it is a destructive mildew. It shall be burned in the fire.", "bsb": "He is to burn the fabric, weave, or knit, whether the contaminated item is wool or linen or leather. Since the mildew is harmful, the article must be burned up.", "asv": "And he shall burn the garment, whether the warp or the woof, in woollen or in linen, or anything of skin, wherein the plague is: for it is a fretting leprosy; it shall be burnt in the fire.", "ylt": "`And he hath burnt the garment, or the warp, or the woof, in wool or in linen, or any vessel of skin in which the plague is; for it is a fretting leprosy; with fire it is burnt.", "tyndale": "And that cloth shalbe burnt, ether warpe or wolfe, whether it be wollen or lynen or any thynge that is made of skynne where in the plage is, for it is a fretynge leprosye and shalbe burnt in the fyre.", "dra": "And therefore it shall be burnt with fire.", "bbe": "And the clothing, or the wool or linen material, or anything of leather in which is the disease, is to be burned: for the disease is biting into it; let it be burned in the fire.", "geneva": "And hee shall burne the garment, or the warpe, or the woofe, whether it bee wollen or linen, or any thing that is made of skin, wherein the plague is: for it is a freating leprosie, therefore it shalbe burnt in the fire.", "wycliffe": "and therfor the cloth schal be brent in flawmes.", "rotherham": "Then shall he burn up the garment whether it be in the warp or the weft in wool or in flax, or any utensil of skin, wherein shall be the plague-spot,—for, a fretting leprosy, it is, in fire, shall it be burnt up.", "darby": "And they shall burn the garment, or the warp or the woof, of wool or of linen, or anything of skin, wherein the sore is; for it is a corroding leprosy: it shall be burned with fire.", "twenty": "", "jps": "And he shall burn the garment, or the warp, or the woof, whether it be of wool or of linen, or any thing of skin, wherein the plague is; for it is a malignant leprosy; it shall be burnt in the fire.", "acv": "And he shall burn the garment, whether the warp or the woof, in woolen or in linen, or anything of skin, in which the disease is, for it is a fretting leprosy. It shall be burnt in the fire.", "anderson": "", "haweis": "", "noyes": "", "webster": "He shall therefore burn that garment, whether warp or woof, in woolen or in linen, or any thing of skin, in which the plague is: for it [is] a fretting leprosy; it shall be burnt in the fire.", "vulgate": "et idcirco conburetur flammis;", "brenton": "He shall burn the garment, either the warp or woof in woollen garments or in flaxen, or in any utensil of skin, in which there may be the plague; because it is a confirmed leprosy; it shall be burnt with fire."}}, {"v": 53, "ref": "13:53", "o": "וְ/אִם֮ יִרְאֶ֣ה הַ/כֹּהֵן֒ וְ/הִנֵּה֙ לֹא פָשָׂ֣ה הַ/נֶּ֔גַע בַּ/בֶּ֕גֶד א֥וֹ בַ/שְּׁתִ֖י א֣וֹ בָ/עֵ֑רֶב א֖וֹ בְּ/כָל כְּלִי עֽוֹר", "en": {"kjv": "And if the priest shall look, and, behold, the plague be not spread in the garment, either in the warp, or in the woof, or in any thing of skin;", "web": "“If the priest examines it, and behold, the plague hasn’t spread in the garment, either in the warp, or in the woof, or in anything of skin;", "bsb": "But when the priest reexamines it, if the mildew has not spread in the fabric, weave, knit, or leather article,", "asv": "And if the priest shall look, and, behold, the plague be not spread in the garment, either in the warp, or in the woof, or in anything of skin;", "ylt": "`And if the priest see, and lo, the plague hath not spread in the garment, or in the warp, or in the woof, or in any vessel of skin,", "tyndale": "Yf the preast se that the plage hath freten no further in the cloth: ether in the warpe or wolfe or in what soeuer thynge of skynne it be,", "dra": "But if he see that it is not grown,", "bbe": "And if the priest sees that the mark is not increased in the clothing or in any part of the material or in the leather,", "geneva": "If the Priest yet see that the plague grow not in the garment, or in the woofe, or in whatsoeuer thing of skin it be,", "wycliffe": "That if he seeth that the spotte wexide not, he schal comaunde,", "rotherham": "But if the priest shall take a view, and lo! the spot has not spread, in the garment, either in warp or in weft,—or in any utensil of skin,", "darby": "But if the priest look, and behold, the sore hath not spread in the garment, or in the warp, or in the woof, or in anything of skin,", "twenty": "", "jps": "And if the priest shall look, and, behold, the plague be not spread in the garment, or in the warp, or in the woof, or in any thing of skin;", "acv": "And if the priest shall look, and, behold, the disease has not spread in the garment, either in the warp, or in the woof, or in anything of skin,", "anderson": "", "haweis": "", "noyes": "", "webster": "And if the priest shall look, and behold, the plague is not spread in the garment, either in the warp or in the woof, or in any thing of skin;", "vulgate": "quod si eam viderit non crevisse;", "brenton": "And if the priest should see, and the plague be not spread in the garments, either in the warp or in the woof, or in any utensil of skin,"}}, {"v": 54, "ref": "13:54", "o": "וְ/צִוָּה֙ הַ/כֹּהֵ֔ן וְ/כִ֨בְּס֔וּ אֵ֥ת אֲשֶׁר בּ֖/וֹ הַ/נָּ֑גַע וְ/הִסְגִּיר֥/וֹ שִׁבְעַת יָמִ֖ים שֵׁנִֽית", "en": {"kjv": "Then the priest shall command that they wash the thing wherein the plague is, and he shall shut it up seven days more:", "web": "then the priest shall command that they wash the thing in which the plague is, and he shall isolate it seven more days.", "bsb": "the priest is to order the contaminated article to be washed and isolated for another seven days.", "asv": "then the priest shall command that they wash the thing wherein the plague is, and he shall shut it up seven days more:", "ylt": "then hath the priest commanded, and they have washed that in which the plague is , and he hath shut it up a second seven days.", "tyndale": "then let the preast comaunde the to wasshe the thynge wherein the plage is, and let him shutt it vpp vij. dayes moo.", "dra": "He shall give orders, and they shall wash that part wherein the leprosy is: and he shall shut it up other seven days.", "bbe": "Then the priest will give orders for the thing on which the mark is, to be washed, and to be shut up for seven days more:", "geneva": "Then the Priest shall commaund them to wash the thing wherein the plague is, and he shall shut it vp seuen dayes more.", "wycliffe": "and thei schulen waische that thing wherynne the lepre is, and he schal close it ayen bi seuene othere daies;", "rotherham": "then shall the priest give command, and they shall wash that wherein is the spot,—and he shall shut it up seven days more;", "darby": "then the priest shall command that they wash the thing wherein the sore is, and he shall shut it up seven days a second time.", "twenty": "", "jps": "then the priest shall command that they wash the thing wherein the plague is, and he shall shut it up seven days more.", "acv": "then the priest shall command that they wash the thing in which the disease is, and he shall shut it up seven more days.", "anderson": "", "haweis": "", "noyes": "", "webster": "Then the priest shall command that they wash [the thing] in which the plague [is], and he shall shut it up seven days more:", "vulgate": "praecipiet et lavabunt id in quo lepra est recludetque illud septem diebus aliis;", "brenton": "then the priest shall give directions, and one shall wash that on which there may have been the plague, and the priest shall set it aside a second time for seven days."}}, {"v": 55, "ref": "13:55", "o": "וְ/רָאָ֨ה הַ/כֹּהֵ֜ן אַחֲרֵ֣י הֻכַּבֵּ֣ס אֶת הַ/נֶּ֗גַע וְ֠/הִנֵּה לֹֽא הָפַ֨ךְ הַ/נֶּ֤גַע אֶת עֵינ/וֹ֙ וְ/הַ/נֶּ֣גַע לֹֽא פָשָׂ֔ה טָמֵ֣א ה֔וּא בָּ/אֵ֖שׁ תִּשְׂרְפֶ֑/נּוּ פְּחֶ֣תֶת הִ֔וא בְּ/קָרַחְתּ֖/וֹ א֥וֹ בְ/גַבַּחְתּֽ/וֹ", "en": {"kjv": "And the priest shall look on the plague, after that it is washed: and, behold, if the plague have not changed his colour, and the plague be not spread; it is unclean; thou shalt burn it in the fire; it is fret inward, whether it be bare within or without.", "web": "Then the priest shall examine it, after the plague is washed; and behold, if the plague hasn’t changed its color, and the plague hasn’t spread, it is unclean; you shall burn it in the fire. It is a mildewed spot, whether the bareness is inside or outside.", "bsb": "After it has been washed, the priest is to reexamine it, and if the mildewed article has not changed in appearance, it is unclean. Even though the mildew has not spread, you must burn it, whether the rot is on the front or back.", "asv": "and the priest shall look, after that the plague is washed; and, behold, if the plague have not changed its color, and the plague be not spread, it is unclean; thou shalt burn it in the fire: it is a fret, whether the bareness be within or without.", "ylt": "And the priest hath seen that which hath the plague after it hath been washed, and lo, the plague hath not changed its aspect, and the plague hath not spread, --it is unclean; with fire thou dost burn it; it is a fretting in its back-part or in its front-part.", "tyndale": "And let the preast loke on it agayne after that the plage is wasshed: Yf the plage haue not chaunged his fascion though it be spred no further abrode, it is yet vncleane. And se that ye burne it in the fyre, for it is frete in warde: whether in parte or in all together.", "dra": "And when he shall see that the former colour is not returned, nor yet the leprosy spread, he shall judge it unclean: and shall burn it with fire, for the leprosy has taken hold of the outside of the garment, or through the whole.", "bbe": "And if, after the mark has been washed, the priest sees that the colour of it is not changed and it is not increased, it is to be burned in the fire: the disease is working in it, though the damage may be inside or outside.", "geneva": "Againe ye Priest shall looke on the plague, after it is washed: and if the plague haue not changed his colour, though the plague haue spred no further, it is vncleane: thou shalt burne it in the fire, for it is a fret inwarde, whether the spot bee in the bare place of the whole, or in part thereof.", "wycliffe": "and whanne he seeth the formere face not turned ayen, netheles that nether the lepre wexede, he schal deme that thing vnclene, and he schal brenne it in fier, for lepre is sched in the ouer part of the cloth, ether thorouy al.", "rotherham": "then shall the priest take a view after the plagued garment hath been washed and lo! if the spot hath not changed its look, then though the spot hath not spread, yet unclean, it is, in the fire, shalt thou burn it up,—a sunken spot, it is, in the back thereof, or in the front thereof.", "darby": "And the priest shall look on the sore after the washing, and behold, if the sore have not changed its appearance, and the sore have not spread, it is unclean: thou shalt burn it with fire: it is a fretting sore on what is threadbare or where the nap is gone.", "twenty": "", "jps": "And the priest shall look, after that the plague is washed; and, behold, if the plague have not changed its colour, and the plague be not spread, it is unclean; thou shalt burn it in the fire; it is a fret, whether the bareness be within or without.", "acv": "And the priest shall look, after the disease is washed, and, behold, if the disease has not changed its color, and the disease has not spread, it is unclean. Thou shall burn it in the fire. It is a fret, whether the bareness be inside or outside.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall look on the plague after it is washed: and behold, [if] the plague hath not changed its color, and the plague hath not spread; it [is] unclean; thou shalt burn it in the fire; it [is] fret inward, [whether] it [is] bare within or without.", "vulgate": "et cum viderit faciem quidem pristinam non reversam nec tamen crevisse lepram inmundum iudicabit et igne conburet eo quod infusa sit in superficie vestimenti vel per totum lepra;", "brenton": "And the priest shall look upon it after the plague has been washed; and if this, even the plague, has not changed its appearance, and the plague does not spread, it is unclean; it shall be burnt with fire: it is fixed in the garment, in the warp, or in the woof."}}, {"v": 56, "ref": "13:56", "o": "וְ/אִם֮ רָאָ֣ה הַ/כֹּהֵן֒ וְ/הִנֵּה֙ כֵּהָ֣ה הַ/נֶּ֔גַע אַחֲרֵ֖י הֻכַּבֵּ֣ס אֹת֑/וֹ וְ/קָרַ֣ע אֹת֗/וֹ מִן הַ/בֶּ֨גֶד֙ א֣וֹ מִן הָ/ע֔וֹר א֥וֹ מִן הַ/שְּׁתִ֖י א֥וֹ מִן הָ/עֵֽרֶב", "en": {"kjv": "And if the priest look, and, behold, the plague be somewhat dark after the washing of it; then he shall rend it out of the garment, or out of the skin, or out of the warp, or out of the woof:", "web": "If the priest looks, and behold, the plague has faded after it is washed, then he shall tear it out of the garment, or out of the skin, or out of the warp, or out of the woof:", "bsb": "If the priest examines it and the mildew has faded after it has been washed, he must cut the contaminated section out of the fabric, leather, weave, or knit.", "asv": "And if the priest look, and, behold, the plague be dim after the washing thereof, then he shall rend it out of the garment, or out of the skin, or out of the warp, or out of the woof:", "ylt": "`And if the priest hath seen, and lo, the plague is become weak after it hath been washed, then he hath rent it out of the garment, or out of the skin, or out of the warp, or out of the woof;", "tyndale": "But and yf the preast se that it is somwhat blackysh after that it is wasshed, let him rent it out of the clothe, or out of the skynne or out of the warpe or wolfe.", "dra": "But if the place of the leprosy be somewhat dark, after the garment is washed, he shall tear it off, and divide it from that which is sound.", "bbe": "And if the priest sees that the mark is less bright after the washing, then let him have it cut out of the clothing or the leather or from the threads of the material:", "geneva": "And if the Priest see that the plague bee darker, after that it is washed, he shall cut it out of the garment, or out of the skin, or out of the warpe, or out of the woofe.", "wycliffe": "Ellis if the `place of lepre is derkere, aftir that the cloth is waischun, he schal breke awey that place, and schal departe fro the hool.", "rotherham": "And, if the priest hath taken a view, and lo! the spot is, faint, since it hath been washed, then shall he rend it out of the garment, or out of the skin, whether out of the warp or out of the weft;", "darby": "But if the priest look, and behold, the sore hath become pale after the washing of it, then he shall rend it from the garment, or from the skin, or from the warp, or from the woof.", "twenty": "", "jps": "And if the priest look, and, behold, the plague be dim after the washing thereof, then he shall rend it out of the garment, or out of the skin, or out of the warp, or out of the woof.", "acv": "And if the priest looks, and, behold, the disease is dim after the washing of it, then he shall tear it out of the garment, or out of the skin, or out of the warp, or out of the woof.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if the priest shall look, and behold, the plague [is] somewhat dark after the washing of it; then he shall rend it out of the garment, or out of the skin, or out of the warp, or out of the woof:", "vulgate": "sin autem obscurior fuerit locus leprae postquam vestis est lota abrumpet eum et a solido dividet;", "brenton": "And if the priest should look, and the spot be dark after it has been washed, he shall tear it off from the garment, either from the warp or from the woof, or from the skin."}}, {"v": 57, "ref": "13:57", "o": "וְ/אִם תֵּרָאֶ֨ה ע֜וֹד בַּ֠/בֶּגֶד אֽוֹ בַ/שְּׁתִ֤י אֽוֹ בָ/עֵ֨רֶב֙ א֣וֹ בְ/כָל כְּלִי ע֔וֹר פֹּרַ֖חַת הִ֑וא בָּ/אֵ֣שׁ תִּשְׂרְפֶ֔/נּוּ אֵ֥ת אֲשֶׁר בּ֖/וֹ הַ/נָּֽגַע", "en": {"kjv": "And if it appear still in the garment, either in the warp, or in the woof, or in any thing of skin; it is a spreading plague: thou shalt burn that wherein the plague is with fire.", "web": "and if it appears again in the garment, either in the warp, or in the woof, or in anything of skin, it is spreading. You shall burn with fire that in which the plague is.", "bsb": "But if it reappears in the fabric, weave, or knit, or on any leather article, it is spreading. You must burn the contaminated article.", "asv": "and if it appear still in the garment, either in the warp, or in the woof, or in anything of skin, it is breaking out: thou shalt burn that wherein the plague is with fire.", "ylt": "and if it still be seen in the garment, or in the warp, or in the woof, or in any vessel of skin, it is a fretting; with fire thou dost burn it--that in which the plague is .", "tyndale": "But and yf it apeare any moare in the cloth ether in the warpe or in the wolfe or in any thynge made of skynne than it is a waxynge plage. And se that ye burne that with fyre, where in the plage is.", "dra": "And if after this there appear in those places that before were without spot, a flying and wandering leprosy: it must be burnt with fire.", "bbe": "And if the mark is still seen in the clothing or in the threads of the material or in the leather, it is the disease coming out: the thing in which the disease is will have to be burned with fire.", "geneva": "And if it appeare stil in ye garment or in the warpe, or in the woofe, or in any thing made of skin, it is a spreading leprie: thou shalt burne the thing wherein the plague is, in the fire.", "wycliffe": "That if fleynge lepre and vnstidefast apperith ferthermore in these places, that weren vnwemmed bifore, it owith be brent in fier; if it ceessith,", "rotherham": "and, if it appear still in the garment—either in the warp or in the weft, or in any utensil of skin, a breaking out, it is,—in the fire, shalt thou burn up that wherein is the plague.", "darby": "And if it appear still in the garment, or in the warp, or in the woof, or in anything of skin, it is a [leprosy] breaking out: thou shalt burn with fire that wherein the sore is.", "twenty": "", "jps": "And if it appear still in the garment, or in the warp, or in the woof, or in any thing of skin, it is breaking out, thou shalt burn that wherein the plague is with fire.", "acv": "And if it still appears in the garment, either in the warp, or in the woof, or in anything of skin, it is breaking out. Thou shall burn that in which the disease is with fire.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if it shall appear still in the garment, either in the warp, or in the woof, or in any thing of skin; it [is] a spreading [plague]: thou shalt burn that in which the plague [is], with fire.", "vulgate": "quod si ultra apparuerit in his locis quae prius inmaculata erant lepra volatilis et vaga debet igne conburi;", "brenton": "And if it should still appear in the garment, either in the warp or in the woof, or in any article of skin, it is a leprosy bursting forth: that wherein is the plague shall be burnt with fire."}}, {"v": 58, "ref": "13:58", "o": "וְ/הַ/בֶּ֡גֶד אֽוֹ הַ/שְּׁתִ֨י אוֹ הָ/עֵ֜רֶב אֽוֹ כָל כְּלִ֤י הָ/עוֹר֙ אֲשֶׁ֣ר תְּכַבֵּ֔ס וְ/סָ֥ר מֵ/הֶ֖ם הַ/נָּ֑גַע וְ/כֻבַּ֥ס שֵׁנִ֖ית וְ/טָהֵֽר", "en": {"kjv": "And the garment, either warp, or woof, or whatsoever thing of skin it be, which thou shalt wash, if the plague be departed from them, then it shall be washed the second time, and shall be clean.", "web": "The garment, either the warp, or the woof, or whatever thing of skin it is, which you shall wash, if the plague has departed from them, then it shall be washed the second time, and it will be clean.”", "bsb": "If the mildew disappears from the fabric, weave, or knit, or any leather article after washing, then it is to be washed again, and it will be clean.", "asv": "And the garment, either the warp, or the woof, or whatsoever thing of skin it be, which thou shalt wash, if the plague be departed from them, then it shall be washed the second time, and shall be clean.", "ylt": "`And the garment, or the warp, or the woof, or any vessel of skin which thou dost wash when the plague hath turned aside from them, then it hath been washed a second time, and hath been clean.", "tyndale": "Moreouer the cloth ether warpe or wolfe or what soeuer thinge of skynne it be which thou hast wasshed and the plage be departed from it, shalbe wasshed once agayne: and then it is cleane.", "dra": "If it cease, he shall wash with water the parts that are pure, the second time: and they shall be clean.", "bbe": "And the material of the clothing, or anything of skin, which has been washed, if the mark has gone out of it, let it be washed a second time and it will be clean.", "geneva": "If thou hast washed ye garment or ye warpe, or ye woofe, or whatsouer thing of skin it be, if the plague be departed therefrom, then shall it be washed the second time, and be cleane.", "wycliffe": "he schal waische the secounde tyme tho thingis that ben cleene, and tho schulen be cleene.", "rotherham": "But, as for the garment—whether the warp or the weft or any utensil of skin which thou shalt wash, and the plague shall depart therefrom, then shall it be washed a second time, and shall be clean.", "darby": "But the garment, or the warp, or the woof, or whatever thing of skin which thou hast washed, and the sore departeth from them, it shall be washed a second time, and it is clean.", "twenty": "", "jps": "And the garment, or the warp, or the woof, or whatsoever thing of skin it be, which thou shalt wash, if the plague be departed from them, then it shall be washed the second time, and shall be clean.", "acv": "And the garment, either the warp, or the woof, or whatever thing of skin it be, which thou shall wash, if the disease has departed from them, then it shall be washed the second time, and shall be clean.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the garment, either warp, or woof, or whatever thing of skin [it is], which thou shalt wash, if the plague hath departed from them, then it shall be washed the second time, and shall be clean.", "vulgate": "si cessaverit lavabit ea quae pura sunt secundo et munda erunt;", "brenton": "And the garment, or the warp, or the woof, or any article of skin, which shall be washed, and the plague depart from it, shall also be washed again, and shall be clean."}}, {"v": 59, "ref": "13:59", "o": "זֹ֠את תּוֹרַ֨ת נֶֽגַע צָרַ֜עַת בֶּ֥גֶד הַ/צֶּ֣מֶר א֣וֹ הַ/פִּשְׁתִּ֗ים א֤וֹ הַ/שְּׁתִי֙ א֣וֹ הָ/עֵ֔רֶב א֖וֹ כָּל כְּלִי ע֑וֹר לְ/טַהֲר֖/וֹ א֥וֹ לְ/טַמְּאֽ/וֹ", "en": {"kjv": "This is the law of the plague of leprosy in a garment of woollen or linen, either in the warp, or woof, or any thing of skins, to pronounce it clean, or to pronounce it unclean.", "web": "This is the law of the plague of mildew in a garment of wool or linen, either in the warp, or the woof, or in anything of skin, to pronounce it clean, or to pronounce it unclean.", "bsb": "This is the law concerning a mildew contamination in wool or linen fabric, weave, or knit, or any leather article, for pronouncing it clean or unclean.”", "asv": "This is the law of the plague of leprosy in a garment of woollen or linen, either in the warp, or the woof, or anything of skin, to pronounce it clean, or to pronounce it unclean.", "ylt": "`This is the law of a plague of leprosy in a garment of wool or of linen, or of the warp or of the woof, or of any vessel of skin, to pronounce it clean or to pronounce it unclean.'", "tyndale": "This is the lawe of the plage of leprosye in a cloth whether it be wolle or lynen: eyther whether it be in the warpe or wolfe or in any thynge made of skynnes, to make it cleane or vncleane.", "dra": "This is the law touching the leprosy of any woollen or linen garment, either in the warp or woof, or any thing of skins: how it ought to be cleaned, or pronounced unclean.", "bbe": "This is the law about the leper's disease in the thread of wool or linen material, in clothing or in anything of skin, saying how it is to be judged clean or unclean.", "geneva": "This is the lawe of the plague of leprosie in a garment of wollen or linnen, or in the warpe, or in the woofe, or in any thing of skin, to make it cleane or vncleane.", "wycliffe": "This is the lawe of lepre of cloth, wollun and lynnun, of warp and of oof, and of al purtenaunce of skiyn, hou it owith to be clensyd, ethir `to be defoulid.", "rotherham": "This, is the law as to the plague-spot of leprosy, in a garment of wool or of flax, whether in the warp or the weft, or in any utensil of skin,—To pronounce it clean, or to pronounce it unclean.", "darby": "This is the law of the sore of leprosy in a garment of wool or linen, or in the warp, or in the woof, or in anything of skin, to cleanse it, or to pronounce it unclean.", "twenty": "", "jps": "This is the law of the plague of leprosy in a garment of wool or linen, or in the warp, or in the woof, or in any thing of skin, to pronounce it clean, or to pronounce it unclean.", "acv": "This is the law of a leprous disease in a garment of woolen or linen, either in the warp, or the woof, or anything of skin, to pronounce it clean, or to pronounce it unclean.", "anderson": "", "haweis": "", "noyes": "", "webster": "This [is] the law of the plague of leprosy in a garment of woolen or linen, either in the warp or woof, or any thing of skins, to pronounce it clean, or to pronounce it unclean.", "vulgate": "ista est lex leprae vestimenti lanei et linei staminis atque subteminis omnisque supellectilis pelliciae quomodo mundari debeat vel contaminari;", "brenton": "This is the law of the plague of leprosy of a woollen or linen garment, either of the warp, or woof, or any leathern article, to pronounce it clean or unclean."}}]}, {"c": 14, "verses": [{"v": 1, "ref": "14:1", "o": "וַ/יְדַבֵּ֥ר יְהוָ֖ה אֶל מֹשֶׁ֥ה לֵּ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh spoke to Moses, saying,", "bsb": "Then the LORD said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde spake vnto Moses saynge:", "dra": "And the Lord spoke to Moses, saying:", "bbe": "And the Lord said to Moses,", "geneva": "And the Lord spake vnto Moses, saying,", "wycliffe": "And the Lord spak to Moises, and seide, This is the custom of a leprouse man,", "rotherham": "And Yahweh spake unto Moses, saying—", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses, saying:", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "locutusque est Dominus ad Mosen dicens;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 2, "ref": "14:2", "o": "זֹ֤את תִּֽהְיֶה֙ תּוֹרַ֣ת הַ/מְּצֹרָ֔ע בְּ/י֖וֹם טָהֳרָת֑/וֹ וְ/הוּבָ֖א אֶל הַ/כֹּהֵֽן", "en": {"kjv": "This shall be the law of the leper in the day of his cleansing: He shall be brought unto the priest:", "web": "“This shall be the law of the leper in the day of his cleansing. He shall be brought to the priest,", "bsb": "“This is the law for the one afflicted with a skin disease on the day of his cleansing, when he is brought to the priest.", "asv": "This shall be the law of the leper in the day of his cleansing: he shall be brought unto the priest:", "ylt": "`This is a law of the leper, in the day of his cleansing, that he hath been brought in unto the priest,", "tyndale": "this is the lawe of a leper when he shalbe clesed. he shalbe broughte vnto the preast,", "dra": "This is the rite of a leper, when he is to be cleansed. He shall be brought to the priest:", "bbe": "This is the law of the leper on the day when he is made clean: he is to be taken to the priest;", "geneva": "This is the law of the leper in the day of his clensing: that is, he shall be brought vnto the Priest,", "wycliffe": "whanne he schal be clensid. He schal be brouyt to the preest,", "rotherham": "This, shall be the law of the leper, in the day when he is declared clean,—he shall be brought in unto the priest;", "darby": "This shall be the law of the leper in the day of his cleansing: he shall be brought unto the priest,", "twenty": "", "jps": "This shall be the law of the leper in the day of his cleansing: he shall be brought unto the priest.", "acv": "This shall be the law of the man with a leprous disease in the day of his cleansing: He shall be brought to the priest,", "anderson": "", "haweis": "", "noyes": "", "webster": "This shall be the law of the leper in the day of his cleansing: He shall be brought to the priest:", "vulgate": "hic est ritus leprosi quando mundandus est adducetur ad sacerdotem;", "brenton": "This is the law of the leper: in whatsoever day he shall have been cleansed, then shall he be brought to the priest."}}, {"v": 3, "ref": "14:3", "o": "וְ/יָצָא֙ הַ/כֹּהֵ֔ן אֶל מִ/ח֖וּץ לַֽ/מַּחֲנֶ֑ה וְ/רָאָה֙ הַ/כֹּהֵ֔ן וְ/הִנֵּ֛ה נִרְפָּ֥א נֶֽגַע הַ/צָּרַ֖עַת מִן הַ/צָּרֽוּעַ", "en": {"kjv": "And the priest shall go forth out of the camp; and the priest shall look, and, behold, if the plague of leprosy be healed in the leper;", "web": "and the priest shall go out of the camp. The priest shall examine him, and behold, if the plague of leprosy is healed in the leper,", "bsb": "The priest is to go outside the camp to examine him, and if the skin disease of the afflicted person has healed,", "asv": "and the priest shall go forth out of the camp; and the priest shall look; and, behold, if the plague of leprosy be healed in the leper,", "ylt": "and the priest hath gone out unto the outside of the camp, and the priest hath seen, and lo, the plague of leprosy hath ceased from the leper,", "tyndale": "and the preast shall goo out without the hoste and loke apo him. Yf the plage of leprosye be healed in the leper,", "dra": "Who going out of the camp, when he shall find that the leprosy is cleansed,", "bbe": "And the priest is to go outside the tent-circle; and if, after looking, the priest sees that the mark of the disease has gone from him,", "geneva": "And the Priest shall go out of the campe, and the Priest shall consider him: and if the plague of leprosie be healed in the leper,", "wycliffe": "which preest schal go out of the castels, and whanne he schal fynde that the lepre is clensid,", "rotherham": "then shall the priest go forth unto the outside of the camp,—and the priest shall take a view, and lo! if the plague of leprosy hath been healed out of the leper,;", "darby": "and the priest shall go out of the camp; and when the priest looketh, and behold, the sore of leprosy is healed in the leper,", "twenty": "", "jps": "And the priest shall go forth out of the camp; and the priest shall look, and, behold, if the plague of leprosy be healed in the leper;", "acv": "and the priest shall go forth out of the camp. And the priest shall look, and, behold, if a leprous disease be healed in the man with a leprous disease,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall go forth out of the camp: and the priest shall look, and behold, [if] the plague of leprosy is healed in the leper;", "vulgate": "qui egressus e castris cum invenerit lepram esse mundatam;", "brenton": "And the priest shall come forth out of the camp, and the priest shall look, and, behold, the plague of the leprosy is removed from the leper."}}, {"v": 4, "ref": "14:4", "o": "וְ/צִוָּה֙ הַ/כֹּהֵ֔ן וְ/לָקַ֧ח לַ/מִּטַּהֵ֛ר שְׁתֵּֽי צִפֳּרִ֥ים חַיּ֖וֹת טְהֹר֑וֹת וְ/עֵ֣ץ אֶ֔רֶז וּ/שְׁנִ֥י תוֹלַ֖עַת וְ/אֵזֹֽב", "en": {"kjv": "Then shall the priest command to take for him that is to be cleansed two birds alive and clean, and cedar wood, and scarlet, and hyssop:", "web": "then the priest shall command them to take for him who is to be cleansed two living clean birds, and cedar wood, and scarlet, and hyssop.", "bsb": "the priest shall order that two live clean birds, cedar wood, scarlet yarn, and hyssop be brought for the one to be cleansed.", "asv": "then shall the priest command to take for him that is to be cleansed two living clean birds, and cedar wood, and scarlet, and hyssop:", "ylt": "and the priest hath commanded, and he hath taken for him who is to be cleansed, two clean living birds, and cedar wood, and scarlet, and hyssop.", "tyndale": "the shall the preast commaunde that there be brought for hi that shalbe clensed .ij. lyuynge byrdes that are cleane, ad cipresse wodd, and a pece of purple cloth and ysope.", "dra": "Shall command him that is to be purified, to offer for himself two living sparrows, which it is lawful to eat, and cedar wood, and scarlet, and hyssop.", "bbe": "Then the priest is to give orders to take, for him who is to be made clean, two living clean birds and some cedar wood and red thread and hyssop.", "geneva": "Then shall the Priest commaund to take for him that is clensed, two sparrowes aliue and cleane, and cedar wood and a skarlet lace, and hyssope.", "wycliffe": "he schal comaunde to the man which is clensid, that he offre for hym silf twei quyke sparewis, whiche it is leueful to ete, and a `tree of cedre, and vermylyoun , and isope.", "rotherham": "then shall the priest give command,—and there shall be taken—for him that is to be cleansed—two living clean birds,—and cedar wood, and crimson am hyssop;", "darby": "then shall the priest command to take for him that is to be cleansed two clean living birds, and cedar-wood, and scarlet, and hyssop.", "twenty": "", "jps": "then shall the priest command to take for him that is to be cleansed two living clean birds, and cedar-wood, and scarlet, and hyssop.", "acv": "then the priest shall command to take two living clean birds, and cedar wood, and scarlet, and hyssop for him who is to be cleansed.", "anderson": "", "haweis": "", "noyes": "", "webster": "Then shall the priest command to take for him that is to be cleansed two birds alive, [and] clean, and cedar-wood, and scarlet, and hyssop.", "vulgate": "praecipiet ei qui purificatur ut offerat pro se duos passeres vivos quos vesci licitum est et lignum cedrinum vermiculumque et hysopum;", "brenton": "And the priest shall give directions, and they shall take for him that is cleansed two clean live birds, and cedar wood, and spun scarlet, and hyssop."}}, {"v": 5, "ref": "14:5", "o": "וְ/צִוָּה֙ הַ/כֹּהֵ֔ן וְ/שָׁחַ֖ט אֶת הַ/צִּפּ֣וֹר הָ/אֶחָ֑ת אֶל כְּלִי חֶ֖רֶשׂ עַל מַ֥יִם חַיִּֽים", "en": {"kjv": "And the priest shall command that one of the birds be killed in an earthen vessel over running water:", "web": "The priest shall command them to kill one of the birds in an earthen vessel over running water.", "bsb": "Then the priest shall command that one of the birds be slaughtered over fresh water in a clay pot.", "asv": "and the priest shall command to kill one of the birds in an earthen vessel over running water.", "ylt": "`And the priest hath commanded, and he hath slaughtered the one bird upon an earthen vessel, over running water;", "tyndale": "And the preast shall comaunde that one of the byrdes be kylled ouer an erthe vessell of runnynge water.", "dra": "And he shall command one of the sparrows to be immolated in an earthen vessel over living waters.", "bbe": "And the priest will give orders for one of the birds to be put to death in a vessel made of earth, over flowing water.", "geneva": "And the Priest shall commaund to kill one of the birdes ouer pure water in an earthen vessell.", "wycliffe": "And the preest schal comaunde that oon of the sparewes be offrid in `a vessel of erthe,", "rotherham": "and the priest shall give command, and one bird shall be slain,—within an earthen vessel over living water:", "darby": "And the priest shall command that one bird be killed in an earthen vessel over running water:", "twenty": "", "jps": "And the priest shall command to kill one of the birds in an earthen vessel over running water.", "acv": "And the priest shall command to kill one of the birds in an earthen vessel over running water.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall command that one of the birds be killed in an earthen vessel, over running water.", "vulgate": "et unum e passeribus immolari iubebit in vase fictili super aquas viventes;", "brenton": "And the priest shall give direction, and they shall kill one bird over an earthen vessel over running water."}}, {"v": 6, "ref": "14:6", "o": "אֶת הַ/צִּפֹּ֤ר הַֽ/חַיָּה֙ יִקַּ֣ח אֹתָ֔/הּ וְ/אֶת עֵ֥ץ הָ/אֶ֛רֶז וְ/אֶת שְׁנִ֥י הַ/תּוֹלַ֖עַת וְ/אֶת הָ/אֵזֹ֑ב וְ/טָבַ֨ל אוֹתָ֜/ם וְ/אֵ֣ת הַ/צִּפֹּ֣ר הַֽ/חַיָּ֗ה בְּ/דַם֙ הַ/צִּפֹּ֣ר הַ/שְּׁחֻטָ֔ה עַ֖ל הַ/מַּ֥יִם הַֽ/חַיִּֽים", "en": {"kjv": "As for the living bird, he shall take it, and the cedar wood, and the scarlet, and the hyssop, and shall dip them and the living bird in the blood of the bird that was killed over the running water:", "web": "As for the living bird, he shall take it, and the cedar wood, and the scarlet, and the hyssop, and shall dip them and the living bird in the blood of the bird that was killed over the running water.", "bsb": "And he is to take the live bird together with the cedar wood, scarlet yarn, and hyssop, and dip them into the blood of the bird that was slaughtered over the fresh water.", "asv": "As for the living bird, he shall take it, and the cedar wood, and the scarlet, and the hyssop, and shall dip them and the living bird in the blood of the bird that was killed over the running water:", "ylt": "as to the living bird, he taketh it, and the cedar wood, and the scarlet, and the hyssop, and hath dipped them and the living bird in the blood of the slaughtered bird, over the running water,", "tyndale": "And the preast shall take the lyuynge byrde and the cypresse wodd and the purple ad the ysope, ad shall dyppe the and the lyuynge byrde in the bloude of the slayne byrde and in the renynge water", "dra": "But the other that is alive, he shall dip, with the cedar wood, and the scarlet and the hyssop, in the blood of the sparrow that is immolated:", "bbe": "And he will take the living bird and the wood and the red thread and the hyssop and put them in the blood of the bird which was put to death over flowing water.", "geneva": "After, he shall take the liue sparowe with the cedar wood, and the skarlet lace, and the hyssope, and shall dip them and the liuing sparowe in the blood of the sparowe slaine, ouer the pure water,", "wycliffe": "on quyke watris; sotheli he schal dippe the tother sparewe quyk with the `tre of cedre, and with a reed threed and ysope, in the blood of the sparewe offrid,", "rotherham": "as for the living bird, he shall take, it, and the cedar wood and the crimson, and the hyssop,—and shall dip them and the living bird, in the blood of the bird that hath been slain over the living water;", "darby": "as to the living bird — he shall take it, and the cedar-wood, and the scarlet, and the hyssop, and dip them and the living bird in the blood of the bird that was killed over the running water;", "twenty": "", "jps": "As for the living bird, he shall take it, and the cedar-wood, and the scarlet, and the hyssop, and shall dip them and the living bird in the blood of the bird that was killed over the running water.", "acv": "As for the living bird, he shall take it, and the cedar wood, and the scarlet, and the hyssop, and shall dip them and the living bird in the blood of the bird that was killed over the running water.", "anderson": "", "haweis": "", "noyes": "", "webster": "As for the living bird, he shall take it, and the cedar-wood, and the scarlet, and the hyssop, and shall dip them, and the living bird, in the blood of the bird [that was] killed over the running water.", "vulgate": "alium autem vivum cum ligno cedrino et cocco et hysopo tinguet in sanguine passeris immolati;", "brenton": "And as for the living bird he shall take it, and the cedar wood, and the spun scarlet, and the hyssop, and he shall dip them and the living bird into the blood of the bird that was slain over running water."}}, {"v": 7, "ref": "14:7", "o": "וְ/הִזָּ֗ה עַ֧ל הַ/מִּטַּהֵ֛ר מִן הַ/צָּרַ֖עַת שֶׁ֣בַע פְּעָמִ֑ים וְ/טִ֣הֲר֔/וֹ וְ/שִׁלַּ֛ח אֶת הַ/צִּפֹּ֥ר הַֽ/חַיָּ֖ה עַל פְּנֵ֥י הַ/שָּׂדֶֽה", "en": {"kjv": "And he shall sprinkle upon him that is to be cleansed from the leprosy seven times, and shall pronounce him clean, and shall let the living bird loose into the open field.", "web": "He shall sprinkle on him who is to be cleansed from the leprosy seven times, and shall pronounce him clean, and shall let the living bird go into the open field.", "bsb": "Seven times he shall sprinkle the one to be cleansed of the skin disease. Then he shall pronounce him clean and release the live bird into the open field.", "asv": "and he shall sprinkle upon him that is to be cleansed from the leprosy seven times, and shall pronounce him clean, and shall let go the living bird into the open field.", "ylt": "and he hath sprinkled on him who is to be cleansed from the leprosy seven times, and hath pronounced him clean, and hath sent out the living bird on the face of the field.", "tyndale": "and sprinkle it apon him that must be clensed of his leprosye .vij. tymes and clense him and shall let the lyuynge byrde goo fre in to the feldes.", "dra": "Wherewith he shall sprinkle him that is to be cleansed seven times, that he may be rightly purified. And he shall let go the living sparrow, that it may fly into the field.", "bbe": "And shaking it seven times over the man who is to be made clean, he will say that he is clean and will let the living bird go free into the open country.", "geneva": "And hee shall sprinkle vpon him, that must be clensed of his leprosie, seuen times, and clense him, and shall let goe the liue sparowe into the broad fielde.", "wycliffe": "with which he schal sprenge seuensithis hym that schal be clensid, that he be purgid riytfuli; and he schal delyuere the quyk sparewe, that it fle in to the feeld.", "rotherham": "and shall sprinkle upon him that is to be cleansed from the leprosy, seven times,—and shall pronounce him clean, and shall let go the living bird over the face of the field.", "darby": "and he shall sprinkle upon him that is to be cleansed from the leprosy seven times, and shall pronounce him clean, and shall let the living bird loose into the open field.", "twenty": "", "jps": "And he shall sprinkle upon him that is to be cleansed from the leprosy seven times, and shall pronounce him clean, and shall let go the living bird into the open field.", "acv": "And he shall sprinkle seven times upon him who is to be cleansed from the leprous disease, and shall pronounce him clean, and shall let the living bird go into the open field.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall sprinkle upon him that is to be cleansed from the leprosy seven times, and shall pronounce him clean, and shall let the living bird loose into the open field.", "vulgate": "quo asperget illum qui mundandus est septies ut iure purgetur et dimittet passerem vivum ut in agrum avolet;", "brenton": "And he shall sprinkle seven times upon him that was cleansed of his leprosy, and he shall be clean; and he shall let go the living bird into the field."}}, {"v": 8, "ref": "14:8", "o": "וְ/כִבֶּס֩ הַ/מִּטַּהֵ֨ר אֶת בְּגָדָ֜י/ו וְ/גִלַּ֣ח אֶת כָּל שְׂעָר֗/וֹ וְ/רָחַ֤ץ בַּ/מַּ֨יִם֙ וְ/טָהֵ֔ר וְ/אַחַ֖ר יָב֣וֹא אֶל הַֽ/מַּחֲנֶ֑ה וְ/יָשַׁ֛ב מִ/ח֥וּץ לְ/אָהֳל֖/וֹ שִׁבְעַ֥ת יָמִֽים", "en": {"kjv": "And he that is to be cleansed shall wash his clothes, and shave off all his hair, and wash himself in water, that he may be clean: and after that he shall come into the camp, and shall tarry abroad out of his tent seven days.", "web": "“He who is to be cleansed shall wash his clothes, and shave off all his hair, and bathe himself in water; and he shall be clean. After that he shall come into the camp, but shall dwell outside his tent seven days.", "bsb": "The one being cleansed must wash his clothes, shave off all his hair, and bathe with water; then he will be ceremonially clean. Afterward, he may enter the camp, but he must remain outside his tent for seven days.", "asv": "And he that is to be cleansed shall wash his clothes, and shave off all his hair, and bathe himself in water; and he shall be clean: and after that he shall come into the camp, but shall dwell outside his tent seven days.", "ylt": "`And he who is to be cleansed hath washed his garments, and hath shaved all his hair, and hath bathed with water, and hath been clean, and afterwards he doth come in unto the camp, and hath dwelt at the outside of his tent seven days.", "tyndale": "And he that is clesed shall wasshe his clothes and shaue off all his heer ad wasshe himselfe in water, and the he is cleane. And after that he shall come in to the hoste but shall tarye without his tet .vij. dayes.", "dra": "And when the man hath washed his clothes, he shall shave all the hair of his body, and shall be washed with water: and being purified he shall enter into the camp, yet so that he tarry without his own tent seven days.", "bbe": "And he who is to be made clean will have his clothing washed and his hair cut and have a bath, and he will be clean. And after that he will come back to the tent-circle; but he is to keep outside his tent for seven days.", "geneva": "Then he that shall be clensed, shall wash his clothes, and shaue off all his heare, and wash himselfe in water, so he shalbe cleane: after that shall he come into the host, but shall tary without his tent seuen dayes.", "wycliffe": "And whanne the man hath waische hise clothis, he schal schaue alle the heeris of the bodi, and he schal be waischun in watir, and he schal be clensid, and he schal entre in to the castels; so oneli that he dwelle without his tabernacle bi seuene daies;", "rotherham": "And he that is to be declared clean shall wash his clothes and shave off all his hair, and bathe in water, and be clean, and, afterwards, shall he come into the camp,—and dwell outside his tent, seven days;", "darby": "And he that is to be cleansed shall wash his garments, and shave all his hair, and bathe in water, and he shall be clean; and afterwards shall he come into the camp, and shall abide outside his tent seven days.", "twenty": "", "jps": "And he that is to be cleansed shall wash his clothes, and shave off all his hair, and bathe himself in water, and he shall be clean; and after that he may come into the camp, but shall dwell outside his tent seven days.", "acv": "And he who is to be cleansed shall wash his clothes, and shave off all his hair, and bathe himself in water, and he shall be clean. And after that he shall come into the camp, but shall dwell outside his tent seven days.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he that is to be cleansed shall wash his clothes, and shave off all his hair, and wash himself in water, that he may be clean: and after that he shall come into the camp, and shall tarry abroad out of his tent seven days.", "vulgate": "cumque laverit homo vestimenta sua radet omnes pilos corporis et lavabitur aqua purificatusque ingredietur castra ita dumtaxat ut maneat extra tabernaculum suum septem diebus;", "brenton": "and the man that has been cleansed shall wash his garments, and shall shave off all his hair, and shall wash himself in water, and shall be clean; and after that he shall go into the camp, and shall remain out of his house seven days."}}, {"v": 9, "ref": "14:9", "o": "וְ/הָיָה֩ בַ/יּ֨וֹם הַ/שְּׁבִיעִ֜י יְגַלַּ֣ח אֶת כָּל שְׂעָר֗/וֹ אֶת רֹאשׁ֤/וֹ וְ/אֶת זְקָנ/וֹ֙ וְ/אֵת֙ גַּבֹּ֣ת עֵינָ֔י/ו וְ/אֶת כָּל שְׂעָר֖/וֹ יְגַלֵּ֑חַ וְ/כִבֶּ֣ס אֶת בְּגָדָ֗י/ו וְ/רָחַ֧ץ אֶת בְּשָׂר֛/וֹ בַּ/מַּ֖יִם וְ/טָהֵֽר", "en": {"kjv": "But it shall be on the seventh day, that he shall shave all his hair off his head and his beard and his eyebrows, even all his hair he shall shave off: and he shall wash his clothes, also he shall wash his flesh in water, and he shall be clean.", "web": "It shall be on the seventh day, that he shall shave all his hair off his head and his beard and his eyebrows, even all his hair he shall shave off. He shall wash his clothes, and he shall bathe his body in water, then he shall be clean.", "bsb": "On the seventh day he must shave off all his hair—his head, his beard, his eyebrows, and the rest of his hair. He must wash his clothes and bathe himself with water, and he will be clean.", "asv": "And it shall be on the seventh day, that he shall shave all his hair off his head and his beard and his eyebrows, even all his hair he shall shave off: and he shall wash his clothes, and he shall bathe his flesh in water, and he shall be clean.", "ylt": "`And it hath been, on the seventh day--he shaveth all his hair, his head, and his beard, and his eyebrows, even all his hair he doth shave, and he hath washed his garments, and hath bathed his flesh with water, and hath been clean.", "tyndale": "Whe the seuenth daye is come, he shall shaue off al his heer both apo his heade ad his berde ad on his browes: ad eue all the heer that is on him, shalbe shauen off. And he shall wasshe his clothes and his flesh in water and then he shalbe cleane.", "dra": "And on the seventh day he shall shave the hair of his head, and his beard and his eyebrows, and the hair of all his body. And having washed again his clothes, and his body,", "bbe": "And on the seventh day he is to have all the hair cut off his head and his chin and over his eyes--all his hair is to be cut off--and he will have his clothing washed and his body bathed in water and he will be clean.", "geneva": "So in the seuenth day hee shall shaue off all his heare, both his head, and his beard, and his eye browes: euen all his heare shall he shaue, and shall wash his clothes and shall wash his flesh in water: so he shalbe cleane.", "wycliffe": "and that in the seuenthe dai he schaue the heeris of the heed, and the beerd, and brewis, and the heeris of al the bodi. And whanne the clothis and bodi ben waischun,", "rotherham": "and it shall be on the seventh day, that he shall shave off all the hair of his head, and his beard, and his eyebrows, even all his hair, shall he shave off,—and shall wash his clothes and bathe his flesh in water so shall he be clean.", "darby": "And it shall come to pass on the seventh day, that he shall shave all his hair, his head, and his beard, and his eyebrows, even all his hair shall he shave, and he shall wash his garments, and shall bathe his flesh in water, and he is clean.", "twenty": "", "jps": "And it shall be on the seventh day, that he shall shave all his hair off his head and his beard and his eyebrows, even all his hair he shall shave off; and he shall wash his clothes, and he shall bathe his flesh in water, and he shall be clean.", "acv": "And it shall be on the seventh day, that he shall shave all his hair off his head and his beard and his eyebrows, even all his hair he shall shave off. And he shall wash his clothes, and he shall bathe his flesh in water, and he shall be clean.", "anderson": "", "haweis": "", "noyes": "", "webster": "But it shall be on the seventh day, that he shall shave all his hair off his head, and his beard, and his eye-brows, even all his hair he shall shave off; and he shall wash his clothes, also he shall wash his flesh in water, and he shall be clean.", "vulgate": "et die septimo radat capillos capitis barbamque et supercilia ac totius corporis pilos et lotis rursum vestibus et corpore;", "brenton": "And it shall come to pass on the seventh day, he shall shave off all his hair, his head and his beard, and his eye-brows, even all his hair shall he shave; and he shall wash his garments, and wash his body with water, and shall be clean."}}, {"v": 10, "ref": "14:10", "o": "וּ/בַ/יּ֣וֹם הַ/שְּׁמִינִ֗י יִקַּ֤ח שְׁנֵֽי כְבָשִׂים֙ תְּמִימִ֔ים וְ/כַבְשָׂ֥ה אַחַ֛ת בַּת שְׁנָתָ֖/הּ תְּמִימָ֑ה וּ/שְׁלֹשָׁ֣ה עֶשְׂרֹנִ֗ים סֹ֤לֶת מִנְחָה֙ בְּלוּלָ֣ה בַ/שֶּׁ֔מֶן וְ/לֹ֥ג אֶחָ֖ד שָֽׁמֶן", "en": {"kjv": "And on the eighth day he shall take two he lambs without blemish, and one ewe lamb of the first year without blemish, and three tenth deals of fine flour for a meat offering, mingled with oil, and one log of oil.", "web": "“On the eighth day he shall take two male lambs without defect, and one ewe lamb a year old without defect, and three tenths of an ephah of fine flour for a meal offering, mingled with oil, and one log of oil.", "bsb": "On the eighth day he is to bring two unblemished male lambs, an unblemished ewe lamb a year old, a grain offering of three-tenths of an ephah of fine flour mixed with olive oil, and one log of olive oil.", "asv": "And on the eighth day he shall take two he-lambs without blemish, and one ewe-lamb a year old without blemish, and three tenth parts of an ephah of fine flour for a meal-offering, mingled with oil, and one log of oil.", "ylt": "`And on the eighth day he taketh two lambs, perfect ones, and one ewe-lamb, daughter of a year, a perfect one, and three tenth deals of flour for a present, mixed with oil, and one log of oil.", "tyndale": "And when the .viij. daye is come, let him take ij. lambes without blemysh and a yewelambe of a yere olde without blemysh, and .iij. tenthdeales of fyne floure for a meatofferynge myngled with oyle, and a logge of oyle.", "dra": "On the eighth day, he shall take two lambs without blemish, and an ewe of a year old without blemish, and three tenths of flour tempered with oil for a sacrifice, and a sextary of oil apart.", "bbe": "And on the eighth day let him take two male lambs, without any marks on them, and one female lamb of the first year, without a mark, and three tenth parts of an ephah of the best meal, mixed with oil, and one log of oil.", "geneva": "Then in the eight day he shall take two hee lambes without blemish, and an ewe lambe of a yere olde without blemish, and three tenth deales of fine flower for a meate offering, mingled with oyle, and a pint of oyle.", "wycliffe": "eft in the eiyetithe dai he schal take twei lambren without wem, and a scheep of o yeer without wem, and thre dymes of wheete flour, in to sacrifice, which be spreynte with oile, and bi it silf a sextarie of oyle.", "rotherham": "And, on the eighth day, he shall take two he-lambs, without defect, and one ewe-lamb, the choice of its year without defect,—and three-tenths of fine meal for a meal-offering, overflowed with oil, and one log of oil.", "darby": "And on the eighth day he shall take two he-lambs without blemish, and one yearling ewe-lamb without blemish, and three tenth parts of fine flour mingled with oil, for an oblation, and one log of oil.", "twenty": "", "jps": "And on the eighth day he shall take two he-lambs without blemish, and one ewe-lamb of the first year without blemish, and three tenth parts of an ephah of fine flour for a meal-offering, mingled with oil, and one log of oil.", "acv": "And on the eighth day he shall take two he-lambs without blemish, and one ewe-lamb a year old without blemish, and three tenth parts of an ephah of fine flour for a meal offering, mingled with oil, and one log of oil.", "anderson": "", "haweis": "", "noyes": "", "webster": "And on the eighth day he shall take two he-lambs without blemish, and one ewe-lamb of the first year without blemish, and three tenth-parts of fine flour [for] a meat-offering, mingled with oil, and one log of oil.", "vulgate": "die octavo adsumet duos agnos inmaculatos et ovem anniculam absque macula et tres decimas similae in sacrificium quae conspersa sit oleo et seorsum olei sextarium;", "brenton": "And on the eighth day he shall take two lambs without spot of a year old, and one ewe lamp without spot of a year old, and three-tenths of fine flour for sacrifice kneaded with oil, and one small cup of oil."}}, {"v": 11, "ref": "14:11", "o": "וְ/הֶעֱמִ֞יד הַ/כֹּהֵ֣ן הַֽ/מְטַהֵ֗ר אֵ֛ת הָ/אִ֥ישׁ הַ/מִּטַּהֵ֖ר וְ/אֹתָ֑/ם לִ/פְנֵ֣י יְהוָ֔ה פֶּ֖תַח אֹ֥הֶל מוֹעֵֽד", "en": {"kjv": "And the priest that maketh him clean shall present the man that is to be made clean, and those things, before the Lord, at the door of the tabernacle of the congregation:", "web": "The priest who cleanses him shall set the man who is to be cleansed, and those things, before Yahweh, at the door of the Tent of Meeting.", "bsb": "The priest who performs the cleansing shall present the one to be cleansed, together with these offerings, before the LORD at the entrance to the Tent of Meeting.", "asv": "And the priest that cleanseth him shall set the man that is to be cleansed, and those things, before Jehovah, at the door of the tent of meeting.", "ylt": "`And the priest who is cleansing hath caused the man who is to be cleansed to stand with them before Jehovah, at the opening of the tent of meeting,", "tyndale": "Than let the preast that maketh him cleane, brynge the man that is made cleane with those thynges before the Lorde vnto the dore of the tabernacle of witnesse.", "dra": "And when the priest that purifieth the man, hath presented him, and all these things before the Lord, at the door of the tabernacle of the testimony:", "bbe": "And the priest who is making him clean will put the man who is being made clean, together with these things, before the door of the Tent of meeting.", "geneva": "And the Priest that maketh him cleane shall bring the man which is to bee made cleane, and those things, before the Lord, at the doore of the Tabernacle of the Congregation.", "wycliffe": "And whanne the preest, that purgith the man, hath set hym and alle hise thingis bifor the Lord, in the dore of the tabernacle of witnessyng, he schal take a lomb,", "rotherham": "And the priest that is cleansing him shall cause the man that is to be cleansed, and those things to stand before Yahweh, at the opening of the tent of meeting.", "darby": "And the priest that cleanseth [him] shall present the man that is to be cleansed and those things before Jehovah, at the entrance of the tent of meeting.", "twenty": "", "jps": "And the priest that cleanseth him shall set the man that is to be cleansed, and those things, before HaShem, at the door of the tent of meeting.", "acv": "And the priest who cleanses him shall set the man who is to be cleansed, and those things, before Jehovah, at the door of the tent of meeting.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest that maketh [him] clean, shall present the man that is to be made clean, and those things, before the LORD, [at] the door of the tabernacle of the congregation.", "vulgate": "cumque sacerdos purificans hominem statuerit eum et haec omnia coram Domino in ostio tabernaculi testimonii;", "brenton": "And the priest that cleanses shall present the man under purification, and these offerings before the Lord, at the door of the tabernacle of witness."}}, {"v": 12, "ref": "14:12", "o": "וְ/לָקַ֨ח הַ/כֹּהֵ֜ן אֶת הַ/כֶּ֣בֶשׂ הָ/אֶחָ֗ד וְ/הִקְרִ֥יב אֹת֛/וֹ לְ/אָשָׁ֖ם וְ/אֶת לֹ֣ג הַ/שָּׁ֑מֶן וְ/הֵנִ֥יף אֹתָ֛/ם תְּנוּפָ֖ה לִ/פְנֵ֥י יְהוָֽה", "en": {"kjv": "And the priest shall take one he lamb, and offer him for a trespass offering, and the log of oil, and wave them for a wave offering before the Lord:", "web": "“The priest shall take one of the male lambs, and offer him for a trespass offering, with the log of oil, and wave them for a wave offering before Yahweh.", "bsb": "Then the priest is to take one of the male lambs and present it as a guilt offering, along with the log of olive oil; and he must wave them as a wave offering before the LORD.", "asv": "And the priest shall take one of the he-lambs, and offer him for a trespass-offering, and the log of oil, and wave them for a wave-offering before Jehovah:", "ylt": "and the priest hath taken the one he-lamb, and hath brought it near for a guilt-offering, also the log of oil, and hath waved them--a wave offering before Jehovah.", "tyndale": "And lett the preast take one of the labes and offer him for a trespaceofferynge, and the logge of oyle: and waue them before the Lorde.", "dra": "He shall take a lamb, and offer it for a trespass offering with the sextary of oil. And having offered all before the Lord,", "bbe": "And the priest is to take one of the male lambs and give it as an offering for wrongdoing, and the log of oil, waving them for a wave offering before the Lord;", "geneva": "Then the Priest shall take one lambe, and offer him for a trespasse offering, and the pint of oyle, and shake the to and from before the Lord.", "wycliffe": "and schal offre it for trespas, and schal offre the sextarie of oyle; and whanne alle thingis ben offrid bifor the Lord,", "rotherham": "And the priest shall take one he-lamb, and bring him near as a guilt-bearer and the log of oil,—and shall wave them as a wave-offering, before Yahweh;", "darby": "And the priest shall take one he-lamb, and present it for a trespass-offering, and the log of oil, and wave them as a wave-offering before Jehovah.", "twenty": "", "jps": "And the priest shall take one of the he-lambs, and offer him for a guilt-offering, and the log of oil, and wave them for a wave-offering before HaShem.", "acv": "And the priest shall take one of the he-lambs, and offer him for a trespass offering, and the log of oil, and wave them for a wave offering before Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall take one he-lamb, and offer him for a trespass-offering, and the log of oil, and wave them [for] a wave-offering before the LORD.", "vulgate": "tollet agnum et offeret eum pro delicto oleique sextarium et oblatis ante Dominum omnibus;", "brenton": "And the priest shall take one lamb, and offer him for a trespass-offering, and the cup of oil, and set them apart for a special offering before the Lord."}}, {"v": 13, "ref": "14:13", "o": "וְ/שָׁחַ֣ט אֶת הַ/כֶּ֗בֶשׂ בִּ֠/מְקוֹם אֲשֶׁ֨ר יִשְׁחַ֧ט אֶת הַֽ/חַטָּ֛את וְ/אֶת הָ/עֹלָ֖ה בִּ/מְק֣וֹם הַ/קֹּ֑דֶשׁ כִּ֡י כַּ֠/חַטָּאת הָ/אָשָׁ֥ם הוּא֙ לַ/כֹּהֵ֔ן קֹ֥דֶשׁ קָֽדָשִׁ֖ים הֽוּא", "en": {"kjv": "And he shall slay the lamb in the place where he shall kill the sin offering and the burnt offering, in the holy place: for as the sin offering is the priest’s, so is the trespass offering: it is most holy:", "web": "He shall kill the male lamb in the place where they kill the sin offering and the burnt offering, in the place of the sanctuary; for as the sin offering is the priest’s, so is the trespass offering. It is most holy.", "bsb": "Then he is to slaughter the lamb in the sanctuary area where the sin offering and burnt offering are slaughtered. Like the sin offering, the guilt offering belongs to the priest; it is most holy.", "asv": "and he shall kill the he-lamb in the place where they kill the sin-offering and the burnt-offering, in the place of the sanctuary: for as the sin-offering is the priest’s, so is the trespass-offering: it is most holy.", "ylt": "`And he hath slaughtered the lamb in the place where he slaughtereth the sin-offering and the burnt-offering, in the holy place; for like the sin-offering the guilt-offering is to the priest; it is most holy.", "tyndale": "And than let him slee the lambe in the place where the synofferynge and the burntofferynge are slayne: eue in the holy place. for as the synofferynge is, eue so is the trespace offerynge the preastes: for it is most holy.", "dra": "He shall immolate the lamb, where the victim for sin is wont to be immolated, and the holocaust, that is, in the holy place. For as that which is for sin, so also the victim for a trespass offering pertaineth to the priest: it is holy of holies.", "bbe": "And he is to put the male lamb to death in the place where they put to death the sin-offering and the burned offering, in the holy place; for as the sin-offering is the property of the priest, so is the offering for wrongdoing: it is most holy.", "geneva": "And hee shall kill the lambe in the place where the sinne offring and the burnt offring are slaine, euen in the holy place: for as the sinne offring is the Priests, so is the trespasse offring: for it is most holy.", "wycliffe": "he schal offre the lomb, where the sacrifice for synne and the brent sacrifice is wont to be offrid, that is, in the hooli place; for as for synne so and for trespas the offryng perteyneth to the preest; it is hooli of the noumbre of hooli thingis.", "rotherham": "and shall slay the lamb in the place where the sin-bearer and the ascending-sacrifice are slain, in the holy place,—for like the sin-bearer, the guilt-bearer, is the priest’s, most holy, it is.", "darby": "And he shall slaughter the he-lamb at the place where the sin-offering and the burnt-offering are slaughtered, in a holy place; for as the sin-offering, so the trespass-offering is the priest's: it is most holy.", "twenty": "", "jps": "And he shall kill the he-lamb in the place where they kill the sin-offering and the burnt-offering, in the place of the sanctuary; for as the sin-offering is the priest's, so is the guilt-offering; it is most holy.", "acv": "And he shall kill the he-lamb in the place where they kill the sin offering and the burnt offering, in the place of the sanctuary. For as the sin offering is the priest's, so is the trespass offering; it is most holy.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall slay the lamb in the place where he shall kill the sin-offering and the burnt-offering, in the holy-place: for as the sin-offering [is] the priest's, [so is] the trespass-offering: it [is] most holy.", "vulgate": "immolabit agnum ubi immolari solet hostia pro peccato et holocaustum id est in loco sancto sicut enim pro peccato ita et pro delicto ad sacerdotem pertinet hostia sancta sanctorum est;", "brenton": "and they shall kill the lamb in the place where they kill the whole-burnt-offerings, and the sin-offerings, in the holy places; for it is a sin-offering: as the trespass-offering, it belongs to the priest, it is most holy."}}, {"v": 14, "ref": "14:14", "o": "וְ/לָקַ֣ח הַ/כֹּהֵן֮ מִ/דַּ֣ם הָ/אָשָׁם֒ וְ/נָתַן֙ הַ/כֹּהֵ֔ן עַל תְּנ֛וּךְ אֹ֥זֶן הַ/מִּטַּהֵ֖ר הַ/יְמָנִ֑ית וְ/עַל בֹּ֤הֶן יָד/וֹ֙ הַ/יְמָנִ֔ית וְ/עַל בֹּ֥הֶן רַגְל֖/וֹ הַ/יְמָנִֽית", "en": {"kjv": "And the priest shall take some of the blood of the trespass offering, and the priest shall put it upon the tip of the right ear of him that is to be cleansed, and upon the thumb of his right hand, and upon the great toe of his right foot:", "web": "The priest shall take some of the blood of the trespass offering, and the priest shall put it on the tip of the right ear of him who is to be cleansed, and on the thumb of his right hand, and on the big toe of his right foot.", "bsb": "The priest is to take some of the blood from the guilt offering and put it on the right earlobe of the one to be cleansed, on the thumb of his right hand, and on the big toe of his right foot.", "asv": "And the priest shall take of the blood of the trespass-offering, and the priest shall put it upon the tip of the right ear of him that is to be cleansed, and upon the thumb of his right hand, and upon the great toe of his right foot.", "ylt": "`And the priest hath taken of the blood of the guilt-offering, and the priest hath put on the tip of the right ear of him who is to be cleansed, and on the thumb of his right hand, and on the great toe of his right foot;", "tyndale": "Than lett the preast take of the bloude of the trespaceofferynge, and put it apo the typpe of the right eare of him that is clensed, and apon the thombe of his righte hande and apon the greate too of his righte fote.", "dra": "And the priest taking of the blood of the victim that was immolated for trespass, shall put it upon the tip of the right ear of him that is cleansed, and upon the thumb of his right hand and the great toe of his right foot.", "bbe": "And let the priest take some of the blood of the offering for wrongdoing and put it on the point of the right ear of him who is to be made clean, and on the thumb of his right hand and on the great toe of his right foot;", "geneva": "So the Priest shall take of the blood of the trespasse offring, and put it vpon the lappe of the right eare of him that shalbe clensed, and vpon the thumbe of his right hand, and vpon the great toe of his right foote.", "wycliffe": "And the preest schal take of the blood of sacrifice which is offrid for trespas, and schal putte on the laste part of the riyt eere `of hym which is clensid, and on the thumbis of the riyt hond and foot.", "rotherham": "Then shall the priest take of the blood of the guilt-bearer, and the priest shall put it upon the tip of the right ear of him that is to be cleansed,—and upon the thumb of his right hand, and upon the great toe of his right foot;", "darby": "And the priest shall take of the blood of the trespass-offering, and the priest shall put it on the tip of the right ear of him that is to be cleansed, and on the thumb of his right hand, and on the great toe of his right foot.", "twenty": "", "jps": "And the priest shall take of the blood of the guilt-offering, and the priest shall put it upon the tip of the right ear of him that is to be cleansed, and upon the thumb of his right hand, and upon the great toe of his right foot.", "acv": "And the priest shall take of the blood of the trespass offering, and the priest shall put it upon the tip of the right ear of him who is to be cleansed, and upon the thumb of his right hand, and upon the great toe of his right foot.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall take [some] of the blood of the trespass-offering, and the priest shall put [it] upon the tip of the right ear of him that is to be cleansed, and upon the thumb of his right hand, and upon the great toe of his right foot.", "vulgate": "adsumensque sacerdos de sanguine hostiae quae immolata est pro delicto ponet super extremum auriculae dextrae eius qui mundatur et super pollices manus dextrae et pedis;", "brenton": "And the priest shall take of the blood of the trespass-offering, and the priest shall put it on the tip of the right ear of the person under cleansing, and on the thumb of his right hand, and on the great toe of his right foot."}}, {"v": 15, "ref": "14:15", "o": "וְ/לָקַ֥ח הַ/כֹּהֵ֖ן מִ/לֹּ֣ג הַ/שָּׁ֑מֶן וְ/יָצַ֛ק עַל כַּ֥ף הַ/כֹּהֵ֖ן הַ/שְּׂמָאלִֽית", "en": {"kjv": "And the priest shall take some of the log of oil, and pour it into the palm of his own left hand:", "web": "The priest shall take some of the log of oil, and pour it into the palm of his own left hand.", "bsb": "Then the priest shall take some of the log of olive oil, pour it into his left palm,", "asv": "And the priest shall take of the log of oil, and pour it into the palm of his own left hand;", "ylt": "and the priest hath taken of the log of oil, and hath poured on the left palm of the priest,", "tyndale": "Then let the preast take of the logge of oyle and poure it in to the palme of his lefte hande,", "dra": "And he shall pour of the sextary of oil into his own left hand,", "bbe": "And take some of the oil and put it in the hollow of his left hand;", "geneva": "The Priest shall also take of ye pint of oyle, and powre it into the palme of his left hand,", "wycliffe": "And he schal putte of the sextarie of oyle in to his left hond,", "rotherham": "and the priest shall take of the log of oil,—and shall pour it upon the palm of the priest’s left hand,", "darby": "And the priest shall take of the log of oil, and pour it into his, the priest's, left hand;", "twenty": "", "jps": "And the priest shall take of the log of oil, and pour it into the palm of his own left hand.", "acv": "And the priest shall take of the log of oil, and pour it into the palm of his own left hand.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall take [some] of the log of oil, and pour [it] into the palm of his own left hand:", "vulgate": "et de olei sextario mittet in manum suam sinistram;", "brenton": "And the priest shall take of the cup of oil, and shall pour it upon his own left hand."}}, {"v": 16, "ref": "14:16", "o": "וְ/טָבַ֤ל הַ/כֹּהֵן֙ אֶת אֶצְבָּע֣/וֹ הַ/יְמָנִ֔ית מִן הַ/שֶּׁ֕מֶן אֲשֶׁ֥ר עַל כַּפּ֖/וֹ הַ/שְּׂמָאלִ֑ית וְ/הִזָּ֨ה מִן הַ/שֶּׁ֧מֶן בְּ/אֶצְבָּע֛/וֹ שֶׁ֥בַע פְּעָמִ֖ים לִ/פְנֵ֥י יְהוָֽה", "en": {"kjv": "And the priest shall dip his right finger in the oil that is in his left hand, and shall sprinkle of the oil with his finger seven times before the Lord:", "web": "The priest shall dip his right finger in the oil that is in his left hand, and shall sprinkle some of the oil with his finger seven times before Yahweh.", "bsb": "dip his right forefinger into the oil in his left palm, and sprinkle some of the oil with his finger seven times before the LORD.", "asv": "and the priest shall dip his right finger in the oil that is in his left hand, and shall sprinkle of the oil with his finger seven times before Jehovah.", "ylt": "and the priest hath dipped his right finger in the oil which is on his left palm, and hath sprinkled of the oil with his finger seven times before Jehovah.", "tyndale": "ad dippe his right finger in the oyle that is in the palme of his lefte hand, ad let him sprinkle it with his fynger vij. tymes before the Lorde.", "dra": "And shall dip his right finger in it, and sprinkle it before the Lord seven times.", "bbe": "And let the priest put his right finger in the oil which is in his left hand, shaking it out with his finger seven times before the Lord;", "geneva": "And the Priest shall dip his right finger in the oyle that is in his left hand, and sprinkle of the oyle with his finger seuen times before the Lord.", "wycliffe": "and he schal dippe the riyt fyngur therynne, and schal sprynge seuensithis bifor the Lord.", "rotherham": "and the priest shall dip his right finger [and take] of the oil that is on the palm of his left hand,—and shall sprinkle of the oil with his finger seven times before Yahweh:", "darby": "and the priest shall dip his right finger in the oil that is in his left hand, and shall sprinkle of the oil with his finger seven times before Jehovah.", "twenty": "", "jps": "And the priest shall dip his right finger in the oil that is in his left hand, and shall sprinkle of the oil with his finger seven times before HaShem.", "acv": "And the priest shall dip his right finger in the oil that is in his left hand, and shall sprinkle of the oil with his finger seven times before Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall dip his right finger in the oil that [is] in his left hand, and shall sprinkle of the oil with his finger seven times before the LORD.", "vulgate": "tinguetque digitum dextrum in eo et asperget septies contra Dominum;", "brenton": "And he shall dip with the finger of his right hand into some of the oil that is in his left hand, and he shall sprinkle with his finger seven times before the Lord."}}, {"v": 17, "ref": "14:17", "o": "וּ/מִ/יֶּ֨תֶר הַ/שֶּׁ֜מֶן אֲשֶׁ֣ר עַל כַּפּ֗/וֹ יִתֵּ֤ן הַ/כֹּהֵן֙ עַל תְּנ֞וּךְ אֹ֤זֶן הַ/מִּטַּהֵר֙ הַ/יְמָנִ֔ית וְ/עַל בֹּ֤הֶן יָד/וֹ֙ הַ/יְמָנִ֔ית וְ/עַל בֹּ֥הֶן רַגְל֖/וֹ הַ/יְמָנִ֑ית עַ֖ל דַּ֥ם הָ/אָשָֽׁם", "en": {"kjv": "And of the rest of the oil that is in his hand shall the priest put upon the tip of the right ear of him that is to be cleansed, and upon the thumb of his right hand, and upon the great toe of his right foot, upon the blood of the trespass offering:", "web": "The priest shall put some of the rest of the oil that is in his hand on the tip of the right ear of him who is to be cleansed, and on the thumb of his right hand, and on the big toe of his right foot, upon the blood of the trespass offering.", "bsb": "And the priest is to put some of the oil remaining in his palm on the right earlobe of the one to be cleansed, on the thumb of his right hand, and on the big toe of his right foot, on top of the blood of the guilt offering.", "asv": "And of the rest of the oil that is in his hand shall the priest put upon the tip of the right ear of him that is to be cleansed, and upon the thumb of his right hand, and upon the great toe of his right foot, upon the blood of the trespass-offering:", "ylt": "`And of the residue of the oil which is on his palm, the priest putteth on the tip of the right ear of him who is to be cleansed, and on the thumb of his right hand, and on the great toe of his right foot, on the blood of the guilt-offering;", "tyndale": "And of the rest of the oyle that is in his hande, shall the preast put apon the typpe of the righte eare of him that is clensed, and apon the thombe of his righte hande, and apon the great too of his righte fote: eue apon the bloude of the trespaceofferynge.", "dra": "And the rest of the oil in his left hand, he shall pour upon the tip of the right ear of him that is cleansed, and upon the thumb of his right hand and the great toe of his right foot, and upon the blood that was shed for trespass:", "bbe": "And of the rest of the oil which is in his hand, the priest will put some on the point of the right ear of the man who is to be made clean, and on the thumb of his right hand and on the great toe of his right foot, over the blood of the offering for wrongdoing;", "geneva": "And of the rest of the oyle that is in his hand, shall the Priest put vpon the lap of the right eare of him that is to bee clensed, and vpon the thumbe of his right hand, and vpon the great toe of his right foote, where the blood of the trespasse offring was put.", "wycliffe": "Sotheli he schal schede that that is residue of the oile in the left hond, on the laste part of the riyt eere `of hym which is clensid, and on the thombis of the riyt hond and foot, and on the blood which is sched for trespas,", "rotherham": "and of the remainder of the oil which is on the palm of his hand, shall the priest put upon the tip of the right ear of him that is to be cleansed, and upon the thumb of his right hand, and upon the great toe of his right foot,—upon the blood of the guilt-bearer;", "darby": "And of the rest of the oil that is in his hand shall the priest put on the tip of the right ear of him that is to be cleansed, and on the thumb of his right hand, and on the great toe of his right foot, upon the blood of the trespass-offering.", "twenty": "", "jps": "And of the rest of the oil that is in his hand shall the priest put upon the tip of the right ear of him that is to be cleansed, and upon the thumb of his right hand, and upon the great toe of his right foot, upon the blood of the guilt-offering.", "acv": "And of the rest of the oil that is in his hand the priest shall put upon the tip of the right ear of him who is to be cleansed, and upon the thumb of his right hand, and upon the great toe of his right foot, upon the blood of the trespass offering.", "anderson": "", "haweis": "", "noyes": "", "webster": "And of the rest of the oil that [is] in his hand, shall the priest put upon the tip of the right ear of him that is to be cleansed, and upon the thumb of his right hand, and upon the great toe of his right foot, upon the blood of the trespass-offering.", "vulgate": "quod autem reliquum est olei in leva manu fundet super extremum auriculae dextrae eius qui mundatur et super pollices manus ac pedis dextri et super sanguinem qui fusus est pro delicto;", "brenton": "And the remaining oil that is in his hand, the priest shall put on the tip of the right ear of him that is under cleansing, and on the thumb of his right hand, and on the great toe of his right foot, on the place of the blood of the trespass-offering."}}, {"v": 18, "ref": "14:18", "o": "וְ/הַ/נּוֹתָ֗ר בַּ/שֶּׁ֨מֶן֙ אֲשֶׁר֙ עַל כַּ֣ף הַ/כֹּהֵ֔ן יִתֵּ֖ן עַל רֹ֣אשׁ הַ/מִּטַּהֵ֑ר וְ/כִפֶּ֥ר עָלָ֛י/ו הַ/כֹּהֵ֖ן לִ/פְנֵ֥י יְהוָֽה", "en": {"kjv": "And the remnant of the oil that is in the priest’s hand he shall pour upon the head of him that is to be cleansed: and the priest shall make an atonement for him before the Lord.", "web": "The rest of the oil that is in the priest’s hand he shall put on the head of him who is to be cleansed, and the priest shall make atonement for him before Yahweh.", "bsb": "The rest of the oil in his palm, the priest is to put on the head of the one to be cleansed, to make atonement for him before the LORD.", "asv": "and the rest of the oil that is in the priest’s hand he shall put upon the head of him that is to be cleansed: and the priest shall make atonement for him before Jehovah.", "ylt": "and the remnant of the oil which is on the palm of the priest, he putteth on the head of him who is to be cleansed, and the priest hath made atonement for him before Jehovah.", "tyndale": "And the remnaunte of the oyle that is in the preastes hande, he shall poure apon the heede off hym that is clensed: and so shall the preaste make an attonement for him before the Lorde,", "dra": "And upon his head.", "bbe": "And the rest of the oil in the priest's hand he will put on the head of him who is to be made clean; and so the priest will make him free from sin before the Lord.", "geneva": "But the remnant of the oyle that is in the Priests hand, he shall powre vpon the head of him that is to be clensed: so the Priest shall make an atonement for him before the Lord.", "wycliffe": "and on the heed `of hym.", "rotherham": "and that which remaineth of the oil that is on the palm of the priest’s hand, he shall put upon the head of him that is to be cleansed,—so shall the priest put a propitiatory-covering over him, before Yahweh.", "darby": "And the remainder of the oil that is in the priest's hand he shall put upon the head of him that is to be cleansed, and the priest shall make atonement for him before Jehovah.", "twenty": "", "jps": "And the rest of the oil that is in the priest's hand he shall put upon the head of him that is to be cleansed; and the priest shall make atonement for him before HaShem.", "acv": "And the rest of the oil that is in the priest's hand he shall put upon the head of him who is to be cleansed, and the priest shall make atonement for him before Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the remnant of the oil that [is] in the priest's hand he shall pour upon the head of him that is to be cleansed: and the priest shall make an atonement for him before the LORD.", "vulgate": "et super caput eius;", "brenton": "And the remaining oil that is on the hand of the priest, the priest shall put on the head of the cleansed leper, and the priest shall make atonement for him before the Lord."}}, {"v": 19, "ref": "14:19", "o": "וְ/עָשָׂ֤ה הַ/כֹּהֵן֙ אֶת הַ֣/חַטָּ֔את וְ/כִפֶּ֕ר עַל הַ/מִּטַּהֵ֖ר מִ/טֻּמְאָת֑/וֹ וְ/אַחַ֖ר יִשְׁחַ֥ט אֶת הָ/עֹלָֽה", "en": {"kjv": "And the priest shall offer the sin offering, and make an atonement for him that is to be cleansed from his uncleanness; and afterward he shall kill the burnt offering:", "web": "“The priest shall offer the sin offering, and make atonement for him who is to be cleansed because of his uncleanness: and afterward he shall kill the burnt offering;", "bsb": "Then the priest is to sacrifice the sin offering and make atonement for the one to be cleansed from his uncleanness. After that, the priest shall slaughter the burnt offering", "asv": "And the priest shall offer the sin-offering, and make atonement for him that is to be cleansed because of his uncleanness: and afterward he shall kill the burnt-offering;", "ylt": "`And the priest hath made the sin-offering, and hath made atonement for him who is to be cleansed from his uncleanness, and afterwards he doth slaughter the burnt-offering;", "tyndale": "Then let the preast offer the synneofferynge, ad make an attonement for him that is clensed for his vnclenesse. And tha let the burntoffrynge be slayne,", "dra": "And he shall pray for him before the Lord, and shall offer the sacrifice for sin. Then shall he immolate the holocaust.", "bbe": "And the priest will give the sin-offering, and take away the sin of him who is to be made clean from his unclean condition; and after that he will put the burned offering to death.", "geneva": "And the Priest shall offer the sinne offring and make an atonement for him that is to bee clensed of his vncleannesse: then after shall he kill the burnt offring.", "wycliffe": "And the preest schal preye for hym bifor the Lord, and schal make sacrifice for synne; thanne he schal offre brent sacrifice,", "rotherham": "Then shall the priest offer the sin-bearer, and shall put a propitiatory-covering over him that is to be cleansed because of his uncleanness,—and, afterwards, shall he slay the ascending-sacrifice.", "darby": "And the priest shall offer the sin-offering, and make atonement for him that is to be cleansed from his uncleanness; and afterwards shall he slaughter the burnt-offering.", "twenty": "", "jps": "And the priest shall offer the sin-offering, and make atonement for him that is to be cleansed because of his uncleanness; and afterward he shall kill the burnt-offering.", "acv": "And the priest shall offer the sin offering, and make atonement for him who is to be cleansed because of his uncleanness, and afterward he shall kill the burnt offering.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall offer the sin-offering, and make an atonement for him that is to be cleansed from his uncleanness; and afterward he shall kill the burnt-offering.", "vulgate": "rogabitque pro eo coram Domino et faciet sacrificium pro peccato tunc immolabit holocaustum;", "brenton": "And the priest shall sacrifice the sin-offering, and the priest shall make atonement for the person under purification to cleanse him from his sin, and afterwards the priest shall slay the whole-burnt-offering."}}, {"v": 20, "ref": "14:20", "o": "וְ/הֶעֱלָ֧ה הַ/כֹּהֵ֛ן אֶת הָ/עֹלָ֥ה וְ/אֶת הַ/מִּנְחָ֖ה הַ/מִּזְבֵּ֑חָ/ה וְ/כִפֶּ֥ר עָלָ֛י/ו הַ/כֹּהֵ֖ן וְ/טָהֵֽר", "en": {"kjv": "And the priest shall offer the burnt offering and the meat offering upon the altar: and the priest shall make an atonement for him, and he shall be clean.", "web": "and the priest shall offer the burnt offering and the meal offering on the altar. The priest shall make atonement for him, and he shall be clean.", "bsb": "and offer it on the altar, with the grain offering, to make atonement for him, and he will be clean.", "asv": "and the priest shall offer the burnt-offering and the meal-offering upon the altar: and the priest shall make atonement for him, and he shall be clean.", "ylt": "and the priest hath caused the burnt-offering to ascend, also the present, on the altar, and the priest hath made atonement for him, and he hath been clean.", "tyndale": "ad let the preast put both the burntofferynge and the meateoffrynge apo the alter: ad make an attonement for him, ad tha he shalbe cleane.", "dra": "And put it on the altar with the libations thereof: and the man shall be rightly cleansed.", "bbe": "And the priest is to have the burned offering and the meal offering burned on the altar; and the priest will take away his sin and he will be clean.", "geneva": "So the Priest shall offer ye burnt offring and the meat offring vpon ye altar and the Priest shall make an atonement for him: so he shalbe cleane.", "wycliffe": "and schal putte it in the auter with hise fletynge sacrifices, and the man schal be clensid riytfuli.", "rotherham": "And the priest shall cause the ascending-sacrifice, and the meal-offering to ascend at the altar,—so shall the priest put a propitiatory-covering over him, and he shall be clean.", "darby": "And the priest shall offer the burnt-offering and the oblation upon the altar; and the priest shall make atonement for him, and he shall be clean.", "twenty": "", "jps": "And the priest shall offer the burnt-offering and the meal-offering upon the altar; and the priest shall make atonement for him, and he shall be clean.", "acv": "And the priest shall offer the burnt offering and the meal offering upon the altar, and the priest shall make atonement for him, and he shall be clean.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall offer the burnt-offering, and the meat-offering upon the altar: and the priest shall make an atonement for him, and he shall be clean.", "vulgate": "et ponet illud in altari cum libamentis suis et homo rite mundabitur;", "brenton": "And the priest shall offer the whole-burnt-offering, and the sacrifice upon the altar before the Lord; and the priest shall make atonement for him, and he shall be cleansed."}}, {"v": 21, "ref": "14:21", "o": "וְ/אִם דַּ֣ל ה֗וּא וְ/אֵ֣ין יָד/וֹ֮ מַשֶּׂגֶת֒ וְ֠/לָקַח כֶּ֣בֶשׂ אֶחָ֥ד אָשָׁ֛ם לִ/תְנוּפָ֖ה לְ/כַפֵּ֣ר עָלָ֑י/ו וְ/עִשָּׂר֨וֹן סֹ֜לֶת אֶחָ֨ד בָּל֥וּל בַּ/שֶּׁ֛מֶן לְ/מִנְחָ֖ה וְ/לֹ֥ג שָֽׁמֶן", "en": {"kjv": "And if he be poor, and cannot get so much; then he shall take one lamb for a trespass offering to be waved, to make an atonement for him, and one tenth deal of fine flour mingled with oil for a meat offering, and a log of oil;", "web": "“If he is poor, and can’t afford so much, then he shall take one male lamb for a trespass offering to be waved, to make atonement for him, and one tenth of an ephah of fine flour mingled with oil for a meal offering, and a log of oil;", "bsb": "If, however, the person is poor and cannot afford these offerings, he is to take one male lamb as a guilt offering to be waved to make atonement for him, along with a tenth of an ephah of fine flour mixed with olive oil for a grain offering, a log of olive oil,", "asv": "And if he be poor, and cannot get so much, then he shall take one he-lamb for a trespass-offering to be waved, to make atonement for him, and one tenth part of an ephah of fine flour mingled with oil for a meal-offering, and a log of oil;", "ylt": "`And if he is poor, and his hand is not reaching these things , then he hath taken one lamb--a guilt-offering, for a wave-offering, to make atonement for him, and one-tenth deal of flour mixed with oil for a present, and a log of oil,", "tyndale": "Yf he be poore ad can not gett so moch, tha let him bringe one lambe for a trespaceoffrynge to waue it and to make an attonement for him, ad a tenth deale of fine floure myngled with oyle for a meatoffrynge ad a logge of oyle,", "dra": "But if he be poor, and his hand cannot find the things aforesaid: he shall take a lamb for an offering for trespass, that the priest may pray for him, and a tenth part of flour tempered with oil for a sacrifice, and a sextary of oil:", "bbe": "And if he is poor and not able to get so much, then he may take one male lamb as an offering for wrongdoing, to be waved to take away his sin, and one tenth part of an ephah of the best meal mixed with oil for a meal offering, and a log of oil;", "geneva": "But if he be poore, and not able, then he shall bring one lambe for a trespasse offring to be shaken, for his reconciliation, and a tenth deale of fine flower mingled with oyle, for a meate offring, with a pinte of oyle.", "wycliffe": "That if he is pore, and his hoond may not fynde tho thingis that ben seid, he schal take for trespas a lomb to offryng, that the preest preie for him, and the tenthe part of wheete flour spreynt togidire with oile in to sacrifice, and a sextarie of oile,", "rotherham": "But if he be poor and his hand hath not enough, then shall he take one he-lamb as a guilt-bearer to be waved to put a propitiatory-covering over him,—and one-tenth of fine meal, overflowed with oil for a meal-offering, and a log of oil,", "darby": "But if he be poor, and his hand be not able to get it, then he shall take one lamb for a trespass-offering, for a wave-offering, to make atonement for him; and one tenth part of fine flour mingled with oil for an oblation; and a log of oil,", "twenty": "", "jps": "And if he be poor, and his means suffice not, then he shall take one he-lamb for a guilt-offering to be waved, to make atonement for him, and one tenth part of an ephah of fine flour mingled with oil for a meal-offering, and a log of oil;", "acv": "And if he is poor, and cannot get so much, then he shall take one he-lamb for a trespass offering to be waved, to make atonement for him, and one tenth part of an ephah of fine flour mingled with oil for a meal offering, and a log of oil,", "anderson": "", "haweis": "", "noyes": "", "webster": "And if he [is] poor, and cannot get so much; then he shall take one lamb [for] a trespass-offering to be waved, to make an atonement for him, and one tenth-part of fine flour mingled with oil for a meat-offering, and a log of oil;", "vulgate": "quod si pauper est et non potest manus eius invenire quae dicta sunt adsumet agnum pro delicto ad oblationem ut roget pro eo sacerdos decimamque partem similae conspersae oleo in sacrificium et olei sextarium;", "brenton": "And if he should be poor, and cannot afford so much, he shall take one lamb for his transgression for a separate-offering, so as to make propitiation for him, and a tenth deal of fine flour mingled with oil for a sacrifice, and one cup of oil,"}}, {"v": 22, "ref": "14:22", "o": "וּ/שְׁתֵּ֣י תֹרִ֗ים א֤וֹ שְׁנֵי֙ בְּנֵ֣י יוֹנָ֔ה אֲשֶׁ֥ר תַּשִּׂ֖יג יָד֑/וֹ וְ/הָיָ֤ה אֶחָד֙ חַטָּ֔את וְ/הָ/אֶחָ֖ד עֹלָֽה", "en": {"kjv": "And two turtledoves, or two young pigeons, such as he is able to get; and the one shall be a sin offering, and the other a burnt offering.", "web": "and two turtledoves, or two young pigeons, such as he is able to afford; and the one shall be a sin offering, and the other a burnt offering.", "bsb": "and two turtledoves or two young pigeons, whichever he can afford, one to be a sin offering and the other a burnt offering.", "asv": "and two turtle-doves, or two young pigeons, such as he is able to get; and the one shall be a sin-offering, and the other a burnt-offering.", "ylt": "and two turtle-doves, or two young pigeons, which his hand reacheth to, and one hath been a sin-offering, and the one a burnt-offering;", "tyndale": "ad two turtyll doues or two yonge pygeons which he is able to gett ad let the one be a synneoffrynge and the other a burntoffryng.", "dra": "And two turtles or two young pigeons, of which one may be for sin, and the other for a holocaust.", "bbe": "And two doves or two young pigeons, such as he is able to get; and one will be for a sin-offering and the other for a burned offering.", "geneva": "Also two turtle doues, or two yong pigeons, as he is able, whereof the one shalbe a sinne offering, and the other a burnt offring,", "wycliffe": "and twei turtlis, ethir twei `briddis of culueris, of whiche oon be for synne, and the tothir in to brent sacrifice;", "rotherham": "and two turtle-doves or two young pigeons, for which his hand hath enough,—so shall one be a sin-bearer, and the other an ascending-sacrifice.", "darby": "and two turtle-doves, or two young pigeons, as his hand may be able to get: the one shall be a sin-offering, and the other a burnt-offering.", "twenty": "", "jps": "and two turtle-doves, or two young pigeons, such as his means suffice for; and the one shall be a sin-offering, and the other a burnt-offering.", "acv": "and two turtle-doves, or two young pigeons, such as he is able to get, and the one shall be a sin offering, and the other a burnt offering.", "anderson": "", "haweis": "", "noyes": "", "webster": "And two turtle-doves, or two young pigeons, such as he is able to get; and the one shall be a sin-offering, and the other a burnt-offering.", "vulgate": "duosque turtures sive duos pullos columbae quorum sit unus pro peccato et alter in holocaustum;", "brenton": "and two turtle-doves, or two young pigeons, as he can afford; and the one shall be for a sin-offering, and the other for a whole-burnt-offering."}}, {"v": 23, "ref": "14:23", "o": "וְ/הֵבִ֨יא אֹתָ֜/ם בַּ/יּ֧וֹם הַ/שְּׁמִינִ֛י לְ/טָהֳרָת֖/וֹ אֶל הַ/כֹּהֵ֑ן אֶל פֶּ֥תַח אֹֽהֶל מוֹעֵ֖ד לִ/פְנֵ֥י יְהוָֽה", "en": {"kjv": "And he shall bring them on the eighth day for his cleansing unto the priest, unto the door of the tabernacle of the congregation, before the Lord.", "web": "“On the eighth day he shall bring them for his cleansing to the priest, to the door of the Tent of Meeting, before Yahweh.", "bsb": "On the eighth day he is to bring them for his cleansing to the priest at the entrance to the Tent of Meeting before the LORD.", "asv": "And on the eighth day he shall bring them for his cleansing unto the priest, unto the door of the tent of meeting, before Jehovah:", "ylt": "and he hath brought them in on the eighth day for his cleansing unto the priest, unto the opening of the tent of meeting, before Jehovah.", "tyndale": "And let him brynge them the .viij, daye for his clensynge vnto the preast to the dore of the tabernacle of witnesse before the Lorde.", "dra": "And he shall offer them on the eighth day of his purification to the priest, at the door of the tabernacle of the testimony before the Lord.", "bbe": "And on the eighth day he will take them to the priest, to the door of the Tent of meeting before the Lord, so that he may be made clean.", "geneva": "And he shall bring them the eight day for his clensing vnto the Priest at the doore of the Tabernacle of the Congregation before ye Lord.", "wycliffe": "and he schal offre tho in the eiytthe dai of his clensyng to the preest, at the dore of tabernacle of witnessyng bifor the Lord.", "rotherham": "And he shall bring them in on the eighth day, for his cleansing, unto the priest,—unto the entrance of the tent of meeting, before Yahweh.", "darby": "And he shall bring them on the eighth day of his cleansing unto the priest, unto the entrance of the tent of meeting, before Jehovah.", "twenty": "", "jps": "And on the eighth day he shall bring them for his cleansing unto the priest, unto the door of the tent of meeting, before HaShem.", "acv": "And on the eighth day he shall bring them for his cleansing to the priest, to the door of the tent of meeting, before Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall bring them on the eighth day for his cleansing to the priest, to the door of the tabernacle of the congregation, before the LORD.", "vulgate": "offeretque ea die octavo purificationis suae sacerdoti ad ostium tabernaculi testimonii coram Domino;", "brenton": "And he shall bring them on the eighth day, to purify him, to the priest, to the door of the tabernacle of witness before the Lord."}}, {"v": 24, "ref": "14:24", "o": "וְ/לָקַ֧ח הַ/כֹּהֵ֛ן אֶת כֶּ֥בֶשׂ הָ/אָשָׁ֖ם וְ/אֶת לֹ֣ג הַ/שָּׁ֑מֶן וְ/הֵנִ֨יף אֹתָ֧/ם הַ/כֹּהֵ֛ן תְּנוּפָ֖ה לִ/פְנֵ֥י יְהוָֽה", "en": {"kjv": "And the priest shall take the lamb of the trespass offering, and the log of oil, and the priest shall wave them for a wave offering before the Lord:", "web": "The priest shall take the lamb of the trespass offering, and the log of oil, and the priest shall wave them for a wave offering before Yahweh.", "bsb": "The priest shall take the lamb for the guilt offering, along with the log of olive oil, and wave them as a wave offering before the LORD.", "asv": "and the priest shall take the lamb of the trespass-offering, and the log of oil, and the priest shall wave them for a wave-offering before Jehovah.", "ylt": "`And the priest hath taken the lamb of the guilt-offering, and the log of oil, and the priest hath waved them--a wave-offering before Jehovah;", "tyndale": "And let the preast take the lambe that is the trespaceoffrynge and the logge of oyle, ad waue them before the Lorde.", "dra": "And the priest receiving the lamb for trespass, and the sextary of oil, shall elevate them together.", "bbe": "And the priest will take the lamb of the offering for wrongdoing and the oil, waving them for a wave offering before the Lord;", "geneva": "The the Priest shall take the lambe of the trespasse offring, and the pint of oyle, and the Priest shall shake them to and from before the Lord.", "wycliffe": "And the preest schal take the lomb for trespas, and the sextarie of oile, and schal reise togidere;", "rotherham": "Then shall the priest take the guilt-bearing lamb and the log of oil,—and the priest shall wave them as a wave-offering, before Yahweh.", "darby": "And the priest shall take the he-lamb of the trespass-offering, and the log of oil, and the priest shall wave them as a wave-offering before Jehovah.", "twenty": "", "jps": "And the priest shall take the lamb of the guilt-offering, and the log of oil, and the priest shall wave them for a wave-offering before HaShem.", "acv": "And the priest shall take the lamb of the trespass offering, and the log of oil, and the priest shall wave them for a wave offering before Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall take the lamb of the trespass-offering, and the log of oil, and the priest shall wave them [for] a wave-offering before the LORD.", "vulgate": "qui suscipiens agnum pro delicto et sextarium olei levabit simul;", "brenton": "And the priest shall take the lamb of the trespass-offering, and the cup of oil, and place them for a set-offering before the Lord."}}, {"v": 25, "ref": "14:25", "o": "וְ/שָׁחַט֮ אֶת כֶּ֣בֶשׂ הָֽ/אָשָׁם֒ וְ/לָקַ֤ח הַ/כֹּהֵן֙ מִ/דַּ֣ם הָֽ/אָשָׁ֔ם וְ/נָתַ֛ן עַל תְּנ֥וּךְ אֹֽזֶן הַ/מִּטַּהֵ֖ר הַ/יְמָנִ֑ית וְ/עַל בֹּ֤הֶן יָד/וֹ֙ הַ/יְמָנִ֔ית וְ/עַל בֹּ֥הֶן רַגְל֖/וֹ הַ/יְמָנִֽית", "en": {"kjv": "And he shall kill the lamb of the trespass offering, and the priest shall take some of the blood of the trespass offering, and put it upon the tip of the right ear of him that is to be cleansed, and upon the thumb of his right hand, and upon the great toe of his right foot:", "web": "He shall kill the lamb of the trespass offering. The priest shall take some of the blood of the trespass offering and put it on the tip of the right ear of him who is to be cleansed, and on the thumb of his right hand, and on the big toe of his right foot.", "bsb": "And after he slaughters the lamb for the guilt offering, the priest is to take some of the blood of the guilt offering and put it on the right earlobe of the one to be cleansed, on the thumb of his right hand, and on the big toe of his right foot.", "asv": "And he shall kill the lamb of the trespass-offering; and the priest shall take of the blood of the trespass-offering, and put it upon the tip of the right ear of him that is to be cleansed, and upon the thumb of his right hand, and upon the great toe of his right foot.", "ylt": "and he hath slaughtered the lamb of the guilt-offering, and the priest hath taken of the blood of the guilt-offering, and hath put on the tip of the right ear of him who is to be cleansed, and on the thumb of his right hand, and on the great toe of his right foot;", "tyndale": "And whe the lambe of the trespaceoffrynge is kylled, the preast shall take of the bloude of the trespaceoffrynge, and put it apon the typpe of his righte eare that is clensed, and apon the thombe of his righte hande, and apon the greate too of hys righte fote.", "dra": "And the lamb being immolated, he shall put of the blood thereof upon the tip of the right ear of him that is cleansed, and upon the thumb of his right hand, and the great toe of his right foot.", "bbe": "And he will put to death the lamb of the offering for wrongdoing and the priest will take some of the blood of the offering for wrongdoing and put it on the point of the right ear of him who is to be made clean, and on the thumb of his right hand and on the great toe of his right foot;", "geneva": "And he shall kill the lambe of the trespasse offering, and the Priest shall take of the blood of the trespasse offring, and put it vpon the lap of his right eare that is to be clensed, and vpon ye thumbe of his right hande, and vpon the great toe of his right foote.", "wycliffe": "and whanne the lomb is offrid, he schal putte of the blood therof on the laste part of the riyt eere `of hym that is clensid, and on the thumbis of his riyt hond and foot.", "rotherham": "Then shall the guilt-bearing lamb be slain, and the priest shall take of the blood of the guilt-bearer, and put upon the tip of the right ear of him that is to be cleansed,—and upon the thumb of his right hand, and upon the great toe of his right foot;", "darby": "And he shall slaughter the he-lamb of the trespass-offering; and the priest shall take of the blood of the trespass-offering, and put it upon the tip of the right ear of him that is to be cleansed, and upon the thumb of his right hand, and on the great toe of his right foot.", "twenty": "", "jps": "And he shall kill the lamb of the guilt-offering, and the priest shall take of the blood of the guilt-offering, and put it upon the tip of the right ear of him that is to be cleansed, and upon the thumb of his right hand, and upon the great toe of his right foot.", "acv": "And he shall kill the lamb of the trespass offering. And the priest shall take of the blood of the trespass offering, and put it upon the tip of the right ear of him who is to be cleansed, and upon the thumb of his right hand, and upon the great toe of his right foot.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall kill the lamb of the trespass-offering, and the priest shall take [some] of the blood of the trespass-offering, and put [it] upon the tip of the right ear of him that is to be cleansed, and upon the thumb of his right hand, and upon the great toe of his right foot.", "vulgate": "immolatoque agno de sanguine eius ponet super extremum auriculae dextrae illius qui mundatur et super pollices manus eius ac pedis dextri;", "brenton": "And he shall slay the lamb of the trespass-offering; and the priest shall take of the blood of the trespass-offering, and put it on the tip of the right ear of him that is under purification, and on the thumb of his right hand, and on the great toe of his right foot."}}, {"v": 26, "ref": "14:26", "o": "וּ/מִן הַ/שֶּׁ֖מֶן יִצֹ֣ק הַ/כֹּהֵ֑ן עַל כַּ֥ף הַ/כֹּהֵ֖ן הַ/שְּׂמָאלִֽית", "en": {"kjv": "And the priest shall pour of the oil into the palm of his own left hand:", "web": "The priest shall pour some of the oil into the palm of his own left hand;", "bsb": "Then the priest is to pour some of the oil into his left palm", "asv": "And the priest shall pour of the oil into the palm of his own left hand;", "ylt": "and the priest doth pour of the oil on the left palm of the priest;", "tyndale": "And the preast shall poure of the oyle in to his righte hande,", "dra": "But he shall pour part of the oil into his own left hand,", "bbe": "And the priest will put out some of the oil in the hollow of his left hand,", "geneva": "Also the Priest shall powre of the oyle into the palme of his owne left hand.", "wycliffe": "Sotheli the preest putte the part of oile in to his left hond,", "rotherham": "also of the oil, shall the priest pour out,—on the palm of his own left hand;", "darby": "And the priest shall pour of the oil into [his], the priest's, left hand,", "twenty": "", "jps": "And the priest shall pour of the oil into the palm of his own left hand.", "acv": "And the priest shall pour of the oil into the palm of his own left hand.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall pour of the oil into the palm of his own left hand.", "vulgate": "olei vero partem mittet in manum suam sinistram;", "brenton": "And the priest shall pour of the oil on his own left hand."}}, {"v": 27, "ref": "14:27", "o": "וְ/הִזָּ֤ה הַ/כֹּהֵן֙ בְּ/אֶצְבָּע֣/וֹ הַ/יְמָנִ֔ית מִן הַ/שֶּׁ֕מֶן אֲשֶׁ֥ר עַל כַּפּ֖/וֹ הַ/שְּׂמָאלִ֑ית שֶׁ֥בַע פְּעָמִ֖ים לִ/פְנֵ֥י יְהוָֽה", "en": {"kjv": "And the priest shall sprinkle with his right finger some of the oil that is in his left hand seven times before the Lord:", "web": "and the priest shall sprinkle with his right finger some of the oil that is in his left hand seven times before Yahweh.", "bsb": "and sprinkle with his right forefinger some of the oil in his left palm seven times before the LORD.", "asv": "and the priest shall sprinkle with his right finger some of the oil that is in his left hand seven times before Jehovah:", "ylt": "and the priest hath sprinkled with his right finger of the oil which is on his left palm, seven times before Jehovah.", "tyndale": "and shall sprinkle with his finger of the oyle that is in his lefte hande .vij. tymes before the Lord.", "dra": "And dipping the finger of his right hand in it, he shall sprinkle it seven times before the Lord.", "bbe": "Shaking out drops of oil with his right finger before the Lord seven times:", "geneva": "So ye Priest shall with his right finger sprinkle of the oyle that is in his left hand, seuen times before the Lord.", "wycliffe": "in which he schal dippe the fyngur of the riyt hond, and schal sprynge seuensithes ayens the Lord;", "rotherham": "and the priest shall sprinkle with his right finger, of the oil that is on the palm of his left hand,—seven times, before Yahweh;", "darby": "and the priest shall sprinkle with his right finger of the oil that is in his left hand seven times before Jehovah.", "twenty": "", "jps": "And the priest shall sprinkle with his right finger some of the oil that is in his left hand seven times before HaShem.", "acv": "And the priest shall sprinkle with his right finger some of the oil that is in his left hand seven times before Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall sprinkle with his right finger [some] of the oil that [is] in his left hand seven times before the LORD:", "vulgate": "in quo tinguens digitum dextrae manus asperget septies contra Dominum;", "brenton": "And the priest shall sprinkle with the finger of his right hand some of the oil that is in his left hand seven times before the Lord."}}, {"v": 28, "ref": "14:28", "o": "וְ/נָתַ֨ן הַ/כֹּהֵ֜ן מִן הַ/שֶּׁ֣מֶן אֲשֶׁ֣ר עַל כַּפּ֗/וֹ עַל תְּנ֞וּךְ אֹ֤זֶן הַ/מִּטַּהֵר֙ הַ/יְמָנִ֔ית וְ/עַל בֹּ֤הֶן יָד/וֹ֙ הַ/יְמָנִ֔ית וְ/עַל בֹּ֥הֶן רַגְל֖/וֹ הַ/יְמָנִ֑ית עַל מְק֖וֹם דַּ֥ם הָ/אָשָֽׁם", "en": {"kjv": "And the priest shall put of the oil that is in his hand upon the tip of the right ear of him that is to be cleansed, and upon the thumb of his right hand, and upon the great toe of his right foot, upon the place of the blood of the trespass offering:", "web": "Then the priest shall put some of the oil that is in his hand on the tip of the right ear of him who is to be cleansed, and on the thumb of his right hand, and on the big toe of his right foot, on the place of the blood of the trespass offering.", "bsb": "The priest shall also put some of the oil in his palm on the right earlobe of the one to be cleansed, on the thumb of his right hand, and on the big toe of his right foot—on the same places as the blood of the guilt offering.", "asv": "and the priest shall put of the oil that is in his hand upon the tip of the right ear of him that is to be cleansed, and upon the thumb of his right hand, and upon the great toe of his right foot, upon the place of the blood of the trespass-offering:", "ylt": "`And the priest hath put of the oil which is on his palm, on the tip of the right ear of him who is to be cleansed, and on the thumb of his right hand, and on the great toe of his right foot, on the place of the blood of the guilt-offering;", "tyndale": "And the preast shall put of the oyle that is in his hande (apon the typpe of the righte eare of hi that is clensed, and apo the thombe of his righte hande and apon the great too of his righte fote: euen in the place where the bloude of the trespaceofferynge was put,", "dra": "And he shall touch the tip of the right ear of him that is cleansed, and the thumb of his right hand and the great toe of his right foot, in the place of the blood that was shed for trespass.", "bbe": "And the priest will put some of the oil which is in his hand on the point of the ear of the man who is to be made clean and on the thumb of his right hand and on the great toe of his right foot, on the place where the blood of the offering for wrongdoing was put;", "geneva": "Then the Priest shall put of the oyle that is in his hande, vpon the lap of the right eare of him that is to bee clensed, and vpon the thumbe of his right hande, and vpon the great toe of his right foote: vpon the place of the blood of the trespasse offring.", "wycliffe": "and the preest schal touche the laste part of the riyt eere `of hym that is clensid, and the thombe of the riyt hond and foot, in the place of blood which is sched out for trespas.", "rotherham": "then shall the priest put, of the oil that is on the palm of his hand, upon the tip of the right ear of him that is to be cleansed, and upon the thumb of his right hand, and upon the great toe of his right foot,—upon the place of the blood of the guilt-offering;", "darby": "And the priest shall put of the oil that is in his hand upon the tip of the right ear of him that is to be cleansed, and upon the thumb of his right hand, and on the great toe of his right foot, upon the place of the blood of the trespass-offering.", "twenty": "", "jps": "And the priest shall put of the oil that is in his hand upon the tip of the right ear of him that is to be cleansed, and upon the thumb of his right hand, and upon the great toe of his right foot, upon the place of the blood of the guilt-offering.", "acv": "And the priest shall put of the oil that is in his hand upon the tip of the right ear of him who is to be cleansed, and upon the thumb of his right hand, and upon the great toe of his right foot, upon the place of the blood of the trespass offering.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall put of the oil that [is] in his hand upon the tip of the right ear of him that is to be cleansed, and upon the thumb of his right hand, and upon the great toe of his right foot, upon the place of the blood of the trespass-offering.", "vulgate": "tangetque extremum dextrae auriculae illius qui mundatur et pollices manus ac pedis dextri in loco sanguinis qui effusus est pro delicto;", "brenton": "And the priest shall put of the oil that is on his hand on the tip of the right ear of him that is under purification, and on the thumb of his right hand, and on the great toe of his right foot, on the place of the blood of the trespass-offering."}}, {"v": 29, "ref": "14:29", "o": "וְ/הַ/נּוֹתָ֗ר מִן הַ/שֶּׁ֨מֶן֙ אֲשֶׁר֙ עַל כַּ֣ף הַ/כֹּהֵ֔ן יִתֵּ֖ן עַל רֹ֣אשׁ הַ/מִּטַּהֵ֑ר לְ/כַפֵּ֥ר עָלָ֖י/ו לִ/פְנֵ֥י יְהוָֽה", "en": {"kjv": "And the rest of the oil that is in the priest’s hand he shall put upon the head of him that is to be cleansed, to make an atonement for him before the Lord.", "web": "The rest of the oil that is in the priest’s hand he shall put on the head of him who is to be cleansed, to make atonement for him before Yahweh.", "bsb": "The rest of the oil in his palm, the priest is to put on the head of the one to be cleansed, to make atonement for him before the LORD.", "asv": "and the rest of the oil that is in the priest’s hand he shall put upon the head of him that is to be cleansed, to make atonement for him before Jehovah.", "ylt": "and the remnant of the oil which is on the palm of the priest he doth put on the head of him who is to be cleansed, to make atonement for him, before Jehovah.", "tyndale": "And the reste of the oyle that is in his hande, he shall poure apon the heede of him that is clensed: to make an attonemet for him before the Lorde.", "dra": "And the other part of the oil that is in his left hand, he shall pour upon the head of the purified person, that he may appease the Lord for him.", "bbe": "And the rest of the oil which is in the priest's hand he will put on the head of him who is to be made clean, to take away his sin before the Lord.", "geneva": "But ye rest of the oyle that is in the Priests hand, he shall put vpon the head of him that is to be clensed, to make an atonement for him before the Lord.", "wycliffe": "Sotheli he schal putte the tother part of oile, which is in the left hond, on the `heed of the man clensid, that he plese the Lord for hym.", "rotherham": "and that which remaineth of the oil which is on the palm of the priest’s hand, shall he put upon the head of him that is to be cleansed,—to put a propitiatory-covering over him before Yahweh.", "darby": "And the remainder of the oil that is in the priest's hand he shall put upon the head of him that is to be cleansed, to make atonement for him before Jehovah.", "twenty": "", "jps": "And the rest of the oil that is in the priest's hand he shall put upon the head of him that is to be cleansed, to make atonement for him before HaShem.", "acv": "And the rest of the oil that is in the priest's hand he shall put upon the head of him who is to be cleansed, to make atonement for him before Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the rest of the oil that [is] in the priest's hand he shall put upon the head of him that is to be cleansed, to make an atonement for him before the LORD.", "vulgate": "reliquam autem partem olei quae est in sinistra manu mittet super caput purificati ut placet pro eo Dominum;", "brenton": "And that which is left of the oil which is on the hand of the priest he shall put on the head of him that is purged, and the priest shall make atonement for him before the Lord."}}, {"v": 30, "ref": "14:30", "o": "וְ/עָשָׂ֤ה אֶת הָֽ/אֶחָד֙ מִן הַ/תֹּרִ֔ים א֖וֹ מִן בְּנֵ֣י הַ/יּוֹנָ֑ה מֵ/אֲשֶׁ֥ר תַּשִּׂ֖יג יָדֽ/וֹ", "en": {"kjv": "And he shall offer the one of the turtledoves, or of the young pigeons, such as he can get;", "web": "He shall offer one of the turtledoves, or of the young pigeons, such as he is able to afford,", "bsb": "Then he must sacrifice the turtledoves or young pigeons, whichever he can afford,", "asv": "And he shall offer one of the turtle-doves, or of the young pigeons, such as he is able to get,", "ylt": "`And he hath made the one of the turtle-doves, or of the young pigeons (from that which his hand reacheth to,", "tyndale": "And he shall offer one of the turtyll doues or of the yonge pigeons, soch as he can gett:", "dra": "And he shall offer a turtle, or young pigeon:", "bbe": "And he will make an offering of one of the doves or the young pigeons, such as he is able to get;", "geneva": "Also hee shall present one of the turtle doues, or of the yong pigeons, as he is able:", "wycliffe": "And he schal offre a turtle, ethir a culuer brid,", "rotherham": "Then shall he offer one of the turtle-doves, or of the young pigeons,—of that for which his hand hath enough;", "darby": "And he shall offer one of the turtle-doves, or of the young pigeons, of what his hand was able to get;", "twenty": "", "jps": "And he shall offer one of the turtle-doves, or of the young pigeons, such as his means suffice for;", "acv": "And he shall offer one of the turtle-doves, or of the young pigeons, such as he is able to get,", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall offer one of the turtle-doves, or of the young pigeons, such as he can get;", "vulgate": "et turturem sive pullum columbae offeret;", "brenton": "And he shall offer one of the turtle-doves or of the young pigeons, as he can afford it,"}}, {"v": 31, "ref": "14:31", "o": "אֵ֣ת אֲשֶׁר תַּשִּׂ֞יג יָד֗/וֹ אֶת הָ/אֶחָ֥ד חַטָּ֛את וְ/אֶת הָ/אֶחָ֥ד עֹלָ֖ה עַל הַ/מִּנְחָ֑ה וְ/כִפֶּ֧ר הַ/כֹּהֵ֛ן עַ֥ל הַ/מִּטַּהֵ֖ר לִ/פְנֵ֥י יְהוָֽה", "en": {"kjv": "Even such as he is able to get, the one for a sin offering, and the other for a burnt offering, with the meat offering: and the priest shall make an atonement for him that is to be cleansed before the Lord.", "web": "even such as he is able to afford, the one for a sin offering, and the other for a burnt offering, with the meal offering. The priest shall make atonement for him who is to be cleansed before Yahweh.”", "bsb": "one as a sin offering and the other as a burnt offering, together with the grain offering. In this way the priest will make atonement before the LORD for the one to be cleansed.", "asv": "even such as he is able to get, the one for a sin-offering, and the other for a burnt-offering, with the meal-offering: and the priest shall make atonement for him that is to be cleansed before Jehovah.", "ylt": "even that which his hand reacheth to), the one a sin-offering, and the one a burnt offering, besides the present, and the priest hath made atonement for him who is to be cleansed before Jehovah.", "tyndale": "the one for a synneofferynge and the other for a burntoffrynge apo the alter. And so shall the preast make an attonemet for him that is clensed before the Lorde.", "dra": "One for trespass, and the other for a holocaust, with their libations.", "bbe": "And of these, he will give one for a sin-offering and one for a burned offering, with the meal offering; and the priest will take away the sin of him who is to be made clean before the Lord.", "geneva": "Such, I say, as he is able, the one for a sinne offring, and the other for a burnt offring with the meate offring: so the Priest shall make an atonement for him that is to bee clensed before the Lord.", "wycliffe": "oon for trespas, and the tothir in to brent sacrifice, with her fletynge offryngis.", "rotherham": "even that for which his hand hath enough,—the one as a sin-bearer and the other as an ascending-sacrifice, upon the meal-offering,—so shall the priest put a propitiatory-covering over him that is to be cleansed before Yahweh.", "darby": "of what his hand was able to get shall the one be a sin-offering, and the other a burnt-offering, with the oblation; and the priest shall make atonement for him that is to be cleansed before Jehovah.", "twenty": "", "jps": "even such as his means suffice for, the one for a sin-offering, and the other for a burnt-offering, with the meal-offering; and the priest shall make atonement for him that is to be cleansed before HaShem.", "acv": "even such as he is able to get, the one for a sin offering, and the other for a burnt offering, with the meal offering, and the priest shall make atonement for him who is to be cleansed before Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "[Even] such as he is able to get, the one [for] a sin-offering, and the other [for] a burnt-offering, with the meat-offering. And the priest shall make an atonement for him that is to be cleansed, before the LORD.", "vulgate": "unum pro delicto et alterum in holocaustum cum libamentis suis;", "brenton": "the one for a sin-offering, the other for a whole-burnt-offering with the meat-offering, and the priest shall make an atonement before the Lord for him that is under purification."}}, {"v": 32, "ref": "14:32", "o": "זֹ֣את תּוֹרַ֔ת אֲשֶׁר בּ֖/וֹ נֶ֣גַע צָרָ֑עַת אֲשֶׁ֛ר לֹֽא תַשִּׂ֥יג יָד֖/וֹ בְּ/טָהֳרָתֽ/וֹ", "en": {"kjv": "This is the law of him in whom is the plague of leprosy, whose hand is not able to get that which pertaineth to his cleansing.", "web": "This is the law for him in whom is the plague of leprosy, who is not able to afford the sacrifice for his cleansing.", "bsb": "This is the law for someone who has a skin disease and cannot afford the cost of his cleansing.”", "asv": "This is the law of him in whom is the plague of leprosy, who is not able to get that which pertaineth to his cleansing.", "ylt": "This is a law of him in whom is a plague of leprosy, whose hand reacheth not to his cleansing.'", "tyndale": "This is the lawe of him that hath the plage of leprosye, whose hand is not able to gett that which pertayneth to hys clensynge.", "dra": "This is the sacrifice of a leper, that is not able to have all things that appertain to his cleansing.", "bbe": "This is the law for the man who has the disease of the leper on him, and who is not able to get that which is necessary for making himself clean.", "geneva": "This is the lawe of him which hath the plague of leprosie, who is not able in his clensing to offer the whole.", "wycliffe": "This is the sacrifice of a leprouse man, that may not haue alle thingis in to the clensyng of hym silf.", "rotherham": "This is the law for him in whom hath been the plague of leprosy, whose hand hath not enough for that which pertaineth to his cleansing.", "darby": "This is the law for him in whom is the sore of leprosy, whose hand cannot get what is [regularly prescribed] in his cleansing.", "twenty": "", "jps": "This is the law of him in whom is the plague of leprosy, whose means suffice not for that which pertaineth to his cleansing.", "acv": "This is the law of him in whom is a leprous disease, who is not able to get what pertains to his cleansing.", "anderson": "", "haweis": "", "noyes": "", "webster": "This [is] the law [of him] in whom is the plague of leprosy, whose hand is not able to get [that which pertaineth] to his cleansing.", "vulgate": "hoc est sacrificium leprosi qui habere non potest omnia in emundationem sui;", "brenton": "This is the law for him in whom is the plague of leprosy, and who cannot afford the offerings for his purification."}}, {"v": 33, "ref": "14:33", "o": "וַ/יְדַבֵּ֣ר יְהוָ֔ה אֶל מֹשֶׁ֥ה וְ/אֶֽל אַהֲרֹ֖ן לֵ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses and unto Aaron, saying,", "web": "Yahweh spoke to Moses and to Aaron, saying,", "bsb": "Then the LORD said to Moses and Aaron,", "asv": "And Jehovah spake unto Moses and unto Aaron, saying,", "ylt": "And Jehovah speaketh unto Moses, and unto Aaron, saying,", "tyndale": "And the Lorde spake vnto Moses ad Aaro saynge:", "dra": "And the Lord spoke to Moses and Aaron, saying:", "bbe": "And the Lord said to Moses and Aaron,", "geneva": "The Lord also spake vnto Moses and to Aaron, saying,", "wycliffe": "And the Lord spak to Moises and Aaron, and seide,", "rotherham": "And Yahweh spake unto Moses and unto Aaron saying:", "darby": "And Jehovah spoke to Moses and to Aaron, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses and unto Aaron, saying:", "acv": "And Jehovah spoke to Moses and to Aaron, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses and to Aaron, saying,", "vulgate": "locutus est Dominus ad Mosen et Aaron dicens;", "brenton": "And the Lord spoke to Moses and Aaron, saying,"}}, {"v": 34, "ref": "14:34", "o": "כִּ֤י תָבֹ֨אוּ֙ אֶל אֶ֣רֶץ כְּנַ֔עַן אֲשֶׁ֥ר אֲנִ֛י נֹתֵ֥ן לָ/כֶ֖ם לַ/אֲחֻזָּ֑ה וְ/נָתַתִּי֙ נֶ֣גַע צָרַ֔עַת בְּ/בֵ֖ית אֶ֥רֶץ אֲחֻזַּתְ/כֶֽם", "en": {"kjv": "When ye be come into the land of Canaan, which I give to you for a possession, and I put the plague of leprosy in a house of the land of your possession;", "web": "“When you have come into the land of Canaan, which I give to you for a possession, and I put a spreading mildew in a house in the land of your possession,", "bsb": "“When you enter the land of Canaan, which I am giving you as your possession, and I put a contamination of mildew into a house in that land,", "asv": "When ye are come into the land of Canaan, which I give to you for a possession, and I put the plague of leprosy in a house of the land of your possession;", "ylt": "`When ye come in unto the land of Canaan, which I am giving to you for a possession, and I have put a plague of leprosy in a house in the land of your possession;", "tyndale": "when ye be come vnto the lond of Canaan which I geue you to possesse: yf I put the plage of leprosye in any housse of the lande of youre possession,", "dra": "When you shall come into the land of Chanaan, which I will give you for a possession, if there be the plague or leprosy in a house:", "bbe": "When you have come into the land of Canaan which I will give you for your heritage, if I put the leper's disease on a house in the land of your heritage,", "geneva": "When ye be come vnto the land of Canaan which I giue you in possession, if I sende the plague of leprosie in an house of the land of your possession,", "wycliffe": "Whanne ye han entrid in to the lond of Canaan, which lond Y schal yyue to you in to possessioun, if the wounde of lepre is in the housis,", "rotherham": "When ye enter into the land of Canaan which I am about to give you for a possession,—and I put a plague-mark of leprosy in a house, of the land of your possession,", "darby": "When ye come into the land of Canaan, which I give to you for a possession, and I put a leprous plague in a house of the land of your possession,", "twenty": "", "jps": "When ye are come into the land of Canaan, which I give to you for a possession, and I put the plague of leprosy in a house of the land of your possession;", "acv": "When ye have come into the land of Canaan, which I give to you for a possession, and I put a leprous disease in a house of the land of your possession,", "anderson": "", "haweis": "", "noyes": "", "webster": "When ye shall have come into the land of Canaan, which I give to you for a possession, and I put the plague of leprosy in a house of the land of your possession;", "vulgate": "cum ingressi fueritis terram Chanaan quam ego dabo vobis in possessionem si fuerit plaga leprae in aedibus;", "brenton": "Whensoever ye shall enter into the land of the Chananites, which I give you for a possession, and I shall put the plague of leprosy in the houses of the land of your possession;"}}, {"v": 35, "ref": "14:35", "o": "וּ/בָא֙ אֲשֶׁר ל֣/וֹ הַ/בַּ֔יִת וְ/הִגִּ֥יד לַ/כֹּהֵ֖ן לֵ/אמֹ֑ר כְּ/נֶ֕גַע נִרְאָ֥ה לִ֖/י בַּ/בָּֽיִת", "en": {"kjv": "And he that owneth the house shall come and tell the priest, saying, It seemeth to me there is as it were a plague in the house:", "web": "then he who owns the house shall come and tell the priest, saying, ‘There seems to me to be some sort of plague in the house.’", "bsb": "the owner of the house shall come and tell the priest, ‘Something like mildew has appeared in my house.’", "asv": "then he that owneth the house shall come and tell the priest, saying, There seemeth to me to be as it were a plague in the house.", "ylt": "then hath he whose the house is come in and declared to the priest, saying, As a plague hath appeared to me in the house;", "tyndale": "let him that oweth the house go ad tell the preast saynge, me thinke that there is as it were a leprosy in the housse.", "dra": "He whose house it is, shall go and tell the priest, saying: It seemeth to me, that there is the plague of leprosy in my house,", "bbe": "Then let the owner of the house come and say to the priest, It seems to me that there is a sort of leper's disease in the house.", "geneva": "Then he that oweth the house, shall come and tell the Priest, saying, Me thinke there is like a plague of leprosie in the house.", "wycliffe": "he schal go, whos the hous is, `and schal telle to the preest, and schal seie, It semeth to me, that as a wound of lepre is in myn hous.", "rotherham": "then shall he that owneth the house come in, and tell the priest, saying,—A kind of plague-mark, appeareth to me in the house;", "darby": "then he whose house it is shall come and tell the priest, saying, It seemeth to me like a plague in the house;", "twenty": "", "jps": "then he that owneth the house shall come and tell the priest, saying: 'There seemeth to me to be as it were a plague in the house.'", "acv": "then he who owns the house shall come and tell the priest, saying, There seems to me to be as it were a disease in the house.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he that owneth the house shall come and tell the priest, saying, it seemeth to me [there is] as it were a plague in the house:", "vulgate": "ibit cuius est domus nuntians sacerdoti et dicet quasi plaga leprae videtur mihi esse in domo mea;", "brenton": "then the owner of the house shall come and report to the priest, saying, I have seen as it were a plague in the house."}}, {"v": 36, "ref": "14:36", "o": "וְ/צִוָּ֨ה הַ/כֹּהֵ֜ן וּ/פִנּ֣וּ אֶת הַ/בַּ֗יִת בְּ/טֶ֨רֶם יָבֹ֤א הַ/כֹּהֵן֙ לִ/רְא֣וֹת אֶת הַ/נֶּ֔גַע וְ/לֹ֥א יִטְמָ֖א כָּל אֲשֶׁ֣ר בַּ/בָּ֑יִת וְ/אַ֥חַר כֵּ֛ן יָבֹ֥א הַ/כֹּהֵ֖ן לִ/רְא֥וֹת אֶת הַ/בָּֽיִת", "en": {"kjv": "Then the priest shall command that they empty the house, before the priest go into it to see the plague, that all that is in the house be not made unclean: and afterward the priest shall go in to see the house:", "web": "The priest shall command that they empty the house, before the priest goes in to examine the plague, that all that is in the house not be made unclean. Afterward the priest shall go in to inspect the house.", "bsb": "The priest must order that the house be cleared before he enters it to examine the mildew, so that nothing in the house will become unclean. After this, the priest shall go in to inspect the house.", "asv": "And the priest shall command that they empty the house, before the priest goeth in to see the plague, that all that is in the house be not made unclean: and afterward the priest shall go in to see the house:", "ylt": "and the priest hath commanded, and they have prepared the house before the priest cometh in to see the plague (that all which is in the house be not unclean), and afterwards doth the priest come in to see the house;", "tyndale": "And the preast shall comaunde them to ryd all thinge out of the housse, before the preaste goo in to se the plage: that he make not all that is in the housse vncleane, and then the preast shall goo in and se the housse.", "dra": "And he shall command, that they carry forth all things out of the house, before he go into it, and see whether it have the leprosy, let all things become unclean that are in the house. And afterwards he shall go in to view the leprosy of the house.", "bbe": "And the priest will give orders for everything to be taken out of the house, before he goes in to see the disease, so that the things in the house may not become unclean; and then the priest is to go in to see the house;", "geneva": "Then the Priest shall commande them to emptie the house before the Priest goe into it to see the plague, that all that is in the house be not made vncleane, and then shall the Priest goe in to see the house,", "wycliffe": "And the preest schal comaunde, `that thei bere out of the hous alle thingis bifore that he entre in to it, `and me se where it be lepre, lest alle thingis that ben in the hows, be maad vnclene; and the preest schal entre aftirward, that he se the lepre of the hows.", "rotherham": "and the priest shall give command, and they shall empty the house, ere yet the priest cometh in to view the mark, so that he do not pronounce unclean all that is in the house,—and, after this, shall the priest come in to view the house:", "darby": "and the priest shall command that they empty the house before the priest go into it to see the plague, that all that is in the house be not made unclean; and afterwards the priest shall go in to see the house.", "twenty": "", "jps": "And the priest shall command that they empty the house, before the priest go in to see the plague, that all that is in the house be not made unclean; and afterward the priest shall go in to see the house.", "acv": "And the priest shall command that they empty the house before the priest goes in to see the disease, that all that is in the house not be made unclean. And afterward the priest shall go in to see the house,", "anderson": "", "haweis": "", "noyes": "", "webster": "Then the priest shall command that they empty the house, before the priest shall enter to see the plague, that all that [is] in the house may not be made unclean; and afterward the priest shall go in to see the house:", "vulgate": "at ille praecipiet ut efferant universa de domo priusquam ingrediatur eam et videat utrum lepra sit ne inmunda fiant omnia quae in domo sunt intrabitque postea ut consideret domus lepram;", "brenton": "And the priest shall give orders to remove the furniture of the house, before the priest comes in to see the plague, and thus none of the things in the house shall become unclean; and afterwards the priest shall go in to examine the house."}}, {"v": 37, "ref": "14:37", "o": "וְ/רָאָ֣ה אֶת הַ/נֶּ֗גַע וְ/הִנֵּ֤ה הַ/נֶּ֨גַע֙ בְּ/קִירֹ֣ת הַ/בַּ֔יִת שְׁקַֽעֲרוּרֹת֙ יְרַקְרַקֹּ֔ת א֖וֹ אֲדַמְדַּמֹּ֑ת וּ/מַרְאֵי/הֶ֥ן שָׁפָ֖ל מִן הַ/קִּֽיר", "en": {"kjv": "And he shall look on the plague, and, behold, if the plague be in the walls of the house with hollow strakes, greenish or reddish, which in sight are lower than the wall;", "web": "He shall examine the plague; and behold, if the plague is in the walls of the house with hollow streaks, greenish or reddish, and it appears to be deeper than the wall;", "bsb": "He is to examine the house, and if the mildew on the walls consists of green or red depressions that appear to be beneath the surface of the wall,", "asv": "and he shall look on the plague; and, behold, if the plague be in the walls of the house with hollow streaks, greenish or reddish, and the appearance thereof be lower than the wall;", "ylt": "and he hath seen the plague, and lo, the plague is in the walls of the house, hollow strakes, very green or very red, and their appearance is lower than the wall,", "tyndale": "Yf the preast se that the plage is in the walles of the housse ad that there be holowe strakes pale or rede which seme to be lower than the other partes of the wall,", "dra": "And if he see in the walls thereof as it were little dints, disfigured with paleness or redness, and lower than all he rest:", "bbe": "And if he sees that the walls of the house are marked with hollows of green and red, and if it seems to go deeper than the face of the wall;", "geneva": "And hee shall marke the plague: and if the plague be in the walles of the house, and that there be deepe spots, greenish or reddish, which seeme to be lower then the wall,", "wycliffe": "And whanne he seeth in the wallis therof as litle valeis `foule bi palenesse, ethir bi reednesse, and lowere than the tother hiyere part,", "rotherham": "then shall he view the mark and lo! if the mark is in the walls of the house, with sunken places greenish yellow or reddish,—and they appear to be lower than the [surface of the] wall,", "darby": "And when he looketh on the plague, and behold, the plague is in the walls of the house, greenish or reddish hollows, and their look is deeper than the surface of the wall,", "twenty": "", "jps": "And he shall look on the plague, and, behold, if the plague be in the walls of the house with hollow streaks, greenish or reddish, and the appearance thereof be lower than the wall;", "acv": "and he shall look on the disease. And, behold, if the disease is in the walls of the house with hollow streaks, greenish or reddish, and the appearance of it is deeper than the wall surface,", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall look on the plague, and behold, [if] the plague [is] in the walls of the house, with hollow streaks, greenish, or reddish, which in sight [are] lower than the wall;", "vulgate": "et cum viderit in parietibus illius quasi valliculas pallore sive rubore deformes et humiliores superficie reliqua;", "brenton": "And he shall look on the plague, and, behold, if the plague is in the walls of the house, he will see greenish or reddish cavities, and the appearance of them will be beneath the surface of the walls."}}, {"v": 38, "ref": "14:38", "o": "וְ/יָצָ֧א הַ/כֹּהֵ֛ן מִן הַ/בַּ֖יִת אֶל פֶּ֣תַח הַ/בָּ֑יִת וְ/הִסְגִּ֥יר אֶת הַ/בַּ֖יִת שִׁבְעַ֥ת יָמִֽים", "en": {"kjv": "Then the priest shall go out of the house to the door of the house, and shut up the house seven days:", "web": "then the priest shall go out of the house to the door of the house, and shut up the house seven days.", "bsb": "the priest shall go outside the doorway of the house and close it up for seven days.", "asv": "then the priest shall go out of the house to the door of the house, and shut up the house seven days.", "ylt": "and the priest hath gone out of the house unto the opening of the house, and hath shut up the house seven days.", "tyndale": "then let the preast go out at the housse dores ad shett vp the housse for .vij. dayes.", "dra": "He shall go out of the door of the house, and forthwith shut it up seven days,", "bbe": "Then the priest will go out of the door of the house, and keep the house shut up for seven days:", "geneva": "Then the Priest shall goe out of the house to the doore of the house, and shall cause to shut vp the house seuen dayes.", "wycliffe": "he schal go out at the dore of the hows, and anoon he schal close it bi seuene daies.", "rotherham": "then shall the priest come forth out of the house, unto the entrance of the house,—and shall shut up the house seven days;", "darby": "then the priest shall go out of the house to the entrance of the house, and shut up the house seven days.", "twenty": "", "jps": "then the priest shall go out of the house to the door of the house, and shut up the house seven days.", "acv": "then the priest shall go out of the house to the door of the house, and shut up the house seven days.", "anderson": "", "haweis": "", "noyes": "", "webster": "Then the priest shall go out of the house to the door of the house, and shut up the house seven days:", "vulgate": "egredietur ostium domus et statim claudet eam septem diebus;", "brenton": "And the priest shall come out of the house to the door of the house, and the priest shall separate the house seven days."}}, {"v": 39, "ref": "14:39", "o": "וְ/שָׁ֥ב הַ/כֹּהֵ֖ן בַּ/יּ֣וֹם הַ/שְּׁבִיעִ֑י וְ/רָאָ֕ה וְ/הִנֵּ֛ה פָּשָׂ֥ה הַ/נֶּ֖גַע בְּ/קִירֹ֥ת הַ/בָּֽיִת", "en": {"kjv": "And the priest shall come again the seventh day, and shall look: and, behold, if the plague be spread in the walls of the house;", "web": "The priest shall come again on the seventh day, and look. If the plague has spread in the walls of the house,", "bsb": "On the seventh day the priest is to return and inspect the house. If the mildew has spread on the walls,", "asv": "And the priest shall come again the seventh day, and shall look; and, behold, if the plague be spread in the walls of the house;", "ylt": "`And the priest hath turned back on the seventh day, and hath seen, and lo, the plague hath spread in the walls of the house,", "tyndale": "And let the preast come againe the seuenth daye ad se it: yf the plage be encreased in the walles of the housse,", "dra": "And returning on the seventh day, he shall look upon it. If he find that the leprosy is spread,", "bbe": "And the priest is to come again on the seventh day and have a look and see if the marks on the walls of the house are increased in size;", "geneva": "So the Priest shall come againe ye seuenth day: and if he see that the plague bee increased in the walles of the house,", "wycliffe": "And he schal turne ayen in the seuenthe day, and schal se it; if he fyndith that the lepre encreesside,", "rotherham": "and the priest shall return on the seventh day,—and take a view, and lo! if the mark hath spread in the walls of the house,", "darby": "And the priest shall come again the seventh day, and when he looketh, and behold, the plague hath spread in the walls of the house,", "twenty": "", "jps": "And the priest shall come again the seventh day, and shall look; and, behold, if the plague be spread in the walls of the house;", "acv": "And the priest shall come again the seventh day, and shall look. And, behold, if the disease has spread in the walls of the house,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall come again the seventh day, and shall look; and behold, [if] the plague is spread in the walls of the house;", "vulgate": "reversusque die septimo considerabit eam si invenerit crevisse lepram;", "brenton": "And the priest shall return on the seventh day and view the house; and, behold, if the plague is spread in the walls of the house,"}}, {"v": 40, "ref": "14:40", "o": "וְ/צִוָּה֙ הַ/כֹּהֵ֔ן וְ/חִלְּצוּ֙ אֶת הָ֣/אֲבָנִ֔ים אֲשֶׁ֥ר בָּ/הֵ֖ן הַ/נָּ֑גַע וְ/הִשְׁלִ֤יכוּ אֶתְ/הֶן֙ אֶל מִ/ח֣וּץ לָ/עִ֔יר אֶל מָק֖וֹם טָמֵֽא", "en": {"kjv": "Then the priest shall command that they take away the stones in which the plague is, and they shall cast them into an unclean place without the city:", "web": "then the priest shall command that they take out the stones in which is the plague, and cast them into an unclean place outside of the city:", "bsb": "he must order that the contaminated stones be pulled out and thrown into an unclean place outside the city.", "asv": "then the priest shall command that they take out the stones in which the plague is, and cast them into an unclean place without the city:", "ylt": "and the priest hath commanded, and they have drawn out the stones in which the plague is , and have cast them unto the outside of the city, unto an unclean place;", "tyndale": "let the preast comaunde the to take awaye the stones in which the plage is, ad let the cast the in a foule place without the citie,", "dra": "He shall command, that the stones wherein the leprosy is, be taken out, and cast without the city into an unclean place:", "bbe": "Then the priest will give orders to them to take out the stones in which the disease is seen, and put them out into an unclean place outside the town:", "geneva": "Then the Priest shall commande them to take away the stones wherein the plague is, and they shall cast them into a foule place without the citie.", "wycliffe": "he schal comaunde that the stoonys be cast out, in whyche the lepre is, and that tho stonys be cast out of the citee in an vncleene place.", "rotherham": "then shall the priest give command, and they shall pull out the stones, wherein is the mark,—and cast them forth outside the city, into an unclean place;", "darby": "then the priest shall command that they take away the stones in which the plague is, and they shall cast them out of the city, in an unclean place.", "twenty": "", "jps": "then the priest shall command that they take out the stones in which the plague is, and cast them into an unclean place without the city.", "acv": "then the priest shall command that they take out the stones in which the disease is, and cast them into an unclean place outside the city.", "anderson": "", "haweis": "", "noyes": "", "webster": "Then the priest shall command that they take away the stones in which the plague [is], and they shall cast them into an unclean place without the city:", "vulgate": "iubebit erui lapides in quibus lepra est et proici eos extra civitatem in loco inmundo;", "brenton": "then the priest shall give orders, and they shall take away the stones in which the plague is, and shall cast them out of the city into an unclean place."}}, {"v": 41, "ref": "14:41", "o": "וְ/אֶת הַ/בַּ֛יִת יַקְצִ֥עַ מִ/בַּ֖יִת סָבִ֑יב וְ/שָׁפְכ֗וּ אֶת הֶֽ/עָפָר֙ אֲשֶׁ֣ר הִקְצ֔וּ אֶל מִ/ח֣וּץ לָ/עִ֔יר אֶל מָק֖וֹם טָמֵֽא", "en": {"kjv": "And he shall cause the house to be scraped within round about, and they shall pour out the dust that they scrape off without the city into an unclean place:", "web": "and he shall cause the inside of the house to be scraped all over, and they shall pour out the mortar, that they scraped off, outside of the city into an unclean place.", "bsb": "And he shall have the inside of the house scraped completely and the plaster that is scraped off dumped into an unclean place outside the city.", "asv": "and he shall cause the house to be scraped within round about, and they shall pour out the mortar, that they scrape off, without the city into an unclean place:", "ylt": "and the house he doth cause to be scraped within round about, and they have poured out the clay which they have scraped off, at the outside of the city, at an unclean place;", "tyndale": "ad scrape the house within rounde aboute, ad poure out the dust without the citie in a foule place.", "dra": "And that the house be scraped on the inside round about, and the dust of the scrapings be scattered without the city into an unclean place:", "bbe": "And he will have the house rubbed all over inside, and the paste which is rubbed off will be put out into an unclean place outside the town:", "geneva": "Also hee shall cause to scrape the house within rounde about, and powre the dust, that they haue pared off, without the citie in an vncleane place.", "wycliffe": "Sotheli he schal comaunde that thilke hows be rasid with ynne bi cumpas, and that the dust of the rasyng be spreynt without the citee, in an vnclene place,", "rotherham": "and, the house itself, shall he cause to be scraped on the inside round about,—and they shall pour out the mortar which they have scraped off, outside the city, into an unclean place;", "darby": "And he shall cause the house to be scraped within round about, and they shall pour out the mortar that they have scraped off, out of the city in an unclean place.", "twenty": "", "jps": "And he shall cause the house to be scraped within round about, and they shall pour out the mortar that they scrape off without the city into an unclean place.", "acv": "And he shall cause the house to be scraped inside round about, and they shall pour out the mortar, that they scrape off, outside the city into an unclean place.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall cause the house to be scraped within on all sides, and they shall pour out the dust that they scrape off without the city into an unclean place:", "vulgate": "domum autem ipsam radi intrinsecus per circuitum et spargi pulverem rasurae extra urbem in loco inmundo;", "brenton": "And they shall scrape the house within round about, and shall pour out the dust scraped off outside the city into an unclean place."}}, {"v": 42, "ref": "14:42", "o": "וְ/לָקְחוּ֙ אֲבָנִ֣ים אֲחֵר֔וֹת וְ/הֵבִ֖יאוּ אֶל תַּ֣חַת הָ/אֲבָנִ֑ים וְ/עָפָ֥ר אַחֵ֛ר יִקַּ֖ח וְ/טָ֥ח אֶת הַ/בָּֽיִת", "en": {"kjv": "And they shall take other stones, and put them in the place of those stones; and he shall take other morter, and shall plaister the house.", "web": "They shall take other stones, and put them in the place of those stones; and he shall take other mortar, and shall plaster the house.", "bsb": "So different stones must be obtained to replace the contaminated ones, as well as additional mortar to replaster the house.", "asv": "and they shall take other stones, and put them in the place of those stones; and he shall take other mortar, and shall plaster the house.", "ylt": "and they have taken other stones, and brought them in unto the place of the stones, and other clay he taketh and hath daubed the house.", "tyndale": "And let them take other stones and put them in the places of those stones, and other morter: ad playster the housse with all.", "dra": "And that other stones be laid in the place of them that were taken away, and the house be plastered with other mortar.", "bbe": "And they will take other stones and put them in place of those stones, and he will take other paste and put it on the walls of the house.", "geneva": "And they shall take other stones, and put them in the places of those stones, and shall take other mortar, to plaister the house with.", "wycliffe": "and that othere stoonys be put ayen for these, that ben takun awey, and that the hows be daubid with othir morter.", "rotherham": "and shall take other stones, and put in the place of the stones,—and, other mortar, shall he take and plaster the house.", "darby": "And they shall take other stones, and put them in the place of those stones; and they shall take other mortar, and shall plaster the house.", "twenty": "", "jps": "And they shall take other stones, and put them in the place of those stones; and he shall take other mortar, and shall plaster the house.", "acv": "And they shall take other stones, and put them in the place of those stones. And he shall take other mortar, and shall plaster the house.", "anderson": "", "haweis": "", "noyes": "", "webster": "And they shall take other stones, and put [them] in the place of those stones; and he shall take other mortar, and shall plaster the house.", "vulgate": "lapidesque alios reponi pro his qui ablati fuerint et luto alio liniri domum;", "brenton": "And they shall take other scraped stones, and put them in the place of the former stones, and they shall take other plaster and plaster the house."}}, {"v": 43, "ref": "14:43", "o": "וְ/אִם יָשׁ֤וּב הַ/נֶּ֨גַע֙ וּ/פָרַ֣ח בַּ/בַּ֔יִת אַחַ֖ר חִלֵּ֣ץ אֶת הָ/אֲבָנִ֑ים וְ/אַחֲרֵ֛י הִקְצ֥וֹת אֶת הַ/בַּ֖יִת וְ/אַחֲרֵ֥י הִטּֽוֹחַ", "en": {"kjv": "And if the plague come again, and break out in the house, after that he hath taken away the stones, and after he hath scraped the house, and after it is plaistered;", "web": "“If the plague comes again, and breaks out in the house, after he has taken out the stones, and after he has scraped the house, and after it was plastered;", "bsb": "If the mildew reappears in the house after the stones have been torn out and the house has been scraped and replastered,", "asv": "And if the plague come again, and break out in the house, after that he hath taken out the stones, and after he hath scraped the house, and after it is plastered;", "ylt": "`And if the plague return, and hath broken out in the house, after he hath drawn out the stones, and after the scraping of the house, and after the daubing;", "tyndale": "Yf now the plage come agayne ad breake out in the housse, after that they haue taken awaye the stones and scraped the housse, and after that the housse is playsterd anew:", "dra": "But if after the stones be taken out, and the dust scraped off, and it be plastered with other earth.", "bbe": "And if the disease comes out again in the house after he has taken out the stones and after the walls have been rubbed and the new paste put on,", "geneva": "But if the plague come againe and breake out in the house, after that he hath taken away ye stones, and after that hee hath scraped and playstered the house,", "wycliffe": "But if aftir that the stoonus ben takun awey, and the dust is borun out,", "rotherham": "But if the mark again breaketh out in the house, after the taking out of the stones,—and after the scraping of the house and after the plastering,;", "darby": "And if the plague come again, and break out in the house, after he hath taken away the stones, and after he hath scraped the house, and after it is plastered,", "twenty": "", "jps": "And if the plague come again, and break out in the house, after that the stones have been taken out, and after the house hath been scraped, and after it is plastered;", "acv": "And if the disease comes again, and breaks out in the house, after he has taken out the stones, and after he has scraped the house, and after it is plastered,", "anderson": "", "haweis": "", "noyes": "", "webster": "And if the plague shall return, and break out in the house, after that he hath taken away the stones, and after he hath scraped the house, and after it is plastered;", "vulgate": "sin autem postquam eruti sunt lapides et pulvis elatus et alia terra lita;", "brenton": "And if the plague should return again, and break out in the house after they have taken away the stones and after the house is scraped, and after it has been plastered,"}}, {"v": 44, "ref": "14:44", "o": "וּ/בָא֙ הַ/כֹּהֵ֔ן וְ/רָאָ֕ה וְ/הִנֵּ֛ה פָּשָׂ֥ה הַ/נֶּ֖גַע בַּ/בָּ֑יִת צָרַ֨עַת מַמְאֶ֥רֶת הִ֛וא בַּ/בַּ֖יִת טָמֵ֥א הֽוּא", "en": {"kjv": "Then the priest shall come and look, and, behold, if the plague be spread in the house, it is a fretting leprosy in the house: it is unclean.", "web": "then the priest shall come in and look; and behold, if the plague has spread in the house, it is a destructive mildew in the house. It is unclean.", "bsb": "the priest must come and inspect it. If the mildew has spread in the house, it is a destructive mildew; the house is unclean.", "asv": "then the priest shall come in and look; and, behold, if the plague be spread in the house, it is a fretting leprosy in the house: it is unclean.", "ylt": "then hath the priest come in and seen, and lo, the plague hath spread in the house; it is a fretting leprosy in the house; it is unclean.", "tyndale": "let the preast come and se it. And yf then he perceaue that the plage hath eate further in the housse, then it is a fretynge leprosye that is in the housse ad it is vncleane.", "dra": "The priest going in perceive that the leprosy is returned, and the walls full of spots, it is a lasting leprosy, and the house is unclean.", "bbe": "Then the priest will come and see it; and if the disease in the house is increased in size, it is the leper's disease working out in the house: it is unclean.", "geneva": "Then the Priest shall come and see: and if the plague growe in the house, it is a freating leprosie in the house: it is therefore vncleane.", "wycliffe": "and othere erthe is daubid, the preest entrith, and seeth the lepre turned ayen, and the wallis spreynt with spottis, the lepre is stidfastly dwellynge, and the hows is vnclene;", "rotherham": "then shall the priest come in, and take a view, and lo! if the mark hath spread in the house, a fretting leprosy, it is in the house unclean, it is,", "darby": "then the priest shall come, and when he looketh, and behold, the plague hath spread in the house, it is a corroding leprosy in the house: it is unclean.", "twenty": "", "jps": "then the priest shall come in and look; and, behold, if the plague be spread in the house, it is a malignant leprosy in the house: it is unclean.", "acv": "then the priest shall come in and look. And, behold, if the disease has spread in the house, it is a fretting leprosy in the house; it is unclean.", "anderson": "", "haweis": "", "noyes": "", "webster": "Then the priest shall come and look; and behold, [if] the plague is spread in the house, it [is] a fretting leprosy in the house: it [is] unclean.", "vulgate": "ingressus sacerdos viderit reversam lepram et parietes aspersos maculis lepra est perseverans et inmunda domus;", "brenton": "then the priest shall go in and see if the plague is spread in the house: it is a confirmed leprosy in the house, it is unclean."}}, {"v": 45, "ref": "14:45", "o": "וְ/נָתַ֣ץ אֶת הַ/בַּ֗יִת אֶת אֲבָנָי/ו֙ וְ/אֶת עֵצָ֔י/ו וְ/אֵ֖ת כָּל עֲפַ֣ר הַ/בָּ֑יִת וְ/הוֹצִיא֙ אֶל מִ/ח֣וּץ לָ/עִ֔יר אֶל מָק֖וֹם טָמֵֽא", "en": {"kjv": "And he shall break down the house, the stones of it, and the timber thereof, and all the morter of the house; and he shall carry them forth out of the city into an unclean place.", "web": "He shall break down the house, its stones, and its timber, and all the house’s mortar. He shall carry them out of the city into an unclean place.", "bsb": "It must be torn down with its stones, its timbers, and all its plaster, and taken outside the city to an unclean place.", "asv": "And he shall break down the house, the stones of it, and the timber thereof, and all the mortar of the house; and he shall carry them forth out of the city into an unclean place.", "ylt": "`And he hath broken down the house, its stones, and its wood, and all the clay of the house, and he hath brought them forth unto the outside of the city, unto an unclean place.", "tyndale": "Then they shall breake doune the housse: both stones, tymbre ad all the morter of the housse, and carye it out of the citye vnto a foule place.", "dra": "And they shall destroy it forthwith, and shall cast the stones and timber thereof, and all the dust without the town into an unclean place.", "bbe": "And the house will have to be pulled down, the stones of it and the wood and the paste; and everything is to be taken out to an unclean place outside the town.", "geneva": "And hee shall breake downe the house, with the stones of it, and the timber thereof, and all the mortar of the house, and hee shall carie them out of the citie vnto an vncleane place.", "wycliffe": "which hows thei schulen destrye anoon, and thei schulen caste out of the citee, in an vnclene place, the stoonys therof, and the trees, and al the dust.", "rotherham": "and he shall pull down the house,—the stones thereof, and the timber thereof and all the mortar of the house,—and shall carry them forth outside the city, into an unclean place.", "darby": "And they shall break down the house, the stones of it, and the timber thereof, and all the mortar of the house, and shall carry them forth out of the city to an unclean place.", "twenty": "", "jps": "And he shall break down the house, the stones of it, and the timber thereof, and all the mortar of the house; and he shall carry them forth out of the city into an unclean place.", "acv": "And he shall break down the house, the stones of it, and the timber of it, and all the mortar of the house, and he shall carry them forth out of the city into an unclean place.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall break down the house, its stones, and its timber, and all the mortar of the house: and he shall carry [them] forth out of the city to an unclean place.", "vulgate": "quam statim destruent et lapides eius ac ligna atque universum pulverem proicient extra oppidum in loco inmundo;", "brenton": "And they shall take down the house, and its timbers and its stones, and they shall carry out all the mortar without the city into an unclean place."}}, {"v": 46, "ref": "14:46", "o": "וְ/הַ/בָּא֙ אֶל הַ/בַּ֔יִת כָּל יְמֵ֖י הִסְגִּ֣יר אֹת֑/וֹ יִטְמָ֖א עַד הָ/עָֽרֶב", "en": {"kjv": "Moreover he that goeth into the house all the while that it is shut up shall be unclean until the even.", "web": "“Moreover he who goes into the house while it is shut up shall be unclean until the evening.", "bsb": "Anyone who enters the house during any of the days that it is closed up will be unclean until evening.", "asv": "Moreover he that goeth into the house all the while that it is shut up shall be unclean until the even.", "ylt": "`And he who is going in unto the house all the days he hath shut it up, is unclean till the evening;", "tyndale": "Moreouer he that goeth in to the housse all the whyle that it is shett vp, shalbe vncleane vntyll nighte.", "dra": "He that entereth into the house when it is shut, shall be unclean until evening,", "bbe": "And, in addition, anyone who goes into the house at any time, while it is shut up, will be unclean till evening.", "geneva": "Moreouer he that goeth into the house all the while that it is shut vp, hee shall bee vncleane vntill the euen.", "wycliffe": "He that entrith in to the hous, whanne it is schit, schal be vnclene `til to euentid,", "rotherham": "And as for him that entereth into the house, all the days it is shut up, he shall be unclean until the evening;", "darby": "And he that goeth into the house as long as it is shut up shall be unclean until the even.", "twenty": "", "jps": "Moreover he that goeth into the house all the while that it is shut up shall be unclean until the even.", "acv": "Moreover he who goes into the house all the while that it is shut up shall be unclean until the evening.", "anderson": "", "haweis": "", "noyes": "", "webster": "Moreover, he that goeth into the house all the while that it is shut up, shall be unclean until the evening.", "vulgate": "qui intraverit domum quando clausa est inmundus erit usque ad vesperum;", "brenton": "And he that goes into the house at any time, during its separation, shall be unclean until evening."}}, {"v": 47, "ref": "14:47", "o": "וְ/הַ/שֹּׁכֵ֣ב בַּ/בַּ֔יִת יְכַבֵּ֖ס אֶת בְּגָדָ֑י/ו וְ/הָ/אֹכֵ֣ל בַּ/בַּ֔יִת יְכַבֵּ֖ס אֶת בְּגָדָֽי/ו", "en": {"kjv": "And he that lieth in the house shall wash his clothes; and he that eateth in the house shall wash his clothes.", "web": "He who lies down in the house shall wash his clothes; and he who eats in the house shall wash his clothes.", "bsb": "And anyone who sleeps in the house or eats in it must wash his clothes.", "asv": "And he that lieth in the house shall wash his clothes; and he that eateth in the house shall wash his clothes.", "ylt": "and he who is lying in the house doth wash his garments; and he who is eating in the house doth wash his garments.", "tyndale": "And he that slepeth in the housse shall wasshe his clothes, and he also that eateth in the housse shall wasshe hys clothes.", "dra": "And he that sleepeth in it, and eateth any thing, shall wash his clothes.", "bbe": "And anyone who has been sleeping in the house will have to have his clothing washed; and anyone who takes food in that house will have to have his clothing washed.", "geneva": "Hee also that sleepeth in the house shall wash his clothes: he likewise that eateth in the house, shall wash his clothes.", "wycliffe": "and he that slepith and etith ony thing therynne, schal waische hise clothis.", "rotherham": "And, he that lieth in the house, shall wash his clothes, and he that eateth in the house shall wash his clothes.", "darby": "And he that sleepeth in the house shall wash his garments, and he that eateth in the house shall wash his garments.", "twenty": "", "jps": "And he that lieth in the house shall wash his clothes; and he that eateth in the house shall wash his clothes.", "acv": "And he who lies in the house shall wash his clothes. And he who eats in the house shall wash his clothes.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he that lieth in the house shall wash his clothes: and he that eateth in the house shall wash his clothes.", "vulgate": "et qui dormierit in ea et comederit quippiam lavabit vestimenta sua;", "brenton": "And he that sleeps in the house shall wash his garments, and be unclean until evening; and he that eats in the house shall wash his garments, and be unclean until evening."}}, {"v": 48, "ref": "14:48", "o": "וְ/אִם בֹּ֨א יָבֹ֜א הַ/כֹּהֵ֗ן וְ/רָאָה֙ וְ֠/הִנֵּה לֹא פָשָׂ֤ה הַ/נֶּ֨גַע֙ בַּ/בַּ֔יִת אַחֲרֵ֖י הִטֹּ֣חַ אֶת הַ/בָּ֑יִת וְ/טִהַ֤ר הַ/כֹּהֵן֙ אֶת הַ/בַּ֔יִת כִּ֥י נִרְפָּ֖א הַ/נָּֽגַע", "en": {"kjv": "And if the priest shall come in, and look upon it, and, behold, the plague hath not spread in the house, after the house was plaistered: then the priest shall pronounce the house clean, because the plague is healed.", "web": "“If the priest shall come in, and examine it, and behold, the plague hasn’t spread in the house, after the house was plastered, then the priest shall pronounce the house clean, because the plague is healed.", "bsb": "If, however, the priest comes and inspects it, and the mildew has not spread after the house has been replastered, he shall pronounce the house clean, because the mildew is gone.", "asv": "And if the priest shall come in, and look, and, behold, the plague hath not spread in the house, after the house was plastered; then the priest shall pronounce the house clean, because the plague is healed.", "ylt": "`And if the priest certainly come in, and hath seen, and lo, the plague hath not spread in the house after the daubing of the house, then hath the priest pronounced the house clean, for the plague hath been healed.", "tyndale": "But and yf the preast come and se that the plage hath sprede no futher in the housse after that it is new playsterd, the let him make it cleane for the plage is healed.", "dra": "But if the priest going in perceive that the leprosy is not spread in the house, after it was plastered again, he shall purify it, it being cured.", "bbe": "And if the priest comes in, and sees that the disease is not increased after the new paste has been put on the house, then the priest will say that the house is clean, because the disease is gone.", "geneva": "But if the Priest shall come and see, that the plague hath spread no further in the house, after the house be plaistered, the Priest shall pronounce that house cleane, for the plague is healed.", "wycliffe": "That if the preest entrith, and seeth that the lepre encreesside not in the hows, aftir that it was daubid the secounde tyme, he schal clense it; for heelthe is yoldun.", "rotherham": "But, though the priest do come, into the house, and take a view, yet lo! if the plague-mark hath not spread in the house after the house was plastered, then shall the priest pronounce the house clean, for, healed, is the plague.", "darby": "But if the priest shall come in and look, and behold, the plague hath not spread in the house, after the house hath been plastered, the priest shall pronounce the house clean; for the plague is healed.", "twenty": "", "jps": "And if the priest shall come in, and look, and, behold, the plague hath not spread in the house, after the house was plastered; then the priest shall pronounce the house clean, because the plague is healed.", "acv": "And if the priest shall come in, and look, and, behold, the disease has not spread in the house after the house was plastered, then the priest shall pronounce the house clean, because the disease is healed.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if the priest shall come in, and look [upon it], and behold, the plague hath not spread in the house, after the house was plastered: then the priest shall pronounce the house clean, because the plague is healed.", "vulgate": "quod si introiens sacerdos viderit lepram non crevisse in domo postquam denuo lita est purificabit eam reddita sanitate;", "brenton": "and if the priest shall arrive and enter and see, and behold the plague be not at all spread in the house after the house has been plastered, then the priest shall declare the house clean, because the plague is healed."}}, {"v": 49, "ref": "14:49", "o": "וְ/לָקַ֛ח לְ/חַטֵּ֥א אֶת הַ/בַּ֖יִת שְׁתֵּ֣י צִפֳּרִ֑ים וְ/עֵ֣ץ אֶ֔רֶז וּ/שְׁנִ֥י תוֹלַ֖עַת וְ/אֵזֹֽב", "en": {"kjv": "And he shall take to cleanse the house two birds, and cedar wood, and scarlet, and hyssop:", "web": "To cleanse the house he shall take two birds, and cedar wood, and scarlet, and hyssop.", "bsb": "He is to take two birds, cedar wood, scarlet yarn, and hyssop to purify the house;", "asv": "And he shall take to cleanse the house two birds, and cedar-wood, and scarlet, and hyssop:", "ylt": "`And he hath taken for the cleansing of the house two birds, and cedar wood, and scarlet, and hyssop;", "tyndale": "And let him take to clense the housse with all: two birdes, cypresse wodd, ad purple clothe ad ysope.", "dra": "And for the purification thereof he shall take two sparrows, and cedar wood, and scarlet, and hyssop.", "bbe": "And in order to make the house clean, let him take two birds and cedar-wood and red thread and hyssop;", "geneva": "Then shall he take to purifie the house, two sparrowes, and cedar wood, and skarlet lace, and hyssope.", "wycliffe": "And in the clensyng therof he schal take twey sparewis, and `a tre of cedre, and `a reed threed, and isope.", "rotherham": "Then shall he take to cleanse, the house, two birds,—and cedar wood, and crimson, and hyssop;", "darby": "And he shall take, to purge the house from the defilement, two birds, and cedar-wood, and scarlet, and hyssop;", "twenty": "", "jps": "And he shall take to cleanse the house two birds, and cedar-wood, and scarlet, and hyssop.", "acv": "And he shall take two birds, and cedar wood, and scarlet, and hyssop to cleanse the house.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall take to cleanse the house two birds, and cedar-wood, and scarlet, and hyssop:", "vulgate": "et in purificationem eius sumet duos passeres lignumque cedrinum et vermiculum atque hysopum;", "brenton": "And he shall take to purify the house two clean living birds, and cedar wood, and spun scarlet, and hyssop."}}, {"v": 50, "ref": "14:50", "o": "וְ/שָׁחַ֖ט אֶת הַ/צִּפֹּ֣ר הָ/אֶחָ֑ת אֶל כְּלִי חֶ֖רֶשׂ עַל מַ֥יִם חַיִּֽים", "en": {"kjv": "And he shall kill the one of the birds in an earthen vessel over running water:", "web": "He shall kill one of the birds in an earthen vessel over running water.", "bsb": "and he shall slaughter one of the birds over fresh water in a clay pot.", "asv": "and he shall kill one of the birds in an earthen vessel over running water:", "ylt": "and he hath slaughtered the one bird upon an earthen vessel, over running water;", "tyndale": "And let him kyll one of the byrdes ouer an erthen vessel of runnynge water,", "dra": "And having immolated one sparrow in an earthen vessel, over living waters,", "bbe": "And put one of the birds to death in a vessel of earth over flowing water;", "geneva": "And hee shall kill one sparowe ouer pure water in an earthen vessell,", "wycliffe": "And whanne o sparewe is offrid in a vessel of erthe, on quyk watris,", "rotherham": "and shall kill one bird,—within an earthen vessel over living water;", "darby": "and he shall kill one bird in an earthen vessel over running water;", "twenty": "", "jps": "And he shall kill one of the birds in an earthen vessel over running water.", "acv": "And he shall kill one of the birds in an earthen vessel over running water.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall kill one of the birds in an earthen vessel, over running water:", "vulgate": "et immolato uno passere in vase fictili super aquas vivas;", "brenton": "And he shall slay one bird in an earthen vessel over running water."}}, {"v": 51, "ref": "14:51", "o": "וְ/לָקַ֣ח אֶת עֵֽץ הָ֠/אֶרֶז וְ/אֶת הָ֨/אֵזֹ֜ב וְ/אֵ֣ת שְׁנִ֣י הַ/תּוֹלַ֗עַת וְ/אֵת֮ הַ/צִּפֹּ֣ר הַֽ/חַיָּה֒ וְ/טָבַ֣ל אֹתָ֗/ם בְּ/דַם֙ הַ/צִּפֹּ֣ר הַ/שְּׁחוּטָ֔ה וּ/בַ/מַּ֖יִם הַֽ/חַיִּ֑ים וְ/הִזָּ֥ה אֶל הַ/בַּ֖יִת שֶׁ֥בַע פְּעָמִֽים", "en": {"kjv": "And he shall take the cedar wood, and the hyssop, and the scarlet, and the living bird, and dip them in the blood of the slain bird, and in the running water, and sprinkle the house seven times:", "web": "He shall take the cedar wood, and the hyssop, and the scarlet, and the living bird, and dip them in the blood of the slain bird, and in the running water, and sprinkle the house seven times.", "bsb": "Then he shall take the cedar wood, the hyssop, the scarlet yarn, and the live bird, dip them in the blood of the slaughtered bird and the fresh water, and sprinkle the house seven times.", "asv": "and he shall take the cedar-wood, and the hyssop, and the scarlet, and the living bird, and dip them in the blood of the slain bird, and in the running water, and sprinkle the house seven times:", "ylt": "and he hath taken the cedar wood, and the hyssop, and the scarlet, and the living bird, and hath dipped them in the blood of the slaughtered bird, and in the running water, and hath sprinkled upon the house seven times.", "tyndale": "ad take the cipresse wodd, the ysope, the purple ad the lyuynge byrde, ad dyppe them in the bloude of the slayne byrde and in the runninge water, and sprinkle apon the housse seuen tymes,", "dra": "He shall take the cedar wood, and the hyssop, and the scarlet, and the living sparrow, and shall dip all in the blood of the sparrow that is immolated, and in the living water: and he shall sprinkle the house seven times.", "bbe": "And take the cedar-wood and the hyssop and the red thread and the living bird and put them in the blood of the dead bird and in the flowing water, shaking it over the house seven times.", "geneva": "And shall take the cedar wood, and the hyssope, and the skarlet lace with the liue Sparrow, and dip them in the blood of the slayne Sparrow, and in the pure water, and sprinkle the house seuen times:", "wycliffe": "he schal take the `tre of cedre, and ysope, and reed threed, and the quyk sparewe, and he schal dippe alle thingis in the blood of the sparewe offrid, and in lyuynge watris;", "rotherham": "and take the cedar wood and the hyssop, and the crimson and the living bird, and dip them in the blood of the slain bird, and in the living water,—and sprinkle the house seven times;", "darby": "and he shall take the cedar-wood and the hyssop and the scarlet, and the living bird, and dip them in the blood of the bird that was killed, and in the running water, and sprinkle the house seven times;", "twenty": "", "jps": "And he shall take the cedar-wood, and the hyssop, and the scarlet, and the living bird, and dip them in the blood of the slain bird, and in the running water, and sprinkle the house seven times.", "acv": "And he shall take the cedar wood, and the hyssop, and the scarlet, and the living bird, and dip them in the blood of the slain bird, and in the running water, and sprinkle the house seven times.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall take the cedar-wood, and the hyssop, and the scarlet, and the living bird, and dip them in the blood of the slain bird, and in the running water, and sprinkle the house seven times:", "vulgate": "tollet lignum cedrinum et hysopum et coccum et passerem vivum et intinguet omnia in sanguine passeris immolati atque in aquis viventibus et asperget domum septies;", "brenton": "And he shall take the cedar wood, and the spun scarlet, and the hyssop, and the living bird; and shall dip it into the blood of the bird slain over running water, and with them he shall sprinkle the house seven times."}}, {"v": 52, "ref": "14:52", "o": "וְ/חִטֵּ֣א אֶת הַ/בַּ֔יִת בְּ/דַם֙ הַ/צִּפּ֔וֹר וּ/בַ/מַּ֖יִם הַֽ/חַיִּ֑ים וּ/בַ/צִּפֹּ֣ר הַ/חַיָּ֗ה וּ/בְ/עֵ֥ץ הָ/אֶ֛רֶז וּ/בָ/אֵזֹ֖ב וּ/בִ/שְׁנִ֥י הַ/תּוֹלָֽעַת", "en": {"kjv": "And he shall cleanse the house with the blood of the bird, and with the running water, and with the living bird, and with the cedar wood, and with the hyssop, and with the scarlet:", "web": "He shall cleanse the house with the blood of the bird, and with the running water, with the living bird, with the cedar wood, with the hyssop, and with the scarlet;", "bsb": "And he shall cleanse the house with the bird’s blood, the fresh water, the live bird, the cedar wood, the hyssop, and the scarlet yarn.", "asv": "and he shall cleanse the house with the blood of the bird, and with the running water, and with the living bird, and with the cedar-wood, and with the hyssop, and with the scarlet:", "ylt": "`And he hath cleansed the house with the blood of the bird, and with the running water, and with the living bird, and with the cedar wood, and with the hyssop, and with the scarlet;", "tyndale": "and clense the housse with the bloude of the byrde, and with the runninge water, ad with the lyuyng byrde, ad with the cypresse wodd, ad the ysope ad the purple clothe", "dra": "And shall purify it as well with the blood of the sparrow, as with the living water, and with the living sparrow, and with the cedar wood, and the hyssop, and the scarlet.", "bbe": "And he will make the house clean with the blood of the bird and the flowing water and with the living bird and with the cedar-wood and the hyssop and the red thread.", "geneva": "So shall hee clense the house with ye blood of the sparowe, and with the pure water, and with the liue sparowe, and with the cedar wood, and with the hyssope, and with the skarlet lace.", "wycliffe": "and he schal sprynge the hows seuen sithis; and he schal clense it as wel in the blood of the sparewe as in lyuynge watris, and in the quyk sparewe, and in the `tre of cedre, and in ysope, and `reed threed.", "rotherham": "and so cleanse the house, with the blood of the bird and with the living water,—and with the living bird, and with the cedar wood and with the hyssop, and with the crimson;", "darby": "and he shall purge the house from the defilement with the blood of the bird, and with the running water, and with the living bird, and with the cedar-wood, and with the hyssop, and with the scarlet;", "twenty": "", "jps": "And he shall cleanse the house with the blood of the bird, and with the running water, and with the living bird, and with the cedar-wood, and with the hyssop, and with the scarlet.", "acv": "And he shall cleanse the house with the blood of the bird, and with the running water, and with the living bird, and with the cedar wood, and with the hyssop, and with the scarlet,", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall cleanse the house with the blood of the bird, and with the running water, and with the living bird, and with the cedar wood, and with the hyssop, and with the scarlet:", "vulgate": "purificabitque eam tam in sanguine passeris quam in aquis viventibus et in passere vivo lignoque cedrino et hysopo atque vermiculo;", "brenton": "and he shall purify the house with the blood of the bird, and with the running water, and with the living bird, and with the cedar wood, and with the hyssop, and with the spun scarlet."}}, {"v": 53, "ref": "14:53", "o": "וְ/שִׁלַּ֞ח אֶת הַ/צִּפֹּ֧ר הַֽ/חַיָּ֛ה אֶל מִ/ח֥וּץ לָ/עִ֖יר אֶל פְּנֵ֣י הַ/שָּׂדֶ֑ה וְ/כִפֶּ֥ר עַל הַ/בַּ֖יִת וְ/טָהֵֽר", "en": {"kjv": "But he shall let go the living bird out of the city into the open fields, and make an atonement for the house: and it shall be clean.", "web": "but he shall let the living bird go out of the city into the open field. So shall he make atonement for the house; and it shall be clean.”", "bsb": "Finally, he is to release the live bird into the open fields outside the city. In this way he will make atonement for the house, and it will be clean.", "asv": "but he shall let go the living bird out of the city into the open field: so shall he make atonement for the house; and it shall be clean.", "ylt": "and he hath sent away the living bird unto the outside of the city unto the face of the field, and hath made atonement for the house, and it hath been clean.", "tyndale": "And he shall lett the lyuynge byrde flee oute off the towne in to the wylde feldes, and so make an attonement for the housse, and it shalbe cleane.", "dra": "And when he hath let go the sparrow to fly freely away into the field, he shall pray for the house: and it shall be rightly cleansed.", "bbe": "But he will let the living bird go out of the town into the open country; so he will take away sin from the house and it will be clean.", "geneva": "Afterwarde he shall let go the liue sparowe out of the towne into the broad fieldes: so shall he make atonement for the house, and it shall be cleane.", "wycliffe": "And whanne he hath left the sparewe to fle in to the feeld frely, he schal preye for the hows, and it schal be clensid riytfuli.", "rotherham": "and shall let go the living bird unto the outside of the city, unto the face of the field,—so shall he put a propitiatory-covering over the house and it shall be clean.", "darby": "and he shall let the living bird loose out of the city into the open field; and he shall make atonement for the house, and it is clean.", "twenty": "", "jps": "But he shall let go the living bird out of the city into the open field; so shall he make atonement for the house; and it shall be clean.", "acv": "but he shall let the living bird go out of the city into the open field. So he shall make atonement for the house, and it shall be clean.", "anderson": "", "haweis": "", "noyes": "", "webster": "But he shall let go the living bird out of the city into the open fields, and make an atonement for the house: and it shall be clean.", "vulgate": "cumque dimiserit passerem avolare in agrum libere orabit pro domo et iure mundabitur;", "brenton": "And he shall let the living bird go out of the city into the field, and shall make atonement for the house, and it shall be clean."}}, {"v": 54, "ref": "14:54", "o": "זֹ֖את הַ/תּוֹרָ֑ה לְ/כָל נֶ֥גַע הַ/צָּרַ֖עַת וְ/לַ/נָּֽתֶק", "en": {"kjv": "This is the law for all manner of plague of leprosy, and scall,", "web": "This is the law for any plague of leprosy, and for an itch,", "bsb": "This is the law for any infectious skin disease, for a scaly outbreak,", "asv": "This is the law for all manner of plague of leprosy, and for a scall,", "ylt": "`This is the law for every plague of the leprosy and for scall,", "tyndale": "This is the lawe of all maner plage of leprosye and breakynge out,", "dra": "This is the law of every kind of leprosy and stroke.", "bbe": "This is the law for all signs of the leper's disease and for skin diseases;", "geneva": "This is the law for euery plague of leprosie and blacke spot,", "wycliffe": "This is the lawe of al lepre,", "rotherham": "This, is the law,—for every plague-mark of leprosy and for scall;", "darby": "This is the law for every sore of leprosy, and for the scall,", "twenty": "", "jps": "This is the law for all manner of plague of leprosy, and for a scall;", "acv": "This is the law for all manner of a leprous disease, and for a scall,", "anderson": "", "haweis": "", "noyes": "", "webster": "This [is] the law for all manner of plague of leprosy, and scall,", "vulgate": "ista est lex omnis leprae et percussurae;", "brenton": "This is the law concerning every plague of leprosy and scurf,"}}, {"v": 55, "ref": "14:55", "o": "וּ/לְ/צָרַ֥עַת הַ/בֶּ֖גֶד וְ/לַ/בָּֽיִת", "en": {"kjv": "And for the leprosy of a garment, and of a house,", "web": "and for the destructive mildew of a garment, and for a house,", "bsb": "for mildew in clothing or in a house,", "asv": "and for the leprosy of a garment, and for a house,", "ylt": "and for leprosy of a garment, and of a house,", "tyndale": "and of the leprosye off clothe and housse:", "dra": "Of the leprosy of garments and houses,", "bbe": "And for signs of disease in clothing, or in a house;", "geneva": "And of the leprosie of the garment, and of the house,", "wycliffe": "and of smytyng, of lepre of clothis, and of housis,", "rotherham": "and for garment leprosy, and for house [leprosy] ;", "darby": "and for the leprosy of garments, and of houses,", "twenty": "", "jps": "and for the leprosy of a garment, and for a house;", "acv": "and for a leprous disease of a garment, and for a house,", "anderson": "", "haweis": "", "noyes": "", "webster": "And for the leprosy of a garment, and of a house,", "vulgate": "leprae vestium et domorum;", "brenton": "and of the leprosy of a garment, and of a house,"}}, {"v": 56, "ref": "14:56", "o": "וְ/לַ/שְׂאֵ֥ת וְ/לַ/סַּפַּ֖חַת וְ/לַ/בֶּהָֽרֶת", "en": {"kjv": "And for a rising, and for a scab, and for a bright spot:", "web": "and for a rising, and for a scab, and for a bright spot;", "bsb": "and for a swelling, rash, or spot,", "asv": "and for a rising, and for a scab, and for a bright spot;", "ylt": "and for a rising, and for a scab, and for a bright spot, --", "tyndale": "and of rysynges, scabbes and glysterynge white", "dra": "Of a scar and of blisters breaking out of a shining spot, and when the colours are diversely changed:", "bbe": "And for a growth or a bad place or a bright mark on the skin;", "geneva": "And of the swelling, and of the skab, and of the white spot.", "wycliffe": "of syngne of wounde, and of litle whelkis brekynge out, of spotte schynynge, and in colours chaungid in to dyuerse spices,", "rotherham": "and for rising, and for scab and for a bright spot;", "darby": "and for the rising, and for the scab, and for the bright spot,", "twenty": "", "jps": "and for a rising, and for a scab, and for a bright spot;", "acv": "and for a rising, and for a scab, and for a bright spot,", "anderson": "", "haweis": "", "noyes": "", "webster": "And for a rising, and for a scab, and for a bright spot:", "vulgate": "cicatricis et erumpentium papularum lucentis maculae et in varias species coloribus inmutatis;", "brenton": "and of a sore, and of a clear spot, and of a shining one,"}}, {"v": 57, "ref": "14:57", "o": "לְ/הוֹרֹ֕ת בְּ/י֥וֹם הַ/טָּמֵ֖א וּ/בְ/י֣וֹם הַ/טָּהֹ֑ר זֹ֥את תּוֹרַ֖ת הַ/צָּרָֽעַת", "en": {"kjv": "To teach when it is unclean, and when it is clean: this is the law of leprosy.", "web": "to teach when it is unclean, and when it is clean. This is the law of leprosy.", "bsb": "to determine when something is clean or unclean. This is the law regarding skin diseases and mildew.”", "asv": "to teach when it is unclean, and when it is clean: this is the law of leprosy.", "ylt": "to direct in the day of being unclean, and in the day of being clean; this is the law of the leprosy.'", "tyndale": "", "dra": "That it may be known when a thing is clean or unclean.", "bbe": "To make clear when it is unclean and when it is clean: this is the law about the disease of the leper.", "geneva": "This is the lawe of the leprosie to teache when a thing is vncleane, and when it is cleane.", "wycliffe": "that it may be wist, what is cleene, ether uncleene.", "rotherham": "to give instruction, on the day of declaring unclean, and on the day of declaring clean,—This is the law of leprosy.", "darby": "to teach when there is uncleanness, and when it is purified: this is the law of leprosy.", "twenty": "", "jps": "to teach when it is unclean, and when it is clean; this is the law of leprosy.", "acv": "to teach when it is unclean, and when it is clean. This is the law of a leprous disease.", "anderson": "", "haweis": "", "noyes": "", "webster": "To teach when [it is] unclean, and when [it is] clean: this [is] the law of leprosy.", "vulgate": "ut possit sciri quo tempore mundum quid vel inmundum sit;", "brenton": "and of declaring in what day it is unclean, and in what day it shall be purged: this is the law of the leprosy."}}]}, {"c": 15, "verses": [{"v": 1, "ref": "15:1", "o": "וַ/יְדַבֵּ֣ר יְהוָ֔ה אֶל מֹשֶׁ֥ה וְ/אֶֽל אַהֲרֹ֖ן לֵ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses and to Aaron, saying,", "web": "Yahweh spoke to Moses and to Aaron, saying,", "bsb": "And the LORD said to Moses and Aaron,", "asv": "And Jehovah spake unto Moses and to Aaron, saying,", "ylt": "And Jehovah speaketh unto Moses, and unto Aaron, saying,", "tyndale": "And the Lorde spake vnto Moses and Aaron sayenge,", "dra": "And the Lord spoke to Moses and Aaron, saying:", "bbe": "And the Lord said to Moses and to Aaron,", "geneva": "Moreouer the Lord spake vnto Moses, and to Aaron, saying,", "wycliffe": "And the Lord spak to Moises and Aaron, `and seide,", "rotherham": "And Yahweh spake unto Moses and unto Aaron saying:", "darby": "And Jehovah spoke to Moses and to Aaron, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses and to Aaron, saying:", "acv": "And Jehovah spoke to Moses and to Aaron, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses and to Aaron, saying,", "vulgate": "locutusque est Dominus ad Mosen et Aaron dicens;", "brenton": "And the Lord spoke to Moses and Aaron, saying,"}}, {"v": 2, "ref": "15:2", "o": "דַּבְּרוּ֙ אֶל בְּנֵ֣י יִשְׂרָאֵ֔ל וַ/אֲמַרְתֶּ֖ם אֲלֵ/הֶ֑ם אִ֣ישׁ אִ֗ישׁ כִּ֤י יִהְיֶה֙ זָ֣ב מִ/בְּשָׂר֔/וֹ זוֹב֖/וֹ טָמֵ֥א הֽוּא", "en": {"kjv": "Speak unto the children of Israel, and say unto them, When any man hath a running issue out of his flesh, because of his issue he is unclean.", "web": "“Speak to the children of Israel, and tell them, ‘When any man has a discharge from his body, because of his discharge he is unclean.", "bsb": "“Say to the Israelites, ‘When any man has a bodily discharge, the discharge is unclean.", "asv": "Speak unto the children of Israel, and say unto them, When any man hath an issue out of his flesh, because of his issue he is unclean.", "ylt": "`Speak unto the sons of Israel, and ye have said unto them, When there is an issue out of the flesh of any man, for his issue he is unclean;", "tyndale": "speake vnto the children of Israel and saye vnto them: euery ma that hath a runnynge yssue in his flesh, is vncleane by the reason of his yssue.", "dra": "Speak to the children of Israel, and say to them: The man that hath an issue of seed, shall be unclean.", "bbe": "Say to the children of Israel: If a man has an unclean flow from his flesh, it will make him unclean.", "geneva": "Speake vnto the children of Israel, and say vnto them, Whosoeuer hath an issue from his flesh, is vncleane, because of his issue.", "wycliffe": "Speke ye to the sones of Israel, and seie ye to hem, A man that suffrith the rennyng out of seed, schal be vncleene;", "rotherham": "Speak unto the sons of Israel, and ye shall say unto them,—When, any man whatsoever, hath a flowing from his flesh, his flux, is, unclean.", "darby": "Speak unto the children of Israel, and say unto them, If any man have a flux from his flesh, because of his flux he is unclean.", "twenty": "", "jps": "Speak unto the children of Israel, and say unto them: When any man hath an issue out of his flesh, his issue is unclean.", "acv": "Speak to the sons of Israel, and say to them, When any man has an issue out of his flesh, he is unclean because of his issue.", "anderson": "", "haweis": "", "noyes": "", "webster": "Speak to the children of Israel, and say to them, When any man hath a running issue out of his flesh, [because of] his issue he [is] unclean.", "vulgate": "loquimini filiis Israhel et dicite eis vir qui patitur fluxum seminis inmundus erit;", "brenton": "Speak to the children of Israel, and thou shalt say to them, Whatever man shall have an issue out of his body, his issue is unclean."}}, {"v": 3, "ref": "15:3", "o": "וְ/זֹ֛את תִּהְיֶ֥ה טֻמְאָת֖/וֹ בְּ/זוֹב֑/וֹ רָ֣ר בְּשָׂר֞/וֹ אֶת זוֹב֗/וֹ אֽוֹ הֶחְתִּ֤ים בְּשָׂר/וֹ֙ מִ/זּוֹב֔/וֹ טֻמְאָת֖/וֹ הִֽוא", "en": {"kjv": "And this shall be his uncleanness in his issue: whether his flesh run with his issue, or his flesh be stopped from his issue, it is his uncleanness.", "web": "This shall be his uncleanness in his discharge: whether his body runs with his discharge, or his body has stopped from his discharge, it is his uncleanness.", "bsb": "This uncleanness is from his discharge, whether his body allows the discharge to flow or blocks it. So his discharge will bring about uncleanness.", "asv": "And this shall be his uncleanness in his issue: whether his flesh run with his issue, or his flesh be stopped from his issue, it is his uncleanness.", "ylt": "and this is his uncleanness in his issue--his flesh hath run with his issue, or his flesh hath stopped from his issue; it is his uncleanness.", "tyndale": "And hereby shall it be knowne when he is vncleane. Yf his fleshe runne, or yf his flesh congele by the reason off his yssue, than he is vncleane.", "dra": "And then shall he be judged subject to this evil, when a filthy humour, at every moment, cleaveth to his flesh, and gathereth there.", "bbe": "If the flow goes on or if the part is stopped up, to keep back the flow, he is still unclean.", "geneva": "And this shalbe his vncleannes in his issue: when his flesh auoydeth his issue, or if his flesh be stopped from his issue, this is his vncleannes.", "wycliffe": "and thanne he schal be demed to be suget to this vice, whanne bi alle momentis foul vmour `ethir moysture cleueth to his fleisch, and growith togidere.", "rotherham": "And, this shall be his uncleanness in his flux,—whether his flesh is running with his flux or his flesh hath closed from his flux, his uncleanness, it is.", "darby": "And this shall be his uncleanness in his flux: whether his flesh run with his flux, or his flesh be closed from his flux, it is his uncleanness.", "twenty": "", "jps": "And this shall be his uncleanness in his issue: whether his flesh run with his issue, or his flesh be stopped from his issue, it is his uncleanness.", "acv": "And this shall be his uncleanness in his issue, whether his flesh runs with his issue, or his flesh has stopped from his issue, it is his uncleanness.", "anderson": "", "haweis": "", "noyes": "", "webster": "And this shall be his uncleanness in his issue: whether his flesh shall run with his issue, or his flesh be stopped from his issue, it [is] his uncleanness.", "vulgate": "et tunc iudicabitur huic vitio subiacere cum per momenta singula adheserit carni illius atque concreverit foedus humor;", "brenton": "And this is the law of his uncleanness; whoever has a gonorrhoea out of his body, this is his uncleanness in him by reason of the issue, by which, his body is affected through the issue: all the days of the issue of his body, by which his body is affected through the issue, there is his uncleanness."}}, {"v": 4, "ref": "15:4", "o": "כָּל הַ/מִּשְׁכָּ֗ב אֲשֶׁ֨ר יִשְׁכַּ֥ב עָלָ֛י/ו הַ/זָּ֖ב יִטְמָ֑א וְ/כָֽל הַ/כְּלִ֛י אֲשֶׁר יֵשֵׁ֥ב עָלָ֖י/ו יִטְמָֽא", "en": {"kjv": "Every bed, whereon he lieth that hath the issue, is unclean: and every thing, whereon he sitteth, shall be unclean.", "web": "“‘Every bed whereon he who has the discharge lies shall be unclean; and everything he sits on shall be unclean.", "bsb": "Any bed on which the man with the discharge lies will be unclean, and any furniture on which he sits will be unclean.", "asv": "Every bed whereon he that hath the issue lieth shall be unclean; and everything whereon he sitteth shall be unclean.", "ylt": "`All the bed on which he lieth who hath the issue is unclean, and all the vessel on which he sitteth is unclean;", "tyndale": "Euery couche whereon he lyeth ad euery thinge whereon he sytteth shalbe vncleane", "dra": "Every bed on which he sleepeth, shall be unclean, and every place on which he sitteth.", "bbe": "Every bed on which he has been resting will be unclean, and everything on which he has been seated will be unclean.", "geneva": "Euery bed whereon he lyeth that hath the issue, shall be vncleane, and euery thing whereon he sitteth, shalbe vncleane.", "wycliffe": "Ech bed in which he slepith schal be vncleene, and where euer he sittith.", "rotherham": "All the bed whereon he that hath the flux lieth, shall be unclean,—and, every piece of furniture whereon he sitteth, shall be unclean.", "darby": "Every bed whereon he lieth that hath the flux shall be unclean; and every object on which he sitteth shall be unclean.", "twenty": "", "jps": "Every bed whereon he that hath the issue lieth shall be unclean; and every thing whereon he sitteth shall be unclean.", "acv": "Every bed on which he who has the issue lies shall be unclean, and everything on which he sits shall be unclean.", "anderson": "", "haweis": "", "noyes": "", "webster": "Every bed on which he lieth that hath the issue, is unclean: and every thing on which he sitteth, shall be unclean.", "vulgate": "omne stratum in quo dormierit inmundum erit et ubicumque sederit;", "brenton": "Every bed on which he that has the issue shall happen to lie, is unclean; and every seat on which he that has the issue may happen to sit, shall be unclean."}}, {"v": 5, "ref": "15:5", "o": "וְ/אִ֕ישׁ אֲשֶׁ֥ר יִגַּ֖ע בְּ/מִשְׁכָּב֑/וֹ יְכַבֵּ֧ס בְּגָדָ֛י/ו וְ/רָחַ֥ץ בַּ/מַּ֖יִם וְ/טָמֵ֥א עַד הָ/עָֽרֶב", "en": {"kjv": "And whosoever toucheth his bed shall wash his clothes, and bathe himself in water, and be unclean until the even.", "web": "Whoever touches his bed shall wash his clothes, and bathe himself in water, and be unclean until the evening.", "bsb": "Anyone who touches his bed must wash his clothes and bathe with water, and he will be unclean until evening.", "asv": "And whosoever toucheth his bed shall wash his clothes, and bathe himself in water, and be unclean until the even.", "ylt": "and any one who cometh against his bed doth wash his garments, and hath bathed with water, and been unclean till the evening.", "tyndale": "He that twicheth his couch, shall wassh his clothes ad bath him selfe with water, ad be vncleane vntyll the euen.", "dra": "If any man touch his bed, he shall wash his clothes and being washed with water, he shall be unclean until the evening.", "bbe": "And anyone touching his bed is to have his clothing washed and his body bathed in water and be unclean till evening.", "geneva": "Whosoeuer also toucheth his bed, shall wash his clothes, and wash himselfe in water, and shall be vncleane vntill the euen.", "wycliffe": "If ony man touchith his bed, he schal waische his clothis, and he schal be waischun in watir, and schal be vncleene `til to euentid.", "rotherham": "And whosoever toucheth his bed shall wash his clothes and bathe in water and be unclean until the evening.", "darby": "And whoever toucheth his bed shall wash his garments, and bathe in water, and be unclean until the even.", "twenty": "", "jps": "And whosoever toucheth his bed shall wash his clothes, and bathe himself in water, and be unclean until the even.", "acv": "And whoever touches his bed shall wash his clothes, and bathe himself in water, and be unclean until the evening.", "anderson": "", "haweis": "", "noyes": "", "webster": "And whoever toucheth his bed, shall wash his clothes, and bathe [himself] in water, and be unclean until the evening.", "vulgate": "si quis hominum tetigerit lectum eius lavabit vestimenta sua et ipse lotus aqua inmundus erit usque ad vesperum;", "brenton": "And the man who shall touch his bed, shall wash his garments, and bathe himself in water, and shall be unclean till evening."}}, {"v": 6, "ref": "15:6", "o": "וְ/הַ/יֹּשֵׁב֙ עַֽל הַ/כְּלִ֔י אֲשֶׁר יֵשֵׁ֥ב עָלָ֖י/ו הַ/זָּ֑ב יְכַבֵּ֧ס בְּגָדָ֛י/ו וְ/רָחַ֥ץ בַּ/מַּ֖יִם וְ/טָמֵ֥א עַד הָ/עָֽרֶב", "en": {"kjv": "And he that sitteth on any thing whereon he sat that hath the issue shall wash his clothes, and bathe himself in water, and be unclean until the even.", "web": "He who sits on anything whereon the man who has the discharge sat shall wash his clothes, and bathe himself in water, and be unclean until the evening.", "bsb": "Whoever sits on furniture on which the man with the discharge was sitting must wash his clothes and bathe with water, and he will be unclean until evening.", "asv": "And he that sitteth on anything whereon he that hath the issue sat shall wash his clothes, and bathe himself in water, and be unclean until the even.", "ylt": "`And he who is sitting on the vessel on which he sitteth who hath the issue, doth wash his garments, and hath bathed with water, and been unclean till the evening.", "tyndale": "He that sytteth on that whereon he satt, shall wassh his clothes and bathe him selfe with water and be vncleane vntill the euenynge", "dra": "If a man sit where that man hath sitten, he also shall wash his clothes: and being washed with water, shall be unclean until the evening.", "bbe": "And he who has been seated on anything on which the unclean man has been seated is to have his clothing washed and his body bathed in water and be unclean till evening.", "geneva": "And he that sitteth on any thing, whereon he sate that hath the issue, shall wash his clothes, and wash himselfe in water, and shalbe vncleane vntill the euen.", "wycliffe": "If a man sittith where he satt, also thilke man schal waische hise clothis, and he schal be waischun in watir, and schal be vnclene `til to euentid.", "rotherham": "And, he that sitteth on that whereon he that hath the flux hath sat, shall wash his clothes, and bathe in water, and be unclean until the evening.", "darby": "And he that sitteth on any object whereon he sat that hath the flux shall wash his garments, and bathe in water, and be unclean until the even.", "twenty": "", "jps": "And he that sitteth on any thing whereon he that hath the issue sat shall wash his clothes, and bathe himself in water, and be unclean until the even.", "acv": "And he who sits on anything on which he who has the issue sat shall wash his clothes, and bathe himself in water, and be unclean until the evening.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he that sitteth on [any] thing on which he sat that hath the issue, shall wash his clothes, and bathe [himself] in water, and be unclean until the evening.", "vulgate": "si sederit ubi ille sederat et ipse lavabit vestimenta sua et lotus aqua inmundus erit usque ad vesperum;", "brenton": "And whosoever sits on the seat on which he that has the issue may have sat, shall wash his garments, and bathe himself in water, and shall be unclean until evening."}}, {"v": 7, "ref": "15:7", "o": "וְ/הַ/נֹּגֵ֖עַ בִּ/בְשַׂ֣ר הַ/זָּ֑ב יְכַבֵּ֧ס בְּגָדָ֛י/ו וְ/רָחַ֥ץ בַּ/מַּ֖יִם וְ/טָמֵ֥א עַד הָ/עָֽרֶב", "en": {"kjv": "And he that toucheth the flesh of him that hath the issue shall wash his clothes, and bathe himself in water, and be unclean until the even.", "web": "“‘He who touches the body of him who has the discharge shall wash his clothes, and bathe himself in water, and be unclean until the evening.", "bsb": "Whoever touches the body of the man with a discharge must wash his clothes and bathe with water, and he will be unclean until evening.", "asv": "And he that toucheth the flesh of him that hath the issue shall wash his clothes, and bathe himself in water, and be unclean until the even.", "ylt": "`And he who is coming against the flesh of him who hath the issue, doth wash his garments, and hath bathed with water, and hath been unclean till the evening.", "tyndale": "And he that twicheth his flesh shall wasshe his clothes and bathe him selfe in water and be vncleane vnto the euen.", "dra": "He that toucheth his flesh, shall wash his clothes: and being himself washed with water shall be unclean until the evening.", "bbe": "And anyone touching the flesh of the unclean man is to have his clothing washed and his body bathed in water and be unclean till evening.", "geneva": "Also he that toucheth the flesh of him that hath the issue, shall wash his clothes, and wash himselfe in water, and shalbe vncleane vntil the euen.", "wycliffe": "He that touchith hise fleischis, schal waische hise clothis, and he schal be waischun in watir, and schal be vncleene `til to euentid.", "rotherham": "And, he that toucheth the flesh of him that hath the flux, shall wash his clothes and bathe in water and be unclean until the evening,", "darby": "And he that toucheth the flesh of him that hath the flux shall wash his garments, and bathe in water, and be unclean until the even.", "twenty": "", "jps": "And he that toucheth the flesh of him that hath the issue shall wash his clothes, and bathe himself in water, and be unclean until the even.", "acv": "And he who touches the flesh of him who has the issue shall wash his clothes, and bathe himself in water, and be unclean until the evening.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he that toucheth the flesh of him that hath the issue, shall wash his clothes, and bathe [himself] in water, and be unclean until the evening.", "vulgate": "qui tetigerit carnem eius lavabit vestimenta sua et ipse lotus aqua inmundus erit usque ad vesperum;", "brenton": "And he that touches the skin of him that has the issue, shall wash his garments and bathe himself in water, and shall be unclean till evening."}}, {"v": 8, "ref": "15:8", "o": "וְ/כִֽי יָרֹ֛ק הַ/זָּ֖ב בַּ/טָּה֑וֹר וְ/כִבֶּ֧ס בְּגָדָ֛י/ו וְ/רָחַ֥ץ בַּ/מַּ֖יִם וְ/טָמֵ֥א עַד הָ/עָֽרֶב", "en": {"kjv": "And if he that hath the issue spit upon him that is clean; then he shall wash his clothes, and bathe himself in water, and be unclean until the even.", "web": "“‘If he who has the discharge spits on him who is clean, then he shall wash his clothes, and bathe himself in water, and be unclean until the evening.", "bsb": "If the man with the discharge spits on one who is clean, that person must wash his clothes and bathe with water, and he will be unclean until evening.", "asv": "And if he that hath the issue spit upon him that is clean, then he shall wash his clothes, and bathe himself in water, and be unclean until the even.", "ylt": "`And when he who hath the issue spitteth on him who is clean, then he hath washed his garments, and hath bathed with water, and been unclean till the evening.", "tyndale": "Yf any soch spytt apon him that is cleane, he must wasshe his clothes and bathe him selfe in water and be vncleane vntill euen.", "dra": "If such a man cast his spittle upon him that is clean, he shall wash his clothes: and being washed with water, he shall be unclean until the evening.", "bbe": "And if liquid from the mouth of the unclean man comes on to him who is clean, then he is to have his clothing washed and his body bathed in water and be unclean till evening.", "geneva": "If he also, that hath the issue, spit vpon him that is cleane, he shall wash his clothes, and wash himselfe in water, and shalbe vncleane vntill the euen.", "wycliffe": "If sich a man castith out spetyng on hym that is cleene, he schal waische his clothis, and he schal be waischun in watir, and schal be vncleene `til to euentid.", "rotherham": "And, when he that hath a flux spitteth on him that is clean, then shall he wash his clothes and bathe in water and be unclean until the evening.", "darby": "And if he that hath the flux spit upon him that is clean, then he shall wash his garments, and bathe in water, and be unclean until the even.", "twenty": "", "jps": "And if he that hath the issue spit upon him that is clean, then he shall wash his clothes, and bathe himself in water, and be unclean until the even.", "acv": "And if he who has the issue spits upon him who is clean, then he shall wash his clothes, and bathe himself in water, and be unclean until the evening.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if he that hath the issue shall spit upon him that is clean; then he shall wash his clothes, and bathe [himself] in water, and be unclean until the evening.", "vulgate": "si salivam huiuscemodi homo iecerit super eum qui mundus est lavabit vestem suam et lotus aqua inmundus erit usque ad vesperum;", "brenton": "And if he that has the issue should spit upon one that is clean, that person shall wash his garments, and bathe himself in water, and be unclean until evening."}}, {"v": 9, "ref": "15:9", "o": "וְ/כָל הַ/מֶּרְכָּ֗ב אֲשֶׁ֨ר יִרְכַּ֥ב עָלָ֛י/ו הַ/זָּ֖ב יִטְמָֽא", "en": {"kjv": "And what saddle soever he rideth upon that hath the issue shall be unclean.", "web": "“‘Whatever saddle he who has the discharge rides on shall be unclean.", "bsb": "Any saddle on which the man with the discharge rides will be unclean.", "asv": "And what saddle soever he that hath the issue rideth upon shall be unclean.", "ylt": "`And all the saddle on which he rideth who hath the issue is unclean;", "tyndale": "And what soeuer sadell that he rydeth apo, shalbe vncleane.", "dra": "The saddle on which he hath sitten shall be unclean.", "bbe": "And any leather seat on a horse on which the unclean man has been seated will be unclean.", "geneva": "And what saddle soeuer he rideth vpon, that hath the issue, shalbe vncleane,", "wycliffe": "The sadil on which he sittith,", "rotherham": "And, every saddle whereon he that hath the flux rideth, shall be unclean.", "darby": "And what carriage soever he rideth upon that hath the flux shall be unclean.", "twenty": "", "jps": "And what saddle soever he that hath the issue rideth upon shall be unclean.", "acv": "And whatever saddle he who has the issue rides upon shall be unclean.", "anderson": "", "haweis": "", "noyes": "", "webster": "And whatever saddle he rideth upon that hath the issue, shall be unclean.", "vulgate": "sagma super quo sederit inmundum erit;", "brenton": "And every ass's saddle, on which the man with the issue shall have mounted, shall be unclean till evening."}}, {"v": 10, "ref": "15:10", "o": "וְ/כָל הַ/נֹּגֵ֗עַ בְּ/כֹל֙ אֲשֶׁ֣ר יִהְיֶ֣ה תַחְתָּ֔י/ו יִטְמָ֖א עַד הָ/עָ֑רֶב וְ/הַ/נּוֹשֵׂ֣א אוֹתָ֔/ם יְכַבֵּ֧ס בְּגָדָ֛י/ו וְ/רָחַ֥ץ בַּ/מַּ֖יִם וְ/טָמֵ֥א עַד הָ/עָֽרֶב", "en": {"kjv": "And whosoever toucheth any thing that was under him shall be unclean until the even: and he that beareth any of those things shall wash his clothes, and bathe himself in water, and be unclean until the even.", "web": "Whoever touches anything that was under him shall be unclean until the evening. He who carries those things shall wash his clothes, and bathe himself in water, and be unclean until the evening.", "bsb": "Whoever touches anything that was under him will be unclean until evening, and whoever carries such things must wash his clothes and bathe with water, and he will be unclean until evening.", "asv": "And whosoever toucheth anything that was under him shall be unclean until the even: and he that beareth those things shall wash his clothes, and bathe himself in water, and be unclean until the even.", "ylt": "and any one who is coming against anything which is under him is unclean till the evening, and he who is bearing them doth wash his garments, and hath bathed with water, and been unclean till the evening.", "tyndale": "And whosoeuer twicheth any thinge that was vnder him, shalbe vncleane vnto the eue. And he that beareth any soch thinges shall wassh his clothes ad batbe hi self in water ad be vncleane vnto the eue,", "dra": "And whatsoever has been under him that hath the issue of seed, shall be unclean until the evening. He that carrieth any of these things, shall wash his clothes: and being washed with water, he shall be unclean until the evening.", "bbe": "And anyone touching anything which was under him will be unclean till the evening; anyone taking up any of these things is to have his clothing washed and his body bathed in water and be unclean till evening.", "geneva": "And whosoeuer toucheth any thing that was vnder him, shall be vncleane vnto the euen: and he that beareth those things, shall wash his clothes, and wash himselfe in water, and shall be vncleane vntill the euen.", "wycliffe": "schal be vncleene; and ech man that touchith what euer thing is vndur hym that suffrith the fletyng out of seed, schal be defoulid `til to euentid. He that berith ony of these thingis, schal waische hise clothis, and he schal be waischun in watir, and schal be vncleene `til to euentid.", "rotherham": "And, whosoever toucheth anything that was under him shall be unclean until the evening; and, he that carrieth them shall wash his clothes and bathe in water, and be unclean until the evening.", "darby": "And whoever toucheth anything that was under him shall be unclean until the even; and he that carrieth them shall wash his garments, and bathe in water, and be unclean until the even.", "twenty": "", "jps": "And whosoever toucheth any thing that was under him shall be unclean until the even; and he that beareth those things shall wash his clothes, and bathe himself in water, and be unclean until the even.", "acv": "And whoever touches anything that was under him shall be unclean until the evening. And he who bears those things shall wash his clothes, and bathe himself in water, and be unclean until the evening.", "anderson": "", "haweis": "", "noyes": "", "webster": "And whoever toucheth any thing that was under him shall be unclean until the evening; and he that beareth [any of] those things, shall wash his clothes, and bathe [himself] in water, and be unclean until the evening.", "vulgate": "et quicquid sub eo fuerit qui fluxum seminis patitur pollutum erit usque ad vesperum qui portaverit horum aliquid lavabit vestem suam et ipse lotus aqua inmundus erit usque ad vesperum;", "brenton": "And every one that touches whatsoever shall have been under him shall be unclean until evening; and he that takes them up shall wash his garments, and bathe himself in water, and shall be unclean until evening."}}, {"v": 11, "ref": "15:11", "o": "וְ/כֹ֨ל אֲשֶׁ֤ר יִגַּע בּ/וֹ֙ הַ/זָּ֔ב וְ/יָדָ֖י/ו לֹא שָׁטַ֣ף בַּ/מָּ֑יִם וְ/כִבֶּ֧ס בְּגָדָ֛י/ו וְ/רָחַ֥ץ בַּ/מַּ֖יִם וְ/טָמֵ֥א עַד הָ/עָֽרֶב", "en": {"kjv": "And whomsoever he toucheth that hath the issue, and hath not rinsed his hands in water, he shall wash his clothes, and bathe himself in water, and be unclean until the even.", "web": "“‘Whoever he who has the discharge touches, without having rinsed his hands in water, he shall wash his clothes, and bathe himself in water, and be unclean until the evening.", "bsb": "If the man with the discharge touches anyone without first rinsing his hands with water, the one who was touched must wash his clothes and bathe with water, and he will be unclean until evening.", "asv": "And whomsoever he that hath the issue toucheth, without having rinsed his hands in water, he shall wash his clothes, and bathe himself in water, and be unclean until the even.", "ylt": "`And anyone against whom he cometh who hath the issue (and his hands hath not rinsed with water) hath even washed his garments, and bathed with water, and been unclean till the evening.", "tyndale": "ad whosoeuer he twicheth (yf he haue not first washed his handes in water) must wasshe his clothes, ad bathe him selfe in water, ad be vncleane vnto the euenynge.", "dra": "Every person whom such a one shall touch, not having washed his hands before, shall wash his clothes: and being washed with water, shall be unclean until the evening.", "bbe": "And anyone on whom the unclean man puts his hands, without washing them in water, is to have his clothing washed and his body bathed in water and be unclean till evening.", "geneva": "Likewise whomesoeuer hee toucheth that hath the issue (and hath not washed his handes in water) shall wash his clothes and wash himselfe in water, and shalbe vncleane vntill the euen.", "wycliffe": "Ech man, whom he that is such touchith with hondis not waischun bifore, schal waische hise clothis, and he schal be waischun in watir, and schal be vncleene `til to euentid.", "rotherham": "And, whomsoever he that hath the flux toucheth, not having rinsed, his hands in water, then shall he wash his clothes, and bathe in water and be unclean until the evening,", "darby": "And whomsoever he toucheth who hath the flux and hath not rinsed his hands in water — he shall wash his garments, and bathe in water, and be unclean until the even.", "twenty": "", "jps": "And whomsoever he that hath the issue toucheth, without having rinsed his hands in water, he shall wash his clothes, and bathe himself in water, and be unclean until the even.", "acv": "And whomever he who has the issue touches, without having rinsed his hands in water, he shall wash his clothes, and bathe himself in water, and be unclean until the evening.", "anderson": "", "haweis": "", "noyes": "", "webster": "And whomsoever he toucheth that hath the issue (and hath not rinsed his hands in water) he shall wash his clothes, and bathe [himself] in water, and be unclean until the evening.", "vulgate": "omnis quem tetigerit qui talis est non lotis ante manibus lavabit vestimenta sua et lotus aqua inmundus erit usque ad vesperum;", "brenton": "And whomsoever he that has the issue shall touch, if he have not rinsed his hands in water, he shall wash his garments, and bathe his body in water, and shall be unclean until evening."}}, {"v": 12, "ref": "15:12", "o": "וּ/כְלִי חֶ֛רֶשׂ אֲשֶׁר יִגַּע בּ֥/וֹ הַ/זָּ֖ב יִשָּׁבֵ֑ר וְ/כָל כְּלִי עֵ֔ץ יִשָּׁטֵ֖ף בַּ/מָּֽיִם", "en": {"kjv": "And the vessel of earth, that he toucheth which hath the issue, shall be broken: and every vessel of wood shall be rinsed in water.", "web": "“‘The earthen vessel, which he who has the discharge touches, shall be broken; and every vessel of wood shall be rinsed in water.", "bsb": "Any clay pot that the man with the discharge touches must be broken, and any wooden utensil must be rinsed with water.", "asv": "And the earthen vessel, which he that hath the issue toucheth, shall be broken; and every vessel of wood shall be rinsed in water.", "ylt": "`And the earthen vessel which he who hath the issue cometh against is broken; and every wooden vessel is rinsed with water.", "tyndale": "And yf he twych a vessell off erth, it shalbe broken: and all vessels of wodd shalbe rensed in the water.", "dra": "If he touch a vessel of earth, it shall be broken: but if a vessel of wood, it shall be washed with water.", "bbe": "And any vessel of earth which has been touched by the unclean man will have to be broken and any vessel of wood washed.", "geneva": "And the vessel of earth that he toucheth, which hath the issue, shalbe broken: and euery vessel of wood shalbe rinsed in water.", "wycliffe": "`A vessel of erthe which he touchith, schal be brokun; but a `vessel of tre schal be waischun in watir.", "rotherham": "And the earthen vessel which he that hath the flux toucheth shall be broken in pieces,—and, every vessel of wood, shall be rinsed in water.", "darby": "And the vessel of earth that he toucheth who hath the flux shall be broken; and every vessel of wood shall be rinsed in water.", "twenty": "", "jps": "And the earthen vessel, which he that hath the issue toucheth, shall be broken; and every vessel of wood shall be rinsed in water.", "acv": "And the earthen vessel, which he who has the issue touches, shall be broken, and every vessel of wood shall be rinsed in water.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the vessel of earth that he toucheth who hath the issue, shall be broken: and every vessel of wood shall be rinsed in water.", "vulgate": "vas fictile quod tetigerit confringetur vas autem ligneum lavabitur aqua;", "brenton": "And the earthen vessel which he that has the issue shall happen to touch, shall be broken; and a wooden vessel shall be washed with water, and shall be clean."}}, {"v": 13, "ref": "15:13", "o": "וְ/כִֽי יִטְהַ֤ר הַ/זָּב֙ מִ/זּוֹב֔/וֹ וְ/סָ֨פַר ל֜/וֹ שִׁבְעַ֥ת יָמִ֛ים לְ/טָהֳרָת֖/וֹ וְ/כִבֶּ֣ס בְּגָדָ֑י/ו וְ/רָחַ֧ץ בְּשָׂר֛/וֹ בְּ/מַ֥יִם חַיִּ֖ים וְ/טָהֵֽר", "en": {"kjv": "And when he that hath an issue is cleansed of his issue; then he shall number to himself seven days for his cleansing, and wash his clothes, and bathe his flesh in running water, and shall be clean.", "web": "“‘When he who has a discharge is cleansed of his discharge, then he shall count to himself seven days for his cleansing, and wash his clothes; and he shall bathe his flesh in running water, and shall be clean.", "bsb": "When the man has been cleansed from his discharge, he must count off seven days for his cleansing, wash his clothes, and bathe himself in fresh water, and he shall be clean.", "asv": "And when he that hath an issue is cleansed of his issue, then he shall number to himself seven days for his cleansing, and wash his clothes; and he shall bathe his flesh in running water, and shall be clean.", "ylt": "`And when he who hath the issue is clean from his issue, then he hath numbered to himself seven days for his cleansing, and hath washed his garments, and hath bathed his flesh with running water, and been clean.", "tyndale": "When he that hath an yssue is clensed of his yssue, let him numbre .vij. dayes after he is cleane, ad wasshe his clothes, and bathe his fleshe in runnynge water, ad then he is cleane.", "dra": "If he who suffereth this disease be healed, he shall number seven days after his cleansing: and having washed his clothes, and all his body in living water, he shall be clean.", "bbe": "And when a man who has a flow from his body is made clean from it, he is to take seven days to make himself clean, washing his clothing and bathing his body in flowing water, and then he will be clean.", "geneva": "But if he that hath an issue, be cleansed of his issue, then shall he count him seuen dayes for his cleansing, and wash his clothes, and wash his flesh in pure water: so shall he be cleane.", "wycliffe": "If he that suffrith sich a passioun, is heelid, he schal noumbre seuene daies aftir his clensyng, and whanne the clothis and al `the bodi ben waischun in lyuynge watris, he schal be clene.", "rotherham": "And when he that hath the flux becometh clean from his flux, then shall he number to himself seven days for his cleansing, and wash his clothes,—and bathe his flesh in living water, and be clean.", "darby": "And when he that hath a flux is clean of his flux, then he shall count seven days for his cleansing, and wash his clothes, and bathe his flesh in running water, and he shall be clean.", "twenty": "", "jps": "And when he that hath an issue is cleansed of his issue, then he shall number to himself seven days for his cleansing, and wash his clothes; and he shall bathe his flesh in running water, and shall be clean.", "acv": "And when he who has an issue is cleansed of his issue, then he shall number to himself seven days for his cleansing, and wash his clothes, and he shall bathe his flesh in running water, and shall be clean.", "anderson": "", "haweis": "", "noyes": "", "webster": "And when he that hath an issue is cleansed of his issue; then he shall number to himself seven days for his cleansing, and wash his clothes, and bathe his flesh in running water, and shall be clean.", "vulgate": "si sanatus fuerit qui huiuscemodi sustinet passionem numerabit septem dies post emundationem sui et lotis vestibus ac toto corpore in aquis viventibus erit mundus;", "brenton": "and if he that has the issue should be cleansed of his issue, then shall he number to himself seven days for his purification; and he shall wash his garments, and bathe his body in water, and shall be clean."}}, {"v": 14, "ref": "15:14", "o": "וּ/בַ/יּ֣וֹם הַ/שְּׁמִינִ֗י יִֽקַּֽח ל/וֹ֙ שְׁתֵּ֣י תֹרִ֔ים א֥וֹ שְׁנֵ֖י בְּנֵ֣י יוֹנָ֑ה וּ/בָ֣א לִ/פְנֵ֣י יְהוָ֗ה אֶל פֶּ֨תַח֙ אֹ֣הֶל מוֹעֵ֔ד וּ/נְתָנָ֖/ם אֶל הַ/כֹּהֵֽן", "en": {"kjv": "And on the eighth day he shall take to him two turtledoves, or two young pigeons, and come before the Lord unto the door of the tabernacle of the congregation, and give them unto the priest:", "web": "“‘On the eighth day he shall take two turtledoves, or two young pigeons, and come before Yahweh to the door of the Tent of Meeting, and give them to the priest:", "bsb": "On the eighth day he is to take two turtledoves or two young pigeons, come before the LORD at the entrance to the Tent of Meeting, and give them to the priest.", "asv": "And on the eighth day he shall take to him two turtle-doves, or two young pigeons, and come before Jehovah unto the door of the tent of meeting, and give them unto the priest:", "ylt": "`And on the eighth day he taketh to himself two turtle-doves, or two young pigeons, and hath come in before Jehovah unto the opening of the tent of meeting, and hath given them unto the priest;", "tyndale": "And the .viij. daye let him take two turtill doues or two yonge pigeons, and come before the Lorde vnto the dore of the tabernacle of witnesse ad geue them vnto the preast.", "dra": "And on the eighth day he shall take two turtles, or two young pigeons, and he shall come before the Lord, to the door of the tabernacle of the testimony, and shall give them to the priest.", "bbe": "And on the eighth day he is to take two doves or two young pigeons and come before the Lord to the door of the Tent of meeting and give them to the priest:", "geneva": "Then the eight day he shall take vnto him two Turtle doues or two yong pigeons, and come before the Lord at the doore of the Tabernacle of the Congregation, and shall giue them vnto the Priest.", "wycliffe": "Forsothe in the eiytthe dai he schal take twei turtlis, ethir twei `briddis of a culuer, and he schal come in the `siyt of the Lord at the dore of tabernacle of witnessyng, and schal yyue tho to the preest;", "rotherham": "And, on the eighth day, he shall take for himself two turtle doves or two young pigeons,—and come in before Yahweh, unto the entrance of the tent of meeting, and give them to the priest;", "darby": "And on the eighth day he shall take two turtle-doves, or two young pigeons, and come before Jehovah unto the entrance of the tent of meeting, and give them unto the priest.", "twenty": "", "jps": "And on the eighth day he shall take to him two turtle-doves, or two young pigeons, and come before HaShem unto the door of the tent of meeting, and give them unto the priest.", "acv": "And on the eighth day he shall take to him two turtle-doves, or two young pigeons, and come before Jehovah to the door of the tent of meeting, and give them to the priest.", "anderson": "", "haweis": "", "noyes": "", "webster": "And on the eighth day he shall take to him two turtle-doves, or two young pigeons, and come before the LORD to the door of the tabernacle of the congregation, and give them to the priest:", "vulgate": "die autem octavo sumet duos turtures aut duos pullos columbae et veniet in conspectu Domini ad ostium tabernaculi testimonii dabitque eos sacerdoti;", "brenton": "And on the eighth day he shall take to himself two turtle-doves or two young pigeons, and he shall bring them before the Lord to the doors of the tabernacle of witness, and shall give them to the priest."}}, {"v": 15, "ref": "15:15", "o": "וְ/עָשָׂ֤ה אֹתָ/ם֙ הַ/כֹּהֵ֔ן אֶחָ֣ד חַטָּ֔את וְ/הָ/אֶחָ֖ד עֹלָ֑ה וְ/כִפֶּ֨ר עָלָ֧י/ו הַ/כֹּהֵ֛ן לִ/פְנֵ֥י יְהוָ֖ה מִ/זּוֹבֽ/וֹ", "en": {"kjv": "And the priest shall offer them, the one for a sin offering, and the other for a burnt offering; and the priest shall make an atonement for him before the Lord for his issue.", "web": "and the priest shall offer them, the one for a sin offering, and the other for a burnt offering. The priest shall make atonement for him before Yahweh for his discharge.", "bsb": "The priest is to sacrifice them, one as a sin offering and the other as a burnt offering. In this way the priest will make atonement for the man before the LORD because of his discharge.", "asv": "and the priest shall offer them, the one for a sin-offering, and the other for a burnt-offering; and the priest shall make atonement for him before Jehovah for his issue.", "ylt": "and the priest hath made them, one a sin-offering, and the one a burnt-offering; and the priest hath made atonement for him before Jehovah, because of his issue.", "tyndale": "And the preast shall offer them: the one for a synneofferynge, and the other for a burntofferynge: and make an attonement for him before the Lord, as cocernynge his yssue.", "dra": "Who shall offer one for sin, and the other for a holocaust: and he shall pray for him before the Lord, that he may be cleansed of the issue of his seed.", "bbe": "And they are to be offered by the priest, one for a sin-offering and one for a burned offering, and the priest will take away his sin before the Lord on account of his flow.", "geneva": "And the Priest shall make of the one of them a sinne offring, and of the other a burnt offering: so the Priest shall make an atonement for him before the Lord, for his issue.", "wycliffe": "and the preest schal make oon for synne, and the tother in to brent sacrifice; and the preest schal preye for hym bifor the Lord, that he be clensid fro the fletyng out of his seed.", "rotherham": "and the priest shall offer them, one as a sin-bearer and the other as an ascending-sacrifice,—so shall the priest put a propitiatory-covering over him, before Yahweh, because of his flux.", "darby": "And the priest shall offer them, one as a sin-offering, and one as a burnt-offering; and the priest shall make atonement for him before Jehovah for his flux.", "twenty": "", "jps": "And the priest shall offer them, the one for a sin-offering, and the other for a burnt-offering; and the priest shall make atonement for him before HaShem for his issue.", "acv": "And the priest shall offer them, the one for a sin offering, and the other for a burnt offering, and the priest shall make atonement for him before Jehovah for his issue.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall offer them, the one [for] a sin-offering, and the other [for] a burnt-offering; and the priest shall make an atonement for him before the LORD for his issue.", "vulgate": "qui faciet unum pro peccato et alterum in holocaustum rogabitque pro eo coram Domino ut emundetur a fluxu seminis sui;", "brenton": "And the priest shall offer them one for a sin-offering, and the other for a whole-burnt-offering; and the priest shall make atonement for him before the Lord for his issue."}}, {"v": 16, "ref": "15:16", "o": "וְ/אִ֕ישׁ כִּֽי תֵצֵ֥א מִמֶּ֖/נּוּ שִׁכְבַת זָ֑רַע וְ/רָחַ֥ץ בַּ/מַּ֛יִם אֶת כָּל בְּשָׂר֖/וֹ וְ/טָמֵ֥א עַד הָ/עָֽרֶב", "en": {"kjv": "And if any man’s seed of copulation go out from him, then he shall wash all his flesh in water, and be unclean until the even.", "web": "“‘If any man has an emission of semen, then he shall bathe all his flesh in water, and be unclean until the evening.", "bsb": "When a man has an emission of semen, he must bathe his whole body with water, and he will be unclean until evening.", "asv": "And if any man’s seed of copulation go out from him, then he shall bathe all his flesh in water, and be unclean until the even.", "ylt": "`And when a man's seed of copulation goeth out from him, then he hath bathed with water all his flesh, and been unclean till the evening.", "tyndale": "Yf any mans seed departe fro him in his slepe, he shall wassh his flesh in water ad be vncleane vntill eue.", "dra": "The man from whom the seed of copulation goeth out, shall wash all his body with water: and he shall be unclean until the evening.", "bbe": "And if a man's seed goes out from him, then all his body will have to be bathed in water and he will be unclean till evening.", "geneva": "Also if any mans issue of seede depart from him, he shall wash all his flesh in water, and be vncleane vntill the euen.", "wycliffe": "A man fro whom the seed of letcherie, `ethir of fleischli couplyng, goith out, schal waische in watir al his bodi, and he schal be vncleene `til to euentid.", "rotherham": "And, when there goeth out from, any man, an outflow of seed, then shall he bathe all his flesh in water, and be unclean until the evening.", "darby": "And if any man's seed of copulation pass from him, then he shall bathe his whole flesh in water, and be unclean until the even.", "twenty": "", "jps": "And if the flow of seed go out from a man, then he shall bathe all his flesh in water, and be unclean until the even.", "acv": "And if any man's seed of copulation go out from him, then he shall bathe all his flesh in water, and be unclean until the evening.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if any man's seed of copulation shall go from him, then he shall wash all his flesh in water, and be unclean until the evening.", "vulgate": "vir de quo egreditur semen coitus lavabit aqua omne corpus suum et inmundus erit usque ad vesperum;", "brenton": "And the man whose seed of copulation shall happen to go forth from him, shall then wash his whole body, and shall be unclean until evening."}}, {"v": 17, "ref": "15:17", "o": "וְ/כָל בֶּ֣גֶד וְ/כָל ע֔וֹר אֲשֶׁר יִהְיֶ֥ה עָלָ֖י/ו שִׁכְבַת זָ֑רַע וְ/כֻבַּ֥ס בַּ/מַּ֖יִם וְ/טָמֵ֥א עַד הָ/עָֽרֶב", "en": {"kjv": "And every garment, and every skin, whereon is the seed of copulation, shall be washed with water, and be unclean until the even.", "web": "Every garment, and every skin, whereon the semen is, shall be washed with water, and be unclean until the evening.", "bsb": "Any clothing or leather on which there is an emission of semen must be washed with water, and it will remain unclean until evening.", "asv": "And every garment, and every skin, whereon is the seed of copulation, shall be washed with water, and be unclean until the even.", "ylt": "`And any garment, or any skin on which there is seed of copulation, hath also been washed with water, and been unclean till the evening.", "tyndale": "And all the clothes or furres whereon soch seed chaunceth shalbe washed with water ad be vncleane vnto the eue.", "dra": "The garment or skin that he weareth, he shall wash with water: and it shall be unclean until the evening.", "bbe": "And any clothing or skin on which the seed comes is to be washed with water and be unclean till evening.", "geneva": "And euery garment, and euery skinne whereupon shalbe issue of seede, shall be euen washed with water, and be vncleane vnto the euen.", "wycliffe": "He schal waische in watir the cloth `and skyn which he hath, and it schal be unclene `til to euentid.", "rotherham": "And, in the case of any garment or any skin whereupon there shall come to be an outflow of seed, then shall it be washed in water, and be unclean until the evening.", "darby": "And every garment, and every skin, whereon the seed of copulation shall be, shall be washed with water, and be unclean until the even.", "twenty": "", "jps": "And every garment, and every skin, whereon is the flow of seed, shall be washed with water, and be unclean until the even.", "acv": "And every garment, and every skin, on which is the seed of copulation, shall be washed with water, and be unclean until the evening.", "anderson": "", "haweis": "", "noyes": "", "webster": "And every garment, and every skin on which is the seed of copulation, shall be washed with water, and be unclean until the evening.", "vulgate": "vestem et pellem quam habuerit lavabit aqua et inmunda erit usque ad vesperum;", "brenton": "And every garment, and every skin on which there shall be the seed of copulation shall both be washed with water, and be unclean until evening."}}, {"v": 18, "ref": "15:18", "o": "וְ/אִשָּׁ֕ה אֲשֶׁ֨ר יִשְׁכַּ֥ב אִ֛ישׁ אֹתָ֖/הּ שִׁכְבַת זָ֑רַע וְ/רָחֲצ֣וּ בַ/מַּ֔יִם וְ/טָמְא֖וּ עַד הָ/עָֽרֶב", "en": {"kjv": "The woman also with whom man shall lie with seed of copulation, they shall both bathe themselves in water, and be unclean until the even.", "web": "If a man lies with a woman and there is an emission of semen, they shall both bathe themselves in water, and be unclean until the evening.", "bsb": "If a man lies with a woman and there is an emission of semen, both must bathe with water, and they will remain unclean until evening.", "asv": "The woman also with whom a man shall lie with seed of copulation, they shall both bathe themselves in water, and be unclean until the even.", "ylt": "`And a woman with whom a man lieth with seed of copulation, they also have bathed with water, and been unclean till the evening.", "tyndale": "And yf a woma lye with soche a whone, they shall wash the selues with water and be vncleane vntyll even.", "dra": "The woman, with whom he copulateth, shall be washed with water: and shall be unclean until the evening.", "bbe": "And if a man has sex relations with a woman and his seed goes out from him, the two of them will have to be bathed in water and will be unclean till evening.", "geneva": "If he that hath an issue of seede, do lie with a woman, they shall both wash themselues with water, and be vncleane vntill the euen.", "wycliffe": "The womman with which he `is couplid fleischli, schal be waischun in watir, and schal be vncleene `til to euentid.", "rotherham": "Also, a woman with whom man lieth carnally, then shall they bathe in water, and be unclean until the evening.", "darby": "And a woman with whom a man lieth with seed of copulation — they shall bathe in water, and be unclean until the even.", "twenty": "", "jps": "The woman also with whom a man shall lie carnally, they shall both bathe themselves in water, and be unclean until the even.", "acv": "The woman also with whom a man shall lie with seed of copulation, they shall both bathe themselves in water, and be unclean until the evening.", "anderson": "", "haweis": "", "noyes": "", "webster": "The woman also with whom man shall lie [with] seed of copulation, they shall [both] bathe [themselves] in water, and be unclean until the evening.", "vulgate": "mulier cum qua coierit lavabitur aqua et inmunda erit usque ad vesperum;", "brenton": "And a woman, if a man shall lie with her with seed of copulation—they shall both bathe themselves in water and shall be unclean until evening."}}, {"v": 19, "ref": "15:19", "o": "וְ/אִשָּׁה֙ כִּֽי תִהְיֶ֣ה זָבָ֔ה דָּ֛ם יִהְיֶ֥ה זֹבָ֖/הּ בִּ/בְשָׂרָ֑/הּ שִׁבְעַ֤ת יָמִים֙ תִּהְיֶ֣ה בְ/נִדָּתָ֔/הּ וְ/כָל הַ/נֹּגֵ֥עַ בָּ֖/הּ יִטְמָ֥א עַד הָ/עָֽרֶב", "en": {"kjv": "And if a woman have an issue, and her issue in her flesh be blood, she shall be put apart seven days: and whosoever toucheth her shall be unclean until the even.", "web": "“‘If a woman has a discharge, and her discharge in her flesh is blood, she shall be in her impurity seven days: and whoever touches her shall be unclean until the evening.", "bsb": "When a woman has a discharge consisting of blood from her body, she will be unclean due to her menstruation for seven days, and anyone who touches her will be unclean until evening.", "asv": "And if a woman have an issue, and her issue in her flesh be blood, she shall be in her impurity seven days: and whosoever toucheth her shall be unclean until the even.", "ylt": "`And when a woman hath an issue--blood is her issue in her flesh--seven days she is in her separation, and any one who is coming against her is unclean till the evening.", "tyndale": "Whe a womas naturall course of bloud runeth, she shalbe put aparte .vij. dayes: ad whosoeuer twycheth her shalbe vncleane vnto the eue.", "dra": "The woman, who at the return of the month, hath her issue of blood, shall be separated seven days.", "bbe": "And if a woman has a flow of blood from her body, she will have to be kept separate for seven days, and anyone touching her will be unclean till evening.", "geneva": "Also when a woman shall haue an issue, and her issue in her flesh shalbe blood, she shalbe put apart seuen dayes: and whosoeuer toucheth her, shalbe vncleane vnto the euen.", "wycliffe": "A womman that suffrith the fletyng out of blood, whanne the moneth cometh ayen, schal be departid bi seuene daies; ech man that touchith hir schal be vncleene `til to euentid,", "rotherham": "And, when a, woman, hath a flow, and her flow in her flesh is, blood, seven days, shall she continue in her removal, and whosoever toucheth her, shall be unclean until the evening;", "darby": "And if a woman have a flux, and her flux in her flesh be blood, she shall be seven days in her separation, and whoever toucheth her shall be unclean until the even.", "twenty": "", "jps": "And if a woman have an issue, and her issue in her flesh be blood, she shall be in her impurity seven days; and whosoever toucheth her shall be unclean until the even.", "acv": "And if a woman has an issue, and her issue in her flesh is blood, she shall be seven days in her impurity, and whoever touches her shall be unclean until the evening.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if a woman shall have an issue, [and] her issue in her flesh be blood, she shall be put apart seven days: and whoever toucheth her shall be unclean until the evening.", "vulgate": "mulier quae redeunte mense patitur fluxum sanguinis septem diebus separabitur;", "brenton": "And the woman whosoever shall have an issue of blood, when her issue shall be in her body, shall be seven days in her separation; every one that touches her shall be unclean until evening."}}, {"v": 20, "ref": "15:20", "o": "וְ/כֹל֩ אֲשֶׁ֨ר תִּשְׁכַּ֥ב עָלָ֛י/ו בְּ/נִדָּתָ֖/הּ יִטְמָ֑א וְ/כֹ֛ל אֲשֶׁר תֵּשֵׁ֥ב עָלָ֖י/ו יִטְמָֽא", "en": {"kjv": "And every thing that she lieth upon in her separation shall be unclean: every thing also that she sitteth upon shall be unclean.", "web": "“‘Everything that she lies on in her impurity shall be unclean. Everything also that she sits on shall be unclean.", "bsb": "Anything on which she lies or sits during her menstruation will be unclean,", "asv": "And everything that she lieth upon in her impurity shall be unclean: everything also that she sitteth upon shall be unclean.", "ylt": "`And anything on which she lieth in her separation is unclean, and anything on which she sitteth is unclean;", "tyndale": "And all that she lyeth apo as longe as she is put aparte shalbe vnclene.", "dra": "Every one that toucheth her, shall be unclean until the evening.", "bbe": "And everything on which she has been resting, while she is kept separate, will be unclean, and everything on which she has been seated will be unclean.", "geneva": "And whatsoeuer she lieth vpon in her separation, shalbe vncleane, and euery thing that she sitteth vpon, shalbe vncleane.", "wycliffe": "and the place in which sche slepith ether sittith in the daies of hir departyng, schal be defoulid.", "rotherham": "and, whatsoever she lieth upon in her removal, shall be unclean,—and, whatsoever she sitteth upon, shall be unclean;", "darby": "And everything that she lieth upon in her separation shall be unclean; and everything that she sitteth upon shall be unclean.", "twenty": "", "jps": "And every thing that she lieth upon in her impurity shall be unclean; every thing also that she sitteth upon shall be unclean.", "acv": "And everything that she lies upon in her impurity shall be unclean. Also everything that she sits upon shall be unclean.", "anderson": "", "haweis": "", "noyes": "", "webster": "And every thing that she lieth upon in her separation shall be unclean: every thing also that she sitteth upon shall be unclean.", "vulgate": "omnis qui tetigerit eam inmundus erit usque ad vesperum;", "brenton": "And every thing whereon she shall lie in her separation, shall be unclean; and whatever she shall sit upon, shall be unclean."}}, {"v": 21, "ref": "15:21", "o": "וְ/כָל הַ/נֹּגֵ֖עַ בְּ/מִשְׁכָּבָ֑/הּ יְכַבֵּ֧ס בְּגָדָ֛י/ו וְ/רָחַ֥ץ בַּ/מַּ֖יִם וְ/טָמֵ֥א עַד הָ/עָֽרֶב", "en": {"kjv": "And whosoever toucheth her bed shall wash his clothes, and bathe himself in water, and be unclean until the even.", "web": "Whoever touches her bed shall wash his clothes, and bathe himself in water, and be unclean until the evening.", "bsb": "and anyone who touches her bed must wash his clothes and bathe with water, and he will be unclean until evening.", "asv": "And whosoever toucheth her bed shall wash his clothes, and bathe himself in water, and be unclean until the even.", "ylt": "and any one who is coming against her bed doth wash his garments, and hath bathed with water, and been unclean till the evening.", "tyndale": "And whosoeuer twicheth hir couch shall wash his clothes and bathe hi selfe with water ad be vncleane vnto the eue.", "dra": "And every thing that she sleepeth on, or that she sitteth on in the days of her separation, shall be defiled.", "bbe": "And anyone touching her bed will have to have his clothing washed and his body bathed in water and be unclean till evening.", "geneva": "Whosoeuer also toucheth her bedde, shall wash his clothes, and wash himselfe with water, and shalbe vncleane vnto the euen.", "wycliffe": "He that touchith her bed, schal waische hise clothis, and he schal be waischun in watir, and schal be vncleene `til to euentid.", "rotherham": "and whosoever toucheth her bed, shall wash his clothes and bathe in water and be unclean until the evening;", "darby": "And whoever toucheth her bed shall wash his garments, and bathe in water, and be unclean until the even.", "twenty": "", "jps": "And whosoever toucheth her bed shall wash his clothes, and bathe himself in water, and be unclean until the even.", "acv": "And whoever touches her bed shall wash his clothes, and bathe himself in water, and be unclean until the evening.", "anderson": "", "haweis": "", "noyes": "", "webster": "And whoever toucheth her bed shall wash his clothes, and bathe [himself] in water, and be unclean until the evening.", "vulgate": "et in quo dormierit vel sederit diebus separationis suae polluetur;", "brenton": "And whosoever shall touch her bed shall wash his garments, and bathe his body in water, and shall be unclean until evening."}}, {"v": 22, "ref": "15:22", "o": "וְ/כָל הַ/נֹּגֵ֔עַ בְּ/כָל כְּלִ֖י אֲשֶׁר תֵּשֵׁ֣ב עָלָ֑י/ו יְכַבֵּ֧ס בְּגָדָ֛י/ו וְ/רָחַ֥ץ בַּ/מַּ֖יִם וְ/טָמֵ֥א עַד הָ/עָֽרֶב", "en": {"kjv": "And whosoever toucheth any thing that she sat upon shall wash his clothes, and bathe himself in water, and be unclean until the even.", "web": "Whoever touches anything that she sits on shall wash his clothes, and bathe himself in water, and be unclean until the evening.", "bsb": "Whoever touches any furniture on which she was sitting must wash his clothes and bathe with water, and he will be unclean until evening.", "asv": "And whosoever toucheth anything that she sitteth upon shall wash his clothes, and bathe himself in water, and be unclean until the even.", "ylt": "`And any one who is coming against any vessel on which she sitteth doth wash his garments, and hath washed with water, and been unclean till the evening.", "tyndale": "And whosoeuer twicheth any thinge that she satt apo, shall wassh his clothes ad washe him selfe also in water, ad be vncleane vnto the eue:", "dra": "He that toucheth her bed shall wash his clothes: and being himself washed with water, shall be unclean until the evening.", "bbe": "And anyone touching anything on which she has been seated will have to have his clothing washed and his body bathed in water and be unclean till evening.", "geneva": "And whosoeuer toucheth any thing that she sate vpon, shall wash his clothes, and wash him selfe in water, and shalbe vncleane vnto the euen:", "wycliffe": "Who euer touchith ony vessel on which sche sittith, he schal waische hise clothis, and he schal be waischun in watir, and schal be defoulid `til to euentid.", "rotherham": "and, whosoever toucheth any thing whereon she sitteth shall wash his clothes, and bathe in water, and be unclean until the evening;", "darby": "And whoever toucheth any object that she sat upon shall wash his garments, and bathe in water, and be unclean until the even.", "twenty": "", "jps": "And whosoever toucheth any thing that she sitteth upon shall wash his clothes, and bathe himself in water, and be unclean until the even.", "acv": "And whoever touches anything that she sits upon shall wash his clothes, and bathe himself in water, and be unclean until the evening.", "anderson": "", "haweis": "", "noyes": "", "webster": "And whoever toucheth any thing that she sat upon shall wash his clothes, and bathe [himself] in water, and be unclean until the evening.", "vulgate": "qui tetigerit lectum eius lavabit vestimenta sua et ipse lotus aqua inmundus erit usque ad vesperum;", "brenton": "and every one that touches any vessel on which she shall sit, shall wash his garments and bathe himself in water, and shall be unclean until evening."}}, {"v": 23, "ref": "15:23", "o": "וְ/אִ֨ם עַֽל הַ/מִּשְׁכָּ֜ב ה֗וּא א֧וֹ עַֽל הַ/כְּלִ֛י אֲשֶׁר הִ֥וא יֹשֶֽׁבֶת עָלָ֖י/ו בְּ/נָגְע/וֹ ב֑/וֹ יִטְמָ֖א עַד הָ/עָֽרֶב", "en": {"kjv": "And if it be on her bed, or on any thing whereon she sitteth, when he toucheth it, he shall be unclean until the even.", "web": "If it is on the bed, or on anything whereon she sits, when he touches it, he shall be unclean until the evening.", "bsb": "And whether it is a bed or furniture on which she was sitting, whoever touches it will be unclean until evening.", "asv": "And if it be on the bed, or on anything whereon she sitteth, when he toucheth it, he shall be unclean until the even.", "ylt": "`And if it is on the bed, or on the vessel on which she is sitting, in his coming against it, he is unclean till the evening.", "tyndale": "so that whether he twich hir couche or any thige whereo she hath sete, he shalbe vnclene uto the eue.", "dra": "Whosoever shall touch any vessel on which she sitteth, shall wash his clothes: and himself being washed with water, shall be defiled until the evening.", "bbe": "Anyone touching anything on the bed or on the thing on which she has been seated, will be unclean till evening.", "geneva": "So that whether he touche her bed, or any thing whereon shee hath sit, he shalbe vncleane vnto the euen.", "wycliffe": "If a man is couplid fleischli with hir in the tyme of blood that renneth bi monethis, he schal be vncleene bi seuene daies, and ech bed in which he slepith schal be defoulid.", "rotherham": "and, whether, on her bed, it is, or on any thing whereon she hath been sitting, when he toucheth it, he shall be unclean until the evening;", "darby": "And if it be on the bed, or on anything whereon she sitteth, when he toucheth it, he shall be unclean until the even.", "twenty": "", "jps": "And if he be on the bed, or on any thing whereon she sitteth, when he toucheth it, he shall be unclean until the even.", "acv": "And if it be on the bed, or on anything on which she sits, when he touches it, he shall be unclean until the evening.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if it [be] on [her] bed, or on any thing on which she sitteth, when he toucheth it, he shall be unclean until the evening.", "vulgate": "omne vas super quo illa sederit quisquis adtigerit lavabit vestimenta sua et lotus aqua pollutus erit usque ad vesperum;", "brenton": "And whether it be while she is on her bed, or on a seat which she may happen to sit upon when he touches her, he shall be unclean till evening."}}, {"v": 24, "ref": "15:24", "o": "וְ/אִ֡ם שָׁכֹב֩ יִשְׁכַּ֨ב אִ֜ישׁ אֹתָ֗/הּ וּ/תְהִ֤י נִדָּתָ/הּ֙ עָלָ֔י/ו וְ/טָמֵ֖א שִׁבְעַ֣ת יָמִ֑ים וְ/כָל הַ/מִּשְׁכָּ֛ב אֲשֶׁר יִשְׁכַּ֥ב עָלָ֖י/ו יִטְמָֽא", "en": {"kjv": "And if any man lie with her at all, and her flowers be upon him, he shall be unclean seven days; and all the bed whereon he lieth shall be unclean.", "web": "“‘If any man lies with her, and her monthly flow is on him, he shall be unclean seven days; and every bed whereon he lies shall be unclean.", "bsb": "If a man lies with her and her menstrual flow touches him, he will be unclean for seven days, and any bed on which he lies will become unclean.", "asv": "And if any man lie with her, and her impurity be upon him, he shall be unclean seven days; and every bed whereon he lieth shall be unclean.", "ylt": "`And if a man really lie with her, and her separation is on him, then he hath been unclean seven days, and all the bed on which he lieth is unclean.", "tyndale": "ad yf a ma lye with her in the meane tyme, he shalbe put aparte as well as she ad shalbe vncleane .vij. dayes, ad all his couch wherein he slepeth shalbe vncleane.", "dra": "If a man copulateth with her in the time of her flowers, he shall be unclean seven days: and every bed on which he shall sleep, shall be defiled.", "bbe": "And if any man has sex relations with her so that her blood comes on him, he will be unclean for seven days and every bed on which he has been resting will be unclean.", "geneva": "And if a man lye with her, and the flowers of her separation touch him, he shalbe vncleane seuen dayes, and all the whole bed whereon he lieth, shalbe vncleane.", "wycliffe": "A womman that suffrith in many daies the `fletyng out of blood, not in the tyme of monethis, ethir which womman ceessith not to flete out blood aftir the blood of monethis, schal be vncleene as longe as sche `schal be suget to this passioun, as if sche is in the tyme of monethis.", "rotherham": "and if man shall even lie with her, and her cause for removal be upon him, then shall he be unclean seven days,—and, all the bed whereon he shall lie, shall be unclean.", "darby": "And if a man lie with her at all, and the uncleanness of her separation come upon him, he shall be unclean seven days; and every bed whereon he lieth shall be unclean.", "twenty": "", "jps": "And if any man lie with her, and her impurity be upon him, he shall be unclean seven days; and every bed whereon he lieth shall be unclean.", "acv": "And if any man lies with her, and her impurity be upon him, he shall be unclean seven days, and every bed on which he lies shall be unclean.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if any man shall lie with her at all, and her flowers be upon him, he shall be unclean seven days: and all the bed on which he lieth shall be unclean.", "vulgate": "si coierit cum ea vir tempore sanguinis menstrualis inmundus erit septem diebus et omne stratum in quo dormierit polluetur;", "brenton": "And if any one shall lie with her, and her uncleanness be upon him, he shall be unclean seven days; and every bed on which he shall have lain shall be unclean."}}, {"v": 25, "ref": "15:25", "o": "וְ/אִשָּׁ֡ה כִּֽי יָזוּב֩ ז֨וֹב דָּמָ֜/הּ יָמִ֣ים רַבִּ֗ים בְּ/לֹא֙ עֶת נִדָּתָ֔/הּ א֥וֹ כִֽי תָז֖וּב עַל נִדָּתָ֑/הּ כָּל יְמֵ֞י ז֣וֹב טֻמְאָתָ֗/הּ כִּ/ימֵ֧י נִדָּתָ֛/הּ תִּהְיֶ֖ה טְמֵאָ֥ה הִֽוא", "en": {"kjv": "And if a woman have an issue of her blood many days out of the time of her separation, or if it run beyond the time of her separation; all the days of the issue of her uncleanness shall be as the days of her separation: she shall be unclean.", "web": "“‘If a woman has a discharge of her blood many days not in the time of her period, or if she has a discharge beyond the time of her period; all the days of the discharge of her uncleanness shall be as in the days of her period: she is unclean.", "bsb": "When a woman has a discharge of her blood for many days at a time other than her menstrual period, or if it continues beyond her period, she will be unclean all the days of her unclean discharge, just as she is during the days of her menstruation.", "asv": "And if a woman have an issue of her blood many days not in the time of her impurity, or if she have an issue beyond the time of her impurity; all the days of the issue of her uncleanness she shall be as in the days of her impurity: she is unclean.", "ylt": "`And when a woman's issue of blood floweth many days within the time of her separation, or when it floweth over her separation--all the days of the issue of her uncleanness are as the days of her separation; she is unclean.", "tyndale": "When a womans bloude runneth longe tyme: whether out of the tyme of hyr naturall course: as longe as hir vnclennesse runneth, she shalbe vncleane after the maner as when she is put aparte.", "dra": "The woman that hath still issue of blood many days out of her ordinary time, or that ceaseth not to flow after the monthly courses, as long as she is subject to this disease, shall be unclean, in the same manner as if she were in her flowers.", "bbe": "And if a woman has a flow of blood for a long time, not at the time when she generally has it, or if the flow goes on longer than the normal time, she will be unclean while the flow of blood goes on, as she is at other normal times.", "geneva": "Also when a womans issue of blood runneth long time besides the time of her floures, or when she hath an issue, longer then her floures, all the dayes of the issue of her vncleannesse shee shalbe vncleane, as in the time of her floures.", "wycliffe": "Ech bed in which sche slepith, and `vessel in which sche sittith, schal be defoulid.", "rotherham": "And when any woman’s, flow of blood lasteth many day, outside the time of her removal, or when it floweth beyond her removal, all the days of her unclean flow, shall she be as in the days of her removal—unclean, she is.", "darby": "And if a woman have her flux of blood many days out of the time of her separation, or if she have the flux beyond the time of her separation, all the days of the flux of her uncleanness shall she be as [in] the days of her separation: she is unclean.", "twenty": "", "jps": "And if a woman have an issue of her blood many days not in the time of her impurity, or if she have an issue beyond the time of her impurity; all the days of the issue of her uncleanness she shall be as in the days of her impurity: she is unclean.", "acv": "And if a woman has an issue of her blood many days not in the time of her impurity, or if she has an issue beyond the time of her impurity, she shall be all the days of the issue of her uncleanness as in the days of her impurity; she is unclean.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if a woman shall have an issue of her blood many days out of the time of her separation, or if it shall run beyond the time of her separation; all the days of the issue of her uncleanness shall be as the days of her separation: she [shall be] unclean.", "vulgate": "mulier quae patitur multis diebus fluxum sanguinis non in tempore menstruali vel quae post menstruum sanguinem fluere non cessat quamdiu huic subiacet passioni inmunda erit quasi sit in tempore menstruo;", "brenton": "And if a woman have an issue of blood many days, not in the time of her separation; if the blood should also flow after her separation, all the days of the issue of her uncleanness shall be as the days of her separation: she shall be unclean."}}, {"v": 26, "ref": "15:26", "o": "כָּל הַ/מִּשְׁכָּ֞ב אֲשֶׁר תִּשְׁכַּ֤ב עָלָי/ו֙ כָּל יְמֵ֣י זוֹבָ֔/הּ כְּ/מִשְׁכַּ֥ב נִדָּתָ֖/הּ יִֽהְיֶה לָּ֑/הּ וְ/כָֽל הַ/כְּלִי֙ אֲשֶׁ֣ר תֵּשֵׁ֣ב עָלָ֔י/ו טָמֵ֣א יִהְיֶ֔ה כְּ/טֻמְאַ֖ת נִדָּתָֽ/הּ", "en": {"kjv": "Every bed whereon she lieth all the days of her issue shall be unto her as the bed of her separation: and whatsoever she sitteth upon shall be unclean, as the uncleanness of her separation.", "web": "Every bed whereon she lies all the days of her discharge shall be to her as the bed of her period: and everything whereon she sits shall be unclean, as the uncleanness of her period.", "bsb": "Any bed on which she lies or any furniture on which she sits during the days of her discharge will be unclean, like her bed during her menstrual period.", "asv": "Every bed whereon she lieth all the days of her issue shall be unto her as the bed of her impurity: and everything whereon she sitteth shall be unclean, as the uncleanness of her impurity.", "ylt": "`All the bed on which she lieth all the days of her issue is as the bed of her separation to her, and all the vessel on which she sitteth is unclean as the uncleanness of her separation;", "tyndale": "All hir couches whereon she lyeth (as loge as hir yssue lasteth) shalbe vnto her as hir couch when she is put a parte. And what soeuer she sytteth apon, shalbe vncleane, as is hir vnclennesse whe she is put a parte.", "dra": "Every bed on which she sleepeth, and every vessel on which she sitteth, shall be defiled.", "bbe": "Every bed on which she has been resting will be unclean, as at the times when she normally has a flow of blood, and everything on which she has been seated will be unclean, in the same way.", "geneva": "Euery bed whereon shee lyeth (as long as her issue lasteth) shalbe to her as her bed of her separation: and whatsoeuer she sitteth vpon, shalbe vncleane, as her vncleannes whe she is put apart.", "wycliffe": "Who euer touchith hir schal waische his clothis, and he schal be waischun in watir, and schal be vncleene `til to euentid.", "rotherham": "All the bed whereon she lieth during all the days of her flow, like her bed in her removal, shall be to her,—and, every thing whereon she sitteth, shall be, unclean, like the uncleanness in her removal;", "darby": "Every bed whereon she lieth all the days of her flux shall be unto her as the bed of her separation; and every object on which she sitteth shall be unclean, according to the uncleanness of her separation.", "twenty": "", "jps": "Every bed whereon she lieth all the days of her issue shall be unto her as the bed of her impurity; and every thing whereon she sitteth shall be unclean, as the uncleanness of her impurity.", "acv": "Every bed on which she lies all the days of her issue shall be to her as the bed of her impurity, and everything on which she sits shall be unclean, as the uncleanness of her impurity.", "anderson": "", "haweis": "", "noyes": "", "webster": "Every bed on which she lieth all the days of her issue shall be to her as the bed of her separation: and whatever she sitteth upon shall be unclean as the uncleanness of her separation.", "vulgate": "omne stratum in quo dormierit et vas in quo sederit pollutum erit;", "brenton": "And every bed on which she shall lie all the days of her flux shall be to her as the bed of her separation, and every seat whereon she shall sit shall be unclean according to the uncleanness of her separation."}}, {"v": 27, "ref": "15:27", "o": "וְ/כָל הַ/נּוֹגֵ֥עַ בָּ֖/ם יִטְמָ֑א וְ/כִבֶּ֧ס בְּגָדָ֛י/ו וְ/רָחַ֥ץ בַּ/מַּ֖יִם וְ/טָמֵ֥א עַד הָ/עָֽרֶב", "en": {"kjv": "And whosoever toucheth those things shall be unclean, and shall wash his clothes, and bathe himself in water, and be unclean until the even.", "web": "Whoever touches these things shall be unclean, and shall wash his clothes, and bathe himself in water, and be unclean until the evening.", "bsb": "Anyone who touches these things will be unclean; he must wash his clothes and bathe with water, and he will be unclean until evening.", "asv": "And whosoever toucheth those things shall be unclean, and shall wash his clothes, and bathe himself in water, and be unclean until the even.", "ylt": "and any one who is coming against them is unclean, and hath washed his garments, and hath bathed with water, and been unclean till the evening.", "tyndale": "And whosoeuer twicheth them, shalbe vncleane, ad shall wasshe his clothes ad bathe him selfe in water ad be vncleane vnto euen.", "dra": "Whosoever toucheth them shall wash his clothes: and himself being washed with water, shall be unclean until the evening.", "bbe": "And anyone touching these things will be unclean, and his clothing will have to be washed and his body bathed in water and he will be unclean till evening.", "geneva": "And whosoeuer toucheth these things, shall be vncleane, and shall wash his clothes, and wash him selfe in water, and shalbe vncleane vnto the euen.", "wycliffe": "If the blood stondith, and ceessith to flete out, sche schal noumbre seuene daies of hir clensyng,", "rotherham": "and whosoever toucheth them, shall be unclean,—and shall wash his clothes, and bathe in water, and be unclean until the evening.", "darby": "And whoever toucheth them shall be unclean, and shall wash his clothes, and bathe in water, and be unclean until the even.", "twenty": "", "jps": "And whosoever toucheth those things shall be unclean, and shall wash his clothes, and bathe himself in water, and be unclean until the even.", "acv": "And whoever touches those things shall be unclean, and shall wash his clothes, and bathe himself in water, and be unclean until the evening.", "anderson": "", "haweis": "", "noyes": "", "webster": "And whoever toucheth those things shall be unclean, and shall wash his clothes, and bathe [himself] in water, and be unclean until the evening.", "vulgate": "quicumque tetigerit eam lavabit vestimenta sua et ipse lotus aqua inmundus erit usque ad vesperum;", "brenton": "Every one that touches it shall be unclean; and he shall wash his garments, and bathe his body in water, and shall be unclean till evening."}}, {"v": 28, "ref": "15:28", "o": "וְ/אִֽם טָהֲרָ֖ה מִ/זּוֹבָ֑/הּ וְ/סָ֥פְרָה לָּ֛/הּ שִׁבְעַ֥ת יָמִ֖ים וְ/אַחַ֥ר תִּטְהָֽר", "en": {"kjv": "But if she be cleansed of her issue, then she shall number to herself seven days, and after that she shall be clean.", "web": "“‘But if she is cleansed of her discharge, then she shall count to herself seven days, and after that she shall be clean.", "bsb": "When a woman is cleansed of her discharge, she must count off seven days, and after that she will be ceremonially clean.", "asv": "But if she be cleansed of her issue, then she shall number to herself seven days, and after that she shall be clean.", "ylt": "`And if she hath been clean from her issue, then she hath numbered to herself seven days, and afterwards she is clean;", "tyndale": "And when she it clensed of hyr yssue, let hyr counte hir seuen dayes after that she is cleane.", "dra": "If the blood stop and cease to run, she shall count seven days of her purification:", "bbe": "But when her flow of blood is stopped, after seven days she will be clean.", "geneva": "But if she be clensed of her issue, then shee shall count her seuen dayes, and after, shee shall be cleane.", "wycliffe": "and in the eiytthe dai sche schal offre for hir silf to the preest twei turtlis, ethir twei `briddis of culueris, at the dore of the tabernacle of witnessyng;", "rotherham": "But, if she be clean from her flow, then shall she count to herself seven days and afterwards, shall she count herself clean.", "darby": "And if she be cleansed of her flux then she shall count seven days, and after that she shall be clean.", "twenty": "", "jps": "But if she be cleansed of her issue, then she shall number to herself seven days, and after that she shall be clean.", "acv": "But if she is cleansed of her issue, then she shall number to herself seven days, and after that she shall be clean.", "anderson": "", "haweis": "", "noyes": "", "webster": "But if she shall be cleansed of her issue, then she shall number to herself seven days, and after that she shall be clean.", "vulgate": "si steterit sanguis et fluere cessarit numerabit septem dies purificationis suae;", "brenton": "But if she shall be cleansed from her flux, then she shall number to herself seven days, and afterwards she shall be esteemed clean."}}, {"v": 29, "ref": "15:29", "o": "וּ/בַ/יּ֣וֹם הַ/שְּׁמִינִ֗י תִּֽקַּֽח לָ/הּ֙ שְׁתֵּ֣י תֹרִ֔ים א֥וֹ שְׁנֵ֖י בְּנֵ֣י יוֹנָ֑ה וְ/הֵבִיאָ֤ה אוֹתָ/ם֙ אֶל הַ/כֹּהֵ֔ן אֶל פֶּ֖תַח אֹ֥הֶל מוֹעֵֽד", "en": {"kjv": "And on the eighth day she shall take unto her two turtles, or two young pigeons, and bring them unto the priest, to the door of the tabernacle of the congregation.", "web": "On the eighth day she shall take two turtledoves, or two young pigeons, and bring them to the priest, to the door of the Tent of Meeting.", "bsb": "On the eighth day she is to take two turtledoves or two young pigeons and bring them to the priest at the entrance to the Tent of Meeting.", "asv": "And on the eighth day she shall take unto her two turtle-doves, or two young pigeons, and bring them unto the priest, to the door of the tent of meeting.", "ylt": "and on the eighth day she taketh to herself two turtle-doves, or two young pigeons, and hath brought them in unto the priest, unto the opening of the tent of meeting;", "tyndale": "And the .viij daye let her take two turtils or two yonge pigeons and brynge them vnto the preast vnto the dore of the tabernacle of witnesse.", "dra": "And on the eighth day she shall offer for herself to the priest, two turtles, or two young pigeons, at the door of the tabernacle of the testimony:", "bbe": "And on the eighth day let her get two doves or two young pigeons and take them to the priest to the door of the Tent of meeting,", "geneva": "And in the eight day shee shall take vnto her two Turtles or two yong pigeons, and bring them vnto the Priest at the doore of the Tabernacle of the Congregation.", "wycliffe": "and the preest schal make oon for synne, and the tothir in to brent sacrifice; and the preest schal preye for hir bifor the Lord, and for the fletyng out of hir vnclennesse.", "rotherham": "And, on the eighth day, shall she take to herself two turtle doves, or two young pigeons,—and bring them in unto the priest, unto the entrance of the tent of meeting;", "darby": "And on the eighth day she shall take two turtle-doves, or two young pigeons, and bring them unto the priest, unto the entrance of the tent of meeting.", "twenty": "", "jps": "And on the eighth day she shall take unto her two turtle-doves, or two young pigeons, and bring them unto the priest, to the door of the tent of meeting.", "acv": "And on the eighth day she shall take to her two turtle-doves, or two young pigeons, and bring them to the priest, to the door of the tent of meeting.", "anderson": "", "haweis": "", "noyes": "", "webster": "And on the eighth day she shall take to her two turtles, or two young pigeons, and bring them to the priest, to the door of the tabernacle of the congregation.", "vulgate": "et octavo die offeret pro se sacerdoti duos turtures vel duos pullos columbae ad ostium tabernaculi testimonii;", "brenton": "And on the eighth day she shall take two turtle-doves, or two young pigeons, and shall bring them to the priest, to the door of the tabernacle of witness."}}, {"v": 30, "ref": "15:30", "o": "וְ/עָשָׂ֤ה הַ/כֹּהֵן֙ אֶת הָ/אֶחָ֣ד חַטָּ֔את וְ/אֶת הָ/אֶחָ֖ד עֹלָ֑ה וְ/כִפֶּ֨ר עָלֶ֤י/הָ הַ/כֹּהֵן֙ לִ/פְנֵ֣י יְהוָ֔ה מִ/זּ֖וֹב טֻמְאָתָֽ/הּ", "en": {"kjv": "And the priest shall offer the one for a sin offering, and the other for a burnt offering; and the priest shall make an atonement for her before the Lord for the issue of her uncleanness.", "web": "The priest shall offer the one for a sin offering, and the other for a burnt offering; and the priest shall make atonement for her before Yahweh for the uncleanness of her discharge.", "bsb": "The priest is to sacrifice one as a sin offering and the other as a burnt offering. In this way the priest will make atonement for her before the LORD for her unclean discharge.", "asv": "And the priest shall offer the one for a sin-offering, and the other for a burnt-offering; and the priest shall make atonement for her before Jehovah for the issue of her uncleanness.", "ylt": "and the priest hath made the one a sin-offering, and the one a burnt-offering, and the priest hath made atonement for her before Jehovah, because of the issue of her uncleanness.", "tyndale": "And the preast shall offer the one for a synneoffrynge, and the other for a burntofferynge: and so make an attonement for her before the Lorde. as concernynge hir vncleane yssue.", "dra": "And he shall offer one for sin, and the other for a holocaust, and he shall pray for her before the Lord, and for the issue of her uncleanness.", "bbe": "To be offered by the priest, one for a sin-offering and one for a burned offering; and the priest will take away her sin before the Lord on account of her unclean condition.", "geneva": "And the Priest shall make of ye one a sinne offring, and of the other a burnt offring, and the Priest shall make an atonement for her before the Lord, for the issue of her vncleannes.", "wycliffe": "Therfor ye schulen teche the sones of Israel, that thei eschewe vnclennessis, and that thei die not for her filthis, whanne thei defoulen my tabernacle which is among hem.", "rotherham": "and the priest shall offer the one as a sin-bearer, and the other as an ascending-sacrifice,—so shall the priest put a propitiatory-covering over her, before Yahweh, because of her unclean flow.", "darby": "And the priest shall offer the one as a sin-offering, and the other as a burnt-offering; and the priest shall make atonement for her before Jehovah for the flux of her uncleanness.", "twenty": "", "jps": "And the priest shall offer the one for a sin-offering, and the other for a burnt-offering; and the priest shall make atonement for her before HaShem for the issue of her uncleanness.", "acv": "And the priest shall offer the one for a sin offering, and the other for a burnt offering, and the priest shall make atonement for her before Jehovah for the issue of her uncleanness.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall offer the one [for] a sin-offering, and the other [for] a burnt-offering; and the priest shall make an atonement for her before the LORD for the issue of her uncleanness.", "vulgate": "qui unum faciet pro peccato et alterum in holocaustum rogabitque pro ea coram Domino et pro fluxu inmunditiae eius;", "brenton": "And the priest shall offer one for a sin-offering, and the other for a whole-burnt-offering, and the priest shall make atonement for her before the Lord for her unclean flux."}}, {"v": 31, "ref": "15:31", "o": "וְ/הִזַּרְתֶּ֥ם אֶת בְּנֵי יִשְׂרָאֵ֖ל מִ/טֻּמְאָתָ֑/ם וְ/לֹ֤א יָמֻ֨תוּ֙ בְּ/טֻמְאָתָ֔/ם בְּ/טַמְּאָ֥/ם אֶת מִשְׁכָּנִ֖/י אֲשֶׁ֥ר בְּ/תוֹכָֽ/ם", "en": {"kjv": "Thus shall ye separate the children of Israel from their uncleanness; that they die not in their uncleanness, when they defile my tabernacle that is among them.", "web": "“‘Thus you shall separate the children of Israel from their uncleanness, so they will not die in their uncleanness, when they defile my tabernacle that is in their midst.’”", "bsb": "You must keep the children of Israel separate from their uncleanness, so that they do not die by defiling My tabernacle, which is among them.", "asv": "Thus shall ye separate the children of Israel from their uncleanness, that they die not in their uncleanness, when they defile my tabernacle that is in the midst of them.", "ylt": "`And ye have separated the sons of Israel from their uncleanness, and they die not in their uncleanness, in their defiling My tabernacle which is in their midst.", "tyndale": "Make the childern of Israel to kepe them selues fro their vnclenesse, that they dye not in their vnclenesse: whe they haue defiled my habitacion that is amonge them.", "dra": "You shall teach therefore the children of Israel to take heed of uncleanness, that they may not die in their filth, when they shall have defiled my tabernacle that is among them.", "bbe": "In this way may the children of Israel be made free from all sorts of unclean conditions, so that death may not overtake them when they are unclean and when they make unclean my holy place which is among them.", "geneva": "Thus shall yee separate the children of Israel from their vncleannes, that they dye not in their vncleannesse, if they defile my Tabernacle that is among them.", "wycliffe": "This is the lawe of hym that suffrith fletyng out of seed, and which is defoulid with fleischly couplyng,", "rotherham": "Thus shall ye warn the sons of Israel from their uncleanness, And they shall not die in their uncleanness, By reason of their making unclean my habitation which is in their midst.", "darby": "And ye shall separate the children of Israel from their uncleanness, that they die not in their uncleanness, when they defile my tabernacle that is in their midst.", "twenty": "", "jps": "Thus shall ye separate the children of Israel from their uncleanness; that they die not in their uncleanness, when they defile My tabernacle that is in the midst of them.", "acv": "Thus ye shall separate the sons of Israel from their uncleanness, that they not die in their uncleanness when they defile my tabernacle that is in the midst of them.", "anderson": "", "haweis": "", "noyes": "", "webster": "Thus shall ye separate the children of Israel from their uncleanness: that they die not in their uncleanness, when they defile my tabernacle that [is] among them.", "vulgate": "docebitis ergo filios Israhel ut caveant inmunditiam et non moriantur in sordibus suis cum polluerint tabernaculum meum quod est inter eos;", "brenton": "And ye shall cause the children of Israel to beware of their uncleannesses; so they shall not die for their uncleanness, in polluting my tabernacle that is among them."}}, {"v": 32, "ref": "15:32", "o": "זֹ֥את תּוֹרַ֖ת הַ/זָּ֑ב וַ/אֲשֶׁ֨ר תֵּצֵ֥א מִמֶּ֛/נּוּ שִׁכְבַת זֶ֖רַע לְ/טָמְאָה בָֽ/הּ", "en": {"kjv": "This is the law of him that hath an issue, and of him whose seed goeth from him, and is defiled therewith;", "web": "This is the law of him who has a discharge, and of him who has an emission of semen, so that he is unclean thereby;", "bsb": "This is the law of him who has a discharge, of the man who has an emission of semen whereby he is unclean,", "asv": "This is the law of him that hath an issue, and of him whose seed of copulation goeth from him, so that he is unclean thereby;", "ylt": "`This is the law of him who hath an issue, and of him whose seed of copulation goeth out from him, for uncleanness thereby,", "tyndale": "This is the lawe of him that hath a runninge sore, and of him whose seed runneth from him in his slepe and is defiled therewith,", "dra": "This is the law of him that hath the issue of seed, and that is defiled by copulation.", "bbe": "This is the law for the man who has a flow from his body, or whose seed goes from him so that he is unclean;", "geneva": "This is the lawe of him that hath an issue, and of him from whome goeth an issue of seede whereby he is defiled:", "wycliffe": "and of a womman which is departid in the tymes of monethis, ethir which flowith out in contynuel blood, and of the man that slepith with hir.", "rotherham": "This, is the law—Of him that hath a flux,—And of him from whom goeth an outflow of seed, making unclean thereby;", "darby": "This is the law for him that hath a flux, and for the one whose seed of copulation goeth from him, and who is defiled therewith:", "twenty": "", "jps": "This is the law of him that hath an issue, and of him from whom the flow of seed goeth out, so that he is unclean thereby;", "acv": "This is the law of him who has an issue, and of him whose seed of copulation goes from him, so that he is unclean thereby,", "anderson": "", "haweis": "", "noyes": "", "webster": "This [is] the law of him that hath an issue, and [of him] whose seed goeth from him, and [he] is defiled therewith.", "vulgate": "ista est lex eius qui patitur fluxum seminis et qui polluitur coitu;", "brenton": "This is the law of the man who has an issue, and if one discharge seed of copulation, so that he should be polluted by it."}}, {"v": 33, "ref": "15:33", "o": "וְ/הַ/דָּוָה֙ בְּ/נִדָּתָ֔/הּ וְ/הַ/זָּב֙ אֶת זוֹב֔/וֹ לַ/זָּכָ֖ר וְ/לַ/נְּקֵבָ֑ה וּ/לְ/אִ֕ישׁ אֲשֶׁ֥ר יִשְׁכַּ֖ב עִם טְמֵאָֽה", "en": {"kjv": "And of her that is sick of her flowers, and of him that hath an issue, of the man, and of the woman, and of him that lieth with her that is unclean.", "web": "and of her who has her period, and of a man or woman who has a discharge, and of him who lies with her who is unclean.", "bsb": "of a woman in her menstrual period, of any male or female who has a discharge, and of a man who lies with an unclean woman.’”", "asv": "and of her that is sick with her impurity, and of him that hath an issue, of the man, and of the woman, and of him that lieth with her that is unclean.", "ylt": "and of her who is sick in her separation, and of him who hath an issue, the issue of a male or of a female, and of a man who lieth with an unclean woman.'", "tyndale": "and of her that hath an yssue of bloude as longe as she is put a parte, and of whosoeuer hath a runnynge sore whether it be man or woman, and of him that slepeth with her that is vncleane.", "dra": "And of the woman that is separated in her monthly times, or that hath a continual issue of blood, and of the man that sleepeth with her.", "bbe": "And for her who has a flow of blood, and for any man or woman who has an unclean flow, and for him who has sex relations with a woman when she is unclean.", "geneva": "Also of her that is sicke of her floures, and of him that hath a running issue, whether it bee man or woman, and of him that lyeth with her which is vncleane.", "wycliffe": "", "rotherham": "And of her that is unwell with her cause for removal, And of him whose flux floweth, For the male, and for the female,—And for a man who lieth with her that is unclean.", "darby": "and for a woman who is sick in her separation, and for him that hath his flux; for the man and for the woman, and for him that lieth with her that is unclean.", "twenty": "", "jps": "and of her that is sick with her impurity, and of them that have an issue, whether it be a man, or a woman; and of him that lieth with her that is unclean.", "acv": "and of her who is sick with her impurity, and of him who has an issue, of the man, and of the woman, and of him who lies with her who is unclean.", "anderson": "", "haweis": "", "noyes": "", "webster": "And of her that is sick of her flowers, and of him that hath an issue, of the man and of the woman, and of him that lieth with her that is unclean.", "vulgate": "et quae menstruis temporibus separatur vel quae iugi fluit sanguine et hominis qui dormierit cum ea;", "brenton": "And this is the law for her that has the issue of blood in her separation, and as to the person who has an issue of seed, in his issue: it is a law for the male and the female, and for the man who shall have lain with her that is set apart."}}]}, {"c": 16, "verses": [{"v": 1, "ref": "16:1", "o": "וַ/יְדַבֵּ֤ר יְהוָה֙ אֶל מֹשֶׁ֔ה אַחֲרֵ֣י מ֔וֹת שְׁנֵ֖י בְּנֵ֣י אַהֲרֹ֑ן בְּ/קָרְבָתָ֥/ם לִ/פְנֵי יְהוָ֖ה וַ/יָּמֻֽתוּ", "en": {"kjv": "And the Lord spake unto Moses after the death of the two sons of Aaron, when they offered before the Lord, and died;", "web": "Yahweh spoke to Moses, after the death of the two sons of Aaron, when they drew near before Yahweh, and died;", "bsb": "Now the LORD spoke to Moses after the death of two of Aaron’s sons when they approached the presence of the LORD.", "asv": "And Jehovah spake unto Moses, after the death of the two sons of Aaron, when they drew near before Jehovah, and died;", "ylt": "And Jehovah speaketh unto Moses, after the death of the two sons of Aaron, in their drawing near before Jehovah, and they die;", "tyndale": "And the Lorde spake vnto Moses after the deeth of the two sonnes of Aaron, when they had offered before the Lorde and dyed:", "dra": "And the Lord spoke to Moses, after the death of the two sons of Aaron when they were slain upon their offering strange fire:", "bbe": "And the Lord said to Moses, after the death of the two sons of Aaron when they took in strange fire before the Lord and death overtook them;", "geneva": "Fvrthermore the Lord spake vnto Moses, after the death of the two sonnes of Aaron, whe they came to offer before the Lord, and dyed:", "wycliffe": "And the Lord spak to Moises, aftir the deeth of the twei sones of Aaron, whanne thei offriden alien fier, and weren slayn, and comaundide to hym,", "rotherham": "And Yahweh spake unto Moses, after the death of the two sons of Aaron,—when they had offered strange fire before Yahweh and died.", "darby": "And Jehovah spoke to Moses after the death of the two sons of Aaron, when they came near before Jehovah and died;", "twenty": "", "jps": "And HaShem spoke unto Moses, after the death of the two sons of Aaron, when they drew near before HaShem, and died;", "acv": "And Jehovah spoke to Moses, after the death of the two sons of Aaron, when they drew near before Jehovah, and died,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses after the death of the two sons of Aaron, when they offered before the LORD, and died:", "vulgate": "locutusque est Dominus ad Mosen post mortem duum filiorum Aaron quando offerentes ignem alienum interfecti sunt;", "brenton": "And the Lord spoke to Moses after the two sons of Aaron died in bringing strange fire before the Lord, so they died."}}, {"v": 2, "ref": "16:2", "o": "וַ/יֹּ֨אמֶר יְהוָ֜ה אֶל מֹשֶׁ֗ה דַּבֵּר֮ אֶל אַהֲרֹ֣ן אָחִי/ךָ֒ וְ/אַל יָבֹ֤א בְ/כָל עֵת֙ אֶל הַ/קֹּ֔דֶשׁ מִ/בֵּ֖ית לַ/פָּרֹ֑כֶת אֶל פְּנֵ֨י הַ/כַּפֹּ֜רֶת אֲשֶׁ֤ר עַל הָ/אָרֹן֙ וְ/לֹ֣א יָמ֔וּת כִּ֚י בֶּֽ/עָנָ֔ן אֵרָאֶ֖ה עַל הַ/כַּפֹּֽרֶת", "en": {"kjv": "And the Lord said unto Moses, Speak unto Aaron thy brother, that he come not at all times into the holy place within the vail before the mercy seat, which is upon the ark; that he die not: for I will appear in the cloud upon the mercy seat.", "web": "and Yahweh said to Moses, “Tell Aaron your brother, not to come at all times into the Most Holy Place within the veil, before the mercy seat which is on the ark; lest he die: for I will appear in the cloud on the mercy seat.", "bsb": "And the LORD said to Moses: “Tell your brother Aaron not to enter freely into the Most Holy Place behind the veil in front of the mercy seat on the ark, or else he will die, because I appear in the cloud above the mercy seat.", "asv": "and Jehovah said unto Moses, Speak unto Aaron thy brother, that he come not at all times into the holy place within the veil, before the mercy-seat which is upon the ark; that he die not: for I will appear in the cloud upon the mercy-seat.", "ylt": "yea, Jehovah saith unto Moses, `Speak unto Aaron thy brother, and he cometh not in at all times unto the sanctuary within the vail, unto the front of the mercy-seat, which is upon the ark, and he dieth not, for in a cloud I am seen upon the mercy-seat.", "tyndale": "And he sayde vnto Moses: speake vnto Aaron thy brother that he go not at all tymes in to the holy place, that is whithin the vayle that hangeth before the mercyseate which is apon the arcke that he dye not. For I will appeare in a clowde vpon the mercyseate.", "dra": "And he commanded him, saying: Speak to Aaron thy brother, that he enter not at all into the sanctuary, which is within the veil before the propitiatory, with which the ark is covered, lest he die, (for I will appear in a cloud over the oracle),", "bbe": "The Lord said to Moses, Say to Aaron, your brother, that he may not come at all times into the holy place inside the veil, before the cover which is on the ark, for fear that death may overtake him; for I will be seen in the cloud on the cover of the ark.", "geneva": "And the Lord sayd vnto Moses, Speake vnto Aaron thy brother, that he come not at all times into the Holy place within the vayle, before the Merciseate, which is vpon the Arke, that he dye not: for I wil appeare in the cloude vpon the Merciseate.", "wycliffe": "and seide, Speke thou to Aaron, thi brother, that he entre not in al tyme in to the seyntuarie, which is with ynne the veil bifor the propiciatorie, bi which the arke is hilid, that he die not; for Y schal appere in a cloude on Goddis answeryng place;", "rotherham": "And Yahweh said unto Moses—Speak unto Aaron thy brother, that he do not come at all times into the holy place, within the veil,—into the presence of the propitiatory, which is upon the ark, so shall he not die, for, in the cloud, will I appear upon the propitiatory.", "darby": "and Jehovah said to Moses, Speak unto Aaron thy brother, that he come not at all times into the sanctuary inside the veil before the mercy-seat which is upon the ark, that he die not; for I will appear in the cloud upon the mercy-seat.", "twenty": "", "jps": "and HaShem said unto Moses: 'Speak unto Aaron thy brother, that he come not at all times into the holy place within the veil, before the ark-cover which is upon the ark; that he die not; for I appear in the cloud upon the ark-cover.", "acv": "and Jehovah said to Moses, Speak to Aaron thy brother, that he not come at all times into the holy place within the veil, before the mercy-seat which is upon the ark, that he not die, for I will appear in the cloud upon the mercy-seat.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD said to Moses, Speak to Aaron thy brother, that he come not at all times into the holy [place] within the vail, before the mercy-seat, which [is] upon the ark; that he may not die: for I will appear in the cloud upon the mercy-seat.", "vulgate": "et praecepit ei dicens loquere ad Aaron fratrem tuum ne omni tempore ingrediatur sanctuarium quod est intra velum coram propitiatorio quo tegitur arca ut non moriatur quia in nube apparebo super oraculum;", "brenton": "And the Lord said to Moses, Speak to Aaron thy brother, and let him not come in at all times into the holy place within the veil before the propitiatory, which is upon the ark of the testimony, and he shall not die; for I will appear in a cloud on the propitiatory."}}, {"v": 3, "ref": "16:3", "o": "בְּ/זֹ֛את יָבֹ֥א אַהֲרֹ֖ן אֶל הַ/קֹּ֑דֶשׁ בְּ/פַ֧ר בֶּן בָּקָ֛ר לְ/חַטָּ֖את וְ/אַ֥יִל לְ/עֹלָֽה", "en": {"kjv": "Thus shall Aaron come into the holy place: with a young bullock for a sin offering, and a ram for a burnt offering.", "web": "“Aaron shall come into the sanctuary with a young bull for a sin offering, and a ram for a burnt offering.", "bsb": "This is how Aaron is to enter the Holy Place: with a young bull for a sin offering and a ram for a burnt offering.", "asv": "Herewith shall Aaron come into the holy place: with a young bullock for a sin-offering, and a ram for a burnt-offering.", "ylt": "`With this doth Aaron come in unto the sanctuary; with a bullock, a son of the herd, for a sin-offering, and a ram for a burnt-offering;", "tyndale": "But of this maner shall Aaron goo in in to the holy place: with a yonge oxe for a synneofferynge, and a ram for a burntoffrynge.", "dra": "Unless he first do these things. He shall offer a calf for sin, and a ram for a holocaust.", "bbe": "Let Aaron come into the holy place in this way: with an ox for a sin-offering and a male sheep for a burned offering.", "geneva": "After this sort shall Aaron come into the Holy place: euen with a yong bullocke for a sinne offring, and a ramme for a burnt offring.", "wycliffe": "`no but he do these thingis bifore. He schal offer a calf for synne, and a ram in to brent sacrifice;", "rotherham": "Herewith, shall Aaron come into the holy place,—With a bullock the choice of the herd as a sin-bearer, and a ram as an ascending-sacrifice.", "darby": "In this manner shall Aaron come into the sanctuary: with a young bullock for a sin-offering, and a ram for a burnt-offering.", "twenty": "", "jps": "Herewith shall Aaron come into the holy place: with a young bullock for a sin-offering, and a ram for a burnt-offering.", "acv": "Aaron shall come into the holy place this way: with a young bullock for a sin offering, and a ram for a burnt offering.", "anderson": "", "haweis": "", "noyes": "", "webster": "Thus shall Aaron come into the holy [place]: with a young bullock for a sin-offering, and a ram for a burnt-offering.", "vulgate": "nisi haec ante fecerit vitulum offeret pro peccato et arietem in holocaustum;", "brenton": "Thus shall Aaron enter into the holy place; with a calf of the herd for a sin-offering, and having a ram for a whole-burnt-offering."}}, {"v": 4, "ref": "16:4", "o": "כְּתֹֽנֶת בַּ֨ד קֹ֜דֶשׁ יִלְבָּ֗שׁ וּ/מִֽכְנְסֵי בַד֮ יִהְי֣וּ עַל בְּשָׂר/וֹ֒ וּ/בְ/אַבְנֵ֥ט בַּד֙ יַחְגֹּ֔ר וּ/בְ/מִצְנֶ֥פֶת בַּ֖ד יִצְנֹ֑ף בִּגְדֵי קֹ֣דֶשׁ הֵ֔ם וְ/רָחַ֥ץ בַּ/מַּ֛יִם אֶת בְּשָׂר֖/וֹ וּ/לְבֵשָֽׁ/ם", "en": {"kjv": "He shall put on the holy linen coat, and he shall have the linen breeches upon his flesh, and shall be girded with a linen girdle, and with the linen mitre shall he be attired: these are holy garments; therefore shall he wash his flesh in water, and so put them on.", "web": "He shall put on the holy linen coat. He shall have the linen breeches on his body, and shall put on the linen sash, and he shall be clothed with the linen turban. They are the holy garments. He shall bathe his body in water, and put them on.", "bsb": "He is to wear the sacred linen tunic, with linen undergarments. He must tie a linen sash around him and put on the linen turban. These are holy garments, and he must bathe himself with water before he wears them.", "asv": "He shall put on the holy linen coat, and he shall have the linen breeches upon his flesh, and shall be girded with the linen girdle, and with the linen mitre shall he be attired: they are the holy garments; and he shall bathe his flesh in water, and put them on.", "ylt": "a holy linen coat he putteth on, and linen trousers are on his flesh, and with a linen girdle he girdeth himself, and with a linen mitre he wrappeth himself up; they are holy garments; and he hath bathed with water his flesh, and hath put them on.", "tyndale": "And he shall put the holy lynen albe apon him, ad shall haue a lynen breche vppon his flesh, and shall gyrde him with a lynen gyrdell, and put the lynen mytre apon his heede: for they are holy raymentes. And he shall wasshe his flesh with water, and put them on.", "dra": "He shall be vested with a linen tunick: he shall cover his nakedness with linen breeches: he shall be girded with a linen girdle, and he shall put a linen mitre upon his head. For these are holy vestments: all which he shall put on, after he is washed.", "bbe": "Let him put on the holy linen coat, and the linen trousers on his body, and the linen band round him, and the linen head-dress on his head; for this is holy clothing, and before he puts them on his body is to be washed with water.", "geneva": "He shall put on the holy linnen coate, and shall haue linnen breeches vpon his flesh, and shall be girded with a linnen girdle, and shall couer his head with a linnen miter: these are the holy garments: therefore shall hee wash his flesh in water, when he doeth put them on.", "wycliffe": "he schal be clothid with a lynnun coote, he schal hide the schamefast membris with pryuy lynnun clothis; he schal be gird with a lynnun girdil, he schal putte a lynnun mytre on his heed; for these clothis ben hooli, with whiche alle he schal be clothid, whanne he is waischun.", "rotherham": "A holy tunic of linen, shall he put on and drawers of linen, shall be upon his flesh, and with a band of linen, shall he gird himself, and with a turban of linen, shall his head be wrapped about,—holy garments, they are, therefore shall he bathe in water his flesh, and so put them on.", "darby": "A holy linen vest shall he put on, and linen trousers shall be upon his flesh, and he shall be girded with a linen girdle, and with the linen mitre shall he be attired: these are holy garments; and he shall bathe his flesh in water, and put them on.", "twenty": "", "jps": "He shall put on the holy linen tunic, and he shall have the linen breeches upon his flesh, and shall be girded with the linen girdle, and with the linen mitre shall he be attired; they are the holy garments; and he shall bathe his flesh in water, and put them on.", "acv": "He shall put on the holy linen tunic, and he shall have the linen breeches upon his flesh, and shall be girded with the linen sash, and he shall be attired with the linen miter. They are the holy garments, and he shall bathe his flesh in water, and put them on.", "anderson": "", "haweis": "", "noyes": "", "webster": "He shall put on the holy linen coat, and he shall have the linen breeches upon his flesh, and shall be girded with the linen girdle, and with the linen miter shall he be attired: these [are] holy garments; therefore shall he wash his flesh in water, and [so] put them on.", "vulgate": "tunica linea vestietur feminalibus lineis verecunda celabit accingetur zona linea cidarim lineam inponet capiti haec enim vestimenta sunt sancta quibus cunctis cum lotus fuerit induetur;", "brenton": "And he shall put on the consecrated linen tunic, and he shall have on his flesh the linen drawers, and shall gird himself with a linen girdle, and shall put on the linen cap, they are holy garments; and he shall bathe all his body in water, and shall put them on."}}, {"v": 5, "ref": "16:5", "o": "וּ/מֵ/אֵ֗ת עֲדַת֙ בְּנֵ֣י יִשְׂרָאֵ֔ל יִקַּ֛ח שְׁנֵֽי שְׂעִירֵ֥י עִזִּ֖ים לְ/חַטָּ֑את וְ/אַ֥יִל אֶחָ֖ד לְ/עֹלָֽה", "en": {"kjv": "And he shall take of the congregation of the children of Israel two kids of the goats for a sin offering, and one ram for a burnt offering.", "web": "He shall take from the congregation of the children of Israel two male goats for a sin offering, and one ram for a burnt offering.", "bsb": "And he shall take from the congregation of Israel two male goats for a sin offering and one ram for a burnt offering.", "asv": "And he shall take of the congregation of the children of Israel two he-goats for a sin-offering, and one ram for a burnt-offering.", "ylt": "`And from the company of the sons of Israel he taketh two kids of the goats for a sin-offering, and one ram for a burnt-offering;", "tyndale": "And he shall take of the multitude of the childern of Israel two gootes for a synneoffrynge and a ram for a burntofferynge.", "dra": "And he shall receive from the whole multitude of the children of Israel two buck goats for sin, and one ram for a holocaust.", "bbe": "And let him take from the children of Israel two he-goats for a sin-offering and one male sheep for a burned offering.", "geneva": "And hee shall take of the Congregation of the children of Israel, two hee goates for a sinne offring, and a ramme for a burnt offring.", "wycliffe": "And he schal take of al the multitude of the sones of Israel twei kidis for synne, and o ram in to brent sacrifice;", "rotherham": "And, from the assembly of the sons of Israel, shall he receive two he-goats, for bearing sin,—and one ram, as an ascending-sacrifice.", "darby": "And of the assembly of the children of Israel shall he take two bucks of the goats for a sin-offering, and one ram for a burnt-offering.", "twenty": "", "jps": "And he shall take of the congregation of the children of Israel two he-goats for a sin-offering, and one ram for a burnt-offering.", "acv": "And he shall take from the congregation of the sons of Israel two he-goats for a sin offering, and one ram for a burnt offering.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall take of the congregation of the children of Israel two kids of the goats for a sin-offering, and one ram for a burnt-offering.", "vulgate": "suscipietque ab universa multitudine filiorum Israhel duos hircos pro peccato et unum arietem in holocaustum;", "brenton": "And he shall take of the congregation of the children of Israel two kids of the goats for a sin-offering, and one lamb for a whole-burnt-offering."}}, {"v": 6, "ref": "16:6", "o": "וְ/הִקְרִ֧יב אַהֲרֹ֛ן אֶת פַּ֥ר הַ/חַטָּ֖את אֲשֶׁר ל֑/וֹ וְ/כִפֶּ֥ר בַּעֲד֖/וֹ וּ/בְעַ֥ד בֵּיתֽ/וֹ", "en": {"kjv": "And Aaron shall offer his bullock of the sin offering, which is for himself, and make an atonement for himself, and for his house.", "web": "“Aaron shall offer the bull of the sin offering, which is for himself, and make atonement for himself and for his house.", "bsb": "Aaron is to present the bull for his sin offering and make atonement for himself and his household.", "asv": "And Aaron shall present the bullock of the sin-offering, which is for himself, and make atonement for himself, and for his house.", "ylt": "and Aaron hath brought near the bullock of the sin-offering which is his own, and hath made atonement for himself, and for his house;", "tyndale": "And Aaron shall offer the oxe for his synneoffrynge and make an attonement for him ad for his housse.", "dra": "And when he hath offered the cattle and prayed for himself and for his own house:", "bbe": "And Aaron is to give the ox of the sin-offering for himself, to make himself and his house free from sin.", "geneva": "Then Aaron shall offer the bullocke for his sinne offring, and make an atonement for himselfe, and for his house.", "wycliffe": "and whanne he offrith a calf, and preieth for hym,", "rotherham": "Then shall Aaron bring near the sin-bearing bullock which is for himself,—and put a propitiatory-covering about himself, and about his household.", "darby": "And Aaron shall present the bullock of the sin-offering, which is for himself, and make atonement for himself, and for his house.", "twenty": "", "jps": "And Aaron shall present the bullock of the sin-offering, which is for himself, and make atonement for himself, and for his house.", "acv": "And Aaron shall present the bullock of the sin offering, which is for himself, and make atonement for himself, and for his house.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Aaron shall offer his bullock of the sin-offering, which [is] for himself, and make an atonement for himself, and for his house.", "vulgate": "cumque obtulerit vitulum et oraverit pro se et pro domo sua;", "brenton": "And Aaron shall bring the calf for his own sin-offering, and shall make atonement for himself and for his house."}}, {"v": 7, "ref": "16:7", "o": "וְ/לָקַ֖ח אֶת שְׁנֵ֣י הַ/שְּׂעִירִ֑ם וְ/הֶעֱמִ֤יד אֹתָ/ם֙ לִ/פְנֵ֣י יְהוָ֔ה פֶּ֖תַח אֹ֥הֶל מוֹעֵֽד", "en": {"kjv": "And he shall take the two goats, and present them before the Lord at the door of the tabernacle of the congregation.", "web": "He shall take the two goats, and set them before Yahweh at the door of the Tent of Meeting.", "bsb": "Then he shall take the two goats and present them before the LORD at the entrance to the Tent of Meeting.", "asv": "And he shall take the two goats, and set them before Jehovah at the door of the tent of meeting.", "ylt": "and he hath taken the two goats, and hath caused them to stand before Jehovah, at the opening of the tent of meeting.", "tyndale": "And he shall take the two gootes and present them before the Lorde in the dore of the tabernacle of witnesse.", "dra": "He shall make the two buck goats to stand before the Lord in the door of the tabernacle of the testimony.", "bbe": "And he is to take the two goats and put them before the Lord at the door of the Tent of meeting.", "geneva": "And he shall take the two hee goates, and present them before the Lord at the doore of the Tabernacle of the Congregation.", "wycliffe": "and for his hows, he schal make twei `buckis of geet to stonde bifor the Lord, in the dore of the tabernacle of witnessyng;", "rotherham": "Then shall he take the two goats,—and cause them to stand before Yahweh, at the entrance of the tent of meeting.", "darby": "And he shall take the two goats, and set them before Jehovah, before the entrance of the tent of meeting.", "twenty": "", "jps": "And he shall take the two goats, and set them before HaShem at the door of the tent of meeting.", "acv": "And he shall take the two goats, and set them before Jehovah at the door of the tent of meeting.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall take the two goats, and present them before the LORD [at] the door of the tabernacle of the congregation.", "vulgate": "duos hircos stare faciet coram Domino in ostio tabernaculi testimonii;", "brenton": "And he shall take the two goats, and place them before the Lord by the door of the tabernacle of witness."}}, {"v": 8, "ref": "16:8", "o": "וְ/נָתַ֧ן אַהֲרֹ֛ן עַל שְׁנֵ֥י הַ/שְּׂעִירִ֖ם גּוֹרָל֑וֹת גּוֹרָ֤ל אֶחָד֙ לַ/יהוָ֔ה וְ/גוֹרָ֥ל אֶחָ֖ד לַ/עֲזָאזֵֽל", "en": {"kjv": "And Aaron shall cast lots upon the two goats; one lot for the Lord, and the other lot for the scapegoat.", "web": "Aaron shall cast lots for the two goats; one lot for Yahweh, and the other lot for the scapegoat.", "bsb": "After Aaron casts lots for the two goats, one for the LORD and the other for the scapegoat,", "asv": "And Aaron shall cast lots upon the two goats; one lot for Jehovah, and the other lot for Azazel.", "ylt": "`And Aaron hath given lots over the two goats, one lot for Jehovah, and one lot for a goat of departure;", "tyndale": "And Aaro cast lottes ouer the .ij. gootes: one lotte for the Lorde, ad another for a scapegoote.", "dra": "And casting lots upon them both, one to be offered to the Lord, and the other to be the emissary goat:", "bbe": "And Aaron will make selection from the two goats by the decision of the Lord, one goat for the Lord and one for Azazel.", "geneva": "Then Aaron shall cast lots ouer the two hee goates: one lot for the Lord, and the other for the Scape goate.", "wycliffe": "and he schal sende `on euer eithir, o lot to the Lord, and another lot to the goot that schal be sent out.", "rotherham": "And Aaron shall cast lots over the two goats,—one lot for Yahweh, and one lot for Azazel.", "darby": "And Aaron shall cast lots upon the two goats: one lot for Jehovah, and the other lot for Azazel.", "twenty": "", "jps": "And Aaron shall cast lots upon the two goats: one lot for HaShem, and the other lot for Azazel.", "acv": "And Aaron shall cast lots upon the two goats, one lot for Jehovah, and the other lot for the scapegoat.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Aaron shall cast lots upon the two goats; one lot for the LORD, and the other lot for the scape-goat.", "vulgate": "mittens super utrumque sortem unam Domino et alteram capro emissario;", "brenton": "and Aaron shall cast lots upon the two goats, one lot for the Lord, and the other for the scape-goat."}}, {"v": 9, "ref": "16:9", "o": "וְ/הִקְרִ֤יב אַהֲרֹן֙ אֶת הַ/שָּׂעִ֔יר אֲשֶׁ֨ר עָלָ֥ה עָלָ֛י/ו הַ/גּוֹרָ֖ל לַ/יהוָ֑ה וְ/עָשָׂ֖/הוּ חַטָּֽאת", "en": {"kjv": "And Aaron shall bring the goat upon which the Lord’s lot fell, and offer him for a sin offering.", "web": "Aaron shall present the goat on which the lot fell for Yahweh, and offer him for a sin offering.", "bsb": "he shall present the goat chosen by lot for the LORD and sacrifice it as a sin offering.", "asv": "And Aaron shall present the goat upon which the lot fell for Jehovah, and offer him for a sin-offering.", "ylt": "and Aaron hath brought near the goat on which the lot for Jehovah hath gone up, and hath made it a sin-offering.", "tyndale": "And Aaron shall bringe the goote apo which the Lordes lotte fell, and offer him for a synneofferynge.", "dra": "That whose lot fell to be offered to the Lord, he shall offer for sin.", "bbe": "And the goat which is marked out for the Lord, let Aaron give for a sin-offering.", "geneva": "And Aaron shall offer the goat, vpon which the Lords lot shall fal, and make him a sinne offring.", "wycliffe": "Whos lot goith out to the Lord, he schal offre it for synne;", "rotherham": "Then shall Aaron bring near the goat over which came up the lot for Yahweh,—and shall make of him a sin-bearer;", "darby": "And Aaron shall present the goat upon which the lot fell for Jehovah, and offer it [as] a sin-offering.", "twenty": "", "jps": "And Aaron shall present the goat upon which the lot fell for HaShem, and offer him for a sin-offering.", "acv": "And Aaron shall present the goat upon which the lot fell for Jehovah, and offer him for a sin offering.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Aaron shall bring the goat upon which the LORD'S lot fell, and offer him [for] a sin-offering.", "vulgate": "cuius sors exierit Domino offeret illum pro peccato;", "brenton": "And Aaron shall bring forward the goat on which the lot for the Lord fell, and shall offer him for a sin-offering."}}, {"v": 10, "ref": "16:10", "o": "וְ/הַ/שָּׂעִ֗יר אֲשֶׁר֩ עָלָ֨ה עָלָ֤י/ו הַ/גּוֹרָל֙ לַ/עֲזָאזֵ֔ל יָֽעֳמַד חַ֛י לִ/פְנֵ֥י יְהוָ֖ה לְ/כַפֵּ֣ר עָלָ֑י/ו לְ/שַׁלַּ֥ח אֹת֛/וֹ לַ/עֲזָאזֵ֖ל הַ/מִּדְבָּֽרָ/ה", "en": {"kjv": "But the goat, on which the lot fell to be the scapegoat, shall be presented alive before the Lord, to make an atonement with him, and to let him go for a scapegoat into the wilderness.", "web": "But the goat, on which the lot fell for the scapegoat, shall be presented alive before Yahweh, to make atonement for him, to send him away for the scapegoat into the wilderness.", "bsb": "But the goat chosen by lot as the scapegoat shall be presented alive before the LORD to make atonement by sending it into the wilderness as the scapegoat.", "asv": "But the goat, on which the lot fell for Azazel, shall be set alive before Jehovah, to make atonement for him, to send him away for Azazel into the wilderness.", "ylt": "`And the goat on which the lot for a goat of departure hath gone up is caused to stand living before Jehovah to make atonement by it, to send it away for a goat of departure into the wilderness.", "tyndale": "But the goote on which the lotte fell to scape, he shall sett alyue before the Lorde to recocyle with ad to let him goo fre in to the wildernesse.", "dra": "But that whose lot was to be the emissary goat, he shall present before the Lord, that he may pour prayers upon him, and let him go into the wilderness.", "bbe": "But the goat for Azazel is to be placed living before the Lord, for the taking away of sin, that it may be sent away for Azazel into the waste land.", "geneva": "But the goate, on which the lot shall fall to be the Scape goate, shalbe presented aliue before the Lord, to make reconciliation by him, and to let him go (as a Scape goate) into the wildernes.", "wycliffe": "sotheli whos lot goith out in to goot that schal be sent out, he schal sette hym quyk bifor the Lord, that he sende preyers `on hym, and sende hym out in to wildirnesse.", "rotherham": "but, the goat over which came up the lot for Azazel, shall he cause to stand alive—before Yahweh to put a propitiatory-covering over him,—to send him away unto Azazel, towards the desert.", "darby": "And the goat upon which the lot fell for Azazel shall be set alive before Jehovah, to make atonement with it, to send it away as Azazel into the wilderness.", "twenty": "", "jps": "But the goat, on which the lot fell for Azazel, shall be set alive before HaShem, to make atonement over him, to send him away for Azazel into the wilderness.", "acv": "But the goat, on which the lot fell for the scapegoat, shall be set alive before Jehovah, to make atonement for him, to send him away for the scapegoat into the wilderness.", "anderson": "", "haweis": "", "noyes": "", "webster": "But the goat on which the lot fell to be the scape-goat, shall be presented alive before the LORD, to make an atonement with him, [and] to let him go for a scape-goat into the wilderness.", "vulgate": "cuius autem in caprum emissarium statuet eum vivum coram Domino ut fundat preces super eo et emittat illum in solitudinem;", "brenton": "and the goat upon which the lot of the scape-goat came, he shall present alive before the Lord, to make atonement upon him, so as to send him away as a scape-goat, and he shall send him into the wilderness."}}, {"v": 11, "ref": "16:11", "o": "וְ/הִקְרִ֨יב אַהֲרֹ֜ן אֶת פַּ֤ר הַֽ/חַטָּאת֙ אֲשֶׁר ל֔/וֹ וְ/כִפֶּ֥ר בַּֽעֲד֖/וֹ וּ/בְעַ֣ד בֵּית֑/וֹ וְ/שָׁחַ֛ט אֶת פַּ֥ר הַֽ/חַטָּ֖את אֲשֶׁר לֽ/וֹ", "en": {"kjv": "And Aaron shall bring the bullock of the sin offering, which is for himself, and shall make an atonement for himself, and for his house, and shall kill the bullock of the sin offering which is for himself:", "web": "“Aaron shall present the bull of the sin offering, which is for himself, and shall make atonement for himself and for his house, and shall kill the bull of the sin offering which is for himself.", "bsb": "When Aaron presents the bull for his sin offering and makes atonement for himself and his household, he is to slaughter the bull for his own sin offering.", "asv": "And Aaron shall present the bullock of the sin-offering, which is for himself, and shall make atonement for himself, and for his house, and shall kill the bullock of the sin-offering which is for himself.", "ylt": "`And Aaron hath brought near the bullock of the sin-offering which is his own, and hath made atonement for himself, and for his house, and hath slaughtered the bullock of the sin-offering which is his own,", "tyndale": "And Aaron shall bringe the oxe of his synoffrynge, ad reconcyle for him selfe ad for his housholde, and kyll him.", "dra": "After these things are duly celebrated, he shall offer the calf: and praying for himself and for his own house, he shall immolate it.", "bbe": "And Aaron is to give the ox of the sin-offering for himself and take away sin from himself and his house, and put to death the ox of the sin-offering which is for himself.", "geneva": "Thus Aaron shall offer the bullocke for his sinne offring, and make a reconciliation for himselfe, and for his house, and shall kill the bullocke for his sinne offring.", "wycliffe": "Whanne these thingis ben doon riytfuli, he schal offre the calf, and `he schal preye for hym silf, and for his hows, and schal offre the calf.", "rotherham": "So Aaron shall bring near the sin-bearing bullock which is for himself, and shall put a propitiatory-covering about himself, and about his household,—and shall slay the sin-bearing bullock which is for himself;", "darby": "And Aaron shall present the bullock of the sin-offering, which is for himself, and shall make atonement for himself and for his house, and shall slaughter the bullock of the sin-offering which is for himself.", "twenty": "", "jps": "And Aaron shall present the bullock of the sin-offering, which is for himself, and shall make atonement for himself, and for his house, and shall kill the bullock of the sin-offering which is for himself.", "acv": "And Aaron shall present the bullock of the sin offering, which is for himself, and shall make atonement for himself, and for his house, and shall kill the bullock of the sin offering which is for himself.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Aaron shall bring the bullock of the sin-offering, which [is] for himself, and shall make an atonement for himself, and for his house, and shall kill the bullock of the sin-offering which [is] for himself:", "vulgate": "his rite celebratis offeret vitulum et rogans pro se et pro domo sua immolabit eum;", "brenton": "And Aaron shall bring the calf for his sin, and he shall make atonement for himself and for his house, and he shall kill the calf for his sin-offering."}}, {"v": 12, "ref": "16:12", "o": "וְ/לָקַ֣ח מְלֹֽא הַ֠/מַּחְתָּה גַּֽחֲלֵי אֵ֞שׁ מֵ/עַ֤ל הַ/מִּזְבֵּ֨חַ֙ מִ/לִּ/פְנֵ֣י יְהוָ֔ה וּ/מְלֹ֣א חָפְנָ֔י/ו קְטֹ֥רֶת סַמִּ֖ים דַּקָּ֑ה וְ/הֵבִ֖יא מִ/בֵּ֥ית לַ/פָּרֹֽכֶת", "en": {"kjv": "And he shall take a censer full of burning coals of fire from off the altar before the Lord, and his hands full of sweet incense beaten small, and bring it within the vail:", "web": "He shall take a censer full of coals of fire from off the altar before Yahweh, and two handfuls of sweet incense beaten small, and bring it within the veil:", "bsb": "Then he must take a censer full of burning coals from the altar before the LORD, and two handfuls of finely ground fragrant incense, and take them inside the veil.", "asv": "And he shall take a censer full of coals of fire from off the altar before Jehovah, and his hands full of sweet incense beaten small, and bring it within the veil:", "ylt": "and hath taken the fulness of the censer of burning coals of fire from off the altar, from before Jehovah, and the fulness of his hands of thin spice-perfume, and hath brought it within the vail;", "tyndale": "And tha he shall take a censer full of burninge coles out of the alter that is before the Lorde, and his handfull of swete cens beten small and bringe them within the vayle", "dra": "And taking the censer, which he hath filled with the burning coals of the altar, and taking up with his hands the compounded perfume for incense, he shall go in within the veil into the holy place:", "bbe": "And he is to take a vessel full of burning coal from the altar before the Lord and in his hand some sweet perfume crushed small, and take it inside the veil;", "geneva": "And he shall take a censer full of burning coles from off the altar before the Lord, and his handfull of sweete incense beaten small, and bring it within the vayle,", "wycliffe": "And whanne he hath take the censeer, which he hath fillid of the coolis of the auter, and `he hath take in hond the `swete smellynge spicery maad into encense, he schal entre ouer the veil in to the hooli thingis;", "rotherham": "and shall take the censer-full of burning coals of fire from off the altar from before Yahweh, and his hands full of fragrant incense, beaten small,—and bring within the veil;", "darby": "And he shall take the censer full of burning coals of fire from off the altar before Jehovah, and both his hands full of fragrant incense beaten small, and bring it inside the veil.", "twenty": "", "jps": "And he shall take a censer full of coals of fire from off the altar before HaShem, and his hands full of sweet incense beaten small, and bring it within the veil.", "acv": "And he shall take a censer full of coals of fire from off the altar before Jehovah, and his hands full of sweet incense beaten small, and bring it within the veil.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall take a censer full of burning coals of fire from off the altar before the LORD, and his hands full of sweet incense beaten small, and bring [it] within the vail:", "vulgate": "adsumptoque turibulo quod de prunis altaris impleverit et hauriens manu conpositum thymiama in incensum ultra velum intrabit in sancta;", "brenton": "And he shall take his censer full of coals of fire off the altar, which is before the Lord; and he shall fill his hands with fine compound incense, and shall bring it within the veil."}}, {"v": 13, "ref": "16:13", "o": "וְ/נָתַ֧ן אֶֽת הַ/קְּטֹ֛רֶת עַל הָ/אֵ֖שׁ לִ/פְנֵ֣י יְהוָ֑ה וְ/כִסָּ֣ה עֲנַ֣ן הַ/קְּטֹ֗רֶת אֶת הַ/כַּפֹּ֛רֶת אֲשֶׁ֥ר עַל הָ/עֵד֖וּת וְ/לֹ֥א יָמֽוּת", "en": {"kjv": "And he shall put the incense upon the fire before the Lord, that the cloud of the incense may cover the mercy seat that is upon the testimony, that he die not:", "web": "and he shall put the incense on the fire before Yahweh, that the cloud of the incense may cover the mercy seat that is on the testimony, so that he will not die.", "bsb": "He is to put the incense on the fire before the LORD, and the cloud of incense will cover the mercy seat above the Testimony, so that he will not die.", "asv": "and he shall put the incense upon the fire before Jehovah, that the cloud of the incense may cover the mercy-seat that is upon the testimony, that he die not:", "ylt": "and he hath put the perfume on the fire before Jehovah, and the cloud of the perfume hath covered the mercy-seat which is on the testimony, and he dieth not.", "tyndale": "and put the cens apon the fire before the Lorde: that the cloude of the cens maye couer the mercyseate that is apon the witnesse, that he dye not.", "dra": "That when the perfumes are put upon the fire, the cloud and vapour thereof may cover the oracle, which is over the testimony, and he may not die.", "bbe": "And let him put the perfume on the fire before the Lord so that the ark may be covered with a cloud of the smoke of the perfume, in order that death may not overtake him.", "geneva": "And shall put the incense vpon the fire before the Lord, that the cloude of the incense may couer the Merciseat that is vpon the Testimonie: so he shall not dye.", "wycliffe": "that whanne swete smellynge spiceries ben put on the fier, the cloude and `vapour of tho hile Goddis answeryng place, which is on the witnessyng , and he die not.", "rotherham": "and shall put the incense upon the fire before Yahweh,—and the cloud of incense shall cover the propitiatory which is over the testimony, and he shall not die.", "darby": "And he shall put the incense upon the fire before Jehovah, that the cloud of the incense may cover the mercy-seat which is upon the testimony, that he die not.", "twenty": "", "jps": "And he shall put the incense upon the fire before HaShem, that the cloud of the incense may cover the ark-cover that is upon the testimony, that he die not.", "acv": "And he shall put the incense upon the fire before Jehovah, that the cloud of the incense may cover the mercy-seat that is upon the testimony, that he not die.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall put the incense upon the fire before the LORD, that the cloud of the incense may cover the mercy-seat that [is] upon the testimony, that he may not die.", "vulgate": "ut positis super ignem aromatibus nebula eorum et vapor operiat oraculum quod est super testimonium et non moriatur;", "brenton": "And he shall put the incense on the fire before the Lord, and the smoke of the incense shall cover the mercy-seat over the tables of testimony, and he shall not die."}}, {"v": 14, "ref": "16:14", "o": "וְ/לָקַח֙ מִ/דַּ֣ם הַ/פָּ֔ר וְ/הִזָּ֧ה בְ/אֶצְבָּע֛/וֹ עַל פְּנֵ֥י הַ/כַּפֹּ֖רֶת קֵ֑דְמָ/ה וְ/לִ/פְנֵ֣י הַ/כַּפֹּ֗רֶת יַזֶּ֧ה שֶֽׁבַע פְּעָמִ֛ים מִן הַ/דָּ֖ם בְּ/אֶצְבָּעֽ/וֹ", "en": {"kjv": "And he shall take of the blood of the bullock, and sprinkle it with his finger upon the mercy seat eastward; and before the mercy seat shall he sprinkle of the blood with his finger seven times.", "web": "He shall take some of the blood of the bull, and sprinkle it with his finger on the mercy seat on the east; and before the mercy seat he shall sprinkle some of the blood with his finger seven times.", "bsb": "And he is to take some of the bull’s blood and sprinkle it with his finger on the east side of the mercy seat; then he shall sprinkle some of it with his finger seven times before the mercy seat.", "asv": "and he shall take of the blood of the bullock, and sprinkle it with his finger upon the mercy-seat on the east; and before the mercy-seat shall he sprinkle of the blood with his finger seven times.", "ylt": "`And he hath taken of the blood of the bullock, and hath sprinkled with his finger on the front of the mercy-seat eastward; even at the front of the mercy-seat he doth sprinkle seven times of the blood with his finger.", "tyndale": "And he shall take of the bloude of the oxe ad sprinkle it with his finger before the mercyseate eastwarde: euen .vij. tymes.", "dra": "He shall take also of the blood of the calf, and sprinkle with his finger seven times towards the propitiatory to the east.", "bbe": "And let him take some of the blood of the ox, shaking drops of it from his finger on the cover of the ark on the east side, and before it, seven times.", "geneva": "And hee shall take of the blood of the bullocke, and sprinkle it with his finger vpon the Merciseat Eastward: and before the Merciseate shall he sprinkle of the blood with his finger seuen times.", "wycliffe": "Also he schal take of the `blood of the calf, and he schal sprenge seuensithis with the fyngur ayens `the propiciatorie, `to the eest.", "rotherham": "Then shall he take of the blood of the bullock, and shall sprinkle with his finger upon the face of the propitiatory, eastwards,—and before the propitiatory, shall he sprinkle seven times, of the blood, with his finger.", "darby": "And he shall take of the blood of the bullock, and sprinkle with his finger upon the front of the mercy-seat eastward; and before the mercy-seat shall he sprinkle of the blood seven times with his finger.", "twenty": "", "jps": "And he shall take of the blood of the bullock, and sprinkle it with his finger upon the ark-cover on the east; and before the ark-cover shall he sprinkle of the blood with his finger seven times.", "acv": "And he shall take of the blood of the bullock, and sprinkle it with his finger upon the mercy-seat on the east. And he shall sprinkle of the blood with his finger seven times before the mercy-seat.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall take of the blood of the bullock, and sprinkle [it] with his finger upon the mercy-seat eastward: and before the mercy-seat shall he sprinkle of the blood with his finger seven times.", "vulgate": "tollet quoque de sanguine vituli et asperget digito septies contra propitiatorium ad orientem;", "brenton": "And he shall take of the blood of the calf, and sprinkle with his finger on the mercy-seat eastward: before the mercy-seat shall he sprinkle seven times of the blood with his finger."}}, {"v": 15, "ref": "16:15", "o": "וְ/שָׁחַ֞ט אֶת שְׂעִ֤יר הַֽ/חַטָּאת֙ אֲשֶׁ֣ר לָ/עָ֔ם וְ/הֵבִיא֙ אֶת דָּמ֔/וֹ אֶל מִ/בֵּ֖ית לַ/פָּרֹ֑כֶת וְ/עָשָׂ֣ה אֶת דָּמ֗/וֹ כַּ/אֲשֶׁ֤ר עָשָׂה֙ לְ/דַ֣ם הַ/פָּ֔ר וְ/הִזָּ֥ה אֹת֛/וֹ עַל הַ/כַּפֹּ֖רֶת וְ/לִ/פְנֵ֥י הַ/כַּפֹּֽרֶת", "en": {"kjv": "Then shall he kill the goat of the sin offering, that is for the people, and bring his blood within the vail, and do with that blood as he did with the blood of the bullock, and sprinkle it upon the mercy seat, and before the mercy seat:", "web": "“Then he shall kill the goat of the sin offering, that is for the people, and bring his blood within the veil, and do with his blood as he did with the blood of the bull, and sprinkle it on the mercy seat, and before the mercy seat.", "bsb": "Aaron shall then slaughter the goat for the sin offering for the people and bring its blood behind the veil, and with its blood he must do as he did with the bull’s blood: He is to sprinkle it against the mercy seat and in front of it.", "asv": "Then shall he kill the goat of the sin-offering, that is for the people, and bring his blood within the veil, and do with his blood as he did with the blood of the bullock, and sprinkle it upon the mercy-seat, and before the mercy-seat:", "ylt": "`And he hath slaughtered the goat of the sin-offering which is the people's, and hath brought in its blood unto the inside of the vail, and hath done with its blood as he hath done with the blood of the bullock, and hath sprinkled it on the mercy-seat, and at the front of the mercy-seat,", "tyndale": "Then shall he kyll the goote that is the peoples synneofferynge, and brynge hys bloude within the vayle, and doo with his bloude as he dyd with the bloude of the oxe, and let him sprinkle it toward the mercyseate and before the mercyseate:", "dra": "And when he hath killed the buck goat for the sin of the people, he shall carry in the blood thereof within the veil, as he was commanded to do with the blood of the calf, that he may sprinkle it over against the oracle:", "bbe": "Then let him put to death the goat of the sin-offering for the people, and take its blood inside the veil and do with it as he did with the blood of the ox, shaking drops of it on and before the cover of the ark.", "geneva": "Then shall he kill the goate that is the peoples sinne offring, and bring his blood within the vaile, and doe with that blood, as he did with the blood of the bullocke, and sprinckle it vpon the Merciseate, and before the Merciseate.", "wycliffe": "And whanne he hath slayn the `buk of geet, for synne of the puple, he schal brynge in the blood therof with ynne the veil, as it is comaundid of the `blood of the calf, that he sprynge euene ayens Goddis answeryng place,", "rotherham": "Then shall he slay the sin-bearing goat which is for the people, and bring in its blood, within the veil,—and do with its blood, as he did to the blood of the bullock, and shall sprinkle it, upon the propitiatory and before the propitiatory:", "darby": "And he shall slaughter the goat of the sin-offering, which is for the people, and bring its blood inside the veil, and do with its blood as he did with the blood of the bullock, and sprinkle it upon the mercy-seat, and before the mercy-seat;", "twenty": "", "jps": "Then shall he kill the goat of the sin-offering, that is for the people, and bring his blood within the veil, and do with his blood as he did with the blood of the bullock, and sprinkle it upon the ark-cover, and before the ark-cover.", "acv": "Then he shall kill the goat of the sin offering, that is for the people, and bring his blood within the veil, and do with his blood as he did with the blood of the bullock, and sprinkle it upon the mercy-seat, and before the mercy-seat.", "anderson": "", "haweis": "", "noyes": "", "webster": "Then shall he kill the goat of the sin-offering that [is] for the people, and bring his blood within the vail, and do with that blood as he did with the blood of the bullock, and sprinkle it upon the mercy-seat, and before the mercy-seat:", "vulgate": "cumque mactaverit hircum pro peccato populi inferet sanguinem eius intra velum sicut praeceptum est de sanguine vituli ut aspergat e regione oraculi;", "brenton": "And he shall kill the goat for the sin-offering that is for the people, before the Lord; and he shall bring in of its blood within the veil, and shall do with its blood as he did with the blood of the calf, and shall sprinkle its blood on the mercy-seat, in front of the mercy-seat."}}, {"v": 16, "ref": "16:16", "o": "וְ/כִפֶּ֣ר עַל הַ/קֹּ֗דֶשׁ מִ/טֻּמְאֹת֙ בְּנֵ֣י יִשְׂרָאֵ֔ל וּ/מִ/פִּשְׁעֵי/הֶ֖ם לְ/כָל חַטֹּאתָ֑/ם וְ/כֵ֤ן יַעֲשֶׂה֙ לְ/אֹ֣הֶל מוֹעֵ֔ד הַ/שֹּׁכֵ֣ן אִתָּ֔/ם בְּ/ת֖וֹךְ טֻמְאֹתָֽ/ם", "en": {"kjv": "And he shall make an atonement for the holy place, because of the uncleanness of the children of Israel, and because of their transgressions in all their sins: and so shall he do for the tabernacle of the congregation, that remaineth among them in the midst of their uncleanness.", "web": "He shall make atonement for the Holy Place, because of the uncleanness of the children of Israel, and because of their transgressions, even all their sins; and so he shall do for the Tent of Meeting, that dwells with them in the midst of their uncleanness.", "bsb": "So he shall make atonement for the Most Holy Place because of the impurities and rebellious acts of the Israelites in regard to all their sins. He is to do the same for the Tent of Meeting which abides among them, because it is surrounded by their impurities.", "asv": "and he shall make atonement for the holy place, because of the uncleannesses of the children of Israel, and because of their transgressions, even all their sins: and so shall he do for the tent of meeting, that dwelleth with them in the midst of their uncleannesses.", "ylt": "and he hath made atonement for the sanctuary because of the uncleanness of the sons of Israel, and because of their transgressions in all their sins; and so he doth for the tent of meeting which is tabernacling with them in the midst of their uncleannesses.", "tyndale": "ad reconcyle the holy place fro the vnclennesse of the childern of Israel, and from their trespaces ad all there synnes. And so let him doo also vnto the tabernacle of witnesse that dwelleth with them, eue among their vnclennesses.", "dra": "And may expiate the sanctuary from the uncleanness of the children of Israel, and from their transgressions, and all their sins. According to this rite shall he do to the tabernacle of the testimony, which is fixed among them in the midst of the filth of their habitation.", "bbe": "And let him make the holy place free from whatever is unclean among the children of Israel and from their wrongdoing in all their sins; and let him do the same for the Tent of meeting, which has its place among an unclean people.", "geneva": "So he shall purge the Holy place from the vncleannes of the children of Israel, and from their trespasses of all their sinnes: so shall he do also for the Tabernacle of the Cogregation placed with them, in the middes of their vncleannesse.", "wycliffe": "and he schal clense the seyntuarie fro vnclennessis of the sones of Israel, and fro her trespassyngis, and alle synnes. Bi this custom he schal do in the tabernacle of witnessyng, which is set among hem, in the myddis of partis of the abitacioun `of hem.", "rotherham": "so shall he put a propitiatory-covering, over the holy place because of the uncleanness of the sons of Israel, and because of their transgressions to the extent of all their sins,—and, so, shall he do for the tent of meeting which abideth with them, in the midst of their uncleanness.", "darby": "and he shall make atonement for the sanctuary, [to cleanse it] from the uncleanness of the children of Israel, and from their transgressions in all their sins; and so shall he do for the tent of meeting which dwelleth among them in the midst of their uncleanness.", "twenty": "", "jps": "And he shall make atonement for the holy place, because of the uncleannesses of the children of Israel, and because of their transgressions, even all their sins; and so shall he do for the tent of meeting, that dwelleth with them in the midst of their uncleannesses.", "acv": "And he shall make atonement for the holy place, because of the uncleannesses of the sons of Israel, and because of their transgressions, even all their sins. And so he shall do for the tent of meeting that dwells with them in the midst of their uncleannesses.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall make an atonement for the holy [place], because of the uncleanness of the children of Israel, and because of their transgressions in all their sins: and so shall he do for the tabernacle of the congregation that remaineth among them in the midst of their uncleanness.", "vulgate": "et expiet sanctuarium ab inmunditiis filiorum Israhel et a praevaricationibus eorum cunctisque peccatis iuxta hunc ritum faciet tabernaculo testimonii quod fixum est inter eos in medio sordium habitationis eorum;", "brenton": "and he shall make atonement for the sanctuary on account of the uncleanness of the children of Israel, and for their trespasses in the matter of all their sins; and thus shall he do to the tabernacle of witness established among them in the midst of their uncleanness."}}, {"v": 17, "ref": "16:17", "o": "וְ/כָל אָדָ֞ם לֹא יִהְיֶ֣ה בְּ/אֹ֣הֶל מוֹעֵ֗ד בְּ/בֹא֛/וֹ לְ/כַפֵּ֥ר בַּ/קֹּ֖דֶשׁ עַד צֵאת֑/וֹ וְ/כִפֶּ֤ר בַּעֲד/וֹ֙ וּ/בְעַ֣ד בֵּית֔/וֹ וּ/בְעַ֖ד כָּל קְהַ֥ל יִשְׂרָאֵֽל", "en": {"kjv": "And there shall be no man in the tabernacle of the congregation when he goeth in to make an atonement in the holy place, until he come out, and have made an atonement for himself, and for his household, and for all the congregation of Israel.", "web": "No one shall be in the Tent of Meeting when he enters to make atonement in the Holy Place, until he comes out, and has made atonement for himself and for his household, and for all the assembly of Israel.", "bsb": "No one may be in the Tent of Meeting from the time Aaron goes in to make atonement in the Most Holy Place until he leaves, after he has made atonement for himself, his household, and the whole assembly of Israel.", "asv": "And there shall be no man in the tent of meeting when he goeth in to make atonement in the holy place, until he come out, and have made atonement for himself, and for his household, and for all the assembly of Israel.", "ylt": "`And no man is in the tent of meeting in his going in to make atonement in the sanctuary, till his coming out; and he hath made atonement for himself, and for his house, and for all the assembly of Israel.", "tyndale": "And there shalbe no bodye in the tabernacle of witnesse, when he goeth in to make an attonement in the holy place, vntyll he come out agayne. And he shall make an attonement for him selfe and for his housholde, ad for all the multitude of Israel.", "dra": "Let no man be in the tabernacle when the high priest goeth into the sanctuary, to pray for himself and his house, and for the whole congregation of Israel, until he come out.", "bbe": "And no man may be in the Tent of meeting from the time when Aaron goes in to take away sin in the holy place till he comes out, having made himself and his house and all the people of Israel free from sin.", "geneva": "And there shalbe no man in the Tabernacle of the Congregation, when he goeth in to make an atonement in the Holy place, vntill hee come out, and haue made an atonement for himselfe, and for his housholde, and for all the Congregation of Israel.", "wycliffe": "No man be in the tabernacle, whanne the bischop schal entre in to the seyntuarie, that he preye for hym silf, and for his hows, and for al the cumpeny of Israel, til he go out of the tabernacle.", "rotherham": "And no human being, shall be in the tent of meeting, when he cometh in to make a covering by propitiation in the holy place, until he goeth out,—so shall he put a propitiatory-covering about himself and about his household and about all the convocation of Israel.", "darby": "And there shall be no man in the tent of meeting when he goeth in to make atonement in the sanctuary until he come out; and he shall make atonement for himself, and for his house, and for the whole congregation of Israel.", "twenty": "", "jps": "And there shall be no man in the tent of meeting when he goeth in to make atonement in the holy place, until he come out, and have made atonement for himself, and for his household, and for all the assembly of Israel.", "acv": "And there shall be no man in the tent of meeting when he goes in to make atonement in the holy place until he comes out, and has made atonement for himself, and for his household, and for all the assembly of Israel.", "anderson": "", "haweis": "", "noyes": "", "webster": "And there shall be no man in the tabernacle of the congregation when he goeth in to make an atonement in the holy [place], until he shall come out, and shall have made an atonement for himself, and for his household, and for all the congregation of Israel.", "vulgate": "nullus hominum sit in tabernaculo quando pontifex ingreditur sanctuarium ut roget pro se et pro domo sua et pro universo coetu Israhel donec egrediatur;", "brenton": "and there shall be no man in the tabernacle of witness, when he goes in to make atonement in the holy place, until he shall have come out; and he shall make atonement for himself, and for his house, and for all the congregation of the children of Israel."}}, {"v": 18, "ref": "16:18", "o": "וְ/יָצָ֗א אֶל הַ/מִּזְבֵּ֛חַ אֲשֶׁ֥ר לִ/פְנֵֽי יְהוָ֖ה וְ/כִפֶּ֣ר עָלָ֑י/ו וְ/לָקַ֞ח מִ/דַּ֤ם הַ/פָּר֙ וּ/מִ/דַּ֣ם הַ/שָּׂעִ֔יר וְ/נָתַ֛ן עַל קַרְנ֥וֹת הַ/מִּזְבֵּ֖חַ סָבִֽיב", "en": {"kjv": "And he shall go out unto the altar that is before the Lord, and make an atonement for it; and shall take of the blood of the bullock, and of the blood of the goat, and put it upon the horns of the altar round about.", "web": "“He shall go out to the altar that is before Yahweh and make atonement for it, and shall take some of the bull’s blood, and some of the goat’s blood, and put it around on the horns of the altar.", "bsb": "Then he shall go out to the altar that is before the LORD and make atonement for it. He is to take some of the bull’s blood and some of the goat’s blood and put it on all the horns of the altar.", "asv": "And he shall go out unto the altar that is before Jehovah, and make atonement for it, and shall take of the blood of the bullock, and of the blood of the goat, and put it upon the horns of the altar round about.", "ylt": "`And he hath gone out unto the altar which is before Jehovah, and hath made atonement for it; and he hath taken of the blood of the bullock, and of the blood of the goat, and hath put on the horns of the altar round about;", "tyndale": "Then he shall goo out vnto the alter that stondeth before the Lorde, and reconcyle it, and shall take of the bloude of the oxe and of the bloude of the goote, and put it apon the hornes of the altare rounde aboute,", "dra": "And when he is come out to the altar that is before the Lord, let him pray for himself: and taking the blood of the calf, and of the buck goat, let him pour it upon the horns thereof round about.", "bbe": "And he is to go out to the altar which is before the Lord and make it free from sin; and he is to take some of the blood of the ox and the blood of the goat and put it on the horns of the altar and round it;", "geneva": "After, he shall goe out vnto the altar that is before the Lord and make a reconciliation vpon it, and shall take of the blood of the bullocke, and of the blood of the goate, and put it vpon the hornes of the Altar round about:", "wycliffe": "Sotheli whanne he hath go out to the auter which is bifor the Lord, preye he for hym silf, and schede he on the hornes therof, bi cumpas, the blood `that is takun of the calf, and of the `buk of geet;", "rotherham": "Then shall he go out unto the altar which is before Yahweh and shall put a propitiatory-covering thereupon,—and shall take of the blood of the bullock, and of the blood of the goat, and put upon the horns of the altar, round about;", "darby": "And he shall go out unto the altar which is before Jehovah, and make atonement for it; and shall take of the blood of the bullock, and of the goat, and put it upon the horns of the altar round about;", "twenty": "", "jps": "And he shall go out unto the altar that is before HaShem, and make atonement for it; and shall take of the blood of the bullock, and of the blood of the goat, and put it upon the horns of the altar round about.", "acv": "And he shall go out to the altar that is before Jehovah, and make atonement for it. And shall take of the blood of the bullock, and of the blood of the goat, and put it upon the horns of the altar round about.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall go out to the altar that [is] before the LORD, and make an atonement for it; and shall take of the blood of the bullock, and of the blood of the goat, and put [it] upon the horns of the altar round about.", "vulgate": "cum autem exierit ad altare quod coram Domino est oret pro se et sumptum sanguinem vituli atque hirci fundat super cornua eius per gyrum;", "brenton": "And he shall come forth to the altar that is before the Lord, and he shall make atonement upon it; and he shall take of the blood of the calf, and of the blood of the goat, and shall put it on the horns of the altar round about."}}, {"v": 19, "ref": "16:19", "o": "וְ/הִזָּ֨ה עָלָ֧י/ו מִן הַ/דָּ֛ם בְּ/אֶצְבָּע֖/וֹ שֶׁ֣בַע פְּעָמִ֑ים וְ/טִהֲר֣/וֹ וְ/קִדְּשׁ֔/וֹ מִ/טֻּמְאֹ֖ת בְּנֵ֥י יִשְׂרָאֵֽל", "en": {"kjv": "And he shall sprinkle of the blood upon it with his finger seven times, and cleanse it, and hallow it from the uncleanness of the children of Israel.", "web": "He shall sprinkle some of the blood on it with his finger seven times, and cleanse it, and make it holy from the uncleanness of the children of Israel.", "bsb": "He is to sprinkle some of the blood on it with his finger seven times to cleanse it and consecrate it from the uncleanness of the Israelites.", "asv": "And he shall sprinkle of the blood upon it with his finger seven times, and cleanse it, and hallow it from the uncleannesses of the children of Israel.", "ylt": "and he hath sprinkled on it of the blood with his finger seven times, and hath cleansed it, and hath hallowed it from the uncleannesses of the sons of Israel.", "tyndale": "and sprynckle of the bloude apon it with his finger seuen tymes, and clense it, and halowe it fro the vnclennesses of the childern of Israel.", "dra": "And sprinkling with his finger seven times, let him expiate, and sanctify it from the uncleanness of the children of Israel.", "bbe": "Shaking drops of the blood from his finger on it seven times to make it holy and clean from whatever is unclean among the children of Israel.", "geneva": "So shall hee sprinkle of the blood vpon it with his finger seuen times, and clense it, and halowe it from the vncleannes of the children of Israel.", "wycliffe": "and sprynge he seuensithis with the fyngur, and clense he, and halewe the autir fro vnclennessis of the sones of Israel.", "rotherham": "and shall sprinkle upon it, of the blood with his finger seven times,—and shall cleanse it and hallow it, from the uncleannesses of the sons of Israel.", "darby": "and he shall sprinkle upon it of the blood with his finger seven times, and cleanse it, and hallow it from the uncleannesses of the children of Israel.", "twenty": "", "jps": "And he shall sprinkle of the blood upon it with his finger seven times, and cleanse it, and hallow it from the uncleannesses of the children of Israel.", "acv": "And he shall sprinkle of the blood upon it with his finger seven times, and cleanse it, and hallow it from the uncleannesses of the sons of Israel.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall sprinkle of the blood upon it with his finger seven times, and cleanse it, and hallow it from the uncleanness of the children of Israel.", "vulgate": "aspergensque digito septies expiet et sanctificet illud ab inmunditiis filiorum Israhel;", "brenton": "And he shall sprinkle some of the blood upon it seven times with his finger, and shall purge it, and hallow it from the uncleanness of the children of Israel."}}, {"v": 20, "ref": "16:20", "o": "וְ/כִלָּה֙ מִ/כַּפֵּ֣ר אֶת הַ/קֹּ֔דֶשׁ וְ/אֶת אֹ֥הֶל מוֹעֵ֖ד וְ/אֶת הַ/מִּזְבֵּ֑חַ וְ/הִקְרִ֖יב אֶת הַ/שָּׂעִ֥יר הֶ/חָֽי", "en": {"kjv": "And when he hath made an end of reconciling the holy place, and the tabernacle of the congregation, and the altar, he shall bring the live goat:", "web": "“When he has made an end of atoning for the Holy Place, the Tent of Meeting, and the altar, he shall present the live goat.", "bsb": "When Aaron has finished purifying the Most Holy Place, the Tent of Meeting, and the altar, he is to bring forward the live goat.", "asv": "And when he hath made an end of atoning for the holy place, and the tent of meeting, and the altar, he shall present the live goat:", "ylt": "`And he hath ceased from making atonement for the sanctuary, and the tent of meeting, and the altar, and hath brought near the living goat;", "tyndale": "And whe he hath made an ende of recocylinge the holy place and the tabernacle of witnesse ad the alter, let him bringe the lyue goote", "dra": "After he hath cleaned the sanctuary, and the tabernacle, and the altar, then let him offer the living goat.", "bbe": "And when he has done whatever is necessary to make the holy place and the Tent of meeting and the altar free from sin, let him put the living goat before the Lord;", "geneva": "When he hath made an ende of purging the Holy place, and the Tabernacle of the Congregation, and the altar, then he shall bring the liue goate:", "wycliffe": "Aftir that he hath clensid the seyntuarie, and tabernacle, and auter, thanne offre he the lyuynge `buc of geet;", "rotherham": "And, when he hath made an end of covering by propitiation the holy place, and the tent of meeting, and the altar, then shall he bring near the living goat.", "darby": "And when he hath ended making atonement for the sanctuary, and the tent of meeting, and the altar, he shall present the living goat;", "twenty": "", "jps": "And when he hath made an end of atoning for the holy place, and the tent of meeting, and the altar, he shall present the live goat.", "acv": "And when he has made an end of atoning for the holy place, and the tent of meeting, and the altar, he shall present the live goat.", "anderson": "", "haweis": "", "noyes": "", "webster": "And when he hath made an end of reconciling the holy [place], and the tabernacle of the congregation, and the altar, he shall bring the live goat:", "vulgate": "postquam emundarit sanctuarium et tabernaculum et altare tunc offerat hircum viventem;", "brenton": "And he shall finish making atonement for the sanctuary and for the tabernacle of witness, and for the altar; and he shall make a cleansing for the priests, and he shall bring the living goat;"}}, {"v": 21, "ref": "16:21", "o": "וְ/סָמַ֨ךְ אַהֲרֹ֜ן אֶת שְׁתֵּ֣י יד/ו יָדָ֗י/ו עַ֨ל רֹ֣אשׁ הַ/שָּׂעִיר֮ הַ/חַי֒ וְ/הִתְוַדָּ֣ה עָלָ֗י/ו אֶת כָּל עֲוֺנֹת֙ בְּנֵ֣י יִשְׂרָאֵ֔ל וְ/אֶת כָּל פִּשְׁעֵי/הֶ֖ם לְ/כָל חַטֹּאתָ֑/ם וְ/נָתַ֤ן אֹתָ/ם֙ עַל רֹ֣אשׁ הַ/שָּׂעִ֔יר וְ/שִׁלַּ֛ח בְּ/יַד אִ֥ישׁ עִתִּ֖י הַ/מִּדְבָּֽרָ/ה", "en": {"kjv": "And Aaron shall lay both his hands upon the head of the live goat, and confess over him all the iniquities of the children of Israel, and all their transgressions in all their sins, putting them upon the head of the goat, and shall send him away by the hand of a fit man into the wilderness:", "web": "Aaron shall lay both his hands on the head of the live goat, and confess over him all the iniquities of the children of Israel, and all their transgressions, even all their sins; and he shall put them on the head of the goat, and shall send him away into the wilderness by the hand of a man who is in readiness.", "bsb": "Then he is to lay both hands on the head of the live goat and confess over it all the iniquities and rebellious acts of the Israelites in regard to all their sins. He is to put them on the goat’s head and send it away into the wilderness by the hand of a man appointed for the task.", "asv": "and Aaron shall lay both his hands upon the head of the live goat, and confess over him all the iniquities of the children of Israel, and all their transgressions, even all their sins; and he shall put them upon the head of the goat, and shall send him away by the hand of a man that is in readiness into the wilderness:", "ylt": "and Aaron hath laid his two hands on the head of the living goat, and hath confessed over it all the iniquities of the sons of Israel, and all their transgressions in all their sins, and hath put them on the head of the goat, and hath sent it away by the hand of a fit man into the wilderness;", "tyndale": "ad let Aaro put both his handes apon the heede of the lyue goote, and confesse ouer him all the mysdeades of the childern of Israell, and all their trespaces, and all their synnes: and let him put them apo the heed of the goote ad sende him awaye by the handes of one that is acoynted in the wyldernesse.", "dra": "And putting both hands upon his head, let him confess all the iniquities of the children of Israel, and all their offences and sins. And praying that they may light on its head, he shall turn him out by a man ready for it, into the desert.", "bbe": "And Aaron, placing his two hands on the head of the living goat, will make a public statement over him of all the evil doings of the children of Israel and all their wrongdoing, in all their sins; and he will put them on the head of the goat and send him away, in the care of a man who will be waiting there, into the waste land.", "geneva": "And Aaron shall put both his handes vpon the head of the liue goate, and confesse ouer him al the iniquities of the children of Israel, and all their trespasses, in all their sinnes, putting them vpon the head of the goate, and shall sende him away (by the hand of a man appointed) into the wildernes.", "wycliffe": "and whanne euer eithir hond is set on the heed therof, knowleche the preest alle the wickidnessis of the sones of Israel, and alle the trespassis and synnes `of hem, whiche the preest schal wische to the heed therof, and schal sende hym out in to deseert bi a man maad redi.", "rotherham": "And Aaron shall lean his two hands upon the head of the living goat, and confess over him, all the iniquities of the sons of Israel, and all their transgressions, to the extent of all their sins,—and shall put them upon the head of the goat, and then send him away, by the hand of a man appointed towards the desert:", "darby": "and Aaron shall lay both his hands on the head of the living goat, and confess over it all the iniquities of the children of Israel, and all their transgressions in all their sins, and he shall put them on the head of the goat, and shall send him away to the wilderness by the hand of a man standing ready;", "twenty": "", "jps": "And Aaron shall lay both his hands upon the head of the live goat, and confess over him all the iniquities of the children of Israel, and all their transgressions, even all their sins; and he shall put them upon the head of the goat, and shall send him away by the hand of an appointed man into the wilderness.", "acv": "And Aaron shall lay both his hands upon the head of the live goat, and confess over him all the iniquities of the sons of Israel, and all their transgressions, even all their sins. And he shall put them upon the head of the goat, and shall send him away by the hand of a man who is in readiness into the wilderness.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Aaron shall lay both his hands upon the head of the live goat, and confess over him all the iniquities of the children of Israel, and all their transgressions in all their sins, putting them upon the head of the goat, and shall send [him] away by the hand of a fit man into the wilderness:", "vulgate": "et posita utraque manu super caput eius confiteatur omnes iniquitates filiorum Israhel et universa delicta atque peccata eorum quae inprecans capiti eius emittet illum per hominem paratum in desertum;", "brenton": "and Aaron shall lay his hands on the head of the live goat, and he shall declare over him all the iniquities of the children of Israel, and all their unrighteousness, and all their sins; and he shall lay them upon the head of the live goat, and shall send him by the hand of a ready man into the wilderness."}}, {"v": 22, "ref": "16:22", "o": "וְ/נָשָׂ֨א הַ/שָּׂעִ֥יר עָלָ֛י/ו אֶת כָּל עֲוֺנֹתָ֖/ם אֶל אֶ֣רֶץ גְּזֵרָ֑ה וְ/שִׁלַּ֥ח אֶת הַ/שָּׂעִ֖יר בַּ/מִּדְבָּֽר", "en": {"kjv": "And the goat shall bear upon him all their iniquities unto a land not inhabited: and he shall let go the goat in the wilderness.", "web": "The goat shall carry all their iniquities on himself to a solitary land, and he shall let the goat go in the wilderness.", "bsb": "The goat will carry on itself all their iniquities into a solitary place, and the man will release it into the wilderness.", "asv": "and the goat shall bear upon him all their iniquities unto a solitary land: and he shall let go the goat in the wilderness.", "ylt": "and the goat hath borne on him all their iniquities unto a land of separation. `And he hath sent the goat away into the wilderness,", "tyndale": "And the goote shall bere apon him all their mysdeades vnto the wildernesse, and he shall let the goote goo fre in the wildernesse.", "dra": "And when the goat hath carried all their iniquities into an uninhabited land, and shall be let go into the desert:", "bbe": "And the goat will take all their sins into a land cut off from men, and he will send the goat away into the waste land.", "geneva": "So the goate shall beare vpon him all their iniquities into the land that is not inhabited, and he shall let the goate go into the wildernesse.", "wycliffe": "And whanne the `buc of geet hath bore alle the wickidnessis `of hem in to a deseert lond,", "rotherham": "so shall the goat bear upon him all their iniquities into a lone land,—and he shall set the goat free, in the desert.", "darby": "that the goat may bear upon him all their iniquities to a land apart [from men]; and he shall send away the goat into the wilderness.", "twenty": "", "jps": "And the goat shall bear upon him all their iniquities unto a land which is cut off; and he shall let go the goat in the wilderness.", "acv": "And the goat shall bear upon him all their iniquities to a solitary land. And he shall let the goat go in the wilderness.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the goat shall bear upon him all their iniquities to a land not inhabited: and he shall let go the goat in the wilderness.", "vulgate": "cumque portaverit hircus omnes iniquitates eorum in terram solitariam et dimissus fuerit in deserto;", "brenton": "And the goat shall bear their unrighteousnesses upon him into a desert land; and Aaron shall send away the goat into the wilderness."}}, {"v": 23, "ref": "16:23", "o": "וּ/בָ֤א אַהֲרֹן֙ אֶל אֹ֣הֶל מוֹעֵ֔ד וּ/פָשַׁט֙ אֶת בִּגְדֵ֣י הַ/בָּ֔ד אֲשֶׁ֥ר לָבַ֖שׁ בְּ/בֹא֣/וֹ אֶל הַ/קֹּ֑דֶשׁ וְ/הִנִּיחָ֖/ם שָֽׁם", "en": {"kjv": "And Aaron shall come into the tabernacle of the congregation, and shall put off the linen garments, which he put on when he went into the holy place, and shall leave them there:", "web": "“Aaron shall come into the Tent of Meeting, and shall take off the linen garments, which he put on when he went into the Holy Place, and shall leave them there.", "bsb": "Then Aaron is to enter the Tent of Meeting, take off the linen garments he put on before entering the Most Holy Place, and leave them there.", "asv": "And Aaron shall come into the tent of meeting, and shall put off the linen garments, which he put on when he went into the holy place, and shall leave them there:", "ylt": "and Aaron hath come in unto the tent of meeting, and hath stripped off the linen garments which he had put on in his going in unto the sanctuary, and hath placed them there;", "tyndale": "And let Aaron goo in to the tabernacle of wytnesse and put off the lyne clothes which he put on when he wet in in to the holy place, ad leaue them there.", "dra": "Aaron shall return into the tabernacle of the testimony, and putting off the vestments, which he had on him before when he entered into the sanctuary, and leaving them there,", "bbe": "Then let Aaron come into the Tent of meeting and take off the linen clothing which he put on when he went into the holy place, and put them down there;", "geneva": "After, Aaron shall come into the Tabernacle of the Congregation, and put off the linnen clothes, which he put on when he went into the Holy place, and leaue them there.", "wycliffe": "and is left `in deseert, Aaron schal turn ayen in to the tabernacle of witnessyng; and whanne the clothis ben put of, in whiche he was clothid bifore, whanne he entrid in to the seyntuarie of God, and ben left there,", "rotherham": "Then shall Aaron come into the tent of meeting, and put off the linen garments which he put on when he came into the holy place,—and shall leave them there;", "darby": "And Aaron shall go into the tent of meeting, and shall put off the linen garments, which he put on when he went into the sanctuary, and shall leave them there;", "twenty": "", "jps": "And Aaron shall come into the tent of meeting, and shall put off the linen garments, which he put on when he went into the holy place, and shall leave them there.", "acv": "And Aaron shall come into the tent of meeting, and shall put off the linen garments, which he put on when he went into the holy place, and shall leave them there.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Aaron shall come into the tabernacle of the congregation, and shall put off the linen garments which he put on when he went into the holy [place], and shall leave them there:", "vulgate": "revertetur Aaron in tabernaculum testimonii et depositis vestibus quibus prius indutus erat cum intraret sanctuarium relictisque ibi;", "brenton": "And Aaron shall enter into the tabernacle of witness, and shall put off the linen garment, which he had put on, as he entered into the holy place, and shall lay it by there."}}, {"v": 24, "ref": "16:24", "o": "וְ/רָחַ֨ץ אֶת בְּשָׂר֤/וֹ בַ/מַּ֨יִם֙ בְּ/מָק֣וֹם קָד֔וֹשׁ וְ/לָבַ֖שׁ אֶת בְּגָדָ֑י/ו וְ/יָצָ֗א וְ/עָשָׂ֤ה אֶת עֹֽלָת/וֹ֙ וְ/אֶת עֹלַ֣ת הָ/עָ֔ם וְ/כִפֶּ֥ר בַּעֲד֖/וֹ וּ/בְעַ֥ד הָ/עָֽם", "en": {"kjv": "And he shall wash his flesh with water in the holy place, and put on his garments, and come forth, and offer his burnt offering, and the burnt offering of the people, and make an atonement for himself, and for the people.", "web": "Then he shall bathe himself in water in a holy place, and put on his garments, and come out and offer his burnt offering and the burnt offering of the people, and make atonement for himself and for the people.", "bsb": "He is to bathe himself with water in a holy place and put on his own clothes. Then he must go out and sacrifice his burnt offering and the people’s burnt offering to make atonement for himself and for the people.", "asv": "and he shall bathe his flesh in water in a holy place, and put on his garments, and come forth, and offer his burnt-offering and the burnt-offering of the people, and make atonement for himself and for the people.", "ylt": "and he hath bathed his flesh with water in the holy place, and hath put on his garments, and hath come out, and hath made his burnt-offering, and the burnt-offering of the people, and hath made atonement for himself and for the people;", "tyndale": "And let him wasshe his flesh with water in the holy place, and put on his owne rayment and then come out and offer his burntofferynge and the burntofferynge of the people, and make an atonemet for him selfe ad for the people,", "dra": "He shall wash his flesh in the holy place, and shall put on his own garments. And after that he is come out and hath offered his own holocaust, and that of the people, he shall pray both for himself, and for the people.", "bbe": "And after bathing his body in water in a holy place, he is to put on his clothing and come out and give his burned offering and the burned offering of the people, to take away his sin and the sin of the people.", "geneva": "Hee shall wash also his flesh with water in the Holy place, and put on his owne rayment, and come out, and make his burnt offring, and the burnt offring of the people, and make an atonement for himselfe, and for the people.", "wycliffe": "he schal waische his fleisch in the hooli place, and he schal be clothid in his owen clothis, and aftir that he hath go out, and hath offrid the brent sacrifice of hym silf, and of the puple, he schal preye as wel for hym silf, as for the puple;", "rotherham": "and shall bathe his flesh in water in a holy place, and put on his [other] garments,—and go forth, and offer his own ascending-sacrifice, and the ascending-sacrifice of the people, so shall he put a propitiatory-covering about himself, and about the people;", "darby": "and he shall bathe his flesh with water in a holy place, and put on his garments, and go forth, and offer his burnt-offering, and the burnt-offering of the people, and make atonement for himself, and for the people.", "twenty": "", "jps": "And he shall bathe his flesh in water in a holy place and put on his other vestments, and come forth, and offer his burnt-offering and the burnt-offering of the people, and make atonement for himself and for the people.", "acv": "And he shall bathe his flesh in water in a holy place, and put on his garments, and come forth, and offer his burnt offering and the burnt offering of the people, and make atonement for himself and for the people.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall wash his flesh with water in the holy [place], and put on his garments, and come forth, and offer his burnt-offering, and the burnt-offering of the people, and make an atonement for himself, and for the people.", "vulgate": "lavabit carnem suam in loco sancto indueturque vestimentis suis et postquam egressus obtulerit holocaustum suum ac plebis rogabit tam pro se quam pro populo;", "brenton": "And he shall bathe his body in water in the holy place, and shall put on his raiment, and shall go out and offer the whole-burnt-offering for himself and the whole-burnt-offering for the people: and shall make atonement for himself and for his house, and for the people, as for the priests."}}, {"v": 25, "ref": "16:25", "o": "וְ/אֵ֛ת חֵ֥לֶב הַֽ/חַטָּ֖את יַקְטִ֥יר הַ/מִּזְבֵּֽחָ/ה", "en": {"kjv": "And the fat of the sin offering shall he burn upon the altar.", "web": "The fat of the sin offering he shall burn on the altar.", "bsb": "He is also to burn the fat of the sin offering on the altar.", "asv": "And the fat of the sin-offering shall he burn upon the altar.", "ylt": "and with the fat of the sin-offering he doth make perfume on the altar.", "tyndale": "and the fatt of the synofferynge let him burne apon the alter.", "dra": "And the fat that is offered for sins, he shall burn on the altar.", "bbe": "And the fat of the sin-offering is to be burned by him on the altar.", "geneva": "Also the fatte of the sinne offring shall he burne vpon the altar.", "wycliffe": "and he schal brenne on the auter the innere fatnesse which is offrid for synne.", "rotherham": "and, with the fat of the sin-bearer, shall he make a perfume at the altar.", "darby": "And the fat of the sin-offering shall he burn upon the altar.", "twenty": "", "jps": "And the fat of the sin-offering shall he make smoke upon the altar.", "acv": "And he shall burn upon the altar the fat of the sin offering.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the fat of the sin-offering shall he burn upon the altar.", "vulgate": "et adipem qui oblatus est pro peccatis adolebit super altare;", "brenton": "And he shall offer the fat for the sin-offering on the altar."}}, {"v": 26, "ref": "16:26", "o": "וְ/הַֽ/מְשַׁלֵּ֤חַ אֶת הַ/שָּׂעִיר֙ לַֽ/עֲזָאזֵ֔ל יְכַבֵּ֣ס בְּגָדָ֔י/ו וְ/רָחַ֥ץ אֶת בְּשָׂר֖/וֹ בַּ/מָּ֑יִם וְ/אַחֲרֵי כֵ֖ן יָב֥וֹא אֶל הַֽ/מַּחֲנֶֽה", "en": {"kjv": "And he that let go the goat for the scapegoat shall wash his clothes, and bathe his flesh in water, and afterward come into the camp.", "web": "“He who lets the goat go for the scapegoat shall wash his clothes, and bathe his flesh in water, and afterward he shall come into the camp.", "bsb": "The man who released the goat as the scapegoat must wash his clothes and bathe himself with water; afterward he may reenter the camp.", "asv": "And he that letteth go the goat for Azazel shall wash his clothes, and bathe his flesh in water, and afterward he shall come into the camp.", "ylt": "`And he who is sending away the goat for a goat of departure doth wash his garments, and hath bathed his flesh with water, and afterwards he cometh in unto the camp.", "tyndale": "And let him that caryed forth the scapegoote, wasshe his clothes and bathe hys flesh in water and then come in to the hoste agayne.", "dra": "But he that hath let go the emissary goat, shall wash his clothes, and his body with water, and so shall enter into the camp.", "bbe": "And the man who takes away the goat for Azazel is to have his clothing washed and his body bathed in water and then he may come back to the tent-circle.", "geneva": "And he that caried forth the goat, called the Scape goat, shall wash his clothes, and wash his flesh in water, and after that shall come into the hoste.", "wycliffe": "Sotheli he that leet go the `buk of geet able to be sent out, schal waische hise clothis and bodi with water, and so he schal entre in to the castels.", "rotherham": "And he that sent away the goat unto Azazel, shall wash—his clothes, and bathe his flesh in water,—and, after that, shall he come into the camp.", "darby": "And he that letteth go the goat for Azazel shall wash his clothes, and bathe his flesh in water; and afterwards he may come into the camp.", "twenty": "", "jps": "And he that letteth go the goat for Azazel shall wash his clothes, and bathe his flesh in water, and afterward he may come into the camp.", "acv": "And he who lets the goat go for the scapegoat shall wash his clothes, and bathe his flesh in water, and afterward he shall come into the camp.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he that let go the goat for the scape-goat shall wash his clothes, and bathe his flesh in water, and afterward come into the camp.", "vulgate": "ille vero qui dimiserit caprum emissarium lavabit vestimenta sua et corpus aqua et sic ingredietur in castra;", "brenton": "And he that sends forth the goat that has been set apart to be let go, shall wash his garments, and bathe his body in water, and afterwards shall enter into the camp."}}, {"v": 27, "ref": "16:27", "o": "וְ/אֵת֩ פַּ֨ר הַֽ/חַטָּ֜את וְ/אֵ֣ת שְׂעִ֣יר הַֽ/חַטָּ֗את אֲשֶׁ֨ר הוּבָ֤א אֶת דָּמָ/ם֙ לְ/כַפֵּ֣ר בַּ/קֹּ֔דֶשׁ יוֹצִ֖יא אֶל מִ/ח֣וּץ לַֽ/מַּחֲנֶ֑ה וְ/שָׂרְפ֣וּ בָ/אֵ֔שׁ אֶת עֹרֹתָ֥/ם וְ/אֶת בְּשָׂרָ֖/ם וְ/אֶת פִּרְשָֽׁ/ם", "en": {"kjv": "And the bullock for the sin offering, and the goat for the sin offering, whose blood was brought in to make atonement in the holy place, shall one carry forth without the camp; and they shall burn in the fire their skins, and their flesh, and their dung.", "web": "The bull for the sin offering, and the goat for the sin offering, whose blood was brought in to make atonement in the Holy Place, shall be carried outside the camp; and they shall burn their skins, their flesh, and their dung with fire.", "bsb": "The bull for the sin offering and the goat for the sin offering, whose blood was brought into the Most Holy Place to make atonement, must be taken outside the camp; and their hides, flesh, and dung must be burned up.", "asv": "And the bullock of the sin-offering, and the goat of the sin-offering, whose blood was brought in to make atonement in the holy place, shall be carried forth without the camp; and they shall burn in the fire their skins, and their flesh, and their dung.", "ylt": "`And the bullock of the sin-offering, and the goat of the sin-offering, whose blood hath been brought in to make atonement in the sanctuary, doth one bring out unto the outside of the camp, and they have burnt with fire their skins, and their flesh, and their dung;", "tyndale": "And the oxe of the synofferynge and the goote of the synofferynge (whose bloude was brought in to make an atonemet in the holy place) let one carye out without the hoste and burne with fyre: both their skynnes, their flesh ad their donge.", "dra": "But the calf and the buck goat, that were sacrificed for sin, and whose blood was carried into the sanctuary, to accomplish the atonement, they shall carry forth without the camp, and shall burn with fire: their skins and their flesh, and their dung.", "bbe": "And the ox of the sin-offering and the goat of the sin-offering, whose blood was taken in to make the holy place free from sin, are to be taken away outside the tent-circle and their skins and their flesh and their waste are to be burned with fire.", "geneva": "Also the bullocke for the sinne offring, and the goate for the sinne offring (whose blood was brought to make a reconciliation in the Holy place) shall one carie out without the hoste to be burnt in the fire, with their skinnes, and with their flesh, and with their doung.", "wycliffe": "Forsothe thei schulen bere out of the castels the calf and `buk of geet, that weren offrid for synne, and whos blood was brouyt in to the seyntuarie, that the clensyng were fillid; and thei schulen brenne bi fier as well the skynnys, as the fleischis and dung of tho.", "rotherham": "And the, sin-bearing bullock, and the sin-bearing goat whose blood was brought in to make a propitiatory-covering in the holy place, shall be carried forth outside the camp,—and they shall burn up, in fire, their skins and their flesh, and their dung;", "darby": "And the bullock of the sin-offering, and the goat of the sin-offering whose blood was brought in to make atonement in the sanctuary, shall one carry forth outside the camp; and they shall burn with fire their skins, and their flesh, and their dung.", "twenty": "", "jps": "And the bullock of the sin-offering, and the goat of the sin-offering, whose blood was brought in to make atonement in the holy place, shall be carried forth without the camp; and they shall burn in the fire their skins, and their flesh, and their dung.", "acv": "And the bullock of the sin offering, and the goat of the sin offering, whose blood was brought in to make atonement in the holy place, shall be carried forth outside the camp, and they shall burn in the fire their skins, and their flesh, and their dung.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the bullock [for] the sin-offering, and the goat [for] the sin-offering, whose blood was brought in to make atonement in the holy [place], shall [one] carry forth without the camp; and they shall burn in the fire their skins, and their flesh, and their dung.", "vulgate": "vitulum autem et hircum qui pro peccato fuerant immolati et quorum sanguis inlatus est ut in sanctuario expiatio conpleretur asportabunt foras castra et conburent igni tam pelles quam carnes eorum et fimum;", "brenton": "And the calf for the sin-offering, and the goat for the sin-offering, whose blood was brought in to make atonement in the holy place, they shall carry forth out of the camp, and burn them with fire, even their skins and their flesh and their dung."}}, {"v": 28, "ref": "16:28", "o": "וְ/הַ/שֹּׂרֵ֣ף אֹתָ֔/ם יְכַבֵּ֣ס בְּגָדָ֔י/ו וְ/רָחַ֥ץ אֶת בְּשָׂר֖/וֹ בַּ/מָּ֑יִם וְ/אַחֲרֵי כֵ֖ן יָב֥וֹא אֶל הַֽ/מַּחֲנֶֽה", "en": {"kjv": "And he that burneth them shall wash his clothes, and bathe his flesh in water, and afterward he shall come into the camp.", "web": "He who burns them shall wash his clothes, and bathe his flesh in water, and afterward he shall come into the camp.", "bsb": "The one who burns them must wash his clothes and bathe himself with water, and afterward he may reenter the camp.", "asv": "And he that burneth them shall wash his clothes, and bathe his flesh in water, and afterward he shall come into the camp.", "ylt": "and he who is burning them doth wash his garments, and hath bathed his flesh with water, and afterwards he cometh in unto the camp.", "tyndale": "And let him that burneth them, wasshe his clothes ad bathe his flesh in water, and the come in to the hoste agayne.", "dra": "And whosoever burneth them shall wash his clothes, and flesh with water: and so shall enter into the camp.", "bbe": "And the man by whom they are burned is to have his clothing washed and his body bathed in water, and then he may come back to the tent-circle.", "geneva": "And hee that burneth them shall wash his clothes, and wash his flesh in water, and afterward come into the hoste.", "wycliffe": "And who euer brenneth tho, schal waische hise clothis and fleisch in watir, and so he schal entre in to the castels.", "rotherham": "and he that hath burned them, shall wash his clothes, and bathe his flesh in water,—and, after that, shall he come into the camp.", "darby": "And he that burneth them shall wash his clothes, and bathe his flesh in water; and afterwards he may come into the camp.", "twenty": "", "jps": "And he that burneth them shall wash his clothes, and bathe his flesh in water, and afterward he may come into the camp.", "acv": "And he who burns them shall wash his clothes, and bathe his flesh in water, and afterward he shall come into the camp.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he that burneth them shall wash his clothes, and bathe his flesh in water, and afterward he shall come into the camp.", "vulgate": "et quicumque conbuserit ea lavabit vestimenta sua et carnem aqua et sic ingredietur in castra;", "brenton": "And he that burns them shall wash his garments, and bathe his body in water, and afterwards he shall enter into the camp."}}, {"v": 29, "ref": "16:29", "o": "וְ/הָיְתָ֥ה לָ/כֶ֖ם לְ/חֻקַּ֣ת עוֹלָ֑ם בַּ/חֹ֣דֶשׁ הַ֠/שְּׁבִיעִי בֶּֽ/עָשׂ֨וֹר לַ/חֹ֜דֶשׁ תְּעַנּ֣וּ אֶת נַפְשֹֽׁתֵי/כֶ֗ם וְ/כָל מְלָאכָה֙ לֹ֣א תַעֲשׂ֔וּ הָֽ/אֶזְרָ֔ח וְ/הַ/גֵּ֖ר הַ/גָּ֥ר בְּ/תוֹכְ/כֶֽם", "en": {"kjv": "And this shall be a statute for ever unto you: that in the seventh month, on the tenth day of the month, ye shall afflict your souls, and do no work at all, whether it be one of your own country, or a stranger that sojourneth among you:", "web": "“It shall be a statute to you forever: in the seventh month, on the tenth day of the month, you shall afflict your souls, and shall do no kind of work, the native-born, or the stranger who lives as a foreigner among you:", "bsb": "This is to be a permanent statute for you: On the tenth day of the seventh month, you shall humble yourselves and not do any work—whether the native or the foreigner who resides among you—", "asv": "And it shall be a statute for ever unto you: in the seventh month, on the tenth day of the month, ye shall afflict your souls, and shall do no manner of work, the home-born, or the stranger that sojourneth among you:", "ylt": "`And it hath been to you for a statute age-during, in the seventh month, in the tenth of the month, ye humble yourselves, and do no work--the native, and the sojourner who is sojourning in your midst;", "tyndale": "And it shalbe an ordynaunce for euer vnto you. And eue in the tenth daye of the seuenth moneth, ye shall humble youre soules and shall doo no worke at all: whether it be one of youre selues or a straunger that sogeorneth amonge you.", "dra": "And this shall be to you an everlasting ordinance. The seventh month, the tenth day of the month, you shall afflict your souls, and shall do no work, whether it be one of your own country, or a stranger that sojourneth among you.", "bbe": "And let this be an order to you for ever: in the seventh month, on the tenth day, you are to keep yourselves from pleasure and do no sort of work, those who are Israelites by birth and those from other lands who are living among you:", "geneva": "So this shalbe an ordinance for euer vnto you: the tenth day of the seuenth moneth, yee shall humble your soules, and do no worke at all, whether it be one of the same countrey or a strager that soiourneth among you.", "wycliffe": "And this schal be to you a lawful thing euerlastynge; in the seuenthe monethe, in the tenthe dai of the monethe, ye schulen turment youre soulis, and ye schulen not do ony werk, nethir a man borun in the lond, nether a comelyng which is a pilgrym among you.", "rotherham": "And it shall become unto you, a statute age-abiding,—In the seventh month on the tenth of the month, Shall ye humble you souls And, no work, shall ye do, The home-born, Or the sojourner that sojourneth in your midst;", "darby": "And this shall be an everlasting statute unto you. In the seventh month, on the tenth of the month, ye shall afflict your souls, and do no work at all, the home-born, and the stranger that sojourneth among you;", "twenty": "", "jps": "And it shall be a statute for ever unto you: in the seventh month, on the tenth day of the month, ye shall afflict your souls, and shall do no manner of work, the home-born, or the stranger that sojourneth among you.", "acv": "And it shall be a statute forever to you. In the seventh month, on the tenth day of the month, ye shall afflict your souls, and shall do no manner of work, the home-born, or the stranger who sojourns among you.", "anderson": "", "haweis": "", "noyes": "", "webster": "And [this] shall be a statute for ever to you: [that] in the seventh month, on the tenth [day] of the month, ye shall afflict your souls, and do no work at all, [whether it be] one of your own country, or a stranger that sojourneth among you:", "vulgate": "eritque hoc vobis legitimum sempiternum mense septimo decima die mensis adfligetis animas vestras nullumque facietis opus sive indigena sive advena qui peregrinatur inter vos;", "brenton": "And this shall be a perpetual statute for you; in the seventh month, on the tenth day of the month, ye shall humble your souls, and shall do no work, the native and the stranger who abides among you."}}, {"v": 30, "ref": "16:30", "o": "כִּֽי בַ/יּ֥וֹם הַ/זֶּ֛ה יְכַפֵּ֥ר עֲלֵי/כֶ֖ם לְ/טַהֵ֣ר אֶתְ/כֶ֑ם מִ/כֹּל֙ חַטֹּ֣אתֵי/כֶ֔ם לִ/פְנֵ֥י יְהוָ֖ה תִּטְהָֽרוּ", "en": {"kjv": "For on that day shall the priest make an atonement for you, to cleanse you, that ye may be clean from all your sins before the Lord.", "web": "for on this day shall atonement be made for you, to cleanse you; from all your sins you shall be clean before Yahweh.", "bsb": "because on this day atonement will be made for you to cleanse you, and you will be clean from all your sins before the LORD.", "asv": "for on this day shall atonement be made for you, to cleanse you; from all your sins shall ye be clean before Jehovah.", "ylt": "for on this day he maketh atonement for you, to cleanse you; from all your sins before Jehovah ye are clean;", "tyndale": "for that daye shall an attonemet be made for you to clense you from all youre synnes before the Lorde and ye shalbe cleane.", "dra": "Upon this day shall be the expiation for you, and the cleansing from all your sins. You shall be cleansed before the Lord.", "bbe": "For on this day your sin will be taken away and you will be clean: you will be made free from all your sins before the Lord.", "geneva": "For that day shall ye Priest make an atonement for you to clense you: ye shalbe cleane from all your sinnes before the Lord.", "wycliffe": "The delyueryng fro synne, and the clensyng of you schal be in this dai, ye schulen be clensid bifore the Lord fro alle youre synnes;", "rotherham": "For on this day, shall a propitiatory-covering, be put over you, to cleanse you,—From all your sins before Yahweh, shall ye be clean.", "darby": "for on that day shall atonement be made for you, to cleanse you: from all your sins shall ye be clean before Jehovah.", "twenty": "", "jps": "For on this day shall atonement be made for you, to cleanse you; from all your sins shall ye be clean before HaShem.", "acv": "For on this day atonement shall be made for you, to cleanse you. Ye shall be clean from all your sins before Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "For on that day shall [the priest] make an atonement for you, to cleanse you, [that] ye may be clean from all your sins before the LORD.", "vulgate": "in hac die expiatio erit vestri atque mundatio ab omnibus peccatis vestris coram Domino mundabimini;", "brenton": "For in this day he shall make an atonement for you, to cleanse you from all your sins before the Lord, and ye shall be purged."}}, {"v": 31, "ref": "16:31", "o": "שַׁבַּ֨ת שַׁבָּת֥וֹן הִיא֙ לָ/כֶ֔ם וְ/עִנִּיתֶ֖ם אֶת נַפְשֹׁתֵי/כֶ֑ם חֻקַּ֖ת עוֹלָֽם", "en": {"kjv": "It shall be a sabbath of rest unto you, and ye shall afflict your souls, by a statute for ever.", "web": "It is a Sabbath of solemn rest to you, and you shall afflict your souls. It is a statute forever.", "bsb": "It is a Sabbath of complete rest for you, that you may humble yourselves; it is a permanent statute.", "asv": "It is a sabbath of solemn rest unto you, and ye shall afflict your souls; it is a statute for ever.", "ylt": "it is to you a sabbath of rest, and ye have humbled yourselves--a statute age-during.", "tyndale": "It shalbe a sabbath of rest vnto you and ye shall humble youre soules and it shalbe an ordynaunce for euer.", "dra": "For it is a sabbath of rest: and you shall afflict your souls by a perpetual religion.", "bbe": "It is a special Sabbath for you, and you are to keep yourselves from pleasure; it is an order for ever.", "geneva": "This shall be a Sabbath of rest vnto you, and ye shall humble your soules, by an ordinance for euer.", "wycliffe": "for it is sabat of restyng, and ye schulen turment youre soulis bi euerlastynge religioun.", "rotherham": "A sabbath of sacred rest, it is unto you, Therefore shall ye humble your souls, A statute age-abiding.", "darby": "A sabbath of rest shall it be unto you, and ye shall afflict your souls: [it is] an everlasting statute.", "twenty": "", "jps": "It is a sabbath of solemn rest unto you, and ye shall afflict your souls; it is a statute for ever.", "acv": "It is a sabbath of solemn rest to you, and ye shall afflict your souls. It is a statute forever.", "anderson": "", "haweis": "", "noyes": "", "webster": "It [shall be] a sabbath of rest to you, and ye shall afflict your souls by a statute for ever.", "vulgate": "sabbatum enim requietionis est et adfligetis animas vestras religione perpetua;", "brenton": "This shall be to you a most holy sabbath, a rest, and ye shall humble your souls; it is a perpetual ordinance."}}, {"v": 32, "ref": "16:32", "o": "וְ/כִפֶּ֨ר הַ/כֹּהֵ֜ן אֲשֶׁר יִמְשַׁ֣ח אֹת֗/וֹ וַ/אֲשֶׁ֤ר יְמַלֵּא֙ אֶת יָד֔/וֹ לְ/כַהֵ֖ן תַּ֣חַת אָבִ֑י/ו וְ/לָבַ֛שׁ אֶת בִּגְדֵ֥י הַ/בָּ֖ד בִּגְדֵ֥י הַ/קֹּֽדֶשׁ", "en": {"kjv": "And the priest, whom he shall anoint, and whom he shall consecrate to minister in the priest’s office in his father’s stead, shall make the atonement, and shall put on the linen clothes, even the holy garments:", "web": "The priest, who is anointed and who is consecrated to be priest in his father’s place, shall make the atonement, and shall put on the linen garments, even the holy garments.", "bsb": "The priest who is anointed and ordained to succeed his father as high priest shall make atonement. He will put on the sacred linen garments", "asv": "And the priest, who shall be anointed and who shall be consecrated to be priest in his father’s stead, shall make the atonement, and shall put on the linen garments, even the holy garments:", "ylt": "`And the priest whom he doth anoint, and whose hand he doth consecrate to act as priest instead of his father, hath made atonement, and hath put on the linen garments, the holy garments;", "tyndale": "And the preast that is anoynted and whose hande was fylled to mynistre in his fathers steade shall make the attonemet and shall put on the holy lyne vestimetes", "dra": "And the priest that is anointed, and whose hands are consecrated to do the office of the priesthood in his father's stead, shall make atonement. And he shall be vested with the linen robe and the holy vestments.", "bbe": "And the man on whose head the holy oil has been put, and who has been marked out to be a priest in his father's place, will do what is necessary to take away sin, and will put on the linen clothing, even the holy robes:", "geneva": "And the Priest whom he shall anoynt, and whom he shall cosecrate (to minister in his fathers steade) shall make the atonement, and shall put on the linnen clothes and Holy vestments,", "wycliffe": "Sotheli the preest schal clense, which is anoyntid, and whos hondis ben halewid, that he be set in preesthod for his fadir; and he schal be clothid in a lynnun stoole, and in hooli clothis,", "rotherham": "Therefore shall the priest who shall be anointed, and installed, to minister as priest in the stead of his father make propitiation,—So then he shall put on the linen garments the holy garments;", "darby": "And the priest who hath been anointed, and who hath been consecrated, to exercise the priesthood in his father's stead, shall make atonement; and he shall put on the linen garments, the holy garments.", "twenty": "", "jps": "And the priest, who shall be anointed and who shall be consecrated to be priest in his father's stead, shall make the atonement, and shall put on the linen garments, even the holy garments.", "acv": "And the priest, who shall be anointed and who shall be consecrated to be priest in his father's stead, shall make the atonement. And he shall put on the linen garments, even the holy garments,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest whom he shall anoint, and whom he shall consecrate to minister in the priest's office in his father's stead, shall make the atonement, and shall put on the linen clothes, [even] the holy garments:", "vulgate": "expiabit autem sacerdos qui unctus fuerit et cuius initiatae manus ut sacerdotio fungatur pro patre suo indueturque stola linea et vestibus sanctis;", "brenton": "The priest whomsoever they shall anoint shall make atonement, and whomsoever they shall consecrate to exercise the priestly office after his father; and he shall put on the linen robe, the holy garment."}}, {"v": 33, "ref": "16:33", "o": "וְ/כִפֶּר֙ אֶת מִקְדַּ֣שׁ הַ/קֹּ֔דֶשׁ וְ/אֶת אֹ֧הֶל מוֹעֵ֛ד וְ/אֶת הַ/מִּזְבֵּ֖חַ יְכַפֵּ֑ר וְ/עַ֧ל הַ/כֹּהֲנִ֛ים וְ/עַל כָּל עַ֥ם הַ/קָּהָ֖ל יְכַפֵּֽר", "en": {"kjv": "And he shall make an atonement for the holy sanctuary, and he shall make an atonement for the tabernacle of the congregation, and for the altar, and he shall make an atonement for the priests, and for all the people of the congregation.", "web": "Then he shall make atonement for the Holy Sanctuary; and he shall make atonement for the Tent of Meeting and for the altar; and he shall make atonement for the priests and for all the people of the assembly.", "bsb": "and make atonement for the Most Holy Place, the Tent of Meeting, and the altar, and for the priests and all the people of the assembly.", "asv": "and he shall make atonement for the holy sanctuary; and he shall make atonement for the tent of meeting and for the altar; and he shall make atonement for the priests and for all the people of the assembly.", "ylt": "and he hath made atonement for the holy sanctuary; and for the tent of meeting, even for the altar he doth make atonement; yea, for the priests, and for all the people of the assembly he maketh atonement.", "tyndale": "and reconcyle the holy sanctuary and the tabernacle of witnesse ad the alter, and shall make an attonemet also for the preastes and for all the people of the congregacion.", "dra": "And he shall expiate the sanctuary and the tabernacle of the testimony and the altar: the priest also and all the people.", "bbe": "And he will make the holy place and the Tent of meeting and the altar free from sin; he will take away sin from the priests and from all the people.", "geneva": "And shall purge the Holy Sanctuarie and the Tabernacle of the Congregation, and shall clense the altar, and make an atonement for the Priests and for all the people of the Congregation.", "wycliffe": "and he schal clense the seyntuarie, and the tabernacle of witnessyng, and the auter, and the preestis, and al the puple.", "rotherham": "And make propitiation for the holy sanctuary, And for the tent of meeting, and for the altar, shall he make propitiation,—Over the priests also and over all the people of the convocation, shall he put a covering by propitiation.", "darby": "And he shall make atonement for the holy sanctuary; and for the tent of meeting, and for the altar shall he make atonement; and for the priests, and for the whole people of the congregation shall he make atonement.", "twenty": "", "jps": "And he shall make atonement for the most holy place, and he shall make atonement for the tent of meeting and for the altar; and he shall make atonement for the priests and for all the people of the assembly.", "acv": "and shall make atonement for the holy sanctuary, and he shall make atonement for the tent of meeting and for the altar, and he shall make atonement for the priests and for all the people of the assembly.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall make an atonement for the holy sanctuary, and he shall make an atonement for the tabernacle of the congregation, and for the altar: and he shall make an atonement for the priests, and for all the people of the congregation.", "vulgate": "et expiabit sanctuarium et tabernaculum testimonii atque altare sacerdotes quoque et universum populum;", "brenton": "And he shall make atonement for the most holy place, and the tabernacle of witness; and he shall make atonement for the altar, and for the priests; and he shall make atonement for all the congregation."}}, {"v": 34, "ref": "16:34", "o": "וְ/הָֽיְתָה זֹּ֨את לָ/כֶ֜ם לְ/חֻקַּ֣ת עוֹלָ֗ם לְ/כַפֵּ֞ר עַל בְּנֵ֤י יִשְׂרָאֵל֙ מִ/כָּל חַטֹּאתָ֔/ם אַחַ֖ת בַּ/שָּׁנָ֑ה וַ/יַּ֕עַשׂ כַּ/אֲשֶׁ֛ר צִוָּ֥ה יְהוָ֖ה אֶת מֹשֶֽׁה", "en": {"kjv": "And this shall be an everlasting statute unto you, to make an atonement for the children of Israel for all their sins once a year. And he did as the Lord commanded Moses.", "web": "“This shall be an everlasting statute for you, to make atonement for the children of Israel once in the year because of all their sins.” It was done as Yahweh commanded Moses.", "bsb": "This is to be a permanent statute for you, to make atonement once a year for the Israelites because of all their sins.” And all this was done as the LORD had commanded Moses.", "asv": "And this shall be an everlasting statute unto you, to make atonement for the children of Israel because of all their sins once in the year. And he did as Jehovah commanded Moses.", "ylt": "`And this hath been to you for a statute age-during, to make atonement for the sons of Israel, because of all their sins, once in a year;' and he doth as Jehovah hath commanded Moses.", "tyndale": "And this shalbe an euerlastynge ordynaunce vnto you to make an atonement for the childern of Israel for all their synnes once a yere: and it was done eue as the Lorde commaunded Moses.", "dra": "And this shall be an ordinance for ever, that you pray for the children of Israel, and for all their sins once a year. He did therefore as the Lord had commanded Moses.", "bbe": "And let this be an order for ever for you, so that the sin of the children of Israel may be taken away once every year. And he did as the Lord gave orders to Moses.", "geneva": "And this shalbe an euerlasting ordinance vnto you, to make an atonement for the children of Israel for all their sinnes once a yeere: and as the Lord commanded Moses, he did.", "wycliffe": "And this schal be to you a lawful thing euerlastynge, that ye preye for the sones of Israel, and for alle the synnes `of hem, onys in the yeer. Therfor he dide, as the Lord comaundide to Moises.", "rotherham": "So shall this become unto you an age-abiding statute,—to put a propitiatory-covering over the sons of Israel because of all their sins, Once in the year. And he did, As Yahweh commanded Moses.", "darby": "And this shall be an everlasting statute unto you, to make atonement for the children of Israel [to cleanse them] from all their sins once a year. And he did as Jehovah had commanded Moses.", "twenty": "", "jps": "And this shall be an everlasting statute unto you, to make atonement for the children of Israel because of all their sins once in the year.' And he did as HaShem commanded Moses.", "acv": "And this shall be an everlasting statute to you, to make atonement for the sons of Israel because of all their sins once in the year. And he did as Jehovah commanded Moses.", "anderson": "", "haweis": "", "noyes": "", "webster": "And this shall be an everlasting statute to you, to make an atonement for the children of Israel for all their sins once a year. And he did as the LORD commanded Moses.", "vulgate": "eritque hoc vobis legitimum sempiternum ut oretis pro filiis Israhel et pro cunctis peccatis eorum semel in anno fecit igitur sicut praeceperat Dominus Mosi;", "brenton": "And this shall be to you a perpetual statute to make atonement for the children of Israel for all their sins: it shall be done once in the year, as the Lord commanded Moses."}}]}, {"c": 17, "verses": [{"v": 1, "ref": "17:1", "o": "וַ/יְדַבֵּ֥ר יְהוָ֖ה אֶל מֹשֶׁ֥ה לֵּ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh spoke to Moses, saying,", "bsb": "Then the LORD said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde talked with Moses saynge:", "dra": "And the Lord spoke to Moses, saying:", "bbe": "And the Lord said to Moses,", "geneva": "And the Lord spake vnto Moses, saying,", "wycliffe": "And the Lord spak to Moises, and seide, Speke thou to Aaron,", "rotherham": "And Yahweh spake unto Moses saying:—", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses, saying:", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "et locutus est Dominus ad Mosen dicens;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 2, "ref": "17:2", "o": "דַּבֵּ֨ר אֶֽל אַהֲרֹ֜ן וְ/אֶל בָּנָ֗י/ו וְ/אֶל֙ כָּל בְּנֵ֣י יִשְׂרָאֵ֔ל וְ/אָמַרְתָּ֖ אֲלֵי/הֶ֑ם זֶ֣ה הַ/דָּבָ֔ר אֲשֶׁר צִוָּ֥ה יְהוָ֖ה לֵ/אמֹֽר", "en": {"kjv": "Speak unto Aaron, and unto his sons, and unto all the children of Israel, and say unto them; This is the thing which the Lord hath commanded, saying,", "web": "“Speak to Aaron, and to his sons, and to all the children of Israel, and say to them: ‘This is the thing which Yahweh has commanded,", "bsb": "“Speak to Aaron, his sons, and all the Israelites and tell them this is what the LORD has commanded:", "asv": "Speak unto Aaron, and unto his sons, and unto all the children of Israel, and say unto them: This is the thing which Jehovah hath commanded, saying,", "ylt": "`Speak unto Aaron, and unto his sons, and unto all the sons of Israel; and thou hast said unto them, This is the thing which Jehovah hath commanded, saying,", "tyndale": "speake vnto Aaro and vnto his sonnes and vnto all the childern of Israel ad saye vnto them, this is the thynge which the Lorde charged saynge:", "dra": "Speak to Aaron and his sons, and to all the children of Israel, saying to them: This is the word, which the Lord hath commanded, saying:", "bbe": "Say to Aaron and to his sons and to all the children of Israel: This is the order which the Lord has given.", "geneva": "Speake vnto Aaron, and to his sonnes, and to all the children of Israel, and say vnto them, This is the thing which the Lord hath commanded, saying,", "wycliffe": "and to hise sones, and to alle the sones of Israel, and seie thou to hem, This is the word which the Lord comaundide,", "rotherham": "Speak unto Aaron, and unto his sons and unto all the sons of Israel, and thou shalt say unto them,—This, is the thing which Yahweh hath commanded, saying:", "darby": "Speak unto Aaron, and unto his sons, and unto all the children of Israel, and say unto them, This is the thing which Jehovah hath commanded, saying,", "twenty": "", "jps": "Speak unto Aaron, and unto his sons, and unto all the children of Israel, and say unto them: This is the thing which HaShem hath commanded, saying:", "acv": "Speak to Aaron, and to his sons, and to all the sons of Israel, and say to them, This is the thing which Jehovah has commanded, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "Speak to Aaron, and to his sons, and to all the children of Israel, and say to them, This [is] the thing which the LORD hath commanded, saying,", "vulgate": "loquere Aaron et filiis eius et cunctis filiis Israhel et dices ad eos iste est sermo quem mandavit Dominus dicens;", "brenton": "Speak to Aaron and to his sons, and to all the children of Israel, and thou shalt say to them, This is the word which the Lord has commanded, saying,"}}, {"v": 3, "ref": "17:3", "o": "אִ֥ישׁ אִישׁ֙ מִ/בֵּ֣ית יִשְׂרָאֵ֔ל אֲשֶׁ֨ר יִשְׁחַ֜ט שׁ֥וֹר אוֹ כֶ֛שֶׂב אוֹ עֵ֖ז בַּֽ/מַּחֲנֶ֑ה א֚וֹ אֲשֶׁ֣ר יִשְׁחַ֔ט מִ/ח֖וּץ לַֽ/מַּחֲנֶֽה", "en": {"kjv": "What man soever there be of the house of Israel, that killeth an ox, or lamb, or goat, in the camp, or that killeth it out of the camp,", "web": "Whatever man there is of the house of Israel, who kills a bull, or lamb, or goat, in the camp, or who kills it outside the camp,", "bsb": "‘Anyone from the house of Israel who slaughters an ox, a lamb, or a goat in the camp or outside of it", "asv": "What man soever there be of the house of Israel, that killeth an ox, or lamb, or goat, in the camp, or that killeth it without the camp,", "ylt": "Any man of the house of Israel who slaughtereth ox, or lamb, or goat, in the camp, or who slaughtereth at the outside of the camp,", "tyndale": "whatsoeuer he be of the housse of Israel that kylleth an oxe, lambe or goote in the hoste or out of the hoste", "dra": "Any man whosoever of the house of Israel, if he kill an ox, or a sheep, or a goat in the camp, or without the camp,", "bbe": "If any man of Israel puts to death an ox or a lamb or a goat, in or outside the tent-circle;", "geneva": "Whosoeuer he be of the house of Israel that killeth a bullocke, or lambe, or goate in the hoste, or that killeth it out of the hoste,", "wycliffe": "and seide, Ech man of the hows of Israel schal be gilti of blood, if he sleeth an oxe , ether a scheep, ethir a geet in the castels, ethir out of the castels,", "rotherham": "What man soever, there be of the house of Israel, who slayeth an ox or lamb or goat, in the camp,—or who slayeth it outside the camp;", "darby": "Every one of the house of Israel that slaughtereth an ox, or sheep, or goat, in the camp, or that slaughtereth it out of the camp,", "twenty": "", "jps": "What man soever there be of the house of Israel, that killeth an ox, or lamb, or goat, in the camp, or that killeth it without the camp,", "acv": "Whatever man there is of the house of Israel, who kills an ox, or lamb, or goat, in the camp, or who kills it outside the camp,", "anderson": "", "haweis": "", "noyes": "", "webster": "Whatever man [there may be] of the house of Israel, that killeth an ox, or lamb, or goat in the camp, or that killeth [it] out of the camp,", "vulgate": "homo quilibet de domo Israhel si occiderit bovem aut ovem sive capram in castris vel extra castra;", "brenton": "Every man of the children of Israel, or of the strangers abiding among you, who shall kill a calf, or a sheep, or a goat in the camp, or who shall kill it out of the camp,"}}, {"v": 4, "ref": "17:4", "o": "וְ/אֶל פֶּ֜תַח אֹ֣הֶל מוֹעֵד֮ לֹ֣א הֱבִיא/וֹ֒ לְ/הַקְרִ֤יב קָרְבָּן֙ לַֽ/יהוָ֔ה לִ/פְנֵ֖י מִשְׁכַּ֣ן יְהוָ֑ה דָּ֣ם יֵחָשֵׁ֞ב לָ/אִ֤ישׁ הַ/הוּא֙ דָּ֣ם שָׁפָ֔ךְ וְ/נִכְרַ֛ת הָ/אִ֥ישׁ הַ/ה֖וּא מִ/קֶּ֥רֶב עַמּֽ/וֹ", "en": {"kjv": "And bringeth it not unto the door of the tabernacle of the congregation, to offer an offering unto the Lord before the tabernacle of the Lord; blood shall be imputed unto that man; he hath shed blood; and that man shall be cut off from among his people:", "web": "and hasn’t brought it to the door of the Tent of Meeting, to offer it as an offering to Yahweh before Yahweh’s tabernacle: blood shall be imputed to that man. He has shed blood; and that man shall be cut off from among his people.", "bsb": "instead of bringing it to the entrance to the Tent of Meeting to present it as an offering to the LORD before His tabernacle—that man shall incur bloodguilt. He has shed blood and must be cut off from among his people.", "asv": "and hath not brought it unto the door of the tent of meeting, to offer it as an oblation unto Jehovah before the tabernacle of Jehovah: blood shall be imputed unto that man; he hath shed blood; and that man shall be cut off from among his people:", "ylt": "and unto the opening of the tent of meeting hath not brought it in to bring near an offering to Jehovah before the tabernacle of Jehovah, blood is reckoned to that man--blood he hath shed--and that man hath been cut off from the midst of his people;", "tyndale": "and bryngeth the not vnto the dore of the tabernacle of witnesse, to offer an offerynge vnto the Lorde before the dwellynge place of the Lorde, bloude shalbe imputed vnto that man as though he had shed bloude and that man shall perysh from amonge his people.", "dra": "And offer it not at the door of the tabernacle an oblation to the Lord, shall be guilty of blood. As if he had shed blood, so shall he perish from the midst of his people.", "bbe": "And has not taken it to the door of the Tent of meeting, to make an offering to the Lord, before the Lord's House, its blood will be on him, for he has taken life, and he will be cut off from among his people:", "geneva": "And bringeth it not vnto the doore of the Tabernacle of the Congregation to offer an offring vnto the Lord before the Tabernacle of the Lord, blood shalbe imputed vnto that man: he hath shed blood, wherefore that man shall be cut off from among his people.", "wycliffe": "and offrith not an offryng to the Lord at the dore of the tabernacle; as he schedde mannus blood, so he schal perische fro the myddis of his puple.", "rotherham": "and, unto the entrance of the tent of meeting, bringeth it not in, to present it as an oblation unto Yahweh, before the habitation of Yahweh, blood, shall be imputed to that man—blood, hath he shed, therefore shall that man be cut off from the midst of his people:", "darby": "and doth not bring it to the entrance of the tent of meeting to present it as an offering to Jehovah, before the tabernacle of Jehovah, blood shall be reckoned unto that man: he hath shed blood; and that man shall be cut off from among his people,", "twenty": "", "jps": "and hath not brought it unto the door of the tent of meeting, to present it as an offering unto HaShem before the tabernacle of HaShem, blood shall be imputed unto that man; he hath shed blood; and that man shall be cut off from among his people.", "acv": "and has not brought it to the door of the tent of meeting, to offer it as an oblation to Jehovah before the tabernacle of Jehovah, blood shall be imputed to that man. He has shed blood, and that man shall be cut off from among his people,", "anderson": "", "haweis": "", "noyes": "", "webster": "And bringeth it not to the door of the tabernacle of the congregation, to offer an offering to the LORD before the tabernacle of the LORD; blood shall be imputed to that man; he hath shed blood; and that man shall be cut off from among his people:", "vulgate": "et non obtulerit ad ostium tabernaculi oblationem Domino sanguinis reus erit quasi sanguinem fuderit sic peribit de medio populi sui;", "brenton": "and shall not bring it to the door of the tabernacle of witness, so as to sacrifice it for a whole-burnt-offering or peace-offering to the Lord to be acceptable for a sweet-smelling savour: and whosoever shall slay it without, and shall not bring it to the door of the tabernacle of witness, so as to offer it as a gift to the Lord before the tabernacle of the Lord; blood shall be imputed to that man, he has shed blood; that soul shall be cut off from his people."}}, {"v": 5, "ref": "17:5", "o": "לְמַעַן֩ אֲשֶׁ֨ר יָבִ֜יאוּ בְּנֵ֣י יִשְׂרָאֵ֗ל אֶֽת זִבְחֵי/הֶם֮ אֲשֶׁ֣ר הֵ֣ם זֹבְחִים֮ עַל פְּנֵ֣י הַ/שָּׂדֶה֒ וֶֽ/הֱבִיאֻ֣/ם לַֽ/יהוָ֗ה אֶל פֶּ֛תַח אֹ֥הֶל מוֹעֵ֖ד אֶל הַ/כֹּהֵ֑ן וְ/זָ֨בְח֜וּ זִבְחֵ֧י שְׁלָמִ֛ים לַֽ/יהוָ֖ה אוֹתָֽ/ם", "en": {"kjv": "To the end that the children of Israel may bring their sacrifices, which they offer in the open field, even that they may bring them unto the Lord, unto the door of the tabernacle of the congregation, unto the priest, and offer them for peace offerings unto the Lord.", "web": "This is to the end that the children of Israel may bring their sacrifices, which they sacrifice in the open field, that they may bring them to Yahweh, to the door of the Tent of Meeting, to the priest, and sacrifice them for sacrifices of peace offerings to Yahweh.", "bsb": "For this reason the Israelites will bring to the LORD the sacrifices they have been offering in the open fields. They are to bring them to the priest at the entrance to the Tent of Meeting and offer them as sacrifices of peace to the LORD.", "asv": "to the end that the children of Israel may bring their sacrifices, which they sacrifice in the open field, even that they may bring them unto Jehovah, unto the door of the tent of meeting, unto the priest, and sacrifice them for sacrifices of peace-offerings unto Jehovah.", "ylt": "so that the sons of Israel do bring in their sacrifices which they are sacrificing on the face of the field, yea, they have brought them in to Jehovah, unto the opening of the tent of meeting, unto the priest, and they have sacrificed sacrifices of peace-offerings to Jehovah with them.", "tyndale": "Wherfore let the childern of Israel brynge their offerynges they offer in the wyde felde vnto the Lorde: euen vnto the dore of the tabernacle of witnesse and vnto the preast and offer the for peaseofferynges vnto the Lorde.", "dra": "Therefore the children of Israel shall bring to the priest their victims, which they kill in the field, that they may be sanctified to the Lord before the door of the tabernacle of the testimony: and they may sacrifice them for peace offerings to the Lord.", "bbe": "So that the children of Israel may take to the Lord, to the door of the Tent of meeting and to the priest, the offerings which they have put to death in the open country, and that they may make their peace-offerings to the Lord.", "geneva": "Therefore the children of Israel shall bring their offrings, which they would offer abroad in the fielde, and present the vnto ye Lord at the doore of the Tabernacle of ye Congregation by ye Priest, and offer them for peace offrings vnto the Lord.", "wycliffe": "Therfor the sones of Israel owen to offre her sacrifices to the preest, whiche thei sleen in the feeld, that tho be halewid to the Lord, bifor the dore of the tabernacle of witnessyng, and that thei offre tho pesible sacrifices to the Lord.", "rotherham": "to the end that the sons of Israel may bring in their sacrifices which they are offering upon the face of the field, that they may bring them in unto Yahweh—unto the entrance of the tent of meeting, unto the priest,—and that so as peace-offerings unto Yahweh, they may offer them.", "darby": "to the end that the children of Israel bring their sacrifices, which they sacrifice in the open field, that they bring them to Jehovah, unto the entrance of the tent of meeting, unto the priest, and sacrifice them as sacrifices of peace-offerings to Jehovah.", "twenty": "", "jps": "To the end that the children of Israel may bring their sacrifices, which they sacrifice in the open field, even that they may bring them unto HaShem, unto the door of the tent of meeting, unto the priest, and sacrifice them for sacrifices of peace-offerings unto HaShem.", "acv": "to the end that the sons of Israel may bring their sacrifices, which they sacrifice in the open field, even that they may bring them to Jehovah, to the door of the tent of meeting, to the priest, and sacrifice them for sacrifices of peace offerings to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "To the end that the children of Israel may bring their sacrifices which they offer in the open field, even that they may bring them to the LORD, to the door of the tabernacle of the congregation, to the priest, and offer them [for] peace-offerings to the LORD.", "vulgate": "ideo offerre debent sacerdoti filii Israhel hostias suas quas occidunt in agro ut sanctificentur Domino ante ostium tabernaculi testimonii et immolent eas hostias pacificas Domino;", "brenton": "That the children of Israel may offer their sacrifices, all that they shall slay in the fields, and bring them to the Lord unto the doors of the tabernacle of witness to the priest, and they shall sacrifice them as a peace-offering to the Lord."}}, {"v": 6, "ref": "17:6", "o": "וְ/זָרַ֨ק הַ/כֹּהֵ֤ן אֶת הַ/דָּם֙ עַל מִזְבַּ֣ח יְהוָ֔ה פֶּ֖תַח אֹ֣הֶל מוֹעֵ֑ד וְ/הִקְטִ֣יר הַ/חֵ֔לֶב לְ/רֵ֥יחַ נִיחֹ֖חַ לַ/יהוָֽה", "en": {"kjv": "And the priest shall sprinkle the blood upon the altar of the Lord at the door of the tabernacle of the congregation, and burn the fat for a sweet savour unto the Lord.", "web": "The priest shall sprinkle the blood on the altar of Yahweh at the door of the Tent of Meeting, and burn the fat for a pleasant aroma to Yahweh.", "bsb": "The priest will then sprinkle the blood on the altar of the LORD at the entrance to the Tent of Meeting and burn the fat as a pleasing aroma to the LORD.", "asv": "And the priest shall sprinkle the blood upon the altar of Jehovah at the door of the tent of meeting, and burn the fat for a sweet savor unto Jehovah.", "ylt": "`And the priest hath sprinkled the blood upon the altar of Jehovah, at the opening of the tent of meeting, and hath made perfume with the fat for sweet fragrance to Jehovah;", "tyndale": "And the preast shall sprinkle the bloude apon the alter of the Lorde in the dore of the tabernacle of wytnesse and burne the fatt to be a swete sauoure vnto the Lorde.", "dra": "And the priest shall pour the blood upon the altar of the Lord, at the door of the tabernacle of the testimony: and shall burn the fat for a sweet odour to the Lord.", "bbe": "And the priest will put blood on the altar of the Lord at the door of the Tent of meeting, burning the fat for a sweet smell to the Lord.", "geneva": "Then the Priest shall sprinkle the blood vpon the Altar of the Lord before the doore of the Tabernacle of the Congregation, and burne the fat for a sweete sauour vnto the Lord.", "wycliffe": "And the preest schal schede the blood on the auter of the Lord, at the dore of the tabernacle of witnessyng; and he schal brenne the ynnere fatnesse in to odour of swetnesse to the Lord.", "rotherham": "Then shall the priest dash the blood against the altar of Yahweh, at the entrance of the tent of meeting,—and shall make a perfume of the fat, as a satisfying odour unto Yahweh;", "darby": "And the priest shall sprinkle the blood upon the altar of Jehovah, at the entrance of the tent of meeting, and burn the fat for a sweet odour to Jehovah.", "twenty": "", "jps": "And the priest shall dash the blood against the altar of HaShem at the door of the tent of meeting, and make the fat smoke for a sweet savour unto HaShem.", "acv": "And the priest shall sprinkle the blood upon the altar of Jehovah at the door of the tent of meeting, and burn the fat for a sweet savor to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall sprinkle the blood upon the altar of the LORD [at] the door of the tabernacle of the congregation, and burn the fat for a sweet savor to the LORD.", "vulgate": "fundetque sacerdos sanguinem super altare Domini ad ostium tabernaculi testimonii et adolebit adipem in odorem suavitatis Domino;", "brenton": "And the priest shall pour the blood on the altar round about before the Lord by the doors of the tabernacle of witness, and shall offer the fat for a sweet-smelling savour to the Lord."}}, {"v": 7, "ref": "17:7", "o": "וְ/לֹא יִזְבְּח֥וּ עוֹד֙ אֶת זִבְחֵי/הֶ֔ם לַ/שְּׂעִירִ֕ם אֲשֶׁ֛ר הֵ֥ם זֹנִ֖ים אַחֲרֵי/הֶ֑ם חֻקַּ֥ת עוֹלָ֛ם תִּֽהְיֶה זֹּ֥את לָ/הֶ֖ם לְ/דֹרֹתָֽ/ם", "en": {"kjv": "And they shall no more offer their sacrifices unto devils, after whom they have gone a whoring. This shall be a statute for ever unto them throughout their generations.", "web": "They shall no more sacrifice their sacrifices to the goat idols, after which they play the prostitute. This shall be a statute forever to them throughout their generations.’", "bsb": "They must no longer offer their sacrifices to the goat demons to which they have prostituted themselves. This will be a permanent statute for them for the generations to come.’", "asv": "And they shall no more sacrifice their sacrifices unto the he-goats, after which they play the harlot. This shall be a statute forever unto them throughout their generations.", "ylt": "and they sacrifice not any more their sacrifices to goats after which they are going a-whoring; a statute age-during is this to them, to their generations.", "tyndale": "And let them nomoare offer their offerynges vnto deuyls after whom thy goo an whoorynge. And this shalbe an ordynauce for euer vnto you thorow out youre generacyons.", "dra": "And they shall no more sacrifice their victims to devils, with whom they have committed fornication. It shall be an ordinance for ever to them and to their posterity.", "bbe": "And let them make no more offerings to evil spirits, after which they have gone, turning away from the Lord. Let this be a law to them for ever, through all their generations.", "geneva": "And they shall no more offer their offerings vnto deuils, after whom they haue gone a whoring: this shalbe an ordinance for euer vnto them in their generations.", "wycliffe": "And thei schulen no more offre her sacrifices to fendis, with whiche thei diden fornycacioun; it schal be a lawful thing euerlastynge to hem, and to the aftircomeris `of hem.", "rotherham": "so shall they no more offer their sacrifices unto demons after whom they are unchastely going away,—a statute age-abiding, shall this be to them unto their generations.", "darby": "And they shall no more sacrifice their sacrifices unto demons, after whom they go a whoring. This shall be an everlasting statute unto them for their generations.", "twenty": "", "jps": "And they shall no more sacrifice their sacrifices unto the satyrs, after whom they go astray. This shall be a statute for ever unto them throughout their generations.", "acv": "And they shall no more sacrifice their sacrifices to the he-goats, after which they play the harlot. This shall be a statute forever to them throughout their generations.", "anderson": "", "haweis": "", "noyes": "", "webster": "And they shall no more offer their sacrifices to idols, with which they have committed idolatry: This shall be a statute for ever to them throughout their generations.", "vulgate": "et nequaquam ultra immolabunt hostias suas daemonibus cum quibus fornicati sunt legitimum sempiternum erit illis et posteris eorum;", "brenton": "And they shall no longer offer their sacrifices to vain gods after which they go a whoring; it shall be a perpetual statute to you for your generations."}}, {"v": 8, "ref": "17:8", "o": "וַ/אֲלֵ/הֶ֣ם תֹּאמַ֔ר אִ֥ישׁ אִישׁ֙ מִ/בֵּ֣ית יִשְׂרָאֵ֔ל וּ/מִן הַ/גֵּ֖ר אֲשֶׁר יָג֣וּר בְּ/תוֹכָ֑/ם אֲשֶׁר יַעֲלֶ֥ה עֹלָ֖ה אוֹ זָֽבַח", "en": {"kjv": "And thou shalt say unto them, Whatsoever man there be of the house of Israel, or of the strangers which sojourn among you, that offereth a burnt offering or sacrifice,", "web": "“You shall say to them, ‘Any man there is of the house of Israel, or of the strangers who live as foreigners among them, who offers a burnt offering or sacrifice,", "bsb": "Tell them that if anyone from the house of Israel or any foreigner living among them offers a burnt offering or a sacrifice", "asv": "And thou shalt say unto them, Whatsoever man there be of the house of Israel, or of the strangers that sojourn among them, that offereth a burnt-offering or sacrifice,", "ylt": "`And unto them thou sayest: Any man of the house of Israel, or of the sojourners, who sojourneth in your midst, who causeth burnt-offering or sacrifice to ascend,", "tyndale": "And thou shalt saye vnto them: what soeuer man it be of the housse of Israel or of the straungers that sogeorne amonge you that offereth a burntofferynge or any other offerynge", "dra": "And thou shalt say to them: The man of the house of Israel, and of the strangers who sojourn among you, that offereth a holocaust or a victim,", "bbe": "And say to them, If any man of Israel, or any other living among them, makes a burned offering or other offering,", "geneva": "Also thou shalt say vnto them, whosoeuer he be of the house of Israel, or of the strangers which soiourne among them, that offreth a burnt offring or sacrifice,", "wycliffe": "And thou schalt seie to hem, A man of the hows of Israel, and of the comelyngis that ben pilgryms among you, that offrith a brent sacrifice, ethir a slayn sacrifice,", "rotherham": "Wherefore, unto them, shalt thou say: What man soever, there may be of the house of Israel, or of the sojourners that sojourn in their midst,—who causeth to go up an ascending-offering, or a sacrifice;", "darby": "And thou shalt say unto them, Every one of the house of Israel, and of the strangers who sojourn among them, that offereth up a burnt-offering or sacrifice,", "twenty": "", "jps": "And thou shalt say unto them: Whatsoever man there be of the house of Israel, or of the strangers that sojourn among them, that offereth a burnt-offering or sacrifice,", "acv": "And thou shall say to them, Whatever man there is of the house of Israel, or of the strangers that sojourn among them, who offers a burnt offering or sacrifice,", "anderson": "", "haweis": "", "noyes": "", "webster": "And thou shalt say to them, Whatever man [there may be] of the house of Israel, or of the strangers which sojourn among you, that offereth a burnt-offering or sacrifice,", "vulgate": "et ad ipsos dices homo de domo Israhel et de advenis qui peregrinantur apud vos qui obtulerit holocaustum sive victimam;", "brenton": "And thou shalt say to them, Whatever man of the children of Israel, or of the sons of the proselytes abiding among you, shall offer a whole-burnt-offering or a sacrifice,"}}, {"v": 9, "ref": "17:9", "o": "וְ/אֶל פֶּ֜תַח אֹ֤הֶל מוֹעֵד֙ לֹ֣א יְבִיאֶ֔/נּוּ לַ/עֲשׂ֥וֹת אֹת֖/וֹ לַ/יהוָ֑ה וְ/נִכְרַ֛ת הָ/אִ֥ישׁ הַ/ה֖וּא מֵ/עַמָּֽי/ו", "en": {"kjv": "And bringeth it not unto the door of the tabernacle of the congregation, to offer it unto the Lord; even that man shall be cut off from among his people.", "web": "and doesn’t bring it to the door of the Tent of Meeting, to sacrifice it to Yahweh; that man shall be cut off from his people.", "bsb": "but does not bring it to the entrance to the Tent of Meeting to sacrifice it to the LORD, that man must be cut off from his people.", "asv": "and bringeth it not unto the door of the tent of meeting, to sacrifice it unto Jehovah; that man shall be cut off from his people.", "ylt": "and unto the opening of the tent of meeting doth not bring it in to make it to Jehovah--that man hath been cut off from his people.", "tyndale": "and bryngeth it not vnto the dore of the tabernacle of wytnesse to offer vnto the Lorde, that felow shall perysh from amonge his people.", "dra": "And bringeth it not to the door of the tabernacle of the testimony, that it may be offered to the Lord, shall perish from among his people.", "bbe": "And does not take it to the door of the Tent of meeting to make an offering to the Lord, that man will be cut off from among his people.", "geneva": "And bringeth it not vnto ye doore of the Tabernacle of the Congregation to offer it vnto the Lord, euen that man shall be cut off from his people.", "wycliffe": "and bryngith it not to the dore of the tabernacle of witnessyng, that it be offrid to the Lord, schal perische fro his puple.", "rotherham": "and unto the entrance of the tent of meeting, doth not bring it in, to offer it unto Yahweh, then shall that man be cut off from among his kinsfolk.", "darby": "and bringeth it not to the entrance of the tent of meeting, to offer it up to Jehovah — that man shall be cut off from his peoples.", "twenty": "", "jps": "and bringeth it not unto the door of the tent of meeting, to sacrifice it unto HaShem, even that man shall be cut off from his people.", "acv": "and does not bring it to the door of the tent of meeting, to sacrifice it to Jehovah, that man shall be cut off from his people.", "anderson": "", "haweis": "", "noyes": "", "webster": "And bringeth it not to the door of the tabernacle of the congregation, to offer it to the LORD; even that man shall be cut off from among his people.", "vulgate": "et ad ostium tabernaculi testimonii non adduxerit eam ut offeratur Domino interibit de populo suo;", "brenton": "and shall not bring it to the door of the tabernacle of witness to sacrifice it to the Lord, that man shall be destroyed from among his people."}}, {"v": 10, "ref": "17:10", "o": "וְ/אִ֨ישׁ אִ֜ישׁ מִ/בֵּ֣ית יִשְׂרָאֵ֗ל וּ/מִן הַ/גֵּר֙ הַ/גָּ֣ר בְּ/תוֹכָ֔/ם אֲשֶׁ֥ר יֹאכַ֖ל כָּל דָּ֑ם וְ/נָתַתִּ֣י פָנַ֗/י בַּ/נֶּ֨פֶשׁ֙ הָ/אֹכֶ֣לֶת אֶת הַ/דָּ֔ם וְ/הִכְרַתִּ֥י אֹתָ֖/הּ מִ/קֶּ֥רֶב עַמָּֽ/הּ", "en": {"kjv": "And whatsoever man there be of the house of Israel, or of the strangers that sojourn among you, that eateth any manner of blood; I will even set my face against that soul that eateth blood, and will cut him off from among his people.", "web": "“‘Any man of the house of Israel, or of the strangers who live as foreigners among them, who eats any kind of blood, I will set my face against that soul who eats blood, and will cut him off from among his people.", "bsb": "If anyone from the house of Israel or a foreigner living among them eats any blood, I will set My face against that person and cut him off from among his people.", "asv": "And whatsoever man there be of the house of Israel, or of the strangers that sojourn among them, that eateth any manner of blood, I will set my face against that soul that eateth blood, and will cut him off from among his people.", "ylt": "`And any man of the house of Israel, or of the sojourners, who is sojourning in your midst, who eateth any blood, I have even set My face against the person who is eating the blood, and have cut him off from the midst of his people;", "tyndale": "And what soeuer man it be of the housse of Israel or of the straungers that soiourne amonge you that eateth any maner of bloude I will set my face agaynst that soule that eateth bloude, and will destroy him from amonge his people.", "dra": "If any man whosoever of the house of Israel, and of the strangers that sojourn among them, eat blood, I will set my face against his soul, and will cut him off from among his people.", "bbe": "And if any man of Israel, or any other living among them, takes any sort of blood for food, my wrath will be turned against that man and he will be cut off from among his people.", "geneva": "Likewise whosoeuer he be of the house of Israel, or of the strangers that soiourne among them, that eateth any blood, I will euen set my face against that person that eateth blood, and will cut him off from among his people.", "wycliffe": "If ony man of the sones of Israel, and of comelyngis that ben pilgryms among you, etith blood , Y schal sette faste my face ayens `the soule of hym, and Y schal leese hym fro his puple;", "rotherham": "And, what man soever, there may be of the house of Israel, or of the sojourners that sojourn in their midst, that partaketh of any manner of blood, then will I set my face against the person that partaketh of the blood, and will cut him off from the midst of his people.", "darby": "And every one of the house of Israel, or of the strangers who sojourn among them, that eateth any manner of blood, — I will set my face against the soul that hath eaten blood, and will cut him off from among his people;", "twenty": "", "jps": "And whatsoever man there be of the house of Israel, or of the strangers that sojourn among them, that eateth any manner of blood, I will set My face against that soul that eateth blood, and will cut him off from among his people.", "acv": "And whatever man there is of the house of Israel, or of the strangers that sojourn among them, who eats any manner of blood, I will set my face against that soul who eats blood, and will cut him off from among his people.", "anderson": "", "haweis": "", "noyes": "", "webster": "And whatever man [there may be] of the house of Israel, or of the strangers that sojourn among you, that eateth any manner of blood; I will even set my face against that soul that eateth blood, and will cut him off from among his people.", "vulgate": "homo quilibet de domo Israhel et de advenis qui peregrinantur inter eos si comederit sanguinem obfirmabo faciem meam contra animam illius et disperdam eam de populo suo;", "brenton": "And whatever man of the children of Israel, or of the strangers abiding among you, shall eat any blood, I will even set my face against that soul that eats blood, and will destroy it from its people."}}, {"v": 11, "ref": "17:11", "o": "כִּ֣י נֶ֣פֶשׁ הַ/בָּשָׂר֮ בַּ/דָּ֣ם הִוא֒ וַ/אֲנִ֞י נְתַתִּ֤י/ו לָ/כֶם֙ עַל הַ/מִּזְבֵּ֔חַ לְ/כַפֵּ֖ר עַל נַפְשֹׁתֵי/כֶ֑ם כִּֽי הַ/דָּ֥ם ה֖וּא בַּ/נֶּ֥פֶשׁ יְכַפֵּֽר", "en": {"kjv": "For the life of the flesh is in the blood: and I have given it to you upon the altar to make an atonement for your souls: for it is the blood that maketh an atonement for the soul.", "web": "For the life of the flesh is in the blood; and I have given it to you on the altar to make atonement for your souls: for it is the blood that makes atonement by reason of the life.", "bsb": "For the life of the flesh is in the blood, and I have given it to you to make atonement for your souls upon the altar; for it is the blood that makes atonement for the soul.", "asv": "For the life of the flesh is in the blood; and I have given it to you upon the altar to make atonement for your souls: for it is the blood that maketh atonement by reason of the life.", "ylt": "for the life of the flesh is in the blood, and I have given it to you on the altar, to make atonement for your souls; for it is the blood which maketh atonement for the soul.", "tyndale": "for the life of the flesh is in the bloude, and I haue geuen it vnto you apon the alter, to make an attonement for youre soules,", "dra": "Because the life of the flesh is in the blood: and I have given it to you, that you may make atonement with it upon the altar for your souls, and the blood may be for an expiation of the soul.", "bbe": "For the life of the flesh is in its blood; and I have given it to you on the altar to take away your sin: for it is the blood which makes free from sin because of the life in it.", "geneva": "For the life of the flesh is in the blood, and I haue giuen it vnto you to offer vpon the altar, to make an atonement for your soules: for this blood shall make an atonement for the soule.", "wycliffe": "for the lijf of fleisch is in blood, and Y yaf that blood to you, that ye clense on myn auter `for youre soulis, and that the blood be for the synne of soule.", "rotherham": "For as for the life of the flesh, in the blood, it is, therefore have, I, given it unto you upon the altar, to put a propitiatory-covering over your lives,—for the blood, it is, which, by virtue of the life, maketh propitiation.", "darby": "for the soul of the flesh is in the blood; and I have given it to you upon the altar to make atonement for your souls, for it is the blood that maketh atonement for the soul.", "twenty": "", "jps": "For the life of the flesh is in the blood; and I have given it to you upon the altar to make atonement for your souls; for it is the blood that maketh atonement by reason of the life.", "acv": "For the life of the flesh is in the blood, and I have given it to you upon the altar to make atonement for your souls, for it is the blood that makes atonement by reason of the life.", "anderson": "", "haweis": "", "noyes": "", "webster": "For the life of the flesh [is] in the blood: and I have given it to you upon the altar, to make an atonement for your souls: for it [is] the blood [that] maketh an atonement for the soul.", "vulgate": "quia anima carnis in sanguine est et ego dedi illum vobis ut super altare in eo expietis pro animabus vestris et sanguis pro animae piaculo sit;", "brenton": "For the life of flesh is its blood, and I have given it to you on the altar to make atonement for your souls; for its blood shall make atonement for the soul."}}, {"v": 12, "ref": "17:12", "o": "עַל כֵּ֤ן אָמַ֨רְתִּי֙ לִ/בְנֵ֣י יִשְׂרָאֵ֔ל כָּל נֶ֥פֶשׁ מִ/כֶּ֖ם לֹא תֹ֣אכַל דָּ֑ם וְ/הַ/גֵּ֛ר הַ/גָּ֥ר בְּ/תוֹכְ/כֶ֖ם לֹא יֹ֥אכַל דָּֽם", "en": {"kjv": "Therefore I said unto the children of Israel, No soul of you shall eat blood, neither shall any stranger that sojourneth among you eat blood.", "web": "Therefore I have said to the children of Israel, “No person among you shall eat blood, neither shall any stranger who lives as a foreigner among you eat blood.”", "bsb": "Therefore I say to the Israelites, ‘None of you may eat blood, nor may any foreigner living among you eat blood.’", "asv": "Therefore I said unto the children of Israel, No soul of you shall eat blood, neither shall any stranger that sojourneth among you eat blood.", "ylt": "`Therefore I have said to the sons of Israel, No person among you doth eat blood, and the sojourner who is sojourning in your midst doth not eat blood;", "tyndale": "for bloude shall make an attonemet for the soule. And therfore I sayde vnto the childern of Israel: se that no soule of you eate bloude nor yet any straunger that soiourneth amonge you.", "dra": "Therefore I have said to the children of Israel: No soul of you, nor of the strangers that sojourn among you, shall eat blood.", "bbe": "For this reason I have said to the children of Israel, No man among you, or any others living with you, may take blood as food.", "geneva": "Therefore I saide vnto ye children of Israel, None of you shall eate blood: neither the stranger that soiourneth among you, shall eate blood.", "wycliffe": "Therfor Y seide to the sones of Israel, Ech lyuynge man of you schal not ete blood, nethir of the comelyngis that ben pilgryms among you.", "rotherham": "For this cause, have I said unto the sons of Israel, Not a person from among you shall partake of blood,—Even the sojourner that sojourneth in your midst, shall not partake of blood.", "darby": "Therefore have I said unto the children of Israel, No soul of you shall eat blood, neither shall the stranger who sojourneth among you eat blood.", "twenty": "", "jps": "Therefore I said unto the children of Israel: No soul of you shall eat blood, neither shall any stranger that sojourneth among you eat blood.", "acv": "Therefore I said to the sons of Israel, No soul of you shall eat blood, nor shall any stranger that sojourns among you eat blood.", "anderson": "", "haweis": "", "noyes": "", "webster": "Therefore I said to the children of Israel, No soul of you shall eat blood, neither shall any stranger that sojourneth among you eat blood.", "vulgate": "idcirco dixi filiis Israhel omnis anima ex vobis non comedet sanguinem nec ex advenis qui peregrinantur inter vos;", "brenton": "Therefore I said to the children of Israel, No soul of you shall eat blood, and the stranger that abides among you shall not eat blood."}}, {"v": 13, "ref": "17:13", "o": "וְ/אִ֨ישׁ אִ֜ישׁ מִ/בְּנֵ֣י יִשְׂרָאֵ֗ל וּ/מִן הַ/גֵּר֙ הַ/גָּ֣ר בְּ/תוֹכָ֔/ם אֲשֶׁ֨ר יָצ֜וּד צֵ֥יד חַיָּ֛ה אוֹ ע֖וֹף אֲשֶׁ֣ר יֵאָכֵ֑ל וְ/שָׁפַךְ֙ אֶת דָּמ֔/וֹ וְ/כִסָּ֖/הוּ בֶּ/עָפָֽר", "en": {"kjv": "And whatsoever man there be of the children of Israel, or of the strangers that sojourn among you, which hunteth and catcheth any beast or fowl that may be eaten; he shall even pour out the blood thereof, and cover it with dust.", "web": "“‘Whatever man there is of the children of Israel, or of the strangers who live as foreigners among them, who takes in hunting any animal or bird that may be eaten; he shall pour out its blood, and cover it with dust.", "bsb": "And if any Israelite or foreigner living among them hunts down a wild animal or bird that may be eaten, he must drain its blood and cover it with dirt.", "asv": "And whatsoever man there be of the children of Israel, or of the strangers that sojourn among them, who taketh in hunting any beast or bird that may be eaten; he shall pour out the blood thereof, and cover it with dust.", "ylt": "and any man of the sons of Israel, or of the sojourners, who is sojourning in your midst, who hunteth venison, beast or fowl, which is eaten--hath even poured out its blood, and hath covered it with dust;", "tyndale": "What soeuer man it be of the childern of Israel or of the straungers that soiurne amonge you that honteth and catcheth any beest or foule that maye be eate, he shall poure out the bloude ad couer it with erthe.", "dra": "Any man whosoever of the children of Israel, and of the strangers that sojourn among you, if by hunting or fowling, he take a wild beast or a bird, which is lawful to eat, let him pour out its blood, and cover it with earth.", "bbe": "And any man of Israel, or any other living among them, who gets with his bow any beast or bird used for food, is to see that its blood is covered with earth.", "geneva": "Moreouer whosoeuer he be of the children of Israel, or of the strangers that soiourne among the, which by hunting taketh any beast or foule that may be eaten, he shall powre out the blood thereof, and couer it with dust:", "wycliffe": "What euer man of the sones of Israel, and of the comelyngis that ben pilgryms anentis you, takith a wielde beeste, ethir a brid, whiche it is leueful to ete, whether bi huntyng, whether bi haukyng, schede the blood therof, and hile it with erthe;", "rotherham": "And, what man soever, there may be of the sons of Israel, or of the sojourners that sojourn in their midst, who taketh by hunting any wild-beast or bird that may be eaten, then shall he pour out the blood thereof, and cover it with dust;", "darby": "And every one of the children of Israel, and of the strangers who sojourn among them, that catcheth in the hunt a beast or fowl that may be eaten, he shall pour out the blood thereof, and cover it with earth;", "twenty": "", "jps": "And whatsoever man there be of the children of Israel, or of the strangers that sojourn among them, that taketh in hunting any beast or fowl that may be eaten, he shall pour out the blood thereof, and cover it with dust.", "acv": "And whatever man there is of the sons of Israel, or of the strangers that sojourn among them, who takes any beast or bird in hunting that may be eaten, he shall pour out the blood of it, and cover it with dust.", "anderson": "", "haweis": "", "noyes": "", "webster": "And whatever man [there may be] of the children of Israel, or of the strangers that sojourn among you, who hunteth and catcheth any beast or fowl that may be eaten; he shall even pour out its blood, and cover it with dust.", "vulgate": "homo quicumque de filiis Israhel et de advenis qui peregrinantur apud vos si venatione atque aucupio ceperit feram vel avem quibus vesci licitum est fundat sanguinem eius et operiat illum terra;", "brenton": "And whatever man of the children of Israel, or of the strangers abiding among you shall take any animal in hunting, beast, or bird, which is eaten, then shall he pour out the blood, and cover it in the dust."}}, {"v": 14, "ref": "17:14", "o": "כִּֽי נֶ֣פֶשׁ כָּל בָּשָׂ֗ר דָּמ֣/וֹ בְ/נַפְשׁ/וֹ֮ הוּא֒ וָֽ/אֹמַר֙ לִ/בְנֵ֣י יִשְׂרָאֵ֔ל דַּ֥ם כָּל בָּשָׂ֖ר לֹ֣א תֹאכֵ֑לוּ כִּ֣י נֶ֤פֶשׁ כָּל בָּשָׂר֙ דָּמ֣/וֹ הִ֔וא כָּל אֹכְלָ֖י/ו יִכָּרֵֽת", "en": {"kjv": "For it is the life of all flesh; the blood of it is for the life thereof: therefore I said unto the children of Israel, Ye shall eat the blood of no manner of flesh: for the life of all flesh is the blood thereof: whosoever eateth it shall be cut off.", "web": "For as to the life of all flesh, its blood is with its life: therefore I said to the children of Israel, “You shall not eat the blood of any kind of flesh; for the life of all flesh is its blood. Whoever eats it shall be cut off.”", "bsb": "For the life of all flesh is its blood. Therefore I have told the Israelites, ‘You must not eat the blood of any living thing, because the life of all flesh is its blood; whoever eats it must be cut off.’", "asv": "For as to the life of all flesh, the blood thereof is all one with the life thereof: therefore I said unto the children of Israel, Ye shall eat the blood of no manner of flesh; for the life of all flesh is the blood thereof: whosoever eateth it shall be cut off.", "ylt": "for it is the life of all flesh, its blood is for its life; and I say to the sons of Israel, Blood of any flesh ye do not eat, for the life of all flesh is its blood; any one eating it is cut off.", "tyndale": "for the life of all flesh is in the bloude, therfore I sayde vnto the childern of Israel, ye shall eate the bloude of no maner of flesh. for the life of all flesh is in his bloude, and whosoeuer therfore eateth it shall perysh.", "dra": "For the life of all flesh is in the blood. Therefore I said to the children of Israel: you shall not eat the blood of any flesh at all, because the life of the flesh is in the blood, and whosoever eateth it, shall be cut off.", "bbe": "For the blood is the life of all flesh: and so I have said to the children of Israel, You may not take any sort of blood as food, and any man who does so will be cut of.", "geneva": "For ye life of all flesh is his blood, it is ioyned with his life: therefore I sayd vnto the children of Israel, Ye shall eate the blood of no flesh: for the life of al flesh is the blood thereof: whosoeuer eateth it, shalbe cut off.", "wycliffe": "for the lijf of ech fleisch is in blood. Wherfor Y seide to the sones of Israel, Ye schulen not ete the blood of ony fleisch, for the lijf of fleisch is in blood, and who euer etith blood, schal perische.", "rotherham": "for, as for the life of all flesh, the blood thereof, for the life thereof, standeth, therefore have I said unto the sons of Israel—Of the blood of no manner of flesh, shall ye partake, For, the life of all flesh is the blood thereof; whoso partaketh thereof, shall be cut off.", "darby": "for as to the life of all flesh, its blood is the life in it; and I have said unto the children of Israel, Of the blood of no manner of flesh shall ye eat, for the life of all flesh is its blood: whoever eateth it shall be cut off.", "twenty": "", "jps": "For as to the life of all flesh, the blood thereof is all one with the life thereof; therefore I said unto the children of Israel: Ye shall eat the blood of no manner of flesh; for the life of all flesh is the blood thereof; whosoever eateth it shall be cut off.", "acv": "For as to the life of all flesh, the blood of it is with the life of it. Therefore I said to the sons of Israel, Ye shall eat the blood of no manner of flesh, for the life of all flesh is the blood of it. Whoever eats it shall be cut off.", "anderson": "", "haweis": "", "noyes": "", "webster": "For [it is] the life of all flesh, the blood of it [is] for the life of it; therefore I said to the children of Israel, Ye shall eat the blood of no manner of flesh: for the life of all flesh [is] its blood: whoever eateth it shall be cut off.", "vulgate": "anima enim omnis carnis in sanguine est unde dixi filiis Israhel sanguinem universae carnis non comedetis quia anima carnis in sanguine est et quicumque comederit illum interibit;", "brenton": "For the blood of all flesh is its life; and I said to the children of Israel, Ye shall not eat the blood of any flesh, for the life of all flesh is its blood: every one that eats it shall be destroyed."}}, {"v": 15, "ref": "17:15", "o": "וְ/כָל נֶ֗פֶשׁ אֲשֶׁ֨ר תֹּאכַ֤ל נְבֵלָה֙ וּ/טְרֵפָ֔ה בָּ/אֶזְרָ֖ח וּ/בַ/גֵּ֑ר וְ/כִבֶּ֨ס בְּגָדָ֜י/ו וְ/רָחַ֥ץ בַּ/מַּ֛יִם וְ/טָמֵ֥א עַד הָ/עֶ֖רֶב וְ/טָהֵֽר", "en": {"kjv": "And every soul that eateth that which died of itself, or that which was torn with beasts, whether it be one of your own country, or a stranger, he shall both wash his clothes, and bathe himself in water, and be unclean until the even: then shall he be clean.", "web": "“‘Every person that eats what dies of itself, or that which is torn by animals, whether he is native-born or a foreigner, he shall wash his clothes, and bathe himself in water, and be unclean until the evening: then he shall be clean.", "bsb": "And any person, whether native or foreigner, who eats anything found dead or mauled by wild beasts must wash his clothes and bathe with water, and he will be unclean until evening; then he will be clean.", "asv": "And every soul that eateth that which dieth of itself, or that which is torn of beasts, whether he be home-born or a sojourner, he shall wash his clothes, and bathe himself in water, and be unclean until the even: then shall he be clean.", "ylt": "`And any person who eateth a carcase or torn thing, among natives or among sojourners--hath both washed his garments, and hath bathed with water, and hath been unclean until the evening--then he hath been clean;", "tyndale": "And what soeuer soule it be that eateth that which dyed alone or that which was torne with wylde beestes: whether it be one of youre selues or a straunger, he shall wasshe his clothes ad bathe him selfe in water, ad shalbe vncleane vnto the eue, ad tha is he cleane.", "dra": "The soul that eateth that which died of itself, or has been caught by a beast, whether he be one of your own country or a stranger, shall wash his clothes and himself with water, and shall be defiled until the evening: and in this manner he shall be made clean.", "bbe": "And anyone who takes as food anything which has come to a natural end, or anything which has been put to death by beasts, if he is one of you by birth, or of another nation, will have to have his clothing washed and his body bathed in water and be unclean till evening, and then he will be clean.", "geneva": "And euery person that eateth it which dyeth alone, or that which is torne with beastes, whether it be one of the same countrey or a stranger, he shall both wash his clothes, and wash himselfe in water, and be vncleane vnto the euen: after he shalbe cleane.", "wycliffe": "A man that etith a thing deed bi it silf, ethir takun of a beeste, as wel of men borun in the lond, as of comelyngis, he schal waische hise clothis and hym silf in watir, and he schal be `defoulid til to euentid; and by this ordre he schal be maad cleene; that if he waischith not his clothis,", "rotherham": "And, in the case of any person who eateth that which died of itself or was torn in pieces, whether he be home-born, or a sojourner, then shall he wash his clothes, and bathe in water, and be unclean until the evening, and then be clean.", "darby": "And every soul that eateth of a dead carcase, or of that which was torn, be it one home-born, or a stranger, he shall wash his clothes, and bathe in water, and be unclean until the even: then he shall be clean.", "twenty": "", "jps": "And every soul that eateth that which dieth of itself, or that which is torn of beasts, whether he be home-born or a stranger, he shall wash his clothes, and bathe himself in water, and be unclean until the even; then shall he be clean.", "acv": "And every soul who eats that which dies of itself, or that which is torn of beasts, whether he be home-born or a sojourner, he shall wash his clothes, and bathe himself in water, and be unclean until the evening, then he shall be clean.", "anderson": "", "haweis": "", "noyes": "", "webster": "And every soul that eateth that which died [of itself], or that which was torn [with beasts], ([whether it is] one of your own country, or a stranger) he shall both wash his clothes, and bathe [himself] in water, and be unclean until the evening; then shall he be clean.", "vulgate": "anima quae comederit morticinum vel captum a bestia tam de indigenis quam de advenis lavabit vestes suas et semet ipsum aqua et contaminatus erit usque ad vesperum et hoc ordine mundus fiet;", "brenton": "And every soul which eats that which has died of itself, or is taken of beasts, either among the natives or among the strangers, shall wash his garments, and bathe himself in water, and shall be unclean until evening: then shall he be clean."}}, {"v": 16, "ref": "17:16", "o": "וְ/אִם֙ לֹ֣א יְכַבֵּ֔ס וּ/בְשָׂר֖/וֹ לֹ֣א יִרְחָ֑ץ וְ/נָשָׂ֖א עֲוֺנֽ/וֹ", "en": {"kjv": "But if he wash them not, nor bathe his flesh; then he shall bear his iniquity.", "web": "But if he doesn’t wash them, or bathe his flesh, then he shall bear his iniquity.’”", "bsb": "But if he does not wash his clothes and bathe himself, then he shall bear his iniquity.”", "asv": "But if he wash them not, nor bathe his flesh, then he shall bear his iniquity.", "ylt": "and if he wash not, and his flesh bathe not--then he hath borne his iniquity.'", "tyndale": "But ad yf he wasshe them not nor wasshe his flesh he shall beare his synne.", "dra": "But if he do not wash his clothes, and his body, he shall bear his iniquity.", "bbe": "But if his clothing is not washed and his body bathed, his sin will be on him.", "geneva": "But if he wash them not, nor wash his flesh, then he shall beare his iniquitie.", "wycliffe": "ether his bodi, he schal bere his wickidnesse.", "rotherham": "But, if he wash them not, and his flesh, he do not bathe, then shall he bear his iniquity.", "darby": "And if he wash them not nor bathe his flesh, then he shall bear his iniquity.", "twenty": "", "jps": "But if he wash them not, nor bathe his flesh, then he shall bear his iniquity.", "acv": "But if he does not wash them, nor bathe his flesh, then he shall bear his iniquity.", "anderson": "", "haweis": "", "noyes": "", "webster": "But if he doth not wash [them], nor bathe his flesh; then he shall bear his iniquity.", "vulgate": "quod si non laverit vestimenta sua nec corpus portabit iniquitatem suam;", "brenton": "But if he do not wash his garments, and do not bathe his body in water, then shall he bear his iniquity."}}]}, {"c": 18, "verses": [{"v": 1, "ref": "18:1", "o": "וַ/יְדַבֵּ֥ר יְהוָ֖ה אֶל מֹשֶׁ֥ה לֵּ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh said to Moses,", "bsb": "Then the LORD said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde talked with Moses saynge:", "dra": "And the Lord spoke to Moses, saying:", "bbe": "And the Lord said to Moses,", "geneva": "And the Lord spake vnto Moses, saying,", "wycliffe": "And the Lord spak to Moises, and seide, Speke thou to the sones of Israel,", "rotherham": "And Yahweh spake unto Moses, saying:", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses, saying:", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "locutusque est Dominus ad Mosen dicens;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 2, "ref": "18:2", "o": "דַּבֵּר֙ אֶל בְּנֵ֣י יִשְׂרָאֵ֔ל וְ/אָמַרְתָּ֖ אֲלֵ/הֶ֑ם אֲנִ֖י יְהוָ֥ה אֱלֹהֵי/כֶֽם", "en": {"kjv": "Speak unto the children of Israel, and say unto them, I am the Lord your God.", "web": "“Speak to the children of Israel, and say to them, ‘I am Yahweh your God.", "bsb": "“Speak to the Israelites and tell them: I am the LORD your God.", "asv": "Speak unto the children of Israel, and say unto them, I am Jehovah your God.", "ylt": "`Speak unto the sons of Israel, and thou hast said unto them, I am Jehovah your God;", "tyndale": "speake vnto the childern of Israel, ad saye vnto them, I am the Lorde youre God", "dra": "Speak to the children of Israel, and thou shalt say to them: I am the Lord your God.", "bbe": "Say to the children of Israel, I am the Lord your God.", "geneva": "Speake vnto the children of Israel, and say vnto them, I am the Lord your God.", "wycliffe": "and thou schalt seie to hem, Y am youre Lord God;", "rotherham": "Speak unto the sons of Israel, and thou shalt say unto them,—I—Yahweh, am your God:—", "darby": "Speak unto the children of Israel, and say unto them, I am Jehovah yourGod.", "twenty": "", "jps": "Speak unto the children of Israel, and say unto them: I am HaShem your G-d.", "acv": "Speak to the sons of Israel, and say to them, I am Jehovah your God.", "anderson": "", "haweis": "", "noyes": "", "webster": "Speak to the children of Israel, and say to them, I [am] the LORD your God.", "vulgate": "loquere filiis Israhel et dices ad eos ego Dominus Deus vester;", "brenton": "Speak to the children of Israel, and thou shalt say to them, I am the Lord your God."}}, {"v": 3, "ref": "18:3", "o": "כְּ/מַעֲשֵׂ֧ה אֶֽרֶץ מִצְרַ֛יִם אֲשֶׁ֥ר יְשַׁבְתֶּם בָּ֖/הּ לֹ֣א תַעֲשׂ֑וּ וּ/כְ/מַעֲשֵׂ֣ה אֶֽרֶץ כְּנַ֡עַן אֲשֶׁ֣ר אֲנִי֩ מֵבִ֨יא אֶתְ/כֶ֥ם שָׁ֨מָּ/ה֙ לֹ֣א תַעֲשׂ֔וּ וּ/בְ/חֻקֹּתֵי/הֶ֖ם לֹ֥א תֵלֵֽכוּ", "en": {"kjv": "After the doings of the land of Egypt, wherein ye dwelt, shall ye not do: and after the doings of the land of Canaan, whither I bring you, shall ye not do: neither shall ye walk in their ordinances.", "web": "You shall not do as they do in the land of Egypt, where you lived: and you shall not do as they do in the land of Canaan, where I am bringing you; neither shall you walk in their statutes.", "bsb": "You must not follow the practices of the land of Egypt, where you used to live, and you must not follow the practices of the land of Canaan, into which I am bringing you. You must not walk in their customs.", "asv": "After the doings of the land of Egypt, wherein ye dwelt, shall ye not do: and after the doings of the land of Canaan, whither I bring you, shall ye not do; neither shall ye walk in their statutes.", "ylt": "according to the work of the land of Egypt in which ye have dwelt ye do not, and according to the work of the land of Canaan whither I am bringing you in, ye do not, and in their statutes ye walk not.", "tyndale": "Wherfore after the doynges of the land of Egipte wherein ye dwelt, se that ye doo not: nether after the doynges of the lande of Canaan, whether I will bringe you, nether walke ye in their ordinaunces,", "dra": "You shall not do according to the custom of the land of Egypt, in which you dwelt: neither shall you act according to the manner of the country of Chanaan, into which I will bring you. Nor shall you walk in their ordinances.", "bbe": "You may not do those things which were done in the land of Egypt where you were living; and you may not do those things which are done in the land of Canaan where I am taking you, or be guided in your behaviour by their rules.", "geneva": "After ye doings of the land of Egypt, wherin ye dwelt, shall ye not doe: and after the maner of the land of Canaan, whither I will bring you, shall ye not do, neither walke in their ordinances,", "wycliffe": "ye schulen not do by the custom of the lond of Egipt, in which ye dwelliden; ye schulen not do bi the custom of the cuntrei of Canaan, `to which Y schal brynge you yn, nethir ye schulen go in the lawful thingis of hem.", "rotherham": "After the doings of the land of Egypt wherein ye dwelt, shall ye not do,—And after the doings of the land of Canaan whither, I, am bringing you in, shall ye not do, And, in their statutes, shall ye not walk:", "darby": "After the doings of the land of Egypt, wherein ye dwelt, shall ye not do; and after the doings of the land of Canaan, whither I bring you, shall ye not do; neither shall ye walk in their customs.", "twenty": "", "jps": "After the doings of the land of Egypt, wherein ye dwelt, shall ye not do; and after the doings of the land of Canaan, whither I bring you, shall ye not do; neither shall ye walk in their statutes.", "acv": "Ye shall not do after the doings of the land of Egypt, in which ye dwelt, and ye shall not do after the doings of the land of Canaan, where I bring you, nor shall ye walk in their statutes.", "anderson": "", "haweis": "", "noyes": "", "webster": "After the doings of the land of Egypt in which ye dwelt, shall ye not do: and after the doings of the land of Canaan whither I bring you, shall ye not do: neither shall ye walk in their ordinances.", "vulgate": "iuxta consuetudinem terrae Aegypti in qua habitastis non facietis et iuxta morem regionis Chanaan ad quam ego introducturus sum vos non agetis nec in legitimis eorum ambulabitis;", "brenton": "Ye shall not do according to the devices of Egypt, in which ye dwelt: and according to the devices of the land of Chanaan, into which I bring you, ye shall not do; and ye shall not walk in their ordinances."}}, {"v": 4, "ref": "18:4", "o": "אֶת מִשְׁפָּטַ֧/י תַּעֲשׂ֛וּ וְ/אֶת חֻקֹּתַ֥/י תִּשְׁמְר֖וּ לָ/לֶ֣כֶת בָּ/הֶ֑ם אֲנִ֖י יְהוָ֥ה אֱלֹהֵי/כֶֽם", "en": {"kjv": "Ye shall do my judgments, and keep mine ordinances, to walk therein: I am the Lord your God.", "web": "You shall do my ordinances, and you shall keep my statutes, and walk in them: I am Yahweh your God.", "bsb": "You are to practice My judgments and keep My statutes by walking in them. I am the LORD your God.", "asv": "Mine ordinances shall ye do, and my statutes shall ye keep, to walk therein: I am Jehovah your God.", "ylt": "`My judgments ye do, and My statutes ye keep, to walk in them; I am Jehovah your God;", "tyndale": "but doo after my iudgemetes, and kepe myne ordynaunces, to walke therein: for I am the Lorde youre God.", "dra": "You shall do my judgments, and shall observe my precepts, and shall walk in them. I am the Lord your God.", "bbe": "But you are to be guided by my decisions and keep my rules, and be guided by them: I am the Lord your God.", "geneva": "But do after my iudgements, and keepe mine ordinances, to walke therein: I am the Lord your God.", "wycliffe": "Ye schulen do my domes, and ye schulen kepe myn heestis, and ye schulen go in tho; Y am youre Lord God.", "rotherham": "My regulations, shall ye do, And, my statutes, shall ye observe to walk therein,—I—Yahweh, am your God.", "darby": "Mine ordinances shall ye do and my statutes shall ye observe to walk therein: I am Jehovah yourGod.", "twenty": "", "jps": "Mine ordinances shall ye do, and My statutes shall ye keep, to walk therein: I am HaShem your G-d.", "acv": "Ye shall do my ordinances, and ye shall keep my statutes, to walk therein. I am Jehovah your God.", "anderson": "", "haweis": "", "noyes": "", "webster": "Ye shall perform my judgments, and keep my ordinances, to walk in them; I [am] the LORD your God.", "vulgate": "facietis iudicia mea et praecepta servabitis et ambulabitis in eis ego Dominus Deus vester;", "brenton": "Ye shall observe my judgments, and shall keep my ordinances, and shall walk in them: I am the Lord your God."}}, {"v": 5, "ref": "18:5", "o": "וּ/שְׁמַרְתֶּ֤ם אֶת חֻקֹּתַ/י֙ וְ/אֶת מִשְׁפָּטַ֔/י אֲשֶׁ֨ר יַעֲשֶׂ֥ה אֹתָ֛/ם הָ/אָדָ֖ם וָ/חַ֣י בָּ/הֶ֑ם אֲנִ֖י יְהוָֽה", "en": {"kjv": "Ye shall therefore keep my statutes, and my judgments: which if a man do, he shall live in them: I am the Lord.", "web": "You shall therefore keep my statutes and my ordinances; which if a man does, he shall live in them. I am Yahweh.", "bsb": "Keep My statutes and My judgments, for the man who does these things will live by them. I am the LORD.", "asv": "Ye shall therefore keep my statutes, and mine ordinances; which if a man do, he shall live in them: I am Jehovah.", "ylt": "and ye have kept My statutes and My judgments which man doth and liveth in them; I am Jehovah.", "tyndale": "Kepe therfore myne ordinaunces, ad my iudgemetes whiche yf a man doo he shall lyue thereby: for I am the Lorde.", "dra": "Keep my laws and my judgments: which if a man do, he shall live in them, I am the Lord.", "bbe": "So keep my rules and my decisions, which, if a man does them, will be life to him: I am the Lord.", "geneva": "Ye shall keepe therefore my statutes, and my iudgements, which if a man doe, he shall then liue in them: I am the Lord.", "wycliffe": "Kepe ye my lawis and domes, whiche a man `schal do, and schal lyue in tho; Y am youre Lord God.", "rotherham": "Therefore shall ye observe my statutes, and my regulations, Which if the son of earth shall do them, Then shall he live in them,—I, am Yahweh.", "darby": "And ye shall observe my statutes and my judgments, by which the man that doeth them shall live: I am Jehovah.", "twenty": "", "jps": "Ye shall therefore keep My statutes, and Mine ordinances, which if a man do, he shall live by them: I am HaShem.", "acv": "Ye shall therefore keep my statutes, and my ordinances, which if a man does, he shall live in them. I am Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "Ye shall therefore keep my statutes and my judgments: which if a man doeth, he shall live in them: I [am] the LORD.", "vulgate": "custodite leges meas atque iudicia quae faciens homo vivet in eis ego Dominus;", "brenton": "So ye shall keep all my ordinances, and all my judgments, and do them; which if a man do, he shall live in them: I am the Lord your God."}}, {"v": 6, "ref": "18:6", "o": "אִ֥ישׁ אִישׁ֙ אֶל כָּל שְׁאֵ֣ר בְּשָׂר֔/וֹ לֹ֥א תִקְרְב֖וּ לְ/גַלּ֣וֹת עֶרְוָ֑ה אֲנִ֖י יְהוָֽה", "en": {"kjv": "None of you shall approach to any that is near of kin to him, to uncover their nakedness: I am the Lord.", "web": "“‘None of you shall approach anyone who are his close relatives, to uncover their nakedness: I am Yahweh.", "bsb": "None of you are to approach any close relative to have sexual relations. I am the LORD.", "asv": "None of you shall approach to any that are near of kin to him, to uncover their nakedness: I am Jehovah.", "ylt": "`None of you unto any relation of his flesh doth draw near to uncover nakedness; I am Jehovah.", "tyndale": "Se that ye goo to none of youre nyghest kynred for to vncouer their secrettes, for I am the Lorde.", "dra": "No man shall approach to her that is near of kin to him, to uncover her nakedness. I am the Lord.", "bbe": "You may not have sex connection with anyone who is a near relation: I am the Lord.", "geneva": "None shall come neere to any of ye kinred of his flesh to vncouer her shame: I am the Lord.", "wycliffe": "Ech man schal not neiy to the nyy womman of his blood, that he schewe `the filthe of hir; Y am the Lord.", "rotherham": "No person whatsoever, unto any of the near kin of his own flesh, shall approach to uncover the parts of shame,—I, am Yahweh.", "darby": "No one shall approach to any that is his near relation, to uncover his nakedness: I am Jehovah.", "twenty": "", "jps": "None of you shall approach to any that is near of kin to him, to uncover their nakedness. I am HaShem.", "acv": "None of you shall approach to any who are near of kin to him, to uncover nakedness. I am Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "None of you shall approach to any that is near of kin to him, to uncover [their] nakedness: I am the LORD.", "vulgate": "omnis homo ad proximam sanguinis sui non accedet ut revelet turpitudinem eius ego Dominus;", "brenton": "No man shall draw nigh to any of his near kindred to uncover their nakedness; I am the Lord."}}, {"v": 7, "ref": "18:7", "o": "עֶרְוַ֥ת אָבִ֛י/ךָ וְ/עֶרְוַ֥ת אִמְּ/ךָ֖ לֹ֣א תְגַלֵּ֑ה אִמְּ/ךָ֣ הִ֔וא לֹ֥א תְגַלֶּ֖ה עֶרְוָתָֽ/הּ", "en": {"kjv": "The nakedness of thy father, or the nakedness of thy mother, shalt thou not uncover: she is thy mother; thou shalt not uncover her nakedness.", "web": "“‘You shall not uncover the nakedness of your father, nor the nakedness of your mother: she is your mother. You shall not uncover her nakedness.", "bsb": "You must not expose the nakedness of your father by having sexual relations with your mother. She is your mother; you must not have sexual relations with her.", "asv": "The nakedness of thy father, even the nakedness of thy mother, shalt thou not uncover: she is thy mother; thou shalt not uncover her nakedness.", "ylt": "`The nakedness of thy father and the nakedness of thy mother thou dost not uncover, she is thy mother; thou dost not uncover her nakedness.", "tyndale": "The secrettes of thy father and thy mother, se thou vnheale not: she is thy mother, therfore shalt thou not discouer hir secrettes.", "dra": "Thou shalt not uncover the nakedness of thy father, or the nakedness of thy mother: she is thy mother, thou shalt not uncover her nakedness.", "bbe": "You may not have sex relations with your father or your mother: she is your mother, you may not take her.", "geneva": "Thou shalt not vncouer the shame of thy father, nor the shame of thy mother: for she is thy mother, thou shalt not discouer her shame.", "wycliffe": "Thou schalt not diskyuere the filthe of thi fadir and the filthe of thi modir; sche is thi modir, thou schalt not schewe hir filthe.", "rotherham": "The shame of thy father, even the shame of thy mother, shalt thou not uncover,—thy mother, she is, thou shalt not uncover her shame.", "darby": "The nakedness of thy father, and the nakedness of thy mother, shalt thou not uncover: she is thy mother: thou shalt not uncover her nakedness.", "twenty": "", "jps": "The nakedness of thy father, and the nakedness of thy mother, shalt thou not uncover: she is thy mother; thou shalt not uncover her nakedness.", "acv": "The nakedness of thy father, even the nakedness of thy mother, thou shall not uncover. She is thy mother. Thou shall not uncover her nakedness,", "anderson": "", "haweis": "", "noyes": "", "webster": "The nakedness of thy father, or the nakedness of thy mother, shalt thou not uncover: she [is] thy mother, thou shalt not uncover her nakedness.", "vulgate": "turpitudinem patris et turpitudinem matris tuae non discoperies mater tua est non revelabis turpitudinem eius;", "brenton": "Thou shalt not uncover the nakedness of thy father, or the nakedness of thy mother, for she is thy mother; thou shalt not uncover her nakedness."}}, {"v": 8, "ref": "18:8", "o": "עֶרְוַ֥ת אֵֽשֶׁת אָבִ֖י/ךָ לֹ֣א תְגַלֵּ֑ה עֶרְוַ֥ת אָבִ֖י/ךָ הִֽוא", "en": {"kjv": "The nakedness of thy father’s wife shalt thou not uncover: it is thy father’s nakedness.", "web": "“‘You shall not uncover the nakedness of your father’s wife. It is your father’s nakedness.", "bsb": "You must not have sexual relations with your father’s wife; it would dishonor your father.", "asv": "The nakedness of thy father’s wife shalt thou not uncover; it is thy father’s nakedness.", "ylt": "`The nakedness of the wife of thy father thou dost not uncover; it is the nakedness of thy father.", "tyndale": "The secrettes of thy fathers wife shalt thou not discouer, for they are thy fathers secrettes.", "dra": "Thou shalt not uncover the nakedness of thy father's wife: for it is the nakedness of thy father.", "bbe": "And you may not have sex relations with your father's wife: she is your father's.", "geneva": "The shame of thy fathers wife shalt thou not discouer: for it is thy fathers shame.", "wycliffe": "Thou schalt not vnhile the filthe of the wijf of thi fadir, for it is the filthe of thi fadir.", "rotherham": "The shame of thy father’s wife, shalt thou not uncover,—thy father’s shame, it is.", "darby": "The nakedness of thy father's wife shalt thou not uncover: it is thy father's nakedness.", "twenty": "", "jps": "The nakedness of thy father's wife shalt thou not uncover: it is thy father's nakedness.", "acv": "the nakedness of thy father's wife. It is thy father's nakedness.", "anderson": "", "haweis": "", "noyes": "", "webster": "The nakedness of thy father's wife shalt thou not uncover: it [is] thy father's nakedness.", "vulgate": "turpitudinem uxoris patris tui non discoperies turpitudo enim patris tui est;", "brenton": "Thou shalt not uncover the nakedness of thy father's wife; it is thy father's nakedness."}}, {"v": 9, "ref": "18:9", "o": "עֶרְוַ֨ת אֲחֽוֹתְ/ךָ֤ בַת אָבִ֨י/ךָ֙ א֣וֹ בַת אִמֶּ֔/ךָ מוֹלֶ֣דֶת בַּ֔יִת א֖וֹ מוֹלֶ֣דֶת ח֑וּץ לֹ֥א תְגַלֶּ֖ה עֶרְוָתָֽ/ן", "en": {"kjv": "The nakedness of thy sister, the daughter of thy father, or daughter of thy mother, whether she be born at home, or born abroad, even their nakedness thou shalt not uncover.", "web": "“‘You shall not uncover the nakedness of your sister, the daughter of your father, or the daughter of your mother, whether born at home, or born abroad.", "bsb": "You must not have sexual relations with your sister, either your father’s daughter or your mother’s daughter, whether she was born in the same home or elsewhere.", "asv": "The nakedness of thy sister, the daughter of thy father, or the daughter of thy mother, whether born at home, or born abroad, even their nakedness thou shalt not uncover.", "ylt": "`The nakedness of thy sister, daughter of thy father, or daughter of thy mother, born at home or born without; thou dost not uncover their nakedness.", "tyndale": "Thou shalt not discouer the preuyte of thy syster, the doughter of thy father or of thy mother: whether she be borne at home or without.", "dra": "Thou shalt not uncover the nakedness of thy sister by father or by mother: whether born at home or abroad.", "bbe": "You may not take your sister, the daughter of your father or of your mother, wherever her birth took place, among you or in another country.", "geneva": "Thou shalt not discouer the shame of thy sister the daughter of thy father, or the daughter of thy mother, whether shee bee borne at home, or borne without: thou shalt not discouer their shame.", "wycliffe": "Thou schalt not schewe the filthe of thi sistir, of fadir `ether of modir, which sister is gendrid at hoome ether without forth .", "rotherham": "The shame of thy sister daughter of thy father or daughter of thy mother, born at home or born abroad, thou shalt not uncover their shame.", "darby": "The nakedness of thy sister, the daughter of thy father, or daughter of thy mother, born at home, or born abroad — their nakedness shalt thou not uncover.", "twenty": "", "jps": "The nakedness of thy sister, the daughter of thy father, or the daughter of thy mother, whether born at home, or born abroad, even their nakedness thou shalt not uncover.", "acv": "The nakedness of thy sister, the daughter of thy father, or the daughter of thy mother, whether born at home, or born abroad, even their nakedness thou shall not uncover.", "anderson": "", "haweis": "", "noyes": "", "webster": "The nakedness of thy sister, the daughter of thy father, or daughter of thy mother, [whether] born at home, or born abroad, [even] their nakedness thou shalt not uncover.", "vulgate": "turpitudinem sororis tuae ex patre sive ex matre quae domi vel foris genita est non revelabis;", "brenton": "The nakedness of thy sister by thy father or by thy mother, born at home or abroad, their nakedness thou shalt not uncover."}}, {"v": 10, "ref": "18:10", "o": "עֶרְוַ֤ת בַּת בִּנְ/ךָ֙ א֣וֹ בַֽת בִּתְּ/ךָ֔ לֹ֥א תְגַלֶּ֖ה עֶרְוָתָ֑/ן כִּ֥י עֶרְוָתְ/ךָ֖ הֵֽנָּה", "en": {"kjv": "The nakedness of thy son’s daughter, or of thy daughter’s daughter, even their nakedness thou shalt not uncover: for theirs is thine own nakedness.", "web": "“‘You shall not uncover the nakedness of your son’s daughter, or of your daughter’s daughter, even their nakedness: for theirs is your own nakedness.", "bsb": "You must not have sexual relations with your son’s daughter or your daughter’s daughter, for that would shame your family.", "asv": "The nakedness of thy son’s daughter, or of thy daughter’s daughter, even their nakedness thou shalt not uncover: for theirs is thine own nakedness.", "ylt": "`The nakedness of thy son's daughter, or of thy daughter's daughter: thou dost not uncover their nakedness; for theirs is thy nakedness.", "tyndale": "Thou shalt not discouer the secrettes of thy sonnes doughter or thy doughters doughter, for that is thyne awne preuyte:", "dra": "Thou shalt not uncover the nakedness of thy son's daughter, or thy daughter's daughter: because it is thy own nakedness.", "bbe": "You may not have sex relations with your son's daughter or your daughter's daughter, for they are part of yourself;", "geneva": "The shame of thy sonnes daughter, or of thy daughters daughter, thou shalt not, I say, vncouer their shame: for it is thy shame.", "wycliffe": "Thou schalt not schewe the filthe of the douyter of thi sone, ether of neece of thi douyter, for it is thi filthe.", "rotherham": "The shame of the daughter of thy son or the daughter of thy daughter, thou shalt not uncover their shame,—for, thine own shame, they are.", "darby": "The nakedness of thy son's daughter, or of thy daughter's daughter — their nakedness shalt thou not uncover; for theirs is thy nakedness.", "twenty": "", "jps": "The nakedness of thy son's daughter, or of thy daughter's daughter, even their nakedness thou shalt not uncover; for theirs is thine own nakedness.", "acv": "The nakedness of thy son's daughter, or of thy daughter's daughter, even their nakedness thou shall not uncover, for theirs is thine own nakedness.", "anderson": "", "haweis": "", "noyes": "", "webster": "The nakedness of thy son's daughter, or of thy daughter's daughter, [even] their nakedness thou shalt not uncover: for theirs [is] thy own nakedness.", "vulgate": "turpitudinem filiae filii tui vel neptis ex filia non revelabis quia turpitudo tua est;", "brenton": "The nakedness of thy son's daughter, or thy daughter's daughter, their nakedness thou shalt not uncover; because it is thy nakedness."}}, {"v": 11, "ref": "18:11", "o": "עֶרְוַ֨ת בַּת אֵ֤שֶׁת אָבִ֨י/ךָ֙ מוֹלֶ֣דֶת אָבִ֔י/ךָ אֲחוֹתְ/ךָ֖ הִ֑וא לֹ֥א תְגַלֶּ֖ה עֶרְוָתָֽ/הּ", "en": {"kjv": "The nakedness of thy father’s wife’s daughter, begotten of thy father, she is thy sister, thou shalt not uncover her nakedness.", "web": "“‘You shall not uncover the nakedness of your father’s wife’s daughter, conceived by your father, since she is your sister.", "bsb": "You must not have sexual relations with the daughter of your father’s wife, born to your father; she is your sister.", "asv": "The nakedness of thy father’s wife’s daughter, begotten of thy father, she is thy sister, thou shalt not uncover her nakedness.", "ylt": "`The nakedness of a daughter of thy father's wife, begotten of thy father, she is thy sister; thou dost not uncover her nakedness.", "tyndale": "Thou shalt not discouer the secrettes of thy fathers wyues doughter, which she bare to thy father, for she is thy suster: thou shalt therfore not discouer hir secrettes.", "dra": "Thou shalt not uncover the nakedness of thy father's wife's daughter, whom she bore to thy father: and who is thy sister.", "bbe": "Or your father's wife's daughter, the child of your father, for she is your sister.", "geneva": "The shame of thy fathers wiues daughter, begotten of thy father (for she is thy sister) thou shalt not, I say, discouer her shame.", "wycliffe": "Thou schalt not schewe the filthe of the douyter of the wijf of thi fadir, which sche childide to thi fadir, and is thi sistir.", "rotherham": "The shame of the daughter of thy father’s wife, born to thy father, she being, thy sister, thou shalt not uncover her shame.", "darby": "The nakedness of thy father's wife's daughter, begotten of thy father: she is thy sister: thou shalt not uncover her nakedness.", "twenty": "", "jps": "The nakedness of thy father's wife's daughter, begotten of thy father, she is thy sister, thou shalt not uncover her nakedness.", "acv": "The nakedness of thy father's wife's daughter, begotten of thy father, she is thy sister, thou shall not uncover her nakedness.", "anderson": "", "haweis": "", "noyes": "", "webster": "The nakedness of thy father's wife's daughter, begotten by thy father, (she [is] thy sister) thou shalt not uncover her nakedness.", "vulgate": "turpitudinem filiae uxoris patris tui quam peperit patri tuo et est soror tua non revelabis;", "brenton": "Thou shalt not uncover the nakedness of the daughter of thy father's wife; she is thy sister by the same father: thou shalt not uncover her nakedness."}}, {"v": 12, "ref": "18:12", "o": "עֶרְוַ֥ת אֲחוֹת אָבִ֖י/ךָ לֹ֣א תְגַלֵּ֑ה שְׁאֵ֥ר אָבִ֖י/ךָ הִֽוא", "en": {"kjv": "Thou shalt not uncover the nakedness of thy father’s sister: she is thy father’s near kinswoman.", "web": "“‘You shall not uncover the nakedness of your father’s sister: she is your father’s near kinswoman.", "bsb": "You must not have sexual relations with your father’s sister; she is your father’s close relative.", "asv": "Thou shalt not uncover the nakedness of thy father’s sister: she is thy father’s near kinswoman.", "ylt": "`The nakedness of a sister of thy father thou dost not uncover; she is a relation of thy father.", "tyndale": "Thou shalt not vncouer the secrettes off thy fathers syster, for she is thy fathers nexte kyn.", "dra": "Thou shalt not uncover the nakedness of thy father's sister: because she is the flesh of thy father.", "bbe": "You may not have sex connection with your father's sister, for she is your father's near relation.", "geneva": "Thou shalt not vncouer the shame of thy fathers sister: for she is thy fathers kinswoman.", "wycliffe": "Thou schalt not opene the filthe of the `sister of thi fadir, for sche is the fleisch of thi fadir.", "rotherham": "The shame of thy father’s sister, shalt thou not uncover,—thy father’s near of kin, she is.", "darby": "The nakedness of thy father's sister shalt thou not uncover: she is thy father's near relation.", "twenty": "", "jps": "Thou shalt not uncover the nakedness of thy father's sister: she is thy father's near kinswoman.", "acv": "Thou shall not uncover the nakedness of thy father's sister. She is thy father's near kinswoman.", "anderson": "", "haweis": "", "noyes": "", "webster": "Thou shalt not uncover the nakedness of thy father's sister: she [is] thy father's near kinswoman.", "vulgate": "turpitudinem sororis patris tui non discoperies quia caro est patris tui;", "brenton": "Thou shalt not uncover the nakedness of thy father's sister, for she is near akin to thy father."}}, {"v": 13, "ref": "18:13", "o": "עֶרְוַ֥ת אֲחֽוֹת אִמְּ/ךָ֖ לֹ֣א תְגַלֵּ֑ה כִּֽי שְׁאֵ֥ר אִמְּ/ךָ֖ הִֽוא", "en": {"kjv": "Thou shalt not uncover the nakedness of thy mother’s sister: for she is thy mother’s near kinswoman.", "web": "“‘You shall not uncover the nakedness of your mother’s sister: for she is your mother’s near kinswoman.", "bsb": "You must not have sexual relations with your mother’s sister, for she is your mother’s close relative.", "asv": "Thou shalt not uncover the nakedness of thy mother’s sister: for she is thy mother’s near kinswoman.", "ylt": "`The nakedness of thy mother's sister thou dost not uncover; for she is thy mother's relation.", "tyndale": "Thou shalt not dyscouer the secrettes off thy mothers syster, for she is thy mothers nexte kyn.", "dra": "Thou shalt not uncover the nakedness of thy mother's sister: because she is thy mother's flesh.", "bbe": "You may not have sex connection with your mother's sister, for she is your mother's near relation.", "geneva": "Thou shalt not discouer the shame of thy mothers sister: for she is thy mothers kinsewoman.", "wycliffe": "Thou schalt not schewe the filthe of the sistir of thi modir, for sche is the fleisch of thi modir.", "rotherham": "The shame of thy mother’s sister, shalt thou not uncover,—for, thy mother’s near of kin, she is.", "darby": "The nakedness of thy mother's sister shalt thou not uncover; for she is thy mother's near relation.", "twenty": "", "jps": "Thou shalt not uncover the nakedness of thy mother's sister; for she is thy mother's near kinswoman.", "acv": "Thou shall not uncover the nakedness of thy mother's sister, for she is thy mother's near kinswoman.", "anderson": "", "haweis": "", "noyes": "", "webster": "Thou shalt not uncover the nakedness of thy mother's sister: for she [is] thy mother's near kinswoman.", "vulgate": "turpitudinem sororis matris tuae non revelabis eo quod caro sit matris tuae;", "brenton": "Thou shalt not uncover the nakedness of thy mother's sister, for she is near akin to thy mother."}}, {"v": 14, "ref": "18:14", "o": "עֶרְוַ֥ת אֲחִֽי אָבִ֖י/ךָ לֹ֣א תְגַלֵּ֑ה אֶל אִשְׁתּ/וֹ֙ לֹ֣א תִקְרָ֔ב דֹּדָֽתְ/ךָ֖ הִֽוא", "en": {"kjv": "Thou shalt not uncover the nakedness of thy father’s brother, thou shalt not approach to his wife: she is thine aunt.", "web": "“‘You shall not uncover the nakedness of your father’s brother, you shall not approach his wife. She is your aunt.", "bsb": "You must not dishonor your father’s brother by approaching his wife to have sexual relations with her; she is your aunt.", "asv": "Thou shalt not uncover the nakedness of thy father’s brother, thou shalt not approach to his wife: she is thine aunt.", "ylt": "`The nakedness of thy father's brother thou dost not uncover; unto his wife thou dost not draw near; she is thine aunt.", "tyndale": "Thou shalt not open the secrettes of thy fathers brother: that is thou shalt not goo in to his wife, for she is thyne awnte.", "dra": "Thou shalt not uncover the nakedness of thy father's brother: neither shalt thou approach to his wife, who is joined to thee by affinity.", "bbe": "You may not have sex relations with the wife of your father's brother, for she is of your family;", "geneva": "Thou shalt not vncouer the shame of thy fathers brother: that is, thou shalt not goe in to his wife, for she is thine aunte.", "wycliffe": "Thou schalt not shewe the filthe of the brothir of thi fadir, nethir thou schalt neiye to his wijf, which is ioyned to thee bi affinyte.", "rotherham": "The shame of thy father’s brother, shalt thou not uncover unto his wife, shalt thou not approach, thine aunt, she is.", "darby": "The nakedness of thy father's brother shalt thou not uncover; thou shalt not approach his wife: she is thine aunt.", "twenty": "", "jps": "Thou shalt not uncover the nakedness of thy fathers brother, thou shalt not approach to his wife: she is thine aunt.", "acv": "Thou shall not uncover the nakedness of thy father's brother. Thou shall not approach to his wife. She is thine aunt.", "anderson": "", "haweis": "", "noyes": "", "webster": "Thou shalt not uncover the nakedness of thy father's brother, thou shalt not approach to his wife: she [is] thy aunt.", "vulgate": "turpitudinem patrui tui non revelabis nec accedes ad uxorem eius quae tibi adfinitate coniungitur;", "brenton": "Thou shalt not uncover the nakedness of thy father's brother, and thou shalt not go in to his wife; for she is thy relation."}}, {"v": 15, "ref": "18:15", "o": "עֶרְוַ֥ת כַּלָּֽתְ/ךָ֖ לֹ֣א תְגַלֵּ֑ה אֵ֤שֶׁת בִּנְ/ךָ֙ הִ֔וא לֹ֥א תְגַלֶּ֖ה עֶרְוָתָֽ/הּ", "en": {"kjv": "Thou shalt not uncover the nakedness of thy daughter in law: she is thy son’s wife; thou shalt not uncover her nakedness.", "web": "“‘You shall not uncover the nakedness of your daughter-in-law: she is your son’s wife. You shall not uncover her nakedness.", "bsb": "You must not have sexual relations with your daughter-in-law. She is your son’s wife; you are not to have sexual relations with her.", "asv": "Thou shalt not uncover the nakedness of thy daughter-in-law: she is thy son’s wife; thou shalt not uncover her nakedness.", "ylt": "`The nakedness of thy daughter-in-law thou dost not uncover; she is thy son's wife; thou dost not uncover her nakedness.", "tyndale": "Thou shalt not discouer the secrettes of thy doughter in lawe she is thy sonnes wyfe: therfore vncouer not hir secrettes.", "dra": "Thou shalt not uncover the nakedness of thy daughter in law: because she is thy son's wife, neither shalt thou discover her shame.", "bbe": "Or with your daughter-in-law, for she is your son's wife, and you may not take her.", "geneva": "Thou shalt not discouer the shame of thy daughter in lawe: for she is thy sonnes wife: therefore shalt thou not vncouer her shame.", "wycliffe": "Thou schalt not schewe the filthe of thi sones wijf, for sche is the wijf of thi sone, nether thou schalt diskiuere hir schenschip; and no man take his brotheris wijf.", "rotherham": "The shame of thy daughter-in-law, shalt thou not uncover,—thy son’s wife, she is, thou shalt not uncover her shame.", "darby": "The nakedness of thy daughter-in-law shalt thou not uncover: she is thy son's wife; thou shalt not uncover her nakedness.", "twenty": "", "jps": "Thou shalt not uncover the nakedness of thy daughter-in-law: she is thy son' wife; thou shalt not uncover her nakedness.", "acv": "Thou shall not uncover the nakedness of thy daughter-in-law. She is thy son's wife. Thou shall not uncover her nakedness.", "anderson": "", "haweis": "", "noyes": "", "webster": "Thou shalt not uncover the nakedness of thy daughter-in-law: she [is] thy son's wife, thou shalt not uncover her nakedness.", "vulgate": "turpitudinem nurus tuae non revelabis quia uxor filii tui est nec discoperies ignominiam eius;", "brenton": "Thou shalt not uncover the nakedness of thy daughter-in-law, for she is thy son's wife, thou shalt not uncover her nakedness."}}, {"v": 16, "ref": "18:16", "o": "עֶרְוַ֥ת אֵֽשֶׁת אָחִ֖י/ךָ לֹ֣א תְגַלֵּ֑ה עֶרְוַ֥ת אָחִ֖י/ךָ הִֽוא", "en": {"kjv": "Thou shalt not uncover the nakedness of thy brother’s wife: it is thy brother’s nakedness.", "web": "“‘You shall not uncover the nakedness of your brother’s wife. It is your brother’s nakedness.", "bsb": "You must not have sexual relations with your brother’s wife; that would shame your brother.", "asv": "Thou shalt not uncover the nakedness of thy brother’s wife: it is thy brother’s nakedness.", "ylt": "`The nakedness of thy brother's wife thou dost not uncover; it is thy brother's nakedness.", "tyndale": "Thou shalt not vnheale the secrettes of thy brothers wife, for that is thy brothers preuyte.", "dra": "Thou shalt not uncover the nakedness of thy brother's wife: because it is the nakedness of thy brother.", "bbe": "You may not have sex relations with your brother's wife, for she is your brother's.", "geneva": "Thou shalt not discouer the shame of thy brothers wife. for it is thy brothers shame.", "wycliffe": "Thou schalt not schewe the filthe of `the wijf of thi brother, for it is the filthe of thi brothir.", "rotherham": "The shame of thy brother’s wife, shalt thou not uncover,—the shame of thy brother, it is.", "darby": "The nakedness of thy brother's wife shalt thou not uncover: it is thy brother's nakedness.", "twenty": "", "jps": "Thou shalt not uncover the nakedness of thy brother's wife: it is thy brother's nakedness.", "acv": "Thou shall not uncover the nakedness of thy brother's wife. It is thy brother's nakedness.", "anderson": "", "haweis": "", "noyes": "", "webster": "Thou shalt not uncover the nakedness of thy brother's wife: it [is] thy brother's nakedness.", "vulgate": "turpitudinem uxoris fratris tui non revelabis quia turpitudo fratris tui est;", "brenton": "Thou shalt not uncover the nakedness of thy brother's wife: it is thy brother's nakedness."}}, {"v": 17, "ref": "18:17", "o": "עֶרְוַ֥ת אִשָּׁ֛ה וּ/בִתָּ֖/הּ לֹ֣א תְגַלֵּ֑ה אֶֽת בַּת בְּנָ֞/הּ וְ/אֶת בַּת בִּתָּ֗/הּ לֹ֤א תִקַּח֙ לְ/גַלּ֣וֹת עֶרְוָתָ֔/הּ שַׁאֲרָ֥ה הֵ֖נָּה זִמָּ֥ה הִֽוא", "en": {"kjv": "Thou shalt not uncover the nakedness of a woman and her daughter, neither shalt thou take her son’s daughter, or her daughter’s daughter, to uncover her nakedness; for they are her near kinswomen: it is wickedness.", "web": "“‘You shall not uncover the nakedness of a woman and her daughter. You shall not take her son’s daughter, or her daughter’s daughter, to uncover her nakedness; they are near kinswomen: it is wickedness.", "bsb": "You must not have sexual relations with both a woman and her daughter. You are not to marry her son’s daughter or her daughter’s daughter and have sexual relations with her. They are close relatives; it is depraved.", "asv": "Thou shalt not uncover the nakedness of a woman and her daughter; thou shalt not take her son’s daughter, or her daughter’s daughter, to uncover her nakedness; they are near kinswomen: it is wickedness.", "ylt": "`The nakedness of a woman and her daughter thou dost not uncover; her son's daughter, and her daughter's daughter thou dost not take to uncover her nakedness; they are her relations; it is wickedness.", "tyndale": "Thou shalt not discouer the preuytes of the wife ad hir doughter also, nether shalt thou take hir sonnes doughter or hir doughters doughter to vncouer their secrettes: they are hir nexte kyn, it were therfore wikydnesse.", "dra": "Thou shalt not uncover the nakedness of thy wife and her daughter. Thou shalt not take her son's daughter or her daughter's daughter, to discover her shame: because they are her flesh, and such copulation is incest.", "bbe": "You may not take as wife a woman and her daughter, or her son's daughter or her daughter's daughter, for they are of one family: it is an act of shame.", "geneva": "Thou shalt not discouer the shame of the wife and of her daughter, neither shalt thou take her sonnes daughter, nor her daughters daughter, to vncouer her shame: for they are thy kinsfolkes, and it were wickednesse.", "wycliffe": "Thou schalt not schewe the filthe of thi wijf , and of hir douyter; thou schalt not take the douytir of hir sone, and the douytir of hir douyter, that thou schewe hir schenschip; thei ben the fleisch of hir, and siche letcherie is incest.", "rotherham": "The shame of a woman, and of her daughter, shalt thou not uncover,—neither the daughter of her son nor the daughter of her daughter, shalt thou take, to uncover her shame, near of kin, they are, wickedness, it is.", "darby": "The nakedness of a woman and her daughter shalt thou not uncover; thou shalt not take her son's daughter, nor her daughter's daughter, to uncover her nakedness: they are her near relations: it is wickedness.", "twenty": "", "jps": "Thou shalt not uncover the nakedness of a woman and her daughter; thou shalt not take her son's daughter, or her daughter's daughter, to uncover her nakedness: they are near kinswomen; it is lewdness.", "acv": "Thou shall not uncover the nakedness of a woman and her daughter. Thou shall not take her son's daughter, or her daughter's daughter, to uncover her nakedness. They are near kinswomen. It is iniquity.", "anderson": "", "haweis": "", "noyes": "", "webster": "Thou shalt not uncover the nakedness of a woman and her daughter, neither shalt thou take her son's daughter, or her daughter's daughter, to uncover her nakedness; [for] they [are] her near kinswomen: it [is] wickedness.", "vulgate": "turpitudinem uxoris tuae et filiae eius non revelabis filiam filii eius et filiam filiae illius non sumes ut reveles ignominiam eius quia caro illius sunt et talis coitus incestus est;", "brenton": "The nakedness of a woman and her daughter shalt thou not uncover; her son's daughter, and her daughter's daughter, shalt thou not take, to uncover their nakedness, for they are thy kinswomen: it is impiety."}}, {"v": 18, "ref": "18:18", "o": "וְ/אִשָּׁ֥ה אֶל אֲחֹתָ֖/הּ לֹ֣א תִקָּ֑ח לִ/צְרֹ֗ר לְ/גַלּ֧וֹת עֶרְוָתָ֛/הּ עָלֶ֖י/הָ בְּ/חַיֶּֽי/הָ", "en": {"kjv": "Neither shalt thou take a wife to her sister, to vex her, to uncover her nakedness, beside the other in her life time.", "web": "“‘You shall not take a wife to her sister, to be a rival, to uncover her nakedness, while her sister is yet alive.", "bsb": "You must not take your wife’s sister as a rival wife and have sexual relations with her while your wife is still alive.", "asv": "And thou shalt not take a wife to her sister, to be a rival to her, to uncover her nakedness, besides the other in her life-time.", "ylt": "`And a woman unto another thou dost not take, to be an adversary, to uncover her nakedness beside her, in her life.", "tyndale": "Thou shalt not take a wife and hir sister thereto, to vexe hir that thou woldest open hir secrettes as longe as she lyueth.", "dra": "Thou shalt not take thy wife's sister for a harlot, to rival her: neither shalt thou discover her nakedness, while she is yet living.", "bbe": "And you may not take as wife a woman and at the same time her sister, to be in competition with her in her life-time.", "geneva": "Also thou shalt not take a wife with her sister, during her life, to vexe her, in vncouering her shame vpon her.", "wycliffe": "Thou schalt not take `the sister of thi wijf, in to concubynage of hir, nethir thou schalt schewe `the filthe of hir, while thi wijf lyueth yit.", "rotherham": "And, a woman unto her sister, shalt thou not take,—to cause rivalry, by uncovering her shame besides her own while she is living.", "darby": "And thou shalt not take a wife to her sister, to vex her, to uncover her nakedness beside her, during her life.", "twenty": "", "jps": "And thou shalt not take a woman to her sister, to be a rival to her, to uncover her nakedness, beside the other in her lifetime.", "acv": "And thou shall not take a wife in addition to her sister, to be a rival to her, to uncover her nakedness, besides the other in her life-time.", "anderson": "", "haweis": "", "noyes": "", "webster": "Neither shalt thou take a wife to her sister, to vex [her], to uncover her nakedness besides the other in her life-[time].", "vulgate": "sororem uxoris tuae in pelicatum illius non accipies nec revelabis turpitudinem eius adhuc illa vivente;", "brenton": "Thou shalt not take a wife in addition to her sister, as a rival, to uncover her nakedness in opposition to her, while she is yet living."}}, {"v": 19, "ref": "18:19", "o": "וְ/אֶל אִשָּׁ֖ה בְּ/נִדַּ֣ת טֻמְאָתָ֑/הּ לֹ֣א תִקְרַ֔ב לְ/גַלּ֖וֹת עֶרְוָתָֽ/הּ", "en": {"kjv": "Also thou shalt not approach unto a woman to uncover her nakedness, as long as she is put apart for her uncleanness.", "web": "“‘You shall not approach a woman to uncover her nakedness, as long as she is impure by her uncleanness.", "bsb": "You must not approach a woman to have sexual relations with her during her menstrual period.", "asv": "And thou shalt not approach unto a woman to uncover her nakedness, as long as she is impure by her uncleanness.", "ylt": "`And unto a woman in the separation of her uncleanness thou dost not draw near to uncover her nakedness.", "tyndale": "Thou shalt not goo vnto a woman to open hir secrettes, as longe as she is put aparte for hir vnclennesse.", "dra": "Thou shalt not approach to a woman having her flowers: neither shalt thou uncover her nakedness.", "bbe": "And you may not go near a woman or have sex relations with her when she is unclean, at her regular time.", "geneva": "Thou shalt not also go vnto a woman to vncouer her shame, as long as she is put apart for her disease.", "wycliffe": "Thou schalt not neiye to a womman that suffrith rennyng of blood of monethe, nethir thou schalt schewe hir filthe.", "rotherham": "And unto a woman during her removal for uncleanness, shalt thou not approach, to uncover her shame.", "darby": "And thou shalt not approach a woman in the separation of her uncleanness to uncover her nakedness.", "twenty": "", "jps": "And thou shalt not approach unto a woman to uncover her nakedness, as long as she is impure by her uncleanness.", "acv": "And thou shall not approach to a woman to uncover her nakedness, as long as she is impure by her uncleanness.", "anderson": "", "haweis": "", "noyes": "", "webster": "Also thou shalt not approach to a woman to uncover her nakedness, as long as she is put apart for her uncleanness.", "vulgate": "ad mulierem quae patitur menstrua non accedes nec revelabis foeditatem eius;", "brenton": "And thou shalt not go in to a woman under separation for her uncleanness, to uncover her nakedness."}}, {"v": 20, "ref": "18:20", "o": "וְ/אֶל אֵ֨שֶׁת֙ עֲמִֽיתְ/ךָ֔ לֹא תִתֵּ֥ן שְׁכָבְתְּ/ךָ֖ לְ/זָ֑רַע לְ/טָמְאָה בָֽ/הּ", "en": {"kjv": "Moreover thou shalt not lie carnally with thy neighbour’s wife, to defile thyself with her.", "web": "“‘You shall not lie carnally with your neighbor’s wife, and defile yourself with her.", "bsb": "You must not lie carnally with your neighbor’s wife and thus defile yourself with her.", "asv": "And thou shalt not lie carnally with thy neighbor’s wife, to defile thyself with her.", "ylt": "`And unto the wife of thy fellow thou dost not give thy seed of copulation, for uncleanness with her.", "tyndale": "Thou shalt not lye with thy neghbours wife, to defyle thi selfe with her.", "dra": "Thou shalt not lie with thy neighbour's wife: nor be defiled with mingling of seed.", "bbe": "And you may not have sex relations with your neighbour's wife, making yourself unclean with her.", "geneva": "Moreouer, thou shalt not giue thy selfe to thy neighbours wife by carnall copulation, to be defiled with her.", "wycliffe": "Thou schalt not do letcherie with `the wijf of thi neiybore, nether thou schalt be defoulid with medlyng of seed.", "rotherham": "And of the wife of thy neighbour, shalt thou not have carnal knowledge,—to commit uncleanness with her.", "darby": "And thou shalt not lie carnally with thy neighbour's wife, to become unclean with her.", "twenty": "", "jps": "And thou shalt not lie carnally with thy neighbour's wife, to defile thyself with her.", "acv": "And thou shall not lie carnally with thy neighbor's wife, to defile thyself with her.", "anderson": "", "haweis": "", "noyes": "", "webster": "Moreover, thou shalt not lie carnally with thy neighbor's wife, to defile thyself with her.", "vulgate": "cum uxore proximi tui non coibis nec seminis commixtione maculaberis;", "brenton": "And thou shalt not lie with thy neighbour's wife, to defile thyself with her."}}, {"v": 21, "ref": "18:21", "o": "וּ/מִֽ/זַּרְעֲ/ךָ֥ לֹא תִתֵּ֖ן לְ/הַעֲבִ֣יר לַ/מֹּ֑לֶךְ וְ/לֹ֧א תְחַלֵּ֛ל אֶת שֵׁ֥ם אֱלֹהֶ֖י/ךָ אֲנִ֥י יְהוָֽה", "en": {"kjv": "And thou shalt not let any of thy seed pass through the fire to Molech, neither shalt thou profane the name of thy God: I am the Lord.", "web": "“‘You shall not give any of your children to sacrifice to Molech; neither shall you profane the name of your God. I am Yahweh.", "bsb": "You must not give any of your children to be sacrificed to Molech, for you must not profane the name of your God. I am the LORD.", "asv": "And thou shalt not give any of thy seed to make them pass through the fire to Molech; neither shalt thou profane the name of thy God: I am Jehovah.", "ylt": "`And of thy seed thou dost not give to pass over to the Molech; nor dost thou pollute the name of thy God; I am Jehovah.", "tyndale": "Thou shalt not geue of thi seed to offer it vnto Moloch, that thou defile not the name of thi God, for I am the Lorde.", "dra": "Thou shalt not give any of thy seed to be consecrated to the idol Moloch, nor defile the name of thy God. I am the Lord.", "bbe": "And you may not make any of your children go through the fire as an offering to Molech, and you may not put shame on the name of your God: I am the Lord.", "geneva": "Also thou shalt not giue thy children to offer them vnto Molech, neither shalt thou defile the name of thy God: for I am the Lord.", "wycliffe": "Thou schalt not yyue of thi seed, that it be offrid to the idol Moloch, nether thou schalt defoule the name of thi God; Y am the Lord.", "rotherham": "And none of thy seed, shalt thou deliver up, to cause to pass through to Molech,—that thou profane not the name of thy God, I, am Yahweh.", "darby": "And thou shalt not give of thy seed to let them pass through [the fire] to Molech, neither shalt thou profane the name of thyGod: I am Jehovah.", "twenty": "", "jps": "And thou shalt not give any of thy seed to set them apart to Molech, neither shalt thou profane the name of thy G-d: I am HaShem.", "acv": "And thou shall not give any of thy seed to make them pass through the fire to Molech, neither shall thou profane the name of thy God. I am Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And thou shalt not let any of thy seed pass through [the fire] to Molech, neither shalt thou profane the name of thy God: I [am] the LORD.", "vulgate": "de semine tuo non dabis ut consecretur idolo Moloch nec pollues nomen Dei tui ego Dominus;", "brenton": "And thou shalt not give of thy seed to serve a ruler; and thou shalt not profane my holy name; I am the Lord."}}, {"v": 22, "ref": "18:22", "o": "וְ/אֶ֨ת זָכָ֔ר לֹ֥א תִשְׁכַּ֖ב מִשְׁכְּבֵ֣י אִשָּׁ֑ה תּוֹעֵבָ֖ה הִֽוא", "en": {"kjv": "Thou shalt not lie with mankind, as with womankind: it is abomination.", "web": "“‘You shall not lie with a man, as with a woman. That is detestable.", "bsb": "You must not lie with a man as with a woman; that is an abomination.", "asv": "Thou shalt not lie with mankind, as with womankind: it is abomination.", "ylt": "`And with a male thou dost not lie as one lieth with a woman; abomination it is .", "tyndale": "Thou shalt not lye with mankynde as with womankynde, for that is abominacion.", "dra": "Thou shalt not lie with mankind as with womankind: because it is an abomination.", "bbe": "You may not have sex relations with men, as you do with women: it is a disgusting thing.", "geneva": "Thou shalt not lie with ye male as one lieth with a woman: for it is abomination.", "wycliffe": "Thou schalt not be medlid with a man bi letcherie of womman, for it is abhomynacioun.", "rotherham": "And, with mankind, shalt thou not lie as with womankind,—an abomination, it is.", "darby": "And thou shalt not lie with mankind as one lieth with a woman: it is an abomination.", "twenty": "", "jps": "Thou shalt not lie with mankind, as with womankind; it is abomination.", "acv": "Thou shall not lie with mankind, as with womankind. It is abomination.", "anderson": "", "haweis": "", "noyes": "", "webster": "Thou shalt not lie with mankind, as with womankind: it [is] abomination.", "vulgate": "cum masculo non commisceberis coitu femineo quia abominatio est;", "brenton": "And thou shalt not lie with a man as with a woman, for it is an abomination."}}, {"v": 23, "ref": "18:23", "o": "וּ/בְ/כָל בְּהֵמָ֛ה לֹא תִתֵּ֥ן שְׁכָבְתְּ/ךָ֖ לְ/טָמְאָה בָ֑/הּ וְ/אִשָּׁ֗ה לֹֽא תַעֲמֹ֞ד לִ/פְנֵ֧י בְהֵמָ֛ה לְ/רִבְעָ֖/הּ תֶּ֥בֶל הֽוּא", "en": {"kjv": "Neither shalt thou lie with any beast to defile thyself therewith: neither shall any woman stand before a beast to lie down thereto: it is confusion.", "web": "“‘You shall not lie with any animal to defile yourself with it; neither shall any woman give herself to an animal, to lie down with it: it is a perversion.", "bsb": "You must not lie carnally with any animal, thus defiling yourself with it; a woman must not stand before an animal to mate with it; that is a perversion.", "asv": "And thou shalt not lie with any beast to defile thyself therewith; neither shall any woman stand before a beast, to lie down thereto: it is confusion.", "ylt": "`And with any beast thou dost not give thy copulation, for uncleanness with it; and a woman doth not stand before a beast to lie down with it; confusion it is .", "tyndale": "Thou shalt lye with no maner of beeste to defile thy selfe therewith, nether shall any woman stonde before a beest to lye doune thereto, for that is abhominacion.", "dra": "Thou shalt not copulate with any beast: neither shalt thou be defiled with it. A woman shall not lie down to a beast, nor copulate with it: because it is a heinous crime.", "bbe": "And you may not have sex relations with a beast, making yourself unclean with it; and a woman may not give herself to a beast: it is an unnatural act.", "geneva": "Thou shalt not also lie with any beast to bee defiled therewith, neither shall any woman stand before a beast, to lie downe thereto: for it is abomination.", "wycliffe": "Thou schalt not do letcherie with ony beeste, nethir thou schalt be defoulid with it. A womman schal not ligge vnder a beeste, nether schal be medlid therwith , for it is greet synne.", "rotherham": "And of no beast, shalt thou have carnal knowledge to commit uncleanness therewith,—neither shall a woman present herself to a beast to couch down thereto,—confusion, it is.", "darby": "And thou shalt lie with no beast to become unclean therewith; and a woman shall not stand before a beast to lie down with it: it is confusion.", "twenty": "", "jps": "And thou shalt not lie with any beast to defile thyself therewith; neither shall any woman stand before a beast, to lie down thereto; it is perversion.", "acv": "And thou shall not lie with any beast to defile thyself with it, nor shall any woman stand before a beast, to lie down with it. It is a perversion.", "anderson": "", "haweis": "", "noyes": "", "webster": "Neither shalt thou lie with any beast to defile thyself therewith: neither shall any woman stand before a beast to lie down thereto: it [is] confusion.", "vulgate": "cum omni pecore non coibis nec maculaberis cum eo mulier non subcumbet iumento nec miscebitur ei quia scelus est;", "brenton": "Neither shalt thou lie with any quadruped for copulation, to be polluted with it: neither shall a woman present herself before any quadruped to have connexion with it; for it is an abomination."}}, {"v": 24, "ref": "18:24", "o": "אַל תִּֽטַּמְּא֖וּ בְּ/כָל אֵ֑לֶּה כִּ֤י בְ/כָל אֵ֨לֶּה֙ נִטְמְא֣וּ הַ/גּוֹיִ֔ם אֲשֶׁר אֲנִ֥י מְשַׁלֵּ֖חַ מִ/פְּנֵי/כֶֽם", "en": {"kjv": "Defile not ye yourselves in any of these things: for in all these the nations are defiled which I cast out before you:", "web": "“‘Don’t defile yourselves in any of these things: for in all these the nations which I am casting out before you were defiled.", "bsb": "Do not defile yourselves by any of these practices, for by all these things the nations I am driving out before you have defiled themselves.", "asv": "Defile not ye yourselves in any of these things: for in all these the nations are defiled which I cast out from before you;", "ylt": "`Ye are not defiled with all these, for with all these have the nations been defiled which I am sending away from before you;", "tyndale": "Defile not youre selues in any of these thinges, for with all these thinges are these nacions defiled whiche I cast out before you:", "dra": "Defile not yourselves with any of these things with which all the nations have been defiled, which I will cast out before you,", "bbe": "Do not make yourself unclean in any of these ways; for so have those nations whom I am driving out from before you made themselves unclean:", "geneva": "Yee shall not defile your selues in any of these things: for in al these the nations are defiled, which I will cast out before you:", "wycliffe": "Be ye not defoulid in alle these thingis, in whiche alle `folkis, ether hethen men, ben defoulid, whiche folkis Y schal caste out bifor youre siyt,", "rotherham": "Do not make yourselves unclean in any of these things,—For in all these things, have the nations made themselves unclean, whom, I, am sending out from before you.", "darby": "Make not yourselves unclean in any of these things; for in all these have the nations which I am casting out before you made themselves unclean.", "twenty": "", "jps": "Defile not ye yourselves in any of these things; for in all these the nations are defiled, which I cast out from before you.", "acv": "Do not defile ye yourselves in any of these things. For in all these the nations are defiled which I cast out from before you,", "anderson": "", "haweis": "", "noyes": "", "webster": "Defile not ye yourselves in any of these things; for in all these the nations are defiled which I cast out before you:", "vulgate": "ne polluamini in omnibus his quibus contaminatae sunt universae gentes quas ego eiciam ante conspectum vestrum;", "brenton": "Do not defile yourselves with any of these things; for in all these things the nations are defiled, which I drive out before you,"}}, {"v": 25, "ref": "18:25", "o": "וַ/תִּטְמָ֣א הָ/אָ֔רֶץ וָ/אֶפְקֹ֥ד עֲוֺנָ֖/הּ עָלֶ֑י/הָ וַ/תָּקִ֥א הָ/אָ֖רֶץ אֶת יֹשְׁבֶֽי/הָ", "en": {"kjv": "And the land is defiled: therefore I do visit the iniquity thereof upon it, and the land itself vomiteth out her inhabitants.", "web": "The land was defiled: therefore I punished its iniquity, and the land vomited out her inhabitants.", "bsb": "Even the land has become defiled, so I am punishing it for its sin, and the land will vomit out its inhabitants.", "asv": "and the land is defiled: therefore I do visit the iniquity thereof upon it, and the land vomiteth out her inhabitants.", "ylt": "and the land is defiled, and I charge its iniquity upon it, and the land vomiteth out its inhabitants:", "tyndale": "and the lande is defiled, and I will visett the wykednesse thereof apon it. and the lande shal spewe out hir inhabiters.", "dra": "And with which the land is defiled: the abominations of which I will visit, that it may vomit out its inhabitants.", "bbe": "And the land itself has become unclean; so that I have sent on it the reward of its wrongdoing, and the land itself puts out those who are living in it.", "geneva": "And the land is defiled: therefore I wil visit the wickednesse thereof vpon it, and the lande shall vomit out her inhabitants.", "wycliffe": "of whiche the lond is defoulid, of which lond Y schal vysyte the grete synnes, that it spewe out hise dwellers.", "rotherham": "Therefore hath the land become unclean, and I have visited the iniquity thereof upon it,—and the land hath vomited her inhabitants.", "darby": "And the land hath become unclean; and I visit the iniquity thereof upon it, and the land vomiteth out its inhabitants.", "twenty": "", "jps": "And the land was defiled, therefore I did visit the iniquity thereof upon it, and the land vomited out her inhabitants.", "acv": "and the land is defiled. Therefore I visit the iniquity of it upon it, and the land vomits out its inhabitants.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the land is defiled: therefore I do visit its iniquity upon it, and the land itself vomiteth out her inhabitants.", "vulgate": "et quibus polluta est terra cuius ego scelera visitabo ut evomat habitatores suos;", "brenton": "and the land is polluted; and I have recompensed their iniquity to them because of it, and the land is aggrieved with them that dwell upon it."}}, {"v": 26, "ref": "18:26", "o": "וּ/שְׁמַרְתֶּ֣ם אַתֶּ֗ם אֶת חֻקֹּתַ/י֙ וְ/אֶת מִשְׁפָּטַ֔/י וְ/לֹ֣א תַעֲשׂ֔וּ מִ/כֹּ֥ל הַ/תּוֹעֵבֹ֖ת הָ/אֵ֑לֶּה הָֽ/אֶזְרָ֔ח וְ/הַ/גֵּ֖ר הַ/גָּ֥ר בְּ/תוֹכְ/כֶֽם", "en": {"kjv": "Ye shall therefore keep my statutes and my judgments, and shall not commit any of these abominations; neither any of your own nation, nor any stranger that sojourneth among you:", "web": "You therefore shall keep my statutes and my ordinances, and shall not do any of these abominations; neither the native-born, nor the stranger who lives as a foreigner among you;", "bsb": "But you are to keep My statutes and ordinances, and you must not commit any of these abominations—neither your native-born nor the foreigner who lives among you.", "asv": "Ye therefore shall keep my statutes and mine ordinances, and shall not do any of these abominations; neither the home-born, nor the stranger that sojourneth among you", "ylt": "and ye--ye have kept My statutes and My judgments, and do not any of all these abominations, the native and the sojourner who is sojourning in your midst,", "tyndale": "Kepe ye therfore myne ordinaunces and iudgementes, and se that ye commytt none of these abominacions: nether any of you nor ony straunger that soiourneth amonge you", "dra": "Keep ye my ordinances and my judgments: and do not any of these abominations. Neither any of your own nation, nor any stranger that sojourneth among you.", "bbe": "So then keep my rules and my decisions, and do not do any of these disgusting things, those of you who are Israelites by birth, or any others who are living with you:", "geneva": "Ye shall keepe therefore mine ordinances, and my iudgements, and commit none of these abominations, aswell hee that is of the same countrey, as the straunger that soiourneth among you.", "wycliffe": "Kepe ye my lawful thingis and domes, that ye do not of alle these abhomynaciouns, as wel a man borun in the lond as a comelyng which is a pilgrym at you.", "rotherham": "Ye, therefore, shall observe my statutes and my regulations, and have nothing to do with any of these abominations,—whether the home-born, or the sojourner that sojourneth in your midst;", "darby": "But ye shall observe my statutes and my judgments, and shall not commit any of all these abominations: the home-born, and the stranger that sojourneth among you;", "twenty": "", "jps": "Ye therefore shall keep My statutes and Mine ordinances, and shall not do any of these abominations; neither the home-born, nor the stranger that sojourneth among you--", "acv": "Ye therefore shall keep my statutes and my ordinances, and shall not do any of these abominations, neither the home-born, nor the stranger that sojourns among you,", "anderson": "", "haweis": "", "noyes": "", "webster": "Ye shall therefore keep my statutes and my judgments, and shall not commit [any] of these abominations; [neither] any of your own nation, nor any stranger that sojourneth among you.", "vulgate": "custodite legitima mea atque iudicia et non faciat ex omnibus abominationibus istis tam indigena quam colonus qui peregrinatur apud vos;", "brenton": "And ye shall keep all my statutes and all my ordinances, and ye shall do none of these abominations; neither the native, nor the stranger that joins himself with you:"}}, {"v": 27, "ref": "18:27", "o": "כִּ֚י אֶת כָּל הַ/תּוֹעֵבֹ֣ת הָ/אֵ֔ל עָשׂ֥וּ אַנְשֵֽׁי הָ/אָ֖רֶץ אֲשֶׁ֣ר לִ/פְנֵי/כֶ֑ם וַ/תִּטְמָ֖א הָ/אָֽרֶץ", "en": {"kjv": "(For all these abominations have the men of the land done, which were before you, and the land is defiled;)", "web": "(for all these abominations have the men of the land done, that were before you, and the land became defiled);", "bsb": "For the men who were in the land before you committed all these abominations, and the land has become defiled.", "asv": "(for all these abominations have the men of the land done, that were before you, and the land is defiled);", "ylt": "(for all these abominations have the men of the land done who are before you, and the land is defiled),", "tyndale": "(for all these abhominacions haue the men of the lande done whiche were there before you, and the lande is defiled)", "dra": "For all these detestable things the inhabitants of the land have done, that were before you, and have defiled it.", "bbe": "(For all these disgusting things were done by the men of this country who were there before you, and the land has been made unclean by them;)", "geneva": "(For all these abominations haue the men of the land done, which were before you, and the land is defiled:", "wycliffe": "For the dwellers of the lond, that weren bifor you, diden alle these abhomynaciouns, and defouliden that lond.", "rotherham": "For all these abominations, have the men of the land done, who were before you; And so the land hath become unclean:", "darby": "(for all these abominations have the men of the land done, who were before you, and the land hath been made unclean);", "twenty": "", "jps": "for all these abominations have the men of the land done, that were before you, and the land is defiled--", "acv": "(for all these abominations the men of the land have done, who were before you, and the land is defiled),", "anderson": "", "haweis": "", "noyes": "", "webster": "(For all these abominations have the men of the land done, who [were] before you, and the land is defiled;)", "vulgate": "omnes enim execrationes istas fecerunt accolae terrae qui fuerunt ante vos et polluerunt eam;", "brenton": "(for all these abominations the men of the land did who were before you, and the land was defiled,)"}}, {"v": 28, "ref": "18:28", "o": "וְ/לֹֽא תָקִ֤יא הָ/אָ֨רֶץ֙ אֶתְ/כֶ֔ם בְּ/טַֽמַּאֲ/כֶ֖ם אֹתָ֑/הּ כַּ/אֲשֶׁ֥ר קָאָ֛ה אֶת הַ/גּ֖וֹי אֲשֶׁ֥ר לִ/פְנֵי/כֶֽם", "en": {"kjv": "That the land spue not you out also, when ye defile it, as it spued out the nations that were before you.", "web": "that the land not vomit you out also, when you defile it, as it vomited out the nation that was before you.", "bsb": "So if you defile the land, it will vomit you out as it spewed out the nations before you.", "asv": "that the land vomit not you out also, when ye defile it, as it vomited out the nation that was before you.", "ylt": "and the land doth not vomit you out in your defiling it, as it hath vomited out the nation which is before you;", "tyndale": "lest that the lande spewe you out when ye haue defiled it, as it spewed out the nacions that where there before you.", "dra": "Beware then, lest in like manner, it vomit you also out, if you do the like things: as it vomited out the nation that was before you.", "bbe": "So that the land may not put you out from it, when you make it unclean, as it put out the nations which were there before you.", "geneva": "And shall not the lande spue you out if ye defile it, as it spued out the people that were before you?)", "wycliffe": "Therfor be ye war, lest it caste out viliche also you in lijk manere, whanne ye han do lijk synnes, as it castide out vileche the folk, that was bifor you.", "rotherham": "So shall the land not vomit you, through your making it unclean,—as it vomited the nation which was before you.", "darby": "that the land vomit you not out, when ye make it unclean, as it vomited out the nation that was before you.", "twenty": "", "jps": "that the land vomit not you out also, when ye defile it, as it vomited out the nation that was before you.", "acv": "that the land not vomit you out also, when ye defile it, as it vomited out the nation that was before you.", "anderson": "", "haweis": "", "noyes": "", "webster": "That the land may not vomit you out also, when ye defile it, as it vomited out the nations that [were] before you.", "vulgate": "cavete ergo ne et vos similiter evomat cum paria feceritis sicut evomuit gentem quae fuit ante vos;", "brenton": "and lest the land be aggrieved with you in your polluting it, as it was aggrieved with the nations before you."}}, {"v": 29, "ref": "18:29", "o": "כִּ֚י כָּל אֲשֶׁ֣ר יַעֲשֶׂ֔ה מִ/כֹּ֥ל הַ/תּוֹעֵב֖וֹת הָ/אֵ֑לֶּה וְ/נִכְרְת֛וּ הַ/נְּפָשׁ֥וֹת הָ/עֹשֹׂ֖ת מִ/קֶּ֥רֶב עַמָּֽ/ם", "en": {"kjv": "For whosoever shall commit any of these abominations, even the souls that commit them shall be cut off from among their people.", "web": "“‘For whoever shall do any of these abominations, even the souls that do them shall be cut off from among their people.", "bsb": "Therefore anyone who commits any of these abominations must be cut off from among his people.", "asv": "For whosoever shall do any of these abominations, even the souls that do them shall be cut off from among their people.", "ylt": "for any one who doth any of all these abominations--even the persons who are doing so , have been cut off from the midst of their people;", "tyndale": "For whosoeuer shall comytt any of these abhominacions, the same soules that commytt them shall perish from amonge their people.", "dra": "Every soul that shall commit any of these abominations, shall perish from the midst of his people.", "bbe": "For all those who do any of these disgusting things will be cut off from among their people.", "geneva": "For whosoeuer shall commit any of these abominations, the persons that doe so, shall bee cut off from among their people.", "wycliffe": "Ech man that doith ony thing of these abhomynaciouns, schal perische fro the myddis of his puple.", "rotherham": "For whosoever shall have anything to do with any of these abominations, the persons who have, shall be cut off, out of the midst of their people.", "darby": "For whoever committeth any of these abominations, ...the souls that commit them shall be cut off from among their people.", "twenty": "", "jps": "For whosoever shall do any of these abominations, even the souls that do them shall be cut off from among their people.", "acv": "For whoever shall do any of these abominations, even the souls that do them shall be cut off from among their people.", "anderson": "", "haweis": "", "noyes": "", "webster": "For whoever shall commit any of these abominations, even the souls that commit [them] shall be cut off from among their people.", "vulgate": "omnis anima quae fecerit de abominationibus his quippiam peribit de medio populi sui;", "brenton": "For whosoever shall do any of these abominations, the souls that do them shall be destroyed from among their people."}}, {"v": 30, "ref": "18:30", "o": "וּ/שְׁמַרְתֶּ֣ם אֶת מִשְׁמַרְתִּ֗/י לְ/בִלְתִּ֨י עֲשׂ֜וֹת מֵ/חֻקּ֤וֹת הַ/תּֽוֹעֵבֹת֙ אֲשֶׁ֣ר נַעֲשׂ֣וּ לִ/פְנֵי/כֶ֔ם וְ/לֹ֥א תִֽטַּמְּא֖וּ בָּ/הֶ֑ם אֲנִ֖י יְהוָ֥ה אֱלֹהֵי/כֶֽם", "en": {"kjv": "Therefore shall ye keep mine ordinance, that ye commit not any one of these abominable customs, which were committed before you, and that ye defile not yourselves therein: I am the Lord your God.", "web": "Therefore you shall keep my requirements, that you do not practice any of these abominable customs, which were practiced before you, and that you do not defile yourselves with them. I am Yahweh your God.’”", "bsb": "You must keep My charge not to practice any of the abominable customs that were practiced before you, so that you do not defile yourselves by them. I am the LORD your God.”", "asv": "Therefore shall ye keep my charge, that ye practise not any of these abominable customs, which were practised before you, and that ye defile not yourselves therein: I am Jehovah your God.", "ylt": "and ye have kept My charge, so as not to do any of the abominable statutes which have been done before you, and ye do not defile yourselves with them; I am Jehovah your God.'", "tyndale": "Therfore se that ye kepe myne ordinaunces, that ye commytt none of these abhominable customes which were commytted before you: that ye defile not youre selues therewith for I am the Lorde youre God.", "dra": "Keep my commandments. Do not the things which they have done, that have been before you: and be not defiled therein. I am the Lord your God.", "bbe": "So then, keep my orders, so that you may not do any of these disgusting things which were done before you, or make yourselves unclean through them: I am the Lord your God.", "geneva": "Therefore shall yee keepe mine ordinances that ye do not any of the abominable customes, which haue bene done before you, and that yee defile not your selues therein: for I am the Lord your God.", "wycliffe": "Kepe ye myn heestis; nyle ye do tho thingis, whiche thei that weren bifor you diden, and be ye not defoulid in tho; Y am youre Lord God.", "rotherham": "Therefore shall ye keep my charge, So that ye may have nothing to do with any of the abominable statutes with which they have had to do before you, So shall ye not make yourselves unclean thereby,—I—Yahweh, am your God.", "darby": "And ye shall observe my charge, that ye commit not [any] of the abominable customs which were committed before you; and ye shall not make yourselves unclean therein: I am Jehovah yourGod.", "twenty": "", "jps": "Therefore shall ye keep My charge, that ye do not any of these abominable customs, which were done before you, and that ye defile not yourselves therein: I am HaShem your G-d.", "acv": "Therefore ye shall keep my charge, that ye not practice any of these abominable customs, which were practiced before you, and that ye not defile yourselves in it. I am Jehovah your God.", "anderson": "", "haweis": "", "noyes": "", "webster": "Therefore shall ye keep my ordinance, that [ye] commit not [any one] of these abominable customs, which were committed before you, and that ye defile not yourselves in them; I [am] the LORD your God.", "vulgate": "custodite mandata mea nolite facere quae fecerunt hii qui fuerunt ante vos et ne polluamini in eis ego Dominus Deus vester;", "brenton": "And ye shall keep mine ordinances, that ye may not do any of the abominable practices, which have taken place before your time: and ye shall not be polluted in them; for I am the Lord your God."}}]}, {"c": 19, "verses": [{"v": 1, "ref": "19:1", "o": "וַ/יְדַבֵּ֥ר יְהוָ֖ה אֶל מֹשֶׁ֥ה לֵּ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh spoke to Moses, saying,", "bsb": "Then the LORD said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde spake vnto Moses sayenge:", "dra": "The Lord spoke to Moses, saying:", "bbe": "And the Lord said to Moses,", "geneva": "And the Lord spake vnto Moses, saying,", "wycliffe": "The Lord spak to Moises, and seide,", "rotherham": "And Yahweh spake unto Moses, saying:", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses, saying:", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "locutus est Dominus ad Mosen dicens;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 2, "ref": "19:2", "o": "דַּבֵּ֞ר אֶל כָּל עֲדַ֧ת בְּנֵי יִשְׂרָאֵ֛ל וְ/אָמַרְתָּ֥ אֲלֵ/הֶ֖ם קְדֹשִׁ֣ים תִּהְי֑וּ כִּ֣י קָד֔וֹשׁ אֲנִ֖י יְהוָ֥ה אֱלֹהֵי/כֶֽם", "en": {"kjv": "Speak unto all the congregation of the children of Israel, and say unto them, Ye shall be holy: for I the Lord your God am holy.", "web": "“Speak to all the congregation of the children of Israel, and tell them, ‘You shall be holy; for I, Yahweh your God, am holy.", "bsb": "“Speak to the whole congregation of Israel and tell them: Be holy because I, the LORD your God, am holy.", "asv": "Speak unto all the congregation of the children of Israel, and say unto them, Ye shall be holy; for I Jehovah your God am holy.", "ylt": "`Speak unto all the company of the sons of Israel, and thou hast said unto them, Ye are holy, for holy am I, Jehovah, your God.", "tyndale": "speake vnto all the multitude of the childern of Israel, and saye vnto them. Be holy for I the Lorde youre God am holye.", "dra": "Speak to all the congregation of the children of Israel. And thou shalt say to them: Be ye holy, because I the Lord your God am holy.", "bbe": "Say to all the people of Israel, You are to be holy, for I, the Lord your God, am holy.", "geneva": "Speake vnto all the Congregation of the children of Israel, and say vnto them, Ye shalbe holy, for I the Lord your God am holy.", "wycliffe": "Speke thou to al the cumpenye of the sones of Israel, and thou schalt seie to hem, Be ye hooli, for Y am hooli, youre Lord God.", "rotherham": "Speak unto all the assembly of the sons of Israel and thou shalt say unto them—Holy, shall ye be,—For holy, am I—Yahweh—your God", "darby": "Speak unto all the assembly of the children of Israel, and say unto them, Holy shall ye be, for I Jehovah yourGod am holy.", "twenty": "", "jps": "Speak unto all the congregation of the children of Israel, and say unto them: Ye shall be holy; for I HaShem your G-d am holy.", "acv": "Speak to all the congregation of the sons of Israel, and say to them, Ye shall be holy, for I Jehovah your God am holy.", "anderson": "", "haweis": "", "noyes": "", "webster": "Speak to all the congregation of the children of Israel, and say to them, Ye shall be holy: for I the LORD your God [am] holy.", "vulgate": "loquere ad omnem coetum filiorum Israhel et dices ad eos sancti estote quia ego sanctus sum Dominus Deus vester;", "brenton": "Speak to the congregation of the children of Israel, and thou shalt say to them, Ye shall be holy; for I the Lord your God am holy."}}, {"v": 3, "ref": "19:3", "o": "אִ֣ישׁ אִמּ֤/וֹ וְ/אָבִי/ו֙ תִּירָ֔אוּ וְ/אֶת שַׁבְּתֹתַ֖/י תִּשְׁמֹ֑רוּ אֲנִ֖י יְהוָ֥ה אֱלֹהֵי/כֶֽם", "en": {"kjv": "Ye shall fear every man his mother, and his father, and keep my sabbaths: I am the Lord your God.", "web": "“‘Each one of you shall respect his mother and his father. You shall keep my Sabbaths. I am Yahweh your God.", "bsb": "Each of you must respect his mother and father, and you must keep My Sabbaths. I am the LORD your God.", "asv": "Ye shall fear every man his mother, and his father; and ye shall keep my sabbaths: I am Jehovah your God.", "ylt": "`Each his mother and his father ye do fear, and My sabbaths ye do keep; I am Jehovah your God.", "tyndale": "Se that ye feare: euery man his father and his mother, ad that ye kepe my Sabbathes, for I am the Lorde youre God.", "dra": "Let every one fear his father, and his mother. Keep my sabbaths. I am the Lord your God.", "bbe": "Let every man give honour to his mother and to his father and keep my Sabbaths: I am the Lord your God.", "geneva": "Yee shall feare euery man his mother and his father, and shall keepe my Sabbaths: for I am the Lord your God.", "wycliffe": "Ech man drede his fadir and his modir. Kepe ye my sabatis; Y am youre Lord God.", "rotherham": "Ye shall, every one, revere, his father and his mother, And my sabbaths, shall ye observe,—I—Yahweh, am your God.", "darby": "Ye shall reverence every man his mother, and his father, and my sabbaths shall ye keep: I am Jehovah yourGod.", "twenty": "", "jps": "Ye shall fear every man his mother, and his father, and ye shall keep My sabbaths: I am HaShem your G-d.", "acv": "Every man shall fear his mother and his father. And ye shall keep my sabbaths. I am Jehovah your God.", "anderson": "", "haweis": "", "noyes": "", "webster": "Ye shall fear every man his mother and his father, and keep my sabbaths: I [am] the LORD your God.", "vulgate": "unusquisque matrem et patrem suum timeat sabbata mea custodite ego Dominus Deus vester;", "brenton": "Let every one of you reverence his father and his mother; and ye shall keep my sabbaths: I am the Lord your God."}}, {"v": 4, "ref": "19:4", "o": "אַל תִּפְנוּ֙ אֶל הָ֣/אֱלִילִ֔ים וֵֽ/אלֹהֵי֙ מַסֵּכָ֔ה לֹ֥א תַעֲשׂ֖וּ לָ/כֶ֑ם אֲנִ֖י יְהוָ֥ה אֱלֹהֵי/כֶֽם", "en": {"kjv": "Turn ye not unto idols, nor make to yourselves molten gods: I am the Lord your God.", "web": "“‘Don’t turn to idols, nor make molten gods for yourselves. I am Yahweh your God.", "bsb": "Do not turn to idols or make for yourselves molten gods. I am the LORD your God.", "asv": "Turn ye not unto idols, nor make to yourselves molten gods: I am Jehovah your God.", "ylt": "`Ye do not turn unto the idols, and a molten god ye do not make to yourselves; I am Jehovah your God.", "tyndale": "Ye shall not turne vnto ydolls nor make you goddes of metall: I am the Lorde youre God.", "dra": "Turn ye not to idols: nor make to yourselves molten gods. I am the Lord your God.", "bbe": "Do not go after false gods, and do not make metal images of gods for yourselves: I am the Lord your God.", "geneva": "Ye shall not turne vnto idoles, nor make you molten gods: I am the Lord your God.", "wycliffe": "Nyle ye be turned to ydols, nether ye schulen make to you yotun goddis; Y am youre Lord God.", "rotherham": "Do not turn unto things of nought, And, molten gods, shall ye not make to yourselves,—I—Yahweh, am your God.", "darby": "Ye shall not turn unto idols, and ye shall not make to yourselves moltengods: I am Jehovah yourGod.", "twenty": "", "jps": "Turn ye not unto the idols, nor make to yourselves molten gods: I am HaShem your G-d.", "acv": "Turn ye not to idols, nor make to yourselves molten gods. I am Jehovah your God.", "anderson": "", "haweis": "", "noyes": "", "webster": "Turn ye not to idols, nor make to yourselves molten gods: I [am] the LORD your God.", "vulgate": "nolite converti ad idola nec deos conflatiles faciatis vobis ego Dominus Deus vester;", "brenton": "Ye shall not follow idols, and ye shall not make to yourselves molten gods: I am the Lord your God."}}, {"v": 5, "ref": "19:5", "o": "וְ/כִ֧י תִזְבְּח֛וּ זֶ֥בַח שְׁלָמִ֖ים לַ/יהוָ֑ה לִֽ/רְצֹנְ/כֶ֖ם תִּזְבָּחֻֽ/הוּ", "en": {"kjv": "And if ye offer a sacrifice of peace offerings unto the Lord, ye shall offer it at your own will.", "web": "“‘When you offer a sacrifice of peace offerings to Yahweh, you shall offer it so that you may be accepted.", "bsb": "When you sacrifice a peace offering to the LORD, you shall offer it for your acceptance.", "asv": "And when ye offer a sacrifice of peace-offerings unto Jehovah, ye shall offer it that ye may be accepted.", "ylt": "`And when ye sacrifice a sacrifice of peace-offerings to Jehovah, at your pleasure ye do sacrifice it;", "tyndale": "When ye offre youre peaceofferynges vnto the Lorde, ye shall offer them that ye maye be accepted.", "dra": "If ye offer in sacrifice a peace offering to the Lord, that he may be favourable:", "bbe": "And when you give a peace offering to the Lord, do it in the way which is pleasing to the Lord.", "geneva": "And when yee shall offer a peace offering vnto the Lord, ye shall offer it freely.", "wycliffe": "If ye offren a sacrifice of pesible thingis to the Lord, that it be quemeful,", "rotherham": "And when ye would offer a peace-offering unto Yahweh, ye shall offer it that ye may be accepted.", "darby": "And if ye sacrifice a sacrifice of peace-offering to Jehovah, ye shall sacrifice it for your acceptance.", "twenty": "", "jps": "And when ye offer a sacrifice of peace-offerings unto HaShem, ye shall offer it that ye may be accepted.", "acv": "And when ye offer a sacrifice of peace offerings to Jehovah, ye shall offer it that ye may be accepted.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if ye offer a sacrifice of peace-offerings to the LORD, ye shall offer it at your own will.", "vulgate": "si immolaveritis hostiam pacificorum Domino ut sit placabilis;", "brenton": "And if ye will sacrifice a peace-offering to the Lord, ye shall offer it acceptable from yourselves."}}, {"v": 6, "ref": "19:6", "o": "בְּ/י֧וֹם זִבְחֲ/כֶ֛ם יֵאָכֵ֖ל וּ/מִֽ/מָּחֳרָ֑ת וְ/הַ/נּוֹתָר֙ עַד י֣וֹם הַ/שְּׁלִישִׁ֔י בָּ/אֵ֖שׁ יִשָּׂרֵֽף", "en": {"kjv": "It shall be eaten the same day ye offer it, and on the morrow: and if ought remain until the third day, it shall be burnt in the fire.", "web": "It shall be eaten the same day you offer it, and on the next day: and if anything remains until the third day, it shall be burned with fire.", "bsb": "It shall be eaten on the day you sacrifice it, or on the next day; but what remains on the third day must be burned up.", "asv": "It shall be eaten the same day ye offer it, and on the morrow: and if aught remain until the third day, it shall be burnt with fire.", "ylt": "in the day of your sacrificing it is eaten, and on the morrow, and that which is left unto the third day with fire is burnt,", "tyndale": "And it shalbe eaten the same daye ye offer it and on the morowe, but what soeuer is lefte on the thirde daye shalbe burnt in the fire.", "dra": "You shall eat it on the same day it was offered, and the next day. And whatsoever shall be left until the third day, you shall burn with fire.", "bbe": "Let it be used for food on the same day on which it is offered, or on the day after; and whatever is over on the third day is to be burned with fire.", "geneva": "It shall be eaten the day yee offer it, or on the morowe: and that which remaineth vntill the third day, shalbe burnt in the fire.", "wycliffe": "ye schulen ete it in that day, in which it is offrid, and in the tother dai; sotheli what euer thing is residue in to the thridde dai, ye schulen brenne in fier.", "rotherham": "On the day, ye offer it, shall it be eaten, and on the morrow,—but, that which remaineth until the third day, in fire, shall be consumed.", "darby": "On the day when ye sacrifice it shall it be eaten, and on the morrow; and that which remaineth until the third day shall be burned with fire.", "twenty": "", "jps": "It shall be eaten the same day ye offer it, and on the morrow; and if aught remain until the third day, it shall be burnt with fire.", "acv": "It shall be eaten the same day ye offer it, and on the morrow. And if any remain until the third day, it shall be burnt with fire.", "anderson": "", "haweis": "", "noyes": "", "webster": "It shall be eaten the same day ye offer it, and on the morrow: and if aught shall remain until the third day, it shall be burnt in the fire.", "vulgate": "eo die quo fuerit immolata comedetis eam et die altero quicquid autem residuum fuerit in diem tertium igne conburetis;", "brenton": "In what day soever ye shall sacrifice it, it shall be eaten; and on the following day, and if any of it should be left till the third day, it shall be thoroughly burnt with fire."}}, {"v": 7, "ref": "19:7", "o": "וְ/אִ֛ם הֵאָכֹ֥ל יֵאָכֵ֖ל בַּ/יּ֣וֹם הַ/שְּׁלִישִׁ֑י פִּגּ֥וּל ה֖וּא לֹ֥א יֵרָצֶֽה", "en": {"kjv": "And if it be eaten at all on the third day, it is abominable; it shall not be accepted.", "web": "If it is eaten at all on the third day, it is an abomination. It will not be accepted;", "bsb": "If any of it is eaten on the third day, it is tainted and will not be accepted.", "asv": "And if it be eaten at all on the third day, it is an abomination; it shall not be accepted:", "ylt": "and if it be really eaten on the third day, it is an abomination, it is not pleasing,", "tyndale": "Yf it be eaten the thirde daye, it shalbe vncleane ad not accepted.", "dra": "If after two days any man eat thereof, he shall be profane and guilty of impiety:", "bbe": "If any of it is used for food on the third day, it is a disgusting thing and will not be pleasing to the Lord.", "geneva": "For if it be eaten the third day, it shall be vncleane, it shall not be accepted.", "wycliffe": "If ony man etith therof aftir twei daes, he schal be vnhooli, and gilti of vnfeithfulnes `ether wickidnesse; and he schal bere his wickidnesse,", "rotherham": "And, if it, be eaten, on the third day, unclean, it is it shall not be accepted,", "darby": "And if it be eaten at all on the third day, it is an unclean thing: it shall not be accepted.", "twenty": "", "jps": "And if it be eaten at all on the third day, it is a vile thing; it shall not be accepted.", "acv": "And if it is eaten at all on the third day, it is an abomination. It shall not be accepted.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if it shall be eaten at all on the third day, it [is] abominable; it shall not be accepted.", "vulgate": "si quis post biduum comederit ex ea profanus erit et impietatis reus;", "brenton": "And if it should be at all eaten on the third day, it is unfit for sacrifice: it shall not be accepted."}}, {"v": 8, "ref": "19:8", "o": "וְ/אֹֽכְלָי/ו֙ עֲוֺנ֣/וֹ יִשָּׂ֔א כִּֽי אֶת קֹ֥דֶשׁ יְהוָ֖ה חִלֵּ֑ל וְ/נִכְרְתָ֛ה הַ/נֶּ֥פֶשׁ הַ/הִ֖וא מֵ/עַמֶּֽי/הָ", "en": {"kjv": "Therefore every one that eateth it shall bear his iniquity, because he hath profaned the hallowed thing of the Lord: and that soul shall be cut off from among his people.", "web": "but everyone who eats it shall bear his iniquity, because he has profaned the holy thing of Yahweh, and that soul shall be cut off from his people.", "bsb": "Whoever eats it will bear his iniquity, for he has profaned what is holy to the LORD. That person must be cut off from his people.", "asv": "but every one that eateth it shall bear his iniquity, because he hath profaned the holy thing of Jehovah: and that soul shall be cut off from his people.", "ylt": "and he who is eating it his iniquity doth bear, for the holy thing of Jehovah he hath polluted, and that person hath been cut off from his people.", "tyndale": "And he that eateth it shall bere his synne: because he hath defiled the halowed thinges of the Lorde, ad that soule shall perish from amonge his people.", "dra": "And shall bear his iniquity, because he hath defiled the holy thing of the Lord. And that soul shall perish from among his people.", "bbe": "And as for anyone who takes it for food, his sin will be on him, for he has put shame on the holy thing of the Lord: he will be cut off from his people.", "geneva": "Therefore he that eateth it, shall beare his iniquitie, because he hath defiled the halowed thing of the Lord, and that person shalbe cut off from his people.", "wycliffe": "for he defoulide the hooli thing of the Lord, and his soule schal perische fro his puple.", "rotherham": "But he that eateth it, his iniquity, shall bear, because that which had been hallowed unto Yahweh, hath he profaned,—so then that person shall be cut off from among his kinsfolk.", "darby": "And he that eateth it shall bear his iniquity; for he hath profaned the hallowed thing of Jehovah; and that soul shall be cut off from among his peoples.", "twenty": "", "jps": "But every one that eateth it shall bear his iniquity, because he hath profaned the holy thing of HaShem; and that soul shall be cut off from his people.", "acv": "But he who eats it shall bear his iniquity, because he has profaned the holy thing of Jehovah, and that soul shall be cut off from his people.", "anderson": "", "haweis": "", "noyes": "", "webster": "Therefore [every one] that eateth it shall bear his iniquity, because he hath profaned the hallowed thing of the LORD; and that soul shall be cut off from among his people.", "vulgate": "portabit iniquitatem suam quia sanctum Domini polluit et peribit anima illa de populo suo;", "brenton": "And he that eats it shall bear his iniquity, because he has profaned the holy things of the Lord; and the souls that eat it shall be destroyed from among their people."}}, {"v": 9, "ref": "19:9", "o": "וּֽ/בְ/קֻצְרְ/כֶם֙ אֶת קְצִ֣יר אַרְצְ/כֶ֔ם לֹ֧א תְכַלֶּ֛ה פְּאַ֥ת שָׂדְ/ךָ֖ לִ/קְצֹ֑ר וְ/לֶ֥קֶט קְצִֽירְ/ךָ֖ לֹ֥א תְלַקֵּֽט", "en": {"kjv": "And when ye reap the harvest of your land, thou shalt not wholly reap the corners of thy field, neither shalt thou gather the gleanings of thy harvest.", "web": "“‘When you reap the harvest of your land, you shall not wholly reap the corners of your field, neither shall you gather the gleanings of your harvest.", "bsb": "When you reap the harvest of your land, you are not to reap to the very edges of your field or gather the gleanings of your harvest.", "asv": "And when ye reap the harvest of your land, thou shalt not wholly reap the corners of thy field, neither shalt thou gather the gleaning of thy harvest.", "ylt": "`And in your reaping the harvest of your land ye do not completely reap the corner of thy field, and the gleaning of thy harvest thou dost not gather,", "tyndale": "When ye repe doune the rype corne of youre lande, ye shal not repe doune the vtmost borders of youre feldes, nether shalt thou gather that which is left behynd in thy haruest.", "dra": "When thou reapest the corn of thy land, thou shalt not cut down all that is on the face of the earth to the very ground: nor shalt thou gather the ears that remain.", "bbe": "And when you get in the grain from your land, do not let all the grain be cut from the edges of the field, or take up what has been dropped on the earth after the getting in of the grain.", "geneva": "When yee reape the haruest of your land, ye shall not reape euery corner of your field, neither shalt thou gather the glainings of thy haruest.", "wycliffe": "Whanne thou schalt repe the fruytis of thi lond, thou schalt not kitte `til to the ground the corn of the lond, nether thou schalt gadere the eeris of corn that ben left;", "rotherham": "And when ye reap the harvest of your land, thou shalt not wholly clear the border of thy field, in reaping,—nor shalt thou gather up the gleaning of thy harvest.", "darby": "And when ye reap the harvest of your land, thou shalt not wholly reap the corners of thy field, and the gleaning of thy harvest thou shalt not gather.", "twenty": "", "jps": "And when ye reap the harvest of your land, thou shalt not wholly reap the corner of thy field, neither shalt thou gather the gleaning of thy harvest.", "acv": "And when ye reap the harvest of your land, thou shall not wholly reap the corners of thy field, nor shall thou gather the gleaning of thy harvest.", "anderson": "", "haweis": "", "noyes": "", "webster": "And when ye reap the harvest of your land, thou shalt not wholly reap the corners of thy field, neither shalt thou gather the gleanings of thy harvest.", "vulgate": "cum messueris segetes terrae tuae non tondebis usque ad solum superficiem terrae nec remanentes spicas colliges;", "brenton": "And when ye reap the harvest of your land, ye shall not complete the reaping of your field with exactness, and thou shalt not gather that which falls from thy reaping."}}, {"v": 10, "ref": "19:10", "o": "וְ/כַרְמְ/ךָ֙ לֹ֣א תְעוֹלֵ֔ל וּ/פֶ֥רֶט כַּרְמְ/ךָ֖ לֹ֣א תְלַקֵּ֑ט לֶֽ/עָנִ֤י וְ/לַ/גֵּר֙ תַּעֲזֹ֣ב אֹתָ֔/ם אֲנִ֖י יְהוָ֥ה אֱלֹהֵי/כֶֽם", "en": {"kjv": "And thou shalt not glean thy vineyard, neither shalt thou gather every grape of thy vineyard; thou shalt leave them for the poor and stranger: I am the Lord your God.", "web": "You shall not glean your vineyard, neither shall you gather the fallen grapes of your vineyard; you shall leave them for the poor and for the foreigner. I am Yahweh your God.", "bsb": "You must not strip your vineyard bare or gather its fallen grapes. Leave them for the poor and the foreigner. I am the LORD your God.", "asv": "And thou shalt not glean thy vineyard, neither shalt thou gather the fallen fruit of thy vineyard; thou shalt leave them for the poor and for the sojourner: I am Jehovah your God.", "ylt": "and thy vineyard thou dost not glean, even the omitted part of thy vineyard thou dost not gather, to the poor and to the sojourner thou dost leave them; I am Jehovah your God.", "tyndale": "Thou shalt not plucke in all thy vyneyarde clene, nether gather in the grapes that are ouerscaped. But thou shalt leaue them for the pore ad straunger. I am the Lord youre God.", "dra": "Neither shalt thou gather the bunches and grapes that fall down in thy vineyard: but shalt leave them to the poor and the strangers to take. I am the Lord your God.", "bbe": "And do not take all the grapes from your vine-garden, or the fruit dropped on the earth; let the poor man, and the man from another country, have these: I am the Lord your God.", "geneva": "Thou shalt not gather the grapes of thy vineyarde cleane, neyther gather euery grape of thy vineyarde, but thou shalt leaue them for the poore and for the straunger: I am the Lord your God.", "wycliffe": "nethir in thi vyner thou schalt gadere reysyns and greynes fallynge doun, but thou schalt leeue to be gaderid of pore men and pilgryms; Y am youre Lord God.", "rotherham": "And, thy vineyard, shalt thou not go over again, nor gather, every single grape: for the poor and for the sojourner, shalt thou leave them, I—Yahweh, am your God.", "darby": "And thy vineyard shalt thou not glean, neither shalt thou gather what hath been left of thy vineyard; thou shalt leave them for the poor and the stranger: I am Jehovah yourGod.", "twenty": "", "jps": "And thou shalt not glean thy vineyard, neither shalt thou gather the fallen fruit of thy vineyard; thou shalt leave them for the poor and for the stranger: I am HaShem your G-d.", "acv": "And thou shall not glean thy vineyard, nor shall thou gather the fallen fruit of thy vineyard. Thou shall leave them for the poor man and for the sojourner. I am Jehovah your God.", "anderson": "", "haweis": "", "noyes": "", "webster": "And thou shalt not glean thy vineyard, neither shalt thou gather [every] grape of thy vineyard; thou shalt leave them for the poor and stranger: I [am] the LORD your God.", "vulgate": "neque in vinea tua racemos et grana decidentia congregabis sed pauperibus et peregrinis carpenda dimittes ego Dominus Deus vester;", "brenton": "And thou shalt not go over the gathering of thy vineyard, neither shalt thou gather the remaining grapes of thy vineyard: thou shalt leave them for the poor and the stranger: I am the Lord your God."}}, {"v": 11, "ref": "19:11", "o": "לֹ֖א תִּגְנֹ֑בוּ וְ/לֹא תְכַחֲשׁ֥וּ וְ/לֹֽא תְשַׁקְּר֖וּ אִ֥ישׁ בַּ/עֲמִיתֽ/וֹ", "en": {"kjv": "Ye shall not steal, neither deal falsely, neither lie one to another.", "web": "“‘You shall not steal. “‘You shall not lie. “‘You shall not deceive one another.", "bsb": "You must not steal. You must not lie or deceive one another.", "asv": "Ye shall not steal; neither shall ye deal falsely, nor lie one to another.", "ylt": "`Ye do not steal, nor feign, nor lie one against his fellow.", "tyndale": "Ye shall not steale nether lye, nether deale falsely one with another.", "dra": "You shall not steal. You shall not lie: neither shall any man deceive his neighbour.", "bbe": "Do not take anyone's property or be false in act or word to another.", "geneva": "Ye shall not steale, neither deale falsely, neither lie one to another.", "wycliffe": "Ye schulen not do thefte. Ye schulen not lye, and no man disseyue his neiybour.", "rotherham": "Ye shall not steal,—nor deceive nor lie one man to another;", "darby": "Ye shall not steal, and ye shall not deal falsely, and ye shall not lie one to another.", "twenty": "", "jps": "Ye shall not steal; neither shall ye deal falsely, nor lie one to another.", "acv": "Ye shall not steal, nor shall ye deal falsely, nor lie one to another.", "anderson": "", "haweis": "", "noyes": "", "webster": "Ye shall not steal, neither deal falsely, neither lie one to another.", "vulgate": "non facietis furtum non mentiemini nec decipiet unusquisque proximum suum;", "brenton": "Ye shall not steal, ye shall not lie, neither shall one bear false witness as an informer against his neighbour."}}, {"v": 12, "ref": "19:12", "o": "וְ/לֹֽא תִשָּׁבְע֥וּ בִ/שְׁמִ֖/י לַ/שָּׁ֑קֶר וְ/חִלַּלְתָּ֛ אֶת שֵׁ֥ם אֱלֹהֶ֖י/ךָ אֲנִ֥י יְהוָֽה", "en": {"kjv": "And ye shall not swear by my name falsely, neither shalt thou profane the name of thy God: I am the Lord.", "web": "“‘You shall not swear by my name falsely, and profane the name of your God. I am Yahweh.", "bsb": "You must not swear falsely by My name and so profane the name of your God. I am the LORD.", "asv": "And ye shall not swear by my name falsely, and profane the name of thy God: I am Jehovah.", "ylt": "`And ye do not swear by My name to falsehood, or thou hast polluted the name of thy God; I am Jehovah.", "tyndale": "Ye shal not swere by my name falselye: that thou defilest not the name of thy God, I am the Lorde.", "dra": "Thou shalt not swear falsely by my name, nor profane the name of thy God. I am the Lord.", "bbe": "And do not take an oath in my name falsely, putting shame on the name of your God: I am the Lord.", "geneva": "Also yee shall not sweare by my name falsely, neither shalt thou defile the name of thy God: I am the Lord.", "wycliffe": "Thou schalt not forswere in my name, nethir thou schalt defoule the name of thi God; Y am the Lord.", "rotherham": "Nor swear by my name falsely,—And so profane the name of thy God: I, am Yahweh.", "darby": "And ye shall not swear by my name falsely, and profane the name of thyGod: I am Jehovah.", "twenty": "", "jps": "And ye shall not swear by My name falsely, so that thou profane the name of thy G-d: I am HaShem.", "acv": "And ye shall not swear by my name falsely, and profane the name of thy God. I am Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And ye shall not swear by my name falsely, neither shalt thou profane the name of thy God: I [am] the LORD.", "vulgate": "non peierabis in nomine meo nec pollues nomen Dei tui ego Dominus;", "brenton": "And ye shall not swear unjustly by my name, and ye shall not profane the holy name of your God: I am the Lord your God."}}, {"v": 13, "ref": "19:13", "o": "לֹֽא תַעֲשֹׁ֥ק אֶת רֵֽעֲ/ךָ֖ וְ/לֹ֣א תִגְזֹ֑ל לֹֽא תָלִ֞ין פְּעֻלַּ֥ת שָׂכִ֛יר אִתְּ/ךָ֖ עַד בֹּֽקֶר", "en": {"kjv": "Thou shalt not defraud thy neighbour, neither rob him: the wages of him that is hired shall not abide with thee all night until the morning.", "web": "“‘You shall not oppress your neighbor, nor rob him. “‘The wages of a hired servant shall not remain with you all night until the morning.", "bsb": "You must not defraud your neighbor or rob him. You must not withhold until morning the wages due a hired hand.", "asv": "Thou shalt not oppress thy neighbor, nor rob him: the wages of a hired servant shall not abide with thee all night until the morning.", "ylt": "`Thou dost not oppress thy neighbour, nor take plunder; the wages of the hireling doth not remain with thee till morning.", "tyndale": "Thou shalt not begile thy neyghboure with cauellacios, nether robbe him violently, nether shall the workmans laboure abide with the vntyll the mornynge.", "dra": "Thou shalt not calumniate thy neighbour, nor oppress him by violence. The wages of him that hath been hired by thee shall not abide with thee until the morning.", "bbe": "Do not be cruel to your neighbour or take what is his; do not keep back a servant's payment from him all night till the morning.", "geneva": "Thou shalt not do thy neighbour wrong, neither rob him. The workemans hire shall not abide with thee vntil the morning.", "wycliffe": "Thou schalt not make fals chalenge to thi neiybore, nethir thou schalt oppresse hym bi violence. The werk of thin hirid man schal not dwelle at thee til the morewtid.", "rotherham": "Thou shalt not oppress thy neighbour nor rob [him],—The wages of him that is hired shall not tarry with thee, until the morning.", "darby": "Thou shalt not oppress thy neighbour, neither rob him. The wages of the hired servant shall not abide with thee all night until the morning.", "twenty": "", "jps": "Thou shalt not oppress thy neighbour, nor rob him; the wages of a hired servant shall not abide with thee all night until the morning.", "acv": "Thou shall not oppress thy neighbor, nor rob him. The wages of a hired servant shall not abide with thee all night until the morning.", "anderson": "", "haweis": "", "noyes": "", "webster": "Thou shalt not defraud thy neighbor, neither rob [him]: the wages of him that is hired shall not abide with thee all night until the morning.", "vulgate": "non facies calumniam proximo tuo nec vi opprimes eum non morabitur opus mercennarii apud te usque mane;", "brenton": "Thou shalt not injure thy neighbour, neither do thou rob him, neither shall the wages of thy hireling remain with thee until the morning."}}, {"v": 14, "ref": "19:14", "o": "לֹא תְקַלֵּ֣ל חֵרֵ֔שׁ וְ/לִ/פְנֵ֣י עִוֵּ֔ר לֹ֥א תִתֵּ֖ן מִכְשֹׁ֑ל וְ/יָרֵ֥אתָ מֵּ/אֱלֹהֶ֖י/ךָ אֲנִ֥י יְהוָֽה", "en": {"kjv": "Thou shalt not curse the deaf, nor put a stumblingblock before the blind, but shalt fear thy God: I am the Lord.", "web": "“‘You shall not curse the deaf, nor put a stumbling block before the blind; but you shall fear your God. I am Yahweh.", "bsb": "You must not curse the deaf or place a stumbling block before the blind, but you shall fear your God. I am the LORD.", "asv": "Thou shalt not curse the deaf, nor put a stumblingblock before the blind; but thou shalt fear thy God: I am Jehovah.", "ylt": "`Thou dost not revile the deaf; and before the blind thou dost not put a stumbling block; and thou hast been afraid of thy God; I am Jehovah.", "tyndale": "Thou shalt not curse the deaffe, nether put a stomblinge blocke before the blynd: but shalt feare thy God. I am the Lorde.", "dra": "Thou shalt not speak evil of the deaf, nor put a stumbling block before the blind: but thou shalt fear the Lord thy God, because I am the Lord.", "bbe": "Do not put a curse on those who have no hearing, or put a cause of falling in the way of the blind, but keep the fear of your God before you: I am the Lord.", "geneva": "Thou shalt not curse the deafe, neither put a stumbling blocke before the blinde, but shalt feare thy God: I am the Lord.", "wycliffe": "Thou schalt not curse a deef man, nether thou schalt sette an hurtyng bifor a blynd man; but thou schalt drede thi Lord God, for Y am the Lord.", "rotherham": "Thou shalt not curse the deaf, Nor, before the blind, place a stumbling-block,—So shalt thou stand in awe of thy God I, am Yahweh.", "darby": "Thou shalt not revile a deaf person, and thou shalt not put a stumbling-block before a blind one; but thou shalt fear thyGod: I am Jehovah.", "twenty": "", "jps": "Thou shalt not curse the deaf, nor put a stumbling-block before the blind, but thou shalt fear thy G-d: I am HaShem.", "acv": "Thou shall not curse the deaf, nor put a stumbling block before the blind, but thou shall fear thy God. I am Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "Thou shalt not curse the deaf, nor put a stumbling-block before the blind, but shalt fear thy God: I [am] the LORD.", "vulgate": "non maledices surdo nec coram caeco pones offendiculum sed timebis Deum tuum quia ego sum Dominus;", "brenton": "Thou shalt not revile the deaf, neither shalt thou put a stumbling-block in the way of the blind; and thou shalt fear the Lord thy God: I am the Lord your God."}}, {"v": 15, "ref": "19:15", "o": "לֹא תַעֲשׂ֥וּ עָ֨וֶל֙ בַּ/מִּשְׁפָּ֔ט לֹא תִשָּׂ֣א פְנֵי דָ֔ל וְ/לֹ֥א תֶהְדַּ֖ר פְּנֵ֣י גָד֑וֹל בְּ/צֶ֖דֶק תִּשְׁפֹּ֥ט עֲמִיתֶֽ/ךָ", "en": {"kjv": "Ye shall do no unrighteousness in judgment: thou shalt not respect the person of the poor, nor honour the person of the mighty: but in righteousness shalt thou judge thy neighbour.", "web": "“‘You shall do no injustice in judgment. You shall not be partial to the poor, nor show favoritism to the great; but you shall judge your neighbor in righteousness.", "bsb": "You must not pervert justice; you must not show partiality to the poor or favoritism to the rich; you are to judge your neighbor fairly.", "asv": "Ye shall do no unrighteousness in judgment: thou shalt not respect the person of the poor, nor honor the person of the mighty; but in righteousness shalt thou judge thy neighbor.", "ylt": "`Ye do not do perversity in judgment; thou dost not lift up the face of the poor, nor honour the face of the great; in righteousness thou dost judge thy fellow.", "tyndale": "Ye shall doo no vnrightuousnes in iudgement. Thou shalt not fauoure the poore nor honoure the mightye, but shalt iudge thy neghboure rightuously.", "dra": "Thou shalt not do that which is unjust, nor judge unjustly. Respect not the person of the poor: nor honour the countenance of the mighty. But judge thy neighbour according to justice.", "bbe": "Do no wrong in your judging: do not give thought to the position of the poor, or honour to the position of the great; but be a judge to your neighbour in righteousness.", "geneva": "Ye shall not doe vniustly in iudgement. Thou shalt not fauour the person of the poore, nor honour the person of the mightie, but thou shalt iudge thy neighbour iustly.", "wycliffe": "Thou schalt not do that, that is wickid, nether thou schalt deme vniustli; biholde thou not the persoone of a pore man, nethir onoure thou the face of a myyti man; deme thou iustli to thi neiybore.", "rotherham": "Ye shall not act perversely in giving judgment, Thou shalt neither respect the person of the poor, Nor prefer the person of the great,—In righteousness, shalt thou judge thy neighbour.", "darby": "Ye shall do no unrighteousness in judgment; thou shalt not respect the person of the lowly, nor honour the person of the great; in righteousness shalt thou judge thy neighbour.", "twenty": "", "jps": "Ye shall do no unrighteousness in judgment; thou shalt not respect the person of the poor, nor favour the person of the mighty; but in righteousness shalt thou judge thy neighbour.", "acv": "Ye shall do no unrighteousness in judgment. Thou shall not respect the person of the poor man, nor honor the person of the mighty man, but thou shall judge thy neighbor in righteousness.", "anderson": "", "haweis": "", "noyes": "", "webster": "Ye shall do no unrighteousness in judgment; thou shalt not respect the person of the poor, nor honor the person of the mighty: [but] in righteousness shalt thou judge thy neighbor.", "vulgate": "non facies quod iniquum est nec iniuste iudicabis nec consideres personam pauperis nec honores vultum potentis iuste iudica proximo tuo;", "brenton": "Thou shalt not act unjustly in judgment: thou shalt not accept the person of the poor, nor admire the person of the mighty; with justice shalt thou judge thy neighbour."}}, {"v": 16, "ref": "19:16", "o": "לֹא תֵלֵ֤ךְ רָכִיל֙ בְּ/עַמֶּ֔י/ךָ לֹ֥א תַעֲמֹ֖ד עַל דַּ֣ם רֵעֶ֑/ךָ אֲנִ֖י יְהוָֽה", "en": {"kjv": "Thou shalt not go up and down as a talebearer among thy people: neither shalt thou stand against the blood of thy neighbour: I am the Lord.", "web": "“‘You shall not go up and down as a slanderer among your people. “‘You shall not endanger the life of your neighbor. I am Yahweh.", "bsb": "You must not go about spreading slander among your people. You must not endanger the life of your neighbor. I am the LORD.", "asv": "Thou shalt not go up and down as a talebearer among thy people: neither shalt thou stand against the blood of thy neighbor: I am Jehovah.", "ylt": "`Thou dost not go slandering among thy people; thou dost not stand against the blood of thy neighbour; I am Jehovah.", "tyndale": "Thou shalt not go vp ad doune a preuy accuser amoge thy people, nether shalt thou helpe to shed the bloude of thy neyghboure: I am the Lorde.", "dra": "Thou shalt not be a detractor nor a whisperer among the people. Thou shalt not stand against the blood of thy neighbour. I am the Lord.", "bbe": "Do not go about saying untrue things among your people, or take away the life of your neighbour by false witness: I am the Lord.", "geneva": "Thou shalt not walke about with tales among thy people. Thou shalt not stand against the blood of thy neighbour: I am the Lord.", "wycliffe": "Thou schalt not be a sclaunderere, nether a priuey bacbitere in the puplis; thou schalt not stonde ayens the blood of thi neiybore ; Y am the Lord.", "rotherham": "Thou shalt not go about talebearing, among thy people Thou shalt not stand by, over the blood of thy neighbour: I, am Yahweh.", "darby": "Thou shalt not go about as a talebearer among thy people; thou shalt not stand up against the life of thy neighbour: I am Jehovah.", "twenty": "", "jps": "Thou shalt not go up and down as a talebearer among thy people; neither shalt thou stand idly by the blood of thy neighbour: I am HaShem.", "acv": "Thou shall not go up and down as a talebearer among thy people, neither shall thou stand against the blood of thy neighbor. I am Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "Thou shalt not go up and down [as] a tale-bearer among thy people; neither shalt thou stand against the blood of thy neighbor; I [am] the LORD.", "vulgate": "non eris criminator et susurro in populis non stabis contra sanguinem proximi tui ego Dominus;", "brenton": "Thou shalt not walk deceitfully among thy people; thou shalt not rise up against the blood of thy neighbour: I am the Lord your God."}}, {"v": 17, "ref": "19:17", "o": "לֹֽא תִשְׂנָ֥א אֶת אָחִ֖י/ךָ בִּ/לְבָבֶ֑/ךָ הוֹכֵ֤חַ תּוֹכִ֨יחַ֙ אֶת עֲמִיתֶ֔/ךָ וְ/לֹא תִשָּׂ֥א עָלָ֖י/ו חֵֽטְא", "en": {"kjv": "Thou shalt not hate thy brother in thine heart: thou shalt in any wise rebuke thy neighbour, and not suffer sin upon him.", "web": "“‘You shall not hate your brother in your heart. You shall surely rebuke your neighbor, and not bear sin because of him.", "bsb": "You must not harbor hatred against your brother in your heart. Directly rebuke your neighbor, so that you will not incur guilt on account of him.", "asv": "Thou shalt not hate thy brother in thy heart: thou shalt surely rebuke thy neighbor, and not bear sin because of him.", "ylt": "`Thou dost not hate thy brother in thy heart; thou dost certainly reprove thy fellow, and not suffer sin on him.", "tyndale": "Thou shalt not hate thy brother in thyne hart but shalt in any wyse rebuke thy neghbour: that thou bere not synne for his sake.", "dra": "Thou shalt not hate thy brother in thy heart: But reprove him openly, lest thou incur sin through him.", "bbe": "Let there be no hate in your heart for your brother; but you may make a protest to your neighbour, so that he may be stopped from doing evil.", "geneva": "Thou shalt not hate thy brother in thine heart, but thou shalt plainely rebuke thy neighbour, and suffer him not to sinne.", "wycliffe": "Thou schalt not hate thi brothir in thin herte, but repreue hym opynly, lest thou haue synne on hym.", "rotherham": "Thou shalt not hate thy brother in thy heart,—Thou shalt, faithfully reprove, thy neighbour, and not countenance him in sin:", "darby": "Thou shalt not hate thy brother in thy heart; thou shalt earnestly rebuke thy neighbour, lest thou bear sin on account of him.", "twenty": "", "jps": "Thou shalt not hate thy brother in thy heart; thou shalt surely rebuke thy neighbour, and not bear sin because of him.", "acv": "Thou shall not hate thy brother in thy heart. Thou shall surely rebuke thy neighbor, and not bear sin because of him.", "anderson": "", "haweis": "", "noyes": "", "webster": "Thou shalt not hate thy brother in thy heart: thou shalt in any wise rebuke thy neighbor, and not suffer sin upon him.", "vulgate": "ne oderis fratrem tuum in corde tuo sed publice argue eum ne habeas super illo peccatum;", "brenton": "Thou shalt not hate thy brother in thine heart: thou shalt in any wise rebuke thy neighbour, so thou shalt not bear sin on his account."}}, {"v": 18, "ref": "19:18", "o": "לֹֽא תִקֹּ֤ם וְ/לֹֽא תִטֹּר֙ אֶת בְּנֵ֣י עַמֶּ֔/ךָ וְ/אָֽהַבְתָּ֥ לְ/רֵעֲ/ךָ֖ כָּמ֑וֹ/ךָ אֲנִ֖י יְהוָֽה", "en": {"kjv": "Thou shalt not avenge, nor bear any grudge against the children of thy people, but thou shalt love thy neighbour as thyself: I am the Lord.", "web": "“‘You shall not take vengeance, nor bear any grudge against the children of your people; but you shall love your neighbor as yourself. I am Yahweh.", "bsb": "Do not seek revenge or bear a grudge against any of your people, but love your neighbor as yourself. I am the LORD.", "asv": "Thou shalt not take vengeance, nor bear any grudge against the children of thy people; but thou shalt love thy neighbor as thyself: I am Jehovah.", "ylt": "`Thou dost not take vengeance, nor watch the sons of thy people; and thou hast had love to thy neighbour as thyself; I am Jehovah.", "tyndale": "Thou shalt not avenge thy selfe nor bere hate in thy mynde against the childern of thi people, but shalt loue thy neghboure eue as thy self I am the Lorde.", "dra": "Seek not revenge, nor be mindful of the injury of thy citizens. Thou shalt love thy friend as thyself. I am the Lord.", "bbe": "Do not make attempts to get equal with one who has done you wrong, or keep hard feelings against the children of your people, but have love for your neighbour as for yourself: I am the Lord.", "geneva": "Thou shalt not auenge, nor be mindful of wrong against ye childre of thy people, but shalt loue thy neighbour as thy selfe: I am the Lord.", "wycliffe": "Thou schalt not seke veniaunce, nether thou schalt be myndeful of the wrong of thi cyteseyns; thou schalt loue thi freend as thi silf; Y am the Lord.", "rotherham": "Thou shalt not take vengeance neither shalt thou cherish anger against the sons of thy people, So shalt thou love thy neighbour as thyself,—I, am Yahweh.", "darby": "Thou shalt not avenge thyself, nor bear any grudge against the children of thy people, but thou shalt love thy neighbour as thyself: I am Jehovah.", "twenty": "", "jps": "Thou shalt not take vengeance, nor bear any grudge against the children of thy people, but thou shalt love thy neighbour as thyself: I am HaShem.", "acv": "Thou shall not take vengeance, nor bear any grudge against the sons of thy people, but thou shall love thy neighbor as thyself. I am Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "Thou shalt not avenge, nor bear any grudge against the children of thy people, but thou shalt love thy neighbor as thyself; I [am] the LORD.", "vulgate": "non quaeres ultionem nec memor eris iniuriae civium tuorum diliges amicum tuum sicut temet ipsum ego Dominus;", "brenton": "And thy hand shall not avenge thee; and thou shalt not be angry with the children of thy people; and thou shalt love thy neighbour as thyself; I am the Lord."}}, {"v": 19, "ref": "19:19", "o": "אֶֽת חֻקֹּתַ/י֮ תִּשְׁמֹרוּ֒ בְּהֶמְתְּ/ךָ֙ לֹא תַרְבִּ֣יעַ כִּלְאַ֔יִם שָׂדְ/ךָ֖ לֹא תִזְרַ֣ע כִּלְאָ֑יִם וּ/בֶ֤גֶד כִּלְאַ֨יִם֙ שַֽׁעַטְנֵ֔ז לֹ֥א יַעֲלֶ֖ה עָלֶֽי/ךָ", "en": {"kjv": "Ye shall keep my statutes. Thou shalt not let thy cattle gender with a diverse kind: thou shalt not sow thy field with mingled seed: neither shall a garment mingled of linen and woollen come upon thee.", "web": "“‘You shall keep my statutes. “‘You shall not cross-breed different kinds of animals. “‘You shall not sow your field with two kinds of seed; “‘neither shall there come upon you a garment made of two kinds of material.", "bsb": "You are to keep My statutes. You shall not crossbreed two different kinds of livestock; you shall not sow your fields with two kinds of seed; and you shall not wear clothing made of two kinds of material.", "asv": "Ye shall keep my statutes. Thou shalt not let thy cattle gender with a diverse kind: thou shalt not sow thy field with two kinds of seed: neither shall there come upon thee a garment of two kinds of stuff mingled together.", "ylt": "`My statutes ye do keep: thy cattle thou dost not cause to gender with diverse kinds; thy field thou dost not sow with diverse kinds, and a garment of diverse kinds, shaatnez, doth not go up upon thee.", "tyndale": "Kepe myne ordinaunces. Let none of thy catell gendre with a cotrary kynde, nether sowe thy felde with myngled seed, nether shalt thou put on ony garment of lynen and wollen", "dra": "Keep ye my laws. Thou shalt not make thy cattle to gender with beasts of any other kind. Thou shalt not sow thy field with different seeds. Thou shalt not wear a garment that is woven of two sorts.", "bbe": "Keep my laws. Do not let your cattle have offspring by those of a different sort; do not put mixed seed into your field; do not put on a robe made of two sorts of cloth.", "geneva": "Yee shall keepe mine ordinances. Thou shalt not let thy cattel gender with others of diuers kindes. Thou shalt not sowe thy fielde with mingled seede, neyther shall a garment of diuers thinges, as of linen and wollen come vpon thee.", "wycliffe": "Kepe ye my lawis. Thou schalt not make thi beestis to gendre with the lyuynge beestis of another kynde. Thou schalt not sowe the feeld with dyuerse sede. Thou schalt not be clothid in a cloth, which is wouun of twei thingis.", "rotherham": "My statutes, shall ye observe, Thy beasts, shalt thou not cause to breed in two kinds, Thy field, shalt thou not sow with two sorts of seed,—And a garment woven of diverse threads, shalt thou not suffer to come upon thee.", "darby": "My statutes shall ye observe. Thou shalt not let thy cattle gender with another sort; thou shalt not sow thy field with seed of two sorts; and a garment woven of two materials shall not come upon thee.", "twenty": "", "jps": "Ye shall keep My statutes. Thou shalt not let thy cattle gender with a diverse kind; thou shalt not sow thy field with two kinds of seed; neither shall there come upon thee a garment of two kinds of stuff mingled together.", "acv": "Ye shall keep my statutes. Thou shall not let thy cattle engender with a diverse kind. Thou shall not sow thy field with two kinds of seed, neither shall there come upon thee a garment of two kinds of stuff mingled together.", "anderson": "", "haweis": "", "noyes": "", "webster": "Ye shall keep my statutes. Thou shalt not let thy cattle engender with a diverse kind: Thou shalt not sow thy field with mingled seed: neither shall a garment mingled of linen and woolen come upon thee.", "vulgate": "leges meas custodite iumenta tua non facies coire cum alterius generis animantibus agrum non seres diverso semine veste quae ex duobus texta est non indueris;", "brenton": "Ye shall observe my law: thou shalt not let thy cattle gender with one of a different kind, and thou shalt not sow thy vineyard with diverse seed; and thou shalt not put upon thyself a mingled garment woven of two materials."}}, {"v": 20, "ref": "19:20", "o": "וְ֠/אִישׁ כִּֽי יִשְׁכַּ֨ב אֶת אִשָּׁ֜ה שִׁכְבַת זֶ֗רַע וְ/הִ֤וא שִׁפְחָה֙ נֶחֱרֶ֣פֶת לְ/אִ֔ישׁ וְ/הָפְדֵּה֙ לֹ֣א נִפְדָּ֔תָה א֥וֹ חֻפְשָׁ֖ה לֹ֣א נִתַּן לָ֑/הּ בִּקֹּ֧רֶת תִּהְיֶ֛ה לֹ֥א יוּמְת֖וּ כִּי לֹ֥א חֻפָּֽשָׁה", "en": {"kjv": "And whosoever lieth carnally with a woman, that is a bondmaid, betrothed to an husband, and not at all redeemed, nor freedom given her; she shall be scourged; they shall not be put to death, because she was not free.", "web": "“‘If a man lies carnally with a woman who is a slave girl, pledged to be married to another man, and not ransomed, or given her freedom; they shall be punished. They shall not be put to death, because she was not free.", "bsb": "If a man lies carnally with a slave girl promised to another man but who has not been redeemed or given her freedom, there must be due punishment. But they are not to be put to death, because she had not been freed.", "asv": "And whosoever lieth carnally with a woman, that is a bondmaid, betrothed to a husband, and not at all redeemed, nor freedom given her; they shall be punished; they shall not be put to death, because she was not free.", "ylt": "`And when a man lieth with a woman with seed of copulation, and she a maid-servant, betrothed to a man, and not really ransomed, or freedom hath not been given to her, an investigation there is; they are not put to death, for she is not free.", "tyndale": "Yf a man haue to doo with a woman that is bonde and hath bene medled with al of another man which nether is boughte nor fredome geuen her, there shalbe a payne apon it: but they shall not dye, because she was not made fre.", "dra": "If a man carnally lie with a woman that is a bondservant and marriageable, and yet not redeemed with a price, nor made free: they both shall be scourged: and they shall not be put to death, because she was not a free woman.", "bbe": "If any man has sex relations with a servant-woman who has given her word to be married to a man, and has not been made free for a price or in any other way, the thing will be looked into; but they will not be put to death because she was not a free woman.", "geneva": "Whosoeuer also lyeth and medleth with a woman that is a bonde mayde, affianced to a husband, and not redeemed, nor freedome giuen her, she shalbe scourged, but they shall not die, because she is not made free.", "wycliffe": "If a man slepith with a womman by fleischly knowyng of seed, which womman is an `hand maide, ye, a noble womman of kyn, and netheles is not ayenbouyt bi prijs, nethir rewardid with fredom, bothe schulen be betun, and thei schulen not die, for sche was not fre.", "rotherham": "And whosoever lieth carnally with a woman, she being a bondmaid, acquired for a husband, and neither, redeemed, nor, freedom, given her, inquisition, shall be made they shall not be put to death, because she was not free;", "darby": "And if a man lie with a woman for copulation, and she is a bondwoman betrothed to a husband, but not at all ransomed, nor hath freedom been given to her, there shall be a chastisement: they shall not be put to death, for she was not free.", "twenty": "", "jps": "And whosoever lieth carnally with a woman, that is a bondmaid, designated for a man, and not at all redeemed, nor was freedom given her; there shall be inquisition; they shall not be put to death, because she was not free.", "acv": "And whoever lies carnally with a woman, who is a bondmaid, betrothed to a husband, and not at all redeemed, nor freedom given her, they shall be punished. They shall not be put to death, because she was not free.", "anderson": "", "haweis": "", "noyes": "", "webster": "And whoever lieth carnally with a woman that [is] a bond-maid betrothed to a husband, and not at all redeemed, nor freedom given her; she shall be scourged: they shall not be put to death, because she was not free.", "vulgate": "homo si dormierit cum muliere coitu seminis quae sit ancilla etiam nubilis et tamen pretio non redempta nec libertate donata vapulabunt ambo et non morientur quia non fuit libera;", "brenton": "And if any one lie carnally with a woman, and she should be a home-servant kept for a man, and she has not been ransomed, and her freedom has not been given to her, they shall be visited with punishment; but they shall not die, because she was not set at liberty."}}, {"v": 21, "ref": "19:21", "o": "וְ/הֵבִ֤יא אֶת אֲשָׁמ/וֹ֙ לַֽ/יהוָ֔ה אֶל פֶּ֖תַח אֹ֣הֶל מוֹעֵ֑ד אֵ֖יל אָשָֽׁם", "en": {"kjv": "And he shall bring his trespass offering unto the Lord, unto the door of the tabernacle of the congregation, even a ram for a trespass offering.", "web": "He shall bring his trespass offering to Yahweh, to the door of the Tent of Meeting, even a ram for a trespass offering.", "bsb": "The man, however, must bring a ram to the entrance to the Tent of Meeting as his guilt offering to the LORD.", "asv": "And he shall bring his trespass-offering unto Jehovah, unto the door of the tent of meeting, even a ram for a trespass-offering.", "ylt": "`And he hath brought in his guilt-offering to Jehovah, unto the opening of the tent of meeting, a ram for a guilt-offering,", "tyndale": "And he shall brynge for his trespaceofferynge vnto the Lorde: euen vnto the dore off the tabernacle of witnesse, a ram for a trespaceoffrynge.", "dra": "And for his trespass he shall offer a ram to the Lord, at the door of the tabernacle of the testimony.", "bbe": "Let him take his offering for wrongdoing to the Lord, to the door of the Tent of meeting; let him give a male sheep as an offering for wrongdoing.", "geneva": "And he shall bring for his trespasse offring vnto the Lord, at the doore of the Tabernacle of the Congregation, a ramme for a trespasse offering.", "wycliffe": "Sotheli the man for his trespas schal offre a ram to the Lord, at the dore of the tabernacle of witnessyng;", "rotherham": "but he shall bring in his guilt-bearer unto Yahweh, unto the entrance of the tent of meeting,—even a ram as a guilt-bearer;", "darby": "And he shall bring his trespass-offering to Jehovah, unto the entrance of the tent of meeting, a ram for a trespass-offering.", "twenty": "", "jps": "And he shall bring his forfeit unto HaShem, unto the door of the tent of meeting, even a ram for a guilt-offering.", "acv": "And he shall bring his trespass offering to Jehovah, to the door of the tent of meeting, even a ram for a trespass offering.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall bring his trespass-offering to the LORD, to the door of the tabernacle of the congregation, [even] a ram for a trespass-offering.", "vulgate": "pro delicto autem suo offeret Domino ad ostium tabernaculi testimonii arietem;", "brenton": "And he shall bring for his trespass to the Lord to the door of the tabernacle of witness, a ram for a trespass-offering."}}, {"v": 22, "ref": "19:22", "o": "וְ/כִפֶּר֩ עָלָ֨י/ו הַ/כֹּהֵ֜ן בְּ/אֵ֤יל הָֽ/אָשָׁם֙ לִ/פְנֵ֣י יְהוָ֔ה עַל חַטָּאת֖/וֹ אֲשֶׁ֣ר חָטָ֑א וְ/נִסְלַ֣ח ל֔/וֹ מֵ/חַטָּאת֖/וֹ אֲשֶׁ֥ר חָטָֽא", "en": {"kjv": "And the priest shall make an atonement for him with the ram of the trespass offering before the Lord for his sin which he hath done: and the sin which he hath done shall be forgiven him.", "web": "The priest shall make atonement for him with the ram of the trespass offering before Yahweh for his sin which he has committed: and the sin which he has committed shall be forgiven him.", "bsb": "The priest shall make atonement on his behalf before the LORD with the ram of the guilt offering for the sin he has committed, and he will be forgiven the sin he has committed.", "asv": "And the priest shall make atonement for him with the ram of the trespass-offering before Jehovah for his sin which he hath sinned: and the sin which he hath sinned shall be forgiven him.", "ylt": "and the priest hath made atonement for him with the ram of the guilt-offering before Jehovah, for his sin which he hath sinned, and it hath been forgiven him because of his sin which he hath sinned.", "tyndale": "And the preast shall make an attonement for him with the ram of the trespaceofferynge before the Lord, for his synne which he hath done: and it shalbe forgeuen him, as concerninge the synne which he hath done.", "dra": "And the priest shall pray for him: and for his sin before the Lord: and he shall have mercy on him, and the sin shall be forgiven.", "bbe": "And the priest will take away his sin before the Lord with the sheep which is offered for his wrongdoing, and he will have forgiveness for the sin which he has done.", "geneva": "Then the Priest shall make an atonement for him with the ramme of the trespasse offering before the Lord, concerning his sinne which he hath done, and pardon shalbe giuen him for his sinne which he hath committed.", "wycliffe": "and the preest schal preye for hym, and for his trespas, bifor the Lord; and the Lord schal be merciful to hym, and the synne schal be foryouun.", "rotherham": "and the priest shall put a propitiatory-covering over him with the guilt-bearing ram before Yahweh, on account of his sin which he hath committed,—so shall he have forgiveness, from his sin which he hath committed.", "darby": "And the priest shall make atonement for him with the ram of the trespass-offering before Jehovah for his sin which he hath done; and the sin which he hath done shall be forgiven him.", "twenty": "", "jps": "And the priest shall make atonement for him with the ram of the guilt-offering before HaShem for his sin which he hath sinned; and he shall be forgiven for his sin which he hath sinned.", "acv": "And the priest shall make atonement for him with the ram of the trespass offering before Jehovah for his sin which he has sinned. And the sin which he has sinned shall be forgiven him.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall make an atonement for him with the ram of the trespass-offering before the LORD for his sin which he hath done; and the sin which he hath done shall be forgiven him.", "vulgate": "orabitque pro eo sacerdos et pro delicto eius coram Domino et repropitiabitur ei dimitteturque peccatum;", "brenton": "And the priest shall make atonement for him with the ram of the trespass-offering, before the Lord, for the sin which he sinned; and the sin which he sinned shall be forgiven him."}}, {"v": 23, "ref": "19:23", "o": "וְ/כִי תָבֹ֣אוּ אֶל הָ/אָ֗רֶץ וּ/נְטַעְתֶּם֙ כָּל עֵ֣ץ מַאֲכָ֔ל וַ/עֲרַלְתֶּ֥ם עָרְלָת֖/וֹ אֶת פִּרְי֑/וֹ שָׁלֹ֣שׁ שָׁנִ֗ים יִהְיֶ֥ה לָ/כֶ֛ם עֲרֵלִ֖ים לֹ֥א יֵאָכֵֽל", "en": {"kjv": "And when ye shall come into the land, and shall have planted all manner of trees for food, then ye shall count the fruit thereof as uncircumcised: three years shall it be as uncircumcised unto you: it shall not be eaten of.", "web": "“‘When you come into the land, and have planted all kinds of trees for food, then you shall count their fruit as forbidden. Three years shall they be forbidden to you. It shall not be eaten.", "bsb": "When you enter the land and plant any kind of tree for food, you shall regard the fruit as forbidden. For three years it will be forbidden to you and must not be eaten.", "asv": "And when ye shall come into the land, and shall have planted all manner of trees for food, then ye shall count the fruit thereof as their uncircumcision: three years shall they be as uncircumcised unto you; it shall not be eaten.", "ylt": "`And when ye come in unto the land, and have planted all kinds of trees for food, then ye have reckoned as uncircumcised its fruit, three years it is to you uncircumcised, it is not eaten,", "tyndale": "And when ye come to the lande ad haue plated all maner of trees where of me eate, ye shal holde them vncircumcised as concerning their frute: eue thre yere shal they be vncircucysed vnto you ad shall not be eate of,", "dra": "When you shall be come into the land, and shall have planted in it fruit trees, you shall take away the firstfruits of them. The fruit that comes forth shall be unclean to you: neither shall you eat of them.", "bbe": "And when you have come into the land, and have put in all sorts of fruit-trees, their fruit will be as if they had not had circumcision, and for three years their fruit may not be used for food.", "geneva": "Also when ye shall come into the land, and haue planted euery tree for meate, ye shall count the fruite thereof as vncircumcised: three yeere shall it be vncircumcised vnto you, it shall not be eaten:", "wycliffe": "Whanne ye han entrid in to the lond of biheest, and han plauntid therynne appil trees, ye schulen do awei the firste flouris; the applis whiche tho trees bryngen forth, schulen be vncleene to you, nethir ye schulen ete of tho.", "rotherham": "And when ye come into the land, and plant any manner of fruit-tree, then shall ye count as uncircumcised the fruit thereof, three years, shall it be to you as if unclean, it shall not be eaten.", "darby": "And when ye come into the land and plant all manner of trees for food, then ye shall count its fruit as uncircumcised, three years shall it be uncircumcised unto you: it shall not be eaten of;", "twenty": "", "jps": "And when ye shall come into the land, and shall have planted all manner of trees for food, then ye shall count the fruit thereof as forbidden; three years shall it be as forbidden unto you; it shall not be eaten.", "acv": "And when ye shall come into the land, and shall have planted all manner of trees for food, then ye shall count the fruit of it as their uncircumcision. Three years they shall be as uncircumcised to you; it shall not be eaten.", "anderson": "", "haweis": "", "noyes": "", "webster": "And when ye shall come into the land, and shall have planted all manner of trees for food; then ye shall count its fruit as uncircumcised: three years shall it be as uncircumcised to you: it shall not be eaten of.", "vulgate": "quando ingressi fueritis terram et plantaveritis in ea ligna pomifera auferetis praeputia eorum poma quae germinant inmunda erunt vobis nec edetis ex eis;", "brenton": "And whenever ye shall enter into the land which the Lord your God gives you, and shall plant any fruit-tree, then shall ye purge away its uncleanness; its fruit shall be three years uncleansed to you, it shall not be eaten."}}, {"v": 24, "ref": "19:24", "o": "וּ/בַ/שָּׁנָה֙ הָ/רְבִיעִ֔ת יִהְיֶ֖ה כָּל פִּרְי֑/וֹ קֹ֥דֶשׁ הִלּוּלִ֖ים לַ/יהוָֽה", "en": {"kjv": "But in the fourth year all the fruit thereof shall be holy to praise the Lord withal.", "web": "But in the fourth year all its fruit shall be holy, for giving praise to Yahweh.", "bsb": "In the fourth year all its fruit must be consecrated as a praise offering to the LORD.", "asv": "But in the fourth year all the fruit thereof shall be holy, for giving praise unto Jehovah.", "ylt": "and in the fourth year all its fruit is holy--praises for Jehovah.", "tyndale": "ad the fourth yere all the frute of the shalbe holy ad acceptable to the Lorde.", "dra": "But in the fourth year, all their fruit shall be sanctified, to the praise of the Lord.", "bbe": "And in the fourth year all the fruit will be holy as a praise-offering to the Lord.", "geneva": "But in the fourth yere all the fruite thereof shalbe holy to the praise of the Lord.", "wycliffe": "Forsothe in the fourthe yeer al the fruyt of tho trees schal be `halewid preiseful to the Lord;", "rotherham": "But, in the fourth year, all the fruit thereof shall be hallowed for a festival of thanksgiving unto Yahweh.", "darby": "and in the fourth year all the fruit thereof shall be holy for praise to Jehovah;", "twenty": "", "jps": "And in the fourth year all the fruit thereof shall be holy, for giving praise unto HaShem.", "acv": "But in the fourth year all the fruit of it shall be holy, for giving praise to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "But in the fourth year all its fruit shall be holy to praise the LORD [with].", "vulgate": "quarto anno omnis fructus eorum sanctificabitur laudabilis Domino;", "brenton": "And in the fourth year all its fruit shall be holy, a subject of praise to the Lord."}}, {"v": 25, "ref": "19:25", "o": "וּ/בַ/שָּׁנָ֣ה הַ/חֲמִישִׁ֗ת תֹּֽאכְלוּ֙ אֶת פִּרְי֔/וֹ לְ/הוֹסִ֥יף לָ/כֶ֖ם תְּבוּאָת֑/וֹ אֲנִ֖י יְהוָ֥ה אֱלֹהֵי/כֶֽם", "en": {"kjv": "And in the fifth year shall ye eat of the fruit thereof, that it may yield unto you the increase thereof: I am the Lord your God.", "web": "In the fifth year you shall eat its fruit, that it may yield its increase to you. I am Yahweh your God.", "bsb": "But in the fifth year you may eat its fruit; thus your harvest will be increased. I am the LORD your God.", "asv": "And in the fifth year shall ye eat of the fruit thereof, that it may yield unto you the increase thereof: I am Jehovah your God.", "ylt": "And in the fifth year ye do eat its fruit--to add to you its increase; I am Jehovah your God.", "tyndale": "And the fifth yere maye ye eate of the frute of the, ad gather in the encrease of them: I am the Lorde youre God.", "dra": "And in the fifth year you shall eat the fruits thereof, gathering the increase thereof. I am the Lord your God.", "bbe": "But in the fifth year you may take the fruit and the increase of it for your food: I am the Lord your God.", "geneva": "And in the fifth yeere shall ye eate of the fruite of it that it may yeelde to you the encrease thereof: I am the Lord your God.", "wycliffe": "forsothe in the fifthe yeer ye schulen ete fruytis, and schulen gadere applis, whiche tho trees bryngen forth; Y am youre Lord God.", "rotherham": "And in the fifth year, shall ye eat the fruit thereof, that it may enrich you with its increase,—I—Yahweh, am your God.", "darby": "and in the fifth year shall ye eat the fruit thereof, that it may increase unto you the produce thereof: I am Jehovah yourGod.", "twenty": "", "jps": "But in the fifth year may ye eat of the fruit thereof, that it may yield unto you more richly the increase thereof: I am HaShem your G-d.", "acv": "And in the fifth year ye shall eat of the fruit of it, that it may yield to you the increase of it. I am Jehovah your God.", "anderson": "", "haweis": "", "noyes": "", "webster": "And in the fifth year shall ye eat of its fruit, that it may yield to you its increase: I [am] the LORD your God.", "vulgate": "quinto autem anno comedetis fructus congregantes poma quae proferunt ego Dominus Deus vester;", "brenton": "And in the fifth year ye shall eat the fruit, its produce is an increase to you. I am the Lord your God."}}, {"v": 26, "ref": "19:26", "o": "לֹ֥א תֹאכְל֖וּ עַל הַ/דָּ֑ם לֹ֥א תְנַחֲשׁ֖וּ וְ/לֹ֥א תְעוֹנֵֽנוּ", "en": {"kjv": "Ye shall not eat any thing with the blood: neither shall ye use enchantment, nor observe times.", "web": "“‘You shall not eat any meat with the blood still in it; neither shall you use enchantments, nor practice sorcery.", "bsb": "You must not eat anything with blood still in it. You must not practice divination or sorcery.", "asv": "Ye shall not eat anything with the blood: neither shall ye use enchantments, nor practise augury.", "ylt": "`Ye do not eat with the blood; ye do not enchant, nor observe clouds.", "tyndale": "Ye shall eate nothinge with the bloude, ye shall vse no witchcrafte, nor obserue dismall dayes,", "dra": "You shall not eat with blood. You shall not divine nor observe dreams.", "bbe": "Nothing may be used for food with its blood in it; you may not make use of strange arts, or go in search of signs and wonders.", "geneva": "Ye shall not eat the flesh with the blood, ye shall not vse witchcraft, nor obserue times.", "wycliffe": "Ye schulen not ete fleisch with blood. Ye schulen not make veyn diuynyng, nether ye schulen kepe dremes;", "rotherham": "Ye shall eat nothing with the blood thereof,—Ye shall not practise divination neither shall ye use magic.", "darby": "Ye shall eat nothing with the blood. — Ye shall not practise enchantment, nor use auguries.", "twenty": "", "jps": "Ye shall not eat with the blood; neither shall ye practise divination nor soothsaying.", "acv": "Ye shall not eat anything with the blood. Neither shall ye use enchantments, nor practice augury.", "anderson": "", "haweis": "", "noyes": "", "webster": "Ye shall not eat [any thing] with the blood: neither shall ye use enchantment, nor observe times.", "vulgate": "non comedetis cum sanguine non augurabimini nec observabitis somnia;", "brenton": "Eat not on the mountains, nor shall ye employ auguries, nor divine by inspection of birds."}}, {"v": 27, "ref": "19:27", "o": "לֹ֣א תַקִּ֔פוּ פְּאַ֖ת רֹאשְׁ/כֶ֑ם וְ/לֹ֣א תַשְׁחִ֔ית אֵ֖ת פְּאַ֥ת זְקָנֶֽ/ךָ", "en": {"kjv": "Ye shall not round the corners of your heads, neither shalt thou mar the corners of thy beard.", "web": "“‘You shall not cut the hair on the sides of your heads, neither shall you clip off the edge of your beard.", "bsb": "You must not cut off the hair at the sides of your head or clip off the edges of your beard.", "asv": "Ye shall not round the corners of your heads, neither shalt thou mar the corners of thy beard.", "ylt": "`Ye do not round the corner of your head, nor destroy the corner of thy beard.", "tyndale": "ye shall not rounde the lockes of youre heedes, nether shalt thou marre the tuftes of thy beerde.", "dra": "Nor shall you cut your hair roundwise: nor shave your beard.", "bbe": "The ends of the hair round your face and on your chin may not be cut off.", "geneva": "Ye shall not cut rounde the corners of your heades, neither shalt thou marre the tuftes of thy beard.", "wycliffe": "nether ye schulen clippe the heer in round, nether ye schulen schaue the beerd;", "rotherham": "Ye shall not shave in a circle around your head,—nor shalt thou disfigure the fringe of thy beard.", "darby": "— Ye shall not shave the corners of your head round, neither shalt thou mutilate the corners of thy beard.", "twenty": "", "jps": "Ye shall not round the corners of your heads, neither shalt thou mar the corners of thy beard.", "acv": "Ye shall not round the corners of your heads, nor shall thou mar the corners of thy beard.", "anderson": "", "haweis": "", "noyes": "", "webster": "Ye shall not round the corners of your heads, neither shalt thou mar the corners of thy beard.", "vulgate": "neque in rotundum adtondebitis comam nec radatis barbam;", "brenton": "Ye shall not make a round cutting of the hair of your head, nor disfigure your beard."}}, {"v": 28, "ref": "19:28", "o": "וְ/שֶׂ֣רֶט לָ/נֶ֗פֶשׁ לֹ֤א תִתְּנוּ֙ בִּ/בְשַׂרְ/כֶ֔ם וּ/כְתֹ֣בֶת קַֽעֲקַ֔ע לֹ֥א תִתְּנ֖וּ בָּ/כֶ֑ם אֲנִ֖י יְהוָֽה", "en": {"kjv": "Ye shall not make any cuttings in your flesh for the dead, nor print any marks upon you: I am the Lord.", "web": "“‘You shall not make any cuttings in your flesh for the dead, nor tattoo any marks on you. I am Yahweh.", "bsb": "You must not make any cuts in your bodies for the dead or put tattoo marks on yourselves. I am the LORD.", "asv": "Ye shall not make any cuttings in your flesh for the dead, nor print any marks upon you: I am Jehovah.", "ylt": "`And a cutting for the soul ye do not put in your flesh; and a writing, a cross-mark, ye do not put on you; I am Jehovah.", "tyndale": "Ye shall not rent youre flesh for any soules sake, nor printe any markes apon you: I am the Lorde.", "dra": "You shall not make any cuttings in your flesh, for the dead: neither shall you make in yourselves any figures or marks. I am the Lord.", "bbe": "You may not make cuts in your flesh in respect for the dead, or have marks printed on your bodies: I am the Lord.", "geneva": "Ye shall not cut your flesh for the dead, nor make any print of a marke vpon you: I am the Lord,", "wycliffe": "and on deed men ye schulen not kitte youre fleischis, nether ye schulen make to you ony fyguris, ether markis in youre fleisch; Y am the Lord.", "rotherham": "Cuttings for a dead person, shall ye not make in your flesh. And punctures in your persons, shall ye not print,—I, am Yahweh.", "darby": "And cuttings for a dead person shall ye not make in your flesh, nor put any tattoo writing upon you: I am Jehovah.", "twenty": "", "jps": "Ye shall not make any cuttings in your flesh for the dead, nor imprint any marks upon you: I am HaShem.", "acv": "Ye shall not make any cuttings in your flesh for the dead, nor print any marks upon you. I am Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "Ye shall not make any cuttings in your flesh for the dead, nor print any marks upon you: I [am] the LORD.", "vulgate": "et super mortuo non incidetis carnem vestram neque figuras aliquas et stigmata facietis vobis ego Dominus;", "brenton": "And ye shall not make cuttings in your body for a dead body, and ye shall not inscribe on yourselves any marks. I am the Lord your God."}}, {"v": 29, "ref": "19:29", "o": "אַל תְּחַלֵּ֥ל אֶֽת בִּתְּ/ךָ֖ לְ/הַזְנוֹתָ֑/הּ וְ/לֹא תִזְנֶ֣ה הָ/אָ֔רֶץ וּ/מָלְאָ֥ה הָ/אָ֖רֶץ זִמָּֽה", "en": {"kjv": "Do not prostitute thy daughter, to cause her to be a whore; lest the land fall to whoredom, and the land become full of wickedness.", "web": "“‘Don’t profane your daughter, to make her a prostitute; lest the land fall to prostitution, and the land become full of wickedness.", "bsb": "You must not defile your daughter by making her a prostitute, or the land will be prostituted and filled with depravity.", "asv": "Profane not thy daughter, to make her a harlot; lest the land fall to whoredom, and the land become full of wickedness.", "ylt": "`Thou dost not pollute thy daughter to cause her to go a-whoring, that the land go not a-whoring, and the land hath been full of wickedness.", "tyndale": "Thou shalt not pollute thi doughter, that thou woldest maintene her to be an whoore: lest the lade fall to whoredome, ad waxe ful of wekednesse.", "dra": "Make not thy daughter a common strumpet, lest the land be defiled, and filled with wickedness.", "bbe": "Do not make your daughter common by letting her become a loose woman, for fear that the land may become full of shame.", "geneva": "Thou shalt not make thy daughter common, to cause her to be a whore, least the lande also fall to whoredome, and the lande bee full of wickednesse.", "wycliffe": "Sette thou not thi douytir to do leccherie for hire, and the lond be defoulid, and be fillid with synne.", "rotherham": "Do not profane thy daughter by causing her to be unchaste,—lest the land fall to unchastity, and so the land be filled with wickedness.", "darby": "— Do not profane thy daughter, to give her up to whoredom; lest the land practise whoredom, and the land become full of infamy.", "twenty": "", "jps": "Profane not thy daughter, to make her a harlot, lest the land fall into harlotry, and the land become full of lewdness.", "acv": "Do not profane thy daughter, to make her a harlot, lest the land fall to whoredom, and the land become full of wickedness.", "anderson": "", "haweis": "", "noyes": "", "webster": "Do not prostitute thy daughter to cause her to be a harlot: lest the land should fall to lewdness, and the land become full of wickedness.", "vulgate": "ne prostituas filiam tuam et contaminetur terra et impleatur piaculo;", "brenton": "Thou shalt not profane thy daughter to prostitute her; so the land shall not go a whoring, and the land be filled with iniquity."}}, {"v": 30, "ref": "19:30", "o": "אֶת שַׁבְּתֹתַ֣/י תִּשְׁמֹ֔רוּ וּ/מִקְדָּשִׁ֖/י תִּירָ֑אוּ אֲנִ֖י יְהוָֽה", "en": {"kjv": "Ye shall keep my sabbaths, and reverence my sanctuary: I am the Lord.", "web": "“‘You shall keep my Sabbaths, and reverence my sanctuary; I am Yahweh.", "bsb": "You must keep My Sabbaths and have reverence for My sanctuary. I am the LORD.", "asv": "Ye shall keep my sabbaths, and reverence my sanctuary: I am Jehovah.", "ylt": "`My sabbaths ye do keep, and My sanctuary ye do reverence; I am Jehovah.", "tyndale": "Se that ye kepe my Sabbathes and feare my sauctuary: I am the Lorde.", "dra": "Keep ye my sabbaths, and reverence my sanctuary. I am the Lord.", "bbe": "Keep my Sabbaths and have respect for my holy place: I am the Lord.", "geneva": "Ye shall keepe my Sabbaths and reuerence my Sanctuarie: I am the Lord.", "wycliffe": "Kepe ye my sabatis, and drede ye my seyntuarie; Y `am the Lord.", "rotherham": "My sabbaths, shall ye observe, And my sanctuary, shall ye revere,—I, am Yahweh.", "darby": "— My sabbaths shall ye keep, and my sanctuary shall ye reverence: I am Jehovah.", "twenty": "", "jps": "Ye shall keep My sabbaths, and reverence My sanctuary: I am HaShem.", "acv": "Ye shall keep my sabbaths, and reverence my sanctuary. I am Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "Ye shall keep my sabbaths, and reverence my sanctuary: I [am] the LORD.", "vulgate": "sabbata mea custodite et sanctuarium meum metuite ego Dominus;", "brenton": "Ye shall keep my sabbaths, and reverence my sanctuaries: I am the Lord."}}, {"v": 31, "ref": "19:31", "o": "אַל תִּפְנ֤וּ אֶל הָ/אֹבֹת֙ וְ/אֶל הַ/יִּדְּעֹנִ֔ים אַל תְּבַקְשׁ֖וּ לְ/טָמְאָ֣ה בָ/הֶ֑ם אֲנִ֖י יְהוָ֥ה אֱלֹהֵי/כֶֽם", "en": {"kjv": "Regard not them that have familiar spirits, neither seek after wizards, to be defiled by them: I am the Lord your God.", "web": "“‘Don’t turn to those who are mediums, nor to the wizards. Don’t seek them out, to be defiled by them. I am Yahweh your God.", "bsb": "You must not turn to mediums or spiritists; do not seek them out, or you will be defiled by them. I am the LORD your God.", "asv": "Turn ye not unto them that have familiar spirits, nor unto the wizards; seek them not out, to be defiled by them: I am Jehovah your God.", "ylt": "`Ye do not turn unto those having familiar spirits; and unto wizards ye do not seek, for uncleanness by them; I am Jehovah your God.", "tyndale": "Turne not to the that worke with sprites, nether regarde the that obserue disemall dayes: that ye be not defiled by the, for I am the Lorde youre God.", "dra": "Go not aside after wizards: neither ask any thing of soothsayers, to be defiled by them. I am the Lord your God.", "bbe": "Do not go after those who make use of spirits, or wonder-workers; do not go in their ways or become unclean through them: I am the Lord your God.", "geneva": "Ye shall not regarde them that worke with spirites, neither soothsayers: ye shall not seeke to them to be defiled by them: I am the Lord your God.", "wycliffe": "Bowe ye not to astronomyers, nether axe ye ony thing of fals dyuynours, that ye be defoulid bi hem; Y am youre Lord God.", "rotherham": "Do not turn unto mediums, Nor, for oracles, make search, To render yourselves unclean with them, I—Yahweh, am your God.", "darby": "— Turn not unto necromancers and unto soothsayers; seek not after them to make yourselves unclean: I am Jehovah yourGod.", "twenty": "", "jps": "Turn ye not unto the ghosts, nor unto familiar spirits; seek them not out, to be defiled by them: I am HaShem your G-d.", "acv": "Do not turn to those who have familiar spirits, nor to the wizards. Do not seek them out, to be defiled by them. I am Jehovah your God.", "anderson": "", "haweis": "", "noyes": "", "webster": "Regard not them that have familiar spirits, neither seek after wizards, to be defiled by them: I [am] the LORD your God.", "vulgate": "ne declinetis ad magos nec ab ariolis aliquid sciscitemini ut polluamini per eos ego Dominus Deus vester;", "brenton": "Ye shall not attend to those who have in them divining spirits, nor attach yourselves to enchanters, to pollute yourselves with them: I am the Lord your God."}}, {"v": 32, "ref": "19:32", "o": "מִ/פְּנֵ֤י שֵׂיבָה֙ תָּק֔וּם וְ/הָדַרְתָּ֖ פְּנֵ֣י זָקֵ֑ן וְ/יָרֵ֥אתָ מֵּ/אֱלֹהֶ֖י/ךָ אֲנִ֥י יְהוָֽה", "en": {"kjv": "Thou shalt rise up before the hoary head, and honour the face of the old man, and fear thy God: I am the Lord.", "web": "“‘You shall rise up before the gray head, and honor the face of an old man, and you shall fear your God. I am Yahweh.", "bsb": "You are to rise in the presence of the elderly, honor the aged, and fear your God. I am the LORD.", "asv": "Thou shalt rise up before the hoary head, and honor the face of the old man, and thou shalt fear thy God: I am Jehovah.", "ylt": "`At the presence of grey hairs thou dost rise up, and thou hast honoured the presence of an old man, and hast been afraid of thy God; I am Jehovah.", "tyndale": "Thou shalt ryse vp before the hoorehed, ad reuerence the face of the old ma ad dread thy god, for I am the Lorde.", "dra": "Rise up before the hoary head, and honour the person of the aged man: and fear the Lord thy God. I am the Lord.", "bbe": "Get up from your seats before the white-haired, and give honour to the old, and let the fear of your God be before you: I am the Lord.", "geneva": "Thou shalt rise vp before the horehead, and honour the person of the old man, and dread thy God: I am the Lord.", "wycliffe": "Rise thou bifor an hoor heed, and onoure thou the persoone of an eld man , and drede thou thi Lord God; Y am the Lord.", "rotherham": "Before a hoary head, shalt thou rise up, And shalt honour the presence of an elder,—So shalt thou stand in awe of thy God—I, am Yahweh.", "darby": "Before the hoary head thou shalt rise up, and shalt honour the face of an old man; and thou shalt fear thyGod: I am Jehovah.", "twenty": "", "jps": "Thou shalt rise up before the hoary head, and honour the face of the old man, and thou shalt fear thy G-d: I am HaShem.", "acv": "Thou shall rise up before the hoary head, and honor the face of the old man, and thou shall fear thy God. I am Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "Thou shalt rise up before the hoary head, and honor the face of the old man, and fear thy God: I [am] the LORD.", "vulgate": "coram cano capite consurge et honora personam senis et time Deum tuum ego sum Dominus;", "brenton": "Thou shalt rise up before the hoary head, and honour the face of the old man, and shalt fear thy God: I am the Lord your God."}}, {"v": 33, "ref": "19:33", "o": "וְ/כִֽי יָג֧וּר אִתְּ/ךָ֛ גֵּ֖ר בְּ/אַרְצְ/כֶ֑ם לֹ֥א תוֹנ֖וּ אֹתֽ/וֹ", "en": {"kjv": "And if a stranger sojourn with thee in your land, ye shall not vex him.", "web": "“‘If a stranger lives as a foreigner with you in your land, you shall not do him wrong.", "bsb": "When a foreigner resides with you in your land, you must not oppress him.", "asv": "And if a stranger sojourn with thee in your land, ye shall not do him wrong.", "ylt": "`And when a sojourner sojourneth with thee in your land, thou dost not oppress him;", "tyndale": "Yf a straunger soioure by the in youre lande, se that ye vexe him not:", "dra": "If a stranger dwell in your land, and abide among you, do not upbraid hin:", "bbe": "And if a man from another country is living in your land with you, do not make life hard for him;", "geneva": "And if a stranger soiourne with thee in your lande, ye shall not vexe him.", "wycliffe": "If a comelyng enhabitith in youre lond, and dwellith among you, dispise ye not hym,", "rotherham": "And, when there sojourneth with thee a sojourner in your land, ye shall not oppress him:", "darby": "And if a stranger sojourn with thee in your land, ye shall not molest him.", "twenty": "", "jps": "And if a stranger sojourn with thee in your land, ye shall not do him wrong.", "acv": "And if a stranger sojourns with thee in your land, ye shall not do him wrong.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if a stranger shall sojourn with thee in your land, ye shall not oppress him.", "vulgate": "si habitaverit advena in terra vestra et moratus fuerit inter vos ne exprobretis ei;", "brenton": "And if there should come to you a stranger in your land, ye shall not afflict him."}}, {"v": 34, "ref": "19:34", "o": "כְּ/אֶזְרָ֣ח מִ/כֶּם֩ יִהְיֶ֨ה לָ/כֶ֜ם הַ/גֵּ֣ר הַ/גָּ֣ר אִתְּ/כֶ֗ם וְ/אָהַבְתָּ֥ ל/וֹ֙ כָּמ֔וֹ/ךָ כִּֽי גֵרִ֥ים הֱיִיתֶ֖ם בְּ/אֶ֣רֶץ מִצְרָ֑יִם אֲנִ֖י יְהוָ֥ה אֱלֹהֵי/כֶֽם", "en": {"kjv": "But the stranger that dwelleth with you shall be unto you as one born among you, and thou shalt love him as thyself; for ye were strangers in the land of Egypt: I am the Lord your God.", "web": "The stranger who lives as a foreigner with you shall be to you as the native-born among you, and you shall love him as yourself; for you lived as foreigners in the land of Egypt. I am Yahweh your God.", "bsb": "You must treat the foreigner living among you as native-born and love him as yourself, for you were foreigners in the land of Egypt. I am the LORD your God.", "asv": "The stranger that sojourneth with you shall be unto you as the home-born among you, and thou shalt love him as thyself; for ye were sojourners in the land of Egypt: I am Jehovah your God.", "ylt": "as a native among you is the sojourner to you who is sojourning with you, and thou hast had love to him as to thyself, for sojourners ye have been in the land of Egypt; I am Jehovah your God.", "tyndale": "But let the straunger that dwelleth with you, be as one of youre selues, and loue him as thi selfe, for ye were straungers in the lande of Egipte. I am the Lorde youre God.", "dra": "But let him be among you as one of the same country. And you shall love him as yourselves: for you were strangers in the land of Egypt. I am the Lord your God.", "bbe": "Let him be to you as one of your countrymen and have love for him as for yourself; for you were living in a strange land, in the land of Egypt: I am the Lord your God.", "geneva": "But the stranger that dwelleth with you, shalbe as one of your selues, and thou shalt loue him as thy selfe: for ye were strangers in the lad of Egypt: I am the Lord your God.", "wycliffe": "but be he among you as a man borun in the lond; and ye schulen loue hym as you silf, for also ye weren comelyngis in the lond of Egipt; Y am youre Lord God.", "rotherham": "As one home born from among yourselves, shall be unto you the sojourner who sojourneth with you, So shalt thou love him as thyself, For, sojourners, became ye, in the land of Egypt,—I—Yahweh, am your God.", "darby": "As one born among you shall the stranger who sojourneth with you be unto you; and thou shalt love him as thyself; for ye were strangers in the land of Egypt: I am Jehovah yourGod.", "twenty": "", "jps": "The stranger that sojourneth with you shall be unto you as the home-born among you, and thou shalt love him as thyself; for ye were strangers in the land of Egypt: I am HaShem your G-d.", "acv": "The stranger that sojourns with you shall be to you as the home-born among you, and thou shall love him as thyself, for ye were sojourners in the land of Egypt. I am Jehovah your God.", "anderson": "", "haweis": "", "noyes": "", "webster": "[But] the stranger that dwelleth with you shall be to you as one born among you, and thou shalt love him as thyself; for ye were strangers in the land of Egypt: I [am] the LORD your God.", "vulgate": "sed sit inter vos quasi indigena et diligetis eum quasi vosmet ipsos fuistis enim et vos advenae in terra Aegypti ego Dominus Deus vester;", "brenton": "The stranger that comes to you shall be among you as the native, and thou shalt love him as thyself; for ye were strangers in the land of Egypt: I am the Lord your God."}}, {"v": 35, "ref": "19:35", "o": "לֹא תַעֲשׂ֥וּ עָ֖וֶל בַּ/מִּשְׁפָּ֑ט בַּ/מִּדָּ֕ה בַּ/מִּשְׁקָ֖ל וּ/בַ/מְּשׂוּרָֽה", "en": {"kjv": "Ye shall do no unrighteousness in judgment, in meteyard, in weight, or in measure.", "web": "“‘You shall do no unrighteousness in judgment, in measures of length, of weight, or of quantity.", "bsb": "You must not use dishonest measures of length, weight, or volume.", "asv": "Ye shall do no unrighteousness in judgment, in measures of length, of weight, or of quantity.", "ylt": "`Ye do not do perversity in judgment, in mete-yard, in weight, or in liquid measure;", "tyndale": "Ye shall do no vnrightuousnes in iudgemet nether in meteyerde, weyght or measure.", "dra": "Do not any unjust thing in judgment, in rule, in weight, or in measure.", "bbe": "Do not make false decisions in questions of yard-sticks and weights and measures.", "geneva": "Ye shall not doe vniustly in iudgement, in line, in weight, or in measure.", "wycliffe": "Nyle ye do ony wickid thing in doom, in reule, in weiyte, and in mesure; the balance be iust,", "rotherham": "Ye shall not act perversely in giving judgment,—in measures of extent, in weights in measures of capacity:", "darby": "Ye shall do no unrighteousness in judgment, in measure of length, in weight, and in measure of capacity:", "twenty": "", "jps": "Ye shall do no unrighteousness in judgment, in meteyard, in weight, or in measure.", "acv": "Ye shall do no unrighteousness in judgment, in measures of length, of weight, or of quantity.", "anderson": "", "haweis": "", "noyes": "", "webster": "Ye shall do no unrighteousness in judgment, in weight, in measure of length or of capacity.", "vulgate": "nolite facere iniquum aliquid in iudicio in regula in pondere in mensura;", "brenton": "Ye shall not act unrighteously in judgment, in measures and weights and scales."}}, {"v": 36, "ref": "19:36", "o": "מֹ֧אזְנֵי צֶ֣דֶק אַבְנֵי צֶ֗דֶק אֵ֥יפַת צֶ֛דֶק וְ/הִ֥ין צֶ֖דֶק יִהְיֶ֣ה לָ/כֶ֑ם אֲנִי֙ יְהוָ֣ה אֱלֹֽהֵי/כֶ֔ם אֲשֶׁר הוֹצֵ֥אתִי אֶתְ/כֶ֖ם מֵ/אֶ֥רֶץ מִצְרָֽיִם", "en": {"kjv": "Just balances, just weights, a just ephah, and a just hin, shall ye have: I am the Lord your God, which brought you out of the land of Egypt.", "web": "You shall have just balances, just weights, a just ephah, and a just hin. I am Yahweh your God, who brought you out of the land of Egypt.", "bsb": "You shall maintain honest scales and weights, an honest ephah, and an honest hin. I am the LORD your God, who brought you out of the land of Egypt.", "asv": "Just balances, just weights, a just ephah, and a just hin, shall ye have: I am Jehovah your God, who brought you out of the land of Egypt.", "ylt": "righteous balances, righteous weights, a righteous ephah, and a righteous hin ye have; I am Jehovah your God, who hath brought you out from the land of Egypt;", "tyndale": "But ye shal haue true balaces, true weightes, A true Epha ad a true hin. I am the Lorde youre god which broughte you out of the land of Egipte,", "dra": "Let the balance be just and the weights equal, the bushel just, and the sextary equal. I am the Lord your God, that brought you out of the land of Egypt.", "bbe": "Have true scales, true weights and measures for all things: I am the Lord your God, who took you out of the land of Egypt;", "geneva": "You shall haue iust ballances, true weightes, a true Ephah, and a true Hin. I am the Lord your God, which haue brought you out of the lande of Egypt.", "wycliffe": "and the weiytis be euene, the buschel be iust, and the sextarie be euene; Y am youre Lord God, that ladde you out of the lond of Egipt.", "rotherham": "Just balances, just weights, a just ephah and a just hin, shall ye have,—I—Yahweh, am your God, who brought you forth out of the land of Egypt.", "darby": "just balances, just weights, a just ephah, and a just hin shall ye have: I am Jehovah yourGod, who brought you out of the land of Egypt.", "twenty": "", "jps": "Just balances, just weights, a just ephah, and a just hin, shall ye have: I am HaShem your G-d, who brought you out of the land of Egypt.", "acv": "Ye shall have just balances, just weights, a just ephah, and a just hin. I am Jehovah your God, who brought you out of the land of Egypt.", "anderson": "", "haweis": "", "noyes": "", "webster": "Just balances, just weights, a just ephah, and a just hin shall ye have: I [am] the LORD your God, who brought you out of the land of Egypt.", "vulgate": "statera iusta et aequa sint pondera iustus modius aequusque sextarius ego Dominus Deus vester qui eduxi vos de terra Aegypti;", "brenton": "There shall be among you just balances and just weights and just liquid measure. I am the Lord your God, who brought you out of the land of Egypt."}}, {"v": 37, "ref": "19:37", "o": "וּ/שְׁמַרְתֶּ֤ם אֶת כָּל חֻקֹּתַ/י֙ וְ/אֶת כָּל מִשְׁפָּטַ֔/י וַ/עֲשִׂיתֶ֖ם אֹתָ֑/ם אֲנִ֖י יְהוָֽה", "en": {"kjv": "Therefore shall ye observe all my statutes, and all my judgments, and do them: I am the Lord.", "web": "“‘You shall observe all my statutes, and all my ordinances, and do them. I am Yahweh.’”", "bsb": "You must keep all My statutes and all My ordinances and follow them. I am the LORD.”", "asv": "And ye shall observe all my statutes, and all mine ordinances, and do them: I am Jehovah.", "ylt": "and ye have observed all my statutes, and all my judgments, and have done them; I am Jehovah.'", "tyndale": "that ye shulde obserue all myne ordinaunces and iudgementes and that ye shulde kepe them: I am the Lorde.", "dra": "Keep all my precepts, and all my judgments: and do them. I am the Lord.", "bbe": "You are to keep all my rules and my decisions and do them: I am the Lord.", "geneva": "Therefore shall ye obserue all mine ordinances, and all my iudgements, and doe them: I am the Lord.", "wycliffe": "Kepe ye alle myn heestis, and alle domes, and do ye tho; Y am the Lord.", "rotherham": "Therefore shall ye observe all my statutes and all my regulations and do them,—I, am Yahweh.", "darby": "And ye shall observe all my statutes, and all mine ordinances, and do them: I am Jehovah.", "twenty": "", "jps": "And ye shall observe all My statutes, and all Mine ordinances, and do them: I am HaShem.", "acv": "And ye shall observe all my statutes, and all my ordinances, and do them. I am Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "Therefore shall ye observe all my statutes, and all my judgments, and do them: I [am] the LORD.", "vulgate": "custodite omnia praecepta mea et universa iudicia et facite ea ego Dominus;", "brenton": "And ye shall keep all my law and all my ordinances, and ye shall do them: I am the Lord your God."}}]}, {"c": 20, "verses": [{"v": 1, "ref": "20:1", "o": "וַ/יְדַבֵּ֥ר יְהוָ֖ה אֶל מֹשֶׁ֥ה לֵּ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh spoke to Moses, saying,", "bsb": "Then the LORD said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde talked with Moses saynge:", "dra": "And the Lord spoke to Moses, saying:", "bbe": "And the Lord said to Moses,", "geneva": "And the Lord spake vnto Moses, saying,", "wycliffe": "And the Lord spak to Moises, and seide,", "rotherham": "And Yahweh spake unto Moses, saying:", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses, saying:", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "locutusque est Dominus ad Mosen dicens;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 2, "ref": "20:2", "o": "וְ/אֶל בְּנֵ֣י יִשְׂרָאֵ֘ל תֹּאמַר֒ אִ֣ישׁ אִישׁ֩ מִ/בְּנֵ֨י יִשְׂרָאֵ֜ל וּ/מִן הַ/גֵּ֣ר הַ/גָּ֣ר בְּ/יִשְׂרָאֵ֗ל אֲשֶׁ֨ר יִתֵּ֧ן מִ/זַּרְע֛/וֹ לַ/מֹּ֖לֶךְ מ֣וֹת יוּמָ֑ת עַ֥ם הָ/אָ֖רֶץ יִרְגְּמֻ֥/הוּ בָ/אָֽבֶן", "en": {"kjv": "Again, thou shalt say to the children of Israel, Whosoever he be of the children of Israel, or of the strangers that sojourn in Israel, that giveth any of his seed unto Molech; he shall surely be put to death: the people of the land shall stone him with stones.", "web": "“Moreover, you shall tell the children of Israel, ‘Anyone of the children of Israel, or of the strangers who live as foreigners in Israel, who gives any of his seed to Molech; he shall surely be put to death. The people of the land shall stone him with stones.", "bsb": "“Tell the Israelites, ‘Any Israelite or foreigner living in Israel who gives any of his children to Molech must be put to death. The people of the land are to stone him.", "asv": "Moreover, thou shalt say to the children of Israel, Whosoever he be of the children of Israel, or of the strangers that sojourn in Israel, that giveth of his seed unto Molech; he shall surely be put to death: the people of the land shall stone him with stones.", "ylt": "`And unto the sons of Israel thou dost say, Any man of the sons of Israel, and of the sojourners who is sojourning in Israel, who giveth of his seed to the Molech, is certainly put to death; the people of the land do stone him with stones;", "tyndale": "tell the childern of Israel, whosoeuer he be of the childern of Israel or of the straungers that dwel in Israel, that geueth of his seed vnto Moloch he shall dye for it: the people off the lande shall stone hi with stones.", "dra": "Thus shalt thou say to the children of Israel: If any man of the children Israel, or of the strangers that dwell in Israel, give of his seed to the idol Moloch, dying let him die. The people of the land shall stone him.", "bbe": "Again, say to the children of Israel, If any man of the children of Israel, or any other man living in Israel, gives his offspring to Molech, he is certainly to be put to death: he is to be stoned by the people of the land;", "geneva": "Thou shalt say also to the children of Israel, Whosoeuer he be of the children of Israel, or of the strangers that dwell in Israel, that giueth his children vnto Molech, he shall die the death, ye people of ye land shall stone him to death.", "wycliffe": "Speke thou these thingis to the sones of Israel, If eny man of the sones of Israel, and of the comelyngis that dwellen in Israel, yyueth of his seed to the ydol Moloch, die he bi deeth; the puple of the lond schal stone him.", "rotherham": "Unto the sons of Israel, therefore shalt thou say, What man soever, there may be of the sons of Israel, or of the sojourners that sojourn in Israel, that giveth of his seed unto Molech, he shall, surely be put to death,—the people of the land shall stone him with stones;", "darby": "Thou shalt say also to the children of Israel, Every one of the children of Israel, or of the strangers who sojourn in Israel, that giveth of his seed unto Molech, shall certainly be put to death: the people of the land shall stone him with stones.", "twenty": "", "jps": "Moreover, thou shalt say to the children of Israel: Whosoever he be of the children of Israel, or of the strangers that sojourn in Israel, that giveth of his seed unto Molech; he shall surely be put to death; the people of the land shall stone him with stones.", "acv": "Moreover, thou shall say to the sons of Israel, Whoever he is of the sons of Israel, or of the strangers that sojourn in Israel, who gives of his seed to Molech, he shall surely be put to death. The people of the land shall stone him with stones.", "anderson": "", "haweis": "", "noyes": "", "webster": "Again thou shalt say to the children of Israel, Whoever [he be] of the children of Israel, or of the strangers that sojourn in Israel, that giveth [any] of his seed to Molech, he shall surely be put to death: the people of the land shall stone him with stones.", "vulgate": "haec loqueris filiis Israhel homo de filiis Israhel et de advenis qui habitant in Israhel si quis dederit de semine suo idolo Moloch morte moriatur populus terrae lapidabit eum;", "brenton": "Thou shalt also say to the children of Israel, If there shall be any of the children of Israel, or of those who have become proselytes in Israel, who shall give of his seed to Moloch, let him be surely put to death; the nation upon the land shall stone him with stones."}}, {"v": 3, "ref": "20:3", "o": "וַ/אֲנִ֞י אֶתֵּ֤ן אֶת פָּנַ/י֙ בָּ/אִ֣ישׁ הַ/ה֔וּא וְ/הִכְרַתִּ֥י אֹת֖/וֹ מִ/קֶּ֣רֶב עַמּ֑/וֹ כִּ֤י מִ/זַּרְע/וֹ֙ נָתַ֣ן לַ/מֹּ֔לֶךְ לְמַ֗עַן טַמֵּא֙ אֶת מִקְדָּשִׁ֔/י וּ/לְ/חַלֵּ֖ל אֶת שֵׁ֥ם קָדְשִֽׁ/י", "en": {"kjv": "And I will set my face against that man, and will cut him off from among his people; because he hath given of his seed unto Molech, to defile my sanctuary, and to profane my holy name.", "web": "I also will set my face against that person, and will cut him off from among his people because he has given of his seed to Molech, to defile my sanctuary, and to profane my holy name.", "bsb": "And I will set My face against that man and cut him off from his people, because by giving his offspring to Molech, he has defiled My sanctuary and profaned My holy name.", "asv": "I also will set my face against that man, and will cut him off from among his people; because he hath given of his seed unto Molech, to defile my sanctuary, and to profane my holy name.", "ylt": "and I--I set My face against that man, and have cut him off from the midst of his people, for of his seed he hath given to the Molech, so as to defile My sanctuary, and to pollute My holy name.", "tyndale": "And I wil sett my face apon that felowe, and will destroye him from amonge his people: because he hath geuen of his seed vnto Moloch, for to defile my sanctuary and to polute myne holy name.", "dra": "And I will set my face against him: and I will cut him off from the midst of his people, because he hath given of his seed to Moloch, and hath defiled my sanctuary, and profaned my holy name.", "bbe": "And my face will be turned against that man, and he will be cut off from his people; because he has given his offspring to Molech, making my holy place unclean, and making my holy name common.", "geneva": "And I will set my face against that man and cut him off from among his people, because he hath giuen his children vnto Molech, for to defile my Sanctuarie, and to pollute mine holy Name.", "wycliffe": "And Y schal sette faste my face ayens hym, and Y schal kitte awei him fro the myddis of my puple, for he yaf of his seed to Moloch, and defoulide my seyntuarie, and defoulide myn hooli name.", "rotherham": "I, also, will set my face against that man, and will cut him off out of the midst of his people,—because of his seed, hath he given unto Molech, seeing that he hath made unclean my sanctuary, even to the extent of profaning my holy name.", "darby": "And I will set my face against that man, and will cut him off from among his people; because he hath given of his seed unto Molech, so as to make my sanctuary unclean, and to profane my holy name.", "twenty": "", "jps": "I also will set My face against that man, and will cut him off from among his people, because he hath given of his seed unto Molech, to defile My sanctuary, and to profane My holy name.", "acv": "I also will set my face against that man, and will cut him off from among his people, because he has given of his seed to Molech, to defile my sanctuary, and to profane my holy name.", "anderson": "", "haweis": "", "noyes": "", "webster": "And I will set my face against that man, and will cut him off from among his people; because he hath given of his seed to Molech, to defile my sanctuary, and to profane my holy name.", "vulgate": "et ego ponam faciem meam contra illum succidamque eum de medio populi sui eo quod dederit de semine suo Moloch et contaminaverit sanctuarium meum ac polluerit nomen sanctum meum;", "brenton": "And I will set my face against that man, and will cut him off from his people, because he has given of his seed to Moloch, to defile my sanctuary, and profane the name of them that are consecrated to me."}}, {"v": 4, "ref": "20:4", "o": "וְ/אִ֡ם הַעְלֵ֣ם יַעְלִימֽוּ֩ עַ֨ם הָ/אָ֜רֶץ אֶת עֵֽינֵי/הֶם֙ מִן הָ/אִ֣ישׁ הַ/ה֔וּא בְּ/תִתּ֥/וֹ מִ/זַּרְע֖/וֹ לַ/מֹּ֑לֶךְ לְ/בִלְתִּ֖י הָמִ֥ית אֹתֽ/וֹ", "en": {"kjv": "And if the people of the land do any ways hide their eyes from the man, when he giveth of his seed unto Molech, and kill him not:", "web": "If the people of the land all hide their eyes from that person, when he gives of his seed to Molech, and don’t put him to death;", "bsb": "And if the people of the land ever hide their eyes and fail to put to death the man who gives one of his children to Molech,", "asv": "And if the people of the land do at all hide their eyes from that man, when he giveth of his seed unto Molech, and put him not to death;", "ylt": "`And if the people of the land really hide their eyes from that man, in his giving of his seed to the Molech, so as not to put him to death,", "tyndale": "And though that the people of the lande hyde their eyes from that felowe, when he geueth of his seed vnto Moloch, so that they kyll him not:", "dra": "And if the people of the land neglecting, and as it were little regarding my commandment, let alone the man that hath given of his seed to Moloch, and will not kill him:", "bbe": "And if the people of the land do not take note of that man when he gives his offspring to Molech, and do not put him to death,", "geneva": "And if the people of the lande hide their eyes, and winke at that man when he giueth his children vnto Molech, and kill him not,", "wycliffe": "That if the puple of the lond is necgligent, and as litil chargynge myn heeste, and suffrith the man that yaf of his seed to Moloch, nether wole sle hym, Y schal sette my face on that man,", "rotherham": "But, if the people of the land, do even hide, their eyes from that man, when he giveth of his seed unto Molech,—so as not to put him to death,", "darby": "And if the people of the land do any ways hide their eyes from that man, when he giveth of his seed unto Molech, that they kill him not,", "twenty": "", "jps": "And if the people of the land do at all hide their eyes from that man, when he giveth of his seed unto Molech, and put him not to death;", "acv": "And if the people at the land do at all hide their eyes from that man, when he gives of his seed to Molech, and do not put him to death,", "anderson": "", "haweis": "", "noyes": "", "webster": "And if the people of the land do any ways hide their eyes from the man, when he giveth of his seed to Molech, and kill him not;", "vulgate": "quod si neglegens populus terrae et quasi parvipendens imperium meum dimiserit hominem qui dederit de semine suo Moloch nec voluerit eum occidere;", "brenton": "And if the natives of the land should in anywise overlook that man in giving of his seed to Moloch, so as not to put him to death;"}}, {"v": 5, "ref": "20:5", "o": "וְ/שַׂמְתִּ֨י אֲנִ֧י אֶת פָּנַ֛/י בָּ/אִ֥ישׁ הַ/ה֖וּא וּ/בְ/מִשְׁפַּחְתּ֑/וֹ וְ/הִכְרַתִּ֨י אֹת֜/וֹ וְ/אֵ֣ת כָּל הַ/זֹּנִ֣ים אַחֲרָ֗י/ו לִ/זְנ֛וֹת אַחֲרֵ֥י הַ/מֹּ֖לֶךְ מִ/קֶּ֥רֶב עַמָּֽ/ם", "en": {"kjv": "Then I will set my face against that man, and against his family, and will cut him off, and all that go a whoring after him, to commit whoredom with Molech, from among their people.", "web": "then I will set my face against that man, and against his family, and will cut him off, and all who play the prostitute after him, to play the prostitute with Molech, from among their people.", "bsb": "then I will set My face against that man and his family and cut off from among their people both him and all who follow him in prostituting themselves with Molech.", "asv": "then I will set my face against that man, and against his family, and will cut him off, and all that play the harlot after him, to play the harlot with Molech, from among their people.", "ylt": "then I have set My face against that man, and against his family, and have cut him off, and all who are going a-whoring after him, even going a-whoring after the Molech, from the midst of their people.", "tyndale": "yet I will put my face apon that man and apon his houssholde, and will destroy him and all that goo a whooringe with him and comytt hoordome with Moloch from amonge their people.", "dra": "I will set my face against that man, and his kindred, and will cut off both him and all that consented with him, to commit fornication with Moloch, out of the midst of their people.", "bbe": "Then my face will be turned against him and his family, and he and all those who do evil with him will be cut off from among their people.", "geneva": "Then will I set my face against that man, and against his familie, and will cut him off, and all that go a whoring after him to comit whoredome with Molech, from among their people.", "wycliffe": "and his kynrede, and Y schal kitte doun hym, and alle that consentiden to him, that thei schulden do fornycacioun with Moloch, fro the myddis of her puple.", "rotherham": "then will I myself, set my face against that man, and against his family,—and will cut him off, and all that follow unchastely after him—in going unchastely after Molech—out of the midst of their people.", "darby": "then I will set my face against that man, and against his family, and will cut him off, and all that go a whoring after him, to commit whoredom with Molech, from among their people.", "twenty": "", "jps": "then I will set My face against that man, and against his family, and will cut him off, and all that go astray after him, to go astray after Molech, from among their people.", "acv": "then I will set my face against that man, and against his family, and will cut him off, and all who play the harlot after him, to play the harlot with Molech, from among their people.", "anderson": "", "haweis": "", "noyes": "", "webster": "Then I will set my face against that man, and against his family, and will cut him off, and all that go astray after him, to commit lewdness with Molech from among their people.", "vulgate": "ponam faciem meam super hominem illum et cognationem eius succidamque et ipsum et omnes qui consenserunt ei ut fornicarentur cum Moloch de medio populi sui;", "brenton": "then will I set my face against that man and his family, and I will destroy him, and all who have been of one mind with him, so that he should go a whoring to the princes, from their people."}}, {"v": 6, "ref": "20:6", "o": "וְ/הַ/נֶּ֗פֶשׁ אֲשֶׁ֨ר תִּפְנֶ֤ה אֶל הָֽ/אֹבֹת֙ וְ/אֶל הַ/יִּדְּעֹנִ֔ים לִ/זְנ֖וֹת אַחֲרֵי/הֶ֑ם וְ/נָתַתִּ֤י אֶת פָּנַ/י֙ בַּ/נֶּ֣פֶשׁ הַ/הִ֔וא וְ/הִכְרַתִּ֥י אֹת֖/וֹ מִ/קֶּ֥רֶב עַמּֽ/וֹ", "en": {"kjv": "And the soul that turneth after such as have familiar spirits, and after wizards, to go a whoring after them, I will even set my face against that soul, and will cut him off from among his people.", "web": "“‘The person that turns to those who are mediums, and to the wizards, to play the prostitute after them, I will even set my face against that person, and will cut him off from among his people.", "bsb": "Whoever turns to mediums or spiritists to prostitute himself with them, I will also set My face against that person and cut him off from his people.", "asv": "And the soul that turneth unto them that have familiar spirits, and unto the wizards, to play the harlot after them, I will even set my face against that soul, and will cut him off from among his people.", "ylt": "`And the person who turneth unto those having familiar spirits, and unto the wizards, to go a-whoring after them, I have even set My face against that person, and cut him off from the midst of his people.", "tyndale": "Yf any soule turne vnto them that worke with spirites or makers of dysemall dayes and goo a whoorynge after them, I wilt put my face apon that soule and will destroye him from amonge his people.", "dra": "The soul that shall go aside after magicians, and soothsayers, and shall commit fornication with them: I will set my face against that soul, and destroy it out of the midst of its people.", "bbe": "And whoever goes after those who make use of spirits and wonder-workers, doing evil with them, against him will my face be turned, and he will be cut off from among his people.", "geneva": "If any turne after such as worke with spirits, and after soothsayers, to go a whoring after them, then will I set my face against that person, and will cut him off from among his people.", "wycliffe": "If a man bowith to astronomyers, and false dyuynours, and doith fornycacioun with hem, Y schal sette my face ayens hym, and Y schal sle hym fro the mydis of hys puple.", "rotherham": "The person also that turneth unto mediums and unto oracles, in going unchastely after them, then will I set my face against that person, and will cut him off out of the midst of his people.", "darby": "— And the soul that turneth unto necromancers and unto soothsayers, to go a whoring after them, I will set my face against that soul, and will cut him off from among his people.", "twenty": "", "jps": "And the soul that turneth unto the ghosts, and unto the familiar spirits, to go astray after them, I will even set My face against that soul, and will cut him off from among his people.", "acv": "And the soul that turns to those who have familiar spirits, and to the wizards, to play the harlot after them, I will even set my face against that soul, and will cut him off from among his people.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the soul that turneth after such as have familiar spirits, and after wizards, to go astray after them, I will even set my face against that soul, and will cut him off from among his people.", "vulgate": "anima quae declinaverit ad magos et ariolos et fornicata fuerit cum eis ponam faciem meam contra eam et interficiam illam de medio populi sui;", "brenton": "And the soul that shall follow those who have in them divining spirits, or enchanters, so as to go a whoring after them; I will set my face against that soul, and will destroy it from among its people."}}, {"v": 7, "ref": "20:7", "o": "וְ/הִ֨תְקַדִּשְׁתֶּ֔ם וִ/הְיִיתֶ֖ם קְדֹשִׁ֑ים כִּ֛י אֲנִ֥י יְהוָ֖ה אֱלֹהֵי/כֶֽם", "en": {"kjv": "Sanctify yourselves therefore, and be ye holy: for I am the Lord your God.", "web": "“‘Sanctify yourselves therefore, and be holy; for I am Yahweh your God.", "bsb": "Consecrate yourselves, therefore, and be holy, because I am the LORD your God.", "asv": "Sanctify yourselves therefore, and be ye holy; for I am Jehovah your God.", "ylt": "`And ye have sanctified yourselves, and ye have been holy, for I am Jehovah your God;", "tyndale": "Sanctifie youre selues therfore and be holye, for I am the Lorde youre God.", "dra": "Sanctify yourselves, and be ye holy: because I am the Lord your God.", "bbe": "So make and keep yourselves holy, for I am the Lord your God.", "geneva": "Sanctifie your selues therefore, and be holie, for I am the Lord your God.", "wycliffe": "Be ye halewid, and be ye hooli, for Y am hooli, youre Lord God.", "rotherham": "Therefore shall ye hallow yourselves and be holy,—Because I—Yahweh, am your God.", "darby": "Hallow yourselves therefore, and be holy; for I am Jehovah yourGod.", "twenty": "", "jps": "Sanctify yourselves therefore, and be ye holy; for I am HaShem your G-d.", "acv": "Sanctify yourselves therefore, and become ye holy, for I am Jehovah your God.", "anderson": "", "haweis": "", "noyes": "", "webster": "Sanctify yourselves therefore and be ye holy: for I [am] the LORD your God.", "vulgate": "sanctificamini et estote sancti quia ego Dominus Deus vester;", "brenton": "And ye shall be holy, for I the Lord your God am holy."}}, {"v": 8, "ref": "20:8", "o": "וּ/שְׁמַרְתֶּם֙ אֶת חֻקֹּתַ֔/י וַ/עֲשִׂיתֶ֖ם אֹתָ֑/ם אֲנִ֥י יְהוָ֖ה מְקַדִּשְׁ/כֶֽם", "en": {"kjv": "And ye shall keep my statutes, and do them: I am the Lord which sanctify you.", "web": "You shall keep my statutes, and do them. I am Yahweh who sanctifies you.", "bsb": "And you shall keep My statutes and practice them. I am the LORD who sanctifies you.", "asv": "And ye shall keep my statutes, and do them: I am Jehovah who sanctifieth you.", "ylt": "and ye have kept My statutes and have done them; I am Jehovah, sanctifying you.", "tyndale": "And se that ye kepe myne ordinaunces and doo them. For I am the Lorde which sanctifie you.", "dra": "Keep my precepts, and do them. I am the Lord that sanctify you.", "bbe": "And keep my rules and do them: I am the Lord, who make you holy.", "geneva": "Keepe ye therefore mine ordinances, and doe them. I am the Lord which doeth sanctifie you.", "wycliffe": "Kepe ye myn heestis, and do ye tho, for Y am the Lord that halewe you.", "rotherham": "Therefore shall ye observe my statutes, and do them,—I—Yahweh, am he that is hallowing you.", "darby": "And ye shall observe my statutes, and do them: I am Jehovah who hallow you.", "twenty": "", "jps": "And keep ye My statutes, and do them: I am HaShem who sanctify you.", "acv": "And ye shall keep my statutes, and do them. I am Jehovah who sanctifies you.", "anderson": "", "haweis": "", "noyes": "", "webster": "And ye shall keep my statutes, and do them: I [am] the LORD who sanctify you.", "vulgate": "custodite praecepta mea et facite ea ego Dominus qui sanctifico vos;", "brenton": "And ye shall observe my ordinances, and do them: I am the Lord that sanctifies you."}}, {"v": 9, "ref": "20:9", "o": "כִּֽי אִ֣ישׁ אִ֗ישׁ אֲשֶׁ֨ר יְקַלֵּ֧ל אֶת אָבִ֛י/ו וְ/אֶת אִמּ֖/וֹ מ֣וֹת יוּמָ֑ת אָבִ֧י/ו וְ/אִמּ֛/וֹ קִלֵּ֖ל דָּמָ֥י/ו בּֽ/וֹ", "en": {"kjv": "For every one that curseth his father or his mother shall be surely put to death: he hath cursed his father or his mother; his blood shall be upon him.", "web": "“‘For everyone who curses his father or his mother shall surely be put to death: he has cursed his father or his mother; his blood shall be upon him.", "bsb": "If anyone curses his father or mother, he must be put to death. He has cursed his father or mother; his blood shall be upon him.", "asv": "For every one that curseth his father or his mother shall surely be put to death: he hath cursed his father or his mother; his blood shall be upon him.", "ylt": "`For any man who revileth his father and his mother is certainly put to death; his father and his mother he hath reviled: his blood is on him.", "tyndale": "Whosoeuer curseth his father or mother, shall dye for it, his bloude on his heed, because he hath cursed his father or mother.", "dra": "He that curseth his father, or mother, dying let him die. He hath cursed his father, and mother: let his blood be upon him.", "bbe": "Every man cursing his father or his mother is certainly to be put to death; because of his curse on his father or his mother, his blood will be on him.", "geneva": "If there be any that curseth his father or his mother, he shall die the death: seeing hee hath cursed his father and his mother, his blood shalbe vpon him.", "wycliffe": "He that cursith his fadir, ether modir, die bi deeth; if a man cursith fadir and modir, his blood be on hym.", "rotherham": "When, any man whatsoever, curseth his father or his mother, he shall surely be put to death,—his father or his mother, hath he cursed, his blood, shall be upon himself.", "darby": "Whatever man revileth his father and his mother shall certainly be put to death: he hath reviled his father and his mother; his blood is upon him.", "twenty": "", "jps": "For whatsoever man there be that curseth his father or his mother shall surely be put to death; he hath cursed his father or his mother; his blood shall be upon him.", "acv": "For he who curses his father or his mother shall surely be put to death. He has cursed his father or his mother; his blood shall be upon him.", "anderson": "", "haweis": "", "noyes": "", "webster": "For every one that curseth his father or his mother, shall surely be put to death: he hath cursed his father or his mother; his blood [shall be] upon him.", "vulgate": "qui maledixerit patri suo et matri morte moriatur patri matrique maledixit sanguis eius sit super eum;", "brenton": "Every man who shall speak evil of his father or of his mother, let him die the death; has he spoken evil of his father or his mother? he shall be guilty."}}, {"v": 10, "ref": "20:10", "o": "וְ/אִ֗ישׁ אֲשֶׁ֤ר יִנְאַף֙ אֶת אֵ֣שֶׁת אִ֔ישׁ אֲשֶׁ֥ר יִנְאַ֖ף אֶת אֵ֣שֶׁת רֵעֵ֑/הוּ מֽוֹת יוּמַ֥ת הַ/נֹּאֵ֖ף וְ/הַ/נֹּאָֽפֶת", "en": {"kjv": "And the man that committeth adultery with another man’s wife, even he that committeth adultery with his neighbour’s wife, the adulterer and the adulteress shall surely be put to death.", "web": "“‘The man who commits adultery with another man’s wife, even he who commits adultery with his neighbor’s wife, the adulterer and the adulteress shall surely be put to death.", "bsb": "If a man commits adultery with another man’s wife—with the wife of his neighbor—both the adulterer and the adulteress must surely be put to death.", "asv": "And the man that committeth adultery with another man’s wife, even he that committeth adultery with his neighbor’s wife, the adulterer and the adulteress shall surely be put to death.", "ylt": "`And a man who committeth adultery with a man's wife--who committeth adultery with the wife of his neighbour--the adulterer and the adulteress are surely put to death.", "tyndale": "He that breaketh wedlocke with another mans wife shall dye for it: because he hath broke wedlocke with his neghbours wife, and so shall she likewise.", "dra": "If any man commit adultery with the wife of another, and defile his neighbour's wife: let them be put to death, both the adulterer and the adulteress.", "bbe": "And if a man has sex relations with another man's wife, even the wife of his neighbour, he and she are certainly to be put to death.", "geneva": "And the man that committeth adulterie with another mans wife, because he hath comitted adulterie with his neighbours wife, the adulterer and the adulteresse shall die the death.", "wycliffe": "If a man doith leccherie with `the wijf of another man, and doith auowtrie with `the wijf of his neiybore, bothe auowter and auowtresse die bi deeth.", "rotherham": "And, any man, who committeth adultery with the wife of any other man, he that committeth adultery with the wife of his neighbour shall surely be put to death—the adulterer, and the adulteress.", "darby": "And a man that committeth adultery with a man's wife, who committeth adultery with his neighbour's wife, — the adulterer and the adulteress shall certainly be put to death.", "twenty": "", "jps": "And the man that committeth adultery with another man's wife, even he that committeth adultery with his neighbour's wife, both the adulterer and the adulteress shall surely be put to death.", "acv": "And the man who commits adultery with another man's wife, even he who commits adultery with his neighbor's wife, the adulterer and the adulteress shall surely be put to death.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the man that committeth adultery with [another] man's wife, [even he] that committeth adultery with his neighbor's wife, the adulterer and the adulteress shall surely be put to death.", "vulgate": "si moechatus quis fuerit cum uxore alterius et adulterium perpetrarit cum coniuge proximi sui morte moriantur et moechus et adultera;", "brenton": "Whatever man shall commit adultery with the wife of a man, or whoever shall commit adultery with the wife of his neighbour, let them die the death, the adulterer and the adulteress."}}, {"v": 11, "ref": "20:11", "o": "וְ/אִ֗ישׁ אֲשֶׁ֤ר יִשְׁכַּב֙ אֶת אֵ֣שֶׁת אָבִ֔י/ו עֶרְוַ֥ת אָבִ֖י/ו גִּלָּ֑ה מֽוֹת יוּמְת֥וּ שְׁנֵי/הֶ֖ם דְּמֵי/הֶ֥ם בָּֽ/ם", "en": {"kjv": "And the man that lieth with his father’s wife hath uncovered his father’s nakedness: both of them shall surely be put to death; their blood shall be upon them.", "web": "“‘The man who lies with his father’s wife has uncovered his father’s nakedness: both of them shall surely be put to death; their blood shall be upon them.", "bsb": "If a man lies with his father’s wife, he has uncovered his father’s nakedness. Both must surely be put to death; their blood is upon them.", "asv": "And the man that lieth with his father’s wife hath uncovered his father’s nakedness: both of them shall surely be put to death; their blood shall be upon them.", "ylt": "`And a man who lieth with his father's wife--the nakedness of his father he hath uncovered--both of them are certainly put to death; their blood is on them.", "tyndale": "Yf a man lye with his fathers wife ad vncouer his fathers secrettes, they shall both dye for it, their bloude be apon their heedes.", "dra": "If a man lie with his stepmother, and discover the nakedness of his father, let them both be put to death: their blood be upon them.", "bbe": "And the man who has sex relations with his father's wife has put shame on his father: the two of them are to be put to death; their blood will be on them.", "geneva": "And the man that lyeth with his fathers wife, because hee hath vncouered his fathers shame, they shall both dye: their blood shalbe vpon them.", "wycliffe": "If a man slepith with hys stepdamme, and schewith `the schenschip of his fadir, bothe die bi deeth; her blood be on hem.", "rotherham": "And any man who lieth with his father’s wife, the shame of his father, hath uncovered,—they both shall, surely be put to death—their blood shall be upon themselves.", "darby": "And a man that lieth with his father's wife hath uncovered his father's nakedness: both of them shall certainly be put to death; their blood is upon them.", "twenty": "", "jps": "And the man that lieth with his father's wife--he hath uncovered his father's nakedness--both of them shall surely be put to death; their blood shall be upon them.", "acv": "And the man who lies with his father's wife has uncovered his father's nakedness. Both of them shall surely be put to death, their blood shall be upon them.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the man that lieth with his father's wife hath uncovered his father's nakedness; both of them shall surely be put to death: their blood [shall be] upon them.", "vulgate": "qui dormierit cum noverca sua et revelaverit ignominiam patris sui morte moriantur ambo sanguis eorum sit super eos;", "brenton": "And if any one should lie with his father's wife, he has uncovered his father's nakedness: let them both die the death, they are guilty."}}, {"v": 12, "ref": "20:12", "o": "וְ/אִ֗ישׁ אֲשֶׁ֤ר יִשְׁכַּב֙ אֶת כַּלָּת֔/וֹ מ֥וֹת יוּמְת֖וּ שְׁנֵי/הֶ֑ם תֶּ֥בֶל עָשׂ֖וּ דְּמֵי/הֶ֥ם בָּֽ/ם", "en": {"kjv": "And if a man lie with his daughter in law, both of them shall surely be put to death: they have wrought confusion; their blood shall be upon them.", "web": "“‘If a man lies with his daughter-in-law, both of them shall surely be put to death: they have committed a perversion; their blood shall be upon them.", "bsb": "If a man lies with his daughter-in-law, both must surely be put to death. They have acted perversely; their blood is upon them.", "asv": "And if a man lie with his daughter-in-law, both of them shall surely be put to death: they have wrought confusion; their blood shall be upon them.", "ylt": "`And a man who lieth with his daughter-in-law--both of them are certainly put to death; confusion they have made; their blood is on them.", "tyndale": "Yf a man lye with his doughter in lawe thei shall dye both of them: they haue wrought abhominacion, their bloud vpon their heedes.", "dra": "If any man lie with his daughter in law: let both die, because they have done a heinous crime. Their blood be upon them.", "bbe": "And if a man has sex relations with his son's wife, the two of them are to be put to death: it is unnatural; their blood will be on them.", "geneva": "Also the man that lyeth with his daughter in lawe, they both shall dye the death, they haue wrought abomination, their blood shalbe vpon them.", "wycliffe": "If ony man slepith with `his sones wijf, euer either die, for thei han wrouyt greet synne; her blood be on hem.", "rotherham": "And any man who lieth with his daughter-in-law, they both shall, surely be put to death, confusion, have they wrought—their blood shall be upon themselves.", "darby": "And if a man lie with his daughter-in-law, both of them shall certainly be put to death: they have wrought confusion; their blood is upon them.", "twenty": "", "jps": "And if a man lie with his daughter-in-law, both of them shall surely be put to death; they have wrought corruption; their blood shall be upon them.", "acv": "And if a man lies with his daughter-in-law, both of them shall surely be put to death. They have wrought perversion. Their blood shall be upon them.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if a man shall lie with his daughter-in-law, both of them shall surely be put to death: they have wrought confusion; their blood [shall be] upon them.", "vulgate": "si quis dormierit cum nuru sua uterque moriantur quia scelus operati sunt sanguis eorum sit super eos;", "brenton": "And if any one should lie with his daughter-in-law, let them both be put to death; for they have wrought impiety, they are guilty."}}, {"v": 13, "ref": "20:13", "o": "וְ/אִ֗ישׁ אֲשֶׁ֨ר יִשְׁכַּ֤ב אֶת זָכָר֙ מִשְׁכְּבֵ֣י אִשָּׁ֔ה תּוֹעֵבָ֥ה עָשׂ֖וּ שְׁנֵי/הֶ֑ם מ֥וֹת יוּמָ֖תוּ דְּמֵי/הֶ֥ם בָּֽ/ם", "en": {"kjv": "If a man also lie with mankind, as he lieth with a woman, both of them have committed an abomination: they shall surely be put to death; their blood shall be upon them.", "web": "“‘If a man lies with a male, as with a woman, both of them have committed an abomination: they shall surely be put to death; their blood shall be upon them.", "bsb": "If a man lies with a man as with a woman, they have both committed an abomination. They must surely be put to death; their blood is upon them.", "asv": "And if a man lie with mankind, as with womankind, both of them have committed abomination: they shall surely be put to death; their blood shall be upon them.", "ylt": "`And a man who lieth with a male as one lieth with a woman; abomination both of them have done; they are certainly put to death; their blood is on them.", "tyndale": "Yf a man lye with the mankynde after the maner as with woma kynd, they haue both comitted an abhominacion and shall dye for it. Their bloude be apon their heed.", "dra": "If any one lie with a man as with a woman, both have committed an abomination: let them be put to death. Their blood be upon them.", "bbe": "And if a man has sex relations with a man, the two of them have done a disgusting thing: let them be put to death; their blood will be on them.", "geneva": "The man also that lyeth with the male, as one lyeth with a woman, they haue both committed abomination: they shall dye the death, their blood shalbe vpon them.", "wycliffe": "If a man slepith with a man, bi letcherie of a womman, euer either hath wrouyt vnleueful thing, die thei bi deeth; her blood be on hem.", "rotherham": "And any man who lieth with mankind as with womankind, an abomination, have both of them wrought,—they shall, surely be put to death,—their blood, shall be upon themselves.", "darby": "And if a man lie with mankind, as he lieth with a woman, both of them have committed an abomination: they shall certainly be put to death; their blood is upon them.", "twenty": "", "jps": "And if a man lie with mankind, as with womankind, both of them have committed abomination: they shall surely be put to death; their blood shall be upon them.", "acv": "And if a man lies with a man, as with a woman, both of them have committed abomination. They shall surely be put to death; their blood shall be upon them.", "anderson": "", "haweis": "", "noyes": "", "webster": "If a man also shall lie with mankind, as he lieth with a woman, both of them have committed an abomination: they shall surely be put to death; their blood [shall be] upon them.", "vulgate": "qui dormierit cum masculo coitu femineo uterque operati sunt nefas morte moriantur sit sanguis eorum super eos;", "brenton": "And whoever shall lie with a male as with a woman, they have both wrought abomination; let them die the death, they are guilty."}}, {"v": 14, "ref": "20:14", "o": "וְ/אִ֗ישׁ אֲשֶׁ֨ר יִקַּ֧ח אֶת אִשָּׁ֛ה וְ/אֶת אִמָּ֖/הּ זִמָּ֣ה הִ֑וא בָּ/אֵ֞שׁ יִשְׂרְפ֤וּ אֹת/וֹ֙ וְ/אֶתְ/הֶ֔ן וְ/לֹא תִהְיֶ֥ה זִמָּ֖ה בְּ/תוֹכְ/כֶֽם", "en": {"kjv": "And if a man take a wife and her mother, it is wickedness: they shall be burnt with fire, both he and they; that there be no wickedness among you.", "web": "“‘If a man takes a wife and her mother, it is wickedness: they shall be burned with fire, both he and they; that there may be no wickedness among you.", "bsb": "If a man marries both a woman and her mother, it is depraved. Both he and they must be burned in the fire, so that there will be no depravity among you.", "asv": "And if a man take a wife and her mother, it is wickedness: they shall be burnt with fire, both he and they; that there be no wickedness among you.", "ylt": "`And a man who taketh the woman and her mother--it is wickedness; with fire they burn him and them, and there is no wickedness in your midst.", "tyndale": "Yf a man take a wife ad hir mother thereto, it is wekednesse. Me shall burne with fire both him and them, that there be no wekednesse amonge you.", "dra": "If any man after marrying the daughter, marry her mother, he hath done a heinous crime. He shall be burnt alive with them: neither shall so great an abomination remain in the midst of you.", "bbe": "And if a man takes as wife a woman and her mother, it is an act of shame; let them be burned with fire, all three of them, so that there may be no shame among you.", "geneva": "Likewise he that taketh a wife and her mother, committeth wickednesse: they shall burne him and them with fire, that there be no wickednes among you.", "wycliffe": "He that weddith ouer his wijf hir moder, hath wrouyt greet synne; he schal be brent quyk with hem, and so greet vnleueful doynge schal not dwelle in the myddis of you.", "rotherham": "And, any man, who taketh a woman and her mother, wickedness, it is,—in fire, shall both he and they be consumed, that wickedness be not in your midst.", "darby": "And if a man take a wife and her mother, it is infamy: they shall burn him and them with fire, that there be no infamy among you.", "twenty": "", "jps": "And if a man take with his wife also her mother, it is wickedness: they shall be burnt with fire, both he and they; that there be no wickedness among you.", "acv": "And if a man takes a wife and her mother, it is wickedness. They shall be burnt with fire, both he and they, that there be no wickedness among you.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if a man shall take a wife and her mother, it [is] wickedness: they shall be burnt with fire, both he and they: that there be no wickedness among you.", "vulgate": "qui supra uxorem filiam duxerit matrem eius scelus operatus est vivus ardebit cum eis nec permanebit tantum nefas in medio vestri;", "brenton": "Whosoever shall take a woman and her mother, it is iniquity: they shall burn him and them with fire; so there shall not be iniquity among you."}}, {"v": 15, "ref": "20:15", "o": "וְ/אִ֗ישׁ אֲשֶׁ֨ר יִתֵּ֧ן שְׁכָבְתּ֛/וֹ בִּ/בְהֵמָ֖ה מ֣וֹת יוּמָ֑ת וְ/אֶת הַ/בְּהֵמָ֖ה תַּהֲרֹֽגוּ", "en": {"kjv": "And if a man lie with a beast, he shall surely be put to death: and ye shall slay the beast.", "web": "“‘If a man lies with an animal, he shall surely be put to death; and you shall kill the animal.", "bsb": "If a man lies carnally with an animal, he must be put to death. And you are also to kill the animal.", "asv": "And if a man lie with a beast, he shall surely be put to death: and ye shall slay the beast.", "ylt": "`And a man who giveth his lying with a beast is certainly put to death, and the beast ye do slay.", "tyndale": "Yf a man lye with a beest he shall dye, and ye shall slee the beest.", "dra": "He that shall copulate with any beast or cattle, dying let him die: the beast also ye shall kill.", "bbe": "And if a man has sex relations with a beast, let him be put to death, and let the beast be put to destruction.", "geneva": "Also the man that lyeth with a beast, shall dye the death, and ye shall slay the beast.", "wycliffe": "He that doith letcherie with a greet beeste, ethir a litil beeste die bi deeth, also sle ye the beeste.", "rotherham": "And, any man, who hath carnal knowledge of a beast, shall, surely be put to death,—and, the beast, shall ye slay.", "darby": "And if a man lie with a beast for copulation, he shall certainly be put to death; and ye shall kill the beast.", "twenty": "", "jps": "And if a man lie with a beast, he shall surely be put to death; and ye shall slay the beast.", "acv": "And if a man lies with a beast, he shall surely be put to death, and ye shall kill the beast.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if a man shall lie with a beast, he shall surely be put to death: and ye shall slay the beast.", "vulgate": "qui cum iumento et pecore coierit morte moriatur pecus quoque occidite;", "brenton": "And whosoever shall lie with a beast, let him die the death; and ye shall kill the beast."}}, {"v": 16, "ref": "20:16", "o": "וְ/אִשָּׁ֗ה אֲשֶׁ֨ר תִּקְרַ֤ב אֶל כָּל בְּהֵמָה֙ לְ/רִבְעָ֣ה אֹתָ֔/הּ וְ/הָרַגְתָּ֥ אֶת הָ/אִשָּׁ֖ה וְ/אֶת הַ/בְּהֵמָ֑ה מ֥וֹת יוּמָ֖תוּ דְּמֵי/הֶ֥ם בָּֽ/ם", "en": {"kjv": "And if a woman approach unto any beast, and lie down thereto, thou shalt kill the woman, and the beast: they shall surely be put to death; their blood shall be upon them.", "web": "“‘If a woman approaches any animal, and lies down with it, you shall kill the woman and the animal. They shall surely be put to death. Their blood shall be upon them.", "bsb": "If a woman approaches any animal to mate with it, you must kill both the woman and the animal. They must surely be put to death; their blood is upon them.", "asv": "And if a woman approach unto any beast, and lie down thereto, thou shalt kill the woman, and the beast: they shall surely be put to death; their blood shall be upon them.", "ylt": "`And a woman who draweth near unto any beast to lie with it--thou hast even slain the woman and the beast; they are certainly put to death; their blood is on them.", "tyndale": "Yf a woma go vnto a beest ad lye doune thereto: thou shalt kyll the woma ad the beest also they shal dye, ad their bloud be apo their hedes", "dra": "The woman that shall lie under any beast, shall be killed together with the same. Their blood be upon them.", "bbe": "And if a woman goes near a beast and has sex relations with it, you will put an end to the woman and the beast: their blood will be on them.", "geneva": "And if a woman come to any beast, and lye therewith, then thou shalt kill the woman and the beast: they shall die the death, their blood shalbe vpon them.", "wycliffe": "A womman that liggith vndur ony beeste, be slayn togidere with it; the blood `of hem be on hem.", "rotherham": "And, a woman, who approacheth unto any beast, to couch down thereto, then shalt thou slay the woman and the beast,—they shall surely be put to death,—their blood, shall be upon themselves.", "darby": "And if a woman approach unto any beast to gender therewith, thou shalt kill the woman and the beast: they shall certainly be put to death; their blood is upon them.", "twenty": "", "jps": "And if a woman approach unto any beast, and lie down thereto, thou shalt kill the woman, and the beast: they shall surely be put to death; their blood shall be upon them.", "acv": "And if a woman approaches to any beast, and lies down with it, thou shall kill the woman and the beast. They shall surely be put to death; their blood shall be upon them.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if a woman shall approach to any beast, and lie down thereto, thou shalt kill the woman and the beast; they shall surely be put to death; their blood [shall be] upon them.", "vulgate": "mulier quae subcubuerit cuilibet iumento simul interficietur cum eo sanguis eorum sit super eos;", "brenton": "And whatever woman shall approach any beast, so as to have connexion with it, ye shall kill the woman and the beast: let them die the death, they are guilty."}}, {"v": 17, "ref": "20:17", "o": "וְ/אִ֣ישׁ אֲשֶׁר יִקַּ֣ח אֶת אֲחֹת֡/וֹ בַּת אָבִ֣י/ו א֣וֹ בַת אִ֠מּ/וֹ וְ/רָאָ֨ה אֶת עֶרְוָתָ֜/הּ וְ/הִֽיא תִרְאֶ֤ה אֶת עֶרְוָת/וֹ֙ חֶ֣סֶד ה֔וּא וְ/נִ֨כְרְת֔וּ לְ/עֵינֵ֖י בְּנֵ֣י עַמָּ֑/ם עֶרְוַ֧ת אֲחֹת֛/וֹ גִּלָּ֖ה עֲוֺנ֥/וֹ יִשָּֽׂא", "en": {"kjv": "And if a man shall take his sister, his father’s daughter, or his mother’s daughter, and see her nakedness, and she see his nakedness; it is a wicked thing; and they shall be cut off in the sight of their people: he hath uncovered his sister’s nakedness; he shall bear his iniquity.", "web": "“‘If a man takes his sister, his father’s daughter, or his mother’s daughter, and sees her nakedness, and she sees his nakedness; it is a shameful thing. They shall be cut off in the sight of the children of their people. He has uncovered his sister’s nakedness. He shall bear his iniquity.", "bsb": "If a man marries his sister, whether the daughter of his father or of his mother, and they have sexual relations, it is a disgrace. They must be cut off in the sight of their people. He has uncovered the nakedness of his sister; he shall bear his iniquity.", "asv": "And if a man shall take his sister, his father’s daughter, or his mother’s daughter, and see her nakedness, and she see his nakedness; it is a shameful thing; and they shall be cut off in the sight of the children of their people: he hath uncovered his sister’s nakedness; he shall bear his iniquity.", "ylt": "`And a man who taketh his sister, a daughter of his father or daughter of his mother, and he hath seen her nakedness, and she seeth his nakedness: it is a shame; and they have been cut off before the eyes of the sons of their people; the nakedness of his sister he hath uncovered; his iniquity he beareth.", "tyndale": "Yf a ma take his syster his fathers doughter or his mothers doughter, ad se hir secrettes, and she se his secrettes also: it is a weked thinge. Therfore let them perish in the syghte of their people, he hath sene his systers secretnesse, he shall therfore bere his synne.", "dra": "If any man take his sister, the daughter of his father, or the daughter of his mother, and see her nakedness, and she behold her brother's shame: they have committed a crime. They shall be slain, in the sight of their people, because they have discovered one another's nakedness. And they shall bear their iniquity.", "bbe": "And if a man takes his sister, daughter of his father or his mother, and has sex relations with her and she with him, it is an act of shame: they are to be cut off before the children of their people; he has had sex relations with his sister, and his sin will be on him.", "geneva": "Also the man that taketh his sister, his fathers daughter, or his mothers daughter, and seeth her shame and she seeth his shame, it is villenie: therefore they shall be cut off in the sight of their people, because he hath vncouered his sisters shame, he shall beare his iniquitie.", "wycliffe": "He that takith his sistir `the douytir of his fadir, ether the douyter of his modir, and seeth hir filthe, and sche seeth the schenschip of the brothir, thei han wrouyt an vnleueful thing, bothe schulen be slayn in the siyt of her puple; for thei schewiden togidere her filthe, and thei schulen bere her wickidnesse.", "rotherham": "And, any man, who taketh his sister—his father’s daughter or his mother’s daughter, and vieweth her shame, and, she, vieweth his shame, a disgrace, it is,—they shall therefore be cut off in the sight of the sons of their people,—the shame of his sister, hath he uncovered—his iniquity, shall he bear.", "darby": "And if a man take his sister, his father's daughter, or his mother's daughter, and see her nakedness, and she see his nakedness, that is a disgrace; and they shall be cut off before the eyes of the children of their people: he hath uncovered his sister's nakedness; he shall bear his iniquity.", "twenty": "", "jps": "And if a man shall take his sister, his father's daughter, or his mother's daughter, and see her nakedness, and she see his nakedness: it is a shameful thing; and they shall be cut off in the sight of the children of their people: he hath uncovered his sister's nakedness; he shall bear his iniquity.", "acv": "And if a man shall take his sister, his father's daughter, or his mother's daughter, and see her nakedness, and she sees his nakedness, it is a shameful thing, and they shall be cut off in the sight of the sons of their people. He has uncovered his sister's nakedness; he shall bear his iniquity.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if a man shall take his sister, his father's daughter, or his mother's daughter, and see her nakedness, and she see his nakedness; it [is] a wicked thing; and they shall be cut off in the sight of their people: he hath uncovered his sister's nakedness; he shall bear his iniquity.", "vulgate": "qui acceperit sororem suam filiam patris sui vel filiam matris suae et viderit turpitudinem eius illaque conspexerit fratris ignominiam nefariam rem operati sunt occidentur in conspectu populi sui eo quod turpitudinem suam mutuo revelarint et portabunt iniquitatem suam;", "brenton": "Whosoever shall take his sister by his father or by his mother, and shall see her nakedness, and she see his nakedness, it is a reproach: they shall be destroyed before the children of their family; he has uncovered his sister's nakedness, they shall bear their sin."}}, {"v": 18, "ref": "20:18", "o": "וְ֠/אִישׁ אֲשֶׁר יִשְׁכַּ֨ב אֶת אִשָּׁ֜ה דָּוָ֗ה וְ/גִלָּ֤ה אֶת עֶרְוָתָ/הּ֙ אֶת מְקֹרָ֣/הּ הֶֽעֱרָ֔ה וְ/הִ֕יא גִּלְּתָ֖ה אֶת מְק֣וֹר דָּמֶ֑י/הָ וְ/נִכְרְת֥וּ שְׁנֵי/הֶ֖ם מִ/קֶּ֥רֶב עַמָּֽ/ם", "en": {"kjv": "And if a man shall lie with a woman having her sickness, and shall uncover her nakedness; he hath discovered her fountain, and she hath uncovered the fountain of her blood: and both of them shall be cut off from among their people.", "web": "“‘If a man lies with a woman having her monthly period, and uncovers her nakedness; he has made naked her fountain, and she has uncovered the fountain of her blood. Both of them shall be cut off from among their people.", "bsb": "If a man lies with a menstruating woman and has sexual relations with her, he has exposed the source of her flow, and she has uncovered the source of her blood. Both of them must be cut off from among their people.", "asv": "And if a man shall lie with a woman having her sickness, and shall uncover her nakedness; he hath made naked her fountain, and she hath uncovered the fountain of her blood: and both of them shall be cut off from among their people.", "ylt": "`And a man who lieth with a sick woman, and hath uncovered her nakedness, her fountain he hath made bare, and she hath uncovered the fountain of her blood, --even both of them have been cut off from the midst of their people.", "tyndale": "Yf a man lye with a woman in tyme of hyr naturall disease and unheale hir secrettes and vncouer hir fountayne, ad she also open the fountayne of hir bloude, they shall both perishe from amonge their people.", "dra": "If any man lie with a woman in her flowers, and uncover her nakedness, and she open the fountain of her blood: both shall be destroyed out of the midst of their people.", "bbe": "And if a man has sex relations with a woman at the time when she is unwell, he has seen her fountain and she has let the fountain of her blood be uncovered, and the two of them are to be cut off from among their people.", "geneva": "The man also that lyeth with a woman hauing her disease, and vncouereth her shame, and openeth her fountaine, and she open the foutaine of her blood, they shall bee euen both cut off from among their people.", "wycliffe": "If a man doith fleischly knowyng with a womman in the flux of monethe , and schewith hir filthe, and sche openeth the welle of hir blood, bothe schulen be slayn fro the myddis of her puple.", "rotherham": "And, any man, who lieth with a woman having her sickness, and uncovereth her shame, her fountain, hath he exposed, she, also hath uncovered her fountain of blood,—they shall therefore both be cut off out of the midst of their people.", "darby": "And if a man shall lie with a woman in her infirmity, and uncover her nakedness, her flux doth he lay bare, and she hath uncovered the fountain of her blood; and both of them shall be cut off from among their people.", "twenty": "", "jps": "And if a man shall lie with a woman having her sickness, and shall uncover her nakedness--he hath made naked her fountain, and she hath uncovered the fountain of her blood--both of them shall be cut off from among their people.", "acv": "And if a man shall lie with a woman having her sickness, and shall uncover her nakedness, he has made naked her fountain, and she has uncovered the fountain of her blood. And both of them shall be cut off from among their people.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if a man shall lie with a woman having her sickness, and shall uncover her nakedness; he hath discovered her fountain, and she hath uncovered the fountain of her blood: and both of them shall be cut off from among their people.", "vulgate": "qui coierit cum muliere in fluxu menstruo et revelaverit turpitudinem eius ipsaque aperuerit fontem sanguinis sui interficientur ambo de medio populi sui;", "brenton": "And whatever man shall lie with a woman that is set apart for a flux, and shall uncover her nakedness, he has uncovered her fountain, and she has uncovered the flux of her blood: they shall both be destroyed from among their generation."}}, {"v": 19, "ref": "20:19", "o": "וְ/עֶרְוַ֨ת אֲח֧וֹת אִמְּ/ךָ֛ וַ/אֲח֥וֹת אָבִ֖י/ךָ לֹ֣א תְגַלֵּ֑ה כִּ֧י אֶת שְׁאֵר֛/וֹ הֶעֱרָ֖ה עֲוֺנָ֥/ם יִשָּֽׂאוּ", "en": {"kjv": "And thou shalt not uncover the nakedness of thy mother’s sister, nor of thy father’s sister: for he uncovereth his near kin: they shall bear their iniquity.", "web": "“‘You shall not uncover the nakedness of your mother’s sister, nor of your father’s sister; for he has made his close relative naked. They shall bear their iniquity.", "bsb": "You must not have sexual relations with the sister of your mother or your father, for it is exposing one’s own kin; both shall bear their iniquity.", "asv": "And thou shalt not uncover the nakedness of thy mother’s sister, nor of thy father’s sister; for he hath made naked his near kin: they shall bear their iniquity.", "ylt": "`And the nakedness of thy mother's sister, and of thy father's sister, thou dost not uncover; because his relation he hath made bare; their iniquity they bear.", "tyndale": "Thou shalt not vncouer the secrettes of thy mothers syster nor of thy fathers systers, for he that doth so, vncouereth his nexte kyn: ad thei shall bere their mysdoynge.", "dra": "Thou shalt not uncover the nakedness of thy aunt by thy mother, and of thy aunt by thy father. He that doth this, hath uncovered the shame of his own flesh: both shall bear their iniquity.", "bbe": "And you may not have sex connection with your mother's sister or your father's sister, for they are his near relations: their sin will be on them.", "geneva": "Moreouer thou shalt not vncouer the shame of thy mothers sister, nor of thy fathers sister: because he hath vncouered his kin, they shall beare their iniquitie.", "wycliffe": "Thou schalt not diskyuere the filthe of thi modris sistir, and of thi fadris sistir; he, that doith this, schal `make nakid the schenschip of his fleisch, and bothe schulen bere her wickidnesse.", "rotherham": "And the shame of thy mother’s sister, or of thy father’s sister, shalt thou not uncover,—for his near of kin, hath he exposed—their iniquity, shall they bear.", "darby": "And the nakedness of thy mother's sister, and of thy father's sister shalt thou not uncover; for he hath laid naked his near relation: they shall bear their iniquity.", "twenty": "", "jps": "And thou shalt not uncover the nakedness of thy mother's sister, nor of thy father's sister; for he hath made naked his near kin; they shall bear their iniquity.", "acv": "And thou shall not uncover the nakedness of thy mother's sister, nor of thy father's sister, for he has made naked his near kin. They shall bear their iniquity.", "anderson": "", "haweis": "", "noyes": "", "webster": "And thou shalt not uncover the nakedness of thy mother's sister, nor of thy father's sister: for he uncovereth his near kin: they shall bear their iniquity.", "vulgate": "turpitudinem materterae tuae et amitae tuae non discoperies qui hoc fecerit ignominiam carnis suae nudavit portabunt ambo iniquitatem suam;", "brenton": "And thou shalt not uncover the nakedness of thy father's sister, or of the sister of thy mother; for that man has uncovered the nakedness of one near akin: they shall bear their iniquity."}}, {"v": 20, "ref": "20:20", "o": "וְ/אִ֗ישׁ אֲשֶׁ֤ר יִשְׁכַּב֙ אֶת דֹּ֣דָת֔/וֹ עֶרְוַ֥ת דֹּד֖/וֹ גִּלָּ֑ה חֶטְאָ֥/ם יִשָּׂ֖אוּ עֲרִירִ֥ים יָמֻֽתוּ", "en": {"kjv": "And if a man shall lie with his uncle’s wife, he hath uncovered his uncle’s nakedness: they shall bear their sin; they shall die childless.", "web": "If a man lies with his uncle’s wife, he has uncovered his uncle’s nakedness. They shall bear their sin. They shall die childless.", "bsb": "If a man lies with his uncle’s wife, he has uncovered the nakedness of his uncle. They will bear their sin; they shall die childless.", "asv": "And if a man shall lie with his uncle’s wife, he hath uncovered his uncle’s nakedness: they shall bear their sin; they shall die childless.", "ylt": "`And a man who lieth with his aunt, the nakedness of his uncle he hath uncovered; their sin they bear; childless they die.", "tyndale": "Yf a ma lye with his vncles wife, he hath vncouered his vncles secrettes: they shall bere their synne, and shall dye childlesse.", "dra": "If any man lie with the wife of his uncle by the father, or of his uncle by the mother, and uncover the shame of his near akin, both shall bear their sin. They shall die without children.", "bbe": "And if a man has sex relations with the wife of his father's brother, he has put shame on his father's brother: their sin will be on them; till the day of their death they will have no children.", "geneva": "Likewise the man that lyeth with his fathers brothers wife, and vncouereth his vncles shame: they shall beare their iniquitie, and shall die childlesse.", "wycliffe": "He that doith fleischli knowyng with the wijf of `his fadris brother, ether of his modris brother, and schewith the filthe of his kyn, bothe schulen bere her synne, thei schulen die without fre children .", "rotherham": "And, any man, who lieth with his uncle’s wife, the shame of his uncle, hath he uncovered,—their sin, shall they bear—childless, shall they die.", "darby": "And if a man lie with his aunt, he hath uncovered his uncle's nakedness: their sin shall they bear: they shall die childless.", "twenty": "", "jps": "And if a man shall lie with his uncle's wife--he hath uncovered his uncle's nakedness--they shall bear their sin; they shall die childless.", "acv": "And if a man shall lie with his uncle's wife, he has uncovered his uncle's nakedness. They shall bear their sin; they shall die childless.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if a man shall lie with his uncle's wife, he hath uncovered his uncle's nakedness: they shall bear their sin; they shall die childless.", "vulgate": "qui coierit cum uxore patrui vel avunculi sui et revelaverit ignominiam cognationis suae portabunt ambo peccatum suum absque liberis morientur;", "brenton": "Whosoever shall lie with his near kinswoman, has uncovered the nakedness of one near akin to him: they shall die childless."}}, {"v": 21, "ref": "20:21", "o": "וְ/אִ֗ישׁ אֲשֶׁ֥ר יִקַּ֛ח אֶת אֵ֥שֶׁת אָחִ֖י/ו נִדָּ֣ה הִ֑וא עֶרְוַ֥ת אָחִ֛י/ו גִּלָּ֖ה עֲרִירִ֥ים יִהְיֽוּ", "en": {"kjv": "And if a man shall take his brother’s wife, it is an unclean thing: he hath uncovered his brother’s nakedness; they shall be childless.", "web": "“‘If a man takes his brother’s wife, it is an impurity. He has uncovered his brother’s nakedness. They shall be childless.", "bsb": "If a man marries his brother’s wife, it is an act of impurity. He has uncovered the nakedness of his brother; they shall be childless.", "asv": "And if a man shall take his brother’s wife, it is impurity: he hath uncovered his brother’s nakedness; they shall be childless.", "ylt": "`And a man who taketh his brother's wife--it is impurity; the nakedness of his brother he hath uncovered; childless they are.", "tyndale": "Yf a ma take his brothers wife, it is an vnclene thinge, he hath vncouered his brothers secrettes, they shalbe childlesse therfore.", "dra": "He that marrieth his brother's wife, doth an unlawful thing: he hath uncovered his brother's nakedness. They shall be without children.", "bbe": "And if a man takes his brother's wife, it is an unclean act; he has put shame on his brother; they will have no children.", "geneva": "So the man that taketh his brothers wife, committeth filthines, because he hath vncouered his brothers shame: they shalbe childles.", "wycliffe": "He that weddith `the wijf of his brother, doith an vnleueful thing; he schewide `the filthe of his brother, he schal be without fre children.", "rotherham": "And, any man, who taketh his brother’s wife, impurity, it is,—the shame of his brother, hath he uncovered—childless, shall they remain.", "darby": "And if a man take his brother's wife, it is an unclean thing: he hath uncovered his brother's nakedness: they shall be childless.", "twenty": "", "jps": "And if a man shall take his brother's wife, it is impurity: he hath uncovered his brother's nakedness; they shall be childless.", "acv": "And if a man shall take his brother's wife, it is impurity. He has uncovered his brother's nakedness; they shall be childless.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if a man shall take his brother's wife, it [is] an unclean thing: he hath uncovered his brother's nakedness; they shall be childless.", "vulgate": "qui duxerit uxorem fratris sui rem facit inlicitam turpitudinem fratris sui revelavit absque filiis erunt;", "brenton": "Whoever shall take his brother's wife, it is uncleanness; he has uncovered his brother's nakedness; they shall die childless."}}, {"v": 22, "ref": "20:22", "o": "וּ/שְׁמַרְתֶּ֤ם אֶת כָּל חֻקֹּתַ/י֙ וְ/אֶת כָּל מִשְׁפָּטַ֔/י וַ/עֲשִׂיתֶ֖ם אֹתָ֑/ם וְ/לֹא תָקִ֤יא אֶתְ/כֶם֙ הָ/אָ֔רֶץ אֲשֶׁ֨ר אֲנִ֜י מֵבִ֥יא אֶתְ/כֶ֛ם שָׁ֖מָּ/ה לָ/שֶׁ֥בֶת בָּֽ/הּ", "en": {"kjv": "Ye shall therefore keep all my statutes, and all my judgments, and do them: that the land, whither I bring you to dwell therein, spue you not out.", "web": "“‘You shall therefore keep all my statutes, and all my ordinances, and do them; that the land, where I am bringing you to dwell, may not vomit you out.", "bsb": "You are therefore to keep all My statutes and ordinances, so that the land where I am bringing you to live will not vomit you out.", "asv": "Ye shall therefore keep all my statutes, and all mine ordinances, and do them; that the land, whither I bring you to dwell therein, vomit you not out.", "ylt": "`And ye have kept all My statutes, and all My judgments, and have done them, and the land vomiteth you not out whither I am bringing you in to dwell in it;", "tyndale": "Se that ye kepe therfore all myne ordinaunces and all my iudgementes, and that ye doo them: that the londe whether I brynge you to dwell therein, spewe you not oute.", "dra": "Keep my laws and my judgments, and do them: lest the land into which you are to enter to dwell therein, vomit you also out.", "bbe": "So then, keep my rules and my decisions and do them, so that the land which I am giving you as your resting-place may not violently send you out again.", "geneva": "Ye shall keepe therefore all mine ordinances and all my iudgements, and doe them, that the land, whither I bring you to dwel therein, spue you not out.", "wycliffe": "Kepe ye my lawis and my domes, and do ye tho, lest the lond, in to which ye schulen entre and dwelle, caste out viliche also you.", "rotherham": "Therefore shall ye observe all my statutes and all my regulations, and do them,—So shall the land whereinto I am bringing you to dwell therein, not vomit you forth;", "darby": "And ye shall observe all my statutes, and all mine ordinances, and do them, that the land whither I bring you to dwell therein vomit you not out.", "twenty": "", "jps": "Ye shall therefore keep all My statutes, and all Mine ordinances, and do them, that the land, whither I bring you to dwell therein, vomit you not out.", "acv": "Ye shall therefore keep all my statutes, and all my ordinances, and do them, that the land, where I bring you to dwell in it, not vomit you out.", "anderson": "", "haweis": "", "noyes": "", "webster": "Ye shall therefore keep all my statutes, and all my judgments, and do them: that the land whither I bring you to dwell therein, may not vomit you out.", "vulgate": "custodite leges meas atque iudicia et facite ea ne et vos evomat terra quam intraturi estis et habitaturi;", "brenton": "And keep ye all my ordinances, and my judgments; and ye shall do them, and the land shall not be aggrieved with you, into which I bring you to dwell upon it."}}, {"v": 23, "ref": "20:23", "o": "וְ/לֹ֤א תֵֽלְכוּ֙ בְּ/חֻקֹּ֣ת הַ/גּ֔וֹי אֲשֶׁר אֲנִ֥י מְשַׁלֵּ֖חַ מִ/פְּנֵי/כֶ֑ם כִּ֤י אֶת כָּל אֵ֨לֶּה֙ עָשׂ֔וּ וָ/אָקֻ֖ץ בָּֽ/ם", "en": {"kjv": "And ye shall not walk in the manners of the nation, which I cast out before you: for they committed all these things, and therefore I abhorred them.", "web": "You shall not walk in the customs of the nation, which I am casting out before you: for they did all these things, and therefore I abhorred them.", "bsb": "You must not follow the statutes of the nations I am driving out before you. Because they did all these things, I abhorred them.", "asv": "And ye shall not walk in the customs of the nation, which I cast out before you: for they did all these things, and therefore I abhorred them.", "ylt": "and ye walk not in the statutes of the nation which I am sending away from before you, for all these they have done, and I am wearied with them;", "tyndale": "And se that ye walke not in the maners of the nacyons whiche I cast oute before you: For they commytted all these thinges, and I abhorred them.", "dra": "Walk not after the laws of the nations, which I will cast out before you. For they have done all these things: and therefore I abhorred them.", "bbe": "And do not keep the rules of the nations which I am driving out before you; for they did all these things, and for that reason my soul was turned against them.", "geneva": "Wherefore ye shall not walke in the maners of this nation which I cast out before you: for they haue committed all these things, therefore I abhorred them.", "wycliffe": "Nyle ye go in the lawful thingis of naciouns, whiche Y schal caste out bifor you, for thei diden alle these thingis, and Y hadde abhomynacioun of hem.", "rotherham": "So shall ye not walk in the—statutes of the nations, which I am casting out from before you,—For all these things, had they done, Therefore I abhorred them;", "darby": "And ye shall not walk in the customs of the nation which I am casting out before you; for all these things have they done, and they became an abomination to me.", "twenty": "", "jps": "And ye shall not walk in the customs of the nation, which I am casting out before you; for they did all these things, and therefore I abhorred them.", "acv": "And ye shall not walk in the customs of the nation which I cast out before you, for they did all these things, and therefore I abhorred them.", "anderson": "", "haweis": "", "noyes": "", "webster": "And ye shall not walk in the manners of the nations which I cast out before you: for they committed all these things, and therefore I abhorred them.", "vulgate": "nolite ambulare in legitimis nationum quas ego expulsurus sum ante vos omnia enim haec fecerunt et abominatus sum eos;", "brenton": "And walk ye not in the customs of the nations which I drive out from before you; for they have done all these things, and I have abhorred them:"}}, {"v": 24, "ref": "20:24", "o": "וָ/אֹמַ֣ר לָ/כֶ֗ם אַתֶּם֮ תִּֽירְשׁ֣וּ אֶת אַדְמָתָ/ם֒ וַ/אֲנִ֞י אֶתְּנֶ֤/נָּה לָ/כֶם֙ לָ/רֶ֣שֶׁת אֹתָ֔/הּ אֶ֛רֶץ זָבַ֥ת חָלָ֖ב וּ/דְבָ֑שׁ אֲנִי֙ יְהוָ֣ה אֱלֹֽהֵי/כֶ֔ם אֲשֶׁר הִבְדַּ֥לְתִּי אֶתְ/כֶ֖ם מִן הָֽ/עַמִּֽים", "en": {"kjv": "But I have said unto you, Ye shall inherit their land, and I will give it unto you to possess it, a land that floweth with milk and honey: I am the Lord your God, which have separated you from other people.", "web": "But I have said to you, “You shall inherit their land, and I will give it to you to possess it, a land flowing with milk and honey.” I am Yahweh your God, who has separated you from the peoples.", "bsb": "But I have told you that you will inherit their land, since I will give it to you as an inheritance—a land flowing with milk and honey. I am the LORD your God, who has set you apart from the peoples.", "asv": "But I have said unto you, Ye shall inherit their land, and I will give it unto you to possess it, a land flowing with milk and honey: I am Jehovah your God, who hath separated you from the peoples.", "ylt": "and I say to you, Ye--ye do possess their ground, and I--I give it to you to possess it, a land flowing with milk and honey; I am Jehovah your God, who hath separated you from the peoples.", "tyndale": "But I haue sayde vnto you that ye shall enioye their londe, and that I will geue it vnto you to possesse it: eue a londe that floweth with milke and honye. I am the Lord youre God, whiche haue separated you from other nacions:", "dra": "But to you I say: Possess their land which I will give you for an inheritance, a land flowing with milk and honey. I am the Lord your God, who have separated you from other people.", "bbe": "But I have said to you, You will take their land and I will give it to you for your heritage, a land flowing with milk and honey: I am the Lord your God who have made you separate from all other peoples.", "geneva": "But I haue saide vnto you, ye shall inherite their land, and I will giue it vnto you to possesse it, euen a land that floweth with milke and honie: I am the Lord your God, which haue separated you from other people.", "wycliffe": "Forsothe Y speke to you, Welde ye `the lond of hem, which Y schal yyue to you in to eritage, the lond flowynge with mylk and hony; Y am youre Lord God, that departide you fro othere puplis.", "rotherham": "And said unto you—Ye, shall possess their soil, Yea, I myself, will give it you to possess it, A land flowing with milk and honey,—I—Yahweh, am your God, who have distinguished you from the peoples;", "darby": "And I have said unto you, Ye shall possess their land, and I will give it unto you for a possession; a land flowing with milk and honey: I am Jehovah yourGod, who have separated you from the peoples.", "twenty": "", "jps": "But I have said unto you: 'Ye shall inherit their land, and I will give it unto you to possess it, a land flowing with milk and honey.' I am HaShem your G-d, who have set you apart from the peoples.", "acv": "But I have said to you, Ye shall inherit their land, and I will give it to you to possess it, a land flowing with milk and honey. I am Jehovah your God, who has separated you from the peoples.", "anderson": "", "haweis": "", "noyes": "", "webster": "But I have said to you, Ye shall inherit their land, and I will give it to you to possess it, a land that floweth with milk and honey: I [am] the LORD your God, who have separated you from [other] people.", "vulgate": "vobis autem loquor possidete terram eorum quam dabo vobis in hereditatem terram fluentem lacte et melle ego Dominus Deus vester qui separavi vos a ceteris populis;", "brenton": "and I said to you, Ye shall inherit their land, and I will give it to you for a possession, even a land flowing with milk and honey: I am the Lord your God, who have separated you from all people."}}, {"v": 25, "ref": "20:25", "o": "וְ/הִבְדַּלְתֶּ֞ם בֵּֽין הַ/בְּהֵמָ֤ה הַ/טְּהֹרָה֙ לַ/טְּמֵאָ֔ה וּ/בֵין הָ/ע֥וֹף הַ/טָּמֵ֖א לַ/טָּהֹ֑ר וְ/לֹֽא תְשַׁקְּצ֨וּ אֶת נַפְשֹֽׁתֵי/כֶ֜ם בַּ/בְּהֵמָ֣ה וּ/בָ/ע֗וֹף וּ/בְ/כֹל֙ אֲשֶׁ֣ר תִּרְמֹ֣שׂ הָֽ/אֲדָמָ֔ה אֲשֶׁר הִבְדַּ֥לְתִּי לָ/כֶ֖ם לְ/טַמֵּֽא", "en": {"kjv": "Ye shall therefore put difference between clean beasts and unclean, and between unclean fowls and clean: and ye shall not make your souls abominable by beast, or by fowl, or by any manner of living thing that creepeth on the ground, which I have separated from you as unclean.", "web": "“‘You shall therefore make a distinction between the clean animal and the unclean, and between the unclean fowl and the clean: and you shall not make yourselves abominable by animal, or by bird, or by anything with which the ground teems, which I have separated from you as unclean for you.", "bsb": "You are therefore to distinguish between clean and unclean animals and birds. Do not become contaminated by any animal or bird, or by anything that crawls on the ground; I have set these apart as unclean for you.", "asv": "Ye shall therefore make a distinction between the clean beast and the unclean, and between the unclean fowl and the clean: and ye shall not make your souls abominable by beast, or by bird, or by anything wherewith the ground teemeth, which I have separated from you as unclean.", "ylt": "`And ye have made separation between the pure beasts and the unclean, and between the unclean fowl and the pure, and ye do not make yourselves abominable by beast or by fowl, or by anything which creepeth on the ground which I have separated to you for unclean;", "tyndale": "that ye shulde put difference betwene cleane beestes add vncleane, and betwene vncleane foules and them that are cleane. Make not youre soules therfore abhominable with beestes ad foules, and with all maner thinge that crepeth apon the grounde, which I haue separated vnto you to holde them vncleane.", "dra": "Therefore do you also separate the clean beast from the unclean, and the clean fowl from the unclean. Defile not your souls with beasts, or birds, or any things that move on the earth, and which I have shewn you to be unclean:", "bbe": "So then, make division between the clean beast and the unclean, and between the clean bird and the unclean: do not make yourselves disgusting by any beast or bird or anything which goes flat on the earth, which has been marked by me as unclean for you.", "geneva": "Therefore shall ye put difference betweene cleane beastes and vncleane, and betweene vncleane foules and cleane: neither shall ye defile your selues with beastes and foules, nor with any creeping thing, that ye ground bringeth forth, which I haue separated from you as vncleane.", "wycliffe": "Therfor also ye departe a cleene beeste fro vnclene, and a cleene brid fro vncleene, lest ye defoule youre soulis in a beeste, and in briddis, and in alle thingis that ben moued in erthe, and whiche thingis Y schewide to you to be defoulid.", "rotherham": "Therefore shall ye make a distinction—Between the clean beasts, and the unclean,—And between the unclean birds and the clean,—So shall ye not make your persons abominable with beast, or with bird or with anything which creepeth upon the ground, which I have distinguished for you, as unclean.", "darby": "And ye shall make a separation between the clean beast and the unclean, and between the unclean fowl and the clean, and ye shall not make yourselves an abomination by beast, or by fowl, or by anything that creepeth on the ground which I have separated for you, declaring [it] as unclean.", "twenty": "", "jps": "Ye shall therefore separate between the clean beast and the unclean, and between the unclean fowl and the clean; and ye shall not make your souls detestable by beast, or by fowl, or by any thing wherewith the ground teemeth, which I have set apart for you to hold unclean.", "acv": "Ye shall therefore make a distinction between the clean beast and the unclean, and between the unclean fowl and the clean. And ye shall not make your souls abominable by beast, or by bird, or by anything with which the ground teems, which I have separated from you as unclean.", "anderson": "", "haweis": "", "noyes": "", "webster": "Ye shall therefore distinguish between clean beasts and unclean, and between unclean fowls and clean: and ye shall not make your souls abominable by beast or by fowl, or by any manner of living animal that creepeth on the ground, which I have separated from you as unclean.", "vulgate": "separate ergo et vos iumentum mundum ab inmundo et avem mundam ab inmunda ne polluatis animas vestras in pecore et in avibus et cunctis quae moventur in terra et quae vobis ostendi esse polluta;", "brenton": "And ye shall make a distinction between the clean and the unclean cattle, and between clean and unclean birds; and ye shall not defile your souls with cattle, or with birds, or with any creeping things of the earth, which I have separated for you by reason of uncleanness."}}, {"v": 26, "ref": "20:26", "o": "וִ/הְיִ֤יתֶם לִ/י֙ קְדֹשִׁ֔ים כִּ֥י קָד֖וֹשׁ אֲנִ֣י יְהוָ֑ה וָ/אַבְדִּ֥ל אֶתְ/כֶ֛ם מִן הָֽ/עַמִּ֖ים לִ/הְי֥וֹת לִֽ/י", "en": {"kjv": "And ye shall be holy unto me: for I the Lord am holy, and have severed you from other people, that ye should be mine.", "web": "You shall be holy to me; for I, Yahweh, am holy, and have set you apart from the peoples, that you should be mine.", "bsb": "You are to be holy to Me because I, the LORD, am holy, and I have set you apart from the nations to be My own.", "asv": "And ye shall be holy unto me: for I, Jehovah, am holy, and have set you apart from the peoples, that ye should be mine.", "ylt": "and ye have been holy to Me; for holy am I, Jehovah; and I separate you from the peoples to become Mine.", "tyndale": "Be holy vnto me, for I the Lorde am holy and haue seuered you from other nacyons: that ye shulde be myne.", "dra": "You shall be holy unto me, because I the Lord am holy: and I have separated you from other people, that you should be mine.", "bbe": "And you are to be holy to me; for I the Lord am holy and have made you separate from the nations, so that you may be my people.", "geneva": "Therefore shall ye be holie vnto me: for I the Lord am holy, and I haue separated you from other people, that ye shoulde be mine.", "wycliffe": "Ye schulen be hooli to me, for `Y am the hooli Lord, and Y departide you fro othere puplis, that ye schulen be myne.", "rotherham": "Therefore shall ye be unto me, holy persons, for, holy, am, I—Yahweh,—Therefore have I distinguished you from the peoples, that ye may be mine.", "darby": "And ye shall be holy unto me; for I Jehovah am holy, and have separated you from the peoples to be mine.", "twenty": "", "jps": "And ye shall be holy unto Me; for I HaShem am holy, and have set you apart from the peoples, that ye should be Mine.", "acv": "And ye shall be holy to me, for I, Jehovah, am holy, and have set you apart from the peoples, that ye should be mine.", "anderson": "", "haweis": "", "noyes": "", "webster": "And ye shall be holy to me: for I the LORD [am] holy, and have severed you from [other] people, that ye should be mine.", "vulgate": "eritis sancti mihi quia sanctus ego sum Dominus et separavi vos a ceteris populis ut essetis mei;", "brenton": "And ye shall be holy to me; because I the Lord your God am holy, who separated you from all nations, to be mine."}}, {"v": 27, "ref": "20:27", "o": "וְ/אִ֣ישׁ אֽוֹ אִשָּׁ֗ה כִּֽי יִהְיֶ֨ה בָ/הֶ֥ם א֛וֹב א֥וֹ יִדְּעֹנִ֖י מ֣וֹת יוּמָ֑תוּ בָּ/אֶ֛בֶן יִרְגְּמ֥וּ אֹתָ֖/ם דְּמֵי/הֶ֥ם בָּֽ/ם", "en": {"kjv": "A man also or woman that hath a familiar spirit, or that is a wizard, shall surely be put to death: they shall stone them with stones: their blood shall be upon them.", "web": "“‘A man or a woman that is a medium, or is a wizard, shall surely be put to death: they shall stone them with stones. Their blood shall be upon them.’”", "bsb": "A man or a woman who is a medium or spiritist must surely be put to death. They shall be stoned; their blood is upon them.’”", "asv": "A man also or a woman that hath a familiar spirit, or that is a wizard, shall surely be put to death: they shall stone them with stones; their blood shall be upon them.", "ylt": "`And a man or woman--when there is in them a familiar spirit, or who are wizards--are certainly put to death; with stones they stone them; their blood is on them.'", "tyndale": "Yf there be ma or woma that worketh with a sprite or a maker of dysemall dayes, thei shall dye for it. Me shall stone them with stones, ad their bloude shalbe apon them.", "dra": "A man, or woman, in whom there is a pythonical or divining spirit, dying let them die. They shall stone them. Their blood be upon them.", "bbe": "Any man or woman who makes use of spirits, or who is a wonder-worker, is to be put to death: they are to be stoned with stones: their blood will be on them.", "geneva": "And if a man or woman haue a spirite of diuination, or soothsaying in them, they shall die the death: they shall stone them to death, their blood shalbe vpon them.", "wycliffe": "A man ethir a womman, in which is an vncleene spirit spekynge in the `wombe, ethir `a spirit of fals dyuynyng , die thei bi deeth; men schulen oppresse hem bi stoonus; her blood be on hem.", "rotherham": "And as touching man or woman, when there shall be in them a familiar spirit, or the spirit of an oracle, they shall, surely be put to death,—with stones, shall they be stoned—their blood, shall be upon themselves.", "darby": "And if there be a man or a woman in whom is a spirit of Python or of divination, they shall certainly be put to death: they shall stone them with stones; their blood is upon them.", "twenty": "", "jps": "A man also or a woman that divineth by a ghost or a familiar spirit, shall surely be put to death; they shall stone them with stones; their blood shall be upon them.", "acv": "A man or also a woman who has a familiar spirit, or that is a wizard, shall surely be put to death. They shall stone them with stones; their blood shall be upon them.", "anderson": "", "haweis": "", "noyes": "", "webster": "A man also or a woman that hath a familiar spirit, or that is a wizard, shall surely be put to death: they shall stone them with stones: their blood [shall be] upon them.", "vulgate": "vir sive mulier in quibus pythonicus vel divinationis fuerit spiritus morte moriantur lapidibus obruent eos sanguis eorum sit super illos;", "brenton": "And as for a man or woman whosoever of them shall have in them a divining spirit, or be an enchanter, let them both die the death: ye shall stone them with stones, they are guilty."}}]}, {"c": 21, "verses": [{"v": 1, "ref": "21:1", "o": "וַ/יֹּ֤אמֶר יְהוָה֙ אֶל מֹשֶׁ֔ה אֱמֹ֥ר אֶל הַ/כֹּהֲנִ֖ים בְּנֵ֣י אַהֲרֹ֑ן וְ/אָמַרְתָּ֣ אֲלֵ/הֶ֔ם לְ/נֶ֥פֶשׁ לֹֽא יִטַּמָּ֖א בְּ/עַמָּֽי/ו", "en": {"kjv": "And the Lord said unto Moses, Speak unto the priests the sons of Aaron, and say unto them, There shall none be defiled for the dead among his people:", "web": "Yahweh said to Moses, “Speak to the priests, the sons of Aaron, and say to them, ‘A priest shall not defile himself for the dead among his people;", "bsb": "Then the LORD said to Moses, “Speak to Aaron’s sons, the priests, and tell them that a priest is not to defile himself for a dead person among his people,", "asv": "And Jehovah said unto Moses, Speak unto the priests, the sons of Aaron, and say unto them, There shall none defile himself for the dead among his people;", "ylt": "And Jehovah saith unto Moses, `Speak unto the priests, sons of Aaron, and thou hast said unto them, For any person a priest is not defiled among his people,", "tyndale": "And the Lorde sayde vnto Moses: speake vnto the preastes the sonnes of Aaron and saye vnto them. A preast shall defile him selfe at the deth of none of his people,", "dra": "The Lord said also to Moses: Speak to the priests the sons of Aaron, and thou shalt say for them: Let not a priest incur an uncleanness at the death of his citizens.", "bbe": "And the Lord said to Moses, Say to the priests, the sons of Aaron, Let no man make himself unclean for the dead among his people;", "geneva": "And the Lord said vnto Moses, Speake vnto the Priestes the sonnes of Aaron, and say vnto them, Let none be defiled by the dead among his people,", "wycliffe": "And the Lord seide to Moyses, Speke thou to preestis, the sones of Aaron, and thou schalt seie to hem, A preest be not defoulid in the deed men of hise citeseyns,", "rotherham": "And Yahweh said unto Moses, Say unto the priests, the sons of Aaron,—yea thou shalt say unto them, For a dead person, shall no one make himself unclean among his people:", "darby": "And Jehovah said to Moses, Speak unto the priests, the sons of Aaron, and say unto them, There shall none make himself unclean for a dead person among his peoples,", "twenty": "", "jps": "And HaShem said unto Moses: Speak unto the priests the sons of Aaron, and say unto them: There shall none defile himself for the dead among his people;", "acv": "And Jehovah said to Moses, Speak to the priests, the sons of Aaron, and say to them, There shall none defile himself for the dead among his people,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD said to Moses, Speak to the priests, the sons of Aaron, and say to them, There shall none be defiled for the dead among his people:", "vulgate": "dixit quoque Dominus ad Mosen loquere ad sacerdotes filios Aaron et dices eis ne contaminetur sacerdos in mortibus civium suorum;", "brenton": "And the Lord spoke to Moses, saying, Speak to the priests the sons of Aaron, and thou shalt tell them that they shall not defile themselves in their nation for the dead,"}}, {"v": 2, "ref": "21:2", "o": "כִּ֚י אִם לִ/שְׁאֵר֔/וֹ הַ/קָּרֹ֖ב אֵלָ֑י/ו לְ/אִמּ֣/וֹ וּ/לְ/אָבִ֔י/ו וְ/לִ/בְנ֥/וֹ וּ/לְ/בִתּ֖/וֹ וּ/לְ/אָחִֽי/ו", "en": {"kjv": "But for his kin, that is near unto him, that is, for his mother, and for his father, and for his son, and for his daughter, and for his brother,", "web": "except for his relatives that are near to him: for his mother, for his father, for his son, for his daughter, for his brother,", "bsb": "except for his immediate family—his mother, father, son, daughter, or brother,", "asv": "except for his kin, that is near unto him, for his mother, and for his father, and for his son, and for his daughter, and for his brother,", "ylt": "except for his relation who is near unto him--for his mother, and for his father, and for his son, and for his daughter, and for his brother.", "tyndale": "but apon his kyn that is nye vnto him: as his mother, father, sonne, doughter and brother:", "dra": "But only for his kin, such as are near in blood: that is to say, for his father and for his mother, and for his son, and for his daughter, for his brother also:", "bbe": "But only for his near relations, for his mother or his father, his son or his daughter, and his brother;", "geneva": "But by his kinseman that is neere vnto him: to wit, by his mother, or by his father, or by his sonne, or by his daughter, or by his brother,", "wycliffe": "no but oneli in kynesmen and niy of blood, that is, on fadir and modir, and sone and douyter,", "rotherham": "Saving for his kin, that are near unto him, for his mother or for his father, or for his son or for his daughter, or for his brother;", "darby": "except for his immediate relation, who is near unto him — for his mother, and for his father, and for his son, and for his daughter, and for his brother;", "twenty": "", "jps": "except for his kin, that is near unto him, for his mother, and for his father, and for his son, and for his daughter, and for his brother;", "acv": "except for his kin, who is near to him: for his mother, and for his father, and for his son, and for his daughter, and for his brother.", "anderson": "", "haweis": "", "noyes": "", "webster": "But for his kin, that is near to him, [that is], for his mother, and for his father, and for his son, and for his daughter, and for his brother,", "vulgate": "nisi tantum in consanguineis ac propinquis id est super matre et patre et filio ac filia fratre quoque;", "brenton": "but they may mourn for a relative who is very near to them, for a father and mother, and sons and daughters, for a brother,"}}, {"v": 3, "ref": "21:3", "o": "וְ/לַ/אֲחֹת֤/וֹ הַ/בְּתוּלָה֙ הַ/קְּרוֹבָ֣ה אֵלָ֔י/ו אֲשֶׁ֥ר לֹֽא הָיְתָ֖ה לְ/אִ֑ישׁ לָ֖/הּ יִטַּמָּֽא", "en": {"kjv": "And for his sister a virgin, that is nigh unto him, which hath had no husband; for her may he be defiled.", "web": "and for his virgin sister who is near to him, who has had no husband; for her he may defile himself.", "bsb": "or his unmarried sister who is near to him, since she has no husband.", "asv": "and for his sister a virgin, that is near unto him, that hath had no husband; for her may he defile himself.", "ylt": "and for his sister, the virgin, who is near unto him, who hath not been to a man; for her he is defiled.", "tyndale": "and on his syster as loge as she is a mayde ad dwelleth nye him and was neuer geuen to man: on her he maye defile him selfe.", "dra": "And for a maiden sister, who hath had no husband.", "bbe": "And for his sister, a virgin, for she is his near relation and has had no husband, he may make himself unclean.", "geneva": "Or by his sister a maid, that is neere vnto him, which hath not had a husband: for her he may lament.", "wycliffe": "and brother and sister, virgyn, which is not weddid to man;", "rotherham": "or for his sister, a virgin who is near unto him, who belongeth not unto a husband,—for her, he may make himself unclean:", "darby": "and for his sister, a virgin, that is near unto him, who hath had no husband, for her may he make himself unclean.", "twenty": "", "jps": "and for his sister a virgin, that is near unto him, that hath had no husband, for her may he defile himself.", "acv": "And for his sister a virgin, who is near to him, who has had no husband, for her he may defile himself.", "anderson": "", "haweis": "", "noyes": "", "webster": "And for his sister a virgin, that is nigh to him, who hath had no husband: for her he may be defiled.", "vulgate": "et sorore virgine quae non est nupta viro;", "brenton": "and for a virgin sister that is near to one, that is not espoused to a man; for these one shall defile himself."}}, {"v": 4, "ref": "21:4", "o": "לֹ֥א יִטַּמָּ֖א בַּ֣עַל בְּ/עַמָּ֑י/ו לְ/הֵ֖חַלּֽ/וֹ", "en": {"kjv": "But he shall not defile himself, being a chief man among his people, to profane himself.", "web": "He shall not defile himself, being a chief man among his people, to profane himself.", "bsb": "He is not to defile himself for those related to him by marriage, and so profane himself.", "asv": "He shall not defile himself, being a chief man among his people, to profane himself.", "ylt": "`A master priest doth not defile himself among his people--to pollute himself;", "tyndale": "But he shall not make him selfe vncleane vpon a ruelar of his people to polute him selfe with all.", "dra": "But not even for the prince of his people shall he do any thing that may make him unclean.", "bbe": "But let him, being a chief among his people, not make himself unclean in such a way as to put shame on himself.", "geneva": "He shall not lament for the Prince among his people, to pollute him selfe.", "wycliffe": "but nether he schal be defoulid in the prince of his puple.", "rotherham": "He shall not make himself unclean being a chief among his people,—by profaning himself:", "darby": "He shall not make himself unclean [who is] a chief among his peoples, to profane himself.", "twenty": "", "jps": "He shall not defile himself, being a chief man among his people, to profane himself.", "acv": "He shall not defile himself, who is a chief man among his people, to profane himself.", "anderson": "", "haweis": "", "noyes": "", "webster": "[But] he shall not defile himself, [being] a chief man among his people, to profane himself.", "vulgate": "sed nec in principe populi sui contaminabitur;", "brenton": "He shall not defile himself suddenly among his people to profane himself."}}, {"v": 5, "ref": "21:5", "o": "לֹֽא יקרחה יִקְרְח֤וּ קָרְחָה֙ בְּ/רֹאשָׁ֔/ם וּ/פְאַ֥ת זְקָנָ֖/ם לֹ֣א יְגַלֵּ֑חוּ וּ/בִ֨/בְשָׂרָ֔/ם לֹ֥א יִשְׂרְט֖וּ שָׂרָֽטֶת", "en": {"kjv": "They shall not make baldness upon their head, neither shall they shave off the corner of their beard, nor make any cuttings in their flesh.", "web": "“‘They shall not shave their heads, neither shall they shave off the corners of their beards, nor make any cuttings in their flesh.", "bsb": "Priests must not make bald spots on their heads, shave off the edges of their beards, or make cuts in their bodies.", "asv": "They shall not make baldness upon their head, neither shall they shave off the corner of their beard, nor make any cuttings in their flesh.", "ylt": "they do not make baldness on their head, and the corner of their beard they do not shave, and in their flesh they do not make a cutting;", "tyndale": "They shall make the no baldnesse apon their heedes or shaue off the lockes of their beerdes, nor make any markes in their flesh.", "dra": "Neither shall they shave their head, nor their beard, nor make incisions in their flesh.", "bbe": "They are not to have their hair cut off for the dead, or the hair on their chins cut short, or make cuts in their flesh.", "geneva": "They shall not make balde partes vpon their head, nor shaue off the locks of their beard, nor make any cuttings in their flesh.", "wycliffe": "Preestis schulen not schaue the heed, nether beerd, nether thei schulen make keruyngis in her fleischis; thei schulen be hooli to her God,", "rotherham": "They shall not make a baldness behind in their head, And the border of their beard, shall they not cut off,—And, in their flesh, shall they not make incisions.", "darby": "They shall not make any baldness upon their head, neither shall they shave off the corners of their beard, nor make any cuttings in their flesh.", "twenty": "", "jps": "They shall not make baldness upon their head, neither shall they shave off the corners of their beard, nor make any cuttings in their flesh.", "acv": "They shall not make baldness upon their head, neither shall they shave off the corner of their beard, nor make any cuttings in their flesh.", "anderson": "", "haweis": "", "noyes": "", "webster": "They shall not make baldness upon their head, neither shall they shave off the corner of their beard, nor make any cuttings in their flesh.", "vulgate": "non radent caput nec barbam neque in carnibus suis facient incisuras;", "brenton": "And ye shall not shave your head for the dead with a baldness on the top; and they shall not shave their beard, neither shall they make gashes on their flesh."}}, {"v": 6, "ref": "21:6", "o": "קְדֹשִׁ֤ים יִהְיוּ֙ לֵ/אלֹ֣הֵי/הֶ֔ם וְ/לֹ֣א יְחַלְּל֔וּ שֵׁ֖ם אֱלֹהֵי/הֶ֑ם כִּי֩ אֶת אִשֵּׁ֨י יְהוָ֜ה לֶ֧חֶם אֱלֹהֵי/הֶ֛ם הֵ֥ם מַקְרִיבִ֖ם וְ/הָ֥יוּ קֹֽדֶשׁ", "en": {"kjv": "They shall be holy unto their God, and not profane the name of their God: for the offerings of the Lord made by fire, and the bread of their God, they do offer: therefore they shall be holy.", "web": "They shall be holy to their God, and not profane the name of their God; for they offer the offerings of Yahweh made by fire, the bread of their God; therefore they shall be holy.", "bsb": "They must be holy to their God and not profane the name of their God. Because they present to the LORD the offerings made by fire, the food of their God, they must be holy.", "asv": "They shall be holy unto their God, and not profane the name of their God; for the offerings of Jehovah made by fire, the bread of their God, they do offer: therefore they shall be holy.", "ylt": "they are holy to their God, and they pollute not the name of their God, for the fire-offerings of Jehovah, bread of their God, they are bringing near, and have been holy.", "tyndale": "Thei shalbe holy vnto their God, ad not polute the name of their god, for the sacrifices of the Lorde ad the bred of their God thei do offer: therfore they must be holy.", "dra": "They shall be holy to their God, and shall not profane his name. For they offer the burnt offering of the Lord, and the bread of their God: and therefore they shall be holy.", "bbe": "Let them be holy to their God and not make the name of their God common; for the fire offerings of the Lord and the bread of their God are offered by them, and they are to be holy.", "geneva": "They shalbe holy vnto their God, and not pollute the name of their God: for the sacrifices of the Lord made by fire, and the bread of their God they doe offer: therefore they shalbe holie.", "wycliffe": "and thei schulen not defoule his name; for thei offren encense of the Lord, and the looues of her God, and therfore thei schulen be hooli.", "rotherham": "Holy persons, shall they be unto their God, and not profane the name of their God,—for, the altar-flames of Yahweh, the food of their God, do they bring near—Therefore shall they be holy.", "darby": "They shall be holy unto theirGod, and not profane the name of theirGod; for they present Jehovah's offerings by fire, the bread of theirGod; therefore shall they be holy.", "twenty": "", "jps": "They shall be holy unto their G-d, and not profane the name of their G-d; for the offerings of HaShem made by fire, the bread of their G-d, they do offer; therefore they shall be holy.", "acv": "They shall be holy to their God, and not profane the name of their God. For they offer the offerings of Jehovah made by fire, the bread of their God. Therefore they shall be holy.", "anderson": "", "haweis": "", "noyes": "", "webster": "They shall be holy to their God, and not profane the name of their God: for the offerings of the LORD made by fire, [and] the bread of their God they do offer: therefore they shall be holy.", "vulgate": "sancti erunt Deo suo et non polluent nomen eius incensum enim Domini et panes Dei sui offerunt et ideo sancti erunt;", "brenton": "They shall be holy to their God, and they shall not profane the name of their God; for they offer the sacrifices of the Lord as the gifts of their God, and they shall be holy."}}, {"v": 7, "ref": "21:7", "o": "אִשָּׁ֨ה זֹנָ֤ה וַ/חֲלָלָה֙ לֹ֣א יִקָּ֔חוּ וְ/אִשָּׁ֛ה גְּרוּשָׁ֥ה מֵ/אִישָׁ֖/הּ לֹ֣א יִקָּ֑חוּ כִּֽי קָדֹ֥שׁ ה֖וּא לֵ/אלֹהָֽי/ו", "en": {"kjv": "They shall not take a wife that is a whore, or profane; neither shall they take a woman put away from her husband: for he is holy unto his God.", "web": "“‘They shall not marry a woman who is a prostitute, or profane; neither shall they marry a woman divorced from her husband; for he is holy to his God.", "bsb": "A priest must not marry a woman defiled by prostitution or divorced by her husband, for the priest is holy to his God.", "asv": "They shall not take a woman that is a harlot, or profane; neither shall they take a woman put away from her husband: for he is holy unto his God.", "ylt": "`A woman, a harlot, or polluted, they do not take, and a woman cast out from her husband they do not take, for he is holy to his God;", "tyndale": "Thei shall take no wife that is an whoore, or poluted, or put fro hir husbonde: for a preast is holy vnto his God.", "dra": "They shall not take to wife a harlot or a vile prostitute, nor one that has been put away from her husband: because they are consecrated to their God,", "bbe": "They may not take as wife a loose or common woman, or one who has been put away by her husband: for the priest is holy to his God.", "geneva": "They shall not take to wife an whore, or one polluted, neither shall they marrie a woman diuorced from her husband: for such one is holy vnto his God.", "wycliffe": "A preest schal not wedde a wijf a corrupt womman, and a `foul hoore, nether he schal wedde `hir that is forsakun of the hosebonde, for he is halewid to his God,", "rotherham": "A woman that is unchaste or dishonoured, shall they not take, And a woman divorced from her husband, shall they not take,—For holy, he is unto his God.", "darby": "They shall not take as wife a whore, or a dishonoured woman; neither shall they take a woman put away from her husband; for he is holy unto hisGod.", "twenty": "", "jps": "They shall not take a woman that is a harlot, or profaned; neither shall they take a woman put away from her husband; for he is holy unto his G-d.", "acv": "They shall not take a woman who is a harlot, or profane, neither shall they take a woman put away from her husband, for he is holy to his God.", "anderson": "", "haweis": "", "noyes": "", "webster": "They shall not take a wife [that is] a lewd woman, or profane; neither shall they take a woman put away from her husband: for he [is] holy to his God.", "vulgate": "scortum et vile prostibulum non ducet uxorem nec eam quae repudiata est a marito quia consecratus est Deo suo;", "brenton": "They shall not take a woman who is a harlot and profaned, or a woman put away from her husband; for he is holy to the Lord his God."}}, {"v": 8, "ref": "21:8", "o": "וְ/קִדַּשְׁתּ֔/וֹ כִּֽי אֶת לֶ֥חֶם אֱלֹהֶ֖י/ךָ ה֣וּא מַקְרִ֑יב קָדֹשׁ֙ יִֽהְיֶה לָּ֔/ךְ כִּ֣י קָד֔וֹשׁ אֲנִ֥י יְהוָ֖ה מְקַדִּשְׁ/כֶֽם", "en": {"kjv": "Thou shalt sanctify him therefore; for he offereth the bread of thy God: he shall be holy unto thee: for I the Lord, which sanctify you, am holy.", "web": "You shall sanctify him therefore; for he offers the bread of your God. He shall be holy to you; for I Yahweh, who sanctify you, am holy.", "bsb": "You are to regard him as holy, since he presents the food of your God. He shall be holy to you, because I the LORD am holy—I who set you apart.", "asv": "Thou shalt sanctify him therefore; for he offereth the bread of thy God: he shall be holy unto thee; for I Jehovah, who sanctify you, am holy.", "ylt": "and thou hast sanctified him, for the bread of thy God he is bringing near; he is holy to thee; for holy am I, Jehovah, sanctifying you.", "tyndale": "Sanctifie him therfore, for he offereth vp the bred of God: he shal therfore be holy vnto the, for I the Lorde whiche sanctifie you, am holy.", "dra": "And offer the loaves of proposition. Let them therefore be holy because I also am holy: the Lord, who sanctify them.", "bbe": "And he is to be holy in your eyes, for by him the bread of your God is offered; he is to be holy in your eyes, for I the Lord, who make you holy, am holy.", "geneva": "Thou shalt sanctifie him therefore, for he offereth the bread of thy God: he shall be holy vnto thee: for I the Lord, which sanctifie you, am holy.", "wycliffe": "and offrith the looues of settyng forth; therfor be he hooly, for `Y am the hooli Lord that halewith you.", "rotherham": "Therefore shalt thou hold him as holy, for the food of thy God, doth he bring near,—Holy, shall he be to thee, For, holy, am I—Yahweh, who am making you holy.", "darby": "And thou shalt hallow him; for the bread of thyGod doth he present: he shall be holy unto thee; for I, Jehovah, who hallow you am holy.", "twenty": "", "jps": "Thou shalt sanctify him therefore; for he offereth the bread of thy G-d; he shall be holy unto thee; for I HaShem, who sanctify you, am holy.", "acv": "Thou shall sanctify him therefore, for he offers the bread of thy God. He shall be holy to thee, for I Jehovah, who sanctify you, am holy.", "anderson": "", "haweis": "", "noyes": "", "webster": "Thou shalt sanctify him therefore, for he offereth the bread of thy God: he shall be holy to thee: for I the LORD, who sanctify you, [am] holy.", "vulgate": "et panes propositionis offert sit ergo sanctus quia et ego sanctus sum Dominus qui sanctifico vos;", "brenton": "And thou shalt hallow him; he offers the gifts of the Lord your God: he shall be holy, for I the Lord that sanctify them am holy."}}, {"v": 9, "ref": "21:9", "o": "וּ/בַת֙ אִ֣ישׁ כֹּהֵ֔ן כִּ֥י תֵחֵ֖ל לִ/זְנ֑וֹת אֶת אָבִ֨י/הָ֙ הִ֣יא מְחַלֶּ֔לֶת בָּ/אֵ֖שׁ תִּשָּׂרֵֽף", "en": {"kjv": "And the daughter of any priest, if she profane herself by playing the whore, she profaneth her father: she shall be burnt with fire.", "web": "“‘The daughter of any priest, if she profanes herself by playing the prostitute, she profanes her father. She shall be burned with fire.", "bsb": "If a priest’s daughter defiles herself by prostituting herself, she profanes her father; she must be burned in the fire.", "asv": "And the daughter of any priest, if she profane herself by playing the harlot, she profaneth her father: she shall be burnt with fire.", "ylt": "`And a daughter of any priest when she polluteth herself by going a-whoring--her father she is polluting; with fire she is burnt.", "tyndale": "Yf a preastes doughter fall to playe the whore, she poluteth hir father: therfore she shall be burnt with fire.", "dra": "If the daughter of a priest be taken in whoredom and dishonour the name of her father, she shall be burnt with fire.", "bbe": "And if the daughter of a priest makes herself common and by her loose behaviour puts shame on her father, let her be burned with fire.", "geneva": "If a Priestes daughter fall to play the whore, she polluteth her father: therefore shall she be burnt with fire.", "wycliffe": "If the `doutir of a preest is takun in defoulyng of virgynite, and defoulith the name of hir fadir, sche schal be brent in flawmes.", "rotherham": "And, the daughter of any priest, when she profaneth herself by unchastity, Her father, she, doth profane, with fire, shall she be consumed.", "darby": "And the daughter of any priest, if she profane herself by playing the whore, she profaneth her father: she shall be burned with fire.", "twenty": "", "jps": "And the daughter of any priest, if she profane herself by playing the harlot, she profaneth her father: she shall be burnt with fire.", "acv": "And the daughter of any priest, if she profanes herself by playing the harlot, she profanes her father. She shall be burnt with fire.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the daughter of any priest, if she shall profane herself by lewdness, she profaneth her father: she shall be burnt with fire.", "vulgate": "sacerdotis filia si deprehensa fuerit in stupro et violaverit nomen patris sui flammis exuretur;", "brenton": "And if the daughter of a priest should be profaned to go a whoring, she profanes the name of her father: she shall be burnt with fire."}}, {"v": 10, "ref": "21:10", "o": "וְ/הַ/כֹּהֵן֩ הַ/גָּד֨וֹל מֵ/אֶחָ֜י/ו אֲֽשֶׁר יוּצַ֥ק עַל רֹאשׁ֣/וֹ שֶׁ֤מֶן הַ/מִּשְׁחָה֙ וּ/מִלֵּ֣א אֶת יָד֔/וֹ לִ/לְבֹּ֖שׁ אֶת הַ/בְּגָדִ֑ים אֶת רֹאשׁ/וֹ֙ לֹ֣א יִפְרָ֔ע וּ/בְגָדָ֖י/ו לֹ֥א יִפְרֹֽם", "en": {"kjv": "And he that is the high priest among his brethren, upon whose head the anointing oil was poured, and that is consecrated to put on the garments, shall not uncover his head, nor rend his clothes;", "web": "“‘He who is the high priest among his brothers, upon whose head the anointing oil is poured, and that is consecrated to put on the garments, shall not let the hair of his head hang loose, nor tear his clothes;", "bsb": "The priest who is highest among his brothers, who has had the anointing oil poured on his head and has been ordained to wear the priestly garments, must not let his hair hang loose or tear his garments.", "asv": "And he that is the high priest among his brethren, upon whose head the anointing oil is poured, and that is consecrated to put on the garments, shall not let the hair of his head go loose, nor rend his clothes;", "ylt": "`And the high priest of his brethren, on whose head is poured the anointing oil, and hath consecrated his hand to put on the garments, his head doth not uncover, nor rend his garments,", "tyndale": "He that is the hye preast among his brethern vppon whose heed the anoyntynge oyle was poured and whose hande was fylled to put on the vestimetes shall not vncouer his heed nor rent his clothes,", "dra": "The high priest, that is to say, the priest who is the greatest among his brethren, upon whose head the oil of unction hath been poured; and whose hands have been consecrated for the priesthood; and who hath been vested with the holy vestments. He shall not uncover his head: he shall not rend his garments.", "bbe": "And he who is the chief priest among his brothers, on whose head the holy oil has been put, who is marked out to put on the holy robes, may not let his hair go loose or have his clothing out of order as a sign of sorrow.", "geneva": "Also ye hie Priest among his brethren, (vpon whose head the anointing oyle was powred, and hath consecrated his hand to put on the garments) shall not vncouer his head, nor rent his clothes,", "wycliffe": "The bischop, that is the moost preest among hise britheren, on whose heed the oile of anoyntyng is sched, and whose hondis ben sacrid in preesthod, and he is clothid in hooli clothis, schal not diskyuere his heed, he schal not tere hise clothis,", "rotherham": "And, as for the high priest from among his brethren upon whose head is poured the anointing oil, and who is installed, by putting on the garments, His head, shall he not bare, And, his garments, shall he not rend;", "darby": "And the high priest among his brethren, on whose head the anointing oil was poured, and who is consecrated to put on the garments, shall not uncover his head, nor rend his garments.", "twenty": "", "jps": "And the priest that is highest among his brethren, upon whose head the anointing oil is poured, and that is consecrated to put on the garments, shall not let the hair of his head go loose, nor rend his clothes;", "acv": "And he who is the high priest among his brothers, upon whose head the anointing oil is poured, and who is consecrated to put on the garments, shall not let the hair of his head go loose, nor tear his clothes,", "anderson": "", "haweis": "", "noyes": "", "webster": "And [he that is] the high priest among his brethren, upon whose head the anointing oil was poured, and that is consecrated to put on the garments, shall not uncover his head, nor rend his clothes;", "vulgate": "pontifex id est sacerdos maximus inter fratres suos super cuius caput fusum est unctionis oleum et cuius manus in sacerdotio consecratae sunt vestitusque est sanctis vestibus caput suum non discoperiet vestimenta non scindet;", "brenton": "And the priest that is chief among his brethren, the oil having been poured upon the head of the anointed one, and he having been consecrated to put on the garments, shall not take the mitre off his head, and shall not rend his garments:"}}, {"v": 11, "ref": "21:11", "o": "וְ/עַ֛ל כָּל נַפְשֹׁ֥ת מֵ֖ת לֹ֣א יָבֹ֑א לְ/אָבִ֥י/ו וּ/לְ/אִמּ֖/וֹ לֹ֥א יִטַּמָּֽא", "en": {"kjv": "Neither shall he go in to any dead body, nor defile himself for his father, or for his mother;", "web": "neither shall he go in to any dead body, nor defile himself for his father, or for his mother;", "bsb": "He must not go near any dead body; he must not defile himself, even for his father or mother.", "asv": "neither shall he go in to any dead body, nor defile himself for his father, or for his mother;", "ylt": "nor beside any dead person doth he come; for his father and for his mother he doth not defile himself;", "tyndale": "nether shall goo to any deed body nor make him selfe vncleane: no not on his father or mother", "dra": "Nor shall he go in at all to any dead person: not even for his father, or his mother, shall he be defiled.", "bbe": "He may not go near any dead body or make himself unclean for his father or his mother;", "geneva": "Neither shall he goe to any dead bodie, nor make him selfe vncleane by his father or by his mother,", "wycliffe": "and outirli he schal not entre to ony deed man; and he schal not be defoulid on his fadir and modir,", "rotherham": "And, unto no persons of the dead, shall he go in,—For his father or for his mother, shall he not make himself unclean;", "darby": "Neither shall he come near any person dead, nor make himself unclean for his father and for his mother;", "twenty": "", "jps": "neither shall he go in to any dead body, nor defile himself for his father, or for his mother;", "acv": "neither shall he go in to any dead body, nor defile himself for his father, or for his mother,", "anderson": "", "haweis": "", "noyes": "", "webster": "Neither shall he go in to any dead body, nor defile himself for his father, or for his mother;", "vulgate": "et ad omnem mortuum non ingredietur omnino super patre quoque suo et matre non contaminabitur;", "brenton": "neither shall he go in to any dead body, neither shall he defile himself for his father or his mother."}}, {"v": 12, "ref": "21:12", "o": "וּ/מִן הַ/מִּקְדָּשׁ֙ לֹ֣א יֵצֵ֔א וְ/לֹ֣א יְחַלֵּ֔ל אֵ֖ת מִקְדַּ֣שׁ אֱלֹהָ֑י/ו כִּ֡י נֵ֠זֶר שֶׁ֣מֶן מִשְׁחַ֧ת אֱלֹהָ֛י/ו עָלָ֖י/ו אֲנִ֥י יְהוָֽה", "en": {"kjv": "Neither shall he go out of the sanctuary, nor profane the sanctuary of his God; for the crown of the anointing oil of his God is upon him: I am the Lord.", "web": "neither shall he go out of the sanctuary, nor profane the sanctuary of his God; for the crown of the anointing oil of his God is upon him. I am Yahweh.", "bsb": "He must not leave or desecrate the sanctuary of his God, for the consecration of the anointing oil of his God is on him. I am the LORD.", "asv": "neither shall he go out of the sanctuary, nor profane the sanctuary of his God; for the crown of the anointing oil of his God is upon him: I am Jehovah.", "ylt": "nor from the sanctuary doth he go out, nor doth he pollute the sanctuary of his God, for the separation of the anointing oil of his God is on him; I am Jehovah.", "tyndale": "nether shall goo out of the sanctuarye, that he polute not the holy place of his God. for the croune of the anoyntynge oyle of God, is apon him. I am the Lorde.", "dra": "Neither shall he go out of the holy places, lest he defile the sanctuary of the Lord: because the oil of the holy unction of his God is upon him. I am the Lord.", "bbe": "He may not go out of the holy place or make the holy place of his God common; for the crown of the holy oil of his God is on him: I am the Lord.", "geneva": "Neither shall he goe out of the Sanctuarie, nor pollute the holy place of his God: for the crowne of the anoynting oyle of his God is vpon him: I am the Lord.", "wycliffe": "nether he schal go out of hooli thingis, lest he defoule the seyntuarie of the Lord, for the oile of hooli anoyntyng of his God is on hym; Y am the Lord.", "rotherham": "And, out of the sanctuary, shall he not go forth, so shall he not profane the sanctuary of his God,—for the consecration of the anointing oil of his God is upon him—I, am Yahweh.", "darby": "neither shall he go out of the sanctuary, nor profane the sanctuary of hisGod; for the consecration of the anointing oil of hisGod is upon him: I am Jehovah.", "twenty": "", "jps": "neither shall he go out of the sanctuary, nor profane the sanctuary of his G-d; for the consecration of the anointing oil of his G-d is upon him: I am HaShem.", "acv": "neither shall he go out of the sanctuary, nor profane the sanctuary of his God, for the crown of the anointing oil of his God is upon him. I am Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "Neither shall he go out of the sanctuary, nor profane the sanctuary of his God; for the crown of the anointing oil of his God [is] upon him: I [am] the LORD.", "vulgate": "nec egredietur de sanctis ne polluat sanctuarium Domini quia oleum sanctae unctionis Dei sui super eum est ego Dominus;", "brenton": "And he shall not go forth out of the sanctuary, and he shall not profane the sanctuary of his God, because the holy anointing oil of God is upon him: I am the Lord."}}, {"v": 13, "ref": "21:13", "o": "וְ/ה֕וּא אִשָּׁ֥ה בִ/בְתוּלֶ֖י/הָ יִקָּֽח", "en": {"kjv": "And he shall take a wife in her virginity.", "web": "“‘He shall take a wife in her virginity.", "bsb": "The woman he marries must be a virgin.", "asv": "And he shall take a wife in her virginity.", "ylt": "`And he taketh a wife in her virginity;", "tyndale": "He shall take a mayden vnto his wife:", "dra": "He shall take a virgin unto his wife.", "bbe": "And let him take as his wife one who has not had relations with a man.", "geneva": "Also he shall take a maide vnto his wife:", "wycliffe": "He schal wedde a wijf virgyn;", "rotherham": "But, he, shall take a woman in her virginity:", "darby": "And he shall take a wife in her virginity.", "twenty": "", "jps": "And he shall take a wife in her virginity.", "acv": "And he shall take a wife in her virginity.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall take a wife in her virginity.", "vulgate": "virginem ducet uxorem;", "brenton": "He shall take for a wife a virgin of his own tribe."}}, {"v": 14, "ref": "21:14", "o": "אַלְמָנָ֤ה וּ/גְרוּשָׁה֙ וַ/חֲלָלָ֣ה זֹנָ֔ה אֶת אֵ֖לֶּה לֹ֣א יִקָּ֑ח כִּ֛י אִם בְּתוּלָ֥ה מֵ/עַמָּ֖י/ו יִקַּ֥ח אִשָּֽׁה", "en": {"kjv": "A widow, or a divorced woman, or profane, or an harlot, these shall he not take: but he shall take a virgin of his own people to wife.", "web": "A widow, or one divorced, or a woman who has been defiled, or a prostitute, these he shall not marry: but a virgin of his own people shall he take as a wife.", "bsb": "He is not to marry a widow, a divorced woman, or one defiled by prostitution. He is to marry a virgin from his own people,", "asv": "A widow, or one divorced, or a profane woman, a harlot, these shall he not take: but a virgin of his own people shall he take to wife.", "ylt": "widow, or cast out, or polluted one--a harlot--these he doth not take, but a virgin of his own people he doth take for a wife,", "tyndale": "but no wedowe nor deuorsed nor poluted whoore. But he shall take a mayden of his awne people to wife,", "dra": "But a widow or one that is divorced, or defied, or a harlot, he shall not take: but a maid of his own people.", "bbe": "A widow, or one whose husband has put her away, or a common woman of loose behaviour, may not be the wife of a priest; but let him take a virgin from among his people.", "geneva": "But a widowe, or a diuorced woman, or a polluted, or an harlot, these shall he not marrie, but shall take a maide of his owne people to wife:", "wycliffe": "he schal not take a widewe, and forsakun, and a foul womman, and hoore, but a damesele of his puple;", "rotherham": "A widow or a divorced woman or one dishonoured—an unchaste woman, these, shall he not take, But, a virgin from among his own kinsfolk, shall he take to wife;", "darby": "A widow, or a divorced woman, or a dishonoured one, a harlot, these shall he not take; but he shall take as wife a virgin from among his peoples.", "twenty": "", "jps": "A widow, or one divorced, or a profaned woman, or a harlot, these shall he not take; but a virgin of his own people shall he take to wife.", "acv": "A widow, or one divorced, or a profane woman, a harlot, these he shall not take, but he shall take to wife a virgin of his own people.", "anderson": "", "haweis": "", "noyes": "", "webster": "A widow, or a divorced woman, or profane, [or] a harlot, these shall he not take: but he shall take a virgin of his own people for a wife.", "vulgate": "viduam et repudiatam et sordidam atque meretricem non accipiet sed puellam de populo suo;", "brenton": "But a widow, or one that is put away, or profaned, or a harlot, these he shall not take; but he shall take for a wife a virgin of his own people."}}, {"v": 15, "ref": "21:15", "o": "וְ/לֹֽא יְחַלֵּ֥ל זַרְע֖/וֹ בְּ/עַמָּ֑י/ו כִּ֛י אֲנִ֥י יְהוָ֖ה מְקַדְּשֽׁ/וֹ", "en": {"kjv": "Neither shall he profane his seed among his people: for I the Lord do sanctify him.", "web": "He shall not profane his seed among his people, for I am Yahweh who sanctifies him.’”", "bsb": "so that he does not defile his offspring among his people, for I am the LORD who sanctifies him.”", "asv": "And he shall not profane his seed among his people: for I am Jehovah who sanctifieth him.", "ylt": "and he doth not pollute his seed among his people; for I am Jehovah, sanctifying him.'", "tyndale": "that he defyle not his seed apo his people. for I am the Lorde which sanctifye him.", "dra": "He shall not mingle the stock of his kindred with the common people of this nation: for I am the Lord who sanctify him.", "bbe": "And he may not make his seed unclean among his people, for I the Lord have made him holy.", "geneva": "Neyther shall he defile his seede among his people: for I am the Lord which sanctifie him.", "wycliffe": "medle he not the generacioun of his kyn to the comyn puple of his folk, for Y am the Lord, that `halewe hym.", "rotherham": "So shall he not profane his seed, among his kinsfolk,—For I—Yahweh, do hallow him.", "darby": "And he shall not profane his seed among his peoples; for I am Jehovah who do hallow him.", "twenty": "", "jps": "And he shall not profane his seed among his people; for I am HaShem who sanctify him.", "acv": "And he shall not profane his seed among his people, for I am Jehovah who sanctifies him.", "anderson": "", "haweis": "", "noyes": "", "webster": "Neither shall he profane his seed among his people: for I the LORD do sanctify him.", "vulgate": "ne commisceat stirpem generis sui vulgo gentis suae quia ego Dominus qui sanctifico eum;", "brenton": "And he shall not profane his seed among his people: I am the Lord that sanctifies him."}}, {"v": 16, "ref": "21:16", "o": "וַ/יְדַבֵּ֥ר יְהוָ֖ה אֶל מֹשֶׁ֥ה לֵּ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh spoke to Moses, saying,", "bsb": "Then the LORD said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde spake vnto Moses saynge", "dra": "And the Lord spoke to Moses, saying:", "bbe": "And the Lord said to Moses,", "geneva": "And the Lord spake vnto Moses, saying,", "wycliffe": "And the Lord spak to Moyses,", "rotherham": "And Yahweh spake unto Moses, saying:", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses, saying:", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "locutusque est Dominus ad Mosen dicens;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 17, "ref": "21:17", "o": "דַּבֵּ֥ר אֶֽל אַהֲרֹ֖ן לֵ/אמֹ֑ר אִ֣ישׁ מִֽ/זַּרְעֲ/ךָ֞ לְ/דֹרֹתָ֗/ם אֲשֶׁ֨ר יִהְיֶ֥ה ב/וֹ֙ מ֔וּם לֹ֣א יִקְרַ֔ב לְ/הַקְרִ֖יב לֶ֥חֶם אֱלֹהָֽי/ו", "en": {"kjv": "Speak unto Aaron, saying, Whosoever he be of thy seed in their generations that hath any blemish, let him not approach to offer the bread of his God.", "web": "“Say to Aaron, ‘None of your seed throughout their generations who has a defect may approach to offer the bread of his God.", "bsb": "“Say to Aaron, ‘For the generations to come, none of your descendants who has a physical defect may approach to offer the food of his God.", "asv": "Speak unto Aaron, saying, Whosoever he be of thy seed throughout their generations that hath a blemish, let him not approach to offer the bread of his God.", "ylt": "`Speak unto Aaron, saying, No man of thy seed to their generations in whom there is blemish doth draw near to bring near the bread of his God,", "tyndale": "speake vnto Aaron and saye: No man of thi seed in their generacions that hath any deformyte apon him, shall prese for to offer the bred of his God.", "dra": "Say to Aaron: Whosoever of thy seed throughout their families, hath a blemish, he shall not offer bread to his God.", "bbe": "Say to Aaron, If a man of your family, in any generation, is damaged in body, let him not come near to make the offering of the bread of his God.", "geneva": "Speake vnto Aaron, and say, Whosoeuer of thy seede in their generations hath any blemishes, shall not prease to offer the bread of his God:", "wycliffe": "and seide, Speke thou to Aaron; a man of thi seed, bi meynes, that hath a wem, schal not offre breed to his God,", "rotherham": "Speak unto Aaron, saying,—No man of thy seed, unto their generations in whom shall be any blemish, shall come near, to present the food of his God.", "darby": "Speak unto Aaron, saying, Any of thy seed throughout their generations that hath any defect, shall not approach to present the bread of hisGod;", "twenty": "", "jps": "Speak unto Aaron, saying: Whosoever he be of thy seed throughout their generations that hath a blemish, let him not approach to offer the bread of his G-d.", "acv": "Speak to Aaron, saying, Whoever he is of thy seed throughout their generations who has a blemish, let him not approach to offer the bread of his God.", "anderson": "", "haweis": "", "noyes": "", "webster": "Speak to Aaron, saying, whoever [he may be] of thy seed in their generations that hath [any] blemish, let him not approach to offer the bread of his God:", "vulgate": "loquere ad Aaron homo de semine tuo per familias qui habuerit maculam non offeret panes Deo suo;", "brenton": "Say to Aaron, A man of thy tribe throughout your generations, who shall have a blemish on him, shall not draw nigh to offer the gifts of his God."}}, {"v": 18, "ref": "21:18", "o": "כִּ֥י כָל אִ֛ישׁ אֲשֶׁר בּ֥/וֹ מ֖וּם לֹ֣א יִקְרָ֑ב אִ֤ישׁ עִוֵּר֙ א֣וֹ פִסֵּ֔חַ א֥וֹ חָרֻ֖ם א֥וֹ שָׂרֽוּעַ", "en": {"kjv": "For whatsoever man he be that hath a blemish, he shall not approach: a blind man, or a lame, or he that hath a flat nose, or any thing superfluous,", "web": "For whatever man he is that has a defect, he shall not draw near: a blind man, or a lame, or he who has a flat nose, or any deformity,", "bsb": "No man who has any defect may approach—no man who is blind, lame, disfigured, or deformed;", "asv": "For whatsoever man he be that hath a blemish, he shall not approach: a blind man, or a lame, or he that hath a flat nose, or anything superfluous,", "ylt": "for no man in whom is blemish doth draw near--a man blind, or lame or dwarfed, or enlarged,", "tyndale": "ffor none that hath any blemysh shall come nere: whether he be blynde lame snot nosed or that hath any monstrous mebre,", "dra": "Neither shall he approach to minister to him: If he be blind; if he be lame; if he have a little, or a great, or a crooked nose;", "bbe": "For any man whose body is damaged may not come near: one who is blind, or has not the use of his legs, or one who has a broken nose or any unnatural growth,", "geneva": "For whosoeuer hath any blemish, shall not come neere: as a man blinde or lame, or that hath a flat nose, or that hath any misshapen member,", "wycliffe": "nethir schal neiy to his seruyce;", "rotherham": "Surely, no man in whom is any blemish, shall come near,—No man who is blind or lame, or hath a flat nose, or is lanky;", "darby": "for whatever man hath a defect, he shall not approach: a blind man, or a lame, or he that hath a flat nose, or one limb longer than the other,", "twenty": "", "jps": "For whatsoever man he be that hath a blemish, he shall not approach: a blind man, or a lame, or he that hath any thing maimed, or anything too long,", "acv": "For whatever man he is who has a blemish, he shall not approach: not a blind man, or a lame man, or he who has a flat nose, or anything superfluous,", "anderson": "", "haweis": "", "noyes": "", "webster": "For whatever man [he may be] that hath a blemish, he shall not approach: a blind man, or a lame, or he that hath a flat nose, or any thing superfluous,", "vulgate": "nec accedet ad ministerium eius si caecus fuerit si claudus si vel parvo vel grandi et torto naso;", "brenton": "No man who has a blemish on him shall draw nigh; a man blind, lame, with his nose disfigured, or his ears cut,"}}, {"v": 19, "ref": "21:19", "o": "א֣וֹ אִ֔ישׁ אֲשֶׁר יִהְיֶ֥ה ב֖/וֹ שֶׁ֣בֶר רָ֑גֶל א֖וֹ שֶׁ֥בֶר יָֽד", "en": {"kjv": "Or a man that is brokenfooted, or brokenhanded,", "web": "or a man who has an injured foot, or an injured hand,", "bsb": "no man who has a broken foot or hand,", "asv": "or a man that is broken-footed, or broken-handed,", "ylt": "or a man in whom there is a breach in the foot, or a breach in the hand,", "tyndale": "or broken foted or broken handed", "dra": "If his foot, or if his hand be broken;", "bbe": "Or a man with broken feet or hands,", "geneva": "Or a man that hath a broken foote, or a broken hande,", "wycliffe": "if he is blind; if he is crokid; if he is ether of litil, ether of greet, and wrong nose; if he is `of brokun foot, ethir hond;", "rotherham": "nor any man who hath a broken foot,—or a broken hand;", "darby": "or a man that is broken-footed, or broken-handed,", "twenty": "", "jps": "or a man that is broken-footed, or broken-handed,", "acv": "or a man who is broken-footed, or broken-handed,", "anderson": "", "haweis": "", "noyes": "", "webster": "Or a man that is broken-footed, or broken-handed,", "vulgate": "si fracto pede si manu;", "brenton": "a man who has a broken hand or a broken foot,"}}, {"v": 20, "ref": "21:20", "o": "אֽוֹ גִבֵּ֣ן אוֹ דַ֔ק א֖וֹ תְּבַלֻּ֣ל בְּ/עֵינ֑/וֹ א֤וֹ גָרָב֙ א֣וֹ יַלֶּ֔פֶת א֖וֹ מְר֥וֹחַ אָֽשֶׁךְ", "en": {"kjv": "Or crookbackt, or a dwarf, or that hath a blemish in his eye, or be scurvy, or scabbed, or hath his stones broken;", "web": "or hunchbacked, or a dwarf, or one who has a defect in his eye, or an itching disease, or scabs, or who has damaged testicles.", "bsb": "or who is a hunchback or dwarf, or who has an eye defect, a festering rash, scabs, or a crushed testicle.", "asv": "or crook-backed, or a dwarf, or that hath a blemish in his eye, or is scurvy, or scabbed, or hath his stones broken;", "ylt": "or hump-backed, or a dwarf, or with a mixture in his eye, or a scurvy person, or scabbed, or broken-testicled.", "tyndale": "or croke backed, or perleyed, or gogeleyed, or maunge or skaulde or hath his stones broken.", "dra": "If he be crookbacked; or blear eyed; or have a pearl in his eye, or a continual scab, or a dry scurf in his body, or a rupture.", "bbe": "Or one whose back is bent, or one who is unnaturally small, or one who has a damaged eye, or whose skin is diseased, or whose sex parts are damaged;", "geneva": "Or is crooke backt, or bleare eyed, or hath a blemish in his eye, or be skiruie, or skabbed, or haue his stones broken.", "wycliffe": "if he hath a botche; ether if he is blereiyed; if he hath whijt colour in the iye, that lettith the siyt; if he hath contynuel scabbe; if he hath a drye scabbe in the bodi; ethir `is brokun `in the pryuy membris.", "rotherham": "or is hump-backed or a dwarf, or hath defective vision,—or hath scurvy or scab, or is crushed in the stones:", "darby": "or hump-backed, or withered, or that hath a spot in his eye, or hath the itch, or scabs, or his testicles broken.", "twenty": "", "jps": "or crook-backed, or a dwarf, or that hath his eye overspread, or is scabbed, or scurvy, or hath his stones crushed;", "acv": "or crook-backed, or a dwarf, or who has a blemish in his eye, or is scurvy, or scabbed, or has his testicles broken.", "anderson": "", "haweis": "", "noyes": "", "webster": "Or crooked-backed, or a dwarf, or that hath a blemish in his eye, or be scurvy, or scabbed, or hath his peculiar members broken:", "vulgate": "si gibbus si lippus si albuginem habens in oculo si iugem scabiem si inpetiginem in corpore vel hirniosus;", "brenton": "or hump-backed, or blear-eyed, or that has lost his eye-lashes, or a man who has a malignant ulcer, or tetter, or one that has lost a testicle."}}, {"v": 21, "ref": "21:21", "o": "כָּל אִ֞ישׁ אֲשֶׁר בּ֣/וֹ מ֗וּם מִ/זֶּ֨רַע֙ אַהֲרֹ֣ן הַ/כֹּהֵ֔ן לֹ֣א יִגַּ֔שׁ לְ/הַקְרִ֖יב אֶת אִשֵּׁ֣י יְהוָ֑ה מ֣וּם בּ֔/וֹ אֵ֚ת לֶ֣חֶם אֱלֹהָ֔י/ו לֹ֥א יִגַּ֖שׁ לְ/הַקְרִֽיב", "en": {"kjv": "No man that hath a blemish of the seed of Aaron the priest shall come nigh to offer the offerings of the Lord made by fire: he hath a blemish; he shall not come nigh to offer the bread of his God.", "web": "No man of the seed of Aaron the priest who has a defect shall come near to offer the offerings of Yahweh made by fire. Since he has a defect, he shall not come near to offer the bread of his God.", "bsb": "No descendant of Aaron the priest who has a defect shall approach to present the offerings made by fire to the LORD. Since he has a defect, he is not to come near to offer the food of his God.", "asv": "no man of the seed of Aaron the priest, that hath a blemish, shall come nigh to offer the offerings of Jehovah made by fire: he hath a blemish; he shall not come nigh to offer the bread of his God.", "ylt": "`No man in whom is blemish (of the seed of Aaron the priest) doth come nigh to bring near the fire-offerings of Jehovah; blemish is in him; the bread of his God he doth not come nigh to bring near.", "tyndale": "No man that is deformed of the seed of Aaron the preast shall come nye to offer the sacrifyces of the Lorde. Yf he haue a deformyte he shall not prese to offer the bred of his God.", "dra": "Whosoever of the seed of Aaron the priest hath a blemish: he shall not approach to offer sacrifices to the Lord, nor bread to his God.", "bbe": "No man of the offspring of Aaron whose body is damaged in any way may come near to give the fire offerings of the Lord: he is damaged, he may not come near to make the offerings.", "geneva": "None of the seede of Aaron the Priest that hath a blemish, shall come neere to offer the sacrifices of the Lord made by fire, hauing a blemish: he shall not prease to offer the bread of his God.", "wycliffe": "Ech man of the seed of Aaron preest, which man hath a wem, schal not neiye to offre sacrifices to the Lord, nether `to offre looues to his God;", "rotherham": "No, man in whom is a blemish of the seed of Aaron the priest, shall approach, to bring near the altar-flames of Yahweh,—a blemish, is in him, the food of his God, shall he not approach to bring near:", "darby": "No man of the seed of Aaron the priest that hath defect shall come near to present Jehovah's offerings by fire: he hath a defect; he shall not come near to present the bread of hisGod.", "twenty": "", "jps": "no man of the seed of Aaron the priest, that hath a blemish, shall come nigh to offer the offerings of HaShem made by fire; he hath a blemish; he shall not come nigh to offer the bread of his G-d.", "acv": "No man of the seed of Aaron the priest, who has a blemish, shall come near to offer the offerings of Jehovah made by fire; he has a blemish, he shall not come near to offer the bread of his God.", "anderson": "", "haweis": "", "noyes": "", "webster": "No man of the seed of Aaron the priest, that hath a blemish, shall come nigh to offer the offerings of the LORD made by fire; he hath a blemish, he shall not come nigh to offer the bread of his God.", "vulgate": "omnis qui habuerit maculam de semine Aaron sacerdotis non accedet offerre hostias Domino nec panes Deo suo;", "brenton": "Whoever of the seed of Aaron the priest has a blemish on him, shall not draw nigh to offer sacrifices to thy God, because he has a blemish on him; he shall not draw nigh to offer the gifts of God."}}, {"v": 22, "ref": "21:22", "o": "לֶ֣חֶם אֱלֹהָ֔י/ו מִ/קָּדְשֵׁ֖י הַ/קֳּדָשִׁ֑ים וּ/מִן הַ/קֳּדָשִׁ֖ים יֹאכֵֽל", "en": {"kjv": "He shall eat the bread of his God, both of the most holy, and of the holy.", "web": "He shall eat the bread of his God, both of the most holy, and of the holy.", "bsb": "He may eat the most holy food of his God as well as the holy food,", "asv": "He shall eat the bread of his God, both of the most holy, and of the holy:", "ylt": "`Bread of his God--of the most holy things, and of the holy things--he doth eat;", "tyndale": "Notwithstondynge he shall eate of the bred of his God: euen as well of the most holy as of the holy:", "dra": "He shall eat nevertheless of the loaves that are offered in the sanctuary.", "bbe": "He may take of the bread of God, the holy and the most holy;", "geneva": "The bread of his God, euen of the most holie, and of the holy shall he eate:", "wycliffe": "netheles he schal ete the looues that ben offrid in the seyntuarie,", "rotherham": "Of the food of his God, both of the most holy,—and the holy, may he eat:", "darby": "The bread of hisGod, of the most holy and of the holy, shall he eat;", "twenty": "", "jps": "He may eat the bread of his G-d, both of the most holy, and of the holy.", "acv": "He shall eat the bread of his God, both of the most holy, and of the holy,", "anderson": "", "haweis": "", "noyes": "", "webster": "He shall eat the bread of his God, [both] of the most holy, and of the holy.", "vulgate": "vescetur tamen panibus qui offeruntur in sanctuario;", "brenton": "The gifts of God are most holy, and he shall eat of the holy things."}}, {"v": 23, "ref": "21:23", "o": "אַ֣ךְ אֶל הַ/פָּרֹ֜כֶת לֹ֣א יָבֹ֗א וְ/אֶל הַ/מִּזְבֵּ֛חַ לֹ֥א יִגַּ֖שׁ כִּֽי מ֣וּם בּ֑/וֹ וְ/לֹ֤א יְחַלֵּל֙ אֶת מִקְדָּשַׁ֔/י כִּ֛י אֲנִ֥י יְהוָ֖ה מְקַדְּשָֽׁ/ם", "en": {"kjv": "Only he shall not go in unto the vail, nor come nigh unto the altar, because he hath a blemish; that he profane not my sanctuaries: for I the Lord do sanctify them.", "web": "He shall not come near to the veil, nor come near to the altar, because he has a defect; that he may not profane my sanctuaries, for I am Yahweh who sanctifies them.’”", "bsb": "but because he has a defect, he must not go near the veil or approach the altar, so as not to desecrate My sanctuaries. For I am the LORD who sanctifies them.’”", "asv": "only he shall not go in unto the veil, nor come nigh unto the altar, because he hath a blemish; that he profane not my sanctuaries: for I am Jehovah who sanctifieth them.", "ylt": "only, unto the vail he doth not enter, and unto the altar he doth not draw nigh; for blemish is in him; and he doth not pollute My sanctuaries; for I am Jehovah, sanctifying them.'", "tyndale": "but shall not goo in vnto the vayle nor come nye the alter, because he is deformed that he polute not my sanctuary for I am the Lorde that sanctifye them.", "dra": "Yet so that he enter not within the veil, nor approach to the altar: because he hath a blemish, and he must not defile my sanctuary. I am the Lord who sanctify them.", "bbe": "But he may not go inside the veil or come near the altar, because he is damaged; and he may not make my holy places common; for I the Lord have made them holy.", "geneva": "But he shall not goe in vnto the vaile, nor come neere the altar, because hee hath a blemish, least he pollute my Sanctuaries: for I am the Lord that sanctifie them.", "wycliffe": "so oneli that he entre not with ynne the veil; he schal not neiye to the auter, for he hath a wem, and he schal not defoule my seyntuarie; Y am the Lord that halewe hem.", "rotherham": "Only, unto the veil, shall he not come in and unto the altar, shall he not approach—because, a blemish, is in him, so shall he not profane my sanctuaries, For, I—Yahweh, am hallowing them.", "darby": "only he shall not come in unto the veil, nor shall he draw near unto the altar; for he hath a defect: that he profane not my sanctuaries; for I am Jehovah who do hallow them.", "twenty": "", "jps": "Only he shall not go in unto the veil, nor come nigh unto the altar, because he hath a blemish; that he profane not My holy places; for I am HaShem who sanctify them.", "acv": "only he shall not go in to the veil, nor come near to the altar, because he has a blemish, that he not profane my sanctuaries, for I am Jehovah who sanctifies them.", "anderson": "", "haweis": "", "noyes": "", "webster": "Only he shall not go in to the vail, nor come nigh to the altar, because he hath a blemish; that he may not profane my sanctuaries: for I the LORD do sanctify them.", "vulgate": "ita dumtaxat ut intra velum non ingrediatur nec accedat ad altare quia maculam habet et contaminare non debet sanctuarium meum ego Dominus qui sanctifico eos;", "brenton": "Only he shall not approach the veil, and he shall not draw nigh to the altar, because he has a blemish; and he shall not profane the sanctuary of his God, for I am the Lord that sanctifies them."}}, {"v": 24, "ref": "21:24", "o": "וַ/יְדַבֵּ֣ר מֹשֶׁ֔ה אֶֽל אַהֲרֹ֖ן וְ/אֶל בָּנָ֑י/ו וְ/אֶֽל כָּל בְּנֵ֖י יִשְׂרָאֵֽל", "en": {"kjv": "And Moses told it unto Aaron, and to his sons, and unto all the children of Israel.", "web": "So Moses spoke to Aaron, and to his sons, and to all the children of Israel.", "bsb": "Moses told this to Aaron and his sons and to all the Israelites.", "asv": "So Moses spake unto Aaron, and to his sons, and unto all the children of Israel.", "ylt": "And Moses speaketh unto Aaron, and unto his sons, and unto all the sons of Israel.", "tyndale": "And Moses tolde it vnto Aaron and to his sonnes and vnto all the childern of Israel.", "dra": "Moses, therefore spoke to Aaron, and to his sons and to all Israel, all the things that had been commanded him.", "bbe": "These are the words which Moses said to Aaron and to his sons and to all the children of Israel.", "geneva": "Thus spake Moses vnto Aaron, and to his sonnes, and to all the children of Israel.", "wycliffe": "Therfor Moises spak to Aaron, and to hise sones, and to al Israel, alle thingis that weren comaundid to hym.", "rotherham": "And Moses spake [these things] unto Aaron, and unto his sons,—and unto all the sons of Israel.", "darby": "And Moses told it to Aaron, and to his sons, and to all the children of Israel.", "twenty": "", "jps": "So Moses spoke unto Aaron, and to his sons, and unto all the children of Israel.", "acv": "So Moses spoke to Aaron, and to his sons, and to all the sons of Israel.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Moses told [it] to Aaron, and to his sons, and to all the children of Israel.", "vulgate": "locutus est ergo Moses ad Aaron et filios eius et ad omnem Israhel cuncta quae sibi fuerant imperata;", "brenton": "And Moses spoke to Aaron and his sons, and to all the children of Israel."}}]}, {"c": 22, "verses": [{"v": 1, "ref": "22:1", "o": "וַ/יְדַבֵּ֥ר יְהוָ֖ה אֶל מֹשֶׁ֥ה לֵּ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh spoke to Moses, saying,", "bsb": "Then the LORD said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde comened with Moses saynge:", "dra": "And the Lord spoke to Moses saying:", "bbe": "And the Lord said to Moses,", "geneva": "And the Lord spake vnto Moses, saying,", "wycliffe": "And the Lord spak to Moises, and seide, Speke thou to Aaron and to hise sones,", "rotherham": "And Yahweh spake unto Moses, saying:", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses, saying:", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "locutus quoque est Dominus ad Mosen dicens;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 2, "ref": "22:2", "o": "דַּבֵּ֨ר אֶֽל אַהֲרֹ֜ן וְ/אֶל בָּנָ֗י/ו וְ/יִנָּֽזְרוּ֙ מִ/קָּדְשֵׁ֣י בְנֵֽי יִשְׂרָאֵ֔ל וְ/לֹ֥א יְחַלְּל֖וּ אֶת שֵׁ֣ם קָדְשִׁ֑/י אֲשֶׁ֨ר הֵ֧ם מַקְדִּשִׁ֛ים לִ֖/י אֲנִ֥י יְהוָֽה", "en": {"kjv": "Speak unto Aaron and to his sons, that they separate themselves from the holy things of the children of Israel, and that they profane not my holy name in those things which they hallow unto me: I am the Lord.", "web": "“Tell Aaron and his sons to separate themselves from the holy things of the children of Israel, which they make holy to me, and that they not profane my holy name. I am Yahweh.", "bsb": "“Tell Aaron and his sons to treat with respect the sacred offerings that the Israelites have consecrated to Me, so that they do not profane My holy name. I am the LORD.", "asv": "Speak unto Aaron and to his sons, that they separate themselves from the holy things of the children of Israel, which they hallow unto me, and that they profane not my holy name: I am Jehovah.", "ylt": "`Speak unto Aaron, and unto his sons, and they are separated from the holy things of the sons of Israel, and they pollute not My holy name in what they are hallowing to Me; I am Jehovah.", "tyndale": "byd Aaron and his sonnes that they absteyne from the halowed thynges of the childern of Israel which they haue halowed vnto me, that they polute not myne holy name: for I am the Lorde.", "dra": "Speak to Aaron and to his sons, that they beware of those things that are consecrated of the children of Israel: and defile not the name of the things sanctified to me, which they offer. I am the Lord.", "bbe": "Give orders to Aaron and to his sons to keep themselves separate from the holy things of the children of Israel which they give to me, and not to make my holy name common: I am the Lord,", "geneva": "Speake vnto Aaron, and to his sonnes, that they be separated from the holy thinges of the children of Israel, and that they pollute not mine holy name in those things, which they hallowe vnto me: I am the Lord.", "wycliffe": "that thei be war of these thingis of the sones of Israel, whiche thingis ben halewid; and that they defoule not the name of thingis halewid to me, whiche thingis thei offren; Y am the Lord.", "rotherham": "Speak unto Aaron, and unto his sons, That they hold sacredly aloof from the holy things of the sons of Israel, so as not to profane my holy name,—in the things which they are hallowing unto me—I, am Yahweh.", "darby": "Speak unto Aaron, and to his sons, that they separate themselves from the holy things of the children of Israel, and that they profane not my holy name in the things that they hallow unto me: I am Jehovah.", "twenty": "", "jps": "Speak unto Aaron and to his sons, that they separate themselves from the holy things of the children of Israel, which they hallow unto Me, and that they profane not My holy name: I am HaShem.", "acv": "Speak to Aaron and to his sons, that they separate themselves from the holy things of the sons of Israel, which they hallow to me, and that they not profane my holy name. I am Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "Speak to Aaron and to his sons, that they separate themselves from the holy things of the children of Israel, and that they profane not my holy name [in those things] which they hallow to me: I [am] the LORD.", "vulgate": "loquere ad Aaron et ad filios eius ut caveant ab his quae consecrata sunt filiorum Israhel et non contaminent nomen sanctificatorum mihi quae ipsi offerunt ego Dominus;", "brenton": "Speak to Aaron and to his sons, and let them take heed concerning the holy things of the children of Israel, so they shall not profane my holy name in any of the things which they consecrate to me: I am the Lord."}}, {"v": 3, "ref": "22:3", "o": "אֱמֹ֣ר אֲלֵ/הֶ֗ם לְ/דֹרֹ֨תֵי/כֶ֜ם כָּל אִ֣ישׁ אֲשֶׁר יִקְרַ֣ב מִ/כָּל זַרְעֲ/כֶ֗ם אֶל הַ/קֳּדָשִׁים֙ אֲשֶׁ֨ר יַקְדִּ֤ישׁוּ בְנֵֽי יִשְׂרָאֵל֙ לַֽ/יהוָ֔ה וְ/טֻמְאָת֖/וֹ עָלָ֑י/ו וְ/נִכְרְתָ֞ה הַ/נֶּ֧פֶשׁ הַ/הִ֛וא מִ/לְּ/פָנַ֖/י אֲנִ֥י יְהוָֽה", "en": {"kjv": "Say unto them, Whosoever he be of all your seed among your generations, that goeth unto the holy things, which the children of Israel hallow unto the Lord, having his uncleanness upon him, that soul shall be cut off from my presence: I am the Lord.", "web": "“Tell them, ‘If anyone of all your seed throughout your generations approaches the holy things, which the children of Israel make holy to Yahweh, having his uncleanness on him, that soul shall be cut off from before me. I am Yahweh.", "bsb": "Tell them that for the generations to come, if any of their descendants in a state of uncleanness approaches the sacred offerings that the Israelites consecrate to the LORD, that person must be cut off from My presence. I am the LORD.", "asv": "Say unto them, Whosoever he be of all your seed throughout your generations, that approacheth unto the holy things, which the children of Israel hallow unto Jehovah, having his uncleanness upon him, that soul shall be cut off from before me: I am Jehovah.", "ylt": "`Say unto them, To your generations, any man who draweth near, out of all your seed, unto the holy things which the sons of Israel do sanctify to Jehovah, and his uncleanness on him--even that person hath been cut off from before Me; I am Jehovah.", "tyndale": "Saye vnto them: whosoeuer he be of all youre seed amonge youre generacion after you that goeth vnto the halowed thinges which the childern of Israel shall haue halowed vnto the Lorde his vnclennes shalbe apon him: and that soule shall perysh from out of my syghte. I am the Lorde.", "dra": "Say to them and to their posterity: Every man of your race, that approacheth to those things that are consecrated, and which the children of Israel have offered to the Lord, in whom there is uncleanness, shall perish before the Lord. I am the Lord.", "bbe": "Say to them, If any man of all your seed through all your generations, being unclean, comes near the holy things which the children of Israel make holy to the Lord, he will be cut off from before me: I am the Lord.", "geneva": "Say vnto them, Whosoeuer he be of all your seede among your generations after you, that toucheth the holy things which the children of Israel hallowe vnto the Lord, hauing his vncleannesse vpon him, euen that person shall be cut off from my sight: I am the Lord.", "wycliffe": "Seie thou to hem, and to the aftir comeris of hem, Ech man of youre kynrede, `which man neiyeth to tho thingis that ben halewid, and whiche thingis the sones of Israel offreden to the Lord, in `which man is vnclennesse, schal perische bifor the Lord; Y am the Lord.", "rotherham": "Say unto them—Unto your generations, as touching any man who cometh near from among any of your seed, unto the hallowed things which the sons of Israel may hallow unto Yahweh, while his uncleanness is upon him, then shall that person be cut off from before me—I, am Yahweh.", "darby": "Say unto them, Every one of all your seed, throughout your generations, that approacheth the holy things, which the children of Israel hallow unto Jehovah, having his uncleanness upon him, that soul shall be cut off from before me: I am Jehovah.", "twenty": "", "jps": "Say unto them: Whosoever he be of all your seed throughout your generations, that approacheth unto the holy things, which the children of Israel hallow unto HaShem, having his uncleanness upon him, that soul shall be cut off from before Me: I am HaShem.", "acv": "Say to them, Whoever he is of all your seed throughout your generations, that approaches to the holy things, which the sons of Israel hallow to Jehovah, having his uncleanness upon him, that soul shall be cut off from before me. I am Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "Say to them, Whoever [he may be] of all your seed among your generations, that approacheth the holy things, which the children of Israel hallow to the LORD, having his uncleanness upon him, that soul shall be cut off from my presence: I [am] the LORD.", "vulgate": "dic ad eos et ad posteros eorum omnis homo qui accesserit de stirpe vestra ad ea quae consecrata sunt et quae obtulerunt filii Israhel Domino in quo est inmunditia peribit coram Domino ego sum Dominus;", "brenton": "Say to them, Every man throughout your generations, whoever of all your seed shall approach to the holy things, whatsoever the children of Israel shall consecrate to the Lord, while his uncleanness is upon him, that soul shall be cut off from me: I am the Lord your God."}}, {"v": 4, "ref": "22:4", "o": "אִ֣ישׁ אִ֞ישׁ מִ/זֶּ֣רַע אַהֲרֹ֗ן וְ/ה֤וּא צָר֨וּעַ֙ א֣וֹ זָ֔ב בַּ/קֳּדָשִׁים֙ לֹ֣א יֹאכַ֔ל עַ֖ד אֲשֶׁ֣ר יִטְהָ֑ר וְ/הַ/נֹּגֵ֨עַ֙ בְּ/כָל טְמֵא נֶ֔פֶשׁ א֣וֹ אִ֔ישׁ אֲשֶׁר תֵּצֵ֥א מִמֶּ֖/נּוּ שִׁכְבַת זָֽרַע", "en": {"kjv": "What man soever of the seed of Aaron is a leper, or hath a running issue; he shall not eat of the holy things, until he be clean. And whoso toucheth any thing that is unclean by the dead, or a man whose seed goeth from him;", "web": "“‘Whoever of the seed of Aaron is a leper or has an issue; he shall not eat of the holy things, until he is clean. Whoever touches anything that is unclean by the dead, or a man whose seed goes from him;", "bsb": "If a descendant of Aaron has a skin disease or a discharge, he may not eat the sacred offerings until he is clean. Whoever touches anything defiled by a corpse or by a man who has an emission of semen,", "asv": "What man soever of the seed of Aaron is a leper, or hath an issue; he shall not eat of the holy things, until he be clean. And whoso toucheth anything that is unclean by the dead, or a man whose seed goeth from him;", "ylt": "`Any man of the seed of Aaron, and is leprous or hath an issue--of the holy things he doth not eat till that he is clean; and he who is coming against any uncleanness of a person, or a man whose seed of copulation goeth out from him,", "tyndale": "None of the seed of Aaron that is a leper or that hath a runnynge sore shall eate of the halowed thinges vntill he be cleane. And whosoeuer twytcheth any vncleane soule or man whose seed runneth fro him by nyghte,", "dra": "The man of the seed of Aaron, that is a leper, or that suffereth a running of the seed, shall not eat of those things that are sanctified to me, until he be healed. He that toucheth any thing unclean by occasion of the dead: and he whose seed goeth from him as in generation:", "bbe": "No man of the seed of Aaron who is a leper, or who has a flow from his body, may take of the holy food till he is clean. And any man touching anything which is unclean because of the dead, or any man whose seed goes from him;", "geneva": "Whosoeuer also of the seede of Aaron is a leper, or hath a running issue, he shall not eate of the holy things vntill he be cleane: and who so toucheth any that is vncleane, by reason of the dead, or a man whose issue of seede runneth from him,", "wycliffe": "A man of the seed of Aaron, `which man is leprouse, ethir suffrith `fletyng out of seed, schal not ete of these thingis, that ben halewid to me, til he be heelid. He that touchith an vncleene thing on a deed bodi, and fro whom the seed as of leccherie goith out, and which touchith a crepynge beeste,", "rotherham": "No man soever of the seed of Aaron who is a leper, or hath a flux, shall eat of the holy things, until he be clean,—And as for him who toucheth anything that is unclean by the dead, or a man whose seed goeth from him;", "darby": "Whatsoever man of the seed of Aaron is a leper, or hath a flux, he shall not eat of the holy things, until he is clean. And he that toucheth any one that is unclean by a dead person, or a man whose seed of copulation hath passed from him;", "twenty": "", "jps": "What man soever of the seed of Aaron is a leper, or hath an issue, he shall not eat of the holy things, until he be clean. And whoso toucheth any one that is unclean by the dead; or from whomsoever the flow of seed goeth out;", "acv": "Whatever man of the seed of Aaron being a man with a leprous disease, or has an issue, he shall not eat of the holy things until he is clean. And whoever touches anything that is unclean by the dead, or a man whose seed goes from him,", "anderson": "", "haweis": "", "noyes": "", "webster": "Whatever man of the seed of Aaron [is] a leper, or hath a running issue; he shall not eat of the holy things, until he is clean. And whoever toucheth any thing [that is] unclean [by] the dead, or a man whose seed goeth from him;", "vulgate": "homo de semine Aaron qui fuerit leprosus aut patiens fluxum seminis non vescetur de his quae sanctificata sunt mihi donec sanetur qui tetigerit inmundum super mortuo et ex quo egreditur semen quasi coitus;", "brenton": "And the man of the seed of Aaron the priest, if he should have leprosy or issue of the reins, shall not eat of the holy things, until he be cleansed; and he that touches any uncleanness of a dead body, or the man whose seed of copulation shall have gone out from him,"}}, {"v": 5, "ref": "22:5", "o": "אוֹ אִישׁ֙ אֲשֶׁ֣ר יִגַּ֔ע בְּ/כָל שֶׁ֖רֶץ אֲשֶׁ֣ר יִטְמָא ל֑/וֹ א֤וֹ בְ/אָדָם֙ אֲשֶׁ֣ר יִטְמָא ל֔/וֹ לְ/כֹ֖ל טֻמְאָתֽ/וֹ", "en": {"kjv": "Or whosoever toucheth any creeping thing, whereby he may be made unclean, or a man of whom he may take uncleanness, whatsoever uncleanness he hath;", "web": "or whoever touches any creeping thing, whereby he may be made unclean, or a man of whom he may take uncleanness, whatever uncleanness he has;", "bsb": "or whoever touches a crawling creature or a person that makes him unclean, whatever the uncleanness may be—", "asv": "or whosoever toucheth any creeping thing, whereby he may be made unclean, or a man of whom he may take uncleanness, whatsoever uncleanness he hath;", "ylt": "or a man who cometh against any teeming thing which is unclean to him, or against a man who is unclean to him, even any of his uncleanness--", "tyndale": "or whosoeuer twitcheth any worme that is vncleane to him or man that is vncleane to him what soeuer vnclennesse he hath:", "dra": "And he that toucheth a creeping thing, or any unclean thing, the touching of which is defiling:", "bbe": "Or anyone touching any unclean thing which goes flat on the earth, or someone by whom he may be made unclean in any way whatever;", "geneva": "Or the man that toucheth any creeping thing, whereby he may be made vncleane, or a man, by whom he may take vncleannesse, whatsoeuer vncleannesse he hath,", "wycliffe": "and what euer vncleene thing, whos touchyng is foul,", "rotherham": "or a man who toucheth any creeping thing, which is unclean to him,—or [toucheth] any human being who hath uncleanness, to the extent of any thing that maketh him unclean,", "darby": "or a man that toucheth any crawling thing whereby he becometh unclean, or a man by whom he may become unclean, whatever may be his uncleanness,", "twenty": "", "jps": "or whosoever toucheth any swarming thing, whereby he may be made unclean, or a man of whom he may take uncleanness, whatsoever uncleanness he hath;", "acv": "or whoever touches any creeping thing, by which he may be made unclean, or a man of whom he may take uncleanness, whatever uncleanness he has,", "anderson": "", "haweis": "", "noyes": "", "webster": "Or whoever toucheth any creeping animal, by which he may be made unclean, or a man of whom he may take uncleanness, whatever uncleanness he hath:", "vulgate": "et qui tangit reptile et quodlibet inmundum cuius tactus est sordidus;", "brenton": "or whosoever shall touch any unclean reptile, which will defile him, or who shall touch a man, whereby he shall defile him according to all his uncleanness:"}}, {"v": 6, "ref": "22:6", "o": "נֶ֚פֶשׁ אֲשֶׁ֣ר תִּגַּע בּ֔/וֹ וְ/טָמְאָ֖ה עַד הָ/עָ֑רֶב וְ/לֹ֤א יֹאכַל֙ מִן הַ/קֳּדָשִׁ֔ים כִּ֛י אִם רָחַ֥ץ בְּשָׂר֖/וֹ בַּ/מָּֽיִם", "en": {"kjv": "The soul which hath touched any such shall be unclean until even, and shall not eat of the holy things, unless he wash his flesh with water.", "web": "the person that touches any such shall be unclean until the evening, and shall not eat of the holy things, unless he bathe his body in water.", "bsb": "the man who touches any of these will remain unclean until evening. He must not eat from the sacred offerings unless he has bathed himself with water.", "asv": "the soul that toucheth any such shall be unclean until the even, and shall not eat of the holy things, unless he bathe his flesh in water.", "ylt": "the person who cometh against it--hath even been unclean till the evening, and doth not eat of the holy things, but hath bathed his flesh with water,", "tyndale": "the same soule that hath twyched any soch thynge shalbe vncleane vntill euen and shall not eate of the halowed thynges vntill he haue wasshed his flesh with water.", "dra": "Shall be unclean until the evening, and shall not eat those things that are sanctified. But when he hath washed his flesh with water,", "bbe": "Any person touching any such unclean thing will be unclean till evening, and may not take of the holy food till his flesh has been bathed in water;", "geneva": "The person that hath touched such, shall therefore be vncleane vntill the euen, and shall not eat of ye holy things, except he haue washed his flesh with water.", "wycliffe": "schal be vncleene `til to euentid, and he schal not ete these thingis, that ben halewid to me; but whanne he hath waische his fleisch in watir,", "rotherham": "any person who toucheth any such, shall then be unclean until the evening,—and shall not eat of the hallowed things, unless he bathe his flesh in water.", "darby": "— a person that toucheth any such shall be unclean until even, and shall not eat of the holy things; but he shall bathe his flesh with water,", "twenty": "", "jps": "the soul that toucheth any such shall be unclean until the even, and shall not eat of the holy things, unless he bathe his flesh in water.", "acv": "the soul that touches any such shall be unclean until the evening. And shall not eat of the holy things unless he bathe his flesh in water.", "anderson": "", "haweis": "", "noyes": "", "webster": "The soul which hath touched any such shall be unclean until evening, and shall not eat of the holy things, unless he shall wash his flesh with water.", "vulgate": "inmundus erit usque ad vesperum et non vescetur his quae sanctificata sunt sed cum laverit carnem suam aqua;", "brenton": "whatsoever soul shall touch them shall be unclean until evening; he shall not eat of the holy things, unless he bathe his body in water,"}}, {"v": 7, "ref": "22:7", "o": "וּ/בָ֥א הַ/שֶּׁ֖מֶשׁ וְ/טָהֵ֑ר וְ/אַחַר֙ יֹאכַ֣ל מִן הַ/קֳּדָשִׁ֔ים כִּ֥י לַחְמ֖/וֹ הֽוּא", "en": {"kjv": "And when the sun is down, he shall be clean, and shall afterward eat of the holy things; because it is his food.", "web": "When the sun is down, he shall be clean; and afterward he shall eat of the holy things, because it is his bread.", "bsb": "When the sun has set, he will become clean, and then he may eat from the sacred offerings, for they are his food.", "asv": "And when the sun is down, he shall be clean; and afterward he shall eat of the holy things, because it is his bread.", "ylt": "and the sun hath gone in, and he hath been clean, and afterwards he doth eat of the holy things, for it is his food;", "tyndale": "And than when the sonne is doune he shalbe cleane ad shall afterward eate of the halowed thynges: for they are his fode.", "dra": "And the sun is down, then being purified, he shall eat of the sanctified things, because it is his meat.", "bbe": "And when the sun has gone down he will be clean; and after that he may take part in the holy food, because it is his bread.", "geneva": "But when the Sunne is downe, hee shalbe cleane, and shall afterward eate of the holy things: for it is his foode.", "wycliffe": "and the sunne hath go doun, thanne he schal be clensid, and schal ete halewid thingis, for it is his mete.", "rotherham": "When the sun tooth in, then is he clean,—and thereafter, he may eat of the hallowed things, for, his food, it is.", "darby": "and when the sun goeth down, he shall be clean, and may afterwards eat of the holy things; for it is his food.", "twenty": "", "jps": "And when the sun is down, he shall be clean; and afterward he may eat of the holy things, because it is his bread.", "acv": "And when the sun is down, he shall be clean, and afterward he shall eat of the holy things, because it is his bread.", "anderson": "", "haweis": "", "noyes": "", "webster": "And when the sun is set, he shall be clean, and shall afterward eat of the holy things, because it [is] his food.", "vulgate": "et occubuerit sol tunc mundatus vescetur de sanctificatis quia cibus illius est;", "brenton": "and the sun go down, and then he shall be clean; and then shall he eat of all the holy things, for they are his bread."}}, {"v": 8, "ref": "22:8", "o": "נְבֵלָ֧ה וּ/טְרֵפָ֛ה לֹ֥א יֹאכַ֖ל לְ/טָמְאָה בָ֑/הּ אֲנִ֖י יְהוָֽה", "en": {"kjv": "That which dieth of itself, or is torn with beasts, he shall not eat to defile himself therewith: I am the Lord.", "web": "That which dies of itself, or is torn by animals, he shall not eat, defiling himself by it. I am Yahweh.", "bsb": "He must not eat anything found dead or torn by wild animals, which would make him unclean. I am the LORD.", "asv": "That which dieth of itself, or is torn of beasts, he shall not eat, to defile himself therewith: I am Jehovah.", "ylt": "a carcase or torn thing he doth not eat, for uncleanness thereby; I am Jehovah.", "tyndale": "Off a beest that dyeth alone or is rent with wylde beastes he shall not eate to defyle him selfe therwith: I am the Lorde.", "dra": "That which dieth of itself, and that which was taken by a beast, they shall not eat, nor be defiled therewith. I am the Lord.", "bbe": "That which comes to a natural death, or is attacked by beasts, he may not take as food, for it will make him unclean: I am the Lord.", "geneva": "Of a beast that dyeth, or is rent with beasts, whereby he may be defiled, hee shall not eate: I am the Lord.", "wycliffe": "He schal not ete a thing deed bi it silf, and takun of a beeste, nethir he schal be defoulid in tho; Y am the Lord.", "rotherham": "That which dieth of itself or is torn in pieces, shall he not eat to make himself unclean thereby,—I, am Yahweh.", "darby": "Of a dead carcase and what is torn shall he not eat, to make himself unclean therewith: I am Jehovah.", "twenty": "", "jps": "That which dieth of itself, or is torn of beasts, he shall not eat to defile himself therewith: I am HaShem.", "acv": "That which dies of itself, or is torn by beasts, he shall not eat to defile himself with it. I am Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "That which dieth of itself, or is torn [by beasts], he shall not eat to defile himself with it: I [am] the LORD.", "vulgate": "morticinum et captum a bestia non comedent nec polluentur in eis ego sum Dominus;", "brenton": "He shall not eat that which dies of itself, or is taken of beasts, so that he should be polluted by them: I am the Lord."}}, {"v": 9, "ref": "22:9", "o": "וְ/שָׁמְר֣וּ אֶת מִשְׁמַרְתִּ֗/י וְ/לֹֽא יִשְׂא֤וּ עָלָי/ו֙ חֵ֔טְא וּ/מֵ֥תוּ ב֖/וֹ כִּ֣י יְחַלְּלֻ֑/הוּ אֲנִ֥י יְהוָ֖ה מְקַדְּשָֽׁ/ם", "en": {"kjv": "They shall therefore keep mine ordinance, lest they bear sin for it, and die therefore, if they profane it: I the Lord do sanctify them.", "web": "“‘They shall therefore follow my requirements, lest they bear sin for it, and die therein, if they profane it. I am Yahweh who sanctifies them.", "bsb": "The priests must keep My charge, lest they bear the guilt and die because they profane it. I am the LORD who sanctifies them.", "asv": "They shall therefore keep my charge, lest they bear sin for it, and die therein, if they profane it: I am Jehovah who sanctifieth them.", "ylt": "`And they have kept My charge, and bear no sin for it, that they have died for it when they pollute it; I am Jehovah sanctifying them.", "tyndale": "But let them kepe therfore myne ordynaunce lest they lade synne apo them and dye therein when they haue defyled them selues: for I am the Lorde which sanctifye them.", "dra": "Let them keep my precepts, that they may not fall into sin, and die in the sanctuary, when they shall have defiled it. I am the Lord who sanctify them.", "bbe": "So then, let them keep what I have put into their care, for fear that sin may come on them because of it, so causing their death because they have made it common: I am the Lord, who make them holy.", "geneva": "Let them keepe therefore mine ordinance, least they beare their sinne for it, and die for it, if they defile it: I the Lord sanctifie them.", "wycliffe": "Thei schulen kepe myn heestis, that thei be not suget to synne, and die in the seyntuarye, whanne thei han defoulid it; Y am the Lord that halewe you.", "rotherham": "Therefore shall they keep my charge, and shall not bear, for it, sin, and die therein, when they profane it,—I—Yahweh, am hallowing them.", "darby": "And they shall keep my charge, lest they bear sin for it, and die by it, if they profane it: I am Jehovah who do hallow them.", "twenty": "", "jps": "They shall therefore keep My charge, lest they bear sin for it, and die therein, if they profane it: I am HaShem who sanctify them.", "acv": "They shall therefore keep my charge, lest they bear sin for it, and die in it if they profane it. I am Jehovah who sanctifies them.", "anderson": "", "haweis": "", "noyes": "", "webster": "They shall therefore keep my ordinance, lest they bear sin for it, and die therefore, if they profane it: I the LORD do sanctify them.", "vulgate": "custodient praecepta mea ut non subiaceant peccato et moriantur in sanctuario cum polluerint illud ego Dominus qui sanctifico eos;", "brenton": "And they shall keep my ordinances, that they do not bear iniquity because of them, and die because of them, if they shall profane them: I am the Lord God that sanctifies them."}}, {"v": 10, "ref": "22:10", "o": "וְ/כָל זָ֖ר לֹא יֹ֣אכַל קֹ֑דֶשׁ תּוֹשַׁ֥ב כֹּהֵ֛ן וְ/שָׂכִ֖יר לֹא יֹ֥אכַל קֹֽדֶשׁ", "en": {"kjv": "There shall no stranger eat of the holy thing: a sojourner of the priest, or an hired servant, shall not eat of the holy thing.", "web": "“‘No stranger shall eat of the holy thing: a foreigner living with the priests, or a hired servant, shall not eat of the holy thing.", "bsb": "No one outside a priest’s family may eat the sacred offering, nor may the guest of a priest or his hired hand eat it.", "asv": "There shall no stranger eat of the holy thing: a sojourner of the priest’s, or a hired servant, shall not eat of the holy thing.", "ylt": "`And no stranger doth eat of the holy thing; a settler of a priest and an hireling doth not eat of the holy thing;", "tyndale": "There shall no straunger eate of the halowed thinges nether a gest of the preastes or an hyred seruaunte.", "dra": "No stranger shall eat of the sanctified things: a sojourner of the priests, or a hired servant, shall not eat of them.", "bbe": "No outside person may take of the holy food, or one living as a guest in the priest's house, or a servant working for payment.", "geneva": "There shall no stranger also eate of the holie thing, neither the ghest of the Priest, neither shall an hired seruant eat of the holie thing:", "wycliffe": "Ech alien schal not ete of thingis halewid; the hyne which is a straunger, and the hirid man of the preest, schulen not ete of tho. Sotheli these seruauntis,", "rotherham": "And, no stranger, shall eat what is hallowed,—neither, one who dwelleth with a priest nor a hireling shall eat what is hallowed.", "darby": "And no stranger shall eat the holy thing; the sojourner with the priest, and the hired servant, shall not eat of the holy thing.", "twenty": "", "jps": "There shall no common man eat of the holy thing; a tenant of a priest, or a hired servant, shall not eat of the holy thing.", "acv": "There shall no stranger eat of the holy thing. A sojourner of the priest's, or a hired servant, shall not eat of the holy thing.", "anderson": "", "haweis": "", "noyes": "", "webster": "There shall no stranger eat [of] the holy thing: a sojourner of the priest, or a hired servant, shall not eat [of] the holy thing.", "vulgate": "omnis alienigena non comedet de sanctificatis inquilinus sacerdotis et mercennarius non vescentur ex eis;", "brenton": "And no stranger shall eat the holy things: one that sojourns with a priest, or a hireling, shall not eat the holy things."}}, {"v": 11, "ref": "22:11", "o": "וְ/כֹהֵ֗ן כִּֽי יִקְנֶ֥ה נֶ֨פֶשׁ֙ קִנְיַ֣ן כַּסְפּ֔/וֹ ה֖וּא יֹ֣אכַל בּ֑/וֹ וִ/ילִ֣יד בֵּית֔/וֹ הֵ֖ם יֹאכְל֥וּ בְ/לַחְמֽ/וֹ", "en": {"kjv": "But if the priest buy any soul with his money, he shall eat of it, and he that is born in his house: they shall eat of his meat.", "web": "But if a priest buys a slave, purchased by his money, he shall eat of it; and such as are born in his house, they shall eat of his bread.", "bsb": "But if a priest buys a slave with his own money, or if a slave is born in his household, that slave may eat his food.", "asv": "But if a priest buy any soul, the purchase of his money, he shall eat of it; and such as are born in his house, they shall eat of his bread.", "ylt": "and when a priest buyeth a person, the purchase of his money, he doth eat of it, also one born in his house; they do eat of his bread.", "tyndale": "But yf the preast bye any soule with money he maye eate of it and he also that is borne in his housse maye eate of his bred.", "dra": "But he whom the priest hath bought, and he that is his servant, born in his house, these shall eat of them.", "bbe": "But any person for whom the priest has given money, to make him his, may take of it with him; and those who come to birth in his house may take of his bread.", "geneva": "But if the Priest bye any with money, he shall eate of it, also he that is borne in his house: they shall eate of his meate.", "wycliffe": "whom the preest hath bouyt, and which is a borun seruaunt of his hows, schulen ete of tho.", "rotherham": "But when, a priest, buyeth any person, as the purchase of his silver, he may eat thereof,—and, the children of his household, they, may eat of his food.", "darby": "But if a priest buy any one for money, he may eat of it, and he that is born in his house: they may eat of his food.", "twenty": "", "jps": "But if a priest buy any soul, the purchase of his money, he may eat of it; and such as are born in his house, they may eat of his bread.", "acv": "But if a priest buys any soul, the purchase of his money, he shall eat of it, and such as are born in his house, they shall eat of his bread.", "anderson": "", "haweis": "", "noyes": "", "webster": "But if the priest shall buy [any] soul with his money, he shall eat of it, and he that is born in his house: they shall eat of his meat.", "vulgate": "quem autem sacerdos emerit et qui vernaculus domus eius fuerit hii comedent ex eis;", "brenton": "But if a priest should have a soul purchased for money, he shall eat of his bread; and they that are born in his house, they also shall eat of his bread."}}, {"v": 12, "ref": "22:12", "o": "וּ/בַת כֹּהֵ֔ן כִּ֥י תִהְיֶ֖ה לְ/אִ֣ישׁ זָ֑ר הִ֕וא בִּ/תְרוּמַ֥ת הַ/קֳּדָשִׁ֖ים לֹ֥א תֹאכֵֽל", "en": {"kjv": "If the priest’s daughter also be married unto a stranger, she may not eat of an offering of the holy things.", "web": "If a priest’s daughter is married to an outsider, she shall not eat of the heave offering of the holy things.", "bsb": "If the priest’s daughter is married to a man other than a priest, she is not to eat of the sacred contributions.", "asv": "And if a priest’s daughter be married unto a stranger, she shall not eat of the heave-offering of the holy things.", "ylt": "`And a priest's daughter, when she is a strange man's, --she, of the heave-offering of the holy things doth not eat;", "tyndale": "Yf the preastes doughter be maryed vnto a straunger she maye not eate of the halowed heueofferynges.", "dra": "If the daughter of a priest be married to any of the people, she shall not eat of those things that are sanctified nor of the firstfruits.", "bbe": "And if the daughter of a priest is married to an outside person she may not take of the holy things which are lifted up as offerings.", "geneva": "If the Priests daughter also be maried vnto a stranger, she may not eate of the holy offrings.", "wycliffe": "If the `douyter of the preest is weddid to ony of the puple, sche schal not ete of these thingis that ben halewid, and of the firste fruytis;", "rotherham": "And, when, a priest’s daughter, belongeth to a husband, who is a stranger, she, of the heave-offering of the hallowed things, may not eat.", "darby": "And a priest's daughter who is [married] to a stranger may not eat of the heave-offering of the holy things.", "twenty": "", "jps": "And if a priest's daughter be married unto a common man, she shall not eat of that which is set apart from the holy things.", "acv": "And if a priest's daughter be married to a stranger, she shall not eat of the heave offering of the holy things.", "anderson": "", "haweis": "", "noyes": "", "webster": "If the priest's daughter also shall be [married] to a stranger, she may not eat of an offering of the holy things.", "vulgate": "si filia sacerdotis cuilibet ex populo nupta fuerit de his quae sanctificata sunt et de primitiis non vescetur;", "brenton": "And if the daughter of a priest should marry a stranger, she shall not eat of the offerings of the sanctuary."}}, {"v": 13, "ref": "22:13", "o": "וּ/בַת כֹּהֵן֩ כִּ֨י תִהְיֶ֜ה אַלְמָנָ֣ה וּ/גְרוּשָׁ֗ה וְ/זֶרַע֮ אֵ֣ין לָ/הּ֒ וְ/שָׁבָ֞ה אֶל בֵּ֤ית אָבִ֨י/הָ֙ כִּ/נְעוּרֶ֔י/הָ מִ/לֶּ֥חֶם אָבִ֖י/הָ תֹּאכֵ֑ל וְ/כָל זָ֖ר לֹא יֹ֥אכַל בּֽ/וֹ", "en": {"kjv": "But if the priest’s daughter be a widow, or divorced, and have no child, and is returned unto her father’s house, as in her youth, she shall eat of her father’s meat: but there shall no stranger eat thereof.", "web": "But if a priest’s daughter is a widow, or divorced, and has no child, and has returned to her father’s house, as in her youth, she may eat of her father’s bread: but no stranger shall eat any of it.", "bsb": "But if a priest’s daughter with no children becomes widowed or divorced and returns to her father’s house, she may share her father’s food as in her youth. But no outsider may share it.", "asv": "But if a priest’s daughter be a widow, or divorced, and have no child, and be returned unto her father’s house, as in her youth, she shall eat of her father’s bread: but there shall no stranger eat thereof.", "ylt": "and a priest's daughter, when she is a widow, or cast out, and hath no seed, and hath turned back unto the house of her father, as in her youth, of her father's bread she doth eat; but no stranger doth eat of it.", "tyndale": "Notwithstondynge yf the preastes doughter be a wedowe or deuorsed and haueno childe but is returned vnto hir fathers housse agayne she shall eate of hir fathers bred as wel as she dyd in hyr youth. But thereshall no straunger eate there of.", "dra": "But if she be a widow, or divorced, and having no children return to her father's house, she shall eat of her father's meats, as she was wont to do when she was a maid. No stranger hath leave to eat of them.", "bbe": "But if a priest's daughter is a widow, or parted from her husband, and has no child, and has come back to her father's house as when she was a girl, she may take of her father's bread; but no outside person may do so.", "geneva": "Notwithstanding if the Priests daughter be a widowe or diuorced, and haue no childe, but is returned vnto her fathers house shee shall eate of her fathers bread, as she did in her youth but there shall no stranger eate thereof.", "wycliffe": "sotheli if sche is a widewe, ether forsakun, and turneth ayen with out fre children to `the hows of hir fadir, sche schal be susteyned bi the metis of hir fadir, as a damysel was wont; ech alien hath not power to ete of tho.", "rotherham": "But, when a priest’s daughter, cometh to be a widow or divorced and hath no seed, and so she returneth unto the house of her father, as in her youth, of the food of her father, she may eat,—but no stranger, shall eat thereof.", "darby": "But a priest's daughter that becometh a widow, or is divorced, and hath no seed, and returneth unto her father's house, as in her youth, she may eat of her father's food; but no stranger shall eat thereof.", "twenty": "", "jps": "But if a priest's daughter be a widow, or divorced, and have no child, and is returned unto her father's house, as in her youth, she may eat of her father's bread; but there shall no common man eat thereof.", "acv": "But if a priest's daughter be a widow, or divorced, and have no child, and is returned to her father's house, as in her youth, she shall eat of her father's bread, but there shall no stranger eat of it.", "anderson": "", "haweis": "", "noyes": "", "webster": "But if the priest's daughter shall be a widow, or divorced, and shall have no child, and have returned to her father's house, as in her youth, she shall eat of her father's meat; but there shall no stranger eat of it.", "vulgate": "sin autem vidua vel repudiata et absque liberis reversa fuerit ad domum patris sui sicut puella consuerat aletur cibis patris sui omnis alienigena comedendi ex eis non habet potestatem;", "brenton": "And if the daughter of priest should be a widow, or put away, and have no seed, she shall return to her father's house, as in her youth: she shall eat of her father's bread, but no stranger shall eat of it."}}, {"v": 14, "ref": "22:14", "o": "וְ/אִ֕ישׁ כִּֽי יֹאכַ֥ל קֹ֖דֶשׁ בִּ/שְׁגָגָ֑ה וְ/יָסַ֤ף חֲמִֽשִׁית/וֹ֙ עָלָ֔י/ו וְ/נָתַ֥ן לַ/כֹּהֵ֖ן אֶת הַ/קֹּֽדֶשׁ", "en": {"kjv": "And if a man eat of the holy thing unwittingly, then he shall put the fifth part thereof unto it, and shall give it unto the priest with the holy thing.", "web": "“‘If a man eats something holy unwittingly, then he shall add the fifth part of its value to it, and shall give the holy thing to the priest.", "bsb": "If anyone eats a sacred offering in error, he must add a fifth to its value and give the sacred offering to the priest.", "asv": "And if a man eat of the holy thing unwittingly, then he shall put the fifth part thereof unto it, and shall give unto the priest the holy thing.", "ylt": "`And when a man doth eat of a holy thing through ignorance, then he hath added its fifth part to it, and hath given it to the priest, with the holy thing;", "tyndale": "Yf a man eate of the halowed thynges vnwyttingly he shall put the fyfte parte there vnto and make good vnto the preast the halowed thynge.", "dra": "He that eateth of the sanctified things through ignorance, shall add the fifth part with that which he ate, and shall give it to the priest into the sanctuary.", "bbe": "And if a man takes the holy food in error, he will have to give the holy thing back to the priest, with the addition of a fifth part.", "geneva": "If a man eate of the holie thing vnwittingly, he shall put the fift part thereunto, and giue it vnto the Priest with the halowed thing.", "wycliffe": "He that etith bi ignoraunce of halewid thingis, schal adde the fyuethe part with that that he eet, and `schal yyue to the preest in seyntuarie,", "rotherham": "And, when, any man, eateth what is hallowed, by mistake, then shall he add the fifth part of it thereunto, and give unto the priest the hallowed thing:", "darby": "And if a man eat of a holy thing through inadvertence, then he shall put the fifth part thereof unto it, and shall give it unto the priest with the holy thing.", "twenty": "", "jps": "And if a man eat of the holy thing through error, then he shall put the fifth part thereof unto it, and shall give unto the priest the holy thing.", "acv": "And if a man eats of the holy thing unwittingly, then he shall put the fifth part of it to it, and shall give the holy thing to the priest.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if a man shall eat [of] the holy thing unknowingly, then he shall put to it the fifth [part], and shall give [it] to the priest, with the holy thing.", "vulgate": "qui comederit de sanctificatis per ignorantiam addet quintam partem cum eo quod comedit et dabit sacerdoti in sanctuarium;", "brenton": "And the man who shall ignorantly eat holy things, shall add the fifth part to it, and give the holy thing to the priest."}}, {"v": 15, "ref": "22:15", "o": "וְ/לֹ֣א יְחַלְּל֔וּ אֶת קָדְשֵׁ֖י בְּנֵ֣י יִשְׂרָאֵ֑ל אֵ֥ת אֲשֶׁר יָרִ֖ימוּ לַ/יהוָֽה", "en": {"kjv": "And they shall not profane the holy things of the children of Israel, which they offer unto the Lord;", "web": "The priests shall not profane the holy things of the children of Israel, which they offer to Yahweh,", "bsb": "The priests must not profane the sacred offerings that the Israelites present to the LORD", "asv": "And they shall not profane the holy things of the children of Israel, which they offer unto Jehovah,", "ylt": "and they do not pollute the holy things of the sons of Israel--that which they lift up to Jehovah,", "tyndale": "And let the preastes see that they defyle not the halowed thynges of the childern of Israel which they haue offered vnto the Lorde", "dra": "And they shall not profane the sanctified things of the children of Israel, which they offer to the Lord:", "bbe": "And they may not make common the holy things which the children of Israel give to the Lord,", "geneva": "So they shall not defile the holy things of the children of Israel, which they offer vnto the Lord,", "wycliffe": "and thei schulen not defoule the halewid thingis of the sones of Israel, whiche thei offren to the Lord,", "rotherham": "So shall they not profane the hallowed things of the sons of Israel,—which they heave up unto Yahweh;", "darby": "And they shall not profane the holy things of the children of Israel which they offer unto Jehovah,", "twenty": "", "jps": "And they shall not profane the holy things of the children of Israel, which they set apart unto HaShem;", "acv": "And they shall not profane the holy things of the sons of Israel, which they offer to Jehovah,", "anderson": "", "haweis": "", "noyes": "", "webster": "And they shall not profane the holy things of the children of Israel which they offer to the LORD;", "vulgate": "nec contaminabunt sanctificata filiorum Israhel quae offerunt Domino;", "brenton": "And they shall not profane the holy things of the children of Israel, which they offer to the Lord."}}, {"v": 16, "ref": "22:16", "o": "וְ/הִשִּׂ֤יאוּ אוֹתָ/ם֙ עֲוֺ֣ן אַשְׁמָ֔ה בְּ/אָכְלָ֖/ם אֶת קָדְשֵׁי/הֶ֑ם כִּ֛י אֲנִ֥י יְהוָ֖ה מְקַדְּשָֽׁ/ם", "en": {"kjv": "Or suffer them to bear the iniquity of trespass, when they eat their holy things: for I the Lord do sanctify them.", "web": "and so cause them to bear the iniquity that brings guilt, when they eat their holy things; for I am Yahweh who sanctifies them.’”", "bsb": "by allowing the people to eat the sacred offerings and thus to bear the punishment for guilt. For I am the LORD who sanctifies them.”", "asv": "and so cause them to bear the iniquity that bringeth guilt, when they eat their holy things: for I am Jehovah who sanctifieth them.", "ylt": "nor have caused them to bear the iniquity of the guilt-offering in their eating their holy things; for I am Jehovah, sanctifying them.'", "tyndale": "lest they lade them selues with mysdoynge and trespace in eatynge their halowed thinges: for I am the Lorde which halowe them.", "dra": "Lest perhaps they bear the iniquity of their trespass, when they shall have eaten the sanctified things. I am the Lord who sanctify them.", "bbe": "So causing sin to come on them when they take their holy things for food: I am the Lord who make them holy.", "geneva": "Neither cause the people to beare the iniquitie of their trespas, while they eate their holy thing: for I the Lord do halowe them.", "wycliffe": "lest perauenture thei suffren the wickidnesse of her trespas, whanne thei han ete halewid thingis; Y am the Lord that `halewe hem. The Lord spak to Moises, and seide, Speke thou to Aaron and to hise sones, and to alle the sones of Israel, and thou schalt seie to hem, A man of the hous of Israel and of comelyngis that dwellen at hem, which offrith his offryng to the Lord, and ethir paieth avowis, ethir offrith bi his fre wille, what euer thing he offrith in to brent sacrifice of the Lord, that it be offrid bi you,", "rotherham": "nor cause them to bear guilty iniquity, when they eat their hallowed things,—For, I—Yahweh, am hallowing them.", "darby": "and cause them to bear the iniquity of trespass when they eat their holy things; for I am Jehovah who do hallow them.", "twenty": "", "jps": "and so cause them to bear the iniquity that bringeth guilt, when they eat their holy things; for I am HaShem who sanctify them.", "acv": "and so cause them to bear the iniquity that brings guilt when they eat their holy things, for I am Jehovah who sanctifies them.", "anderson": "", "haweis": "", "noyes": "", "webster": "Or suffer them to bear the iniquity of trespass, when they eat their holy things: for I the LORD do sanctify them.", "vulgate": "ne forte sustineant iniquitatem delicti sui cum sanctificata comederint ego Dominus qui sanctifico eos;", "brenton": "So should they bring upon themselves the iniquity of trespass in their eating their holy things: for I am the Lord that sanctifies them."}}, {"v": 17, "ref": "22:17", "o": "וַ/יְדַבֵּ֥ר יְהוָ֖ה אֶל מֹשֶׁ֥ה לֵּ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh spoke to Moses, saying,", "bsb": "Then the LORD said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde spake vnto Moses saynge:", "dra": "And the Lord spoke to Moses, saying:", "bbe": "And the Lord said to Moses,", "geneva": "And the Lord spake vnto Moses, saying,", "wycliffe": "", "rotherham": "And Yahweh spake unto Moses, saying:", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses, saying:", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "locutus est Dominus ad Mosen dicens;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 18, "ref": "22:18", "o": "דַּבֵּ֨ר אֶֽל אַהֲרֹ֜ן וְ/אֶל בָּנָ֗י/ו וְ/אֶל֙ כָּל בְּנֵ֣י יִשְׂרָאֵ֔ל וְ/אָמַרְתָּ֖ אֲלֵ/הֶ֑ם אִ֣ישׁ אִישׁ֩ מִ/בֵּ֨ית יִשְׂרָאֵ֜ל וּ/מִן הַ/גֵּ֣ר בְּ/יִשְׂרָאֵ֗ל אֲשֶׁ֨ר יַקְרִ֤יב קָרְבָּנ/וֹ֙ לְ/כָל נִדְרֵי/הֶם֙ וּ/לְ/כָל נִדְבוֹתָ֔/ם אֲשֶׁר יַקְרִ֥יבוּ לַ/יהוָ֖ה לְ/עֹלָֽה", "en": {"kjv": "Speak unto Aaron, and to his sons, and unto all the children of Israel, and say unto them, Whatsoever he be of the house of Israel, or of the strangers in Israel, that will offer his oblation for all his vows, and for all his freewill offerings, which they will offer unto the Lord for a burnt offering;", "web": "“Speak to Aaron, and to his sons, and to all the children of Israel, and say to them, ‘Whoever is of the house of Israel, or of the foreigners in Israel, who offers his offering, whether it be any of their vows, or any of their freewill offerings, which they offer to Yahweh for a burnt offering;", "bsb": "“Speak to Aaron and his sons and all the Israelites and tell them, ‘Any man of the house of Israel or any foreign resident who presents a gift for a burnt offering to the LORD, whether to fulfill a vow or as a freewill offering,", "asv": "Speak unto Aaron, and to his sons, and unto all the children of Israel, and say unto them, Whosoever he be of the house of Israel, or of the sojourners in Israel, that offereth his oblation, whether it be any of their vows, or any of their freewill-offerings, which they offer unto Jehovah for a burnt-offering;", "ylt": "`Speak unto Aaron, and unto his sons, and unto all the sons of Israel, and thou hast said unto them, Any man of the house of Israel, or of the sojourners in Israel, who bringeth near his offering, of all his vows, or of all his willing offerings which they bring near to Jehovah for a burnt-offering;", "tyndale": "speake vnto Aaron and his sonnes and vnto all the childern of Israel and saye vnto them what soeuer he be of the housse of Israel or straunger in Israel that will offer his offerynge: what soeuer vowe or frewillofferynge it be which they will offer vnto the Lorde for a burntofferynge", "dra": "Speak to Aaron, and to his sons, and to all the children of Israel, and thou shalt say to them: The man of the house of Israel, and of the strangers who dwell with you, that offereth his oblation, either paying his vows, or offering of his own accord, whatsoever it be which he presenteth for a holocaust of the Lord,", "bbe": "Say to Aaron and to his sons and to all the children of Israel, If any man of the children of Israel, or of another nation living in Israel, makes an offering, given because of an oath or freely given to the Lord for a burned offering;", "geneva": "Speake vnto Aaron, and to his sonnes, and to all the children of Israel, and say vnto them, Whosoeuer he be of the house of Israel, or of the strangers in Israel, that will offer his sacrifice for all their vowes, and for all their free offrings, which they vse to offer vnto the Lord for a burnt offring,", "wycliffe": "", "rotherham": "Speak unto Aaron, and unto his sons, and unto all the sons of Israel, and thou shalt say unto them—What man, soever, of the house of Israel, or of the sojourners in Israel, may bring near his oblation, as regardeth any of their vows, or any of their freewill offerings which they may bring near unto Yahweh, as an ascending-sacrifice,", "darby": "Speak unto Aaron, and to his sons, and unto all the children of Israel, and say unto them, Whatever man of the house of Israel, or of the sojourners in Israel, that presenteth his offering for any of his vows, and for any of his voluntary offerings, which they present to Jehovah as a burnt-offering,", "twenty": "", "jps": "Speak unto Aaron, and to his sons, and unto all the children of Israel, and say unto them: Whosoever he be of the house of Israel, or of the strangers in Israel, that bringeth his offering, whether it be any of their vows, or any of their free-will-offerings, which are brought unto HaShem for a burnt-offering;", "acv": "Speak to Aaron, and to his sons, and to all the sons of Israel, and say to them, Whoever he is of the house of Israel, or of the sojourners in Israel, who offers his oblation, whether it be any of their vows, or any of their freewill offerings, which they offer to Jehovah for a burnt offering,", "anderson": "", "haweis": "", "noyes": "", "webster": "Speak to Aaron, and to his sons, and to all the children of Israel, and say to them, Whoever [he may be] of the house of Israel, or of the strangers in Israel, that will offer his oblation for all his vows, and for all his free-will-offerings, which they will offer to the LORD for a burnt-offering:", "vulgate": "loquere ad Aaron et filios eius et ad omnes filios Israhel dicesque ad eos homo de domo Israhel et de advenis qui habitant apud vos qui obtulerit oblationem suam vel vota solvens vel sponte offerens quicquid illud obtulerit in holocaustum Domini;", "brenton": "Speak to Aaron and his sons, and to all the congregation of Israel, and thou shalt say to them, Any man of the children of Israel, or of the strangers that abide among them in Israel, who shall offer his gifts according to all their confession and according to all their choice, whatsoever they may bring to the Lord for whole-burnt-offerings—"}}, {"v": 19, "ref": "22:19", "o": "לִֽ/רְצֹנְ/כֶ֑ם תָּמִ֣ים זָכָ֔ר בַּ/בָּקָ֕ר בַּ/כְּשָׂבִ֖ים וּ/בָֽ/עִזִּֽים", "en": {"kjv": "Ye shall offer at your own will a male without blemish, of the beeves, of the sheep, or of the goats.", "web": "that you may be accepted, you shall offer a male without defect, of the bulls, of the sheep, or of the goats.", "bsb": "must offer an unblemished male from the cattle, sheep, or goats in order for it to be accepted on your behalf.", "asv": "that ye may be accepted, ye shall offer a male without blemish, of the bullocks, of the sheep, or of the goats.", "ylt": "at your pleasure a perfect one, a male of the herd, of the sheep or of the goats;", "tyndale": "to reconcyle them selues it must be a male without blemysh of the oxen shepe or gootes.", "dra": "To be offered by you: it shall be a male without blemish of the beeves, or of the sheep, or of the goats.", "bbe": "So that it may be pleasing to the Lord, let him give a male, without any mark, from among the oxen or the sheep or the goats.", "geneva": "Yee shall offer of your free minde a male without blemish of the beeues, of the sheepe, or of the goates.", "wycliffe": "it schal be a male without wem, of oxen, and of scheep, and of geet; if it hath a wem,", "rotherham": "that ye may be accepted, [it must be] a male without defect, of the beeves, or of the sheep, or of the goats:", "darby": "it shall be for your acceptance, without blemish, a male of the oxen, of the sheep, and of the goats.", "twenty": "", "jps": "that ye may be accepted, ye shall offer a male without blemish, of the beeves, of the sheep, or of the goats.", "acv": "that ye may be accepted, ye shall offer a male without blemish, of the bullocks, of the sheep, or of the goats.", "anderson": "", "haweis": "", "noyes": "", "webster": "[Ye shall offer] at your own will a male without blemish of the beeves, of the sheep, or of the goats.", "vulgate": "ut offeratur per vos masculus inmaculatus erit ex bubus et ex ovibus et ex capris;", "brenton": "your free-will-offerings shall be males without blemish of the herds, or of the sheep, or of the goats."}}, {"v": 20, "ref": "22:20", "o": "כֹּ֛ל אֲשֶׁר בּ֥/וֹ מ֖וּם לֹ֣א תַקְרִ֑יבוּ כִּי לֹ֥א לְ/רָצ֖וֹן יִהְיֶ֥ה לָ/כֶֽם", "en": {"kjv": "But whatsoever hath a blemish, that shall ye not offer: for it shall not be acceptable for you.", "web": "But whatever has a defect, that you shall not offer; for it shall not be acceptable for you.", "bsb": "You must not present anything with a defect, because it will not be accepted on your behalf.", "asv": "But whatsoever hath a blemish, that shall ye not offer: for it shall not be acceptable for you.", "ylt": "nothing in which is blemish do ye bring near, for it is not for a pleasing thing for you.", "tyndale": "let them offer nothynge that is deformed for they shall gett no fauoure there with.", "dra": "If it have a blemish you shall not offer it: neither shall it be acceptable.", "bbe": "But anything which has a mark you may not give; it will not make you pleasing to the Lord.", "geneva": "Ye shall not offer any thing that hath a blemish: for that shall not be acceptable for you.", "wycliffe": "ye schulen not offre, nether it schal be acceptable.", "rotherham": "whatsoever hath in it a blemish, shall ye not bring near,—for it shall not be accepted for you.", "darby": "Nothing that hath a defect shall ye present; for it shall not be acceptable for you.", "twenty": "", "jps": "But whatsoever hath a blemish, that shall ye not bring; for it shall not be acceptable for you.", "acv": "But whatever has a blemish, that ye shall not offer, for it shall not be acceptable for you.", "anderson": "", "haweis": "", "noyes": "", "webster": "[But] whatever hath a blemish, [that] shall ye not offer: for it shall not be acceptable for you.", "vulgate": "si maculam habuerit non offeretis neque erit acceptabile;", "brenton": "They shall not bring to the Lord anything that has a blemish in it, for it shall not be acceptable for you."}}, {"v": 21, "ref": "22:21", "o": "וְ/אִ֗ישׁ כִּֽי יַקְרִ֤יב זֶֽבַח שְׁלָמִים֙ לַ/יהוָ֔ה לְ/פַלֵּא נֶ֨דֶר֙ א֣וֹ לִ/נְדָבָ֔ה בַּ/בָּקָ֖ר א֣וֹ בַ/צֹּ֑אן תָּמִ֤ים יִֽהְיֶה֙ לְ/רָצ֔וֹן כָּל מ֖וּם לֹ֥א יִהְיֶה בּֽ/וֹ", "en": {"kjv": "And whosoever offereth a sacrifice of peace offerings unto the Lord to accomplish his vow, or a freewill offering in beeves or sheep, it shall be perfect to be accepted; there shall be no blemish therein.", "web": "Whoever offers a sacrifice of peace offerings to Yahweh to accomplish a vow, or for a freewill offering, of the herd or of the flock, it shall be perfect to be accepted. It shall have no defect.", "bsb": "When a man presents a peace offering to the LORD from the herd or flock to fulfill a vow or as a freewill offering, it must be without blemish or defect to be acceptable.", "asv": "And whosoever offereth a sacrifice of peace-offerings unto Jehovah to accomplish a vow, or for a freewill-offering, of the herd or of the flock, it shall be perfect to be accepted; there shall be no blemish therein.", "ylt": "`And when a man bringeth near a sacrifice of peace-offerings to Jehovah, to complete a vow, or for a willing-offering, of the herd or of the flock, it is perfect for a pleasing thing: no blemish is in it;", "tyndale": "Yf a man will offer a peaseoffrynge vnto the Lorde and separate a vowe or a frewill offerynge of the oxen or the flocke it must be without deformyte that it maye be accepted. There maye be no blemysh therein:", "dra": "The man that offereth a victim of peace offerings to the Lord, either paying his vows, or offering of his own accord, whether of beeves or of sheep, shall offer it without blemish, that it may be acceptable. There shall be no blemish in it.", "bbe": "And whoever makes a peace-offering to the Lord, in payment of an oath or as a free offering, from the herd or the flock, if it is to be pleasing to the Lord, let it be free from any mark or damage.", "geneva": "And whosoeuer bringeth a peace offring vnto ye Lord to accomplish his vowe, or for a free offring, of the beeues, or of the sheepe, his free offring shall bee perfect, no blemish shalbe in it.", "wycliffe": "A man that offrith a sacrifice of pesyble thingis to the Lord, and ethir paieth auowis, ethir offrith bi fre wille, as wel of oxun as of scheep, he schal offre a beeste without wem, that it be acceptable; ech wem schal not be ther ynne.", "rotherham": "And, whosoever would bring near a peace-offering unto Yahweh, to consecrate a vow or as a freewill-offering with a bullock or a sheep, without defect, shall it be, to be accepted, no, blemish, shall be therein.", "darby": "And if any present a sacrifice of peace-offering to Jehovah to accomplish a vow, or a voluntary offering of oxen or small cattle, it shall be without blemish to be accepted: there shall be no defect therein.", "twenty": "", "jps": "And whosoever bringeth a sacrifice of peace-offerings unto HaShem in fulfilment of a vow clearly uttered, or for a freewill-offering, of the herd or of the flock, it shall be perfect to be accepted; there shall be no blemish therein.", "acv": "And whoever offers a sacrifice of peace offerings to Jehovah to accomplish a vow, or for a freewill offering, of the herd or of the flock, it shall be perfect to be accepted; there shall be no blemish in it.", "anderson": "", "haweis": "", "noyes": "", "webster": "And whoever offereth a sacrifice of peace-offerings to the LORD to accomplish [his] vow, or a free-will-offering in beeves, or sheep, it shall be perfect to be accepted: there shall be in it no blemish.", "vulgate": "homo qui obtulerit victimam pacificorum Domino vel vota solvens vel sponte offerens tam de bubus quam de ovibus inmaculatum offeret ut acceptabile sit omnis macula non erit in eo;", "brenton": "And whatsoever man shall offer a peace-offering to the Lord, discharging a vow, or in the way of free-will-offering, or an offering in your feasts, of the herds or of the sheep, it shall be without blemish for acceptance: there shall be no blemish in it."}}, {"v": 22, "ref": "22:22", "o": "עַוֶּרֶת֩ א֨וֹ שָׁב֜וּר אוֹ חָר֣וּץ אֽוֹ יַבֶּ֗לֶת א֤וֹ גָרָב֙ א֣וֹ יַלֶּ֔פֶת לֹא תַקְרִ֥יבוּ אֵ֖לֶּה לַ/יהוָ֑ה וְ/אִשֶּׁ֗ה לֹא תִתְּנ֥וּ מֵ/הֶ֛ם עַל הַ/מִּזְבֵּ֖חַ לַ/יהוָֽה", "en": {"kjv": "Blind, or broken, or maimed, or having a wen, or scurvy, or scabbed, ye shall not offer these unto the Lord, nor make an offering by fire of them upon the altar unto the Lord.", "web": "Blind, injured, maimed, having a wart, festering, or having a running sore: you shall not offer these to Yahweh, nor make an offering by fire of them on the altar to Yahweh.", "bsb": "You are not to present to the LORD any animal that is blind, injured, or maimed, or anything with a running sore, a festering rash, or a scab; you must not put any of these on the altar as an offering made by fire to the LORD.", "asv": "Blind, or broken, or maimed, or having a wen, or scurvy, or scabbed, ye shall not offer these unto Jehovah, nor make an offering by fire of them upon the altar unto Jehovah.", "ylt": "blind, or broken, or maimed, or having a wen, or scurvy, or scabbed--ye do not bring these near to Jehovah, and a fire-offering ye do not make of them on the altar to Jehovah.", "tyndale": "whether it be blide, broke, wounded or haue a wen, or be maunge or scabbed. se that ye offre no soch vnto the Lorde, nor put an offerynge of any soch apon the alter vnto the Lorde.", "dra": "If it be blind, or broken, or have a scar or blisters, or a scab, or a dry scurf: you shall not offer them to the Lord, nor burn any thing of them upon the Lord's altar.", "bbe": "Anything blind or broken or damaged or having any disease or any mark on it may not be offered to the Lord; you may not make an offering of it by fire on the altar to the Lord.", "geneva": "Blinde, or broken, or maimed, or hauing a wenne, or skiruie, or skabbed: these shall yee not offer vnto the Lord nor make an offring by fire of these vpon the altar of the Lord.", "wycliffe": "If it is blynd, if it is brokun, if it hath a scar, if it hath whelkis, ether scabbe, ethir drie scabbe, ye schulen not offre tho beestis to the Lord, nether ye schulen brenne of tho beestis on the auter of the Lord.", "rotherham": "Blind, or broken, or rent, or having a running sore, or scurvy, or scab, ye shall not bring these near unto Yahweh,—and no, altar-flame, shall ye present therefrom upon the altar, unto Yahweh.", "darby": "Blind, or broken, or maimed, or ulcerous, or with itch, or scabbed — ye shall not present these to Jehovah, nor make an offering by fire of them on the altar to Jehovah.", "twenty": "", "jps": "Blind, or broken, or maimed, or having a wen, or scabbed, or scurvy, ye shall not offer these unto HaShem, nor make an offering by fire of them upon the altar unto HaShem.", "acv": "Blind, or broken, or maimed, or having a skin tumor, or scurvy, or scabbed, ye shall not offer these to Jehovah, nor make an offering by fire of them upon the altar to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "Blind, or broken, or maimed, or having a wen, or scurvy, or scabbed, ye shall not offer these to the LORD, nor make an offering by fire of them upon the altar to the LORD.", "vulgate": "si caecum fuerit si fractum si cicatricem habens si papulas aut scabiem vel inpetiginem non offeretis ea Domino neque adolebitis ex eis super altare Domini;", "brenton": "One that is blind, or broken, or has its tongue cut out, or is troubled with warts, or has a malignant ulcer, or tetters, they shall not offer these to the Lord; neither shall ye offer any of them for a burnt-offering on the altar of the Lord."}}, {"v": 23, "ref": "22:23", "o": "וְ/שׁ֥וֹר וָ/שֶׂ֖ה שָׂר֣וּעַ וְ/קָל֑וּט נְדָבָה֙ תַּעֲשֶׂ֣ה אֹת֔/וֹ וּ/לְ/נֵ֖דֶר לֹ֥א יֵרָצֶֽה", "en": {"kjv": "Either a bullock or a lamb that hath any thing superfluous or lacking in his parts, that mayest thou offer for a freewill offering; but for a vow it shall not be accepted.", "web": "Either a bull or a lamb that has any deformity or lacking in his parts, that you may offer for a freewill offering; but for a vow it shall not be accepted.", "bsb": "You may present as a freewill offering an ox or sheep that has a deformed or stunted limb, but it is not acceptable in fulfillment of a vow.", "asv": "Either a bullock or a lamb that hath anything superfluous or lacking in his parts, that mayest thou offer for a freewill-offering; but for a vow it shall not be accepted.", "ylt": "`As to an ox or a sheep enlarged or dwarfed--a willing-offering ye do make it, but for a vow it is not pleasing.", "tyndale": "An oxe or a shepe that hath any membre out of proporcion, mayst thou offer for a frewillofferynge: but in a vowe it shal not accepted.", "dra": "An ox or a sheep, that hath the ear and the tail cut off, thou mayst offer voluntarily: but a vow may not be paid with them.", "bbe": "An ox or a lamb which has more or less than its natural parts, may be given as a free offering; but it will not be taken in payment of an oath.", "geneva": "Yet a bullocke, or a sheepe that hath any member superfluous, or lacking, such mayest thou present for a free offring, but for a vowe it shall not be accepted.", "wycliffe": "A man may offre wilfuli an oxe and scheep , whanne the eere and tail ben kit of; but avow may not be paied of these beestis.", "rotherham": "Whether an ox or a lamb long or short limb, as a free-will offering, thou mayest offer it, but, for a vow, it shall not be accepted.", "darby": "A bullock and a sheep that hath a member too long or too short, that mayest thou offer as a voluntary offering; but as a vow it shall not be accepted.", "twenty": "", "jps": "Either a bullock or a lamb that hath any thing too long or too short, that mayest thou offer for a freewill-offering; but for a vow it shall not be accepted.", "acv": "Either a bullock or a lamb that has anything superfluous or lacking in his parts, that thou may offer for a freewill offering, but it shall not be accepted for a vow.", "anderson": "", "haweis": "", "noyes": "", "webster": "Either a bullock, or a lamb that hath any thing superfluous or lacking in his parts, that mayest thou offer [for] a free-will-offering; but for a vow it shall not be accepted.", "vulgate": "bovem et ovem aure et cauda amputatis voluntarie offerre potes votum autem ex his solvi non potest;", "brenton": "And a calf or a sheep with the ears cut off, or that has lost its tail, thou shalt slay them for thyself; but they shall not be accepted for thy vow."}}, {"v": 24, "ref": "22:24", "o": "וּ/מָע֤וּךְ וְ/כָתוּת֙ וְ/נָת֣וּק וְ/כָר֔וּת לֹ֥א תַקְרִ֖יבוּ לַֽ/יהוָ֑ה וּֽ/בְ/אַרְצְ/כֶ֖ם לֹ֥א תַעֲשֽׂוּ", "en": {"kjv": "Ye shall not offer unto the Lord that which is bruised, or crushed, or broken, or cut; neither shall ye make any offering thereof in your land.", "web": "That which has its testicles bruised, crushed, broken, or cut, you shall not offer to Yahweh; neither shall you do thus in your land.", "bsb": "You are not to present to the LORD an animal whose testicles are bruised, crushed, torn, or cut; you are not to sacrifice them in your land.", "asv": "That which hath its stones bruised, or crushed, or broken, or cut, ye shall not offer unto Jehovah; neither shall ye do thus in your land.", "ylt": "As to a bruised, or beaten, or enlarged, or cut thing--ye do not bring it near to Jehovah; even in your land ye do not do it.", "tyndale": "Thou shalt not offer vnto the Lorde that which hath his stones broosed broke, plucked out or cutt awaye, nether shalt make any soch in youre lande,", "dra": "you shall not offer to the Lord any beast that hath the testicles bruised, or crushed, or cut and taken away: neither shall you do any such things in your land.", "bbe": "An animal which has its sex parts damaged or crushed or broken or cut, may not be offered to the Lord; such a thing may not be done anywhere in your land.", "geneva": "Ye shall not offer vnto ye Lord that which is bruised or crusshed, or broken, or cut away, neither shall ye make an offring thereof in your land,", "wycliffe": "Ye schulen not offre to the Lord ony beeste, whose priuy membris ben brokun, ethir brisid, ether kit, and takun awey, and outerli ye schulen not do these thingis in youre lond.", "rotherham": "But that which is bruised in the stones or broken therein, or torn or cut, shall ye neither bring ear unto Yahweh, nor on your own land, shall ye offer.", "darby": "That which is bruised, or crushed, or broken, or cut shall ye not present to Jehovah; neither in your land shall ye do [the like].", "twenty": "", "jps": "That which hath its stones bruised, or crushed, or torn, or cut, ye shall not offer unto HaShem; neither shall ye do thus in your land.", "acv": "That which has its testicles bruised, or crushed, or broken, or cut, ye shall not offer to Jehovah, neither shall ye do thus in your land.", "anderson": "", "haweis": "", "noyes": "", "webster": "Ye shall not offer to the LORD that which is bruised, or crushed, or broken, or cut; neither shall ye make [any offering thereof] in your land.", "vulgate": "omne animal quod vel contritis vel tunsis vel sectis ablatisque testiculis est non offeretis Domino et in terra vestra hoc omnino ne faciatis;", "brenton": "That which has broken testicles, or is crushed or gelt or mutilated, —thou shalt not offer them to the Lord, neither shall ye sacrifice them upon your land."}}, {"v": 25, "ref": "22:25", "o": "וּ/מִ/יַּ֣ד בֶּן נֵכָ֗ר לֹ֥א תַקְרִ֛יבוּ אֶת לֶ֥חֶם אֱלֹהֵי/כֶ֖ם מִ/כָּל אֵ֑לֶּה כִּ֣י מָשְׁחָתָ֤/ם בָּ/הֶם֙ מ֣וּם בָּ֔/ם לֹ֥א יֵרָצ֖וּ לָ/כֶֽם", "en": {"kjv": "Neither from a stranger’s hand shall ye offer the bread of your God of any of these; because their corruption is in them, and blemishes be in them: they shall not be accepted for you.", "web": "Neither shall you offer the bread of your God from the hand of a foreigner of any of these; because their corruption is in them. There is a defect in them. They shall not be accepted for you.’”", "bsb": "Neither you nor a foreigner shall present food to your God from any such animal. They will not be accepted on your behalf, because they are deformed and flawed.’”", "asv": "Neither from the hand of a foreigner shall ye offer the bread of your God of any of these; because their corruption is in them, there is a blemish in them: they shall not be accepted for you.", "ylt": "And from the hand of a son of a stranger ye do not bring near the bread of your God, of any of these, for their corruption is in them; blemish is in them; they are not pleasing for you.'", "tyndale": "nether of a straungers hande shall ye offer an offerynge to youre God of any soch. For they marre all in that they haue deformytes in them, and therfore can not be accepted for you.", "dra": "you shall not offer bread to your God, from the hand of a stranger, nor any other thing that he would give: because they are all corrupted, and defiled. You shall not receive them.", "bbe": "And from one who is not an Israelite you may not take any of these for an offering to the Lord; for they are unclean, there is a mark on them, and the Lord will not be pleased with them.", "geneva": "Neither of ye hand of a strager shall ye offer ye bread of your God of any of these, because their corruption is in them, there is a blemish in them: therefore shall they not be accepted for you.", "wycliffe": "Of `the hond of an alien ye schulen not offre looues to youre God, and what euer other thing he wole yyue, for alle thingis ben corrupt and defoulid; ye schulen not resseyue tho.", "rotherham": "Even at the hand of the son of a stranger, shall ye not bring near the food of your God of any of these,—for, their damage is in them, a blemish, is in them, they shall not be accepted for you.", "darby": "Nor from the hand of the stranger shall ye present the bread of yourGod, of any of these; for their corruption is in them: a defect is in them; they shall not be accepted for you.", "twenty": "", "jps": "Neither from the hand of a foreigner shall ye offer the bread of your G-d of any of these, because their corruption is in them, there is a blemish in them; they shall not be accepted for you.", "acv": "Neither from the hand of a foreigner shall ye offer the bread of your God of any of these, because their corruption is in them; there is a blemish in them. They shall not be accepted for you.", "anderson": "", "haweis": "", "noyes": "", "webster": "Neither from a stranger's hand shall ye offer the bread of your God of any of these; because their corruption [is] in them, [and] blemishes [are] in them: they shall not be accepted for you.", "vulgate": "de manu alienigenae non offeretis panes Deo vestro et quicquid aliud dare voluerint quia corrupta et maculata sunt omnia non suscipietis ea;", "brenton": "Neither shall ye offer the gifts of your God of all these things by the hand of a stranger, because there is corruption in them, a blemish in them: these shall not be accepted for you."}}, {"v": 26, "ref": "22:26", "o": "וַ/יְדַבֵּ֥ר יְהוָ֖ה אֶל מֹשֶׁ֥ה לֵּ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh spoke to Moses, saying,", "bsb": "Then the LORD said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde spake vnto Moses saynge:", "dra": "And the Lord spoke to Moses, saying:", "bbe": "And the Lord said to Moses,", "geneva": "And the Lord spake vnto Moses, saying,", "wycliffe": "And the Lord spak to Moises,", "rotherham": "And Yahweh spake unto Moses, saying:—", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses, saying:", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "locutusque est Dominus ad Mosen dicens;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 27, "ref": "22:27", "o": "שׁ֣וֹר אוֹ כֶ֤שֶׂב אוֹ עֵז֙ כִּ֣י יִוָּלֵ֔ד וְ/הָיָ֛ה שִׁבְעַ֥ת יָמִ֖ים תַּ֣חַת אִמּ֑/וֹ וּ/מִ/יּ֤וֹם הַ/שְּׁמִינִי֙ וָ/הָ֔לְאָה יֵרָצֶ֕ה לְ/קָרְבַּ֥ן אִשֶּׁ֖ה לַ/יהוָֽה", "en": {"kjv": "When a bullock, or a sheep, or a goat, is brought forth, then it shall be seven days under the dam; and from the eighth day and thenceforth it shall be accepted for an offering made by fire unto the Lord.", "web": "“When a bull, or a sheep, or a goat, is born, then it shall remain seven days with its mother; and from the eighth day and thenceforth it shall be accepted for the offering of an offering made by fire to Yahweh.", "bsb": "“When an ox, a sheep, or a goat is born, it must remain with its mother for seven days. From the eighth day on, it will be acceptable as an offering made by fire to the LORD.", "asv": "When a bullock, or a sheep, or a goat, is brought forth, then it shall be seven days under the dam; and from the eighth day and thenceforth it shall be accepted for the oblation of an offering made by fire unto Jehovah.", "ylt": "`When ox or lamb or goat is born, and it hath been seven days under its dam, then from the eighth day and henceforth, it is pleasing for an offering, a fire-offering to Jehovah;", "tyndale": "when an oxe, a shepe or a goote is brought forth, it shalbe seue dayes vnder the damme. And from the .viij. daye forth, it shalbe accepted vnto a gifte in the sacrifice of the Lorde.", "dra": "When a bullock, or a sheep, or a goat, is brought forth, they shall be seven days under the udder of their dam: but the eighth day, and thenceforth, they may be offered to the Lord.", "bbe": "When an ox or a sheep or a goat is given birth, let it be with its mother for seven days; and after the eighth day it may be taken as an offering made by fire to the Lord.", "geneva": "When a bullocke, or a sheepe, or a goate shall be brought foorth, it shalbe euen seuen daies vnder his damme: and from the eight day forth, it shalbe accepted for a sacrifice made by fire vnto the Lord.", "wycliffe": "and seide, Whanne an oxe, scheep and goet ben brouyt forth `of the modris wombe, in seuene daies tho schulen be vnder `the tete of her modir; sotheli in the eiyte dai, and fro thennus forth, tho moun be offrid to the Lord,", "rotherham": "When, a beeve or a sheep or a goat, is brought forth, then shall it be seven days under its dam,—and, from the eighth day and onwards, it shall be accepted as an oblation of an altar-flame unto Yahweh,", "darby": "An ox, or a sheep, or a goat, when it is brought forth, shall be seven days under its dam; and from the eighth day and thenceforth it shall be accepted for an offering by fire to Jehovah.", "twenty": "", "jps": "When a bullock, or a sheep, or a goat, is brought forth, then it shall be seven days under the dam; but from the eighth day and thenceforth it may be accepted for an offering made by fire unto HaShem.", "acv": "When a bullock, or a sheep, or a goat, is brought forth, then it shall be seven days under the dam, and from the eighth day and after that it shall be accepted for the oblation of an offering made by fire to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "When a bullock, or a sheep, or a goat is brought forth, then it shall be seven days under the dam; and from the eighth day and thenceforth it shall be accepted for an offering made by fire to the LORD.", "vulgate": "bos ovis et capra cum genita fuerint septem diebus erunt sub ubere matris suae die autem octavo et deinceps offerri poterunt Domino;", "brenton": "As for a calf, or a sheep, or a goat, whenever it is born, then shall it be seven days under its mother; and on the eighth day and after they shall be accepted for sacrifices, a burnt-offering to the Lord."}}, {"v": 28, "ref": "22:28", "o": "וְ/שׁ֖וֹר אוֹ שֶׂ֑ה אֹת֣/וֹ וְ/אֶת בְּנ֔/וֹ לֹ֥א תִשְׁחֲט֖וּ בְּ/י֥וֹם אֶחָֽד", "en": {"kjv": "And whether it be cow or ewe, ye shall not kill it and her young both in one day.", "web": "Whether it is a cow or ewe, you shall not kill it and its young both in one day.", "bsb": "But you must not slaughter an ox or a sheep on the same day as its young.", "asv": "And whether it be cow or ewe, ye shall not kill it and its young both in one day.", "ylt": "but an ox or sheep--it and its young one, ye do not slaughter in one day.", "tyndale": "And whether it be oxe or shepe, ye shall not kyll it, and hir yonge: both in one daye.", "dra": "Whether it be a cow, or a sheep, they shall not be sacrificed the same day with their young ones.", "bbe": "A cow or a sheep may not be put to death with its young on the same day.", "geneva": "As for the cowe or the ewe, yee shall not kill her, and her yong both in one day.", "wycliffe": "whether thilke is a cow, whether `thilke is a scheep; tho schulen not be offrid in o dai with her fruytis.", "rotherham": "Whether cow or ewe—it and its young, shall ye not slaughter on one day.", "darby": "A cow, or sheep — it and its young shall ye not slaughter in one day.", "twenty": "", "jps": "And whether it be cow or ewe, ye shall not kill it and its young both in one day.", "acv": "And whether it be cow or ewe, ye shall not kill it and its young both in one day.", "anderson": "", "haweis": "", "noyes": "", "webster": "And [whether it is] cow, or ewe, ye shall not kill it and her young both in one day.", "vulgate": "sive illa bos sive ovis non immolabuntur una die cum fetibus suis;", "brenton": "And a bullock and a ewe, it and its young, thou shalt not kill in one day."}}, {"v": 29, "ref": "22:29", "o": "וְ/כִֽי תִזְבְּח֥וּ זֶֽבַח תּוֹדָ֖ה לַ/יהוָ֑ה לִֽ/רְצֹנְ/כֶ֖ם תִּזְבָּֽחוּ", "en": {"kjv": "And when ye will offer a sacrifice of thanksgiving unto the Lord, offer it at your own will.", "web": "“When you sacrifice a sacrifice of thanksgiving to Yahweh, you shall sacrifice it so that you may be accepted.", "bsb": "When you sacrifice a thank offering to the LORD, offer it so that it may be acceptable on your behalf.", "asv": "And when ye sacrifice a sacrifice of thanksgiving unto Jehovah, ye shall sacrifice it that ye may be accepted.", "ylt": "`And when ye sacrifice a sacrifice of thanksgiving to Jehovah, at your pleasure ye do sacrifice,", "tyndale": "When ye will offre a thankofferynge vnto the Lorde, ye shall so offre it that ye maye be accepted.", "dra": "If you immolate a victim for thanksgiving to the Lord, that he may be favourable,", "bbe": "And when you make an offering of praise to the Lord, make it in a way which is pleasing to him.", "geneva": "So when ye will offer a thanke offring vnto the Lord, ye shall offer willingly.", "wycliffe": "If ye offren to the Lord a sacrifice for the doyng of thankyngis, that it mai be plesaunt,", "rotherham": "And when ye would offer a sacrifice of thanksgiving unto Yahweh, for your acceptance, shall ye offer it.", "darby": "And when ye sacrifice a sacrifice of thanksgiving to Jehovah, ye shall sacrifice it for your acceptance.", "twenty": "", "jps": "And when ye sacrifice a sacrifice of thanksgiving unto HaShem, ye shall sacrifice it that ye may be accepted.", "acv": "And when ye sacrifice a sacrifice of thanksgiving to Jehovah, ye shall sacrifice it that ye may be accepted.", "anderson": "", "haweis": "", "noyes": "", "webster": "And when ye will offer a sacrifice of thanksgiving to the LORD, offer it at your own will.", "vulgate": "si immolaveritis hostiam pro gratiarum actione Domino ut possit esse placabilis;", "brenton": "And if thou shouldest offer a sacrifice, a vow of rejoicing to the Lord, ye shall offer it so as to be accepted for you."}}, {"v": 30, "ref": "22:30", "o": "בַּ/יּ֤וֹם הַ/הוּא֙ יֵאָכֵ֔ל לֹֽא תוֹתִ֥ירוּ מִמֶּ֖/נּוּ עַד בֹּ֑קֶר אֲנִ֖י יְהוָֽה", "en": {"kjv": "On the same day it shall be eaten up; ye shall leave none of it until the morrow: I am the Lord.", "web": "It shall be eaten on the same day; you shall leave none of it until the morning. I am Yahweh.", "bsb": "It must be eaten that same day. Do not leave any of it until morning. I am the LORD.", "asv": "On the same day it shall be eaten; ye shall leave none of it until the morning: I am Jehovah.", "ylt": "on that day it is eaten, ye do not leave of it till morning; I am Jehovah;", "tyndale": "And the same daye it must be eate vp, so that ye leaue none of it vntill the morowe. For I am the Lorde,", "dra": "You shall eat it the same day. There shall not any of it remain until the morning of the next day. I am the Lord.", "bbe": "Let it be used for food on the same day; do not keep any part of it till the morning: I am the Lord.", "geneva": "The same day it shalbe eaten, yee shall leaue none of it vntill the morowe: I am the Lord.", "wycliffe": "ye schulen ete it in the same dai in which it is offrid; ony thing schal not leeue in the morewtid of the tother dai; Y am the Lord.", "rotherham": "On the same day, shall it be eaten, ye shall not leave thereof until morning,—I, am Yahweh.", "darby": "On that day shall it be eaten: ye shall leave none of it until morning: I am Jehovah.", "twenty": "", "jps": "On the same day it shall be eaten; ye shall leave none of it until the morning: I am HaShem.", "acv": "It shall be eaten on the same day. Ye shall leave none of it until the morning. I am Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "On the same day it shall be eaten up, ye shall leave none of it until the morrow: I [am] the LORD.", "vulgate": "eodem die comedetis eam non remanebit quicquam in mane alterius diei ego Dominus;", "brenton": "In that same day it shall be eaten; ye shall not leave of the flesh till the morrow: I am the Lord."}}, {"v": 31, "ref": "22:31", "o": "וּ/שְׁמַרְתֶּם֙ מִצְוֺתַ֔/י וַ/עֲשִׂיתֶ֖ם אֹתָ֑/ם אֲנִ֖י יְהוָֽה", "en": {"kjv": "Therefore shall ye keep my commandments, and do them: I am the Lord.", "web": "“Therefore you shall keep my commandments, and do them. I am Yahweh.", "bsb": "You are to keep My commandments and practice them. I am the LORD.", "asv": "Therefore shall ye keep my commandments, and do them: I am Jehovah.", "ylt": "and ye have kept my commands, and have done them; I am Jehovah;", "tyndale": "kepe now my commaundementes and do them, for I am the Lorde.", "dra": "Keep my commandments, and do them. I am the Lord.", "bbe": "So then, keep my orders and do them: I am the Lord.", "geneva": "Therefore shall ye keepe my commandements and do them: for I am the Lord.", "wycliffe": "Kepe ye myn heestis, and do ye tho; Y am the Lord.", "rotherham": "So then ye shall observe my commandments, and do them,—I, am Yahweh.", "darby": "And ye shall observe my commandments and do them: I am Jehovah.", "twenty": "", "jps": "And ye shall keep My commandments, and do them: I am HaShem.", "acv": "Therefore ye shall keep my commandments, and do them. I am Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "Therefore shall ye keep my commandments, and do them: I [am] the LORD.", "vulgate": "custodite mandata mea et facite ea ego Dominus;", "brenton": "And ye shall keep my commandments and do them."}}, {"v": 32, "ref": "22:32", "o": "וְ/לֹ֤א תְחַלְּלוּ֙ אֶת שֵׁ֣ם קָדְשִׁ֔/י וְ/נִ֨קְדַּשְׁתִּ֔י בְּ/ת֖וֹךְ בְּנֵ֣י יִשְׂרָאֵ֑ל אֲנִ֥י יְהוָ֖ה מְקַדִּשְׁ/כֶֽם", "en": {"kjv": "Neither shall ye profane my holy name; but I will be hallowed among the children of Israel: I am the Lord which hallow you,", "web": "You shall not profane my holy name, but I will be made holy among the children of Israel. I am Yahweh who makes you holy,", "bsb": "You must not profane My holy name. I must be acknowledged as holy among the Israelites. I am the LORD who sanctifies you,", "asv": "And ye shall not profane my holy name; but I will be hallowed among the children of Israel: I am Jehovah who halloweth you,", "ylt": "and ye do not pollute My holy name, and I have been hallowed in the midst of the sons of Israel; I am Jehovah, sanctifying you,", "tyndale": "And polute not my holy name, that I maye be halowed amonge the childern of Israel. For I am the Lorde which halowe you,", "dra": "Profane not my holy name, that I may be sanctified in the midst of the children of Israel. I am the Lord who sanctify you:", "bbe": "And do not make my holy name common; so that it may be kept holy by the children of Israel: I am the Lord who make you holy,", "geneva": "Neither shall ye pollute mine holy Name, but I will be halowed among the children of Israel. I the Lord sanctifie you,", "wycliffe": "Defoule ye not myn hooli name, that Y be halewid in the myddis of the sones of Israel; Y am the Lord, that halewe you, and ledde you out of the lond of Egipt,", "rotherham": "So shall ye not profane my holy name, So shall I be hallowed in the midst of the sons of Israel,—I, am Yahweh, who am hallowing you;", "darby": "And ye shall not profane my holy name; but I will be hallowed among the children of Israel: I am Jehovah who do hallow you,", "twenty": "", "jps": "And ye shall not profane My holy name; but I will be hallowed among the children of Israel: I am HaShem who hallow you,", "acv": "And ye shall not profane my holy name, but I will be hallowed among the sons of Israel. I am Jehovah who hallows you,", "anderson": "", "haweis": "", "noyes": "", "webster": "Neither shall ye profane my holy name; but I will be hallowed among the children of Israel: I [am] the LORD who hallow you,", "vulgate": "ne polluatis nomen meum sanctum ut sanctificer in medio filiorum Israhel ego Dominus qui sanctifico vos;", "brenton": "And ye shall not profane the name of the Holy One, and I will be sanctified in the midst of the children of Israel. I am the Lord that sanctifies you,"}}, {"v": 33, "ref": "22:33", "o": "הַ/מּוֹצִ֤יא אֶתְ/כֶם֙ מֵ/אֶ֣רֶץ מִצְרַ֔יִם לִ/הְי֥וֹת לָ/כֶ֖ם לֵ/אלֹהִ֑ים אֲנִ֖י יְהוָֽה", "en": {"kjv": "That brought you out of the land of Egypt, to be your God: I am the Lord.", "web": "who brought you out of the land of Egypt, to be your God. I am Yahweh.”", "bsb": "who brought you out of the land of Egypt to be your God. I am the LORD.”", "asv": "who brought you out of the land of Egypt, to be your God: I am Jehovah.", "ylt": "who am bringing you up out of the land of Egypt, to become your God; I am Jehovah.'", "tyndale": "and broughte you out of the londe of Egipte, to be youre God: for I am the Lorde.", "dra": "And who brought you out of the land of Egypt, that I might be your God. I am the Lord.", "bbe": "Who took you out of the land of Egypt that I might be your God: I am the Lord.", "geneva": "Which haue brought you out of the land of Egypt, to be your God: I am the Lord.", "wycliffe": "that Y schulde be to you in to God; Y am the Lord.", "rotherham": "Who brought you forth out of the land of Egypt, that I might become your God,—I, am Yahweh.", "darby": "who brought you out of the land of Egypt, to be yourGod: I am Jehovah.", "twenty": "", "jps": "that brought you out of the land of Egypt, to be your G-d: I am HaShem.", "acv": "who brought you out of the land of Egypt, to be your God. I am Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "That brought you out of the land of Egypt, to be your God: I [am] the LORD.", "vulgate": "et eduxi de terra Aegypti ut essem vobis in Deum ego Dominus;", "brenton": "who brought you out of the land of Egypt, to be your God: I am the Lord."}}]}, {"c": 23, "verses": [{"v": 1, "ref": "23:1", "o": "וַ/יְדַבֵּ֥ר יְהוָ֖ה אֶל מֹשֶׁ֥ה לֵּ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh spoke to Moses, saying,", "bsb": "Then the LORD said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde spake vnto Moses saynge:", "dra": "And the Lord spoke to Moses, saying:", "bbe": "And the Lord said to Moses,", "geneva": "And the Lord spake vnto Moses, saying,", "wycliffe": "And the Lord spak to Moises and seide, Speke thou to the sones of Israel,", "rotherham": "And Yahweh spake unto Moses, saying:", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses, saying:", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "locutus est Dominus ad Mosen dicens;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 2, "ref": "23:2", "o": "דַּבֵּ֞ר אֶל בְּנֵ֤י יִשְׂרָאֵל֙ וְ/אָמַרְתָּ֣ אֲלֵ/הֶ֔ם מוֹעֲדֵ֣י יְהוָ֔ה אֲשֶׁר תִּקְרְא֥וּ אֹתָ֖/ם מִקְרָאֵ֣י קֹ֑דֶשׁ אֵ֥לֶּה הֵ֖ם מוֹעֲדָֽ/י", "en": {"kjv": "Speak unto the children of Israel, and say unto them, Concerning the feasts of the Lord, which ye shall proclaim to be holy convocations, even these are my feasts.", "web": "“Speak to the children of Israel, and tell them, ‘The set feasts of Yahweh, which you shall proclaim to be holy convocations, even these are my set feasts.", "bsb": "“Speak to the Israelites and say to them, ‘These are My appointed feasts, the feasts of the LORD that you are to proclaim as sacred assemblies.", "asv": "Speak unto the children of Israel, and say unto them, The set feasts of Jehovah, which ye shall proclaim to be holy convocations, even these are my set feasts.", "ylt": "`Speak unto the sons of Israel, and thou hast said unto them, Appointed seasons of Jehovah, which ye proclaim, holy convocations, are these: they are My appointed seasons:", "tyndale": "speake vnto the childern of Israel, and saye vnto them. These are the feastes off the Lorde which ye shal call holy feastes.", "dra": "Speak to the children of Israel, and thou shalt say to them: These are the feasts of the Lord, which you shall call holy.", "bbe": "Say to the children of Israel, These are the fixed feasts of the Lord, which you will keep for holy meetings: these are my feasts.", "geneva": "Speake vnto the children of Israel, and say vnto them, The feastes of ye Lord which yee shall call ye holie assemblies, euen these are my feasts.", "wycliffe": "and thou schalt seye to hem, These ben the feries of the Lord, whiche ye schulen clepe hooli.", "rotherham": "Speak unto the sons of Israel and thou shalt say unto them, As for the appointed seasons of Yahweh, which ye shall proclaim as holy convocations, these, are they—my appointed seasons:—", "darby": "Speak unto the children of Israel, and say unto them, [Concerning] the set feasts of Jehovah, which ye shall proclaim as holy convocations — these are my set feasts.", "twenty": "", "jps": "Speak unto the children of Israel, and say unto them: The appointed seasons of HaShem, which ye shall proclaim to be holy convocations, even these are My appointed seasons.", "acv": "Speak to the sons of Israel, and say to them, The set feasts of Jehovah, which ye shall proclaim to be holy convocations, even these are my set feasts.", "anderson": "", "haweis": "", "noyes": "", "webster": "Speak to the children of Israel, and say to them, [Concerning] the feasts of the LORD, which ye shall proclaim [to be] holy convocations, [even] these [are] my feasts.", "vulgate": "loquere filiis Israhel et dices ad eos hae sunt feriae Domini quas vocabitis sanctas;", "brenton": "Speak to the children of Israel, and thou shalt say unto them, The feasts of the Lord which ye shall call holy assemblies, these are my feasts."}}, {"v": 3, "ref": "23:3", "o": "שֵׁ֣שֶׁת יָמִים֮ תֵּעָשֶׂ֣ה מְלָאכָה֒ וּ/בַ/יּ֣וֹם הַ/שְּׁבִיעִ֗י שַׁבַּ֤ת שַׁבָּתוֹן֙ מִקְרָא קֹ֔דֶשׁ כָּל מְלָאכָ֖ה לֹ֣א תַעֲשׂ֑וּ שַׁבָּ֥ת הִוא֙ לַֽ/יהוָ֔ה בְּ/כֹ֖ל מֽוֹשְׁבֹתֵי/כֶֽם", "en": {"kjv": "Six days shall work be done: but the seventh day is the sabbath of rest, an holy convocation; ye shall do no work therein: it is the sabbath of the Lord in all your dwellings.", "web": "“‘Six days shall work be done, but on the seventh day is a Sabbath of solemn rest, a holy convocation; you shall do no kind of work. It is a Sabbath to Yahweh in all your dwellings.", "bsb": "For six days work may be done, but the seventh day is a Sabbath of complete rest, a day of sacred assembly. You must not do any work; wherever you live, it is a Sabbath to the LORD.", "asv": "Six days shall work be done: but on the seventh day is a sabbath of solemn rest, a holy convocation; ye shall do no manner of work: it is a sabbath unto Jehovah in all your dwellings.", "ylt": "six days is work done, and in the seventh day is a sabbath of rest, a holy convocation; ye do no work; it is a sabbath to Jehovah in all your dwellings.", "tyndale": "Sixe dayes ye shall worke, ad the seuenth is the Sabbath of rest an holy feast: so that ye maye do no worke therein, for it is the Sabbath of the Lorde, wheresoeuer ye dwell.", "dra": "Six days shall ye do work: the seventh day, because it is the rest of the sabbath, shall be called holy. You shall do no work on that day: it is the sabbath of the Lord in all your habitations.", "bbe": "On six days work may be done; but the seventh day is a special day of rest, a time for worship; you may do no sort of work: it is a Sabbath to the Lord wherever you may be living.", "geneva": "Six daies shall worke be done, but in the seuenth day shalbe the Sabbath of rest, an holie conuocation: ye shall do no worke therein, it is the Sabbath of the Lord, in all your dwellings.", "wycliffe": "Sixe daies ye schulen do werk, the seuenthe dai schal be clepid hooli, for it is the reste of sabat; ye schulen not do ony werk ther ynne; it is the sabat of the Lord in alle youre abitaciouns.", "rotherham": "Six days, shall work be done, but, on the seventh day, shall there be a sabbath of sacred rest a holy convocation, no work, shall ye do,—a sabbath, shall it be unto Yahweh, in all your dwellings.", "darby": "Six days shall work be done; but on the seventh day is the sabbath of rest, a holy convocation; no manner of work shall ye do: it is the sabbath to Jehovah in all your dwellings.", "twenty": "", "jps": "Six days shall work be done; but on the seventh day is a sabbath of solemn rest, a holy convocation; ye shall do no manner of work; it is a sabbath unto HaShem in all your dwellings.", "acv": "Six days shall work be done, but on the seventh day is a sabbath of solemn rest, a holy convocation. Ye shall do no manner of work. It is a sabbath to Jehovah in all your dwellings.", "anderson": "", "haweis": "", "noyes": "", "webster": "Six days shall work be done: but the seventh day [is] the sabbath of rest, a holy convocation: ye shall do no work [in it]: it [is] the sabbath of the LORD in all your dwellings.", "vulgate": "sex diebus facietis opus dies septimus quia sabbati requies est vocabitur sanctus omne opus non facietis in eo sabbatum Domini est in cunctis habitationibus vestris;", "brenton": "Six days shalt thou do works, but on the seventh day is the sabbath; a rest, a holy convocation to the Lord: thou shalt not do any work, it is a sabbath to the Lord in all your dwellings."}}, {"v": 4, "ref": "23:4", "o": "אֵ֚לֶּה מוֹעֲדֵ֣י יְהוָ֔ה מִקְרָאֵ֖י קֹ֑דֶשׁ אֲשֶׁר תִּקְרְא֥וּ אֹתָ֖/ם בְּ/מוֹעֲדָֽ/ם", "en": {"kjv": "These are the feasts of the Lord, even holy convocations, which ye shall proclaim in their seasons.", "web": "“‘These are the set feasts of Yahweh, even holy convocations, which you shall proclaim in their appointed season.", "bsb": "These are the LORD’s appointed feasts, the sacred assemblies you are to proclaim at their appointed times.", "asv": "These are the set feasts of Jehovah, even holy convocations, which ye shall proclaim in their appointed season.", "ylt": "`These are appointed seasons of Jehovah, holy convocations, which ye proclaim in their appointed seasons:", "tyndale": "These are the feastes of the Lorde whiche ye shall proclayme holy in their ceasons.", "dra": "These also are the holy days of the Lord, which you must celebrate in their seasons.", "bbe": "These are the fixed feasts of the Lord, the holy days of worship which you will keep at their regular times.", "geneva": "These are the feastes of the Lord, and holie conuocations, which yee shall proclaime in their seasons.", "wycliffe": "These ben the hooli feries of the Lord, whiche ye owen to halewe in her tymes.", "rotherham": "These, are the appointed seasons of Yahweh, holy convocations,—which ye shall proclaim in their appointed season:—", "darby": "These are the set feasts of Jehovah, holy convocations, which ye shall proclaim in their seasons:", "twenty": "", "jps": "These are the appointed seasons of HaShem, even holy convocations, which ye shall proclaim in their appointed season.", "acv": "These are the set feasts of Jehovah, even holy convocations, which ye shall proclaim in their appointed season:", "anderson": "", "haweis": "", "noyes": "", "webster": "These [are] the feasts of the LORD, holy convocations, which ye shall proclaim in their seasons.", "vulgate": "hae sunt ergo feriae Domini sanctae quas celebrare debetis temporibus suis;", "brenton": "These are the feasts to the Lord, holy convocations, which ye shall call in their seasons."}}, {"v": 5, "ref": "23:5", "o": "בַּ/חֹ֣דֶשׁ הָ/רִאשׁ֗וֹן בְּ/אַרְבָּעָ֥ה עָשָׂ֛ר לַ/חֹ֖דֶשׁ בֵּ֣ין הָ/עַרְבָּ֑יִם פֶּ֖סַח לַ/יהוָֽה", "en": {"kjv": "In the fourteenth day of the first month at even is the Lord’s passover.", "web": "In the first month, on the fourteenth day of the month in the evening, is Yahweh’s Passover.", "bsb": "The Passover to the LORD begins at twilight on the fourteenth day of the first month.", "asv": "In the first month, on the fourteenth day of the month at even, is Jehovah’s passover.", "ylt": "in the first month, on the fourteenth of the month, between the evenings, is the passover to Jehovah;", "tyndale": "The xiiij. daye of the first moneth at eue is the Lordes Passeouer,", "dra": "The first month, the fourteenth day of the month at evening, is the phase of the Lord.", "bbe": "In the first month, on the fourteenth day of the month at nightfall, is the Lord's Passover;", "geneva": "In the first moneth, and in the fourteenth day of the moneth at euening shalbe ye Passeouer of the Lord.", "wycliffe": "In the firste monethe, in the fourtenthe dai of the monethe, at euentid, is pask of the Lord;", "rotherham": "In the first month, on the fourteenth of the month, between the evenings, is a Passover unto Yahweh;", "darby": "In the first month, on the fourteenth of the month, between the two evenings, is the passover to Jehovah.", "twenty": "", "jps": "In the first month, on the fourteenth day of the month at dusk, is HaShem'S passover.", "acv": "In the first month, on the fourteenth day of the month at evening, is Jehovah's Passover.", "anderson": "", "haweis": "", "noyes": "", "webster": "In the fourteenth [day] of the first month at evening [is] the LORD'S passover.", "vulgate": "mense primo quartadecima die mensis ad vesperum phase Domini est;", "brenton": "In the first month, on the fourteenth day of the month, between the evening times is the Lord's passover."}}, {"v": 6, "ref": "23:6", "o": "וּ/בַ/חֲמִשָּׁ֨ה עָשָׂ֥ר יוֹם֙ לַ/חֹ֣דֶשׁ הַ/זֶּ֔ה חַ֥ג הַ/מַּצּ֖וֹת לַ/יהוָ֑ה שִׁבְעַ֥ת יָמִ֖ים מַצּ֥וֹת תֹּאכֵֽלוּ", "en": {"kjv": "And on the fifteenth day of the same month is the feast of unleavened bread unto the Lord: seven days ye must eat unleavened bread.", "web": "On the fifteenth day of the same month is the feast of unleavened bread to Yahweh. Seven days you shall eat unleavened bread.", "bsb": "On the fifteenth day of the same month begins the Feast of Unleavened Bread to the LORD. For seven days you must eat unleavened bread.", "asv": "And on the fifteenth day of the same month is the feast of unleavened bread unto Jehovah: seven days ye shall eat unleavened bread.", "ylt": "and on the fifteenth day of this month is the feast of unleavened things to Jehovah; seven days unleavened things ye do eat;", "tyndale": "And the .xv. daye of the same moneth is the feast of swete bred vnto the Lorde: vij. dayes ye must eate vnleuended bred.", "dra": "And the fifteenth day of the same month is the solemnity of the unleavened bread of the Lord. Seven days shall you eat unleavened bread.", "bbe": "And on the fifteenth day of the same month is the feast of unleavened bread; for seven days let your food be unleavened bread.", "geneva": "And on the fifteenth day of this moneth shalbe the feast of vnleauened bread vnto the Lord: seuen dayes ye shall eate vnleauened bread.", "wycliffe": "and in the fiftenthe dai of this monethe is the solempnyte of therf looues of the Lord; seuene daies ye schulen ete therf looues;", "rotherham": "and on the fifteenth day of this month, is the festival of unleavened cakes unto Yahweh,—seven days—unleavened cakes, shall ye eat.", "darby": "And on the fifteenth day of this month is the feast of unleavened bread to Jehovah; seven days shall ye eat unleavened bread.", "twenty": "", "jps": "And on the fifteenth day of the same month is the feast of unleavened bread unto HaShem; seven days ye shall eat unleavened bread.", "acv": "And on the fifteenth day of the same month is the feast of unleavened bread to Jehovah. Ye shall eat unleavened bread seven days.", "anderson": "", "haweis": "", "noyes": "", "webster": "And on the fifteenth day of the same month [is] the feast of unleavened bread to the LORD, seven days ye must eat unleavened bread.", "vulgate": "et quintadecima die mensis huius sollemnitas azymorum Domini est septem diebus azyma comedetis;", "brenton": "And on the fifteenth day of this month is the feast of unleavened bread to the Lord; seven days shall ye eat unleavened bread."}}, {"v": 7, "ref": "23:7", "o": "בַּ/יּוֹם֙ הָֽ/רִאשׁ֔וֹן מִקְרָא קֹ֖דֶשׁ יִהְיֶ֣ה לָ/כֶ֑ם כָּל מְלֶ֥אכֶת עֲבֹדָ֖ה לֹ֥א תַעֲשֽׂוּ", "en": {"kjv": "In the first day ye shall have an holy convocation: ye shall do no servile work therein.", "web": "In the first day you shall have a holy convocation. You shall do no regular work.", "bsb": "On the first day you are to hold a sacred assembly; you are not to do any regular work.", "asv": "In the first day ye shall have a holy convocation: ye shall do no servile work.", "ylt": "on the first day ye have a holy convocation, ye do no servile work;", "tyndale": "The first daye shalbe an holy feaste vnto you, so that ye maye do no laborious worke therein", "dra": "The first day shall be most solemn unto you, and holy: you shall do no servile work therein.", "bbe": "On the first day you will have a holy meeting; you may do no sort of field-work.", "geneva": "In the first day yee shall haue an holy conuocation: ye shall do no seruile worke therein.", "wycliffe": "the firste dai schal be moost solempne and hooli to you; ye schulen not do ony `seruyle werk ther ynne,", "rotherham": "On the first day—a holy convocation, shall there be to you: no laborious work, shall ye do.", "darby": "On the first day ye shall have a holy convocation: no manner of servile work shall ye do.", "twenty": "", "jps": "In the first day ye shall have a holy convocation; ye shall do no manner of servile work.", "acv": "In the first day ye shall have a holy convocation. Ye shall do no job work.", "anderson": "", "haweis": "", "noyes": "", "webster": "In the first day ye shall have a holy convocation: ye shall do no servile work in it.", "vulgate": "dies primus erit vobis celeberrimus sanctusque omne opus servile non facietis in eo;", "brenton": "And the first day shall be a holy convocation to you: ye shall do no servile work."}}, {"v": 8, "ref": "23:8", "o": "וְ/הִקְרַבְתֶּ֥ם אִשֶּׁ֛ה לַ/יהוָ֖ה שִׁבְעַ֣ת יָמִ֑ים בַּ/יּ֤וֹם הַ/שְּׁבִיעִי֙ מִקְרָא קֹ֔דֶשׁ כָּל מְלֶ֥אכֶת עֲבֹדָ֖ה לֹ֥א תַעֲשֽׂוּ", "en": {"kjv": "But ye shall offer an offering made by fire unto the Lord seven days: in the seventh day is an holy convocation: ye shall do no servile work therein.", "web": "But you shall offer an offering made by fire to Yahweh seven days. In the seventh day is a holy convocation: you shall do no regular work.’”", "bsb": "For seven days you are to present an offering made by fire to the LORD. On the seventh day there shall be a sacred assembly; you must not do any regular work.’”", "asv": "But ye shall offer an offering made by fire unto Jehovah seven days: in the seventh day is a holy convocation; ye shall do no servile work.", "ylt": "and ye have brought near a fire-offering to Jehovah seven days; in the seventh day is a holy convocation; ye do no servile work.'", "tyndale": "But ye shall offer sacrifices vnto the Lord .vij dayes, and the seuenth daye also shalbe an holy feast, so that ye maye doo no laborious worke therein.", "dra": "But you shall offer sacrifice in fire to the Lord seven days. And the seventh day shall be more solemn, and more holy: and you shall do no servile work therein.", "bbe": "And every day for seven days you will give a burned offering to the Lord; and on the seventh day there will be a holy meeting; you may do no field-work.", "geneva": "Also ye shall offer sacrifice made by fire vnto the Lord seuen daies, and in the seuenth day shalbe an holie conuocation: ye shall do no seruile worke therein.", "wycliffe": "but ye schulen offre sacrifice in fier to the Lord seuene daies; sotheli the seuenthe dai schal be more solempne and hooliere, `that is, `than the formere daies goynge bitwixe, and ye schulen not do ony seruyle werk ther ynne.", "rotherham": "So then ye shall bring near an altar-flame unto Yahweh, seven days,—on the seventh day, [shall there be] a holy convocation, no laborious work, shall ye do.", "darby": "And ye shall present to Jehovah an offering by fire seven days; on the seventh day is a holy convocation: no manner of servile work shall ye do.", "twenty": "", "jps": "And ye shall bring an offering made by fire unto HaShem seven days; in the seventh day is a holy convocation; ye shall do no manner of servile work.", "acv": "But ye shall offer an offering made by fire to Jehovah seven days. In the seventh day is a holy convocation, ye shall do no job work.", "anderson": "", "haweis": "", "noyes": "", "webster": "But ye shall offer an offering made by fire to the LORD seven days: in the seventh day [is] a holy convocation, ye shall do no servile work [in it].", "vulgate": "sed offeretis sacrificium in igne Domino septem diebus dies autem septimus erit celebrior et sanctior nullumque servile opus fiet in eo;", "brenton": "And ye shall offer whole-burnt-offerings to the Lord seven days; and the seventh day shall be a holy convocation to you: ye shall do no servile work."}}, {"v": 9, "ref": "23:9", "o": "וַ/יְדַבֵּ֥ר יְהוָ֖ה אֶל מֹשֶׁ֥ה לֵּ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh spoke to Moses, saying,", "bsb": "And the LORD said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde spake vnto Moses sayenge:", "dra": "And the Lord spoke to Moses, saying:", "bbe": "And the Lord said to Moses,", "geneva": "And the Lord spake vnto Moses, saying,", "wycliffe": "And the Lord spak to Moises and seide,", "rotherham": "And Yahweh spake unto Moses saying:", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses saying:", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "locutusque est Dominus ad Mosen dicens;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 10, "ref": "23:10", "o": "דַּבֵּ֞ר אֶל בְּנֵ֤י יִשְׂרָאֵל֙ וְ/אָמַרְתָּ֣ אֲלֵ/הֶ֔ם כִּֽי תָבֹ֣אוּ אֶל הָ/אָ֗רֶץ אֲשֶׁ֤ר אֲנִי֙ נֹתֵ֣ן לָ/כֶ֔ם וּ/קְצַרְתֶּ֖ם אֶת קְצִירָ֑/הּ וַ/הֲבֵאתֶ֥ם אֶת עֹ֛מֶר רֵאשִׁ֥ית קְצִירְ/כֶ֖ם אֶל הַ/כֹּהֵֽן", "en": {"kjv": "Speak unto the children of Israel, and say unto them, When ye be come into the land which I give unto you, and shall reap the harvest thereof, then ye shall bring a sheaf of the firstfruits of your harvest unto the priest:", "web": "“Speak to the children of Israel, and tell them, ‘When you have come into the land which I give to you, and shall reap its harvest, then you shall bring the sheaf of the first fruits of your harvest to the priest:", "bsb": "“Speak to the Israelites and say, ‘When you enter the land that I am giving you and you reap its harvest, you are to bring to the priest a sheaf of the firstfruits of your harvest.", "asv": "Speak unto the children of Israel, and say unto them, When ye are come into the land which I give unto you, and shall reap the harvest thereof, then ye shall bring the sheaf of the first-fruits of your harvest unto the priest:", "ylt": "`Speak unto the sons of Israel, and thou hast said unto them, When ye come in unto the land which I am giving to you, and have reaped its harvest, and have brought in the sheaf, the beginning of your harvest unto the priest,", "tyndale": "speake vnto the childern of Israell and saye vnto them: when ye be come in to the lande whiche I geue vnto you and repe doune youre haruest, ye shall brynge a shefe of the first frutes of youre haruest vnto the preast,", "dra": "Speak to the children of Israel, and thou shalt say to them: When you shall have entered into the land which I will give you, and shall reap your corn, you shall bring sheaves of ears, the firstfruits of your harvest to the priest.", "bbe": "Say to the children of Israel, When you have come to the land which I will give you, and have got in the grain from its fields, take some of the first-fruits of the grain to the priest;", "geneva": "Speake vnto the children of Israel, and say vnto them, When ye be come into ye land which I giue vnto you, and reape the haruest thereof, then ye shall bring a sheafe of the first fruites of your haruest vnto the Priest,", "wycliffe": "Speke thou to the sones of Israel, and thou schalt seye to hem, Whanne ye han entrid in to the lond which Y schal yyue to you, and han rope corn, ye schulen bere handfuls of eeris of corn, the firste fruytis of youre rype corn, to the preest;", "rotherham": "Speak unto the sons of Israel, and thou shalt say unto them:—When ye enter into the land which, I, am giving you, and ye reap the harvest thereof, then shall ye bring in a sheaf of the first-ripe corn of your harvest, unto the priest;", "darby": "Speak unto the children of Israel and say unto them, When ye come into the land that I give unto you, and ye reap the harvest thereof, then ye shall bring a sheaf of the first-fruits of your harvest unto the priest.", "twenty": "", "jps": "Speak unto the children of Israel, and say unto them: When ye are come into the land which I give unto you, and shall reap the harvest thereof, then ye shall bring the sheaf of the first-fruits of your harvest unto the priest.", "acv": "Speak to the sons of Israel, and say to them, When ye have come into the land which I give to you, and shall reap the harvest of it, then ye shall bring the sheaf of the first-fruits of your harvest to the priest.", "anderson": "", "haweis": "", "noyes": "", "webster": "Speak to the children of Israel, and say to them, When ye shall have come into the land which I give to you, and shall reap the harvest thereof, then ye shall bring a sheaf of the first-fruits of your harvest to the priest:", "vulgate": "loquere filiis Israhel et dices ad eos cum ingressi fueritis terram quam ego dabo vobis et messueritis segetem feretis manipulos spicarum primitias messis vestrae ad sacerdotem;", "brenton": "Speak to the children of Israel, and thou shalt say to them, When ye shall enter into the land which I give you, and reap the harvest of it, then shall ye bring a sheaf, the first-fruits of your harvest, to the priest;"}}, {"v": 11, "ref": "23:11", "o": "וְ/הֵנִ֧יף אֶת הָ/עֹ֛מֶר לִ/פְנֵ֥י יְהוָ֖ה לִֽ/רְצֹנְ/כֶ֑ם מִֽ/מָּחֳרַת֙ הַ/שַּׁבָּ֔ת יְנִיפֶ֖/נּוּ הַ/כֹּהֵֽן", "en": {"kjv": "And he shall wave the sheaf before the Lord, to be accepted for you: on the morrow after the sabbath the priest shall wave it.", "web": "and he shall wave the sheaf before Yahweh, to be accepted for you. On the next day after the Sabbath the priest shall wave it.", "bsb": "And he shall wave the sheaf before the LORD so that it may be accepted on your behalf; the priest is to wave it on the day after the Sabbath.", "asv": "and he shall wave the sheaf before Jehovah, to be accepted for you: on the morrow after the sabbath the priest shall wave it.", "ylt": "then he hath waved the sheaf before Jehovah for your acceptance; on the morrow of the sabbath doth the priest wave it.", "tyndale": "and he shall waue the shefe before the Lorde to be accepted for you: and euen the morow after the Sabbath the preaste shall waue it.", "dra": "Who shall lift up the sheaf before the Lord, the next day after the sabbath, that it may be acceptable for you, and shall sanctify it.", "bbe": "And let the grain be waved before the Lord, so that you may be pleasing to him; on the day after the Sabbath let it be waved by the priest.", "geneva": "And hee shall shake the sheafe before the Lord, that it may be acceptable for you: the morowe after the Sabbath, the Priest shall shake it.", "wycliffe": "and the preest schal reise a bundel bifor the Lord, that it be acceptable for you, in the tother dai of sabat, that is, of pask; and the preest schal halewe that bundel;", "rotherham": "and he shall wave the sheaf before Yahweh, that ye may be accepted,—on the morrow of the sabbath, shall the priest wave it.", "darby": "And he shall wave the sheaf before Jehovah, to be accepted for you; on the next day after the sabbath the priest shall wave it.", "twenty": "", "jps": "And he shall wave the sheaf before HaShem, to be accepted for you; on the morrow after the sabbath the priest shall wave it.", "acv": "And he shall wave the sheaf before Jehovah, to be accepted for you. On the morrow after the sabbath the priest shall wave it.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall wave the sheaf before the LORD, to be accepted for you: on the morrow after the sabbath the priest shall wave it.", "vulgate": "qui elevabit fasciculum coram Domino ut acceptabile sit pro vobis altero die sabbati et sanctificabit illum;", "brenton": "and he shall lift up the sheaf before the Lord, to be accepted for you. On the morrow of the first day the priest shall lift it up."}}, {"v": 12, "ref": "23:12", "o": "וַ/עֲשִׂיתֶ֕ם בְּ/י֥וֹם הֲנִֽיפְ/כֶ֖ם אֶת הָ/עֹ֑מֶר כֶּ֣בֶשׂ תָּמִ֧ים בֶּן שְׁנָת֛/וֹ לְ/עֹלָ֖ה לַ/יהוָֽה", "en": {"kjv": "And ye shall offer that day when ye wave the sheaf an he lamb without blemish of the first year for a burnt offering unto the Lord.", "web": "On the day when you wave the sheaf, you shall offer a male lamb without defect a year old for a burnt offering to Yahweh.", "bsb": "On the day you wave the sheaf, you shall offer a year-old lamb without blemish as a burnt offering to the LORD,", "asv": "And in the day when ye wave the sheaf, ye shall offer a he-lamb without blemish a year old for a burnt-offering unto Jehovah.", "ylt": "`And ye have prepared in the day of your waving the sheaf a lamb, a perfect one, a son of a year, for a burnt-offering to Jehovah,", "tyndale": "And ye shall offer the daye when he waueth the shefe, a labe without blemysh of a yere olde for a burntofferynge vnto the Lorde:", "dra": "And on the same day that the sheaf is consecrated, a lamb without blemish of the first year shall be killed for a holocaust of the Lord.", "bbe": "And on the day of the waving of the grain, you are to give a male lamb of the first year, without any mark, for a burned offering to the Lord.", "geneva": "And that day when yee shake the sheafe, shall yee prepare a lambe without blemish of a yeere olde, for a burnt offring vnto the Lord:", "wycliffe": "and in the same dai, wher ynne the handful is halewid, a lomb of o yeer without wem schal be slayn in to brent sacrifice of the Lord;", "rotherham": "And ye shall offer on the day when ye wave the sheaf, a he-lamb without defect, the finest of its year for an ascending-sacrifice unto Yahweh;", "darby": "And ye shall offer that day when ye wave the sheaf, a he-lamb without blemish, a yearling, for a burnt-offering to Jehovah;", "twenty": "", "jps": "And in the day when ye wave the sheaf, ye shall offer a he-lamb without blemish of the first year for a burnt-offering unto HaShem.", "acv": "And in the day when ye wave the sheaf, ye shall offer a he-lamb without blemish a year old for a burnt offering to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And ye shall offer, that day when ye wave the sheaf, a he-lamb without blemish of the first year for a burnt-offering to the LORD.", "vulgate": "atque in eodem die quo manipulus consecratur caedetur agnus inmaculatus anniculus in holocaustum Domini;", "brenton": "And ye shall offer on the day on which ye bring the sheaf, a lamb without blemish of a year old for a whole-burnt-offering to the Lord."}}, {"v": 13, "ref": "23:13", "o": "וּ/מִנְחָת/וֹ֩ שְׁנֵ֨י עֶשְׂרֹנִ֜ים סֹ֣לֶת בְּלוּלָ֥ה בַ/שֶּׁ֛מֶן אִשֶּׁ֥ה לַ/יהוָ֖ה רֵ֣יחַ נִיחֹ֑חַ וְ/נִסְכֹּ֥/ה יַ֖יִן רְבִיעִ֥ת הַ/הִֽין", "en": {"kjv": "And the meat offering thereof shall be two tenth deals of fine flour mingled with oil, an offering made by fire unto the Lord for a sweet savour: and the drink offering thereof shall be of wine, the fourth part of an hin.", "web": "The meal offering with it shall be two tenth parts of an ephah of fine flour mingled with oil, an offering made by fire to Yahweh for a pleasant aroma; and the drink offering with it shall be of wine, the fourth part of a hin.", "bsb": "along with its grain offering of two-tenths of an ephah of fine flour mixed with oil—an offering made by fire to the LORD, a pleasing aroma—and its drink offering of a quarter hin of wine.", "asv": "And the meal-offering thereof shall be two tenth parts of an ephah of fine flour mingled with oil, an offering made by fire unto Jehovah for a sweet savor; and the drink-offering thereof shall be of wine, the fourth part of a hin.", "ylt": "and its present two tenth deals of flour mixed with oil, a fire-offering to Jehovah, a sweet fragrance, and its drink-offering, wine, a fourth of the hin.", "tyndale": "and the meatoffrynge thereof, two tenth deales of fine floure mengled with oyle to be a sacrifice vnto the Lorde of a swete sauoure: and the drinkofferinge thereto, the fourth deale of an hin of wyne.", "dra": "And the libations shall be offered with it: two tenths of flour tempered with oil, for a burnt offering of the Lord, and a most sweet odour. Libations also of wine, the fourth part of a hin.", "bbe": "And let the meal offering with it be two tenth parts of an ephah of the best meal mixed with oil, an offering made by fire to the Lord for a sweet smell; and the drink offering with it is to be of wine, the fourth part of a hin.", "geneva": "And the meate offring thereof shalbe two tenth deales of fine floure mingled with oyle, for a sacrifice made by fire vnto ye Lord of sweete sauour. and the drinke offring thereof the fourth part of an Hin of wine.", "wycliffe": "and fletynge offryngis schulen be offrid ther with, twei tenthe partis of wheete flour spreynt to gidere with oile, in to encense of the Lord, and swettist odour, and fletynge offryngis of wyn, the fourthe part of hyn.", "rotherham": "and the, meal-offering thereof shall be two-tenth parts of fine meal overflowed with oil, as an altar-flame unto Yahweh a satisfying odour,—and, the drink-offering thereof, [shall be] mine, the fourth of a hin.", "darby": "and the oblation thereof: two tenths of fine flour mingled with oil, an offering by fire to Jehovah for a sweet odour; and the drink-offering thereof, of wine, a fourth part of a hin.", "twenty": "", "jps": "And the meal-offering thereof shall be two tenth parts of an ephah of fine flour mingled with oil, an offering made by fire unto HaShem for a sweet savour; and the drink-offering thereof shall be of wine, the fourth part of a hin.", "acv": "And the meal offering of it shall be two tenth parts of an ephah of fine flour mingled with oil, an offering made by fire to Jehovah for a sweet savor. And the drink offering of it shall be of wine, the fourth part of a hin.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the meat-offering thereof [shall be] two tenth-parts of fine flour mingled with oil, an offering made by fire to the LORD [for] a sweet savor: and the drink-offering thereof [shall be] of wine, the fourth [part] of a hin.", "vulgate": "et libamenta offerentur cum eo duae decimae similae conspersae oleo in incensum Domini odoremque suavissimum liba quoque vini quarta pars hin;", "brenton": "And its meat-offering two tenth portions of fine flour mingled with oil: it is a sacrifice to the Lord, a smell of sweet savour to the Lord, and its drink-offering the fourth part of a hin of wine."}}, {"v": 14, "ref": "23:14", "o": "וְ/לֶחֶם֩ וְ/קָלִ֨י וְ/כַרְמֶ֜ל לֹ֣א תֹֽאכְל֗וּ עַד עֶ֨צֶם֙ הַ/יּ֣וֹם הַ/זֶּ֔ה עַ֚ד הֲבִ֣יאֲ/כֶ֔ם אֶת קָרְבַּ֖ן אֱלֹהֵי/כֶ֑ם חֻקַּ֤ת עוֹלָם֙ לְ/דֹרֹ֣תֵי/כֶ֔ם בְּ/כֹ֖ל מֹשְׁבֹֽתֵי/כֶֽם", "en": {"kjv": "And ye shall eat neither bread, nor parched corn, nor green ears, until the selfsame day that ye have brought an offering unto your God: it shall be a statute for ever throughout your generations in all your dwellings.", "web": "You shall eat neither bread, nor roasted grain, nor fresh grain, until this same day, until you have brought the offering of your God. This is a statute forever throughout your generations in all your dwellings.", "bsb": "You must not eat any bread or roasted or new grain until the very day you have brought this offering to your God. This is to be a permanent statute for the generations to come, wherever you live.", "asv": "And ye shall eat neither bread, nor parched grain, nor fresh ears, until this selfsame day, until ye have brought the oblation of your God: it is a statute for ever throughout your generations in all your dwellings.", "ylt": "`And bread and roasted corn and full ears ye do not eat until this self-same day, until your bringing in the offering of your God--a statute age-during to your generations, in all your dwellings.", "tyndale": "And ye shall eate nether bred, nor parched corne, nor furmentye of new corne: vntyll the selfe same daye that ye haue broughte an offrynge vnto youre God. And this shalbe a lawe for euer vnto youre childern after you, where soeuer ye dwell.", "dra": "You shall not eat either bread, or parched corn, or frumenty or the harvest, until the day that you shall offer thereof to your God. It is a precept for ever throughout your generations, and all your dwellings.", "bbe": "And you may take no bread or dry grain or new grain for food till the very day on which you have given the offering for your God: this is a rule for ever through all your generations wherever you are living.", "geneva": "And ye shall eat neither bread nor parched corne, nor greene eares vntill the selfe same day that ye haue brought an offring vnto your God: this shalbe a lawe for euer in your generations and in all your dwellings.", "wycliffe": "Ye schulen not ete a loof, nether a cake, nether podagis of the corn, `til to the dai in which ye schulen offre therof to youre God; it is a comaundement euerlastynge in youre generaciouns, and alle dwellyng placis.", "rotherham": "And neither bread, nor roasted corn, nor garden-land grain, shall ye eat, until this selfsame day, until ye have brought in the oblation of your God,—an age-abiding statute unto your generations, in all your dwellings.", "darby": "And ye shall not eat bread, or roast corn, or green ears, until the same day that ye have brought the offering of yourGod: [it is] an everlasting statute throughout your generations in all your dwellings.", "twenty": "", "jps": "And ye shall eat neither bread, nor parched corn, nor fresh ears, until this selfsame day, until ye have brought the offering of your G-d; it is a statute for ever throughout your generations in all your dwellings.", "acv": "And ye shall eat neither bread, nor parched grain, nor fresh ears, until this selfsame day, until ye have brought the oblation of your God. It is a statute forever throughout your generations in all your dwellings.", "anderson": "", "haweis": "", "noyes": "", "webster": "And ye shall eat neither bread, nor parched corn, nor green ears, until the same day that ye have brought an offering to your God: [It shall be] a statute for ever throughout your generations in all your dwellings.", "vulgate": "panem et pulentam et pultes non comedetis ex segete usque ad diem qua offeratis ex ea Deo vestro praeceptum est sempiternum in generationibus cunctisque habitaculis vestris;", "brenton": "And ye shall not eat bread, or the new parched corn, until this same day, until ye offer the sacrifices to your God: it is a perpetual statute throughout your generations in all your dwellings."}}, {"v": 15, "ref": "23:15", "o": "וּ/סְפַרְתֶּ֤ם לָ/כֶם֙ מִ/מָּחֳרַ֣ת הַ/שַּׁבָּ֔ת מִ/יּוֹם֙ הֲבִ֣יאֲ/כֶ֔ם אֶת עֹ֖מֶר הַ/תְּנוּפָ֑ה שֶׁ֥בַע שַׁבָּת֖וֹת תְּמִימֹ֥ת תִּהְיֶֽינָה", "en": {"kjv": "And ye shall count unto you from the morrow after the sabbath, from the day that ye brought the sheaf of the wave offering; seven sabbaths shall be complete:", "web": "“‘You shall count from the next day after the Sabbath, from the day that you brought the sheaf of the wave offering; seven Sabbaths shall be completed:", "bsb": "From the day after the Sabbath, the day you brought the sheaf of the wave offering, you are to count off seven full weeks.", "asv": "And ye shall count unto you from the morrow after the sabbath, from the day that ye brought the sheaf of the wave-offering; seven sabbaths shall there be complete:", "ylt": "`And ye have numbered to you from the morrow of the sabbath, from the day of your bringing in the sheaf of the wave-offering: they are seven perfect sabbaths;", "tyndale": "And ye shall counte from the morowe after the Sabbath: euen from the daye that ye broughte the sheffe of the waueoffrynge, vii. wekes complete:", "dra": "You shall count therefore from the morrow after the sabbath, wherein you offered the sheaf of firstfruits, seven full weeks.", "bbe": "And let seven full weeks be numbered from the day after the Sabbath, the day when you give the grain for the wave offering;", "geneva": "Ye shall count also to you from the morowe after the Sabbath, euen from the day that yee shall bring the sheafe of the shake offring, seuen Sabbaths, they shalbe complete.", "wycliffe": "Therfor ye schulen noumbre fro the tother dai of sabat, in which ye offriden handfullis of firste fruytis,", "rotherham": "Then shall ye keep count to yourselves from the morrow of the sabbath, from the day ye brought in the wave sheaf,—seven sabbaths complete, shall there be:", "darby": "And ye shall count from the morning after the sabbath, from the day that ye brought the sheaf of the wave-offering, seven weeks; they shall be complete;", "twenty": "", "jps": "And ye shall count unto you from the morrow after the day of rest, from the day that ye brought the sheaf of the waving; seven weeks shall there be complete;", "acv": "And ye shall count to you from the morrow after the sabbath, from the day that ye brought the sheaf of the wave offering, there shall be complete seven sabbaths.", "anderson": "", "haweis": "", "noyes": "", "webster": "And ye shall count to you from the morrow after the sabbath, from the day that ye brought the sheaf of the wave-offering; seven sabbaths shall be complete:", "vulgate": "numerabitis ergo ab altero die sabbati in quo obtulistis manipulum primitiarum septem ebdomadas plenas;", "brenton": "And ye shall number to yourselves from the day after the sabbath, from the day on which ye shall offer the sheaf of the heave-offering, seven full weeks:"}}, {"v": 16, "ref": "23:16", "o": "עַ֣ד מִֽ/מָּחֳרַ֤ת הַ/שַּׁבָּת֙ הַ/שְּׁבִיעִ֔ת תִּסְפְּר֖וּ חֲמִשִּׁ֣ים י֑וֹם וְ/הִקְרַבְתֶּ֛ם מִנְחָ֥ה חֲדָשָׁ֖ה לַ/יהוָֽה", "en": {"kjv": "Even unto the morrow after the seventh sabbath shall ye number fifty days; and ye shall offer a new meat offering unto the Lord.", "web": "even to the next day after the seventh Sabbath you shall number fifty days; and you shall offer a new meal offering to Yahweh.", "bsb": "You shall count off fifty days until the day after the seventh Sabbath, and then present an offering of new grain to the LORD.", "asv": "even unto the morrow after the seventh sabbath shall ye number fifty days; and ye shall offer a new meal-offering unto Jehovah.", "ylt": "unto the morrow of the seventh sabbath ye do number fifty days, and ye have brought near a new present to Jehovah;", "tyndale": "euen vnto the morow after the .vij. weke ye shall numbre .l. dayes. And the ye shal bringe a newe meatoffrynge unto the Lorde.", "dra": "Even unto the morrow after the seventh week be expired, that is to say, fifty days: and so you shall offer a new sacrifice to the Lord.", "bbe": "Let fifty days be numbered, to the day after the seventh Sabbath; then you are to give a new meal offering to the Lord.", "geneva": "Vnto ye morow after the seuenth Sabbath shall ye nomber fiftie dayes: then yee shall bring a newe meate offring vnto the Lord.", "wycliffe": "seuene fulle woukis, til to the tothir day of fillyng of the seuenthe wouk, that is, fifti dayes; and so ye schulen", "rotherham": "until on the morrow of the seventh sabbath, ye count fifty days,—then shall ye bring near a new meal-offering unto Yahweh.", "darby": "even unto the morning after the seventh sabbath shall ye count fifty days; and ye shall present a new oblation to Jehovah.", "twenty": "", "jps": "even unto the morrow after the seventh week shall ye number fifty days; and ye shall present a new meal-offering unto HaShem.", "acv": "Ye shall number fifty days, even to the morrow after the seventh sabbath, and ye shall offer a new meal offering to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "Even to the morrow after the seventh sabbath shall ye number fifty days; and ye shall offer a new meat-offering to the LORD.", "vulgate": "usque ad alteram diem expletionis ebdomadae septimae id est quinquaginta dies et sic offeretis sacrificium novum Domino;", "brenton": "until the morrow after the last week ye shall number fifty days, and shall bring a new meat-offering to the Lord."}}, {"v": 17, "ref": "23:17", "o": "מִ/מּוֹשְׁבֹ֨תֵי/כֶ֜ם תָּבִ֣יאּוּ לֶ֣חֶם תְּנוּפָ֗ה שְׁ֚תַּיִם שְׁנֵ֣י עֶשְׂרֹנִ֔ים סֹ֣לֶת תִּהְיֶ֔ינָה חָמֵ֖ץ תֵּאָפֶ֑ינָה בִּכּוּרִ֖ים לַֽ/יהוָֽה", "en": {"kjv": "Ye shall bring out of your habitations two wave loaves of two tenth deals: they shall be of fine flour; they shall be baken with leaven; they are the firstfruits unto the Lord.", "web": "You shall bring out of your habitations two loaves of bread for a wave offering made of two tenth parts of an ephah of fine flour. They shall be baked with yeast, for first fruits to Yahweh.", "bsb": "Bring two loaves of bread from your dwellings as a wave offering, each made from two-tenths of an ephah of fine flour, baked with leaven, as the firstfruits to the LORD.", "asv": "Ye shall bring out of your habitations two wave-loaves of two tenth parts of an ephah: they shall be of fine flour, they shall be baken with leaven, for first-fruits unto Jehovah.", "ylt": "out of your dwellings ye bring in bread of a wave-offering, two loaves , of two tenth deals of flour they are, with yeast they are baken, first- fruits to Jehovah.", "tyndale": "And ye shall brynge out of youre habitacions two waueloaues made of two tenthdeales off fine floure leuended and baken, for first frutes vnto the Lorde.", "dra": "Out of all your dwellings, two loaves of the firstfruits, of two tenths of flour leavened, which you shall bake for the firstfruits of the Lord.", "bbe": "Take from your houses two cakes of bread, made of a fifth part of an ephah of the best meal, cooked with leaven, to be waved for first-fruits to the Lord.", "geneva": "Ye shall bring out of your habitations bread for the shake offring: they shalbe two loaues of two tenth deales of fine floure, which shalbe baken with leauen for first fruites vnto the Lord.", "wycliffe": "offre newe sacrifice to the Lord of alle youre dwelling placis, twei looues of the firste fruytis, of twei tenthe partis of flour, `diyt with soure dow, whiche looues ye schulen bake in to the firste fruytis to the Lord.", "rotherham": "Out of your dwellings, shall ye bring in two wave loaves of two-tenths of an ephah, of fine meal, shall they be, with leaven, shall they be baked,—first-fruits unto Yahweh.", "darby": "Out of your dwellings shall ye bring two wave-loaves, of two tenths of fine flour; with leaven shall they be baken; [as] first-fruits to Jehovah.", "twenty": "", "jps": "Ye shall bring out of your dwellings two wave-loaves of two tenth parts of an ephah; they shall be of fine flour, they shall be baked with leaven, for first-fruits unto HaShem.", "acv": "Ye shall bring out of your habitations two wave-loaves of two tenth parts of an ephah. They shall be of fine flour. They shall be baked with leaven, for first-fruits to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "Ye shall bring out of your habitations two wave-loaves of two tenth-parts: they shall be of fine flour, they shall be baked with leaven, [they are] the first-fruits to the LORD.", "vulgate": "ex omnibus habitaculis vestris panes primitiarum duos de duabus decimis similae fermentatae quos coquetis in primitias Domini;", "brenton": "Ye shall bring from your dwelling loaves, as a heave-offering, two loaves: they shall be of two tenth portions of fine flour, they shall be baked with leaven of the first-fruits to the Lord."}}, {"v": 18, "ref": "23:18", "o": "וְ/הִקְרַבְתֶּ֣ם עַל הַ/לֶּ֗חֶם שִׁבְעַ֨ת כְּבָשִׂ֤ים תְּמִימִם֙ בְּנֵ֣י שָׁנָ֔ה וּ/פַ֧ר בֶּן בָּקָ֛ר אֶחָ֖ד וְ/אֵילִ֣ם שְׁנָ֑יִם יִהְי֤וּ עֹלָה֙ לַֽ/יהוָ֔ה וּ/מִנְחָתָ/ם֙ וְ/נִסְכֵּי/הֶ֔ם אִשֵּׁ֥ה רֵֽיחַ נִיחֹ֖חַ לַ/יהוָֽה", "en": {"kjv": "And ye shall offer with the bread seven lambs without blemish of the first year, and one young bullock, and two rams: they shall be for a burnt offering unto the Lord, with their meat offering, and their drink offerings, even an offering made by fire, of sweet savour unto the Lord.", "web": "You shall present with the bread seven lambs without defect a year old, one young bull, and two rams. They shall be a burnt offering to Yahweh, with their meal offering, and their drink offerings, even an offering made by fire, of a sweet aroma to Yahweh.", "bsb": "Along with the bread you are to present seven unblemished male lambs a year old, one young bull, and two rams. They will be a burnt offering to the LORD, together with their grain offerings and drink offerings—an offering made by fire, a pleasing aroma to the LORD.", "asv": "And ye shall present with the bread seven lambs without blemish a year old, and one young bullock, and two rams: they shall be a burnt-offering unto Jehovah, with their meal-offering, and their drink-offerings, even an offering made by fire, of a sweet savor unto Jehovah.", "ylt": "`And ye have brought near, besides the bread, seven lambs, perfect ones, sons of a year, and one bullock, a son of the herd, and two rams; they are a burnt-offering to Jehovah, with their present and their libations, a fire-offering of sweet fragrance to Jehovah.", "tyndale": "And ye shall bringe with the bred seuen lambes without deformyte of one yere of age, and one yonge oxe and .ij. rambes, which shall serue for burntoffrynges vnto the Lorde, with meatoffringes and drinkoffringes longinge to the same, to be a sacrifice of a swete sauoure vnto the Lorde.", "dra": "And you shall offer with the loaves seven lambs without blemish of the first year, and one calf from the herd, and they shall be for a holocaust with their two rams: and they shall be for a holocaust with their libations for a most sweet odour to the Lord.", "bbe": "And with the bread, take seven lambs of the first year, without any marks, and one ox and two male sheep, to be a burned offering to the Lord, with their meal offering and their drink offerings, an offering of a sweet smell made by fire to the Lord.", "geneva": "Also yee shall offer with the bread seuen lambes without blemish of one yeere olde, and a yong bullocke and two rams: they shalbe for a burnt offring vnto the Lord, with their meate offrings and their drinke offrings, for a sacrifice made by fire of a sweete sauour vnto the Lord.", "wycliffe": "And ye schulen offre with the looues seuene lambren of o yeer with out wem, and o calf of the droue, and twey rammes, and these schulen be in brent sacrifice, with her fletynge offryngis, in to swettest odour to the Lord.", "rotherham": "Then shall ye bring near with the bread seven he-lambs without defect of the first year, and one young bullock, and two rams,—they shall be an ascending-sacrifice unto Yahweh, with their meal-offering, and their drink-offerings, an altar-flame of satisfying odour unto Yahweh.", "darby": "And ye shall present with the bread seven he-lambs without blemish, yearlings, and one young bullock, and two rams: they shall be a burnt-offering to Jehovah with their oblation, and their drink-offerings, an offering by fire of a sweet odour to Jehovah.", "twenty": "", "jps": "And ye shall present with the bread seven lambs without blemish of the first year, and one young bullock, and two rams; they shall be a burnt-offering unto HaShem, with their meal-offering, and their drink-offerings, even an offering made by fire, of a sweet savour unto HaShem.", "acv": "And ye shall present with the bread seven lambs without blemish a year old, and one young bullock, and two rams. They shall be a burnt offering to Jehovah, with their meal offering, and their drink offerings, even an offering made by fire, of a sweet savor to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And ye shall offer with the bread seven lambs without blemish of the first year, and one young bullock, and two rams: they shall be [for] a burnt-offering to the LORD, with their meat-offering, and their drink offerings, [even] an offering made by fire of a sweet savor to the LORD.", "vulgate": "offeretisque cum panibus septem agnos inmaculatos anniculos et vitulum de armento unum et arietes duos et erunt in holocausto cum libamentis suis in odorem suavissimum Domino;", "brenton": "And ye shall bring with the loaves seven unblemished lambs of a year old, and one calf of the herd, and two rams without blemish, and they shall be a whole-burnt-offering to the Lord: and their meat-offerings and their drink-offerings shall be a sacrifice, a smell of sweet savour to the Lord."}}, {"v": 19, "ref": "23:19", "o": "וַ/עֲשִׂיתֶ֛ם שְׂעִיר עִזִּ֥ים אֶחָ֖ד לְ/חַטָּ֑את וּ/שְׁנֵ֧י כְבָשִׂ֛ים בְּנֵ֥י שָׁנָ֖ה לְ/זֶ֥בַח שְׁלָמִֽים", "en": {"kjv": "Then ye shall sacrifice one kid of the goats for a sin offering, and two lambs of the first year for a sacrifice of peace offerings.", "web": "You shall offer one male goat for a sin offering, and two male lambs a year old for a sacrifice of peace offerings.", "bsb": "You shall also prepare one male goat as a sin offering and two male lambs a year old as a peace offering.", "asv": "And ye shall offer one he-goat for a sin-offering, and two he-lambs a year old for a sacrifice of peace-offerings.", "ylt": "`And ye have prepared one kid of the goats for a sin-offering, and two lambs, sons of a year, for a sacrifice of peace-offerings,", "tyndale": "And ye shall offer an he goote for a synneofferinge: and two lambes of one yere old for peaceoffringes,", "dra": "You shall offer also a buck goat for sin, and two lambs of the first year for sacrifices of peace offerings.", "bbe": "And you are to give one male goat for a sin-offering and two male lambs of the first year for peace-offerings.", "geneva": "Then ye shall prepare an hee goate for a sinne offring, and two lambes of one yeere olde for peace offrings.", "wycliffe": "Ye schulen make also a buk of geet for synne, and twey lambren of o yeer, sacrificis of pesible thingis.", "rotherham": "Then shall ye offer one he-goat, as a sin-bearer,—and two he-lambs, of the first year, as a peace-offering.", "darby": "And ye shall sacrifice one buck of the goats for a sin-offering, and two he-lambs, yearlings, for a sacrifice of peace-offering.", "twenty": "", "jps": "And ye shall offer one he-goat for a sin-offering, and two he-lambs of the first year for a sacrifice of peace-offerings.", "acv": "And ye shall offer one he-goat for a sin offering, and two he-lambs a year old for a sacrifice of peace offerings.", "anderson": "", "haweis": "", "noyes": "", "webster": "Then ye shall sacrifice one kid of the goats for a sin-offering, and two lambs of the first year for a sacrifice of peace-offerings.", "vulgate": "facietis et hircum pro peccato duosque agnos anniculos hostias pacificorum;", "brenton": "And they shall sacrifice one kid of the goats for a sin-offering, and two lambs of a year old for a peace-offering, with the loaves of the first-fruits."}}, {"v": 20, "ref": "23:20", "o": "וְ/הֵנִ֣יף הַ/כֹּהֵ֣ן אֹתָ֡/ם עַל֩ לֶ֨חֶם הַ/בִּכּוּרִ֤ים תְּנוּפָה֙ לִ/פְנֵ֣י יְהוָ֔ה עַל שְׁנֵ֖י כְּבָשִׂ֑ים קֹ֛דֶשׁ יִהְי֥וּ לַ/יהוָ֖ה לַ/כֹּהֵֽן", "en": {"kjv": "And the priest shall wave them with the bread of the firstfruits for a wave offering before the Lord, with the two lambs: they shall be holy to the Lord for the priest.", "web": "The priest shall wave them with the bread of the first fruits for a wave offering before Yahweh, with the two lambs. They shall be holy to Yahweh for the priest.", "bsb": "The priest is to wave the lambs as a wave offering before the LORD, together with the bread of the firstfruits. The bread and the two lambs shall be holy to the LORD for the priest.", "asv": "And the priest shall wave them with the bread of the first-fruits for a wave-offering before Jehovah, with the two lambs: they shall be holy to Jehovah for the priest.", "ylt": "and the priest hath waved them, besides the bread of the first- fruits --a wave-offering before Jehovah, besides the two lambs; they are holy to Jehovah for the priest;", "tyndale": "And the preast shall waue the with the bred of the first frutes before the Lorde, and with the two lambes. And they shalbe holy vnto the Lorde, and be the preastes.", "dra": "And when the priest hath lifted them up with the loaves of the firstfruits before the Lord, they shall fall to his use.", "bbe": "And these will be waved by the priest, with the bread of the first-fruits, for a wave offering to the Lord, with the two lambs: they will be holy to the Lord for the priest.", "geneva": "And the Priest shall shake them to and from with the bread of the first fruits before the Lord, and with the two lambes: they shalbe holy to the Lord, for the Priest.", "wycliffe": "And whanne the preest hath reisid tho, with the looues of firste fruytys bifor the Lord, tho schulen falle in to his vss.", "rotherham": "And the priest shall wave them, with the firstfruits’ bread, as a wave-offering before Yahweh, with the two he-lambs,—holy, shall they be unto Yahweh, for the priest.", "darby": "And the priest shall wave them with the bread of the first-fruits as a wave-offering before Jehovah, with the two he-lambs; they shall be holy to Jehovah, for the priest.", "twenty": "", "jps": "And the priest shall wave them with the bread of the first-fruits for a wave-offering before HaShem, with the two lambs; they shall be holy to HaShem for the priest.", "acv": "And the priest shall wave them with the bread of the first-fruits for a wave offering before Jehovah, with the two lambs. They shall be holy to Jehovah for the priest.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall wave them with the bread of the first-fruits [for] a wave-offering before the LORD, with the two lambs: they shall be holy to the LORD for the priest.", "vulgate": "cumque elevaverit eos sacerdos cum panibus primitiarum coram Domino cedent in usum eius;", "brenton": "And the priest shall place them with the loaves of the first-fruits an offering before the Lord with the two lambs, they shall be holy to the Lord; they shall belong to the priest that brings them."}}, {"v": 21, "ref": "23:21", "o": "וּ/קְרָאתֶ֞ם בְּ/עֶ֣צֶם הַ/יּ֣וֹם הַ/זֶּ֗ה מִֽקְרָא קֹ֨דֶשׁ֙ יִהְיֶ֣ה לָ/כֶ֔ם כָּל מְלֶ֥אכֶת עֲבֹדָ֖ה לֹ֣א תַעֲשׂ֑וּ חֻקַּ֥ת עוֹלָ֛ם בְּ/כָל מוֹשְׁבֹ֥תֵי/כֶ֖ם לְ/דֹרֹֽתֵי/כֶֽם", "en": {"kjv": "And ye shall proclaim on the selfsame day, that it may be an holy convocation unto you: ye shall do no servile work therein: it shall be a statute for ever in all your dwellings throughout your generations.", "web": "You shall make proclamation on the same day: there shall be a holy convocation to you; you shall do no regular work. This is a statute forever in all your dwellings throughout your generations.", "bsb": "On that same day you are to proclaim a sacred assembly, and you must not do any regular work. This is to be a permanent statute wherever you live for the generations to come.", "asv": "And ye shall make proclamation on the selfsame day; there shall be a holy convocation unto you; ye shall do no servile work: it is a statute for ever in all your dwellings throughout your generations.", "ylt": "and ye have proclaimed on this self-same day: a holy convocation is to you, ye do no servile work--a statute age-during in all your dwellings, to your generations.", "tyndale": "And ye shall make a proclamacio the same daye that it be an holy feast vnto you, and ye shall do no laborious worke therein: And it shalbe a lawe for euer thorowe out all youre habitacions vnto youre childern after you,", "dra": "And you shall call this day most solemn, and most holy. You shall do no servile work therein. It shall be an everlasting ordinance in all your dwellings and generations.", "bbe": "And on the same day, let it be given out that there will be a holy meeting for you: you may do no field-work on that day: it is a rule for ever through all your generations wherever you are living.", "geneva": "So ye shall proclayme the same day, that it may be an holie conuocation vnto you: ye shall doe no seruile worke therein: it shalbe an ordinance for euer in al your dwellinges, throughout your generations.", "wycliffe": "And ye schulen clepe this dai most solempne, and moost hooli; ye schulen not do ther ynne ony seruyle werk; it schal be a lawful thing euerlastynge in alle youre dwellyngis, and generaciouns.", "rotherham": "And ye shall make proclamation on this self-same day—a holy convocation, shall it be unto you; no laborious work, shall ye do,—an age-abiding statute in all your dwellings, unto your generations.", "darby": "And ye shall make proclamation on that same day — a holy convocation shall it be unto you: no manner of servile work shall ye do: [it is] an everlasting statute in all your dwellings throughout your generations.", "twenty": "", "jps": "And ye shall make proclamation on the selfsame day; there shall be a holy convocation unto you; ye shall do no manner of servile work; it is a statute for ever in all your dwellings throughout your generations.", "acv": "And ye shall make proclamation on the selfsame day, there shall be a holy convocation to you. Ye shall do no job work. It is a statute forever in all your dwellings throughout your generations.", "anderson": "", "haweis": "", "noyes": "", "webster": "And ye shall proclaim on the same day, [that] it may be a holy convocation to you: ye shall do no servile work [in it]. [it shall be] a statute for ever in all your dwellings throughout your generations.", "vulgate": "et vocabitis hunc diem celeberrimum atque sanctissimum omne opus servile non facietis in eo legitimum sempiternum erit in cunctis habitaculis et generationibus vestris;", "brenton": "And ye shall call this day a convocation: it shall be holy to you; ye shall do no servile work on it: it is a perpetual ordinance throughout your generations in all your habitations."}}, {"v": 22, "ref": "23:22", "o": "וּֽ/בְ/קֻצְרְ/כֶ֞ם אֶת קְצִ֣יר אַרְצְ/כֶ֗ם לֹֽא תְכַלֶּ֞ה פְּאַ֤ת שָֽׂדְ/ךָ֙ בְּ/קֻצְרֶ֔/ךָ וְ/לֶ֥קֶט קְצִירְ/ךָ֖ לֹ֣א תְלַקֵּ֑ט לֶֽ/עָנִ֤י וְ/לַ/גֵּר֙ תַּעֲזֹ֣ב אֹתָ֔/ם אֲנִ֖י יְהוָ֥ה אֱלֹהֵי/כֶֽם", "en": {"kjv": "And when ye reap the harvest of your land, thou shalt not make clean riddance of the corners of thy field when thou reapest, neither shalt thou gather any gleaning of thy harvest: thou shalt leave them unto the poor, and to the stranger: I am the Lord your God.", "web": "“‘When you reap the harvest of your land, you shall not wholly reap into the corners of your field, neither shall you gather the gleanings of your harvest: you shall leave them for the poor, and for the foreigner. I am Yahweh your God.’”", "bsb": "When you reap the harvest of your land, do not reap all the way to the edges of your field or gather the gleanings of your harvest. Leave them for the poor and the foreign resident. I am the LORD your God.’”", "asv": "And when ye reap the harvest of your land, thou shalt not wholly reap the corners of thy field, neither shalt thou gather the gleaning of thy harvest: thou shalt leave them for the poor, and for the sojourner: I am Jehovah your God.", "ylt": "`And in your reaping the harvest of your land thou dost not complete the corner of thy field in thy reaping, and the gleaning of thy harvest thou dost not gather, to the poor and to the sojourner thou dost leave them; I Jehovah am your God.'", "tyndale": "When ye repe doune youre haruest, thou shalt not make cleane ryddaunce off thy felde, nether shalt thou make any aftergatheringe of thy haruest: but shalt leue them vnto the poore and the straunger. I am the Lorde youre God.", "dra": "And when you reap the corn of your land, you shall not cut it to the very ground: neither shall you gather the ears that remain. But you shall leave them for the poor and for the strangers. I am the Lord your God.", "bbe": "And when you get in the grain from your land, do not let all the grain at the edges of the field be cut, and do not take up the grain which has been dropped in the field; let that be for the poor, and for the man from another country: I am the Lord your God.", "geneva": "And when you reape the haruest of your land, thou shalt not rid cleane the corners of thy field when thou reapest, neither shalt thou make any aftergathering of thy haruest, but shalt leaue them vnto the poore and to the stranger: I am the Lord your God.", "wycliffe": "Forsothe aftir that ye han rope the corn of youre lond, ye schulen not kitte it `til to the ground, nether ye schulen gadere the `eeris of corn abidynge, but ye schulen leeue tho to pore men and pilgrymys; Y am `youre Lord God.", "rotherham": "And, when ye reap the harvest of your land, thou shalt not wholly clear the border of thy field when thou reapest, and, the gleanings of thy field, shalt thou not glean,—for the poor and for the sojourner, shalt thou leave them. I—Yahweh, am your God.", "darby": "And when ye reap the harvest of your land, thou shalt not in thy harvest entirely reap the corners of thy field, and the gleaning of thy harvest shalt thou not gather: thou shalt leave them unto the poor and to the stranger: I am Jehovah yourGod.", "twenty": "", "jps": "And when ye reap the harvest of your land, thou shalt not wholly reap the corner of thy field, neither shalt thou gather the gleaning of thy harvest; thou shalt leave them for the poor, and for the stranger: I am HaShem your G-d.", "acv": "And when ye reap the harvest of your land, thou shall not wholly reap the corners of thy field, neither shall thou gather the gleaning of thy harvest. Thou shall leave them for the poor man, and for the sojourner. I am Jehovah your God.", "anderson": "", "haweis": "", "noyes": "", "webster": "And when ye reap the harvest of your land, thou shalt not make clean riddance of the corners of thy field when thou reapest, neither shalt thou gather any gleaning of thy harvest: thou shalt leave them to the poor, and to the stranger: I [am] the LORD your God.", "vulgate": "postquam autem messueritis segetem terrae vestrae non secabitis eam usque ad solum nec remanentes spicas colligetis sed pauperibus et peregrinis dimittetis eas ego Dominus Deus vester;", "brenton": "And when ye shall reap the harvest of your land, ye shall not fully reap the remainder of the harvest of your field when thou reapest, and thou shalt not gather that which falls from thy reaping; thou shalt leave it for the poor and the stranger: I am the Lord your God."}}, {"v": 23, "ref": "23:23", "o": "וַ/יְדַבֵּ֥ר יְהוָ֖ה אֶל מֹשֶׁ֥ה לֵּ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh spoke to Moses, saying,", "bsb": "The LORD also said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde spake vnto Moses saynge:", "dra": "And the Lord spoke to Moses, saying:", "bbe": "And the Lord said to Moses,", "geneva": "And the Lord spake vnto Moses, saying,", "wycliffe": "And the Lord spak to Moises, and seide,", "rotherham": "And Yahweh spake unto Moses, saying:", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses, saying:", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "locutusque est Dominus ad Mosen dicens;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 24, "ref": "23:24", "o": "דַּבֵּ֛ר אֶל בְּנֵ֥י יִשְׂרָאֵ֖ל לֵ/אמֹ֑ר בַּ/חֹ֨דֶשׁ הַ/שְּׁבִיעִ֜י בְּ/אֶחָ֣ד לַ/חֹ֗דֶשׁ יִהְיֶ֤ה לָ/כֶם֙ שַׁבָּת֔וֹן זִכְר֥וֹן תְּרוּעָ֖ה מִקְרָא קֹֽדֶשׁ", "en": {"kjv": "Speak unto the children of Israel, saying, In the seventh month, in the first day of the month, shall ye have a sabbath, a memorial of blowing of trumpets, an holy convocation.", "web": "“Speak to the children of Israel, saying, ‘In the seventh month, on the first day of the month, shall be a solemn rest to you, a memorial of blowing of trumpets, a holy convocation.", "bsb": "“Speak to the Israelites and say, ‘On the first day of the seventh month you are to have a day of rest, a sacred assembly announced by trumpet blasts.", "asv": "Speak unto the children of Israel, saying, In the seventh month, on the first day of the month, shall be a solemn rest unto you, a memorial of blowing of trumpets, a holy convocation.", "ylt": "`Speak unto the sons of Israel, saying, In the seventh month, on the first of the month, ye have a sabbath, a memorial of shouting, a holy convocation;", "tyndale": "speake vnto the childern of Israel ad saye. The first daye of the suenth moneth shalbe a rest of remembraunce vnto you, to blowe hornes in an holy feast it shalbe,", "dra": "Say to the children of Israel: The seventh month, on the first day of the month, you shall keep a sabbath, a memorial, with the sound of trumpets, and it shall be called holy.", "bbe": "Say to the children of Israel, In the seventh month, on the first day of the month, let there be a special day of rest for you, a day of memory, marked by the blowing of horns, a meeting for worship.", "geneva": "Speake vnto the children of Israel, and say, In the seuenth moneth, and in the first day of the moneth shall ye haue a Sabbath, for the remembrance of blowing the trumpets, an holy conuocation.", "wycliffe": "Speke thou to the sones of Israel, In the seuenthe monethe, in the firste day of the monethe, schal be sabat memorial to yow, sownynge with trumpis, and it schal be clepid hooli;", "rotherham": "Speak unto the sons of Israel, saying:—In the seventh month on the first of the month, shall there be unto you a sacred rest, a trumpet-blowing commemoration a holy convocation:", "darby": "Speak unto the children of Israel, saying, In the seventh month, on the first of the month, shall ye have a rest, a memorial of blowing of trumpets, a holy convocation.", "twenty": "", "jps": "Speak unto the children of Israel, saying: In the seventh month, in the first day of the month, shall be a solemn rest unto you, a memorial proclaimed with the blast of horns, a holy convocation.", "acv": "Speak to the sons of Israel, saying, In the seventh month, on the first day of the month, shall be a solemn rest to you, a memorial of blowing of trumpets, a holy convocation.", "anderson": "", "haweis": "", "noyes": "", "webster": "Speak to the children of Israel, saying, In the seventh month, in the first [day] of the month, shall ye have a sabbath, a memorial of blowing of trumpets, a holy convocation.", "vulgate": "loquere filiis Israhel mense septimo prima die mensis erit vobis sabbatum memorabile clangentibus tubis et vocabitur sanctum;", "brenton": "Speak to the children of Israel, saying, In the seventh month, on the first day of the month, ye shall have a rest, a memorial of trumpets: it shall be to you a holy convocation."}}, {"v": 25, "ref": "23:25", "o": "כָּל מְלֶ֥אכֶת עֲבֹדָ֖ה לֹ֣א תַעֲשׂ֑וּ וְ/הִקְרַבְתֶּ֥ם אִשֶּׁ֖ה לַ/יהוָֽה", "en": {"kjv": "Ye shall do no servile work therein: but ye shall offer an offering made by fire unto the Lord.", "web": "You shall do no regular work; and you shall offer an offering made by fire to Yahweh.’”", "bsb": "You must not do any regular work, but you are to present an offering made by fire to the LORD.’”", "asv": "Ye shall do no servile work; and ye shall offer an offering made by fire unto Jehovah.", "ylt": "ye do no servile work, and ye have brought near a fire-offering to Jehovah.'", "tyndale": "and ye shall do no laborious worke therein, and ye shall offer sacrifice vnto the Lorde.", "dra": "You shall do no servile work therein, and you shall offer a holocaust to the Lord.", "bbe": "Do no field-work and give to the Lord an offering made by fire.", "geneva": "Ye shall do no seruile worke therein, but offer sacrifice made by fire vnto the Lord.", "wycliffe": "ye schulen not do ony seruyle werk ther ynne, and ye schulen offre brent sacrifice to the Lord.", "rotherham": "no laborious work, shall ye do,—but ye shall bring near an altar-flame unto Yahweh.", "darby": "No manner of servile work shall ye do; and ye shall present an offering by fire to Jehovah.", "twenty": "", "jps": "Ye shall do no manner of servile work; and ye shall bring an offering made by fire unto HaShem.", "acv": "Ye shall do no job work, and ye shall offer an offering made by fire to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "Ye shall do no servile work [in it]; but ye shall offer an offering made by fire to the LORD.", "vulgate": "omne opus servile non facietis in eo et offeretis holocaustum Domino;", "brenton": "Ye shall do no servile work, and ye shall offer a whole-burnt-offering to the Lord."}}, {"v": 26, "ref": "23:26", "o": "וַ/יְדַבֵּ֥ר יְהוָ֖ה אֶל מֹשֶׁ֥ה לֵּ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh spoke to Moses, saying,", "bsb": "Again the LORD said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde spake vnto Moses sayenge:", "dra": "And the Lord spoke to Moses, saying:", "bbe": "And the Lord said to Moses,", "geneva": "And the Lord spake vnto Moses, saying,", "wycliffe": "And the Lord spak to Moises, and seide, In the tenthe day of this seuenthe monethe,", "rotherham": "And Yahweh spake unto Moses, saying,", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses, saying:", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "locutusque est Dominus ad Mosen dicens;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 27, "ref": "23:27", "o": "אַ֡ךְ בֶּ/עָשׂ֣וֹר לַ/חֹדֶשׁ֩ הַ/שְּׁבִיעִ֨י הַ/זֶּ֜ה י֧וֹם הַ/כִּפֻּרִ֣ים ה֗וּא מִֽקְרָא קֹ֨דֶשׁ֙ יִהְיֶ֣ה לָ/כֶ֔ם וְ/עִנִּיתֶ֖ם אֶת נַפְשֹׁתֵי/כֶ֑ם וְ/הִקְרַבְתֶּ֥ם אִשֶּׁ֖ה לַ/יהוָֽה", "en": {"kjv": "Also on the tenth day of this seventh month there shall be a day of atonement: it shall be an holy convocation unto you; and ye shall afflict your souls, and offer an offering made by fire unto the Lord.", "web": "“However on the tenth day of this seventh month is the day of atonement: it shall be a holy convocation to you, and you shall afflict yourselves; and you shall offer an offering made by fire to Yahweh.", "bsb": "“The tenth day of this seventh month is the Day of Atonement. You shall hold a sacred assembly and humble yourselves, and present an offering made by fire to the LORD.", "asv": "Howbeit on the tenth day of this seventh month is the day of atonement: it shall be a holy convocation unto you, and ye shall afflict your souls; and ye shall offer an offering made by fire unto Jehovah.", "ylt": "`Only--on the tenth of this seventh month is a day of atonements; ye have a holy convocation, and ye have humbled yourselves, and have brought near a fire-offering to Jehovah;", "tyndale": "also the tenth daye of the selfe seueth moneth, is a daye of an attonement, and shalbe on holy feast vnto you, ad ye shall humble youre soules and offer sacrifice vnto the Lorde.", "dra": "Upon the tenth day of this seventh month shall be the day of atonement. It shall be most solemn, and shall be called holy: and you shall await your souls on that day, and shall offer a holocaust to the Lord.", "bbe": "The tenth day of this seventh month is the day for the taking away of sin; let it be a holy day of worship; you are to keep from pleasure, and give to the Lord an offering made by fire.", "geneva": "The tenth also of this seuenth moneth shalbe a day of reconciliation: it shalbe an holie conuocation vnto you, and yee shall humble your soules, and offer sacrifice made by fire vnto the Lord.", "wycliffe": "the day of clensyngis schal be moost solempne, and it schal be clepid hooli; and ye schulen turmente youre soulis to God, and ye schulen offre brent sacrifice to the Lord;", "rotherham": "Surely on the tenth of this seventh month, is, the Day of Propitiation, a holy convocation, shall it be to you, therefore shall ye humble your souls,—and bring near an altar-flame unto Yahweh.", "darby": "Also on the tenth of this seventh month is the day of the atonement: a holy convocation shall it be unto you; and ye shall afflict your souls, and present an offering by fire to Jehovah.", "twenty": "", "jps": "Howbeit on the tenth day of this seventh month is the day of atonement; there shall be a holy convocation unto you, and ye shall afflict your souls; and ye shall bring an offering made by fire unto HaShem.", "acv": "However on the tenth day of this seventh month is the day of atonement. It shall be a holy convocation to you, and ye shall afflict your souls, and ye shall offer an offering made by fire to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "Also on the tenth [day] of this seventh month [there shall be] a day of atonement; it shall be a holy convocation to you, and ye shall afflict your souls, and offer an offering made by fire to the LORD.", "vulgate": "decimo die mensis huius septimi dies expiationum erit celeberrimus et vocabitur sanctus adfligetisque animas vestras in eo et offeretis holocaustum Domino;", "brenton": "Also on the tenth day of this seventh month is a day of atonement: it shall be a holy convocation to you; and ye shall humble your souls, and offer a whole-burnt-offering to the Lord."}}, {"v": 28, "ref": "23:28", "o": "וְ/כָל מְלָאכָה֙ לֹ֣א תַעֲשׂ֔וּ בְּ/עֶ֖צֶם הַ/יּ֣וֹם הַ/זֶּ֑ה כִּ֣י י֤וֹם כִּפֻּרִים֙ ה֔וּא לְ/כַפֵּ֣ר עֲלֵי/כֶ֔ם לִ/פְנֵ֖י יְהוָ֥ה אֱלֹהֵי/כֶֽם", "en": {"kjv": "And ye shall do no work in that same day: for it is a day of atonement, to make an atonement for you before the Lord your God.", "web": "You shall do no kind of work in that same day; for it is a day of atonement, to make atonement for you before Yahweh your God.", "bsb": "On this day you are not to do any work, for it is the Day of Atonement, when atonement is made for you before the LORD your God.", "asv": "And ye shall do no manner of work in that same day; for it is a day of atonement, to make atonement for you before Jehovah your God.", "ylt": "and ye do no work in this self-same day, for it is a day of atonements, to make atonement for you, before Jehovah your God.", "tyndale": "Moreouer ye shall do no worke the same daye, for it is a daye of attonement to make an attonemet for you before the Lord your God.", "dra": "You shall do no servile work in the time of this day: because it is a day of propitiation, that the Lord your God may be merciful unto you.", "bbe": "And on that day you may do no sort of work, for it is a day of taking away sin, to make you clean before the Lord your God.", "geneva": "And ye shall doe no worke that same day: for it is a day of reconciliation, to make an atonement for you before the Lord your God.", "wycliffe": "ye schulen not do ony werk in the tyme of this day, for it is the day of the clensyng, that youre Lord God be merciful to you.", "rotherham": "And, no work, shall ye do, on this selfsame day,—for a day of propitiation, it is, to put a propitiatory-covering over you before Yahweh your God.", "darby": "And ye shall do no manner of work on that same day; for it is a day of atonement, to make atonement for you before Jehovah yourGod.", "twenty": "", "jps": "And ye shall do no manner of work in that same day; for it is a day of atonement, to make atonement for you before HaShem your G-d.", "acv": "And ye shall do no manner of work in that same day, for it is a day of atonement, to make atonement for you before Jehovah your God.", "anderson": "", "haweis": "", "noyes": "", "webster": "And ye shall do no work in that same day; for it [is] a day of atonement, to make an atonement for you before the LORD your God.", "vulgate": "omne opus non facietis in tempore diei huius quia dies propitiationis est ut propitietur vobis Dominus Deus vester;", "brenton": "Ye shall do no work on this self-same day: for this is a day of atonement for you, to make atonement for you before the Lord your God."}}, {"v": 29, "ref": "23:29", "o": "כִּ֤י כָל הַ/נֶּ֨פֶשׁ֙ אֲשֶׁ֣ר לֹֽא תְעֻנֶּ֔ה בְּ/עֶ֖צֶם הַ/יּ֣וֹם הַ/זֶּ֑ה וְ/נִכְרְתָ֖ה מֵֽ/עַמֶּֽי/הָ", "en": {"kjv": "For whatsoever soul it be that shall not be afflicted in that same day, he shall be cut off from among his people.", "web": "For whoever it is who shall not deny himself in that same day; shall be cut off from his people.", "bsb": "If anyone does not humble himself on this day, he must be cut off from his people.", "asv": "For whatsoever soul it be that shall not be afflicted in that same day; he shall be cut off from his people.", "ylt": "`For any person who is not humbled in this self-same day hath even been cut off from his people;", "tyndale": "For what soeuer soule it be that humbleth not him selfe that daye, he shalbe destroyde from amonge his people.", "dra": "Every soul that is not afflicted on this day, shall perish from among his people.", "bbe": "For any person, whoever he may be, who takes his pleasure on that day will be cut off from his people.", "geneva": "For euery person that humbleth not himselfe that same day, shall euen be cut off from his people.", "wycliffe": "Ech `man which is not tourmentid in this day, schal perische fro his puplis,", "rotherham": "For, whosoever be the person that shall not be humbled on this selfsame day, then shall he be cut off from among his kinsfolk.", "darby": "For every soul that is not afflicted on that same day, shall be cut off from among his peoples.", "twenty": "", "jps": "For whatsoever soul it be that shall not be afflicted in that same day, he shall be cut off from his people.", "acv": "For whatever soul it be who shall not be afflicted in that same day, he shall be cut off from his people.", "anderson": "", "haweis": "", "noyes": "", "webster": "For whatever soul [it may be] that shall not be afflicted in that same day, he shall be cut off from among his people.", "vulgate": "omnis anima quae adflicta non fuerit die hoc peribit de populis suis;", "brenton": "Every soul that shall not be humbled in that day, shall be cut off from among its people."}}, {"v": 30, "ref": "23:30", "o": "וְ/כָל הַ/נֶּ֗פֶשׁ אֲשֶׁ֤ר תַּעֲשֶׂה֙ כָּל מְלָאכָ֔ה בְּ/עֶ֖צֶם הַ/יּ֣וֹם הַ/זֶּ֑ה וְ/הַֽאֲבַדְתִּ֛י אֶת הַ/נֶּ֥פֶשׁ הַ/הִ֖וא מִ/קֶּ֥רֶב עַמָּֽ/הּ", "en": {"kjv": "And whatsoever soul it be that doeth any work in that same day, the same soul will I destroy from among his people.", "web": "Whoever it is who does any kind of work in that same day, that person I will destroy from among his people.", "bsb": "I will destroy from among his people anyone who does any work on this day.", "asv": "And whatsoever soul it be that doeth any manner of work in that same day, that soul will I destroy from among his people.", "ylt": "and any person who doth any work in this self-same day I have even destroyed that person from the midst of his people;", "tyndale": "And what soeuer soule do any maner worke that daye, the same I will destroye from amonge his people.", "dra": "And every soul that shall do any work, the same will I destroy from among his people.", "bbe": "And if any person, whoever he may be, on that day does any sort of work, I will send destruction on him from among his people.", "geneva": "And euery person that shall doe any work that same day, the same person also will I destroy from among his people.", "wycliffe": "and Y schal do a way fro his puple that man that doith eny thing of werk in that dai;", "rotherham": "And, whosoever be the person that shall do any work on this selfsame day, then will I destroy that person from the midst of his people.", "darby": "And every soul that doeth any manner of work on that same day, the same soul will I destroy from among his people.", "twenty": "", "jps": "And whatsoever soul it be that doeth any manner of work in that same day, that soul will I destroy from among his people.", "acv": "And whatever soul it be who does any manner of work in that same day, that soul I will destroy from among his people.", "anderson": "", "haweis": "", "noyes": "", "webster": "And whatever soul [it may be] that doeth any work in that same day, the same soul will I destroy from among his people.", "vulgate": "et quae operis quippiam fecerit delebo eam de populo suo;", "brenton": "And every soul which shall do work on that day, that soul shall be destroyed from among its people."}}, {"v": 31, "ref": "23:31", "o": "כָּל מְלָאכָ֖ה לֹ֣א תַעֲשׂ֑וּ חֻקַּ֤ת עוֹלָם֙ לְ/דֹרֹ֣תֵי/כֶ֔ם בְּ/כֹ֖ל מֹֽשְׁבֹֽתֵי/כֶֽם", "en": {"kjv": "Ye shall do no manner of work: it shall be a statute for ever throughout your generations in all your dwellings.", "web": "You shall do no kind of work: it is a statute forever throughout your generations in all your dwellings.", "bsb": "You are not to do any work at all. This is a permanent statute for the generations to come, wherever you live.", "asv": "Ye shall do no manner of work: it is a statute for ever throughout your generations in all your dwellings.", "ylt": "ye do no work--a statute age-during to your generations in all your dwellings.", "tyndale": "Se that ye do no maner worke therfore. And it shalbe a lawe for euer vnto youre generacions after you in all youre dwellynges.", "dra": "You shall do no work therefore on that day: it shall be an everlasting ordinance unto you in all your generations, and dwellings.", "bbe": "You may not do any sort of work: this is an order for ever through all your generations wherever you may be living.", "geneva": "Ye shall do no maner worke therefore: this shalbe a law for euer in your generations, throughout all your dwellings.", "wycliffe": "therfor ye schulen not do ony thing of werk in that dai; it schal be a lawful thing euerlastynge to you in alle youre generaciouns and abitaciouns;", "rotherham": "No work, shall ye do,—an age-abiding statute to your generations, in all your dwellings.", "darby": "No manner of work shall ye do: [it is] an everlasting statute throughout your generations in all your dwellings.", "twenty": "", "jps": "Ye shall do no manner of work; it is a statute for ever throughout your generations in all your dwellings.", "acv": "Ye shall do no manner of work. It is a statute forever throughout your generations in all your dwellings.", "anderson": "", "haweis": "", "noyes": "", "webster": "Ye shall do no manner of work. [It shall be] a statute for ever throughout your generations in all your dwellings.", "vulgate": "nihil ergo operis facietis in eo legitimum sempiternum erit vobis in cunctis generationibus et habitationibus vestris;", "brenton": "Ye shall do no manner of work: it is a perpetual statute throughout your generations in all your habitations."}}, {"v": 32, "ref": "23:32", "o": "שַׁבַּ֨ת שַׁבָּת֥וֹן הוּא֙ לָ/כֶ֔ם וְ/עִנִּיתֶ֖ם אֶת נַפְשֹׁתֵי/כֶ֑ם בְּ/תִשְׁעָ֤ה לַ/חֹ֨דֶשׁ֙ בָּ/עֶ֔רֶב מֵ/עֶ֣רֶב עַד עֶ֔רֶב תִּשְׁבְּת֖וּ שַׁבַּתְּ/כֶֽם", "en": {"kjv": "It shall be unto you a sabbath of rest, and ye shall afflict your souls: in the ninth day of the month at even, from even unto even, shall ye celebrate your sabbath.", "web": "It shall be a Sabbath of solemn rest for you, and you shall deny yourselves. In the ninth day of the month at evening, from evening to evening, you shall keep your Sabbath.”", "bsb": "It will be a Sabbath of complete rest for you, and you shall humble yourselves. From the evening of the ninth day of the month until the following evening you are to keep your Sabbath.”", "asv": "It shall be unto you a sabbath of solemn rest, and ye shall afflict your souls: in the ninth day of the month at even, from even unto even, shall ye keep your sabbath.", "ylt": "It is a sabbath of rest to you, and ye have humbled yourselves in the ninth of the month at even; from evening till evening ye do keep your sabbath.'", "tyndale": "A sabbath of reste it shalbe vnto you, and ye shall humble youre soules. The .ix. daye of the moneth at euen and so forth from eue to euen agayne, ye shall kepe your Sabbath.", "dra": "It is a sabbath of rest, and you shall afflict your souls beginning on the ninth day of the month. From evening until evening you shall celebrate your sabbaths.", "bbe": "Let this be a Sabbath of special rest to you, and keep yourselves from all pleasure; on the ninth day of the month at nightfall from evening to evening, let this Sabbath be kept.", "geneva": "This shalbe vnto you a Sabbath of rest, and ye shall humble your soules: in the ninth day of the moneth at euen, from euen to euen shall ye celebrate your Sabbath.", "wycliffe": "it is the sabat of restyng. Ye schulen turmente youre soulis fro the nynthe day of the monethe; fro euentid `til to euentid ye schulen halewe youre sabatis.", "rotherham": "A sabbath of sacred rest, shall it be unto you, so shall ye humble your souls,—on the ninth of the month in the evening, from evening to evening, shall ye keep your sabbath.", "darby": "A sabbath of rest shall it be unto you; and ye shall afflict your souls. On the ninth of the month at even, from even unto even, shall ye celebrate your sabbath.", "twenty": "", "jps": "It shall be unto you a sabbath of solemn rest, and ye shall afflict your souls; in the ninth day of the month at even, from even unto even, shall ye keep your sabbath.", "acv": "It shall be to you a sabbath of solemn rest, and ye shall afflict your souls. In the ninth day of the month at evening, from evening to evening, ye shall keep your sabbath.", "anderson": "", "haweis": "", "noyes": "", "webster": "It [shall be] to you a sabbath of rest, and ye shall afflict your souls in the ninth [day] of the month at evening: from evening to evening shall ye celebrate your sabbath.", "vulgate": "sabbatum requietionis est adfligetis animas vestras die nono mensis a vespero usque ad vesperum celebrabitis sabbata vestra;", "brenton": "It shall be a holy sabbath to you; and ye shall humble your souls, from the ninth day of the month: from evening to evening ye shall keep your sabbaths."}}, {"v": 33, "ref": "23:33", "o": "וַ/יְדַבֵּ֥ר יְהוָ֖ה אֶל מֹשֶׁ֥ה לֵּ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh spoke to Moses, saying,", "bsb": "And the LORD said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde spake vnto Moses sayenge:", "dra": "And the Lord spoke to Moses, saying:", "bbe": "And the Lord said to Moses,", "geneva": "And the Lord spake vnto Moses, saying,", "wycliffe": "And the Lord spak to Moises,", "rotherham": "And Yahweh spake unto Moses, saying:", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses, saying:", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "et locutus est Dominus ad Mosen dicens;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 34, "ref": "23:34", "o": "דַּבֵּ֛ר אֶל בְּנֵ֥י יִשְׂרָאֵ֖ל לֵ/אמֹ֑ר בַּ/חֲמִשָּׁ֨ה עָשָׂ֜ר י֗וֹם לַ/חֹ֤דֶשׁ הַ/שְּׁבִיעִי֙ הַ/זֶּ֔ה חַ֧ג הַ/סֻּכּ֛וֹת שִׁבְעַ֥ת יָמִ֖ים לַ/יהֹוָֽה", "en": {"kjv": "Speak unto the children of Israel, saying, The fifteenth day of this seventh month shall be the feast of tabernacles for seven days unto the Lord.", "web": "“Speak to the children of Israel, and say, ‘On the fifteenth day of this seventh month is the feast of tents for seven days to Yahweh.", "bsb": "“Speak to the Israelites and say, ‘On the fifteenth day of the seventh month the Feast of Tabernacles to the LORD begins, and it continues for seven days.", "asv": "Speak unto the children of Israel, saying, On the fifteenth day of this seventh month is the feast of tabernacles for seven days unto Jehovah.", "ylt": "`Speak unto the sons of Israel, saying, In the fifteenth day of this seventh month is a feast of booths seven days to Jehovah;", "tyndale": "speake vnto the childern of Israel ad saye: the xv. daye of the same seuenth moneth shalbe the feast of tabernacles .vij. dayes uto the Lorde.", "dra": "Say to the children of Israel: From the fifteenth day of this same seventh month, shall be kept the feast of tabernacles, seven days to the Lord.", "bbe": "Say to the children of Israel, On the fifteenth day of this seventh month let the feast of tents be kept to the Lord for seven days.", "geneva": "Speake vnto the children of Israel, and say, In the fifteenth day of this seueth moneth shalbe for seuen dayes the feast of Tabernacles vnto the Lord.", "wycliffe": "and seide, Speke thou to the sones of Israel, Fro the fiftenthe day of this seuenthe monethe schulen be the feries of tabernaclis, in seuene daies to the Lord;", "rotherham": "Speak unto the sons of Israel, saying:—On the fifteenth day of this seventh month, shall be the festival of booths, for seven days, unto Yahweh.", "darby": "Speak unto the children of Israel, saying, On the fifteenth day of this seventh month is the feast of booths seven days to Jehovah.", "twenty": "", "jps": "Speak unto the children of Israel, saying: On the fifteenth day of this seventh month is the feast of tabernacles for seven days unto HaShem.", "acv": "Speak to the sons of Israel, saying, On the fifteenth day of this seventh month is the feast of tabernacles for seven days to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "Speak to the children of Israel, saying, The fifteenth day of this seventh month [shall be] the feast of tabernacles [for] seven days to the LORD.", "vulgate": "loquere filiis Israhel a quintodecimo die mensis huius septimi erunt feriae tabernaculorum septem diebus Domino;", "brenton": "Speak to the children of Israel, saying, On the fifteenth day of this seventh month, there shall be a feast of tabernacles seven days to the Lord."}}, {"v": 35, "ref": "23:35", "o": "בַּ/יּ֥וֹם הָ/רִאשׁ֖וֹן מִקְרָא קֹ֑דֶשׁ כָּל מְלֶ֥אכֶת עֲבֹדָ֖ה לֹ֥א תַעֲשֽׂוּ", "en": {"kjv": "On the first day shall be an holy convocation: ye shall do no servile work therein.", "web": "On the first day shall be a holy convocation: you shall do no regular work.", "bsb": "On the first day there shall be a sacred assembly. You must not do any regular work.", "asv": "On the first day shall be a holy convocation: ye shall do no servile work.", "ylt": "on the first day is a holy convocation, ye do no servile work,", "tyndale": "The first daye shalbe an holy feast, so that ye shall do no laborious worke therein.", "dra": "The first day shall be called most solemn and most holy: you shall do no servile work therein. And seven days you shall offer holocausts to the Lord.", "bbe": "On the first day there will be a holy meeting: do no field-work.", "geneva": "In the first day shalbe an holie conuocation: ye shall do no seruile worke therein.", "wycliffe": "the firste dai schal be clepid moost solempne and moost hooli, ye schulen not do ony seruyle werk ther ynne;", "rotherham": "On the first day, [shall be] a holy convocation,—no laborious work, shall ye do.", "darby": "On the first day there shall be a holy convocation: no manner of servile work shall ye do.", "twenty": "", "jps": "On the first day shall be a holy convocation; ye shall do no manner of servile work.", "acv": "On the first day shall be a holy convocation. Ye shall do no job work.", "anderson": "", "haweis": "", "noyes": "", "webster": "On the first day [shall be] a holy convocation: ye shall do no servile work [in it].", "vulgate": "dies primus vocabitur celeberrimus atque sanctissimus omne opus servile non facietis;", "brenton": "And on the first day shall be a holy convocation; ye shall do no servile work."}}, {"v": 36, "ref": "23:36", "o": "שִׁבְעַ֣ת יָמִ֔ים תַּקְרִ֥יבוּ אִשֶּׁ֖ה לַ/יהוָ֑ה בַּ/יּ֣וֹם הַ/שְּׁמִינִ֡י מִקְרָא קֹדֶשׁ֩ יִהְיֶ֨ה לָ/כֶ֜ם וְ/הִקְרַבְתֶּ֨ם אִשֶּׁ֤ה לַֽ/יהוָה֙ עֲצֶ֣רֶת הִ֔וא כָּל מְלֶ֥אכֶת עֲבֹדָ֖ה לֹ֥א תַעֲשֽׂוּ", "en": {"kjv": "Seven days ye shall offer an offering made by fire unto the Lord: on the eighth day shall be an holy convocation unto you; and ye shall offer an offering made by fire unto the Lord: it is a solemn assembly; and ye shall do no servile work therein.", "web": "Seven days you shall offer an offering made by fire to Yahweh. On the eighth day shall be a holy convocation to you; and you shall offer an offering made by fire to Yahweh. It is a solemn assembly; you shall do no regular work.", "bsb": "For seven days you are to present an offering made by fire to the LORD. On the eighth day you are to hold a sacred assembly and present an offering made by fire to the LORD. It is a solemn assembly; you must not do any regular work.", "asv": "Seven days ye shall offer an offering made by fire unto Jehovah: on the eighth day shall be a holy convocation unto you; and ye shall offer an offering made by fire unto Jehovah: it is a solemn assembly; ye shall do no servile work.", "ylt": "seven days ye bring near a fire-offering to Jehovah, on the eighth day ye have a holy convocation, and ye have brought near a fire-offering to Jehovah; it is a restraint, ye do no servile work.", "tyndale": "Seuen dayes ye shall offer sacrifice vnto the Lorde, and the .viij daye shalbe an holy feast vnto you ad ye shall offer sacrifice vnto the Lorde. It is the ende of the feast, and ye shall do no laborious worke therein.", "dra": "The eighth day also shall be most solemn and most holy: and you shall offer holocausts to the Lord. For it is the day of assembly and congregation. You shall do no servile work therein.", "bbe": "Every day for seven days give an offering made by fire to the Lord; and on the eighth day there is to be a holy meeting, when you are to give an offering made by fire to the Lord; this is a special holy day: you may do no field-work on that day.", "geneva": "Seuen daies ye shall offer sacrifice made by fire vnto the Lord, and in the eight day shalbe an holy conuocation vnto you, and ye shall offer sacrifices made by fire vnto the Lord: it is the solemne assemblie, yee shall doe no seruile worke therein.", "wycliffe": "and in seuene daies ye schulen offre brent sacrifices to the Lord, and the eiythe dai schal be moost solempne and moost hooli; and ye schulen offre brent sacrifice to the Lord, for it is the day of cumpany, and of gaderyng; ye schulen not do ony seruyle werk ther ynne.", "rotherham": "Seven days, shall ye bring near an altar-flame unto Yahweh: on the eighth day—a holy convocation, shall there be unto you so shall ye bring near an altar-flame unto Yahweh—the closing of the feast, it is, no laborious work, shall ye do.", "darby": "Seven days ye shall present an offering by fire to Jehovah; on the eighth day shall be a holy convocation unto you; and ye shall present an offering by fire to Jehovah: it is a solemn assembly; no manner of servile work shall ye do.", "twenty": "", "jps": "Seven days ye shall bring an offering made by fire unto HaShem; on the eighth day shall be a holy convocation unto you; and ye shall bring an offering made by fire unto HaShem; it is a day of solemn assembly; ye shall do no manner of servile work.", "acv": "Seven days ye shall offer an offering made by fire to Jehovah. On the eighth day shall be a holy convocation to you, and ye shall offer an offering made by fire to Jehovah. It is a solemn assembly; ye shall do no job work.", "anderson": "", "haweis": "", "noyes": "", "webster": "Seven days ye shall offer an offering made by fire to the LORD: on the eighth day shall be a holy convocation to you, and ye shall offer an offering made by fire to the LORD: it [is] a solemn assembly; [and] ye shall do no servile work [in it].", "vulgate": "et septem diebus offeretis holocausta Domino dies quoque octavus erit celeberrimus atque sanctissimus et offeretis holocaustum Domino est enim coetus atque collectae omne opus servile non facietis in eo;", "brenton": "Seven days shall ye offer whole-burnt-offerings to the Lord, and the eighth-day shall be a holy convocation to you; and ye shall offer whole-burnt-offerings to the Lord: it is a time of release, ye shall do no servile work."}}, {"v": 37, "ref": "23:37", "o": "אֵ֚לֶּה מוֹעֲדֵ֣י יְהוָ֔ה אֲשֶׁר תִּקְרְא֥וּ אֹתָ֖/ם מִקְרָאֵ֣י קֹ֑דֶשׁ לְ/הַקְרִ֨יב אִשֶּׁ֜ה לַ/יהוָ֗ה עֹלָ֧ה וּ/מִנְחָ֛ה זֶ֥בַח וּ/נְסָכִ֖ים דְּבַר י֥וֹם בְּ/יוֹמֽ/וֹ", "en": {"kjv": "These are the feasts of the Lord, which ye shall proclaim to be holy convocations, to offer an offering made by fire unto the Lord, a burnt offering, and a meat offering, a sacrifice, and drink offerings, every thing upon his day:", "web": "“‘These are the appointed feasts of Yahweh, which you shall proclaim to be holy convocations, to offer an offering made by fire to Yahweh, a burnt offering, and a meal offering, a sacrifice, and drink offerings, each on its own day;", "bsb": "These are the LORD’s appointed feasts, which you are to proclaim as sacred assemblies for presenting offerings by fire to the LORD—burnt offerings and grain offerings, sacrifices and drink offerings, each on its designated day.", "asv": "These are the set feasts of Jehovah, which ye shall proclaim to be holy convocations, to offer an offering made by fire unto Jehovah, a burnt-offering, and a meal-offering, a sacrifice, and drink-offerings, each on its own day;", "ylt": "`These are appointed seasons of Jehovah, which ye proclaim holy convocations, to bring near a fire-offering to Jehovah, a burnt-offering, and a present, a sacrifice, and libations, a thing of a day in its day,", "tyndale": "These are the feastes of the Lorde whiche ye shall proclayme holy feastes, for to offer sacrifice vnto the Lorde, burntofferynges, meatofferynges, and drinkoffrynges euery daye:", "dra": "These are the feasts of the Lord which you shall call most solemn and most holy, and shall offer on them oblations to the Lord: holocausts and libations according to the rite of every day.", "bbe": "These are the fixed feasts of the Lord, to be kept by you as holy days of worship, for making an offering by fire to the Lord; a burned offering, a meal offering, an offering of beasts, and drink offerings; every one on its special day;", "geneva": "These are the feastes of the Lord (which ye shall call holie conuocations) to offer sacrifice made by fire vnto the Lord, as burnt offring, and meate offring, sacrifice, and drinke offrings, euery one vpon his day,", "wycliffe": "These ben the feries of the Lord, whiche ye schulen clepe moost solempne and moost hooli; and in tho ye schulen offre offryngis to the Lord, brent sacrifices, and fletynge offeryngis, bi the custom of ech day,", "rotherham": "These, are the appointed seasons of Yahweh, which ye shall proclaim, as holy convocations,—for bringing near as an altar-flame unto Yahweh, an ascending-sacrifice, and a meal-offering, a sacrifice and a drink-offering, each day’s appointment on its own day:—", "darby": "These are the set feasts of Jehovah, which ye shall proclaim as holy convocations, to present an offering by fire to Jehovah, a burnt-offering, and an oblation, a sacrifice, and drink-offerings, everything upon its day;", "twenty": "", "jps": "These are the appointed seasons of HaShem, which ye shall proclaim to be holy convocations, to bring an offering made by fire unto HaShem, a burnt-offering, and a meal-offering, a sacrifice, and drink-offerings, each on its own day;", "acv": "These are the set feasts of Jehovah, which ye shall proclaim to be holy convocations, to offer an offering made by fire to Jehovah, a burnt offering, and a meal offering, a sacrifice, and drink offerings, each on its own day.", "anderson": "", "haweis": "", "noyes": "", "webster": "These [are] the feasts of the LORD, which ye shall proclaim [to be] holy convocations, to offer an offering made by fire to the LORD, a burnt-offering, and a meat-offering, a sacrifice, and drink-offerings, every thing upon its day:", "vulgate": "hae sunt feriae Domini quas vocabitis celeberrimas et sanctissimas offeretisque in eis oblationes Domino holocausta et libamenta iuxta ritum uniuscuiusque diei;", "brenton": "These are the feasts to the Lord, which ye shall call holy convocations, to offer burnt-offerings to the Lord, whole-burnt-offerings and their meat-offerings, and their drink-offerings, that for each day on its day:"}}, {"v": 38, "ref": "23:38", "o": "מִ/לְּ/בַ֖ד שַׁבְּתֹ֣ת יְּהוָ֑ה וּ/מִ/לְּ/בַ֣ד מַתְּנֽוֹתֵי/כֶ֗ם וּ/מִ/לְּ/בַ֤ד כָּל נִדְרֵי/כֶם֙ וּ/מִ/לְּ/בַד֙ כָּל נִדְב֣וֹתֵי/כֶ֔ם אֲשֶׁ֥ר תִּתְּנ֖וּ לַ/יהוָֽה", "en": {"kjv": "Beside the sabbaths of the Lord, and beside your gifts, and beside all your vows, and beside all your freewill offerings, which ye give unto the Lord.", "web": "besides the Sabbaths of Yahweh, and besides your gifts, and besides all your vows, and besides all your freewill offerings, which you give to Yahweh.", "bsb": "These offerings are in addition to the offerings for the LORD’s Sabbaths, and in addition to your gifts, to all your vow offerings, and to all the freewill offerings you give to the LORD.", "asv": "besides the sabbaths of Jehovah, and besides your gifts, and besides all your vows, and besides all your freewill-offerings, which ye give unto Jehovah.", "ylt": "apart from the sabbaths of Jehovah, and apart from your gifts, and apart from all your vows, and apart from all your willing-offerings, which ye give to Jehovah.", "tyndale": "besyde the sabbathes of the Lorde, ad besyde youre giftes, and all youre vowes, and all your frewillofferynges whiche ye shall geue vnto the Lorde.", "dra": "Besides the sabbaths of the Lord, and your gifts, and those things that you offer by vow, or which you shall give to the Lord voluntarily.", "bbe": "In addition to the Sabbaths of the Lord, and in addition to the things you give and the oaths you make and the free offerings to the Lord.", "geneva": "Beside the Sabbaths of the Lord, and beside your giftes, and beside al your vowes, and beside all your free offrings, which ye shall giue vnto the Lord.", "wycliffe": "outakun the sabatis of the Lord, and youre yiftys, and whiche ye offren bi avow, ether whiche ye yyuen bi fre wille to the Lord.", "rotherham": "besides the sabbaths of Yahweh, and besides your presents, and besides all your vows, and besides all your freewill offerings which ye shall give unto Yahweh.", "darby": "besides the sabbaths of Jehovah, and besides your gifts, and besides all your vows, and besides all your voluntary offerings, which ye give to Jehovah.", "twenty": "", "jps": "beside the sabbaths of HaShem, and beside your gifts, and beside all your vows, and beside all your freewill-offerings, which ye give unto HaShem.", "acv": "Besides the sabbaths of Jehovah, and besides your gifts, and besides all your vows, and besides all your freewill offerings, which ye give to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "Beside the sabbaths of the LORD, and beside your gifts, and beside all your vows, and beside all your free-will-offerings, which ye give to the LORD.", "vulgate": "exceptis sabbatis Domini donisque vestris et quae offertis ex voto vel quae sponte tribuitis Domino;", "brenton": "besides the sabbaths of the Lord, and besides your gifts, and besides all your vows, and besides your free-will-offerings, which ye shall give to the Lord."}}, {"v": 39, "ref": "23:39", "o": "אַ֡ךְ בַּ/חֲמִשָּׁה֩ עָשָׂ֨ר י֜וֹם לַ/חֹ֣דֶשׁ הַ/שְּׁבִיעִ֗י בְּ/אָסְפְּ/כֶם֙ אֶת תְּבוּאַ֣ת הָ/אָ֔רֶץ תָּחֹ֥גּוּ אֶת חַג יְהוָ֖ה שִׁבְעַ֣ת יָמִ֑ים בַּ/יּ֤וֹם הָֽ/רִאשׁוֹן֙ שַׁבָּת֔וֹן וּ/בַ/יּ֥וֹם הַ/שְּׁמִינִ֖י שַׁבָּתֽוֹן", "en": {"kjv": "Also in the fifteenth day of the seventh month, when ye have gathered in the fruit of the land, ye shall keep a feast unto the Lord seven days: on the first day shall be a sabbath, and on the eighth day shall be a sabbath.", "web": "“‘So on the fifteenth day of the seventh month, when you have gathered in the fruits of the land, you shall keep the feast of Yahweh seven days: on the first day shall be a solemn rest, and on the eighth day shall be a solemn rest.", "bsb": "On the fifteenth day of the seventh month, after you have gathered the produce of the land, you are to celebrate a feast to the LORD for seven days. There shall be complete rest on the first day and also on the eighth day.", "asv": "Howbeit on the fifteenth day of the seventh month, when ye have gathered in the fruits of the land, ye shall keep the feast of Jehovah seven days: on the first day shall be a solemn rest, and on the eighth day shall be a solemn rest.", "ylt": "`Only--in the fifteenth day of the seventh month, in your gathering the increase of the land, ye do keep the feast of Jehovah seven days; on the first day is a sabbath, and on the eighth day a sabbath;", "tyndale": "Moreouer in the .xv. daye of the seuenth moneth after that ye haue gathered in the frutes of the lande, ye shall kepe holy daye vnto the Lorde .vij: dayes longe. The first daye shall be a daye of reste, and the .viij. daye shalbe a daye of rest.", "dra": "So from the fifteenth day of the seventh month, when you shall have gathered in all the fruits of your land, you shall celebrate the feast of the Lord seven days. On the first day and the eighth shall be a sabbath: that is a day of rest.", "bbe": "But on the fifteenth day of the seventh month, when you have got in all the fruits of the land, you will keep the feast of the Lord for seven days: the first day will be a Sabbath, and the eighth day the same.", "geneva": "But in the fifteenth day of the seueth moneth, when ye haue gathered in the fruite of the land, ye shall keepe an holie feast vnto the Lord seuen daies: in the first day shalbe a Sabbath: likewise in the eight day shalbe a Sabbath.", "wycliffe": "Therfor fro the fiftenthe day of the seuenthe monethe, whanne ye han gaderid alle the fruytis of youre lond, ye schulen halewe the feries of the Lord seuene daies; in the firste day and the eiyte schal be sabat, that is, reste.", "rotherham": "Surely, on the fifteenth day of the seventh month, when ye have gathered in the yield of the land, shall ye celebrate the festival of Yahweh seven days,—on the first day, a sacred rest, and, on the eighth day, a sacred rest.", "darby": "But on the fifteenth day of the seventh month, when ye have gathered in the produce of the land, ye shall celebrate the feast of Jehovah seven days: on the first day there shall be rest, and on the eighth day there shall be rest.", "twenty": "", "jps": "Howbeit on the fifteenth day of the seventh month, when ye have gathered in the fruits of the land, ye shall keep the feast of HaShem seven days; on the first day shall be a solemn rest, and on the eighth day shall be a solemn rest.", "acv": "However on the fifteenth day of the seventh month, when ye have gathered in the fruits of the land, ye shall keep the feast of Jehovah seven days. On the first day shall be a solemn rest, and on the eighth day shall be a solemn rest.", "anderson": "", "haweis": "", "noyes": "", "webster": "Also in the fifteenth day of the seventh month, when ye have gathered in the fruit of the land, ye shall keep a feast to the LORD seven days: on the first day [shall be] a sabbath, and on the eighth day [shall be] a sabbath.", "vulgate": "a quintodecimo ergo die mensis septimi quando congregaveritis omnes fructus terrae vestrae celebrabitis ferias Domini septem diebus die primo et die octavo erit sabbatum id est requies;", "brenton": "And on the fifteenth day of this seventh month, when ye shall have completely gathered in the fruits of the earth, ye shall keep a feast to the Lord seven days; on the first day there shall be a rest, and on the eighth day a rest."}}, {"v": 40, "ref": "23:40", "o": "וּ/לְקַחְתֶּ֨ם לָ/כֶ֜ם בַּ/יּ֣וֹם הָ/רִאשׁ֗וֹן פְּרִ֨י עֵ֤ץ הָדָר֙ כַּפֹּ֣ת תְּמָרִ֔ים וַ/עֲנַ֥ף עֵץ עָבֹ֖ת וְ/עַרְבֵי נָ֑חַל וּ/שְׂמַחְתֶּ֗ם לִ/פְנֵ֛י יְהוָ֥ה אֱלֹהֵי/כֶ֖ם שִׁבְעַ֥ת יָמִֽים", "en": {"kjv": "And ye shall take you on the first day the boughs of goodly trees, branches of palm trees, and the boughs of thick trees, and willows of the brook; and ye shall rejoice before the Lord your God seven days.", "web": "You shall take on the first day the fruit of goodly trees, branches of palm trees, and boughs of thick trees, and willows of the brook; and you shall rejoice before Yahweh your God seven days.", "bsb": "On the first day you are to gather the fruit of majestic trees, the branches of palm trees, and the boughs of leafy trees and of willows of the brook. And you are to rejoice before the LORD your God for seven days.", "asv": "And ye shall take you on the first day the fruit of goodly trees, branches of palm-trees, and boughs of thick trees, and willows of the brook; and ye shall rejoice before Jehovah your God seven days.", "ylt": "and ye have taken to yourselves on the first day the fruit of beautiful trees, branches of palms, and boughs of thick trees, and willows of a brook, and have rejoiced before Jehovah your God seven days.", "tyndale": "And ye shall take you the first daye, the frutes of goodly trees and the braunches off palme trees and the bowes of thicke trees, ad wylowes of the broke, and shall reioyse before the Lorde .vij. dayes.", "dra": "And you shall take to you on the first day the fruits of the fairest tree, and branches of palm trees, and boughs of thick trees, and willows of the brook: And you shall rejoice before the Lord your God.", "bbe": "On the first day, take the fruit of fair trees, branches of palm-trees, and branches of thick trees and trees from the riverside, and be glad before the Lord for seven days.", "geneva": "And yee shall take you in the first day the fruite of goodly trees, branches of palme trees, and the boughes of thicke trees, and willowes of the brooke, and shall reioyce before the Lord your God seuen daies.", "wycliffe": "And ye schulen take to you in the firste day fruytis of the faireste tree, and braunchis of palm trees, and braunchis of a `tree of thicke boowis, and salewis of the rennynge streem, and ye schulen be glad bifor youre Lord God;", "rotherham": "So then ye shall take you, on the first day, boughs of goodly trees, branches, of palm-trees, and boughs of thick trees, and poplars of the ravine,—and shall rejoice before Yahweh your God, seven days.", "darby": "And ye shall take on the first day the fruit of beautiful trees, palm branches and the boughs of leafy trees, and willows of the brook; and ye shall rejoice before Jehovah yourGod seven days.", "twenty": "", "jps": "And ye shall take you on the first day the fruit of goodly trees, branches of palm-trees, and boughs of thick trees, and willows of the brook, and ye shall rejoice before HaShem your G-d seven days.", "acv": "And ye shall take to you on the first day the fruit of goodly trees, branches of palm trees, and boughs of thick trees, and willows of the brook, and ye shall rejoice before Jehovah your God seven days.", "anderson": "", "haweis": "", "noyes": "", "webster": "And ye shall take you on the first day the boughs of goodly trees, branches of palm-trees, and the boughs of thick trees, and willows of the brook; and ye shall rejoice before the LORD your God seven days.", "vulgate": "sumetisque vobis die primo fructus arboris pulcherrimae spatulasque palmarum et ramos ligni densarum frondium et salices de torrente et laetabimini coram Domino Deo vestro;", "brenton": "And on the first day ye shall take goodly fruit of trees, and branches of palm trees, and thick boughs of trees, and willows, and branches of osiers from the brook, to rejoice before the Lord your God seven days in the year."}}, {"v": 41, "ref": "23:41", "o": "וְ/חַגֹּתֶ֤ם אֹת/וֹ֙ חַ֣ג לַֽ/יהוָ֔ה שִׁבְעַ֥ת יָמִ֖ים בַּ/שָּׁנָ֑ה חֻקַּ֤ת עוֹלָם֙ לְ/דֹרֹ֣תֵי/כֶ֔ם בַּ/חֹ֥דֶשׁ הַ/שְּׁבִיעִ֖י תָּחֹ֥גּוּ אֹתֽ/וֹ", "en": {"kjv": "And ye shall keep it a feast unto the Lord seven days in the year. It shall be a statute for ever in your generations: ye shall celebrate it in the seventh month.", "web": "You shall keep it a feast to Yahweh seven days in the year. It is a statute forever throughout your generations. You shall keep it in the seventh month.", "bsb": "You are to celebrate this as a feast to the LORD for seven days each year. This is a permanent statute for the generations to come; you are to celebrate it in the seventh month.", "asv": "And ye shall keep it a feast unto Jehovah seven days in the year: it is a statute for ever throughout your generations; ye shall keep it in the seventh month.", "ylt": "`And ye have kept it a feast to Jehovah, seven days in a year--a statute age-during to your generations; in the seventh month ye keep it a feast.", "tyndale": "And ye shall kepe it holy daye vnto the Lorde .vij. dayes in the yere. And it shalbe a lawe for euer vnto youre childern after you, that ye kepe that feast in the seuenth moneth.", "dra": "And you shall keep the solemnity thereof seven days in the year. It shall be an everlasting ordinance in your generations. In the seventh month shall you celebrate this feast.", "bbe": "And let this feast be kept before the Lord for seven days in the year: it is a rule for ever from generation to generation; in the seventh month let it be kept.", "geneva": "So ye shall keepe this feast vnto the Lord seuen daies in the yere, by a perpetuall ordinance through your generations: in the seuenth moneth shall you keepe it.", "wycliffe": "and ye schulen halewe his solempnyte seuene daies bi the yeer; it schal be a lawful thing euerlastynge in youre generaciouns. In the seuenthe monethe ye schulen halewe feestis,", "rotherham": "So shall ye celebrate it as a festival unto Yahweh, seven days in the year,—a statute age-abiding, to your generations. In the seventh month, shall ye celebrate it;", "darby": "And ye shall celebrate it as a feast to Jehovah seven days in the year: [it is] an everlasting statute throughout your generations; in the seventh month shall ye celebrate it.", "twenty": "", "jps": "And ye shall keep it a feast unto HaShem seven days in the year; it is a statute for ever in your generations; ye shall keep it in the seventh month.", "acv": "And ye shall keep it a feast to Jehovah seven days in the year. It is a statute forever throughout your generations. Ye shall keep it in the seventh month.", "anderson": "", "haweis": "", "noyes": "", "webster": "And ye shall keep it a feast to the LORD seven days in the year. [It shall be] a statute for ever in your generations; ye shall celebrate it in the seventh month.", "vulgate": "celebrabitisque sollemnitatem eius septem diebus per annum legitimum sempiternum erit in generationibus vestris mense septimo festa celebrabitis;", "brenton": "It is a perpetual statute for your generations: in the seventh month ye shall keep it."}}, {"v": 42, "ref": "23:42", "o": "בַּ/סֻּכֹּ֥ת תֵּשְׁב֖וּ שִׁבְעַ֣ת יָמִ֑ים כָּל הָֽ/אֶזְרָח֙ בְּ/יִשְׂרָאֵ֔ל יֵשְׁב֖וּ בַּ/סֻּכֹּֽת", "en": {"kjv": "Ye shall dwell in booths seven days; all that are Israelites born shall dwell in booths:", "web": "You shall dwell in booths seven days. All who are native-born in Israel shall dwell in booths,", "bsb": "You are to dwell in booths for seven days. All the native-born of Israel must dwell in booths,", "asv": "Ye shall dwell in booths seven days; all that are home-born in Israel shall dwell in booths;", "ylt": "`In booths ye dwell seven days; all who are natives in Israel dwell in booths,", "tyndale": "And ye shall dwell in bothes seuen dayes: euen all that are Israelites borne, shall dwell in bothes,", "dra": "And you shall dwell in bowers seven days. Every one that is of the race of Israel, shall dwell in tabernacles:", "bbe": "For seven days you will be living in tents; all those who are Israelites by birth are to make tents their living-places:", "geneva": "Ye shall dwell in boothes seuen daies: all that are Israelites borne, shall dwel in boothes,", "wycliffe": "and ye schulen dwelle in schadewynge placis seuene daies; ech man that is of the kyn of Israel, schal dwelle in tabernaclis, that youre aftercomers lerne,", "rotherham": "In booths, shall ye dwell seven days;—All the home-born in Israel, shall dwell in booths:", "darby": "In booths shall ye dwell seven days; all born in Israel shall dwell in booths;", "twenty": "", "jps": "Ye shall dwell in booths seven days; all that are home-born in Israel shall dwell in booths;", "acv": "Ye shall dwell in booths seven days. All who are home-born in Israel shall dwell in booths,", "anderson": "", "haweis": "", "noyes": "", "webster": "Ye shall dwell in booths seven days: all that are Israelites born shall dwell in booths:", "vulgate": "et habitabitis in umbraculis septem diebus omnis qui de genere est Israhel manebit in tabernaculis;", "brenton": "Seven days ye shall dwell in tabernacles: every native in Israel shall dwell in tents,"}}, {"v": 43, "ref": "23:43", "o": "לְמַעַן֮ יֵדְע֣וּ דֹרֹֽתֵי/כֶם֒ כִּ֣י בַ/סֻּכּ֗וֹת הוֹשַׁ֨בְתִּי֙ אֶת בְּנֵ֣י יִשְׂרָאֵ֔ל בְּ/הוֹצִיאִ֥/י אוֹתָ֖/ם מֵ/אֶ֣רֶץ מִצְרָ֑יִם אֲנִ֖י יְהוָ֥ה אֱלֹהֵי/כֶֽם", "en": {"kjv": "That your generations may know that I made the children of Israel to dwell in booths, when I brought them out of the land of Egypt: I am the Lord your God.", "web": "that your generations may know that I made the children of Israel to dwell in booths, when I brought them out of the land of Egypt. I am Yahweh your God.’”", "bsb": "so that your descendants may know that I made the Israelites dwell in booths when I brought them out of the land of Egypt. I am the LORD your God.’”", "asv": "that your generations may know that I made the children of Israel to dwell in booths, when I brought them out of the land of Egypt: I am Jehovah your God.", "ylt": "so that your generations do know that in booths I caused the sons of Israel to dwell; in my bringing them out of the land of Egypt; I, Jehovah, am your God.'", "tyndale": "that youre children after you maye knowe howe that I made the childern of Israel dwell in bothes, when I broughte them out of the lande of Egipte: for I am the Lorde youre God.", "dra": "That your posterity may know, that I made the children of Israel to dwell in tabernacles, when I brought them out of the land of Egypt. I am the Lord your God.", "bbe": "So that future generations may keep in mind how I gave the children of Israel tents as their living-places when I took them out of the land of Egypt: I am the Lord your God.", "geneva": "That your posterity may know that I haue made the children of Israel to dwell in boothes, when I brought them out of the lande of Egypt: I am the Lord your God.", "wycliffe": "that Y made the sones of Israel to dwelle in tabernaculis, whanne Y ledde hem out of the lond of Egipt; Y am youre Lord God.", "rotherham": "To the end that your generations may know, that, in booths, made I the sons of Israel to dwell, when I brought them forth out of the land of Egypt,—I—Yahweh, am your God.", "darby": "that your generations may know that I caused the children of Israel to dwell in booths, when I brought them out of the land of Egypt: I am Jehovah yourGod.", "twenty": "", "jps": "that your generations may know that I made the children of Israel to dwell in booths, when I brought them out of the land of Egypt: I am HaShem your G-d.", "acv": "that your generations may know that I made the sons of Israel to dwell in booths, when I brought them out of the land of Egypt. I am Jehovah your God.", "anderson": "", "haweis": "", "noyes": "", "webster": "That your generations may know that I made the children of Israel to dwell in booths, when I brought them out of the land of Egypt: I [am] the LORD your God.", "vulgate": "ut discant posteri vestri quod in tabernaculis habitare fecerim filios Israhel cum educerem eos de terra Aegypti ego Dominus Deus vester;", "brenton": "that your posterity may see, that I made the children of Israel to dwell in tents, when I brought them out of the land of Egypt: I am the Lord your God."}}, {"v": 44, "ref": "23:44", "o": "וַ/יְדַבֵּ֣ר מֹשֶׁ֔ה אֶת מֹעֲדֵ֖י יְהוָ֑ה אֶל בְּנֵ֖י יִשְׂרָאֵֽל", "en": {"kjv": "And Moses declared unto the children of Israel the feasts of the Lord.", "web": "Moses declared to the children of Israel the appointed feasts of Yahweh.", "bsb": "So Moses announced to the Israelites the appointed feasts of the LORD.", "asv": "And Moses declared unto the children of Israel the set feasts of Jehovah.", "ylt": "And Moses speaketh concerning the appointed seasons of Jehovah unto the sons of Israel.", "tyndale": "And Moses told all the feastes of the Lorde vnto the childern of Israel.", "dra": "And Moses spoke concerning the feasts of the Lord to the children of Israel.", "bbe": "And Moses made clear to the children of Israel the orders about the fixed feasts of the Lord.", "geneva": "So Moses declared vnto the children of Israel the feastes of the Lord.", "wycliffe": "And Moises spak of the solempnytees of the Lord to the sones of Israel.", "rotherham": "So then Moses declared, the appointed seasons of Yahweh, unto the sons of Israel.", "darby": "And Moses declared the set feasts of Jehovah to the children of Israel.", "twenty": "", "jps": "And Moses declared unto the children of Israel the appointed seasons of HaShem.", "acv": "And Moses declared to the sons of Israel the set feasts of Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Moses declared to the children of Israel the feasts of the LORD.", "vulgate": "locutusque est Moses super sollemnitatibus Domini ad filios Israhel;", "brenton": "And Moses recounted the feasts of the Lord to the children of Israel."}}]}, {"c": 24, "verses": [{"v": 1, "ref": "24:1", "o": "וַ/יְדַבֵּ֥ר יְהוָ֖ה אֶל מֹשֶׁ֥ה לֵּ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh spoke to Moses, saying,", "bsb": "Then the LORD said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde spake vnto Moses saynge:", "dra": "And the Lord spoke to Moses, saying:", "bbe": "And the Lord said to Moses,", "geneva": "And the Lord spake vnto Moses, saying,", "wycliffe": "And the Lord spak to Moises, and seide, Comaunde thou to the sones of Israel,", "rotherham": "And Yahweh spake unto Moses, saying:", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses, saying:", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "et locutus est Dominus ad Mosen dicens;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 2, "ref": "24:2", "o": "צַ֞ו אֶת בְּנֵ֣י יִשְׂרָאֵ֗ל וְ/יִקְח֨וּ אֵלֶ֜י/ךָ שֶׁ֣מֶן זַ֥יִת זָ֛ךְ כָּתִ֖ית לַ/מָּא֑וֹר לְ/הַעֲלֹ֥ת נֵ֖ר תָּמִֽיד", "en": {"kjv": "Command the children of Israel, that they bring unto thee pure oil olive beaten for the light, to cause the lamps to burn continually.", "web": "“Command the children of Israel, that they bring to you pure olive oil beaten for the light, to cause a lamp to burn continually.", "bsb": "“Command the Israelites to bring you pure oil of pressed olives for the light, to keep the lamps burning continually.", "asv": "Command the children of Israel, that they bring unto thee pure olive oil beaten for the light, to cause a lamp to burn continually.", "ylt": "`Command the sons of Israel, and they bring unto thee pure olive oil, beaten, for the lamp, to cause a light to go up continually;", "tyndale": "commaunde the childern of Israel that they bringe vnto the, pure oyle olyue bete for lightes to poure in to the lampes allwaye,", "dra": "Command the children of Israel, that they bring unto thee the finest and clearest oil of olives, to furnish the lamps continually,", "bbe": "Give orders to the children of Israel to give you clean olive oil for the light, so that a light may be burning at all times,", "geneva": "Commande the children of Israel that they bring vnto thee pure oyle oliue beaten, for the light, to cause ye lampes to burne continually.", "wycliffe": "that thei brynge to thee oile of olyues, pureste oile, and briyt, to the lanternes to be ordeyned contynueli with out the veil of witnessyng,", "rotherham": "Command the sons of Israel, That they bring unto thee—pure oil olive, beaten, for giving light,—to cause the lamp to burn up continually.", "darby": "Command the children of Israel that they bring unto thee pure beaten olive oil for the light, to light the lamp continually.", "twenty": "", "jps": "'Command the children of Israel, that they bring unto thee pure olive oil beaten for the light, to cause a lamp to burn continually.", "acv": "Command the sons of Israel, that they bring to thee pure beaten olive oil for the light, to cause a lamp to burn continually.", "anderson": "", "haweis": "", "noyes": "", "webster": "Command the children of Israel, that they bring to thee pure olive oil beaten for the light, to cause the lamps to burn continually.", "vulgate": "praecipe filiis Israhel ut adferant tibi oleum de olivis purissimum ac lucidum ad concinnandas lucernas iugiter;", "brenton": "Charge the children of Israel, and let them take for thee pure olive oil beaten for the light, to burn a lamp continually,"}}, {"v": 3, "ref": "24:3", "o": "מִ/חוּץ֩ לְ/פָרֹ֨כֶת הָ/עֵדֻ֜ת בְּ/אֹ֣הֶל מוֹעֵ֗ד יַעֲרֹךְ֩ אֹת֨/וֹ אַהֲרֹ֜ן מֵ/עֶ֧רֶב עַד בֹּ֛קֶר לִ/פְנֵ֥י יְהוָ֖ה תָּמִ֑יד חֻקַּ֥ת עוֹלָ֖ם לְ/דֹרֹֽתֵי/כֶֽם", "en": {"kjv": "Without the vail of the testimony, in the tabernacle of the congregation, shall Aaron order it from the evening unto the morning before the Lord continually: it shall be a statute for ever in your generations.", "web": "Outside of the veil of the Testimony, in the Tent of Meeting, shall Aaron keep it in order from evening to morning before Yahweh continually: it shall be a statute forever throughout your generations.", "bsb": "Outside the veil of the Testimony in the Tent of Meeting, Aaron is to tend the lamps continually before the LORD from evening until morning. This is to be a permanent statute for the generations to come.", "asv": "Without the veil of the testimony, in the tent of meeting, shall Aaron keep it in order from evening to morning before Jehovah continually: it shall be a statute for ever throughout your generations.", "ylt": "at the outside of the vail of the testimony in the tent of meeting doth Aaron arrange it from evening till morning before Jehovah continually--a statute age-during to your generations;", "tyndale": "without the vayle of testimonye within the tabernacle of witnesse. And Aaron shall dresse them both euen and morninge before the Lorde alwayes. And it shalbe a lawe for euer amoge youre childern after you.", "dra": "Without the veil of the testimony in the tabernacle of the covenant. And Aaron shall set them from evening until morning before the Lord, by a perpetual service and rite in your generations.", "bbe": "Outside the veil of the ark in the Tent of meeting; let Aaron see that it is burning from evening till morning at all times before the Lord: it is a rule for ever through all your generations.", "geneva": "Without the vaile of the Testimonie, in the Tabernacle of the Congregation, shall Aaron dresse them, both euen and morning before the Lord alwayes: this shalbe a lawe for euer through your generations.", "wycliffe": "in the tabernacle of boond of pees; and Aaron schal araye tho lanternes fro euentid `til to euentid bifor the Lord, bi religioun and custom euerlastynge in youre generaciouns;", "rotherham": "Outside the veil of the testimony, in the tent of meeting, shall Aaron order it, from evening until morning, before Yahweh continually,—a statute age-abiding, to your generations.", "darby": "Outside the veil of the testimony, in the tent of meeting, shall Aaron dress it from evening to morning before Jehovah continually: [it is] an everlasting statute throughout your generations.", "twenty": "", "jps": "Without the veil of the testimony, in the tent of meeting, shall Aaron order it from evening to morning before HaShem continually; it shall be a statute for ever throughout your generations.", "acv": "Aaron shall keep it outside the veil of the testimony, in the tent of meeting, in order from evening to morning before Jehovah continually. It shall be a statute forever throughout your generations.", "anderson": "", "haweis": "", "noyes": "", "webster": "Without the vail of the testimony, in the tabernacle of the congregation, shall Aaron order it from the evening to the morning before the LORD continually: [It shall be] a statute for ever in your generations.", "vulgate": "extra velum testimonii in tabernaculo foederis ponetque eas Aaron a vespere usque in mane coram Domino cultu rituque perpetuo in generationibus vestris;", "brenton": "outside the veil in the tabernacle of witness; and Aaron and his sons shall burn it from evening until morning before the Lord continually, a perpetual statute throughout your generations."}}, {"v": 4, "ref": "24:4", "o": "עַ֚ל הַ/מְּנֹרָ֣ה הַ/טְּהֹרָ֔ה יַעֲרֹ֖ךְ אֶת הַ/נֵּר֑וֹת לִ/פְנֵ֥י יְהוָ֖ה תָּמִֽיד", "en": {"kjv": "He shall order the lamps upon the pure candlestick before the Lord continually.", "web": "He shall keep in order the lamps on the pure gold lamp stand before Yahweh continually.", "bsb": "He shall tend the lamps on the pure gold lampstand before the LORD continually.", "asv": "He shall keep in order the lamps upon the pure candlestick before Jehovah continually.", "ylt": "by the pure candlestick he doth arrange the lights before Jehovah continually.", "tyndale": "And he shal dresse the lampes apon the pure candelsticke before the Lorde perpetually.", "dra": "They shall be set upon the most pure candlestick before the Lord continually.", "bbe": "Let Aaron put the lights in order on the support before the Lord at all times.", "geneva": "He shall dresse the lampes vpon the pure Candlesticke before the Lord perpetually.", "wycliffe": "tho schulen be set euere on a clenneste candilstike in the siyt of the Lord.", "rotherham": "Upon the pure lampstand, shall he order the lamps,—before Yahweh, continually.", "darby": "Upon the pure candlestick shall he arrange the lamps before Jehovah continually.", "twenty": "", "jps": "He shall order the lamps upon the pure candlestick before HaShem continually.", "acv": "He shall keep the lamps upon the pure lampstand in order before Jehovah continually.", "anderson": "", "haweis": "", "noyes": "", "webster": "Ye shall order the lamps upon the pure candlestick before the LORD continually.", "vulgate": "super candelabro mundissimo ponentur semper in conspectu Domini;", "brenton": "Ye shall burn the lamps on the pure lamp-stand before the Lord till the morrow."}}, {"v": 5, "ref": "24:5", "o": "וְ/לָקַחְתָּ֣ סֹ֔לֶת וְ/אָפִיתָ֣ אֹתָ֔/הּ שְׁתֵּ֥ים עֶשְׂרֵ֖ה חַלּ֑וֹת שְׁנֵי֙ עֶשְׂרֹנִ֔ים יִהְיֶ֖ה הַֽ/חַלָּ֥ה הָ/אֶחָֽת", "en": {"kjv": "And thou shalt take fine flour, and bake twelve cakes thereof: two tenth deals shall be in one cake.", "web": "“You shall take fine flour, and bake twelve cakes of it: two tenth parts of an ephah shall be in one cake.", "bsb": "You are also to take fine flour and bake twelve loaves, using two-tenths of an ephah for each loaf,", "asv": "And thou shalt take fine flour, and bake twelve cakes thereof: two tenth parts of an ephah shall be in one cake.", "ylt": "`And thou hast taken flour, and hast baked twelve cakes with it, two tenth deals are in the one cake,", "tyndale": "And thou shalt take fine floure ad bake .xij wastels thereof, two tenthdeales shall euery wastell be.", "dra": "Thou shalt take also fine flour, and shalt bake twelve loaves thereof, two tenths shall be in every loaf.", "bbe": "And take the best meal and make twelve cakes of it, a fifth part of an ephah in every cake.", "geneva": "Also thou shalt take fine floure, and bake twelue cakes thereof: two tenth deales shalbe in one cake.", "wycliffe": "Also thou schalt take wheete flour, and thou schalt bake therof twelue looues, which schulen haue ech bi hem silf twei tenthe partis,", "rotherham": "And thou shalt take fine meal, and bake it, in twelve cakes,—of two-tenths, shall each cake be.", "darby": "And thou shalt take fine wheaten flour, and bake twelve cakes thereof; each cake shall be of two tenths.", "twenty": "", "jps": "And thou shalt take fine flour, and bake twelve cakes thereof: two tenth parts of an ephah shall be in one cake.", "acv": "And thou shall take fine flour, and bake twelve cakes of it. Two tenth parts of an ephah shall be in one cake.", "anderson": "", "haweis": "", "noyes": "", "webster": "And thou shalt take fine flour, and bake twelve cakes of it: two tenth-parts shall be in one cake.", "vulgate": "accipies quoque similam et coques ex ea duodecim panes qui singuli habebunt duas decimas;", "brenton": "And ye shall take fine flour, and make of it twelve loaves; each loaf shall be of two tenth parts."}}, {"v": 6, "ref": "24:6", "o": "וְ/שַׂמְתָּ֥ אוֹתָ֛/ם שְׁתַּ֥יִם מַֽעֲרָכ֖וֹת שֵׁ֣שׁ הַֽ/מַּעֲרָ֑כֶת עַ֛ל הַ/שֻּׁלְחָ֥ן הַ/טָּהֹ֖ר לִ/פְנֵ֥י יְהוָֽה", "en": {"kjv": "And thou shalt set them in two rows, six on a row, upon the pure table before the Lord.", "web": "You shall set them in two rows, six on a row, on the pure gold table before Yahweh.", "bsb": "and set them in two rows—six per row—on the table of pure gold before the LORD.", "asv": "And thou shalt set them in two rows, six on a row, upon the pure table before Jehovah.", "ylt": "and thou hast set them two ranks (six in the rank) on the pure table before Jehovah,", "tyndale": "And make two rowes of them, sixe on a rowe apon the pure table before the Lorde,", "dra": "And thou shalt set them six and six, one against another, upon the most clean table before the Lord.", "bbe": "And put them in two lines, six in a line, on the holy table before the Lord.", "geneva": "And thou shalt set them in two rowes, six in a rowe vpon the pure table before the Lord.", "wycliffe": "of whiche thou schalt sette sexe on euer eithir side, on a clenneste boord bifor the Lord;", "rotherham": "And thou shalt set them in two rows, six in a row,—upon the pure table, before Yahweh.", "darby": "And thou shalt set them in two rows, six in a row, upon the pure table before Jehovah.", "twenty": "", "jps": "And thou shalt set them in two rows, six in a row, upon the pure table before HaShem.", "acv": "And thou shall set them in two rows, six on a row, upon the pure table before Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And thou shalt set them in two rows, six in a row, upon the pure table before the LORD.", "vulgate": "quorum senos altrinsecus super mensam purissimam coram Domino statues;", "brenton": "And ye shall put them in two rows, each row containing six loaves, on the pure table before the Lord."}}, {"v": 7, "ref": "24:7", "o": "וְ/נָתַתָּ֥ עַל הַֽ/מַּעֲרֶ֖כֶת לְבֹנָ֣ה זַכָּ֑ה וְ/הָיְתָ֤ה לַ/לֶּ֨חֶם֙ לְ/אַזְכָּרָ֔ה אִשֶּׁ֖ה לַֽ/יהוָֽה", "en": {"kjv": "And thou shalt put pure frankincense upon each row, that it may be on the bread for a memorial, even an offering made by fire unto the Lord.", "web": "You shall put pure frankincense on each row, that it may be to the bread for a memorial, even an offering made by fire to Yahweh.", "bsb": "And you are to place pure frankincense near each row, so that it may serve as a memorial portion for the bread, an offering made by fire to the LORD.", "asv": "And thou shalt put pure frankincense upon each row, that it may be to the bread for a memorial, even an offering made by fire unto Jehovah.", "ylt": "and thou hast put on the rank pure frankincense, and it hath been to the bread for a memorial, a fire-offering to Jehovah.", "tyndale": "and put pure frankencens vppon the rowes. And it shalbe bred of remembraunce, ad an offerynge to the Lorde.", "dra": "And thou shalt put upon them the clearest frankincense, that the bread may be for a memorial of the oblation of the Lord.", "bbe": "And on the lines of cakes put clean sweet-smelling spices, for a sign on the bread, an offering made by fire to the Lord.", "geneva": "Thou shalt also put pure incense vpon the rowes, that in steade of the bread it may bee for a remembrance, and an offering made by fire to the Lord.", "wycliffe": "and thou schalt sette clereste encense on tho looues, that the looues be in to mynde of offryng of the Lord;", "rotherham": "And thou shalt put upon each row pure frankincense,—so shall it belong unto the bread as a memorial, an altar-flame unto Yahweh.", "darby": "And thou shalt put pure frankincense upon each row; and it shall be a bread of remembrance, an offering by fire to Jehovah.", "twenty": "", "jps": "And thou shalt put pure frankincense with each row, that it may be to the bread for a memorial-part, even an offering made by fire unto HaShem.", "acv": "And thou shall put pure frankincense upon each row, that it may be on the bread for a memorial, even an offering made by fire to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And thou shalt put pure frankincense upon [each] row, that it may be on the bread for a memorial, [even] an offering made by fire to the LORD.", "vulgate": "et pones super eos tus lucidissimum ut sit panis in monumentum oblationis Domini;", "brenton": "And ye shall put on each row pure frankincense and salt; and these things shall be for loaves for a memorial, set forth before the Lord."}}, {"v": 8, "ref": "24:8", "o": "בְּ/י֨וֹם הַ/שַּׁבָּ֜ת בְּ/י֣וֹם הַ/שַּׁבָּ֗ת יַֽעַרְכֶ֛/נּוּ לִ/פְנֵ֥י יְהוָ֖ה תָּמִ֑יד מֵ/אֵ֥ת בְּנֵֽי יִשְׂרָאֵ֖ל בְּרִ֥ית עוֹלָֽם", "en": {"kjv": "Every sabbath he shall set it in order before the Lord continually, being taken from the children of Israel by an everlasting covenant.", "web": "Every Sabbath day he shall set it in order before Yahweh continually. It is on the behalf of the children of Israel an everlasting covenant.", "bsb": "Every Sabbath day the bread is to be set out before the LORD on behalf of the Israelites as a permanent covenant.", "asv": "Every sabbath day he shall set it in order before Jehovah continually; it is on the behalf of the children of Israel, an everlasting covenant.", "ylt": "`On each sabbath-day he arrangeth it before Jehovah continually, from the sons of Israel--a covenant age-during;", "tyndale": "Euery Sabbath he shall put them in rowes before the Lorde euer more, geuen off the childern of Israel, that it be an euerlastynge couenaunte.", "dra": "Every sabbath they shall be changed before the Lord: being received of the children of Israel by an everlasting covenant.", "bbe": "Every Sabbath day regularly, the priest is to put it in order before the Lord: it is offered for the children of Israel, an agreement made for ever.", "geneva": "Euery Sabbath hee shall put them in rowes before the Lord euermore, receiuing them of the children of Israel for an euerlasting couenant.", "wycliffe": "bi ech sabat tho schulen be chaungid bifor the Lord, and schulen be takun of the sones of Israel bi euerlastynge boond of pees;", "rotherham": "Sabbath day by sabbath day, shall he order it before Yahweh continually,—from the sons of Israel as an age-abiding covenant:", "darby": "Every sabbath day he shall arrange it before Jehovah continually, on the part of the children of Israel: [it is] an everlasting covenant.", "twenty": "", "jps": "Every sabbath day he shall set it in order before HaShem continually; it is from the children of Israel, an everlasting covenant.", "acv": "Every sabbath day he shall set it in order before Jehovah continually. It is on the behalf of the sons of Israel, an everlasting covenant.", "anderson": "", "haweis": "", "noyes": "", "webster": "Every sabbath he shall set it in order before the LORD continually, [being taken] from the children of Israel by an everlasting covenant.", "vulgate": "per singula sabbata mutabuntur coram Domino suscepti a filiis Israhel foedere sempiterno;", "brenton": "On the sabbath-day they shall be set forth before the Lord continually before the children of Israel, for an everlasting covenant."}}, {"v": 9, "ref": "24:9", "o": "וְ/הָֽיְתָה֙ לְ/אַהֲרֹ֣ן וּ/לְ/בָנָ֔י/ו וַ/אֲכָלֻ֖/הוּ בְּ/מָק֣וֹם קָדֹ֑שׁ כִּ֡י קֹדֶשׁ֩ קָֽדָשִׁ֨ים ה֥וּא ל֛/וֹ מֵ/אִשֵּׁ֥י יְהוָ֖ה חָק עוֹלָֽם", "en": {"kjv": "And it shall be Aaron’s and his sons’; and they shall eat it in the holy place: for it is most holy unto him of the offerings of the Lord made by fire by a perpetual statute.", "web": "It shall be for Aaron and his sons; and they shall eat it in a holy place: for it is most holy to him of the offerings of Yahweh made by fire by a perpetual statute.”", "bsb": "It belongs to Aaron and his sons, who are to eat it in a holy place; for it is to him a most holy part of the offerings made by fire to the LORD—his portion forever.”", "asv": "And it shall be for Aaron and his sons; and they shall eat it in a holy place: for it is most holy unto him of the offerings of Jehovah made by fire by a perpetual statute.", "ylt": "and it hath been to Aaron, and to his sons, and they have eaten it in the holy place, for it is most holy to him, from the fire-offerings of Jehovah--a statute age-during.'", "tyndale": "And they shalbe Aarons and his sonnes, and they shall eate them in the holy place. For they are most holy vnto him of the offerynges of the Lorde, and shalbe a dutye for euer.", "dra": "And they shall be Aaron's and his sons', that they may eat them in the holy place: because it is most holy of the sacrifices of the Lord by a perpetual right.", "bbe": "And it will be for Aaron and his sons; they are to take it for food in a holy place: it is the most holy of all the offerings made by fire to the Lord, a rule for ever.", "geneva": "And the bread shalbe Aarons and his sonnes, and they shall eate it in the holie place: for it is most holie vnto him of the offrings of the Lord made by fire by a perpetuall ordinance.", "wycliffe": "and tho schulen be Aarons and hise sones, that thei ete tho in the hooli place, for it is hooli of the noumbre of hooli thingis, of the sacrifices of the Lord, bi euerlastynge lawe.", "rotherham": "so shall it be for Aaron and for his sons, and they shall eat it in a holy place,—for most holy, shall it be unto him from among the altar-flames of Yahweh, a statute age-abiding.", "darby": "And it shall be Aaron's and his sons'; and they shall eat it in a holy place; for it is most holy unto him of Jehovah's offerings by fire: [it is] an everlasting statute.", "twenty": "", "jps": "And it shall be for Aaron and his sons; and they shall eat it in a holy place; for it is most holy unto him of the offerings of HaShem made by fire, a perpetual due.'", "acv": "And it shall be for Aaron and his sons. And they shall eat it in a holy place, for it is most holy to him of the offerings of Jehovah made by fire by a perpetual statute.", "anderson": "", "haweis": "", "noyes": "", "webster": "And it shall be Aaron's and his sons'; and they shall eat it in the holy place: for it [is] most holy to him of the offerings of the LORD made by fire by a perpetual statute.", "vulgate": "eruntque Aaron et filiorum eius ut comedant eos in loco sancto quia sanctum sanctorum est de sacrificiis Domini iure perpetuo;", "brenton": "And they shall be for Aaron and his sons, and they shall eat them in the holy place: for this is their most holy portion of the offerings made to the Lord, a perpetual statute."}}, {"v": 10, "ref": "24:10", "o": "וַ/יֵּצֵא֙ בֶּן אִשָּׁ֣ה יִשְׂרְאֵלִ֔ית וְ/הוּא֙ בֶּן אִ֣ישׁ מִצְרִ֔י בְּ/ת֖וֹךְ בְּנֵ֣י יִשְׂרָאֵ֑ל וַ/יִּנָּצוּ֙ בַּֽ/מַּחֲנֶ֔ה בֶּ֚ן הַ/יִּשְׂרְאֵלִ֔ית וְ/אִ֖ישׁ הַ/יִּשְׂרְאֵלִֽי", "en": {"kjv": "And the son of an Israelitish woman, whose father was an Egyptian, went out among the children of Israel: and this son of the Israelitish woman and a man of Israel strove together in the camp;", "web": "The son of an Israelite woman, whose father was an Egyptian, went out among the children of Israel; and the son of the Israelite woman and a man of Israel strove together in the camp.", "bsb": "Now the son of an Israelite mother and an Egyptian father went out among the Israelites, and a fight broke out in the camp between him and an Israelite.", "asv": "And the son of an Israelitish woman, whose father was an Egyptian, went out among the children of Israel; and the son of the Israelitish woman and a man of Israel strove together in the camp:", "ylt": "And a son of an Israelitish woman goeth out (and he is son of an Egyptian man), in the midst of the sons of Israel, and strive in the camp do the son of the Israelitish woman and a man of Israel,", "tyndale": "And the sonne of an Israelitish wife whose father was an Egiptian, went oute amonge the childern of Israel. And this sonne off the Israelitish wife and a man of Israel, strooue togither in the hoste.", "dra": "And behold there went out the son of a woman of Israel, whom she had of an Egyptian, among the children of Israel: and fell at words in the camp with a man of Israel.", "bbe": "And a son of an Israelite woman, whose father was an Egyptian, went out among the children of Israel and had a fight with a man of Israel by the tents;", "geneva": "And there went out among the children of Israel the sonne of an Israelitish woman, whose father was an Egyptian: and this sonne of the Israelitish woman, and a man of Israel stroue together in the hoste.", "wycliffe": "Lo! forsothe the sone of a womman of Israel, whom sche childide of a man Egipcian, yede out among the sones of Israel, and chidde in the castels with a man of Israel,", "rotherham": "And forth went the son of a woman of Israel—he being the son of a man of Egypt—in the midst of the sons of Israel;", "darby": "And the son of an Israelitish woman — but withal the son of an Egyptian, — went out among the children of Israel; and this son of the Israelitess and a man of Israel strove together in the camp;", "twenty": "", "jps": "And the son of an Israelitish woman, whose father was an Egyptian, went out among the children of Israel; and the son of the Israelitish woman and a man of Israel strove together in the camp.", "acv": "And the son of an Israelite woman, whose father was an Egyptian, went out among the sons of Israel. And the son of the Israelite woman and a man of Israel strove together in the camp,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the son of an Israelitish woman whose father [was] an Egyptian, went out among the children of Israel; and this son of the Israelitish [woman] and a man of Israel strove together in the camp;", "vulgate": "ecce autem egressus filius mulieris israhelitis quem pepererat de viro aegyptio inter filios Israhel iurgatus est in castris cum viro israhelite;", "brenton": "And there went forth a son of an Israelitish woman, and he was son of an Egyptian man among the sons of Israel; and they fought in the camp, the son of the Israelitish woman, and a man who was an Israelite."}}, {"v": 11, "ref": "24:11", "o": "וַ֠/יִּקֹּב בֶּן הָֽ/אִשָּׁ֨ה הַ/יִּשְׂרְאֵלִ֤ית אֶת הַ/שֵּׁם֙ וַ/יְקַלֵּ֔ל וַ/יָּבִ֥יאוּ אֹת֖/וֹ אֶל מֹשֶׁ֑ה וְ/שֵׁ֥ם אִמּ֛/וֹ שְׁלֹמִ֥ית בַּת דִּבְרִ֖י לְ/מַטֵּה דָֽן", "en": {"kjv": "And the Israelitish woman’s son blasphemed the name of the Lord, and cursed. And they brought him unto Moses: (and his mother’s name was Shelomith, the daughter of Dibri, of the tribe of Dan:)", "web": "The son of the Israelite woman blasphemed the Name, and cursed; and they brought him to Moses. His mother’s name was Shelomith, the daughter of Dibri, of the tribe of Dan.", "bsb": "The son of the Israelite woman blasphemed the Name with a curse. So they brought him to Moses. (His mother’s name was Shelomith daughter of Dibri, of the tribe of Dan.)", "asv": "and the son of the Israelitish woman blasphemed the Name, and cursed; and they brought him unto Moses. And his mother’s name was Shelomith, the daughter of Dibri, of the tribe of Dan.", "ylt": "and the son of the Israelitish woman execrateth the Name, and revileth; and they bring him in unto Moses; and his mother's name is Shelomith daughter of Dibri, of the tribe of Dan;", "tyndale": "And the Israelitish womans sonne blasphemed the name and cursed, and they broughte him vnto Moses. And his mothers name was Selamyth, the doughter off Dybri off the trybe of Dan:", "dra": "And when he had blasphemed the name, and had cursed it, he was brought to Moses. (Now his mother was called Salumith, the daughter of Dabri, of the tribe of Dan.)", "bbe": "And the son of the Israelite woman said evil against the holy Name, with curses; and they took him to Moses. His mother's name was Shelomith, the daughter of Dibri, of the tribe of Dan.", "geneva": "So the Israelitish womans sonne blasphemed the name of the Lord, and cursed, and they brought him vnto Moses (his mothers name also was Shelomith, the daughter of Dibri, of the tribe of Dan)", "wycliffe": "and whanne he hadde blasfemyd the name of the Lord, and hadde cursid the Lord, he was brouyt to Moises; forsothe his modir was clepid Salumyth, the douytir of Dabry, of the lynage of Dan;", "rotherham": "and the son of the woman of Israel, and a man of Israel, reviled one another in the camp. And the son of the Israelitish woman uttered contemptuously the Name, and reviled. So they brought him in unto Moses,—now, the name of his mother, was Shelomith, daughter of Dibri, of the tribe of Dan;", "darby": "and the Israelitish woman's son blasphemed the Name, and cursed; and they brought him to Moses. And his mother's name was Shelomith, the daughter of Dibri, of the tribe of Dan.", "twenty": "", "jps": "And the son of the Israelitish woman blasphemed the Name, and cursed; and they brought him unto Moses. And his mother's name was Shelomith, the daughter of Dibri, of the tribe of Dan.", "acv": "and the son of the Israelite woman blasphemed the Name, and cursed. And they brought him to Moses. And his mother's name was Shelomith, the daughter of Dibri, of the tribe of Dan.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the Israelitish woman's son blasphemed the name [of the LORD], and cursed: and they brought him to Moses: (and his mother's name [was] Shelomith, the daughter of Dibri, of the tribe of Dan:)", "vulgate": "cumque blasphemasset nomen et maledixisset ei adductus est ad Mosen vocabatur autem mater eius Salumith filia Dabri de tribu Dan;", "brenton": "And the son of the Israelitish woman named THE NAME and curse; and they brought him to Moses: and his mother's name was Salomith, daughter of Dabri of the tribe of Dan."}}, {"v": 12, "ref": "24:12", "o": "וַ/יַּנִּיחֻ֖/הוּ בַּ/מִּשְׁמָ֑ר לִ/פְרֹ֥שׁ לָ/הֶ֖ם עַל פִּ֥י יְהוָֽה", "en": {"kjv": "And they put him in ward, that the mind of the Lord might be shewed them.", "web": "They put him in custody, until Yahweh’s will should be declared to them.", "bsb": "They placed him in custody until the will of the LORD should be made clear to them.", "asv": "And they put him in ward, that it might be declared unto them at the mouth of Jehovah.", "ylt": "and he causeth him to rest in charge--to explain to them by the mouth of Jehovah.", "tyndale": "and they putt him in warde, that Moses shulde declare vnto them what the Lorde sayde thereto.", "dra": "And they put him into prison, till they might know what the Lord would command.", "bbe": "And they kept him shut up, till a decision might be given by the mouth of the Lord.", "geneva": "And they put him in warde, till he tolde them the minde of the Lord.", "wycliffe": "and thei senten hym to prisoun, til thei wisten what the Lord comaundide.", "rotherham": "and they put him in ward,—that a clear answer might be given to them at the mouth of Yahweh.", "darby": "And they confined him, that they might decide at the mouth of Jehovah.", "twenty": "", "jps": "And they put him in ward, that it might be declared unto them at the mouth of HaShem.", "acv": "And they put him in ward, that it might be declared to them at the mouth of Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And they put him in custody, that the mind of the LORD might be shown to them.", "vulgate": "miseruntque eum in carcerem donec nossent quid iuberet Dominus;", "brenton": "And they put him in ward, to judge him by the command of the Lord."}}, {"v": 13, "ref": "24:13", "o": "וַ/יְדַבֵּ֥ר יְהוָ֖ה אֶל מֹשֶׁ֥ה לֵּ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh spoke to Moses, saying,", "bsb": "Then the LORD said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde spake vnto Moses sayenge,", "dra": "And the Lord spoke to Moses,", "bbe": "And the Lord said to Moses,", "geneva": "Then the Lord spake vnto Moses, saying,", "wycliffe": "And the Lord spak to Moises and seide,", "rotherham": "Then spake Yahweh unto Moses, saying:", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses, saying:", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "qui locutus est ad Mosen;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 14, "ref": "24:14", "o": "הוֹצֵ֣א אֶת הַֽ/מְקַלֵּ֗ל אֶל מִ/חוּץ֙ לַֽ/מַּחֲנֶ֔ה וְ/סָמְכ֧וּ כָֽל הַ/שֹּׁמְעִ֛ים אֶת יְדֵי/הֶ֖ם עַל רֹאשׁ֑/וֹ וְ/רָגְמ֥וּ אֹת֖/וֹ כָּל הָ/עֵדָֽה", "en": {"kjv": "Bring forth him that hath cursed without the camp; and let all that heard him lay their hands upon his head, and let all the congregation stone him.", "web": "“Bring out of the camp him who cursed; and let all who heard him lay their hands on his head, and let all the congregation stone him.", "bsb": "“Take the blasphemer outside the camp, and have all who heard him lay their hands on his head; then have the whole assembly stone him.", "asv": "Bring forth him that hath cursed without the camp; and let all that heard him lay their hands upon his head, and let all the congregation stone him.", "ylt": "`Bring out the reviler unto the outside of the camp; and all those hearing have laid their hands on his head, and all the company have stoned him.", "tyndale": "bringe him that cursed without the hoste, and let all that herde him, put their handes apo his heed, and let all the multitude stone him.", "dra": "Saying: Bring forth the blasphemer without the camp: and let them that heard him, put their hands upon his head: and let all the people stone him.", "bbe": "Take the curser outside the tent-circle; and let all in whose hearing the words were said put their hands on his head, and let him be stoned by all the people.", "geneva": "Bring the blasphemer without the hoste, and let all that heard him, put their handes vpon his head, and let all the Congregation stone him.", "wycliffe": "Lede out the blasfemere without the castels, and alle men that herden, sette her hondis on his heed, and al the puple stone hym.", "rotherham": "Bring forth him that reviled unto the outside of the camp, then shall all that heard [him] lean their hands upon his head,—and all the assembly shall stone him.", "darby": "Lead the reviler outside the camp; and all that heard [him] shall lay their hands upon his head, and the whole assembly shall stone him.", "twenty": "", "jps": "'Bring forth him that hath cursed without the camp; and let all that heard him lay their hands upon his head, and let all the congregation stone him.", "acv": "Bring forth him who has cursed outside the camp, and let all who heard him lay their hands upon his head, and let all the congregation stone him.", "anderson": "", "haweis": "", "noyes": "", "webster": "Bring forth him that hath cursed without the camp; and let all that heard [him] lay their hands upon his head, and let all the congregation stone him.", "vulgate": "dicens educ blasphemum extra castra et ponant omnes qui audierunt manus suas super caput eius et lapidet eum populus universus;", "brenton": "Bring forth him that cursed outside the camp, and all who heard shall lay their hands upon his head, and all the congregation shall stone him."}}, {"v": 15, "ref": "24:15", "o": "וְ/אֶל בְּנֵ֥י יִשְׂרָאֵ֖ל תְּדַבֵּ֣ר לֵ/אמֹ֑ר אִ֥ישׁ אִ֛ישׁ כִּֽי יְקַלֵּ֥ל אֱלֹהָ֖י/ו וְ/נָשָׂ֥א חֶטְאֽ/וֹ", "en": {"kjv": "And thou shalt speak unto the children of Israel, saying, Whosoever curseth his God shall bear his sin.", "web": "You shall speak to the children of Israel, saying, ‘Whoever curses his God shall bear his sin.", "bsb": "And you are to tell the Israelites, ‘If anyone curses his God, he shall bear the consequences of his sin.", "asv": "And thou shalt speak unto the children of Israel, saying, Whosoever curseth his God shall bear his sin.", "ylt": "`And unto the sons of Israel thou dost speak, saying, When any man revileth his God--then he hath borne his sin;", "tyndale": "And speake vnto the childern of Israel sayenge: Whosoeuer curseth his God, shall bere his synne:", "dra": "And thou shalt speak to the children of Israel: The man that curseth his God, shall bear his sin:", "bbe": "And say to the children of Israel, As for any man cursing God, his sin will be on his head.", "geneva": "And thou shalt speake vnto the children of Israel, saying, Whosoeuer curseth his God, shall beare his sinne.", "wycliffe": "And thou schalt speke to the sones of Israel, A man that cursith his God,", "rotherham": "And, unto the sons of Israel, shalt thou speak saying,—What man soever curseth his God shall bear his sin.", "darby": "And thou shalt speak unto the children of Israel, saying, Every one when he revileth hisGod shall bear his sin.", "twenty": "", "jps": "And thou shalt speak unto the children of Israel, saying: Whosoever curseth his G-d shall bear his sin.", "acv": "And thou shall speak to the sons of Israel, saying, Whoever curses his God shall bear his sin.", "anderson": "", "haweis": "", "noyes": "", "webster": "And thou shalt speak to the children of Israel, saying, Whoever curseth his God shall bear his sin.", "vulgate": "et ad filios Israhel loqueris homo qui maledixerit Deo suo portabit peccatum suum;", "brenton": "And speak to the sons of Israel, and thou shalt say to them, Whosoever shall curse God shall bear his sin."}}, {"v": 16, "ref": "24:16", "o": "וְ/נֹקֵ֤ב שֵׁם יְהוָה֙ מ֣וֹת יוּמָ֔ת רָג֥וֹם יִרְגְּמוּ ב֖/וֹ כָּל הָ/עֵדָ֑ה כַּ/גֵּר֙ כָּֽ/אֶזְרָ֔ח בְּ/נָקְב/וֹ שֵׁ֖ם יוּמָֽת", "en": {"kjv": "And he that blasphemeth the name of the Lord, he shall surely be put to death, and all the congregation shall certainly stone him: as well the stranger, as he that is born in the land, when he blasphemeth the name of the Lord, shall be put to death.", "web": "He who blasphemes Yahweh’s name, he shall surely be put to death. All the congregation shall certainly stone him. The foreigner as well as the native-born, when he blasphemes the Name, shall be put to death.", "bsb": "Whoever blasphemes the name of the LORD must surely be put to death; the whole assembly must surely stone him, whether he is a foreign resident or native; if he blasphemes the Name, he must be put to death.", "asv": "And he that blasphemeth the name of Jehovah, he shall surely be put to death; all the congregation shall certainly stone him: as well the sojourner, as the home-born, when he blasphemeth the name of Jehovah, shall be put to death.", "ylt": "and he who is execrating the name of Jehovah is certainly put to death; all the company do certainly cast stones at him; as a sojourner so a native, in his execrating the Name, is put to death.", "tyndale": "And he that blasphemeth the name of the Lorde, shall dye for it: all the multitude shall stone him to deeth. And the straunger as well as the Israelite yf he curse the name, shall dye for it.", "dra": "And he that blasphemeth the name of the Lord, dying let him die. All the multitude shall stone him, whether he be a native or a stranger. He that blasphemeth the name of the Lord, dying let him die.", "bbe": "And he who says evil against the name of the Lord will certainly be put to death; he will be stoned by all the people; the man who is not of your nation and one who is an Israelite by birth, whoever says evil against the holy Name is to be put to death.", "geneva": "And he that blasphemeth the name of the Lord, shalbe put to death: all the Congregation shall stone him to death: aswell the stranger, as he that is borne in the lande: when he blasphemeth the name of the Lord, let him beslaine.", "wycliffe": "schal bere his synne, and he that blasfemeth the name of the Lord, die bi deeth; al the multitude of the puple schal oppresse hym with stoonus, whether he that blasfemede the name of the Lord is a citeseyn, whether a pilgrym, die he bi deeth.", "rotherham": "And, he that contemptuously uttereth the name of Yahweh, shall be, surely put to death, all the assembly shall, surely stone, him,—as the sojourner so the home-born, when he contemptuously uttereth the Name, he shall be put to death.", "darby": "And he that blasphemeth the name of Jehovah shall certainly be put to death; all the assembly shall certainly stone him; as well the stranger as he that is home-born, when he blasphemeth the Name, shall be put to death.", "twenty": "", "jps": "And he that blasphemeth the name of HaShem, he shall surely be put to death; all the congregation shall certainly stone him; as well the stranger, as the home-born, when he blasphemeth the Name, shall be put to death.", "acv": "And he who blasphemes the name of Jehovah, he shall surely be put to death. All the congregation shall certainly stone him. As well the sojourner, as the home-born, when he blasphemes the Name, shall be put to death.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he that blasphemeth the name of the LORD, he shall surely be put to death, [and] all the congregation shall certainly stone him: as well the stranger, as he that is born in the land, when he blasphemeth the name [of the LORD], shall be put to death.", "vulgate": "et qui blasphemaverit nomen Domini morte moriatur lapidibus opprimet eum omnis multitudo sive ille civis seu peregrinus fuerit qui blasphemaverit nomen Domini morte moriatur;", "brenton": "And he that names the name of the Lord, let him die the death: let all the congregation of Israel stone him with stones; whether he be a stranger or a native, let him die for naming the name of the Lord."}}, {"v": 17, "ref": "24:17", "o": "וְ/אִ֕ישׁ כִּ֥י יַכֶּ֖ה כָּל נֶ֣פֶשׁ אָדָ֑ם מ֖וֹת יוּמָֽת", "en": {"kjv": "And he that killeth any man shall surely be put to death.", "web": "“‘He who strikes any man mortally shall surely be put to death.", "bsb": "And if a man takes the life of anyone else, he must surely be put to death.", "asv": "And he that smiteth any man mortally shall surely be put to death.", "ylt": "`And when a man smiteth any soul of man, he is certainly put to death.", "tyndale": "He that kylleth any man, shall dye for it:", "dra": "He that striketh and killeth a man: dying let him die.", "bbe": "And anyone who takes another's life is certainly to be put to death.", "geneva": "He also that killeth any man, he shall be put to death.", "wycliffe": "He that smytith and sleeth a man, die bi deeth;", "rotherham": "And, when, any man, by smiting taketh the life of any human being, he shall be surely put to death,", "darby": "And if any one smiteth any man mortally, he shall certainly be put to death.", "twenty": "", "jps": "And he that smiteth any man mortally shall surely be put to death.", "acv": "And he who smites any man mortally shall surely be put to death.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he that killeth any man shall surely be put to death.", "vulgate": "qui percusserit et occiderit hominem morte moriatur;", "brenton": "And whosoever shall smite a man and he die, let him die the death."}}, {"v": 18, "ref": "24:18", "o": "וּ/מַכֵּ֥ה נֶֽפֶשׁ בְּהֵמָ֖ה יְשַׁלְּמֶ֑/נָּה נֶ֖פֶשׁ תַּ֥חַת נָֽפֶשׁ", "en": {"kjv": "And he that killeth a beast shall make it good; beast for beast.", "web": "He who strikes an animal mortally shall make it good, life for life.", "bsb": "Whoever kills an animal must make restitution—life for life.", "asv": "And he that smiteth a beast mortally shall make it good, life for life.", "ylt": "`And he who smiteth a beast repayeth it, body for body.", "tyndale": "but he that kylleth a beest shall paye for it, beest for beest.", "dra": "He that killeth a beast, shall make it good that is to say, shall give beast for beast.", "bbe": "And anyone wounding a beast and causing its death, will have to make payment for it: a life for a life.", "geneva": "And he that killeth a beast, he shall restore it, beast for beast.", "wycliffe": "he that smytith a beeste, yelde oon in his stide, that is, lijf for lijf .", "rotherham": "And he that by smiting taketh away the life of a beast, shall make it good,—life for life.", "darby": "And he that smiteth a beast mortally shall make it good, life for life.", "twenty": "", "jps": "And he that smiteth a beast mortally shall make it good: life for life.", "acv": "And he who smites a beast mortally shall make it good, life for life.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he that killeth a beast shall make it good; beast for beast.", "vulgate": "qui percusserit animal reddat vicarium id est animam pro anima;", "brenton": "And whosoever shall smite a beast, and it shall die, let him render life for life."}}, {"v": 19, "ref": "24:19", "o": "וְ/אִ֕ישׁ כִּֽי יִתֵּ֥ן מ֖וּם בַּ/עֲמִית֑/וֹ כַּ/אֲשֶׁ֣ר עָשָׂ֔ה כֵּ֖ן יֵעָ֥שֶׂה לּֽ/וֹ", "en": {"kjv": "And if a man cause a blemish in his neighbour; as he hath done, so shall it be done to him;", "web": "If anyone injures his neighbor; as he has done, so shall it be done to him:", "bsb": "If anyone injures his neighbor, whatever he has done must be done to him:", "asv": "And if a man cause a blemish in his neighbor; as he hath done, so shall it be done to him:", "ylt": "`And when a man putteth a blemish in his fellow, as he hath done so it is done to him;", "tyndale": "Yf a man mayme his neyghboure as he hath done, so shall it be done to him agayne:", "dra": "He that giveth a blemish to any of his neighbours: as he hath done, so shall it be done to him:", "bbe": "And if a man does damage to his neighbour, as he has done, so let it be done to him;", "geneva": "Also if a man cause any blemish in his neighbour: as he hath done, so shall it be done to him.", "wycliffe": "If a man yyueth a wem to ony of hise citeseyns, as he dide, so be it don to him;", "rotherham": "And, when, any man, inflicteth a blemish upon his neighbour, as he hath done, so, shall it be done to him:", "darby": "And if a man cause a blemish in his neighbour, as he hath done, so shall it be done to him;", "twenty": "", "jps": "And if a man maim his neighbour; as he hath done, so shall it be done to him:", "acv": "And if a man causes a blemish in his neighbor, as he has done, so shall it be done to him:", "anderson": "", "haweis": "", "noyes": "", "webster": "And if a man shall cause a blemish in his neighbor; as he hath done, so shall it be done to him;", "vulgate": "qui inrogaverit maculam cuilibet civium suorum sicut fecit fiet ei;", "brenton": "And whosoever shall inflict a blemish on his neighbour, as he has done to him, so shall it be done to himself in return;"}}, {"v": 20, "ref": "24:20", "o": "שֶׁ֚בֶר תַּ֣חַת שֶׁ֔בֶר עַ֚יִן תַּ֣חַת עַ֔יִן שֵׁ֖ן תַּ֣חַת שֵׁ֑ן כַּ/אֲשֶׁ֨ר יִתֵּ֥ן מוּם֙ בָּֽ/אָדָ֔ם כֵּ֖ן יִנָּ֥תֶן בּֽ/וֹ", "en": {"kjv": "Breach for breach, eye for eye, tooth for tooth: as he hath caused a blemish in a man, so shall it be done to him again.", "web": "fracture for fracture, eye for eye, tooth for tooth; as he has injured someone, so shall it be done to him.", "bsb": "fracture for fracture, eye for eye, tooth for tooth. Just as he injured the other person, the same must be inflicted on him.", "asv": "breach for breach, eye for eye, tooth for tooth; as he hath caused a blemish in a man, so shall it be rendered unto him.", "ylt": "breach for breach, eye for eye, tooth for tooth; as he putteth a blemish in a man so it is done in him.", "tyndale": "broke for broke, eye for eye and toth for toth: euen as he hath maymed a man, so shall he be maymed agayne.", "dra": "Breach for breach, eye for ere, tooth for tooth, shall he restore. What blemish he gave, the like shall he be compelled to suffer.", "bbe": "Wound for wound, eye for eye, tooth for tooth; whatever damage he has done, so let it be done to him.", "geneva": "Breache for breach, eye for eye, tooth for tooth: such a blemish as he hath made in any, such shalbe repayed to him.", "wycliffe": "he schal restore brekyng for brekyng, iye for iye, tooth for tooth; what maner wem he yaf, he schal be compellid to suffre sich a wem.", "rotherham": "fracture for fracture, eye for eye, tooth for tooth, as he inflicteth a blemish upon a human being, so, shall one be inflicted upon him.", "darby": "breach for breach, eye for eye, tooth for tooth: as he hath caused a blemish in a man, so shall it be done to him.", "twenty": "", "jps": "breach for breach, eye for eye, tooth for tooth; as he hath maimed a man, so shall it be rendered unto him.", "acv": "injury for injury, eye for eye, tooth for tooth, as he has caused a blemish in a man, so shall it be rendered to him.", "anderson": "", "haweis": "", "noyes": "", "webster": "Breach for breach, eye for eye, tooth for tooth: as he hath caused a blemish in a man, so shall it be done to him.", "vulgate": "fracturam pro fractura oculum pro oculo dentem pro dente restituet qualem inflixerit maculam talem sustinere cogetur;", "brenton": "bruise for bruise, eye for eye, tooth for tooth: as any one may inflict a blemish on a man, so shall it be rendered to him."}}, {"v": 21, "ref": "24:21", "o": "וּ/מַכֵּ֥ה בְהֵמָ֖ה יְשַׁלְּמֶ֑/נָּה וּ/מַכֵּ֥ה אָדָ֖ם יוּמָֽת", "en": {"kjv": "And he that killeth a beast, he shall restore it: and he that killeth a man, he shall be put to death.", "web": "He who kills an animal shall make it good; and he who kills a man shall be put to death.", "bsb": "Whoever kills an animal must make restitution, but whoever kills a man must be put to death.", "asv": "And he that killeth a beast shall make it good: and he that killeth a man shall be put to death.", "ylt": "`And he who smiteth a beast repayeth it, and he who smiteth the life of man is put to death;", "tyndale": "So nowe he that kylleth a beest, shall paye for it: but he that kylleth a man, shall dye for it.", "dra": "He that striketh a beast, shall render another. He that striketh a man shall be punished.", "bbe": "He who puts a beast to death will have to make payment for it; he who puts a man to death will himself be put to death.", "geneva": "And he that killeth a beast shall restore it: but he that killeth a man shall be slaine.", "wycliffe": "He that smytith werk beeste, yeelde another; he that smytith a man, schal be punyschid .", "rotherham": "And he that killeth a beast, shall make it good,-and he that killeth a human being, shall be put to death.", "darby": "He that smiteth a beast [mortally] shall make it good; and he that smiteth a man [mortally] shall be put to death.", "twenty": "", "jps": "And he that killeth a beast shall make it good; and he that killeth a man shall be put to death.", "acv": "And he who kills a beast shall make it good. And he who kills a man shall be put to death.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he that killeth a beast, he shall restore it: and he that killeth a man, he shall be put to death.", "vulgate": "qui percusserit iumentum reddet aliud qui percusserit hominem punietur;", "brenton": "Whosoever shall smite a man, and he shall die, let him die the death."}}, {"v": 22, "ref": "24:22", "o": "מִשְׁפַּ֤ט אֶחָד֙ יִהְיֶ֣ה לָ/כֶ֔ם כַּ/גֵּ֥ר כָּ/אֶזְרָ֖ח יִהְיֶ֑ה כִּ֛י אֲנִ֥י יְהוָ֖ה אֱלֹהֵי/כֶֽם", "en": {"kjv": "Ye shall have one manner of law, as well for the stranger, as for one of your own country: for I am the Lord your God.", "web": "You shall have one kind of law for the foreigner as well as the native-born; for I am Yahweh your God.’”", "bsb": "You are to have the same standard of law for the foreign resident and the native; for I am the LORD your God.’”", "asv": "Ye shall have one manner of law, as well for the sojourner, as for the home-born: for I am Jehovah your God.", "ylt": "one judgment is to you; as a sojourner so is a native; for I am Jehovah your God.'", "tyndale": "Ye shall haue one maner of lawe amonge you: eue for the straunger as wel as for one of youre selues, for I am the Lorde youre God.", "dra": "Let there be equal judgment among you, whether he be a stranger, or a native that offends: because I am the Lord your God.", "bbe": "You are to have the same law for a man of another nation living among you as for an Israelite; for I am the Lord your God.", "geneva": "Ye shall haue one lawe: it shalbe aswel for the stranger as for one borne in the countrey: for I am the Lord your God.", "wycliffe": "Euene doom be among you, whether a pilgrym ethir a citeseyn synneth, for Y am youre Lord God.", "rotherham": "One rule, shall ye have, as the sojourner, so the home-born, shall be,—For, I—Yahweh, am your God.", "darby": "Ye shall have one law: as the stranger, so the home-born; for I am Jehovah yourGod.", "twenty": "", "jps": "Ye shall have one manner of law, as well for the stranger, as for the home-born; for I am HaShem your G-d.'", "acv": "Ye shall have one manner of law, as for the sojourner, as for the home-born, for I am Jehovah your God.", "anderson": "", "haweis": "", "noyes": "", "webster": "Ye shall have one manner of law, as well for the stranger, as for one of your own country: for I [am] the LORD your God.", "vulgate": "aequum iudicium sit inter vos sive peregrinus sive civis peccaverit quia ego sum Dominus Deus vester;", "brenton": "There shall be one judgment for the stranger and the native, for I am the Lord your God."}}, {"v": 23, "ref": "24:23", "o": "וַ/יְדַבֵּ֣ר מֹשֶׁה֮ אֶל בְּנֵ֣י יִשְׂרָאֵל֒ וַ/יּוֹצִ֣יאוּ אֶת הַֽ/מְקַלֵּ֗ל אֶל מִ/חוּץ֙ לַֽ/מַּחֲנֶ֔ה וַ/יִּרְגְּמ֥וּ אֹת֖/וֹ אָ֑בֶן וּ/בְנֵֽי יִשְׂרָאֵ֣ל עָשׂ֔וּ כַּֽ/אֲשֶׁ֛ר צִוָּ֥ה יְהוָ֖ה אֶת מֹשֶֽׁה", "en": {"kjv": "And Moses spake to the children of Israel, that they should bring forth him that had cursed out of the camp, and stone him with stones. And the children of Israel did as the Lord commanded Moses.", "web": "Moses spoke to the children of Israel; and they brought out him who had cursed out of the camp, and stoned him with stones. The children of Israel did as Yahweh commanded Moses.", "bsb": "Then Moses spoke to the Israelites, and they took the blasphemer outside the camp and stoned him. So the Israelites did as the LORD had commanded Moses.", "asv": "And Moses spake to the children of Israel; and they brought forth him that had cursed out of the camp, and stoned him with stones. And the children of Israel did as Jehovah commanded Moses.", "ylt": "And Moses speaketh unto the sons of Israel, and they bring out the reviler unto the outside of the camp, and stone him with stones; and the sons of Israel have done as Jehovah hath commanded Moses.", "tyndale": "And Moses tolde the childern of Israel, that they shulde bringe him that had cursed, out of the hoste, and stone him with stones. And the childern of Israel dyd as the Lorde comaunded Moses.", "dra": "And Moses spoke to the children of Israel. And they brought forth him that had blasphemed, without the camp: and they stoned him. And the children of Israel did as the Lord had commanded Moses.", "bbe": "And Moses said these words to the children of Israel, and they took the man who had been cursing outside the tent-circle and had him stoned. The children of Israel did as the Lord gave orders to Moses.", "geneva": "Then Moses tolde the children of Israel, and they brought the blasphemer out of the hoste, and stoned him with stones: so the children of Israel did as the Lord had commanded Moses.", "wycliffe": "And Moyses spak to the sones of Israel, and thei brouyten forth out of the castels hym that blasfemede, and oppressiden with stoonus. And the sones of Israel diden, as the Lord comaundide to Moyses.", "rotherham": "So then Moses spake unto the sons of Israel, and they took forth the reviler, unto the outside of the camp, and stoned him with stones. Thus, the sons of Israel did, as Yahweh commanded Moses.", "darby": "And Moses spoke to the children of Israel; and they led the reviler outside the camp and stoned him with stones. And the children of Israel did as Jehovah had commanded Moses.", "twenty": "", "jps": "And Moses spoke to the children of Israel, and they brought forth him that had cursed out of the camp, and stoned him with stones. And the children of Israel did as HaShem commanded Moses.", "acv": "And Moses spoke to the sons of Israel, and they brought forth him who had cursed out of the camp, and stoned him with stones. And the sons of Israel did as Jehovah commanded Moses.", "anderson": "", "haweis": "", "noyes": "", "webster": "And Moses spoke to the children of Israel, that they should bring forth him that had cursed out of the camp, and stone him with stones: and the children of Israel did as the LORD commanded Moses.", "vulgate": "locutusque est Moses ad filios Israhel et eduxerunt eum qui blasphemaverat extra castra ac lapidibus oppresserunt feceruntque filii Israhel sicut praeceperat Dominus Mosi;", "brenton": "And Moses spoke to the children of Israel, and they brought him that had cursed out of the camp, and stoned him with stones: and the children of Israel did as the Lord commanded Moses."}}]}, {"c": 25, "verses": [{"v": 1, "ref": "25:1", "o": "וַ/יְדַבֵּ֤ר יְהוָה֙ אֶל מֹשֶׁ֔ה בְּ/הַ֥ר סִינַ֖י לֵ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses in mount Sinai, saying,", "web": "Yahweh said to Moses in Mount Sinai,", "bsb": "Then the LORD said to Moses on Mount Sinai,", "asv": "And Jehovah spake unto Moses in mount Sinai, saying,", "ylt": "And Jehovah speaketh unto Moses, in mount Sinai, saying,", "tyndale": "And the Lorde spake vnto Moses in mount Sinai sayenge,", "dra": "And the Lord spoke to Moses in mount Sinai, saying:", "bbe": "And the Lord said to Moses on Mount Sinai,", "geneva": "And the Lord spake vnto Moses in mount Sinai, saying,", "wycliffe": "And the Lord spak to Moises in the hil of Synai,", "rotherham": "And Yahweh spake unto Moses in Mount Sinai, saying—", "darby": "And Jehovah spoke to Moses in mount Sinai, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses in mount Sinai, saying:", "acv": "And Jehovah spoke to Moses at mount Sinai, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses in mount Sinai, saying,", "vulgate": "locutusque est Dominus ad Mosen in monte Sinai dicens;", "brenton": "And the Lord spoke to Moses in the mount Sina, saying,"}}, {"v": 2, "ref": "25:2", "o": "דַּבֵּ֞ר אֶל בְּנֵ֤י יִשְׂרָאֵל֙ וְ/אָמַרְתָּ֣ אֲלֵ/הֶ֔ם כִּ֤י תָבֹ֨אוּ֙ אֶל הָ/אָ֔רֶץ אֲשֶׁ֥ר אֲנִ֖י נֹתֵ֣ן לָ/כֶ֑ם וְ/שָׁבְתָ֣ה הָ/אָ֔רֶץ שַׁבָּ֖ת לַ/יהוָֽה", "en": {"kjv": "Speak unto the children of Israel, and say unto them, When ye come into the land which I give you, then shall the land keep a sabbath unto the Lord.", "web": "“Speak to the children of Israel, and tell them, ‘When you come into the land which I give you, then the land shall keep a Sabbath to Yahweh.", "bsb": "“Speak to the Israelites and say to them: When you enter the land that I am giving you, the land itself must observe a Sabbath to the LORD.", "asv": "Speak unto the children of Israel, and say unto them, When ye come into the land which I give you, then shall the land keep a sabbath unto Jehovah.", "ylt": "`Speak unto the sons of Israel, and thou hast said unto them, When ye come in unto the land which I am giving to you, then hath the land kept a sabbath to Jehovah.", "tyndale": "speake vnto the childern of Israel and saye vnto the. When ye be come in to the lande whiche I geue you, let the londe rest a Sabbath vnto the Lorde.", "dra": "Speak to the children of Israel, and thou shalt say to them: When you shall have entered into the land which I will give you, observe the rest of the sabbath of the Lord.", "bbe": "Say to the children of Israel, When you come into the land which I will give you, let the land keep a Sabbath to the Lord.", "geneva": "Speake vnto the children of Israel, and say vnto them, When ye shall come into the lande which I giue you, the lande shall keepe Sabbath vnto the Lord.", "wycliffe": "and seide, Speke thou to the sones of Israel, and thou schalt seye to hem, Whanne ye han entrid in to the lond which Y schal yyue to you, `the erthe kepe the sabat of the Lord;", "rotherham": "Speak unto the sons of Israel, and thou shalt say unto them:—When ye enter into the land which, I, am giving you, then shall the land keep a sabbath unto Yahweh.", "darby": "Speak unto the children of Israel and say unto them, When ye come into the land that I will give you, the land shall celebrate a sabbath to Jehovah.", "twenty": "", "jps": "Speak unto the children of Israel, and say unto them: When ye come into the land which I give you, then shall the land keep a sabbath unto HaShem.", "acv": "Speak to the sons of Israel, and say to them, When ye come into the land which I give you, then shall the land keep a sabbath to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "Speak to the children of Israel, and say to them, When ye come into the land which I give you, then shall the land keep a sabbath to the LORD.", "vulgate": "loquere filiis Israhel et dices ad eos quando ingressi fueritis terram quam ego dabo vobis sabbatizet sabbatum Domini;", "brenton": "Speak to the children of Israel, and thou shalt say to them, Whensoever ye shall have entered into the land, which I give to you, then the land shall rest which I give to you, for its sabbaths to the Lord."}}, {"v": 3, "ref": "25:3", "o": "שֵׁ֤שׁ שָׁנִים֙ תִּזְרַ֣ע שָׂדֶ֔/ךָ וְ/שֵׁ֥שׁ שָׁנִ֖ים תִּזְמֹ֣ר כַּרְמֶ֑/ךָ וְ/אָסַפְתָּ֖ אֶת תְּבוּאָתָֽ/הּ", "en": {"kjv": "Six years thou shalt sow thy field, and six years thou shalt prune thy vineyard, and gather in the fruit thereof;", "web": "You shall sow your field six years, and you shall prune your vineyard six years, and gather in its fruits;", "bsb": "For six years you may sow your field and prune your vineyard and gather its crops.", "asv": "Six years thou shalt sow thy field, and six years thou shalt prune thy vineyard, and gather in the fruits thereof;", "ylt": "`Six years thou dost sow thy field, and six years thou dost prune thy vineyard, and hast gathered its increase,", "tyndale": "Sixe yeres thou shalt sowe thi felde, and sixe yere thou shalt cut thi vynes and gather in thi frutes.", "dra": "Six years thou shalt sow thy field and six years thou shalt prune thy vineyard, and shalt gather the fruits thereof.", "bbe": "For six years put seed into your land, and for six years give care to your vines and get in the produce of them;", "geneva": "Sixe yeeres thou shalt sowe thy field, and sixe yeeres thou shalt cut thy vineyarde, and gather the fruite thereof.", "wycliffe": "sixe yeeris thou schalt sowe thi feeld, and sixe yeeris thou schalt kitte thi vyner, and thou schalt gadere the fruytis ther of;", "rotherham": "Six years, shalt thou sow thy field, and, six years, shalt thou prune thy vineyard,—and gather the increase thereof;", "darby": "Six years shalt thou sow thy field, and six years shalt thou prune thy vineyard, and gather in the produce thereof,", "twenty": "", "jps": "Six years thou shalt sow thy field, and six years thou shalt prune thy vineyard, and gather in the produce thereof.", "acv": "Six years thou shall sow thy field, and six years thou shall prune thy vineyard, and gather in the fruits of it,", "anderson": "", "haweis": "", "noyes": "", "webster": "Six years thou shalt sow thy field, and six years thou shalt prune thy vineyard, and gather in the fruit thereof;", "vulgate": "sex annis seres agrum tuum et sex annis putabis vineam tuam colligesque fructus eius;", "brenton": "Six years thou shalt sow thy field, and six years thou shall prune thy vine, and gather in its fruit."}}, {"v": 4, "ref": "25:4", "o": "וּ/בַ/שָּׁנָ֣ה הַ/שְּׁבִיעִ֗ת שַׁבַּ֤ת שַׁבָּתוֹן֙ יִהְיֶ֣ה לָ/אָ֔רֶץ שַׁבָּ֖ת לַ/יהוָ֑ה שָֽׂדְ/ךָ֙ לֹ֣א תִזְרָ֔ע וְ/כַרְמְ/ךָ֖ לֹ֥א תִזְמֹֽר", "en": {"kjv": "But in the seventh year shall be a sabbath of rest unto the land, a sabbath for the Lord: thou shalt neither sow thy field, nor prune thy vineyard.", "web": "but in the seventh year there shall be a Sabbath of solemn rest for the land, a Sabbath to Yahweh. You shall not sow your field or prune your vineyard.", "bsb": "But in the seventh year there shall be a Sabbath of complete rest for the land—a Sabbath to the LORD. You are not to sow your field or prune your vineyard.", "asv": "but in the seventh year shall be a sabbath of solemn rest for the land, a sabbath unto Jehovah: thou shalt neither sow thy field, nor prune thy vineyard.", "ylt": "and in the seventh year a sabbath of rest is to the land, a sabbath to Jehovah; thy field thou dost not sow, and thy vineyard thou dost not prune;", "tyndale": "But the seuenth yere shall be a Sabbath of rest vnto the londe. The Lordes Sabbath it shalbe, ad thou shalt nether sowe thi felde, nor cut thy vynes.", "dra": "But in the seventh year there shall be a sabbath to the land, of the resting of the Lord. Thou shalt not sow thy field, nor prune thy vineyard.", "bbe": "But let the seventh year be a Sabbath of rest for the land, a Sabbath to the Lord; do not put seed into your land or have your vines cut.", "geneva": "But the seuenth yeere shalbe a Sabbath of rest vnto the lande: it shall be the Lordes Sabbath: thou shalt neither sowe thy fielde, nor cut thy vineyarde.", "wycliffe": "forsothe in the seuenthe yeer schal be sabat of the erthe of the restyng of the Lord;", "rotherham": "but, in the seventh year—a sabbath of sacred rest, shall there be unto the land, a sabbath unto Yahweh: thy field, shalt thou not sow, and, thy vineyard, shalt thou not prune;", "darby": "but in the seventh year shall be a sabbath of rest for the land, a sabbath to Jehovah. Thy field shalt thou not sow, and thy vineyard shalt thou not prune.", "twenty": "", "jps": "But in the seventh year shall be a sabbath of solemn rest for the land, a sabbath unto HaShem; thou shalt neither sow thy field, nor prune thy vineyard.", "acv": "but in the seventh year shall be a sabbath of solemn rest for the land, a sabbath to Jehovah. Thou shall neither sow thy field, nor prune thy vineyard.", "anderson": "", "haweis": "", "noyes": "", "webster": "But in the seventh year shall be a sabbath of rest to the land, a sabbath for the LORD: thou shalt neither sow thy field, nor prune thy vineyard.", "vulgate": "septimo autem anno sabbatum erit terrae requietionis Domini agrum non seres et vineam non putabis;", "brenton": "But in the seventh year shall be a sabbath, it shall be a rest to the land, a sabbath to the Lord: thou shalt not sow thy field, and thou shalt not prune thy vine."}}, {"v": 5, "ref": "25:5", "o": "אֵ֣ת סְפִ֤יחַ קְצִֽירְ/ךָ֙ לֹ֣א תִקְצ֔וֹר וְ/אֶת עִנְּבֵ֥י נְזִירֶ֖/ךָ לֹ֣א תִבְצֹ֑ר שְׁנַ֥ת שַׁבָּת֖וֹן יִהְיֶ֥ה לָ/אָֽרֶץ", "en": {"kjv": "That which groweth of its own accord of thy harvest thou shalt not reap, neither gather the grapes of thy vine undressed: for it is a year of rest unto the land.", "web": "What grows of itself in your harvest you shall not reap, and you shall not gather the grapes of your undressed vine. It shall be a year of solemn rest for the land.", "bsb": "You are not to reap the aftergrowth of your harvest or gather the grapes of your untended vines. The land must have a year of complete rest.", "asv": "That which groweth of itself of thy harvest thou shalt not reap, and the grapes of thy undressed vine thou shalt not gather: it shall be a year of solemn rest for the land.", "ylt": "the spontaneous growth of thy harvest thou dost not reap, and the grapes of thy separated thing thou dost not gather, a year of rest it is to the land.", "tyndale": "The corne that groweth by it selfe thou shalt not repe, nether gather the grapes that growe without thy dressynge: but it shalbe a Sabbath of rest vnto the londe.", "dra": "What the ground shall bring forth of itself, thou shalt not reap: neither shalt thou gather the grapes or the firstfruits as a vintage. For it is a year of rest to the land.", "bbe": "That which comes to growth of itself may not be cut, and the grapes of your uncared-for vines may not be taken off; let it be a year of rest for the land.", "geneva": "That which groweth of it owne accorde of thy haruest, thou shalt not reape, neither gather the grapes that thou hast left vnlaboured: for it shalbe a yeere of rest vnto the land.", "wycliffe": "thou schalt not sowe the feeld, and thou schalt not kitte the vyner, thou schalt not repe tho thingis whiche the erthe bryngith forth `bi fre wille, and thou schalt not gadere the grapis of thi firste fruytis, as vyndage; for it is the yeer of restyng of the lond; but tho schulen be to you in to mete,", "rotherham": "that which groweth of itself of thy harvest, shalt thou not reap; and the grapes of thine unpruned vines, shalt thou not cut off: a year of sacred rest, shall there be to the land.", "darby": "That which springeth up from the scattered seed of thy harvest thou shalt not reap, and the grapes of thine undressed vines thou shalt not gather: a year of rest shall it be for the land.", "twenty": "", "jps": "That which groweth of itself of thy harvest thou shalt not reap, and the grapes of thy undressed vine thou shalt not gather; it shall be a year of solemn rest for the land.", "acv": "That which grows of itself of thy harvest thou shall not reap, and the grapes of thy undressed vine thou shall not gather. It shall be a year of solemn rest for the land.", "anderson": "", "haweis": "", "noyes": "", "webster": "That which groweth of its own accord of thy harvest, thou shalt not reap, neither gather the grapes of thy vine undressed: [for] it is a year of rest to the land.", "vulgate": "quae sponte gignit humus non metes et uvas primitiarum tuarum non colliges quasi vindemiam annus enim requietionis terrae est;", "brenton": "And thou shalt not gather the spontaneous produce of thy field, and thou shalt not gather fully the grapes of thy dedication: it shall be a year of rest to the land."}}, {"v": 6, "ref": "25:6", "o": "וְ֠/הָיְתָה שַׁבַּ֨ת הָ/אָ֤רֶץ לָ/כֶם֙ לְ/אָכְלָ֔ה לְ/ךָ֖ וּ/לְ/עַבְדְּ/ךָ֣ וְ/לַ/אֲמָתֶ֑/ךָ וְ/לִ/שְׂכִֽירְ/ךָ֙ וּ/לְ/תוֹשָׁ֣בְ/ךָ֔ הַ/גָּרִ֖ים עִמָּֽ/ךְ", "en": {"kjv": "And the sabbath of the land shall be meat for you; for thee, and for thy servant, and for thy maid, and for thy hired servant, and for thy stranger that sojourneth with thee,", "web": "The Sabbath of the land shall be for food for you; for yourself, for your servant, for your maid, for your hired servant, and for your stranger, who lives as a foreigner with you.", "bsb": "Whatever the land yields during the Sabbath year shall be food for you—for yourself, your manservant and maidservant, the hired hand or foreigner who stays with you,", "asv": "And the sabbath of the land shall be for food for you; for thee, and for thy servant and for thy maid, and for thy hired servant and for thy stranger, who sojourn with thee.", "ylt": "`And the sabbath of the land hath been to you for food, to thee, and to thy man-servant, and to thy handmaid, and to thy hireling, and to thy settler, who are sojourning with thee;", "tyndale": "Neuerthelesse the Sabbath of the londe shalbe meate for you: euen for the and thy servaunte and for thy mayde and for thy hyred servaunte and for the straunger that dwelleth with the:", "dra": "But they shall be unto you for meat, to thee and to thy manservant, to thy maidservant and thy hireling, and to the strangers that sojourn with thee.", "bbe": "And the Sabbath of the land will give food for you and your man-servant and your woman-servant and those working for payment, and for those of another country who are living among you;", "geneva": "And the rest of the lande shall be meate for you, euen for thee, and for thy seruant, and for thy mayde, and for thy hired seruant, and for the stranger that soiourneth with thee:", "wycliffe": "to thee, and to thi seruaunt, to thin handmaide, and to thin hirid man, and to the comelyng which is a pilgrym at thee; alle thingis that `comen forth,", "rotherham": "So shall the sabbath of the land be unto you for food: unto thee, and unto thy servant and unto thy handmaid,—and unto thy hireling, and unto thy settlers that are sojourning with thee;", "darby": "And the sabbath of the land shall be for food for you, for thee, and for thy bondman, and for thy handmaid, and for thy hired servant, and for him that dwelleth as a sojourner with thee, and for thy cattle,", "twenty": "", "jps": "And the sabbath-produce of the land shall be for food for you: for thee, and for thy servant and for thy maid, and for thy hired servant and for the settler by thy side that sojourn with thee;", "acv": "And the sabbath of the land shall be for food for you: for thee, and for thy servant and for thy maid, and for thy hired servant and for thy stranger, who sojourns with thee.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the sabbath of the land shall be food for you; for thee, and for thy servant, and for thy maid, and for thy hired servant, and for thy stranger that sojourneth with thee,", "vulgate": "sed erunt vobis in cibum tibi et servo tuo ancillae et mercennario tuo et advenae qui peregrinantur apud te;", "brenton": "And the sabbaths of the land shall be food for thee, and for thy man-servant, and for thy maid-servant, and thy hireling, and the stranger that abides with thee."}}, {"v": 7, "ref": "25:7", "o": "וְ/לִ֨/בְהֶמְתְּ/ךָ֔ וְ/לַֽ/חַיָּ֖ה אֲשֶׁ֣ר בְּ/אַרְצֶ֑/ךָ תִּהְיֶ֥ה כָל תְּבוּאָתָ֖/הּ לֶ/אֱכֹֽל", "en": {"kjv": "And for thy cattle, and for the beast that are in thy land, shall all the increase thereof be meat.", "web": "For your livestock also, and for the animals that are in your land, shall all its increase be for food.", "bsb": "and for your livestock and the wild animals in your land. All its growth may serve as food.", "asv": "And for thy cattle, and for the beasts that are in thy land, shall all the increase thereof be for food.", "ylt": "and to thy cattle, and to the beast which is in thy land, is all thine increase for food.", "tyndale": "and for thi catell and for the beestes that are in thy londe, shall all the encrease thereof be meate.", "dra": "All things that grow shall be meat to thy beasts and to thy cattle.", "bbe": "And for your cattle and the beasts on the land; all the natural increase of the land will be for food.", "geneva": "And for thy cattell, and for the beastes that are in thy lande shall all the encrease thereof be meate.", "wycliffe": "schulen yyue mete to thi werk beestis and smale beestis.", "rotherham": "and unto thy tame-beasts, and unto the wild-beasts that are in thy land, shall belong all the increase thereof for food.", "darby": "and for the beasts that are in thy land: all the produce thereof shall be for food.", "twenty": "", "jps": "and for thy cattle, and for the beasts that are in thy land, shall all the increase thereof be for food.", "acv": "And for thy cattle, and for the beasts that are in thy land, all the increase of it shall be for food.", "anderson": "", "haweis": "", "noyes": "", "webster": "And for thy cattle, and for the beast that [are] in thy land, shall all the increase of it be food.", "vulgate": "iumentis tuis et pecoribus omnia quae nascuntur praebebunt cibum;", "brenton": "And for thy cattle, and for the wild beats that are in thy land, shall every fruit of it be for food."}}, {"v": 8, "ref": "25:8", "o": "וְ/סָפַרְתָּ֣ לְ/ךָ֗ שֶׁ֚בַע שַׁבְּתֹ֣ת שָׁנִ֔ים שֶׁ֥בַע שָׁנִ֖ים שֶׁ֣בַע פְּעָמִ֑ים וְ/הָי֣וּ לְ/ךָ֗ יְמֵי֙ שֶׁ֚בַע שַׁבְּתֹ֣ת הַ/שָּׁנִ֔ים תֵּ֥שַׁע וְ/אַרְבָּעִ֖ים שָׁנָֽה", "en": {"kjv": "And thou shalt number seven sabbaths of years unto thee, seven times seven years; and the space of the seven sabbaths of years shall be unto thee forty and nine years.", "web": "“‘You shall count off seven Sabbaths of years, seven times seven years; and there shall be to you the days of seven Sabbaths of years, even forty-nine years.", "bsb": "And you shall count off seven Sabbaths of years—seven times seven years—so that the seven Sabbaths of years amount to forty-nine years.", "asv": "And thou shalt number seven sabbaths of years unto thee, seven times seven years; and there shall be unto thee the days of seven sabbaths of years, even forty and nine years.", "ylt": "`And thou hast numbered to thee seven sabbaths of years, seven years seven times, and the days of the seven sabbaths of years have been to thee nine and forty years,", "tyndale": "Then numbre seuen wekes of yeres, that is, seuen tymes seuen yere: and the space of the seuen wekes of yeres will be vnto the .xlix. yere.", "dra": "Thou shalt also number to thee seven weeks of years: that is to say, seven times seven, which together make forty-nine years.", "bbe": "And let seven Sabbaths of years be numbered to you, seven times seven years; even the days of seven Sabbaths of years, that is forty-nine years;", "geneva": "Also thou shalt number seuen Sabbaths of yeeres vnto thee, euen seuen times seuen yeere: and the space of the seuen Sabbaths of yeeres will be vnto thee nine and fourtie yeere.", "wycliffe": "Also thou schalt noumbre to thee seuene woukis of yeeris, that is, seuene sithes seuene, whiche togidere maken nyn and fourti yeer;", "rotherham": "And thou shalt count to thee seven weeks of years, seven years, seven times,—so shall the days of the seven weeks of years become to thee forty-nine years.", "darby": "And thou shalt count seven sabbaths of years, seven times seven years; so that the days of the seven sabbaths of years be unto thee forty-nine years.", "twenty": "", "jps": "And thou shalt number seven sabbaths of years unto thee, seven times seven years; and there shall be unto thee the days of seven sabbaths of years, even forty and nine years.", "acv": "And thou shall number seven sabbaths of years to thee, seven times seven years, and there shall be to thee the days of seven sabbaths of years, even forty-nine years.", "anderson": "", "haweis": "", "noyes": "", "webster": "And thou shalt number seven sabbaths of years to thee, seven times seven years; and the space of the seven sabbaths of years shall be to thee forty and nine years.", "vulgate": "numerabis quoque tibi septem ebdomades annorum id est septem septies quae simul faciunt annos quadraginta novem;", "brenton": "And thou shalt reckon to thyself seven sabbaths of years, seven times seven years; and they shall be to thee seven weeks of years, nine and forty years."}}, {"v": 9, "ref": "25:9", "o": "וְ/הַֽעֲבַרְתָּ֞ שׁוֹפַ֤ר תְּרוּעָה֙ בַּ/חֹ֣דֶשׁ הַ/שְּׁבִעִ֔י בֶּ/עָשׂ֖וֹר לַ/חֹ֑דֶשׁ בְּ/יוֹם֙ הַ/כִּפֻּרִ֔ים תַּעֲבִ֥ירוּ שׁוֹפָ֖ר בְּ/כָל אַרְצְ/כֶֽם", "en": {"kjv": "Then shalt thou cause the trumpet of the jubile to sound on the tenth day of the seventh month, in the day of atonement shall ye make the trumpet sound throughout all your land.", "web": "Then you shall sound the loud trumpet on the tenth day of the seventh month. On the Day of Atonement you shall sound the trumpet throughout all your land.", "bsb": "Then you are to sound the horn far and wide on the tenth day of the seventh month, the Day of Atonement. You shall sound it throughout your land.", "asv": "Then shalt thou send abroad the loud trumpet on the tenth day of the seventh month; in the day of atonement shall ye send abroad the trumpet throughout all your land.", "ylt": "and thou hast caused a trumpet of shouting to pass over in the seventh month, in the tenth of the month; in the day of the atonements ye do cause a trumpet to pass over through all your land;", "tyndale": "And then thou shalt make an horne blowe: euen in the tenth daye of the seuenth moneth, which is the daye of attonement. And then shall ye make the horne blowe, euen thorowe out all youre lande.", "dra": "And thou shalt sound the trumpet in the seventh month, the tenth day of the month, in the time of the expiation in all your land.", "bbe": "Then let the loud horn be sounded far and wide on the tenth day of the seventh month; on the day of taking away sin let the horn be sounded through all your land.", "geneva": "Then thou shalt cause to blow the trumpet of the Iubile in the tenth day of the seuenth moneth: euen in the day of the reconciliation shall ye make the trumpet blowe, throughout all your lande.", "wycliffe": "and thou schalt sowne with a clarioun in the seuenthe monethe, in the tenthe dai of the monethe, in the tyme of propiciacioun, `that is, merci, in al youre lond.", "rotherham": "Then shalt thou cause a signal-horn to pass through in the seventh month, on the tenth of the month: on the Day of Propitiation, shall ye cause a horn to pass throughout all your land.", "darby": "Then shalt thou cause the loud sound of the trumpet to go forth in the seventh month, on the tenth of the month; on the day of atonement shall ye cause the trumpet to go forth throughout your land.", "twenty": "", "jps": "Then shalt thou make proclamation with the blast of the horn on the tenth day of the seventh month; in the day of atonement shall ye make proclamation with the horn throughout all your land.", "acv": "Then thou shall send abroad the loud trumpet on the tenth day of the seventh month. In the day of atonement ye shall send abroad the trumpet throughout all your land.", "anderson": "", "haweis": "", "noyes": "", "webster": "Then shalt thou cause the trumpet of the jubilee to sound, on the tenth [day] of the seventh month, in the day of atonement shall ye make the trumpet sound throughout all your land.", "vulgate": "et clanges bucina mense septimo decima die mensis propitiationis tempore in universa terra vestra;", "brenton": "In the seventh month, on the tenth day of the month, ye shall make a proclamation with the sound of a trumpet in all your land; on the day of atonement ye shall make a proclamation with a trumpet in all your land."}}, {"v": 10, "ref": "25:10", "o": "וְ/קִדַּשְׁתֶּ֗ם אֵ֣ת שְׁנַ֤ת הַ/חֲמִשִּׁים֙ שָׁנָ֔ה וּ/קְרָאתֶ֥ם דְּר֛וֹר בָּ/אָ֖רֶץ לְ/כָל יֹשְׁבֶ֑י/הָ יוֹבֵ֥ל הִוא֙ תִּהְיֶ֣ה לָ/כֶ֔ם וְ/שַׁבְתֶּ֗ם אִ֚ישׁ אֶל אֲחֻזָּת֔/וֹ וְ/אִ֥ישׁ אֶל מִשְׁפַּחְתּ֖/וֹ תָּשֻֽׁבוּ", "en": {"kjv": "And ye shall hallow the fiftieth year, and proclaim liberty throughout all the land unto all the inhabitants thereof: it shall be a jubile unto you; and ye shall return every man unto his possession, and ye shall return every man unto his family.", "web": "You shall make the fiftieth year holy, and proclaim liberty throughout the land to all its inhabitants. It shall be a jubilee to you; and each of you shall return to his own property, and each of you shall return to his family.", "bsb": "So you are to consecrate the fiftieth year and proclaim liberty in the land for all its inhabitants. It shall be your Jubilee, when each of you is to return to his property and to his clan.", "asv": "And ye shall hallow the fiftieth year, and proclaim liberty throughout the land unto all the inhabitants thereof: it shall be a jubilee unto you; and ye shall return every man unto his possession, and ye shall return every man unto his family.", "ylt": "and ye have hallowed the year, the fiftieth year; and ye have proclaimed liberty in the land to all its inhabitants; a jubilee it is to you; and ye have turned back each unto his possession; yea, each unto his family ye do turn back.", "tyndale": "And ye shall halowe the fiftith yere, and proclayme libertie thorowe out the lande vnto all the inhabiters thereof, It shalbe a yere of hornes blowynge vnto you and ye shall returne: euery man vnto his possession and euery man vnto his kynred agayne.", "dra": "And thou shalt sanctify the fiftieth year, and shalt proclaim remission to all the inhabitants of thy land: for it is the year of jubilee. Every man shall return to his possession, and every one shall go back to his former family:", "bbe": "And let this fiftieth year be kept holy, and say publicly that everyone in the land is free from debt: it is the Jubilee, and every man may go back to his heritage and to his family.", "geneva": "And ye shall halowe that yeere, euen the fiftieth yeere, and proclaime libertie in the lande to all the inhabitants thereof: it shalbe the Iubile vnto you, and ye shall returne euery man vnto his possession, and euery man shall returne vnto his familie.", "wycliffe": "And thou schalt halewe the fiftithe yeer, and thou schalt clepe remissioun to alle the dwellers of thi lond; for thilke yeer is iubilee; a man schal turne ayen to hys possessioun, and ech man schal go ayen to the firste meynee,", "rotherham": "So shall ye hallow the fiftieth year, and proclaim freedom throughout the land to all the dwellers thereof,—a jubilee, shall it be unto you, and ye shall return, every man unto his possession, and every man unto his family, shall ye return.", "darby": "And ye shall hallow the year of the fiftieth year, and proclaim liberty in the land unto all the inhabitants thereof; a [year of] jubilee shall it be unto you, and ye shall return every man unto his possession, and ye shall return every man unto his family;", "twenty": "", "jps": "And ye shall hallow the fiftieth year, and proclaim liberty throughout the land unto all the inhabitants thereof; it shall be a jubilee unto you; and ye shall return every man unto his possession, and ye shall return every man unto his family.", "acv": "And ye shall hallow the fiftieth year, and proclaim liberty throughout the land to all the inhabitants of it. It shall be a jubilee to you, and ye shall return every man to his possession, and ye shall return every man to his family.", "anderson": "", "haweis": "", "noyes": "", "webster": "And ye shall hallow the fiftieth year, and proclaim liberty throughout [all] the land to all its inhabitants: it shall be a jubilee to you; and ye shall return every man to his possession, and ye shall return every man to his family.", "vulgate": "sanctificabisque annum quinquagesimum et vocabis remissionem cunctis habitatoribus terrae tuae ipse est enim iobeleus revertetur homo ad possessionem suam et unusquisque rediet ad familiam pristinam;", "brenton": "And ye shall sanctify the year, the fiftieth year, and ye shall proclaim a release upon the land to all that inhabit it; it shall be given a year of release, a jubilee for you; and each one shall depart to his possession, and ye shall go each to his family."}}, {"v": 11, "ref": "25:11", "o": "יוֹבֵ֣ל הִ֗וא שְׁנַ֛ת הַ/חֲמִשִּׁ֥ים שָׁנָ֖ה תִּהְיֶ֣ה לָ/כֶ֑ם לֹ֣א תִזְרָ֔עוּ וְ/לֹ֤א תִקְצְרוּ֙ אֶת סְפִיחֶ֔י/הָ וְ/לֹ֥א תִבְצְר֖וּ אֶת נְזִרֶֽי/הָ", "en": {"kjv": "A jubile shall that fiftieth year be unto you: ye shall not sow, neither reap that which groweth of itself in it, nor gather the grapes in it of thy vine undressed.", "web": "That fiftieth year shall be a jubilee to you. In it you shall not sow, neither reap that which grows of itself, nor gather from the undressed vines.", "bsb": "The fiftieth year will be a Jubilee for you; you are not to sow the land or reap its aftergrowth or harvest the untended vines.", "asv": "A jubilee shall that fiftieth year be unto you: ye shall not sow, neither reap that which groweth of itself in it, nor gather the grapes in it of the undressed vines.", "ylt": "`A jubilee it is , the fiftieth year, a year it is to you; ye sow not, nor reap its spontaneous growth, nor gather its separated things;", "tyndale": "A yere of hornes blowynge shall that fiftieth yere be vnto you. Ye shall not sowe nether repe the corne that groweth by it selfe, nor gather the grapes that growe without thi laboure", "dra": "Because it is the jubilee and the fiftieth year. You shall not sow, nor reap the things that grow in the field of their own accord, neither shall you gather the firstfruits of the vines,", "bbe": "Let this fiftieth year be the Jubilee: no seed may be planted, and that which comes to growth of itself may not be cut, and the grapes may not be taken from the uncared-for vines.", "geneva": "This fiftieth yeere shalbe a yeere of Iubile vnto you: ye shall not sowe, neither reape that which groweth of it selfe, neither gather the grapes thereof, that are left vnlaboured.", "wycliffe": "for it is iubilee, and the fiftithe yeer. Ye schulen not sowe, nether ye schulen repe thingis, that comen forth freli in the feeld, and ye schulen not gadere the firste fruytis of vyndage, for the halewyng of iubilee;", "rotherham": "A jubilee, shall that fiftieth year be unto you,—ye shall not sow, neither shall ye reap the self-grown corn thereof, nor cut off the grapes of the unpruned vines thereof.", "darby": "a year of jubilee shall that fiftieth year be unto you: ye shall not sow, neither reap its aftergrowth, nor gather [the fruit of] its undressed vines.", "twenty": "", "jps": "A jubilee shall that fiftieth year be unto you; ye shall not sow, neither reap that which groweth of itself in it, nor gather the grapes in it of the undressed vines.", "acv": "That fiftieth year shall be a jubilee to you. Ye shall not sow, neither reap that which grows of itself in it, nor gather in it of the undressed vines.", "anderson": "", "haweis": "", "noyes": "", "webster": "A jubilee shall that fiftieth year be to you: ye shall not sow, neither reap that which groweth of itself in it, nor gather [the grapes] in it of thy vine undressed.", "vulgate": "quia iobeleus est et quinquagesimus annus non seretis neque metetis sponte in agro nascentia et primitias vindemiae non colligetis;", "brenton": "This is a jubilee of release, the year shall be to you the fiftieth year: ye shall not sow, nor reap the produce that comes of itself from the land, neither shall ye gather its dedicated fruits."}}, {"v": 12, "ref": "25:12", "o": "כִּ֚י יוֹבֵ֣ל הִ֔וא קֹ֖דֶשׁ תִּהְיֶ֣ה לָ/כֶ֑ם מִן הַ֨/שָּׂדֶ֔ה תֹּאכְל֖וּ אֶת תְּבוּאָתָֽ/הּ", "en": {"kjv": "For it is the jubile; it shall be holy unto you: ye shall eat the increase thereof out of the field.", "web": "For it is a jubilee; it shall be holy to you. You shall eat of its increase out of the field.", "bsb": "For it is a Jubilee; it shall be holy to you. You may eat only the crops taken directly from the field.", "asv": "For it is a jubilee; it shall be holy unto you: ye shall eat the increase thereof out of the field.", "ylt": "for a jubilee it is , holy it is to you; out of the field ye eat its increase;", "tyndale": "For it is a yere of hornes blowinge and shalbe holy vnto you: how be it, yet ye shall eate of the encrease of the felde.", "dra": "Because of the sanctification of the jubilee. But as they grow you shall presently eat them.", "bbe": "For it is the Jubilee, and it is holy to you; your food will be the natural increase of the field.", "geneva": "For it is the Iubile, it shall be holy vnto you: ye shall eate of the encrease thereof out of the fielde.", "wycliffe": "but anoon ye schulen ete thingis takun awey;", "rotherham": "For, a jubilee, it is, holy, shall it be unto you,—out of the field, shall ye eat her increase.", "darby": "For it is the jubilee; it shall be holy unto you; out of the field shall ye eat its produce.", "twenty": "", "jps": "For it is a jubilee; it shall be holy unto you; ye shall eat the increase thereof out of the field.", "acv": "For it is a jubilee; it shall be holy to you. Ye shall eat the increase of it out of the field.", "anderson": "", "haweis": "", "noyes": "", "webster": "For it [is] the jubilee; it shall be holy to you: ye shall eat the increase of it out of the field.", "vulgate": "ob sanctificationem iobelei sed statim ablata comedetis;", "brenton": "For it is a jubilee of release; it shall be holy to you, ye shall eat its fruits off the fields."}}, {"v": 13, "ref": "25:13", "o": "בִּ/שְׁנַ֥ת הַ/יּוֹבֵ֖ל הַ/זֹּ֑את תָּשֻׁ֕בוּ אִ֖ישׁ אֶל אֲחֻזָּתֽ/וֹ", "en": {"kjv": "In the year of this jubile ye shall return every man unto his possession.", "web": "“‘In this Year of Jubilee each of you shall return to his property.", "bsb": "In this Year of Jubilee, each of you shall return to his own property.", "asv": "In this year of jubilee ye shall return every man unto his possession.", "ylt": "in the year of this jubilee ye turn back each unto his possession.", "tyndale": "And in this yere of hornes blowinge ye shall returne, euery man vnto his possession agayne.", "dra": "In the year of the jubilee all shall return to their possessions.", "bbe": "In this year of Jubilee, let every man go back to his heritage.", "geneva": "In the yeere of this Iubile, ye shall returne euery man vnto his possession.", "wycliffe": "in the yeer of iubilee alle men go ayen to her possessiouns.", "rotherham": "In this same jubilee year, shall ye return every man unto his possession.", "darby": "In this year of the jubilee ye shall return every man unto his possession.", "twenty": "", "jps": "In this year of jubilee ye shall return every man unto his possession.", "acv": "In this year of jubilee ye shall return every man to his possession.", "anderson": "", "haweis": "", "noyes": "", "webster": "In the year of this jubilee ye shall return every man to his possession.", "vulgate": "anno iobelei redient omnes ad possessiones suas;", "brenton": "In the year of the release even the jubilee of it, shall each one return to his possession."}}, {"v": 14, "ref": "25:14", "o": "וְ/כִֽי תִמְכְּר֤וּ מִמְכָּר֙ לַ/עֲמִיתֶ֔/ךָ א֥וֹ קָנֹ֖ה מִ/יַּ֣ד עֲמִיתֶ֑/ךָ אַל תּוֹנ֖וּ אִ֥ישׁ אֶת אָחִֽי/ו", "en": {"kjv": "And if thou sell ought unto thy neighbour, or buyest ought of thy neighbour’s hand, ye shall not oppress one another:", "web": "“‘If you sell anything to your neighbor, or buy from your neighbor, you shall not wrong one another.", "bsb": "If you make a sale to your neighbor or a purchase from him, you must not take advantage of each other.", "asv": "And if thou sell aught unto thy neighbor, or buy of thy neighbor’s hand, ye shall not wrong one another.", "ylt": "`And when thou sellest anything to thy fellow, or buyest from the hand of thy fellow, ye do not oppress one another;", "tyndale": "When thou sellest oughte vnto thy neyghboure or byest off thy neyghboures hande, ye shall not oppresse one another:", "dra": "When thou shalt sell any thing to thy neighbour, or shalt buy of him: grieve not thy brother. But thou shalt buy of him according to the number of years from the jubilee.", "bbe": "And in the business of trading goods for money, do no wrong to one another.", "geneva": "And when thou sellest ought to thy neighbour, or byest at thy neighbours hande, ye shall not oppresse one another:", "wycliffe": "Whanne thou schalt sille ony thing to thi citeseyn, ether schalt bie of hym, make thou not sory thi brother, but bi the noumbre of `yeeris of iubile thou schalt bie of him,", "rotherham": "And when ye sell anything to thy neighbour, or buy aught at thy neighbour’s hand, do not overreach one another.", "darby": "And if ye sell ought unto your neighbour, or buy of your neighbour's hand, ye shall not overreach one another.", "twenty": "", "jps": "And if thou sell aught unto thy neighbour, or buy of thy neighbour's hand, ye shall not wrong one another.", "acv": "And if thou sell anything to thy neighbor, or buy of thy neighbor's hand, ye shall not wrong each other.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if thou shalt sell aught to thy neighbor, or buy [aught] of thy neighbor's hand, ye shall not oppress one another:", "vulgate": "quando vendes quippiam civi tuo vel emes ab eo ne contristes fratrem tuum sed iuxta numerum annorum iobelei emes ab eo;", "brenton": "And if thou shouldest sell a possession to thy neighbour, or if thou shouldest buy of thy neighbour, let not a man oppress his neighbour."}}, {"v": 15, "ref": "25:15", "o": "בְּ/מִסְפַּ֤ר שָׁנִים֙ אַחַ֣ר הַ/יּוֹבֵ֔ל תִּקְנֶ֖ה מֵ/אֵ֣ת עֲמִיתֶ֑/ךָ בְּ/מִסְפַּ֥ר שְׁנֵֽי תְבוּאֹ֖ת יִמְכָּר לָֽ/ךְ", "en": {"kjv": "According to the number of years after the jubile thou shalt buy of thy neighbour, and according unto the number of years of the fruits he shall sell unto thee:", "web": "According to the number of years after the Jubilee you shall buy from your neighbor. According to the number of years of the crops he shall sell to you.", "bsb": "You are to buy from your neighbor according to the number of years since the last Jubilee; he is to sell to you according to the number of harvest years remaining.", "asv": "According to the number of years after the jubilee thou shalt buy of thy neighbor, and according unto the number of years of the crops he shall sell unto thee.", "ylt": "by the number of years after the jubilee thou dost buy from thy fellow; by the number of the years of increase he doth sell to thee;", "tyndale": "but accordynge to the numbre of yeres after the trompett yere, thou shalt bye of thy neyghboure, and accordynge vnto the numbre off fruteyeres, he shall sell vnto the.", "dra": "And he shall sell to thee according to the computation of the fruits.", "bbe": "Let your exchange of goods with your neighbours have relation to the number of years after the year of Jubilee, and the number of times the earth has given her produce.", "geneva": "But according to the nomber of yeeres after the Iubile thou shalt bye of thy neighbour: also according to the nomber of the yeeres of the reuenues, he shall sell vnto thee.", "wycliffe": "and bi the rekenyng of fruytis he schal sille to thee.", "rotherham": "By the number of years after the jubilee, shalt thou buy of thy neighbour,—by the number of the years of increase, shall he sell unto thee;", "darby": "According to the number of years since the jubilee, thou shalt buy of thy neighbour; according to the number of years of the produce, he shall sell unto thee.", "twenty": "", "jps": "According to the number of years after the jubilee thou shalt buy of thy neighbour, and according unto the number of years of the crops he shall sell unto thee.", "acv": "According to the number of years after the jubilee thou shall buy of thy neighbor, and according to the number of years of the crops he shall sell to thee.", "anderson": "", "haweis": "", "noyes": "", "webster": "According to the number of years after the jubilee thou shalt buy of thy neighbor, [and] according to the number of years of the fruits he shall sell to thee:", "vulgate": "et iuxta supputationem frugum vendet tibi;", "brenton": "According to the number of years after the jubilee shalt thou buy of thy neighbour, according to the number of years of the fruits shall he sell to thee."}}, {"v": 16, "ref": "25:16", "o": "לְ/פִ֣י רֹ֣ב הַ/שָּׁנִ֗ים תַּרְבֶּה֙ מִקְנָת֔/וֹ וּ/לְ/פִי֙ מְעֹ֣ט הַ/שָּׁנִ֔ים תַּמְעִ֖יט מִקְנָת֑/וֹ כִּ֚י מִסְפַּ֣ר תְּבוּאֹ֔ת ה֥וּא מֹכֵ֖ר לָֽ/ךְ", "en": {"kjv": "According to the multitude of years thou shalt increase the price thereof, and according to the fewness of years thou shalt diminish the price of it: for according to the number of the years of the fruits doth he sell unto thee.", "web": "According to the length of the years you shall increase its price, and according to the shortness of the years you shall diminish its price; for he is selling the number of the crops to you.", "bsb": "You shall increase the price in proportion to a greater number of years, or decrease it in proportion to a lesser number of years; for he is selling you a given number of harvests.", "asv": "According to the multitude of the years thou shalt increase the price thereof, and according to the fewness of the years thou shalt diminish the price of it; for the number of the crops doth he sell unto thee.", "ylt": "according to the multitude of the years thou dost multiply its price, and according to the fewness of the years thou dost diminish its price; for a number of increases he is selling to thee;", "tyndale": "Accordinge vnto the multitude of yeres, thou shalt encrease the price thereof and accordinge to the fewnesse of yeres, thou shalt mynish the price: for the numbre of frute he shall sell vnto the.", "dra": "The more years remain after the jubilee, the more shall the price increase: and the less time is counted, so much the less shall the purchase cost. For he shall sell to thee the time of the fruits.", "bbe": "If the number of years is great, the price will be increased, and if the number of years is small, the price will be less, for it is the produce of a certain number of years which the man is giving you.", "geneva": "According to the multitude of yeeres, thou shalt increase the price thereof, and according to the fewnesse of yeeres, thou shalt abate the price of it: for the nomber of fruites doeth he sell vnto thee.", "wycliffe": "Bi as myche as mo yeeris dwellen after the iubilee, by so myche also the prijs schal encreesse, and bi as myche as thou noumbrist lesse of tyme, bi so myche and the biyng schal cost lesse; for he schal sille to thee the time of fruytis.", "rotherham": "according to the multitude of the years, shalt thou increase the price thereof, and, according to the fewness of the years, shalt thou diminish the price thereof,—because the sum of the increase, it is that he selleth thee.", "darby": "According to the greater number of the years, thou shalt increase the price thereof; and according to the fewness of years, thou shalt diminish the price of it; for it is the number of crops that he selleth unto thee.", "twenty": "", "jps": "According to the multitude of the years thou shalt increase the price thereof, and according to the fewness of the years thou shalt diminish the price of it; for the number of crops doth he sell unto thee.", "acv": "According to the multitude of the years thou shall increase the price of it, and according to the fewness of the years thou shall diminish the price of it, for the number of the crops he sells to thee.", "anderson": "", "haweis": "", "noyes": "", "webster": "According to the multitude of years thou shalt increase the price of it, and according to the fewness of years thou shalt diminish the price of it: for [according] to the number [of the years] of the fruits doth he sell to thee.", "vulgate": "quanto plus anni remanserint post iobeleum tanto crescet et pretium et quanto minus temporis numeraveris tanto minoris et emptio constabit tempus enim frugum vendet tibi;", "brenton": "According as there may be a greater number of years he shall increase the value of his possession, and according as there may be a less number of years he shall lessen the value of his possession; for according to the number of his crops, so shall he sell to thee."}}, {"v": 17, "ref": "25:17", "o": "וְ/לֹ֤א תוֹנוּ֙ אִ֣ישׁ אֶת עֲמִית֔/וֹ וְ/יָרֵ֖אתָ מֵֽ/אֱלֹהֶ֑י/ךָ כִּ֛י אֲנִ֥י יְהֹוָ֖ה אֱלֹהֵי/כֶֽם", "en": {"kjv": "Ye shall not therefore oppress one another; but thou shalt fear thy God: for I am the Lord your God.", "web": "You shall not wrong one another; but you shall fear your God: for I am Yahweh your God.", "bsb": "Do not take advantage of each other, but fear your God; for I am the LORD your God.", "asv": "And ye shall not wrong one another; but thou shalt fear thy God: for I am Jehovah your God.", "ylt": "and ye do not oppress one another, and thou hast been afraid of thy God; for I am Jehovah your God.", "tyndale": "And see that no ma oppresse his neyghboure, but feare thi God. For I am the Lorde youre God.", "dra": "Do not afflict your countrymen: but let every one fear his God. Because I am the Lord your God.", "bbe": "And do no wrong, one to another, but let the fear of your God be before you; for I am the Lord your God.", "geneva": "Oppresse not ye therefore any man his neighbour, but thou shalt feare thy God: for I am the Lord your God.", "wycliffe": "Nyle ye turment men of youre lynagis, but ech man drede his God; for Y am youre Lord God.", "rotherham": "So then ye shall not overreach one another; but thou shalt stand in awe of thy God,—for, I—Yahweh, am your God.", "darby": "And ye shall not oppress one another; but thou shalt fear thyGod; for I am Jehovah yourGod.", "twenty": "", "jps": "And ye shall not wrong one another; but thou shalt fear thy G-d; for I am HaShem your G-d.", "acv": "And ye shall not wrong each other, but thou shall fear thy God, for I am Jehovah your God.", "anderson": "", "haweis": "", "noyes": "", "webster": "Ye shall not therefore oppress one another; but thou shalt fear thy God: for I [am] the LORD your God.", "vulgate": "nolite adfligere contribules vestros sed timeat unusquisque Deum suum quia ego Dominus Deus vester;", "brenton": "Let not a man oppress his neighbour, and thou shalt fear the Lord thy God: I am the Lord thy God."}}, {"v": 18, "ref": "25:18", "o": "וַ/עֲשִׂיתֶם֙ אֶת חֻקֹּתַ֔/י וְ/אֶת מִשְׁפָּטַ֥/י תִּשְׁמְר֖וּ וַ/עֲשִׂיתֶ֣ם אֹתָ֑/ם וִֽ/ישַׁבְתֶּ֥ם עַל הָ/אָ֖רֶץ לָ/בֶֽטַח", "en": {"kjv": "Wherefore ye shall do my statutes, and keep my judgments, and do them; and ye shall dwell in the land in safety.", "web": "“‘Therefore you shall do my statutes, and keep my ordinances and do them; and you shall dwell in the land in safety.", "bsb": "You are to keep My statutes and carefully observe My judgments, so that you may dwell securely in the land.", "asv": "Wherefore ye shall do my statutes, and keep mine ordinances and do them; and ye shall dwell in the land in safety.", "ylt": "`And ye have done My statutes, and My judgments ye keep, and have done them, and ye have dwelt on the land confidently,", "tyndale": "Wherfore do after myne ordinaunces and kepe my lawes ad doo them, that ye maye dwell in the lande in saftie.", "dra": "Do my precepts, and keep my judgments, and fulfil them: that you may dwell in the land without any fear.", "bbe": "So keep my rules and my decisions and do them, and you will be safe in your land.", "geneva": "Wherefore ye shall obey mine ordinances, and keepe my lawes, and do them, and ye shall dwell in the land in safetie.", "wycliffe": "Do ye my comaundementis, and kepe ye my domes, and fille ye tho, that ye moun dwelle in his lond without ony drede,", "rotherham": "Wherefore ye shall do my statutes, and my regulations, shall ye observe and do them,—so shall ye dwell upon the land with confidence;", "darby": "And ye shall do my statutes, and observe mine ordinances and do them: thus shall ye dwell in your land securely.", "twenty": "", "jps": "Wherefore ye shall do My statutes, and keep Mine ordinances and do them; and ye shall dwell in the land in safety.", "acv": "Therefore ye shall do my statutes, and keep my ordinances and do them, and ye shall dwell in the land in safety.", "anderson": "", "haweis": "", "noyes": "", "webster": "Wherefore ye shall do my statutes, and keep my judgments, and do them; and ye shall dwell in the land in safety.", "vulgate": "facite praecepta mea et iudicia custodite et implete ea ut habitare possitis in terra absque ullo pavore;", "brenton": "And ye shall keep all my ordinances, and all my judgments; and do ye observe them, and ye shall keep them, and dwell securely in the land."}}, {"v": 19, "ref": "25:19", "o": "וְ/נָתְנָ֤ה הָ/אָ֨רֶץ֙ פִּרְיָ֔/הּ וַ/אֲכַלְתֶּ֖ם לָ/שֹׂ֑בַע וִֽ/ישַׁבְתֶּ֥ם לָ/בֶ֖טַח עָלֶֽי/הָ", "en": {"kjv": "And the land shall yield her fruit, and ye shall eat your fill, and dwell therein in safety.", "web": "The land shall yield its fruit, and you shall eat your fill, and dwell therein in safety.", "bsb": "Then the land will yield its fruit, so that you can eat your fill and dwell in safety in the land.", "asv": "And the land shall yield its fruit, and ye shall eat your fill, and dwell therein in safety.", "ylt": "and the land hath given its fruit, and ye have eaten to satiety, and have dwelt confidently on it.", "tyndale": "And the lande shall geue her frute, and ye shall eate youre fille and dwell therein in saftie.", "dra": "And the ground may yield you its fruits, of which you may eat your fill, fearing no man's invasion.", "bbe": "And the land will give her fruit, and you will have food in full measure and be safe in the land.", "geneva": "And the lande shall giue her fruite, and ye shall eate your fill, and dwell therein in safetie.", "wycliffe": "and that the erthe brynge forth hise fruytis to you, whiche ye schulen ete `til to fulnesse, and drede not the assailyng of ony man.", "rotherham": "and the land shall yield her fruit; and ye shall eat to the full,—and shall dwell with confidence thereupon.", "darby": "And the land shall yield its fruit, and ye shall eat and be satisfied, and dwell therein securely.", "twenty": "", "jps": "And the land shall yield her fruit, and ye shall eat until ye have enough, and dwell therein in safety.", "acv": "And the land shall yield its fruit, and ye shall eat your fill, and dwell in safety in it.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the land shall yield her fruit, and ye shall eat your fill, and dwell in it in safety.", "vulgate": "et gignat vobis humus fructus suos quibus vescamini usque ad saturitatem nullius impetum formidantes;", "brenton": "And the land shall yield her increase, and ye shall eat to fullness, and shall dwell securely in it."}}, {"v": 20, "ref": "25:20", "o": "וְ/כִ֣י תֹאמְר֔וּ מַה נֹּאכַ֤֖ל בַּ/שָּׁנָ֣ה הַ/שְּׁבִיעִ֑ת הֵ֚ן לֹ֣א נִזְרָ֔ע וְ/לֹ֥א נֶאֱסֹ֖ף אֶת תְּבוּאָתֵֽ/נוּ", "en": {"kjv": "And if ye shall say, What shall we eat the seventh year? behold, we shall not sow, nor gather in our increase:", "web": "If you said, “What shall we eat the seventh year? Behold, we shall not sow, nor gather in our increase”;", "bsb": "Now you may wonder, ‘What will we eat in the seventh year if we do not sow or gather our produce?’", "asv": "And if ye shall say, What shall we eat the seventh year? behold, we shall not sow, nor gather in our increase;", "ylt": "`And when ye say, What do we eat in the seventh year, lo, we do not sow, nor gather our increase?", "tyndale": "Yf ye shall saye, what shall we eate the seuenth yere in as moche as we shall not sowe nor gether in oure encrease.", "dra": "But if you say: What shall we eat the seventh year, if we sow not, nor gather our fruits?", "bbe": "And if you say, Where will our food come from in the seventh year, when we may not put in seed, or get in the increase", "geneva": "And if ye shall say, What shall we eate the seuenth yeere, for we shall not sowe, nor gather in our increase?", "wycliffe": "That if ye seien, what schulen we ete in the seuenthe yeer, if we sowen not, nether gaderen oure fruytis?", "rotherham": "And since ye may say, What shall we eat in the seventh year? Lo! we are not to sow, neither are we to gather our increase!", "darby": "And if ye say, What shall we eat in the seventh year? behold, we may not sow, nor gather in our produce;", "twenty": "", "jps": "And if ye shall say: 'What shall we eat the seventh year? behold, we may not sow, nor gather in our increase';", "acv": "And if ye shall say, What shall we eat the seventh year? Behold, we shall not sow, nor gather in our increase,", "anderson": "", "haweis": "", "noyes": "", "webster": "And if ye shall say, What shall we eat the seventh year? behold, we shall not sow nor gather in our increase:", "vulgate": "quod si dixeritis quid comedemus anno septimo si non seruerimus neque collegerimus fruges nostras;", "brenton": "And if ye should say, What shall we eat in this seventh year, if we do not sow nor gather in our fruits?"}}, {"v": 21, "ref": "25:21", "o": "וְ/צִוִּ֤יתִי אֶת בִּרְכָתִ/י֙ לָ/כֶ֔ם בַּ/שָּׁנָ֖ה הַ/שִּׁשִּׁ֑ית וְ/עָשָׂת֙ אֶת הַ/תְּבוּאָ֔ה לִ/שְׁלֹ֖שׁ הַ/שָּׁנִֽים", "en": {"kjv": "Then I will command my blessing upon you in the sixth year, and it shall bring forth fruit for three years.", "web": "then I will command my blessing on you in the sixth year, and it shall bear fruit for the three years.", "bsb": "But I will send My blessing upon you in the sixth year, so that the land will yield a crop sufficient for three years.", "asv": "then I will command my blessing upon you in the sixth year, and it shall bring forth fruit for the three years.", "ylt": "then I have commanded My blessing on you in the sixth year, and it hath made the increase for three years;", "tyndale": "I wyll sende my blessynge apon you in the sixte yere,", "dra": "I will give you my blessing the sixth year: and it shall yield the fruits of three years.", "bbe": "Then I will send my blessing on you in the sixth year, and the land will give fruit enough for three years.", "geneva": "I will sende my blessing vpon you in the sixt yeere, and it shall bring foorth fruite for three yeeres.", "wycliffe": "Y schal yyue my blessyng to you in the sixte yeer, and it schal make fruytis of three yeer;", "rotherham": "Therefore will I command my blessing upon you, in the sixth year,—and it shall make the increase of three years;", "darby": "then I will command my blessing upon you in the sixth year, that it may bring forth produce for three years;", "twenty": "", "jps": "then I will command My blessing upon you in the sixth year, and it shall bring forth produce for the three years.", "acv": "then I will command my blessing upon you in the sixth year, and it shall bring forth fruit for the three years.", "anderson": "", "haweis": "", "noyes": "", "webster": "Then I will command my blessing upon you in the sixth year, and it shall bring forth fruit for three years.", "vulgate": "dabo benedictionem meam vobis anno sexto et faciet fructus trium annorum;", "brenton": "Then will I send my blessing upon you in the sixth year, and the land shall produce its fruits for three years."}}, {"v": 22, "ref": "25:22", "o": "וּ/זְרַעְתֶּ֗ם אֵ֚ת הַ/שָּׁנָ֣ה הַ/שְּׁמִינִ֔ת וַ/אֲכַלְתֶּ֖ם מִן הַ/תְּבוּאָ֣ה יָשָׁ֑ן עַ֣ד הַ/שָּׁנָ֣ה הַ/תְּשִׁיעִ֗ת עַד בּוֹא֙ תְּב֣וּאָתָ֔/הּ תֹּאכְל֖וּ יָשָֽׁן", "en": {"kjv": "And ye shall sow the eighth year, and eat yet of old fruit until the ninth year; until her fruits come in ye shall eat of the old store.", "web": "You shall sow the eighth year, and eat of the fruits, the old store; until the ninth year, until its fruits come in, you shall eat the old store.", "bsb": "While you are sowing in the eighth year, you will be eating from the previous harvest, until the ninth year’s harvest comes in.", "asv": "And ye shall sow the eighth year, and eat of the fruits, the old store; until the ninth year, until its fruits come in, ye shall eat the old store.", "ylt": "and ye have sown the eighth year, and have eaten of the old increase; until the ninth year, until the coming in of its increase, ye do eat the old.", "tyndale": "and it shall brynge forth frute for thre yeres: and ye shall sowe the eyghte yere and eate of olde frute vntill the .ix. yere, and euen vntyll hir frutes come, ye shall eate of olde stoare.", "dra": "And the eighth year you shall sow, and shall eat of the old fruits, until the ninth year: till new grow up, you shall eat the old store.", "bbe": "And in the eighth year you will put in your seed, and get your food from the old stores, till the fruit of the ninth year is ready.", "geneva": "And ye shall sowe the eight yeere, and eate of the olde fruite vntill the ninth yeere: vntill the fruite thereof come, ye shall eate the olde.", "wycliffe": "and ye schulen sowe in the eiyte yeer, and ye schulen ete elde fruytis `til to the nynthe yeer; til newe thingis comen forth ye schulen ete the elde thingis.", "rotherham": "and ye shall sow, the eighth year, and eat of old store,—until the ninth year until the coming in of the increase thereof, shall ye eat old store.", "darby": "and ye shall sow in the eighth year, and ye shall eat of the old fruit until the ninth year; until her produce come in, ye shall eat the old.", "twenty": "", "jps": "And ye shall sow the eighth year, and eat of the produce, the old store; until the ninth year, until her produce come in, ye shall eat the old store.", "acv": "And ye shall sow the eighth year, and eat of the fruits, the old storage, until the ninth year. Until its fruits come in, ye shall eat the old storage.", "anderson": "", "haweis": "", "noyes": "", "webster": "And ye shall sow the eighth year, and eat of old fruit until the ninth year; until its fruits come in ye shall eat [of] the old [store].", "vulgate": "seretisque anno octavo et comedetis veteres fruges usque ad nonum annum donec nova nascantur edetis vetera;", "brenton": "And ye shall sow in the eighth year, and eat old fruits till the ninth year: until its fruit come, ye shall eat old fruits of the old."}}, {"v": 23, "ref": "25:23", "o": "וְ/הָ/אָ֗רֶץ לֹ֤א תִמָּכֵר֙ לִ/צְמִתֻ֔ת כִּי לִ֖/י הָ/אָ֑רֶץ כִּֽי גֵרִ֧ים וְ/תוֹשָׁבִ֛ים אַתֶּ֖ם עִמָּדִֽ/י", "en": {"kjv": "The land shall not be sold for ever: for the land is mine; for ye are strangers and sojourners with me.", "web": "“‘The land shall not be sold in perpetuity, for the land is mine; for you are strangers and live as foreigners with me.", "bsb": "The land must not be sold permanently, because it is Mine, and you are but foreigners and residents with Me.", "asv": "And the land shall not be sold in perpetuity; for the land is mine: for ye are strangers and sojourners with me.", "ylt": "`And the land is not sold--to extinction, for the land is Mine, for sojourners and settlers are ye with Me;", "tyndale": "Wherfore the londe shall not be solde for euer, because that the lande is myne, and ye but straungers and soiourners with me:", "dra": "The land also shall not be sold for ever: because it is mine, and you are strangers and sojourners with me.", "bbe": "No exchange of land may be for ever, for the land is mine, and you are as my guests, living with me for a time.", "geneva": "Also the lande shall not be solde to be cut off from the familie: for the land is mine, and ye be but strangers and soiourners with me.", "wycliffe": "Also the lond schal not be seeld `in to with outen ende, for it is myn, and ye ben my comelyngis and tenauntis;", "rotherham": "The land moreover shall not be sold beyond recovery, for, mine, is the land,—for, sojourners and settlers, ye are with me.", "darby": "And the land shall not be sold for ever; for the land is mine; for ye are strangers and sojourners with me.", "twenty": "", "jps": "And the land shall not be sold in perpetuity; for the land is Mine; for ye are strangers and settlers with Me.", "acv": "And the land shall not be sold in perpetuity, for the land is mine. For ye are strangers and sojourners with me.", "anderson": "", "haweis": "", "noyes": "", "webster": "The land shall not be sold for ever; for the land [is] mine, for ye [are] strangers and sojourners with me.", "vulgate": "terra quoque non veniet in perpetuum quia mea est et vos advenae et coloni mei estis;", "brenton": "And the land shall not be sold for a permanence; for the land is mine, because ye are strangers and sojourners before me."}}, {"v": 24, "ref": "25:24", "o": "וּ/בְ/כֹ֖ל אֶ֣רֶץ אֲחֻזַּתְ/כֶ֑ם גְּאֻלָּ֖ה תִּתְּנ֥וּ לָ/אָֽרֶץ", "en": {"kjv": "And in all the land of your possession ye shall grant a redemption for the land.", "web": "In all the land of your possession you shall grant a redemption for the land.", "bsb": "Thus for every piece of property you possess, you must provide for the redemption of the land.", "asv": "And in all the land of your possession ye shall grant a redemption for the land.", "ylt": "and in all the land of your possession a redemption ye do give to the land.", "tyndale": "and ye shall thorowe oute all the lande of youre possession, let the londe go home fre agayne.", "dra": "For which cause all the country of your possession shall be under the condition of redemption.", "bbe": "Wherever there is property in land, the owner is to have the right of getting it back.", "geneva": "Therefore in all the land of your possession ye shall graunt a redemption for the lande.", "wycliffe": "wherfor al the cuntre of youre possessioun schal be seeld vndur the condicioun of ayenbiyng.", "rotherham": "And, in all the land of your possession, a right of redemption, shall ye give to the land.", "darby": "And in all the land of your possession ye shall grant a redemption for the land.", "twenty": "", "jps": "And in all the land of your possession ye shall grant a redemption for the land.", "acv": "And in all the land of your possession ye shall grant a redemption for the land.", "anderson": "", "haweis": "", "noyes": "", "webster": "And in all the land of your possession ye shall grant a redemption for the land.", "vulgate": "unde cuncta regio possessionis vestrae sub redemptionis condicione vendetur;", "brenton": "And in every land of your possession, ye shall allow ransoms for the land."}}, {"v": 25, "ref": "25:25", "o": "כִּֽי יָמ֣וּךְ אָחִ֔י/ךָ וּ/מָכַ֖ר מֵ/אֲחֻזָּת֑/וֹ וּ/בָ֤א גֹֽאֲל/וֹ֙ הַ/קָּרֹ֣ב אֵלָ֔י/ו וְ/גָאַ֕ל אֵ֖ת מִמְכַּ֥ר אָחִֽי/ו", "en": {"kjv": "If thy brother be waxen poor, and hath sold away some of his possession, and if any of his kin come to redeem it, then shall he redeem that which his brother sold.", "web": "“‘If your brother becomes poor, and sells some of his possessions, then his kinsman who is next to him shall come, and redeem that which his brother has sold.", "bsb": "If your brother becomes impoverished and sells some of his property, his nearest of kin may come and redeem what his brother has sold.", "asv": "If thy brother be waxed poor, and sell some of his possession, then shall his kinsman that is next unto him come, and shall redeem that which his brother hath sold.", "ylt": "`When thy brother becometh poor, and hath sold his possession, then hath his redeemer who is near unto him come, and he hath redeemed the sold thing of his brother;", "tyndale": "When thy brother is waxed poore and hath solde awaye of his possession: yf any off his kyn come to redeme it, he shall by out that whiche his brother solde.", "dra": "If thy brother being impoverished sell his little possession, and his kinsman will: he may redeem what he had sold.", "bbe": "If your brother becomes poor, and has to give up some of his land for money, his nearest relation may come and get back that which his brother has given up.", "geneva": "If thy brother be impouerished, and sell his possession, then his redeemer shall come, euen his neere kinsman, and bye out that which his brother solde.", "wycliffe": "If thi brother is maad pore, and sillith his litil possessioun, and his nyy kynesman wole, he may ayenbie that that he seelde;", "rotherham": "When thy brother waxeth poor, and so selleth aught of his possession, then may his kinsman that is near unto him come in, and redeem that which was sold by his brother.", "darby": "If thy brother grow poor, and sell of his possession, then shall his redeemer, his nearest relation, come and redeem that which his brother sold.", "twenty": "", "jps": "If thy brother be waxen poor, and sell some of his possession, then shall his kinsman that is next unto him come, and shall redeem that which his brother hath sold.", "acv": "If thy brother becomes poor, and sells some of his possession, then his kinsman who is next to him shall come, and shall redeem that which his brother has sold.", "anderson": "", "haweis": "", "noyes": "", "webster": "If thy brother shall have become poor, and have sold [some] of his possession, and if any of his kin shall come to redeem it, then shall he redeem that which his brother sold.", "vulgate": "si adtenuatus frater tuus vendiderit possessiunculam suam et voluerit propinquus eius potest redimere quod ille vendiderat;", "brenton": "And if thy brother who is with thee be poor, and should have sold part of his possession, and his kinsman who is nigh to him come, then he shall redeem the possession which his brother has sold."}}, {"v": 26, "ref": "25:26", "o": "וְ/אִ֕ישׁ כִּ֛י לֹ֥א יִֽהְיֶה לּ֖/וֹ גֹּאֵ֑ל וְ/הִשִּׂ֣יגָה יָד֔/וֹ וּ/מָצָ֖א כְּ/דֵ֥י גְאֻלָּתֽ/וֹ", "en": {"kjv": "And if the man have none to redeem it, and himself be able to redeem it;", "web": "If a man has no one to redeem it, and he becomes prosperous and finds sufficient means to redeem it;", "bsb": "Or if a man has no one to redeem it for him, but he prospers and acquires enough to redeem his land,", "asv": "And if a man have no one to redeem it, and he be waxed rich and find sufficient to redeem it;", "ylt": "and when a man hath no redeemer, and his own hand hath attained, and he hath found as sufficient for its redemption,", "tyndale": "And though he haue no man to redeme it for him, yet yf hys hande can get sufficyent to bye it oute agayne,", "dra": "But if he have no kinsman, and he himself can find the price to redeem it:", "bbe": "And if he has no one to get it back for him, and later he himself gets wealth and has enough money to get it back;", "geneva": "And if he haue no redeemer, but hath gotten and founde to bye it out,", "wycliffe": "sotheli if he hath no nyy kynesman, and he may fynde prijs to ayenbie,", "rotherham": "And, when, any man, hath no kinsman,—but his own hand getteth enough, so that he findeth what is needed to redeem it,", "darby": "And if the man have no one having right of redemption, and his hand have acquired and found what sufficeth for its redemption,", "twenty": "", "jps": "And if a man have no one to redeem it, and he be waxen rich and find sufficient means to redeem it;", "acv": "And if a man has no one to redeem it, and he becomes rich and finds sufficient to redeem it,", "anderson": "", "haweis": "", "noyes": "", "webster": "And if the man shall have none to redeem it, and himself be able to redeem it;", "vulgate": "sin autem non habuerit proximum et ipse pretium ad redimendum potuerit invenire;", "brenton": "And if one have no near kinsman, and he prosper with his hand, and he find sufficient money, even his ransom;"}}, {"v": 27, "ref": "25:27", "o": "וְ/חִשַּׁב֙ אֶת שְׁנֵ֣י מִמְכָּר֔/וֹ וְ/הֵשִׁיב֙ אֶת הָ֣/עֹדֵ֔ף לָ/אִ֖ישׁ אֲשֶׁ֣ר מָֽכַר ל֑/וֹ וְ/שָׁ֖ב לַ/אֲחֻזָּתֽ/וֹ", "en": {"kjv": "Then let him count the years of the sale thereof, and restore the overplus unto the man to whom he sold it; that he may return unto his possession.", "web": "then let him reckon the years since its sale, and restore the surplus to the man to whom he sold it; and he shall return to his property.", "bsb": "he shall calculate the years since its sale, repay the balance to the man to whom he sold it, and return to his property.", "asv": "then let him reckon the years of the sale thereof, and restore the overplus unto the man to whom he sold it; and he shall return unto his possession.", "ylt": "then he hath reckoned the years of its sale, and hath given back that which is over to the man to whom he sold it , and he hath returned to his possession.", "tyndale": "then let him counte how longe it hath bene solde, and delyuer the rest vnto him to whome he solde it, ad so he shall returne vnto his possession agayne.", "dra": "The value of the fruits shall be counted from that time when he sold it. And the overplus he shall restore to the buyer, and so shall receive his possession again.", "bbe": "Then let him take into account the years from the time when he gave it up, and make up the loss for the rest of the years to him who took it, and so get back his property.", "geneva": "Then shall he count the yeeres of his sale, and restore the ouerplus to the man, to whome he solde it: so shall he returne to his possession.", "wycliffe": "the fruytis schulen be rekynyd fro that tyme in which he seelde, and he schal yelde `that that is residue to the biere, and he schal resseyue so his possessioun.", "rotherham": "then shall he reckon the years since he sold it, and restore the overplus to the man to whom he sold it,—and shall return to his possession.", "darby": "then shall he reckon the years since the sale thereof, and restore the overplus unto the man to whom he sold it; and so return unto his possession.", "twenty": "", "jps": "then let him count the years of the sale thereof, and restore the overplus unto the man to whom he sold it; and he shall return unto his possession.", "acv": "then let him reckon the years of the sale of it, and restore the excess to the man to whom he sold it, and he shall return to his possession.", "anderson": "", "haweis": "", "noyes": "", "webster": "Then let him count the years of the sale of it, and restore the overplus to the man to whom he sold it; that he may return to his possession.", "vulgate": "conputabuntur fructus ex eo tempore quo vendidit et quod reliquum est reddet emptori sicque recipiet possessionem suam;", "brenton": "then shall he calculate the years of his sale, and he shall give what is due to the man to whom he sold it, and he shall return to his possession."}}, {"v": 28, "ref": "25:28", "o": "וְ/אִ֨ם לֹֽא מָֽצְאָ֜ה יָד֗/וֹ דֵּי֮ הָשִׁ֣יב ל/וֹ֒ וְ/הָיָ֣ה מִמְכָּר֗/וֹ בְּ/יַד֙ הַ/קֹּנֶ֣ה אֹת֔/וֹ עַ֖ד שְׁנַ֣ת הַ/יּוֹבֵ֑ל וְ/יָצָא֙ בַּ/יֹּבֵ֔ל וְ/שָׁ֖ב לַ/אֲחֻזָּתֽ/וֹ", "en": {"kjv": "But if he be not able to restore it to him, then that which is sold shall remain in the hand of him that hath bought it until the year of jubile: and in the jubile it shall go out, and he shall return unto his possession.", "web": "But if he isn’t able to get it back for himself, then what he has sold shall remain in the hand of him who has bought it until the Year of Jubilee: and in the Jubilee it shall be released, and he shall return to his property.", "bsb": "But if he cannot obtain enough to repay him, what he sold will remain in possession of the buyer until the Year of Jubilee. In the Jubilee, however, it is to be released, so that he may return to his property.", "asv": "But if he be not able to get it back for himself, then that which he hath sold shall remain in the hand of him that hath bought it until the year of jubilee: and in the jubilee it shall go out, and he shall return unto his possession.", "ylt": "`And if his hand hath not found sufficiency to give back to him, then hath his sold thing been in the hand of him who buyeth it till the year of jubilee; and it hath gone out in the jubilee, and he hath returned to his possession.", "tyndale": "But and yf his hande ca not get sufficiet to restore it to him agayne, then that whiche is solde shall remayne in the hande of him that hath boughte it, vntyll the horneyere: and in the horne yere it shall come out, and he shall returne vnto his possession agayne.", "dra": "But if his hands find not the means to repay the price, the buyer shall have what he bought, until the year of the jubilee. For in that year all that is sold shall return to the owner, and to the ancient possessor.", "bbe": "But if he is not able to get it back for himself, then it will be kept by him who gave a price for it, till the year of Jubilee; and in that year it will go back to its first owner and he will have his property again.", "geneva": "But if he can not get sufficient to restore to him, then that which is solde, shall remaine in the hande of him that hath bought it, vntill the yere of the Iubile: and in the Iubile it shall come out, and he shall returne vnto his possession.", "wycliffe": "That if his hond fynde not, that he yelde the prijs, the biere schal haue that that he bouyte, `til to the yeer of iubilee; for in that yeer ech sillyng schal go ayen to the lord, and to the firste weldere.", "rotherham": "But, if his hand have not found enough to get it back unto him, then shall that which he sold remain in the hand of him that bought it, until the year of the jubilee,—and shall go out in the jubilee, and he shall return unto his possession.", "darby": "And if his hand have not found what sufficeth for him to restore it to him, then that which is sold shall remain in the hand of the purchaser, until the year of jubilee; and in the jubilee it shall go out, and he shall return unto his possession.", "twenty": "", "jps": "But if he have not sufficient means to get it back for himself, then that which he hath sold shall remain in the hand of him that hath bought it until the year of jubilee; and in the jubilee it shall go out, and he shall return unto his possession.", "acv": "But if he is not able to get it back for himself, then that which he has sold shall remain in the hand of him who has bought it until the year of jubilee. And in the jubilee it shall go out, and he shall return to his possession.", "anderson": "", "haweis": "", "noyes": "", "webster": "But if he shall not be able to restore [it] to him, then that which is sold shall remain in the hand of him that hath bought it until the year of jubilee: and in the jubilee it shall go out, and he shall return to his possession.", "vulgate": "quod si non invenerit manus eius ut reddat pretium habebit emptor quod emerat usque ad annum iobeleum in ipso enim omnis venditio redit ad dominum et ad possessorem pristinum;", "brenton": "But if his hand have not prospered sufficiently, so as that he should restore the money to him, then he that bought the possessions shall have them till the sixth year of the release; and it shall go out in the release, and the owner shall return to his possession."}}, {"v": 29, "ref": "25:29", "o": "וְ/אִ֗ישׁ כִּֽי יִמְכֹּ֤ר בֵּית מוֹשַׁב֙ עִ֣יר חוֹמָ֔ה וְ/הָיְתָה֙ גְּאֻלָּת֔/וֹ עַד תֹּ֖ם שְׁנַ֣ת מִמְכָּר֑/וֹ יָמִ֖ים תִּהְיֶ֥ה גְאֻלָּתֽ/וֹ", "en": {"kjv": "And if a man sell a dwelling house in a walled city, then he may redeem it within a whole year after it is sold; within a full year may he redeem it.", "web": "“‘If a man sells a dwelling house in a walled city, then he may redeem it within a whole year after it has been sold. For a full year he shall have the right of redemption.", "bsb": "If a man sells a house in a walled city, he retains his right of redemption until a full year after its sale; during that year it may be redeemed.", "asv": "And if a man sell a dwelling-house in a walled city, then he may redeem it within a whole year after it is sold; for a full year shall he have the right of redemption.", "ylt": "`And when a man selleth a dwelling-house in a walled city, then hath his right of redemption been until the completion of a year from its selling; days--is his right of redemption;", "tyndale": "Yf a man sell a dwellynge house in a walled cytie he maye bye it out agayne any tyme withi a hole yere after it is solde: and that shalbe the space in which he maye redeme it agayne.", "dra": "He that selleth a house within the walls of a city, shall have the liberty to redeem it, until one year be expired.", "bbe": "And if a man gives his house in a walled town for money, he has the right to get it back for the space of a full year after he has given it up.", "geneva": "Likewise if a man sell a dwelling house in a walled citie, he may bye it out againe within a whole yeere after it is solde: within a yeere may he bye it out.", "wycliffe": "He that sillith his hows, with ynne the wallis of a citee, schal haue licence to ayenbie til o yeer be fillid;", "rotherham": "And, when, any man, selleth a dwelling-house in a walled city, then shall his right of redemption remain until the completion of a year after he sold it,—for, [a year of] days, shall his right of redemption remain.", "darby": "And if any one sell a dwelling-house in a walled city, then he shall have the right of redemption up to the end of the year of the sale thereof; for a full year shall he have the right of redemption.", "twenty": "", "jps": "And if a man sell a dwelling-house in a walled city, then he may redeem it within a whole year after it is sold; for a full year shall he have the right of redemption.", "acv": "And if a man sells a dwelling-house in a walled city, then he may redeem it within a whole year after it is sold. For a full year he shall have the right of redemption.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if a man shall sell a dwelling-house in a walled city, then he may redeem it within a whole year after it is sold: [within] a full year may he redeem it.", "vulgate": "qui vendiderit domum intra urbis muros habebit licentiam redimendi donec unus impleatur annus;", "brenton": "And if any one should sell an inhabited house in a walled city, then there shall be the ransom of it, until the time is fulfilled: its time of ransom shall be a full year."}}, {"v": 30, "ref": "25:30", "o": "וְ/אִ֣ם לֹֽא יִגָּאֵ֗ל עַד מְלֹ֣את ל/וֹ֮ שָׁנָ֣ה תְמִימָה֒ וְ֠/קָם הַ/בַּ֨יִת אֲשֶׁר בָּ/עִ֜יר אֲשֶׁר לא ל֣/וֹ חֹמָ֗ה לַ/צְּמִיתֻ֛ת לַ/קֹּנֶ֥ה אֹת֖/וֹ לְ/דֹרֹתָ֑י/ו לֹ֥א יֵצֵ֖א בַּ/יֹּבֵֽל", "en": {"kjv": "And if it be not redeemed within the space of a full year, then the house that is in the walled city shall be established for ever to him that bought it throughout his generations: it shall not go out in the jubile.", "web": "If it isn’t redeemed within the space of a full year, then the house that is in the walled city shall be made sure in perpetuity to him who bought it, throughout his generations. It shall not be released in the Jubilee.", "bsb": "If it is not redeemed by the end of a full year, then the house in the walled city is permanently transferred to its buyer and his descendants. It is not to be released in the Jubilee.", "asv": "And if it be not redeemed within the space of a full year, then the house that is in the walled city shall be made sure in perpetuity to him that bought it, throughout his generations: it shall not go out in the jubilee.", "ylt": "and if it is not redeemed until the fulness to him of a perfect year, then hath the house which is in a walled city been established to extinction to the buyer of it, to his generations; it goeth not out in the jubilee;", "tyndale": "But and yf it be not bought out agayne within the space of a full yere then the housse in the walled cytie shalbe stablished for euer vnto him that boughte it and to his successoures after hi and shall not goo out in the trompet yere.", "dra": "If he redeem it not, and the whole year be fully out, the buyer shall possess it, and his posterity for ever, and it cannot be redeemed, not even in the jubilee.", "bbe": "And if he does not get it back by the end of the year, then the house in the town will become the property of him who gave the money for it, and of his children for ever; it will not go from him in the year of Jubilee.", "geneva": "But if it be not bought out within ye space of a ful yeere, then the house that is in the walled citie, shalbe stablished, as cut off from the familie, to him that bought it, throughout his generations: it shall not goe out in the Iubile.", "wycliffe": "if he ayenbieth not, and the sercle of the yeer is passid, the biere schal welde it, and his eiris `in to with outen ende, and it schal not mow be ayenbouyt, ye, in the iubilee.", "rotherham": "But, if it be not redeemed before the end of a full year, then shall the house that is in the city that hath walls be confirmed, beyond recovery, to him who bought it, unto his generations,—it shall not go out in the jubilee.", "darby": "But if it be not redeemed until a whole year is complete, then the house that is in the walled city shall be established for ever to him that bought it, throughout his generations: it shall not go out in the jubilee.", "twenty": "", "jps": "And if it be not redeemed within the space of a full year, then the house that is in the walled city shall be made sure in perpetuity to him that bought it, throughout his generations; it shall not go out in the jubilee.", "acv": "And if it be not redeemed within the space of a full year, then the house that is in the walled city shall be made sure in perpetuity to him who bought it, throughout his generations. It shall not go out in the jubilee.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if it shall not be redeemed within the space of a full year, then the house that [is] in the walled city shall be established for ever to him that bought it, throughout his generations: it shall not go out in the jubilee,", "vulgate": "si non redemerit et anni circulus fuerit evolutus emptor possidebit eam et posteri eius in perpetuum et redimi non poterit etiam in iobeleo;", "brenton": "And if it be not ransomed until there be completed of its time a full year, the house which is in the walled city shall be surely confirmed to him that bought it, throughout his generations; and it shall not go out in the release."}}, {"v": 31, "ref": "25:31", "o": "וּ/בָתֵּ֣י הַ/חֲצֵרִ֗ים אֲשֶׁ֨ר אֵין לָ/הֶ֤ם חֹמָה֙ סָבִ֔יב עַל שְׂדֵ֥ה הָ/אָ֖רֶץ יֵחָשֵׁ֑ב גְּאֻלָּה֙ תִּהְיֶה לּ֔/וֹ וּ/בַ/יֹּבֵ֖ל יֵצֵֽא", "en": {"kjv": "But the houses of the villages which have no wall round about them shall be counted as the fields of the country: they may be redeemed, and they shall go out in the jubile.", "web": "But the houses of the villages which have no wall around them shall be reckoned with the fields of the country: they may be redeemed, and they shall be released in the Jubilee.", "bsb": "But houses in villages with no walls around them are to be considered as open fields. They may be redeemed, and they shall be released in the Jubilee.", "asv": "But the houses of the villages which have no wall round about them shall be reckoned with the fields of the country: they may be redeemed, and they shall go out in the jubilee.", "ylt": "and a house of the villages which have no wall round about, on the field of the country is reckoned; redemption is to it, and in the jubilee it goeth out.", "tyndale": "But the housses in villagies which haue no walles rounde aboute them shalbe counted like vnto the feldes of the cuntre and maye be boughte out agayne at any season and shall goo out fre in the trompett yere.", "dra": "But if the house be in a village, that hath no walls, it shall be sold according to the same law as the fields. If it be not redeemed before, in the jubilee it shall return to the owner.", "bbe": "But houses in small unwalled towns will be the same as property in the country; they may be got back, and they will go back to their owners in the year of Jubilee.", "geneva": "But the houses of villages, which haue no walles round about them, shalbe esteemed as the fielde of the countrey: they may be bought out againe, and shall goe out in the Iubile.", "wycliffe": "Forsothe if the hows is in a town `that hath not wallis, it schal be seeld bi the lawe of feeldis; sotheli if it is not ayenbouyt in the iubilee, it schal turne ayen to `his lord.", "rotherham": "But as for the houses of villages which have no wall round about them, with the fields of land, shall it be reckoned,—a right of redemption, shall belong to it, and, in the jubilee, shall it go out.", "darby": "But the houses in villages that have no wall round about them shall be reckoned as the fields of the country: they may be redeemed, and they shall go out in the jubilee.", "twenty": "", "jps": "But the houses of the villages which have no wall round about them shall be reckoned with the fields of the country; they may be redeemed, and they shall go out in the jubilee.", "acv": "But the houses of the villages which have no wall round about them shall be reckoned with the fields of the country. They may be redeemed, and they shall go out in the jubilee.", "anderson": "", "haweis": "", "noyes": "", "webster": "But the houses of the villages which have no walls around them, shall be counted as the fields of the country: they may be redeemed, and they shall go out in the jubilee.", "vulgate": "sin autem in villa fuerit domus quae muros non habet agrorum iure vendetur si ante redempta non fuerit in iobeleo revertetur ad dominum;", "brenton": "But the houses in the villages which have not a wall round about them, shall be reckoned as the fields of the country: they shall always be redeemable, and they shall go out in the release."}}, {"v": 32, "ref": "25:32", "o": "וְ/עָרֵי֙ הַ/לְוִיִּ֔ם בָּתֵּ֖י עָרֵ֣י אֲחֻזָּתָ֑/ם גְּאֻלַּ֥ת עוֹלָ֖ם תִּהְיֶ֥ה לַ/לְוִיִּֽם", "en": {"kjv": "Notwithstanding the cities of the Levites, and the houses of the cities of their possession, may the Levites redeem at any time.", "web": "“‘Nevertheless the cities of the Levites, the houses in the cities of their possession, the Levites may redeem at any time.", "bsb": "As for the cities of the Levites, the Levites always have the right to redeem their houses in the cities they possess.", "asv": "Nevertheless the cities of the Levites, the houses of the cities of their possession, may the Levites redeem at any time.", "ylt": "`As to cities of the Levites--houses of the cities of their possession--redemption age-during is to the Levites;", "tyndale": "Notwithstondynge the cityes of the leuytes and the housses in the cyties of their possessios the leuites maye redeme at all ceasons.", "dra": "The houses of Levites, which are in cities, may always be redeemed.", "bbe": "But the houses in the towns of the Levites may be got back by the Levites at any time.", "geneva": "Notwithstanding, the cities of the Leuites, and the houses of the cities of their possession, may the Leuites redeeme at all seasons.", "wycliffe": "The howsis of dekenes, that ben in citees, moun euer be ayenbouyt; if tho ben not ayenbouyt,", "rotherham": "And as for the cities of the Levites, the houses of the cities of their possession, an age-abiding right of redemption, shall pertain unto the Levites.", "darby": "But as to the cities of the Levites, the houses in the cities of their possession, the Levites shall have a perpetual right of redemption.", "twenty": "", "jps": "But as for the cities of the Levites, the houses of the cities of their possession, the Levites shall have a perpetual right of redemption.", "acv": "Nevertheless the cities of the Levites, the houses of the cities of their possession, the Levites may redeem at any time.", "anderson": "", "haweis": "", "noyes": "", "webster": "Notwithstanding the cities of the Levites, [and] the houses of the cities of their possession, may the Levites redeem at any time.", "vulgate": "aedes Levitarum quae in urbibus sunt semper possunt redimi;", "brenton": "And the cities of the Levites, the houses of the cities in their possession, shall be always redeemable to the Levites."}}, {"v": 33, "ref": "25:33", "o": "וַ/אֲשֶׁ֤ר יִגְאַל֙ מִן הַ/לְוִיִּ֔ם וְ/יָצָ֧א מִמְכַּר בַּ֛יִת וְ/עִ֥יר אֲחֻזָּת֖/וֹ בַּ/יֹּבֵ֑ל כִּ֣י בָתֵּ֞י עָרֵ֣י הַ/לְוִיִּ֗ם הִ֚וא אֲחֻזָּתָ֔/ם בְּ/ת֖וֹךְ בְּנֵ֥י יִשְׂרָאֵֽל", "en": {"kjv": "And if a man purchase of the Levites, then the house that was sold, and the city of his possession, shall go out in the year of jubile: for the houses of the cities of the Levites are their possession among the children of Israel.", "web": "The Levites may redeem the house that was sold, and the city of his possession, and it shall be released in the Jubilee; for the houses of the cities of the Levites are their possession among the children of Israel.", "bsb": "So whatever belongs to the Levites may be redeemed—a house sold in a city they possess—and must be released in the Jubilee, because the houses in the cities of the Levites are their possession among the Israelites.", "asv": "And if one of the Levites redeem, then the house that was sold, and the city of his possession, shall go out in the jubilee; for the houses of the cities of the Levites are their possession among the children of Israel.", "ylt": "as to him who redeemeth from the Levites, both the sale of a house and the city of his possession have gone out in the jubilee, for the houses of the cities of the Levites are their possession in the midst of the sons of Israel.", "tyndale": "And yf a man purchace ought of the leuytes: whether it be house or citie that they possesse, the bargayne shall goo out in the tropet yere. for the housses of the cyties of the leuites are their possessions amonge the childern of Israel.", "dra": "If they be not redeemed, in the jubilee they shall all return to the owners: because the houses of the cities of the Levites are for their possessions among the children of Israel.", "bbe": "And if a Levite does not give money to get back his property, his house in the town which was exchanged for money will come back to him in the year of Jubilee. For the houses of the towns of the Levites are their property among the children of Israel.", "geneva": "And if a man purchase of the Leuites, the house that was solde, and the citie of their possession shall goe out in the Iubile: for the houses of the cities of the Leuites are their possession among the children of Israel.", "wycliffe": "tho schulen turne ayen in the iubilee `to the lordis; for the `howsis of the citees of dekenes ben for possessiouns among the sones of Israel;", "rotherham": "And, if one of the Levites should not redeem, then shall the sale of the house and the city of his possession go out in the jubilee; for, the houses of the cities of the Levites are their possession, in the midst of the sons of Israel.", "darby": "And if any one redeem from one of the Levites, then the house that was sold, in the city of his possession, shall go out in the jubilee; for the houses of the cities of the Levites are their possession among the children of Israel.", "twenty": "", "jps": "And if a man purchase of the Levites, then the house that was sold in the city of his possession, shall go out in the jubilee; for the houses of the cities of the Levites are their possession among the children of Israel.", "acv": "And if a man purchases from the Levites, then the house that was sold, and the city of his possession, shall go out in the jubilee. For the houses of the cities of the Levites are their possession among the sons of Israel.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if a man shall purchase of the Levites, then the house that was sold, and the city of his possession shall go out in the [year of] jubilee; for the houses of the cities of the Levites [are] their possession among the children of Israel.", "vulgate": "si redemptae non fuerint in iobeleo revertentur ad dominos quia domus urbium leviticarum pro possessionibus sunt inter filios Israhel;", "brenton": "And if any one shall redeem a house of the Levites, then shall their sale of the houses of their possession go out in the release; because the houses of the cities of the Levites are their possession in the midst of the children of Israel."}}, {"v": 34, "ref": "25:34", "o": "וּֽ/שְׂדֵ֛ה מִגְרַ֥שׁ עָרֵי/הֶ֖ם לֹ֣א יִמָּכֵ֑ר כִּֽי אֲחֻזַּ֥ת עוֹלָ֛ם ה֖וּא לָ/הֶֽם", "en": {"kjv": "But the field of the suburbs of their cities may not be sold; for it is their perpetual possession.", "web": "But the field of the suburbs of their cities may not be sold; for it is their perpetual possession.", "bsb": "But the open pastureland around their cities may not be sold, for this is their permanent possession.", "asv": "But the field of the suburbs of their cities may not be sold; for it is their perpetual possession.", "ylt": "And a field, a suburb of their cities, is not sold; for a possession age-during it is to them.", "tyndale": "But the feldes that lye rounde aboute their cyties shall not be bought: for they are their possessions for euer.", "dra": "But let not their suburbs be sold, because it is a perpetual possession.", "bbe": "But the land on the outskirts of their towns may not be exchanged for money, for it is their property for ever.", "geneva": "But the fielde of the suburbes of their cities, shall not be solde: for it is their perpetuall possession.", "wycliffe": "forsothe the suburbabis of hem schulen not be seeld, for it is euerlastynge possessioun.", "rotherham": "But the field of the pasture-land of their cities, shall not be sold,—for an age-abiding possession, it is unto them.", "darby": "And the field of the suburbs of their cities shall not be sold; for it is their perpetual possession.", "twenty": "", "jps": "But the fields of the open land about their cities may not be sold; for that is their perpetual possession.", "acv": "But the field of the suburbs of their cities may not be sold, for it is their perpetual possession.", "anderson": "", "haweis": "", "noyes": "", "webster": "But the field of the suburbs of their cities may not be sold, for it [is] their perpetual possession.", "vulgate": "suburbana autem eorum non venient quia possessio sempiterna est;", "brenton": "And the lands set apart for their cities shall not be sold, because this is their perpetual possession."}}, {"v": 35, "ref": "25:35", "o": "וְ/כִֽי יָמ֣וּךְ אָחִ֔י/ךָ וּ/מָ֥טָה יָד֖/וֹ עִמָּ֑/ךְ וְ/הֶֽחֱזַ֣קְתָּ בּ֔/וֹ גֵּ֧ר וְ/תוֹשָׁ֛ב וָ/חַ֖י עִמָּֽ/ךְ", "en": {"kjv": "And if thy brother be waxen poor, and fallen in decay with thee; then thou shalt relieve him: yea, though he be a stranger, or a sojourner; that he may live with thee.", "web": "“‘If your brother has become poor, and his hand can’t support himself among you; then you shall uphold him. He shall live with you like an alien and a temporary resident.", "bsb": "Now if your countryman becomes destitute and cannot support himself among you, then you are to help him as you would a foreigner or stranger, so that he can continue to live among you.", "asv": "And if thy brother be waxed poor, and his hand fail with thee; then thou shalt uphold him: as a stranger and a sojourner shall he live with thee.", "ylt": "`And when thy brother is become poor, and his hand hath failed with thee, then thou hast kept hold on him, sojourner and settler, and he hath lived with thee;", "tyndale": "Yf thi brother be waxed poore and falle in decaye with the receaue him as a straunger or a soiourner and let him lyue by the.", "dra": "If thy brother be impoverished, and weak of hand, and thou receive him as a stranger and sojourner, and he live with thee:", "bbe": "And if your brother becomes poor and is not able to make a living, then you are to keep him with you, helping him as you would a man from another country who is living among you.", "geneva": "Moreouer, if thy brother be impouerished, and fallen in decay with thee, thou shalt relieue him, and as a stranger and soiourner, so shall he liue with thee.", "wycliffe": "If thi brother is maad pore, and feble in power, and thou resseyuest hym as a comelyng and pilgrym, and he lyueth with thee,", "rotherham": "And, when thy brother waxeth poor, and his hand becometh feeble with thee, then shalt thou strengthen him, as a sojourner and a settler, so shall he live with thee.", "darby": "And if thy brother grow poor, and he be fallen into decay beside thee, then thou shalt relieve him, [be he] stranger or sojourner, that he may live beside thee.", "twenty": "", "jps": "And if thy brother be waxen poor, and his means fail with thee; then thou shalt uphold him: as a stranger and a settler shall he live with thee.", "acv": "And if thy brother becomes poor, and his hand fails with thee, then thou shall uphold him; he shall live with thee as a stranger and a sojourner.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if thy brother shall have become poor, and fallen in decay with thee; then thou shalt relieve him: [yea, though he] may [be] a stranger, or a sojourner; that he may live with thee.", "vulgate": "si adtenuatus fuerit frater tuus et infirmus manu et susceperis eum quasi advenam et peregrinum et vixerit tecum;", "brenton": "And if thy brother who is with thee become poor, and he fail in resources with thee, thou shalt help him as a stranger and a sojourner, and thy brother shall live with thee."}}, {"v": 36, "ref": "25:36", "o": "אַל תִּקַּ֤ח מֵֽ/אִתּ/וֹ֙ נֶ֣שֶׁךְ וְ/תַרְבִּ֔ית וְ/יָרֵ֖אתָ מֵֽ/אֱלֹהֶ֑י/ךָ וְ/חֵ֥י אָחִ֖י/ךָ עִמָּֽ/ךְ", "en": {"kjv": "Take thou no usury of him, or increase: but fear thy God; that thy brother may live with thee.", "web": "Take no interest from him or profit, but fear your God; that your brother may live among you.", "bsb": "Do not take any interest or profit from him, but fear your God, that your countryman may live among you.", "asv": "Take thou no interest of him or increase, but fear thy God; that thy brother may live with thee.", "ylt": "thou takest no usury from him, or increase; and thou hast been afraid of thy God; and thy brother hath lived with thee;", "tyndale": "And thou shalt take none vsurye of him nor yet vantage. But shalt feare thi God that thi brother maye lyue with the.", "dra": "Take not usury of him nor more than thou gavest. Fear thy God, that thy brother may live with thee.", "bbe": "Take no interest from him, in money or in goods, but have the fear of your God before you, and let your brother make a living among you.", "geneva": "Thou shalt take no vsurie of him, nor vantage, but thou shalt feare thy God, that thy brother may liue with thee.", "wycliffe": "take thou not vsuris of hym, nether more than thou hast youe; drede thou thi God, that thi brothir mai lyue anentis thee.", "rotherham": "Do not accept from him interest or profit, but stand thou in awe of thy God,—so shall thy brother live with thee.", "darby": "Thou shalt take no usury nor increase of him; and thou shalt fear thyGod; that thy brother may live beside thee.", "twenty": "", "jps": "Take thou no interest of him or increase; but fear thy G-d; that thy brother may live with thee.", "acv": "Take thou no interest from him or increase, but fear thy God, that thy brother may live with thee.", "anderson": "", "haweis": "", "noyes": "", "webster": "Take thou no interest of him, or increase; but fear thy God; that thy brother may live with thee.", "vulgate": "ne accipias usuras ab eo nec amplius quam dedisti time Deum tuum ut vivere possit frater tuus apud te;", "brenton": "Thou shalt not receive from him interest, nor increase: and thou shalt fear thy God: I am the Lord: and thy brother shall live with thee."}}, {"v": 37, "ref": "25:37", "o": "אֶ֨ת כַּסְפְּ/ךָ֔ לֹֽא תִתֵּ֥ן ל֖/וֹ בְּ/נֶ֑שֶׁךְ וּ/בְ/מַרְבִּ֖ית לֹא תִתֵּ֥ן אָכְלֶֽ/ךָ", "en": {"kjv": "Thou shalt not give him thy money upon usury, nor lend him thy victuals for increase.", "web": "You shall not lend him your money at interest, nor give him your food for profit.", "bsb": "You must not lend him your silver at interest or sell him your food for profit.", "asv": "Thou shalt not give him thy money upon interest, nor give him thy victuals for increase.", "ylt": "thy money thou givest not to him in usury, and for increase thou givest not thy food;", "tyndale": "Thou shalt not lende him thi money apon vsurye nor lende him of thi fode to haue avantage by it for", "dra": "Thou shalt not give him thy money upon usury: nor exact of him any increase of fruits.", "bbe": "Do not take interest on the money which you let him have or on the food which you give him.", "geneva": "Thou shalt not giue him thy money to vsurie, nor lende him thy vitailes for increase.", "wycliffe": "Thou schalt not yyue to hym thi money to vsure, and thou schalt not axe ouer `aboundaunce, ether encrees ouer of fruytis;", "rotherham": "Thy silver, shalt thou not give him on interest,—neither, for profit, shalt thou give him thy food.", "darby": "Thy money shalt thou not give him upon usury, nor lend him thy victuals for increase.", "twenty": "", "jps": "Thou shalt not give him thy money upon interest, nor give him thy victuals for increase.", "acv": "Thou shall not give him thy money upon interest, nor give him thy food for profit.", "anderson": "", "haweis": "", "noyes": "", "webster": "Thou shalt not give him thy money upon interest, nor lend him thy victuals for increase.", "vulgate": "pecuniam tuam non dabis ei ad usuram et frugum superabundantiam non exiges;", "brenton": "Thou shalt not lend thy money to him at interest, and thou shalt not lend thy meat to him to be returned with increase."}}, {"v": 38, "ref": "25:38", "o": "אֲנִ֗י יְהוָה֙ אֱלֹ֣הֵי/כֶ֔ם אֲשֶׁר הוֹצֵ֥אתִי אֶתְ/כֶ֖ם מֵ/אֶ֣רֶץ מִצְרָ֑יִם לָ/תֵ֤ת לָ/כֶם֙ אֶת אֶ֣רֶץ כְּנַ֔עַן לִ/הְי֥וֹת לָ/כֶ֖ם לֵ/אלֹהִֽים", "en": {"kjv": "I am the Lord your God, which brought you forth out of the land of Egypt, to give you the land of Canaan, and to be your God.", "web": "I am Yahweh your God, who brought you out of the land of Egypt, to give you the land of Canaan, and to be your God.", "bsb": "I am the LORD your God, who brought you out of the land of Egypt to give you the land of Canaan and to be your God.", "asv": "I am Jehovah your God, who brought you forth out of the land of Egypt, to give you the land of Canaan, and to be your God.", "ylt": "I am Jehovah your God, who hath brought you out of the land of Egypt, to give to you the land of Canaan, to become your God.", "tyndale": "I am the Lorde youre God which broughte you out of the lande of Egipte, to geue you the lande of Canaan and to be youre God.", "dra": "I am the Lord your God, who brought you out of the land of Egypt, that I might give you the land of Chanaan, and might be your God.", "bbe": "I am the Lord your God, who took you out of the land of Egypt to give you the land of Canaan, that I might be your God.", "geneva": "I am the Lord your God, which haue brought you out of the lande of Egypt, to giue you the lande of Canaan, and to be your God.", "wycliffe": "Y am youre Lord God, that ladde you out of the lond of Egipt, that Y schulde yyue to you the lond of Canaan, and that Y schulde be youre God.", "rotherham": "I—Yahweh, am your God, who brought you forth out of the land of Egypt,—to give unto you the land of Canaan, to become your God,", "darby": "I am Jehovah yourGod, who brought you forth out of the land of Egypt, to give you the land of Canaan, to be yourGod.", "twenty": "", "jps": "I am HaShem your G-d, who brought you forth out of the land of Egypt, to give you the land of Canaan, to be your G-d.", "acv": "I am Jehovah your God, who brought you forth out of the land of Egypt, to give you the land of Canaan, and to be your God.", "anderson": "", "haweis": "", "noyes": "", "webster": "I [am] the LORD your God, who brought you out of the land of Egypt, to give you the land of Canaan, [and] to be your God.", "vulgate": "ego Dominus Deus vester qui eduxi vos de terra Aegypti ut darem vobis terram Chanaan et essem vester Deus;", "brenton": "I am the Lord your God, who brought you out of the land of Egypt, to give you the land of Chanaan, so as to be your God."}}, {"v": 39, "ref": "25:39", "o": "וְ/כִֽי יָמ֥וּךְ אָחִ֛י/ךָ עִמָּ֖/ךְ וְ/נִמְכַּר לָ֑/ךְ לֹא תַעֲבֹ֥ד בּ֖/וֹ עֲבֹ֥דַת עָֽבֶד", "en": {"kjv": "And if thy brother that dwelleth by thee be waxen poor, and be sold unto thee; thou shalt not compel him to serve as a bondservant:", "web": "“‘If your brother has grown poor among you, and sells himself to you; you shall not make him to serve as a slave.", "bsb": "If a countryman among you becomes destitute and sells himself to you, then you must not force him into slave labor.", "asv": "And if thy brother be waxed poor with thee, and sell himself unto thee; thou shalt not make him to serve as a bondservant.", "ylt": "`And when thy brother becometh poor with thee, and he hath been sold to thee, thou dost not lay on him servile service;", "tyndale": "Yf thi brother that dwelleth by the waxe poore and sell him selfe vnto the thou shalt not let him laboure as a bondseruaunte doeth:", "dra": "If thy brother constrained by poverty, sell himself to thee: thou shalt not oppress him with the service of bondservants.", "bbe": "And if your brother becomes poor and gives himself to you for money, do not make use of him like a servant who is your property;", "geneva": "If thy brother also that dwelleth by thee, be impouerished, and be sold vnto thee, thou shalt not compel him to serue as a bond seruant,", "wycliffe": "If thi brother compellid bi pouert sillith hym silf to thee, thou schalt not oppresse hym bi seruage of seruauntis,", "rotherham": "And when thy brother waxeth poor with thee, and so selleth himself unto thee, thou shalt not bind him with the bondage of a bondman:", "darby": "And if thy brother grow poor beside thee, and be sold unto thee, thou shalt not compel him to serve as a bondservant:", "twenty": "", "jps": "And if thy brother be waxen poor with thee, and sell himself unto thee, thou shalt not make him to serve as a bondservant.", "acv": "And if thy brother becomes poor with thee, and sells himself to thee, thou shall not impose upon him servile labor.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if thy brother [that dwelleth] by thee shall have become poor, and be sold to thee; thou shalt not compel him to serve as a bond servant:", "vulgate": "si paupertate conpulsus vendiderit se tibi frater tuus non eum opprimes servitute famulorum;", "brenton": "And if thy brother by thee be lowered, and be sold to thee, he shall not serve thee with the servitude of a slave."}}, {"v": 40, "ref": "25:40", "o": "כְּ/שָׂכִ֥יר כְּ/תוֹשָׁ֖ב יִהְיֶ֣ה עִמָּ֑/ךְ עַד שְׁנַ֥ת הַ/יֹּבֵ֖ל יַעֲבֹ֥ד עִמָּֽ/ךְ", "en": {"kjv": "But as an hired servant, and as a sojourner, he shall be with thee, and shall serve thee unto the year of jubile:", "web": "As a hired servant, and as a temporary resident, he shall be with you; he shall serve with you until the Year of Jubilee:", "bsb": "Let him stay with you as a hired worker or temporary resident; he is to work for you until the Year of Jubilee.", "asv": "As a hired servant, and as a sojourner, he shall be with thee; he shall serve with thee unto the year of jubilee:", "ylt": "as an hireling, as a settler, he is with thee, till the year of the jubilee he doth serve with thee, --", "tyndale": "but as an hyred seruaunte and as a soiourner he shalbe with the and shall serue the vnto the trompetyere", "dra": "But he shall be as a hireling, and a sojourner: he shall work with thee until the year of the jubilee.", "bbe": "But let him be with you as a servant working for payment, till the year of Jubilee;", "geneva": "But as an hired seruant, and as a soiourner he shalbe with thee: he shall serue thee vnto the yeere of the Iubile.", "wycliffe": "but he schal be as an hirid man and tenaunt; `til to the yeer of iubilee he schal worche at thee,", "rotherham": "as a hired servant, as a settler, shall he remain with thee,—until the year of the jubilee, shall he serve with thee:", "darby": "as a hired servant, as a sojourner, shall he be with thee; until the year of jubilee shall he serve thee.", "twenty": "", "jps": "As a hired servant, and as a settler, he shall be with thee; he shall serve with thee unto the year of jubilee.", "acv": "He shall be with thee as a hired servant, and as a sojourner. He shall serve with thee to the year of jubilee.", "anderson": "", "haweis": "", "noyes": "", "webster": "[But] as a hired servant, [and] as a sojourner he shall be with thee, [and] shall serve thee to the year of jubilee.", "vulgate": "sed quasi mercennarius et colonus erit usque ad annum iobeleum operabitur apud te;", "brenton": "He shall be with thee as a hireling or a sojourner, he shall work for thee till the year of release:"}}, {"v": 41, "ref": "25:41", "o": "וְ/יָצָא֙ מֵֽ/עִמָּ֔/ךְ ה֖וּא וּ/בָנָ֣י/ו עִמּ֑/וֹ וְ/שָׁב֙ אֶל מִשְׁפַּחְתּ֔/וֹ וְ/אֶל אֲחֻזַּ֥ת אֲבֹתָ֖י/ו יָשֽׁוּב", "en": {"kjv": "And then shall he depart from thee, both he and his children with him, and shall return unto his own family, and unto the possession of his fathers shall he return.", "web": "then he shall go out from you, he and his children with him, and shall return to his own family, and to the possession of his fathers.", "bsb": "Then he and his children are to be released, and he may return to his clan and to the property of his fathers.", "asv": "then shall he go out from thee, he and his children with him, and shall return unto his own family, and unto the possession of his fathers shall he return.", "ylt": "then he hath gone out from thee, he and his sons with him, and hath turned back unto his family; even unto the possession of his fathers he doth turn back.", "tyndale": "and then shall he departe fro the: both he and his childern with him and shall returne vnto his awne kynred agayne and vnto the possessions of his fathers.", "dra": "And afterwards he shall go out with his children: and shall return to his kindred and to the possession of his fathers.", "bbe": "Then he will go out from you, he and his children with him, and go back to his family and to the property of his fathers.", "geneva": "Then shall he depart from thee, both hee, and his children with him, and shall returne vnto his familie, and vnto the possession of his fathers shall he returne:", "wycliffe": "and aftirward he schal go out with his fre children, and he schal turne ayen to the kynrede, and to `the possessioun of his fadris.", "rotherham": "then shall he go forth from thee, he and his sons with him,—and shall return unto his family, and unto the possession of his fathers, shall he return.", "darby": "Then shall he depart from thee, he and his children with him, and shall return unto his own family, and unto the possession of his fathers shall he return.", "twenty": "", "jps": "Then shall he go out from thee, he and his children with him, and shall return unto his own family, and unto the possession of his fathers shall he return.", "acv": "Then he shall go out from thee, he and his sons with him, and shall return to his own family. And he shall return to the possession of his fathers.", "anderson": "", "haweis": "", "noyes": "", "webster": "And [then] shall he depart from thee, [both] he and his children with him, and shall return to his own family, and to the possession of his fathers shall he return.", "vulgate": "et postea egredietur cum liberis suis et revertetur ad cognationem et ad possessionem patrum suorum;", "brenton": "and he shall go out in the release, and his children with him; and he shall go to his family, he shall hasten back to his patrimony."}}, {"v": 42, "ref": "25:42", "o": "כִּֽי עֲבָדַ֣/י הֵ֔ם אֲשֶׁר הוֹצֵ֥אתִי אֹתָ֖/ם מֵ/אֶ֣רֶץ מִצְרָ֑יִם לֹ֥א יִמָּכְר֖וּ מִמְכֶּ֥רֶת עָֽבֶד", "en": {"kjv": "For they are my servants, which I brought forth out of the land of Egypt: they shall not be sold as bondmen.", "web": "For they are my servants, whom I brought out of the land of Egypt. They shall not be sold as slaves.", "bsb": "Because the Israelites are My servants, whom I brought out of the land of Egypt, they are not to be sold as slaves.", "asv": "For they are my servants, whom I brought forth out of the land of Egypt: they shall not be sold as bondmen.", "ylt": "`For they are My servants, whom I have brought out from the land of Egypt: they are not sold with the sale of a servant;", "tyndale": "for they are my seruauntes which I brought out of the lande of Egipte and shall not be solde as bondmen.", "dra": "For they are my servants, and I brought them out of the land of Egypt: let them not be sold as bondmen.", "bbe": "For they are my servants whom I took out from the land of Egypt; they may not become the property of another.", "geneva": "For they are my seruants, whom I brought out of the lande of Egypt: they shall not be solde as bondmen are solde.", "wycliffe": "For thei ben my seruauntis, and Y ledde hem out of the lond of Egipt; thei schulen not be seeld bi the condicioun of seruauntis;", "rotherham": "For, my bondmen, they are, whom I brought forth out of the land of Egypt,—they shall not sell themselves with the sale of a bondman.", "darby": "For they are my bondmen, whom I brought forth out of the land of Egypt: they shall not be sold as [men] sell bondmen.", "twenty": "", "jps": "For they are My servants, whom I brought forth out of the land of Egypt; they shall not be sold as bondmen.", "acv": "For they are my servants, whom I brought forth out of the land of Egypt. They shall not be sold as bondmen.", "anderson": "", "haweis": "", "noyes": "", "webster": "For they [are] my servants, which I brought out of the land of Egypt; they shall not be sold as bond-men.", "vulgate": "mei enim servi sunt et ego eduxi eos de terra Aegypti non venient condicione servorum;", "brenton": "Because these are my servants, whom I brought out of the land of Egypt; such an one shall not be sold as a common servant."}}, {"v": 43, "ref": "25:43", "o": "לֹא תִרְדֶּ֥ה ב֖/וֹ בְּ/פָ֑רֶךְ וְ/יָרֵ֖אתָ מֵ/אֱלֹהֶֽי/ךָ", "en": {"kjv": "Thou shalt not rule over him with rigour; but shalt fear thy God.", "web": "You shall not rule over him with harshness, but shall fear your God.", "bsb": "You are not to rule over them harshly, but you shall fear your God.", "asv": "Thou shalt not rule over him with rigor, but shalt fear thy God.", "ylt": "thou rulest not over him with rigour, and thou hast been afraid of thy God.", "tyndale": "Se therfore that thou reigne not ouer him cruelly but feare thi God.", "dra": "Afflict him not by might: but fear thy God.", "bbe": "Do not be a hard master to him, but have the fear of God before you.", "geneva": "Thou shalt not rule ouer him cruelly, but shalt feare thy God.", "wycliffe": "turmente thou not hem bi thi power, but drede thou thi Lord.", "rotherham": "Thou shalt not rule over him with rigour,—so shalt thou stand in awe of thy God.", "darby": "Thou shalt not rule over him with rigour; and thou shalt fear thyGod.", "twenty": "", "jps": "Thou shalt not rule over him with rigour; but shalt fear thy G-d.", "acv": "Thou shall not rule over him with rigor, but shall fear thy God.", "anderson": "", "haweis": "", "noyes": "", "webster": "Thou shalt not rule over him with rigor, but shalt fear thy God.", "vulgate": "ne adfligas eum per potentiam sed metuito Deum tuum;", "brenton": "Thou shalt not oppress him with labour, and shalt fear the Lord thy God."}}, {"v": 44, "ref": "25:44", "o": "וְ/עַבְדְּ/ךָ֥ וַ/אֲמָתְ/ךָ֖ אֲשֶׁ֣ר יִהְיוּ לָ֑/ךְ מֵ/אֵ֣ת הַ/גּוֹיִ֗ם אֲשֶׁר֙ סְבִיבֹ֣תֵי/כֶ֔ם מֵ/הֶ֥ם תִּקְנ֖וּ עֶ֥בֶד וְ/אָמָֽה", "en": {"kjv": "Both thy bondmen, and thy bondmaids, which thou shalt have, shall be of the heathen that are round about you; of them shall ye buy bondmen and bondmaids.", "web": "“‘As for your male and your female slaves, whom you may have; of the nations that are around you, from them you may buy male and female slaves.", "bsb": "Your menservants and maidservants shall come from the nations around you, from whom you may purchase them.", "asv": "And as for thy bondmen, and thy bondmaids, whom thou shalt have; of the nations that are round about you, of them shall ye buy bondmen and bondmaids.", "ylt": "`And thy man-servant and thy handmaid whom thou hast are of the nations who are round about you; of them ye buy man-servant and handmaid,", "tyndale": "Yf thou wilt haue bondseruauntes and maydens thou shalt bye them of the heythen that are rounde aboute you", "dra": "Let your bondmen, and your bondwomen, be of the nations that are round about you:", "bbe": "But you may get servants as property from among the nations round about; from them you may take men-servants and women-servants.", "geneva": "Thy bond seruant also, and thy bond maid, which thou shalt haue, shalbe of the heathen that are rounde about you: of them shall ye bye seruants and maydes.", "wycliffe": "A seruaunt and handmaide be to you of naciouns that ben in youre cumpas,", "rotherham": "And as for thy bondman and thy bond-maid which thou shalt have, of the nations that are round about you—from them, may ye buy bondman and bond-maid.", "darby": "And as for thy bondman and thy handmaid whom thou shalt have — of the nations that are round about you, of them shall ye buy bondmen and handmaids.", "twenty": "", "jps": "And as for thy bondmen, and thy bondmaids, whom thou mayest have: of the nations that are round about you, of them shall ye buy bondmen and bondmaids.", "acv": "And as for thy bondmen, and thy bondmaids, whom thou shall have, from the nations that are round about you, ye shall buy bondmen and bondmaids from them.", "anderson": "", "haweis": "", "noyes": "", "webster": "Both thy bond-men, and thy bond-maids, which thou shalt have, [shall be] of the heathen that are around you; of them shall ye buy bond-men and bond-maids.", "vulgate": "servus et ancilla sint vobis de nationibus quae in circuitu vestro sunt;", "brenton": "And whatever number of men-servants and maid-servants thou shalt have, thou shalt purchase male and female servants from the nations that are round about thee."}}, {"v": 45, "ref": "25:45", "o": "וְ֠/גַם מִ/בְּנֵ֨י הַ/תּוֹשָׁבִ֜ים הַ/גָּרִ֤ים עִמָּ/כֶם֙ מֵ/הֶ֣ם תִּקְנ֔וּ וּ/מִ/מִּשְׁפַּחְתָּ/ם֙ אֲשֶׁ֣ר עִמָּ/כֶ֔ם אֲשֶׁ֥ר הוֹלִ֖ידוּ בְּ/אַרְצְ/כֶ֑ם וְ/הָי֥וּ לָ/כֶ֖ם לַֽ/אֲחֻזָּֽה", "en": {"kjv": "Moreover of the children of the strangers that do sojourn among you, of them shall ye buy, and of their families that are with you, which they begat in your land: and they shall be your possession.", "web": "Moreover of the children of the aliens who live among you, of them you may buy, and of their families who are with you, which they have conceived in your land; and they will be your property.", "bsb": "You may also purchase them from the foreigners residing among you or their clans living among you who are born in your land. These may become your property.", "asv": "Moreover of the children of the strangers that sojourn among you, of them shall ye buy, and of their families that are with you, which they have begotten in your land: and they shall be your possession.", "ylt": "and also of the sons of the settlers who are sojourning with you, of them ye buy, and of their families who are with you, which they have begotten in your land, and they have been to you for a possession;", "tyndale": "and of the childern of the straungers that are soiorners amonge you ad of their generacios that are with you, which they begate in youre lade.", "dra": "And of the strangers that sojourn among you, or that were born of them in your land. These you shall have for servants:", "bbe": "And in addition, you may get, for money, servants from among the children of other nations who are living with you, and from their families which have come to birth in your land; and these will be your property.", "geneva": "And moreouer of the children of the stragers, that are soiourners among you, of them shall ye bye, and of their families that are with you, which they begate in your lande: these shall be your possession.", "wycliffe": "and of comelyngis that ben pilgrimys at you, ether thei that ben borun of hem in youre lond; ye schulen haue these seruauntis,", "rotherham": "Moreover also, of the sons of the settlers who are sojourning with you—of them, may ye buy, and of their families that are with you, which they have begotten in your land,—so shall they become yours, as a possession;", "darby": "Moreover of the children of them that dwell as sojourners with you, of them may ye buy, and of their family that is with you, which they beget in your land, and they shall be your possession.", "twenty": "", "jps": "Moreover of the children of the strangers that do sojourn among you, of them may ye buy, and of their families that are with you, which they have begotten in your land; and they may be your possession.", "acv": "Moreover of the sons of the strangers who sojourn among you, ye shall buy from them, and from their families that are with you, which they have begotten in your land, and they shall be your possession.", "anderson": "", "haweis": "", "noyes": "", "webster": "Moreover of the children of the strangers that sojourn among you, of them shall ye buy, and of their families that are with you, which they begat in your land: and they shall be your possession.", "vulgate": "et de advenis qui peregrinantur apud vos vel qui ex his nati fuerint in terra vestra hos habebitis famulos;", "brenton": "And of the sons of the sojourners that are among you, of these ye shall buy and of their relations, all that shall be in your lands; let them be to you for a possession."}}, {"v": 46, "ref": "25:46", "o": "וְ/הִתְנַחֲלְתֶּ֨ם אֹתָ֜/ם לִ/בְנֵי/כֶ֤ם אַחֲרֵי/כֶם֙ לָ/רֶ֣שֶׁת אֲחֻזָּ֔ה לְ/עֹלָ֖ם בָּ/הֶ֣ם תַּעֲבֹ֑דוּ וּ/בְ/אַ֨חֵי/כֶ֤ם בְּנֵֽי יִשְׂרָאֵל֙ אִ֣ישׁ בְּ/אָחִ֔י/ו לֹא תִרְדֶּ֥ה ב֖/וֹ בְּ/פָֽרֶךְ", "en": {"kjv": "And ye shall take them as an inheritance for your children after you, to inherit them for a possession; they shall be your bondmen for ever: but over your brethren the children of Israel, ye shall not rule one over another with rigour.", "web": "You may make them an inheritance for your children after you, to hold for a possession; of them may you take your slaves forever; but over your brothers the children of Israel you shall not rule, one over another, with harshness.", "bsb": "You may leave them to your sons after you to inherit as property; you can make them slaves for life. But as for your brothers, the Israelites, no man may rule harshly over his brother.", "asv": "And ye shall make them an inheritance for your children after you, to hold for a possession; of them shall ye take your bondmen for ever: but over your brethren the children of Israel ye shall not rule, one over another, with rigor.", "ylt": "and ye have taken them for inheritance to your sons after you, to occupy for a possession; to the age ye lay service upon them, but upon your brethren, the sons of Israel, one with another, thou dost not rule over him with rigour.", "tyndale": "And ye shall possesse them and geue them vnto youre childern after you, to possesse them for euer: and they shalbe youre bond men: But ouer youre brethern the childern of Israel ye shall not reigne one ouer another cruelly.", "dra": "And by right of inheritance shall leave them to your posterity, and shall possess them for ever. But oppress not your brethren the children of Israel by might.", "bbe": "And they will be your children's heritage after you, to keep as their property; they will be your servants for ever; but you may not be hard masters to your countrymen, the children of Israel.", "geneva": "So ye shall take them as inheritance for your children after you, to possesse them by inheritance, ye shall vse their labours for euer: but ouer your brethren the children of Israel ye shall not rule one ouer another with crueltie.", "wycliffe": "and bi riyt of eritage ye schulen `sende ouer to aftir comeris, and ye schulen welde with outen ende; sothely oppresse ye not bi power youre britheren, the sones of Israel.", "rotherham": "and ye may take them as an inheritance for your sons after you to inherit as a possession, unto times age-abiding, of them, may ye take to be bondmen,—but, over your brethren the sons of Israel—a man over his brother, ye shall not rule, over him with rigour.", "darby": "And ye shall leave them as an inheritance to your children after you, to inherit them as a possession: these may ye make your bondmen for ever; but as for your brethren, the children of Israel, ye shall not rule over one another with rigour.", "twenty": "", "jps": "And ye may make them an inheritance for your children after you, to hold for a possession: of them may ye take your bondmen for ever; but over your brethren the children of Israel ye shall not rule, one over another, with rigour.", "acv": "And ye shall make them an inheritance for your sons after you, to hold for a possession. Ye shall take your permanent bondmen from them, but over your brothers the sons of Israel ye shall not rule, one over another, with rigor.", "anderson": "", "haweis": "", "noyes": "", "webster": "And ye shall take them as an inheritance for your children after you, to inherit [them for] a possession, they shall be your bond-men for ever: but over your brethren the children of Israel, ye shall not rule one over another with rigor.", "vulgate": "et hereditario iure transmittetis ad posteros ac possidebitis in aeternum fratres autem vestros filios Israhel ne opprimatis per potentiam;", "brenton": "And ye shall distribute them to your children after you, and they shall be to you permanent possessions for ever: but of your brethren the children of Israel, one shall not oppress his brother in labours."}}, {"v": 47, "ref": "25:47", "o": "וְ/כִ֣י תַשִּׂ֗יג יַ֣ד גֵּ֤ר וְ/תוֹשָׁב֙ עִמָּ֔/ךְ וּ/מָ֥ךְ אָחִ֖י/ךָ עִמּ֑/וֹ וְ/נִמְכַּ֗ר לְ/גֵ֤ר תּוֹשָׁב֙ עִמָּ֔/ךְ א֥וֹ לְ/עֵ֖קֶר מִשְׁפַּ֥חַת גֵּֽר", "en": {"kjv": "And if a sojourner or stranger wax rich by thee, and thy brother that dwelleth by him wax poor, and sell himself unto the stranger or sojourner by thee, or to the stock of the stranger’s family:", "web": "“‘If an alien or temporary resident with you becomes rich, and your brother beside him has grown poor, and sells himself to the stranger or foreigner living among you, or to a member of the stranger’s family;", "bsb": "If a foreigner residing among you prospers, but your countryman dwelling near him becomes destitute and sells himself to the foreigner or to a member of his clan,", "asv": "And if a stranger or sojourner with thee be waxed rich, and thy brother be waxed poor beside him, and sell himself unto the stranger or sojourner with thee, or to the stock of the stranger’s family;", "ylt": "`And when the hand of a sojourner or settler with thee attaineth riches , and thy brother with him hath become poor, and he hath been sold to a sojourner, a settler with thee, or to the root of the family of a sojourner,", "tyndale": "When a straunger and a soiourner waxeth rych by the ad thi brother that dwelleth by him waxeth poore and sell him selfe vnto the straunger that dwelleth by the or to any of the straungers kyn:", "dra": "If the hand of a stranger or a sojourner grow strong among you, and thy brother being impoverished sell himself to him, or to any of his race:", "bbe": "And if one from another nation living among you gets wealth, and your countryman, at his side, becomes poor and gives himself for money to the man from another nation or to one of his family;", "geneva": "If a soiourner or a stranger dwelling by thee get riches, and thy brother by him be impouerished, and sell him selfe vnto the stranger or soiourner dwelling by thee, or to the stocke of the strangers familie,", "wycliffe": "If the hond of a comelyng and of a pilgrim wexith strong at you, and thi brother is maad pore, and sillith hym silf to hym,", "rotherham": "And, when the hand of the sojourner and settler with thee getteth possessions, and thy brother with him, waxeth poor,—and so he selleth himself to the sojourner [who is] a settler with thee, or to one who hath taken root, of the family of the sojourner,", "darby": "And if a stranger or sojourner become wealthy beside thee, and thy brother beside him grow poor, and sell himself unto the stranger, who is settled by thee, or to a scion of the stranger's family,", "twenty": "", "jps": "And if a stranger who is a settler with thee be waxen rich, and thy brother be waxen poor beside him, and sell himself unto the stranger who is a settler with thee, or to the offshoot of a stranger's family,", "acv": "And if a stranger or sojourner with thee becomes rich, and thy brother becomes poor beside him, and sells himself to the stranger or sojourner with thee, or to the stock of the stranger's family,", "anderson": "", "haweis": "", "noyes": "", "webster": "And if a sojourner or a stranger shall become rich by thee, and thy brother [that dwelleth] by him shall become poor, and sell himself to the stranger [or] sojourner by thee, or to the stock of the stranger's family:", "vulgate": "si invaluerit apud vos manus advenae atque peregrini et adtenuatus frater tuus vendiderit se ei aut cuiquam de stirpe eius;", "brenton": "And if a stranger or sojourner with thee wax rich, and thy brother in distress be sold to the stranger or the sojourner that is with thee, or to a proselyte by extraction;"}}, {"v": 48, "ref": "25:48", "o": "אַחֲרֵ֣י נִמְכַּ֔ר גְּאֻלָּ֖ה תִּהְיֶה לּ֑/וֹ אֶחָ֥ד מֵ/אֶחָ֖י/ו יִגְאָלֶֽ/נּוּ", "en": {"kjv": "After that he is sold he may be redeemed again; one of his brethren may redeem him:", "web": "after he is sold he may be redeemed. One of his brothers may redeem him;", "bsb": "he retains the right of redemption after he has sold himself. One of his brothers may redeem him:", "asv": "after that he is sold he may be redeemed: one of his brethren may redeem him;", "ylt": "after he hath been sold, there is a right of redemption to him; one of his brethren doth redeem him,", "tyndale": "after that he is solde he maye be redemed agayne. one of his brethren maye bye him out:", "dra": "After the sale he may be redeemed. He that will of his brethren shall redeem him:", "bbe": "After he has given himself he has the right to be made free, for a price, by one of his brothers,", "geneva": "After that he is solde, he may be bought out: one of his brethren may bye him out,", "wycliffe": "ether to ony of his kyn, he may be ayenbouyt aftir the sillyng; he that wole of hise britheren, ayenbie hym; bothe `the brother of fadir,", "rotherham": "after that he hath sold himself, a right of redemption, pertaineth to him,—one of his brethren, may redeem him;", "darby": "after that he is sold there shall be right of redemption for him; one of his brethren may redeem him.", "twenty": "", "jps": "after that he is sold he may be redeemed; one of his brethren may redeem him;", "acv": "he may be redeemed after he is sold. One of his brothers may redeem him.", "anderson": "", "haweis": "", "noyes": "", "webster": "After that he is sold he may be redeemed again; one of his brethren may redeem him:", "vulgate": "post venditionem potest redimi qui voluerit ex fratribus suis redimet eum;", "brenton": "after he is sold to him there shall be redemption for him, one of his brethren shall redeem him."}}, {"v": 49, "ref": "25:49", "o": "אוֹ דֹד֞/וֹ א֤וֹ בֶן דֹּד/וֹ֙ יִגְאָלֶ֔/נּוּ אֽוֹ מִ/שְּׁאֵ֧ר בְּשָׂר֛/וֹ מִ/מִּשְׁפַּחְתּ֖/וֹ יִגְאָלֶ֑/נּוּ אֽוֹ הִשִּׂ֥יגָה יָד֖/וֹ וְ/נִגְאָֽל", "en": {"kjv": "Either his uncle, or his uncle’s son, may redeem him, or any that is nigh of kin unto him of his family may redeem him; or if he be able, he may redeem himself.", "web": "or his uncle, or his uncle’s son, may redeem him, or any who is a close relative to him of his family may redeem him; or if he has grown rich, he may redeem himself.", "bsb": "either his uncle or cousin or any close relative from his clan may redeem him. Or if he prospers, he may redeem himself.", "asv": "or his uncle, or his uncle’s son, may redeem him, or any that is nigh of kin unto him of his family may redeem him; or if he be waxed rich, he may redeem himself.", "ylt": "or his uncle, or a son of his uncle, doth redeem him, or any of the relations of his flesh, of his family, doth redeem him, or--his own hand hath attained--then he hath been redeemed.", "tyndale": "whether it be his vncle or his vncles sonne or any that is nye of kynne vnto him of his kynred: ether yf his hande can get so moch he maye be loosed.", "dra": "Either his uncle, or his uncle's son, or his kinsman, by blood, or by affinity. But if he himself be able also, he shall redeem himself:", "bbe": "Or his father's brother, or the son of his father's brother, or any near relation; or if he gets money, he may make himself free.", "geneva": "Or his vncle, or his vncles sonne may bye him out, or any of the kindred of his flesh among his familie, may redeeme him: either if he can get so much, he may bye him selfe out.", "wycliffe": "and the sone of `the fadris brother, and kynesman, and alye. Ellis if also he schal mow, he schal ayenbie hym silf,", "rotherham": "or, his uncle or his uncle’s son, may redeem him, or, a near flesh-relation of his, of his family, may redeem him, or, his own hand may have gotten enough, and, so he may redeem himself.", "darby": "Either his uncle or his uncle's son may redeem him, or one of his next relations of his family may redeem him; or if his means be sufficient, he may redeem himself.", "twenty": "", "jps": "or his uncle, or his uncle's son, may redeem him, or any that is nigh of kin unto him of his family may redeem him; or if he be waxen rich, he may redeem himself.", "acv": "Or his uncle, or his uncle's son, may redeem him. Or any who is near of kin to him of his family may redeem him. Or if he becomes rich, he may redeem himself.", "anderson": "", "haweis": "", "noyes": "", "webster": "Either his uncle, or his uncle's son may redeem him, or [any] that is nigh of kin to him of his family, may redeem him; or if he is able, he may redeem himself.", "vulgate": "et patruus et patruelis et consanguineus et adfinis sin autem et ipse potuerit redimet se;", "brenton": "A brother of his father, or a son of his father's brother shall redeem him; or let one of his near kin of his tribe redeem him, and if he should be rich and redeem himself,"}}, {"v": 50, "ref": "25:50", "o": "וְ/חִשַּׁב֙ עִם קֹנֵ֔/הוּ מִ/שְּׁנַת֙ הִמָּ֣כְר/וֹ ל֔/וֹ עַ֖ד שְׁנַ֣ת הַ/יֹּבֵ֑ל וְ/הָיָ֞ה כֶּ֤סֶף מִמְכָּר/וֹ֙ בְּ/מִסְפַּ֣ר שָׁנִ֔ים כִּ/ימֵ֥י שָׂכִ֖יר יִהְיֶ֥ה עִמּֽ/וֹ", "en": {"kjv": "And he shall reckon with him that bought him from the year that he was sold to him unto the year of jubile: and the price of his sale shall be according unto the number of years, according to the time of an hired servant shall it be with him.", "web": "He shall reckon with him who bought him from the year that he sold himself to him to the Year of Jubilee. The price of his sale shall be according to the number of years; he shall be with him according to the time of a hired servant.", "bsb": "He and his purchaser will then count the time from the year he sold himself up to the Year of Jubilee. The price of his sale will be determined by the number of years, based on the daily wages of a hired hand.", "asv": "And he shall reckon with him that bought him from the year that he sold himself to him unto the year of jubilee: and the price of his sale shall be according unto the number of years; according to the time of a hired servant shall he be with him.", "ylt": "`And he hath reckoned with his buyer from the year of his being sold to him till the year of jubilee, and the money of his sale hath been by the number of years; as the days of an hireling it is with him.", "tyndale": "And he shall reken with him that boughte him from the yere that he was solde in vnto the trompet yere and the pryce of his byenge shalbe acordynge vnto the numbre of yeres and he shalbe with him as a hyred seruaunte.", "dra": "Counting only the years from the time of his selling unto the year of the jubilee: and counting the money that he was sold for, according to the number of the years and the reckoning of a hired servant.", "bbe": "And let the years be numbered from the time when he gave himself to his owner till the year of Jubilee, and the price given for him will be in relation to the number of years, on the scale of the payment of a servant.", "geneva": "Then he shall recken with his byer from the yeere that he was solde to him, vnto the yere of Iubile: and the money of his sale shalbe according to the number of yeeres: according to the time of an hyred seruant shall he be with him.", "wycliffe": "while the yeeris ben rykenid oneli fro the tyme of his sillyng `til in to the yeer of iubylee; and while the money, for which he was seeld, is rikenyd bi the noumbre of yeeris, and while the hire of an hirid man is rikenyd.", "rotherham": "Then shall he reckon with him that bought him, from the year that he was sold to him, unto the year of the jubilee,—and the silver for which he was sold shall be by the number of years, according to the days of a hired servant, shall he be with him.", "darby": "And he shall reckon with him that bought him from the year that he was sold to him unto the year of jubilee; and the price of his sale shall be according to the number of the years, according to the days of a hired servant shall he be with him.", "twenty": "", "jps": "And he shall reckon with him that bought him from the year that he sold himself to him unto the year of jubilee; and the price of his sale shall be according unto the number of years; according to the time of a hired servant shall he be with him.", "acv": "And he shall reckon with him who bought him from the year that he sold himself to him to the year of jubilee. And the price of his sale shall be according to the number of years. He shall be with him according to the time of a hired servant.", "anderson": "", "haweis": "", "noyes": "", "webster": "And he shall reckon with him that bought him, from the year that he was sold to him, to the year of jubilee: and the price of his sale shall be according to the number of years, according to the time of a hired servant shall it be with him.", "vulgate": "supputatis dumtaxat annis a tempore venditionis suae usque ad annum iobeleum et pecunia qua venditus fuerat iuxta annorum numerum et rationem mercennarii supputata;", "brenton": "then shall he calculate with his purchaser from the year that he sold himself to him until the year of release: and the money of his purchase shall be as that of a hireling, he shall be with him from year to year."}}, {"v": 51, "ref": "25:51", "o": "אִם ע֥וֹד רַבּ֖וֹת בַּ/שָּׁנִ֑ים לְ/פִי/הֶן֙ יָשִׁ֣יב גְּאֻלָּת֔/וֹ מִ/כֶּ֖סֶף מִקְנָתֽ/וֹ", "en": {"kjv": "If there be yet many years behind, according unto them he shall give again the price of his redemption out of the money that he was bought for.", "web": "If there are yet many years, according to them he shall give back the price of his redemption out of the money that he was bought for.", "bsb": "If many years remain, he must pay for his redemption in proportion to his purchase price.", "asv": "If there be yet many years, according unto them he shall give back the price of his redemption out of the money that he was bought for.", "ylt": "`If yet many years, according to them he giveth back his redemption money , from the money of his purchase.", "tyndale": "Yf there be yet many yeres behynde acordynge vnto them he shall geue agayne for his delyueraunce of the money that he was solde for.", "dra": "If there be many years that remain until the jubilee, according to them shall he also repay the price.", "bbe": "If there is still a long time, he will give back, on account of it, a part of the price which was given for him.", "geneva": "If there be many yeeres behind, according to them he shall giue againe for his deliuerance, of the money that he was bought for.", "wycliffe": "If mo yeeris ben that dwellen `til to the iubilee, bi these yeeris he schal yelde also the prijs; if fewe yeeris ben,", "rotherham": "If there is yet a multitude of years, according to them, shall he return, as his redemption price, of the silver of him that bought him.", "darby": "If there are yet many years, according unto them shall he return his redemption [money] out of the money that he was bought for;", "twenty": "", "jps": "If there be yet many years, according unto them he shall give back the price of his redemption out of the money that he was bought for.", "acv": "If there be yet many years, according to them he shall give back the price of his redemption out of the money that he was bought for.", "anderson": "", "haweis": "", "noyes": "", "webster": "If [there shall be] yet many years [behind], according to them he shall give again the price of his redemption out of the money that he was bought for.", "vulgate": "si plures fuerint anni qui remanent usque ad iobeleum secundum hos reddet et pretium;", "brenton": "And if any have a greater number of years than enough, according to these he shall pay his ransom out of his purchase-money."}}, {"v": 52, "ref": "25:52", "o": "וְ/אִם מְעַ֞ט נִשְׁאַ֧ר בַּ/שָּׁנִ֛ים עַד שְׁנַ֥ת הַ/יֹּבֵ֖ל וְ/חִשַּׁב ל֑/וֹ כְּ/פִ֣י שָׁנָ֔י/ו יָשִׁ֖יב אֶת גְּאֻלָּתֽ/וֹ", "en": {"kjv": "And if there remain but few years unto the year of jubile, then he shall count with him, and according unto his years shall he give him again the price of his redemption.", "web": "If there remain but a few years to the year of jubilee, then he shall reckon with him; according to his years of service he shall give back the price of his redemption.", "bsb": "If only a few years remain until the Year of Jubilee, he is to calculate and pay his redemption according to his remaining years.", "asv": "And if there remain but few years unto the year of jubilee, then he shall reckon with him; according unto his years shall he give back the price of his redemption.", "ylt": "`And if few are left of the years till the year of jubilee, then he hath reckoned with him, according to his years he doth give back his redemption money ;", "tyndale": "Yf there remayne but few yeres vnto the trompet yere he shall so counte with him and acordynge vnto his yeres geue him agayne for his redempcion", "dra": "If few, he shall make the reckoning with him according to the number of the years: and shall repay to the buyer of what remaineth of the years.", "bbe": "And if there is only a short time, he will take account of it with his master, and in relation to the number of years he will give back the price of making him free.", "geneva": "If there remaine but fewe yeeres vnto the yeere of Iubile, then he shall count with him, and according to his yeeres giue againe for his redemption.", "wycliffe": "he schal sette rikenyng with hym bi the noumbre of yeeris;", "rotherham": "Or, if [there is] but a small remainder of years, until the year of the jubilee, then shall he reckon to himself, according to the years thereof, shall he return his price of redemption.", "darby": "and if there remain but few years unto the year of jubilee, then he shall reckon with him; according unto his [remaining] years [of service] shall he give him back his redemption [money].", "twenty": "", "jps": "And if there remain but few years unto the year of jubilee, then he shall reckon with him; according unto his years shall he give back the price of his redemption.", "acv": "And if there remain but few years to the year of jubilee, then he shall reckon with him. He shall give back the price of his redemption according to his years.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if there shall remain but few years to the year of jubilee, then he shall count with him, [and] according to his years shall he give him again the price of his redemption.", "vulgate": "si pauci ponet rationem cum eo iuxta annorum numerum et reddet emptori quod reliquum est annorum;", "brenton": "And if but a little time be left of the years to the year of release, then shall he reckon to him according to his years, and shall pay his ransom"}}, {"v": 53, "ref": "25:53", "o": "כִּ/שְׂכִ֥יר שָׁנָ֛ה בְּ/שָׁנָ֖ה יִהְיֶ֣ה עִמּ֑/וֹ לֹֽא יִרְדֶּ֥/נּֽוּ בְּ/פֶ֖רֶךְ לְ/עֵינֶֽי/ךָ", "en": {"kjv": "And as a yearly hired servant shall he be with him: and the other shall not rule with rigour over him in thy sight.", "web": "As a servant hired year by year shall he be with him. He shall not rule with harshness over him in your sight.", "bsb": "He shall be treated like a man hired from year to year, but a foreign owner must not rule over him harshly in your sight.", "asv": "As a servant hired year by year shall he be with him: he shall not rule with rigor over him in thy sight.", "ylt": "as an hireling, year by year, he is with him, and he doth not rule him with rigour before thine eyes.", "tyndale": "and shalbe with him yere by yere as an hyred seruaunte and the other shall not reygne cruelly ouer him in thi syghte.", "dra": "His wages being allowed for which he served before: he shall not afflict him violently in thy sight.", "bbe": "And he will be with him as a servant working for payment year by year; his master is not to be cruel to him before your eyes.", "geneva": "He shalbe with him yeere by yeere as an hired seruant: he shall not rule cruelly ouer him in thy sight.", "wycliffe": "and he schal yeelde to the biere that that is residue of yeeris, while tho yeeris, bi whiche he seruyde bifore, ben rikenyd for hiris; he schal not turmente `that Ebreu violentli in thi siyt.", "rotherham": "As a servant hired year by year, shall he be with him, he shall not rule over him with rigour, before thine eyes.", "darby": "As a hired servant shall he be with him year by year; [his master] shall not rule with rigour over him before thine eyes.", "twenty": "", "jps": "As a servant hired year by year shall he be with him; he shall not rule with rigour over him in thy sight.", "acv": "He shall be with him as a servant hired year by year. He shall not rule with rigor over him in thy sight.", "anderson": "", "haweis": "", "noyes": "", "webster": "[And] as a yearly hired servant shall he be with him: [and the other] shall not rule with rigor over him in thy sight.", "vulgate": "quibus ante servivit mercedibus inputatis non adfliget eum violenter in conspectu tuo;", "brenton": "as a hireling; he shall be with him from year to year; thou shalt not oppress him with labour before thee."}}, {"v": 54, "ref": "25:54", "o": "וְ/אִם לֹ֥א יִגָּאֵ֖ל בְּ/אֵ֑לֶּה וְ/יָצָא֙ בִּ/שְׁנַ֣ת הַ/יֹּבֵ֔ל ה֖וּא וּ/בָנָ֥י/ו עִמּֽ/וֹ", "en": {"kjv": "And if he be not redeemed in these years, then he shall go out in the year of jubile, both he, and his children with him.", "web": "If he isn’t redeemed by these means, then he shall be released in the Year of Jubilee, he, and his children with him.", "bsb": "Even if he is not redeemed in any of these ways, he and his children shall be released in the Year of Jubilee.", "asv": "And if he be not redeemed by these means, then he shall go out in the year of jubilee, he, and his children with him.", "ylt": "`And if he is not redeemed in these years , then he hath gone out in the year of jubilee, he and his sons with him.", "tyndale": "Yf he be not bought fre in the meane tyme then he shall goo out in the trompet yere and his childern with him.", "dra": "And if by these means he cannot be redeemed, in the year of the jubilee he shall go out with his children.", "bbe": "And if he is not made free in this way, he will go out in the year of Jubilee, he and his children with him.", "geneva": "And if he be not redeemed thus, he shall go out in the yeere of Iubile, he, and his children with him.", "wycliffe": "That if he may not be ayenbouyt bi this, he schal go out with his free children in the `yeer of iubilee; for the sones of Israel ben myn seruauntis,", "rotherham": "But if he be not redeemed in any of these ways, then shall he go out in the jubilee year, he, and his sons with him.", "darby": "And if he be not redeemed in this manner, then he shall go out in the year of jubilee, he and his children with him.", "twenty": "", "jps": "And if he be not redeemed by any of these means, then he shall go out in the year of jubilee, he, and his children with him.", "acv": "And if he is not redeemed by these means, then he shall go out in the year of jubilee, he, and his sons with him.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if he shall not be redeemed in these [years], then he shall go out in the year of jubilee, [both] he, and his children with him.", "vulgate": "quod si per haec redimi non potuerit anno iobeleo egredietur cum liberis suis;", "brenton": "And if he do not pay his ransom accordingly, he shall go out in the year of his release, he and his children with him."}}, {"v": 55, "ref": "25:55", "o": "כִּֽי לִ֤/י בְנֵֽי יִשְׂרָאֵל֙ עֲבָדִ֔ים עֲבָדַ֣/י הֵ֔ם אֲשֶׁר הוֹצֵ֥אתִי אוֹתָ֖/ם מֵ/אֶ֣רֶץ מִצְרָ֑יִם אֲנִ֖י יְהוָ֥ה אֱלֹהֵי/כֶֽם", "en": {"kjv": "For unto me the children of Israel are servants; they are my servants whom I brought forth out of the land of Egypt: I am the Lord your God.", "web": "For to me the children of Israel are servants; they are my servants whom I brought out of the land of Egypt. I am Yahweh your God.", "bsb": "For the Israelites are My servants. They are My servants, whom I brought out of the land of Egypt. I am the LORD your God.", "asv": "For unto me the children of Israel are servants; they are my servants whom I brought forth out of the land of Egypt: I am Jehovah your God.", "ylt": "For to Me are the sons of Israel servants; My servants they are , whom I have brought out of the land of Egypt; I, Jehovah, am your God.", "tyndale": "for the childern of Israel are my seruauntes which I broughte out of the lande of Egipte. I am the Lorde youre God.", "dra": "For the children of Israel are my servants, whom I brought forth out of the land of Egypt.", "bbe": "For the children of Israel are servants to me; they are my servants whom I took out of the land of Egypt: I am the Lord your God.", "geneva": "For vnto me the children of Israel are seruants: they are my seruants, who I haue brought out of the land of Egypt: I am ye Lord your God.", "wycliffe": "whiche Y ledde out of the lond of Egipt.", "rotherham": "For, unto me, are the sons of Israel, bondmen, my bondmen, they are, whom I brought forth out of the land of Egypt. I, Yahweh, am your God.", "darby": "For the children of Israel are servants unto me; they are my servants whom I brought forth out of the land of Egypt: I am Jehovah yourGod.", "twenty": "", "jps": "For unto Me the children of Israel are servants; they are My servants whom I brought forth out of the land of Egypt: I am HaShem your G-d.", "acv": "For the sons of Israel are servants to me. They are my servants whom I brought forth out of the land of Egypt. I am Jehovah your God.", "anderson": "", "haweis": "", "noyes": "", "webster": "For to me the children of Israel [are] servants, they [are] my servants whom I brought out of the land of Egypt: I [am] the LORD your God.", "vulgate": "mei sunt enim servi filii Israhel quos eduxi de terra Aegypti;", "brenton": "For the children of Israel are my servants: they are my attendants, whom I brought out of the land of Egypt."}}]}, {"c": 26, "verses": [{"v": 1, "ref": "26:1", "o": "לֹֽא תַעֲשׂ֨וּ לָ/כֶ֜ם אֱלִילִ֗ם וּ/פֶ֤סֶל וּ/מַצֵּבָה֙ לֹֽא תָקִ֣ימוּ לָ/כֶ֔ם וְ/אֶ֣בֶן מַשְׂכִּ֗ית לֹ֤א תִתְּנוּ֙ בְּ/אַרְצְ/כֶ֔ם לְ/הִֽשְׁתַּחֲוֺ֖ת עָלֶ֑י/הָ כִּ֛י אֲנִ֥י יְהוָ֖ה אֱלֹהֵי/כֶֽם", "en": {"kjv": "Ye shall make you no idols nor graven image, neither rear you up a standing image, neither shall ye set up any image of stone in your land, to bow down unto it: for I am the Lord your God.", "web": "“‘You shall make for yourselves no idols, neither shall you raise up an engraved image or a pillar, neither shall you place any figured stone in your land, to bow down to it; for I am Yahweh your God.", "bsb": "“You must not make idols for yourselves or set up a carved image or sacred pillar; you must not place a sculpted stone in your land to bow down to it. For I am the LORD your God.", "asv": "Ye shall make you no idols, neither shall ye rear you up a graven image, or a pillar, neither shall ye place any figured stone in your land, to bow down unto it: for I am Jehovah your God.", "ylt": "`Ye do not make to yourselves idols; and graven image or standing image ye do not set up to yourselves; and a stone of imagery ye do not put in your land, to bow yourselves to it; for I am Jehovah your God.", "tyndale": "Ye shall make you no ydolles nor grauen ymage nether rere you vpp any piler nether ye shall sett vp any ymage of stone in youre lande to bowe youre selues there to: for I am the Lorde youre God.", "dra": "I am the Lord your God. You shall not make to yourselves any idol or graven thing: neither shall you erect pillars, nor set up a remarkable stone in your land, to adore it. For I am the Lord your God.", "bbe": "Do not make images of false gods, or put up an image cut in stone or a pillar or any pictured stone in your land, to give worship to it; for I am the Lord your God.", "geneva": "Ye shall make you none idoles nor grauen image, neither reare you vp any pillar, neither shall ye set any image of stone in your land to bow downe to it: for I am the Lord your God.", "wycliffe": "Y am youre Lord God; ye schulen not make to you an ydol, and a grauun ymage, nether ye schulen reise titlis, nether ye schulen sette a noble stoon in youre lond, that ye worschipe it; for Y am youre Lord God.", "rotherham": "Ye shall not make unto you idols,—neither image nor pillar, shall ye set up for yourselves, nor sculptured stone, shall ye place in your land, to bow yourselves down thereunto,-For, I Yahweh, am your God.", "darby": "Ye shall make yourselves no idols, neither rear you up for yourselves carved image, or statue, nor shall ye set up a figured stone in your land, to bow down unto it; for I am Jehovah yourGod.", "twenty": "", "jps": "Ye shall make you no idols, neither shall ye rear you up a graven image, or a pillar, neither shall ye place any figured stone in your land, to bow down unto it; for I am HaShem your G-d.", "acv": "Ye shall make for you no idols. Neither shall ye rear up for you a graven image, or a pillar. Neither shall ye place any figured stone in your land, to bow down to it. For I am Jehovah your God.", "anderson": "", "haweis": "", "noyes": "", "webster": "Ye shall make you no idols nor graven image, neither rear you up a standing image, neither shall ye set up [any] image of stone in your land, to bow down to it: for I [am] the LORD your God.", "vulgate": "ego Dominus Deus vester non facietis vobis idolum et sculptile nec titulos erigetis nec insignem lapidem ponetis in terra vestra ut adoretis eum ego enim sum Dominus Deus vester;", "brenton": "I am the Lord your God: ye shall not make to yourselves gods made with hands, or graven; neither shall ye rear up a pillar for yourselves, neither shall ye set up a stone for an object in your land to worship it: I am the Lord your God."}}, {"v": 2, "ref": "26:2", "o": "אֶת שַׁבְּתֹתַ֣/י תִּשְׁמֹ֔רוּ וּ/מִקְדָּשִׁ֖/י תִּירָ֑אוּ אֲנִ֖י יְהוָֽה", "en": {"kjv": "Ye shall keep my sabbaths, and reverence my sanctuary: I am the Lord.", "web": "“‘You shall keep my Sabbaths, and have reverence for my sanctuary. I am Yahweh.", "bsb": "You must keep My Sabbaths and have reverence for My sanctuary. I am the LORD.", "asv": "Ye shall keep my sabbaths, and reverence my sanctuary: I am Jehovah.", "ylt": "`My sabbaths ye do keep, and My sanctuary ye do reverence; I am Jehovah.", "tyndale": "kepe my sabbathes and feare my sanctuary. for I am the Lorde.", "dra": "Keep my sabbaths, and reverence my sanctuary. I am the Lord.", "bbe": "Keep my Sabbaths and give honour to my holy place: I am the Lord.", "geneva": "Ye shall keepe my Sabbaths, and reuerence my Sanctuarie: I am the Lord.", "wycliffe": "Kepe ye my sabatis, and drede ye at my seyntuarie; Y am the Lord.", "rotherham": "My sabbaths, shall ye observe, And, my sanctuary, shall ye revere,—I, am Yahweh.", "darby": "Ye shall observe my sabbaths, and my sanctuary shall ye reverence: I am Jehovah.", "twenty": "", "jps": "Ye shall keep My sabbaths, and reverence My sanctuary: I am HaShem.", "acv": "Ye shall keep my sabbaths, and reverence my sanctuary. I am Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "Ye shall keep my sabbaths, and reverence my sanctuary: I [am] the LORD.", "vulgate": "custodite sabbata mea et pavete ad sanctuarium meum ego Dominus;", "brenton": "Ye shall keep my sabbaths, and reverence my sanctuaries: I am the Lord."}}, {"v": 3, "ref": "26:3", "o": "אִם בְּ/חֻקֹּתַ֖/י תֵּלֵ֑כוּ וְ/אֶת מִצְוֺתַ֣/י תִּשְׁמְר֔וּ וַ/עֲשִׂיתֶ֖ם אֹתָֽ/ם", "en": {"kjv": "If ye walk in my statutes, and keep my commandments, and do them;", "web": "“‘If you walk in my statutes, and keep my commandments, and do them;", "bsb": "If you follow My statutes and carefully keep My commandments,", "asv": "If ye walk in my statutes, and keep my commandments, and do them;", "ylt": "`If in My statutes ye walk, and My commands ye keep, and have done them,", "tyndale": "Yf ye shall walke in myne ordynaunces and kepe my commaundmentes and do them", "dra": "If you walk in my precepts, and keep my commandments, and do them, I will give you rain in due seasons.", "bbe": "If you are guided by my rules, and keep my laws and do them,", "geneva": "If ye walke in mine ordinances, and keepe my commandements, and doe them,", "wycliffe": "If ye gon in myn heestis, and kepen my comaundementis, and doon tho, Y schal yyue to you reynes in her tymes,", "rotherham": "If, in my statutes, ye will walk,—And my commandments, ye will observe, and do them,", "darby": "If ye walk in my statutes, and observe my commandments and do them,", "twenty": "", "jps": "If ye walk in My statutes, and keep My commandments, and do them;", "acv": "If ye walk in my statutes, and keep my commandments, and do them,", "anderson": "", "haweis": "", "noyes": "", "webster": "If ye walk in my statutes, and keep my commandments, and do them;", "vulgate": "si in praeceptis meis ambulaveritis et mandata mea custodieritis et feceritis ea dabo vobis pluvias temporibus suis;", "brenton": "If ye will walk in my ordinances, and keep my commandments, and do them,"}}, {"v": 4, "ref": "26:4", "o": "וְ/נָתַתִּ֥י גִשְׁמֵי/כֶ֖ם בְּ/עִתָּ֑/ם וְ/נָתְנָ֤ה הָ/אָ֨רֶץ֙ יְבוּלָ֔/הּ וְ/עֵ֥ץ הַ/שָּׂדֶ֖ה יִתֵּ֥ן פִּרְיֽ/וֹ", "en": {"kjv": "Then I will give you rain in due season, and the land shall yield her increase, and the trees of the field shall yield their fruit.", "web": "then I will give you your rains in their season, and the land shall yield its increase, and the trees of the field shall yield their fruit.", "bsb": "I will give you rains in their season, and the land will yield its produce, and the trees of the field will bear their fruit.", "asv": "then I will give your rains in their season, and the land shall yield its increase, and the trees of the field shall yield their fruit.", "ylt": "then I have given your rains in their season, and the land hath given her produce, and the tree of the field doth give its fruit;", "tyndale": "then I will sende you rayne in the ryght ceason ad youre londe shall yelde hir encrease and the trees of the felde shall geue their frute.", "dra": "And the ground shall bring forth its increase: and the trees shall be filled with fruit.", "bbe": "Then I will give you rain at the right time, and the land will give her increase and the trees of the field will give their fruit;", "geneva": "I will then sende you raine in due season, and the land shall yelde her increase, and the trees of the fielde shall giue her fruite.", "wycliffe": "and the erthe schal brynge forth his fruyt, and trees schulen be fillid with applis;", "rotherham": "Then will I give your rains in their season,—And the land shall yield her increase, And, the trees of the field, shall yield their fruit.", "darby": "then I will give your rain in the season thereof, and the land shall yield its produce, and the trees of the field shall yield their fruit;", "twenty": "", "jps": "then I will give your rains in their season, and the land shall yield her produce, and the trees of the field shall yield their fruit.", "acv": "then I will give your rains in their season, and the land shall yield its increase, and the trees of the field shall yield their fruit.", "anderson": "", "haweis": "", "noyes": "", "webster": "Then I will give you rain in due season, and the land shall yield her increase, and the trees of the field shall yield their fruit:", "vulgate": "et terra gignet germen suum et pomis arbores replebuntur;", "brenton": "then will I give you the rain in its season, and the land shall produce its fruits, and the trees of the field shall yield their fruit."}}, {"v": 5, "ref": "26:5", "o": "וְ/הִשִּׂ֨יג לָ/כֶ֥ם דַּ֨יִשׁ֙ אֶת בָּצִ֔יר וּ/בָצִ֖יר יַשִּׂ֣יג אֶת זָ֑רַע וַ/אֲכַלְתֶּ֤ם לַחְמְ/כֶם֙ לָ/שֹׂ֔בַע וִֽ/ישַׁבְתֶּ֥ם לָ/בֶ֖טַח בְּ/אַרְצְ/כֶֽם", "en": {"kjv": "And your threshing shall reach unto the vintage, and the vintage shall reach unto the sowing time: and ye shall eat your bread to the full, and dwell in your land safely.", "web": "Your threshing shall reach to the vintage, and the vintage shall reach to the sowing time. You shall eat your bread to the full, and dwell in your land safely.", "bsb": "Your threshing will continue until the grape harvest, and the grape harvest will continue until sowing time; you will have your fill of food to eat and will dwell securely in your land.", "asv": "And your threshing shall reach unto the vintage, and the vintage shall reach unto the sowing time; and ye shall eat your bread to the full, and dwell in your land safely.", "ylt": "and reached to you hath the threshing, the gathering, and the gathering doth reach the sowing- time ; and ye have eaten your bread to satiety, and have dwelt confidently in your land.", "tyndale": "And the threshynge shall reach vnto wyne haruest and the wyneharuest shall reach vnto sowyng tyme and ye shall eate youre bred in plenteousnes and shall dwell in youre lande peasably.", "dra": "The threshing of your harvest shall reach unto the vintage, and the vintage shall reach unto the sowing time: and you shall eat your bread to the full, and dwell in your land without fear.", "bbe": "And the crushing of the grain will overtake the cutting of the grapes, and the cutting of the grapes will overtake the planting of the seed, and there will be bread in full measure, and you will be living in your land safely.", "geneva": "And your threshing shall reache vnto the vintage, and the vintage shall reache vnto sowing time, and you shall eate your bread in plenteousnesse, and dwell in your land safely.", "wycliffe": "the threschyng of ripe cornes schal take vyndage, and vyndage schal occupie seed, and ye schulen ete youre breed in fulnesse, and ye schulen dwelle in youre lond without drede.", "rotherham": "Then shall your threshing reach unto the vintage, And, the vintage, shall reach unto the seedtime,—And ye shall eat your food to the full, And shall dwell securely in your land.", "darby": "and your threshing shall reach unto the vintage, and the vintage shall reach unto the sowing-time; and ye shall eat your bread to the full, and dwell in your land securely.", "twenty": "", "jps": "And your threshing shall reach unto the vintage, and the vintage shall reach unto the sowing time; and ye shall eat your bread until ye have enough, and dwell in your land safely.", "acv": "And your threshing shall reach to the vintage, and the vintage shall reach to the sowing time, and ye shall eat your bread to the full, and dwell in your land safely.", "anderson": "", "haweis": "", "noyes": "", "webster": "And your threshing shall reach to the vintage, and the vintage shall reach to the sowing time; and ye shall eat your bread to the full, and dwell in your land safely.", "vulgate": "adprehendet messium tritura vindemiam et vindemia occupabit sementem et comedetis panem vestrum in saturitatem et absque pavore habitabitis in terra vestra;", "brenton": "And your threshing time shall overtake the vintage, and your vintage shall overtake your seed time; and ye shall eat your bread to the full; and ye shall dwell safely upon your land, and war shall not go through your land."}}, {"v": 6, "ref": "26:6", "o": "וְ/נָתַתִּ֤י שָׁלוֹם֙ בָּ/אָ֔רֶץ וּ/שְׁכַבְתֶּ֖ם וְ/אֵ֣ין מַחֲרִ֑יד וְ/הִשְׁבַּתִּ֞י חַיָּ֤ה רָעָה֙ מִן הָ/אָ֔רֶץ וְ/חֶ֖רֶב לֹא תַעֲבֹ֥ר בְּ/אַרְצְ/כֶֽם", "en": {"kjv": "And I will give peace in the land, and ye shall lie down, and none shall make you afraid: and I will rid evil beasts out of the land, neither shall the sword go through your land.", "web": "“‘I will give peace in the land, and you shall lie down, and no one will make you afraid. I will remove evil animals out of the land, neither shall the sword go through your land.", "bsb": "And I will give peace to the land, and you will lie down with nothing to fear. I will rid the land of dangerous animals, and no sword will pass through your land.", "asv": "And I will give peace in the land, and ye shall lie down, and none shall make you afraid: and I will cause evil beasts to cease out of the land, neither shall the sword go through your land.", "ylt": "`And I have given peace in the land, and ye have lain down, and there is none causing trembling; and I have caused evil beasts to cease out of the land, and the sword doth not pass over into your land.", "tyndale": "And I wil sende peace in youre londe that ye shall slepe, and no man shal make you afrayde. And I will ryd euell beestes out of youre londe, and there shall no swerde goo thorowe out youre lande.", "dra": "I will give peace in your coasts: you shall sleep, and there shall be none to make you afraid. I will take away evil beasts: and the sword shall not pass through your quarters.", "bbe": "And I will give you peace in the land, and you will take your rest and no one will give you cause for fear; and I will put an end to all evil beasts in the land, and no sword of war will go through your land.", "geneva": "And I will sende peace in the land, and ye shall sleepe and none shall make you afraid: also I will rid euill beastes out of the lande, and the sworde shall not go through your lande.", "wycliffe": "Y schal yyue pees in youre coostis; ye schulen slepe, and noon schal be that schal make you aferd; Y schal do awei yuel beestis fro you, and a swerd schal not passe bi youre termes.", "rotherham": "And I will give peace in the land, And ye shall lie down, and nothing shall make you afraid; And I will take away vicious beasts out of the land; And, the sword, shall not go through your land.", "darby": "And I will give peace in the land, and ye shall lie down, and none shall make you afraid; and I will put away the evil beasts out of the land; and the sword shall not go through your land.", "twenty": "", "jps": "And I will give peace in the land, and ye shall lie down, and none shall make you afraid; and I will cause evil beasts to cease out of the land, neither shall the sword go through your land.", "acv": "And I will give peace in the land, and ye shall lie down, and none shall make you afraid. And I will cause evil beasts to cease out of the land, nor shall the sword go through your land.", "anderson": "", "haweis": "", "noyes": "", "webster": "And I will give peace in the land, and ye shall lie down, and none shall make [you] afraid: and I will rid the land of evil beasts, neither shall the sword go through your land.", "vulgate": "dabo pacem in finibus vestris dormietis et non erit qui exterreat auferam malas bestias et gladius non transibit terminos vestros;", "brenton": "And I will give peace in your land, and ye shall sleep, and none shall make you afraid; and I will destroy the evil beasts out of your land,"}}, {"v": 7, "ref": "26:7", "o": "וּ/רְדַפְתֶּ֖ם אֶת אֹיְבֵי/כֶ֑ם וְ/נָפְל֥וּ לִ/פְנֵי/כֶ֖ם לֶ/חָֽרֶב", "en": {"kjv": "And ye shall chase your enemies, and they shall fall before you by the sword.", "web": "You shall chase your enemies, and they shall fall before you by the sword.", "bsb": "You will pursue your enemies, and they will fall by the sword before you.", "asv": "And ye shall chase your enemies, and they shall fall before you by the sword.", "ylt": "`And ye have pursued your enemies, and they have fallen before you by the sword;", "tyndale": "And ye shall chace youre enemyes, and they shall fall before you vppon the swerde.", "dra": "You shall pursue your enemies: and they shall fall before you.", "bbe": "And you will put to flight those who are against you, and they will be put to death by your swords.", "geneva": "Also ye shall chase your enemies, and they shall fall before you vpon the sworde.", "wycliffe": "Ye schulen pursue youre enemyes, and thei schulen falle bifor you;", "rotherham": "And ye shall chase your foes,—And they shall fall before you by the sword;", "darby": "And ye shall chase your enemies, and they shall fall before you by the sword;", "twenty": "", "jps": "And ye shall chase your enemies, and they shall fall before you by the sword.", "acv": "And ye shall chase your enemies, and they shall fall before you by the sword.", "anderson": "", "haweis": "", "noyes": "", "webster": "And ye shall chase your enemies, and they shall fall before you by the sword.", "vulgate": "persequemini inimicos vestros et corruent coram vobis;", "brenton": "and ye shall pursue your enemies, and they shall fall before you with slaughter."}}, {"v": 8, "ref": "26:8", "o": "וְ/רָדְפ֨וּ מִ/כֶּ֤ם חֲמִשָּׁה֙ מֵאָ֔ה וּ/מֵאָ֥ה מִ/כֶּ֖ם רְבָבָ֣ה יִרְדֹּ֑פוּ וְ/נָפְל֧וּ אֹיְבֵי/כֶ֛ם לִ/פְנֵי/כֶ֖ם לֶ/חָֽרֶב", "en": {"kjv": "And five of you shall chase an hundred, and an hundred of you shall put ten thousand to flight: and your enemies shall fall before you by the sword.", "web": "Five of you shall chase a hundred, and a hundred of you shall chase ten thousand; and your enemies shall fall before you by the sword.", "bsb": "Five of you will pursue a hundred, and a hundred of you will pursue ten thousand, and your enemies will fall by the sword before you.", "asv": "And five of you shall chase a hundred, and a hundred of you shall chase ten thousand; and your enemies shall fall before you by the sword.", "ylt": "and five of you have pursued a hundred, and a hundred of you do pursue a myriad; and your enemies have fallen before you by the sword.", "tyndale": "And fiue of you shall chace an hundred, and an hundred of you shall put .x. thousande to flighte, and youre enemyes shall fall before you apon the swerde.", "dra": "Five of yours shall pursue a hundred others: and a hundred of you ten thousand. Your enemies shall fall before you by the sword.", "bbe": "Then five of you will put to flight a hundred, and a hundred of you will put to flight ten thousand, and all who are against you will be put to death by your swords.", "geneva": "And fiue of you shall chase an hundreth, and an hundreth of you shall put ten thousande to flight, and your enemies shall fall before you vpon the sworde.", "wycliffe": "fyue of youre men schulen pursue an hundrid aliens, and an hundrid of you schulen pursue ten thousande; youre enemyes schulen falle bi swerd in youre siyt.", "rotherham": "And, five, of you shall chase, a hundred, And, a hundred, of you shall put ten thousand to flight,—So shall your foes fall before you, by the sword.", "darby": "and five of you shall chase a hundred, and a hundred of you shall put ten thousand to flight; and your enemies shall fall beside you by the sword.", "twenty": "", "jps": "And five of you shall chase a hundred, and a hundred of you shall chase ten thousand; and your enemies shall fall before you by the sword.", "acv": "And five of you shall chase a hundred, and a hundred of you shall chase ten thousand, and your enemies shall fall before you by the sword.", "anderson": "", "haweis": "", "noyes": "", "webster": "And five of you shall chase a hundred, and a hundred of you shall put ten thousand to flight: and your enemies shall fall before you by the sword.", "vulgate": "persequentur quinque de vestris centum alienos et centum ex vobis decem milia cadent inimici vestri in conspectu vestro gladio;", "brenton": "And five of you shall chase a hundred, and a hundred of you shall chase tens of thousands; and your enemies shall fall before you by the sword."}}, {"v": 9, "ref": "26:9", "o": "וּ/פָנִ֣יתִי אֲלֵי/כֶ֔ם וְ/הִפְרֵיתִ֣י אֶתְ/כֶ֔ם וְ/הִרְבֵּיתִ֖י אֶתְ/כֶ֑ם וַ/הֲקִימֹתִ֥י אֶת בְּרִיתִ֖/י אִתְּ/כֶֽם", "en": {"kjv": "For I will have respect unto you, and make you fruitful, and multiply you, and establish my covenant with you.", "web": "“‘I will have respect for you, and make you fruitful, and multiply you, and will establish my covenant with you.", "bsb": "I will turn toward you and make you fruitful and multiply you, and I will establish My covenant with you.", "asv": "And I will have respect unto you, and make you fruitful, and multiply you, and will establish my covenant with you.", "ylt": "`And I have turned unto you, and have made you fruitful, and have multiplied you, and have established My covenant with you;", "tyndale": "And I wil turne vnto you and encrease you and multipye you, and sett vpp my testament with you.", "dra": "I will look on you, and make you increase: you shall be multiplied, and I will establish my covenant with you.", "bbe": "And I will have pleasure in you and make you fertile and greater in number; and I will keep my agreement with you.", "geneva": "For I will haue respect vnto you, and make you encrease, and multiplie you, and establish my couenant with you.", "wycliffe": "Y schal biholde you, and Y schal make you to encreesse; ye schulen be multiplied; and Y schal make stedfast my couenaunt with you;", "rotherham": "And I will turn unto you, And make you fruitful,—And multiply you, And will establish my covenant with you.", "darby": "And I will turn my face towards you and make you fruitful, and multiply you, and establish my covenant with you.", "twenty": "", "jps": "And I will have respect unto you, and make you fruitful, and multiply you; and will establish My covenant with you.", "acv": "And I will have respect to you, and make you fruitful, and multiply you, and will establish my covenant with you.", "anderson": "", "haweis": "", "noyes": "", "webster": "For I will have respect to you, and make you fruitful, and multiply you, and establish my covenant with you.", "vulgate": "respiciam vos et crescere faciam multiplicabimini et firmabo pactum meum vobiscum;", "brenton": "And I will look upon you, and increase you, and multiply you, and establish my covenant with you."}}, {"v": 10, "ref": "26:10", "o": "וַ/אֲכַלְתֶּ֥ם יָשָׁ֖ן נוֹשָׁ֑ן וְ/יָשָׁ֕ן מִ/פְּנֵ֥י חָדָ֖שׁ תּוֹצִֽיאוּ", "en": {"kjv": "And ye shall eat old store, and bring forth the old because of the new.", "web": "You shall eat old store long kept, and you shall move out the old because of the new.", "bsb": "You will still be eating the old supply of grain when you need to clear it out to make room for the new.", "asv": "And ye shall eat old store long kept, and ye shall bring forth the old because of the new.", "ylt": "and ye have eaten old store , and the old because of the new ye bring out.", "tyndale": "And ye shall eate olde store, ad cast out the olde for plentuousnes of the newe.", "dra": "You shall eat the oldest of the old store: and, new coming on, you shall cast away the old.", "bbe": "And old stores long kept will be your food, and you will take out the old because of the new;", "geneva": "Ye shall eate also olde store, and cary out olde because of the newe.", "wycliffe": "ye schulen ete the eldest of elde thingis, and ye schulen caste forth elde thingis, whanne newe thingis schulen come aboue;", "rotherham": "And ye shall eat old store well seasoned,—And the old from before the new, shall ye put forth.", "darby": "And ye shall eat old store, and clear away the old because of the new.", "twenty": "", "jps": "And ye shall eat old store long kept, and ye shall bring forth the old from before the new.", "acv": "And ye shall eat old storage long kept, and ye shall bring forth the old because of the new.", "anderson": "", "haweis": "", "noyes": "", "webster": "And ye shall eat old store, and bring forth the old because of the new.", "vulgate": "comedetis vetustissima veterum et vetera novis supervenientibus proicietis;", "brenton": "And ye shall eat that which is old and very old, and bring forth the old to make way for the new."}}, {"v": 11, "ref": "26:11", "o": "וְ/נָתַתִּ֥י מִשְׁכָּנִ֖/י בְּ/תוֹכְ/כֶ֑ם וְ/לֹֽא תִגְעַ֥ל נַפְשִׁ֖/י אֶתְ/כֶֽם", "en": {"kjv": "And I will set my tabernacle among you: and my soul shall not abhor you.", "web": "I will set my tent among you, and my soul won’t abhor you.", "bsb": "And I will make My dwelling place among you, and My soul will not despise you.", "asv": "And I will set my tabernacle among you: and my soul shall not abhor you.", "ylt": "`And I have given My tabernacle in your midst, and My soul doth not loathe you;", "tyndale": "I will make my dwellynge place amonge you, and my soule shall not loothe you.", "dra": "I will set my tabernacle in the midst of you: and my soul shall not cast you off.", "bbe": "And I will put my holy House among you, and my soul will not be turned away from you in disgust.", "geneva": "And I will set my Tabernacle among you, and my soule shall not lothe you.", "wycliffe": "Y schal sette my tabernacle in the myddis of you, and my soule schal not caste you awey;", "rotherham": "And I will set my habitation in your midst,—And my soul shall not abhor you;", "darby": "And I will set my habitation among you; and my soul shall not abhor you;", "twenty": "", "jps": "And I will set My tabernacle among you, and My soul shall not abhor you.", "acv": "And I will set my tabernacle among you, and my soul shall not abhor you.", "anderson": "", "haweis": "", "noyes": "", "webster": "And I will set my tabernacle among you: and my soul shall not abhor you.", "vulgate": "ponam tabernaculum meum in medio vestri et non abiciet vos anima mea;", "brenton": "And I will set my tabernacle among you, and my soul shall not abhor you;"}}, {"v": 12, "ref": "26:12", "o": "וְ/הִתְהַלַּכְתִּי֙ בְּ/ת֣וֹכְ/כֶ֔ם וְ/הָיִ֥יתִי לָ/כֶ֖ם לֵֽ/אלֹהִ֑ים וְ/אַתֶּ֖ם תִּהְיוּ לִ֥/י לְ/עָֽם", "en": {"kjv": "And I will walk among you, and will be your God, and ye shall be my people.", "web": "I will walk among you, and will be your God, and you will be my people.", "bsb": "I will walk among you and be your God, and you will be My people.", "asv": "And I will walk among you, and will be your God, and ye shall be my people.", "ylt": "and I have walked habitually in your midst, and have become your God, and ye--ye are become My people;", "tyndale": "And I will walke amonge you and wilbe youre God, and ye shalbe my people.", "dra": "I will walk among you, and will be your God: and you shall be my people.", "bbe": "And I will be present among you and will be your God and you will be my people.", "geneva": "Also I will walke among you, and I wil be your God, and ye shalbe my people.", "wycliffe": "Y schal go among you, and Y schal be youre God, and ye schulen be a puple to me.", "rotherham": "But I will walk to and fro in your midst, And will be unto you a God, And, ye, shall be unto me a people.", "darby": "and I will walk among you, and will be yourGod, and ye shall be to me a people.", "twenty": "", "jps": "And I will walk among you, and will be your G-d, and ye shall be My people.", "acv": "And I will walk among you, and will be your God, and ye shall be my people.", "anderson": "", "haweis": "", "noyes": "", "webster": "And I will walk among you, and will be your God, and ye shall be my people.", "vulgate": "ambulabo inter vos et ero vester Deus vosque eritis populus meus;", "brenton": "and I will walk among you, and be your God, and ye shall be my people."}}, {"v": 13, "ref": "26:13", "o": "אֲנִ֞י יְהוָ֣ה אֱלֹֽהֵי/כֶ֗ם אֲשֶׁ֨ר הוֹצֵ֤אתִי אֶתְ/כֶם֙ מֵ/אֶ֣רֶץ מִצְרַ֔יִם מִֽ/הְיֹ֥ת לָ/הֶ֖ם עֲבָדִ֑ים וָ/אֶשְׁבֹּר֙ מֹטֹ֣ת עֻלְּ/כֶ֔ם וָ/אוֹלֵ֥ךְ אֶתְ/כֶ֖ם קֽוֹמְמִיּֽוּת", "en": {"kjv": "I am the Lord your God, which brought you forth out of the land of Egypt, that ye should not be their bondmen; and I have broken the bands of your yoke, and made you go upright.", "web": "I am Yahweh your God, who brought you out of the land of Egypt, that you should not be their slaves. I have broken the bars of your yoke, and made you go upright.", "bsb": "I am the LORD your God, who brought you out of the land of Egypt so that you would no longer be slaves to the Egyptians. I broke the bars of your yoke and enabled you to walk in uprightness.", "asv": "I am Jehovah your God, who brought you forth out of the land of Egypt, that ye should not be their bondmen; and I have broken the bars of your yoke, and made you go upright.", "ylt": "I am Jehovah your God, who have brought you out of the land of the Egyptians, from being their servants; and I break the bars of your yoke, and cause you to go erect.", "tyndale": "For I am the Lorde youre God, whiche broughte you out off the lande of the Egiptians, that ye shulde not be their bondemen, and I brake the bowes of youre yockes, and made you go vprighte.", "dra": "I am the Lord your God: who have brought you out of the land of the Egyptians, that you should not serve them: and who have broken the chains of your necks, that you might go upright.", "bbe": "I am the Lord your God, who took you out of the land of Egypt so that you might not be servants to them; by me the cords of your yoke were broken and I made you go upright.", "geneva": "I am the Lord your God which haue brought you out of the lande of Egypt, that yee should not be their bondmen, and I haue broken ye bonds of your yoke, and made you goe vpright.", "wycliffe": "Y am youre Lord God, that ledde you out of the lond of Egipcians, that ye schulden not serue hem, and which haue broke the chaynes of youre nollis, that ye schulde go vpriyt.", "rotherham": "I—Yahweh, am your God who brought you forth out of the land of Egypt, that ye should not be their bondmen; so I brake in pieces the staves of your yoke, and caused you to walk, erect.", "darby": "I am Jehovah yourGod, who brought you forth out of the land of Egypt, that ye should not be their bondmen; and I have broken the bands of your yoke, and made you walk upright.", "twenty": "", "jps": "I am HaShem your G-d, who brought you forth out of the land of Egypt, that ye should not be their bondmen; and I have broken the bars of your yoke, and made you go upright.", "acv": "I am Jehovah your God, who brought you forth out of the land of Egypt, that ye should not be their bondmen. And I have broken the bars of your yoke, and made you go upright.", "anderson": "", "haweis": "", "noyes": "", "webster": "I [am] the LORD your God, who brought you out of the land of Egypt, that ye should not be their bond-men, and I have broken the bands of your yoke, and made you go upright.", "vulgate": "ego Dominus Deus vester qui eduxi vos de terra Aegyptiorum ne serviretis eis et qui confregi catenas cervicum vestrarum ut incederetis erecti;", "brenton": "I am the Lord your God, who brought you out of the land of Egypt, where ye were slaves; and I broke the band of your yoke, and brought you forth openly."}}, {"v": 14, "ref": "26:14", "o": "וְ/אִם לֹ֥א תִשְׁמְע֖וּ לִ֑/י וְ/לֹ֣א תַעֲשׂ֔וּ אֵ֥ת כָּל הַ/מִּצְוֺ֖ת הָ/אֵֽלֶּה", "en": {"kjv": "But if ye will not hearken unto me, and will not do all these commandments;", "web": "“‘But if you will not listen to me, and will not do all these commandments;", "bsb": "If, however, you fail to obey Me and to carry out all these commandments,", "asv": "But if ye will not hearken unto me, and will not do all these commandments;", "ylt": "`And if ye do not hearken to Me, and do not all these commands;", "tyndale": "But and yf ye will not harken vnto me, nor will do all these my commaundementes,", "dra": "But if you will not hear me, nor do all my commandments:", "bbe": "But if you do not give ear to me, and do not keep all these my laws;", "geneva": "But if ye will not obey me, nor do all these commandements,", "wycliffe": "That if ye heren not me, nether doon alle myn heestis,", "rotherham": "But, if ye will not hearken unto me, And will not do all these commandments;", "darby": "But if ye hearken not unto me, and do not all these commandments,", "twenty": "", "jps": "But if ye will not hearken unto Me, and will not do all these commandments;", "acv": "But if ye will not hearken to me, and will not do all these commandments,", "anderson": "", "haweis": "", "noyes": "", "webster": "But if ye will not hearken to me, and will not do all these commandments;", "vulgate": "quod si non audieritis me nec feceritis omnia mandata mea;", "brenton": "But if ye will not hearken to me, nor obey these my ordinances,"}}, {"v": 15, "ref": "26:15", "o": "וְ/אִם בְּ/חֻקֹּתַ֣/י תִּמְאָ֔סוּ וְ/אִ֥ם אֶת מִשְׁפָּטַ֖/י תִּגְעַ֣ל נַפְשְׁ/כֶ֑ם לְ/בִלְתִּ֤י עֲשׂוֹת֙ אֶת כָּל מִצְוֺתַ֔/י לְ/הַפְרְ/כֶ֖ם אֶת בְּרִיתִֽ/י", "en": {"kjv": "And if ye shall despise my statutes, or if your soul abhor my judgments, so that ye will not do all my commandments, but that ye break my covenant:", "web": "and if you shall reject my statutes, and if your soul abhors my ordinances, so that you will not do all my commandments, but break my covenant;", "bsb": "and if you reject My statutes, despise My ordinances, and neglect to carry out all My commandments, and so break My covenant,", "asv": "and if ye shall reject my statutes, and if your soul abhor mine ordinances, so that ye will not do all my commandments, but break my covenant;", "ylt": "and if at My statutes ye kick, and if My judgments your soul loathe, so as not to do all My commands--to your breaking My covenant--", "tyndale": "or yf ye shall despyse myne ordinaunces ether yf youre soules refuse my lawes, so that ye wil not do all my commaundnentes, but shall breake myne appoyntment:", "dra": "If you despise my laws, and contemn my judgments so as not to do those things which are appointed by me, and to make void my covenant:", "bbe": "And if you go against my rules and if you have hate in your souls for my decisions and you do not do all my orders, but go against my agreement;", "geneva": "And if ye shall despise mine ordinances, either if your soule abhorre my lawes, so that yee will not do all my commandements, but breake my couenant,", "wycliffe": "and if ye forsaken my lawis, and despisen my domes, that ye doon not tho thingis that ben ordeyned of me, and that ye brengen my couenaunt to auoydyng, also Y schal do these thingis to you;", "rotherham": "And if, my statutes, ye refuse, And, my regulations, your souls shall abhor,—So that ye will not do all my commandments, But shall break my covenant", "darby": "and if ye shall despise my statutes, and if your soul shall abhor mine ordinances, so that ye do not all my commandments, that ye break my covenant,", "twenty": "", "jps": "and if ye shall reject My statutes, and if your soul abhor Mine ordinances, so that ye will not do all My commandments, but break My covenant;", "acv": "and if ye shall reject my statutes, and if your soul abhors my ordinances, so that ye will not do all my commandments, but break my covenant,", "anderson": "", "haweis": "", "noyes": "", "webster": "And if ye shall despise my statutes, or if your soul shall abhor my judgments, so that ye will not do all my commandments, [but] that ye break my covenant:", "vulgate": "si spreveritis leges meas et iudicia mea contempseritis ut non faciatis ea quae a me constituta sunt et ad irritum perducatis pactum meum;", "brenton": "but disobey them, and your soul should loathe my judgments, so that ye should not keep all my commands, so as to break my covenant,"}}, {"v": 16, "ref": "26:16", "o": "אַף אֲנִ֞י אֶֽעֱשֶׂה זֹּ֣את לָ/כֶ֗ם וְ/הִפְקַדְתִּ֨י עֲלֵי/כֶ֤ם בֶּֽהָלָה֙ אֶת הַ/שַּׁחֶ֣פֶת וְ/אֶת הַ/קַּדַּ֔חַת מְכַלּ֥וֹת עֵינַ֖יִם וּ/מְדִיבֹ֣ת נָ֑פֶשׁ וּ/זְרַעְתֶּ֤ם לָ/רִיק֙ זַרְעֲ/כֶ֔ם וַ/אֲכָלֻ֖/הוּ אֹיְבֵי/כֶֽם", "en": {"kjv": "I also will do this unto you; I will even appoint over you terror, consumption, and the burning ague, that shall consume the eyes, and cause sorrow of heart: and ye shall sow your seed in vain, for your enemies shall eat it.", "web": "I also will do this to you: I will appoint terror over you, even consumption and fever, that shall consume the eyes, and make the soul to pine away. You will sow your seed in vain, for your enemies will eat it.", "bsb": "then this is what I will do to you: I will bring upon you sudden terror, wasting disease, and fever that will destroy your sight and drain your life. You will sow your seed in vain, because your enemies will eat it.", "asv": "I also will do this unto you: I will appoint terror over you, even consumption and fever, that shall consume the eyes, and make the soul to pine away; and ye shall sow your seed in vain, for your enemies shall eat it.", "ylt": "I also do this to you, and I have appointed over you trouble, the consumption, and the burning fever, consuming eyes, and causing pain of soul; and your seed in vain ye have sowed, and your enemies have eaten it;", "tyndale": "then I will do this agayne vnto you: I will viset you with vexations, swellynge and feuers, that shall make youre eyes dasell and with sorowes of herte. And ye shall sowe youre seed in vayne, for youre enemyes shall eate it.", "dra": "I also will do these things to you. I will quickly visit you with poverty, and burning heat, which shall waste your eyes, and consume your lives. You shall sow your seed in vain, which shall be devoured by your enemies.", "bbe": "This will I do to you: I will put fear in your hearts, even wasting disease and burning pain, drying up the eyes and making the soul feeble, and you will get no profit from your seed, for your haters will take it for food.", "geneva": "Then wil I also do this vnto you, I wil appoint ouer you fearefulnes, a consumption, and the burning ague to consume the eyes, and make the heart heauie, and you shall sowe your seede in vaine: for your enemies shall eate it:", "wycliffe": "Y schal visyte you swiftly in nedynesse and brennyng, which schal turment youre iyen, and schal waste youre lyues; in veyn ye schulen sowe seed, that schal be deuourid of enemyes;", "rotherham": "I also, will do this unto you—I will set over you, for terror, consumption and fever, Causing the eyes to fail and the soul to pine away,—And ye shall sow, in vain, your seed, for it shall be eaten by your foes.", "darby": "I also will do this unto you — I will even appoint over you terror, consumption, and fever, which shall cause the eyes to fail, and the soul to waste away; and ye shall sow your seed in vain, for your enemies shall eat it.", "twenty": "", "jps": "I also will do this unto you: I will appoint terror over you, even consumption and fever, that shall make the eyes to fail, and the soul to languish; and ye shall sow your seed in vain, for your enemies shall eat it.", "acv": "I also will do this to you: I will appoint terror over you, even consumption and fever, that shall consume the eyes, and make the soul to pine away. And ye shall sow your seed in vain, for your enemies shall eat it.", "anderson": "", "haweis": "", "noyes": "", "webster": "I also will do this to you, I will even appoint over you terror, consumption, and the burning ague, that shall consume the eyes, and cause sorrow of heart: and ye shall sow your seed in vain, for your enemies shall eat it.", "vulgate": "ego quoque haec faciam vobis visitabo vos velociter in egestate et ardore qui conficiat oculos vestros et consumat animas frustra seretis sementem quae ab hostibus devorabitur;", "brenton": "then will I do thus to you: I will even bring upon you perplexity and the itch, and the fever that causes your eyes to waste away, and disease that consumes your life; and ye shall sow your seeds in vain, and your enemies shall eat them."}}, {"v": 17, "ref": "26:17", "o": "וְ/נָתַתִּ֤י פָנַ/י֙ בָּ/כֶ֔ם וְ/נִגַּפְתֶּ֖ם לִ/פְנֵ֣י אֹיְבֵי/כֶ֑ם וְ/רָד֤וּ בָ/כֶם֙ שֹֽׂנְאֵי/כֶ֔ם וְ/נַסְתֶּ֖ם וְ/אֵין רֹדֵ֥ף אֶתְ/כֶֽם", "en": {"kjv": "And I will set my face against you, and ye shall be slain before your enemies: they that hate you shall reign over you; and ye shall flee when none pursueth you.", "web": "I will set my face against you, and you will be struck before your enemies. Those who hate you will rule over you; and you will flee when no one pursues you.", "bsb": "And I will set My face against you, so that you will be defeated by your enemies. Those who hate you will rule over you, and you will flee when no one pursues you.", "asv": "And I will set my face against you, and ye shall be smitten before your enemies: they that hate you shall rule over you; and ye shall flee when none pursueth you.", "ylt": "and I have set My face against you, and ye have been smitten before your enemies; and those hating you have ruled over you, and ye have fled, and there is none pursuing you.", "tyndale": "And I will set my face agenste you and ye shal fall before youre enemyes, and they that hate you shal raigne ouer you, ad ye shall flee whe no man foloweth you.", "dra": "I will set my face against you, and you shall fall down before your enemies: and shall be made subject to them that hate you. You shall flee when no man pursueth you.", "bbe": "And my face will be turned from you, and you will be broken before those who are against you, and your haters will become your rulers, and you will go in flight when no man comes after you.", "geneva": "And I will set my face against you, and ye shall fal before your enemies, and they that hate you, shall raigne ouer you, and yee shall flee when none pursueth you.", "wycliffe": "Y schal sette my face ayens you, and ye schulen falle bifor youre enemyes, and ye schulen be sugetis to hem that haten you; ye schulen fle, while no man pursueth.", "rotherham": "And I will set my face against you, And ye shall be smitten before your foes,-And be trodden down by them who hate you, And shall flee when no one is pursuing you.", "darby": "And I will set my face against you, that ye may be routed before your enemies; they that hate you shall have dominion over you; and ye shall flee when none pursueth you.", "twenty": "", "jps": "And I will set My face against you, and ye shall be smitten before your enemies; they that hate you shall rule over you; and ye shall flee when none pursueth you.", "acv": "And I will set my face against you, and ye shall be smitten before your enemies. Those who hate you shall rule over you, and ye shall flee when no man pursues you.", "anderson": "", "haweis": "", "noyes": "", "webster": "And I will set my face against you, and ye shall be slain before your enemies: they that hate you shall reign over you, and ye shall flee when none pursueth you.", "vulgate": "ponam faciem meam contra vos et corruetis coram hostibus vestris et subiciemini his qui oderunt vos fugietis nemine persequente;", "brenton": "And I will set my face against you, and ye shall fall before your enemies, and they that hate you shall pursue you; and ye shall flee, no one pursuing you."}}, {"v": 18, "ref": "26:18", "o": "וְ/אִ֨ם עַד אֵ֔לֶּה לֹ֥א תִשְׁמְע֖וּ לִ֑/י וְ/יָסַפְתִּי֙ לְ/יַסְּרָ֣ה אֶתְ/כֶ֔ם שֶׁ֖בַע עַל חַטֹּאתֵי/כֶֽם", "en": {"kjv": "And if ye will not yet for all this hearken unto me, then I will punish you seven times more for your sins.", "web": "“‘If you in spite of these things will not listen to me, then I will chastise you seven times more for your sins.", "bsb": "And if after all this you will not obey Me, I will proceed to punish you sevenfold for your sins.", "asv": "And if ye will not yet for these things hearken unto me, then I will chastise you seven times more for your sins.", "ylt": "`And if unto these ye hearken not to Me, --then I have added to chastise you seven times for your sins;", "tyndale": "And yf ye will not yet for all this herken vnto me, than will I punish you seuen tymes more for youre synnes,", "dra": "But if you will not yet for all this obey me: I will chastise you seven times more for your sins.", "bbe": "And if, even after these things, you will not give ear to me, then I will send you punishment seven times more for your sins.", "geneva": "And if ye wil not for these things obey me, then wil I punish you seuen times more, according to your sinnes,", "wycliffe": "But if nether so ye obeyen to me, Y schal adde youre chastisyngis seuenfold for youre synnes;", "rotherham": "And, if even with these things, ye will not hearken unto me, Then will I yet further correct you seven times, for your sins.", "darby": "And if for this ye hearken not unto me, I will punish you sevenfold more for your sins,", "twenty": "", "jps": "And if ye will not yet for these things hearken unto Me, then I will chastise you seven times more for your sins.", "acv": "And if for these things ye will not yet hearken to me, then I will chastise you seven times more for your sins.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if ye will not yet for all this hearken to me, then I will punish you seven times more for your sins.", "vulgate": "sin autem nec sic oboedieritis mihi addam correptiones vestras septuplum propter peccata vestra;", "brenton": "And if ye still refuse to hearken to me, then will I chasten you yet more even seven times for your sins."}}, {"v": 19, "ref": "26:19", "o": "וְ/שָׁבַרְתִּ֖י אֶת גְּא֣וֹן עֻזְּ/כֶ֑ם וְ/נָתַתִּ֤י אֶת שְׁמֵי/כֶם֙ כַּ/בַּרְזֶ֔ל וְ/אֶֽת אַרְצְ/כֶ֖ם כַּ/נְּחֻשָֽׁה", "en": {"kjv": "And I will break the pride of your power; and I will make your heaven as iron, and your earth as brass:", "web": "I will break the pride of your power, and I will make your sky like iron, and your soil like brass.", "bsb": "I will break down your stubborn pride and make your sky like iron and your land like bronze,", "asv": "And I will break the pride of your power: and I will make your heaven as iron, and your earth as brass;", "ylt": "and I have broken the pride of your strength, and have made your heavens as iron, and your earth as brass;", "tyndale": "and will breake the pride off youre strength. For I will make the heaue ouer you as harde as yerne, and youre londe as hard as brasse.", "dra": "And I will break the pride of your stubbornness: and I will make to you the heaven above as iron, and the earth as brass.", "bbe": "And the pride of your strength will be broken, and I will make your heaven as iron and your earth as brass;", "geneva": "And I wil breake the pride of your power, and I will make your heauen as yron, and your earth as brasse:", "wycliffe": "and Y schal al tobreke the pride of youre hardnesse, and Y schal yyue to you heuene aboue as of yrun, and the erthe as bras;", "rotherham": "So will I break your pomp of power, And will set your heavens as iron, and your land as bronze;", "darby": "and I will break the arrogance of your power; and I will make your heaven as iron, and your earth as bronze,", "twenty": "", "jps": "And I will break the pride of your power; and I will make your heaven as iron, and your earth as brass.", "acv": "And I will break the pride of your power. And I will make your sky as iron, and your earth as brass,", "anderson": "", "haweis": "", "noyes": "", "webster": "And I will break the pride of your power; and I will make your heaven as iron, and your earth as brass:", "vulgate": "et conteram superbiam duritiae vestrae daboque caelum vobis desuper sicut ferrum et terram aeneam;", "brenton": "And I will break down the haughtiness of your pride; and I will make your heaven iron, and your earth as it were brass."}}, {"v": 20, "ref": "26:20", "o": "וְ/תַ֥ם לָ/רִ֖יק כֹּחֲ/כֶ֑ם וְ/לֹֽא תִתֵּ֤ן אַרְצְ/כֶם֙ אֶת יְבוּלָ֔/הּ וְ/עֵ֣ץ הָ/אָ֔רֶץ לֹ֥א יִתֵּ֖ן פִּרְיֽ/וֹ", "en": {"kjv": "And your strength shall be spent in vain: for your land shall not yield her increase, neither shall the trees of the land yield their fruits.", "web": "Your strength will be spent in vain; for your land won’t yield its increase, neither will the trees of the land yield their fruit.", "bsb": "and your strength will be spent in vain. For your land will not yield its produce, and the trees of the land will not bear their fruit.", "asv": "and your strength shall be spent in vain; for your land shall not yield its increase, neither shall the trees of the land yield their fruit.", "ylt": "and consumed hath been your strength in vain, and your land doth not give her produce, and the tree of the land doth not give its fruit.", "tyndale": "And so youre laboure shalbe spent in vayne. For youre londe shall not geue hir encrease, nether the trees of the londe shall geue their frutes.", "dra": "Your labour shall be spent in vain: the ground shall not bring forth her increase: nor the trees yield their fruit.", "bbe": "And your strength will be used up without profit; for your land will not give her increase and the trees of the field will not give their fruit.", "geneva": "And your strength shalbe spent in vaine: neither shall your lande giue her increase, neither shall the trees of the land giue their fruite.", "wycliffe": "youre trauel schal be wastid in veyn, nether the erthe schal brynge forth fruyt, nethir trees schulen yyue applis.", "rotherham": "And your strength shall be spent in vain,—And your land shall not yield her increase, And the trees of the land, shall not yield their fruit.", "darby": "and your strength shall be spent in vain, and your land shall not yield its produce; and the trees of the land shall not yield their fruit.", "twenty": "", "jps": "And your strength shall be spent in vain; for your land shall not yield her produce, neither shall the trees of the land yield their fruit.", "acv": "and your strength shall be spent in vain, for your land shall not yield its increase, nor shall the trees of the land yield their fruit.", "anderson": "", "haweis": "", "noyes": "", "webster": "And your strength shall be spent in vain: for your land shall not yield her increase, neither shall the trees of the land yield their fruits.", "vulgate": "consumetur in cassum labor vester non proferet terra germen nec arbores poma praebebunt;", "brenton": "And your strength shall be in vain; and your land shall not yield its seed, and the tree of your field shall not yield its fruit."}}, {"v": 21, "ref": "26:21", "o": "וְ/אִם תֵּֽלְכ֤וּ עִמִּ/י֙ קֶ֔רִי וְ/לֹ֥א תֹאב֖וּ לִ/שְׁמֹ֣עַֽ לִ֑/י וְ/יָסַפְתִּ֤י עֲלֵי/כֶם֙ מַכָּ֔ה שֶׁ֖בַע כְּ/חַטֹּאתֵי/כֶֽם", "en": {"kjv": "And if ye walk contrary unto me, and will not hearken unto me; I will bring seven times more plagues upon you according to your sins.", "web": "“‘If you walk contrary to me, and won’t listen to me, then I will bring seven times more plagues on you according to your sins.", "bsb": "If you walk in hostility toward Me and refuse to obey Me, I will multiply your plagues seven times, according to your sins.", "asv": "And if ye walk contrary unto me, and will not hearken unto me, I will bring seven times more plagues upon you according to your sins.", "ylt": "`And if ye walk with Me in opposition, and are not willing to hearken to Me, then I have added to you a plague seven times, according to your sins,", "tyndale": "And yf ye walke contrary vnto me and will not herken vnto me, I will bringe seuen tymes moo plages apon you acordinge to your synnnes.", "dra": "If you walk contrary to me, and will not hearken to me, I will bring seven times more plagues upon you for your sins.", "bbe": "And if you still go against me and will not give ear to me, I will put seven times more punishments on you because of your sins.", "geneva": "And if ye walke stubburnly against me, and will not obey mee, I will then bring seuen times more plagues vpon you, according to your sinnes.", "wycliffe": "If ye goon contrarie to me, nether wolen here me, Y schal adde youre woundis til in to seuenfold for youre synnes;", "rotherham": "If therefore, ye will go in opposition to me, And not be willing to hearken unto me, Then will I yet further plague you seven times according to your sins;", "darby": "And if ye walk contrary unto me, and will not hearken unto me, I will bring sevenfold more plagues upon you according to your sins.", "twenty": "", "jps": "And if ye walk contrary unto Me, and will not hearken unto Me; I will bring seven times more plagues upon you according to your sins.", "acv": "And if ye walk contrary to me, and will not hearken to me, I will bring seven times more plagues upon you according to your sins.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if ye shall walk contrary to me, and will not hearken to me, I will bring seven times more plagues upon you according to your sins.", "vulgate": "si ambulaveritis ex adverso mihi nec volueritis audire me addam plagas vestras usque in septuplum propter peccata vestra;", "brenton": "And if after this ye should walk perversely, and not be willing to obey me, I will further bring upon you seven plagues according to your sins."}}, {"v": 22, "ref": "26:22", "o": "וְ/הִשְׁלַחְתִּ֨י בָ/כֶ֜ם אֶת חַיַּ֤ת הַ/שָּׂדֶה֙ וְ/שִׁכְּלָ֣ה אֶתְ/כֶ֔ם וְ/הִכְרִ֨יתָה֙ אֶת בְּהֶמְתְּ/כֶ֔ם וְ/הִמְעִ֖יטָה אֶתְ/כֶ֑ם וְ/נָשַׁ֖מּוּ דַּרְכֵי/כֶֽם", "en": {"kjv": "I will also send wild beasts among you, which shall rob you of your children, and destroy your cattle, and make you few in number; and your high ways shall be desolate.", "web": "I will send the wild animals among you, which will rob you of your children, destroy your livestock, and make you few in number. Your roads will become desolate.", "bsb": "I will send wild animals against you to rob you of your children, destroy your livestock, and reduce your numbers, until your roads lie desolate.", "asv": "And I will send the beast of the field among you, which shall rob you of your children, and destroy your cattle, and make you few in number; and your ways shall become desolate.", "ylt": "and sent against you the beast of the field, and it hath bereaved you; and I have cut off your cattle, and have made you few, and your ways have been desolate.", "tyndale": "I will sende in wylde beestes apon you, which shall robbe you of youre childern and destroye youre catell, and make you so fewe in numbre that youre hye wayes shall growe vnto a wildernesse.", "dra": "And I will send in upon you the beasts of the field, to destroy you and your cattle, and make you few in number: and that your highways may be desolate.", "bbe": "I will let loose the beasts of the field among you, and they will take away your children and send destruction on your cattle, so that your numbers will become small and your roads become waste.", "geneva": "I will also sende wilde beastes vpon you, which shall spoyle you, and destroy your cattell, and make you fewe in number: so your hye waies shalbe desolate.", "wycliffe": "Y schal sende out in to you cruel beestis of the feeld, that schulen waste you and youre beestis, and schulen brynge alle thingis to fewnesse, and youre weies schulen be forsakun.", "rotherham": "And will send among you the wild-beast of the field And it shall rob you of your children, And cut off your cattle, And make you few in number; And your roads shall be silent.", "darby": "And I will send the beasts of the field among you, that they may rob you of your children, and cut off your cattle, and make you few in number; and your streets shall be desolate.", "twenty": "", "jps": "And I will send the beast of the field among you, which shall rob you of your children, and destroy your cattle, and make you few in number; and your ways shall become desolate.", "acv": "And I will send the beast of the field among you, which shall rob you of your sons, and destroy your cattle, and make you few in number, and your ways shall become desolate.", "anderson": "", "haweis": "", "noyes": "", "webster": "I will also send wild beasts among you, which shall rob you of your children, and destroy your cattle, and make you few in number, and your [high]-ways shall be desolate.", "vulgate": "emittamque in vos bestias agri quae consumant et vos et pecora vestra et ad paucitatem cuncta redigant desertaeque fiant viae vestrae;", "brenton": "And I will send upon you the wild beasts of the land, and they shall devour you, and shall consume your cattle: and I will make you few in number, and your ways shall be desolate."}}, {"v": 23, "ref": "26:23", "o": "וְ/אִ֨ם בְּ/אֵ֔לֶּה לֹ֥א תִוָּסְר֖וּ לִ֑/י וַ/הֲלַכְתֶּ֥ם עִמִּ֖/י קֶֽרִי", "en": {"kjv": "And if ye will not be reformed by me by these things, but will walk contrary unto me;", "web": "“‘If by these things you won’t be reformed to me, but will walk contrary to me;", "bsb": "And if in spite of these things you do not accept My discipline, but continue to walk in hostility toward Me,", "asv": "And if by these things ye will not be reformed unto me, but will walk contrary unto me;", "ylt": "`And if by these ye are not instructed by Me, and have walked with Me in opposition,", "tyndale": "And yf ye will not be lerned yet for all this but shall walke contrarye vnto me,", "dra": "And if even so you will not amend, but will walk contrary to me:", "bbe": "And if by these things you will not be turned to me, but still go against me;", "geneva": "Yet if by these ye will not be reformed by me, but walke stubburnly against me,", "wycliffe": "That if nether so ye wolen resseyue doctryn, but goon contrarie to me,", "rotherham": "And, if, by these things, ye will not be corrected by me,—But will go in opposition to me,", "darby": "And if ye will not be disciplined by me through these, but walk contrary unto me,", "twenty": "", "jps": "And if in spite of these things ye will not be corrected unto Me, but will walk contrary unto Me;", "acv": "And if by these things ye will not be reformed to me, but will walk contrary to me,", "anderson": "", "haweis": "", "noyes": "", "webster": "And if ye will not be reformed by me by these things, but will walk contrary to me;", "vulgate": "quod si nec sic volueritis recipere disciplinam sed ambulaveritis ex adverso mihi;", "brenton": "And if hereupon ye are not corrected, but walk perversely towards me,"}}, {"v": 24, "ref": "26:24", "o": "וְ/הָלַכְתִּ֧י אַף אֲנִ֛י עִמָּ/כֶ֖ם בְּ/קֶ֑רִי וְ/הִכֵּיתִ֤י אֶתְ/כֶם֙ גַּם אָ֔נִי שֶׁ֖בַע עַל חַטֹּאתֵי/כֶֽם", "en": {"kjv": "Then will I also walk contrary unto you, and will punish you yet seven times for your sins.", "web": "then I will also walk contrary to you; and I will strike you, even I, seven times for your sins.", "bsb": "then I will act with hostility toward you, and I will strike you sevenfold for your sins.", "asv": "then will I also walk contrary unto you; and I will smite you, even I, seven times for your sins.", "ylt": "then I have walked--I also--with you in opposition, and have smitten you, even I, seven times for your sins;", "tyndale": "then will I also walke contrarye vnto you and will punish you yet seuen tymes for youre synnes.", "dra": "I also will walk contrary to you, and will strike you seven times for your sins.", "bbe": "Then I will go against you, and I will give you punishment, I myself, seven times for all your sins.", "geneva": "Then wil I also walke stubburnly against you, and I will smite you yet seuen times for your sinnes:", "wycliffe": "also Y schal go aduersarie ayens you, and Y schal smyte you seuen sithis for youre synnes;", "rotherham": "Then will, I also, go in opposition to you. And, I, even I, will plague you seven times for your sins;", "darby": "then will I also walk contrary unto you, and will smite you, even I, sevenfold for your sins.", "twenty": "", "jps": "then will I also walk contrary unto you; and I will smite you, even I, seven times for your sins.", "acv": "then I also will walk contrary to you, and I will smite you, even I, seven times for your sins.", "anderson": "", "haweis": "", "noyes": "", "webster": "Then will I also walk contrary to you, and I will punish you yet seven times for your sins.", "vulgate": "ego quoque contra vos adversus incedam et percutiam vos septies propter peccata vestra;", "brenton": "I also will walk with you with a perverse spirit, and I also will smite you seven times for your sins."}}, {"v": 25, "ref": "26:25", "o": "וְ/הֵבֵאתִ֨י עֲלֵי/כֶ֜ם חֶ֗רֶב נֹקֶ֨מֶת֙ נְקַם בְּרִ֔ית וְ/נֶאֱסַפְתֶּ֖ם אֶל עָרֵי/כֶ֑ם וְ/שִׁלַּ֤חְתִּי דֶ֨בֶר֙ בְּ/ת֣וֹכְ/כֶ֔ם וְ/נִתַּתֶּ֖ם בְּ/יַד אוֹיֵֽב", "en": {"kjv": "And I will bring a sword upon you, that shall avenge the quarrel of my covenant: and when ye are gathered together within your cities, I will send the pestilence among you; and ye shall be delivered into the hand of the enemy.", "web": "I will bring a sword upon you that will execute the vengeance of the covenant. You will be gathered together within your cities, and I will send the pestilence among you. You will be delivered into the hand of the enemy.", "bsb": "And I will bring a sword against you to execute the vengeance of the covenant. Though you withdraw into your cities, I will send a plague among you, and you will be delivered into the hand of the enemy.", "asv": "And I will bring a sword upon you, that shall execute the vengeance of the covenant; and ye shall be gathered together within your cities: and I will send the pestilence among you; and ye shall be delivered into the hand of the enemy.", "ylt": "and I have brought in on you a sword, executing the vengeance of a covenant; and ye have been gathered unto your cities, and I have sent pestilence into your midst, and ye have been given into the hand of an enemy.", "tyndale": "I will sende a swerde apon you, that shall avenge my testament with you. And when ye are fled vnto youre cities, I will sende the pestelence amonge you, ye shall be delyuered in to the handes of youre enemyes.", "dra": "And I will bring in upon you the sword that shall avenge my covenant. And when you shall flee into the cities, I will send the pestilence in the midst of you. And you shall be delivered into the hands of your enemies,", "bbe": "And I will send a sword on you to give effect to the punishment of my agreement; and when you come together into your towns I will send disease among you and you will be given up into the hands of your haters.", "geneva": "And I wil send a sword vpon you, that shall auenge the quarel of my couenant: and when ye are gathered in your cities, I wil send the pestilence among you, and ye shall be deliuered into the hand of the enemie.", "wycliffe": "and Y schal brynge yn on you the swerd, vengere of my boond of pees ; and whanne ye fleen in to citees, Y schal sende pestilence in the myddis of you, and ye schulen be bitakun in the hondis of enemyes,", "rotherham": "And will bring in upon you a sword that shall inflict the covenanted avenging: So shall ye be gathered into your cities,—Then will I send a pestilence into your midst, And ye shall be delivered into the hand of an enemy.", "darby": "And I will bring a sword upon you that avengeth with the vengeance of the covenant, and ye shall be gathered together into your cities, and I will send the pestilence among you; and ye shall be delivered into the hand of the enemy.", "twenty": "", "jps": "And I will bring a sword upon you, that shall execute the vengeance of the covenant; and ye shall be gathered together within your cities; and I will send the pestilence among you; and ye shall be delivered into the hand of the enemy.", "acv": "And I will bring a sword upon you that shall execute the vengeance of the covenant, and ye shall be gathered together within your cities. And I will send the pestilence among you, and ye shall be delivered into the hand of the enemy.", "anderson": "", "haweis": "", "noyes": "", "webster": "And I will bring a sword upon you, that shall avenge the quarrel of [my] covenant: and when ye are gathered within your cities, I will send the pestilence among you: and ye shall be delivered into the hand of the enemy.", "vulgate": "inducamque super vos gladium ultorem foederis mei cumque confugeritis in urbes mittam pestilentiam in medio vestri et trademini hostium manibus;", "brenton": "And I will bring upon you a sword avenging the cause of my covenant, and ye shall flee for refuge to your cities; and I will send out death against you, and ye shall be delivered into the hands of your enemies."}}, {"v": 26, "ref": "26:26", "o": "בְּ/שִׁבְרִ֣/י לָ/כֶם֮ מַטֵּה לֶחֶם֒ וְ֠/אָפוּ עֶ֣שֶׂר נָשִׁ֤ים לַחְמְ/כֶם֙ בְּ/תַנּ֣וּר אֶחָ֔ד וְ/הֵשִׁ֥יבוּ לַחְמְ/כֶ֖ם בַּ/מִּשְׁקָ֑ל וַ/אֲכַלְתֶּ֖ם וְ/לֹ֥א תִשְׂבָּֽעוּ", "en": {"kjv": "And when I have broken the staff of your bread, ten women shall bake your bread in one oven, and they shall deliver you your bread again by weight: and ye shall eat, and not be satisfied.", "web": "When I break your staff of bread, ten women shall bake your bread in one oven, and they shall deliver your bread again by weight. You shall eat, and not be satisfied.", "bsb": "When I cut off your supply of bread, ten women will bake your bread in a single oven and dole out your bread by weight, so that you will eat but not be satisfied.", "asv": "When I break your staff of bread, ten women shall bake your bread in one oven, and they shall deliver your bread again by weight: and ye shall eat, and not be satisfied.", "ylt": "`In My breaking to you the staff of bread, then ten women have baked your bread in one oven, and have given back your bread by weight; and ye have eaten, and are not satisfied.", "tyndale": "And when I haue broken the staffe of youre bred: that .x. wyues shall bake youre bred in one ouen and men shall delyuer you youre bred agayne by weyghte, tha shal ye eate and shall not be satisfied.", "dra": "After I shall have broken the staff of your bread: so that ten women shall bake your bread in one oven, and give it out by weight: and you shall eat, and shall not be filled,", "bbe": "When I take away your bread of life, ten women will be cooking bread in one oven, and your bread will be measured out by weight; you will have food but never enough.", "geneva": "When I shall breake the staffe of your bread, then ten women shall bake your breade in one ouen, and they shall deliuer your bread againe by weight, and ye shall eate, but not be satisfied.", "wycliffe": "aftir that Y haue broke the staf of youre breed, so that ten wymmen bake looues in oon ouene, and yelde tho looues at weiyte; and ye schulen ete, and ye schulen not be fillid.", "rotherham": "When I have broken your staff of bread, then shall ten women bake your bread in one oven, And give back your bread by weight,—And ye shall eat and not be filled.", "darby": "When I break the staff of your bread, ten women shall bake your bread in one oven, and shall deliver you the bread again by weight; and ye shall eat, and not be satisfied.", "twenty": "", "jps": "When I break your staff of bread, ten women shall bake your bread in one oven, and they shall deliver your bread again by weight; and ye shall eat, and not be satisfied.", "acv": "When I break your staff of bread, ten women shall bake your bread in one oven, and they shall deliver your bread again by weight, and ye shall eat, and not be satisfied.", "anderson": "", "haweis": "", "noyes": "", "webster": "[And] when I have broke the staff of your bread, ten women shall bake your bread in one oven, and they shall deliver [you] your bread again by weight: and ye shall eat, and not be satisfied.", "vulgate": "postquam confregero baculum panis vestri ita ut decem mulieres in uno clibano coquant panes et reddant eos ad pondus et comedetis et non saturabimini;", "brenton": "When I afflict you with famine of bread, then ten women shall bake your loaves in one oven, and they shall render your loaves by weight; and ye shall eat, and not be satisfied."}}, {"v": 27, "ref": "26:27", "o": "וְ/אִ֨ם בְּ/זֹ֔את לֹ֥א תִשְׁמְע֖וּ לִ֑/י וַ/הֲלַכְתֶּ֥ם עִמִּ֖/י בְּ/קֶֽרִי", "en": {"kjv": "And if ye will not for all this hearken unto me, but walk contrary unto me;", "web": "“‘If you in spite of this won’t listen to me, but walk contrary to me;", "bsb": "But if in spite of all this you do not obey Me, but continue to walk in hostility toward Me,", "asv": "And if ye will not for all this hearken unto me, but walk contrary unto me;", "ylt": "`And if for this ye hearken not to Me, and have walked with Me in opposition,", "tyndale": "And yf ye will not yet for all this harken vnto me, but shall walke contrarye vnto me,", "dra": "But if you will not for all this hearken to me, but will walk against me", "bbe": "And if, after all this, you do not give ear to me, but go against me still,", "geneva": "Yet if ye will not for this obey mee, but walke against me stubburnly,", "wycliffe": "But if nethir bi these thingis ye heren me, but goon ayens me,", "rotherham": "And, if, with this, ye will not hearken to me,—But will go in opposition to me,", "darby": "And if for this ye hearken not to me, but walk contrary unto me,", "twenty": "", "jps": "And if ye will not for all this hearken unto Me, but walk contrary unto Me;", "acv": "And if for all this ye will not hearken to me, but walk contrary to me,", "anderson": "", "haweis": "", "noyes": "", "webster": "And if ye will not for all this hearken to me, but walk contrary to me;", "vulgate": "sin autem nec per haec audieritis me sed ambulaveritis contra me;", "brenton": "And if hereupon ye will not obey me, but walk perversely towards me,"}}, {"v": 28, "ref": "26:28", "o": "וְ/הָלַכְתִּ֥י עִמָּ/כֶ֖ם בַּ/חֲמַת קֶ֑רִי וְ/יִסַּרְתִּ֤י אֶתְ/כֶם֙ אַף אָ֔נִי שֶׁ֖בַע עַל חַטֹּאתֵי/כֶם", "en": {"kjv": "Then I will walk contrary unto you also in fury; and I, even I, will chastise you seven times for your sins.", "web": "then I will walk contrary to you in wrath. I will also chastise you seven times for your sins.", "bsb": "then I will walk in fury against you, and I, even I, will punish you sevenfold for your sins.", "asv": "then I will walk contrary unto you in wrath; and I also will chastise you seven times for your sins.", "ylt": "then I have walked with you in the fury of opposition, and have chastised you, even I, seven times for your sins.", "tyndale": "then I will walke contrary vnto you also wrathfully and will also chastice you seuen tymes for youre synnes:", "dra": "I will also go against you with opposite fury: and I will chastise you with seven plagues for your sins,", "bbe": "Then my wrath will be burning against you, and I will give you punishment, I myself, seven times for your sins.", "geneva": "Then will I walke stubburnly in mine anger against you, and I will also chastice you seuen times more according to your sinnes.", "wycliffe": "and Y schal go ayens you in contrarie woodnesse, and Y schal chastise you bi seuene veniaunces for youre synnes,", "rotherham": "Then will I go in a rage of opposition to you,—And I, even I, will correct you seven times for your sins;", "darby": "then I will walk contrary unto you also in fury; and I, even I, will chastise you seven-fold for your sins.", "twenty": "", "jps": "then I will walk contrary unto you in fury; and I also will chastise you seven times for your sins.", "acv": "then I will walk contrary to you in wrath, and I also will chastise you seven times for your sins.", "anderson": "", "haweis": "", "noyes": "", "webster": "Then I will walk contrary to you also in fury; and I, even I, will chastise you seven times for your sins.", "vulgate": "et ego incedam adversum vos in furore contrario et corripiam vos septem plagis propter peccata vestra;", "brenton": "then will I walk with you with a froward mind, and I will chasten you seven-fold according to your sins."}}, {"v": 29, "ref": "26:29", "o": "וַ/אֲכַלְתֶּ֖ם בְּשַׂ֣ר בְּנֵי/כֶ֑ם וּ/בְשַׂ֥ר בְּנֹתֵי/כֶ֖ם תֹּאכֵֽלוּ", "en": {"kjv": "And ye shall eat the flesh of your sons, and the flesh of your daughters shall ye eat.", "web": "You will eat the flesh of your sons, and you will eat the flesh of your daughters.", "bsb": "You will eat the flesh of your own sons and daughters.", "asv": "And ye shall eat the flesh of your sons, and the flesh of your daughters shall ye eat.", "ylt": "`And ye have eaten the flesh of your sons; even flesh of your daughters ye do eat.", "tyndale": "so that ye shall eate the flesh of youre sonnes and the flesh of youre doughters.", "dra": "So that you shall eat the flesh of your sons and of your daughters.", "bbe": "Then you will take the flesh of your sons and the flesh of your daughters for food;", "geneva": "And ye shall eate ye flesh of your sonnes, and the flesh of your daughters shall ye deuoure.", "wycliffe": "so that ye ete the fleischis of youre sones, and of youre douytris;", "rotherham": "And ye shall eat the flesh of your sons,—Yea, even the flesh of your daughters, shall ye eat.", "darby": "And ye shall eat the flesh of your sons, and the flesh of your daughters shall ye eat.", "twenty": "", "jps": "And ye shall eat the flesh of your sons, and the flesh of your daughters shall ye eat.", "acv": "And ye shall eat the flesh of your sons, and the flesh of your daughters ye shall eat.", "anderson": "", "haweis": "", "noyes": "", "webster": "And ye shall eat the flesh of your sons, and the flesh of your daughters shall ye eat.", "vulgate": "ita ut comedatis carnes filiorum et filiarum vestrarum;", "brenton": "And ye shall eat the flesh of your sons, and the flesh of your daughters shall ye eat."}}, {"v": 30, "ref": "26:30", "o": "וְ/הִשְׁמַדְתִּ֞י אֶת בָּמֹֽתֵי/כֶ֗ם וְ/הִכְרַתִּי֙ אֶת חַמָּ֣נֵי/כֶ֔ם וְ/נָֽתַתִּי֙ אֶת פִּגְרֵי/כֶ֔ם עַל פִּגְרֵ֖י גִּלּוּלֵי/כֶ֑ם וְ/גָעֲלָ֥ה נַפְשִׁ֖/י אֶתְ/כֶֽם", "en": {"kjv": "And I will destroy your high places, and cut down your images, and cast your carcases upon the carcases of your idols, and my soul shall abhor you.", "web": "I will destroy your high places, and cut down your incense altars, and cast your dead bodies upon the bodies of your idols; and my soul will abhor you.", "bsb": "I will destroy your high places, cut down your incense altars, and heap your lifeless bodies on the lifeless remains of your idols; and My soul will despise you.", "asv": "And I will destroy your high places, and cut down your sun-images, and cast your dead bodies upon the bodies of your idols; and my soul shall abhor you.", "ylt": "And I have destroyed your high places, and cut down your images, and have put your carcases on the carcases of your idols, and My soul hath loathed you;", "tyndale": "And I will destroye youre alters bylt apon hye hylles, and ouerthrowe youre images, and cast youre carkasses apon the bodies of youre ydolles, and my soule shall abhorre you.", "dra": "I will destroy your high places, and break your idols. You shall fall among the ruins of your idols, and my soul shall abhor you.", "bbe": "And I will send destruction on your high places, overturning your perfume altars, and will put your dead bodies on your broken images, and my soul will be turned from you in disgust.", "geneva": "I will also destroy your hye places, and cut away your images, and cast your carkeises vpon the bodies of your idoles, and my soule shall abhorre you.", "wycliffe": "Y schal destrie youre hiye thingis, and Y schal breke youre symylacris; ye schulen falle bitwixe the fallyngis of your ydols, and my soule schal haue you abhomynable,", "rotherham": "And I will destroy your high places And cut down your sun-pillars, And cast your carcases upon the carcases of your manufactured gods,—Thus shall my soul abhor you.", "darby": "And I will lay waste your high places, and cut down your sun-pillars, and cast your carcases upon the carcases of your idols; and my soul shall abhor you.", "twenty": "", "jps": "And I will destroy your high places, and cut down your sun-pillars, and cast your carcasses upon the carcasses of your idols; and My soul shall abhor you.", "acv": "And I will destroy your high places, and cut down your sun-images, and cast your dead bodies upon the bodies of your idols, and my soul shall abhor you.", "anderson": "", "haweis": "", "noyes": "", "webster": "And I will destroy your high places, and cut down your images, and cast your carcasses upon the carcasses of your idols, and my soul shall abhor you.", "vulgate": "destruam excelsa vestra et simulacra confringam cadetis inter ruinas idolorum vestrorum et abominabitur vos anima mea;", "brenton": "And I will render your pillars desolate, and will utterly destroy your wooden images made with hands; and I will lay your carcases on the carcases of your idols, and my soul shall loathe you."}}, {"v": 31, "ref": "26:31", "o": "וְ/נָתַתִּ֤י אֶת עָֽרֵי/כֶם֙ חָרְבָּ֔ה וַ/הֲשִׁמּוֹתִ֖י אֶת מִקְדְּשֵׁי/כֶ֑ם וְ/לֹ֣א אָרִ֔יחַ בְּ/רֵ֖יחַ נִיחֹֽחֲ/כֶֽם", "en": {"kjv": "And I will make your cities waste, and bring your sanctuaries unto desolation, and I will not smell the savour of your sweet odours.", "web": "I will lay your cities waste, and will bring your sanctuaries to desolation. I will not take delight in the sweet fragrance of your offerings.", "bsb": "I will reduce your cities to rubble and lay waste your sanctuaries, and I will refuse to smell the pleasing aroma of your sacrifices.", "asv": "And I will make your cities a waste, and will bring your sanctuaries unto desolation, and I will not smell the savor of your sweet odors.", "ylt": "and I have made your cities a waste, and have made desolate your sanctuaries, and I smell not at your sweet fragrances;", "tyndale": "And I will make youre cities desolate, and bringe youre sanctuaries vnto nought, and will not smell the sauoures of youre swete odoures.", "dra": "Insomuch that I will bring your cities to be a wilderness: and I will make your sanctuaries desolate: and will receive no more your sweet odours.", "bbe": "And I will make your towns waste and send destruction on your holy places; I will take no pleasure in the smell of your sweet perfumes;", "geneva": "And I will make your cities desolate, and bring your Sanctuarie vnto nought, and will not smelll the sauour of your sweete odours.", "wycliffe": "in so myche that Y turne youre citees in to wildirnesse, and make youre seyntuaries forsakun, nether Y schal resseyue more the swettest odour;", "rotherham": "And I will give your cities unto desolation, And make your holy places dumb,—And will find no fragrance in your satisfying odour;", "darby": "And I will lay waste your cities and desolate your sanctuaries; and I will not smell your sweet odours.", "twenty": "", "jps": "And I will make your cities a waste, and will bring your sanctuaries unto desolation, and I will not smell the savour of your sweet odours.", "acv": "And I will make your cities a waste, and will bring your sanctuaries to desolation, and I will not smell the savor of your sweet odors.", "anderson": "", "haweis": "", "noyes": "", "webster": "And I will make your cities waste, and bring your sanctuaries to desolation, and I will not smell the savor of your sweet odors.", "vulgate": "in tantum ut urbes vestras redigam in solitudinem et deserta faciam sanctuaria vestra nec recipiam ultra odorem suavissimum;", "brenton": "And I will lay your cities waste, and I will make your sanctuaries desolate, and I will not smell the savour of your sacrifices."}}, {"v": 32, "ref": "26:32", "o": "וַ/הֲשִׁמֹּתִ֥י אֲנִ֖י אֶת הָ/אָ֑רֶץ וְ/שָֽׁמְמ֤וּ עָלֶ֨י/הָ֙ אֹֽיְבֵי/כֶ֔ם הַ/יֹּשְׁבִ֖ים בָּֽ/הּ", "en": {"kjv": "And I will bring the land into desolation: and your enemies which dwell therein shall be astonished at it.", "web": "I will bring the land into desolation; and your enemies that dwell therein will be astonished at it.", "bsb": "And I will lay waste the land, so that your enemies who dwell in it will be appalled.", "asv": "And I will bring the land into desolation; and your enemies that dwell therein shall be astonished at it.", "ylt": "and I have made desolate the land, and your enemies, who are dwelling in it, have been astonished at it.", "tyndale": "And I will bringe the londe vnto a wildernesse: so that youre enemyes which dwell therein shall wondre at it.", "dra": "And I will destroy your land: and your enemies shall be astonished at it, when they shall be the inhabitants thereof.", "bbe": "And I will make your land a waste, a wonder to your haters living in it.", "geneva": "I will also bring the land vnto a wildernes, and your enemies, which dwell therein, shalbe astonished thereat.", "wycliffe": "and Y schal destrye youre lond, and youre enemyes schulen be astonyed theronne, whanne thei schulen be enhabiters therof;", "rotherham": "And, I, will make the land dumb, And your foes that dwell therein shall regard it with dumb amazement:", "darby": "And I will bring the land into desolation; that your enemies who dwell there in may be astonished at it.", "twenty": "", "jps": "And I will bring the land into desolation; and your enemies that dwell therein shall be astonished at it.", "acv": "And I will bring the land into desolation, and your enemies who dwell in it shall be astonished at it.", "anderson": "", "haweis": "", "noyes": "", "webster": "And I will bring the land into desolation: and your enemies who dwell in it shall be astonished at it.", "vulgate": "disperdamque terram vestram et stupebunt super ea inimici vestri cum habitatores illius fuerint;", "brenton": "And I will lay your land desolate, and your enemies who dwell in it shall wonder at it."}}, {"v": 33, "ref": "26:33", "o": "וְ/אֶתְ/כֶם֙ אֱזָרֶ֣ה בַ/גּוֹיִ֔ם וַ/הֲרִיקֹתִ֥י אַחֲרֵי/כֶ֖ם חָ֑רֶב וְ/הָיְתָ֤ה אַרְצְ/כֶם֙ שְׁמָמָ֔ה וְ/עָרֵי/כֶ֖ם יִהְי֥וּ חָרְבָּֽה", "en": {"kjv": "And I will scatter you among the heathen, and will draw out a sword after you: and your land shall be desolate, and your cities waste.", "web": "I will scatter you among the nations, and I will draw out the sword after you. Your land will be a desolation, and your cities shall be a waste.", "bsb": "But I will scatter you among the nations and will draw out a sword after you as your land becomes desolate and your cities are laid waste.", "asv": "And you will I scatter among the nations, and I will draw out the sword after you: and your land shall be a desolation, and your cities shall be a waste.", "ylt": "And you I scatter among nations, and have drawn out after you a sword, and your land hath been a desolation, and your cities are a waste.", "tyndale": "And I will strawe you amonge the heethen, and will drawe out a swerde after you, and youre lande shalbe wast, and youre cities desolate.", "dra": "And I will scatter you among the Gentiles: and I will draw out the sword after you. And your land shall be desert, and your cities destroyed.", "bbe": "And I will send you out in all directions among the nations, and my sword will be uncovered against you, and your land will be without any living thing, and your towns will be made waste.", "geneva": "Also I wil scatter you among the heathen, and will drawe out a sworde after you, and your land shalbe waste, and your cities shalbe desolate.", "wycliffe": "forsothe Y schal scatere you in to folkis, ether hethen men, and Y schal drawe out of the schethe the swerd aftir you, and youre lond schal be forsakun, and youre citees schulen be cast doun.", "rotherham": "When, even you, I scatter among the nations, And make bare after you, a sword, Then shall your land become an astonishment, And your cities become a desolation.", "darby": "And I will scatter you among the nations, and will draw out the sword after you; and your land shall be desolation, and your cities waste.", "twenty": "", "jps": "And you will I scatter among the nations, and I will draw out the sword after you; and your land shall be a desolation, and your cities shall be a waste.", "acv": "And I will scatter you among the nations, and I will draw out the sword after you, and your land shall be a desolation, and your cities shall be a waste.", "anderson": "", "haweis": "", "noyes": "", "webster": "And I will scatter you among the heathen, and will draw out a sword after you: and your land shall be desolate, and your cities waste.", "vulgate": "vos autem dispergam in gentes et evaginabo post vos gladium eritque terra vestra deserta et civitates dirutae;", "brenton": "And I will scatter you among the nations, and the sword shall come upon you and consume you; and your land shall be desolate, and your cities shall be desolate."}}, {"v": 34, "ref": "26:34", "o": "אָז֩ תִּרְצֶ֨ה הָ/אָ֜רֶץ אֶת שַׁבְּתֹתֶ֗י/הָ כֹּ֚ל יְמֵ֣י הֳשַׁמָּ֔/ה וְ/אַתֶּ֖ם בְּ/אֶ֣רֶץ אֹיְבֵי/כֶ֑ם אָ֚ז תִּשְׁבַּ֣ת הָ/אָ֔רֶץ וְ/הִרְצָ֖ת אֶת שַׁבְּתֹתֶֽי/הָ", "en": {"kjv": "Then shall the land enjoy her sabbaths, as long as it lieth desolate, and ye be in your enemies’ land; even then shall the land rest, and enjoy her sabbaths.", "web": "Then the land will enjoy its Sabbaths as long as it lies desolate and you are in your enemies’ land. Even then the land will rest and enjoy its Sabbaths.", "bsb": "Then the land shall enjoy its Sabbaths all the days it lies desolate, while you are in the land of your enemies. At that time the land will rest and enjoy its Sabbaths.", "asv": "Then shall the land enjoy its sabbaths, as long as it lieth desolate, and ye are in your enemies’ land; even then shall the land rest, and enjoy its sabbaths.", "ylt": "`Then doth the land enjoy its sabbaths--all the days of the desolation, and ye in the land of your enemies--then doth the land rest, and hath enjoyed its sabbaths;", "tyndale": "Then the lande shall reioyse in hir Sabbathes, as longe as it lyeth voyde and ye in youre enemies londe: euen then shall the londe kepe holye daye and reioyse in hir Sabbathes.", "dra": "Then shall the land enjoy her sabbaths all the days of her desolation. When you shall be", "bbe": "Then will the land take pleasure in its Sabbaths while it is waste and you are living in the land of your haters; then will the land have rest.", "geneva": "Then shall the land inioy her Sabbaths, as long as it lieth voide, and yee shalbe in your enemies land: then shall the land rest, and enioy her Sabbaths.", "wycliffe": "Thanne `hise sabatis schulen plese the erthe, in alle the daies of his wildirnesse; whanne ye ben in the lond of enemyes,", "rotherham": "Then, shall the land be paid her sabbaths, All the days she lieth desolate, While, ye, are in the land of your foes,—Then, shall the land keep sabbath, And pay off her sabbaths:", "darby": "Then shall the land enjoy its sabbaths all the days of the desolation, when ye are in your enemies' land; then shall the land rest, and enjoy its sabbaths.", "twenty": "", "jps": "Then shall the land be paid her sabbaths, as long as it lieth desolate, and ye are in your enemies' land; even then shall the land rest, and repay her sabbaths.", "acv": "Then the land shall enjoy its sabbaths, as long as it lies desolate, and ye are in your enemies' land, even then shall the land rest, and enjoy its sabbaths.", "anderson": "", "haweis": "", "noyes": "", "webster": "Then shall the land enjoy its sabbaths, as long as it lieth desolate, and ye [are] in your enemies' land; [even] then shall the land rest, and enjoy its sabbaths.", "vulgate": "tunc placebunt terrae sabbata sua cunctis diebus solitudinis suae quando fueritis;", "brenton": "Then the land shall enjoy its sabbaths all the days of its desolation."}}, {"v": 35, "ref": "26:35", "o": "כָּל יְמֵ֥י הָשַּׁמָּ֖/ה תִּשְׁבֹּ֑ת אֵ֣ת אֲשֶׁ֧ר לֹֽא שָׁבְתָ֛ה בְּ/שַׁבְּתֹתֵי/כֶ֖ם בְּ/שִׁבְתְּ/כֶ֥ם עָלֶֽי/הָ", "en": {"kjv": "As long as it lieth desolate it shall rest; because it did not rest in your sabbaths, when ye dwelt upon it.", "web": "As long as it lies desolate it shall have rest, even the rest which it didn’t have in your Sabbaths, when you lived on it.", "bsb": "As long as it lies desolate, the land will have the rest it did not receive during the Sabbaths when you lived in it.", "asv": "As long as it lieth desolate it shall have rest, even the rest which it had not in your sabbaths, when ye dwelt upon it.", "ylt": "all the days of the desolation it resteth that which it hath not rested in your sabbaths in your dwelling on it.", "tyndale": "And as longe as it lyeth voyde it shall rest, for that it coude not reste in youre Sabbathes, when ye dwelt therein.", "dra": "In the enemy's land, she shall keep a sabbath, and rest in the sabbaths of her desolation: because she did not rest in your sabbaths, when you dwelt therein.", "bbe": "All the days while it is waste will the land have rest, such rest as it never had in your Sabbaths, when you were living in it.", "geneva": "All the dayes that it lieth voide, it shall rest, because it did not rest in your Sabbaths, when ye dwelt vpon it.", "wycliffe": "it schal `kepe sabat, and schal reste in the sabatis of his wildirnesse, for it restide not in youre sabatis, whanne ye dwelliden therynne.", "rotherham": "All the days she lieth desolate, shall she keep sabbath,—the which she kept not as your sabbaths,—while ye dwelt thereupon.", "darby": "All the days of the desolation it shall rest, [the days in] which it did not rest on your sabbaths, when ye dwelt therein.", "twenty": "", "jps": "As long as it lieth desolate it shall have rest; even the rest which it had not in your sabbaths, when ye dwelt upon it.", "acv": "As long as it lies desolate it shall have rest, even the rest which it had not in your sabbaths, when ye dwelt upon it.", "anderson": "", "haweis": "", "noyes": "", "webster": "As long as it lieth desolate, it shall rest; because it did not rest in your sabbaths, when ye dwelt upon it.", "vulgate": "in terra hostili sabbatizabit et requiescet in sabbatis solitudinis suae eo quod non requieverit in sabbatis vestris quando habitabatis in ea;", "brenton": "And ye shall be in the land of your enemies; then the land shall keep its sabbaths, and the land shall enjoy its sabbaths all the days of its desolation: it shall keep sabbaths which it kept not among your sabbaths, when ye dwelt in it."}}, {"v": 36, "ref": "26:36", "o": "וְ/הַ/נִּשְׁאָרִ֣ים בָּ/כֶ֔ם וְ/הֵבֵ֤אתִי מֹ֨רֶךְ֙ בִּ/לְבָבָ֔/ם בְּ/אַרְצֹ֖ת אֹיְבֵי/הֶ֑ם וְ/רָדַ֣ף אֹתָ֗/ם ק֚וֹל עָלֶ֣ה נִדָּ֔ף וְ/נָס֧וּ מְנֻֽסַת חֶ֛רֶב וְ/נָפְל֖וּ וְ/אֵ֥ין רֹדֵֽף", "en": {"kjv": "And upon them that are left alive of you I will send a faintness into their hearts in the lands of their enemies; and the sound of a shaken leaf shall chase them; and they shall flee, as fleeing from a sword; and they shall fall when none pursueth.", "web": "“‘As for those of you who are left, I will send a faintness into their hearts in the lands of their enemies. The sound of a driven leaf will put them to flight; and they shall flee, as one flees from the sword. They will fall when no one pursues.", "bsb": "As for those of you who survive, I will send a faintness into their hearts in the lands of their enemies, so that even the sound of a windblown leaf will put them to flight. And they will flee as one flees the sword, and fall when no one pursues them.", "asv": "And as for them that are left of you, I will send a faintness into their heart in the lands of their enemies: and the sound of a driven leaf shall chase them; and they shall flee, as one fleeth from the sword; and they shall fall when none pursueth.", "ylt": "`And those who are left of you--I have also brought a faintness into their heart in the lands of their enemies, and the sound of a leaf driven away hath pursued them, and they have fled--flight from a sword--and they have fallen, and there is none pursuing.", "tyndale": "And vppon them that are left alyue of you I will sende a feyntnesse in to their hertes in the londe of their enemies: so that the sounde of a leef that falleth, shall chace them and they shall flee as though thei fled a swerde, and shall fall no man folowinge them.", "dra": "And as to them that shall remain of you I will send fear in their hearts in the countries of their enemies. The sound of a flying leaf shall terrify them: and they shall flee as it were from the sword. They shall fall, when no man pursueth them.", "bbe": "And as for the rest of you, I will make their hearts feeble in the land of their haters, and the sound of a leaf moved by the wind will send them in flight, and they will go in flight as from the sword, falling down when no one comes after them;", "geneva": "And vpon them that are left of you, I will send euen a faintnes into their hearts in ye land of their enemies, and the sounde of a leafeshaken shall chase them, and they shall flee as fleeing from a sword, and they shall fall, no man pursuing them.", "wycliffe": "And Y schal yyue drede in `the hertis of hem, whiche schulen abide of you, in the cuntreis of enemyes; the sown of a leef fleynge schal make hem aferd, and so thei schulen fle it as a swerd; thei schulen falle, while noon pursueth,", "rotherham": "And as for such as are left of you, Then will I bring faintness into their heart, in the lands of their foes,—So that the sound of a driven leaf shall chase them, And they shall flee as though fleeing from a sword And they shall fall, when no one is pursuing;", "darby": "And as to those that remain of you — I will send faintness into their hearts in the lands of their enemies, that the sound of a driven leaf shall chase them, and they shall flee, as fleeing from a sword; and they shall fall when none pursueth;", "twenty": "", "jps": "And as for them that are left of you, I will send a faintness into their heart in the lands of their enemies; and the sound of a driven leaf shall chase them; and they shall flee, as one fleeth from the sword; and they shall fall when none pursueth.", "acv": "And as for those who are left of you, I will send a faintness into their heart in the lands of their enemies. And the sound of a driven leaf shall chase them, and they shall flee as a man flees from the sword, and they shall fall when no man pursues.", "anderson": "", "haweis": "", "noyes": "", "webster": "And upon them that are left [alive] of you, I will send a faintness into their hearts in the lands of their enemies; and the sound of a shaken leaf shall chase them; and they shall flee, as fleeing from a sword; and they shall fall, when none pursueth.", "vulgate": "et qui de vobis remanserint dabo pavorem in cordibus eorum in regionibus hostium terrebit eos sonitus folii volantis et ita fugient quasi gladium cadent nullo sequente;", "brenton": "And to those who are left of you I will bring bondage into their heart in the land of their enemies; and the sound of a shaken leaf shall chase them, and they shall flee as fleeing from war, and shall fall when none pursues them."}}, {"v": 37, "ref": "26:37", "o": "וְ/כָשְׁל֧וּ אִישׁ בְּ/אָחִ֛י/ו כְּ/מִ/פְּנֵי חֶ֖רֶב וְ/רֹדֵ֣ף אָ֑יִן וְ/לֹא תִֽהְיֶ֤ה לָ/כֶם֙ תְּקוּמָ֔ה לִ/פְנֵ֖י אֹֽיְבֵי/כֶֽם", "en": {"kjv": "And they shall fall one upon another, as it were before a sword, when none pursueth: and ye shall have no power to stand before your enemies.", "web": "They will stumble over one another, as it were before the sword, when no one pursues. You will have no power to stand before your enemies.", "bsb": "They will stumble over one another as before the sword, though no one is behind them. So you will not be able to stand against your enemies.", "asv": "And they shall stumble one upon another, as it were before the sword, when none pursueth: and ye shall have no power to stand before your enemies.", "ylt": "And they have stumbled one on another, as from the face of a sword, and there is none pursuing, and ye have no standing before your enemies,", "tyndale": "And they shall fall one uppon another, as it were before a swerde euen no man folowinge them, and ye shall haue no power to stonde before youre enemyes:", "dra": "And they shall every one fall upon their brethren as fleeing from wars: none of you shall dare to resist your enemies.", "bbe": "Falling on one another, as before the sword, when no one comes after them; you will give way before your haters.", "geneva": "They shall fall also one vpon another, as before a sword, though none pursue them, and ye shall not be able to stand before your enemies:", "wycliffe": "and alle schulen falle on her britheren, as fleynge bateils; no man of you schal be hardi to ayenstonde enemyes;", "rotherham": "And they shall stumble one upon another as from before a sword, when, pursuer there is none; And ye shall not have wherewith to stand before your foes;", "darby": "and they shall stumble one over another, as it were before a sword, when none pursueth; and ye shall have no power to stand before your enemies.", "twenty": "", "jps": "And they shall stumble one upon another, as it were before the sword, when none pursueth; and ye shall have no power to stand before your enemies.", "acv": "And they shall stumble one upon another, as it were before the sword, when no man pursues. And ye shall have no power to stand before your enemies.", "anderson": "", "haweis": "", "noyes": "", "webster": "And they shall fall one upon another, as it were before a sword, when none pursueth: and ye shall have no power to stand before your enemies.", "vulgate": "et corruent singuli super fratres suos quasi bella fugientes nemo vestrum inimicis audebit resistere;", "brenton": "And brother shall disregard brother as in war, when none pursues; and ye shall not be able to withstand your enemies."}}, {"v": 38, "ref": "26:38", "o": "וַ/אֲבַדְתֶּ֖ם בַּ/גּוֹיִ֑ם וְ/אָכְלָ֣ה אֶתְ/כֶ֔ם אֶ֖רֶץ אֹיְבֵי/כֶֽם", "en": {"kjv": "And ye shall perish among the heathen, and the land of your enemies shall eat you up.", "web": "You will perish among the nations. The land of your enemies will eat you up.", "bsb": "You will perish among the nations, and the land of your enemies will consume you.", "asv": "And ye shall perish among the nations, and the land of your enemies shall eat you up.", "ylt": "and ye have perished among the nations, and the land of your enemies hath consumed you.", "tyndale": "And ye shall perish amonge the hethen, ad the londe of youre enemyes shall eate you vpp.", "dra": "You shall perish among the Gentiles: and an enemy's land shall consume you.", "bbe": "And death will overtake you among strange nations, and the land of your haters will be your destruction.", "geneva": "And ye shall perish among the heathen, and the land of your enemies shall eate you vp.", "wycliffe": "ye schulen perische among hethen men, and the lond of enemyes schal waaste you.", "rotherham": "And ye shall perish among the nations,—And the land of your foes shall eat you up;", "darby": "And ye shall perish among the nations, and the land of your enemies shall eat you up.", "twenty": "", "jps": "And ye shall perish among the nations, and the land of your enemies shall eat you up.", "acv": "And ye shall perish among the nations, and the land of your enemies shall eat you up.", "anderson": "", "haweis": "", "noyes": "", "webster": "And ye shall perish among the heathen, and the land of your enemies shall eat you up.", "vulgate": "peribitis inter gentes et hostilis vos terra consumet;", "brenton": "And ye shall perish among the Gentiles, and the land of your enemies shall devour you."}}, {"v": 39, "ref": "26:39", "o": "וְ/הַ/נִּשְׁאָרִ֣ים בָּ/כֶ֗ם יִמַּ֨קּוּ֙ בַּֽ/עֲוֺנָ֔/ם בְּ/אַרְצֹ֖ת אֹיְבֵי/כֶ֑ם וְ/אַ֛ף בַּ/עֲוֺנֹ֥ת אֲבֹתָ֖/ם אִתָּ֥/ם יִמָּֽקּוּ", "en": {"kjv": "And they that are left of you shall pine away in their iniquity in your enemies’ lands; and also in the iniquities of their fathers shall they pine away with them.", "web": "Those of you who are left will pine away in their iniquity in your enemies’ lands; and also in the iniquities of their fathers they shall pine away with them.", "bsb": "Those of you who survive in the lands of your enemies will waste away in their iniquity and will decay in the sins of their fathers.", "asv": "And they that are left of you shall pine away in their iniquity in your enemies’ lands; and also in the iniquities of their fathers shall they pine away with them.", "ylt": "`And those who are left of you--they consume away in their iniquity, in the lands of your enemies; and also in the iniquities of their fathers, with them they consume away.", "tyndale": "And thei that are left of you, shall pyne awaye in their vnrightuousnes, euen in their enemies londe, and also in the mysdeades of their fathers shall they consume.", "dra": "And if of them also some remain, they shall pine away in their iniquities, in the land of their enemies: and they shall be afflicted for the sins of their fathers, and their own.", "bbe": "And those of you who are still living will be wasting away in their sins in the land of your haters; in the sins of their fathers they will be wasting away.", "geneva": "And they that are left of you, shall pine away for their iniquitie, in your enemies landes, and for the iniquities of their fathers shall they pine away with them also.", "wycliffe": "That if summe of these Jewes dwellen, thei schulen faile in her wickidnessis, in the lond of her enemyes, and thei schulen be turmentid for the synne of her fadris,", "rotherham": "And they who are left of you, shall melt away in their iniquity, in the lands of your foes; Yea also, in the iniquity of their fathers with them, shall they melt away.", "darby": "And they that remain of you shall waste away through their iniquity in your enemies' lands; and also through the iniquities of their fathers shall they waste away with them.", "twenty": "", "jps": "And they that are left of you shall pine away in their iniquity in your enemies' lands; and also in the iniquities of their fathers shall they pine away with them.", "acv": "And those who are left of you shall pine away in their iniquity in your enemies' lands, and also in the iniquities of their fathers they shall pine away with them.", "anderson": "", "haweis": "", "noyes": "", "webster": "And they that are left of you shall pine away in their iniquity in your enemies' lands; and also in the iniquities of their fathers shall they pine away with them.", "vulgate": "quod si et de his aliqui remanserint tabescent in iniquitatibus suis in terra inimicorum suorum et propter peccata patrum suorum et sua adfligentur;", "brenton": "And those who are left of you shall perish, because of their sins, and because of the sins of their fathers: in the land of their enemies shall they consume away."}}, {"v": 40, "ref": "26:40", "o": "וְ/הִתְוַדּ֤וּ אֶת עֲוֺנָ/ם֙ וְ/אֶת עֲוֺ֣ן אֲבֹתָ֔/ם בְּ/מַעֲלָ֖/ם אֲשֶׁ֣ר מָֽעֲלוּ בִ֑/י וְ/אַ֕ף אֲשֶׁר הָֽלְכ֥וּ עִמִּ֖/י בְּ/קֶֽרִי", "en": {"kjv": "If they shall confess their iniquity, and the iniquity of their fathers, with their trespass which they trespassed against me, and that also they have walked contrary unto me;", "web": "“‘If they confess their iniquity, and the iniquity of their fathers, in their trespass which they trespassed against me, and also that, because they walked contrary to me,", "bsb": "But if they will confess their iniquity and that of their fathers in the unfaithfulness that they practiced against Me, by which they have also walked in hostility toward Me—", "asv": "And they shall confess their iniquity, and the iniquity of their fathers, in their trespass which they trespassed against me, and also that, because they walked contrary unto me,", "ylt": "`And--they have confessed their iniquity, and the iniquity of their fathers, in their trespass which they have trespassed against Me, and also, that they have walked with Me, in opposition,", "tyndale": "And they shall confesse their misdedes and the misdeades of their fathers in their trespases which thei haue trespased against me, and for that also that thei haue walked contrary vnto me.", "dra": "Until they confess their iniquities, and the iniquities of their ancestors, whereby they have transgressed against me, and walked contrary unto me.", "bbe": "And they will have grief for their sins and for the sins of their fathers, when their hearts were untrue to me, and they went against me;", "geneva": "Then they shall confesse their iniquitie, and the wickednes of their fathers for their trespasse, which they haue trespassed against mee, and also because they haue walked stubburnly against me.", "wycliffe": "and for her owne synnes, til thei knoulechen her wickidnesses, and han mynde of her yuels, bi whiche thei trespassiden ayens me, and yeden contrarie to me.", "rotherham": "Then shall they confess their iniquity, And the iniquity of their fathers, In their unfaithfulness wherewith they had been unfaithful towards me; Yea moreover, because they had gone in opposition to me,", "darby": "And they shall confess their iniquity, and the iniquity of their fathers, through their unfaithfulness wherein they were unfaithful to me, and also that they have walked contrary unto me,", "twenty": "", "jps": "And they shall confess their iniquity, and the iniquity of their fathers, in their treachery which they committed against Me, and also that they have walked contrary unto Me.", "acv": "And they shall confess their iniquity, and the iniquity of their fathers, in their trespass which they trespassed against me, and also that, because they walked contrary to me,", "anderson": "", "haweis": "", "noyes": "", "webster": "If they shall confess their iniquity, and the iniquity of their fathers, with their trespass which they trespassed against me, and that also they have walked contrary to me;", "vulgate": "donec confiteantur iniquitates suas et maiorum suorum quibus praevaricati sunt in me et ambulaverunt ex adverso mihi;", "brenton": "And they shall confess their sins, and the sins of their fathers, that they have transgressed and neglected me, and that they have walked perversely before me,"}}, {"v": 41, "ref": "26:41", "o": "אַף אֲנִ֗י אֵלֵ֤ךְ עִמָּ/ם֙ בְּ/קֶ֔רִי וְ/הֵבֵאתִ֣י אֹתָ֔/ם בְּ/אֶ֖רֶץ אֹיְבֵי/הֶ֑ם אוֹ אָ֣ז יִכָּנַ֗ע לְבָבָ/ם֙ הֶֽ/עָרֵ֔ל וְ/אָ֖ז יִרְצ֥וּ אֶת עֲוֺנָֽ/ם", "en": {"kjv": "And that I also have walked contrary unto them, and have brought them into the land of their enemies; if then their uncircumcised hearts be humbled, and they then accept of the punishment of their iniquity:", "web": "I also walked contrary to them, and brought them into the land of their enemies; if then their uncircumcised heart is humbled, and they then accept the punishment of their iniquity;", "bsb": "and I acted with hostility toward them and brought them into the land of their enemies—and if their uncircumcised hearts will be humbled and they will make amends for their iniquity,", "asv": "I also walked contrary unto them, and brought them into the land of their enemies: if then their uncircumcised heart be humbled, and they then accept of the punishment of their iniquity;", "ylt": "also I walk to them in opposition, and have brought them into the land of their enemies--or then their uncircumcised heart is humbled, and then they accept the punishment of their iniquity, --", "tyndale": "Therfore I also will walke contrary vnto them, and will brynge them in to the londe of their enemyes. And then at the leest waye their vncircumcysed hertes shall be tamed, ad then they shall make an attonement for their misdedes.", "dra": "Therefore I also will walk against them, and bring them into their enemies' land until their uncircumcised mind be ashamed. Then shall they pray for their sins.", "bbe": "So that I went against them and sent them away into the land of their haters: if then the pride of their hearts is broken and they take the punishment of their sins,", "geneva": "Therefore I wil walke stubburnly against them, and bring them into the land of their enemies: so then their vncircumcised hearts shalbe humbled, and then they shalt willingly beare the punishment of their iniquitie.", "wycliffe": "Therfor and Y schal go ayens hem, and Y schal brynge hem in to the lond of enemyes, til the vncircumcidid soule of hem be aschamed; thanne thei schulen preie for her wickidnesses,", "rotherham": "I also, must needs go in opposition to them, and bring them into the land of their foes,—Save only that, if, even then, their uncircumcised heart shall be humbled, And, even then, they shall accept as a payment the punishment of their iniquity,", "darby": "so that I also walked contrary unto them, and brought them into the land of their enemies. If then their uncircumcised heart be humbled, and they then accept the punishment of their iniquity,", "twenty": "", "jps": "I also will walk contrary unto them, and bring them into the land of their enemies; if then perchance their uncircumcised heart be humbled, and they then be paid the punishment of their iniquity;", "acv": "I also walked contrary to them, and brought them into the land of their enemies. If then their uncircumcised heart be humbled, and they then accept of the punishment of their iniquity,", "anderson": "", "haweis": "", "noyes": "", "webster": "And [that] I also have walked contrary to them, and have brought them into the land of their enemies; if then their uncircumcised hearts shall be humbled, and they then accept of the punishment of their iniquity:", "vulgate": "ambulabo igitur et ego contra eos et inducam illos in terram hostilem donec erubescat incircumcisa mens eorum tunc orabunt pro impietatibus suis;", "brenton": "and I walked with them with a perverse mind; and I will destroy them in the land of their enemies: then shall their uncircumcised heart be ashamed, and then shall they acquiesce in the punishment of their sins."}}, {"v": 42, "ref": "26:42", "o": "וְ/זָכַרְתִּ֖י אֶת בְּרִיתִ֣/י יַעֲק֑וֹב וְ/אַף֩ אֶת בְּרִיתִ֨/י יִצְחָ֜ק וְ/אַ֨ף אֶת בְּרִיתִ֧/י אַבְרָהָ֛ם אֶזְכֹּ֖ר וְ/הָ/אָ֥רֶץ אֶזְכֹּֽר", "en": {"kjv": "Then will I remember my covenant with Jacob, and also my covenant with Isaac, and also my covenant with Abraham will I remember; and I will remember the land.", "web": "then I will remember my covenant with Jacob; and also my covenant with Isaac, and also my covenant with Abraham; and I will remember the land.", "bsb": "then I will remember My covenant with Jacob and My covenant with Isaac and My covenant with Abraham, and I will remember the land.", "asv": "then will I remember my covenant with Jacob; and also my covenant with Isaac, and also my covenant with Abraham will I remember; and I will remember the land.", "ylt": "then I have remembered My covenant with Jacob, and also My covenant with Isaac, and also My covenant with Abraham I remember, and the land I remember.", "tyndale": "And I wil remembre my bonde with Iacob and my testamet with Isaac, and my testament with Abraham, and will thinke on the londe.", "dra": "And I will remember my covenant, that I made with Jacob, and Isaac, and Abraham. I will remember also the land:", "bbe": "Then I will keep in mind the agreement which I made with Jacob and with Isaac and with Abraham, and I will keep in mind the land.", "geneva": "Then I will remember my couenant with Iaakob, and my couenant also with Izhak, and also my couenant with Abraham will I remember, and will remember the land.", "wycliffe": "and Y schal haue mynde of my boond of pees, which Y couenauntide with Jacob, Ysaac, and Abraham; also Y schal be myndeful of the lond,", "rotherham": "Then will I remember my covenant with Jacob Yea moreover, my covenant with Isaac, Yea moreover, my covenant with Abraham, will I remember; And the land, will I remember.", "darby": "I will remember my covenant with Jacob, and also my covenant with Isaac, and also my covenant with Abraham will I remember; and I will remember the land.", "twenty": "", "jps": "then will I remember My covenant with Jacob, and also My covenant with Isaac, and also My covenant with Abraham will I remember; and I will remember the land.", "acv": "then I will remember my covenant with Jacob, and also my covenant with Isaac, and also my covenant with Abraham will I remember, and I will remember the land.", "anderson": "", "haweis": "", "noyes": "", "webster": "Then will I remember my covenant with Jacob, and also my covenant with Isaac, and also my covenant with Abraham will I remember; and I will remember the land.", "vulgate": "et recordabor foederis mei quod pepigi cum Iacob et Isaac et Abraham terrae quoque memor ero;", "brenton": "And I will remember the covenant of Jacob, and the covenant of Isaac, and the covenant of Abraam will I remember."}}, {"v": 43, "ref": "26:43", "o": "וְ/הָ/אָרֶץ֩ תֵּעָזֵ֨ב מֵ/הֶ֜ם וְ/תִ֣רֶץ אֶת שַׁבְּתֹתֶ֗י/הָ בָּ/הְשַׁמָּ/ה֙ מֵ/הֶ֔ם וְ/הֵ֖ם יִרְצ֣וּ אֶת עֲוֺנָ֑/ם יַ֣עַן וּ/בְ/יַ֔עַן בְּ/מִשְׁפָּטַ֣/י מָאָ֔סוּ וְ/אֶת חֻקֹּתַ֖/י גָּעֲלָ֥ה נַפְשָֽׁ/ם", "en": {"kjv": "The land also shall be left of them, and shall enjoy her sabbaths, while she lieth desolate without them: and they shall accept of the punishment of their iniquity: because, even because they despised my judgments, and because their soul abhorred my statutes.", "web": "The land also will be left by them, and will enjoy its Sabbaths while it lies desolate without them: and they will accept the punishment of their iniquity; because, even because they rejected my ordinances, and their soul abhorred my statutes.", "bsb": "For the land will be abandoned by them, and it will enjoy its Sabbaths by lying desolate without them. And they will pay the penalty for their iniquity, because they rejected My ordinances and abhorred My statutes.", "asv": "The land also shall be left by them, and shall enjoy its sabbaths, while it lieth desolate without them: and they shall accept of the punishment of their iniquity; because, even because they rejected mine ordinances, and their soul abhorred my statutes.", "ylt": "`And--the land is left of them, and doth enjoy its sabbaths, in the desolation without them, and they accept the punishment of their iniquity, because, even because, against My judgments they have kicked, and My statutes hath their soul loathed,", "tyndale": "For the londe shall be lefte of them and shall haue pleasure in hir Sabbathes, while she lyeth wast without them, and they shall make an attonement for their misdeades, because they despysed my lawes and their soules refused myne ordinaunces.", "dra": "Which when she shall be left by them, shall enjoy her sabbaths, being desolate for them. But they shall pray for their sins, because they rejected my judgments, and despised my laws.", "bbe": "And the land, while she is without them, will keep her Sabbaths; and they will undergo the punishment of their sins, because they were turned away from my decisions and in their souls was hate for my laws.", "geneva": "The land also in the meane season shalbe left of them, and shall enioye her Sabbaths while she lieth waste without them, but they shall willingly suffer the punishment of their iniquitie, because they despised my lawes, and because their soule abhorred mine ordinances.", "wycliffe": "which, whanne it is left of hem, schal plese to it silf in `his sabatis, and schal suffre wildirnesse for hem; forsothe thei schulen preye for her synnes, for thei castiden awey my domes, and despyseden my lawis;", "rotherham": "For, the land, shall be left of them, And shall be paid her sabbaths, while she lieth desolate without them, They also, accepting, as a payment, the punishment of their iniquity, Because, yea because, my regulations, they refused, And my statutes, their soul abhorred.", "darby": "For the land shall be left by them, and shall enjoy its sabbaths, when it is in desolation without them; and they shall accept the punishment of their iniquity; because, even because they despised my judgments, and their soul abhorred my statutes.", "twenty": "", "jps": "For the land shall lie forsaken without them, and shall be paid her sabbaths, while she lieth desolate without them; and they shall be paid the punishment of their iniquity; because, even because they rejected Mine ordinances, and their soul abhorred My statutes.", "acv": "The land also shall be left by them, and shall enjoy its sabbaths while it lies desolate without them. And they shall accept of the punishment of their iniquity, because, even because they rejected my ordinances, and their soul abhorred my statutes.", "anderson": "", "haweis": "", "noyes": "", "webster": "The land also shall be left by them, and shall enjoy her sabbaths, while she lieth desolate without them: and they shall accept of the punishment of their iniquity; because, even because they despised my judgments, and because their soul abhorred my statutes.", "vulgate": "quae cum relicta fuerit ab eis conplacebit sibi in sabbatis suis patiens solitudinem propter illos ipsi vero rogabunt pro peccatis suis eo quod abiecerint iudicia mea et leges meas despexerint;", "brenton": "And I will remember the land, and the land shall be left of them; then the land shall enjoy her sabbaths, when it is deserted through them: and they shall accept the punishment of their iniquities, because they neglected my judgments, and in their soul loathed my ordinances."}}, {"v": 44, "ref": "26:44", "o": "וְ/אַף גַּם זֹ֠את בִּֽ/הְיוֹתָ֞/ם בְּ/אֶ֣רֶץ אֹֽיְבֵי/הֶ֗ם לֹֽא מְאַסְתִּ֤י/ם וְ/לֹֽא גְעַלְתִּי/ם֙ לְ/כַלֹּתָ֔/ם לְ/הָפֵ֥ר בְּרִיתִ֖/י אִתָּ֑/ם כִּ֛י אֲנִ֥י יְהוָ֖ה אֱלֹהֵי/הֶֽם", "en": {"kjv": "And yet for all that, when they be in the land of their enemies, I will not cast them away, neither will I abhor them, to destroy them utterly, and to break my covenant with them: for I am the Lord their God.", "web": "Yet for all that, when they are in the land of their enemies, I will not reject them, neither will I abhor them, to destroy them utterly, and to break my covenant with them; for I am Yahweh their God;", "bsb": "Yet in spite of this, when they are in the land of their enemies, I will not reject or despise them so as to destroy them and break My covenant with them; for I am the LORD their God.", "asv": "And yet for all that, when they are in the land of their enemies, I will not reject them, neither will I abhor them, to destroy them utterly, and to break my covenant with them; for I am Jehovah their God;", "ylt": "and also even this, in their being in the land of their enemies, I have not rejected them, nor have I loathed them, to consume them, to break My covenant with them; for I am Jehovah their God; --", "tyndale": "And yet for all that when thei be in the londe of their enemyes, I will not so cast them awaye nor my soule shall not so abhorre them, that I will vtterlye destroye the ad breake myne appoyntment with them: for I am the Lorde their God.", "dra": "And yet for all that when they were in the land of their enemies, I did not cast them off altogether. Neither did I so despise them that they should be quite consumed: and I should make void my covenant with them. For I am the Lord their God.", "bbe": "But for all that, when they are in the land of their haters I will not let them go, or be turned away from them, or give them up completely; my agreement with them will not be broken, for I am the Lord their God.", "geneva": "Yet notwithstanding this, when they shalbe in the lande of their enemies, I wil not cast them away, neither will I abhorre them, to destroy them vtterly, nor to breake my couenant with them: for I am the Lord their God:", "wycliffe": "netheles, yhe, whanne thei weren in `the lond of enemyes, Y castide not hem awey outirli, nether Y dispiside hem, so that thei weren wastid, and that Y made voide my couenaunt with hem; for Y am the Lord God of hem.", "rotherham": "And yet even so when they are in the land of their foes I have not refused them Neither have I abhorred them To make an end of them, To break my covenant with them,—For, I—Yahweh, am their God.", "darby": "And yet for all that, when they are in the land of their enemies, I will not despise them, and will not abhor them, to make an end of them utterly, to break my covenant with them, for I am Jehovah theirGod.", "twenty": "", "jps": "And yet for all that, when they are in the land of their enemies, I will not reject them, neither will I abhor them, to destroy them utterly, and to break My covenant with them; for I am HaShem their G-d.", "acv": "And yet for all that, when they are in the land of their enemies, I will not reject them, neither will I abhor them, to destroy them utterly, and to break my covenant with them, for I am Jehovah their God,", "anderson": "", "haweis": "", "noyes": "", "webster": "And yet for all that, when they shall be in the land of their enemies, I will not cast them away, neither will I abhor them, to destroy them utterly, and to break my covenant with them; for I [am] the LORD their God.", "vulgate": "et tamen etiam cum essent in terra hostili non penitus abieci eos neque sic despexi ut consumerentur et irritum facerem pactum meum cum eis ego enim sum Dominus Deus eorum;", "brenton": "And yet not even thus, while they were in the land of their enemies, did I overlook them, nor did I loathe them so as to consume them, to break my covenant made with them; for I am the Lord their God."}}, {"v": 45, "ref": "26:45", "o": "וְ/זָכַרְתִּ֥י לָ/הֶ֖ם בְּרִ֣ית רִאשֹׁנִ֑ים אֲשֶׁ֣ר הוֹצֵֽאתִי אֹתָ/ם֩ מֵ/אֶ֨רֶץ מִצְרַ֜יִם לְ/עֵינֵ֣י הַ/גּוֹיִ֗ם לִ/הְיֹ֥ת לָ/הֶ֛ם לֵ/אלֹהִ֖ים אֲנִ֥י יְהוָֽה", "en": {"kjv": "But I will for their sakes remember the covenant of their ancestors, whom I brought forth out of the land of Egypt in the sight of the heathen, that I might be their God: I am the Lord.", "web": "but I will for their sake remember the covenant of their ancestors, whom I brought out of the land of Egypt in the sight of the nations, that I might be their God. I am Yahweh.’”", "bsb": "But for their sake I will remember the covenant with their fathers, whom I brought out of the land of Egypt in the sight of the nations, that I might be their God. I am the LORD.”", "asv": "but I will for their sakes remember the covenant of their ancestors, whom I brought forth out of the land of Egypt in the sight of the nations, that I might be their God: I am Jehovah.", "ylt": "then I have remembered for them the covenant of the ancestors, whom I brought forth out of the land of Egypt before the eyes of the nations to become their God; I am Jehovah.'", "tyndale": "I will therfore remebre vnto the the first couenaunt made when I broughte them out of the lond of Egipte in the sighte of the hethen to be their God: for I am the Lorde.", "dra": "And I will remember my former covenant, when I brought them out of the land of Egypt, in the sight of the Gentiles, to be their God. I am the Lord. These are the judgments, and precepts, and laws, which the Lord gave between him and the children of Israel, in mount Sinai, by the hand of Moses.", "bbe": "And because of them I will keep in mind the agreement which I made with their fathers, whom I took out of the land of Egypt before the eyes of the nations, to be their God: I am the Lord.", "geneva": "But I will remember for them the couenant of olde when I brought them out of ye land of Egypt in the sight of the heathen that I might be their God: I am the Lord.", "wycliffe": "And Y schal haue mynde of my formere boond of pees, whanne Y ledde hem out of the lond of Egipt, in the siyt of hethene men, that Y schulde be her God; Y am the Lord God. These ben the comaundementis, and domes, and lawis, whiche the Lord yaf bitwixe hym silf and bitwixe the sones of Israel, in the hil of Synay, bi the hond of Moises.", "rotherham": "Therefore will I remember in their behalf the covenant of their ancestors,—Whom, I brought forth out of the land of Egypt in the sight of the nations, that I might be their God—I—Yahweh.", "darby": "But I will remember toward them the covenant with their ancestors whom I brought forth out of the land of Egypt before the eyes of the nations, that I might be theirGod: I am Jehovah.", "twenty": "", "jps": "But I will for their sakes remember the covenant of their ancestors, whom I brought forth out of the land of Egypt in the sight of the nations, that I might be their G-d: I am HaShem.", "acv": "but for their sakes I will remember the covenant of their ancestors, whom I brought forth out of the land of Egypt in the sight of the nations, that I might be their God. I am Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "But I will for their sakes remember the covenant of their ancestors, whom I brought out of the land of Egypt in the sight of the heathen, that I might be their God: I [am] the LORD.", "vulgate": "et recordabor foederis mei pristini quando eduxi eos de terra Aegypti in conspectu gentium ut essem Deus eorum ego Dominus Deus haec sunt praecepta atque iudicia et leges quas dedit Dominus inter se et inter filios Israhel in monte Sinai per manum Mosi;", "brenton": "And I will remember their former covenant, when I brought them out of the land of Egypt, out of the house of bondage before the nation, to be their God; I am the Lord."}}, {"v": 46, "ref": "26:46", "o": "אֵ֠לֶּה הַֽ/חֻקִּ֣ים וְ/הַ/מִּשְׁפָּטִים֮ וְ/הַ/תּוֹרֹת֒ אֲשֶׁר֙ נָתַ֣ן יְהוָ֔ה בֵּינ֕/וֹ וּ/בֵ֖ין בְּנֵ֣י יִשְׂרָאֵ֑ל בְּ/הַ֥ר סִינַ֖י בְּ/יַד מֹשֶֽׁה", "en": {"kjv": "These are the statutes and judgments and laws, which the Lord made between him and the children of Israel in mount Sinai by the hand of Moses.", "web": "These are the statutes, ordinances and laws, which Yahweh made between him and the children of Israel in Mount Sinai by Moses.", "bsb": "These are the statutes, ordinances, and laws that the LORD established between Himself and the Israelites through Moses on Mount Sinai.", "asv": "These are the statutes and ordinances and laws, which Jehovah made between him and the children of Israel in mount Sinai by Moses.", "ylt": "These are the statutes, and the judgments, and the laws, which Jehovah hath given between Him and the sons of Israel, in mount Sinai, by the hand of Moses.", "tyndale": "These are the ordinaunces, iudgemetes, ad lawes which the Lorde made betwene him ad the childern of Israel in mount Sinai by the hade of Moses.", "dra": "", "bbe": "These are the rules, decisions, and laws, which the Lord made between himself and the children of Israel in Mount Sinai, by the hand of Moses.", "geneva": "These are the ordinances, and the iudgements, and the lawes, which the Lord made betweene him, and the children of Israel in mount Sinai, by the hand of Moses.", "wycliffe": "", "rotherham": "These are the statutes and the regulations and the laws, which Yahweh granted between himself, and the sons of Israel,—in Mount Sinai by the mediation of Moses.", "darby": "These are the statutes and ordinances and laws which Jehovah made between him and the children of Israel in mount Sinai, by the hand of Moses.", "twenty": "", "jps": "These are the statutes and ordinances and laws, which HaShem made between Him and the children of Israel in mount Sinai by the hand of Moses.", "acv": "These are the statutes and ordinances and laws, which Jehovah made between him and the sons of Israel at mount Sinai by Moses.", "anderson": "", "haweis": "", "noyes": "", "webster": "These [are] the statutes, and judgments, and laws, which the LORD made between him and the children of Israel in mount Sinai by the hand of Moses.", "vulgate": "", "brenton": "These are my judgments and my ordinances, and the law which the Lord gave between himself and the children of Israel, in the mount Sina, by the hand of Moses."}}]}, {"c": 27, "verses": [{"v": 1, "ref": "27:1", "o": "וַ/יְדַבֵּ֥ר יְהוָ֖ה אֶל מֹשֶׁ֥ה לֵּ/אמֹֽר", "en": {"kjv": "And the Lord spake unto Moses, saying,", "web": "Yahweh spoke to Moses, saying,", "bsb": "Then the LORD said to Moses,", "asv": "And Jehovah spake unto Moses, saying,", "ylt": "And Jehovah speaketh unto Moses, saying,", "tyndale": "And the Lorde spake vnto Moses saynge:", "dra": "And the Lord spoke to Moses, saying:", "bbe": "And the Lord said to Moses,", "geneva": "Moreouer the Lord spake vnto Moses, saying,", "wycliffe": "And the Lord spak to Moises and seide, Speke thou to the sones of Israel,", "rotherham": "And Yahweh spake unto Moses, saying:", "darby": "And Jehovah spoke to Moses, saying,", "twenty": "", "jps": "And HaShem spoke unto Moses, saying:", "acv": "And Jehovah spoke to Moses, saying,", "anderson": "", "haweis": "", "noyes": "", "webster": "And the LORD spoke to Moses, saying,", "vulgate": "locutusque est Dominus ad Mosen dicens;", "brenton": "And the Lord spoke to Moses, saying,"}}, {"v": 2, "ref": "27:2", "o": "דַּבֵּ֞ר אֶל בְּנֵ֤י יִשְׂרָאֵל֙ וְ/אָמַרְתָּ֣ אֲלֵ/הֶ֔ם אִ֕ישׁ כִּ֥י יַפְלִ֖א נֶ֑דֶר בְּ/עֶרְכְּ/ךָ֥ נְפָשֹׁ֖ת לַֽ/יהוָֽה", "en": {"kjv": "Speak unto the children of Israel, and say unto them, When a man shall make a singular vow, the persons shall be for the Lord by thy estimation.", "web": "“Speak to the children of Israel, and say to them, ‘When a man consecrates a person to Yahweh in a vow, according to your valuation,", "bsb": "“Speak to the Israelites and say to them, ‘When someone makes a special vow to the LORD involving the value of persons,", "asv": "Speak unto the children of Israel, and say unto them, When a man shall accomplish a vow, the persons shall be for Jehovah by thy estimation.", "ylt": "`Speak unto the sons of Israel, and thou hast said unto them, When a man maketh a wonderful vow, by thy valuation the persons are Jehovah's.", "tyndale": "speake vnto the childern of Israel and saye vnto them: Yf any man will geue a synguler vowe vnto the Lorde acordynge to the value", "dra": "Speak to the children of Israel, and thou shalt say to them: The man that shall have made a vow, and promised his soul to God, shall give the price according to estimation.", "bbe": "Say to the children of Israel, If a man makes a special oath, you will give your decision as to the value of the persons for the Lord.", "geneva": "Speake vnto the children of Israel, and say vnto them, If any man shall make a vowe of a person vnto the Lord, by thy estimation,", "wycliffe": "and thou schalt seye to hem, A man that makith avow, and bihetith his soule to God, schal yyue the priys vndur valu, ether preisyng.", "rotherham": "Speak unto the sons of Israel and thou shall say unto them—When any man would consecrate and pay a vow by thine estimate of lives unto Yahweh,", "darby": "Speak unto the children of Israel and say unto them, When any one devoteth [anything] by a vow, the persons shall be for Jehovah according to thy valuation.", "twenty": "", "jps": "Speak unto the children of Israel, and say unto them: When a man shall clearly utter a vow of persons unto HaShem, according to thy valuation,", "acv": "Speak to the sons of Israel, and say to them, When a man shall accomplish a vow, the persons shall be for Jehovah by thy estimation.", "anderson": "", "haweis": "", "noyes": "", "webster": "Speak to the children of Israel, and say to them, When a man shall make a singular vow, the persons [shall be] for the LORD, by thy estimation.", "vulgate": "loquere filiis Israhel et dices ad eos homo qui votum fecerit et spoponderit Deo animam suam sub aestimatione dabit pretium;", "brenton": "Speak to the children of Israel, and thou shalt say to them, Whosoever shall vow a vow as the valuation of his soul for the Lord,"}}, {"v": 3, "ref": "27:3", "o": "וְ/הָיָ֤ה עֶרְכְּ/ךָ֙ הַ/זָּכָ֔ר מִ/בֶּן֙ עֶשְׂרִ֣ים שָׁנָ֔ה וְ/עַ֖ד בֶּן שִׁשִּׁ֣ים שָׁנָ֑ה וְ/הָיָ֣ה עֶרְכְּ/ךָ֗ חֲמִשִּׁ֛ים שֶׁ֥קֶל כֶּ֖סֶף בְּ/שֶׁ֥קֶל הַ/קֹּֽדֶשׁ", "en": {"kjv": "And thy estimation shall be of the male from twenty years old even unto sixty years old, even thy estimation shall be fifty shekels of silver, after the shekel of the sanctuary.", "web": "your valuation of a male from twenty years old even to sixty years old shall be fifty shekels of silver, after the shekel of the sanctuary.", "bsb": "if the valuation concerns a male from twenty to sixty years of age, then your valuation shall be fifty shekels of silver, according to the sanctuary shekel.", "asv": "And thy estimation shall be of the male from twenty years old even unto sixty years old, even thy estimation shall be fifty shekels of silver, after the shekel of the sanctuary.", "ylt": "When thy valuation hath been of the male from a son of twenty years even unto a son of sixty years, then hath been thy valuation fifty shekels of silver by the shekel of the sanctuary.", "tyndale": "of his soule then shall the male from .xx. yere vnto .lx. be set at fyftie sycles of syluer after the sycle of the sanctuary", "dra": "If it be a man from twenty years old unto sixty years old, he shall give fifty sicles of silver, after the weight of the sanctuary:", "bbe": "And you will put the value of a male from twenty years to sixty years old at fifty shekels of silver, by the scale of the holy place.", "geneva": "Then thy estimation shall bee thus: a male from twentie yeere olde vnto sixty yeere olde shalbe by thy estimation euen fifty shekels of siluer, after the shekel of the Sanctuarie.", "wycliffe": "If it is a male, fro the twentithe yeer `til to the sixtithe yeer, he schal yyue fifti siclis of siluer, at the mesure of seyntuarie, if it is a womman,", "rotherham": "then shall, thine estimate be for the male from twenty years of age even to sixty years of age, yea thine estimate shall be—fifty shekels of silver by the shekel of the sanctuary;", "darby": "And thy valuation shall be of the male from twenty years old even unto sixty years old: thy valuation shall be fifty shekels of silver, after the shekel of the sanctuary;", "twenty": "", "jps": "then thy valuation shall be for the male from twenty years old even unto sixty years old, even thy valuation shall be fifty shekels of silver, after the shekel of the sanctuary.", "acv": "And thy estimation shall be of the male from twenty years old even to sixty years old, even thy estimation shall be fifty shekels of silver, after the shekel of the sanctuary.", "anderson": "", "haweis": "", "noyes": "", "webster": "And thy estimation shall be, of the male from twenty years old even to sixty years old, even thy estimation shall be fifty shekels of silver, after the shekel of the sanctuary.", "vulgate": "si fuerit masculus a vicesimo usque ad sexagesimum annum dabit quinquaginta siclos argenti ad mensuram sanctuarii;", "brenton": "the valuation of a male from twenty years old to sixty years old shall be his valuation shall be fifty didrachms of silver by the standard of the sanctuary."}}, {"v": 4, "ref": "27:4", "o": "וְ/אִם נְקֵבָ֖ה הִ֑וא וְ/הָיָ֥ה עֶרְכְּ/ךָ֖ שְׁלֹשִׁ֥ים שָֽׁקֶל", "en": {"kjv": "And if it be a female, then thy estimation shall be thirty shekels.", "web": "If she is a female, then your valuation shall be thirty shekels.", "bsb": "Or if it is a female, then your valuation shall be thirty shekels.", "asv": "And if it be a female, then thy estimation shall be thirty shekels.", "ylt": "And if it is a female--then hath thy valuation been thirty shekels;", "tyndale": "and the female at .xxx. sycles.", "dra": "If a woman, thirty.", "bbe": "And if it is a female, the value will be thirty shekels.", "geneva": "But if it be a female, then thy valuation shall be thirtie shekels.", "wycliffe": "sche schal yyue thretti siclis;", "rotherham": "but if it be, a female, then shall thine estimate be thirty shekels.", "darby": "and if it be of a female, thy valuation shall be thirty shekels.", "twenty": "", "jps": "And if it be a female, then thy valuation shall be thirty shekels.", "acv": "And if it be a female, then thy estimation shall be thirty shekels.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if it [shall be] a female, then thy estimation shall be thirty shekels.", "vulgate": "si mulier triginta;", "brenton": "And the valuation of a female shall be thirty didrachms."}}, {"v": 5, "ref": "27:5", "o": "וְ/אִ֨ם מִ/בֶּן חָמֵ֜שׁ שָׁנִ֗ים וְ/עַד֙ בֶּן עֶשְׂרִ֣ים שָׁנָ֔ה וְ/הָיָ֧ה עֶרְכְּ/ךָ֛ הַ/זָּכָ֖ר עֶשְׂרִ֣ים שְׁקָלִ֑ים וְ/לַ/נְּקֵבָ֖ה עֲשֶׂ֥רֶת שְׁקָלִֽים", "en": {"kjv": "And if it be from five years old even unto twenty years old, then thy estimation shall be of the male twenty shekels, and for the female ten shekels.", "web": "If the person is from five years old even to twenty years old, then your valuation shall be for a male twenty shekels, and for a female ten shekels.", "bsb": "And if the person is from five to twenty years of age, then your valuation for the male shall be twenty shekels, and for the female ten shekels.", "asv": "And if it be from five years old even unto twenty years old, then thy estimation shall be of the male twenty shekels, and for the female ten shekels.", "ylt": "and if from a son of five years even unto a son of twenty years--then hath thy valuation been of the male twenty shekels, and for the female, ten shekels;", "tyndale": "And from .v. yeres to xx. the male shalbe set at .xx. sycles and the female at .x. sycles.", "dra": "But from the fifth year until the twentieth, a man shall give twenty sicles: a woman ten.", "bbe": "And if the person is from five to twenty years old, the value will be twenty shekels for a male, and ten for a female.", "geneva": "And from fiue yere old to twentie yere olde thy valuation shall be for the male twentie shekels, and for the female ten shekels.", "wycliffe": "forsothe fro the fifthe yeer `til to the twentithe yeer, a male schal yyue twenti cyclis, a womman schal yyue ten ciclis;", "rotherham": "And, if it be from five years of age even unto twenty years of age, then shall thine estimate be for the male, twenty shekels,—and, for the female, ten shekels.", "darby": "And if it be from five years old even unto twenty years old, thy valuation of the male shall be twenty shekels, and for the female ten shekels.", "twenty": "", "jps": "And if it be from five years old even unto twenty years old, then thy valuation shall be for the male twenty shekels, and for the female ten shekels.", "acv": "And if it be from five years old even to twenty years old, then thy estimation shall be of the male twenty shekels, and for the female ten shekels.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if [it shall be] from five years old even to twenty years old, then thy estimation shall be of the male twenty shekels, and for the female ten shekels.", "vulgate": "a quinto autem anno usque ad vicesimum masculus dabit viginti siclos femina decem;", "brenton": "And if it be from five years old to twenty, the valuation of a male shall be twenty didrachms, and of a female ten didrachms."}}, {"v": 6, "ref": "27:6", "o": "וְ/אִ֣ם מִ/בֶּן חֹ֗דֶשׁ וְ/עַד֙ בֶּן חָמֵ֣שׁ שָׁנִ֔ים וְ/הָיָ֤ה עֶרְכְּ/ךָ֙ הַ/זָּכָ֔ר חֲמִשָּׁ֥ה שְׁקָלִ֖ים כָּ֑סֶף וְ/לַ/נְּקֵבָ֣ה עֶרְכְּ/ךָ֔ שְׁלֹ֥שֶׁת שְׁקָלִ֖ים כָּֽסֶף", "en": {"kjv": "And if it be from a month old even unto five years old, then thy estimation shall be of the male five shekels of silver, and for the female thy estimation shall be three shekels of silver.", "web": "If the person is from a month old even to five years old, then your valuation shall be for a male five shekels of silver, and for a female your valuation shall be three shekels of silver.", "bsb": "Now if the person is from one month to five years of age, then your valuation for the male shall be five shekels of silver, and for the female three shekels of silver.", "asv": "And if it be from a month old even unto five years old, then thy estimation shall be of the male five shekels of silver, and for the female thy estimation shall be three shekels of silver.", "ylt": "and if from a son of a month even unto a son of five years--then hath thy valuation been of the male five shekels of silver, and for the female thy valuation is three shekels of silver;", "tyndale": "And from a moneth vnto .v. yere the male shalbe set at .v. sycles of syluer and the female at thre.", "dra": "From one month until the fifth year, for a male shall be given five sicles: for a female three.", "bbe": "And if the person is from one month to five years old, then the value for a male will be five shekels of silver, and for a female three shekels.", "geneva": "But from a moneth old vnto fiue yere old, thy price of the male shall bee fiue shekels of siluer, and thy price of the female, three shekels of siluer.", "wycliffe": "fro o monethe `til to the fifthe yeer, fyue ciclis schulen be youun for a male, thre ciclis for a womman;", "rotherham": "And, if it be from a month old even unto five years old, then shall thine estimate be—for the male, five shekels of silver,—and, for the female, thine estimate [shall be] three shekels of silver.", "darby": "And if it be from a month old even unto five years old, thy valuation of the male shall be five shekels of silver; and for the female thy valuation shall be three shekels of silver.", "twenty": "", "jps": "And if it be from a month old even unto five years old, then thy valuation shall be for the male five shekels of silver, and for the female thy valuation shall be three shekels of silver.", "acv": "And if it be from a month old even to five years old, then thy estimation shall be of the male five shekels of silver, and for the female thy estimation shall be three shekels of silver.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if [it shall be] from a month old even to five years old, then thy estimation shall be of the male five shekels of silver, and for the female thy estimation [shall be] three shekels of silver.", "vulgate": "ab uno mense usque ad annum quintum pro masculo dabuntur quinque sicli pro femina tres;", "brenton": "And from a month old to five years old, the valuation of a male shall be five didrachms, and of a female, three didrachms of silver."}}, {"v": 7, "ref": "27:7", "o": "וְ֠/אִם מִ/בֶּן שִׁשִּׁ֨ים שָׁנָ֤ה וָ/מַ֨עְלָ/ה֙ אִם זָכָ֔ר וְ/הָיָ֣ה עֶרְכְּ/ךָ֔ חֲמִשָּׁ֥ה עָשָׂ֖ר שָׁ֑קֶל וְ/לַ/נְּקֵבָ֖ה עֲשָׂרָ֥ה שְׁקָלִֽים", "en": {"kjv": "And if it be from sixty years old and above; if it be a male, then thy estimation shall be fifteen shekels, and for the female ten shekels.", "web": "If the person is from sixty years old and upward; if he is a male, then your valuation shall be fifteen shekels, and for a female ten shekels.", "bsb": "And if the person is sixty years of age or older, then your valuation shall be fifteen shekels for the male and ten shekels for the female.", "asv": "And if it be from sixty years old and upward; if it be a male, then thy estimation shall be fifteen shekels, and for the female ten shekels.", "ylt": "and if from a son of sixty years and above--if a male, then hath thy valuation been fifteen shekels, and for a female, ten shekels.", "tyndale": "And the man that is .lx. and aboue shalbe valowed at .xv. sicles, ad the woman at .x.", "dra": "A man that is sixty years old or upward, shall give fifteen sicles: a woman ten.", "bbe": "And for sixty years old and over, for a male the value will be fifteen shekels, and for a female, ten.", "geneva": "And from sixty yeere olde and aboue, if he be a male, then thy price shalbe fifteene shekels, and for the female ten shekels.", "wycliffe": "a male of sixti yeer and ouer schal yyue fiftene ciclis, a womman schal yyue ten cyclis.", "rotherham": "And if it be from sixty years of age and upwards, if a male, then shall thine estimate be fifteen shekels,—and, for the female, ten shekels.", "darby": "And if it be from sixty years old and above, if it be a male, thy valuation shall be fifteen shekels; and for the female ten shekels.", "twenty": "", "jps": "And if it be from sixty years old and upward: if it be a male, then thy valuation shall be fifteen shekels, and for the female ten shekels.", "acv": "And if it be from sixty years old and upward, if it be a male, then thy estimation shall be fifteen shekels, and for the female ten shekels.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if [it shall be] from sixty years old and above; if a male, then thy estimation shall be fifteen shekels, and for the female ten shekels.", "vulgate": "sexagenarius et ultra masculus dabit quindecim siclos femina decem;", "brenton": "And if from sixty year old and upward, if it be a male, his valuation shall be fifteen didrachms of silver, and if a female, ten didrachms."}}, {"v": 8, "ref": "27:8", "o": "וְ/אִם מָ֥ךְ הוּא֙ מֵֽ/עֶרְכֶּ֔/ךָ וְ/הֶֽעֱמִיד/וֹ֙ לִ/פְנֵ֣י הַ/כֹּהֵ֔ן וְ/הֶעֱרִ֥יךְ אֹת֖/וֹ הַ/כֹּהֵ֑ן עַל פִּ֗י אֲשֶׁ֤ר תַּשִּׂיג֙ יַ֣ד הַ/נֹּדֵ֔ר יַעֲרִיכֶ֖/נּוּ הַ/כֹּהֵֽן", "en": {"kjv": "But if he be poorer than thy estimation, then he shall present himself before the priest, and the priest shall value him; according to his ability that vowed shall the priest value him.", "web": "But if he is poorer than your valuation, then he shall be set before the priest, and the priest shall assign a value to him. The priest shall assign a value according to his ability to pay.", "bsb": "But if the one making the vow is too poor to pay the valuation, he is to present the person before the priest, who shall set the value according to what the one making the vow can afford.", "asv": "But if he be poorer than thy estimation, then he shall be set before the priest, and the priest shall value him; according to the ability of him that vowed shall the priest value him.", "ylt": "`And if he is poorer than thy valuation, then he hath presented himself before the priest, and the priest hath valued him; according to that which the hand of him who is vowing doth reach doth the priest value him.", "tyndale": "Yf he be to poore so to be set, the let him come before the preast: and let the preast value him acordynge as the hande of him that vowed is able to gete.", "dra": "If he be poor, and not able to pay the estimation, he shall stand before the priest: and as much as he shall value him at, and see him able to pay, so much shall he give.", "bbe": "But if he is poorer than the value which you have put on him, then let him be taken to the priest, and the priest will put a value on him, such as it is possible for him to give.", "geneva": "But if he be poorer then thou hast esteemed him, then shall hee present himselfe before the Priest, and the Priest shall value him, according to the abilitie of him that vowed, so shall the Priest value him.", "wycliffe": "If it is a pore man, and may not yelde the valu, he schal stonde bifor the preest, and as myche as the preest preisith, and seeth that the pore man may yelde, so myche he schal yyue.", "rotherham": "But if he be, too poor, for thine estimate, then shall he present himself before the priest, and the priest shall estimate him,—according to that which the hand of him who would vow can attain to, shall the priest estimate him.", "darby": "And if he be poorer than thy valuation, he shall present himself before the priest, and the priest shall value him: according to his means that vowed shall the priest value him.", "twenty": "", "jps": "But if he be too poor for thy valuation, then he shall be set before the priest, and the priest shall value him; according to the means of him that vowed shall the priest value him.", "acv": "But if he be poorer than thy estimation, then he shall be set before the priest, and the priest shall value him; according to the ability of him who vowed shall the priest value him.", "anderson": "", "haweis": "", "noyes": "", "webster": "But if he shall be poorer than thy estimation, then he shall present himself before the priest, and the priest shall value him: according to his ability that vowed shall the priest value him.", "vulgate": "si pauper fuerit et aestimationem reddere non valebit stabit coram sacerdote et quantum ille aestimaverit et viderit eum posse reddere tantum dabit;", "brenton": "And if the man be too poor for the valuation, he shall stand before the priest; and the priest shall value him: according to what the man who has vowed can afford, the priest shall value him."}}, {"v": 9, "ref": "27:9", "o": "וְ/אִם בְּהֵמָ֔ה אֲשֶׁ֨ר יַקְרִ֧יבוּ מִמֶּ֛/נָּה קָרְבָּ֖ן לַֽ/יהוָ֑ה כֹּל֩ אֲשֶׁ֨ר יִתֵּ֥ן מִמֶּ֛/נּוּ לַ/יהוָ֖ה יִֽהְיֶה קֹּֽדֶשׁ", "en": {"kjv": "And if it be a beast, whereof men bring an offering unto the Lord, all that any man giveth of such unto the Lord shall be holy.", "web": "“‘If it is an animal, of which men offer an offering to Yahweh, all that any man gives of such to Yahweh becomes holy.", "bsb": "If he vows an animal that may be brought as an offering to the LORD, any such animal given to the LORD shall be holy.", "asv": "And if it be a beast, whereof men offer an oblation unto Jehovah, all that any man giveth of such unto Jehovah shall be holy.", "ylt": "`And if it is a beast of which they bring near an offering to Jehovah, all that one giveth of it to Jehovah is holy;", "tyndale": "Yf it be of the beestes of which men bringe an offeringe vnto the Lorde: all that any man geueth of soch vnto the Lorde shalbe holy.", "dra": "But a beast that may be sacrificed to the Lord, if any one shall vow, shall be holy,", "bbe": "And if it is a beast of which men make offerings to the Lord, whatever any man gives of such to the Lord will be holy.", "geneva": "And if it be a beast, whereof men bring an offering vnto the Lord, all that one giueth of such vnto the Lord, shalbe holy.", "wycliffe": "Forsothe if ony man avowith a beeste, that may be offrid to the Lord, it schal be hooli,", "rotherham": "And if it be a beast whereof men may bring near an oblation unto Yahweh, all that whereof aught is given to Yahweh, shall be holy.", "darby": "And if it be a beast whereof men bring an offering unto Jehovah, all that they give of such unto Jehovah shall be holy.", "twenty": "", "jps": "And if it be a beast, whereof men bring an offering unto HaShem, all that any man giveth of such unto HaShem shall be holy.", "acv": "And if it be a beast, of which men offer an oblation to Jehovah, all that any man gives of such to Jehovah shall be holy.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if [it shall be] a beast of which men bring an offering to the LORD, all that [any man] giveth of such to the LORD shall be holy.", "vulgate": "animal autem quod immolari potest Domino si quis voverit sanctum erit;", "brenton": "And if it be from the cattle that are offered as a gift to the Lord, whoever shall offer one of these to the Lord, it shall be holy."}}, {"v": 10, "ref": "27:10", "o": "לֹ֣א יַחֲלִיפֶ֗/נּוּ וְ/לֹֽא יָמִ֥יר אֹת֛/וֹ ט֥וֹב בְּ/רָ֖ע אוֹ רַ֣ע בְּ/ט֑וֹב וְ/אִם הָמֵ֨ר יָמִ֤יר בְּהֵמָה֙ בִּ/בְהֵמָ֔ה וְ/הָֽיָה ה֥וּא וּ/תְמוּרָת֖/וֹ יִֽהְיֶה קֹּֽדֶשׁ", "en": {"kjv": "He shall not alter it, nor change it, a good for a bad, or a bad for a good: and if he shall at all change beast for beast, then it and the exchange thereof shall be holy.", "web": "He shall not alter it, nor change it, a good for a bad, or a bad for a good: and if he shall at all change animal for animal, then both it and that for which it is changed shall be holy.", "bsb": "He must not replace it or exchange it, either good for bad or bad for good. But if he does substitute one animal for another, both that animal and its substitute will be holy.", "asv": "He shall not alter it, nor change it, a good for a bad, or a bad for a good: and if he shall at all change beast for beast, then both it and that for which it is changed shall be holy.", "ylt": "he doth not change it nor exchange it, a good for a bad, or a bad for a good; and if he really change beast for beast, --then it hath been--it and its exchange is holy.", "tyndale": "He maye not alter it nor chaunge it: a good for a bad or a bad for a goode. Yf he chaunge beest for beest then both the same beest and it also where with it was chaunged shall be holy.", "dra": "And cannot be changed: that is to say, neither a better for a worse, nor a worse for a better. And if he shall change it: both that which was changed, and that for which it was changed, shall be consecrated to the Lord.", "bbe": "It may not be changed in any way, a good given for a bad, or a bad for a good; if one beast is changed for another, the two will be holy.", "geneva": "He shall not alter it nor change it, a good for a badde, nor a badde for a good: and if hee change beast for beast, then both this and that, which was changed for it, shall be holy.", "wycliffe": "and schal not mow be chaungid, that is, nethir a betere for `an yuel, nether `a worse for a good; and if he chaungith it, bothe that, that is chaungid, and that, for which it is chaungid, schal be halewid to the Lord.", "rotherham": "He shall not alter it, nor change it—good for bad or bad for good,—but if he, do, change beast for beast, then shall, both it and what was given in exchange for it be holy.", "darby": "They shall not alter it nor change it, a good for a bad, or a bad for a good; and if he at all change beast for beast, then it and the exchange thereof shall be holy.", "twenty": "", "jps": "He shall not alter it, nor change it, a good for a bad, or a bad for a good; and if he shall at all change beast for beast, then both it and that for which it is changed shall be holy.", "acv": "He shall not alter it, nor change it, a good for a bad, or a bad for a good. And if he shall at all change beast for beast, then both it and that for which it is changed shall be holy.", "anderson": "", "haweis": "", "noyes": "", "webster": "He shall not alter it, nor change it, a good for a bad, or a bad for a good: and if he shall at all change beast for beast, then it and the exchange of it shall be holy.", "vulgate": "et mutari non poterit id est nec melius malo nec peius bono quod si mutaverit et ipsum quod mutatum est et illud pro quo mutatum est consecratum erit Domino;", "brenton": "He shall not change it, a good for a bad, or a bad for a good; and if he do at all change it, a beast for a beast, it and the substitute shall be holy."}}, {"v": 11, "ref": "27:11", "o": "וְ/אִם֙ כָּל בְּהֵמָ֣ה טְמֵאָ֔ה אֲ֠שֶׁר לֹא יַקְרִ֧יבוּ מִמֶּ֛/נָּה קָרְבָּ֖ן לַֽ/יהוָ֑ה וְ/הֶֽעֱמִ֥יד אֶת הַ/בְּהֵמָ֖ה לִ/פְנֵ֥י הַ/כֹּהֵֽן", "en": {"kjv": "And if it be any unclean beast, of which they do not offer a sacrifice unto the Lord, then he shall present the beast before the priest:", "web": "If it is any unclean animal, of which they do not offer as an offering to Yahweh, then he shall set the animal before the priest;", "bsb": "But if the vow involves any of the unclean animals that may not be brought as an offering to the LORD, the animal must be presented before the priest.", "asv": "And if it be any unclean beast, of which they do not offer an oblation unto Jehovah, then he shall set the beast before the priest;", "ylt": "`And if it is any unclean beast of which they do not bring near an offering to Jehovah, then he hath presented the beast before the priest,", "tyndale": "yf it be any maner of vncleane beest of which men maye not offer vnto the Lorde let him brynge the beest before the preast", "dra": "An unclean beast, which cannot be sacrificed to the Lord, if any man shall vow, shall be brought before the priest:", "bbe": "And if it is any unclean beast, of which offerings are not made to the Lord, then let him take the beast before the priest;", "geneva": "And if it be any vncleane beast, of which men do not offer a sacrifice vnto the Lord, hee shall then present the beast before the Priest.", "wycliffe": "Sotheli if ony man avowith an vncleene beeste, that may not be offrid to the Lord, it schal be brouyt bifor the preest,", "rotherham": "And, if it be any unclean beast whereof men may not bring near an oblation to Yahweh, then shall he present the beast before the priest:", "darby": "And if it be any unclean beast, of which they do not bring an offering unto Jehovah, then he shall present the beast before the priest;", "twenty": "", "jps": "And if it be any unclean beast, of which they may not bring an offering unto HaShem, then he shall set the beast before the priest.", "acv": "And if it be any unclean beast, of which they do not offer an oblation to Jehovah, then he shall set the beast before the priest,", "anderson": "", "haweis": "", "noyes": "", "webster": "And if [it shall be] any unclean beast, of which they do not offer a sacrifice to the LORD, then he shall present the beast before the priest:", "vulgate": "animal inmundum quod immolari Domino non potest si quis voverit adducetur ante sacerdotem;", "brenton": "And if it be any unclean beast, of which none are offered as a gift to the Lord, he shall set the beast before the priest."}}, {"v": 12, "ref": "27:12", "o": "וְ/הֶעֱרִ֤יךְ הַ/כֹּהֵן֙ אֹתָ֔/הּ בֵּ֥ין ט֖וֹב וּ/בֵ֣ין רָ֑ע כְּ/עֶרְכְּ/ךָ֥ הַ/כֹּהֵ֖ן כֵּ֥ן יִהְיֶֽה", "en": {"kjv": "And the priest shall value it, whether it be good or bad: as thou valuest it, who art the priest, so shall it be.", "web": "and the priest shall value it, whether it is good or bad. As you the priest values it, so shall it be.", "bsb": "The priest shall set its value, whether high or low; as the priest values it, the price will be set.", "asv": "and the priest shall value it, whether it be good or bad: as thou the priest valuest it, so shall it be.", "ylt": "and the priest hath valued it; whether good or bad, according to thy valuation, O priest, so it is;", "tyndale": "and let the preast value it. And whether it be good or bad as the preast setteth it so shall it be.", "dra": "Who judging whether it be good or bad, shall set the price.", "bbe": "And let the priest put a value on it, if it is good or bad; whatever value the priest puts on it, so will it be.", "geneva": "And the Priest shall value it, whether it be good or bad: and as thou valuest it, which art the Priest, so shall it bee.", "wycliffe": "and the preest schal deme whether it is good ether yuel, and schal sette the prijs;", "rotherham": "and the priest shall estimate it, whether it is good or bad,—according to thine estimate, O priest, so, shall it be.", "darby": "and the priest shall value it, [judging] between good and bad: according to the valuation of the priest, so shall it be.", "twenty": "", "jps": "And the priest shall value it, whether it be good or bad; as thou the priest valuest it, so shall it be.", "acv": "and the priest shall value it, whether it be good or bad. As thou the priest values it, so shall it be.", "anderson": "", "haweis": "", "noyes": "", "webster": "And the priest shall value it, whether it be good or bad: as thou valuest it, [who art] the priest, so shall it be.", "vulgate": "qui diiudicans utrum bonum an malum sit statuet pretium;", "brenton": "And the priest shall make a valuation between the good and the bad, and accordingly as the priest shall value it, so shall it stand."}}, {"v": 13, "ref": "27:13", "o": "וְ/אִם גָּאֹ֖ל יִגְאָלֶ֑/נָּה וְ/יָסַ֥ף חֲמִישִׁת֖/וֹ עַל עֶרְכֶּֽ/ךָ", "en": {"kjv": "But if he will at all redeem it, then he shall add a fifth part thereof unto thy estimation.", "web": "But if he will indeed redeem it, then he shall add the fifth part of it to its valuation.", "bsb": "If, however, the owner decides to redeem the animal, he must add a fifth to its value.", "asv": "But if he will indeed redeem it, then he shall add the fifth part thereof unto thy estimation.", "ylt": "and if he really redeem it, then he hath added its fifth to thy valuation.", "tyndale": "And yf he will bye it agayne let him geue the fyfte parte moare to that it was set at.", "dra": "Which, if he that offereth it will give, he shall add above the estimation the fifth part.", "bbe": "But if he has a desire to get it back for himself, let him give a fifth more than your value.", "geneva": "But if he will bye it againe, then hee shall giue the fift part of it more, aboue thy valuation.", "wycliffe": "which prijs if he that offrith wole yyue, he schal adde the fifthe part ouer the valu.", "rotherham": "But if he should please to redeem, it, then shall he add the fifth part thereof unto thine estimate.", "darby": "And if they will in any wise redeem it, then they shall add a fifth [part] thereof unto thy valuation.", "twenty": "", "jps": "But if he will indeed redeem it, then he shall add the fifth part thereof unto thy valuation.", "acv": "But if he will indeed redeem it, then he shall add the fifth part of it to thy estimation.", "anderson": "", "haweis": "", "noyes": "", "webster": "But if he will at all redeem it, then he shall add a fifth [part] of it to thy estimation.", "vulgate": "quod si dare voluerit is qui offert addet supra aestimationis quintam partem;", "brenton": "And if the worshipper will at all redeem it, he shall add the fifth part to its value."}}, {"v": 14, "ref": "27:14", "o": "וְ/אִ֗ישׁ כִּֽי יַקְדִּ֨שׁ אֶת בֵּית֥/וֹ קֹ֨דֶשׁ֙ לַֽ/יהוָ֔ה וְ/הֶעֱרִיכ/וֹ֙ הַ/כֹּהֵ֔ן בֵּ֥ין ט֖וֹב וּ/בֵ֣ין רָ֑ע כַּ/אֲשֶׁ֨ר יַעֲרִ֥יךְ אֹת֛/וֹ הַ/כֹּהֵ֖ן כֵּ֥ן יָקֽוּם", "en": {"kjv": "And when a man shall sanctify his house to be holy unto the Lord, then the priest shall estimate it, whether it be good or bad: as the priest shall estimate it, so shall it stand.", "web": "“‘When a man dedicates his house to be holy to Yahweh, then the priest shall evaluate it, whether it is good or bad: as the priest shall evaluate it, so shall it stand.", "bsb": "Now if a man consecrates his house as holy to the LORD, then the priest shall value it either as good or bad. The price will stand just as the priest values it.", "asv": "And when a man shall sanctify his house to be holy unto Jehovah, then the priest shall estimate it, whether it be good or bad: as the priest shall estimate it, so shall it stand.", "ylt": "`And when a man sanctifieth his house, a holy thing to Jehovah, then hath the priest valued it, whether good or bad; as the priest doth value it so it standeth;", "tyndale": "Yf any man dedicate his housse it shalbe holy vnto the Lorde. And the preast shall set it. whether it be good or bad and as the preast hath set it so it shalbe.", "dra": "If a man shall vow his house, and sanctify it to the Lord, the priest shall consider it, whether it be good or bad: and it shall be sold according to the price, which he shall appoint.", "bbe": "And if a man has given his house as holy to the Lord, then the priest will put a value on it, if it is good or bad; as the priest gives decision so will the value be fixed.", "geneva": "Also whe a man shall dedicate his house to be holy vnto the Lord, then the Priest shall value it, whether it be good or bad, and as ye Priest shall prise it, so shall the value be.", "wycliffe": "If a man avowith his hows, and halewith it to the Lord, the preest schal biholde, `whether it is good ether yuel, and bi the prijs, which is ordeyned of hym, it schal be seld;", "rotherham": "And, when, any man, would hallow his house to be holy unto Yahweh, then shall the priest estimate it, whether it is good or bad,—as the priest shall estimate it, so, shall it stand.", "darby": "And when any one halloweth his house, that it may be holy to Jehovah, the priest shall value it, [judging] between good and bad: as the priest shall value it, so shall it stand.", "twenty": "", "jps": "And when a man shall sanctify his house to be holy unto HaShem, then the priest shall value it, whether it be good or bad; as the priest shall value it, so shall it stand.", "acv": "And when a man shall sanctify his house to be holy to Jehovah, then the priest shall estimate it, whether it be good or bad. As the priest shall estimate it, so shall it stand.", "anderson": "", "haweis": "", "noyes": "", "webster": "And when a man shall sanctify his house [to be] holy to the LORD, then the priest shall estimate it, whether it is good or bad: as the priest shall estimate it, so shall it stand.", "vulgate": "homo si voverit domum suam et sanctificaverit Domino considerabit eam sacerdos utrum bona an mala sit et iuxta pretium quod ab eo fuerit constitutum venundabitur;", "brenton": "And whatsoever man shall consecrate his house as holy to the Lord, the priest shall make a valuation of it between the good and the bad: as the priest shall value it, so shall it stand."}}, {"v": 15, "ref": "27:15", "o": "וְ/אִ֨ם הַ/מַּקְדִּ֔ישׁ יִגְאַ֖ל אֶת בֵּית֑/וֹ וְ֠/יָסַף חֲמִישִׁ֧ית כֶּֽסֶף עֶרְכְּ/ךָ֛ עָלָ֖י/ו וְ/הָ֥יָה לֽ/וֹ", "en": {"kjv": "And if he that sanctified it will redeem his house, then he shall add the fifth part of the money of thy estimation unto it, and it shall be his.", "web": "If he who dedicates it will redeem his house, then he shall add the fifth part of the money of your valuation to it, and it shall be his.", "bsb": "But if he who consecrated his house redeems it, he must add a fifth to the assessed value, and it will belong to him.", "asv": "And if he that sanctified it will redeem his house, then he shall add the fifth part of the money of thy estimation unto it, and it shall be his.", "ylt": "and if he who is sanctifying doth redeem his house, then he hath added a fifth of the money of thy valuation to it, and it hath become his.", "tyndale": "Yf he that sanctifyed it will redeme his housse let him geue the fyfte parte of the money that it was iudged at thereto and it shalbe his.", "dra": "But if he that vowed, will redeem it, he shall give the fifth part of the estimation over and above: and shall have the house.", "bbe": "And if the owner has a desire to get back his house, let him give a fifth more than your value, and it will be his.", "geneva": "But if he that sanctified it, will redeeme his house, then hee shall giue thereto the fift part of money more then thy estimation, and it shalbe his.", "wycliffe": "sotheli if he that avowide wole ayen-bie it, he schal yyue the fifthe part of the valu aboue, and he schal haue the hows.", "rotherham": "But, if he that halloweth it, would redeem his house, then shall he add the fifth part of the silver of thine estimate thereunto and it shall be his.", "darby": "And if he that halloweth it will redeem his house, he shall add the fifth of the money of thy valuation unto it, and it shall be his.", "twenty": "", "jps": "And if he that sanctified it will redeem his house, then he shall add the fifth part of the money of thy valuation unto it, and it shall be his.", "acv": "And if he who sanctified it will redeem his house, then he shall add the fifth part of the money of thy estimation to it, and it shall be his.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if he that sanctified it will redeem his house, then he shall add the fifth [part] of the money of thy estimation to it, and it shall be his.", "vulgate": "sin autem ille qui voverat voluerit redimere eam dabit quintam partem aestimationis supra et habebit domum;", "brenton": "And if he that has sanctified it should redeem his house, he shall add to it the fifth part of the money of the valuation, and it shall be his."}}, {"v": 16, "ref": "27:16", "o": "וְ/אִ֣ם מִ/שְּׂדֵ֣ה אֲחֻזָּת֗/וֹ יַקְדִּ֥ישׁ אִישׁ֙ לַֽ/יהוָ֔ה וְ/הָיָ֥ה עֶרְכְּ/ךָ֖ לְ/פִ֣י זַרְע֑/וֹ זֶ֚רַע חֹ֣מֶר שְׂעֹרִ֔ים בַּ/חֲמִשִּׁ֖ים שֶׁ֥קֶל כָּֽסֶף", "en": {"kjv": "And if a man shall sanctify unto the Lord some part of a field of his possession, then thy estimation shall be according to the seed thereof: an homer of barley seed shall be valued at fifty shekels of silver.", "web": "“‘If a man dedicates to Yahweh part of the field of his possession, then your valuation shall be according to the seed for it. The sowing of a homer of barley shall be valued at fifty shekels of silver.", "bsb": "If a man consecrates to the LORD a parcel of his land, then your valuation shall be proportional to the seed required for it—fifty shekels of silver for every homer of barley seed.", "asv": "And if a man shall sanctify unto Jehovah part of the field of his possession, then thy estimation shall be according to the sowing thereof: the sowing of a homer of barley shall be valued at fifty shekels of silver.", "ylt": "`And if of the field of his possession a man sanctify to Jehovah, then hath thy valuation been according to its seed; a homer of barley-seed at fifty shekels of silver;", "tyndale": "Yf a man halowe a pece of his enhereted londe vnto the Lorde it shalbe set acordynge to that it beareth. Yf it bere an homer of barlye it shall be set at fyftie sicles of syluer.", "dra": "And if he vow the field of his possession, and consecrate it to the Lord, the price shall be rated according to the measure of the seed. If the ground be sown with thirty bushels of barley, let it be sold for fifty sicles of silver.", "bbe": "And if a man gives to the Lord part of the field which is his property, then let your value be in relation to the seed which is planted in it; a measure of barley grain will be valued at fifty shekels of silver.", "geneva": "If also a man dedicate to the Lord any grounde of his inheritance, then shalt thou esteeme it according to the seede therof: an Homer of barlie seede shalbe at fiftie shekels of siluer.", "wycliffe": "That if he avowith the feeld of his possessioun, and halewith to the Lord, the prijs schal be demed bi the mesure of seed; if the feeld is sowun with thritti buyschels of barli, it schal be seeld for fifti siclys of siluer.", "rotherham": "And if of the field of his possession any man would hallow unto Yahweh, then shall thine estimate be according to the seed thereof,—the seed of a homer of barley, at fifty shekels of silver.", "darby": "And if a man hallow to Jehovah [part] of a field of his possession, thy valuation shall be according to what may be sown in it: the homer of barley seed at fifty shekels of silver.", "twenty": "", "jps": "And if a man shall sanctify unto HaShem part of the field of his possession, then thy valuation shall be according to the sowing thereof; the sowing of a homer of barley shall be valued at fifty shekels of silver.", "acv": "And if a man shall sanctify to Jehovah part of the field of his possession, then thy estimation shall be according to the sowing of it, the sowing of a homer of barley at fifty shekels of silver.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if a man shall sanctify to the LORD [some part] of a field of his possession, then thy estimation shall be according to the seed of it: a homer of barley seed [shall be valued] at fifty shekels of silver.", "vulgate": "quod si agrum possessionis suae voverit et consecraverit Domino iuxta mensuram sementis aestimabitur pretium si triginta modiis hordei seritur terra quinquaginta siclis veniet argenti;", "brenton": "And if a man should hallow to the Lord a part of the field of his possession, then the valuation shall be according to its seed, fifty didrachms of silver for a homer of barley."}}, {"v": 17, "ref": "27:17", "o": "אִם מִ/שְּׁנַ֥ת הַ/יֹּבֵ֖ל יַקְדִּ֣ישׁ שָׂדֵ֑/הוּ כְּ/עֶרְכְּ/ךָ֖ יָקֽוּם", "en": {"kjv": "If he sanctify his field from the year of jubile, according to thy estimation it shall stand.", "web": "If he dedicates his field from the Year of Jubilee, according to your valuation it shall stand.", "bsb": "If he consecrates his field during the Year of Jubilee, the price will stand according to your valuation.", "asv": "If he sanctify his field from the year of jubilee, according to thy estimation it shall stand.", "ylt": "if from the year of the jubilee he sanctify his field, according to thy valuation it standeth;", "tyndale": "yf he halowe his felde inmediatly from the trompet yere it shalbe worth acordynge as it is estemed. But and if he halowe his felde after the tropetyere the preast shall reke the price with him acordynge to the yeres that remayne vnto the tropet yere, ad there after it shalbe lower sett.", "dra": "If he vow his field immediately from the year of jubilee that is beginning: as much as it may be worth, at so much it shall be rated.", "bbe": "If he gives his field from the year of Jubilee, the value will be fixed by your decision.", "geneva": "If he dedicate his field immediatly from the yeere of Iubile, it shall bee worth as thou doest esteeme it.", "wycliffe": "If he auowith the feeld anoon for the yeer of the iubilee bigynnynge, as myche as it may be worth, bi so myche it schal be preisid;", "rotherham": "If, from the year of jubilee, he would hallow his field, according to thine estimate, shall it stand.", "darby": "If he hallow his field from the year of jubilee, according to thy valuation shall it stand;", "twenty": "", "jps": "If he sanctify his field from the year of jubilee, according to thy valuation it shall stand.", "acv": "If he sanctifies his field from the year of jubilee, according to thy estimation it shall stand.", "anderson": "", "haweis": "", "noyes": "", "webster": "If he shall sanctify his field from the year of jubilee, according to thy estimation it shall stand.", "vulgate": "si statim ab anno incipientis iobelei voverit agrum quanto valere potest tanto aestimabitur;", "brenton": "And if he should sanctify his field from the year of release, it shall stand according to his valuation."}}, {"v": 18, "ref": "27:18", "o": "וְ/אִם אַחַ֣ר הַ/יֹּבֵל֮ יַקְדִּ֣ישׁ שָׂדֵ/הוּ֒ וְ/חִשַּׁב ל֨/וֹ הַ/כֹּהֵ֜ן אֶת הַ/כֶּ֗סֶף עַל פִּ֤י הַ/שָּׁנִים֙ הַ/נּ֣וֹתָרֹ֔ת עַ֖ד שְׁנַ֣ת הַ/יֹּבֵ֑ל וְ/נִגְרַ֖ע מֵֽ/עֶרְכֶּֽ/ךָ", "en": {"kjv": "But if he sanctify his field after the jubile, then the priest shall reckon unto him the money according to the years that remain, even unto the year of the jubile, and it shall be abated from thy estimation.", "web": "But if he dedicates his field after the Jubilee, then the priest shall reckon to him the money according to the years that remain to the Year of Jubilee; and an abatement shall be made from your valuation.", "bsb": "But if he consecrates his field after the Jubilee, the priest is to calculate the price in proportion to the years left until the next Year of Jubilee, so that your valuation will be reduced.", "asv": "But if he sanctify his field after the jubilee, then the priest shall reckon unto him the money according to the years that remain unto the year of jubilee; and an abatement shall be made from thy estimation.", "ylt": "and if after the jubilee he sanctify his field, then hath the priest reckoned to him the money according to the years which are left, unto the year of the jubilee, and it hath been abated from thy valuation.", "tyndale": "", "dra": "But if some time after, the priest shall reckon the money according to the number of years that remain until the jubilee, and the price shall be abated.", "bbe": "But if he gives his field after the year of Jubilee, the amount of the money will be worked out by the priest in relation to the number of years till the coming year of Jubilee, and the necessary amount will be taken off your value.", "geneva": "But if hee dedicate his fielde after the Iubile, then the Priest shall recken him the money according to ye yeeres that remaine vnto the yere of Iubile, and it shalbe abated by thy estimation.", "wycliffe": "but if it be after `sum part of tyme, the preest schal rykene the money bi the noumbre of yeeris that ben residue `til to the iubilee, and it schal be withdrawun of the prijs.", "rotherham": "But if after the jubilee he would hallow his field, then shall the priest reckon to him the silver, according to the years that remain, until the year of the jubilee,—and it shall be abated from thine estimate.", "darby": "but if he hallow his field after the jubilee, then the priest shall reckon unto him the money according to the years that remain, until the year of the jubilee; and there shall be a reduction from thy valuation.", "twenty": "", "jps": "But if he sanctify his field after the jubilee, then the priest shall reckon unto him the money according to the years that remain unto the year of jubilee, and an abatement shall be made from thy valuation.", "acv": "But if he sanctifies his field after the jubilee, then the priest shall reckon to him the money according to the years that remain to the year of jubilee, and an abatement shall be made from thy estimation.", "anderson": "", "haweis": "", "noyes": "", "webster": "But if he shall sanctify his field after the jubilee, then the priest shall reckon to him the money according to the years that remain, even to the year of the jubilee, and it shall be abated from thy estimation.", "vulgate": "sin autem post aliquantum temporis supputabit sacerdos pecuniam iuxta annorum qui reliqui sunt numerum usque ad iobeleum et detrahetur ex pretio;", "brenton": "And if he should sanctify his field in the latter time after the release, the priest shall reckon to him the money for the remaining years, until the next year of release, and it shall be deducted as an equivalent from his full valuation."}}, {"v": 19, "ref": "27:19", "o": "וְ/אִם גָּאֹ֤ל יִגְאַל֙ אֶת הַ/שָּׂדֶ֔ה הַ/מַּקְדִּ֖ישׁ אֹת֑/וֹ וְ֠/יָסַף חֲמִשִׁ֧ית כֶּֽסֶף עֶרְכְּ/ךָ֛ עָלָ֖י/ו וְ/קָ֥ם לֽ/וֹ", "en": {"kjv": "And if he that sanctified the field will in any wise redeem it, then he shall add the fifth part of the money of thy estimation unto it, and it shall be assured to him.", "web": "If he who dedicated the field will indeed redeem it, then he shall add the fifth part of the money of your valuation to it, and it shall remain his.", "bsb": "And if the one who consecrated the field decides to redeem it, he must add a fifth to the assessed value, and it shall belong to him.", "asv": "And if he that sanctified the field will indeed redeem it, then he shall add the fifth part of the money of thy estimation unto it, and it shall be assured to him.", "ylt": "`And if he really redeem the field--he who is sanctifying it--then he hath added a fifth of the money of thy valuation to it, and it hath been established to him;", "tyndale": "Yf he that sanctifyed the felde will redeme it agayne let him put the fyfte parte of the pryce that it was set at,", "dra": "And if he that had vowed, will redeem his field, he shall add the fifth part of the money of the estimation, and shall possess it.", "bbe": "And if the man who has given the field has a desire to get it back, let him give a fifth more than the price at which it was valued and it will be his.", "geneva": "And if he that dedicateth it, will redeeme the fielde, then he shall put the fift parte of the price, that thou esteemedst it at, thereunto, and it shall remaine his.", "wycliffe": "That if he that avowide wole ayenbie the feeld, he schal adde the fyuethe part of the money preisid, and he schal welde it;", "rotherham": "But, if he that hath hallowed it should be pleased to redeem, the field, then shall he add the fifth part of the silver of thine estimate thereunto and it shall be assured to him.", "darby": "And if he that hallowed the field will in any wise redeem it, he shall add the fifth of the money of thy valuation unto it, and it shall be assured to him;", "twenty": "", "jps": "And if he that sanctified the field will indeed redeem it, then he shall add the fifth part of the money of thy valuation unto it, and it shall be assured to him.", "acv": "And if he who sanctified the field will indeed redeem it, then he shall add the fifth part of the money of thy estimation to it, and it shall be assured to him.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if he that sanctified the field will in any wise redeem it, then he shall add the fifth [part] of the money of thy estimation to it, and it shall be assured to him.", "vulgate": "quod si voluerit redimere agrum ille qui voverat addet quintam partem aestimatae pecuniae et possidebit eum;", "brenton": "And if he that sanctified the field would redeem it, he shall add to its value the fifth part of the money, and it shall be his."}}, {"v": 20, "ref": "27:20", "o": "וְ/אִם לֹ֤א יִגְאַל֙ אֶת הַ/שָּׂדֶ֔ה וְ/אִם מָכַ֥ר אֶת הַ/שָּׂדֶ֖ה לְ/אִ֣ישׁ אַחֵ֑ר לֹ֥א יִגָּאֵ֖ל עֽוֹד", "en": {"kjv": "And if he will not redeem the field, or if he have sold the field to another man, it shall not be redeemed any more.", "web": "If he will not redeem the field, or if he has sold the field to another man, it shall not be redeemed any more;", "bsb": "If, however, he does not redeem the field, or if he has sold it to another man, it may no longer be redeemed.", "asv": "And if he will not redeem the field, or if he have sold the field to another man, it shall not be redeemed any more:", "ylt": "and if he do not redeem the field, or if he hath sold the field to another man, it is not redeemed any more;", "tyndale": "there vnto and it shalbe his yf he will not it shalbe redemed nomoare.", "dra": "And if he will not redeem it, but it be sold to any other man, he that vowed it, may not redeem it any more.", "bbe": "But if he has no desire to get it back, or if he has given it for a price to another man, it may not be got back again.", "geneva": "And if he will not redeeme the fielde, but the Priest sell the fielde to another man, it shalbe redeemed no more.", "wycliffe": "but if he nyle ayenbie, but it is seeld to ony othir man, he that avowide schal `no more mowe ayenbie it;", "rotherham": "But if he will not redeem the field, but have sold the field to another man, it shall be redeemable no longer;", "darby": "but if he do not redeem the field, or if he sell the field to another man, it cannot be redeemed any more;", "twenty": "", "jps": "And if he will not redeem the field, or if he have sold the field to another man, it shall not be redeemed any more.", "acv": "And if he will not redeem the field, or if he has sold the field to another man, it shall not be redeemed any more,", "anderson": "", "haweis": "", "noyes": "", "webster": "And if he will not redeem the field, or if he shall have sold the field to another man, it shall not be redeemed any more.", "vulgate": "sin autem noluerit redimere sed alteri cuilibet fuerit venundatus ultra eum qui voverat redimere non poterit;", "brenton": "And if he do not redeem the field, but should sell the field to another man, he shall not after redeem it."}}, {"v": 21, "ref": "27:21", "o": "וְ/הָיָ֨ה הַ/שָּׂדֶ֜ה בְּ/צֵאת֣/וֹ בַ/יֹּבֵ֗ל קֹ֛דֶשׁ לַֽ/יהוָ֖ה כִּ/שְׂדֵ֣ה הַ/חֵ֑רֶם לַ/כֹּהֵ֖ן תִּהְיֶ֥ה אֲחֻזָּתֽ/וֹ", "en": {"kjv": "But the field, when it goeth out in the jubile, shall be holy unto the Lord, as a field devoted; the possession thereof shall be the priest’s.", "web": "but the field, when it goes out in the Jubilee, shall be holy to Yahweh, as a devoted field. It shall be owned by the priests.", "bsb": "When the field is released in the Jubilee, it will become holy, like a field devoted to the LORD; it becomes the property of the priests.", "asv": "but the field, when it goeth out in the jubilee, shall be holy unto Jehovah, as a field devoted; the possession thereof shall be the priest’s.", "ylt": "and the field hath been, in its going out in the jubilee, holy to Jehovah as a field which is devoted; to the priest is its possession.", "tyndale": "But when the felde goeth out in the trompet yere it shalbe holy vnto the Lorde: euen as a thinge dedycated, ad it shall be the preastes possession.", "dra": "For when the day of jubilee cometh, it shall be sanctified to the Lord, and as a possession consecrated, pertaineth to the right of the priest.", "bbe": "But the field, when it becomes free at the year of Jubilee, will be holy to the Lord, as a field given under oath: it will be the property of the priest.", "geneva": "But the field shalbe holy to the Lord, whe it goeth out in the Iubile, as a fielde separate from common vses: the possession thereof shall be the Priests.", "wycliffe": "for whanne the dai of iubilee cometh, it schal be halewid to the Lord, and the possessioun halewid perteyneth to the riyt of preestis.", "rotherham": "so shall the field, when it goeth out in the jubilee, be holy unto Yahweh as a devoted, field,—to the priest, shall belong the possession thereof.", "darby": "and the field, when it goeth out in the jubilee, shall be holy to Jehovah, as a field devoted; the possession thereof shall be the priest's.", "twenty": "", "jps": "But the field, when it goeth out in the jubilee, shall be holy unto HaShem, as a field devoted; the possession thereof shall be the priest's.", "acv": "but the field, when it goes out in the jubilee, shall be holy to Jehovah, as a field set apart; the possession of it shall be the priest's.", "anderson": "", "haweis": "", "noyes": "", "webster": "But the field, when it goeth out in the jubilee, shall be holy to the LORD, as a field devoted: the possession of it shall be the priest's.", "vulgate": "quia cum iobelei venerit dies sanctificatus erit Domino et possessio consecrata ad ius pertinet sacerdotum;", "brenton": "But the field shall be holy to the Lord after the release, as separated land; the priest shall have possession of it."}}, {"v": 22, "ref": "27:22", "o": "וְ/אִם֙ אֶת שְׂדֵ֣ה מִקְנָת֔/וֹ אֲשֶׁ֕ר לֹ֖א מִ/שְּׂדֵ֣ה אֲחֻזָּת֑/וֹ יַקְדִּ֖ישׁ לַֽ/יהוָֽה", "en": {"kjv": "And if a man sanctify unto the Lord a field which he hath bought, which is not of the fields of his possession;", "web": "“‘If he dedicates a field to Yahweh which he has bought, which is not of the field of his possession,", "bsb": "Now if a man consecrates to the LORD a field he has purchased, which is not a part of his own property,", "asv": "And if he sanctify unto Jehovah a field which he hath bought, which is not of the field of his possession;", "ylt": "`And if the field of his purchase (which is not of the fields of his possession) one sanctify to Jehovah--", "tyndale": "Yf a man sanctifie vnto the Lorde a felde which he hath boughte and is not of his enheritaunce", "dra": "If a field that was bought, and not of a man's ancestors' possession, be sanctified to the Lord:", "bbe": "And if a man gives to the Lord a field which he has got for money from another, which is not part of his heritage;", "geneva": "If a man also dedicate vnto ye Lord a fielde which he hath bought, which is not of the groud of his inheritance,", "wycliffe": "If the feeld is bouyt, and is not of the possessioun of grettere men,", "rotherham": "If, however, a field that he hath bought, which is not of the fields of his possession, he would hallow unto Yahweh,", "darby": "And if he hallow to Jehovah a field that he hath bought, which is not of the fields of his possession,", "twenty": "", "jps": "And if he sanctify unto HaShem a field which he hath bought, which is not of the field of his possession;", "acv": "And if he sanctifies to Jehovah a field which he has bought, which is not of the field of his possession,", "anderson": "", "haweis": "", "noyes": "", "webster": "And if [a man] shall sanctify to the LORD a field which he hath bought, which [is] not of the fields of his possession;", "vulgate": "si ager emptus et non de possessione maiorum sanctificatus fuerit Domino;", "brenton": "And if he should consecrate to the Lord of a field which he has bought, which is not of the field of his possession,"}}, {"v": 23, "ref": "27:23", "o": "וְ/חִשַּׁב ל֣/וֹ הַ/כֹּהֵ֗ן אֵ֚ת מִכְסַ֣ת הָֽ/עֶרְכְּ/ךָ֔ עַ֖ד שְׁנַ֣ת הַ/יֹּבֵ֑ל וְ/נָתַ֤ן אֶת הָ/עֶרְכְּ/ךָ֙ בַּ/יּ֣וֹם הַ/ה֔וּא קֹ֖דֶשׁ לַ/יהוָֽה", "en": {"kjv": "Then the priest shall reckon unto him the worth of thy estimation, even unto the year of the jubile: and he shall give thine estimation in that day, as a holy thing unto the Lord.", "web": "then the priest shall reckon to him the worth of your valuation up to the Year of Jubilee; and he shall give your valuation on that day, as a holy thing to Yahweh.", "bsb": "then the priest shall calculate for him the value up to the Year of Jubilee, and the man shall pay the assessed value on that day as a sacred offering to the LORD.", "asv": "then the priest shall reckon unto him the worth of thy estimation unto the year of jubilee: and he shall give thine estimation in that day, as a holy thing unto Jehovah.", "ylt": "then hath the priest reckoned to him the amount of thy valuation unto the year of jubilee, and he hath given thy valuation in that day--a holy thing to Jehovah;", "tyndale": "then the preast shall reken with him what it is worth vnto the trompet yere and he shall geue the price that it is set at the same daye, and it shalbe holy vnto the Lorde.", "dra": "The priest shall reckon the price according to the number of years, unto the jubilee. And he that had vowed, shall give that to the Lord.", "bbe": "Then the value fixed by you up to the year of Jubilee will be worked out for him by the priest, and in that day he will give the amount of your value as holy to the Lord.", "geneva": "Then the Priest shall set the price to him, as thou esteemest it, vnto the yeere of Iubile, and he shall giue thy price the same day, as a thing holy vnto the Lord.", "wycliffe": "and is halewid to the Lord, the preest schal determyne the prijs bi the noumbre of yeeris `til to the iubilee, and he that avowide the feeld schal yyue the prijs to the Lord;", "rotherham": "then shall the priest reckon to him the amount of thine estimate until the year of the jubilee,—and he shall give thine estimate, in that day, as holy unto Yahweh.", "darby": "the priest shall reckon unto him the amount of thy valuation, unto the year of the jubilee; and he shall give thy valuation on that day, [as] holy to Jehovah.", "twenty": "", "jps": "then the priest shall reckon unto him the worth of thy valuation unto the year of jubilee; and he shall give thy valuation in that day, as a holy thing unto HaShem.", "acv": "then the priest shall reckon to him the worth of thy estimation to the year of jubilee, and he shall give thine estimation in that day, as a holy thing to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "Then the priest shall reckon to him the worth of thy estimation, [even] to the year of the jubilee, and he shall give thy estimation in that day, [as] a holy thing to the LORD.", "vulgate": "supputabit sacerdos iuxta annorum numerum usque ad iobeleum pretium et dabit ille qui voverat eum Domino;", "brenton": "the priest shall reckon to him the full valuation from the year of release, and he shall pay the valuation in that day as holy to the Lord."}}, {"v": 24, "ref": "27:24", "o": "בִּ/שְׁנַ֤ת הַ/יּוֹבֵל֙ יָשׁ֣וּב הַ/שָּׂדֶ֔ה לַ/אֲשֶׁ֥ר קָנָ֖/הוּ מֵ/אִתּ֑/וֹ לַ/אֲשֶׁר ל֖/וֹ אֲחֻזַּ֥ת הָ/אָֽרֶץ", "en": {"kjv": "In the year of the jubile the field shall return unto him of whom it was bought, even to him to whom the possession of the land did belong.", "web": "In the Year of Jubilee the field shall return to him from whom it was bought, even to him to whom the possession of the land belongs.", "bsb": "In the Year of Jubilee the field shall return to the one from whom it was bought—the original owner of the land.", "asv": "In the year of jubilee the field shall return unto him of whom it was bought, even to him to whom the possession of the land belongeth.", "ylt": "in the year of the jubilee the field returneth to him from whom he bought it, to him whose is the possession of the land.", "tyndale": "But in the trompet yere, the felde shall returne vnto him, of whome he boughte it, whose enheritaunce of londe it was.", "dra": "But in the jubilee, it shall return to the former owner, who had sold it, and had it in the lot of his possession.", "bbe": "In the year of Jubilee the field will go back to him from whom he got it, that is, to him whose heritage it was.", "geneva": "But in the yeere of Iubile, the fielde shall returne vnto him, of whome it was bought: to him, I say, whose inheritance the land was.", "wycliffe": "forsothe in the iubilee it schal turne ayen to the formere lord that seelde it, and `haue he in to the eritage of his possessioun.", "rotherham": "In the year of the jubilee, shall the field return unto him from whom he bought it to him whose it was as a possession in the land.", "darby": "In the year of the jubilee the field shall return unto him of whom it was bought — to him to whom the land belonged.", "twenty": "", "jps": "In the year of jubilee the field shall return unto him of whom it was bought, even to him to whom the possession of the land belongeth.", "acv": "In the year of jubilee the field shall return to him of whom it was bought, even to him to whom the possession of the land belongs.", "anderson": "", "haweis": "", "noyes": "", "webster": "In the year of the jubilee, the field shall return to him of whom it was bought, [even] to him to whom the possession of the land [belonged].", "vulgate": "in iobeleo autem revertetur ad priorem dominum qui vendiderat eum et habuerat in sortem possessionis suae;", "brenton": "And in the year of release the land shall be restored to the man of whom the other bought it, whose the possession of the land was."}}, {"v": 25, "ref": "27:25", "o": "וְ/כָל עֶרְכְּ/ךָ֔ יִהְיֶ֖ה בְּ/שֶׁ֣קֶל הַ/קֹּ֑דֶשׁ עֶשְׂרִ֥ים גֵּרָ֖ה יִהְיֶ֥ה הַ/שָּֽׁקֶל", "en": {"kjv": "And all thy estimations shall be according to the shekel of the sanctuary: twenty gerahs shall be the shekel.", "web": "All your valuations shall be according to the shekel of the sanctuary: twenty gerahs to the shekel.", "bsb": "Every valuation will be according to the sanctuary shekel, twenty gerahs to the shekel.", "asv": "And all thy estimations shall be according to the shekel of the sanctuary: twenty gerahs shall be the shekel.", "ylt": "And all thy valuation is by the shekel of the sanctuary: twenty gerahs is the shekel.", "tyndale": "And all settinge shalbe acordinge to the holy sycle. One sycle maketh .xx. Geras.", "dra": "All estimation shall be made according to the sicle of the sanctuary. A sicle hath twenty obols.", "bbe": "And let all your values be based on the shekel of the holy place, that is, twenty gerahs to the shekel.", "geneva": "And all thy valuation shall bee according to the shekel of the Sanctuarie: a shekel conteyneth twenty gerahs.", "wycliffe": "`Ech preisyng schal be peisid bi the sicle of seyntuarie; a sicle hath twenti halpens.", "rotherham": "And, every estimate of thine, shall be by the holy shekel,—twenty gerahs, make the shekel.", "darby": "And all thy valuation shall be according to the shekel of the sanctuary: twenty gerahs shall be the shekel.", "twenty": "", "jps": "And all thy valuations shall be according to the shekel of the sanctuary; twenty gerahs shall be the shekel.", "acv": "And all thy estimations shall be according to the shekel of the sanctuary; twenty gerahs shall be the shekel.", "anderson": "", "haweis": "", "noyes": "", "webster": "And all thy estimations shall be according to the shekel of the sanctuary: twenty gerahs shall be the shekel.", "vulgate": "omnis aestimatio siclo sanctuarii ponderabitur siclus viginti obolos habet;", "brenton": "And every valuation shall be by holy weights: the didrachm shall be twenty oboli."}}, {"v": 26, "ref": "27:26", "o": "אַךְ בְּכ֞וֹר אֲשֶׁר יְבֻכַּ֤ר לַֽ/יהוָה֙ בִּ/בְהֵמָ֔ה לֹֽא יַקְדִּ֥ישׁ אִ֖ישׁ אֹת֑/וֹ אִם שׁ֣וֹר אִם שֶׂ֔ה לַֽ/יהוָ֖ה הֽוּא", "en": {"kjv": "Only the firstling of the beasts, which should be the Lord’s firstling, no man shall sanctify it; whether it be ox, or sheep: it is the Lord’s.", "web": "“‘Only the firstborn among animals, which is made a firstborn to Yahweh, no man may dedicate it; whether an ox or sheep. It is Yahweh’s.", "bsb": "But no one may consecrate a firstborn of the livestock, because a firstborn belongs to the LORD. Whether it is an ox or a sheep, it is the LORD’s.", "asv": "Only the firstling among beasts, which is made a firstling to Jehovah, no man shall sanctify it; whether it be ox or sheep, it is Jehovah’s.", "ylt": "`Only, a firstling which is Jehovah's firstling among beasts--no man doth sanctify it, whether ox or sheep; it is Jehovah's.", "tyndale": "But the firstborne of the beestes that pertayne vnto the Lorde, maye no ma sanctifie: whether it be oxe or shepe, for they are the Lordes allredy.", "dra": "The firstborn, which belong to the Lord, no man may sanctify and vow: whether it be bullock, or sheep, they are the Lord's.", "bbe": "But a man may not give by oath to the Lord the first-fruits of cattle which are offered to the Lord: if it is an ox or a sheep it is the Lord's.", "geneva": "Notwithstanding the first borne of the beastes, because it is the Lordes first borne, none shall dedicate such, be it bullocke, or sheepe; for it is the Lords.", "wycliffe": "No man may halewe and avowe the firste gendrid thingis that perteynen to the Lord, whether it is oxe, whether scheep, tho ben the Lordis part.", "rotherham": "Only the firstling which is born a firstling to Yahweh, among beasts, no man shall hallow it,—whether ox or sheep, unto Yahweh, it belongeth.", "darby": "Only the firstling which is offered as firstling to Jehovah among the cattle, that shall no man hallow, whether it be ox or sheep; it is Jehovah's.", "twenty": "", "jps": "Howbeit the firstling among beasts, which is born as a firstling to HaShem, no man shall sanctify it; whether it be ox or sheep, it is HaShem'S.", "acv": "Only the firstling among beasts, which is made a firstling to Jehovah, no man shall sanctify it, whether it be ox or sheep, it is Jehovah's.", "anderson": "", "haweis": "", "noyes": "", "webster": "Only the firstling of the beasts, which should be the LORD'S firstling, no man shall sanctify it; whether ox, or sheep: it [is] the LORD'S.", "vulgate": "primogenita quae ad Dominum pertinent nemo sanctificare poterit et vovere sive bos sive ovis fuerit Domini sunt;", "brenton": "And every first-born which shall be produced among thy cattle shall be the Lord's, and no man shall sanctify it: whether calf or sheep, it is the Lord's."}}, {"v": 27, "ref": "27:27", "o": "וְ/אִ֨ם בַּ/בְּהֵמָ֤ה הַ/טְּמֵאָה֙ וּ/פָדָ֣ה בְ/עֶרְכֶּ֔/ךָ וְ/יָסַ֥ף חֲמִשִׁת֖/וֹ עָלָ֑י/ו וְ/אִם לֹ֥א יִגָּאֵ֖ל וְ/נִמְכַּ֥ר בְּ/עֶרְכֶּֽ/ךָ", "en": {"kjv": "And if it be of an unclean beast, then he shall redeem it according to thine estimation, and shall add a fifth part of it thereto: or if it be not redeemed, then it shall be sold according to thy estimation.", "web": "If it is an unclean animal, then he shall buy it back according to your valuation, and shall add to it the fifth part of it; or if it isn’t redeemed, then it shall be sold according to your valuation.", "bsb": "But if it is among the unclean animals, then he may redeem it according to your valuation and add a fifth of its value. If it is not redeemed, then it shall be sold according to your valuation.", "asv": "And if it be of an unclean beast, then he shall ransom it according to thine estimation, and shall add unto it the fifth part thereof: or if it be not redeemed, then it shall be sold according to thy estimation.", "ylt": "And if among the unclean beasts, then he hath ransomed it at thy valuation, and he hath added its fifth to it; and if it is not redeemed, then it hath been sold at thy valuation.", "tyndale": "Yf it be an vncleane beest, then let him redeme it as it is sett at, and geue the fifte parte moare thereto. Yf it be not redemed, the let it be solde as it is rated.", "dra": "And if it be an unclean beast, he that offereth it shall redeem it, according to thy estimation, and shall add the fifth part of the price. If he will not redeem it, it shall be sold to another for how much soever it was estimated by thee.", "bbe": "And if it is an unclean beast, then the owner of it may give money to get it back, in agreement with the value fixed by you, by giving a fifth more; or if it is not taken back, let it be given for money in agreement with your valuing.", "geneva": "But if it be an vncleane beast, then he shall redeeme it by thy valuation, and giue the fift part more thereto: and if it be not redeemed, then it shalbe solde, according to thy estimation.", "wycliffe": "That if the beeste is vncleene, he that offride schal ayenbie by his valu, and he schal adde the fyuethe part of prijs; if he nyle ayenbie, it schal be seeld to another man, as myche euer as it is `set at valu.", "rotherham": "But, if it be among the beasts that are unclean, then shall he ransom it by thine estimate, and add the fifth part of it thereunto,—but, if it is not redeemed, then shall it be sold by thine estimate.", "darby": "But if it be of an unclean beast, then he shall ransom it according to thy valuation, and shall add a fifth of it thereto; and if it be not redeemed, it shall be sold according to thy valuation.", "twenty": "", "jps": "And if it be of an unclean beast, then he shall ransom it according to thy valuation, and shall add unto it the fifth part thereof; or if it be not redeemed, then it shall be sold according to thy valuation.", "acv": "And if it be of an unclean beast, then he shall ransom it according to thine estimation, and shall add to it the fifth part of it, or if it be not redeemed, then it shall be sold according to thy estimation.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if [it shall be] of an unclean beast, then he shall redeem [it], according to thy estimation, and shall add to it a fifth [part] of it: or if it shall be not redeemed, then it shall be sold according to thy estimation.", "vulgate": "quod si inmundum est animal redimet qui obtulit iuxta aestimationem tuam et addet quintam partem pretii si redimere noluerit vendetur alteri quantocumque a te fuerit aestimatum;", "brenton": "But if he should redeem an unclean beast, according to its valuation, then he shall add the fifth part to it, and it shall be his; and if he redeem it not, it shall be sold according to its valuation."}}, {"v": 28, "ref": "27:28", "o": "אַךְ כָּל חֵ֡רֶם אֲשֶׁ֣ר יַחֲרִם֩ אִ֨ישׁ לַֽ/יהוָ֜ה מִ/כָּל אֲשֶׁר ל֗/וֹ מֵ/אָדָ֤ם וּ/בְהֵמָה֙ וּ/מִ/שְּׂדֵ֣ה אֲחֻזָּת֔/וֹ לֹ֥א יִמָּכֵ֖ר וְ/לֹ֣א יִגָּאֵ֑ל כָּל חֵ֕רֶם קֹֽדֶשׁ קָֽדָשִׁ֥ים ה֖וּא לַ/יהוָֽה", "en": {"kjv": "Notwithstanding no devoted thing, that a man shall devote unto the Lord of all that he hath, both of man and beast, and of the field of his possession, shall be sold or redeemed: every devoted thing is most holy unto the Lord.", "web": "“‘Notwithstanding, no devoted thing, that a man shall devote to Yahweh of all that he has, whether of man or animal, or of the field of his possession, shall be sold or redeemed: every devoted thing is most holy to Yahweh.", "bsb": "Nothing that a man sets apart to the LORD from all he owns—whether a man, an animal, or his inherited land—can be sold or redeemed; everything so devoted is most holy to the LORD.", "asv": "Notwithstanding, no devoted thing, that a man shall devote unto Jehovah of all that he hath, whether of man or beast, or of the field of his possession, shall be sold or redeemed: every devoted thing is most holy unto Jehovah.", "ylt": "`Only, no devoted thing which a man devoteth to Jehovah, of all that he hath, of man, and beast, and of the field of his possession, is sold or redeemed; every devoted thing is most holy to Jehovah.", "tyndale": "Notwithstondinge no dedicated thinge that a man dedicateth vnto the Lorde, of all his goode, whether it be man or beest or lande off his enheritaunce, shalbe solde or redemed: for all dedicate thiges are most holy vnto the Lorde.", "dra": "Any thing that is devoted to the Lord, whether it be man, or beast, or field, shall not be sold: neither may it be redeemed. Whatsoever is once consecrated shall be holy of holies to the Lord.", "bbe": "But nothing which a man has given completely to the Lord, out of all his property, of man or beast, or of the land which is his heritage, may be given away or got back in exchange for money; anything completely given is most holy to the Lord.", "geneva": "Notwithstanding, nothing separate from the common vse that a man doeth separate vnto the Lord of all that he hath (whether it bee man or beast, or lande of his inheritance) may be solde nor redeemed: for euery thing separate from the common vse is most holy vnto the Lord.", "wycliffe": "Al thing which is halewid to the Lord, whether it is man, whether beeste, whether feeld , it schal not be seeld, nether it schal mow be ayenbouyt; whateuer thing is halewid onys, it schal be hooli of the noumbre of hooli thingis to the Lord,", "rotherham": "Only no devoted thing which any man shall devote unto Yahweh, of all that belongeth to him,—of man or beast, or of the field of his possession, shall be either sold or redeemed,—as to every devoted thing, most holy, it is unto Yahweh.", "darby": "Notwithstanding, no devoted thing that a man hath devoted to Jehovah of all that he hath, of man or beast, or of the field of his possession, shall be sold or redeemed: every devoted thing is most holy to Jehovah.", "twenty": "", "jps": "Notwithstanding, no devoted thing, that a man may devote unto HaShem of all that he hath, whether of man or beast, or of the field of his possession, shall be sold or redeemed; every devoted thing is most holy unto HaShem.", "acv": "Notwithstanding, nothing set apart, that a man shall set apart to Jehovah of all that he has, whether of man or beast, or of the field of his possession, shall be sold or redeemed; everything set apart is most holy to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "Notwithstanding, no devoted thing that a man shall devote to the LORD of all that he hath, [both] of man and beast, and of the field of his possession, shall be sold or redeemed: every devoted thing is most holy to the LORD.", "vulgate": "omne quod Domino consecratur sive homo fuerit sive animal sive ager non veniet nec redimi poterit quicquid semel fuerit consecratum sanctum sanctorum erit Domino;", "brenton": "And every dedicated thing which a man shall dedicate to the Lord of all that he has, whether man or beast, or of the field of his possession, he shall not sell it, nor redeem it: every devoted thing shall be most holy to the Lord."}}, {"v": 29, "ref": "27:29", "o": "כָּל חֵ֗רֶם אֲשֶׁ֧ר יָחֳרַ֛ם מִן הָ/אָדָ֖ם לֹ֣א יִפָּדֶ֑ה מ֖וֹת יוּמָֽת", "en": {"kjv": "None devoted, which shall be devoted of men, shall be redeemed; but shall surely be put to death.", "web": "“‘No one devoted, who shall be devoted from among men, shall be ransomed; he shall surely be put to death.", "bsb": "No person set apart for destruction may be ransomed; he must surely be put to death.", "asv": "No one devoted, that shall be devoted from among men, shall be ransomed; he shall surely be put to death.", "ylt": "`No devoted thing, which is devoted of man, is ransomed, it is surely put to death.", "tyndale": "No dedicate thinge therfore that is dedicate of ma, may be redemed, but must nedes dye", "dra": "And any consecration that is offered by man, shall not be redeemed, but dying shall die.", "bbe": "Any man given completely to the Lord may not be got back: he is certainly to be put to death.", "geneva": "Nothing separate from the common vse, which shall be separate from man, shalbe redeemed, but dye the death.", "wycliffe": "and ech halewyng which is offrid of man, schal not be ayenbouyt, but it schal die bi deeth.", "rotherham": "As touching any one devoted, who may be devoted from among men he shall not be ransomed,—he must be, surely put to death.", "darby": "Nothing devoted, which shall be devoted from among men, shall be ransomed: it shall certainly be put to death.", "twenty": "", "jps": "None devoted, that may be devoted of men, shall be ransomed; he shall surely be put to death.", "acv": "No one set apart, who shall be set apart from among men, shall be ransomed; he shall surely be put to death.", "anderson": "", "haweis": "", "noyes": "", "webster": "None devoted, which shall be devoted by men, shall be redeemed: [but] shall surely be put to death.", "vulgate": "et omnis consecratio quae offertur ab homine non redimetur sed morte morietur;", "brenton": "And whatever shall be dedicated of men, shall not be ransomed, but shall be surely put to death."}}, {"v": 30, "ref": "27:30", "o": "וְ/כָל מַעְשַׂ֨ר הָ/אָ֜רֶץ מִ/זֶּ֤רַע הָ/אָ֨רֶץ֙ מִ/פְּרִ֣י הָ/עֵ֔ץ לַ/יהוָ֖ה ה֑וּא קֹ֖דֶשׁ לַֽ/יהוָֽה", "en": {"kjv": "And all the tithe of the land, whether of the seed of the land, or of the fruit of the tree, is the Lord’s: it is holy unto the Lord.", "web": "“‘All the tithe of the land, whether of the seed of the land or of the fruit of the trees, is Yahweh’s. It is holy to Yahweh.", "bsb": "Thus any tithe from the land, whether from the seed of the land or the fruit of the trees, belongs to the LORD; it is holy to the LORD.", "asv": "And all the tithe of the land, whether of the seed of the land, or of the fruit of the tree, is Jehovah’s: it is holy unto Jehovah.", "ylt": "And all tithe of the land, of the seed of the land, of the fruit of the tree, is Jehovah's--holy to Jehovah.", "tyndale": "All these tithes of the londe, whether it be of the corne of the felde or frute of the trees, shalbe holy vnto the Lorde.", "dra": "All tithes of the land, whether of corn, or of the fruits of trees, are the Lord's, and are sanctified to him.", "bbe": "And every tenth part of the land, of the seed planted, or of the fruit of trees, is holy to the Lord.", "geneva": "Also all the tithe of the lande both of the seede of the ground, and of the fruite of the trees is the Lords: it is holy to the Lord.", "wycliffe": "Alle the tithis of erthe, whether of fruytis, whether of applis of trees, ben the Lordis part, and ben halewid to hym;", "rotherham": "And, as for all the tithe of the land whether of the seed of the land, [or] of the fruit of the trees, unto Yahweh, it belongeth,—as something holy unto Yahweh.", "darby": "And as to every tithe of the land, of the seed of the land, and of the fruit of the tree, it is Jehovah's: it is holy to Jehovah.", "twenty": "", "jps": "And all the tithe of the land, whether of the seed of the land, or of the fruit of the tree, is HaShem'S; it is holy unto HaShem.", "acv": "And all the tithe of the land, whether of the seed of the land, or of the fruit of the tree, is Jehovah's; it is holy to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And all the tithe of the land, [whether] of the seed of the land, [or] of the fruit of the tree, [is] the LORD'S: [it is] holy to the LORD.", "vulgate": "omnes decimae terrae sive de frugibus sive de pomis arborum Domini sunt et illi sanctificantur;", "brenton": "Every tithe of the land, both of the seed of the land, and of the fruit of trees, is the Lord's, holy to the Lord."}}, {"v": 31, "ref": "27:31", "o": "וְ/אִם גָּאֹ֥ל יִגְאַ֛ל אִ֖ישׁ מִ/מַּֽעַשְׂר֑/וֹ חֲמִשִׁית֖/וֹ יֹסֵ֥ף עָלָֽי/ו", "en": {"kjv": "And if a man will at all redeem ought of his tithes, he shall add thereto the fifth part thereof.", "web": "If a man redeems anything of his tithe, he shall add a fifth part to it.", "bsb": "If a man wishes to redeem part of his tithe, he must add a fifth to its value.", "asv": "And if a man will redeem aught of his tithe, he shall add unto it the fifth part thereof.", "ylt": "`And if a man really redeem any of his tithe, its fifth he addeth to it.", "tyndale": "Yf any man will redeme oughte of his tithes, let him adde the fifte parte moare thereto.", "dra": "And if any man will redeem his tithes, he shall add the fifth part of them.", "bbe": "And if a man has a desire to get back any of the tenth part which he has given, let him give a fifth more.", "geneva": "But if a man will redeeme any of his tithe, he shall adde the fift part thereto.", "wycliffe": "sotheli if ony man wole ayenbie hise tithis, he schal adde the fyuethe part of tho; of alle tithis,", "rotherham": "But, if any man should be pleased, to redeem, aught of his tithes, the fifth part thereof, shall he add thereunto.", "darby": "And if any one will at all redeem of his tithes, he shall add thereto the fifth thereof.", "twenty": "", "jps": "And if a man will redeem aught of his tithe, he shall add unto it the fifth part thereof.", "acv": "And if a man will redeem any of his tithe, he shall add to it the fifth part of it.", "anderson": "", "haweis": "", "noyes": "", "webster": "And if a man will at all redeem [aught] of his tithes, he shall add to it the fifth [part] of it.", "vulgate": "si quis autem voluerit redimere decimas suas addet quintam partem earum;", "brenton": "And if a man should at all redeem his tithe, he shall add the fifth part to it, and it shall be his."}}, {"v": 32, "ref": "27:32", "o": "וְ/כָל מַעְשַׂ֤ר בָּקָר֙ וָ/צֹ֔אן כֹּ֥ל אֲשֶׁר יַעֲבֹ֖ר תַּ֣חַת הַ/שָּׁ֑בֶט הָֽ/עֲשִׂירִ֕י יִֽהְיֶה קֹּ֖דֶשׁ לַֽ/יהוָֽה", "en": {"kjv": "And concerning the tithe of the herd, or of the flock, even of whatsoever passeth under the rod, the tenth shall be holy unto the Lord.", "web": "All the tithe of the herds or the flocks, whatever passes under the rod, the tenth shall be holy to Yahweh.", "bsb": "Every tenth animal from the herd or flock that passes under the shepherd’s rod will be holy to the LORD.", "asv": "And all the tithe of the herd or the flock, whatsoever passeth under the rod, the tenth shall be holy unto Jehovah.", "ylt": "`And all the tithe of the herd and of the flock--all that passeth by under the rod--the tenth is holy to Jehovah;", "tyndale": "And the tithes of oxen and shepe and of all that goeth vnder the herdemans kepinge, shalbe holye tithes vnto the Lorde.", "dra": "Of all the tithes of oxen, and sheep, and goats, that pass under the shepherd's rod, every tenth that cometh shall be sanctified to the Lord.", "bbe": "And a tenth part of the herd and of the flock, whatever goes under the rod of the valuer, will be holy to the Lord.", "geneva": "And euery tithe of bullock, and of sheepe, and of all that goeth vnder the rod, the tenth shalbe holy vnto the Lord.", "wycliffe": "of scheep, and of oxen, and of geet, that passen vndur the `yerde of scheepherde, whateuer thing cometh to the tenthe part, it schal be halewid to the Lord;", "rotherham": "And, as for all the tithe of herd and flock, all that passeth under the rod, the tenth, shall be holy unto Yahweh.", "darby": "And as to every tithe of the herd, or of the flock, of whatever passeth under the rod, the tenth shall be holy to Jehovah.", "twenty": "", "jps": "And all the tithe of the herd or the flock, whatsoever passeth under the rod, the tenth shall be holy unto HaShem.", "acv": "And all the tithe of the herd or the flock, whatever passes under the rod, the tenth shall be holy to Jehovah.", "anderson": "", "haweis": "", "noyes": "", "webster": "And concerning the tithe of the herd, or of the flock, [even] of whatever passeth under the rod, the tenth shall be holy to the LORD.", "vulgate": "omnium decimarum boves et oves et caprae quae sub pastoris virga transeunt quicquid decimum venerit sanctificabitur Domino;", "brenton": "And every tithe of oxen, and of sheep, and whatsoever may come in numbering under the rod, the tenth shall be holy to the Lord."}}, {"v": 33, "ref": "27:33", "o": "לֹ֧א יְבַקֵּ֛ר בֵּֽין ט֥וֹב לָ/רַ֖ע וְ/לֹ֣א יְמִירֶ֑/נּוּ וְ/אִם הָמֵ֣ר יְמִירֶ֔/נּוּ וְ/הָֽיָה ה֧וּא וּ/תְמוּרָת֛/וֹ יִֽהְיֶה קֹ֖דֶשׁ לֹ֥א יִגָּאֵֽל", "en": {"kjv": "He shall not search whether it be good or bad, neither shall he change it: and if he change it at all, then both it and the change thereof shall be holy; it shall not be redeemed.", "web": "He shall not search whether it is good or bad, neither shall he change it. If he changes it at all, then both it and that for which it is changed shall be holy. It shall not be redeemed.’”", "bsb": "He must not inspect whether it is good or bad, and he shall not make any substitution. But if he does make a substitution, both the animal and its substitute shall become holy; they cannot be redeemed.’”", "asv": "He shall not search whether it be good or bad, neither shall he change it: and if he change it at all, then both it and that for which it is changed shall be holy; it shall not be redeemed.", "ylt": "he enquireth not between good and bad, nor doth he change it; and if he really change it--then it hath been--it and its exchange is holy; it is not redeemed.'", "tyndale": "Men shal not loke yf it be good or bad nor shall chaunge it. Yf any man chaunge it then both it and that it was chaunged with all, shalbe holy and maye not be redemed.", "dra": "It shall not be chosen neither good nor bad, neither shall it be changed for another. If any man change it: both that which was changed, and that for which it was changed, shall be sanctified to the Lord, and shall not be redeemed.", "bbe": "He may not make search to see if it is good or bad, or make any changes in it; and if he makes exchange of it for another, the two will be holy; he will not get them back again.", "geneva": "He shall not looke if it be good or bad, neither shall he change it: els if he change it, both it, and that it was changed withall, shalbe holy, and it shall not be redeemed.", "wycliffe": "it schal not be chosun, nether good, nether yuel; nethir it schal be chaungid for another; if ony man chaungith, bothe that, that is chaungid, and that, for which it is chaungid, schal be halewid to the Lord, and it schal not be ayenbouyt.", "rotherham": "He shall not examine whether it be good or bad neither shall he change it,—or, if he do in anywise change, it, then shall both, it and what is given in exchange for it, be holy, it shall not be redeemed.", "darby": "He shall not search whether it be good or bad, neither shall he change it; and if he change it at all, then both it and the exchange thereof shall be holy; it shall not be redeemed.", "twenty": "", "jps": "He shall not inquire whether it be good or bad, neither shall he change it; and if he change it at all, then both it and that for which it is changed shall be holy; it shall not be redeemed.", "acv": "He shall not search whether it be good or bad, neither shall he change it. And if he changes it at all, then both it and that for which it is changed shall be holy; it shall not be redeemed.", "anderson": "", "haweis": "", "noyes": "", "webster": "He shall not search whether it is good or bad, neither shall he change it: and if he shall change it at all, then both it and the change of it shall be holy; it shall not be redeemed.", "vulgate": "non eligetur nec bonum nec malum nec altero commutabitur si quis mutaverit et quod mutatum est et pro quo mutatum est sanctificabitur Domino et non redimetur;", "brenton": "Thou shalt not change a good for a bad, or a bad for a good; and if thou shouldest at all change it, its equivalent also shall be holy, it shall not be redeemed."}}, {"v": 34, "ref": "27:34", "o": "אֵ֣לֶּה הַ/מִּצְוֺ֗ת אֲשֶׁ֨ר צִוָּ֧ה יְהוָ֛ה אֶת מֹשֶׁ֖ה אֶל בְּנֵ֣י יִשְׂרָאֵ֑ל בְּ/הַ֖ר סִינָֽי", "en": {"kjv": "These are the commandments, which the Lord commanded Moses for the children of Israel in mount Sinai.", "web": "These are the commandments which Yahweh commanded Moses for the children of Israel on Mount Sinai.", "bsb": "These are the commandments that the LORD gave to Moses for the Israelites on Mount Sinai.", "asv": "These are the commandments, which Jehovah commanded Moses for the children of Israel in mount Sinai.", "ylt": "These are the commands which Jehovah hath commanded Moses for the sons of Israel, in mount Sinai.", "tyndale": "These are the commaundmentes whiche the Lorde gaue Moses in charge to geue vnto the childern of Israel in mount Sinai.", "dra": "These are the precepts which the Lord commanded Moses for the children of Israel in mount Sinai.", "bbe": "These are the orders which the Lord gave to Moses for the children of Israel in Mount Sinai.", "geneva": "These are the commandements which the Lord commanded by Moses vnto the children of Israel in mount Sinai.", "wycliffe": "These ben the comaundementis whiche the Lord comaundide to Moises, and to the sones of Israel, in the hil of Synay.", "rotherham": "These are the commandments which Yahweh commanded Moses for the sons of Israel,—in Mount Sinai.", "darby": "These are the commandments which Jehovah commanded Moses for the children of Israel upon mount Sinai.", "twenty": "", "jps": "These are the commandments, which HaShem commanded Moses for the children of Israel in mount Sinai.", "acv": "These are the commandments, which Jehovah commanded Moses for the sons of Israel at mount Sinai.", "anderson": "", "haweis": "", "noyes": "", "webster": "These [are] the commandments which the LORD commanded Moses for the children of Israel in mount Sinai.", "vulgate": "haec sunt praecepta quae mandavit Dominus Mosi ad filios Israhel in monte Sinai;", "brenton": "These are the commandments which the Lord commanded Moses for the sons of Israel in mount Sina."}}]}]};
window.BOOKS=[{"slug": "mark", "name": "Mark", "file": "Mark.html", "testament": "NT"}, {"slug": "matthew", "name": "Matthew", "file": "Matthew.html", "testament": "NT"}, {"slug": "luke", "name": "Luke", "file": "Luke.html", "testament": "NT"}, {"slug": "john", "name": "John", "file": "John.html", "testament": "NT"}, {"slug": "acts", "name": "Acts", "file": "Acts.html", "testament": "NT"}, {"slug": "romans", "name": "Romans", "file": "Romans.html", "testament": "NT"}, {"slug": "1corinthians", "name": "1 Corinthians", "file": "1Corinthians.html", "testament": "NT"}, {"slug": "philippians", "name": "Philippians", "file": "Philippians.html", "testament": "NT"}, {"slug": "colossians", "name": "Colossians", "file": "Colossians.html", "testament": "NT"}, {"slug": "philemon", "name": "Philemon", "file": "Philemon.html", "testament": "NT"}, {"slug": "hebrews", "name": "Hebrews", "file": "Hebrews.html", "testament": "NT"}, {"slug": "genesis", "name": "Genesis", "file": "Genesis.html", "testament": "OT"}, {"slug": "exodus", "name": "Exodus", "file": "Exodus.html", "testament": "OT"}, {"slug": "leviticus", "name": "Leviticus", "file": "Leviticus.html", "testament": "OT"}, {"slug": "numbers", "name": "Numbers", "file": "Numbers.html", "testament": "OT"}, {"slug": "deuteronomy", "name": "Deuteronomy", "file": "Deuteronomy.html", "testament": "OT"}, {"slug": "ruth", "name": "Ruth", "file": "Ruth.html", "testament": "OT"}, {"slug": "job", "name": "Job", "file": "Job.html", "testament": "OT"}, {"slug": "psalms", "name": "Psalms", "file": "Psalms.html", "testament": "OT"}, {"slug": "isaiah", "name": "Isaiah", "file": "Isaiah.html", "testament": "OT"}, {"slug": "ezekiel", "name": "Ezekiel", "file": "Ezekiel.html", "testament": "OT"}, {"slug": "daniel", "name": "Daniel", "file": "Daniel.html", "testament": "OT"}];
window.ANNOT={"16:8": [{"ref": "16:8", "title": "Azazel — a desert power, not \"escape\"", "finding": "Aaron casts lots: גּוֹרָל אֶחָד לַיהוָה וְגוֹרָל אֶחָד לַעֲזָאזֵל (\"one lot for YHWH, one lot for Azazel\"). The strict grammatical parallel — a lot \"for YHWH\" paired with a lot \"for Azazel\" — treats עֲזָאזֵל as a comparable named recipient, not an abstract process, undercutting the traditional \"scapegoat\" (e-scape-goat) gloss built on a folk reading of the name. Second Temple tradition (1 Enoch 8:1, 10:4-8) makes this explicit, naming Azazel a desert demon bound in the wilderness — the same wilderness (הַמִּדְבָּרָה) to which the loaded goat is driven in this chapter.", "category": "pagan", "citation": "1 Enoch 8:1, 10:4-8", "tier": "STRONG-INFERENCE"}], "17:11": [{"ref": "17:11", "title": "The life is in the blood", "finding": "כִּי נֶפֶשׁ הַבָּשָׂר בַּדָּם הִוא (\"for the life/soul of the flesh is in the blood\") grounds Israel's entire sacrificial logic: blood atones because it carries נֶפֶשׁ (nefesh, life). Hebrews 9:22 directly paraphrases this premise — χωρὶς αἱματεκχυσίας οὐ γίνεται ἄφεσις (\"without the pouring out of blood there is no forgiveness\") — building the letter's whole cultic argument on this one Levitical principle.", "category": "typology", "citation": "Hebrews 9:22", "tier": "DEMONSTRABLE"}], "19:18": [{"ref": "19:18", "title": "Love your neighbor, word for word", "finding": "וְאָהַבְתָּ לְרֵעֲךָ כָּמוֹךָ (\"and you shall love your neighbor as yourself\") is quoted verbatim from the LXX (ἀγαπήσεις τὸν πλησίον σου ὡς σεαυτόν) by Mark 12:31, Matthew 22:39, Paul (Rom 13:9, Gal 5:14), and James 2:8 — an unusually wide multiple-attestation of one Levitical clause functioning as a summary of Torah ethics. The verbatim, cross-author reuse makes this one of the most secure Torah-to-NT quotations in the corpus.", "category": "typology", "citation": "Mark 12:31; Matthew 22:39; Romans 13:9; Galatians 5:14; James 2:8", "tier": "DEMONSTRABLE"}], "19:2": [{"ref": "19:2", "title": "Holiness Code — a stratum after P", "finding": "קְדֹשִׁים תִּהְיוּ כִּי קָדוֹשׁ אֲנִי יְהוָה אֱלֹהֵיכֶם (\"you shall be holy, for I, YHWH your God, am holy\") is the programmatic refrain of Leviticus 17-26, the block scholars (Knohl, Milgrom) isolate as H, the Holiness source, distinct from the surrounding priestly rulebook (P). Our own documentary-clock probe found H's marker profile trending later than core P by +0.38 (CI 0.17-0.66) once the confounding אנכי/אני pronoun is excluded, though the genre-matched law-vs-law comparison narrows to +0.15-0.18 with a confidence interval touching zero — a suggestive, not certain, confirmation of Knohl's directional claim that H postdates P.", "category": "source-critical", "citation": "study-documentary-clock.md (Probe HEB4, H vs P); Knohl, The Sanctuary of Silence", "tier": "STRONG-INFERENCE"}], "11:44": [{"ref": "11:44", "title": "\"Be holy, for I am holy\" — quoted by name", "finding": "כִּי אֲנִי יְהוָה אֱלֹהֵיכֶם וְהִתְקַדִּשְׁתֶּם וִהְיִיתֶם קְדֹשִׁים כִּי קָדוֹשׁ אָנִי (\"for I am YHWH your God; sanctify yourselves and be holy, for I am holy\") is quoted almost verbatim in 1 Peter 1:16 — γέγραπται ὅτι ἅγιοι ἔσεσθε, ὅτι ἐγὼ ἅγιος (\"it is written, you shall be holy, for I am holy\") — with Peter's own citation formula pointing straight back to this clause (echoed again at 11:45, 19:2, 20:26). A clean, formula-marked LXX quotation.", "category": "typology", "citation": "1 Peter 1:16", "tier": "DEMONSTRABLE"}], "25:10": [{"ref": "25:10", "title": "Jubilee's דְּרוֹר becomes Jesus's manifesto", "finding": "The Jubilee law proclaims דְּרוֹר (deror, \"liberty/release\") throughout the land (25:10). Isaiah 61:1 borrows this rare legal term — לִקְרֹא לִשְׁבוּיִם דְּרוֹר (\"to proclaim liberty to captives\") — and Luke 4:18-19 has Jesus read exactly that Isaiah passage in the Nazareth synagogue as his opening manifesto. The chain (Leviticus's legal term → Isaiah's prophetic reuse → Jesus's programmatic citation of Isaiah) is a genuine three-stage inner-biblical trajectory, though Luke quotes Isaiah, not Leviticus, directly.", "category": "typology", "citation": "Isaiah 61:1; Luke 4:18-19", "tier": "STRONG-INFERENCE"}], "24:16": [{"ref": "24:16", "title": "Blasphemy of the Name — the charge at Jesus's trial", "finding": "וְנֹקֵב שֵׁם יְהוָה מוֹת יוּמָת (\"one who pierces/pronounces the Name of YHWH shall surely die\") sets the capital law for blasphemy standing behind the charge brought against Jesus in Mark 14:64 and the crowd's attempt to stone him in John 8:58-59 and 10:31-33 for claiming divine prerogatives. The Gospels never cite Leviticus 24:16 by chapter and verse, but the legal category they invoke is this one.", "category": "ot-allusion", "citation": "Mark 14:64; John 8:58-59; John 10:31-33", "tier": "STRONG-INFERENCE"}], "16:34": [{"ref": "16:34", "title": "Once a year, once for all", "finding": "The Day of Atonement is לְחֻקַּת עוֹלָם...אַחַת בַּשָּׁנָה (\"an everlasting statute... once in the year\"). Hebrews 9:7 and 9:25-26 explicitly key off this \"once a year\" (ἅπαξ τοῦ ἐνιαυτοῦ) repetition to argue that Christ's single, unrepeated self-offering supersedes it — Hebrews' whole \"better sacrifice\" argument is built as a direct contrast with this verse's own vocabulary of annual repetition.", "category": "typology", "citation": "Hebrews 9:7, 25-26", "tier": "DEMONSTRABLE"}]};